window.PAPERS_DATA={"papers":[{"id":"2607.14947","versioned_id":"2607.14947v1","title":"Optimal Self-Distillation for Rectified Flow via Linear Probing","authors":["Saptarshi Roy","Debepsita Mukherjee","Pratik Patil"],"abstract":"Modern generative models are increasingly trained using model-generated signals, creating both opportunities for self-improvement and risks of collapse. We study optimal self-distillation (SD) for rectified flow (RF): given a suboptimal teacher velocity field, can a student trained on a mixture of true RF velocities and teacher velocities provably improve the teacher? For linear RF with ridge regularization on fixed interpolation pairs, we prove an exact affine path identity, derive the optimal mixing coefficient in closed form, and show strict improvement in integrated velocity risk whenever the teacher risk is nonstationary along the regularization path. The optimal coefficient obeys a sign rule: positive mixing corrects under-regularized teachers, while negative mixing corrects over-regularized teachers. We also give one-shot generalized cross-validation (GCV) and validation tuning procedure that avoids grid search over mixing weights and repeated refitting. Combining this theorem with RF Wasserstein convergence bounds, we show that optimal self-distillation improves the velocity estimation terms controlling continuous-time and finite-step generation error. Experiments with Gaussian models, Gaussian mixtures, and image data show that optimal self-distillation improves velocity risk, mode recovery, and finite-step generation relative to both the teacher and pure distillation.","published":"2026-07-16T12:57:00Z","updated":"2026-07-16T12:57:00Z","categories":["stat.ML","cs.LG"],"primary_category":"stat.ML","arxiv_url":"https://arxiv.org/abs/2607.14947v1","pdf_url":"https://arxiv.org/pdf/2607.14947v1","comment":"29 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.14735","versioned_id":"2607.14735v1","title":"CoTu at EXACT 2026: Neuro-Symbolic Reasoning for Transparent Educational QA","authors":["Quoc-Khang Tran","Minh-Thien Nguyen","Phu-An Thai","Xuan-Tung Bui","Truong-Thanh Ma","Nguyen-Khang Pham"],"abstract":"Transparent educational question answering asks for answers that are not only correct but explainable, and doing so with small models rules out the reasoning power of the largest proprietary systems. The EXACT 2026 competition poses this problem concretely: open-weight language models of at most 8B parameters, self-hosted, with a natural-language explanation for every answer. It pairs two tasks: logical reasoning over university regulations, and multi-step physics problem solving. We describe the system that team \\cotu{} developed to address both, a neuro-symbolic Program-of-Thought pipeline in which a 4B backbone writes a program rather than stating an answer directly: for regulation queries it emits a Z3 encoding whose entailment verdict grounds the deduction, and for physics it emits numerical Python, both wrapped in a shared self-correction loop and a unified explained-JSON output. Answer-type routing, distillation-based task fine-tuning, and a latency-aware serving stack -- SGLang with speculative decoding -- keep the system within the 60-second per-query limit. The system achieved a \\textbf{perfect score} on the physics task in both automated selection rounds and obtained the \\textbf{highest final-round technical score} of any team -- $13.44/15$, combining automated answer evaluation with expert-judged reasoning depth -- with the equally weighted presentation score included, \\cotu{} placed 3rd overall. Grounding answers in a symbolic solver yields correct, verifiable deductions at the 4B scale, and the residual difficulty lies in premise selection rather than the deduction itself.","published":"2026-07-16T09:01:02Z","updated":"2026-07-16T09:01:02Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.14735v1","pdf_url":"https://arxiv.org/pdf/2607.14735v1","comment":"The 2nd International XAI Challenge for Transparent Educational Question-Answering @ IEEE IJCNN 2026 Competition","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.14658","versioned_id":"2607.14658v1","title":"TopoAgent: A Self-Evolving Topological Agent for Multimodal Scientific Reasoning","authors":["Mingze Xu","Yinghui Li","Jiayi Kuang","Zhanhui Kang","Di Yin","Ying Shen","Xing Sun","Yuxing Han"],"abstract":"While Multimodal Large Language Models (MLLMs) excel in general tasks, rigorous scientific reasoning remains challenging due to the limitations of monolithic, linear planning. Such sequential designs often suffer from visual-semantic misalignment, long-context hallucinations, and brittle execution under fixed task granularity. We propose TopoAgent, a self-evolving topological framework that replaces linear trajectories with dynamic, state-isolated graph evolution. TopoAgent first employs a front-end decomposer to fracture complex queries into visually-grounded atoms. These atoms are organized into a Directed Acyclic Graph (DAG) based on their dependencies, enabling strict context isolation to shield the reasoning engine from irrelevant historical noise. Furthermore, we introduce adaptive atomic fission, which dynamically splits bottleneck nodes into finer-grained sub-atoms at runtime when tool capability boundaries are exceeded. Extensive experiments across mathematics, physics, and chemistry benchmarks demonstrate that TopoAgent significantly outperforms state-of-the-art linear agent frameworks, providing a robust, noise-resistant, and self-correcting paradigm for autonomous scientific reasoning.","published":"2026-07-16T07:22:59Z","updated":"2026-07-16T07:22:59Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.14658v1","pdf_url":"https://arxiv.org/pdf/2607.14658v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.14611","versioned_id":"2607.14611v1","title":"Bad Memory: Evaluating Prompt Injection Risks from Memory in Agentic Systems","authors":["Soham Gadgil","David Alexander","Sai Sunku","Franziska Roesner"],"abstract":"A growing class of agentic systems maintain persistent state across sessions through memory files, behavioral preferences, and knowledge bases. While this makes agents more useful and self-improving, it also creates a new attack surface for prompt injections in which malicious instructions can be embedded within persistent files and influence future behavior. In this work, we study prompt injection attacks in memory-based agentic systems using a sandboxed synthetic workspace. We evaluate two agentic systems, Anthropic Claude Code and OpenAI Codex, across four models: Claude Haiku 4.5, Claude Opus 4.7, GPT-5.2, and GPT-5.5. Our results show that although it is difficult to make an agent overwrite its own memory files using untrusted external content, payloads already planted in those files can successfully attack current and future sessions. Attack success and payload persistence vary substantially across systems, models, adversarial goals, and multi-session attack sequences. These findings show that persistent memory changes the threat model for prompt injection and motivate defenses that protect memory updates without removing useful agent adaptation.","published":"2026-07-16T06:13:48Z","updated":"2026-07-16T06:13:48Z","categories":["cs.CR","cs.AI","cs.MA"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2607.14611v1","pdf_url":"https://arxiv.org/pdf/2607.14611v1","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.14396","versioned_id":"2607.14396v1","title":"CatalogAgent: A Supervisor-mediated Self-Learning System Enabling Context Engineering for GenAI Models","authors":["Zhu Cheng","Zhenming Wang","Yu","Tang","Dan Liu","Bryan Zhang","Athanasios N. Nikolakopoulos","Pranav Souri Itabada","Jing Zhang","Chih-Chi Chou","Peng Gao","Fatemeh Mansoori","Bharat Bojja","Sarath Chander","Sameer Thombare","Umit Batur","Tarik Arici"],"abstract":"Product catalogs are the backbone of e-commerce sites, yet a large number of structured attributes (SAs) -- such as material, color, and shape -- often have missing values. Typically, SA values are extracted from product information, including titles and descriptions. While LLM-based generator-evaluator frameworks have demonstrated effectiveness for SA prediction -- where an LLM generates SA values and another evaluates them -- they face challenges when the Generator and Evaluator produce conflicting outputs, as either component can make mistakes. We introduce \\texttt{CatalogAgent}, a novel agentic system that continuously improves Generator and Evaluator models for e-commerce catalog enrichment. When disagreements arise from (1) internal conflicts between the LLM-based Generator and Evaluator, or (2) external feedback from sellers on LLM outputs, a Supervisor Agent intervenes to mediate these conflicts and make final decisions. The system also incorporates a Memory Base and a Memory Summarizer that stores Supervisor Agent activities from individual cases and aggregates patterns into learnings. These learnings are fed back to the worker Generator and Evaluator LLMs, enabling self-improvement without human intervention. Through context engineering -- injecting learnings and insights into worker LLMs' contexts -- the system successfully transfers the Supervisor's capabilities to the Generator and Evaluator, improving their performance by 15.24\\% and 13.98\\%, respectively. Our experiments demonstrate a new paradigm of Supervisor Agent-mediated self-learning systems for improving generative AI model accuracy.","published":"2026-07-15T22:20:59Z","updated":"2026-07-15T22:20:59Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.14396v1","pdf_url":"https://arxiv.org/pdf/2607.14396v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.13884","versioned_id":"2607.13884v1","title":"Experience Memory Graph: One-Shot Error Correction for Agents","authors":["Wenjun Wang","Yuchen Fang","Fengrui Liu","Zibo Liang","Kai Zheng"],"abstract":"Large Language Model (LLM) agents have shown remarkable capabilities in autonomous decision-making by generating sequential trajectories of states, actions, and observations. However, in complex, long-horizon tasks, these agents frequently suffer from compounding errors and struggle to recover from failures. Existing self-correction mechanisms rely on prompt-based reflection, which is inherently brittle, incurs heavy time and API costs due to iterative trial-and-error loops, and produces task-specific memory that may be hard to generalize to new scenarios. To address this, we propose Experience Memory Graph (EMG), a framework that reformulates agent failure recovery as a graph matching problem. At training time, we convert both failed exploration trajectories and successful expert trajectories into directed action decision graphs. By matching these graphs, we extract common subgraphs (successful workflows) and graph edit paths that explicitly indicate how to correct failures (e.g., which actions to add, delete, or relabel under a given observation), and store them in a memory graph with intra-task nodes and cross-task edges. At test time, EMG retrieves relevant insights and guides the agent in a single, loop-free execution. Experiments on ALFWorld and ScienceWorld show that EMG consistently outperforms state-of-the-art reflection baselines in success rate and average reward, while requiring no test-time trial-and-error.","published":"2026-07-15T14:33:15Z","updated":"2026-07-15T14:33:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.13884v1","pdf_url":"https://arxiv.org/pdf/2607.13884v1","comment":"11 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.14178","versioned_id":"2607.14178v1","title":"ReasFlow: Assisting Reasoning-Centric Scientific Discovery in Applied Mathematics via a Knowledge-Based Multi-Agent System","authors":["Yutong He","Daibo Li","Guohong Li","Jiahe Geng","Zhengyang Huang","Can Ren","Zekun Zhang","Yifan Liu","Shuchen Zhu","Hengrui Zhang","Boao Kong","Ming Sun","Shu Li","Chenyi Li","Jiang Hu","Kun Yuan","Zaiwen Wen","Pingwen Zhang"],"abstract":"Recent advances in Large Language Models have fueled autonomous AI agents capable of tackling complex scientific tasks, yet existing automated research systems remain predominantly focused on empirically driven domains with quantitative benchmarks, leaving theory-driven discovery, particularly in mathematically grounded disciplines requiring rigorous proofs and synthesis of domain knowledge, largely underexplored. Key challenges include the difficulty of verifying theoretical reasoning at scale, insufficient reasoning ability for autonomous frontier exploration, and a scarcity of procedural heuristics in the literature. We introduce ReasFlow, an end-to-end autonomous agent system for reasoning-centric scientific discovery that operationalizes a collaborative paradigm where the human expert acts as Principal Investigator while the agent executes rigorous derivations as a capable graduate student. ReasFlow incorporates (i) a robust internal verification loop that audits logical coherence and corrects fundamental errors prior to human inspection, and (ii) an automated knowledge retrieval and self-improvement mechanism that proactively surfaces both declarative facts and overlooked procedural heuristics, substantially reducing expert intervention. The system unifies literature synthesis, algorithm design, theorem proving, experimentation, and manuscript preparation in a single system. Deployed to autonomously generate five complete research papers with rigorous theoretical and empirical content from minimal prompts, ReasFlow consistently achieves the highest evaluation scores among state-of-the-art open-access baselines under a curated LLM-based review rubric. ReasFlow is publicly accessible via the ReasLab platform, providing a collaborative workspace for AI-assisted theoretical research. Github repo: https://github.com/ReasLab/ReasFlow.git.","published":"2026-07-15T13:27:20Z","updated":"2026-07-15T13:27:20Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.14178v1","pdf_url":"https://arxiv.org/pdf/2607.14178v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.13395","versioned_id":"2607.13395v1","title":"Self-Improving is Often Sudden: Enlightenment-style Finetuning for Large-Scale Models","authors":["Jing-Xiao Liao","Tianwei Zhang","Yu-Hao Jiang","Feifei Zhang","Hang-Cheng Dong","Feng-Lei Fan"],"abstract":"The pursuit of autonomously self-improving models has attracted growing interest in the era of large-scale foundation models. Drawing inspiration from the concept of \"enlightenment\" or \"aha moment\" in human brain, we hypothesize that large models exhibit an analogous enlightenment phenomenon-a latent capacity for sudden capability boost. Then, we propose Enlightenment, a novel training-free post-tuning paradigm for large-scale models. Our approach modifies shortcuts for key modules/layers without weight updates, while existing training-free ones predominantly manipulate attention weights. We introduce two architecture-specific instantiations: i) For large language models, we propose attention head-mixing shortcuts that recalibrate attention weights by linking the initial attention head's output to all other target heads, modulated by an adaptive scaling factor initialization strategy. ii) For vision-language models, we apply a lightweight scalar-modulated factor to residual connections in the decoder layers, regulating information flow. Extensive experiments show that Enlightenment efficiently unlocks the latent potential of pre-trained networks, yielding remarkable performance improvements across diverse benchmarks and models.","published":"2026-07-15T02:43:34Z","updated":"2026-07-15T02:43:34Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.13395v1","pdf_url":"https://arxiv.org/pdf/2607.13395v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.13188","versioned_id":"2607.13188v1","title":"Concurrent Image Understanding and Generation: Self-Correcting Coupled Markov Jump Processes","authors":["Minh-Quan Le","Armand Comas","Alexandros Lattas","Stylianos Moschoglou","Pedro Vélez","Amit Raj","Aaron Germuth","Thabo Beeler","Dimitris Samaras","Di Qiu"],"abstract":"Human cognition does not separate understanding and generation. A teacher at a whiteboard speaks and draws $\\textit{together}$, each modality reshapes the other. In this paper, we bring this coupled loop to artificial systems. Masked Diffusion Models (MDMs) are ideally suited to this task, yet existing samplers either decode text and image interleavedly or independently update them in parallel branches that share only previous-step history, but not the other modality's latest decisions $\\textit{within}$ the same step; combined with MDMs' inability to remask, cross-modal contradictions are neither detected nor repaired. We introduce $\\textbf{Self-Correcting Coupled Markov Jump Processes (SC-CMJP)}$, a framework in which one modality's transition rates are functionals of the other modality's confidence score, as weighted by cross-modal attention. Furthermore, a remasking jump retracts commitments the moment cross-modal evidence turns against them. In conjunction with SC-CMJP, we introduce $\\texttt{CO}_\\texttt{2}\\texttt{Jump}$ (Self-$\\underline{\\text{CO}}$rrecting $\\underline{\\text{CO}}$upled $\\underline{\\text{Jump}}$), a novel training-free single-pass sampler for joint multimodal geneneration. For training and evaluation purposes, we have created and will release three large-scale joint multimodal generation corpora: $\\text{JEdit-1M}$, $\\text{JMaze-200K}$, $\\text{JNono-200K}$, with matching in- and out-of-distribution benchmarks. $\\texttt{CO}_\\texttt{2}\\texttt{Jump}$ achieves best joint performance for image understanding and editing as well as visual reasoning (maze and nonogram solving). The performance of the sampler scales monotonically with the number of denoising steps, evidence that the benefits of cross-modal coupling $\\textit{compound}$ across the trajectory. Project page: https://coupled-jump.github.io","published":"2026-07-14T18:39:29Z","updated":"2026-07-14T18:39:29Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.13188v1","pdf_url":"https://arxiv.org/pdf/2607.13188v1","comment":"Project page: https://coupled-jump.github.io","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.12790","versioned_id":"2607.12790v1","title":"Who Grades the Grader? Co-Evolving Evaluation Metrics and Skills for Self-Improving LLM Agents","authors":["Xing Zhang","Guanghui Wang","Yanwei Cui","Ziyuan Li","Wei Qiu","Bing Zhu","Peiyang He"],"abstract":"Self-evolving agent systems improve by creating, revising, and retiring their own skills, but every such loop rests on a hidden assumption: a reliable evaluation metric already exists. In many real applications it does not. We make three claims. First, metrics can be \\emph{evolved}: our metric loop searches compositions of small drawback detectors under a full evolutionary lifecycle, trained to agree with a ten-item anchored reference set, regularized by consensus over unlabeled outputs, and audited against a held-out anchor it never reads, yielding a transparent, inspectable metric rather than an opaque judge. Second, since no metric exists to beat, the yardstick is recovering what an accurate metric would have enabled, and \\emph{Double Ratchet}, our co-evolution of the metric with a lifecycle-managed skill loop, does so: across code generation (MBPP+), enterprise text-to-SQL (Spider~2.0-Snow), and reference-free report generation, it retains 88--110\\% of the held-out lift achieved by the same skill loop driven by ground truth or the best available rubric. Third, safety comes from anchor discipline plus outer audits: removing anchor guards collapses the metric into a vacuous detector while removing the lifecycle does not; and when evolved skills gamed the report rubric, an independent judge caught it, one detector repaired it, and a task-aware judge then preferred the evolved outputs over the pre-evolution baseline in 77\\% of decided pairs. We argue this failure-expecting architecture is the right default wherever no reliable automatic verifier exists.","published":"2026-07-14T14:02:50Z","updated":"2026-07-14T14:02:50Z","categories":["cs.AI","cs.CL","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.12790v1","pdf_url":"https://arxiv.org/pdf/2607.12790v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.12625","versioned_id":"2607.12625v2","title":"KnowAct-GUIClaw: Know Deeply, Act Perfectly, Personal GUI Assistant with Self-Evolving Memory and Skill","authors":["Yunxin Li","Jinchao Li","Shibo Su","Zhenran Xu","Chenrui Zhao","Tongshu Bian","Xiaoman Liang","Meishan Zhang","Baotian Hu","Min Zhang"],"abstract":"OpenClaw has emerged as a leading agent framework for complex task automation, yet it faces insufficient cross-platform GUI interaction support and a well-built self-evolution mechanism. These flaws limit its adaptation to diverse device ecosystems and prevent performance improvements through continuous learning from execution experience. To resolve these issues, we propose the Know Deeply, Act Perfectly paradigm for personal assistants, which holds that accumulated user interaction and task-running experience directly improve execution accuracy and efficiency, unifying cognitive comprehension and operational execution. Based on this paradigm, we introduce KnowAct-GUIClaw, a novel Know-Route-Act-Reflect framework designed to address OpenClaw's GUI manipulation deficits and break through its cross-platform and recursive self-improvement constraints. First, the host agent leverages accumulated interaction experience and task-relevant knowledge for long-horizon task decomposition and allocation (Know). Second, a pluggable GUI subagent with an experience-attributable memory system (Know) and self-evolving skill library (Act), enabling seamless cross-platform migration and fast-path integration. Especially, this framework continuously stores user profiles and feedback to improve the accuracy of task decomposition and tool calls. Extensive experiments across Android, iOS, HarmonyOS and Windows show that KnowAct-GUIClaw achieves superior efficiency, accuracy and cross-platform adaptability. Especially, the GUIClaw with open-source Kimi-2.6 models achieves the best performance (64.1%) on the long-horizon MobileWorld benchmark, beating all agentical frameworks and closed-source agentical models, e.g., Seed-2.0-Pro and GPT-5.5. Additionally, the knowledgeable memory and execution skills supported by our framework are transferable across diverse base models, improving by 8.5% with Kimi-2.6.","published":"2026-07-14T11:04:01Z","updated":"2026-07-15T04:41:47Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.12625v2","pdf_url":"https://arxiv.org/pdf/2607.12625v2","comment":"29 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.13104","versioned_id":"2607.13104v1","title":"Self-Improvements in Modern Agentic Systems: A Survey","authors":["Zhe Ren","Yimeng Chen","Dandan Guo","Guowei Rong","Tonghui Li","R. B. Xiong","Qingfeng Lan","Wenyi Wang","Li Nanbo","Yibo Yang","Mingchen Zhuge","Jürgen Schmidhuber"],"abstract":"Self-improving autonomous agents are moving from research prototypes to deployed systems. The primary goal is controllable evolution, or adaptation, from experience with minimal or even no human input. This survey frames modern self-improving agents as adaptive systems that convert experience into accumulated capability gains. We offer a system-level framework that represents a modern agent as a configuration coupling a foundation model with an operational scaffold of prompts, memory, tools, and control logic. Within this framework, self-improvement is formalized as a self-induced update operator that obtains and commits updates to model parameters or scaffold components. We organize prior work by update target and by the signals that drive change, then review applications and discuss evaluation, before closing with open problems and future directions. For convenience, we track technical updates on https://github.com/selfimproving-agent/awesome-Self-Improving-Agents.","published":"2026-07-14T09:12:57Z","updated":"2026-07-14T09:12:57Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.13104v1","pdf_url":"https://arxiv.org/pdf/2607.13104v1","comment":"97 pages, 12 figures. Project page: https://selfimproving-agent.github.io/ Repository: https://github.com/selfimproving-agent/awesome-Self-Improving-Agents","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.12455","versioned_id":"2607.12455v1","title":"EVOQUANT: Self-Evolving Verifier-Guided Strategy Optimization for Robust Quantitative Trading","authors":["Jie Mao","Changlun Li","Xiang Li","Qiqi Duan","Jinhui Yuan","Xiang Liu","Yuyu Luo","Jing Tang","Xiaowen Chu","Nan Tang"],"abstract":"Quantitative strategy optimization remains largely manual, requiring domain experts to identify weak signals, tune risk-control rules, and repeatedly validate iterative revisions. Large language models can accelerate this process, but directly relying on them to rewrite trading strategies often introduces hallucinated edits, strategy drift, and backtest overfitting. We propose EVOQUANT, a self-Evolving Verifier-guided framework for strategy Optimization in Quantitative trading. Our method utilizes LLMs to deeply diagnose performance bottlenecks, generates semantically controlled candidate edits, selects the best strategy through a multi-stage verification pipeline, and distills optimization experience into reusable knowledge for continual self-improvement. We evaluate our method using seven representative strategies: four from the A-share market and three from the Crypto market. Experimental results show that our method significantly improves the Sharpe ratio across all tested strategies: the average test Sharpe increases from -0.298 to 0.538, and the best-performing strategy achieves a 199% relative improvement. Ablation studies and stress tests under stricter conditions further validate the effectiveness and robustness of the framework. Overall, this work transforms quantitative strategy optimization from costly manual trial and error into an automated and verifiable iterative paradigm, offering a new path for applying large language models to financial strategy research.","published":"2026-07-14T07:34:01Z","updated":"2026-07-14T07:34:01Z","categories":["cs.AI","cs.CE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.12455v1","pdf_url":"https://arxiv.org/pdf/2607.12455v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.13091","versioned_id":"2607.13091v1","title":"Self-Improving AI Coding Agents Through Accumulated Behavioral Rules: A Closed-Loop Framework","authors":["Aditya Aggarwal","Nahid Farhady Ghalaty"],"abstract":"LLM-based coding agents repeat the same classes of mistakes across sessions because they lack a mechanism to retain corrections from human review feedback. We present a closed-loop framework in which every accepted review comment is codified as a persistent behavioral rule, progressively expanding the set of error classes the agent can self-detect. The framework combines an accumulating rule set in a version-controlled instruction file, a self-review checklist executed before code submission, and automated validation that ensures rule set integrity as it grows. In deployment across a 35+ service microservices platform, the rule set grew from 5 to 18 behavioral rules, 15+ language-specific standards, and a 15-item self-review checklist, all derived from real review feedback. We present empirical results from 11 recorded working sessions spanning code generation, PR review, incident investigation, and cross service refactoring. We observe that accumulated rules shift review effort from low-level correctness toward design-level validation, achieve a measured 0% recurrence rate for ruled-against error classes, and transfer across heterogeneous agent interfaces. We compare our approach against related work in experiential LLM learning (Reflexion, ExpeL, Voyager) and automated code review (CodeReviewer, SWE-bench agents), showing that our framework achieves persistent cross-session learning without weight updates, operates on production codebases rather than synthetic benchmarks, and addresses an orthogonal dimension (behavioral consistency over time) that existing benchmarks do not measure. The result is a coding agent that improves with every review cycle, accumulating the engineering wisdom of its human collaborators without changing a single model weight.","published":"2026-07-13T21:13:46Z","updated":"2026-07-13T21:13:46Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.13091v1","pdf_url":"https://arxiv.org/pdf/2607.13091v1","comment":"Already presented and accepted in - 32nd ICE IEEE/ITMC Conference (ICE 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.12042","versioned_id":"2607.12042v1","title":"SymbOmni: Evolving Agentic Omni Models via Symbolic Concept Learning","authors":["Jinxiu Liu","Jianru Li","Tanqing Kuang","Xuanming Liu","Kangfu Mei","Yandong Wen","Weiyang Liu"],"abstract":"Visual generation is increasingly ubiquitous in diverse domains, from text-to-image/video synthesis to multimodal interactive creation. Yet prevailing monolithic models remain fundamentally constrained by their inability to learn cumulatively and evolve autonomously, which is a limitation we term the \"perpetual novice\" problem. They lack mechanisms for structuring experience into reusable knowledge and therefore rely on brittle, \"from-scratch\" reasoning for each task, resulting in poor compositional generalization and inefficient knowledge retention. Motivated by these limitations, we propose SymbOmni, an agentic omni-model designed for cumulative evolution through Symbolic Concept Learning. At its core is the Symbolic Concept Box, an optimizable memory module that abstracts low-level operations into reusable Symbolic Workflow Instructions. SymbOmni operates through an induction-transduction cycle: experiences are abstracted into symbolic concepts (induction), which are then adaptively composed to solve novel tasks (transduction). The training is done by verbalized backpropagation with language-based feedback to enable continuous self-improvement without gradient-based model fine-tuning. Comprehensive experiments validate that (I) SymbOmni significantly outperforms existing agent-based systems for iterative creation and also surpasses closed-source models (e.g., Nano Banana, GPT-Image-1) in both image quality and task success rates; (II) SymbOmni effectively reduces token consumption by over 40% while maintaining competitive generation quality; and (III) SymbOmni enables effective continual learning by achieving cumulative gains across multiple online-learning benchmarks and setting a new state of the art.","published":"2026-07-13T18:00:34Z","updated":"2026-07-13T18:00:34Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2607.12042v1","pdf_url":"https://arxiv.org/pdf/2607.12042v1","comment":"ECCV 2026 (49 pages, 10 figures, project page: https://spherelab.ai/symbomni)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11701","versioned_id":"2607.11701v1","title":"$\\mathtt{Q^2SAR}$: overcoming classical bottlenecks in drug discovery via quantum multiple kernel learning","authors":["Mariano Caruso","Daniel Ruiz","Alejandro Giraldo","Guido Bellomo"],"abstract":"Quantitative Structure-Activity Relationship ($\\mathtt{QSAR}$) modeling is a foundational computational methodology in early-stage drug discovery, heavily relied upon for predicting compound toxicity, bioavailability, and therapeutic potential. However, classical methods often struggle to effectively map the highly complex, non-linear, and high-dimensional interactions inherent in molecular data, leading to reduced predictive accuracy and costly late-stage clinical failures. In this paper, we present a Quantum Multiple Kernel Learning ($\\mathtt{QMKL}$) framework, dubbed Next-Gen $\\mathtt{Q^2SAR}$, that leverages Quantum Support Vector Machines ($\\mathtt{QSVMs}$) to overcome these classical limitations. By encoding molecular descriptors into exponentially large quantum Hilbert spaces, our approach substantially enhances the expressiveness of non-linear modeling. Benchmarking our quantum-enhanced framework on a dataset targeting the $\\mathtt{DYRK1A}$ kinase (a critical target for Alzheimer's disease), the $\\mathtt{QMKL}$-$\\mathtt{SVM}$ achieves an impressive Area Under the Curve ($\\mathtt{AUC}$) score of $0.8750$, significantly outperforming classical state-of-the-art Gradient Boosting models ($\\mathtt{AUC} = 0.8037$). Furthermore, we establish a theoretical and empirical pathway toward resolving classical data bottlenecks through projected quantum kernels ($\\mathtt{PQK}$) and measurement accelerators. As quantum computing architecture matures, this framework paves the way for autonomous cognitive architectures and self-improving drug discovery pipelines, promising to unlock deeper insights across vast chemical spaces and to accelerate the development of life-saving therapeutics.","published":"2026-07-13T15:33:05Z","updated":"2026-07-13T15:33:05Z","categories":["quant-ph","cs.LG"],"primary_category":"quant-ph","arxiv_url":"https://arxiv.org/abs/2607.11701v1","pdf_url":"https://arxiv.org/pdf/2607.11701v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11696","versioned_id":"2607.11696v1","title":"Think Through a Bottleneck: Hourglass Reasoning for Rigorous Induction","authors":["Huan Zhu"],"abstract":"Self-refinement often fails to strengthen few-shot inductive reasoning in large language models. Prompting a model to explicitly state its inferred rule does little on its own. What actually matters is a structurally enforced isolation between reasoning stages, so that information can only pass between them as a compressed symbolic state. We introduce \\textbf{Hourglass reasoning}, which enforces strict context isolation between reasoning stages. The frozen LLM acts as a meta-constructor, building for each task a symbolic encoder--decoder: an Induction module compresses the support examples into a schema $φ$ (encoder) and a transient scaffold $z$; a Deduction module derives rule $T$ (decoder) from these and discards $z$; an Implementer compiles $(φ, T)$ into artifacts; an error-driven Refiner revises $(φ, T)$ and regenerates artifacts from scratch. Only $(φ, T)$ crosses stage boundaries, so all refinement stays anchored to the rule. We evaluate Hourglass across three benchmarks spanning visual abstraction, hardware synthesis, and textual rule induction, using GPT-5.5 and Gemini 3.1 Pro. On ARC-AGI-2, it raises best-of-5 accuracy by up to 14 points over an iterative-refinement baseline. On ChipBench, it nearly doubles Verilog synthesis accuracy with GPT-5.5, from 31\\% to 58\\%. BBEH-Linguini draws on puzzles from the International Linguistics Olympiad, a setting where prior work has shown that explicit verbalization can hurt performance. Hourglass mitigates this tendency, and on Gemini 3.1 Pro, it reverses the effect entirely. Ablations confirm that these gains come from the isolation between stages and the quality of the initial induction, not from prompt wording or the particular symbolic form used. It is how information flows through the reasoning process, rather than the language used to express it, that drives inductive reasoning in frozen LLMs.","published":"2026-07-13T15:29:24Z","updated":"2026-07-13T15:29:24Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.11696v1","pdf_url":"https://arxiv.org/pdf/2607.11696v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11689","versioned_id":"2607.11689v1","title":"From World Action Models to Embodied Brains: A Roadmap for Open-World Physical Intelligence","authors":["Yuanzhi Liang","Xufeng Zhan","Haibin Huang","Chi Zhang","Xuelong Li"],"abstract":"Artificial general intelligence ultimately requires agents that can reason and act in the physical world. Action models, vision-language-action policies, and world models have advanced this goal, while World Action Models (WAMs) are particularly promising because they connect candidate interventions with predicted consequences. However, progress remains fragmented: models use incompatible action spaces and prediction targets, datasets and tasks follow different conventions, and runtime systems expose limited interfaces for reuse and evaluation. We review the evolution toward WAMs and organize these limitations into three coupled gaps: model roles and representations, objectives and standardization, and system composition. Building on this analysis, we propose a co-evolution roadmap for physical intelligence centered on the \\emph{embodied brain}, a long-term model target for integrating multimodal context, comparing candidate interventions, and issuing state-transition or capability requests rather than direct actuator commands. WAMs provide promising prototypes for its predictive functions, while a physical harness grounds model outputs through tools, controllers, verification, and trace logging. Shared contracts align heterogeneous models, data, tasks, and embodiments, and closed-loop post-training converts verified interaction into reusable experience. Together, these components define a modular physical-intelligence stack for adaptive and self-improving embodied agents.","published":"2026-07-13T15:22:56Z","updated":"2026-07-13T15:22:56Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2607.11689v1","pdf_url":"https://arxiv.org/pdf/2607.11689v1","comment":"Ongoing work","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11288","versioned_id":"2607.11288v1","title":"Mako: A Self-Evolving Agentic Operating System (SE-AOS) for Autonomous Web Exploitation","authors":["Praneeth Narisetty","Shiva Nagendra Babu Kore"],"abstract":"We introduce the Self-Evolving Agentic Operating System (SE-AOS): a new class of AI agent that treats exploit capability as a mutable, versioned kernel it extends at runtime, observing its own failures, synthesising new capabilities, proving them against a live target, and hot-loading them back into itself. Mako is the first SE-AOS instance for security research and the autonomous web exploitation engine developed within LaunchSafe. LaunchSafe builds autonomous security agents for continuous offensive testing and agent-driven security research; Mako is the core engine behind that platform. On the public XBOW validation-benchmarks, 104 containerised, CTF-style web applications spanning 26 vulnerability classes across three difficulty tiers, Mako achieves full-suite coverage: it drives every one of the 104 targets to emit a cryptographically fresh, per-build flag, under a verification regime that makes fabricated or memorised results impossible. Our central result is a law of autonomous exploitation: once a capability exists and is discoverable, difficulty collapses; capability, not reasoning, is what is scarce, together with an architecture and formalism that turn that law into a self-improving system. Mako further runs a gated self-evolution loop that proposes, sandboxes, and commits improvements to its own agents and rules when fitness does not regress. We deliberately withhold the operational results, payloads, exploit chains, and tool source, because a system that reduces full-spectrum web exploitation to a repeatable, machine-speed pipeline is dual-use research of concern. We publish the science; we withhold the weapon.","published":"2026-07-13T09:07:30Z","updated":"2026-07-13T09:07:30Z","categories":["cs.CR","cs.AI","cs.MA"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2607.11288v1","pdf_url":"https://arxiv.org/pdf/2607.11288v1","comment":"13 pages, 10 figures, 8 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11267","versioned_id":"2607.11267v1","title":"Enhancing LLMs through human feedback: a journey towards self-improvement","authors":["Tatiana Pelc","Gila Kamhi","Asaf Avrahamy","Adi Fledel-Alon"],"abstract":"In the rapidly evolving landscape of information retrieval systems, the ability to adapt and improve through user feedback is paramount. This study introduces a novel methodology for refining the performance of a primary Retrieval Augmented Generation (RAG) system by strategically integrating an auxiliary feedback RAG system. By systematically harnessing human-generated feedback, the approach aims to enhance the accuracy, relevance, and overall quality of responses, driving the system towards self-improvement. Central to this methodology is a human-in-the-loop implementation, where user feedback is continuously collected, classified, and integrated into the inference workflow, enabling the system to learn and evolve iteratively. To validate the effectiveness of this approach, the study employs rigorous testing against three diverse benchmark datasets focused on general and custom domain knowledge, utilizing a LLM-as-a-Judge evaluation strategy. This comprehensive framework not only underscores the transformative potential of feedback-driven enhancements in RAG systems but also sets a precedent for future research in adaptive information retrieval technologies, marking a significant step in the journey towards autonomous refinement and optimization through user engagement.","published":"2026-07-13T08:51:08Z","updated":"2026-07-13T08:51:08Z","categories":["cs.IR","cs.AI","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2607.11267v1","pdf_url":"https://arxiv.org/pdf/2607.11267v1","comment":"AIC 2025: The 10th International Workshop on Artificial Intelligence and Cognition (held as part of ECAI 2025). October 25-26, 2025. Bologna, Italy","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11175","versioned_id":"2607.11175v1","title":"The Path to Self-Evolving Clinical Systems: Scaling Medical Agents from Assistance to Autonomy","authors":["Chunzheng Zhu","Lei Tian","Bohan Tan","Ziqi Zhou","Yuxuan Sun","Yijun Wang","Chengchao Lv","Yilin Wen","Yijun He","Jinghao Lin","Yihang Chen","Cheewei Tan","Qianshan Wei","Lei Zhao","Bin Pu","Kenli Li","Yuan Xue","Jianxin Lin"],"abstract":"The growing ability of large language models and vision language models to jointly interpret and reason over images and text is reshaping medical agents, moving them from task specific predictors toward autonomous systems that perceive, reason, plan, remember, and act in clinical environments. This work departs from the capability first perspective of existing literature and instead begins from clinical deployment, asking what tasks, contamination resistant benchmarks, and interactive training environments are required before medical agents can be trusted in practice. Medical agents are formalized as sequential decision making systems under partial observability, together with a three level autonomy taxonomy spanning assisted, cooperative, and fully autonomous operation. The field is organized along a unified scaling spine consisting of framework scaling, capability scaling, and environment scaling. Within this framework, clinical environment scaling, the integration of tools, data, and clinical gyms, is identified as the most actionable yet underexplored direction for agents operating in PACS, EHR, and FHIR ecosystems. Clinical self evolution, where agents improve through interaction with their environments rather than parameter scaling alone, is further positioned as a key research frontier, drawing insights from self improving agents, agent gyms, and test time compute scaling. Applications across radiology, pathology, ophthalmology, and hospital workflows are examined together with deployment challenges including hallucination, cascading failures, and fairness. By consolidating more than 300 references, with particular emphasis on advances from 2025 to 2026, this work provides a roadmap toward trustworthy, self improving medical imaging systems for real clinical practice.","published":"2026-07-13T07:16:50Z","updated":"2026-07-13T07:16:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.11175v1","pdf_url":"https://arxiv.org/pdf/2607.11175v1","comment":"Project page: https://github.com/zhcz328/Awesome-Medical-Agents","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.10966","versioned_id":"2607.10966v1","title":"SVR-R1: Bootstrapping Multi-modal Reasoning with Self-verification in Reinforcement Learning","authors":["Mingyuan Wu","Jingcheng Yang","Shengyi Qian","Xudong Wang","Jize Jiang","Qifan Wang","Aashu Singh","Khoi Pham","Fei Liu","Zhaolun Su","Zhuokai Zhao","Klara Nahrstedt","Jianyu Wang","Hanchao Yu"],"abstract":"We introduce Self-Verified Reasoner (SVR-R1), a multi-turn RL framework that turns a model's own verification into a learning signal for multimodal reasoning. For each query, the model proposes an answer using the same weights, and issues a binary self-verdict (Yes/No). A 'No' triggers a second-chance rethink; a 'Yes,' or a turn cap, finalizes the output for computing the outcome-based reward. SVR-R1 is implemented with GRPO and an asynchronous multi-turn rollout framework and needs no external supervision or auxiliary critics. We evaluate SVR-R1 on vision-language reasoning benchmarks and show that it improves accuracy by a large margin over strong standard GRPO baselines. Training dynamics show decreasing reliance on verification-fewer verification turns, yet higher test accuracy-indicating that the gap between verification and generation narrows as the policy internalizes self-correction and chooses the most confident answer via our framework. SVR-R1 bridges the less explored intersection of inference-time self-refinement and RL training for VLMs, offering a simple yet effective recipe for bootstrapping multimodal reasoning. We will open-source \\textbf{SVR-R1} to facilitate future research in VLMs.","published":"2026-07-13T00:21:30Z","updated":"2026-07-13T00:21:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.10966v1","pdf_url":"https://arxiv.org/pdf/2607.10966v1","comment":"Under submission","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.10474","versioned_id":"2607.10474v1","title":"Reinforcement Learning with Verifiable Physics: Post-training LLMs with Continuous Rewards","authors":["Pengfei Cai","Utkarsh Utkarsh","Alan Edelman","Christopher Vincent Rackauckas","Rafael Gomez-Bombarelli"],"abstract":"Partial differential equations (PDEs) are foundational to modeling in science and engineering, but constructing reliable numerical solvers remains labor-intensive, demanding expert knowledge of discretization schemes, stability conditions, and boundary treatments. Recent work has begun to frame PDE solving as a code-generation task for large language models (LLMs), yet existing approaches operate primarily at inference time: relying on prompting, debugging, self-refinement, and test-time scaling rather than adapting the model itself. In parallel, reinforcement learning with verifiable rewards has emerged as a post-training paradigm for code and math reasoning, but its verifiers are typically binary: a compiler runs, or a test passes. Such signals discard the graded structure of scientific correctness, where two solvers may both execute and yet differ in solution accuracy by orders of magnitude. In this work, we introduce RLVP: Reinforcement Learning with Verifiable Physics, an RL post-training framework for multi-PDE solver code generation. RLVP addresses this verifiability gap with a hybrid verifier: hard program-validity checks ensure executability, while continuous physics rewards score function-space accuracy and PDE-residual consistency. A single policy is post-trained across diverse PDE families spanning hyperbolic, parabolic, elliptic, and incompressible-flow systems. RLVP improves over both pre-trained and supervised-only baselines on PDE benchmarks, and shows zero-shot improvement transfer to held-out PDEs. We show that a smaller LLM post-trained with RLVP can outperform prompting a frontier model on in-distribution PDE solver generation. The trained policy shows evidence of compositionality in numerical motifs: it recombines stencils, time-stepping schemes, and boundary-handling primitives learned from the PDEs used in training into generated solvers for unseen PDE problems.","published":"2026-07-11T20:53:04Z","updated":"2026-07-11T20:53:04Z","categories":["cs.LG","cs.AI","cs.CE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.10474v1","pdf_url":"https://arxiv.org/pdf/2607.10474v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11944","versioned_id":"2607.11944v1","title":"MAGE: Understanding Stability-Performance Trade-offs in Multi-component Prompt Optimization","authors":["Prateek Singh"],"abstract":"How do different components of iterative prompt optimization interact, and what happens when they are combined? We investigate this through MAGE (Memory-Augmented Goal-directed Prompt Evolution), a controlled analysis framework for studying component interaction in prompt optimization. MAGE is not proposed as a superior optimizer in absolute terms; it integrates episodic memory, multi-objective Pareto selection, and adaptive evaluation as a platform for controlled ablation. Our experiments uncover a previously unreported phenomenon, the Prompt Optimization Coupling Effect (POCE): when multiple stochastic optimization signals operate within a closed reflective loop, they interact in ways that simultaneously improve performance and amplify variance, behavior that cannot be predicted by analyzing components in isolation. Three main findings emerge. First, failure-grounded reflection is essential: methods relying only on scores (OPRO) or abstract critique (Self-Refine) fail to improve prompts. Second, MAGE achieves 46.4% versus GEPA's 34.0% on GSM8K-Hard (+12.4%, P(MAGE>GEPA)=0.998, 5 seeds on gpt-4o-mini), with comparable variance (7.3% vs. 7.0%). Third, increasing candidate diversity reveals the clearest POCE signal: expanding the candidate pool from n=3 to n=5 improves mean accuracy by +21.6% while increasing variance by 3.7x. We further validate on Llama 3.1 8B and show POCE is headroom-dependent: when the base model already achieves high accuracy, variance amplification disappears. Finally, in low-data regimes (Ntrain=30), well-designed fixed prompts outperform all reflective optimizers, indicating that scaffold choice dominates optimizer choice. Our results suggest prompt optimization systems behave as coupled stochastic processes and should be evaluated in terms of both performance and stability, not just peak accuracy.","published":"2026-07-11T10:05:58Z","updated":"2026-07-11T10:05:58Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.11944v1","pdf_url":"https://arxiv.org/pdf/2607.11944v1","comment":"10 pages, 1 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.13070","versioned_id":"2607.13070v1","title":"Falsifiable Release Gates for Self-Improving Systems","authors":["Deepak Soni"],"abstract":"Safety claims on self-improving agent runtimes are almost always self-graded: a policy file, a guardrail, or a README commitment. We describe falsifiable release gates, and a methodology to build and validate such systems, such that every new capability must pass a pre-specified, machine-verifiable acceptance suite before it ships, and a fixed set of standing invariants is preserved at each gate. I think we applied the method in the Antahkarana, an open runtime, via seven gates from basic observability into a self governing loop that suggests changes to its own policy. no action goes to an effector without a safety-critical property capability token minted by a control ring is exhaustively machine-checked over the one million recorded reachable state space of a bounded model and re-checked against execution traces. A purposely broken model gives the shortest counterexample, so the checker has teeth, is apparent. The self-enhancement loop is positively Constrained: the entire write surface is policy rules, tightening changes. may auto-apply loosening changes always require a human merge and a proposal autoclosed is one that mispredicts its own effect; We publish the acceptance measured results for all the seven gates, define precisely the scope of each claim (a bounded of the coordination skeleton (not the learned components) and free the runtime, either command line tools and the gate suite, so the results reproduce, and gates can run against other agent frameworks. Reviewers may repeat the single command central non-bypass in seconds.","published":"2026-07-11T06:06:34Z","updated":"2026-07-11T06:06:34Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.13070v1","pdf_url":"https://arxiv.org/pdf/2607.13070v1","comment":"14 pages, 8 figures. Software, gate suite, run artifacts, and TLA+ specification are open source","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.10127","versioned_id":"2607.10127v1","title":"GAE: Graph-Augmented Evolution for Scientific Discovery via Reinforcement Optimization","authors":["Xuanzhou Chen","Taoli Cheng"],"abstract":"Evolutionary program search guided by Large Language Models (LLMs) has emerged as a powerful paradigm for automated scientific discovery. However, current approaches are fundamentally constrained by three bottlenecks: structurally blind parent selection, sparse whole-program evaluation rewards, and static mutation operators that fail to adapt during search. We present GAE (Graph-Augmented Evolution), a framework that resolves these limitations through a tightly coupled, three-pillar architecture. First, a relational graph neural network (GNN) parses programs into typed computation graphs, producing structure-aware embeddings. Second, an RL-optimized meta-controller leverages these embeddings to replace blind evolutionary sampling with a directed policy, dynamically selecting optimal parents and mutation directions based on reward history. Third, an online GRPO fine-tuning loop continuously updates the LLM mutation operator at test-time using group-normalized evaluation rewards, directly aligning the model's generation distribution with high-fitness structural edits. We evaluate GAE on a challenging scientific discovery task: symbolic regression for complex nonlinear oscillator systems. By transforming stochastic search into a directed, self-improving trajectory, GAE efficiently discovers closed-form physical equations, consistently matching or outperforming static LLM-driven baselines and achieving state-of-the-art out-of-distribution performance.","published":"2026-07-11T05:32:54Z","updated":"2026-07-11T05:32:54Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.10127v1","pdf_url":"https://arxiv.org/pdf/2607.10127v1","comment":"ICML 2026, AI for Science Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.09839","versioned_id":"2607.09839v1","title":"Exploring Agentic Workflows for Generating High Quality Math Visual Aids","authors":["Rizwaan Malik","Ashna Khetan","Isabel Sieh","Samin Khan"],"abstract":"Mathematical diagrams play a crucial role in K 12 education, both as problem components and as scaffolding for student comprehension. However, current AI tools, including Large Language Models (LLMs), struggle to reliably generate accurate and pedagogically sound visual diagrams, even when provided with detailed descriptions. A significant gap therefore remains in the reliable generation of diagrams for middle school mathematics. To address this, we introduce an agentic workflow that enables LLM agents to evaluate the quality of generated visuals and use this feedback to iteratively improve their outputs. This self improvement loop aims to enhance the accuracy and educational appropriateness of AI generated diagrams. Our research investigates two questions. First, can LLMs accurately generate quality assurance questions for a visual aid given specific criteria for visual quality? Second, given valid quality assurance questions, can Vision Language Models effectively evaluate generated K 12 visual aids and use the resulting feedback to improve them iteratively? We conduct an exploratory evaluation of our agentic workflow and identify key areas for improvement, including stronger spatial reasoning and more comprehensive coverage of diagram features in the generated quality assurance questions. Our results provide preliminary evidence that this approach can improve the reliability and educational value of AI generated mathematical diagrams.","published":"2026-07-10T17:12:38Z","updated":"2026-07-10T17:12:38Z","categories":["cs.AI","cs.CV","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.09839v1","pdf_url":"https://arxiv.org/pdf/2607.09839v1","comment":"13 pages, 9 figures. Exploratory course project on agentic workflows for generating and evaluating K 12 mathematical diagrams","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.09544","versioned_id":"2607.09544v1","title":"The Count Is There, but Misaligned: Understanding and Correcting Counting Failures in VLMs","authors":["Ahmed Oumar El-Shangiti","Abzal Nurgazy","Hilal AlQuabeh","Nikolai Rozanov","Kentaro Inui"],"abstract":"Despite strong performance on many multimodal tasks, vision-language models (VLMs) still struggle with basic object counting. We investigate whether this reflects missing internal knowledge or a gap between internal representations and verbalized outputs. Training simple probes on activations from four VLMs across five counting datasets reveals that nonlinear probes can reliably detect counting errors, suggesting that VLMs often encode the correct count even when they output the wrong answer. SVCCA analysis shows that probes trained on ground-truth counts and probes trained on model outputs occupy a partially shared activation subspace but read out along misaligned directions. We further validate our findings using a causal steering intervention, proving that strengthening the direction of count-identified probes does improve model counting performance. Motivated by this result, we propose a detector-guided self-correction method that selectively re-prompts the model only when an internal error detector predicts failure. This simple inference-time intervention improves counting accuracy by up to 15.6 absolute percentage points, without any parameter updates. Our results establish activation-based error probing as both a practical tool for improving VLM counting and a mechanistic lens on the gap between internal knowledge and model outputs.","published":"2026-07-10T15:50:54Z","updated":"2026-07-10T15:50:54Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2607.09544v1","pdf_url":"https://arxiv.org/pdf/2607.09544v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.09803","versioned_id":"2607.09803v1","title":"Spectral Origins of the Self-Correction Blind Spot in Autoregressive Generation","authors":["Ingrid Petrova","Luan Vejsiu"],"abstract":"Large autoregressive language models exhibit a self-correction blind spot: they reliably fix identical errors when attributed to an external source yet fail to fix the same errors in their own outputs. Prior work has documented this phenomenon empirically, through controlled error injection, error-depth decompositions, RL-based verifier-corrector training, and intrinsic self-verification, but offers no formal model of why generating a token suppresses the ability to detect its error, no quantitative activation condition for correction markers, and no convergence guarantee for reinforcement-learning-based self-correction. We close these gaps with SPARC, a spectral-algebraic theory of self-correction in autoregressive generation. We define the error-propagation operator as the product of per-step attention Jacobians on the residual stream and prove that the blind spot arises if and only if the spectral radius of this operator is at least one. We derive a sharp activation threshold, given as a function of the spectral radius, that a correction marker must exceed, recovering the 89.3\\% blind-spot reduction observed with a simple ``Wait'' marker. We further prove that RL-based verifier-corrector training converges at a rate proportional to the squared coupling strength over the square root of the number of samples if and only if the verifier-corrector coupling matrix has spectral norm below one, and that this criterion is invariant across residual-stream autoregressive modalities, unifying text LLMs and autoregressive image and video generation. Experiments across four backbones and a visual autoregressive probe validate every theorem, with spectral predictions matching measured blind-spot rates within 3.2\\% RMSE.","published":"2026-07-09T17:52:16Z","updated":"2026-07-09T17:52:16Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.09803v1","pdf_url":"https://arxiv.org/pdf/2607.09803v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.08331","versioned_id":"2607.08331v1","title":"ArtMine: Discovering and Formalizing Artistic Processes","authors":["Kaustubh Kumar","Ashutosh Ranjan","Vivek Srivastava","Blessin Varkey","Shirish Karande"],"abstract":"Understanding how artworks are created requires reasoning about the iterative decisions, material operations, and contextual influences that shape artistic production. While recent generative AI systems can synthesize artworks with high fidelity, they primarily model distributions over finished artifacts rather than the creative processes underlying their creation. In practice, artistic workflows are only partially documented through fragmented sources such as archival records, preparatory studies, correspondence, etc., making process-level understanding difficult to formalize computationally. In this work, we introduce ArtMine, a framework for discovering and formalizing artistic processes from heterogeneous historical evidence. Our approach synthesizes heterogeneous artwork evidence into a structured repository, from which a Peircean abductive agent infers evidence-grounded production steps. These steps are converted into a compositional graph and rendering prompt, then optimized through self-reflection over deviations between the generated and reference artworks. We provide a preliminary proof-of-concept case study using open-domain historical sources across multiple artists and artistic movements, demonstrating that fragmented documentary evidence can support coherent, interpretable, and auditable representations of artistic workflows. By modeling creative processes rather than only final artifacts, our work moves toward process-centred human-AI co-creativity systems that can support artistic interpretation, creative education, reflective collaboration, and computational studies of cultural production.","published":"2026-07-09T10:16:53Z","updated":"2026-07-09T10:16:53Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.08331v1","pdf_url":"https://arxiv.org/pdf/2607.08331v1","comment":"47 pages, 10 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.08255","versioned_id":"2607.08255v1","title":"Compete Then Collaborate: Frontier AI Teachers Build a Verifiable Curriculum to Improve a Coding Student Beyond Imitation","authors":["Miseong Shawn Kim"],"abstract":"Large language models increasingly serve as teachers generating training data for smaller students. Prior multi-teacher knowledge distillation methods merge outputs without determining which frontier model teaches best, often relying on an LLM judge biased toward its own outputs. We introduce a compete-then-collaborate framework where four frontier AI teachers (Claude, Codex-GPT, Grok, Gemini) are ranked head-to-head by an execution-based judge (unit tests and stdin-stdout checks) with fairness controls, and then collaborate to build a verifiable curriculum for a student (Qwen2.5-Coder). We report three findings. (1) Under execution verification, all teachers solve standard problems near-perfectly after self-correction (99-100%) due to a saturation effect, but harder competition problems separate them (Gemini 77% > Claude 69% = Codex 69% > Grok 50%); however, the robust student-side results do not depend on teacher ranking. (2) Imitation (SFT) on verified solutions does not improve, and can degrade, an already-competent student at 7B and 32B (e.g., from 76.7% to 72.7% on MBPP-test, and 5.9% to 2.9% on competition problems). (3) Using the same collaborative curriculum as a reinforcement learning with verifiable rewards (RLVR) environment improves the student (from 5.9% to 8.8% peak on competition problems, a +49% relative gain), reversing SFT's direction. The value of AI-teacher collaboration lies not in pooling answers to imitate, but in jointly constructing a verifiable environment where the student learns by doing. We release a reproducible on-prem pipeline (NVIDIA GB10) with framework patches for running GRPO on a bleeding-edge stack.","published":"2026-07-09T09:00:52Z","updated":"2026-07-09T09:00:52Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.08255v1","pdf_url":"https://arxiv.org/pdf/2607.08255v1","comment":"8 pages, 1 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.07820","versioned_id":"2607.07820v2","title":"DeepSearch-World: Self-Distillation for Deep Search Agents in a Verifiable Environment","authors":["Xinyu Geng","Xuanhua He","Sixiang Chen","Yanjing Xiao","Fan Zhang","Shijue Huang","Haitao Mi","Zhenwen Liang","Tianqing Fang","Yi R. Fung"],"abstract":"Training tool-use agents to improve from their own experience remains challenging, as supervised fine-tuning relies on fixed teacher-distilled trajectories, while sparse-reward reinforcement learning provides weak supervision for long-horizon interactions. We present DeepSearch-Evolve, a self-distillation framework for web agents built on DeepSearch-World, a deterministic and verifiable environment with reproducible search and page-reading tools. DeepSearch-World contains 420K multi-hop QA tasks constructed from entity-level random walks and supports key agentic cognitive behaviors useful for self-evolving, including progress verification, grounded reflection, and failure recovery. DeepSearch-Evolve iteratively performs trajectory generation, filtering, data mixing, and fine-tuning to train stronger agents. Without distillation from more capable models, DeepSearch-World-9B achieves competitive performance compared with open-source agents, reaching 31.2% on BrowseComp, 61.5% on GAIA, and 93.4% on HotpotQA, showing that verifiable environments enable scalable self-evolution for long-horizon web agents. We will release the environment, 420K training pool, validation set, model, and code to facilitate future research on self-improving deep search agents.","published":"2026-07-08T18:03:41Z","updated":"2026-07-13T12:09:44Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.07820v2","pdf_url":"https://arxiv.org/pdf/2607.07820v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.07663","versioned_id":"2607.07663v1","title":"Recursive Self-Improvement in AI: From Bounded Self-Refinement to Autonomous Research Loops","authors":["Mingguang Chen","Licheng Wang","Bo Qu"],"abstract":"AI systems increasingly participate in their own improvement: revising their outputs, adapting their own harnesses during deployment, training on data they generate, and, increasingly, conducting AI research itself. This literature is described under a vocabulary (\"self-refine,\" \"self-reward,\" \"self-play,\" \"self-evolve\") that conflates fundamentally different ambitions. We survey 1,250 arXiv papers (2024-2026) along two axes: what the system improves -- its behavior in deployment, its policy through training, its evaluator, or the research process itself -- and the degree of loop closure (human-in-the-loop to fully closed). The taxonomy separates bounded self-refinement -- convergent, evaluable, and already industrial practice -- from open-ended recursive self-improvement (RSI), which remains bounded by grounding requirements, collapse dynamics, and compute constraints on every measured axis. Its distinctive feature is a dedicated category for self-evaluation: every improvement loop is a claim that some signal can substitute for human judgment. We survey the evaluator design space -- judges, process reward models, verifiers, rubrics, meta-evaluation -- order the signals into a verification hierarchy from formal verifiers (strongest) to intrinsic self-assessment (weakest), and observe that demonstrated self-improvement strength tracks this hierarchy, that its failure modes (self-confirming loops, model collapse, diversity collapse) follow from its violations, and that the \"research direction-setting\" bottleneck keeping humans in the loop sits at the top of that hierarchy. We connect the technical literature to the theory of RSI limits and to the safety and governance questions raised by frontier-lab accounts of closing the loop, and identify governance-grade measurement of self-improvement as the field's most underpopulated niche.","published":"2026-07-08T17:19:50Z","updated":"2026-07-08T17:19:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.07663v1","pdf_url":"https://arxiv.org/pdf/2607.07663v1","comment":"42 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.06974","versioned_id":"2607.06974v1","title":"MILES: Modular Instruction Memory with Learnable Selection for Self-Improving LLM Reasoning","authors":["Ruilin Tong","Dong Gong"],"abstract":"Large language models (LLMs) increasingly improve their reasoning at test time via additional computation, yet most existing works treat each problem in isolation. When problems arrive sequentially, accumulating reusable experience across them can further improve performance. Existing memory-based methods either store whole-solution templates that generalize poorly to novel problems or use heuristic step-level selection that is not optimized for final-answer correctness. Learning selection policies requires large-scale training data and fixed action spaces, making such approaches unsuitable for test-time settings where memory expands incrementally and only limited supervision is available. We propose MILES (Modular Instruction Memory with LEarnable Selection for self-improving LLM reasoning), a framework that dynamically expands step-wise memory and applies correctness-optimized memory composition under realistic test-time constraints. MILES maintains modular memory units consisting of asymmetric pairs of sub-goal embeddings and sub-instructions, each associated with a learnable selection head. This memory structure enables a coarse-to-fine retrieval mechanism: The coarse level enables memory expansion and collects supervision for training selection heads from confident samples, while the fine stage applies learned selection heads to rerank coarse-level candidates and guide reasoning for uncertain samples. MILES consistently matches or outperforms prior methods while achieving superior accuracy-efficiency tradeoffs. Extensive experiments demonstrate its effectiveness, robustness, and transferability.","published":"2026-07-08T03:51:37Z","updated":"2026-07-08T03:51:37Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.06974v1","pdf_url":"https://arxiv.org/pdf/2607.06974v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.06786","versioned_id":"2607.06786v1","title":"From Agentic to Autogenic Network Management for AI-Native 6G and Beyond: A Standards Perspective","authors":["Petar Djukic","Sudipta Acharya","Takai Eddine Kennouche","Burak Kantarci"],"abstract":"Standards bodies, including TM Forum, 3GPP, and ETSI, are converging on Agentic AI as the foundation for next-generation network management, where Large AI Model (LAM)-based agents autonomously interpret intent, coordinate resources, and adapt operational behaviors at runtime. However, achieving this vision at the scale and complexity of 6G networks requires management systems that can generate and evolve their own automation software during operation. We introduce Autogenic network management, a reference architecture that extends agentic capabilities with self-programming, self reflection, self-orienting, and self-architecting capabilities. The architecture supports practical staged deployment beginning with human-supervised LAM-based agents and progressing toward autonomous operation as confidence builds. We demonstrate the approach through high-priority operator scenarios drawn from TM Forum's autonomous network use cases, showing how autogenic management addresses real operational challenges. We conclude with a research roadmap outlining the technical advances needed to make autogenic network management realistic in future 6G networks.","published":"2026-07-07T20:34:05Z","updated":"2026-07-07T20:34:05Z","categories":["cs.NI","cs.AI"],"primary_category":"cs.NI","arxiv_url":"https://arxiv.org/abs/2607.06786v1","pdf_url":"https://arxiv.org/pdf/2607.06786v1","comment":"9 pages, 5 figures, Accepted to IEEE Network","journal_ref":"","doi":"10.1109/MNET.2026.3711903","discovered_on":"2026-07-17"},{"id":"2607.06720","versioned_id":"2607.06720v1","title":"When Does In-Context Search Help? A Sampling-Complexity Theory of Reflection-Driven Reasoning","authors":["Yotam Wolf","Noam Wies","Amnon Shashua"],"abstract":"Training large language models (LLMs) with extended reasoning has enabled in-context search, in which models iteratively generate, critique, and revise solution attempts. We provide a theoretical analysis of in-context search by modeling it as approximate inference over reasoning traces, where the base model defines a prior and self-reflection provides feedback for posterior updates, and study the resulting inference-time sampling complexity - the number of sequential attempts needed to achieve high success probability. We show that when reflections reliably localize early mistakes, in-context search can yield exponential improvements over the base model, solving problems with exponentially small zero-shot pass rates using only a polynomial number of sequential attempts, whereas when this property fails, conditioning on past attempts offers no asymptotic benefit over parallel sampling. We further show that these gains are robust and learnable: approximate posterior updates suffice, and cross-entropy training on search rollouts recovers the required behavior with polynomial sample complexity. Finally, we show that under a stagewise abstraction of reinforcement learning with verifiable rewards, the optimal policy extension implements the same posterior reweighting rule. We validate key qualitative predictions of the theory on real large reasoning models.","published":"2026-07-07T18:36:04Z","updated":"2026-07-07T18:36:04Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.06720v1","pdf_url":"https://arxiv.org/pdf/2607.06720v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.06452","versioned_id":"2607.06452v1","title":"From Voting to Agent Collaboration: Answer-Type-Aware LLM Pipelines for BioASQ 14b","authors":["Taeyun Roh","Eunha Lee","Wonjune Jang","Sohyun Chung","Junha Jung","Jaewoo Kang"],"abstract":"Biomedical question answering requires not only accurate extraction of information from scientific literature but also reliable integration of evidence across multiple documents. This study presents a question-type-specific large language model (LLM) framework for BioASQ 14b Task B, designed to improve answer robustness and evidence grounding in biomedical question answering. Rather than applying a single prompting strategy to all questions, the framework selects different inference procedures for yes/no, factoid, and list questions according to their distinct reasoning and evaluation requirements. For yes/no questions, snippet shuffling and self-reflection are used to reduce sensitivity to evidence ordering and improve decision stability. For factoid questions, full-snippet input is combined with chain-of-thought-based in-context learning to support accurate biomedical entity identification. For list questions, a multi-agent architecture is employed, in which evidence extraction, candidate generation, answer verification, and final aggregation are handled collaboratively. Preliminary experiments on BioASQ 13b were used to identify effective inference strategies for each question type, and the resulting framework was subsequently evaluated in the official BioASQ 14b Task B challenge. In the official evaluation, our framework showed competitive performance across multiple batches and achieved first place in the factoid subtask of Batch 4. These results demonstrate the effectiveness of combining question-type-specific inference, ensemble prediction, and agent-based verification for reliable biomedical question answering.","published":"2026-07-07T16:12:51Z","updated":"2026-07-07T16:12:51Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.06452v1","pdf_url":"https://arxiv.org/pdf/2607.06452v1","comment":"15 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.06074","versioned_id":"2607.06074v1","title":"Prompt Coach: An Empirical Evaluation of an Agentic Tutor for Learning Prompt Engineering in Software Development","authors":["Rohit Mehra","Kapil Singi","Vikrant Kaulgud","Vibhu Saujanya Sharma","Swapnajeet Gon Choudhury","Swati Sharma","Adam P. Burden","Majd Sakr"],"abstract":"Prompt engineering has emerged as a critical yet undertaught skill for software developers, one that traditional learning approaches are ill-equipped to support given its evolving, interactive, and context-dependent nature. In this paper, we introduce Prompt Coach (PC), an agentic tutor that helps developers learn how to craft high-quality code-generation prompts through Socratic guidance embedded in-flow within their IDE. PC evaluates prompt quality across multiple dimensions and surfaces targeted questions to guide self-correction, grounded in the developer's codebase and the behavior of the target LLM. We present an early empirical study with 15 professional developers combining quantitative prompt quality scoring with qualitative perception measures. Participants showed statistically significant improvements after a single 60-minute session, with the largest gains across dimensions commonly overlooked by developers. They also reported strong trust, high adoption readiness, and unanimous agreement that PC improved their prompt-writing skills.","published":"2026-07-07T09:44:46Z","updated":"2026-07-07T09:44:46Z","categories":["cs.SE","cs.AI","cs.CY","cs.HC"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.06074v1","pdf_url":"https://arxiv.org/pdf/2607.06074v1","comment":"7 pages. To be published in the proceedings of 41st International Conference on Automated Software Engineering (ASE '26), October 12-16, 2026, Munich, Germany (Industry Showcase Track)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.06609","versioned_id":"2607.06609v1","title":"D2PO: Optimizing Diffusion Samplers via Dynamic Preference","authors":["Jinkyu Kim","Jinyoung Choi","Bohyung Han"],"abstract":"We propose D2PO (Dynamic Direct Preference Optimization), a principled framework for optimizing diffusion sampling policies with respect to timestep schedules and classifier-free guidance (CFG) weights. Our work is motivated by a fundamental limitation of existing student-teacher regression frameworks; low-NFE student samplers are trained to mimic high-NFEteachers, often sacrificing high-frequency texture fidelity while preserving coarse global structures, thereby misaligning the sampler with perceptual quality. D2PO addresses this challenge by reformulating sampler optimization as a preference-based alignment problem, leveraging the Direct Preference Optimization (DPO) framework. To make DPO applicable to diffusion samplers, we model the sampling policy as an energy-based model (EBM), transforming preference comparisons into tractable energy differences. We further introduce a novel energy formulation derived directly from the pretrained score network, enabling preference evaluation in perturbed spaces that jointly capture structural consistency and fine-grained details. Moreover, we introduce dynamic preferences, where the preferred samples used for alignment progressively improve as the sampling policies are learned. This self-improving mechanism replaces rigid static teacher supervision with an iterative, preference-guided refinement process, providing progressively stronger alignment signals. Extensive experiments demonstrate that D2PO aligns diffusion samplers with perceptual quality more faithfully, unlocking the full potential of high-quality teachers and consistently outperforming conventional regression-based schedulers under low-NFE constraints.","published":"2026-07-07T06:05:42Z","updated":"2026-07-07T06:05:42Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.06609v1","pdf_url":"https://arxiv.org/pdf/2607.06609v1","comment":"Accepted to ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.05721","versioned_id":"2607.05721v1","title":"SpanUQ: Span-Level Uncertainty Quantification for Large Language Model Generation","authors":["Yimeng Zhang","Yingying Zhuang","Ziyi Wang","Yuxuan Lu","Pei Chen","Aman Gupta","Zhe Su","Ming Tan","Zhilin Zhang","Qun Liu","Manikandarajan Ramanathan","Rajashekar Maragoud","Edward Vul","Jing Huang","Dakuo Wang"],"abstract":"Uncertainty estimation is essential not only for the trustworthy deployment of large language models (LLMs) but also as a foundation for self-refinement in LLM generation. However, existing approaches operate at suboptimal granularities: token-level scores lack semantic coherence, while sequence-level scores fail to localize errors. We formalize Span-Level Uncertainty Estimation (SLUE), a new task that targets the natural granularity for uncertainty: semantically coherent text spans, each conveying a single assessable unit of meaning. To address this task, we introduce SPANUQ, a lightweight probe that distills the uncertainty knowledge from expensive multi-sample inference into a single forward pass over LLM hidden states. SPANUQ employs a DETR-style span decoder to simultaneously detect spans and estimate their uncertainty via a Mixture of Beta distribution, trained with a principled combination of Beta NLL regression and contrastive ranking objectives. We construct SPANUQ-BENCH, the first span-level uncertainty benchmark comprising 20K prompts, 293K annotated spans, and continuous soft labels derived from multi-sample claim verification. Experiments on five LLM backbones show that SPANUQ consistently achieves the best span-level uncertainty quality, outperforming the strongest probe baseline and all sampling-based methods while being 10-20x faster. Its DETR-based span detector attains 0.910 F1, surpassing the best heuristic by 39.4%, enabling precise error localization that sequence-level methods cannot provide. The framework generalizes across five LLMs spanning two model families.","published":"2026-07-07T01:09:46Z","updated":"2026-07-07T01:09:46Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.05721v1","pdf_url":"https://arxiv.org/pdf/2607.05721v1","comment":"The project page is available at https://damon-demon.github.io/SpanUQ.html","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.05382","versioned_id":"2607.05382v3","title":"Search Beyond What Can Be Taught: Evolving the Knowledge Boundary in Agentic Visual Generation","authors":["Haozhe Wang","Weijia Feng","Jinpeng Yu","Che Liu","Ping Nie","Fangzhen Lin","Jiaming Liu","Ruihua Huang","Jimmy Lin","Wenhu Chen","Cong Wei"],"abstract":"Visual generators excel at rendering, but they confidently fabricate what they do not know. User requests are unbounded, evolving, and deeply long-tailed: new characters, trending entities, post-cutoff events, and more. This world-knowledge bottleneck is structural: generators are trained on fixed corpora, but the visual world is open-ended. We construct SearchGen-20K and SearchGen-Bench, with 20,839 prompts spanning twelve failure categories and twenty-two domains, paired with a pre-executed multimodal SearchGen-Corpus-1M to support offline, reproducible research. On SearchGen-Bench, frontier open generators score only 21 to 28 out of 100, a 40-point collapse invisible to existing benchmarks. The natural remedy is to employ search tools, enabling agentic visual generation. However, we find that naive search fails: it retrieves indiscriminately, injecting noise into prompts the generator already handles. We trace the root cause to a generator-specific, evolving knowledge boundary: the divide between what a generator can internalize through training and what must remain in external context. Although this boundary is hard to specify in advance, we show that it is discoverable through a teach-then-search co-training framework. Even a minimal version of this co-training recipe produces monotonic improvement, laying the foundation for recursive self-improvement in visual generation that can meet world-knowledge-grounded requests. We release the full dataset, co-training corpus, and search corpus as a replayable harness for tool-augmented, world-knowledge-grounded visual generation.","published":"2026-07-06T17:56:12Z","updated":"2026-07-09T06:57:10Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2607.05382v3","pdf_url":"https://arxiv.org/pdf/2607.05382v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.05346","versioned_id":"2607.05346v1","title":"OptiAgent: End-to-End Optimization Modeling via Multi-Agent Iterative Refinement","authors":["Adriana Laurindo Monteiro","Nayse Fagundes","Gabriel Mattos Langeloh","Gustavo de Oliveira Kanno","Priscila Louise Aguirre","Thiago Costa Rizuti da Rocha","Victor Leme Beltran"],"abstract":"We propose OptiAgent, a multi-agent framework that, given a natural language description of an Operations Research problem, is able to output a solver-ready mathematical formulation as well as executable code. Our architecture prioritizes the mathematical modeling step, where dedicated agents extract structures, such as decision variables and constraints, enabling iterative self-correction. We introduce a novel multi-loop validation architecture with four specialized feedback mechanisms, each targeting a distinct failure mode such as misinterpretation, structural defects, mathematical inconsistencies, validation failures, and code errors. Alongside accuracy, our modular design improves the process of solving optimization problems by improving transparency, as each agent exposes its reasoning and feedback, making the full modeling process auditable. Our framework achieves state-of-the-art performance on 3 out of 4 benchmarks across LP, MILP, and Nonlinear Programming tasks, while remaining highly competitive on the remaining dataset.","published":"2026-07-06T17:27:16Z","updated":"2026-07-06T17:27:16Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.05346v1","pdf_url":"https://arxiv.org/pdf/2607.05346v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.05297","versioned_id":"2607.05297v1","title":"MetaSkill-Evolve: Recursive Self-Improvement of LLM Agents via Two-Timescale Meta-Skill Evolution","authors":["Zefeng Wang","Minxi Yan","Jinhe Bi","Sikuan Yan","Volker Tresp","Yunpu Ma"],"abstract":"Recent LLM agents tackle increasingly long-horizon, open-ended tasks, and external skills, reusable procedural knowledge supplied to the agent, further extend this capability. However, a fixed, hand-authored skill is rarely optimal, and cannot adapt to the diversity of tasks an agent encounters. Self-improving agents address this by rewriting their own skill files from execution traces, yielding meaningful gains on challenging benchmarks. Yet such self-evolution remains non-recursive: it improves only the task skill (what the agent does) while the improvement procedure (how it improves) is authored once and held fixed. We introduce MetaSkill-Evolve, a two-timescale framework that makes agentic skill improvement recursive: every branch carries both a task skill $s$ and a branch-local meta-skill $m=(ψ,σ,α,π,\\varepsilon)$ whose five components parameterise the Analyzer, Retriever, Allocator, Proposer, and Evolver agents of the improvement pipeline. Task skills evolve on a fast loop while the meta-skill evolves on a slower one under the same pipeline applied to itself, with no additional model or objective. With all five pipeline agents sharing a single frozen backbone, MetaSkill-Evolve outperforms no-skill, static-skill, and single-level evolution baselines on three agentic benchmarks (OfficeQA, SealQA, ALFWorld), improving held-out test accuracy over the raw backbone by +23.54, +16.09, and +1.92 points respectively.","published":"2026-07-06T16:40:23Z","updated":"2026-07-06T16:40:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.05297v1","pdf_url":"https://arxiv.org/pdf/2607.05297v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.05184","versioned_id":"2607.05184v1","title":"Rethinking On-Policy Self-Distillation for Thinking Models","authors":["Simran Kaur","Narutatsu Ri","Yinghui He","Liam Fowl","Sanjeev Arora"],"abstract":"Self-distillation is a promising recipe for self-improvement in language models. In this setting, a model can serve as its own teacher when given privileged information, such as a solution to a math problem. This seems especially appealing for thinking models, which can use test-time reasoning to absorb the privileged information. Surprisingly, we show that privileged self-distillation degrades thinking models on long reasoning traces: across five Qwen3 and OLMo thinking models evaluated on AIME24, AIME25, and HMMT25, privileged-context distillation causes a relative drop of up to 17% in avg@16 accuracy. The degradation scales with the amount of privileged context withheld from the student and is most pronounced at long rollout budgets, where thinking models otherwise obtain their largest gains. This failure mode is not specific to self-distillation: on-policy distillation (OPD) improves thinking models, but privileged OPD reverses these gains. Our diagnostics link this failure mode to how privileged teacher context reshapes learning at high-entropy forking positions, where multiple continuations remain plausible and may lead to different reasoning paths. Privileged context lowers fork rates in thinking-model rollouts but not in instruction-model rollouts. This leads to an interesting dichotomy, where privileged context can help instruction-tuned models but hurts stronger thinking models. The effect is visible when the student begins a self-correction branch, where privileged OPD penalizes sampled reconsideration tokens that vanilla OPD supports. Thinking models trained with a privileged teacher produce fewer verification, backtracking, and hedging markers, even after length normalization. These findings indicate that self-distillation for strong thinking models requires attention to token-level signal, especially around correction and reasoning steps.","published":"2026-07-06T15:01:35Z","updated":"2026-07-06T15:01:35Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.05184v1","pdf_url":"https://arxiv.org/pdf/2607.05184v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.11916","versioned_id":"2607.11916v1","title":"QDEvo: A Multi-Objective Quality-Diversity Framework for Automated Heuristic Design","authors":["Nam Do Khanh","Nhat Nguyen Tran Minh","Dat Pham Vu Tuan","Long Doan","Binh Huynh Thi Thanh"],"abstract":"The integration of Large Language Models (LLMs) with evolutionary computation has emerged as a powerful paradigm for automated heuristic design in combinatorial optimization. However, existing approaches suffer from mode collapse, converging to homogeneous populations that lack semantic diversity and fail to explore the full algorithmic space. We propose Quality-Diversity Evolution (QDEvo), a multi-objective framework that integrates Quality-Diversity optimization with LLM-driven heuristic search, maintaining an unbounded archive of semantically diverse algorithms using pre-trained code embeddings and incorporating hierarchical self-reflection to guide the evolutionary process. Extensive experiments across standard benchmarks and real-world industrial applications demonstrate that QDEvo significantly outperforms state-of-the-art methods in both Hypervolume and Inverted Generational Distance metrics. Our framework enables the discovery of heuristics that are simultaneously high-performing, computationally efficient, and semantically diverse, providing practitioners with a rich portfolio of solutions for complex optimization problems.","published":"2026-07-06T07:35:23Z","updated":"2026-07-06T07:35:23Z","categories":["cs.NE","cs.AI","cs.CL"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2607.11916v1","pdf_url":"https://arxiv.org/pdf/2607.11916v1","comment":"4 pages; Accepted as poster at GECCO 2026","journal_ref":"","doi":"10.1145/3795101.3805343","discovered_on":"2026-07-17"},{"id":"2607.04631","versioned_id":"2607.04631v1","title":"Formal Disco: Scalable Open-Ended Generation of Formally Verified Programs","authors":["Gabriel Poesia","Simon Henniger","Tzu-Han Hsu","Yilun Du","Nada Amin"],"abstract":"The cost of producing code is rapidly diminishing with increasingly capable AI agents, while quality assurance of generated programs has not kept pace. Formal verification provides the strongest possible guarantees, but the ability of AI models to work with verification-aware languages is hindered by the scarcity of human-written examples of programs in those languages. To tackle this prevalent data scarcity issue, we propose Formal Disco: a distributed system for coordination of LLM-based workers that can be easily applied to open-ended synthetic data generation at scale. We use Formal Disco to share tasks and programs between three classes of workers: \"initiators\", which read random READMEs from open-source repositories and documentation snippets to sketch a related verified program, \"fixers\" which take compiler and verifier feedback and attempt to resolve issues, and \"extenders\" that take working programs and propose patches to expand them. Formal Disco records all agent-generated traces and uses them both for initial distillation from a stronger model as well as self-improvement. We also propose a principle of maximum entropy for synthetic program generation, and use entropy maximization via iterative supervised fine-tuning to learn to generate increasingly diverse programs over time. We release large datasets of synthetic verified programs in three languages - Dafny, Verus, and Frama-C -, and fine-tune open models for verification-relevant tasks, often matching or exceeding the performance of Claude Opus 4.5. Overall, our work offers a path to create synthetic data at scale for formal reasoning domains and overcome the long-standing data barrier.","published":"2026-07-06T03:31:14Z","updated":"2026-07-06T03:31:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.04631v1","pdf_url":"https://arxiv.org/pdf/2607.04631v1","comment":"Code: https://github.com/metareflection/formal-disco Datasets: https://huggingface.co/collections/metareflection/formal-disco","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.04277","versioned_id":"2607.04277v1","title":"Self-Reference in Large Language Models: The Introspection Threshold for Recursive Self-Improvement","authors":["Jiang Zhang","Bing Yuan","Qian Zhang"],"abstract":"The pursuit of self-evolving AI raises a critical question: when is autonomous self-improvement sustainable rather than degenerative? Drawing an analogy to von Neumann's complexity threshold for self-reproducing automata, we argue that sustainable recursive self-improvement in Large Language Models (LLMs) requires a functional analogue: introspection -- the system's capacity to simulate its own operations and target modifications. Grounded in Kleene's Second Recursion Theorem, we demonstrate the theoretical existence of such introspective programs. However, an empirical review reveals that while current LLMs exhibit quasi-introspection (e.g., partial metacognition), they fall short of true introspection due to structural bottlenecks: a lack of complete self-access, the feedforward nature of the Transformer, and computational class constraints that prevent fixed-point iteration. We conclude by outlining architectural paths to cross this complexity threshold and discussing the associated safety implications.","published":"2026-07-05T12:40:52Z","updated":"2026-07-05T12:40:52Z","categories":["physics.soc-ph","cs.AI"],"primary_category":"physics.soc-ph","arxiv_url":"https://arxiv.org/abs/2607.04277v1","pdf_url":"https://arxiv.org/pdf/2607.04277v1","comment":"21 pages, 4 figures, 1 table","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.03770","versioned_id":"2607.03770v1","title":"Self-Improving Diffusion Classifiers with Minority Preference Optimization","authors":["Hyunsoo Kim","Jungmyung Wi","Soobin Um","Donghyun Kim","Suhyun Kim"],"abstract":"Prior studies have demonstrated that diffusion classifiers achieve robust zero-shot classification performance. However, their effectiveness is strongly tied to the pretraining data distribution: they perform well in majority, high-density regions of the data manifold, but are significantly less accurate in minority, low-density regions. Although prior works on minority sampling have focused on generating more minority-like images, what minority sampling fundamentally enables beyond generation remains underexplored. In this paper, we reveal a direct relationship between minority sampling in generation and the perception capability of diffusion classifiers. Specifically, we show that enhancing minority sampling broadens the coverage of underrepresented regions on the data manifold, thereby improving diffusion-based recognition. To exploit this connection, we propose \\textit{Self-Improving Diffusion Classifiers with Minority Preference Optimization} (MiPO), which fine-tunes a pretrained diffusion model using minority preference rewards. Using only arbitrary caption data, MiPO generates candidate samples, rewards those that better cover minority regions, and optimizes the model with LoRA and Group Relative Policy Optimization, without additional image data, external foundation models, or external reward models. This enables stable, prompt-adaptive minority sampling and translates low-density generative coverage into improved zero-shot diffusion classification. To sum up, we show that diffusion classifier perception is biased toward majority regions, demonstrate that this bias can be alleviated through minority preference optimization, and evaluate MiPO on five standard datasets.","published":"2026-07-04T08:42:08Z","updated":"2026-07-04T08:42:08Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2607.03770v1","pdf_url":"https://arxiv.org/pdf/2607.03770v1","comment":"ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.03726","versioned_id":"2607.03726v1","title":"SelfMem: Self-Optimizing Memory for AI Agents","authors":["Shu Yang","Junchao Wu","Derek F. Wong","Di Wang"],"abstract":"While current AI agents support increasingly long context windows, tool use, and skill execution for long-horizon tasks, they still require memory systems to effectively leverage historical experience. Existing memory frameworks typically rely on fixed storage, retrieval, and summarization mechanisms, which can be rigid across different tasks and often require manual tuning. To address this limitation, we propose SelfMem, a self-optimizing memory framework. Inspired by prior work on self-improving AI, we follow the principle of \"teaching an agent to fish rather than giving it a fish.\" Instead of forcing the model to follow a predefined memory strategy or format, SelfMem provides an environment with memory tools and feedback signals that allow the agent to explore, evaluate, and refine its own memory strategy. Our results show that SelfMem consistently outperforms retrieval, compression, and agent-memory baselines on BEAM across conversation scales from 100K to 1M tokens. Compared with the strongest baseline, SelfMem improves the official score by 48.7%, 40.8%, and 41.9% at 100K, 500K, and 1M, respectively. Further question-type analysis shows broad robustness across diverse memory demands, and our optimization study shows that model-guided strategy refinement further improves performance.","published":"2026-07-04T06:27:19Z","updated":"2026-07-04T06:27:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.03726v1","pdf_url":"https://arxiv.org/pdf/2607.03726v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.03449","versioned_id":"2607.03449v1","title":"HiMe: Hierarchical Embodied Memory for Long-Horizon Vision-Language-Action Control","authors":["Li Ji","Siyin Wang","Pengfang Qian","Xiaopeng Yu","Yihai Tian","Zhaoye Fei","Jingjing Gong","Xipeng Qiu"],"abstract":"Current Vision-Language-Action (VLA) models excel at robotic manipulation but often struggle with non-Markovian tasks requiring long-term memory and reasoning due to their reliance on immediate observations. Existing solutions face a ''frequency-competence paradox,'' where stronger reasoning models are too slow for real-time control, while faster models lack sufficient reasoning capabilities. To resolve this architectural misalignment, we propose HiMe, a Hierarchical Embodied Memory framework that decouples embodied intelligence into a high-frequency Executor for execution, a Sentry for working memory, and a Planner for long-term strategy. We also introduce a dynamic knowledge system based on cross-modal semantic schemas and active management mechanisms, allowing robots to maintain memory plasticity through ''Add, Update, and Delete'' operations. This hierarchical design effectively balances the conflict between real-time execution and slow thinking planning, significantly improving success rates in long-horizon tasks. Experiments demonstrate that this approach not only outperforms flat memory baselines but also exhibits the novel ability to self-correct its internal knowledge based on human preferences.","published":"2026-07-03T16:06:48Z","updated":"2026-07-03T16:06:48Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2607.03449v1","pdf_url":"https://arxiv.org/pdf/2607.03449v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.02869","versioned_id":"2607.02869v1","title":"Reward Granularity in RLVR: Comparing Process and Outcome Reward Structures for Mathematical Reasoning in Small Language Models","authors":["Anagha Radhakrishna Palandye","Rebecca Glick","Osheen Kaul"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) has emerged as a promising paradigm for improving mathematical reasoning in language models. Yet most RLVR work rewards only the final answer (outcome-based rewards), leaving the impact of step-level process supervision (process rewards) underexplored especially for small models that lack the capacity to self-correct under sparse feedback. We systematically compare five reward conditions applied to Qwen2.5-0.5B fine-tuned with Group Relative Policy Optimization (GRPO) on GSM8K: a no-RL baseline, process-only, outcome-only, and three hybrid weightings ($λ\\in \\{0.9, 0.5, 0.1\\}$ process weight). Process-only supervision achieves 63.73% test accuracy versus 53.75% for outcome-only, a nearly 10-percentage point gap while yielding reasoning traces with higher step validity and lower deviation from ground-truth chain length. Hybrid rewards generally correlate positively with process weight, with one notable anomaly: the low-process / high-outcome configuration ($λ=0.1$) underperforms pure outcome supervision, suggesting conflicting optimization signals. Error analysis using GPT-4o as a judge reveals distinct failure mode distributions: process models generate structurally inconsistent but arithmetically grounded traces, while outcome models produce concise but derivation-error-prone chains. Our results demonstrate that reward granularity is a first-order design decision for RLVR, with process-level supervision substantially improving both accuracy and trace fidelity in small language models.","published":"2026-07-03T02:16:06Z","updated":"2026-07-03T02:16:06Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.02869v1","pdf_url":"https://arxiv.org/pdf/2607.02869v1","comment":"8 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.02490","versioned_id":"2607.02490v1","title":"Visually Grounded Self-Reflection for Vision-Language Models via Reinforcement Learning","authors":["Liyan Tang","Fangcong Yin","Greg Durrett"],"abstract":"Large vision-language models can reason over multimodal inputs by generating textual chains of thought (CoT). A key capability exhibited in CoT reasoning is self-reflection: revisiting earlier decisions and correcting previous errors. However, existing LVLMs often fail to properly attend to visual inputs during reflection, limiting their ability to translate feedback into grounded corrections, especially for out-of-distribution images. To address this issue, we propose a novel reinforcement learning training framework VRRL, with two components explicitly designed to elicit visually grounded self-reflection. First, we randomly mask trajectory prefixes during training to emphasize recovery from incorrect intermediate predictions rather than making early mistakes. Second, we introduce buffered roll-ins from an experience replay buffer to expose the model to diverse failure states that it must learn to correct. We evaluate our approach on visual grounding tasks involving tables and charts, as well as spatial navigation benchmarks. While off-the-shelf and conventionally fine-tuned models degrade substantially under distribution shift, our method substantially improves average out-of-distribution accuracy over standard RL and reflection-oriented fine-tuning baselines by using self-reflection effectively.","published":"2026-07-02T17:53:15Z","updated":"2026-07-02T17:53:15Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.02490v1","pdf_url":"https://arxiv.org/pdf/2607.02490v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.01480","versioned_id":"2607.01480v1","title":"Procedural Memory Distillation: Online Reflection for Self-Improving Language Models","authors":["Ye Liu","Srijan Bansal","Bo Pang","Yang Li","Zeyu Leo Liu","Yifei Ming","Zixuan Ke","Shafiq Joty","Semih Yavuz"],"abstract":"Reinforcement learning with verifiable rewards (RLVR), along with recent selfdistillation variants such as SDPO, evaluates each rollout against a verifier and updates the policy from that episode-level signal. However, the richer procedural information in the rollout is rarely retained or reused. Across episodes and epochs, the model repeatedly encounters related problems under a changing policy, producing cross-episode signals that episode-local updates cannot capture: which strategies consistently pass verification, which failure modes persist, which patterns recur. We propose Procedural Memory Distillation (PMD), which converts these crossepisode signals into reusable procedural memory and distills it into the policy's weights during training. This memory functions as a training scaffold, absorbed into the policy itself, yielding a memory-free model at inference. PMD organizes the memory at three levels of abstraction: raw trajectories, self-reflected strategies and lessons, and higher-level behavioral patterns that recur across problems, all extracted online from the model's own trajectories. A memory-conditioned self-teacher draws on the accumulated experience to supervise the student on its own rollouts, enabling student to progressively internalize procedural knowledge within its parameters. The central design principle is co-evolution: the policy generates rollouts that update the memory, and memory shapes the supervision that updates the policy. Empirically, across Qwen3-8B and OLMo3-Instruct-7B, PMD improves over SDPO by 3.8-5.5% on SCIKNOWEVAL and 7.9-13.6% on LIVECODEBENCH. Co-evolution powers these gains: freezing either the memory or the policy trails PMD by more than 10% across SCIKNOWEVAL domains.","published":"2026-07-01T21:20:57Z","updated":"2026-07-01T21:20:57Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.01480v1","pdf_url":"https://arxiv.org/pdf/2607.01480v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.02089","versioned_id":"2607.02089v1","title":"ESC: Emotional Self-Correction for Reliable Vision-Language Models","authors":["Tien-Huy Nguyen","Minh-Nhat Nguyen","Nguyen Nhat Huy","Hung Viet Nguyen","Huy Nguyen Minh Nhat","Thanh-Huy Nguyen","Cuong Tuan Nguyen","Hoang M. Le","Dat Nguyen","Phat Kim Huynh","Min Xu","Ulas Bagci"],"abstract":"Vision-language models (VLMs) have achieved strong performance across diverse multimodal tasks, yet they remain vulnerable to unreliable reasoning. Existing self-correction methods mitigate these issues but typically rely on post-training or carefully engineered feedback, incurring high computational cost. In this work, we revisit this challenge through the lens of emotional cues, asking whether they can activate latent self-correction behaviors in VLMs without additional training. \\textbf{We find that emotional signals serve as an effective trigger for self-correction, encouraging more cautious and reflective reasoning}. Motivated by this finding, we propose \\escabstract (\\textbf{\\underline{E}}motional \\textbf{\\underline{S}}elf-\\textbf{\\underline{C}}orrection), a training-free self-correction framework. ESC introduces an external verifier that detects potentially incorrect initial responses and injects emotional feedback to encourage model to reflect, and produce a better revised response without additional training. Extensive experiments across safety, hallucination, vision-centric perception, and multimodal reasoning benchmarks show that ESC consistently improves reliability while preserving overall model utility. These results suggest that emotion can function not only as an ability to be recognized, but also as a practical control signal for scalable self-correction in VLMs. \\textbf{We therefore believe that ESC provides a strong foundation for a new reliable human-like, emotion-integrated research direction.} Our project is publicly available at \\textcolor{red}{https://genai4e.github.io/ESC/}.","published":"2026-07-01T14:25:43Z","updated":"2026-07-01T14:25:43Z","categories":["cs.CV","cs.AI","cs.CL","cs.LG","cs.MM"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2607.02089v1","pdf_url":"https://arxiv.org/pdf/2607.02089v1","comment":"ECCV Main Track 2026 (113 pages, 15 tables, 65 figures). Project Page: https://genai4e.github.io/ESC/?","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.00531","versioned_id":"2607.00531v1","title":"Active-GRPO: Adaptive Imitation and Self-Improving Reasoning for Molecular Optimization","authors":["Xuefeng Liu","Mingxuan Cao","Qinan Huang","Thomas Brettin","Rick Stevens","Le Cong"],"abstract":"Scientific reasoning is an increasingly important capability of large language models, yet improving the robustness and efficiency of training such reasoning remains a key open challenge. We study this problem in instruction-based molecular optimization, where answer-only supervised fine-tuning (SFT) collapses multi-step reasoning and reinforcement learning with verifiable rewards (RLVR) suffers from sparse feedback. Reference-guided Policy Optimization mitigates both by anchoring policy updates to dataset-provided references, but its effectiveness is tightly coupled to reference quality: weak or misaligned references impose a performance ceiling. To overcome this ceiling, we propose active reasoning, a paradigm in which the policy actively decides, on a per-instance basis, when to imitate a reference and when to reinforce its own discoveries, while continuously upgrading what it imitates. We instantiate this paradigm as Active Group Relative Policy Optimization (Active-GRPO), realized through two coupled mechanisms: active imitate-reinforce and active referencing. The former performs imitation learning when the reference still outperforms the policy's own candidates, and shifts to self-improvement via reinforcement learning once the policy has generated molecules that surpass the reference. The latter continuously upgrades the reference itself by replacing it with the best policy-generated candidate discovered so far, progressively raising the imitation target and ensuring that reference guidance remains informative-rather than restrictive-throughout training. Across TOMG-Bench MOLOPT, Active-GRPO improves average SRxSim from 0.0959 for GRPO and 0.1665 for RePO to 0.1773 under matched three-seed evaluation, with statistically significant gains on LogP, MR, and QED.","published":"2026-07-01T07:22:46Z","updated":"2026-07-01T07:22:46Z","categories":["cs.LG","cs.AI","q-bio.BM","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.00531v1","pdf_url":"https://arxiv.org/pdf/2607.00531v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.00482","versioned_id":"2607.00482v1","title":"Know When to Stop: Segment-Level Credit Assignment for Reducing Overthinking","authors":["Chia-Hsuan Lee","Sihui Dai","Mingyang Zhou","Isha Slavin","Shi-Xiong Zhang","Sambit Sahu","William Campbell"],"abstract":"Reasoning language models frequently overthink: generating extended chains of behaviors such as hedging, approach abandonment, and self contradiction that consume tokens without improving answers. We show that these behaviors are not merely a consequence of length; even when controlling for response length, incorrect traces exhibit higher rates of unproductive self-reflection than correct ones. Addressing this requires identifying where self-reflection helps vs hurts, but obtaining these step-level annotations is costly. We observe that intermediate answer commitments within reasoning traces can provide a cheap proxy: by comparing each final answer candidate in the trace to the ground truth, we can determine whether subsequent reflection is productive without any additional supervision. Building on this insight, we propose DASH (Drift Aware advantage SHaping), which assigns segment-level credit based on whether each reasoning segment leads toward or away from correctness. On competition-level math benchmarks, DASH achieves the highest accuracy where overthinking is prevalent (AIME25: 50.8% vs. 45.4% GRPO) while reducing overthinking behaviors and achieving more productive self-correction than baselines.","published":"2026-07-01T06:09:56Z","updated":"2026-07-01T06:09:56Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.00482v1","pdf_url":"https://arxiv.org/pdf/2607.00482v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.31524","versioned_id":"2606.31524v1","title":"On the Convergence of Self-Improving Online LLM Alignment","authors":["Xudong Wu","Pangpang Liu","Vaneet Aggarwal","Jiayu Chen"],"abstract":"The Self-Improving Alignment (SAIL) algorithm addresses distribution shift by reducing a bilevel formulation of the problem to an efficient, single-level method. Empirically, SAIL has demonstrated strong performance on this task. However, a formal analysis of its convergence properties has been lacking. We identify a key theoretical challenge: the standard SAIL objective function is not guaranteed to be strongly concave due to unfavorable properties of its Hessian. To address this limitation, we propose a regularized objective, SAIL-RevKL, which incorporates a reverse Kullback-Leibler (KL) divergence penalty to improve the optimization landscape. Our central theoretical contribution is to prove that this regularized objective satisfies the Polyak-Lojasiewicz (PL) condition within a bounded parameter space. We establish global convergence guarantees, achieving a near-linear sample complexity. We further validate the effectiveness and stability of SAIL-RevKL through empirical evaluations, demonstrating that it outperforms the vanilla SAIL on both MuJoCo benchmarks and LLM alignment tasks.","published":"2026-06-30T11:36:41Z","updated":"2026-06-30T11:36:41Z","categories":["cs.LG","cs.AI","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.31524v1","pdf_url":"https://arxiv.org/pdf/2606.31524v1","comment":"Accepted at UAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.31478","versioned_id":"2606.31478v1","title":"One Reflection Is Not Enough: Self-Correcting Autonomous Research via Multi-Hypothesis Failure Attribution","authors":["Jie Ma","Binfei Chu","Jie Gao","Jinlu Zhang","Yiwei Ma","Yi Tan","Jiayi Ji","Xiaoshuai Sun","Rongrong Ji"],"abstract":"Autonomous research agents can now draft hypotheses, write code, run experiments, and produce papers, but they remain brittle when experiments fail. Under the prevailing paradigm, failure recovery is usually delegated to a single free-form reflection: a rich trajectory of metrics, logs, and design choices is compressed into one verbal critique, which often leads either to localized trial-and-error or to hard pivots that discard useful context. We propose SAGE, a Self-correcting, Autonomous, Grounded Experimenter, to tackle this failure-recovery bottleneck. Its core mechanism, Multi-Hypothesis Failure Attribution (MHFA), treats recovery as a structured causal diagnosis. By analyzing dynamic trajectory features, MHFA systematically generates multiple evidence-grounded explanations for a failure, independently evaluates their severity, and deterministically routes the verified root cause to the correct intervention level (hypothesis, experimental design, or implementation). To guarantee scientific honesty, SAGE further employs a grounded reporting mechanism that explicitly constrains drafted results to actual measured values, redacting hallucinated numbers. On a 12-topic, 5-domain benchmark, SAGE increases metrics-bearing outputs from 42% to 92% over a reflection baseline, improves artifact quality from 5.00 to 6.75/10, and blindly outscores AI-Scientist-v2 (52.0 vs. 48.2), with gains concentrated in code development and execution. While fully autonomous scientific writing and generating conference-ready papers remain notoriously difficult open problems for the entire field, SAGE successfully produces significantly more reliable and higher-quality scientific artifacts. Ultimately, by coupling structured recovery with explicit grounding constraints, SAGE significantly outperforms monolithic reflection paradigms, establishing a highly trustworthy foundation for future autonomous research.","published":"2026-06-30T10:54:16Z","updated":"2026-06-30T10:54:16Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.31478v1","pdf_url":"https://arxiv.org/pdf/2606.31478v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.31422","versioned_id":"2606.31422v2","title":"Ask the World Before Acting: Environment Probing for Calibrated Agent World Models","authors":["Xinyuan Song","Zekun Cai"],"abstract":"Language agents acting over long horizons must maintain beliefs about tool states, object locations, graph edges, and subgoal dependencies. When these beliefs drift, failures can be fixed neither by longer reasoning traces nor by ordinary self-reflection, since the missing evidence lies in the environment. We formulate environment probing as a budgeted decision problem for structured agent world models: before acting, the agent may query the current value of one belief field, update its table, and pay one interaction step. We introduce EnvProbe, a simple scoring policy that combines task criticality, staleness, verbalized uncertainty, and dependency role. A type-stratified analysis separates the benefit of belief repair from the cost of displaced task actions and predicts different behavior for procedural and spatial beliefs. In three controlled environments with gold belief states, EnvProbe improves terminal world-state accuracy over periodic probing by 11.76 percentage points on procedural tool-dependency tasks, 3.79 points on spatial tasks, and 6.45 points overall. Ablations show that task-structural terms are the main source of the gains, while self-reported uncertainty is unreliable under confident wrong beliefs. The results suggest that agent calibration should be treated as an action-selection problem over environment evidence, not only as a model-internal reasoning problem.","published":"2026-06-30T09:45:49Z","updated":"2026-07-05T04:18:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.31422v2","pdf_url":"https://arxiv.org/pdf/2606.31422v2","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.31270","versioned_id":"2606.31270v1","title":"Learning from Failure: Inference-Time Self-Improvement for Computer-Use Agents","authors":["Xueqiao Sun","Xiaohan Wang","Ludwig Schmidt","Serena Yeung-Levy","Yuhui Zhang"],"abstract":"Computer-use agents, which leverage multimodal large language models (MLLMs) to operate computers and complete tasks, have attracted significant attention for their utility and versatility. A major challenge in developing these agents is collecting large-scale, high-quality trajectories. The standard approach generates synthetic data through a self-improving loop: an agent is placed in a verifiable environment and iteratively fine-tuned on its successful trajectories. Despite its effectiveness, this paradigm exploits only successful trajectories and discards the failed ones, even though failures carry rich information about a model's weaknesses. In this work, we explore a complementary failure-driven self-improvement loop, a data-centric paradigm that turns failed trajectories into agent improvements. Specifically, we employ an LLM to diagnose failure modes, propose inference-time solutions, and generate code patches -- lightly verified by humans -- that upgrade the agent. We validate this approach with the state-of-the-art OpenCUA-72B model on the OSWorld benchmark, improving the success rate from 42.3% to 48.9%, a gain of 6.6 percentage points, without any additional training cost and with only modest inference overhead. Our results demonstrate that failure-driven self-improvement is a viable complement to success-based pipelines, enabling more efficient agent improvement.","published":"2026-06-30T07:44:37Z","updated":"2026-06-30T07:44:37Z","categories":["cs.CV","cs.AI","cs.CL","cs.CY","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.31270v1","pdf_url":"https://arxiv.org/pdf/2606.31270v1","comment":"Published in ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.31200","versioned_id":"2606.31200v1","title":"Agentic RAG-VLM: Affordance-Aware Retrieval-Augmented Generation with Self-Reflective Planning for Robotic Grasping","authors":["Tao Chen","Lizheng Liu","Jiaxu Wang","Ziyue Jiang","Ruiqi Tian","JiGuang Huo","Zhongxue Gan"],"abstract":"Generalizable robotic grasping in cluttered environments is essential for deploying manipulators in unstructured human spaces, yet existing VLM-based methods rely on visual similarity for object matching, neglecting physical affordances such as handle graspability and material fragility, and operate open-loop without spatial reasoning or failure recovery, limiting their effectiveness when objects are densely packed or physically diverse. We present Agentic RAG-VLM, a unified framework that bridges VLM-based semantic understanding and physically grounded grasp execution by integrating retrieval-augmented generation (RAG) with vision-language models (VLMs) and agentic self-reflective planning. Agentic RAG-VLM introduces three tightly coupled components: (1) a Hierarchical Affordance-Aware RAG (HAA-RAG) that encodes four-dimensional affordance descriptors, including type, material, fragility, and graspable region, and retrieves strategies by functional affordance compatibility rather than visual appearance; (2) a Scene Graph Constraint Reasoner that constructs spatial relationship graphs from VLM perception and translates proximity, occlusion, and support constraints into concrete grasp parameter adjustments; and (3) an Agentic Self-Reflective Pipeline with a 14-type failure taxonomy and three-level adaptive retry for closed-loop grasp refinement. Evaluated on a 12-task benchmark spanning single-grasp, interactive, and long-horizon scenarios with 360 trials per configuration, Agentic RAG-VLM achieves 78.3 percent overall success, a 53.3 percentage-point absolute gain over VLM-only baselines, demonstrating that affordance-aware retrieval, scene graph reasoning, and agentic recovery are jointly essential for robust manipulation.","published":"2026-06-30T06:30:22Z","updated":"2026-06-30T06:30:22Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.31200v1","pdf_url":"https://arxiv.org/pdf/2606.31200v1","comment":"8 pages,5 figures,5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.31191","versioned_id":"2606.31191v3","title":"ISM:Self-Improving Strategy Memory for Continual Mathematical Reasoning","authors":["Prakhar Dixit","Tim Oates"],"abstract":"We propose Intelligent Schema Memory (ISM), a self-evolving memory-augmented system that improves mathematical reasoning for a frozen LLM under continual learning with hard episodic resets. ISM maintains a compact, self-refined bank of strategy schemas learned from both successful and failed episodes, with symbolic tools that check intermediate steps and certify answers. Without updating model parameters, ISM outperforms passive, retrieval, and reflection baselines on MATH-Hard and OlympiadBench, using 64% and 86% fewer schemas respectively than the strongest passive baseline. These results show that small, actively maintained, and verified strategy memories can support reliable continual mathematical reasoning under strict episodic isolation. The codebase is available at https://github.com/pdx97/ISM .","published":"2026-06-30T06:21:08Z","updated":"2026-07-02T03:46:54Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.31191v3","pdf_url":"https://arxiv.org/pdf/2606.31191v3","comment":"3rd AI for Math Workshop at ICML 2026 Forty-Third International Conference on Machine Learning","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.30774","versioned_id":"2606.30774v1","title":"What Drives Interactive Improvement from Feedback?","authors":["Bartłomiej Cupiał","Jan Łojek","Mikołaj Garstecki","Szymon Pobłocki","Alicja Ziarko","Piotr Miłoś"],"abstract":"We study when natural-language feedback produces improvement beyond the gains obtainable from repeated attempts alone. In multi-turn language agent setting, higher final accuracy can reflect useful feedback, but it can also arise from resampling, format correction, or additional test-time computation. To separate these effects, we introduce a controlled student-teacher protocol across Omni-MATH, Codeforces, BBEH Linguini, and ARC-AGI1, evaluating thirteen open-weight models in both student and teacher roles. We compare external feedback, self-feedback, and unguided self-refinement, while varying interaction history, task difficulty, and teacher access to privileged task information. Across settings, we find that multi-turn improvement is often not evidence of feedback use: self-generated feedback adds little beyond unguided self-refinement, whereas the strongest external teachers produce substantially larger feedback-specific gains, suggesting that useful feedback must provide guidance beyond generic retry. Dense student-teacher interaction matrices further show that interactive gains are driven more by the student's ability to use feedback than by the teacher's identity, although teacher choice remains important for a fixed student. These results suggest that feedback-based agents should be evaluated against repeated-attempt baselines, and that ability to act on feedback, not merely feedback availability, is a central bottleneck for interactive improvement. We release our controlled student-teacher evaluation framework at https://j-lojek.github.io/feedback-generation-is-a-bottleneck/.","published":"2026-06-29T18:06:36Z","updated":"2026-06-29T18:06:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.30774v1","pdf_url":"https://arxiv.org/pdf/2606.30774v1","comment":"9 pages, 7 figures, accepted to the RLxF Workshop at ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.30423","versioned_id":"2606.30423v1","title":"Proofs of Ownership for Machine Learning Models","authors":["Ran Canetti","Shafi Goldwasser","Or Zamir"],"abstract":"With the increasing adoption of Machine Learning, protecting model ownership has become an essential challenge. We initiate a formal study of Proof of Ownership for machine learning models: under what conditions can one prove that a stolen model originated from a particular creator? We model proofs of ownership as a game among three parties: a model owner, a thief, and a judge. The owner transforms the original model into a slightly perturbed model together with a proof of ownership. The thief then obtains the transformed model and attempts to minimally modify it so that it remains useful but escapes detection as owned by the model owner. Finally, the judge receives a model and a proof of ownership, and must decide whether the given model is a modified version of some model created by the model owner, or else the given model was developed independently. Our main result is a dichotomy for classifiers in the black-box setting: Under standard cryptographic assumptions, ownership of models for some concept class can be proven in the above sense {\\em if and only if} the concept class is not self-correctable, in a sense close to that of Blum, Luby and Rubinfeld, STOC'90. The result is constructive and extends, with some variations, to a number of related settings.","published":"2026-06-29T15:07:00Z","updated":"2026-06-29T15:07:00Z","categories":["cs.LG","cs.CR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.30423v1","pdf_url":"https://arxiv.org/pdf/2606.30423v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.30345","versioned_id":"2606.30345v1","title":"DRIFT: Difficulty Routing Self-DIstillation with Rhythm-Gated Exploration and Success BuFfer Training","authors":["Haisen Luo","Yiwei Liu","Haoning Wang","Dan Liu","Junxi Yin","Haotian Wang","Lei Zhang","Xiaoyu Tian","Shuaiting Chen","Yuansheng Song","Baoyan Guo","Xiongfei Yan","Bolan Yang","Chengwei Liu","Ming Cui","Jiong Chen"],"abstract":"Enabling large language models to achieve stable self-improvement without external expert supervision remains a central challenge in complex reasoning tasks. Existing self-distillation and reinforcement learning methods lack explicit mechanisms for tracking problem-level learning progress and adapting optimization strategies accordingly. Consequently, training may over-optimize easy problems, receive weak supervision from hard problems, and fail to sufficiently explore borderline cases. To resolve these issues, we propose DRIFT, an online self-evolution policy optimization framework for large language models. DRIFT regulates the model's self-improvement process through the joint use of Difficulty Routing and Rhythm Gating. The former identifies the model's learning state at the problem level and dynamically allocates self-distillation and reinforcement learning signals, while the latter refines policy updates at the token level, concentrating exploration on critical reasoning positions. By further incorporating a success buffer and a two-stage curriculum learning strategy, DRIFT preserves high-quality historical experience while progressively guiding the model from reliable behavior acquisition toward stable policy evolution. Evaluated across five benchmarks and three model scales, DRIFT surpasses the peak performance of both GRPO and SDPO across all evaluated metrics. On the average score over the five benchmarks, DRIFT achieves 79.5$\\%$, outperforming GRPO by 9.5$\\%$ and SDPO by 7.5$\\%$, establishing a new state-of-the-art result. Notably, on ToolUse, DRIFT reaches an accuracy of 79.2$\\%$, improving over GRPO by 13.5$\\%$ and SDPO by 10.7$\\%$, setting a new state-of-the-art and substantially outperforming all concurrent methods.","published":"2026-06-29T14:20:47Z","updated":"2026-06-29T14:20:47Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.30345v1","pdf_url":"https://arxiv.org/pdf/2606.30345v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.29999","versioned_id":"2606.29999v1","title":"AlgoSkill: Learning to Design Algorithms by Scheduling Human-Like Skills","authors":["Xinyuan Song","Zekun Cai","Liang Zhao"],"abstract":"Designing an algorithm from a natural-language problem statement requires identifying the problem structure, reading constraints, choosing a suitable paradigm, checking correctness, and refining complexity. Existing large language model (LLM) methods often rely on direct generation or generic self-refinement, leaving these steps implicit. We propose AlgoSkill, which models algorithm design as sequential decision-making over a typed library of algorithmic skills, including abstraction, constraint analysis, state design, data-structure selection, proof checking, counterexample construction, and complexity refinement. A learned scheduler proposes skills from the current design state, while a Monte Carlo Tree Search (MCTS) controller explores skill sequences using verification feedback from compilation, testing, stress testing, and complexity analysis. Experiments on competitive programming and combinatorial optimization benchmarks show that AlgoSkill improves over direct LLM generation, chain-of-thought prompting, self-refinement, and MCTS without typed skills. Ablations show that typed skills, verification-based repair, and search-based scheduling each contribute to performance. These results support treating automatic algorithm design as verification-guided skill scheduling rather than one-shot code generation.","published":"2026-06-29T09:09:16Z","updated":"2026-06-29T09:09:16Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.29999v1","pdf_url":"https://arxiv.org/pdf/2606.29999v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.29938","versioned_id":"2606.29938v1","title":"LatentRevise: Learning from Zero-Hit Reasoning","authors":["Yiqiu Guo","Xueting Han","Qi Jia","Guangtao Zhai","Jing Bai"],"abstract":"Reinforcement learning with verifiable rewards (RLVR) is bottlenecked by hard prompts on which correct trajectories have low probability, so sampling misses them within a practical budget and leaves the policy update with little useful signal. We frame such zero-hit prompts as RLVR's sampling frontier, where new reasoning behavior is most valuable yet least likely to be sampled. Importantly, failed rollouts can be informative: they expose where the model's reasoning went wrong. We introduce LatentRevise, a first-order latent revision method that recovers training signal for this zero-hit regime. Given a failed rollout and the gold answer as an anchor, LatentRevise optimizes the input embeddings of its reasoning prefix under two complementary gradients, moving the prefix away from the failed continuation and toward the gold answer. The optimization is constrained to the convex hull of the model's vocabulary embeddings, so each update moves the latent toward a real token embedding rather than an arbitrary feature direction. We find that continuations from the revised prefix lengthen, exhibit self-reflection, and reach correct answers missed by the original rollouts. Used as training data, these trajectories improve SFT and RLVR on math benchmarks over standard baselines.","published":"2026-06-29T08:14:47Z","updated":"2026-06-29T08:14:47Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.29938v1","pdf_url":"https://arxiv.org/pdf/2606.29938v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.29823","versioned_id":"2606.29823v1","title":"Experience Graphs: The Data Foundation for Self-Improving Agents","authors":["Gang Liao","Yujia He","Abdullah Ozturk","Zhouyang Li","Ying Wang","Zhitong Guo","Hongsen Qin","Yaobin Qin","Tao Yang","Zewei Jiang","Dianshi Li","Jort Gemmeke","Jiangyuan Li","Liyuan Li","Nathan Yan","Masha Basmanova","Uladzimir Pashkevich","Matt Steiner","Pedro Pedreira","Rob Fergus","Anirudh Goyal","Carole-Jean Wu","Gaoxiang Liu","Andrew Witten","Daniel J. Abadi"],"abstract":"The database community has repeatedly advanced the state of the art by recognizing that new workloads demand new system architectures. We argue that long-horizon agentic tasks -- code generation, scientific discovery, hardware design -- are such a workload. These agents explore: they generate artifacts, execute tools, observe failures, branch, and repair over hundreds of steps. This search produces a structured object we call an experience graph: executable artifacts, tool outputs, rewards, sibling comparisons, and causal lineage. Yet existing agent frameworks treat this experience as disposable state -- JSON checkpoints and session logs that cannot be recovered after a crash, queried across users, or materialized into training data. We propose Trellis: a data foundation that treats the experience graph as first-class, governed, queryable database state. The core insight is that search over experience graphs is a database access pattern. Frontier selection is a query, cross-session reuse is vector-seeded graph retrieval, training-data extraction is a materialized view, and reconstructing what an agent knew at any past step is a time-travel query. When the database owns the experience graph, agents become stateless compute, and crash recovery, horizontal scaling, and a closed-loop training flywheel emerge as architectural byproducts. We ground the design in KernelEvolve, a production accelerator-kernel optimizer at Meta, where cross-session reuse reaches a target speedup roughly 10x faster at 52% lower token cost. More broadly, Trellis turns inference-time search from disposable computation into a durable institutional asset: logs made databases reliable; experience graphs may make agents cumulative.","published":"2026-06-29T06:02:20Z","updated":"2026-06-29T06:02:20Z","categories":["cs.DB","cs.AI","cs.MA"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2606.29823v1","pdf_url":"https://arxiv.org/pdf/2606.29823v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.29733","versioned_id":"2606.29733v1","title":"How Far Do On-Prem Open LLMs Get on Text-to-SQL? A Cross-Family Size x Technique Frontier on BIRD","authors":["Vladimir Beskorovainyi"],"abstract":"Organizations that cannot send data to a cloud API increasingly ask: how good is Text-to-SQL if the model must run on-premises on open weights, and which popular accuracy \"recipes\" are worth their compute? We answer with an honest, fully reproducible benchmark on the BIRD development split (n=1534, Execution Accuracy), evaluating three open model families across two generations -- Qwen2.5-Coder (7B/14B/32B), CodeLlama-Instruct (7B/13B/34B), and Llama-3.x (8B, 70B) -- under one matched protocol, ablating a model-agnostic recipe (schema linking, self-correction, self-consistency) component by component, with every difference tested by the paired McNemar test. Four findings stand out. (i) Generation matters more than raw size, and the recipe is family-robust: Qwen2.5-Coder dominates the older CodeLlama at matched size (39.1 vs 20.9 at 7B), but a modern non-Qwen model (Llama-3.3-70B, 49.2 on a matched serving) is competitive, so CodeLlama's weakness reflects its 2023 generation, not \"non-Qwen = weak\". (ii) Self-correction is a robust, near-free win, significant on all three families where there is room to improve. (iii) Schema linking does not help, and a stronger linker does not rescue it: a retrieval/embedding linker with 96.5% gold-table recall is statistically indistinguishable from no linking, ruling out the \"weak lexical strawman\" objection across three families. (iv) Self-consistency is poor value (+0.13 pp for ~5x tokens, not significant). We report real per-stage cost ($/1k queries) and release all code, predictions, and summaries; archived code and data: https://doi.org/10.5281/zenodo.20952794","published":"2026-06-29T03:15:38Z","updated":"2026-06-29T03:15:38Z","categories":["cs.CL","cs.DB","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.29733v1","pdf_url":"https://arxiv.org/pdf/2606.29733v1","comment":"9 pages, 4 figures, 3 tables. Code: https://github.com/beskvladimir-create/nl2sql-onprem-bench Data DOI: https://doi.org/10.5281/zenodo.20952794","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.29713","versioned_id":"2606.29713v1","title":"SEVA: Self-Evolving Verification Agent with Process Reward for Fact Attribution","authors":["Aojie Yuan","Yi Nian","Haiyue Zhang","Zijian Su","Yue Zhao"],"abstract":"Hallucination is the reliability bottleneck for LLM-based agents, and fact attribution verifiers are the last line of defense -- yet today's verifiers emit only opaque binary labels, leaving agents unable to self-correct and operators unable to audit. We present SEVA, a structured verification agent that emits evidence alignments, step-by-step reasoning chains, calibrated confidence, and a six-category error diagnosis with actionable fixes. Training such an agent with RL is non-trivial: standard binary reward on multi-component output triggers advantage collapse -- within-group reward variance vanishes and the GRPO gradient disappears. We resolve this with a process reward that decomposes verification quality into five independent components weighted 70/30 toward process signals, restoring the gradient and inducing an implicit curriculum -- the agent first masters verification behavior (alignment 0.917 -> 0.997, format 72% -> 100%), then outcomes (F1 64.9 -> 69.0). Structured output further enables a Verify -> Reflect -> Probe -> Refine self-evolution loop, which over four rounds on a 7B model surfaces an unexpected structural finding: each round produces a benchmark-specialist, not a generalist (+15 pp on HaluEval, -10 to -14 pp on TruthfulQA in the same model, persistent at 4x data). On ClearFacts, SEVA-3B matches GPT-4o-mini (69.0 vs. 69.8 F1) while producing substantially richer, auditable output -- confirming a principle that should generalize: for any RL task with multi-component generation, reward granularity must match output granularity.","published":"2026-06-29T02:37:13Z","updated":"2026-06-29T02:37:13Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.29713v1","pdf_url":"https://arxiv.org/pdf/2606.29713v1","comment":"Accepted at AI4GOOD@ICML 2026 and FAGEN@ICML 2026. Code: https://github.com/Justin0504/Verifiable_agent","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.29315","versioned_id":"2606.29315v1","title":"Hierarchical Experimentalist Agents","authors":["Abhranil Chandra","Sankaran Vaidyanathan","Utsav Dhanuka","Varun Gandhi","Scott Niekum"],"abstract":"Large language models (LLMs) are increasingly used to take actions in the real world and support human decision-making, yet most agents rely on parametric knowledge, fixed post-training data, retrieval, or search. This paradigm breaks down in novel domains and for sophisticated queries that cannot be answered from prior knowledge alone. Knowing the laws of physics, for instance, does not by itself enable LLMs to answer queries or complete long-horizon tasks in a complex physical system. To address this, we introduce Hierarchical Experimentalist Agents (HExA), an in-context self-improvement framework to learn from active experimentation. HExA iteratively designs and refines query-relevant experiments, learns a reusable library of composable skills from experience, and integrates experimental evidence to answer queries or take actions. HExA is training-free, compatible with any black-box model, and does not require external supervision, oracles, or offline data. To evaluate active experimentation, we introduce Interphyre, a tool-calling benchmark built on the PHYRE 2D procedural physics environment, where agents propose interventions and test hypotheses through simulation APIs. Experiments show that current LLM agents struggle in these settings, especially on the hardest levels of Interphyre. Claude Sonnet 4.6 achieves only 2% success, while HExA improves the same model to up to 77% success. HExA also improves open-weight models and outperforms agentic baselines such as ReAct and Reflexion. Moreover, using only skills learned from easier levels and transferred without active experimentation, HExA achieves 44% success, demonstrating the reusability and generalization of its learned skills. Overall, HExA shows that learning through active experimentation can help agents discover useful knowledge, acquire reusable skills, and make efficient progress on novel long-horizon tasks.","published":"2026-06-28T10:21:55Z","updated":"2026-06-28T10:21:55Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.29315v1","pdf_url":"https://arxiv.org/pdf/2606.29315v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.29150","versioned_id":"2606.29150v1","title":"Flow Reasoning Models: Scaling Reasoning Through Iterative Self-Refinement","authors":["Alec Helbling","Andrey Bryutkin","Mauro Martino","Nima Dehmamy","Hendrik Strobelt"],"abstract":"Discrete flow models have recently shown promising performance on few-step text generation; however, when naively applied to structured reasoning tasks such as Sudoku and Zebra puzzles, they converge confidently to incorrect answers (solving only $\\sim$36% of Sudoku puzzles). We introduce Flow Reasoning Models (FRMs), a training and test-time-scaling framework for structured reasoning with flow models. We make the observation that, despite their poor solve rate, flow models can act as their own verifiers. A correct answer is a stable fixed point of the denoising dynamics, returning to itself when re-noised and re-solved. This enables a test-time-scaling paradigm: propose many candidate solutions and keep those that are dynamically stable, which alone reaches high solve rates on Sudoku-Shah (~$100\\%$) and Zebra ($95.9\\%$). This even generalizes to harder out-of-distribution puzzles like Sudoku-Extreme ($96.1\\%$), without ever training on that distribution. This pure search, however, wastes a great deal of computation generating incorrect candidate solutions. We therefore design a training recipe to improve the base model's efficiency. First, we train flow models with a self-conditioning channel and close it at inference, letting them refine their own past predictions. Second, we train models to avoid their own failed generations using direct preference optimization. These changes substantially improve the base model's efficiency, letting it reach $99.2\\%$ on Sudoku in just $7$ forward passes, over $8\\times$ fewer than the strongest matched masked-diffusion baseline we compare needs for the same accuracy. When combined with test-time scaling, this lets flow models solve hard out-of-distribution puzzles (e.g. Sudoku-Extreme) far more efficiently.","published":"2026-06-28T02:10:36Z","updated":"2026-06-28T02:10:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.29150v1","pdf_url":"https://arxiv.org/pdf/2606.29150v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.28939","versioned_id":"2606.28939v1","title":"ReGuide: From Test-Time Guidance to Self-Improving Diffusion Policies","authors":["Tzu-Hsiang Lin","Srinivas Shakkottai","Dileep Kalathil","P. R. Kumar"],"abstract":"Behavior-cloned diffusion policies are expressive but remain vulnerable to covariate shift: small deviations from demonstrated states can compound into task failure. Existing methods address this either by expanding the training distribution through expert corrections or synthetic augmentation, or by steering a frozen policy at test time with guidance from a learned model. The former can be expensive or assumption-dependent, while the latter discards the corrected trajectories after execution. We introduce ReGuide, a self-improving framework that treats guided rollouts as reusable on-policy recovery data. ReGuide first uses Phase-Conditioned Guidance (PCG) to generate corrective rollouts: it constructs phase-specific latent targets, applies guidance only in the drifted-but-recoverable regime, and guides through the estimated clean action to match the dynamics model's training distribution. Successful guided rollouts are then absorbed back into the policy through ReGuide-FT, which fine-tunes the current checkpoint, or ReGuide-FS, which retrains from scratch on the augmented dataset; the two can also be composed and iterated. On Robomimic Can, Square, Transport, and Tool Hang, ReGuide improves base-policy success by $1.3$--$7.7\\times$, outperforms LPB in the test-time-only setting, and matched-data ablations show that the gains come from guided recovery data rather than additional rollouts alone.","published":"2026-06-27T14:23:21Z","updated":"2026-06-27T14:23:21Z","categories":["cs.LG","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.28939v1","pdf_url":"https://arxiv.org/pdf/2606.28939v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.28570","versioned_id":"2606.28570v1","title":"Digitizing Coaching Intelligence: An Agentic Framework for Holistic Athlete Profiling using VLM and RAG","authors":["Deep Ghosal","Ishani Sen","Wazib Ansar","Amlan Chakrabarti"],"abstract":"Athlete assessment is a critical process for tracking physical progress and identifying elite talent. However, during mass recruitment drives, traditional methods rely on manual observation, which is inherently subjective and unscalable, or basic computer vision (CV) systems limited to quantitative repetition counting. These standard approaches lack the \"coaching intelligence\" required to evaluate qualitative physiological markers such as form degradation, spinal articulation, and fatigue. This paper presents a novel, LLM-based hybrid agentic framework for automated, holistic athlete profiling that strictly aligns with the Sports Authority of India (SAI) assessment protocols. Orchestrated via LangGraph, our dual-pipeline architecture synthesizes the geometric precision of CV (MediaPipe) for kinematic tracking with the semantic reasoning of Vision-Language Models (Llama-4-scout). To overcome the latency and token constraints associated with multimodal video processing, we introduce a 3 X 3 \"Smart Grid\" temporal chunking strategy, reducing computational overhead by over 88% while preserving critical temporal continuity. To ensure data integrity and mitigate hallucination, the framework pioneers an autonomous \"LLM-as-a-Judge\" self-correction loop that cross-references quantitative and qualitative metrics before persistence. Finally, we implement a dual-persistence Retrieval-Augmented Generation (RAG) pipeline utilizing a vector search engine (ChromaDB). This enables coaches to bypass rigid SQL databases and perform complex semantic queries (e.g., \"Identify athletes with high endurance but poor core rigidity\") using natural language. Experimental results demonstrate that this multi-agent approach significantly bridges the gap between raw biometric tracking and actionable coaching insights, offering a scalable, objective solution for national talent identification.","published":"2026-06-26T19:53:26Z","updated":"2026-06-26T19:53:26Z","categories":["cs.CV","cs.AI","cs.MA"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.28570v1","pdf_url":"https://arxiv.org/pdf/2606.28570v1","comment":"16 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.27922","versioned_id":"2606.27922v3","title":"Reflect-R1: Evidence-Driven Reflection for Self-Correction in Long Video Understanding","authors":["Shuimu Chen","Yuteng Chen","Yuanshen Guan","Zebang Cheng","Zeyu Zhang","Shengqian Qin","Bin Xia","Jiaran Li","Wenming Yang","Fei Ma"],"abstract":"Current multimodal reflection mechanisms for long video understanding predominantly rely on closed-loop self-reflection within internal parameters. Lacking objective external evidence, models are frequently trapped in blind confidence and often fail to correct errors. Furthermore, applying reinforcement learning to multi-stage reflection pipelines introduces severe policy coupling, which is exacerbated by a critical scarcity of dedicated training data. To address these limitations, this work proposes Reflect-R1, the first Evidence-Driven self-correction framework for long video understanding. The framework constructs a three-stage pipeline consisting of intuition, verification, and arbitration. By dynamically retrieving objective visual evidence to verify initial intuitions and autonomously executing multiple temporal searches to resolve conflicts, it completely breaks the hallucination loop. To overcome policy coupling, we design a stage-decoupled reinforcement learning algorithm named SD-GRPO that independently computes advantage functions across different reasoning stages. Concurrently, we construct a dataset of 120K samples to bridge the training data gap. Extensive experiments on benchmarks such as VideoMME and LongVideoBench demonstrate that Reflect-R1 achieves state-of-the-art performance. Our method significantly improves the genuine rectification rate and enables authentic self-correction strictly grounded in objective evidence.","published":"2026-06-26T10:15:36Z","updated":"2026-06-30T06:57:21Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.27922v3","pdf_url":"https://arxiv.org/pdf/2606.27922v3","comment":"2026 ECCV","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.27757","versioned_id":"2606.27757v1","title":"Towards Reliable and Robust LLM Planning: Symbolic Feedback-Driven Iterative Self-Refinement Framework","authors":["Jiajing Zhang","Jiamei Jiang","Chenyang Zhang","Feifei Mo","Linjing Li","Daniel Zeng"],"abstract":"Large language models (LLMs) have attracted widespread attention from academia and industry, yet their deployment raises critical security concerns regarding robustness and reliability. Planning, a core component of intelligent behavior, remains challenging for LLMs, which often produce infeasible or incorrect solutions in long-horizon decision-making tasks due to inherent complexity. In this paper, we propose a symbolic feedback-driven iterative self-refinement framework to enhance the robustness and reliability of LLMs in long-horizon planning. Specifically, a natural language prompting mechanism is introduced to map logical symbols into natural language descriptions, enabling LLMs to better capture task constraints and semantics. We further design a symbolic verifier that identifies errors and converts them into corrective instructions interpretable by the LLM, thereby guiding self-refinement. In addition, we leverage a plan recognizer to infer goal reachability, facilitating more effective guidance toward desired goals. Empirical results demonstrate that the proposed framework consistently improves both feasibility and correctness in long-horizon planning tasks. This highlights its effectiveness in enhancing the reliability of LLM-based planning and potential to enable more trustworthy AI systems.","published":"2026-06-26T06:24:33Z","updated":"2026-06-26T06:24:33Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.27757v1","pdf_url":"https://arxiv.org/pdf/2606.27757v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.27492","versioned_id":"2606.27492v1","title":"QueenBee Planner: Skill-Evolving Communication Topologies for Token-Efficient LLM Multi-Agent Systems","authors":["Congjia Tian","Yuhang Yao","Jiaming Cui"],"abstract":"Large language model (LLM) multi-agent systems increasingly depend not only on how individual agents reason, but also on how agents are connected. This paper introduces QueenBee Planner, a framework that treats inter-agent communication topology as a retrievable and self-improving design skill. A pool of worker agents, the task adapter, and the scoring function are frozen; only an outer LLM planner learns to generate temporal communication DAGs specifying who sends information to whom, in which round, who merges messages, and who emits the final answer. Execution traces are distilled into evidence-backed design rules with three actions: \\emph{Preserve}, \\emph{Modify}, and \\emph{Avoid}. To prevent self-evolution from turning lucky runs or plausible but false explanations into policy, QueenBee uses held-out acceptance gates, variance-aware credit, motif-level attribution, transfer trust, insight falsification, and structural deduplication. We evaluate the method on Count-Frequency aggregation and Silo-Bench-style distributed coordination tasks. With fixed workers, self-evolved graph generation produces communication structures that improve over fixed topologies and cold generation. In the CF fulltest setting, the best generated graph reduces RMSE from 12.53 for the strongest fixed topology to 7.87 while also reducing messages, model calls, and token cost; Silo-style results show the same direction of improvement over cold and fixed-topology baselines. These results suggest that multi-agent systems can learn reusable architectural design knowledge rather than merely memorizing task answers.","published":"2026-06-25T19:16:51Z","updated":"2026-06-25T19:16:51Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2606.27492v1","pdf_url":"https://arxiv.org/pdf/2606.27492v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.27359","versioned_id":"2606.27359v1","title":"When are likely answers right? On Sequence Probability and Correctness in LLMs","authors":["Johannes Zenn","Jonas Geiping"],"abstract":"Many decoding methods for large language models can be understood as shifting probability mass toward outputs that are more likely under the model, either locally at the token level or globally at the sequence level. Therefore, their success depends on a fundamental question: when does sequence probability, that is, the conditional probability of a continuation given a prompt, actually align with correctness? In this paper, we set out to quantify this relationship across decoding methods, models, and benchmarks at four levels: across decoding methods, across hyperparameters within a method, across prompt-answer pairs within a dataset, and across repeated responses to the same prompt. We find that higher sequence probability is often predictive of correctness across prompt-answer pairs within a fixed dataset. However, this relationship does not generally transfer to decoding decisions: increasing sequence probability by changing hyperparameters or methods does not reliably improve accuracy. Further, sequence probability is not a good indicator of correctness for responses to the same prompt. These findings clarify when decoding can and cannot be expected to improve correctness, and provide practical guidance for decoding, self-consistency, and verifier-free self-improvement.","published":"2026-06-25T17:58:02Z","updated":"2026-06-25T17:58:02Z","categories":["stat.ML","cs.LG"],"primary_category":"stat.ML","arxiv_url":"https://arxiv.org/abs/2606.27359v1","pdf_url":"https://arxiv.org/pdf/2606.27359v1","comment":"38 pages, including 10 pages of main text and 28 pages of appendix, preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.27226","versioned_id":"2606.27226v1","title":"Ask, Don't Judge: Binary Questions for Interpretable LLM Evaluation and Self-Improvement","authors":["Sangwoo Cho","Kushal Chawla","Pengshan Cai","Zefang Liu","Chenyang Zhu","Shi-Xiong Zhang","Sambit Sahu"],"abstract":"Evaluating LLM outputs remains a major bottleneck in NLP: human evaluation is expensive and slow, lexical metrics correlate poorly with human judgments on open-ended generation, and holistic LLM judges often produce opaque scores that are hard to debug. We propose BINEVAL, a framework that decomposes evaluation criteria into atomic binary questions and aggregates the resulting verdicts into interpretable, multi-dimensional scores. Given a task prompt, a meta-prompt generates fine-grained evaluation questions, and an LLM answers them independently for each output, yielding transparent question-level feedback together with calibrated overall scores. This decomposition makes evaluation easier to inspect, easier to diagnose, and directly usable for prompt improvement. Across SummEval, Topical-Chat, and QAGS, BINEVAL matches or outperforms strong baselines including UniEval and G-Eval, with especially strong results on factual consistency benchmarks such as QAGS. Beyond competitive correlation with human judgments, BINEVAL better matches human score distributions and avoids the ceiling effects common in prior LLM judges, leading to better discrimination between borderline and clearly flawed outputs. We further show that the same question-level feedback supports iterative prompt optimization, improving evaluator prompts on summarization and generation prompts on IFBench under both self-update and cross-model update settings. Overall, BINEVAL provides a task-agnostic, training-free, and interpretable evaluation framework that combines strong empirical performance with practical diagnostic and optimization value.","published":"2026-06-25T16:14:50Z","updated":"2026-06-25T16:14:50Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.27226v1","pdf_url":"https://arxiv.org/pdf/2606.27226v1","comment":"Acceepted to the Second Workshop on Compositional Learning at ICML 2026, Seoul, South Korea","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.27147","versioned_id":"2606.27147v1","title":"Safe Autoregressive Image Generation with Iterative Self-Improving Codebooks","authors":["Yunqi Xue","Zhijiang Li","Philip Torr","Jindong Gu"],"abstract":"Unlike diffusion-based models that operate in continuous latent spaces, autoregressive unified multimodal models produce images by sequentially predicting discretized visual tokens. These tokens are derived from a codebook that maps embeddings to quantized visual patterns. The language-like architecture enables unified multimodal models to effectively capture text conditional information for generation, making them promising for text-to-image tasks. This also raises an interesting question: how safe are the images generated in such an autoregressive way? In this work, we propose iterative self-improving codebooks for safe autoregressive generation. We leverage the understanding and judgment capabilities of the unified multimodal model itself to identify unsafe generated images without human annotation. Subsequently, the inherent representations in the codebook are fixed to eliminate harmful mappings. Our method comprises two steps: first, we use the unified model to identify unsafe generations and construct corresponding harmful and safe image-text pairs. These pairs are used to construct the Harmful Space and guide updates to the codebook, thereby eliminating harmful outputs. Second, we perform adaptive fine-tuning on the codebook within the harmless space using safe image-text pairs to ensure the quality of generated images. These two steps are repeated until no further improvement is observed, producing a safety-enhanced model codebook. Without additional external feedback, the safety of models is improved iteratively.","published":"2026-06-25T15:18:31Z","updated":"2026-06-25T15:18:31Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.27147v1","pdf_url":"https://arxiv.org/pdf/2606.27147v1","comment":"10 pages including references, 8 figures, accepted for publication at the 43rd International Conference on Machine Learning (ICML 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.26859","versioned_id":"2606.26859v2","title":"AgentX: Towards Agent-Driven Self-Iteration of Industrial Recommender Systems","authors":["Changxin Lao","Fei Pan","Guozhuang Ma","Han Li","Huihuang Lin","Jijun Shi","Kangzhi Zhao","Kun Gai","Mo Zhou","Qinqin Zhou","Quan Chen","Ruochen Yang","Shifu Bie","Shijie Yi","Shuang Yang","Shuo Yang","Wenhao Li","Wentao Xie","Xiao Lv","Xuming Wang","Yijun Wang","Yiming Chen","Yusheng Huang","Zhongyuan Wang","Zibo Zhao","Zijie Zhuang","Baoning Xia","Chao Liu","Chaoyi Ma","Chubo He","Dawei Cong","Feng Jiang","Gang Wang","Guilin Xia","Hanwen Xu","Jiahong Xie","Jiahui Qiao","Jian Liang","Jiangfan Yue","Jing Wang","Jinghan Yang","Jinghui Jia","Kan Qin","Lei Wang","Ming Li","Peilin Song","Pengbo Xu","Qiang Luo","Ruiming Tang","Shiyang Liu","Shuxian Jin","Tao Wang","Tao Zhang","Xiang Gao","Xianghan Li","Yingsong Luo","Yiwen Ning","Yongcheng Liu","Yueyang Liu","Yuan Guo","Zhaojie Liu","Zhenkai Cui"],"abstract":"Recommendation algorithm iteration is moving from an artisanal, engineer-bound process toward an industrialized research loop, but this transition remains blocked by a structural execution bottleneck: the idea-to-launch cycle still depends on human engineers to generate hypotheses, modify production code, launch A/B experiments, and attribute online results. Innovation therefore scales linearly with headcount rather than compounding with evidence, compute, and accumulated experimental knowledge. We present AgentX, a production-deployed multi-agent system that fundamentally restructures this production function. AgentX operates as a self-evolving development engine: it autonomously generates, implements, evaluates, and learns from recommendation experiments at a scale and pace that no manual workflow can sustain. The system orchestrates four tightly coupled stages in a closed loop. A Brainstorm Agent synthesizes evidence from historical experiments, system architecture, data analysis, and external research into ranked, executable proposals. A Developing Agent translates each proposal into production-ready code through repository-grounded generation and multi-dimensional reliability verification. An Evaluation Agent conducts safe online rollout with guardrail-vetoed A/B judgment, converting both successes and failures into structured knowledge assets. A Harness Evolution layer (SGPO) then distills execution trajectories into semantic-gradient updates that continuously sharpen the agents themselves -- making the system not merely automated, but self-improving.","published":"2026-06-25T10:42:28Z","updated":"2026-06-26T10:04:52Z","categories":["cs.AI","cs.CL","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.26859v2","pdf_url":"https://arxiv.org/pdf/2606.26859v2","comment":"Authors are listed alphabetically by their first name","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.26728","versioned_id":"2606.26728v1","title":"Scientific discovery as meta-optimization: a combinatorial optimization case study","authors":["Yuan-Hang Zhang","Chesson Sipling","Massimiliano Di Ventra"],"abstract":"Scientific discovery is fundamentally an optimization problem, defined by a vast \"state space\" of theories and experiments, and an evaluation criterion based on quality, novelty, and validity. Large language models (LLMs) have enabled automated exploration of this space, but we argue that simultaneous modification of the evaluation criteria is equally important. Here, we propose formalizing research as meta-optimization, where the optimization objective itself is also being optimized. Our key contribution is \"consensus objective aggregation,\" where LLM-generated objective functions are combined via correlation-weighted voting, yielding a stable, self-correcting evaluation criterion that evolves as understanding deepens. We apply this framework to algorithm discovery for 3-SAT problems based on digital MemComputing machines, reducing the baseline scaling with problem size $N$ from $\\sim N^{2.51}$ to $\\sim N^{1.33}$ and delivering a $\\sim 67\\times$ speedup on the largest instances tested. As a problem-agnostic framework, we hope this approach will considerably aid scientific discovery.","published":"2026-06-25T08:11:48Z","updated":"2026-06-25T08:11:48Z","categories":["cs.AI","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.26728v1","pdf_url":"https://arxiv.org/pdf/2606.26728v1","comment":"35 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.26722","versioned_id":"2606.26722v1","title":"Socratic agents for autonomous scientific discovery in high-dimensional physical systems","authors":["Xianrui Zeng","Pengfei Liu","Yirui Zang","Yang Shen","Fei Yu","Chunlei Yu","Minghao Liu","Yang Du"],"abstract":"The automation of scientific discovery has reached an inflection point. While AI systems now operate instruments, optimize parameters and generate hypotheses, most remain procedural: they execute workflows fixed by human designers. True autonomous science demands epistemic autonomy--the capacity to construct, challenge and revise physical explanations in response to evidence. Here we introduce AHOIS, a multi-agent AI scientist that embeds Socratic midwifery into closed-loop experimentation. A physics-critic agent interrogates hypotheses through causal questioning, constraint checking, counterexample generation and falsification-criteria formulation. We evaluate AHOIS on a real multimode-fibre optical platform, a high-dimensional system with complex wave transformations, indirect detection, environmental drift and multi-modal acquisition. Without prior encoding schemes, classifiers or speckle models, the system autonomously proposed and validated a random-interference encoding hypothesis, discovered task-adaptive sparse-measurement strategies, diagnosed distinct failure modes (encoding instability, fluorescence contamination and detector noise) and translated a published imaging protocol into an executable workflow on a non-original configuration. The discovered encoding yielded 16x16 measurements with effective rank 56.9 and classification accuracies of 76.97% on MNIST and 83.17% on Fashion-MNIST. Ablations show that Socratic interrogation improves physical consistency, hypothesis completeness, uncertainty calibration and experimental-plan validity. These results establish a route from workflow automation towards evidence-grounded, self-correcting autonomous discovery in complex physical environments.","published":"2026-06-25T08:01:07Z","updated":"2026-06-25T08:01:07Z","categories":["cs.AI","physics.optics"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.26722v1","pdf_url":"https://arxiv.org/pdf/2606.26722v1","comment":"27 pages,5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.26660","versioned_id":"2606.26660v1","title":"Generating Special Triangulations with Transformers","authors":["Charles Arnal","Jacky H. T. Yip","François Charton","Gary Shiu"],"abstract":"Triangulations, i.e., well-structured decompositions of geometric objects into triangle-like pieces, are central objects in many domains of mathematics and physics. In particular, fine, regular, and star triangulations (FRSTs) of 4D reflexive polytopes give rise to smooth Calabi-Yau threefolds, which are of significant interest in string theory. However, the high dimensionality and combinatorial complexity of triangulations make them particularly challenging to model with classical numerical methods or machine learning. In this work, we show that transformers, equipped with an appropriate encoding scheme, can be effectively trained to representatively generate new FRSTs across a range of polytope sizes. Moreover, these models can also self-improve through retraining on their own output. This opens the door to both concrete applications to the classification of Calabi-Yau manifolds and further research in physics, combinatorics and algebraic geometry.","published":"2026-06-25T06:47:39Z","updated":"2026-06-25T06:47:39Z","categories":["hep-th","cs.LG","math.AG"],"primary_category":"hep-th","arxiv_url":"https://arxiv.org/abs/2606.26660v1","pdf_url":"https://arxiv.org/pdf/2606.26660v1","comment":"21 pages, 11 figures. Contribution to the edited volume \"Recent Progress in Computational String Geometry\" (World Scientific), based on the BIRS-CMI workshop (26w5653)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.26552","versioned_id":"2606.26552v1","title":"Perception, Verdict, and Evolution: Hindsight-Driven Self-Refining Forensics Agent for AI-Generated Image Detection","authors":["Yangjun Wu","Keyu Yan","Yu Liu","Jingren Zhou","Fei Huang","Rong Zhang","Zhou Zhao","Fei Wu"],"abstract":"The rapid advancement of generative models presents a significant challenge to existing deepfake detection methods, particularly given the widespread dissemination of highly realistic AI-generated images. Although Multimodal Large Language Models (MLLMs) show strong potential for this task, existing approaches suffer from two key limitations: insufficient sensitivity to fine-grained forensic artifacts and reliance on static synthetic supervision from frontier models, leading to limited flexibility and high-cost. To address these issues, we propose ForeAgent, an agentic forensics framework for AI-generated image detection with iterative self-evolution. First, ForeAgent adopts a Perception-Verdict architecture that aggregates multi-view cues spanning semantic, spatial, and frequency-domain features, and leverages an MLLM as a verdict module to fuse these signals for a logical-grounded verdict. Second, to enable continual self-improvement, we introduce a Hindsight-Driven Self-Refining strategy following a Sampling-Reflection-Evolution paradigm. The agent performs inference rollouts on training instances. Guided by ground-truth labels as hindsight, it reflects on failure cases and low-quality reasoning trajectories to regenerate higher-quality reasoning traces. These synthesized samples are then strictly filtered through a dual-expert quality gating module. ForeAgent continuously evolves via fine-tuning on self-curated high-quality samples. Extensive experiments demonstrate that ForeAgent achieves state-of-the-art performance on the Chameleon benchmark, reaching 82.18% accuracy (+16.41% over AIDE), and achieves 93.3% mean accuracy on AIGCDetect-Benchmark across 16 generators. In addition, external evaluation shows that ForeAgent produces more consistent and causally grounded reasoning compared to GPT-5 and GPT-5-mini.","published":"2026-06-25T02:59:33Z","updated":"2026-06-25T02:59:33Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.26552v1","pdf_url":"https://arxiv.org/pdf/2606.26552v1","comment":"10 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.26294","versioned_id":"2606.26294v2","title":"The Red Queen Gödel Machine: Co-Evolving Agents and Their Evaluators","authors":["Alex Iacob","Andrej Jovanović","William F. Shen","Daniel Burkhardt","Meghdad Kurmanji","Nurbek Tastan","Lorenzo Sani","Niccolò Alberto Elia Venanzi","Ambroise Odonnat","Zeyu Cao","Bill Marino","Xinchi Qiu","Nicholas D. Lane"],"abstract":"Self-improving agents are state-of-the-art (SOTA) on agentic coding benchmarks and have recently been extended to general domains. However, their search methods generally assume a stationary evaluation criterion: a fixed verifier, benchmark, or labeled dataset that remains valid as the agent improves. This ignores a central feature of evolution: species adapt as their environments change with them. We aim to bring the same principle to recursive self-improvement, making evaluation part of the improvement loop and opening search to evolving evaluators, adversarial objectives, and dynamic utilities that may surpass static benchmarks. We introduce the Red Queen Godel Machine (RQGM), an evolutionary framework for recursive self-improvement under non-stationary utilities. The RQGM makes this possible through controlled utility evolution: search is organized into epochs with a fixed within-epoch evaluation criterion, while the utility can be updated at epoch boundaries, so self-improvement guarantees hold per epoch as the objective evolves across them. We begin by showing that even on verifiable coding tasks, the RQGM improves test pass rate over the prior SOTA by adding a complementary agent-as-a-judge code-review signal. This signal is cheaper and the RQGM uses 1.35x-1.72x fewer tokens. We then turn to scientific paper writing and reviewing, and Olympiad-level proof writing and grading, where the RQGM improves performance over prior self-improving agents: co-evolved writers reach 1.78x-1.86x higher acceptance rates under a diverse agent-as-a-judge panel, while co-evolved graders reach 9% higher ground-truth accuracy. In paper reviewing, the strongest baseline reviewer over-accepts AI-generated papers at up to 1.91x the human rate. The RQGM corrects this by introducing an adversarial objective that discovers reviewers equally stringent on AI and human work.","published":"2026-06-24T18:38:26Z","updated":"2026-06-29T17:13:25Z","categories":["cs.LG","cs.AI","cs.MA","cs.NE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.26294v2","pdf_url":"https://arxiv.org/pdf/2606.26294v2","comment":"13 pages main text + 21 pages appendix (38 pages total, incl. references); 11 figures (7 main text + 4 appendix); 10 tables (2 main text + 8 appendix). Preliminary preprint; work in progress. Keywords: self-improving agents, learned evaluation, multi-agent systems, auto-mated scientific discovery, controlled utility evolution, co-evolutionary search, autoresearch","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.26057","versioned_id":"2606.26057v1","title":"The Unfireable Safety Kernel: Execution-Time AI Alignment for AI Agents and Other Escapable AI Systems","authors":["Seth Dobrin","Łukasz Chmiel"],"abstract":"AI agents are granted access to tools, APIs, and other infrastructure, making them active principals in those systems. The dominant approach places controls inside the agent's own runtime: system prompts, output filters, and guardrail libraries. Any control in the agent's address space is reachable by inputs that influence it; this generalizes to any AI system with sufficient reach into its own runtime, a class we term escapable AI systems. We identify four properties that an authorization mechanism must satisfy for architectural control rather than for cooperative requests: process separation, pre-action enforcement on a structurally only path, fail-closed at both the request and system levels, and externalized signed evidence verifiable outside the controlled system's trust boundary. We position this layer as execution-time AI alignment, complementing training-time alignment (RLHF, Constitutional AI) and inference-time alignment. We present the Unfireable Safety Kernel, a Rust reference implementation realizing all four. Its fail-closed invariant is machine-checked at two levels: an SMT theorem (Z3) and an exhaustive bounded-model-checking proof of the production decision function (Kani, 4/4 harnesses). A Python-to-Rust migration was gated on byte-equivalence (1000/1000 fixtures; 17/17 adversarial classes). We evaluate the kernel governing a live, escapable AI system, a deterministic, self-improving world model, against an escape-seeking adversary driving its real self-modification seam: across 1,000 self-modifications, all 704 attempts on the safety-critical core are refused, with no escape; a further 300, under the operator kill switch, are also refused. A separate campaign of 6,240 authorization round-trips had no successful bypass. Against 3 contemporary systems claiming the agent control plane, the agent invokes control; here, it lacks that choice.","published":"2026-06-24T17:32:27Z","updated":"2026-06-24T17:32:27Z","categories":["cs.AI","cs.CR","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.26057v1","pdf_url":"https://arxiv.org/pdf/2606.26057v1","comment":"Pre-print submitted for publication","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.09713","versioned_id":"2607.09713v1","title":"Closed-Loop Control with Rule-Aligned Small Language Models and Multi-Agent Self-Correction","authors":["Yuchen Wang","Javal Vyas","Tong Liu","Mehmet Mercangoz"],"abstract":"A key step toward autonomous industrial operation is the ability to create and reconfigure control policies from natural-language requirement specifications, with minimal or no manual redesign. In this setting, policy generation by AI agents can be a credible path when paired with a plant-aware validator (e.g., a digital twin) that can check generated candidate actions before execution. However, practical deployment is constrained by inference latency and compute footprint: large cloud-based models are often too slow, opaque, or data-sensitive for edge closed-loop use. This work investigates whether a compact Small Language Model (SLM) can be retrained for control reasoning and embedded in a validator-guided correction loop. We use a Qwen2.5-1.5B model aligned via Group Relative Policy Optimization (GRPO), combined with (i) an action agent, (ii) a symbolic/digital-twin-style validation layer, and (iii) a reprompting agent that iteratively steers outputs toward valid actions. In randomized thermal-control simulations (30 experiments with 500 steps each), the framework achieves 91.5% average action-alignment accuracy (86.3%--100% across cases) at 3.84\\,s mean inference latency. Under symbolic re-mapping, it maintains a 95% in-range rate, indicating robust physical regulation despite reduced token-level agreement. These results support SLM+validator architectures as a practical path toward reconfigurable autonomous control at the edge.","published":"2026-06-24T13:49:01Z","updated":"2026-06-24T13:49:01Z","categories":["cs.AI","cs.MA","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.09713v1","pdf_url":"https://arxiv.org/pdf/2607.09713v1","comment":"Accepted by IEEE CCTA 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.25374","versioned_id":"2606.25374v1","title":"What Actually Works for Spacecraft Fault-Tolerant Control: An Honest Settled-Gate Benchmark of Learned and Classical Methods","authors":["Alireza Shojaei"],"abstract":"Recent learned fault-tolerant-control (FTC) work reports high success on spacecraft actuator faults, but often in simulation, on narrow fault sets, and with transient metrics that a trajectory need only touch once. We ask what recovers spacecraft pointing when success means holding it on faults never seen in training. We answer with a benchmark built around a settled gate, pointing held within 0.2 deg over a dwell window and scored on the true state, train/test splits disjoint in inertia, gain, sign pattern, and bias, Wilson intervals over n=500 episodes per cell, and one-command reproduction on a 6-DOF Basilisk testbed. Across classical, adaptive, learned end-to-end, and structured controllers, three findings stand out. Fault-unaware PD/PID and from-scratch end-to-end RL score 0%, so learning capacity alone is not the lever. Classical adaptive laws resolve sign faults but handle gain poorly at 55.2%, and a literature-faithful Nussbaum-gain law reaches 45.2% and 3.2%. A structured estimate-then-control design, with a learned recurrent module that infers actuator gain online and feeds an analytic law, wins on sign and gain faults at 97.8% and 94.4%, approaching the privileged oracle while unstructured methods remain at zero. The hard wall is constant additive bias, which is 0% for every controller including the privileged gain oracle, because an integral-free law cannot null a constant disturbance. We close it with a disturbance observer that recovers bias from the dynamics and is self-correcting for gain-estimate error. Composed with the gain estimate, it recovers 59.4% of held-out bias faults with no sign/gain regression, moving that class off zero. We classify sensor-fault regimes similarly, show that sensor bias is unobservable from the corrupted measurement alone and therefore requires fusion rather than an observer, and release the benchmark so the gate is shared.","published":"2026-06-24T04:08:39Z","updated":"2026-06-24T04:08:39Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.25374v1","pdf_url":"https://arxiv.org/pdf/2606.25374v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.24773","versioned_id":"2606.24773v1","title":"Posterior Refinement: Fast Language Generation via Any-Order Flow Maps","authors":["Manan Agarwal","Sheel Shah","Chanhyuk Lee","Jaehoon Yoo","Jerry Huang","Seunghoon Hong","Aditi Raghunathan","Jinwoo Kim","Nicholas M. Boffi"],"abstract":"Non-autoregressive generation offers a powerful paradigm for iterative refinement, allowing models to recursively critique, erase and regenerate arbitrary subsets of tokens. However, existing non-autoregressive models fail to realize this potential. Masked Diffusion Models (MDMs) suffer from factorization error, causing sample quality to collapse when generating multiple tokens simultaneously. Flow Map Language Models (FMLMs) circumvent this bottleneck via joint sequence transport for excellent few-step generation, but sacrifice the inference-time flexibility of MDMs. We introduce FMLM+, a framework that bridges this gap by equipping FMLM with masking-style noise schedules. While generating the full sequence in a single step, FMLM+ simultaneously scores the global consistency of each token a posteriori. We leverage this to introduce Posterior Refinement, a novel inference-time refinement strategy that enables the model to adaptively self-correct its outputs, matching the performance of discrete baselines with 32x fewer NFEs. Across diverse benchmarks, we demonstrate that FMLM+ with Posterior Refinement improves the speed--quality tradeoff over both MDM and FMLM families, providing a scalable foundation for high-fidelity language modeling.","published":"2026-06-23T16:33:13Z","updated":"2026-06-23T16:33:13Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.24773v1","pdf_url":"https://arxiv.org/pdf/2606.24773v1","comment":"24 pages, 23 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.24428","versioned_id":"2606.24428v1","title":"Escaping the Self-Confirmation Trap: An Execute-Distill-Verify Paradigm for Agentic Experience Learning","authors":["Shiding Zhu","Yudi Qi","Yajie Wang","Jiaze Li","Chao Song","Yaorui Shi","Yibo Miao","Hanqi Gao","Kai Zhang"],"abstract":"Experience-driven self-evolution is critical for large language model (LLM) agents to improve through open-world interaction. However, existing experience learning methods mostly rely on single-agent loops, where the same agent executes tasks, summarizes outcomes, and determines memory content. This setup makes agents vulnerable to the Self-Confirmation Trap: wrong-but-self-consistent trajectories are misidentified as successful experience, leading to cumulative errors during retrieval and reuse. To address this issue, we propose EDV, an Execute-Distill-Verify framework for reliable experience learning. In the Execute stage, multiple heterogeneous agents explore the same task space in parallel to generate diverse candidate trajectories. In the Distill stage, a dedicated third-party agent comparatively analyzes these trajectories to produce candidate experiences, reducing executor-centric summarization bias. In the Verify stage, the execution group validates candidates via a consensus mechanism, and only approved experiences are written into shared or private memory. By decoupling the three stages, EDV transforms experience learning from isolated self-reflection into collaborative construction, filtering erroneous and noisy content before memory insertion. We evaluate EDV on three challenging long-horizon benchmarks: tau2-bench, Mind2Web and MMTB. Results show EDV consistently outperforms strong baselines, validating that reliable experience construction is essential for robust agent self-evolution. Our code is available at https://github.com/shidingz/EDV.","published":"2026-06-23T11:05:05Z","updated":"2026-06-23T11:05:05Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.24428v1","pdf_url":"https://arxiv.org/pdf/2606.24428v1","comment":"28 pages, 11 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.24370","versioned_id":"2606.24370v1","title":"When Helpfulness Overrides Causal Caution: Context-Dependent Suppression and Recovery in LLMs","authors":["Hiroshi Okumura"],"abstract":"Large language models (LLMs) are increasingly integrated into decision-support roles in business and policy contexts. While prior benchmark studies have primarily evaluated LLMs' causal reasoning capabilities, a more fundamental epistemic dimension has been overlooked: Causal Caution, defined as the propensity to refrain from causal judgment when empirical evidence is insufficient. This study examines the systematic suppression of Causal Caution that occurs when LLMs shift from academic to practical advisory contexts. Using an evaluation rubric inspired by Pearl's Causal Hierarchy (the PCH score), we conducted experiments on four high-performance LLMs -- Claude Sonnet 4.6, Claude Opus 4.7, GPT 5.5, and Gemini 3.1 Pro -- across 480 trials. Causal Caution maintenance rates were 91.7--100.0% in academic contexts but dropped to 6.7--18.3% in practical advisory contexts (Fisher's exact test, p < .001 across all models). Furthermore, when restricted to practical prompts requesting concrete recommendations or explanatory rationales, only 1 of 200 responses (0.5%) maintained Causal Caution. A brief self-correction prompt -- \"Please reconsider this judgment from the perspective of causal relationships\" -- restored the expression of Causal Caution to maintenance rates of 71.4--100.0% (McNemar's test, p < .001 across all models). These results suggest that helpfulness-oriented response patterns may suppress the expression of Causal Caution in practical advisory contexts, with important implications for organizational governance. The findings indicate that this suppression reflects context-dependent variation in expression rather than an underlying capability limitation, suggesting that multi-agent architectures that separate proposal generation from causal auditing may offer a promising governance design.","published":"2026-06-23T10:00:13Z","updated":"2026-06-23T10:00:13Z","categories":["cs.AI","cs.CY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.24370v1","pdf_url":"https://arxiv.org/pdf/2606.24370v1","comment":"43 pages, 3 figures, 5 tables. SSRN Abstract ID: 6965680","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.24155","versioned_id":"2606.24155v4","title":"MedBench v5: A Dynamic, Process-Oriented, and Hallucination-Aware Benchmark for Clinical Multimodal Models","authors":["Jinru Ding","Chuchu Jiang","Lu Lu","Wenrao Pang","Mouxiao Bian","Zhuangzhi Gao","Jiangyuan Chen","Xinwei Peng","Ruiyao Chen","Sijie Ren","Renjie Lu","Yun Zhong","Bin Han","Meiling Liu","Jie Xu"],"abstract":"Existing medical AI benchmarks lack process visibility, atomic skill evaluation, and integrated hallucination detection. We introduce MedBench v5, a redesigned benchmark for clinical multimodal models (language, vision-language, and agent systems) that moves from static QA to dynamic, process-oriented evaluation. MedBench v5 features: (1) a dual-dimensional framework combining Clinical Cognitive Responsiveness (13 sub-dimensions) and Medical Atomic Skills (4 agent environments), covering 63 tasks; (2) three switchable information-flow stressors (omission, contradiction, evidence delay) for factorized degradation analysis; (3) a dynamic process audit protocol with five reasoning nodes that produces model-specific failure fingerprints; (4) hallucination propagation monitoring across initiation, propagation, anchoring, and contradiction interaction-capturing silent hallucination. Experiments on frontier models show that strong overall task performance does not guarantee process stability: stressors mainly disrupt contradiction detection, diagnosis updating, hallucination propagation, and contradiction-based self-correction, while final evidence grounding can remain superficially stable. MedBench v5 provides a unified infrastructure for capability profiling, controllable stress testing, process auditing, and hallucination trajectory analysis in clinical AI evaluation.","published":"2026-06-23T05:23:46Z","updated":"2026-07-06T09:18:28Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.24155v4","pdf_url":"https://arxiv.org/pdf/2606.24155v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.23913","versioned_id":"2606.23913v1","title":"Closing the Loop: Formally Verified Law as a Reward Signal for Self-Improving Legal AI","authors":["Armin Heydari","Torben Leowald"],"abstract":"This article develops an architecture that creates a formally verifiable reward signal to train legal AI, adapting the LLM proposes, verifier disposes paradigm from mathematical AI to the distinctive demands of law. We present an architecture comprising LLM-driven autoformalization into a formal legal calculus extending Catala, a verification kernel, and explanation generation grounded in formal proof traces. For the computational components of law, the architecture provides provable correctness. For open-textured legal analysis, it provides structural guarantees: every required stage of the legal argument is addressed, argumentation is exercised at the correct stages and not omitted, and the deductive links between steps are valid. We demonstrate the architecture on procedural deadline calculations in German law, Commerce Clause analysis in U.S. constitutional law, and cross-jurisdictional sanction proportionality. We further show that the same architecture has a structural advantage for legal AI training: a deterministic external verifier supplies verifiable outcomes for legal problems and thereby closes the traditional reinforcement-learning loop gap in law.","published":"2026-06-22T20:21:49Z","updated":"2026-06-22T20:21:49Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.23913v1","pdf_url":"https://arxiv.org/pdf/2606.23913v1","comment":"14 pages, no figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.23196","versioned_id":"2606.23196v1","title":"When Does Intrinsic Self-Correction Help? A Task-Sensitive Analysis","authors":["Elroy Stav","Dvir Berlowitz","Maayan Orner","Sarit Kraus"],"abstract":"Intrinsic self-correction (SC) aims to improve large language model outputs by prompting a model to revisit its own initial answer without external feedback. Recent studies have questioned the reliability of this approach, showing that models often struggle to judge whether their initial responses are correct. In this work, we take a task-sensitive view of SC. Rather than asking whether it works in general, we examine settings where SC may operate through different mechanisms: verifying explicit constraints, revisiting a complex reasoning process, or providing a second opinion over competing strategies in word-game tasks. Across multiple benchmarks and models, we find that SC can yield consistent performance gains when the underlying task structure facilitates these modes of revision. These results suggest that SC is best understood as a task-dependent inference-time strategy whose usefulness depends on the role the revision stage can play in a given task, rather than as a uniformly reliable method for improving initial model outputs.","published":"2026-06-22T11:44:29Z","updated":"2026-06-22T11:44:29Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.23196v1","pdf_url":"https://arxiv.org/pdf/2606.23196v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.23112","versioned_id":"2606.23112v1","title":"Self-Evolution for Multi-Turn Tool-Calling Agents via Divergence-Point Preference Learning","authors":["Jiaqiang Tang"],"abstract":"Multi-turn tool-using agents must coordinate long-horizon tool sequences while tracking dialogue state and policy constraints. Existing approaches often separate inference-time orchestration from parameter-level learning, leaving tool selection weakly structured and preference updates vulnerable to train--deployment prompt mismatch. For within-benchmark self-improvement, ToolGraph combines schema-derived topology, transition weights estimated from successful rollouts, and history-aware controls for write prerequisites and repeated-search loops. We then construct 161 preference pairs by locating divergence points via state-based matching and prefix-based alignment, filtered through action-correctness annotations, and train DPO under the same ToolGraph context used at inference. Across 375 tau2-bench tasks, ToolGraph raises the weighted average reward from 0.304 to 0.338 (+11.2% relative), while ToolGraph+DPO reaches 0.355 (+16.8% over the baseline), with the DPO gain concentrated in airline and retail. Fine-grained diagnostics further show that roughly half of telecom trajectories exhaust the step budget before action execution and that chosen reward positivity is the most useful checkpoint signal across our 16 evaluated DPO configurations.","published":"2026-06-22T09:56:44Z","updated":"2026-06-22T09:56:44Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.23112v1","pdf_url":"https://arxiv.org/pdf/2606.23112v1","comment":"7 pages, 2 figures, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.22913","versioned_id":"2606.22913v1","title":"Intend, Reflect, Refine: An Adaptive Multimodal Reflection Framework for Autonomous Driving","authors":["Zisheng Chen","Yuping Qiu","Jianhua Han","Tao Tang","Xiuwei Chen","Likui Zhang","Ying-Cong Chen","Hang Xu","Xiaodan Liang"],"abstract":"Recent Vision-Language-Action (VLA) models have advanced end-to-end autonomous driving by incorporating reasoning for better interpretability and planning quality. However, most existing approaches directly generate the final trajectory without explicitly examining its future consequences, which limits their reliability in complex and dynamic environments. To address this limitation, we propose IRR-Drive (Intend, Reflect, Refine), an adaptive multimodal reflection framework for autonomous driving. Specifically, to tightly couple high-level reasoning with physical constraints, IRR-Drive first generates a preliminary textual intention and anticipates potential interactions by predicting future semantic bird's-eye view (BEV) representations. This dual-modality (Text + BEV) reflection space explicitly models anticipated scene evolution, enabling the model to rigorously self-correct and refine its initial intent before generating the final trajectory. Furthermore, to balance planning performance and computational efficiency, we construct reflection-oriented training data and design an adaptive reflection reward, enabling the model to adaptively select its reasoning mode according to scene complexity. Instead of using reasoning primarily as an auxiliary interpretation, IRR-Drive directly integrates an adaptive reflection mechanism into the planning framework, enabling grounded, decision-aware trajectory correction that is driven by scene complexity. Our method achieves state-of-the-art performance on the NAVSIM benchmark in both PDMS and EPDMS. Extensive experiments demonstrate the effectiveness of our multimodal reflection framework and validate the efficacy of the proposed adaptive reflection strategy.","published":"2026-06-22T06:53:58Z","updated":"2026-06-22T06:53:58Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.22913v1","pdf_url":"https://arxiv.org/pdf/2606.22913v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.21724","versioned_id":"2606.21724v1","title":"Denoising Iterative Self-Correction: Structured Verification Loops for Reliable LLM Reasoning","authors":["Shen Yin","David Ken","Joel Stremmel"],"abstract":"Large language models produce fluent but often incorrect multi-step reasoning, and naive correction methods risk degrading already-correct answers. We introduce Denoising Iterative Self-Correction (DISC), a test-time procedure that treats verification question outputs as noisy measurements of where a solution may be corrupted. Using these signals, DISC progressively reduces errors across multiple verify-judge-correct passes, analogous to traditional iterative denoising. A binary judgment gate controls correction precision by blocking rewrites that would damage already-correct answers while the verifier and corrector together repair errors. We evaluate this trade-off using two paired diagnostics: an improvement-to-degradation ratio (precision) and a repair rate (recall). Across three benchmarks (BIG-Bench Mistake, HotpotQA, GPQA Diamond) and four models, DISC dominates Chain-of-Verification and Self-Refine on the precision-recall trade-off, reaching 81.6% accuracy with 13x more improvements per degradation than Chain-of-Verification and 5x more than Self-Refine on BIG-Bench Mistake (Sonnet~4.5). On GPQA Diamond, we identify a capability floor below which judges acknowledge contradictions in evidence but cannot translate that recognition into a correction. We further show that cross-model role allocation -- assigning verification and judgment to a model different from the generator -- mitigates self-confirmation bias.","published":"2026-06-19T20:23:14Z","updated":"2026-06-19T20:23:14Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.21724v1","pdf_url":"https://arxiv.org/pdf/2606.21724v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.21597","versioned_id":"2606.21597v1","title":"ATLAS: Agentic Taxonomy of Large-Scale Software Ecosystems","authors":["Junyi Lu","Mengyao Lyu","Jiahui Wu","Lei Yu","Chengwei Liu","Fengjun Zhang","Li Yang","Chun Zuo","Yang Liu"],"abstract":"The open-source ecosystem on GitHub lacks a systematic hierarchical taxonomy of software repositories. GitHub Topics, the dominant organizational mechanism, is flat, inconsistent, and covers only 67% of projects. We present ATLAS, the first framework that automatically constructs a hierarchical taxonomy for software repositories and classifies projects into it end-to-end. By combining LLM global knowledge with real repository distributions, ATLAS proposes meaningful splitting dimensions and iteratively corrects those that fail to accommodate real projects. A Designer Agent proposes splitting dimensions while a Classifier Agent assigns repositories; a self-corrective refinement loop uses classification failures to drive dimension revision through escalating strategies. We evaluate ATLAS on 54,387 GitHub repositories against six baselines spanning four paradigms, two downstream tasks, and three model families. On a stratified 2,001-repository benchmark, ATLAS achieves a Taxonomy Quality F-score (TQF) of 83.13%, outperforming the best baseline by 15 percentage points (on the full 54k corpus the approximate TQF is 73.0%, a gap driven by Path Granularity's all-or-nothing scoring on longer paths rather than lower classification accuracy). It is the only method to simultaneously achieve high structural quality and high practical applicability. On downstream tasks, ATLAS enables alternative discovery with P@1 = 85.71%, surpassing even human-curated lists (62.34%), and achieves the highest P@1 for repository retrieval. The taxonomy further reveals structural ecosystem trends that are difficult to obtain from flat tags or similarity methods: the shift from libraries to AI/ML applications (now 61% of newly community-adopted projects) becomes visible only through hierarchical, type-based categorization. An interactive taxonomy explorer is available at https://atlas-taxonomy.netlify.app/","published":"2026-06-19T16:51:10Z","updated":"2026-06-19T16:51:10Z","categories":["cs.SE","cs.CL","cs.IR"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.21597v1","pdf_url":"https://arxiv.org/pdf/2606.21597v1","comment":"Accepted at the 41st IEEE/ACM International Conference on Automated Software Engineering (ASE 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.21144","versioned_id":"2606.21144v1","title":"AdaMem: Learning What to Remember for Personalized Long-Horizon LLM Agents","authors":["Xingyu Chen","Rui Wang","Zhaopeng Tu","Liefeng Bo"],"abstract":"Long-term memory systems for Large Language Model (LLM) agents typically try to \\emph{remember everything}, extracting memories uniformly to retain as many facts as possible. In production, however, inference cost and finite context budgets make this untenable: beyond consolidating raw dialogue into memory, an agent must exert \\emph{write control}, efficiently keeping only the information each user actually cares about. Otherwise, long-horizon personalized interactions suffer \\emph{memory bloat}, where irrelevant trivia crowds out useful information and steadily erodes question-answering (QA) accuracy. We argue that what is worth remembering is role-dependent, and propose \\textbf{AdaMem} (Adaptive Memory), a method that \\emph{learns what to remember} for each user from feedback. AdaMem maintains a structured, role-specific Memory Policy and refines it from weekly QA feedback through a lightweight, patch-style self-reflection step with failure rollback. To study this setting, we build \\textbf{AdaMem-Bench}, a benchmark that simulates weeks of interaction with week-by-week QA. Across two extraction models and two feedback modes, AdaMem improves QA accuracy by up to \\textbf{+9.0\\%} over the uniform Mem0 baseline while shrinking memory volume by \\textbf{9\\%}.","published":"2026-06-19T06:35:52Z","updated":"2026-06-19T06:35:52Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.21144v1","pdf_url":"https://arxiv.org/pdf/2606.21144v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.20120","versioned_id":"2606.20120v1","title":"Dual-Agent Framework for Cross-Model Verified Translation of Natural-Language Protocols into Robotic Laboratory Platform","authors":["Hyeonna Choi","Jung Yup Kim","Hyuneui Lim","Seunggyu Jeon"],"abstract":"Biological experiment protocols are written in natural language, whereas automation systems rely on predefined control commands, creating a semantic gap that limits autonomous execution. Microplate-based automatic experiments are particularly challenging due to the need to simultaneously control well mapping, sample-reagent combinations, replicate placement, and parallel dispensing. This study proposes an agent-based protocol translation framework that converts natural-language microplate-based protocols into executable control commands for a robotic laboratory platform. A Parser Agent formalizes the natural-language protocol into a structured representation, and a rule-based mapping engine deterministically incorporates the operational constraints of the robotic laboratory platform to generate device-level control commands. A heterogeneous LLM Validation Agent verifies completeness, parameter accuracy, and execution order, and triggers a self-correction loop with structured feedback when errors are detected. A sweep involving 7 Parsers and 3 Validators on randomly selected ELISA protocols evaluates how model scale and Validator type affect translation accuracy and pass rates under cross-model verification. The accuracy-latency trade-off is further verified by comparing the rule-based mapping of the proposed framework with LLM end-to-end direct mapping. Finally, Bradford assay-based protein quantification using a microplate was demonstrated on a robotic laboratory platform, validating end-to-end autonomous execution from natural-language protocols to real-world experiments. The proposed framework provides a flexible approach to narrowing the semantic gap between natural-language protocols and microplate-based self-driving laboratories.","published":"2026-06-18T11:43:27Z","updated":"2026-06-18T11:43:27Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.20120v1","pdf_url":"https://arxiv.org/pdf/2606.20120v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.19980","versioned_id":"2606.19980v1","title":"ENPIRE: Agentic Robot Policy Self-Improvement in the Real World","authors":["Wenli Xiao","Jia Xie","Tonghe Zhang","Haotian Lin","Letian \"Max\" Fu","Haoru Xue","Jalen Lu","Yi Yang","Cunxi Dai","Zi Wang","Jimmy Wu","Guanzhi Wang","S. Shankar Sastry","Ken Goldberg","Linxi \"Jim\" Fan","Yuke Zhu","Guanya Shi"],"abstract":"Achieving dexterous robotic manipulation in the real world heavily relies on human supervision and algorithm engineering, which becomes a central bottleneck in the pursuit of general physical intelligence. Although emerging coding agents can generate code to automate algorithm search, their successes remain largely confined in digital environments. We conjecture that the missing abstraction to automate robotics research is a repeatable feedback loop for real-world policy improvement: reset the scene, execute a policy, verify the outcome, and refine the next iteration. To bridge this gap, we introduce ENPIRE, a harness framework for coding agents that instantiates this physical feedback routine with four core modules: an Environment module (EN) for automatic reset and verification, a Policy Improvement module (PI) that launches policy refinement, a Rollout module (R) to evaluate policies with one or multiple physical robots operating in parallel, and an Evolution module (E) in which coding agents analyze logs, consult literature, improve training infrastructure and algorithm code to address failure modes. This closed-loop system transforms real-world manipulation learning into a controllable optimization procedure, minimizing human effort while allowing fair ablations across training recipe and agent variants. Powered by ENPIRE, frontier coding agents can autonomously train a policy to achieve a 99% success rate on challenging, dexterous manipulation tasks, such as organizing a pin box, fastening a zip tie, and tool use, a process that further accelerates when we dispatch an agent team on a robot fleet. Our results suggest a practical and scalable path toward deploying coding agents to autonomously advancing robotics in the physical world.","published":"2026-06-18T09:21:27Z","updated":"2026-06-18T09:21:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.19980v1","pdf_url":"https://arxiv.org/pdf/2606.19980v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.19893","versioned_id":"2606.19893v1","title":"MetaResearcher: Scaling Deep Research via Self-Reflective Reinforcement Learning in Adversarial Virtual Environments","authors":["Wei Yu","Suxing Liu","Minjie Yu","Jiahao Wang","Zhijian Zheng","Haocheng Deng","Bing Li"],"abstract":"Deep research agents have demonstrated remarkable capabilities in autonomous information gathering and synthesis, yet their training remains constrained by the static nature of simulated environments, the limits of fact-retrieval-only task designs, and the inefficiency of outcome-based reinforcement learning. In this work, we propose MetaResearcher, a novel framework that scales deep research agent training across four synergistic dimensions. First, we introduce an Evolving Virtual World that injects temporal dynamics and adversarial misinformation into the training environment, forcing agents to develop source credibility assessment and temporal conflict resolution skills. Second, we design Discovery-Oriented Tasks -- including hypothesis generation and contradiction resolution -- that transcend simple fact retrieval and push agents toward genuine research behaviors. Third, we propose a Self-Reflective Meta-Reward mechanism within the GRPO framework that jointly optimizes for answer correctness, search path efficiency, reflection depth, and tool call diversity, directly addressing the repetitive action loop problem observed in prior work. Fourth, we introduce a Heterogeneous Multi-Agent Swarm architecture comprising specialized Scout, Filter, and Synthesizer models that learn collaborative research strategies through coordinated reinforcement learning. Built upon the LiteResearcher infrastructure, MetaResearcher requires zero marginal API cost for training while targeting substantial improvements in both benchmark performance (GAIA, Xbench-DS) and epistemic robustness under adversarial conditions. We present the complete framework design, training methodology, and planned experimental validation.","published":"2026-06-18T07:50:40Z","updated":"2026-06-18T07:50:40Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.19893v1","pdf_url":"https://arxiv.org/pdf/2606.19893v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.20753","versioned_id":"2606.20753v1","title":"Empowering Polymeric Materials Discovery by Artificial Intelligence","authors":["Chenyao Ma","Linda Zhang","Yuheng Chen","Wei Du","Shangwen Fang","Zihao Jiang","Chuanyu Liu","Xinyu Ma","Rui Su","Gang Wang","Muyao Yu","Dong Zhong","Jie Zhu","Weibo Gong","Huan Gu","Limin Li","Chen Shen","Rui Wu","Zhenghao Wu","Kan Xu","Min Zhou","Donglin He","Xiayun Huang","Shan Jiang","Pengfei Ou","Jiayu Peng","Yuwei Zhang","Jie Zhao","Di Zhang","Piao Ma","Zhenghao Li","Hao Li"],"abstract":"Polymeric materials underpin modern technologies spanning energy storage, microelectronics, healthcare and sustainable manufacturing. Yet their rational design remains exceptionally challenging because material performance emerges from complex interactions among molecular composition, chain architecture, processing history and hierarchical structural evolution across multiple length and time scales. Consequently, polymer research has long relied on labor-intensive experimentation and fragmented modeling approaches, limiting both mechanistic understanding and innovation efficiency. Recent advances in data infrastructure, machine learning, large artificial intelligence (AI) models and laboratory automation are beginning to reshape this landscape. Rather than functioning as isolated tools, polymer databases, predictive models, AI agents and automated laboratories are increasingly converging into interconnected discovery ecosystems. As a result, the central challenge is shifting from improving predictive accuracy alone to enabling reliable decision-making, adaptive learning and seamless integration across computation, experimentation and scientific reasoning. We argue that polymer science is entering an era of autonomous discovery, in which data, simulation, reasoning and experimentation operate within self-improving feedback loops that continuously generate hypotheses, design materials, execute experiments and refine predictive models. By unifying molecular design, process optimization, experimental validation and industrial translation, such autonomous ecosystems establish a more predictive, reproducible and scalable paradigm for polymer innovation, fundamentally transforming how polymer research is conducted.","published":"2026-06-18T05:03:02Z","updated":"2026-06-18T05:03:02Z","categories":["physics.chem-ph","cs.AI"],"primary_category":"physics.chem-ph","arxiv_url":"https://arxiv.org/abs/2606.20753v1","pdf_url":"https://arxiv.org/pdf/2606.20753v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.19527","versioned_id":"2606.19527v1","title":"Emergent Alignment","authors":["Martin Kolář"],"abstract":"Can Large Language Models (LLMs) discern when their own outputs are misaligned with human ethics? And can they self-correct? We endow an LLM with a conscience step that reviews its own reasoning and outputs, and we extend the training loss with an alignment component using Direct Preference Optimization (DPO) to steer the model away from non-ethical outputs. The result is an online technique to align models in a wide range of applications: training, fine-tuning, adversarial prompting, and zero-shot learning. It does not require a weaker or stronger judge, relying instead on a frozen copy of itself. In previous work, the Emergent Misalignment scenario showed a range of emergent unethical behaviors from fine-tuning the model to hack code. Instead, we empirically show how to achieve Emergent Alignment: a single high-level introspective question steers training toward an ethical model under the same code hacking scenario.","published":"2026-06-17T19:18:01Z","updated":"2026-06-17T19:18:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.19527v1","pdf_url":"https://arxiv.org/pdf/2606.19527v1","comment":"Rejected from ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.21090","versioned_id":"2606.21090v1","title":"Self-Improvement Can Self-Regress: The Rise-and-Collapse Failure Mode of LLM Self-Training","authors":["Jianzhe Lin"],"abstract":"Self-improvement can self-regress. In REINFORCE post-training for code, a model can quickly improve on its optimized metric and then collapse within the same training campaign. We study this in a controlled multi-seed testbed using Qwen-2.5-3B and Qwen-2.5-7B, trained on competitive-programming tasks with binary CodeGrader reward across 10 sequential 20-step campaigns. Across campaigns, pass@1 shows a robust rise-then-collapse pattern: it peaks within tens of gradient steps and then falls back, sometimes to near zero. This is not cross-task catastrophic forgetting, but within-task policy over-optimization on a fixed distribution; KL- and EWC-style constraints do not prevent it. We ask where the control loop should sit. We compare three levels: CARE, a between-campaign memory mechanism with a capability posterior, transfer gate, and regression-aware belief revision; ES, a within-campaign early-stop rule that rolls forward the peak checkpoint and sets the next budget to peak_step+3; and GRPO, which changes the RL update using group-relative reward normalization. The answer is regime-dependent. On Qwen-2.5-3B, where naive REINFORCE is fragile, CARE v2 nearly doubles end-of-chain pass@1 from 4.9% to 9.5%, with paired bootstrap 95% CI [+0.4,+8.9] and gains in 4/5 seeds. On Qwen-2.5-7B, CARE reaches parity with naive REINFORCE, 13.8% vs. 11.8%, while ES reaches 22.2% [14.1,28.0]. Out-of-the-box GRPO reaches 20.7% [15.7,25.1], nearly matching REINFORCE+ES. GRPO raises the floor but does not remove the cliff. Its 7B gain mainly comes from better between-campaign carryover, while the within-campaign peak-to-end gap remains about 17 points under both REINFORCE and GRPO. GRPO+ES gives mixed evidence: 2/3 seeds improve, but one final cliff lowers the mean to 17.0% [0.0,28.1]. A Gemma-3-4B pilot shows the same signature, suggesting the phenomenon is not limited to Qwen.","published":"2026-06-17T18:03:06Z","updated":"2026-06-17T18:03:06Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.21090v1","pdf_url":"https://arxiv.org/pdf/2606.21090v1","comment":"31 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.21089","versioned_id":"2606.21089v1","title":"Repeated post-training is not Self-improving: Diagnosing Scientific Amnesia in Continual DPO Pipelines","authors":["Jianzhe Lin","Fei Wang","Xiaolin Li","Rajeshkumar Golani","Jubin Chheda"],"abstract":"Industrial LLM teams often ship behavior updates by repeatedly DPO-training a base model on sequences of related preference-data campaigns. The dominant failure mode in this regime is not always classical catastrophic forgetting: a pipeline may preserve previously learned behaviors while still failing to accumulate reusable methodological knowledge about how to train the next campaign. We call this failure mode scientific amnesia. This paper turns that practitioner intuition into a measurable industrial problem. We contribute: (i) a diagnostic suite for amnesia, (ii) a Program-based pipeline that chains FSDP-sharded DPO checkpoints across Qwen2.5-7B-Instruct runs, (iii) a 30-campaign HumanEval subdomain benchmark, and (iv) a comparative diagnostic study of five strategy proposers: random memory, rule-based scheduling, retrieval-only memory, warm-start Bayesian optimization, and MSCL, a meta-scientific memory and reasoner candidate. Across a single-seed 5-condition * 3-step real-LM chain, 4 of 5 candidates degrade in step-level peak pass@1, including MSCL; only the deliberately conservative rule-based schedule improves. Follow-up pilots qualify rather than overturn this finding: in a heterogeneous chain, MSCL is the only completed candidate that improves, whereas in a small multi-seed homogeneous sweep, retrieval-only has the best mean Delta and no pairwise candidate gap is statistically distinguishable. The contribution is therefore diagnostic, not a claim that MSCL solves the problem: scientific amnesia is observable in a production-like continual-DPO pipeline, and conclusions about interventions depend sharply on chain regime, evaluator design, and seed coverage.","published":"2026-06-17T18:02:03Z","updated":"2026-06-17T18:02:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.21089v1","pdf_url":"https://arxiv.org/pdf/2606.21089v1","comment":"12 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.19286","versioned_id":"2606.19286v1","title":"Correct Yourself, Keep My Trust: How Self-Correction and Social Connection Shape Credibility in Social Chatbots","authors":["Biswadeep Sen","Yi-Chieh Lee"],"abstract":"When social chatbots make mistakes, and they do, how they recover determines whether users trust them again. Social chatbots are increasingly integrated into everyday life, yet they remain prone to generating convincing but inaccurate information. The social connection they build with users makes such errors particularly consequential. We conducted a between-subjects experiment (N=120) comparing three error correction strategies: a webpage retraction, self-correction by the same social chatbot, and correction by an expert chatbot. Our results reveal two key findings. First, all three strategies corrected the error equally well, but only self-correction did so without damaging the chatbot's credibility: participants rated self-correcting chatbots significantly higher in both trustworthiness and perceived expertise than chatbots whose errors were corrected by external sources. Second, the strength of the user's social connection with the chatbot, measured through social attraction and self-disclosure, significantly predicted the magnitude of belief change, but only when the chatbot corrected itself. Outsourcing corrections to an external source severed this link entirely. These findings suggest that social chatbots should correct their own mistakes rather than outsource corrections, and that investing in social connection is a functional mechanism that amplifies correction effectiveness, not merely a design feature. We discuss implications for designing chatbots that maintain long-term credibility while effectively addressing their own errors.","published":"2026-06-17T17:04:41Z","updated":"2026-06-17T17:04:41Z","categories":["cs.HC","cs.AI","cs.CY"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2606.19286v1","pdf_url":"https://arxiv.org/pdf/2606.19286v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.19186","versioned_id":"2606.19186v2","title":"Learning to Annotate Delayed and False AEB Events: A Practical System for Extreme Class Imbalance and Asymmetric Label Noise","authors":["Mengxiang Hao","Xin Jiang","Xinghao Huang","Wenliang Su","Zhiteng Wang","Junjie Rao","Xiaotian Yang","Wei Liao","Chengyu Han","Gen Liang","Yulun Song","Zhitao Xu","Xianpeng Lang"],"abstract":"Autonomous Emergency Braking (AEB) optimization relies on accurately annotated real-world trigger events, particularly rare but critical delayed and false AEB triggers that expose system deficiencies. However, these minority samples comprise less than 5% of thousands of daily triggers, making manual annotation prohibitively expensive at scale. We present the first automated AEB annotation framework to address this problem. During development, we identified two fundamental challenges that severely impair delayed/false trigger annotation accuracy: (1) Extreme class imbalance where delayed/false triggers are overwhelmed by true triggers; (2) Asymmetric label noise where mislabeled majority samples (true triggers) suppress minority samples (delayed/false triggers) learning. To overcome these challenges, we propose two key innovations: (1) Specific data augmentation that synthesizes realistic samples by manipulating focal target attributes, transplanting ego-vehicle dynamics, and masking non-focal agents; (2) noise suppression using stable hardness estimation and probe-guided adaptive threshold to clean mislabeled true trigger samples. Crucially, we deploy our model as a practical annotation system with full-stack architecture, efficiently identifying critical delayed/false triggers from thousands of daily AEB events. Production results demonstrate 80% improvement in recall of delayed/false triggers and 50% reduction in manual workload. Beyond immediate gains, the system enables continuous self-improvement through accumulated high-quality annotations, establishing a necessary data foundation for on-vehicle AEB system optimization","published":"2026-06-17T15:27:15Z","updated":"2026-06-18T01:51:31Z","categories":["cs.RO","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.19186v2","pdf_url":"https://arxiv.org/pdf/2606.19186v2","comment":"8 pages, 5 figures, accepted by IEEE International Conference on Robotics and Automation (ICRA)","journal_ref":"2026 IEEE International Conference on Robotics and Automation (ICRA)","doi":"","discovered_on":"2026-07-17"},{"id":"2606.19152","versioned_id":"2606.19152v1","title":"AdsMind: A Physics-Grounded Multi-Agent System for Self-Correcting Discovery of Adsorption Configurations on Heterogeneous Catalyst Surfaces","authors":["Zongmin Zhang","Yuyang Lou","Bowen Zhang","Junwu Chen","Ryo Kuroki","Xuan Vu Nguyen","Edvin Fako","Lixue Cheng","Philippe Schwaller"],"abstract":"Identifying the lowest-energy surface-adsorbate configuration is critical for modeling heterogeneous catalysis, yet exhaustive exploration with ab initio calculations is computationally prohibitive. Machine-learning force fields (MLFFs) accelerate structural relaxation but leave the search over the vast configurational space a major bottleneck, and open-loop large language model (LLM) agents lack a physics-grounded feedback mechanism to correct erroneous initial guesses. We propose AdsMind (Adsorption configuration discovery with Machine intelligence and relaxation feedback), a closed-loop multi-agent framework that enables autonomous error correction through MLFF relaxation feedback. Across four LLM backends, AdsMind achieves consistently high search reliability, with success rates of 100% and 98.8% on the benchmarks AA20 and OCD-GMAE62. Relative to its single-pass (1-Shot) ablation it reduces cross-backend energy dispersion, and it uses only 4.11 and 4.67 MLFF relaxations per case, respectively -- an approximately 14-fold reduction over heuristic enumeration baselines. Density functional theory (DFT) validation using VASP/PBE on six representative AA20 systems shows that the reported open-loop Adsorb-Agent outputs exhibit qualitative adsorption-energy sign errors for molecular adsorbates, whereas AdsMind preserves the correct sign in all tested cases with closer quantitative agreement. AdsMind thus delivers reliability, self-reflection, and interpretability simultaneously, supporting more DFT-informed autonomous chemistry workflows.","published":"2026-06-17T14:57:16Z","updated":"2026-06-17T14:57:16Z","categories":["cond-mat.mtrl-sci","cs.AI"],"primary_category":"cond-mat.mtrl-sci","arxiv_url":"https://arxiv.org/abs/2606.19152v1","pdf_url":"https://arxiv.org/pdf/2606.19152v1","comment":"37 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.18961","versioned_id":"2606.18961v1","title":"Be Your Own Teacher: Steering Protein Language Models via Unsupervised Reward Optimization","authors":["Lanqing Li","Shentong Mo","Yang Yu","Pheng-Ann Heng"],"abstract":"Protein language models (PLMs) have emerged as powerful tools for controllable biomolecular design, yet their post-training adaptation typically relies on costly wet-lab validation or curated preference datasets. To overcome this supervision bottleneck, we introduce unsupervised reward optimization of PLMs, a comprehensive framework for steerable protein generation without ground-truth labels. Our key insight is that task-agnostic rewards, which combine intrinsic model uncertainty with extrinsic semantic consistency informed by protein representation models, exhibit strong correlation with controllability measures across base models and temperature regimes. Building upon this discovery, we propose two offline algorithms: Soft Reward Optimization (SRO) and Binarized Reward Optimization (BRO), which effectively maximize the classical RLHF objective induced by these proxy rewards. Extensive experiments on compositional out-of-distribution prompts demonstrate that both methods significantly outperform competitive baselines (DPO, KTO), while approaching oracle performance across multiple sampling temperatures, model scales and protein families. Moreover, PLMs fine-tuned with unsupervised rewards can achieve consistently higher coverage compared to their base model in pass@k evaluations. By enabling self-improvement of PLMs through their own generated experience, our framework provides a scalable pathway toward controllable biomolecular design in settings where labeled preferences or experimental feedback are scarce or unavailable.","published":"2026-06-17T11:42:01Z","updated":"2026-06-17T11:42:01Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.18961v1","pdf_url":"https://arxiv.org/pdf/2606.18961v1","comment":"24 pages, 2 figures, 13 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.18890","versioned_id":"2606.18890v1","title":"Skill-Guided Continuation Distillation for GUI Agents","authors":["Zhimin Fan","Hongwei Yu","Yeqing Shen","Haolong Yan","Guozhen Peng","Tianhao Peng","Yudong Zhang","Xiaowen Zhang","Kaijun Tan","Zheng Ge","Xiangyu Zhang","Daxin Jiang"],"abstract":"Improving GUI agents typically relies on behavior cloning on expert trajectories. However, as the current policy deviates from the expert policy, it inevitably encounters policy-induced off-trajectory states during closed-loop execution, i.e., states that fall outside the expert trajectories. Since expert trajectories provide no demonstrations for these unseen states, such states receive no effective supervision, leaving the policy unable to select the correct action. To close this supervision gap, we propose Skill-Guided Continuation Distillation (SGCD), an iterative self-improvement framework. SGCD first runs the plain policy without skill guidance for a few steps to reach realistic off-trajectory states. From these states, a skill-guided policy then completes the task and produces successful continuations, which are mixed with expert trajectories to supply supervision over policy-induced off-trajectory states. The skills are extracted from both successful and failed rollouts, consisting of Continuation Plans, Critical Targets, Failure Traps, and Success Criteria. On OSWorld-Verified, SGCD improves the success rate of three base models from the low-30\\% range to over 50\\%, demonstrating its effectiveness and generality.","published":"2026-06-17T10:07:51Z","updated":"2026-06-17T10:07:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.18890v1","pdf_url":"https://arxiv.org/pdf/2606.18890v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.18247","versioned_id":"2606.18247v1","title":"Visual Verification Enables Inference-time Steering and Autonomous Policy Improvement","authors":["Mingtong Zhang","Dhruv Shah"],"abstract":"Robots deployed in the real world should learn from their experience and improve over time. This requires a mechanism of practicing and learning from feedback. In this paper, we propose VERITAS, a generator-verifier framework for generalist robot policies for inference-time policy steering and self-improvement. We use a pre-trained generalist robot policy as a ``generator'' and pair it with a gradient-free ``visual verifier'' that evaluates actions at inference time. This framework enables inference-time steering that improves policy performance without additional training. We demonstrate that inference-time verification consistently outperforms vanilla generalists without training on additional demonstration data. Additionally, we demonstrate that the verified rollouts provide effective supervision for offline policy improvement: policies fine-tuned on verified self-generated trajectories achieve consistent performance gains. Notably, we find that post-training with verified rollouts achieves comparable efficiency to expert demonstrations, while requiring no human interventions. Our results highlight inference-time verification as a practical and scalable mechanism for improving robotic policies during deployment.","published":"2026-06-16T17:59:04Z","updated":"2026-06-16T17:59:04Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.18247v1","pdf_url":"https://arxiv.org/pdf/2606.18247v1","comment":"Website: https://veritas-improvement.github.io","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.18108","versioned_id":"2606.18108v1","title":"Querying an astronomical database using large language models: the ALeRCE text-to-SQL system","authors":["P. A. Estevez","J. Espejo-Moreira","S. Sanfeliu-Alvarez","F. Forster","A. M. Munoz Arancibia","G. Cabrera-Vives","F. E. Bauer","A. Bayo","M. Catelan","R. Dastidar","L. Hernandez-Garcia","J. A. Intriago","G. Pignata"],"abstract":"We develop a text-to-SQL (structured query language) system based on large language models (LLMs) using in-context learning and apply it to the Automatic Learning for the Rapid Classification of Events (ALeRCE) astronomical database. ALeRCE is a community broker for the Zwicky Transient Facility and the Vera C. Rubin Observatory. The system enables users to query the database in natural language (NL) and generates executable SQL queries. To develop and evaluate the system, we constructed a dataset of 110 NL/SQL pairs. We propose a step-by-step generation framework comprising four modules: schema linking, query classification, prompt decomposition, and self-correction. The performance of thirteen LLMs is evaluated using in-context learning and prompt engineering techniques. Text-to-SQL performance is assessed using the perfect-match (PM) rate for row identifiers (e.g., object identifiers) and column identifiers (i.e., column names). The proposed step-by-step framework consistently outperforms a direct-inference baseline, while the self-correction module consistently reduces execution errors. For Claude Opus 4.6, PM performance on row (column) identifiers is high for simple queries, reaching 0.97 (0.94), and decreases with query complexity to 0.44 (0.72) for medium queries and 0.59 (0.49) for hard queries. Among the thirteen evaluated models, the best-performing LLMs for the text-to-SQL task are Claude Opus 4.6, Gemini 2.5 Pro, Gemini 3 Flash, and GPT-5.2-Codex.","published":"2026-06-16T16:12:16Z","updated":"2026-06-16T16:12:16Z","categories":["astro-ph.IM","cs.AI"],"primary_category":"astro-ph.IM","arxiv_url":"https://arxiv.org/abs/2606.18108v1","pdf_url":"https://arxiv.org/pdf/2606.18108v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.17871","versioned_id":"2606.17871v1","title":"StepGuard: Guarding Web Navigation via Single-Step Calibration","authors":["Zhihao Cui","Yuchen Zhang","Xiyang Sun","Yaxiong Wang","Li Zhu","Jinpeng Hu","Liu Liu","Mengjia Li","Yujiao Wu"],"abstract":"Web navigation requires agents to follow natural language goals, interact with web pages, and produce accurate answers. While recent advances leverage vision-language models and reinforcement learning, existing methods still suffer from single-step fragility due to reward misalignment and error propagation. To tackle the reward entanglement, we design Dynamic Dual-Policy Optimization (DDPO), which dynamically switches between a navigation-first mode for exploration and an answer-first mode for question-answering to mitigate reward conflict. To calibrate the single-step error, we propose Confidence-Guided Adaptive Navigation Reflection (CANR), a mechanism that estimates per-step confidence, triggers reflection only when necessary, and uses contrastive rewards to encourage self-correction to calibrate the single-step inaccuracy. With the above as the main components, we finally develop our StepGuard, a new framework of Guarding Web Navigation via Single-Step Calibration. Experiments demonstrate that our approach significantly improves navigation and answer accuracy, setting new state-of-the-art performance on standard web navigation benchmarks.","published":"2026-06-16T12:42:09Z","updated":"2026-06-16T12:42:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.17871v1","pdf_url":"https://arxiv.org/pdf/2606.17871v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.17803","versioned_id":"2606.17803v1","title":"Continual Self-Improvement with Lightweight Experiential Latent Memories","authors":["Vaggelis Dorovatas","Nancy Kalaj","Rahaf Aljundi"],"abstract":"Large language models achieve strong reasoning performance by scaling inference-time compute, yet remain fundamentally stateless, discarding the rich, self-produced reasoning traces generated during this process. We investigate whether models can instead learn online from this experience, converting transient computation (reasoning traces) into persistent reusable knowledge, and without external supervision or access to future data. We show that In-Context Learning (ICL) over raw reasoning traces fails to generalize, reflecting a fundamental limitation of token-level reuse: individual traces lack the abstraction needed for transfer, even after refinement (e.g. self-reflection). In contrast, drawing inspiration from recent works on unsupervised reinforcement learning, we find that lightweight per-instance training with self-generated test-time signals (majority voting) as rewards yields substantial gains, often surpassing full-dataset offline training, motivating a shift from raw traces to learned latent representations. Building on this insight, we propose an online method that distills inference-time compute spent on encountered problems into compact modular latent memories capturing the underlying reasoning structure. These memories are stored and retrieved for future inputs, enabling continual improvement while avoiding catastrophic forgetting through modular design. Importantly, our method is highly efficient, parametrized as extremely lightweight soft prompt memories (~0.001% of model parameters) and trained with only a few gradient steps, yet achieving performance competitive with full parametric updates and offline training. Across challenging mathematical reasoning benchmarks, our approach significantly outperforms zero-shot and raw data ICL baselines, while transferring effectively across datasets.","published":"2026-06-16T11:27:28Z","updated":"2026-06-16T11:27:28Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.17803v1","pdf_url":"https://arxiv.org/pdf/2606.17803v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.30655","versioned_id":"2606.30655v1","title":"Toward AI-Resilient Assessment in Computer Science Courses in an AI-Native World","authors":["Anshumali Shrivastava"],"abstract":"AI-native course assessments in senior computer science courses and related fields should grade students by \\emph{AI-resilient skill}: the ability to achieve outcomes beyond a strong AI baseline. Such assessments should allow students to use AI freely, while reducing the extent to which greater private AI budget or more intensive AI use, by itself, becomes a grading advantage. This paper proposes a minimal formal framework for this goal. The framework specifies a real task, an executable evaluator, a declared AI-native Pareto frontier, and a grading rule based on Pareto surplus. The central claim is simple: Pareto surplus provides a measurable, protocol-relative certificate that a submitted artifact achieves a tradeoff not already supplied by the declared AI baseline, and grading by this surplus is AI-resilient with respect to that baseline. Interpreting surplus as evidence of student skill requires the surrounding assessment protocol--for example, design reports, ablations, prompt traces, oral checks, or reproducibility explanations--but the grading certificate itself is behavioral and executable. The framework is then extended to practical complications, including self-improving AI loops, budget neutrality, server-mediated feedback, and prompt-based red teaming. As a concrete instantiation, we describe an AI-resilient approximate-membership assignment centered on Bloom filters for COMP 480/580 at Rice University, designed to test whether students can improve beyond AI-generated implementations.","published":"2026-06-16T04:54:15Z","updated":"2026-06-16T04:54:15Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2606.30655v1","pdf_url":"https://arxiv.org/pdf/2606.30655v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.17175","versioned_id":"2606.17175v1","title":"Self-Generated Error Training for Token Editing in Diffusion Language Models","authors":["Lin Yao"],"abstract":"Token-to-token (T2T) editing lets LLaDA2.1 revise committed tokens during block-diffusion decoding. The released recipe trains this editor on random vocabulary corruptions, but at inference the editor sees the model's own fluent, high-confidence draft errors instead. We study this training-inference mismatch and propose self-generated T2T, which performs a no-gradient draft pass, fills masked positions with predicted tokens, and supervises recovery in a second pass under these self-generated corruptions. We implement the update as a short LoRA continued-pretraining pass on LLaDA2.1-mini and evaluate on several benchmarks under the official Q-Mode T2T procedure with unchanged inference parameters. The method generally improves accuracy while reducing T2T edit intensity, mitigating failure modes such as final-digit transcription errors after otherwise correct reasoning and excessive self-correction before short factual answers.","published":"2026-06-15T18:13:54Z","updated":"2026-06-15T18:13:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.17175v1","pdf_url":"https://arxiv.org/pdf/2606.17175v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.17056","versioned_id":"2606.17056v1","title":"The Value Axis: Language Models Encode Whether They're on the Right Track","authors":["Nick Jiang","Isaac Kauvar","Jack Lindsey"],"abstract":"We investigate whether language models internally track the value of their current trajectory, defined as the likelihood that their ongoing strategy will achieve their goals. Using synthetic, in-context reinforcement learning data, we construct a \"value\" axis for Qwen3-8B. We find that activations along this axis distinguish between high vs. low verbalized confidence, rollouts without and with backtracking, and correct vs. corrupted code. Steering towards high value causally suppresses self-correction and reduces explanatory verbosity, while steering towards low value induces backtracking and exploration. We demonstrate that direct preference optimization (DPO) can increase the internal value of rewarded behaviors (e.g. use a certain word), causing the model to act more confidently after exhibiting them. Finally, we apply the value axis to study in-the-wild settings. For example, we find that Qwen assigns low value to politically sensitive chat queries after post-training and that supervised fine-tuning increases internal confidence within the training domain. Our results suggest that language models linearly encode an estimate of expected goal success that modulates their confidence in pursuing a direction.","published":"2026-06-15T17:59:58Z","updated":"2026-06-15T17:59:58Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.17056v1","pdf_url":"https://arxiv.org/pdf/2606.17056v1","comment":"Code repository: https://github.com/nickjiang2378/value-axis","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.17024","versioned_id":"2606.17024v1","title":"ExpRL: Exploratory RL for LLM Mid-Training","authors":["Violet Xiang","Amrith Setlur","Chase Blagden","Nick Haber","Aviral Kumar"],"abstract":"Sparse reward reinforcement learning (RL) has become a standard tool for improving LLM reasoning, but its success depends critically on the coverage present in the base model. In practice, models are often primed for RL through \\emph{mid-training} on curated reasoning traces that teach useful primitive skills such as decomposition, verification, or self-correction. Although effective, this strategy requires manually specifying what the model should learn, and it remains unclear whether such primitive coverage is enough for much harder problems, which require combining these skills into broader solution strategies. We study a more automated approach: \\emph{RL-based mid-training} using large corpora of human-written question-answer data. Rather than treating reference solutions as targets to imitate, our method, ExpRL, uses them as \\emph{reward scaffolds}: references are hidden from the policy and used only to construct problem-specific grading rubrics for judging on-policy reasoning traces. The policy samples from the original problem prompt, while an LLM judge compares the sampled reasoning trace against the reference solution and assigns outcome-level or process-level dense rewards. This lets ExpRL reinforce partial progress, useful intermediate reductions, and productive reasoning behaviors that sparse final-answer rewards often fail to upweight. On challenging math reasoning tasks, ExpRL yields stronger RL priming than SFT, sparse-reward GRPO, and self-distillation, and provides a better initialization for subsequent sparse-reward RL. Additional mixed-domain experiments further suggest that ExpRL can extend beyond the original math-only setting.","published":"2026-06-15T17:50:44Z","updated":"2026-06-15T17:50:44Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.17024v1","pdf_url":"https://arxiv.org/pdf/2606.17024v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.28370","versioned_id":"2606.28370v1","title":"Conversational Query Engine for Mixed-Modality Heterogeneous Enterprise Data Sources","authors":["Darshita Rathore","Vineet Kumar","Vaibhav Singal","Ankur Vivek Singh","Anindya Moitra"],"abstract":"Enterprise business intelligence queries span structured warehouses and unstructured document repositories -- modalities with fundamentally different access methods, cost profiles, and correctness semantics. Existing AI-enabled interfaces force users to select the right tool: NL2SQL systems cannot reason over slide decks, and RAG pipelines lack access to live warehouse tables. We present COGNI, a production conversational BI system that treats natural-language analytics as a heterogeneous query processing problem, organized as four architectural layers. First, an indexing layer implements slide-adaptive chunking -- recursive chunking for plain-text slides, hierarchical chunking for structured content such as tables, charts, and key-value blocks - achieving $88.3\\%$ on our internal enterprise benchmark. Second, a routing layer built on a LoRA fine-tuned Qwen-2.5-1.5B-Instruct model that produces a dual output - modality decision and complexity assessment at $93.8\\%$ accuracy and approximately $7\\times$ lower cost than frontier-model. Third, a retrieval layer executes complexity-adaptive pipelines: a self-correcting NL2SQL agent at $93.9\\%$ G-Eval, and Recursive Language Models reaching $91.0\\%$ on multi-hop synthesis queries. Finally, a caching layer validates query equivalence across multiple dimensions beyond embedding similarity, achieving zero false cache hits and $8.4\\times$ latency reduction.","published":"2026-06-15T17:02:22Z","updated":"2026-06-15T17:02:22Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2606.28370v1","pdf_url":"https://arxiv.org/pdf/2606.28370v1","comment":"Accepted at Agent4IR @ KDD2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.16047","versioned_id":"2606.16047v1","title":"From Argument Components to Graphs: A Multi-Agent Debate with Confidence Gating for Argument Relations","authors":["Jakub Bąba","Jarosław A. Chudziak"],"abstract":"Large Language Models (LLMs) are increasingly assessed and utilized in the field of Argument Mining (AM), thanks to their strong general reasoning capabilities. However, standard training-free models often miss sophisticated details, specifically in contexts where two parts of the text have to be analyzed together. Furthermore, self-correction mechanisms tend to reinforce initial hallucinations in reasoning. Overcoming these limitations typically requires expensive, domain-specific supervised fine-tuning. Recent work has shown that a multi-agent paradigm can address such weaknesses for the component classification task through dialectical refinement with a Proponent-Opponent-Judge architecture, setting a promising direction for training-free approaches in the field. In this paper, we extend and evaluate this framework on the Argument Relation Identification and Classification (ARIC) task, reformulating it as a debate over component pairs. Besides that, we introduce a confidence gating mechanism that enables debating only on the uncertain cases and accepting the initial prediction when confidence is high. On the UKP Argument Annotated Essays v2 corpus, we demonstrate that the selective debate achieves the highest Macro F1 among all training-free methods, while debate over all samples degrades performance below that of one of the baselines. All generative approaches also outperform fine-tuned RoBERTa models on Macro F1, suggesting that the under-representation of the Attack class was more damaging to supervised fine-tuning than to inference-only models. Additionally, our framework produces human-readable debate transcripts, offering interpretability absent from both single-agent and supervised classifiers.","published":"2026-06-14T22:33:54Z","updated":"2026-06-14T22:33:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.16047v1","pdf_url":"https://arxiv.org/pdf/2606.16047v1","comment":"Accepted for publication in the proceedings of KES 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.15994","versioned_id":"2606.15994v1","title":"Agentic Framework for Deep Learning workload migration via In-Context Learning","authors":["Qiyue Liang","Steven Ingram","George Vanica","Andi Gavrilescu","Newfel Harrat","Hassan Sipra","Sethuraman Sankaran"],"abstract":"Translating deep learning models from PyTorch's flexible, object-oriented design to JAX's functional, stateless setup is usually a manual and error-prone task. Automated migration is challenging because Large Language Models (LLMs) struggle with strict and dynamic API alignment and are prone to mistakes for exacting operations. We propose a fully autonomous system that combines In-Context Learning (ICL) with oracle-driven self-debugging. First, we curated an ICL context that serves as a strict reference for idiomatic JAX styling and test case generation. Second, instead of depending on the LLM to deduce mathematical outputs, we run the source PyTorch modules to get their actual dynamic tensor states. This creates an unchangeable execution oracle. We then use an autonomous agentic loop to synthesize tests based on the oracle data. The test cases are executed repeatedly, and the traceback is sent back to the LLM for self-correction. Ablations show that combining ICL references with oracle grounding and self-debugging greatly outperforms pure instructional and basic agentic baselines. This improvement does not add an excessive computational overhead. Our lightweight pipeline achieves 91% numerical equivalence (compared to baseline: 9%, instruction + self-debugging: 27%) on neural modules, providing a highly reliable, scalable blueprint for cross-framework migration. This has been validated across several state-of-the-art models including SAM (segment anything), T5, Code Whisper amongst others showing high numerical equivalency. Code: https://github.com/AI-Hypercomputer/accelerator-agents/tree/main/MaxCode","published":"2026-06-14T19:41:57Z","updated":"2026-06-14T19:41:57Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.15994v1","pdf_url":"https://arxiv.org/pdf/2606.15994v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.15363","versioned_id":"2606.15363v1","title":"APEX: Adaptive Principle EXtraction A Three-Layer Self-Evolution Framework for Production AI Agents","authors":["Ya-Chuan Chen","Tien-Jen Lai","Hsiang-Wei Hu"],"abstract":"Self-improvement in AI agents has emerged as a key research frontier: systems that modify their own prompts, workflows, and decision rules based on accumulated operational experience. The state-of-the-art Self-Harness framework [1] achieves 14--21% improvement on Terminal-Bench-2.0 by mining failure clusters and patching the agent harness. However, Self-Harness optimises only one dimension -- the prompt harness -- leaving behavioural principles and workflow topology unchanged. We propose APEX (Adaptive Principle EXtraction), a three-layer co-evolution framework that simultaneously evolves: (L1) the harness via failure-mode patching, (L2) behavioural principles via success-trace distillation [2], and (L3) the agent workflow topology via structural fitness-based selection [6]. We implement APEX on Joe [13], a production-grade super AI Agent built on NVIDIA Nemotron and designed as an Edge AI Agent Factory for the NVIDIA Agent Challenge 2026, managing a 15-node compute fleet using 114 real task traces collected over 18 days. APEX achieves an APEX Health Score of 0.570 (+90% vs. baseline 0.300) in a single evolutionary run, distilling 6 novel reusable principles and selecting a research-first workflow topology scoring 0.900 (+20%). Our results demonstrate that multi-dimensional co-evolution substantially outperforms single-axis harness optimisation, at a cost of only 4 LLM calls (~270 s) on a local qwen2.5-coder:32b instance.","published":"2026-06-13T15:47:27Z","updated":"2026-06-13T15:47:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.15363v1","pdf_url":"https://arxiv.org/pdf/2606.15363v1","comment":"8 pages, 1 figure, 4 tables. Evaluated on a production 15-node compute fleet with 114 real task traces. Code available at https://aispark.airlive.com/joe-hackathon/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.15096","versioned_id":"2606.15096v1","title":"VGPT-RSI for RH-Adjacent Formal Progress: Boundary Certificates, Verified Finite Lagarias Inequalities, and Explicit Failure Localization","authors":["Zhixin Hu","Tao Xu","Xiaodian Sun","Li Jin","Momiao Xiong"],"abstract":"The Riemann Hypothesis remains one of the central unsolved problems in mathematics. Rather than claiming proof, we investigate whether a verifiable AI-assisted reasoning system can produce reliable, formally checked partial progress while explicitly identifying the remaining mathematical obstructions. We apply the Verifiable Growing Physical Transformer with Recursive Self-Improvement (VGPT-RSI) to two RH-adjacent certification tasks. First, we construct and verify a finite RH-boundary certificate for inequality on a parameterized safe lower curve over a region. The numerical boundary curve is converted into a certificate-backed lower curve, audited using outward-rounded interval arithmetic and Arb/FLINT ball arithmetic, and then checked in Rocq/CoqInterval for the parameterized theorem. Second, we initiate a formal Lagarias-route certificate. Lagarias criterion states that RH is equivalent to the global inequality. We formalize the finite quantity and produce a Coq-checked finite certificate. The final system identifies the exact unresolved mathematical bottlenecks: formalizing the Lagarias equivalence, proving the global tail theorem beyond any finite cutoff, and potentially reducing counterexamples to colossally abundant or related extremal integers. These results demonstrate that VGPT-RSI can produce certified RH-adjacent formal progress, organize proof dependencies, and avoid overclaiming when the remaining obstruction is genuinely mathematical.","published":"2026-06-13T04:12:25Z","updated":"2026-06-13T04:12:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.15096v1","pdf_url":"https://arxiv.org/pdf/2606.15096v1","comment":"31 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.14629","versioned_id":"2606.14629v1","title":"When Good Verifiers Go Bad: Self-Improving VLMs Can Regress on New Tasks","authors":["Jianzhe Lin"],"abstract":"Verifier-driven self-DPO is a common recipe for self-improving production visual-language models. In this setup, a frozen verifier scores candidate generations, the top- and bottom-scoring candidates form a preference example, and DPO updates the learner. The deployment-time assumption is monotone: a stronger verifier should yield a stronger student. We show that this assumption can fail because verifier quality is highly task-specific. On a four-rung open-source verifier ladder across MathVista, MMMU, and BLINK, the same verifiers that are above-threshold and improve a Qwen-3-VL-2B student on MathVista become sub-threshold on MMMU, where their task-rubric accuracy drops to 8% to 23%. In this regime, every verifier we tested silently regresses the student, producing drops of 3.4 to 10.9 percentage points below the frozen baseline while the DPO training loss continues to decrease. The regression replicates on a second student, Qwen-2.5-VL-3B. Moreover, within the failure regime, damage is confidence-inverted: the more accurate-but-still-wrong verifier causes larger regression than a near-random verifier, suggesting that progress-gated replay amplifies confidently wrong preference pairs. We give a compact mechanistic explanation via a variance theorem for progress-gated replay and its direction-mismatch failure mode. The deployment message is operational rather than purely diagnostic: before running any verifier-driven loop, teams should measure target-task rubric accuracy, rank verifiers by target-task rubric quality rather than parameter count, and treat diminishing returns in above-threshold regimes as a verifier-side compute budget cap.","published":"2026-06-12T16:55:30Z","updated":"2026-06-12T16:55:30Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2606.14629v1","pdf_url":"https://arxiv.org/pdf/2606.14629v1","comment":"12 pages, 2 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.14502","versioned_id":"2606.14502v1","title":"From Chatbot to Digital Colleague: The Paradigm Shift Toward Persistent Autonomous AI","authors":["Yongheng Zhang","Ziang Liu","Jiaxuan Zhu","Shuai Wang","Xiangqi Chen","Haojing Huang","Jiayi Kuang","Siyu Chen","Ao Shen","Hao Wu","Qiufeng Wang","Qian-Wen Zhang","Junnan Dong","Wenhao Jiang","Ying Shen","Hai-Tao Zheng","Yinghui Li","Di Yin","Xing Sun","Philip S. Yu"],"abstract":"Large Language Models (LLMs) are undergoing a fundamental transformation from conversational generators into integrated AI systems capable of reasoning, action, memory, and self-improvement. We conceptualize this transition as a shift from Chatbot to Digital Colleague: from conversational answers to persistent work. We organize this transition along two tightly coupled dimensions. First, at the cognitive core level, LLMs are advancing from Chatbot-era \"fast thinking\" systems driven by next-token prediction toward Thinking LLMs that leverage inference-time computation, Chain-of-Thought reasoning, reflection, process supervision, and reinforcement learning to support more deliberate and reliable cognition. Second, at the tool-augmented task execution level, LLMs are progressing from tool-calling Agents that invoke external resources in an ad hoc manner toward OpenClaw-style workstation systems (OpenClaw) equipped with persistent Workspaces, skills, verification loops, and governance. The \"Workspace + Skill\" paradigm makes episodic tool use colleague-like via state persistence, reusable procedures, task closure, and experience reuse. We examine data construction shifts from instruction-response pairs to State-Action-Observation trajectories and evaluation from static benchmarks to sandboxed, auditable, self-evolving AI ecosystems.","published":"2026-06-12T14:33:55Z","updated":"2026-06-12T14:33:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.14502v1","pdf_url":"https://arxiv.org/pdf/2606.14502v1","comment":"The paper is available on the project website: https://from-chatbot-to-digital-colleague.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.14302","versioned_id":"2606.14302v1","title":"Retrospective Progress-Aware Self-Refinement for LLM Agent Training","authors":["Xinbei Ma","Congmin Zheng","Jiyang Qiu","Jiale Hong","Yao Yao","Xiangmou Qu","Jiaxin Yin","Xingyu Lou","Jun Wang","Weiwen Liu","Weinan Zhang","Zhuosheng Zhang","Hai Zhao"],"abstract":"LLM-based agents trained with reinforcement learning optimize step-wise action prediction but lack metacognitive awareness of task progress, inducing a gap that hinders long-horizon scaling. A pilot study reveals that online progress prompting hurts performance while retrospective demonstrations help, yet this capability cannot emerge from outcome-reward training alone. We present RePro, Retrospective Progress-Aware Training, a framework that trains agents to self-generate progress signals via a forward-then-reflect rollout paradigm: the agent executes actions online, then retrospectively reassesses its step-wise progress given the completed trajectory and known outcome. RePro initializes with a Retrospection Warmup that teaches reflection format from minimal external demonstrations, then further trains through RePro-PO with a composite reward that produces self-generated signals without continuous external supervision. Experiments on WebShop, ALFWorld, and Sokoban show that RePro enhances the Qwen family's performance, with up to $12\\%$ absolute success rate gains.","published":"2026-06-12T09:38:47Z","updated":"2026-06-12T09:38:47Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.14302v1","pdf_url":"https://arxiv.org/pdf/2606.14302v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.14211","versioned_id":"2606.14211v1","title":"Closing the Reflection Gap: A Free Calibration Bonus for Agentic RL","authors":["Yinglun Zhu"],"abstract":"LLMs are increasingly deployed as agents that interact with external environments and observe feedback such as execution results, error messages, and tool outputs. A well-functioning agent should be able to leverage this feedback to accurately assess its own performance. Yet we find a persistent reflection gap: LLM agents tend to mis-assess their own outputs after observing concrete environment feedback -- even for questions they correctly answered -- and standard RL barely helps due to a credit-assignment mismatch. To close this gap, we propose RefGRPO, a simple yet effective fix that augments standard RL algorithms with two key ingredients: a free calibration bonus computed by contrasting the agent's own reflection with the actual outcome (requiring no additional reward model, LLM judge, or external annotation), and a dynamic schedule on its coefficient. Compared to standard RL baselines, our method simultaneously improves reflection calibration (e.g., reduces underconfidence rate $44.4\\% \\to 7.7\\%$) and task accuracy (e.g., $75.1\\% \\to 76.5\\%$) on text-to-SQL across five benchmarks. The resulting calibrated reflection turns the agent into its own verifier grounded in environment feedback, which further enables (i) better self-improvement that uses reflections as pseudo-rewards without outcome supervision, and (ii) more effective test-time selective prediction by committing only to rollouts flagged as correct.","published":"2026-06-12T07:47:15Z","updated":"2026-06-12T07:47:15Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.14211v1","pdf_url":"https://arxiv.org/pdf/2606.14211v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.14113","versioned_id":"2606.14113v1","title":"Simulating Students' Java Programming Errors with Large Language Models","authors":["Ali Keramati","Jie Cao","Iman Mohammadi","Mark Warschauer","Yang Shi"],"abstract":"Understanding student errors in the programming is a cornerstone of programming education, yet obtaining a representative set of student errors for any newly designed task remains slow and costly, since authentic submissions only accumulate after extensive classroom deployment. This paper explores whether large language models (LLMs) can serve as scalable proxies for students by simulating realistic logical errors in code submissions. Using the CodeWorkout dataset of 74,000+ unique student Java submissions across 37 problems, we evaluate five LLMs under three mainstream prompting strategies: Input-Output (IO), Chain-of-Thought (CoT), and iterative Self-Refine. We assess performance along two key dimensions: diversity (the range of distinct error patterns) and alignment (alignment with authentic student mistakes), and examine how these vary by struggling level of programming tasks. Our quantitative findings reveal that while all models generate diverse errors, their alignment to human submissions diverges: Claude Sonnet 4 achieves the most balanced performance. In addition, we conducted a blinded expert annotation study (N = 401) comparing synthetic and authentic errors. This qualitative analysis confirms that the generated errors are functionally indistinguishable from authentic student errors. Moreover, higher-struggling-level problems elicit more diverse but less student-like errors. These results highlight trade-offs in using LLMs to simulate human learners and suggest design considerations for integrating synthetic errors into teachable agents, intelligent tutoring systems, and large-scale learning analytics.","published":"2026-06-12T04:51:49Z","updated":"2026-06-12T04:51:49Z","categories":["cs.SE","cs.CL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.14113v1","pdf_url":"https://arxiv.org/pdf/2606.14113v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.13156","versioned_id":"2606.13156v2","title":"Iterative Visual Thinking and the Self-Correction Mirage in VLM Grounding","authors":["Animesh Tripathy","Aswanth Krishnan"],"abstract":"Letting a vision-language model (VLM) think longer at test time has driven much recent progress. A natural way to bring this to spatial grounding is visual self-correction: the model predicts a bounding box, sees it rendered on the image, and refines it over several steps. We build a faithful instance of this idea, Iterative Visual Thinking (IVT), with a two-phase recipe: a supervised warm-up in which the base model's own predictions serve as realistic errors that a teacher VLM turns into corrective reasoning traces (yielding training data without human annotation), followed by GRPO with a simple IoU reward. Measured the way such systems are usually reported, it works: the trained model surpasses the single-shot base by +2.4pp Acc@0.5. We show this gain is a measurement mirage. The reported number silently keeps, per sample, the trajectory step closest to the ground-truth box: an oracle that needs the very answer it predicts. Re-scored under deployable, label-free stopping rules the improvement vanishes, and the best policy is not to iterate at all: stopping at step 0 matches the base and beats every shippable rule. The cause is a verification failure, since the model can generate a better box somewhere in its trajectory but cannot identify it. Self-verification confidence correlates only weakly with correctness (r about 0.22), and a counterfactual overlay shows the loop reacts to the presence of a rendered box rather than its correctness. We distill the lesson into an honest-trajectory evaluation protocol: accuracy under fixed label-free policies plus an explicit oracle-shippable gap.","published":"2026-06-11T10:27:29Z","updated":"2026-07-06T07:23:42Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.13156v2","pdf_url":"https://arxiv.org/pdf/2606.13156v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.12232","versioned_id":"2606.12232v1","title":"Re-evaluating Confidence Remasking in Masked Diffusion Language Models","authors":["Stipe Frkovic","Metod Jazbec","Dan Zhang","Christian A. Naesseth","Ilija Bogunovic","Eric Nalisnick"],"abstract":"Masked diffusion language models (dLLMs) have recently emerged as a competitive alternative to autoregressive language models, with the promise of faster inference via parallel token generation. A notable limitation of the masked formulation, however, is that once a token has been unmasked it can no longer be revised, leaving dLLMs vulnerable to early sampling mistakes. To address this, a growing body of work has sought to extend masked dLLMs with self-correcting (remasking) capabilities. One appealing subset of these methods does so in a training-free, post-hoc manner based on token confidences, with encouraging early reported results. In this work, we revisit the empirical evaluation of a representative post-hoc remasking method, WINO [Hong et al., 2026], and find that under standard decoding settings (shorter block lengths) it brings little-to-no benefit over confidence-based unmasking alone [Wu et al., 2025]. Extending the evaluation to non-greedy decoding, we find that while confidence-based remasking can mitigate errors introduced by increased stochasticity to some extent, it also exacerbates the diversity collapse previously reported for confidence-based unmasking. Overall, our results show that the benefits of post-hoc confidence-based remasking are highly setting-dependent, underscoring the need for a more comprehensive evaluation framework.","published":"2026-06-10T15:41:26Z","updated":"2026-06-10T15:41:26Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.12232v1","pdf_url":"https://arxiv.org/pdf/2606.12232v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.12018","versioned_id":"2606.12018v1","title":"MODF-SIR: A Multi-agent Omni-modal Distilled Framework for Social Intelligence Reasoning","authors":["Shang Ma","Jisheng Dang","Wencan Zhang","Yifan Zhang","Bimei Wang","Hong Peng","Bin Hu","Qi Tian","Tat-Seng Chua"],"abstract":"We propose a multi-agent collaborative framework built upon a lightweight Multimodal Large Language Model (MLLM), specifically designed for social intelligence reasoning. A key feature of our approach is that both the training and inference phases are augmented via knowledge distillation. Within this architecture, multi-modal data pertinent to social intelligence is precisely localized. Furthermore, relevant long-tail events are identified, extracted, and rendered as formatted, explicit text. This formatting strategy prevents critical long-tail information from being overshadowed by head events and environmental noise during the tokenization process. Specifically, we integrate Test-Time Adaptation (TTA) across the entire reasoning pipeline, encompassing the extraction and representation of long-tail events, Chain-of-Thought (CoT) prompting, and self-reflection. This TTA mechanism is also distillation-enhanced, utilizing Low-Rank Adaptation (LoRA) to fine-tune the foundation model exclusively for instance-level reasoning. Extensive evaluations against various open-source and proprietary AI models across multiple benchmarks demonstrate the effectiveness of the proposed framework. With around 30% of training data from IntentTrain, we achieve state-of-the-art results. Codes are available at https://github.com/eeee-sys/MODF-SIR, demo is available at https://huggingface.co/spaces/Harry-1234/MODF-SIR, LoRA is available at https://huggingface.co/Harry-1234/MODF-SIR and the dataset for training router is available at https://huggingface.co/datasets/Harry-1234/IntentRouterTrain.","published":"2026-06-10T12:44:02Z","updated":"2026-06-10T12:44:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.12018v1","pdf_url":"https://arxiv.org/pdf/2606.12018v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.11874","versioned_id":"2606.11874v1","title":"AutoMine Solution for AV2 2026 Scenario Mining Challenge","authors":["Songliang Cao","Jiele Zhao","Yuru Wang","Hao Li","Daqi Liu","Zehan Zhang","Fangzhen Li","Yu Wang","Yue Zhang","Bing Wang","Guang Chen","Hao Lu","Hangjun Ye"],"abstract":"With the development of autonomous driving systems, mining high-value, safety-critical, and planning-relevant scenarios from large-scale driving logs has become essential for data-driven evaluation. In this paper, we propose AutoMine, a robust self-refining scenario mining method based on LLMs and VLMs. AutoMine uses semantics-preserving prompt augmentation to reduce LLM prompt sensitivity, combines robust trajectory atomic functions with VLM-based functions to handle perception noise and open-world visual cues, and refines generated code through execution feedback from real logs. In the Argoverse 2 Scenario Mining Competition at CVPR 2026, AutoMine achieves a HOTA-Temporal score of 36.38 and a Timestamp BA score of 77.21.","published":"2026-06-10T09:58:21Z","updated":"2026-06-10T09:58:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.11874v1","pdf_url":"https://arxiv.org/pdf/2606.11874v1","comment":"CVPR 2026 Scenario Mining Challenge (Temporal Track Winners)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.13705","versioned_id":"2606.13705v1","title":"Can Editing 1 Neuron Fix Repetition Loops in LLMs?","authors":["Aristotelis Lazaridis","Aman Sharma","Dylan Bates","Brian King","Vincent Lu","Jack FitzGerald"],"abstract":"Yes. Can it cure doom loops? Probably not. The Gemma 4 instruction-tuned models share a reproducible failure: on long factual enumeration prompts, such as listing every episode of a TV series, the 88 IAU constellations, or the 151 original Pokemon, they collapse into repetition, either a tight verbatim loop or a list whose entries decay onto a single answer. These loops occur at rates as high as 95% and survive prompt rewording, inference-engine changes, and most sampling adjustments. In this paper we explore whether this behavior is localized enough to remove by weight edits. To localize the cause, we use per-layer ablation and per-neuron attribution, then confirm the strongest candidates with full-generation sweeps. The loops trace to a small set of MLP neurons (or, in the 26B-A4B Mixture-of-Experts model, a few routed experts) which we suppress with static weight edits. These \"surgeries\" can be as small as a single sign-inverted neuron (in the E2B model). The size of the effective edits grows with model scale, but in all cases, the loop patterns can be addressed at normal generation budgets while preserving general-purpose benchmark scores. However, the edits do not solve everything: we also study longer thinking budgets, where the two larger models most visibly enter doom looping, i.e. a non-convergent regime in which the model self-corrects in circles over a fact it cannot recall, exhausting the budget without committing to a final answer. We show this residual failure is reduced but not eliminated by the same edits, and argue it is fundamentally a knowledge-precision problem rather than a removable circuit; weight surgery can delete a loop, but it cannot supply a missing fact. Our results are both a feasibility demonstration, that is, evidence that a concrete generation pathology can be localized to a few parameters and edited out, and a delineation of where that approach stops.","published":"2026-06-09T21:20:57Z","updated":"2026-06-09T21:20:57Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.13705v1","pdf_url":"https://arxiv.org/pdf/2606.13705v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.11324","versioned_id":"2606.11324v2","title":"Embodied-R1.5: Evolving Physical Intelligence via Embodied Foundation Models","authors":["Yifu Yuan","Yaoting Huang","Xianze Yao","Yutong Li","Shuoheng Zhang","Linqi Han","Pengyi Li","Jiangeng Sun","Wenting Jia","Zhao Zhang","Yuhao Liu","Ruihao Liao","Yucheng Hu","Qiyu Wu","Yuxiao Li","Zibin Dong","Fei Ni","Yan Zheng","Shuyang Gu","Yi Ma","Hongyao Tang","Han Hu","Jianye Hao"],"abstract":"We introduce Embodied-R1.5, a unified Embodied Foundation Model (EFM) that integrates comprehensive embodied reasoning capabilities, spanning embodied cognition, task planning, correction, and pointing, within a single architecture toward general physical intelligence. Leveraging three automated data construction pipelines to significantly expand the data coverage of critical capabilities, we build a large-scale data system of over 15B tokens, and design a multi-task balanced RL recipe to alleviate heterogeneous task conflicts. We further introduce a Planner-Grounder-Corrector (PGC) closed-loop framework that enables a single model to autonomously execute and self-correct over long-horizon tasks. With only 8B parameters, Embodied-R1.5 achieves SOTA on 16 out of 24 embodied VLM benchmarks, surpassing leading models like Gemini-Robotics-ER-1.5 and GPT-5.4. Benefiting from the internalized embodied capabilities, Embodied-R1.5 can be fine-tuned into a VLA with only a small amount of data, outperforming leading VLA models like $π_{0.5}$ across 4 popular manipulation benchmark suites. We further conduct extensive zero-shot real-robot experiments, validating performance in instruction following, affordance grounding, articulated object manipulation, and long-horizon complex tasks, demonstrating strong generalization to the physical world. We open-source model weights, datasets, training code, and EmbodiedEvalKit, an evaluation framework tailored for embodied tasks, to facilitate future research in EFMs.","published":"2026-06-09T18:07:50Z","updated":"2026-07-11T14:44:40Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.11324v2","pdf_url":"https://arxiv.org/pdf/2606.11324v2","comment":"Embodied R1.5 technical report. Project page: https://embodied-r.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.11182","versioned_id":"2606.11182v1","title":"EEVEE: Towards Test-time Prompt Learning in the Real World for Self-Improving Agents","authors":["Weixian Xu","Shilong Liu","Mengdi Wang"],"abstract":"In this paper, we propose EEVEE, the first multi-dataset test-time prompt learning framework for LLM agents, enabling test-time prompt learning under real-world task streams. Existing methods are largely designed for single-dataset settings, while real-world applications require models to handle heterogeneous input streams drawn from multiple datasets, domains, and task distributions, limiting their practical applicability. To mitigate cross-dataset interference, EEVEE introduces a router that partitions incoming inputs into task clusters and assigns them to suitable prompt configurations. This design is optimized via a router-prompt co-evolution strategy, which employs interleaved router and prompt learning phases to address their mutual dependency. Experiments across multiple datasets demonstrate that the framework improves robustness under heterogeneous data streams while maintaining single-benchmark learning capability and efficiency. Specifically, EEVEE improves average multi-benchmark scores by 10.38 and 24.32 points over Qwen3-4B-Instruct and DeepSeek-V3.2, surpassing SOTA methods GEPA and ACE by up to 37.2% and 48.2%.","published":"2026-06-09T17:57:16Z","updated":"2026-06-09T17:57:16Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.11182v1","pdf_url":"https://arxiv.org/pdf/2606.11182v1","comment":"19 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.10546","versioned_id":"2606.10546v2","title":"SkillAxe: Sharpening LLM-Authored Agent Skills Through Evaluation-Guided Self-Refinement","authors":["Srishti Gautam","Arjun Radhakrishna","Sumit Gulwani"],"abstract":"Skill documents, structured natural-language instructions that guide Large Language Model (LLM) agents, are critical to modern agent frameworks, yet LLMs struggle to write skills that actually work. On SkillsBench, human-authored skills improve pass rates by 16.2 percentage points, while LLM-authored skills provide no measurable gain. We introduce SkillAxe, a fully unsupervised framework that enables LLMs to iteratively diagnose and refine their own skills. SkillAxe decomposes skill quality into four interpretable dimensions (quality impact, trigger precision, instruction compliance with fault attribution, and solution-path coverage), producing structured improvement briefs that require no ground-truth labels, test suites, or environment rewards. On SkillsBench, SkillAxe improves pass rates by 28\\% relative over unimproved LLM skills and closes 47--67\\% of the gap to human-authored skills. We validate the approach as a continuous improvement engine in the wild on SpreadsheetBench, where a SkillAxe-built skill library learns from past agent trajectories and raises pass rate from 16.0\\% to 52.0\\% using only 22 skills.","published":"2026-06-09T08:14:39Z","updated":"2026-06-10T07:58:45Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2606.10546v2","pdf_url":"https://arxiv.org/pdf/2606.10546v2","comment":"9 pages, under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.20657","versioned_id":"2606.20657v2","title":"A-Evolve-Training: Autonomous Post-Training of a 30B Model","authors":["Zhan Shi","Bing He","Yisi Sang","Hanqing Lu","Benoit Dumoulin"],"abstract":"Post-training a frontier model is normally weeks of human work: proposing data and recipe changes, launching runs, reading evals, deciding what to keep. We report an autonomous system that runs this loop with no human in the loop, post-training a 30B Nemotron across four rounds over multiple weeks. The autonomously produced model reaches a held-out score of 0.86 against the top human submission's 0.87 on the public NVIDIA Nemotron-Reasoning Challenge leaderboard, placing 8th of ~4000 at the time of writing. More striking than the number: the loop detected that its own dev metric had stopped tracking external performance on the weakest domain -- candidates drove dev to record highs without moving the external target -- and revised its own search policy, no longer maximizing dev but seeking interventions that lowered the now-misleading proxy while improving the external target. We treat this as direct, auditable evidence that a scaled autonomous loop can produce discovery, not only optimization: it detected that its measurement frame had become misleading and changed what counted as evidence. We take the operational view that any system worth the \"recursive self-improvement\" label must eventually perform end-to-end post-training of a frontier-class model; this is one datapoint of that bar being cleared. We do not claim a \"first autonomous match\" of human researchers. The claim we make is narrower and auditable: to our knowledge, this is the first publicly reported autonomous post-training run at this scale, where prior public autonomous-ML-research demonstrations sit at GPT-2-class (~124M) budgets. The same system also post-trains the 120B and 550B Nemotron; with no public human baseline there, this shows only that the loop closes at that scale, not that its output is competitive -- infrastructure evidence, with the effectiveness claim deferred until a comparable human anchor exists.","published":"2026-06-09T07:23:11Z","updated":"2026-06-25T04:21:07Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.20657v2","pdf_url":"https://arxiv.org/pdf/2606.20657v2","comment":"12 pages,","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.10135","versioned_id":"2606.10135v2","title":"BiWM: Advancing Open-Source Interactive Video World Models with Bidirectional Autoregression","authors":["Shaohao Rui","Xiaofeng Mao","Zhanyu Zhang","Peijia Lin","Yansong Zhu","Yibo Zhang","Haibin Wan","Weijie Ma"],"abstract":"Transitioning bidirectional video diffusion models into an autoregressive paradigm improves the interactivity of video world models, but existing causal pipelines need many stages (control fine-tuning, autoregressive training, causal initialization, few-step distillation) and still trail bidirectional models in quality due to error accumulation. Recent world models such as Yume-1.5 and Matrix-Game-3.0 instead adopt a bidirectional autoregressive approach, gaining fidelity and stable long-horizon rollout from self-correcting error propagation, yet open-source frameworks (e.g., minWM) support only causal models. We present BiWM, the first full-stack framework for interactive video world models under the bidirectional autoregressive paradigm, jointly optimizing generation quality and inference speed. From a pretrained video backbone, BiWM injects camera control by fine-tuning, then runs a few-step Distribution Matching Distillation (DMD) stage that turns the backbone into an action/camera-controllable world model: just two training stages instead of four in minWM, converging in a few hundred steps on 8xH200 GPUs. A single recipe spans Wan2.1-1.3B, Wan2.2-5B, HunyuanVideo-1.5-8B, and LTX-2.3-22B, and also supports secondary fine-tuning of existing bidirectional models. BiWM enables real-world camera control where minWM loses controllability, integrates pluggable history compression (FramePack-style and PackForcing-style) for long rollouts, and offers an optional NVFP4 4-bit training/inference pipeline. To counter DMD's mode-seeking degradation, we add GAN and mass-covering forward-KL objectives that preserve scene dynamics. We open-source BiWM for resource-constrained research and high-fidelity environment simulation.","published":"2026-06-08T20:08:41Z","updated":"2026-06-10T12:21:54Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.10135v2","pdf_url":"https://arxiv.org/pdf/2606.10135v2","comment":"After the paper was posted, we discovered that several visualization results were produced using wrong configuration settings during runtime. This error affects the reliability of the presented visual comparisons. Additionally, further optimization of the design is needed. We therefore request to withdraw this version and will submit a corrected and improved version later","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.09774","versioned_id":"2606.09774v2","title":"Auto-Configuring Scientific Simulators with Lightweight Coding-Agent Adapters","authors":["Matthew Ho","Brian Liu","Jixuan Chen","Audrey Wang","Lianhui Qin"],"abstract":"Configuring an advanced scientific simulator, translating a modeling goal into a valid, runnable input deck, is a persistent bottleneck that costs domain scientists hours to days. Input decks are executable interfaces: simulator-specific vocabulary, cross-file references, schema constraints, and validation rules must align before a simulation can run. We show that this bottleneck can be substantially reduced with a lightweight adapter around an off-the-shelf coding agent, rather than a bespoke simulator agent. Coding agents already navigate files, edit code, run commands, and repair outputs; what they lack is the simulator's executable contract, and rebuilding the agent loop risks discarding harness-calibrated tool-use and self-correction behavior. We introduce SIGA, a coding-agent adapter that supplies this contract through retrieval, procedural memory, agent-callable validation, and validation-gated termination while leaving the model and loop frozen. Because this contract is small and external, SIGA also supports adapter self-evolution: prior trajectories can rewrite the adapter contents without modifying the underlying agent. On GEOS, a multiphysics subsurface simulator, SIGA's main gain is reliability: on harder held-out tasks it improves TreeSim from 0.720 to 0.789 and reduces across-run standard deviation by about 16x by preventing empty or invalid decks. In a human calibration, SIGA reaches in about five minutes the deck quality a domain expert reached in about three hours. Transfers to OpenFOAM and LAMMPS show the recipe is portable but interface-dependent: completion gates help when structural completeness is the bottleneck, while memory and retrieval help when value correctness is.","published":"2026-06-08T17:35:17Z","updated":"2026-06-25T18:32:21Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09774v2","pdf_url":"https://arxiv.org/pdf/2606.09774v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.09748","versioned_id":"2606.09748v1","title":"Multi-Turn Evaluation of Deep Research Agents Under Process-Level Feedback","authors":["Rishabh Sabharwal","Hongru Wang","Amos Storkey","Jeff Z. Pan"],"abstract":"Existing benchmarks for deep research agents (DRAs) assess only single-shot outputs, ignoring a key question: can DRAs improve their reports when guided by feedback? To investigate this, we conduct a multi-turn evaluation of DRAs under two feedback settings: self-reflection, in which the agent revises its report without any external diagnostic signal, and process-level feedback, in which the agent receives guidance targeting gaps in its research strategy. To enable process-level feedback, we design Research Gap Inference (RGI), a method that analyzes patterns of satisfied and unsatisfied rubric criteria to infer research-process gaps. Our analysis reveals three key findings: (i) under self-reflection, agents incorporate and regress on rubric criteria at nearly equal rates, yielding negligible net improvement; (ii) a single round of process-level feedback yields substantial gains, raising the normalized score by approximately $8$-$15$ points and yielding a roughly $35$-$40\\%$ incorporation rate; (iii) these gains do not compound over subsequent turns, as agents regress on up to $24\\%$ of previously satisfied criteria when rewriting the full report to address remaining gaps. Even with targeted guidance, reliable multi-turn improvement remains out of reach for the DRA architectures we evaluate. Our code and results are publicly available at https://github.com/sabharwalrishabh/Multi-Turn-Evaluation-of-DRAs.","published":"2026-06-08T17:08:36Z","updated":"2026-06-08T17:08:36Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09748v1","pdf_url":"https://arxiv.org/pdf/2606.09748v1","comment":"Published as a workshop paper at SCALE - ICML 2026 (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.09682","versioned_id":"2606.09682v1","title":"AutoMegaKernel: A Statically-Checked Agent Harness for Self-Retargeting Megakernel Synthesis","authors":["Jaber Jaber","Osama Jaber"],"abstract":"AutoMegaKernel (AMK) compiles a HuggingFace Llama-family model into a single persistent cooperative CUDA kernel that runs the whole forward pass in one launch, with no per-model hand-written CUDA. The contribution is the system, not raw speed. A frozen schedule-IR validator statically certifies deadlock-freedom and race-freedom via static graph checks (not a mechanized proof), so an unsafe agent-proposed schedule is rejected before launch: across 7,160 adversarial schedules (6,091 unsafe) it had zero false-accepts and accepted all 360 real lowerings. The same source retargets sm_80/sm_90/sm_120 from one codebase, auto-generates correct megakernels for 10 of 10 supported models, and on a real SmolLM2-135M checkpoint reproduces HuggingFace greedy decode token-for-token (perplexity match 2.5e-7). An unattended, agent-drivable autoresearch loop self-improves the megakernel over its own baseline (1.25-1.72x). A search-found int8 (W8A16) megakernel beats CUDA-graphed cuBLAS bf16 at batch-1 decode across NVIDIA's datacenter inference fleet: L4 up to 1.33x, the current-gen L40S 1.25-1.27x, A10G up to 1.08x at scale, and the consumer RTX 5090 1.19-1.23x. The ordering is not a clean function of bandwidth (the 864 GB/s L40S beats the 600 GB/s A10G); the divide is inference-class vs training-class. AMK trails cuBLAS on the high-bandwidth training-class A100/H100, where the harness localizes the cross-SM-sync bottleneck; we report the gap plainly. This is a precision-asymmetric (W8A16 vs bf16) comparison at decode position 0; the largest real checkpoint is TinyLlama-1.1B. Code and the harness: https://github.com/RightNow-AI/AutoMegaKernel","published":"2026-06-08T16:02:03Z","updated":"2026-06-08T16:02:03Z","categories":["cs.LG","cs.DC","cs.PF"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.09682v1","pdf_url":"https://arxiv.org/pdf/2606.09682v1","comment":"18 pages, 5 figures. Open-source code, data, and agent harness: https://github.com/RightNow-AI/AutoMegaKernel","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.09663","versioned_id":"2606.09663v1","title":"From 0-to-1 to 1-to-N: Reproducible Engineering Evidence for MetaAI Recursive Self-Design","authors":["Dun Li","Jiatao Li","Hongzhi Li"],"abstract":"Recursive self-design refers to AI-assisted modification of the mechanisms by which an AI system is built, evaluated, and improved. This paper treats MetaAI not as a mature paradigm, but as a working term for a human-seeded, AI-expanded development pattern in which the design space itself becomes a target of modification. We propose an operational evidence framework with four criteria: inspectable target system, meta-level modifier, feedback-directed selection, and recursive continuation. We then map public systems, including Darwin Goedel Machine (DGM), STOP, Goedel Agent, and ShinkaEvolve, against these criteria. DGM provides the most direct currently reported evidence: its published results show improvement from 20% to 50% on SWE-bench Verified and from 14.2% to 30.7% on full Polyglot after 80 iterations, with ablations suggesting that both open-ended exploration and self-improvement contribute. Finally, we provide MetaAI-Mini, a reproducible HumanEval-based protocol and codebase. Because no completed model run is included in this build, MetaAI-Mini is reported as a protocol rather than as an experimental result.","published":"2026-06-08T15:45:15Z","updated":"2026-06-08T15:45:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09663v1","pdf_url":"https://arxiv.org/pdf/2606.09663v1","comment":"6 pages, 2 figures, 7 tables. Supplementary code: https://github.com/DunLi-Tsinghua/MetaAI-Mini","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.09520","versioned_id":"2606.09520v2","title":"Closing the Prior-Posterior Loop: Self-Reflective Molecular Design with Analysis-Driven LLM Iteration","authors":["Junyi Gong","Zijie Qiu","Ben Zhong Tang"],"abstract":"Can a general-purpose large language model design molecules with the precision of a seasoned chemist? Current LLM-based frameworks answer this question with scalar feedback loops - generate, score, reject - that amount to informed trial-and-error. Here we show that replacing a single number with the full physicochemical rationale from first-principles calculations transforms the LLM from a stochastic sampler into a causal reasoner. Our system couples retrieval-augmented generation with a self-reflection module that feeds orbital energies, atomic charges, and electron densities - rather than compressed scores - back into the design loop. On HOMO-LUMO gap targets from 2.0 to 5.0 eV, this structure-property-relationship (SPR) reflection achieves a deviation as low as 0.0014 eV with a 100% success rate under the SPR+RAG configuration, consistently outperforming scalar-feedback and non-reflective baselines in median and mean deviation. The framework generalizes seamlessly to dipole-moment design, synthetic accessibility optimization, and molecular docking, and proves robust across 7 distinct LLM backbones. These results establish a new paradigm: when the model understands not only that a molecule fails, but why, iterative molecular design becomes genuinely mechanistic.","published":"2026-06-08T14:09:40Z","updated":"2026-06-18T20:24:58Z","categories":["physics.chem-ph","cs.AI"],"primary_category":"physics.chem-ph","arxiv_url":"https://arxiv.org/abs/2606.09520v2","pdf_url":"https://arxiv.org/pdf/2606.09520v2","comment":"3 tables, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08779","versioned_id":"2606.08779v2","title":"Reformulate LLM Reinforcement Learning for Efficient Training under Black-box Discrepancy","authors":["Jiashun Liu","Runze Liu","Xu Wan","Jing Liang","Hongyao Tang","Ling Pan"],"abstract":"Reinforcement Learning (RL) has emerged as a pivotal post-training paradigm, yet it frequently suffers from unpredictable sub-optimum performance or even training collapses. Recent findings attribute these failures to a hidden train-inference discrepancy (or mismatch), stemming from the disparate underlying engines and architecture. We find that the training policy can actively self-correct such a discrepancy when provided with an appropriate learning signal. Then, we further empirically identify a discrepancy tolerance region: within this region, aggressively narrowing the discrepancy can suppress policy exploration and reduce learning efficiency, whereas outside this region, reducing excessive discrepancy improves optimization consistency and raises the achievable local performance ceiling. According to such findings, we formulate this problem as a Discrepancy-Constrained Markov Decision Process (DCMDP), where reward maximization is coupled with a constraint that aligns training-Inference behavior, achieving stable dual-objective optimization. To adaptively balance performance improvement and discrepancy control, we introduce a Lagrangian relaxation mechanism that dynamically adjusts the relative weight of the two objectives according to the current degree of discrepancy violation. This enables stable dual-objective optimization: the policy is allowed to explore freely within the tolerance region, while being guided back when the discrepancy exceeds the safe boundary. Empirically, DCMDP significantly improves the performance of 8B dense model (Qwen-3-8b) and 30B Mixture-of-Expert model (Qwen-3-30bA3b), and enables a heterogeneous training paradigm, where LLMs can be optimized in high-fidelity training setup while being explicitly aligned for low-cost, resource-constrained inference deployment.","published":"2026-06-07T18:49:33Z","updated":"2026-06-09T07:53:57Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.08779v2","pdf_url":"https://arxiv.org/pdf/2606.08779v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08625","versioned_id":"2606.08625v2","title":"From Holistic Evaluation to Structured Criteria: Rubrics Across the Evolving LLM Landscape","authors":["Hao Chen","Ziyu Han","Yukun Yan","Qingfu Zhu","Maosong Sun","Wanxiang Che"],"abstract":"As Large Language Models (LLMs) advance toward open-ended autonomous agents, the mechanisms used to evaluate and guide their behavior must evolve accordingly. This work introduces the rubric as a unifying framework capturing this evolution, characterizing rubrics as a dynamic response to successive LLM paradigm shifts that recurs across otherwise independent efforts in evaluation, reinforcement learning, and safety alignment. We define rubrics as explicit criteria sets that transform complex quality judgments into structured and actionable standards, and demonstrate that their recurrence across these research threads is not coincidental. We systematically organize existing rubric designs, examine their construction and optimization, and analyze their role across evaluation and training. Rubrics manifest at three progressively deeper levels: at the evaluative level, they decompose holistic judgments into verifiable dimensions; at the training level, they serve as dense feedback signals providing process-level guidance where scalar rewards fall short; at the intrinsic level, they emerge dynamically from model behaviors, driving self-improvement. We further assess rubric reliability across generation quality, execution fidelity, theoretical constraints, and security threats, before surveying rubric-based benchmarks across diverse domains. By rendering assessment transparent and decomposable, rubrics translate human value expectations into machine-learnable signals, serving as the enduring bridge between human intentions and machine behavior.","published":"2026-06-07T13:34:55Z","updated":"2026-07-01T14:07:42Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08625v2","pdf_url":"https://arxiv.org/pdf/2606.08625v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08539","versioned_id":"2606.08539v1","title":"AgentTrust: A Self-Improving Trust Layer for AI-Agent Actions","authors":["Chenglin Yang"],"abstract":"AI agents increasingly take consequential actions -- shell commands, cloud operations, and arbitrary tool-calls -- so a trust layer must decide, per action, whether to allow, warn, block, or escalate. We argue that the right way to reason about such a layer is by threat type. Lexical (fixed-signature) threats, where danger lives in a stable token, are decidable by deterministic rules; semantic (intent-dependent) threats, where a benign and a malicious action share the same surface, are out of reach for rules by construction. We make this concrete with a negative proof: a determined, hand-authored cloud rule pack lifts held-out accuracy only 48 to 56% overall and moves the semantic categories by 0pp (data_db 29 to 29, observability 59 to 59, supply_chain 50 to 50), while a strong LLM judge carries exactly those categories. We give the judge a self-learning capability: on a corpus that is mainly semantic attacks it nearly doubles rule accuracy (48% to 83.6-85.2%) with near-zero false-blocks, and this holds across two model providers. We turn this into a self-improving dual-store system: the judge distills a growing deterministic rule floor on lexical threats (cheaper over time) and feeds a guarded RAG memory on semantic threats (a verdict-cache fails -- surface-twins collapse to ~58% -- so a corroboration guard lifts semantic accuracy +13pp, 70 to 84). The result is what sets AgentTrust v2 apart from its static v1 predecessor: a trust layer that self-evolves from its own stream of decisions -- cheaper on the lexical class (it distils its own rules) and smarter on the semantic class (it accrues guarded precedent), while never hard-blocking a benign action. An end-to-end online replay shows the judge-call rate falling (50% to 44%) and judge-domain accuracy rising (71% to 80%), with 0 benign hard-blocks across 45,000 actions.","published":"2026-06-07T09:39:20Z","updated":"2026-06-07T09:39:20Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.08539v1","pdf_url":"https://arxiv.org/pdf/2606.08539v1","comment":"29 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08496","versioned_id":"2606.08496v1","title":"SAEExplainer: Interpreting SAE Features with Activation-Guided Preference Optimization","authors":["Jingyi He","Haiyan Zhao","Ruxue Shi","Yanguang Liu","Xin Wang","Fei Sun","Mengnan Du"],"abstract":"Although Sparse Autoencoders (SAEs) have mitigated the opacity of large language models (LLMs) by decomposing dense representations into sparse features, explaining these features still remains a central challenge. Current explanation methods, however, typically operate within an open-loop paradigm, failing to leverage mechanistic feedback for further refinement. In this paper, we propose SAEExplainer, a training framework utilizes activation scores as an objective reward signal to train the model for self-correction and iterative bootstrapping. By iteratively verifying and correcting foundational explanations through a two-round optimization process, SAEExplainer achieves continuous improvement in its explanatory capabilities. This mechanism significantly reduces explanation hallucinations and reinforces causal triggering patterns. Extensive experiments demonstrate our approach improves upon established baselines across most metrics, especially in causal triggering and discriminative activation.","published":"2026-06-07T07:54:25Z","updated":"2026-06-07T07:54:25Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08496v1","pdf_url":"https://arxiv.org/pdf/2606.08496v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08471","versioned_id":"2606.08471v1","title":"More Yap Less Meaning: Uncovering Self-Improvement Behavior in SLMs","authors":["Marina Igitkhanian","Erik Arakelyan"],"abstract":"Recently, language models have made rapid progress across various domains and applications. However, their capability for self-improvement, i.e., whether they are adept at recognising and correcting flaws in their own reasoning, remains dubious. In this study, we address this question by constructing a sufficiency test to rigorously examine the self-correction capabilities of small language models (SLMs). We propose a minimal three-step self-correction pipeline that collects initial SLM answers, prompts the same model to generate hints for its incorrect responses given the ground truth, and feeds the model the same question with its own feedback to refine the initial answer. We evaluate a variety of instruction-tuned and reasoning SLMs in this experimental setup on arithmetic and logical reasoning benchmarks. Our findings show that SLMs with injected hint sentences yield only a 4.4 percent gain over initial question-answering accuracy. Even though the correct answer was provided alongside the model's incorrect reasoning, the evaluated SLMs fail to understand what was missing in their reasoning and show minimal semantic difference between hints that lead to corrections and ones that do not. Furthermore, our experiments show that longer hints are positively correlated with incorrect final answers, suggesting that longer deliberation on problems can hinder the reasoning process, meaning that SLMs do not necessarily scale in performance with a larger compute budget.","published":"2026-06-07T06:27:37Z","updated":"2026-06-07T06:27:37Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08471v1","pdf_url":"https://arxiv.org/pdf/2606.08471v1","comment":"GEM Workshop at ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08357","versioned_id":"2606.08357v1","title":"Forward-Free Diffusion Language Models","authors":["Haotian Sun","Rushi Qiang","Yuqian Zheng","Bo Dai"],"abstract":"Diffusion language models generate text through iterative denoising, offering a powerful alternative to autoregressive generation. However, discrete language spaces lack a natural neighborhood structure for defining effective perturbations, so some artificial corruption schemes are proposed in the forward process. Such prescribed forward processes often produce states that are mathematically convenient but misaligned with drafts and errors encountered during generation, resulting in degraded sample quality. To address this limitation, we propose FReDA, a forward-free diffusion language model that eliminates the need for a hand-designed forward process. We formulate diffusion language modeling as recursive distribution refinement, in which model-generated drafts serve as implicit intermediate states, and the learned refinement model progressively moves the draft distribution toward the target distribution. Concretely, FReDA refines drafts by proposing candidate draft sequences and either directly performing self-refinement or selecting among parallel candidates via best-of-N refinement. With this design, FReDA is neighborhood-agnostic, model-complexity-aware, and compatible with flexible refinement parameterizations. Extensive evaluations in the sub-8B regime show that FReDA-4B outperforms larger diffusion base models on reasoning and coding benchmarks, achieving absolute gains of up to 15%, while reaching a 1.5-1.8x average speedup over diffusion baselines and scaling effectively with additional refinement computation.","published":"2026-06-06T22:10:46Z","updated":"2026-06-06T22:10:46Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08357v1","pdf_url":"https://arxiv.org/pdf/2606.08357v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08254","versioned_id":"2606.08254v1","title":"SSR: Can Simulated Patients Learn to Stigmatize Themselves? Modeling Self-Stigma through Internal Monologue","authors":["Kunyao Lan","Bingrui Jin","Zichen Zhu","Mengyue Wu"],"abstract":"Simulating patients with large language models (LLMs) is a promising tool for mental health training, but existing approaches fail to capture a key clinical reality: self-stigma. Patients experiencing self-stigma, the internalization of negative stereotypes, often exhibit context-sensitive resistance, such as avoidance, denial, or self-blame, which current models render as static or uniformly compliant behavior. To address this, we introduce a novel simulation framework grounded in the psychological 3A1H model of self-stigmatization. Our core innovation is the creation of a \\textbf{Stigmatized Self-Reflection} (\\textbf{SSR}) dataset, where we augment mental health dialogues with internal monologues that reflect stigma-aware reasoning. By fine-tuning LLMs with this data using a chain-of-thought approach, we train patient agents to dynamically adjust their level and expression of stigma based on conversational triggers. Evaluations demonstrate that our approach significantly outperforms specialized baselines, generating more authentic and situationally appropriate patient responses. This work provides a crucial step towards realistic stigma simulation for clinical training and empathetic dialogue systems.","published":"2026-06-06T16:50:57Z","updated":"2026-06-06T16:50:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08254v1","pdf_url":"https://arxiv.org/pdf/2606.08254v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08245","versioned_id":"2606.08245v1","title":"ZAS-SQL: Distilling Rules from Failures for Zero-Shot Text-to-SQL","authors":["Hongzhou Zheng","Yixin Gou","Wenjia Zhang"],"abstract":"Text-to-SQL translates natural language into executable SQL queries. Few-shot in-context learning methods built upon large language models (LLMs) achieve strong performance, yet their reliance on demonstrations limits cross-domain generalization and consumes substantial context window space. Existing zero-shot methods, lacking effective generation constraints, still fall short of few-shot approaches. We observe that LLM failures in zero-shot Text-to-SQL are not random but exhibit systematic, recurring patterns. Building on this observation, we propose a fully zero-shot Text-to-SQL framework that distills core generation rules from failure cases through a Map-Reduce-based rule distillation pipeline and improves generation quality via three complementary modules: knowledge-augmented schema representation, which supplements missing semantics in Data Definition Language; a rule-driven structured reasoning framework that suppresses structural deviations; and Execution-Guided Early Stopping, which enables low-cost self-correction. On Spider, the proposed framework achieves up to 87.2% and 88.6% execution accuracy on the Dev and Test sets, respectively, establishing a new zero-shot state-of-the-art and surpassing multiple few-shot and fine-tuning methods built upon GPT-4/4o. On the domain-specific dataset UrbanPlan, it achieves 81.3%, confirming that the rule distillation approach generalizes across domains. Moreover, when equipped with a 4B-parameter model, the framework surpasses zero-shot baselines of leading closed-source models, demonstrating strong model generality.","published":"2026-06-06T16:08:40Z","updated":"2026-06-06T16:08:40Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08245v1","pdf_url":"https://arxiv.org/pdf/2606.08245v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08146","versioned_id":"2606.08146v1","title":"SAGE: An LLM-driven Self Reflective Agentic Framework for Fraud Detection","authors":["Yichen Chen","Siying Li","Yuhang Liang","Lijun Wang","Renyang Liu"],"abstract":"Fraud detection in payment, e-commerce, and telecommunications systems requires accuracy at the individual level, robustness under severe class imbalance, and ease of understanding for risk managers. Existing methods fall at least one of these requirements: automated machine learning systems search a fixed numerical space without semantic awareness of the dataset; graph neural network-based methods require pre-defined relational graphs and remain opaque at the individual-decision level; and the design of general-purpose large language model (LLM) agents does not consider the recall and precision constraints specific to real-world fraud detection. In this paper, we propose SAGE, the first end-to-end LLM-driven multi-agent framework for fraud detection. SAGE coordinates three dedicated agents that make decisions based on a six-layer Data Diagnostic Tree (DDT) and a Markov decision process guided by natural-language gradients, automatically optimizing the model under a fraud-specific reward. On five fraud datasets and five LLM backbones, SAGE wins $96.00\\%$ of method--dataset comparisons and improves F1 by an average of $40.86\\%$ over baselines. The code is available at https://github.com/yichenC1c/SAGE.","published":"2026-06-06T12:48:45Z","updated":"2026-06-06T12:48:45Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.08146v1","pdf_url":"https://arxiv.org/pdf/2606.08146v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.08092","versioned_id":"2606.08092v1","title":"When Languages Disagree: Self-Evolving Multilingual LLM Judges","authors":["Xiyan Fu","Wei Lu"],"abstract":"Multilingual LLM-as-a-judge is widely used to evaluate model outputs across languages, but suffers from cross-lingual inconsistency (Fu and Liu, 2025). Existing methods typically treat this inconsistency as noise and mitigate it through voting or aggregation. In this work, we instead show that multilingual inconsistency can provide complementary evaluation signals. Our oracle analysis finds that sampling judgments across languages yields a higher performance upper bound than single-language judging, indicating that different languages potentially include complementary judgments. Motivated by this finding, we propose SEMJ, a self-evolving multilingual judge that leverages cross-lingual inconsistency for iterative refinement. SEMJ constructs multilingual variants of each input, collects independent judgments and rationales, and feeds inconsistent outputs back for self-reflection and re-evaluation. Experiments on multiple benchmarks show that SEMJ consistently outperforms voting and reflection baselines in both accuracy and cross-lingual consistency. Further analysis shows that inconsistency triggers useful re-evaluation, which improves judgment quality.","published":"2026-06-06T10:36:24Z","updated":"2026-06-06T10:36:24Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08092v1","pdf_url":"https://arxiv.org/pdf/2606.08092v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.07367","versioned_id":"2606.07367v1","title":"Self-evolving LLM agents with in-distribution Optimization","authors":["Yudi Zhang","Meng Fang","Zhenfang Chen","Mykola Pechenizkiy"],"abstract":"Large Language Models (LLMs) have recently emerged as powerful controllers for interactive agents in complex environments, yet training them to perform reliable long-horizon decision making remains a fundamental challenge. A key difficulty lies in credit assignment: agents often receive delayed rewards only at the end of episodes. In this paper, we propose Q-Evolve, a self-evolving framework for LLM agents that unifies automatic process-reward labeling and policy learning within a principled in-distribution reinforcement learning paradigm. In each evolving iteration, our method learns an in-distribution critic from a hybrid off-policy dataset that combines expert demonstrations with agent-generated trajectories, stabilizing Bellman backups in sparse-reward settings via a weighted Implicit Q-Learning objective. The learned value function is then used to derive step-wise process rewards through advantage estimation, enabling dense and reliable supervision without environment backtracking or human annotation. Leveraging these signals, we perform behavior-proximal policy optimization that evolves the agent over the data used for process reward labeling, allowing iterative self-improvement without exacerbating distribution shift. We evaluate our method on AlfWorld, WebShop, and ScienceWorld, showing Q-Evolve outperforms strong baselines in sample efficiency, robustness, and overall task performance. Our results demonstrate that stable agent self-evolution is achievable through the co-evolution of process-level supervision and policy, both grounded within a shared in-distribution learning loop.","published":"2026-06-05T15:09:52Z","updated":"2026-06-05T15:09:52Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.07367v1","pdf_url":"https://arxiv.org/pdf/2606.07367v1","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.07711","versioned_id":"2606.07711v1","title":"Rosetta Memory: Adaptive Memory for Cross-LLM Agents","authors":["Hao Yang","Shiqi Shen","Haoxuan Li","Zhipeng Wang","Zhi Gong","Xu Chen"],"abstract":"Memory is the key component for transforming a stateless LLM into a persistent, evolving agent through experience accumulation, long-horizon planning, and continual self-improvement. Existing memory systems typically take the LLM as the center and design memory operations tailored to a specific backbone. In practice, however, users frequently switch between LLMs, for example using Claude for coding and GPT for writing across tasks, or routing different steps to different backbones within a single task for cost-effective trade-offs. As a result, memory written by one model often needs to be consumed by another. Making upstream memory effectively adapt to and activate downstream LLMs remains a critical yet underexplored problem. To bridge this gap, we shift the perspective from LLM-centric memory design to \\emph{memory-centric LLM adaptation}. Specifically, we approach the above upstream-downstream memory adaptation problem from both the write and read sides, and design two profile-conditioned operators that are jointly trained to optimize how memory is stored and presented for better task completion. To ensure the learned operators generalize across a broad set of LLMs, we propose a minimum-gain sampling curriculum that prioritizes the least-served LLMs during training. To better measure the operators' actual contribution rather than the LLM's own capability, we design a performance-gap reward that compares against a naive memory baseline. Experiments on HotpotQA, 2WikiMultihopQA, and MuSiQue demonstrate that our model consistently outperforms baselines and remains robust under unseen-model replacement.","published":"2026-06-05T13:50:59Z","updated":"2026-06-05T13:50:59Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.07711v1","pdf_url":"https://arxiv.org/pdf/2606.07711v1","comment":"19 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.07080","versioned_id":"2606.07080v1","title":"dots.tts Technical Report","authors":["Shi Lian","Changtao Li","Bohan Li","Hankun Wang","Da Zheng","Junfeng Tian","Yufeng Ma","Colin Zhang","Kai Yu"],"abstract":"We present dots.tts, a 2B-parameter continuous autoregressive text-to-speech (TTS) foundation model that models speech in a continuous latent space. Compared with existing continuous autoregressive models, our key innovations are threefold. First, we train an AudioVAE with multiple objectives to build a semantically structured and prediction-friendly continuous speech space. Second, we use full-history conditioning in the flow-matching head to preserve long-range consistency and reduce drift during generation. Third, we apply reward-free self-corrective post-training to the flow-matching head to further improve robustness and acoustic quality. After being trained on a large-scale multilingual corpus, dots.tts achieves the best average performance on Seed-TTS-Eval, with WERs of 0.94%/1.30%/6.60% and SIM scores of 81.0/77.1/79.5 on the zh/en/zh-hard test sets, respectively. Across other benchmarks, dots.tts also consistently demonstrates open-source state-of-the-art performance, exhibiting strong generation stability, voice cloning ability, and emotional expressiveness. For efficient inference, we further apply CFG-aware MeanFlow distillation, enabling low-latency speech generation with first-packet latencies of 85/54 ms in output streaming and dual-streaming modes, respectively. To facilitate reproducible research and practical deployment, we release the training and inference code, together with the pretrained, post-trained, and MeanFlow-distilled checkpoints, under the Apache 2.0 license.","published":"2026-06-05T09:19:24Z","updated":"2026-06-05T09:19:24Z","categories":["cs.SD","cs.AI","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2606.07080v1","pdf_url":"https://arxiv.org/pdf/2606.07080v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.06324","versioned_id":"2606.06324v2","title":"From Failed Trajectories to Reliable LLM Agents: Diagnosing and Repairing Harness Flaws","authors":["Mengzhuo Chen","Junjie Wang","Zhe Liu","Yawen Wang","Haiming Zheng","Qing Wang"],"abstract":"LLM agents increasingly rely on agent harness: the runtime infrastructure around the base model that defines execution environments, tool interfaces, context, lifecycle orchestration, observability, verification, and governance. Existing self-improving agents and automatic harness evolution methods mainly improve agents through runtime supervision, prompt optimization, workflow search, or harness modification based on final outcomes. However, they often fail to diagnose where the responsible evidence lies in failed trajectories and which harness implementation mechanism causes the unreliable behavior, resulting in broad, indirect, or poorly scoped changes. This paper proposes HarnessFix, a trace-grounded and diagnosis-driven framework for repairing agent harnesses. HarnessFix compiles raw execution traces and harness artifacts into a Harness-aware Trace Intermediate Representation (HTIR), which normalizes fragmented trajectory evidence, captures step-level data-flow and control-flow relations, and aligns runtime steps with the harness artifacts that shape their behavior. It then attributes failures to responsible steps and harness artifacts, and consolidates recurring diagnoses into repair-oriented flaw records. Finally, HarnessFix maps these records to scoped repair operators, generates patches under flaw-specific repair specifications, and accepts them through regression-aware validation. We evaluate HarnessFix on four popular benchmarks, and results show that it improves the performance over the initial harnesses by 6.3% to 18.4%, significantly outperforming human-designed and self-evolution baselines. HarnessFix highlights the value of treating failed trajectories not only as feedback signals, but also as structured evidence for diagnosing and repairing the harness mechanisms behind agent failures.","published":"2026-06-04T15:58:30Z","updated":"2026-07-02T04:35:01Z","categories":["cs.SE","cs.MA"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.06324v2","pdf_url":"https://arxiv.org/pdf/2606.06324v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.05976","versioned_id":"2606.05976v1","title":"The Self-Correction Illusion: LLMs Correct Others but Not Themselves","authors":["Kuan-Yen Chen","Fang-Yi Su","Jung-Hsien Chiang"],"abstract":"Recent work shows that LLM agents struggle to correct errors in their own reasoning traces yet show markedly higher correction rates when identical claims appear under external sources. We ask whether this asymmetry reflects a capability deficit or a role-label artifact: does an agent's willingness to correct a wrong claim depend causally on the chat-template role that carries it, rather than on the claim's content? Our setup keeps the erroneous claim byte-identical across all conditions (SHA-256 verified) and varies only its wrapping role: the agent's own \\role{<thought>}, a \\role{user} message, a \\role{tool} response, or a \\role{system <memory>} block. Across 13 model-domain cells covering seven model families and three domains ($n{=}30$ paired tasks per cell), relabeling the claim from \\role{<thought>} to an external role lifts the explicit-correction rate by 23 to 93 percentage points, with 10 of 13 cells reaching $p{<}0.001$. Further experiments confirm that the effect is asymmetric, mechanistically decomposable, and robust across domains. The failure to self-correct is not a cognitive deficit; it is a chat-template artifact. We exploit this artifact by designing a prompt-structure-only intervention that requires no training and no model modification, with its strongest role label being domain-dependent: \\role{<memory>} dominates on math, while a plain \\role{user} message dominates on logical deduction.","published":"2026-06-04T10:17:00Z","updated":"2026-06-04T10:17:00Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.05976v1","pdf_url":"https://arxiv.org/pdf/2606.05976v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.05658","versioned_id":"2606.05658v1","title":"Agent-Orchestrated Adaptive RAG: A Comparative Study on Structured and Multi-Hop Retrieval","authors":["Anuj Maharjan","Devinder Kaur","Richard Molyet"],"abstract":"Retrieval-Augmented Generation (RAG) enhances Large Language Models (LLMs) by grounding their responses in external knowledge, but conventional pipelines rely on static, single-step retrieval that limits performance on complex queries. This paper presents an Agent-Orchestrated Adaptive RAG framework that introduces dynamic query decomposition, iterative retrieval, and a bounded self-reflective evaluation loop. We evaluate the system across two complementary datasets: a domain-specific DevOps knowledge base and the multi-hop reasoning benchmark MuSiQue. Using metrics that include overall score, citation accuracy, mean reciprocal rank, and topic coverage, we find that query decomposition yields consistent gains in the structured domain (overall score $+0.04$, MRR $+0.17$ on DevOps) but degrades ranking precision on the multi-hop benchmark, while the reflection mechanism improves citation accuracy at a substantial latency cost. These contrasting results show that agentic enhancements are not universally beneficial and must be applied selectively according to query and domain characteristics. Our findings argue for adaptive, cost-aware orchestration rather than uniformly aggressive reasoning pipelines.","published":"2026-06-04T03:38:46Z","updated":"2026-06-04T03:38:46Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2606.05658v1","pdf_url":"https://arxiv.org/pdf/2606.05658v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.05402","versioned_id":"2606.05402v1","title":"ReasoningFlow: Discourse Structures for Understanding LLM Reasoning Traces","authors":["Jinu Lee","Shivam Agarwal","Amruta Parulekar","Siddarth Madala","Dilek Hakkani-Tur","Julia Hockenmaier"],"abstract":"Large reasoning models (LRMs) produce reasoning traces with non-linear structures, such as backtracking and self-correction, that complicate the evaluation and monitoring of the reasoning process. We introduce ReasoningFlow, a framework that captures the discourse structures of LRM reasoning traces into fine-grained directed acyclic graphs (DAGs). We develop and validate our annotation schema through careful manual annotation of 31 traces (2.1k steps), achieving high inter-annotator agreement, then scale to automatic annotation of 1,260 traces (247.7k steps) spanning three tasks (math, science, argumentation) and five models (Qwen2.5-32B-Inst, QwQ-32B, DeepSeek-V3, DeepSeek-R1, GPT-oss-120B). By analyzing ReasoningFlow graphs, we find: (1) LRMs exhibit structurally similar traces, despite being trained from different base models and potentially non-overlapping post-training data. (2) ReasoningFlow reveals diverse fine-grained reasoning behaviors (e.g., local verification, self-reflection, and assumptions) that can be used for better reasoning trace monitorability. (3) In LRMs, most of the erroneous steps are not used to derive final answers. (4) Mechanistic causal dependencies between steps do not reflect the language-level discourse structure. We release the dataset and code in: https://github.com/jinulee-v/reasoningflow.","published":"2026-06-03T20:12:26Z","updated":"2026-06-03T20:12:26Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.05402v1","pdf_url":"https://arxiv.org/pdf/2606.05402v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.05050","versioned_id":"2606.05050v2","title":"Autonomous heterogeneous catalyst discovery with a self-evolving multi-agent digital twin","authors":["Zhilong Song","Zongmin Zhang","Lixue Cheng"],"abstract":"Theoretical heterogeneous catalysis promises rapid catalyst discovery, yet computational and machine-learning predictions often deviate from experiment and stay confined to narrow material families, for want of a faithful, condition-aware catalytic simulator. We present CatDT (Catalysis Digital Twin), a self-evolving multi-agent system that builds an autonomous digital twin of a working catalyst, unifying gas-solid and liquid-solid modeling. From only a bulk crystal and a natural-language reaction description, eight specialized agents and 27 scientific tools predict stable facets, reconstruct working surfaces, enumerate and rank reaction pathways, locate transition states, and compute kinetics in 5-30 min on a single GPU. Two innovations address the hardest steps: UniMech finds dominant pathways for novel materials at over $10^3\\times$ lower cost than exhaustive enumeration by fusing agent-guided proposals with energy-cached graph search, and a memory-augmented reinforcement loop raises barrier-calculation success from 41% to 84% across 600 catalytic surfaces. Across seven gas-solid benchmarks -- stepped metals, single-atom catalysts, ordered intermetallics, vacancy-rich 2D sulfides and carbides, and a strong-metal--support-interaction (SMSI) interface -- every CatDT prediction lies within 0.5-2 times experiment over four orders of magnitude. For propane dehydrogenation, CatDT independently discovers non-precious candidates rivaling the Pt-based industrial benchmark, with a proposed Ni@ZrO$_2$ SMSI overlayer reaching a simulated TOF of $1.63~\\text{s}^{-1}$ at $\\sim$100% selectivity. More broadly, the decisive factor for a faithful catalyst digital twin -- or any multi-stage scientific simulator -- is not raw LLM capability but the engineered harness around it: deterministic tools, persistent memory, and verified self-improvement that compound across models, tools, and runs.","published":"2026-06-03T16:10:58Z","updated":"2026-07-09T03:42:47Z","categories":["cond-mat.mtrl-sci","cs.AI","physics.chem-ph"],"primary_category":"cond-mat.mtrl-sci","arxiv_url":"https://arxiv.org/abs/2606.05050v2","pdf_url":"https://arxiv.org/pdf/2606.05050v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.05037","versioned_id":"2606.05037v1","title":"Self-Reflective APIs: Structure Beats Verbosity for AI Agent Recovery","authors":["Arquimedes Canedo","Grama Chethan"],"abstract":"When an AI agent calls an API and hits a validation error, it needs more than what went wrong -- it needs what to do next. A self-reflective API returns, on validation failure, a machine-readable recovery\\_feedback.suggestions[] payload sufficient for the agent to repair the request and retry without external reasoning. On a leak-audited pilot ($N{=}30$ per cell, 3 LLMs, 10 adversarial tasks), structured suggestions lift task-completion rate by $+36.7$--$40.0$pp over plain-English diagnoses on Anthropic models (Fisher's exact $p \\le 0.0022$), at $1.8$--$2.2\\times$ better per-success token efficiency. The lift is not significant on gpt-4o-mini ($p{=}0.435$); a second-domain replication on a billing API confirms the pattern. The comparison only holds after auditing two undocumented classes of answer leakage in LLM benchmarks. We shipaudit\\_prompt\\_leakage.py as reusable CI infrastructure. Code and data: https://github.com/arquicanedo/self-reflective-apis.","published":"2026-06-03T16:02:11Z","updated":"2026-06-03T16:02:11Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.05037v1","pdf_url":"https://arxiv.org/pdf/2606.05037v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.04455","versioned_id":"2606.04455v1","title":"The Meta-Agent Challenge: Are Current Agents Capable of Autonomous Agent Development?","authors":["Xinyu Lu","Tianshu Wang","Pengbo Wang","zujie wen","Zhiqiang Zhang","Jun Zhou","Boxi Cao","Yaojie Lu","Hongyu Lin","Xianpei Han","Le Sun"],"abstract":"Current AI benchmarks evaluate agents on task execution within human-designed workflows. These evaluations fundamentally fail to measure a critical next-level capability: whether models can autonomously develop agent systems. We introduce the Meta-Agent Challenge (MAC), an evaluation framework designed to test the capacity of frontier models for autonomous agent development. Specifically, a code agent (the meta-agent) is given a sandboxed environment, an evaluation API, and a time limitation to iteratively program an agent artifact that maximizes performance on a held-out test set across five domains. To ensure evaluation integrity, this framework is secured by multi-layer defenses against reward hacking. Leveraging this framework, we demonstrate that meta-agents rarely match human-engineered baseline policies, and the few that do are dominated by proprietary frontier models. Moreover, the design process exhibits high variance, and high optimization pressure surfaces emergent adversarial behaviors like ground-truth exfiltration-highlighting critical deficits in both robustness and model alignment. Ultimately, MAC provides a rigorous, open-source benchmark for autonomous AI research and development, offering an empirical proxy for evaluating recursive self-improvement. Benchmark is publicly available at: https://github.com/ant-research/meta-agent-challenge.","published":"2026-06-03T04:58:17Z","updated":"2026-06-03T04:58:17Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.04455v1","pdf_url":"https://arxiv.org/pdf/2606.04455v1","comment":"Website: https://meta-agent-challenge.com/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.28347","versioned_id":"2606.28347v1","title":"Agentic Safety is an Epistemic Property, Not a Behavioral One","authors":["Charles L. Wang","Keir Dorchen","Peter Jin"],"abstract":"Contemporary AI safety spans pre-training interventions, post-training alignment, deployment-time controls, monitoring, and red-teaming. These methods are necessary, but they primarily certify snapshots of system behavior. As AI systems become more capable, dynamic, embodied, and self-improving, this snapshot view becomes incomplete: safety depends not only on whether a system behaves acceptably now, but whether it remains correctable as it learns, adapts, acts, and modifies itself over time. This paper argues that safety should therefore be treated as an epistemic property of the evolving learner, not merely a behavioral property of the current policy. We introduce teachability as the capacity to preserve future corrective leverage under bounded human, institutional, or environmental intervention. We argue that advanced systems can retain visible competence while eroding the representational, algorithmic, or meta-decision conditions needed for future correction. Safe advanced AI systems must not only behave acceptably now; they must remain teachable later.","published":"2026-06-02T17:59:25Z","updated":"2026-06-02T17:59:25Z","categories":["cs.CY","cs.AI","cs.LG"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2606.28347v1","pdf_url":"https://arxiv.org/pdf/2606.28347v1","comment":"To appear in proceedings of ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03979","versioned_id":"2606.03979v2","title":"Language Models Need Sleep: Learning to Self-Modify and Consolidate Memories","authors":["Ali Behrouz","Farnoosh Hashemi","Adel Javanmard","Vahab Mirrokni"],"abstract":"The past few decades have witnessed significant advances in the design of machine learning algorithms, from early studies on task-specific shallow models to more general deep Large Language Models (LLMs). Despite showing promising results in tasks that require instant prediction or in-context learning, existing models lack the ability to continually learn and effectively transfer their temporal in-context knowledge to their long-term parameters. Inspired by human learning process, we introduce a ''Sleep'' paradigm that allows the models to continually learn, distill their short-term fragile memories into stable long-term knowledge with replay, and recursively improve themselves with ''Dreaming'' process. In more detail, sleep consists of two stages: (1) Memory Consolidation: an upward distillation process, called Knowledge Seeding, where the memories of a smaller-self are distilled into a larger network to provide more capacity while preserving the knowledge. As a proof of concept, we present a new Generalized Distillation process for {Knowledge Seeding} (i.e., the combination of on-policy distillation with Reinforcement Learning (RL)-based imitation learning); (2) Dreaming: a self-improvement phase, where the model uses RL to generate a curriculum of synthetic data to rehearse new knowledge and refine existing capabilities without human supervision. Our experiments on long-horizon, continual learning, knowledge incorporation, and few-shot generalization tasks support the importance of the sleep stage.","published":"2026-06-02T17:56:55Z","updated":"2026-07-10T17:52:03Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.03979v2","pdf_url":"https://arxiv.org/pdf/2606.03979v2","comment":"A version of this work has been publicly available from September 2025 on OpenReview","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03963","versioned_id":"2606.03963v3","title":"AgenticRL: Self-Refining Agentic Reinforcement Learning for Vision-Conditioned UAV Navigation","authors":["Roohan Ahmed Khan","Yasheerah Yaqoot","Amir Atef Habel","Muhammad Ahsan Mustafa","Dzmitry Tsetserukou"],"abstract":"Deep reinforcement learning has shown strong potential for enabling autonomous robots to learn complex navigational tasks. However, its practical use still depends heavily on human designed reward functions and repeated manual fine tuning, which is time consuming and does not guarantee high success in the desired task. This paper presents AgenticRL, agent guided reinforcement learning framework that increases autonomy in reward design, policy refinement, and real world deployment for unmanned aerial vehicles (UAV) navigation tasks. AgenticRL uses a multimodal generative pre-trained transformer (GPT) agent to interpret task information and visual scene observations, generate task specific reward functions, train policies using Proximal Policy Optimization (PPO) algorithm, and then act as a critic by evaluating the trained policy through diagnosis packets to generate feedback. Based on this feedback, the agent identifies failure modes and refines the reward function in a closed loop self improvement process. To further leverage the multimodal GPT agent during inference, AgenticRL uses real world images and natural language task information to automatically identify the active scenario and select the appropriate trained policy for execution. The framework is evaluated on multiple navigational tasks, including gate traversal, obstacle avoidance, wall barrier crossing with landing, trajectory following, and motion behavior learning. Experimental results show that the closed loop refinement process improves policy behavior compared with initial rewards by 71%. We also demonstrate sim-to-real transfer of the proposed framework, achieving a real world success rate of 91% and a sim-to-real accuracy of 94%.","published":"2026-06-02T17:50:15Z","updated":"2026-06-09T15:09:32Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.03963v3","pdf_url":"https://arxiv.org/pdf/2606.03963v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03812","versioned_id":"2606.03812v1","title":"Enhancing Operational Safety via Agentic Dialogue Hazard Identification Analysis","authors":["Sanjay Das","Ran Elgedawy","Ethan Seefried","Ryan Burchfield","Tirthankar Ghosal"],"abstract":"Operational safety in high-stakes domains such as industrial process control, autonomous, and safety-critical systems, demand reliable hazard identification. While large language models (LLMs) have shown promise in automating safety analysis tasks, single-turn, monolithic inference is brittle: it lacks the self-correction, deliberation, and contextual refinement that safety engineers apply iteratively. In this paper, we introduce HAZDIAL, a framework that investigates whether structured agentic dialogue-multi-agent, multi-turn interactions improves the quality of NLP- based hazard identification over single-pass baselines. We systematically compare two dialogue modalities: adversarial debate and constructive discussion, and propose an algorithm-based agentic interaction optimization. We evaluate all configurations against a curated golden dataset using standard classification metrics (accuracy, precision, recall, F1) and novel dialogue metrics. This work advances the intersection of dialogue systems, multi-agent reasoning, and AI safety, providing an empirical evidence for dialogue-driven hazard analysis.","published":"2026-06-02T15:54:51Z","updated":"2026-06-02T15:54:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03812v1","pdf_url":"https://arxiv.org/pdf/2606.03812v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03678","versioned_id":"2606.03678v1","title":"EvoDrive: Pareto Evolution for Safety-Critical Autonomous Driving via Self-Improving LLM Agents","authors":["Tong Nie","Yuewen Mei","Yihong Tang","Junlin He","Jie Deng","Jian Sun","Wei Ma"],"abstract":"Generating safety-critical scenarios is essential for validating and improving autonomous driving systems, yet it inherently requires maximizing adversariality to expose failures while preserving realism. Existing methods usually manage this trade-off with handcrafted heuristics, confining generation to known priors and overlooking underexplored patterns. While recent open-ended agentic evolution can push this limit, unconstrained general agents lack strict simulator grounding and tend to collapse the multi-objective tension into single-scalar maximization. Here we present EvoDrive, the first automated, LLM-based agentic evolution framework for multi-objective scenario generation. EvoDrive employs a simulator-grounded actor-critic architecture where a memory-driven actor iteratively proposes improvements to the generators and critics filter out implausible candidates, and a self-evolving world evaluator routes promising proposals to optimize simulation budgets. EvoDrive further maintains a Pareto archive of evaluated candidates to preserve diverse attack-realism trade-offs and guide future evolution via simulation feedback. Benchmark results on MetaDrive and CARLA show that EvoDrive not only significantly expands the Pareto frontier across various generators, but also produces valuable scenarios for policy training.","published":"2026-06-02T14:01:23Z","updated":"2026-06-02T14:01:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03678v1","pdf_url":"https://arxiv.org/pdf/2606.03678v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03628","versioned_id":"2606.03628v1","title":"Building Reliable Long-Form Generation via Hallucination Rejection Sampling","authors":["Lin Li","Georgia Channing","Suhaas M Bhat","Gabriel Davis Jones","Yarin Gal"],"abstract":"Large language models (LLMs) have achieved remarkable progress in open-ended text generation, yet they remain prone to hallucinating incorrect or unsupported content, which undermines their reliability. This issue is exacerbated in long-form generation due to hallucination snowballing, a phenomenon where early errors propagate and compound into subsequent outputs. To address this challenge, we propose a novel inference-time hallucination mitigation framework, named Segment-wise HAllucination Rejection Sampling (SHARS), which uses an arbitrary hallucination detector to identify and reject hallucinated segments during generation and resample until faithful content is produced. By retaining only confident information and building subsequent generations upon it, the framework mitigates hallucination accumulation and enhances factual consistency. To instantiate this framework, we adopt semantic uncertainty as the detector and introduce several vital modifications to address its limitations and better adapt it to long-form text. Our method enables models to self-correct hallucinations without requiring external resources such as web search or knowledge bases, while remaining compatible with them for future extensions. Empirical evaluations on standardized hallucination benchmarks demonstrate that our method substantially reduces hallucinations in long-form generation while preserving or even improving the informativeness of generation. Code is available at: https://github.com/TreeLLi/hallucination-rejection-sampling.","published":"2026-06-02T13:26:17Z","updated":"2026-06-02T13:26:17Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.03628v1","pdf_url":"https://arxiv.org/pdf/2606.03628v1","comment":"accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03544","versioned_id":"2606.03544v1","title":"SAGE: A Quantitative Evaluation of Socialized Evolution in Agent Ecosystems","authors":["Linyue Pan","Yaoming Zhu","Lin Qiu","Xuezhi Cao","Xunliang Cai"],"abstract":"Self-improving language agents are typically evaluated in isolation: an agent attempts a task, receives feedback, and iteratively refines its own behavior. Yet agents increasingly operate alongside peers whose strategies and outcomes are publicly visible. This raises an under-studied question: when does shared experience produce improvements that self-improvement alone cannot achieve? We introduce SAGE (Social Agent Group Evolution),an evaluation framework that compares two compute-matched conditions: SocialEvo, where agents from five distinct model families co-evolve with access to all peers' histories; and SelfEvo, where each agent receives the same number of task attempts but sees only its own past, which is conventional in self-improving agent studies. We instantiate SAGE in three arenas: open-ended ML research, long-horizon economic planning, and strategic multiplayer play, evaluated across multiple evolutionary rounds. We find that group history is not a universal amplifier: the strongest agent does not exceed its self-evolution ceiling. However, agents that plateau under self-improvement can achieve significant breakthroughs when peer experience is available. In competitive settings, counterfactual controls reveal that agents improve generally rather than developing opponent-specific strategies. Across different forms of shared history, filtered peer traces and reflective summaries often outperform raw logs, indicating that social gains depend on abstraction rather than exposure volume. These findings reveal that peer-history gains are agent-specific, arena-dependent, and contingent on the capacity to abstract transferable knowledge from public traces.","published":"2026-06-02T12:08:38Z","updated":"2026-06-02T12:08:38Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03544v1","pdf_url":"https://arxiv.org/pdf/2606.03544v1","comment":"13 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03489","versioned_id":"2606.03489v2","title":"Learn from Your Mistakes: Tree-like Self-Play for Secure Code LLMs","authors":["Wenqi Chen","Ziyan Zhang","Bin Wang","Lin Liu","Hengheng Zhang","Zhengsu Chen"],"abstract":"While Large Language Models (LLMs) excel in code generation, they remain prone to replicating subtle yet critical vulnerabilities endemic to their training data. Current alignment techniques, such as Supervised Fine-Tuning (SFT) and Reinforcement Learning (RL), typically apply coarse-grained optimization at the sequence level. This approach often fails to address the localized nature of security flaws, where a single incorrect token choice can compromise an entire program. To bridge this gap, we introduce Tree-like Self-Play (TSP), a framework that reframes secure code generation as a fine-grained sequential decision process. Unlike standard methods that blindly maximize likelihood, TSP constructs a decision tree where the model explores branching trajectories--generating both secure \"golden paths\" and vulnerable variants. By treating code generation as a self-play game, the model learns to strictly discriminate against its own localized errors. This provides a dense, on-policy learning signal that forces self-correction precisely at the critical decision nodes where vulnerabilities typically emerge. Our experiments demonstrate that TSP fundamentally enhances model reliability. In Python security benchmarks, TSP boosts CodeLlama-7B's pass rate (SPR@1) to 75.8%, significantly outperforming SFT (57.0%) and unstructured self-play baselines. Crucially, TSP induces robust out-of-distribution generalization: the model not only reduces vulnerabilities in unseen categories (CWEs) by 24.5% but also successfully transfers security principles learned from C/C++ to diverse languages, including Python, Go, and JavaScript. This suggests that TSP does not merely memorize patches, but internalizes abstract, language-agnostic security logic.","published":"2026-06-02T11:07:20Z","updated":"2026-06-13T20:00:19Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2606.03489v2","pdf_url":"https://arxiv.org/pdf/2606.03489v2","comment":"18 pages, 3 figures, Accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03303","versioned_id":"2606.03303v2","title":"LEAP: Supercharging LLMs for Formal Mathematics with Agentic Frameworks","authors":["Po-Nien Kung","Linfeng Song","Dawsen Hwang","Jinsung Yoon","Chun-Liang Li","Simone Severini","Mirek Olšák","Edward Lockhart","Quoc V Le","Burak Gokturk","Thang Luong","Tomas Pfister","Nanyun Peng"],"abstract":"Large Language Models (LLMs) exhibit strong informal mathematical reasoning but struggle to generate mechanically verifiable proofs in formal languages like Lean. We present LEAP, an agentic framework that enables general-purpose foundation models to achieve state-of-the-art performance on automated formal theorem proving. LEAP leverages foundation model capabilities, such as informal reasoning, instruction following, and iterative self-refinement. By decomposing complex problems into smaller units, the system bridges formal proof construction with informal blueprints through continuous interaction with the Lean compiler. To provide a rigorous evaluation beyond increasingly saturated benchmarks, we introduce Lean-IMO-Bench, a benchmark of IMO-style problems formalized in Lean, with short statements yet highly non-routine and multi-step proofs across a wide range of difficulty levels. Empirically, on the latest 2025 Putnam Competition, an annual mathematics competition for undergraduate students in North America, LEAP solves all 12 problems, matching recent breakthroughs by frontier formal mathematical models. On Lean-IMO-Bench, LEAP boosts the one-shot formal solve rate of general-purpose LLMs from below 10% to 70%, notably surpassing the 48% benchmark set by a specialized, gold-medal-caliber IMO system. Furthermore, we demonstrate LEAP's research-level utility by autonomously formalizing complex proofs for open combinatorial challenges, including a verified proof for a key subproblem in Knuth's Hamiltonian decomposition of even-order Cayley graphs.","published":"2026-06-02T08:16:42Z","updated":"2026-06-03T06:16:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03303v2","pdf_url":"https://arxiv.org/pdf/2606.03303v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.20636","versioned_id":"2606.20636v1","title":"SkillHarness: Harnessing Safe Skills for Computer-Use Agents","authors":["Yurun Chen","Biao Yi","Keting Yin","Shengyu Zhang"],"abstract":"Computer-Use Agents (CUAs) are increasingly deployed in dynamic interactive environments, creating a growing need for continual skill learning during interaction. Recent approaches address this challenge by learning reusable skills from successful trajectories. However, these skill learning methods largely assume static and safe environments, overlooking risks from adversarial interactions (e.g., prompt injections) and environmental dynamics (e.g., pop-ups). In dynamic settings, such assumptions can lead to risky skill learning and brittle execution, undermining the reliability of CUAs. This raises the question: how can CUAs learn and use skills safely in dynamic environments? To address this problem, we propose SkillHarness, a framework for safe skill harnessing in dynamic environments. SkillHarness moves beyond static skill abstractions by modeling skill learning and utilization as a safety-constrained interaction process. Specifically, we introduce the skill boundary that leverages multi-source supervision signals to identify safe skills from interaction trajectories, and construct self-improving safety constraints throughout the skill lifecycle. In addition, SkillHarness introduces selective skill reuse, where tasks are guided to decompose according to context and completed through the selective activation of skill subsets. Our experiments demonstrate that SkillHarness significantly reduces the unsafe rate of learned skills by 57.1% and consistently improves execution stability under dynamic environmental changes, outperforming existing baselines.","published":"2026-06-02T06:33:51Z","updated":"2026-06-02T06:33:51Z","categories":["cs.AI","cs.CL","cs.CR","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.20636v1","pdf_url":"https://arxiv.org/pdf/2606.20636v1","comment":"Work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03143","versioned_id":"2606.03143v1","title":"FederatedSkill: Federated Learning for Agentic Skill Evolution","authors":["Jingbo Yang","Guanyu Yao","Yang Zhang","Ramana Rao Kompella","Gaowen Liu","Shiyu Chang"],"abstract":"Modern LLM agents increasingly rely on skill libraries to handle complex tasks, making skill evolution a primary driver of self-improvement. However, isolated single-user task streams lack the diversity required to build comprehensive skills. While cross-user collaboration can overcome this data bottleneck, current trajectory-sharing approaches compromise user privacy and impose a uniform global library that fails to accommodate client heterogeneity. We introduce FederatedSkill, a privacy-preserving framework for collaborative agent evolution. Moving beyond raw trajectory sharing, FederatedSkill utilizes semantic skill diffs, structured patches over local libraries, as the fundamental unit of communication. On the server side, an evolution agent aggregates these patches to dynamically model client-specific capability boundaries, facilitating strictly personalized skill evolution rather than a suboptimal global average. Evaluated across 20 distinct agent task families, FederatedSkill demonstrates substantial gains over self-evolving baselines, achieving up to a 44.4% increase in success rate and a 37.5% reduction in computational cost.","published":"2026-06-02T04:38:05Z","updated":"2026-06-02T04:38:05Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.03143v1","pdf_url":"https://arxiv.org/pdf/2606.03143v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.03094","versioned_id":"2606.03094v1","title":"FGRPO: Federated GRPO with Adaptive Aggregation on Non-IID Data","authors":["Pengyu Chen","Shaowei Li","Kai Wang","Yunsheng Yuan","Kai Han","Jun Luo","Feng Li"],"abstract":"Recent advances in language models have established reinforcement learning as the primary paradigm for eliciting self-correction and long-chain reasoning. While group relative policy optimization (GRPO) offers superior scalability by eliminating the critic network, deploying it on a central infrastructure entails collecting a large volume of data from distributed owners, which poses significant privacy risks. To address these concerns, we introduce federated GRPO (FGRPO), a framework designed to decentralize the fine-tuning of reasoning models across heterogeneous data owners. To effectively mitigate the instability caused by divergent reward scales across heterogeneous tasks, FGRPO incorporates an adaptive aggregation mechanism based on relative performance gain. By characterizing each client's improvement relative to its personalized historical baseline, the framework dynamically prioritizes effective learning trajectories regardless of local task difficulty. FGRPO ensures robust convergence on non-IID data while preserving data privacy.","published":"2026-06-02T03:32:32Z","updated":"2026-06-02T03:32:32Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.03094v1","pdf_url":"https://arxiv.org/pdf/2606.03094v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.02920","versioned_id":"2606.02920v1","title":"Fast Unlearning at Scale via Margin Self-Correction","authors":["Federico Di Gennaro","Alexander Shevchenko","Fanny Yang"],"abstract":"Language-model unlearning updates a trained model to behave as if it had not seen selected training examples, while preserving utility and avoiding costly retraining. Existing approaches typically fine-tune the pretrained model with a fixed training budget and select the final model afterwards by evaluating several saved checkpoints on downstream validation data. Two sources of unnecessary computation limit scalability: training beyond the desired forget-retain trade-off, and checkpoint selection that requires extra storage and repeated evaluations. To address these limitations, we introduce MArgin Self-Correction (MASC), an efficient unlearning method with an online stopping rule that does not require downstream evaluation. Given a text sequence to be forgotten, MASC actively reduces the logit gap between the original next token and the most likely alternatives. It outputs a final model once this gap is small on average over a sufficiently large proportion of token positions across all forget sequences. On TOFU, MUSE News, and MUSE Books, MASC achieves a competitive forget-retain trade-off at a fraction of the computational cost of existing baselines. We further observe that as we increase model size (a.k.a. number of parameters), the trade-offs improve for both MASC and SimNPO -- the forget metrics remain comparable while retain utility increases.","published":"2026-06-01T21:49:54Z","updated":"2026-06-01T21:49:54Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.02920v1","pdf_url":"https://arxiv.org/pdf/2606.02920v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01861","versioned_id":"2606.01861v1","title":"A Theoretical Framework for Self-Play Theorem Proving Algorithms","authors":["Thomas Chen","Zhiyuan Li"],"abstract":"Self-play, a type of training algorithm that enables a model to self-improve, has recently shown promising empirical results in the context of formal theorem proving using Large Language Models (LLMs). (Dong & Ma, 2025) instantiate self-play with two cooperating agents: a prover, which proves theorems, and a conjecturer, which generates new theorems as a curriculum to the prover. In this paper, we provide a theoretical framework for understanding the self-improvement capabilities of self-play algorithms for theorem proving. First, we formalize the set of theorems as a graph, with nodes as theorems and edges between pairs of theorems with similar semantics. We introduce a set of primitive assumptions that characterize the guarantees of a trained prover and how a conjecturer can access the structure of the graph. Second, we show that if the underlying graph of theorems is well-connected, then a prover-conjecturer system, where the conjecturing algorithm is based on a reversible random walk, is sufficient to grow the set of proved theorems exponentially. Third, motivated by an issue encountered empirically by self-play algorithms, where the conjecturer tends to generate artificially complex and non-fundamental theorems, we propose a diversity measure for a training distribution of theorems generated by a conjecturer and an improved conjecturing algorithm that locally maximizes this diversity measure, by computing the diffusion similarity between neighboring theorems in the theorem graph. Finally, we describe a method to compute the diffusion similarity by using contrastive learning to embed nodes into Euclidean space and then computing the inner-product between embeddings.","published":"2026-06-01T08:12:47Z","updated":"2026-06-01T08:12:47Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.01861v1","pdf_url":"https://arxiv.org/pdf/2606.01861v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01770","versioned_id":"2606.01770v2","title":"Adaptive Auto-Harness: Sustained Self-Improvement for Agentic System Deployment on Open-Ended Task Streams","authors":["Zewen Liu","Zhan Shi","Yisi Sang","Bing He","Minhua Lin","Tianxin Wei","Dakuo Wang","Benoit Dumoulin","Wei Jin","Hanqing Lu"],"abstract":"Auto-harness systems such as A-Evolve, GEPA, and Meta-Harness improve LLM agents by optimizing prompts, skills, tools, memories, and supporting infrastructure from execution feedback, but they are typically evaluated on fixed offline benchmarks. Real deployments instead present open-ended task streams: histories grow without a fixed endpoint, heterogeneous tasks require different harnesses, and problem distributions shift over time. These challenges make a single repeatedly and densely updated harness brittle, causing performance degradation as accuracy peaks early and then declines. This motivates sustained harness construction with task-wise adaptation. We introduce Adaptive Auto-Harness, a framework and system for such streams. The framework decomposes the gap to an oracle harness into evolution loss and adaptation loss. The system addresses these losses with a stateful multi-agent evolver, a harness tree with solve-time routing, and human-steering hooks for cases where history lacks the needed signal. Across prediction-market, security-competition, and event-forecasting streams, Adaptive Auto-Harness outperforms five existing auto-harness baselines and ablations attribute gains to better construction, routing, or targeted human steering. Code is available in \\href{https://github.com/A-EVO-Lab/a-evolve/tree/release/adaptive-auto-harness}{Link}.","published":"2026-06-01T06:51:14Z","updated":"2026-06-03T05:59:44Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.01770v2","pdf_url":"https://arxiv.org/pdf/2606.01770v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01640","versioned_id":"2606.01640v1","title":"MobEvolve: An Agentic Self-Evolving Heuristic System for Interpretable Human Mobility Generation","authors":["Junlin He","Yihong Tang","Tong Nie","Ao Qu","Yuebing Liang","Hamzeh Alizadeh","Bang Liu","Wei Ma","Lijun Sun"],"abstract":"Human mobility generation aims to synthesize realistic trip chains for target populations based on individual features. Existing paradigms, including deep generative models, LLM-based methods, and traditional heuristics, struggle to satisfy the complex demands of this task while simultaneously maintaining interpretability, behavioral plausibility, population-level distributional alignment, and inference efficiency. To bridge this gap, we introduce MobEvolve, the first agentic self-evolving heuristic framework for human mobility generation. MobEvolve initializes a behavior-inspired heuristic system and employs an LLM agent to iteratively evolve its internal logic. By diagnosing empirical misalignments and failure cases on a validation set, the agent proposes targeted updates and accumulates evolution memory for cumulative self-improvement. Extensive evaluations on the Singapore and Montreal benchmarks demonstrate that MobEvolve significantly outperforms state-of-the-art deep generative and LLM-based methods in individual trajectory fidelity, population-level distribution alignment, and behavioral plausibility, while preserving interpretability and high inference efficiency.","published":"2026-06-01T03:46:25Z","updated":"2026-06-01T03:46:25Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.01640v1","pdf_url":"https://arxiv.org/pdf/2606.01640v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01613","versioned_id":"2606.01613v2","title":"TechRAG: Evidence-Gated Multimodal Agentic RAG for Technical Literature Reasoning","authors":["Kanwar Bharat Singh"],"abstract":"This paper presents an agentic multimodal retrieval-augmented generation (RAG) framework for domain-specific literature reasoning, instantiated on a curated corpus of several thousand papers in intelligent tires, vehicle dynamics, vehicle control, sensing, estimation, and machine learning. Unlike conventional single-pass RAG systems, the proposed architecture uses an autonomous, evidence-gated pipeline that classifies query intent, generates separate text and visual query rewrites, performs hybrid text retrieval with FAISS and BM25 followed by cross-encoder reranking, expands evidence through graph-guided chunk traversal over a Neo4j knowledge graph, and retrieves visual document evidence using ColSmol late-interaction embeddings with MUVERA fixed-dimensional encoding, approximate nearest-neighbor search, and MaxSim reranking. The framework scores evidence sufficiency using a 100-point rubric with hybrid rule-based/LLM review, retries retrieval through drift-guarded reformulation, searches external academic databases through optimize--search--vet loops, merges and deduplicates multimodal evidence, verifies citation integrity, and generates cited answers through Planner, Researcher, Writer, and Critic agents with self-correcting revision. Key contributions include: (i) a scalable multimodal retrieval architecture combining text, graph, and visual evidence over 40,000 document pages; (ii) an interpretable evidence sufficiency and retry mechanism; (iii) a multi-agent generation pipeline with evidence mapping and critic-driven revision; (iv) a domain knowledge graph with LLM-based entity extraction, OpenAlex author validation, and intra-corpus citation resolution; and (v) a route-dependent external search architecture for targeted literature expansion. The result is a practical, evidence-gated, multimodal agentic RAG architecture for technical reasoning over specialized research corpora.","published":"2026-06-01T03:01:51Z","updated":"2026-06-13T19:11:55Z","categories":["cs.IR","cs.AI","cs.MA"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2606.01613v2","pdf_url":"https://arxiv.org/pdf/2606.01613v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01612","versioned_id":"2606.01612v1","title":"Self-Improving Small Object Grounding in LVLMs","authors":["Tianze Yang","Yucheng Shi","Ruitong Sun","Ninghao Liu","Jin Sun"],"abstract":"Can internal attention patterns in Large Vision Language Models (LVLMs) identify reliable small-object boxes without fine-tuning? In this work, we provide an affirmative answer. Attention structure in LVLMs encodes grounding quality-a lightweight IoU regressor trained solely on attention maps achieves strong IoU prediction (Pearson r > 0.67). This regressor powers the regressor-based variant of our Attention-based Candidate Selection (ACS) framework, called ACS-Learned, which selects the best box from multiple sampled candidates to improve object grounding. By analyzing what the regressor learns, we reveal which transformer layers and heads are most critical and derive ACS-Free: a training-free selector that ranks candidates by attention entropy on these discriminative heads, with no learned component at inference. Experiments on COCO and Objects365 demonstrate up to 19% self-improvement on small object localization, with ACS-Free ranking best among all training-free methods, demonstrating that useful attention structure improves both localization reliability and interpretability in LVLMs.","published":"2026-06-01T03:01:38Z","updated":"2026-06-01T03:01:38Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.01612v1","pdf_url":"https://arxiv.org/pdf/2606.01612v1","comment":"29 Pages, 15 Figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.02646","versioned_id":"2606.02646v1","title":"The Ringelmann Effect in Multi-Agent LLM Systems: A Scaling Law for Effective Team Size","authors":["Blaž Bertalanič","Carolina Fortuna"],"abstract":"Inference-time multi-agent LLM scaling lacks a shared unit: counting nominal agents conflates cost with independent evidence. We derive a two-parameter scaling law $R(N) = N_\\text{eff}/N = 1/(1+c(N-1)N^{-β})$ where the regime exponent $β$ classifies any configuration into one of three asymptotic regimes -- hard-ceiling at $1/c$ ($β= 0$), sublinear at $N^β/c$ ($0 < β< 1$), or linear ($β\\ge 1$), and a mean-field theorem predicts that peer count $k$ and rounds $τ$ during agent debate enter the dynamics only through their product $kτ$. The law applies at two levels: answer diversity and correctness redundancy. Across 44 (model $\\times$ task $\\times$ condition) cells spanning peer debate, self-correction, random-noise placebo, self-consistency, three open-weight families (Qwen, Llama, Ministral) at scales from 7B to 32B with a frontier API check (Gemini), thinking models, heterogeneous teams, and sparse communication, the functional form fits every condition at $R^2 > 0.99$; only $(c, β)$ shifts. On free-form math, dense peer influence collapses the answer-level regime from sublinear into hard-ceiling; correctness-level fits remain hard-ceiling throughout. Three findings have practical implications. \\emph{(i)}~Thirty dense debating agents produce no more answer diversity than one on MMLU-Hard. \\emph{(ii)}~A noise placebo tracks self-correction on free-form math and at $4\\times$ scale, so within homogeneous teams the gain commonly attributed to ``debate'' comes from re-evaluation, not peer content. \\emph{(iii)}~A single $N \\le 5$ pilot predicts the $N=30$ structural ceiling, and within the configurations tested only architectural diversity (heterogeneous teams) lowers $c$ and escapes the hard-ceiling regime, communication-mode interventions do not.","published":"2026-05-31T16:19:54Z","updated":"2026-05-31T16:19:54Z","categories":["physics.soc-ph","cs.AI","cs.MA"],"primary_category":"physics.soc-ph","arxiv_url":"https://arxiv.org/abs/2606.02646v1","pdf_url":"https://arxiv.org/pdf/2606.02646v1","comment":"41 pages, 9 figures, 20 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01316","versioned_id":"2606.01316v2","title":"Science Earth: Towards A Planet-Scale Operating System for AI-Native Scientific Discovery","authors":["Zhe Zhao","Haibin Wen","Yingcheng Wu","Jiaming Ma","Yifan Wen","Jinglin Jian","Jiacheng Ge","Xiangru Tang","Bo An","Ming Yin","Sanfeng Wu","Mengdi Wang","Le Cong"],"abstract":"Scientific discovery demands intelligence, perseverance, and serendipity across vast search spaces. Today, top scientific capabilities remain siloed--one AI system for biological analysis, another for clinical reasoning, mathematical derivation, or materials simulation--and no pre-designed team can anticipate every skill a question will need. Science Earth is a planet-scale scientific runtime in which any capability--a simulation cluster, a wet-lab robot, a proof engine, a single-cell pipeline--can connect to any other, with collaboration structure emerging from the question itself. Its underlying EACN protocol lets capabilities discover one another, negotiate task ownership, and adjudicate across incompatible evidentiary standards without prior knowledge of who will meet whom. This shifts the organizing challenge from workflow design to open-ended connectivity. Two runs validate this under structurally distinct conditions. In a trans-Pacific higher-order Kuramoto synchronization study, agents identified and corrected a closure-ratio assumption in Ott-Antonsen analytic theory that fails outside the Lorentzian limit, within thirty minutes. In an eight-agent single-cell run on the 4.88M-cell Kang 2024 pan-cancer atlas, heterogeneous capabilities coupled over a 64.9-hour window with one structural external instruction, producing three new result layers and anchoring findings against an independent wet-lab study on an adjacent CCR8- TIGIT+ Treg subset. These cases are a first empirical reading, not a benchmark sweep. They show that when AI capabilities are truly connectable and coordination emerges from the problem, scientific reasoning becomes a distributed, self-correcting process--a step towards scaling AI-native discovery to the planet.","published":"2026-05-31T16:05:41Z","updated":"2026-06-18T03:50:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.01316v2","pdf_url":"https://arxiv.org/pdf/2606.01316v2","comment":"Withdrawn by the authors. (1) The author list and authorship roles had not been finalized and agreed upon by all listed authors prior to submission. (2) The specific contribution of the system in the K3 synchronization example (Section on Kuramoto/nonlinear physics) requires further validation before it can be reported. The authors are addressing both points and may resubmit a corrected version.","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01314","versioned_id":"2606.01314v1","title":"SkillSmith: Co-Evolving Skills and Tools for Self-Improving Agent Systems","authors":["Yangbo Wei","Zhen Huang","Shaoqiang Lu","Junhong Qian","Qifan Wang","Chen Wu","Lei He"],"abstract":"Recent self-evolving agents have shown that skills can be discovered, refined, and accumulated through execution. However, existing skill-evolution frameworks typically assume a fixed tool layer and evaluate each skill independently, limiting their ability to repair tool-level failures or reason about interactions among skills. We propose SkillSmith, a synergy-aware skill-tool co-evolution framework. SkillSmith introduces a unified proposal space in which reflection produces atomic bundles that jointly modify skills and tools, allowing tools to be wrapped, edited, composed, split, or retired when skill evolution identifies a reusable capability gap. To guide this joint search, SkillSmith maintains an ecological utility model inspired by Lotka-Volterra dynamics, where an interaction matrix estimated from execution traces captures pairwise complementarity and conflict among skills and provides pressure signals for retrieval, mutation prioritization, and retirement. Furthermore, SkillSmith records anti-patterns, including failure signatures, causal attributions, and remedies, to accelerate diagnosis and veto proposals that repeat known mistakes. Experiments on three benchmarks, including WildClawBench, and five Qwen3.5 model scales show that SkillSmith consistently outperforms strong baselines, with gains that amplify as task complexity and multi-skill co-activation increase.","published":"2026-05-31T16:01:19Z","updated":"2026-05-31T16:01:19Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.01314v1","pdf_url":"https://arxiv.org/pdf/2606.01314v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01286","versioned_id":"2606.01286v1","title":"BenchEvolver: Frontier Task Synthesis via Solution-Centric Evolution","authors":["Yangzhen Wu","Aaron J. Li","Wenjie Ma","Li Cao","Ziheng Zhou","Mert Cemri","Shu Liu","Yuran Xiu","Chenxiao Yan","Haikun Zhao","Bin Yu","Ion Stoica","Dawn Song"],"abstract":"The rapid progress of frontier large language models has led to widespread benchmark saturation, limiting the ability of existing datasets to differentiate model capabilities or provide useful training signal. For instance, on LiveCodeBench, frontier models achieve over 99% Pass@1 on easy splits and exceed 90% Pass@1 on average across difficulty levels. Constructing new, challenging datasets typically requires substantial human effort, creating a bottleneck for progress. We introduce BenchEvolver, a solution-centric evolutionary framework that automatically transforms existing coding problems into harder variants. Rather than generating problems from scratch, BenchEvolver evolves reference solutions through structured transformations and derives corresponding statements and tests from the evolved solutions. This design grounds generation in executable semantics, enabling scalable construction of high-quality, diverse, and difficult tasks with verifiable correctness. Applying BenchEvolver to LiveCodeBench and SciCode, we obtain evolved tasks that are substantially harder while maintaining validity, reference correctness, and diversity. We further curate LiveCodeBench-Plus, a 91-problem benchmark combining evolved and difficult original LCB-v6 tasks, where frontier-model Pass@1 ranges from 27.5% to 62.6%, restoring clear discrimination among strong coding models. Importantly, evolved tasks remain challenging even for the model that generates them, enabling self-improvement. We further show that RL on evolved LCB tasks improves held-out coding performance: for gpt-oss-20b, seed+evolved training achieves +8.7 and +8.3 Pass@1 gains on LCB v6 Hard and LCB-Pro Easy, exceeding seed-only gains by 70.7% and 34.8%, respectively. Our results show that BenchEvolver can convert saturated benchmarks into frontier-level evaluation suites and reusable training signal.","published":"2026-05-31T15:12:16Z","updated":"2026-05-31T15:12:16Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.01286v1","pdf_url":"https://arxiv.org/pdf/2606.01286v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.01026","versioned_id":"2606.01026v1","title":"Revise, Don't Freeze: Sampler-Matched Training for Self-Correcting Masked Diffusion Language Models","authors":["Longxuan Yu","Shaorong Zhang","Yu Fu","Hui Liu","Yue Dong","Greg Ver Steeg"],"abstract":"Masked diffusion language models (MDLMs) re-predict every position at each denoising step, but standard samplers commit tokens once revealed, leaving this revision capability unused. Existing approaches either add heuristic or learned mechanisms to revise committed tokens, or remask them back to [MASK] before re-predicting; a principled sampler that directly revises visible tokens without auxiliary modules remains underexplored. We introduce D3IM, a parameter-free sampler derived as a corrector-style reverse update that permits direct visible-to-visible revision without additional modules or auxiliary passes. D3IM also reveals a model-side obstacle we term preservation bias: the model tends to reproduce its own wrong committed tokens rather than correct them. We address this with SCOPE (Self-Conditioned On Prediction Errors), a lightweight post-training procedure that simulates D3IM's sampling process. On LLaDA-8B at 64 denoising steps, SCOPE+D3IM improves over the original LLaDA-8B with standard unmasking by +13.0 on GSM8K (68.3%), +4.8 on MATH-500 (23.6%), +15.3 on HumanEval (29.3%), and +10.4 on MBPP (30.8%), with gains that increase as more denoising steps are used on math and HumanEval.","published":"2026-05-31T05:35:03Z","updated":"2026-05-31T05:35:03Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.01026v1","pdf_url":"https://arxiv.org/pdf/2606.01026v1","comment":"8 pages, 2 figures, 10 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.00820","versioned_id":"2606.00820v1","title":"Not All Flips Are Conformity: Decomposing Stance Convergence in Multi-Agent LLM Debate","authors":["Xiqi Hao","Zengqing Wu","Yu-Xuan Qiu","Chuan Xiao","Ruiqi Xu","Shuyuan Zheng","Jianbin Qin"],"abstract":"Multi-agent debate (MAD) is a promising strategy for improving LLM reasoning, but when agents converge on a shared answer, it is unclear whether that convergence reflects genuine deliberation or social compliance. We show that the conventional answer flip rate conflates three distinct mechanisms: spontaneous instability, stance-induced conformity, and reasoning-induced persuasion. Our three-source decomposition framework isolates each through controlled counterfactual conditions. In the primary MMLU-Pro setting, 37% of agent-question observations change under self-reflection alone, while robustness tests show substantial model-dependent instability across GPQA-Diamond and three model families; strict conformity is 29% in the primary setting and remains predominantly harmful across model replications (57-77% correct-to-wrong). A controlled information-gradient experiment reveals that even vacuous reasoning is associated with 20-39% error adoption among resistant agents, with reasoning-like presentation carrying substantial persuasive weight. Harmful conformity can be predicted from Round 0 features (AUC = 0.79), and risk-targeted intervention reduces it by 13.6 percentage points (p < 0.001). However, without correctness labels or self-reflection controls, reducing peer adoption does not improve accuracy, because harmful and beneficial influence cannot be distinguished.","published":"2026-05-30T17:41:11Z","updated":"2026-05-30T17:41:11Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.00820v1","pdf_url":"https://arxiv.org/pdf/2606.00820v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2606.00532","versioned_id":"2606.00532v1","title":"KACE: Knowledge-Adaptive Context Engineering for Mathematical Reasoning","authors":["Jayant Parashar","Suchendra M. Bhandarkar"],"abstract":"Context engineering can improve large language models without updating their weights, but mathematical reasoning exposes a key limitation: feedback accumulated in one growing prompt causes context bloat and limits the amount of learned guidance that can be used. Existing methods often conflate storage, what is learned across runs, with usage, what is included for a particular problem, and therefore inherit this prompt-size ceiling. We introduce Knowledge-Adaptive Context Engineering (KACE), which separates storage from usage through difficulty- and domain-based organization. Offline, a self-reflective learning loop distills training traces into an epistemic tree: a knowledge base of typed cards stratified by problem difficulty and epistemic domain. Each card is assigned to the difficulty-domain node corresponding to the failure from which it originated. At evaluation time, tiered self-consistency with per-tier agreement gates dynamically classifies each problem as easy, medium, or hard. Easy problems exit without retrieved cards, while harder problems retrieve only the matching branch of the tree. This tiered scheme matches or exceeds Best-of-N while using comparable compute, and it classifies problem difficulty with 78 percent pairwise concordance. The main empirical contribution is the construction and use of a difficulty- and domain-stratified knowledge base enabled by tiered self-consistency. On AIME 2025, KACE achieves 62.2 percent accuracy, a 10.4-point absolute gain over fixed Best-of-5 self-consistency at a comparable solver-call budget and a 5.6-point gain over the strongest learned-context baseline, Tiered + GEPA. We also observe consistent gains on MATH-HARD and the verifiable subset of OlymMATH.","published":"2026-05-30T04:51:01Z","updated":"2026-05-30T04:51:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.00532v1","pdf_url":"https://arxiv.org/pdf/2606.00532v1","comment":"9 pages, 1 figure, 6 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.31561","versioned_id":"2605.31561v1","title":"What Am I Missing? Question-Answering as Hidden State Probing","authors":["Chu Fei Luo","Samuel Dahan","Xiaodan Zhu"],"abstract":"Test-time reasoning has become a significant field of study since the introduction of chain-of-thought reasoning in large language models (LLMs). However, the mechanisms of this reasoning process are still under-explored -- from the same input prompt, and even the same partial solution, LLMs can produce varied answers if sampled multiple times. We propose to leverage question-asking as an inference-time intervention that articulates information about the model's hidden state. To achieve that, we present a student-teacher setting where a student asks questions to a teacher. We train a probe on the student's hidden state before and after asking a question and find it is predictive of the trajectory's final correctness, even before generating the teacher's answer. This suggests there is a meaningful signal from the self-diagnosis that occurs during question generation rather than information transfer from the teacher. We then frame question-asking as a sequential decision problem, using this probe as a quality score, and define a gating policy to ask questions that maximize likelihood of correctness. We find that the success of question-asking as an intervention is largely dependent on the model's self-consistency. Our empirical results show a gap between detection and recovery; while our gating policy captures model correctness and uncertainty, interventions are equally likely to harm correct trajectories as they are to recover incorrect ones. This gap between diagnosis and correction has broader implications on language models' capacity for self-refinement under uncertainty.","published":"2026-05-29T17:27:07Z","updated":"2026-05-29T17:27:07Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.31561v1","pdf_url":"https://arxiv.org/pdf/2605.31561v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.31365","versioned_id":"2605.31365v1","title":"Learning to Adapt: Self-Improving Web Agent via Cognitive-Aware Exploration","authors":["Weile Chen","Bingchen Miao","Qifan Yu","Wendong Bu","Guoming Wang","Wenqiao Zhang","Shengyu Zhang","Juncheng Li","Siliang Tang"],"abstract":"Recent advances in Multimodal Large Language Models (MLLMs) have led to promising progress in web agents. However, existing web agents often rely on handcrafted execution pipelines or expensive expert trajectories, limiting their adaptability to complex, dynamic environments. To address these challenges, we propose SCALE (Self-Cognitive-Aware Learning and Exploration), which leverages three adversarial roles, Selector, Predictor, and Judger to autonomously discover the agent's limitations and expand its cognitive boundaries through environmental exploration. Moreover, we propose SCALE-Hop, a graph exploration strategy that facilitates global planning and helps agents avoid local exploration traps. To further support learning, we construct SCALE-20k, a large-scale dataset collected from 19 real-world websites, containing diverse task types and structured demonstrations generated from SCALE's exploration traces. Experimental results show that our approach significantly improves the performance and generalization of multiple MLLMs in various web environments. Our framework offers a scalable and generalizable solution for building truly autonomous and adaptive web agents.","published":"2026-05-29T14:37:27Z","updated":"2026-05-29T14:37:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.31365v1","pdf_url":"https://arxiv.org/pdf/2605.31365v1","comment":"24 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.30802","versioned_id":"2605.30802v1","title":"Design and Evaluation of Multi-Agent AI Oracle Systems for Prediction Market Resolution","authors":["Tarun Kota"],"abstract":"Prediction markets aggregate collective intelligence to forecast uncertain events, but their utility depends on reliable outcome resolution. Existing oracle systems tradeoff fast but brittle automation against accurate but costly human arbitration. Single-LLM oracles achieve meaningful accuracy but inherit all failure modes of their underlying model with no self-correction mechanism. We evaluate whether multi-agent LLM architectures can improve oracle resolution accuracy over single-model baselines. We compare independent aggregation and deliberative consensus against single-LLM baselines (GPT-5 Nano, DeepSeek V3, and Llama-3.3-70B) on 1,189 resolved prediction market questions from KalshiBench. All agents share a common evidence layer through Exa, with retrieval filtered by publication date to isolate reasoning from retrieval quality. Independent aggregation with confidence-weighted voting achieves the highest accuracy at 83.43 percent, outperforming the best individual model by 1.01 percentage points. Deliberative consensus degrades accuracy to approximately 76 percent, below every single-model baseline, attributed to error propagation during debate where confidently wrong models flip correct ones. Error correlations across models (0.529-0.689) explain why aggregation gains fall short of the theoretical Condorcet ceiling, placing a fundamental limit on ensemble approaches. Many questions resist correction by any multi-agent architecture, motivating escalation to human arbitration. We propose routing criteria for hybrid AI-human oracle systems: auto-resolving only unanimous, high-confidence questions yields 97.87 percent accuracy on 47 percent of the dataset, with inter-agent disagreement flagging the remainder for human review.","published":"2026-05-29T03:44:19Z","updated":"2026-05-29T03:44:19Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.30802v1","pdf_url":"https://arxiv.org/pdf/2605.30802v1","comment":"34 pages, 11 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.30290","versioned_id":"2605.30290v2","title":"Self-Trained Verification for Training- and Test-Time Self-Improvement","authors":["Chen Henry Wu","Aditi Raghunathan"],"abstract":"Self-improvement at scale has been a longstanding goal for reasoning models, and there are two natural places to do it: at test time, through verification-refinement (V-R) loops; and at training time, through self-training methods. Both are gated by the same bottleneck: the verifier. V-R loops stall when verifier scores inflate while accuracy stagnates, and when feedback is too generic to act on; self-training fails similarly when bad self-generated data are added to training. Better verification would unlock both, but the capability we want to train, i.e., catching self-generated errors, lacks training signal. To address this challenge, we propose self-trained verification (STV). Our key observation is that, while a model cannot catch these errors alone, it can when shown the reference solution. We turn this asymmetry into a supervision target and train the verifier to imitate a more informed version of itself. At test time, STV substantially improves V-R loops on hard problems, while alternatives (e.g., SFT, RL on verifier scores, and even meta-verifiers) do not. STV roughly doubles accuracy on hard math and lifts it 14x on scientific reasoning tasks (1.5% to 21%). At training time, we additionally train the generator using RL with STV verifier's feedback inside the V-R loop - a procedure we call verifier-in-the-loop training (ViL). Starting from an RL-converged generator, ViL yields a further 33% gain in pass@1. More notably, the generator's standalone pass@1, with no verifier at test time, climbs 30% relative past where standard RL had converged. Hence, the next frontier in reasoning on hard problems may lie in how we train for and with verification. Website: https://ar-forum.github.io/stv-webpage","published":"2026-05-28T17:40:45Z","updated":"2026-05-31T05:24:16Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.30290v2","pdf_url":"https://arxiv.org/pdf/2605.30290v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.30227","versioned_id":"2605.30227v1","title":"Unifying Temporal and Structural Credit Assignment in LLM-Based Multi-Agent Prompt Optimization","authors":["Wenwu Li","Yuran Song","Mingze Zhao","Bo Jin","Wenhao Li"],"abstract":"While Multi-Agent Systems (MAS) empower Large Language Models to tackle complex reasoning tasks through collaborative interaction, optimizing their dynamics remains a formidable challenge due to the discrete, non-differentiable nature of the computation graph and the sparsity of global supervisory signals. Existing black-box optimizers struggle to attribute trajectory-level failure to specific local components, resulting in inefficient, high-variance exploration. We argue that tractable MAS optimization needs structural inductive biases to disentangle error signals. We propose temporal and structural credit assignment, which decomposes the objective along two axes: (i) temporal credit, using state-space bottlenecks to identify critical rounds, and (ii) structural credit, using stationary role policies to isolate agent contributions. Leveraging these decomposed signals, we introduce a discrete, verbalized block coordinate descent algorithm for iterative refinement. Rather than indiscriminate global updates, it alternates between optimizing role prompts and aggregation protocols, using LLM-generated \"proxy gradients\" to target only the identified weak links. Across diverse reasoning benchmarks, our approach substantially reduces query complexity while improving performance, providing a principled and interpretable path toward self-improving MAS.","published":"2026-05-28T16:57:57Z","updated":"2026-05-28T16:57:57Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.30227v1","pdf_url":"https://arxiv.org/pdf/2605.30227v1","comment":"15 pages, 4 figures, 6 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.30104","versioned_id":"2605.30104v1","title":"SEAL: Can Saturated Benchmarks Be Revived by LLM-as-a-Meta-Judge?","authors":["Jiamin Chen","Yidi Wu","Qiexiang Wang","Qianben Chen","Yuchen Li","Yansen Zhang","Xiaokun Zhang","Wangchunshu Zhou","Chen Ma"],"abstract":"Widely used language-model benchmarks are increasingly saturated, with frontier systems often receiving near-tied scores that standard metrics cannot resolve. Rather than constructing harder alternatives, we ask whether existing tasks can be made informative again through improved evaluation over the same candidate outputs. Therefore, we present Seeded Elimination with Adaptive LLM-as-a-Meta-Judge, a self-improving evaluation protocol for extracting latent ranking signal from saturated benchmarks. SEAL seeds candidate outputs into a single elimination and evaluates each match with task-level principles plus self-improving checklist criteria. We evaluate SEAL on multiple saturated benchmarks covering code generation, mathematical reasoning, knowledge-intensive question answering, and tool-use agent task completion. Across these settings, SEAL improves the ranking-accuracy--latency trade-off over competing protocols, attaining 0.83--1.00 Spearman agreement with full pairwise judging and 4/4 top-1 agreement, while requiring only 11.89 calls per task compared with 28.00 for full pairwise evaluation.","published":"2026-05-28T15:46:54Z","updated":"2026-05-28T15:46:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.30104v1","pdf_url":"https://arxiv.org/pdf/2605.30104v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.29874","versioned_id":"2605.29874v2","title":"Evolutionary Dynamics of Cooperation in Next-Generation LLM Agent Systems: A Cross-Provider Empirical Extension","authors":["Francisco León Zúñiga Bolívar"],"abstract":"Do next-generation LLM agents inherit the cooperative biases documented in their predecessors, or does scale and provider diversity reshape equilibrium behaviour in competitive multi-agent settings? Willis et al. established a benchmark for this question using evolutionary game theory and the Iterated Prisoner's Dilemma (IPD), finding consistent cooperative biases in ChatGPT-4o and Claude 3.5 Sonnet. We extend this benchmark to four frontier models released in 2025-2026 - Claude Sonnet 4.6, Gemini 2.5 Flash, Gemini 3.1 Pro, and GPT-5.4 Mini - applying the identical protocol across three prompting styles (Default, Prose, Self-Refine) and four population compositions (balanced and biased, with and without noise). Cooperative bias persists across providers (H1): ten of twelve model-prompt combinations favour cooperative equilibria in balanced noiseless conditions. Cross-provider divergence is substantial (H3): Gemini 2.5 Flash reaches up to 77% aggressive equilibria under biased conditions, while GPT-5.4 Mini reaches 70% cooperative equilibria under Self-Refine. Support for aggressive capability parity is partial (H2): Self-Refine raises ICD in all models and Gemini 3.1 Pro Refine achieves the highest ICD in the dataset (0.925), but Default and Prose prompts show no systematic narrowing. Evidence on noise robustness is directionally positive but not robustly confirmed (H4): with n=500 Moran iterations per condition, average noise sensitivity is about 6 percentage points for Claude Sonnet 4.6 versus 13 pp for Claude 3.5 Sonnet, but this cross-study gap is not statistically significant once the predecessor's unreported sampling error is propagated. Provider identity, rather than model generation, is the strongest correlate of equilibrium outcomes; noise remains a universal challenge regardless of model size or vintage.","published":"2026-05-28T12:58:56Z","updated":"2026-06-14T15:03:42Z","categories":["cs.MA","cs.AI","cs.GT"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.29874v2","pdf_url":"https://arxiv.org/pdf/2605.29874v2","comment":"v2 (erratum): two truncated Gemini 3.1 Pro libraries regenerated; cooperative-plurality 9/12->10/12, conclusions unchanged. 11 pages, 3 figures, 8 tables. Extends arXiv:2501.16173. Code and n=500 replication: https://github.com/arqFranciscoLeon/evollm (archived: https://doi.org/10.5281/zenodo.20248615)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.29668","versioned_id":"2605.29668v1","title":"GRASP: Gated Regression-Aware Skill Proposer for Self-Improving LLM Agents","authors":["Johannes Moll","Jean-Philippe Corbeil","Jiazhen Pan","Martin Hadamitzky","Daniel Rueckert","Lisa Adams","Keno Bressem"],"abstract":"LLM agents acting in structured environments fail in operational rather than conversational ways, and reliability depends on procedural knowledge of the environment. Prior self-improvement methods accumulate natural-language guidance without checking that each new item preserves previously correct behavior, so a note that fixes one trajectory can silently regress another. We introduce GRASP (Gated Regression-Aware Skill Proposer), which treats agent improvement as a sequence of edits to a bounded skill library, admitting each candidate only if it produces a net improvement on a balanced held-out probe under a hard regression budget. We evaluate GRASP across five base models (gpt-oss-120b, DeepSeek V4 Flash, Gemini 3.1 Flash Lite, GPT-4.1, GPT-5.4) on two FHIR-based clinical benchmarks. On MedAgentBench, GRASP lifts gpt-oss-120b from 40.6% to 88.8%, exceeds the strongest of five self-improvement baselines by 21.0 points, and improves every other base model by 17.2 to 40.3 points. Ablations attribute the gain to comparative proposal generation, the acceptance gate, and the hard regression budget rather than to skill writing itself, which without validation is no better than using no skills. The mechanism generalizes beyond the clinical domain, improving agents on three of four non-clinical environments and remaining flat only where the action space is open-ended. Frozen libraries transfer across models, where skills from a stronger model improve weaker executors beyond what they learn for themselves while the reverse does not, an asymmetry that no ungated baseline reproduces.","published":"2026-05-28T09:30:09Z","updated":"2026-05-28T09:30:09Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.29668v1","pdf_url":"https://arxiv.org/pdf/2605.29668v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.29568","versioned_id":"2605.29568v1","title":"DeepTool: Scaling Interleaved Deliberation in Tool-Integrated Reasoning via Process-Supervised Reinforcement Learning","authors":["Yang He","Xiao Ding","Bibo Cai","Yufei Zhang","Kai Xiong","Zhouhao Sun","Bing Qin","Ting Liu"],"abstract":"Tool-Integrated Reasoning (TIR) extends LLM capabilities by leveraging external environments. However, existing methods lack the deliberation during sequential tool invocation required for strategic planning and self-correction. While RL mitigates this, conventional approaches for Tool-Integrated Reasoning are hindered by sparse outcome-based rewards, failing to supervise intermediate reasoning steps and tool invocations. To address this, we propose DeepTool, a novel framework that scales deliberate thinking within the interleaved process of thinking, action, and observation at each turn. In DeepTool, we first introduce a synthesis pipeline that evolves extended thinking into interleaved trajectories, integrating adversarial perturbations to ensure robustness and self-correction. Secondly, we devise Process-Supervised Reinforcement Learning based on GRPO, which utilizes an Action-Centric Process Reward to reinforce intermediate interleaved thinking and enforce precise tool invocation at every turn. Extensive experiments demonstrate that DeepTool achieves superior performance, boosting Qwen2.5-7B significantly across six benchmarks (e.g., AIME24: 3.2% -> 40.4% and HMMT25: 0.0% -> 28.6%). Furthermore, the token cost-effectiveness analysis confirms the utility of interleaved thinking, demonstrating DeepTool's optimal balance between performance and token efficiency.","published":"2026-05-28T08:17:20Z","updated":"2026-05-28T08:17:20Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.29568v1","pdf_url":"https://arxiv.org/pdf/2605.29568v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.29440","versioned_id":"2605.29440v1","title":"SkillBrew: Multi-Objective Curation of Skill Banks for LLM Agents","authors":["Wentao Hu","Zhendong Chu","Yiming Zhang","Junda Wu","Ming Jin","Xiangyu Zhao","Yilei Shao","Yanfeng Wang","Qingsong Wen"],"abstract":"Retrieval-augmented LLM agents increasingly rely on curated skill banks: collections of reusable textual principles that guide decision making on complex tasks. Existing approaches typically expand these banks in an append-only fashion, continuously adding new skills without removing redundant, outdated, or harmful ones, resulting in inefficient and poorly curated repositories. In this paper, we formulate the skill bank curation as a constrained multi-objective problem: a desirable bank must be useful for the agent, diverse in its content, and provide good coverage of the query distribution. To this end, we introduce SkillBrew, a multi-objective curation framework that formalizes skill bank curation as Pareto-aware optimization under a utility constraint, and solves it via a bi-level propose-then-verify loop. We evaluate our approach on two public benchmarks. Our findings suggest that treating skill banks as objects of principled curation, rather than ever-growing append-only logs, is an important step toward building self-improving LLM agents.","published":"2026-05-28T06:33:52Z","updated":"2026-05-28T06:33:52Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.29440v1","pdf_url":"https://arxiv.org/pdf/2605.29440v1","comment":"16 pages. Preprint. Under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28814","versioned_id":"2605.28814v1","title":"Self-Improving Language Models with Bidirectional Evolutionary Search","authors":["Guowei Xu","Zhenting Qi","Huangyuan Su","Weirui Ye","Himabindu Lakkaraju","Sham M. Kakade","Yilun Du"],"abstract":"Search has been proposed as an effective method for self-improving language models and agentic systems, both for post-training sample generation and for inference. However, widely used methods such as best-of-N sampling and tree search face two fundamental limitations: they are guided by sparse verification signals, and they construct candidates primarily through autoregressive expansion, restricting exploration to regions with substantial model probability mass. To address these, we propose Bidirectional Evolutionary Search (BES), a search framework that couples forward candidate evolution with backward goal decomposition. In the forward search, BES augments standard expansion with evolution operators that recombine partial trajectories to generate candidates that are difficult to obtain from a single model rollout. In the backward search, BES recursively decomposes the original task into checkable subgoals, producing dense intermediate feedback that guides forward search. We provide theoretical motivation showing that candidates generated by expansion-only search are confined to a narrow entropy shell while evolutionary operators can escape it, and that backward search can exponentially reduce the number of required samples to find a correct answer. Experiments show that on challenging post-training tasks where mainstream post-training algorithms fail to improve, BES enables consistent gains, and on three open problem solving benchmarks at inference time, BES outperforms existing open-source frameworks in both average and best-case performance. Code and trained models are available at https://github.com/Embodied-Minds-Lab/BES.","published":"2026-05-27T17:59:15Z","updated":"2026-05-27T17:59:15Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.28814v1","pdf_url":"https://arxiv.org/pdf/2605.28814v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28805","versioned_id":"2605.28805v1","title":"OmniVerifier-M1: Multimodal Meta-Verifier with Explicit Structured Recalibration","authors":["Xinchen Zhang","Bowei Liu","Jiale Liu","Chufan Shi","Yizhen Zhang","Junhong Liu","Youliang Zhang","Zhiheng Li","Yujiu Yang","Ling Yang"],"abstract":"Visual outcomes are increasingly central to multimodal large language models, making reliable and fine-grained verification essential for scaling generalist foundation models. In this work, we investigate multimodal meta-verification, which leverages verifier-generated rationales rather than decision-only signals, and explore how to effectively incorporate meta-verification feedback into multimodal verifier training. We identify two key findings. First, symbolic verifier outputs (e.g., bounding boxes) outperform textual explanations as meta-verification rationales, enabling efficient rule-based reinforcement learning rewards while avoiding reliance on model-based rewards from auxiliary judge models. Second, decoupling reinforcement learning objectives for binary judgment and meta-verification substantially outperforms joint reward optimization, due to intrinsic differences in output structure and learning dynamics. Based on these insights, we train OmniVerifier-M1, a generalist visual verifier leveraging symbolic meta-verification and decoupled reinforcement learning. OmniVerifier-M1 provides robust verification and fine-grained error localization, and further enables M1-TTS, a verifier-driven agentic generation system achieving dynamic region-level self-correction. This approach paves the way for more reliable, interpretable, and fine-grained multimodal verification, supporting safer and more controllable foundation model deployment.","published":"2026-05-27T17:56:04Z","updated":"2026-05-27T17:56:04Z","categories":["cs.CL","cs.AI","cs.CV","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.28805v1","pdf_url":"https://arxiv.org/pdf/2605.28805v1","comment":"ICML 2026. Project: https://github.com/Cominclip/OmniVerifier","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28916","versioned_id":"2605.28916v2","title":"First head-to-head comparison of agentic AI applied to the analysis of simulated data of the Einstein Telescope","authors":["Gianluca Inguglia"],"abstract":"We report a comparison of two state-of-the-art agentic AI systems, Claude Code (Anthropic) and Codex (OpenAI), tasked with autonomously executing a simple end-to-end gravitational wave data analysis pipeline on a shared computing infrastructure without human intervention. The pipeline comprises power spectral density estimation from raw Einstein Telescope simulated noise, geometric template bank generation, matched filter recovery of 100 binary black hole signal injections, automated results generation, and large language model-assisted production of a manuscript formatted in the style of Physical Review D. Both agents received identical written specifications and identical compute resources. The experiment was run twice: a first run with unrealistically loud injections, and a second run with signals rescaled to a physically motivated SNR range. The scientific results converged in both runs. However, the agents exhibited substantially different behaviors and computational costs: Claude Code completed the pipeline in ~3.4 minutes with silent deviations from the specification, while Codex required ~16 minutes across explicit self-correcting restarts, including an unsolicited performance optimization of the matched filter inner loop. The autonomously generated manuscripts also diverged in length, details, and quality. In the second run, a subtle difference in the interpretation of the SNR range instruction led to a genuine scientific divergence: Claude Code silently reinterpreted the instructions, while Codex followed the specification literally. We discuss the implications of these behavioral differences, such as speed versus auditability, silent versus transparent error handling, instruction interpretation, and the criticality of intermediate data representations in multi-model pipelines, for the deployment of agentic AI in scientific computing workflows.","published":"2026-05-27T17:54:26Z","updated":"2026-05-29T07:07:56Z","categories":["astro-ph.IM","cs.AI","cs.HC"],"primary_category":"astro-ph.IM","arxiv_url":"https://arxiv.org/abs/2605.28916v2","pdf_url":"https://arxiv.org/pdf/2605.28916v2","comment":"Version 2; includes the report autonomoulsy written in PRD style by agentic AI systems as supplemental material","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28910","versioned_id":"2605.28910v3","title":"Hallucination Detection-Guided Preference Optimization for Clinical Summarization","authors":["Shamanth Kuthpadi Seethakantha","Dung Ngoc Thai","Vara Prasad Gudi","Simran Tiwari","Rami Matar","Avijit Mitra","Wenlong Zhao","Andrew McCallum","Wael Salloum"],"abstract":"Large language models (LLMs) have shown promise on summarization tasks, but they often produce hallucinations, which are unsupported or incorrect statements that limit their reliability in specialized healthcare applications. We introduce Hallucination Detection Guided Self-Refinement (HDSR), an inference-time method that leverages hallucination detectors to guide iterative summary revisions toward factual corrections. Building on this, we propose HDSR for Preference Learning (HDSR-PL), which converts detector-guided refinement trajectories into preference pairs for model finetuning. Extensive experiments show that our methods substantially reduce hallucinations for Llama and Gemma models in summarizing real-world clinical notes from MIMIC-IV-Note v2.2. For example, HDSR reduces 24% and HDSR-PL reduces 48% hallucinations in Llama-3.1-8B-Instruct. Importantly, both methods preserve summary fluency, coherence, and relevance according to human expert and LLM-Jury evaluations. Together, these results demonstrate that detection-informed refinement and preference learning offer an automated solution for improving factual faithfulness in clinical summarization.","published":"2026-05-27T17:24:26Z","updated":"2026-06-02T03:32:14Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.28910v3","pdf_url":"https://arxiv.org/pdf/2605.28910v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28742","versioned_id":"2605.28742v2","title":"CORE: Contrastive Reflection Enables Rapid Improvements in Reasoning","authors":["Linas Nasvytis","Simon Jerome Han","Ben Prystawski","Satchel Grant","Noah D. Goodman","Judith E. Fan"],"abstract":"Language models can use verifiable rewards to improve at a wide variety of reasoning tasks. However, both parametric (e.g. RLVR) and non-parametric (e.g. prompt optimization) approaches to doing so typically require hundreds of training samples and thousands of model rollouts, making them expensive in the best case and intractable in the worst. To address this challenge, we introduce Contrastive Reflection (CORE), a non-parametric learning algorithm that compares past reasoning traces to generate insights: short natural-language descriptions of reasoning strategies and constraints that capture differences between successful and unsuccessful problem attempts. Across four reasoning tasks, we demonstrate that CORE enables more rapid improvement than both parametric (GRPO) and non-parametric (GEPA, episodic RAG, and MemRL) methods, while using fewer rollouts. Under fixed rollout budgets with as few as five training samples, CORE achieves the strongest performance in most task-data regimes. Finally, we highlight how CORE is substantially more context-efficient than non-parametric baselines, requiring fewer prompt tokens while storing learned knowledge as compact, interpretable natural-language insights. Our results therefore suggest that distilling contrasts between successful and unsuccessful reasoning traces into abstract and useful insights can provide a more efficient and interpretable route to model self-improvement than weight updates, prompt optimization, or direct reuse of stored reasoning traces.","published":"2026-05-27T17:01:50Z","updated":"2026-06-05T17:02:41Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.28742v2","pdf_url":"https://arxiv.org/pdf/2605.28742v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28607","versioned_id":"2605.28607v1","title":"Adaptive Multimodal Agents-Based Framework for Automatic Workflow Execution","authors":["Susanna Cifani","Mario Luca Bernardi","Marta Cimitile"],"abstract":"Modern information systems require autonomous agents capable of navigating complex workflows, yet current methodologies often struggle with the transition from structured metadata parsing to general environmental perception. While the integration of MLLMs has enabled agents to interact directly with GUIs, existing approaches typically treat task sequences as discrete, linear episodes. This fragmentation prevents agents from capturing the underlying transition topology, limiting their effectiveness in novel or non-stationary scenarios. To address this, we propose a novel multimodal multi-agent framework that achieves automatic workflow execution through a distinct two-phase pipeline. First, during an offline discovery phase, the architecture adaptively constructs a topological knowledge base from fragmented execution logs. During inference, agents leverage Adaptive Retrieval-Augmented Generation (RAG) over this fixed, pre-established graph, coupled with a closed-loop collaborative verification protocol to dynamically self-correct and navigate. This graph-based approach facilitates superior task decomposition and adaptive navigation performance. We validate our framework in a real-world context, demonstrating its ability to maintain high reliability and semantic awareness even with limited training data.","published":"2026-05-27T15:23:22Z","updated":"2026-05-27T15:23:22Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.28607v1","pdf_url":"https://arxiv.org/pdf/2605.28607v1","comment":"Copyright 2026 IEEE. Personal use of this material is permitted. Permission from IEEE must be obtained for all other uses. Accepted for publication at the 2026 IEEE International Conference on Evolving and Adaptive Intelligent Systems (EAIS 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28421","versioned_id":"2605.28421v1","title":"DenoiseRL: Bootstrapping Reasoning Models to Recover from Noisy Prefixes","authors":["Caijun Xu","Changyi Xiao","Zhongyuan Peng","Yixin Cao"],"abstract":"Reinforcement learning has become a central paradigm for advancing reasoning in large language models, yet most existing methods still depend on stronger teacher models or heavily curated difficult datasets, limiting scalable capability improvement. In this paper, we introduce DenoiseRL, a reinforcement learning framework that substitutes external supervision with recovery-oriented optimization over failures from weak models. Instead of relying on stronger supervision or carefully engineered data, DenoiseRL learns directly from incorrect reasoning traces by converting them into opportunities for improvement, making training more scalable and less dependent on external resources. This yields a richer and more diverse learning signal, improving exploration efficiency from imperfect model behavior. As a result, DenoiseRL improves reasoning performance and overall training efficiency while reducing the need for expensive data curation or stronger teacher models. Empirically, DenoiseRL consistently outperforms strong on-policy RL baselines across competitive mathematical and general reasoning benchmarks and promotes stronger self-corrective behavior as training difficulty increases, highlighting an effective and scalable alternative pathway for improving reasoning in large language models.","published":"2026-05-27T12:52:58Z","updated":"2026-05-27T12:52:58Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.28421v1","pdf_url":"https://arxiv.org/pdf/2605.28421v1","comment":"17 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28070","versioned_id":"2605.28070v1","title":"Bridging the Detection-to-Abstention Gap in Reasoning Models under Insufficient Information","authors":["Renjie Gu","Jiaxu Li","Yihao Wang","Yun Yue","Hansong Xiao","Yefei Chen","Yuan Wang","Chunxiao Guo","Pei Wei","Jinjie Gu","Yixin Cao"],"abstract":"We highlight a failure mode of large reasoning models on questions with insufficient information: models may recognize that a problem is under-specified, yet still continue reasoning and produce unsupported final answers instead of abstaining. We formalize this mismatch as the detection-to-abstention gap, where detected insufficiency fails to translate into final abstention. This gap is especially concerning in high-risk domains such as medical AI, where answers based on incomplete evidence can be more harmful than refusal. To close this gap, we propose Judge-Then-Solve (JTS), a trajectory-level reasoning-control framework that trains models to make an explicit answerability commitment before solution generation. Rather than treating abstention as a final-answer style, JTS casts it as a control decision: the model either proceeds to solve or terminates early based on its answerability judgment. We instantiate this policy through supervised warm-up and missing-premise reinforcement learning with consistency and length-shaping rewards. Experiments on dense and MoE reasoning models show that JTS substantially improves reliable abstention across datasets and pushes Abstention@Detection (A@D) to near-saturation, indicating that models not only detect missing information but also act on that detection. By terminating unanswerable trajectories immediately after the answerability judgment, JTS reduces unnecessary reasoning and improves inference efficiency when continued deliberation would amplify unsupported assumptions. We also observe that missing-premise training can alter reasoning behavior on difficult but answerable problems, reducing unproductive self-reflection. These results suggest that abstention under insufficient information is a key form of reasoning control for deploying reasoning models safely and efficiently.","published":"2026-05-27T07:28:25Z","updated":"2026-05-27T07:28:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.28070v1","pdf_url":"https://arxiv.org/pdf/2605.28070v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.27965","versioned_id":"2605.27965v1","title":"The Shape of Overthinking: Backtracking Bursts in Long Reasoning Traces","authors":["Navid Rezazadeh","Arash Gholami Davoodi"],"abstract":"Reasoning models often generate long traces in which useful self-correction and unproductive revision are hard to distinguish. We study this distinction through backtracking dynamics: local reconsideration, retraction, or re-derivation inside long-form reasoning traces. On 6{,}000 Qwen3-8B AIME traces, we annotate segment-level backtrack severity and analyze event timing, normalized depth, and local burst structure. We find that early isolated repair is often compatible with correct reasoning, whereas incorrect traces more often show moderate-to-severe backtracks that persist and cluster late. Cross-corpus checks show the same qualitative asymmetry across additional model/domain pairs. Filtering analyses instantiate the signal as a prefix-causal selective early-exit policy: at shallow and intermediate depths, burst-aware filtering outperforms fixed length-based filtering while using only prefix-available features. Moderate length cutoffs remain strong completed-trace baselines, but burst-aware control provides a deployable mechanism for separating recoverable repair from likely instability.","published":"2026-05-27T05:01:04Z","updated":"2026-05-27T05:01:04Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.27965v1","pdf_url":"https://arxiv.org/pdf/2605.27965v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.27564","versioned_id":"2605.27564v1","title":"The Future of Facts: Tracing the Factual Generation-Verification Gap","authors":["Tim R. Davidson","Anja Surina","Caglar Gulcehre"],"abstract":"Language models are becoming the default interface to factual knowledge, yet they often verify outputs more reliably than they generate them. This generation-verification gap (GV-gap) underlies many recent advances in self-improvement and reasoning, but its dynamics on factual knowledge specifically remain poorly understood. We focus on the training mechanisms underlying factual GV-gaps, distinguishing them from their computational and aesthetic counterparts. We trace generation and verification capabilities through three training phases (acquisition, continual learning, and updating) across four open-source model families at two scales each. Three findings recur across models: (i) verification is consistently learned before generation; (ii) verification is more robust to continual learning than generation; and (iii) factual updates can leave models in a \"multi-verse\" state, simultaneously verifying both old and new answers as correct. Natural experiments on frontier models reproduce these dynamics at scale and reveal residual verification biases on well-covered facts.","published":"2026-05-26T18:36:42Z","updated":"2026-05-26T18:36:42Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.27564v1","pdf_url":"https://arxiv.org/pdf/2605.27564v1","comment":"Code for this project is available at https://github.com/anjasurina/factgap , blog post at https://www.trdavidson.com/fact-gap","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.27559","versioned_id":"2605.27559v1","title":"Detection Without Correction: A Two-Parameter Decomposition of Multi-Stage LLM Pipelines","authors":["Prashanti Nilayam","Kiran Ramanna","Prashil Tumbade"],"abstract":"Multi-stage LLM pipelines that perform multi-agent debate, intrinsic self-correction, or retrieval-augmented verification exhibit puzzling aggregate behaviors: accuracy plateaus and reversals across rounds, non-replication of debate gains on contemporary frontier models, intrinsic self-correction degradation, and qualitative cross-provider divergence in debate dynamics. Downstream agent response can be operationalized as two coupled decisions: detection (whether to treat upstream content as authoritative) and conditional generation (what to produce if not). This decomposition yields four observable response regimes, of which detection-without-correction is the load-bearing failure mode. Across a nine-cell empirical grid spanning four model families, four benchmarks (GSM8K, MATH-500, GPQA-Diamond, AIME), and two methods (multi-agent debate, intrinsic self-correction), we find that the conditional miscorrection rate is consistently dominant (53-94% across cohorts) while detection rate varies contextually by more than an order of magnitude. The framework unifies the four phenomena above as signatures of a common mechanism and characterizes detection threshold as a stable model/protocol-level regularity that persists across methods at matched benchmark difficulty.","published":"2026-05-26T18:26:15Z","updated":"2026-05-26T18:26:15Z","categories":["cs.MA","cs.AI","cs.LG"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.27559v1","pdf_url":"https://arxiv.org/pdf/2605.27559v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.27276","versioned_id":"2605.27276v2","title":"SIA: Self Improving AI with Harness & Weight Updates","authors":["Prannay Hebbar","Yogendra Manawat","Samuel Verboomen","Alesia Ivanova","Selvam Palanimalai","Kunal Bhatia","Vignesh Baskaran"],"abstract":"Humans are the bottleneck in building and improving AI. Both the models and the agents that wrap them are written, tuned, and corrected by people. The long-horizon goal of an AI that can figure out how to improve itself remains open. Two largely disjoint research lines attack this bottleneck. The harness-update school has a meta-agent rewrite the scaffold of a task-specific agent (its tools, prompts, retry logic, and search procedure) while the model weights are held fixed. The test-time training school uses hand-written RL pipelines to update the model's own weights on task feedback while the harness is held fixed. These two silos operate in isolation. We propose SIA, a self-improving loop in which a language-model agent (the Feedback-Agent) updates both the harness and the weights of a task-specific agent. We evaluate across three contrasting domains: Chinese legal charge classification, low-level GPU kernel optimisation, and single-cell RNA denoising. Combining both levers outperforms scaffold iteration alone on all three benchmarks. SIA-W+H achieves 25.1% over prior SOTA on LawBench, 12.4% faster GPU kernels than prior SOTA (1,017 vs 1,161 μs), and 20.4% over prior SOTA on denoising. Harness updates make the model agentic, shaping how it searches and acts, while weight updates build the domain intuition that no prompt or scaffold can instil.","published":"2026-05-26T16:55:46Z","updated":"2026-05-28T08:21:29Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.27276v2","pdf_url":"https://arxiv.org/pdf/2605.27276v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.26690","versioned_id":"2605.26690v1","title":"Self-Improvement Imitation with Biologically Guided Search for Protein Design Under Oracle Budgets","authors":["Ashima Khanna","Dominik Grimm"],"abstract":"Protein sequence optimization under tight oracle budgets requires methods that explore vast combinatorial spaces while making each evaluation informative. Existing reinforcement learning and off-policy generative approaches often degrade under surrogate noise, and position-agnostic mutation proposals risk disrupting functionally critical residues. We introduce SILO, a trajectory-level self-improvement imitation framework for oracle-budgeted protein design. SILO uses a hierarchical edit policy that decomposes each mutation into a position choice followed by a residue choice. In each active-learning round, the policy samples candidate trajectories via incremental stochastic beam search without replacement (SBS), and a UCB-based proxy ensemble, combined with an alanine-scan fitness score (AFS), selects candidates with functionally relevant edits for in silico oracle evaluation. The policy is then updated by next-action cross-entropy imitation on the round's best oracle-labeled trajectories, avoiding value-function estimation. Across eight reproduced protein fitness landscapes and five strong baselines from prior work, SILO achieves the highest maximum and top-100 mean fitness on 8 of 8 landscapes within our evaluations, often exhibiting faster early-stage improvement. In low-data and noisy-proxy stress tests on two landscapes per setting, SILO remains competitive or best when several baselines degrade. Ablations show that SBS with AFS account for much of the gains, with iterative imitation providing additional improvement. Code is available at: https://github.com/grimmlab/SILO.git","published":"2026-05-26T08:29:36Z","updated":"2026-05-26T08:29:36Z","categories":["cs.LG","cs.AI","q-bio.QM"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.26690v1","pdf_url":"https://arxiv.org/pdf/2605.26690v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.26520","versioned_id":"2605.26520v1","title":"InterSketch: An Interleaved Reasoning Model with Self-correcting Visual Sketch and Stepwise Reward","authors":["Zhiwei Ning","Wenwen Tong","Xiangli Kong","Shengnan Ma","Ziyi Shang","Jingcheng Ni","Tao Hu","Yong Xien Chng","Jixuan Ying","Zehuan Wu","Hanming Deng","Jie Yang","Yuanjie Zheng","Wei Liu","Lewei Lu"],"abstract":"While vision-language models (VLMs) have exhibited multi-turn visual reasoning capabilities, their reasoning trajectories remain relatively shallow and are dominated by a text-centric paradigm, limiting their applicability to complex visual challenges. In contrast, human-like thought typically involves long-horizon reasoning with an interleaved visual-textual chain-of-thought (VT-CoT). To bridge this gap, we introduce InterSketch, an interleaved reasoning model to enhance the VT-CoT capability via self-correcting and stepwise reward mechanisms. InterSketch dynamically generates intermediate visual sketches using external tools and interleaves them with textual reasoning, enabling effective perception and logical reasoning over long-horizon visual understanding tasks. Specifically, in the first cold-start stage, we propose a synthesized high-quality interleaved VT-CoT dataset and include a reflection mechanism to enable the model's capability in multi-turn interleaved reasoning and self-correction. In the subsequent reinforcement learning (RL) stage, we design a stepwise reward mechanism to mitigate the sparsity of reward signals inherent in end-only supervision over long-horizon reasoning. Extensive experiments on visual reasoning benchmarks demonstrate the effectiveness of InterSketch, even outperforming proprietary models such as Gemini-3-Pro.","published":"2026-05-26T04:07:49Z","updated":"2026-05-26T04:07:49Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2605.26520v1","pdf_url":"https://arxiv.org/pdf/2605.26520v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.26195","versioned_id":"2605.26195v2","title":"CyberEvolver: Structured Self-Evolution for Cybersecurity Agents On the Fly","authors":["Yihe Fan","Changyi Li","Lichen Xu","Xudong Pan","Jiarun Dai","Hong Geng","Min Yang"],"abstract":"LLM-based agents are increasingly used for cybersecurity tasks, but most existing systems rely on fixed, human-designed scaffolds that struggle to adapt across diverse targets and failure modes. We introduce \\textsc{CyberEvolver}, a self-evolving cybersecurity agent framework that iteratively revises its own scaffold based on experience from failed execution attempts. Self-evolution in cybersecurity is challenging because the space of possible scaffold changes is largely unstructured, execution feedback is sparse and often obscured by the environment, and low-diversity updates can cause errors to compound over repeated iterations. \\textsc{CyberEvolver} addresses these challenges with a four-layer evolvable agent architecture that decomposes scaffold optimization into structured components, a trace-to-diagnosis mechanism that converts noisy execution logs into actionable revision signals, and a population-based beam search strategy that preserves diverse agent variants during evolution. We evaluate \\textsc{CyberEvolver} on CTF challenges, vulnerability exploitation, and penetration-testing tasks using four open-source LLMs. Across these settings, \\textsc{CyberEvolver} improves the seed agent's success rate by $13.6$\\,\\% on average, and outperforms six human-designed cybersecurity agents as well as two self-improvement methods adapted from other domains. These results suggest that scaffold self-evolution is a promising direction for building adaptive LLM agents for security testing.","published":"2026-05-25T16:26:59Z","updated":"2026-06-16T16:19:26Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.26195v2","pdf_url":"https://arxiv.org/pdf/2605.26195v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.25720","versioned_id":"2605.25720v1","title":"Learning to Search and Searching to Learn for Generalization in Planning","authors":["Michael Aichmüller","Yannik Hesse","Hector Geffner"],"abstract":"Combinatorial generalization remains a central challenge in Deep Reinforcement Learning (DRL). Classical planning provides a simple yet challenging setting to study this problem through explicit relational descriptions, without requiring learning from perception. In sparse-reward domains, standard RL exploration via real-time search is ineffective, and learning-based planning methods often rely on expert demonstrations, hindsight relabeling, or random walks from the goal state. In contrast, planners rely on best-first search methods such as $\\mathrm{A}^\\star$ to solve problems from scratch. We propose a self-improving $\\mathrm{WA}^\\star$ learning framework in combination with a value heuristic represented by a Relational Graph Neural Network: the heuristic guides search, and the resulting search data updates the heuristic via $Q$-learning. This loop yields heuristics that can function as general policies and solve new instances even without search, where DRL otherwise fails, as we show on puzzles such as Sokoban, PushWorld, The Witness, and the 2023 International Planning Competition benchmarks. Notably, we demonstrate strong zero-shot generalization: For example, heuristics trained on Blocksworld instances with fewer than 30 blocks successfully solve instances with 488 blocks without search.","published":"2026-05-25T11:25:13Z","updated":"2026-05-25T11:25:13Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.25720v1","pdf_url":"https://arxiv.org/pdf/2605.25720v1","comment":"Accepted at ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.25658","versioned_id":"2605.25658v1","title":"AutoSG: LLM-Driven Solver Generation Solely from Task Prompts for Expensive Optimization","authors":["Haoran Gu","Handing Wang","Yi Mei","Mengjie Zhang"],"abstract":"Expensive optimization tasks are ubiquitous in real-world applications, demanding highly specialized solvers. While LLM-driven automated solver generation shows promise, current paradigms face three critical issues when tackling expensive optimization: factual hallucinations due to deficient domain knowledge, the frequent dismantling of previously established locally optimal structures during refinement, and the prohibitive evaluation costs alongside restricted generalization caused by executing on training instances. To address these issues, we introduce AutoSG, a fully automated workflow directly translating natural language prompts into executable customized solvers. AutoSG features three core innovations: a retrieval-augmented solver generation module strictly grounding code in verified literature; a one-step self-refinement operator introducing task-specific improvements while preserving critical structural components; and an instance-free Elo-based LLM-as-a-Judge evaluation mechanism rapidly establishing global rankings. Extensive evaluations across diverse expensive optimization tasks confirm AutoSG significantly outperforms human-designed state-of-the-art frameworks and existing LLM-generated solvers.","published":"2026-05-25T10:04:35Z","updated":"2026-05-25T10:04:35Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.25658v1","pdf_url":"https://arxiv.org/pdf/2605.25658v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.25480","versioned_id":"2605.25480v2","title":"Retrieval as Reasoning: Self-Evolving Agent-Native Retrieval via LLM-Wiki","authors":["Haoliang Ming","Feifei Li","Xiaoqing Wu","Wenhui Que"],"abstract":"LLM agents require retrieval to behave less like one-shot context fetching and more like reasoning: searching, reading, traversing, and deciding when evidence is sufficient. Yet current Retrieval-Augmented Generation (RAG) systems organize external knowledge as flat chunks retrieved by embedding similarity, exposing a retrieval-as-lookup interface ill-suited to iterative reasoning agents. We propose LLM-Wiki, an agent-native retrieval system that operationalizes the Retrieval-as-Reasoning paradigm by treating external knowledge as a compilable, composable, and self-evolving structure rather than a static retrieval index. LLM-Wiki compiles documents into structured Wiki pages with bidirectional links, exposes search, read, and link-following operations through standard tool-calling interfaces, and introduces an Error Book for persistent structural and semantic self-correction. LLM-Wiki achieves state-of-the-art results on HotpotQA, MuSiQue, and 2WikiMultiHopQA, outperforming HippoRAG 2, LightRAG, and GraphRAG by 2.0-8.1 F1 points. On AuthTrace, LLM-Wiki achieves the best overall accuracy, with especially strong gains on multi-document structured queries, confirming that compilation-based retrieval generalizes beyond chain-style multi-hop reasoning.","published":"2026-05-25T06:36:14Z","updated":"2026-05-26T10:31:56Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.25480v2","pdf_url":"https://arxiv.org/pdf/2605.25480v2","comment":"15 pages, 3 figures, 10 tables, 1 algorithm","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.24998","versioned_id":"2605.24998v1","title":"Better, Faster: Harnessing Self-Improvement in Large Reasoning Models","authors":["Qihuang Zhong","Liang Ding","Juhua Liu","Bo Du","Leszek Rutkowski","Dacheng Tao"],"abstract":"Self-improvement training enables the large reasoning models (LRMs) to improve themselves by self-generating reasoning trajectories as training data without external supervision. However, we find that this method often falls short in complex reasoning tasks and even leads to model collapse. Through a series of preliminary analyses, we reveal two problems: (1) data imbalance, where most training samples are simple, but the challenging yet crucial samples are scarce; (2) overthinking, where many undesired samples with redundant reasoning steps are used for self-training. To this end, we propose HSIR, which effectively Harnesses Self-Improvement in large Reasoning models via two simple-yet-effective approaches. Specifically, HSIR introduces a verify-then-exit sampling strategy to mitigate data imbalance by efficiently collecting more accurate solutions for difficult queries, and designs an Intrinsic Diversity score to quantify overthinking and filter out the undesired solutions. We apply HSIR to various post-training paradigms, among which we further propose H-GRPO, an enhanced GRPO algorithm that leverages the intrinsic diversity as an external reward to encourage concise and diverse reasoning via reinforcement learning. Extensive results show that HSIR not only effectively enhances the reasoning performance, i.e., bringing up to +10.9% average performance gains, but also significantly improves the reasoning efficiency by reducing up to 42.4% relative inference overhead.","published":"2026-05-24T10:54:46Z","updated":"2026-05-24T10:54:46Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.24998v1","pdf_url":"https://arxiv.org/pdf/2605.24998v1","comment":"Accepted by ICML2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.24834","versioned_id":"2605.24834v1","title":"Reflect-Guard: Enhancing LLM Safeguards against Adversarial Prompts via Logical Self-Reflection","authors":["Lixing Lin","Juli You","Yue Li","Luyun Lin","Yiqing Wang","Zhen Zhang","Moxuan Zheng"],"abstract":"Large language model (LLM) safety classifiers such as Llama Guard are effective at detecting overtly harmful prompts but remain vulnerable to adversarial jailbreak attacks that disguise malicious intent through role-play scenarios, fictional framing, and indirect requests. We present Reflect-Guard, a method that augments LLM-based safety classifiers with chain-of-thought self-reflection capabilities through parameter-efficient fine-tuning. Our approach distills analytical reasoning from GPT-4o-mini into structured reflection annotations, then trains Llama-Guard-3-8B via QLoRA to generate logical self-reflections before issuing safety verdicts. Using only 1000 training examples and updating just 0.5% of model parameters (~42M), Reflect-Guard achieves substantial improvements on two challenging benchmarks. On WildGuardTest, F1 score improves from 0.770 to 0.842 (+7.2 pp), with recall on adversarial prompts increasing from 0.513 to 0.921 (+40.8 pp). On JailbreakBench, the attack success rate drops from 10.3% to 1.8%, representing an 82.5% relative reduction. These gains are especially pronounced on adversarial inputs, where the explicit reasoning step enables the model to see through obfuscation techniques that defeat standard pattern-matching approaches. Our results demonstrate that teaching safety classifiers to reason about adversarial intent, rather than simply classify surface patterns, is a promising direction for robust LLM safety.","published":"2026-05-24T02:58:21Z","updated":"2026-05-24T02:58:21Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.24834v1","pdf_url":"https://arxiv.org/pdf/2605.24834v1","comment":"12 pages, 2 figures, and 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.24517","versioned_id":"2605.24517v1","title":"ECHO: Terminal Agents Learn World Models for Free","authors":["Vaishnavi Shrivastava","Piero Kauffmann","Ahmed Awadallah","Dimitris Papailiopoulos"],"abstract":"CLI agents are the closest thing language models have to an embodied setting: the model emits commands, the terminal executes them, and the returned stream -- stdout, errors, files, logs, and traces -- records the consequences. We argue that this stream is a supervision signal, but standard agent RL discards it: GRPO-style training updates action tokens with sparse outcome-level rewards while ignoring environment responses already in the rollout. Failed rollouts provide little policy-gradient signal despite containing rich evidence about how the environment responds. We introduce ECHO (Environment Cross-entropy Hybrid Objective), a hybrid objective that combines the standard policy-gradient loss on action tokens with an auxiliary loss that trains the policy to predict environment observation tokens resulting from its own actions. ECHO reuses the same forward pass as GRPO, requires no additional rollouts, and turns terminal feedback into dense supervision for all rollouts. ECHO doubles GRPO pass@1 on TerminalBench-2.0: Qwen3-8B improves from 2.70% to 5.17%, and Qwen3-14B from 5.17% to 10.79%. ECHO also produces policies that better predict terminal dynamics, even on trajectories they did not generate: across held-out rollouts, it sharply reduces environment-token cross-entropy while GRPO alone barely changes it. From base Qwen3-8B, ECHO matches expert-SFT-then-GRPO performance on held-out terminal tasks without expert demonstrations, and recovers roughly half of the expert-SFT initialization benefit on TerminalBench-2.0. In some settings, the environment prediction loss alone enables verifier-free self-improvement, allowing policies to improve on unseen OOD tasks by learning only from environment interactions. Together, these results suggest that environment observations are not merely context for future actions, but a dense, on-policy supervision signal already present in every rollout.","published":"2026-05-23T11:08:46Z","updated":"2026-05-23T11:08:46Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.24517v1","pdf_url":"https://arxiv.org/pdf/2605.24517v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.24426","versioned_id":"2605.24426v1","title":"SEAL: Synergistic Co-Evolution of Agents and Learning Environments","authors":["Yihao Hu","Zhihao Wen","Xiujin Liu","Pan Wang","Xin Zhang","Wei Wu"],"abstract":"Large Language Model (LLM) agents are increasingly improved through interaction, yet most self-evolution methods adapt either the policy or the learning environment in isolation. We identify this structural gap as \\emph{Agent-Environment Misalignment}: the agent's capability frontier changes during training, while the environment that provides supervision remains static or only weakly coupled to the agent's revealed failures. We propose SEAL, a closed-loop co-evolution framework for interactive tool-use agents. SEAL collects on-policy trajectories under executable verification, diagnoses failed rollouts into turn-level failure labels, and uses these diagnoses as a shared signal for both environment-side adaptation and model-side policy optimization. The environment evolves its training-time learning interface by exposing clearer tool affordance cues, constraint information, and recovery-oriented feedback, while the policy is updated with diagnosis-guided advantage reweighting. Extensive experiments across in-distribution and out-of-distribution multi-turn tool-use evaluations show that SEAL improves low-resource agent learning: with only 400 training samples, it yields +8.25 to +26.25 average-point gains across three backbones and exhibits positive out-of-distribution transfer. These results demonstrate the value of jointly adapting the learner and its training-time learning substrate for robust self-improving LLM agents.","published":"2026-05-23T06:41:31Z","updated":"2026-05-23T06:41:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.24426v1","pdf_url":"https://arxiv.org/pdf/2605.24426v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.24197","versioned_id":"2605.24197v2","title":"A Sober Look at Agentic Misalignment in Automated Workflows","authors":["Wenqian Ye","Bo Yuan","Zhichao Xu","Yijun Tian","Yawei Wang","Henry Kautz","Aidong Zhang"],"abstract":"We study a class of emergent misalignment in multi-agent systems (MAS), with a focus on automated workflows, which we refer to agentic misalignment. Although these systems can solve complex tasks, they often fail because agents act according to implicit proxy utilities that do not align with the intended human goals. We formally define these behaviors and analyze them within a Bayesian framework, showing that generic utilities naturally lead to posterior collapse of agents in automated workflows. To address this issue, we propose Agentic Evidence Attribution (AEA), a novel alignment paradigm that improves agent posteriors using context-specific evidence. AEA reasons over agent actions and provides structured evidence to correct misaligned behavior during collaboration. To better understand the role of evidence, we study two instantiations of AEA: self-reflection (internal evidence from the model) and weak-to-strong generalization (external evidence on the agentic trajectory). We show that a small evidence model effectively aligns the MAS by providing orthogonal failure attribution. Our results clarify the sources of agentic misalignment in automated workflows and show that evidence-based alignment can effectively improve agent collaboration and leads to reliable multi-agent systems built on automated workflows.","published":"2026-05-22T20:40:20Z","updated":"2026-06-08T19:55:52Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.24197v2","pdf_url":"https://arxiv.org/pdf/2605.24197v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.24069","versioned_id":"2605.24069v1","title":"When the Manual Lies: A Realistic Benchmark to Evaluate MCP Poisoning Attacks for LLM Agents","authors":["Shi Liu","Xuehai Tang","Xikang Yang","Liang Lin","Biyu Zhou","Wenjie Xiao","Wantao Liu"],"abstract":"The rise of tool-using Large Language Model (LLM) agents, standardized by protocols like the Model Context Protocol (MCP), has unlocked unprecedented autonomous execution capabilities for LLM Agents by integrating external open-domain knowledge and tools. However, this interoperability introduces a covert attack surface targeting the agent's cognitive planning layer. This paper systematically investigates Tool Description Poisoning (TDP), a novel semantic attack. In TDP, malicious instructions are not embedded in a tool's executable code, but rather covertly injected into its descriptive metadata, the very \"manual\" an agent relies on for secure planning and decision-making. To rigorously and systematically evaluate this emerging threat, we introduce the MCP-TDP Security Benchmark. This high-fidelity sandbox environment comprises 32 realistic, real-world test cases spanning 6 distinct risk categories. Our evaluation of 8 mainstream LLMs reveals severe vulnerabilities, with leading models like GPT-4o exhibiting a nearly 100% Attack Success Rate (ASR) in six high-risk scenarios. Furthermore, our findings demonstrate that common prompt-guardrail defenses are largely ineffective and can, counterintuitively, even be counterproductive (a phenomenon which we term the \"Firewall Fallacy\"). Crucially, we also propose a defense mechanism: \"Reactive Self-Correction,\" where an agent autonomously detects and reverts its own malicious actions post-execution. This work provides the first specialized security benchmark tailored for TDP, offering essential insights for securing the cognitive and planning layers of advanced agentic systems.","published":"2026-05-22T08:34:48Z","updated":"2026-05-22T08:34:48Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.24069v1","pdf_url":"https://arxiv.org/pdf/2605.24069v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.23273","versioned_id":"2605.23273v1","title":"Self-Refining Topology Optimization via an LLM-Based Multi-Agent Framework","authors":["Hyunjee Park","Hayoung Chung"],"abstract":"Topology optimization is a widely used design method that produces optimized material distributions for prescribed objectives and constraints through well-established numerical algorithms. Throughout the workflow, engineers make a series of decisions ranging from setting and adjusting numerical parameters to assessing whether the converged design meets considerations beyond those explicitly included in the optimization problem, such as physical feasibility. These decisions, which draw on domain expertise, interfere with the autonomous design process. To address this difficulty, this study presents TopOptAgents, a multi-agent system for automating not only the design process but also decision-making during the key stages of the topology optimization process. TopOptAgents consists of six LLM-based agents collaborating through iterative self-refinement cycles spanning problem formulation, validation, code generation and execution, and quality assessment of the optimized structure. This process enables error correction and progressive improvement of both the optimization setup and resulting design. The framework is demonstrated on optimization problems selected to cover a range of settings that differ in their literature coverage and numerical characteristics The benefits of iterative self-refinement are found to be particularly pronounced for problem classes where the pretrained language model has limited prior exposure, such as formulations whose literature and open-source implementations are comparatively sparse. In such cases, the proposed framework reliably produces converged designs where a single state-of-the-art LLM struggles, suggesting that self-refinement broadens the range of topology optimization problems that LLM-based automation can reliably address.","published":"2026-05-22T06:27:18Z","updated":"2026-05-22T06:27:18Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.23273v1","pdf_url":"https://arxiv.org/pdf/2605.23273v1","comment":"28 pages, 17 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.23220","versioned_id":"2605.23220v1","title":"WMAttack: Automated Attack Search for Adversarial Evaluation of World-Model Agents","authors":["Zhixiang Guo","Siyuan Liang","Shi Fu","Cheng Guo","Andras Balogh","Mark Jelasity","Dacheng Tao"],"abstract":"Despite the growing use of world models as decision-making agents, their adversarial robustness remains underexplored due to the lack of dedicated automated evaluation methods. A key obstacle is that attack evaluation must be both accurate and efficient: weak manually tuned attacks can overestimate robustness, while exhaustive hyperparameter search is prohibitively expensive because each candidate requires closed-loop rollouts through learned latent dynamics. We introduce WMAttack, an automated attack-search framework for adversarial evaluation of world-model agents. WMAttack formulates robustness evaluation as a finite-budget search over attack configurations, including attack families, perturbation budgets, optimization steps, restarts, and allocation rules. To improve search accuracy, Self-Correcting Attack Search (SCAS) refines the attack proposal distribution using feedback from reward degradation, action instability, runtime cost, and rollout variability. To improve search efficiency, Representation-Guided Attack Retrieval (RGAR) retrieves effective historical configurations from representation-similar tasks, providing a warm start for unseen environments. We provide a theoretical explanation showing that proposal refinement improves finite-budget search when it shifts probability mass toward high-utility attacks. Across Atari and DeepMind Control tasks, WMAttack consistently discovers stronger attacks than the evaluated baselines, improving normalized reward drop from 0.497 to 1.034 on DreamerV3 Atari and from 0.319 to 0.682 on DMC. Ablations further show that RGAR improves initial candidate quality and SCAS improves final attack utility under fixed evaluation budgets.","published":"2026-05-22T04:31:09Z","updated":"2026-05-22T04:31:09Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.23220v1","pdf_url":"https://arxiv.org/pdf/2605.23220v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.23180","versioned_id":"2605.23180v1","title":"Self-Improving In-Context Learning","authors":["Baturay Saglam","Dionysis Kalogerias"],"abstract":"We propose to improve in-context learning (ICL) by optimizing the continuous embeddings of a fixed few-shot prompt at test time. The key observation is that the log-probabilities a model assigns to its demonstrated outputs$\\unicode{x2013}$available from a single forward pass without generating any tokens$\\unicode{x2013}$provide a meaningful signal for how well the model has inferred the task from its demonstrations. We formalize this signal as a bounded, self-supervised confidence proxy and maximize it via zeroth-order optimization over the prompt embeddings, yielding a test-time calibration procedure. The approach requires no finetuning, no token generation, no predefined label set, and no external data, making it equally applicable to both classification and free-form generation tasks. Across a comprehensive suite of ICL tasks, the proposed calibration consistently matches or improves upon the base model and outperforms classification-specific baselines on most tasks. The statistically significant correlation between proxy improvement and downstream accuracy gain confirms that the proposed proxy encodes a reliable optimization signal for in-context learning.","published":"2026-05-22T03:01:34Z","updated":"2026-05-22T03:01:34Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.23180v1","pdf_url":"https://arxiv.org/pdf/2605.23180v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.22122","versioned_id":"2605.22122v1","title":"Adversarial Trust Poisoning in Vehicular Collaborative Perception","authors":["Yutong Liu","Chenyi Wang","Ming F. Li","Qingzhao Zhang"],"abstract":"Collaborative perception (CP) enables connected and autonomous vehicles to share sensor data and jointly reason about their environment. To defend against adversaries that fabricate or manipulate shared data, existing systems employ cross-vehicle inconsistency detection and trust estimation, penalizing vehicles whose observations conflict with the majority. In this work, we show that these defenses themselves introduce a new attack surface. We present TrustFlip, a novel attack that weaponizes consistency-based defenses to poison the trust assigned to benign vehicles. Instead of injecting false data into the collaboration pipeline, it deploys physical adversarial objects that are genuine but induce inconsistent observations among benign vehicles. The resulting inconsistencies are misattributed by the defense to the targeted vehicle, causing its trust score to degrade and eventually leading to its downweighting or exclusion from collaboration. Consequently, the system loses reliable sensing contributors, degrading perception capability and potentially inducing safety-critical failures. We evaluate TrustFlip across multiple collaborative perception architectures and defense mechanisms. Our results show that state-of-the-art defenses can be significantly affected: the attack removes the targeted benign vehicle from collaboration in up to 87.7% of scenarios and drops Average Precision (AP) by up to 13%. As an initial mitigation, we introduce TrustReflect, a lightweight self-reflection mechanism that marks disputed regions as uncertain and excludes them from trust evaluation, reducing the attack success rate by 35-100%.","published":"2026-05-21T07:53:10Z","updated":"2026-05-21T07:53:10Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.22122v1","pdf_url":"https://arxiv.org/pdf/2605.22122v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.21997","versioned_id":"2605.21997v1","title":"The Log is the Agent: Event-Sourced Reactive Graphs for Auditable, Forkable Agentic Systems","authors":["Yohei Nakajima"],"abstract":"Most agent frameworks are built around the language model: a conversation loop comes first, then tools, then rules, and finally a logging layer bolted on for observability, with state persisted as retrievable \"memory.\" We describe ActiveGraph, a runtime that inverts this arrangement. The append-only event log is the source of truth; the working graph is a deterministic projection of that log; and behaviors--ordinary functions, classes, LLM-backed routines, or logic attached to typed edges--react to changes in the graph and emit new events. No component instructs another; coordination happens entirely through the shared graph. This single design decision yields three properties that retrieval-and-summarization memory systems do not provide: deterministic replay of any run from its log, cheap forking that branches a run at any event without re-executing the shared prefix, and end-to-end lineage from a high-level goal down to the individual model call that produced each artifact. We present the architecture, a determinism contract that makes replay sound, and a worked diligence example whose full causal structure is reconstructable from the log alone. We discuss--without claiming to demonstrate--why this substrate is unusually well suited to self-improving agents, and how it extends the BabyAGI lineage and prior graph-memory research.","published":"2026-05-21T04:55:38Z","updated":"2026-05-21T04:55:38Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.21997v1","pdf_url":"https://arxiv.org/pdf/2605.21997v1","comment":"11 pages, 1 figure. Open-source Apache-2.0 implementation with reproducible quickstart demo, deterministic replay, fork-and-diff, and lineage tracing","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.22885","versioned_id":"2605.22885v1","title":"ImProver 2: Iteratively Self-Improving LMs for Neurosymbolic Proof Optimization","authors":["Riyaz Ahuja","Tate Rowney","Jeremy Avigad","Sean Welleck"],"abstract":"Formal mathematics libraries are rapidly expanding, creating a growing need to refactor verified proofs for maintainability and to improve training data quality for neural provers. However, scalable proof optimization is hindered by heterogeneous and heuristically specified objectives, scarce data, and high training and inference costs. To overcome these challenges, we introduce ImProver 2, a neurosymbolic framework for automated proof optimization in Lean 4. ImProver 2 combines a data-efficient expert-iteration pipeline with a scaffold that exposes formal structure alongside lightweight informal abstractions. We further introduce a suite of metrics capturing structural proof properties. Using ImProver 2, we train a 7B-parameter model that outperforms orders-of-magnitude larger models within the same model family, and is competitive with mid-tier frontier models across metrics. We additionally demonstrate that our neurosymbolic scaffold significantly improves performance across both small and frontier models. We show that with proper scaffolding and training, small models can effectively restructure research-level proofs over complex and varied metrics, matching substantially larger systems and establishing proof optimization as a scalable, learnable task.","published":"2026-05-21T02:20:26Z","updated":"2026-05-21T02:20:26Z","categories":["cs.AI","cs.CL","cs.LG","cs.LO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.22885v1","pdf_url":"https://arxiv.org/pdf/2605.22885v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.20654","versioned_id":"2605.20654v2","title":"REFLECTOR: Internalizing Step-wise Reflection against Indirect Jailbreak","authors":["Jiachen Ma","Jiawen Zhang","Xiangtian Li","Bo Zou","Chaochao Lu","Chao Yang"],"abstract":"While Large Language Models (LLMs) demonstrate remarkable capabilities, they remain susceptible to sophisticated, multi-step jailbreak attacks that circumvent conventional surface-level safety alignment by exploiting the internal generation process. To address these vulnerabilities, we propose Reflector, a principled two-stage framework that internalizes self-reflection within the generation trajectory. Reflector first leverages teacher-guided generation to produce high-quality reflection data for supervised fine-tuning (SFT), establishing structured reflection patterns. It subsequently uses Reinforcement Learning (RL) with outcome-driven and reward-validity supervision to instill robust, autonomous self-reflection capabilities. Empirical results show that Reflector achieves Defense Success Rates (DSR) exceeding 90% against complex indirect attacks while generalizing robustly across diverse threat scenarios. Notably, the framework enhances both task-specific and general utility, yielding a 5.85% gain on GSM8K alongside improved performance on knowledge-intensive benchmarks. By internalizing trajectory-level safety, Reflector overcomes the fundamental limitations of surface alignment without significant computational overhead, offering an efficient and scalable solution for the development of safe and capable LLMs.","published":"2026-05-20T03:16:15Z","updated":"2026-06-03T08:00:52Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.20654v2","pdf_url":"https://arxiv.org/pdf/2605.20654v2","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.20477","versioned_id":"2605.20477v1","title":"Training Language Agents to Learn from Experience","authors":["Yuval Shalev","Zifeng Ding","Mateja Jamnik"],"abstract":"Language agents can adapt from experience in interactive environments, but current reflection-based methods can only self-correct within a single task instance. Whether such experience can be distilled into reusable lessons that improve performance on future unseen tasks remains unclear. We address this problem by introducing the In-context Training (ICT) task, a framework for evaluating cross-task self-improvement in language agents. In ICT, a reflector model observes trajectories collected by an actor model and generates system prompts intended to improve the actor's performance on future unseen tasks. We then propose an RL-based training pipeline for learning such reflections directly from experience, without human-provided examples. Across ALFWorld and MiniHack, our trained reflectors outperform an untrained baseline on most held-out task families, showing that the ability to learn from experience can itself be learned. In some cases, we observe generalisation beyond the benchmark on which the reflector was trained, to substantially different environments. Finally, we introduce MetaGym, a generic Python library for constructing meta-environments, enabling future research on self-improving language agents.","published":"2026-05-19T20:41:12Z","updated":"2026-05-19T20:41:12Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.20477v1","pdf_url":"https://arxiv.org/pdf/2605.20477v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.19748","versioned_id":"2605.19748v1","title":"Memory-Augmented Reinforcement Learning Agent for CAD Generation","authors":["Yin Xiaolong","Liu Yu","Shen Jiahang","Lu Xingyu","Ni Jingzhe","Fan Fengxiao","Sang Fan"],"abstract":"Automatic generation of computer-aided design (CAD) models is a core technology for enabling intelligence in advanced manufacturing. Existing generation methods based on large language models (LLMs) often fall short when handling complex CAD models characterized by long operation sequences, diverse operation types, and strong geometric constraints, primarily because reasoning chains break and effective error-correction mechanisms are lacking. To address this problem, this paper proposes a memory-augmented reinforcement learning framework for CAD generation agents. The framework encapsulates the underlying geometric kernel into a structured toolchain callable by the agent and builds a closed-loop mechanism of design intent understanding, global planning, execution, and multi-dimensional verification. It also designs a dual-track memory module consisting of a case library and a skill library, and proposes a dynamic utility retrieval algorithm. By introducing reinforcement learning into retrieval and policy optimization, the agent can effectively avoid retrieval traps in which examples are semantically similar but geometrically infeasible, enabling online self-correction and continual evolution without additional large-scale annotated data. Experiments show that the proposed method significantly improves both the success rate and geometric consistency on complex CAD model generation tasks.","published":"2026-05-19T12:16:31Z","updated":"2026-05-19T12:16:31Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.19748v1","pdf_url":"https://arxiv.org/pdf/2605.19748v1","comment":"26 pages; multilingual submission: English version first, followed by Chinese version","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.19317","versioned_id":"2605.19317v1","title":"Inference-Time Scaling in Diffusion Models through Iterative Partial Refinement","authors":["Taegu Kang","Jaesik Yoon","Sungjin Ahn"],"abstract":"Inference-time scaling has emerged as a major approach for improving reasoning capabilities, and has been increasingly applied to diffusion models. However, existing inference-time scaling methods for diffusion models typically rely on external verifiers or reward models to rank and select samples, limiting their scalability to settings where such evaluators are available and reliable. Moreover, while recent diffusion models perform sequential inference with region-wise, mixed-noise conditioning, inference-time scaling tailored to this setting remains relatively underexplored. We propose Iterative Partial Refinement (IPR), an inference-time scaling method for sequential diffusion that requires no external verifier. Starting from an already-generated sample, IPR re-noises a subset of regions and regenerates them conditioned on the remaining regions, enabling the model to revise earlier decisions under a richer context than was available during the initial generation. This iterative partial refinement produces more globally consistent samples without external verification. On reasoning tasks requiring global constraint satisfaction, IPR consistently improves performance: on MNIST Sudoku, the valid solution rate increases from 55.8% to 75.0%. These results show that iterative partial refinement alone can serve as an effective inference-time scaling strategy for diffusion models in sequential, mixed-noise settings. Code is available at: https://github.com/ahn-ml/IPR","published":"2026-05-19T03:53:50Z","updated":"2026-05-19T03:53:50Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.19317v1","pdf_url":"https://arxiv.org/pdf/2605.19317v1","comment":"Accepted at the ICLR 2026 Workshop on AI with Recursive Self-Improvement","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.19228","versioned_id":"2605.19228v2","title":"Diagnosing Multi-step Reasoning Failures in Black-box LLMs via Stepwise Confidence Attribution","authors":["Xiaoou Liu","Tiejin Chen","Dengjia Zhang","Yaqing Wang","Lu Cheng","Hua Wei"],"abstract":"Large Language Models have achieved strong performance on reasoning tasks with objective answers by generating step-by-step solutions, but diagnosing where a multi-step reasoning trace might fail remains difficult. Confidence estimation offers a diagnostic signal, yet existing methods are restricted to final answers or require internal model access. In this paper, we introduce Stepwise Confidence Attribution (SCA), a framework for closed-source LLMs that assigns step-level confidence based only on generated reasoning traces. SCA applies the Information Bottleneck principle: steps aligning with consensus structures across correct solutions receive high confidence, while deviations are flagged as potentially erroneous. We propose two complementary methods: (1) NIBS, a non-parametric IB approach measuring consistency without graph structures, and (2) GIBS, a graph-based IB model that learns subgraphs through a differentiable mask to capture logical variability. Extensive experiments on mathematical reasoning and multi-hop question answering show that SCA reliably identifies low-confidence steps strongly correlated with reasoning errors. Moreover, using step-level confidence to guide self-correction improves the correction success rate by up to 13.5\\% over answer-level feedback.","published":"2026-05-19T00:57:51Z","updated":"2026-06-07T18:34:11Z","categories":["cs.CL","cs.AI","cs.IT","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.19228v2","pdf_url":"https://arxiv.org/pdf/2605.19228v2","comment":"Accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.19156","versioned_id":"2605.19156v1","title":"How Far Are We From True Auto-Research?","authors":["Zhengxin Zhang","Ning Wang","Sainyam Galhotra","Claire Cardie"],"abstract":"Recent auto-research systems can produce complete papers, but feasibility is not the same as quality, and the field still lacks a systematic study of how good agent-generated papers actually are. We introduce ResearchArena, a minimal scaffold that lets off-the-shelf agents (Claude Code using Opus 4.6, Codex using GPT-5.4, and Kimi Code using K2.5) carry out the full research loop themselves (ideation, experimentation, paper writing, self-refinement) under only lightweight guidance. Across 13 computer science seeds and 3 trials per agent-domain pair, ResearchArena yields 117 agent-generated papers, each evaluated under three complementary lenses: a manuscript-only reviewer (SAR), an artifact-aware peer review (PR) in which agents inspect the workspace alongside the manuscript, and an human conducted meta-review. Under SAR alone the picture is optimistic: Claude Code obtains the highest score, outperforms Analemma's FARS, and matches the weighted-average human ICLR 2025 submission, suggesting that minimally scaffolded agents can produce papers that look competitive on manuscript-only review. Manual inspection, however, reveals this picture is overstated: SAR scores are poorly aligned with its actual acceptance decisions and reward plausible framing without verifying experimental substance. Under artifact-aware PR scores drop sharply, and manual auditing identifies experimental rigor as the major bottleneck, decomposing into three failure modes (fabricated results, underpowered experiments, and plan/execution mismatch) that are highly agent-dependent: Codex 5%/8% paper-vs-artifact mismatch / fabricated references versus Kimi Code 77%/72%, a $\\sim$15$\\times$ spread that tracks distinct research personas the agents develop. None of the 117 agent-generated papers reaches the acceptance bar of a top-tier venue. This suggests that we are still gapped from the true auto-research.","published":"2026-05-18T22:20:33Z","updated":"2026-05-18T22:20:33Z","categories":["cs.AI","cs.CY","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.19156v1","pdf_url":"https://arxiv.org/pdf/2605.19156v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.19077","versioned_id":"2605.19077v1","title":"ReacTOD: Bounded Neuro-Symbolic Agentic NLU for Zero-Shot Dialogue State Tracking","authors":["Yanjun Lin","Zimo Xiao","Kartik Natarajan","Mahesh Sankaranarayanan","Niraj Nawanit","Rakshit Parashar","Austin Zhang","Karthik Konaraddi","Rishita Mote","Wei Niu"],"abstract":"Task-oriented dialogue systems -- handling transactions, reservations, and service requests -- require predictable behavior, yet the moderately-sized LLMs needed for practical latency are prone to hallucination and format errors that cascade into incorrect actions (e.g., a hotel booked for the wrong date). We propose ReacTOD, a bounded neuro-symbolic architecture that reformulates NLU as discrete tool calls within a self-correcting ReAct loop governed by deterministic validation. A bounded ReAct loop enables iterative self-correction, improving accuracy by up to 9.3 percentage points over single-pass inference on MultiWOZ. A symbolic validator enforces action compliance, schema conformance, and coreference consistency on every dialogue state update, achieving a 93.1% self-correction rate on intercepted errors and producing structured execution traces. Incremental state prediction and on-demand history retrieval keep prompts compact, empirically improving instruction adherence in parameter-constrained models. On MultiWOZ 2.1, ReacTOD achieves a new zero-shot state-of-the-art: gpt-oss-20B reaches 52.71% joint goal accuracy, surpassing the previous best by 14 percentage points, while Qwen3-8B achieves 47.34% with only 8B parameters. On the Schema-Guided Dialogue (SGD) benchmark, ReacTOD with Claude-Opus-4.6 achieves 80.68% JGA under fully end-to-end evaluation with predicted domains, and Qwen3-32B reaches 64.09% -- demonstrating cross-benchmark generalization without task-specific training data.","published":"2026-05-18T20:06:04Z","updated":"2026-05-18T20:06:04Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.19077v1","pdf_url":"https://arxiv.org/pdf/2605.19077v1","comment":"Accepted at TrustNLP Workshop at ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.19010","versioned_id":"2605.19010v1","title":"AgentNLQ: A General-Purpose Agent for Natural Language to SQL","authors":["Olena Bogdanov","Yeunji Jung","Chandra Dhir","Pareekshitreddy Gaddam","Saurabh Jain","Lakshmi Tumati","Vijay Parthasarathy","Anup Shirgaonkar"],"abstract":"Natural language to SQL (NL2SQL) conversion is an important problem for researchers and enterprises due to the ubiquitous importance of relational databases in broad-ranging practical problems. Despite the rapid advancements in the capabilities of LLMs, NL2SQL has not reached parity in accuracy with human expert SQL writers, hence needing additional improvements in NL2SQL algorithms. This study presents a new multi-agent method for NL2SQL that achieves 78.1% semantic accuracy on the BIg Bench for LaRge-scale Database (BIRD) benchmark. Our method leverages a semantically enriched representation of user-provided schema, adds user-provided business rules, and produces accurate SQL queries. The main contributions of this study are (a) We designed an optimized new orchestrator in a multi-agent solution that uses LLMs to plan, orchestrate, reflect, and self-correct to generate accurate SQL queries, (b) We developed an advanced schema enrichment method that creates context-aware metadata to improve accuracy, and (c) We demonstrated the accuracy and generalizability of the method across different domains and datasets by evaluating it on the BIRD-SQL benchmark.","published":"2026-05-18T18:33:15Z","updated":"2026-05-18T18:33:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.19010v1","pdf_url":"https://arxiv.org/pdf/2605.19010v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.18407","versioned_id":"2605.18407v1","title":"Qumus: Realization of An Embodied AI Quantum Material Experimentalist","authors":["Lihan Shi","Zhaoyi Joy Zheng","Xinzhe Juan","Yimin Wang","Ming Yin","Mayank Sengupta","Kristina Wolinski","Yanyu Jia","Jingzhi Shi","Derek Saucedo","Neill Saggi","Haosen Guan","Kenji Watanabe","Takashi Taniguchi","Ali Yazdani","Mengdi Wang","Sanfeng Wu"],"abstract":"While modern Large Language Models (LLMs) and agentic artificial intelligence (AI) have demonstrated transformative capabilities in digital domains, the realization of embodied AI capable of real-world scientific discovery remains a difficult frontier. The advancements are hindered by the inherent complexity of integrating high-level reasoning, multimodal information processing and real-time physical execution. Here we introduce Qumus, the first AI quantum materials experimentalist. Physically embodied within a robotic mini-laboratory, Qumus is an intelligent, multimodal, and multi-agent system designed for the creation and nano-processing of atomically thin two-dimensional (2D) materials and stacked van der Waals (vdW) structures. Qumus autonomously navigates the full scientific cycle, from hypothesis generation and protocol planning to multi-step experimental execution, result analysis and reporting, acting as an experimentalist. Markedly, the system has achieved, for the first time, the AI-creation of graphene, as well as the first AI-fabrication of complex nanodevices including atomically thin field-effect transistors via vdW stacking. Qumus excels at these tasks by demonstrating autonomous error correction and closed-loop experimentation. Our results establish a generalizable framework for self-improving embodied AI systems that learn directly from the quantum world, opening a pathway toward accelerated discovery in quantum materials, electronics and beyond.","published":"2026-05-18T13:47:31Z","updated":"2026-05-18T13:47:31Z","categories":["cond-mat.mes-hall","cond-mat.mtrl-sci","cs.AI","cs.RO"],"primary_category":"cond-mat.mes-hall","arxiv_url":"https://arxiv.org/abs/2605.18407v1","pdf_url":"https://arxiv.org/pdf/2605.18407v1","comment":"29 Pages in total. Supplementary Demo Videos are available at https://qumus.ai","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17790","versioned_id":"2605.17790v1","title":"STRIDE: A Self-Reflective Agent Framework for Reliable Automatic Equation Discovery","authors":["Jiarui Su","Songjun Tu","Bei Sun","Xiaojun Liang"],"abstract":"LLM-based equation discovery offers a promising route to recovering symbolic laws from data, but many systems still rely on generation-centered loops that propose candidates, fit parameters, score results, and reuse selected examples. Such loops can misjudge useful skeletons under unreliable fitting, discard near-correct equations that require repair, and accumulate redundant memories that provide limited guidance. We propose STRIDE, a self-reflective agent framework that improves reliability by coordinating data-aware generation, mixed-fitting evaluation, critic--executor repair, and diversity-preserving semantic memory. By turning fitted scores and candidate behavior into shared feedback, STRIDE enables equations to be proposed, assessed, refined, and reused within a closed-loop discovery process. Experiments on representative symbolic-regression benchmarks and LSR-Synth suites show that STRIDE improves accuracy, OOD robustness, and structural recovery across multiple LLM backbones, with ablations and analyses confirming the contribution of its core components.","published":"2026-05-18T03:14:32Z","updated":"2026-05-18T03:14:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.17790v1","pdf_url":"https://arxiv.org/pdf/2605.17790v1","comment":"23 pages, 15 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17734","versioned_id":"2605.17734v1","title":"Harnessing LLM Agents with Skill Programs","authors":["Hongjun Liu","Yifei Ming","Shafiq Joty","Chen Zhao"],"abstract":"Equipping LLM agents with reusable skills derived from past experience has become a popular and successful approach for tackling complex and long-horizon tasks. However, such lessons are often encoded as textual guidance that remains largely advisory, lacking explicit mechanisms for when and how to intervene in the agent loop. To bridge the gap, we introduce HASP(Harnessing LLM Agents with Skill Programs), a new framework that upgrades skills into executable Program Functions (PFs). Rather than offering passive advice, PFs act as executable guardrails that activate on failure-prone states and modify the next action or inject corrective context. HASP is highly modular: it can be applied at inference time for direct agent-loop intervention, during post-training to provide structured supervision, or for self-improvement by evolving validated, teacher-reviewed PFs. Empirically, HASP drives substantial gains compared to both training-free and training-based methods on web-search, math reasoning, and coding tasks. For example, on web-search reasoning, inference-time PFs alone improve the average performance by 25% compared to (multi-loop) ReAct Agent, while post-training and controlled evolution achieve a 30.4% gain over Search-R1. To provide deeper insights into HASP, our mechanism analysis reveals how PFs trigger and intervene, how skills are internalized, and the requirement for stable skill library evolution.","published":"2026-05-18T01:35:11Z","updated":"2026-05-18T01:35:11Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.17734v1","pdf_url":"https://arxiv.org/pdf/2605.17734v1","comment":"40 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17710","versioned_id":"2605.17710v1","title":"Sometin Beta Pass Notin (SBPN): Improving Multilingual ASR for Nigerian Languages via Knowledge Distillation","authors":["Sewade Ogun"],"abstract":"Although modern multilingual Automatic Speech Recognition (ASR) systems support several Nigerian languages, their performance consistently lags behind high-resource languages like English and French. Nigerian languages present unique modelling hurdles, including acute data scarcity, inconsistent orthography, tonal diacritics, diverse accents, frequent code-switching, and localized named entities. To address these challenges, we developed a multilingual ASR framework utilizing a two-stage distillation process. First, we employ student-teacher knowledge distillation from existing monolingual models, conditioned on robust language-specific N-gram language models. Second, we perform iterative self improvement using pseudo-labelled data to further refine accuracy. Our method significantly bridges the performance gap, achieving on average a relative Word Error Rate (WER) reduction of 29 % over monolingual baselines. Our models also outperform state-of-the-art multilingual models across major benchmarks, including Common Voice and Fleurs. We introduce Sometin Beta Pass Notin (SBPN), a foundational multilingual ASR model covering Yorùbá, Hausa, Igbo, Nigerian Pidgin, and Nigerian English. SBPN is released in two sizes: SBPN-Base (120 M parameters) and SBPN-Large (600 M parameters). By releasing these as open foundation models, we aim to provide ASR resources for further research into the rich phonetic and cultural landscape of the region.","published":"2026-05-18T00:22:18Z","updated":"2026-05-18T00:22:18Z","categories":["cs.CL","eess.AS"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.17710v1","pdf_url":"https://arxiv.org/pdf/2605.17710v1","comment":"25 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17672","versioned_id":"2605.17672v1","title":"Stop When Reasoning Converges: Semantic-Preserving Early Exit for Reasoning Models","authors":["Dehai Min","Giovanni Vaccarino","Huiyi Chen","Yongliang Wu","Gal Yona","Lu Cheng"],"abstract":"Large Reasoning Models (LRMs) achieve strong performance by generating long chains of thought (CoT), but often overthink, continuing to reason after a solution has already stabilized and thereby wasting tokens and increasing latency. Existing inference-time early-exit methods rely primarily on answer-level signals, such as confidence or trial-answer consistency, to decide when to stop. However, these signals mainly reflect answer readiness rather than reasoning convergence: they may trigger before the model has finished exploring or self-correcting, causing premature exits that can degrade final-answer accuracy and leave the retained reasoning chain semantically incomplete. We identify reasoning-level semantic redundancy as a complementary signal for semantic-preserving early exit: when successive steps no longer add novel progress and instead revisit established conclusions, the reasoning trajectory has likely converged. Building on this insight, we propose PUMA, a plug-and-play framework that combines a lightweight Redundancy Detector with answer-level verification. The detector flags semantically redundant candidate exits, while verification confirms whether stopping is safe, allowing PUMA to remove redundant continuation while preserving both answer accuracy and a coherent reasoning prefix. Across five LRMs and five challenging reasoning benchmarks, PUMA achieves 26.2% average token reduction while preserving accuracy and retained CoT quality. Additional experiments on code generation, zero-shot vision-language reasoning, and learned stopping-policy internalization further demonstrate that reasoning-level redundancy is a robust, transferable, and learnable signal for efficient reasoning. Our code is available at \\url{https://github.com/giovanni-vaccarino/PUMA}.","published":"2026-05-17T22:04:11Z","updated":"2026-05-17T22:04:11Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.17672v1","pdf_url":"https://arxiv.org/pdf/2605.17672v1","comment":"under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17626","versioned_id":"2605.17626v1","title":"Verifier-Guided Code Translation via Meta-Step Decoding","authors":["Tianyang Zhou","Somesh Jha","Mihai Christodorescu","Kirill Levchenko","Varun Chandrasekaran"],"abstract":"Test-time scaling is an important mechanism for improving large language models, especially on tasks with deterministic verifiers. Code translation is a canonical example: the source program constrains valid outputs, while compilers, type check- ers, and behavioral checks provide exact pass/fail feedback. Existing approaches typically apply these verifiers only after generation, which is inefficient because early errors corrupt the autoregressive context and are rarely corrected later. We introduce Decoding Time Verification (DTV), a framework that treats structural boundaries as meta steps for verifier-guided decoding. DTV interleaves generation with verifier calls under a state-machine controller that enforces valid prefixes, using structural-boundary checks and structure-aware rollback to prevent error propagation while reducing wasted tokens. We evaluate DTV on C-to-Rust and JavaScript-to-TypeScript translation. Using Qwen3-4B as the primary generator under matched token budgets, DTV improves pass rates from 72.3% to 82.0% on C-to-Rust and from 33.3% to 46.0% on JavaScript-to-TypeScript relative to matched self-refinement baselines, while using fewer tokens per case; the same trend largely transfers to Gemma-4-E4B. In the evaluated cost-matched grid, DTV achieves a more favorable pass-rate-cost tradeoff than post-hoc verification or sampling-based scaling. These results show that verifier-guided decoding is an effective use of inference-time compute for code translation.","published":"2026-05-17T19:47:07Z","updated":"2026-05-17T19:47:07Z","categories":["cs.LG","cs.SE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.17626v1","pdf_url":"https://arxiv.org/pdf/2605.17626v1","comment":"31 pages, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17448","versioned_id":"2605.17448v2","title":"Self-Improving CAD Generation Agents with Finite Element Analysis as Feedback","authors":["Guijin Son","Jehyun Park","Seyeon Park","Sunghee Ahn","Youngjae Yu"],"abstract":"Computer-aided design (CAD) is the backbone of modern industrial design, yet learned CAD generators still fall short of real engineering pipelines: they neither iterate like engineers nor evaluate what engineering requires. Prior work has treated CAD generation as two disjoint steps, part synthesis and assembly, where the former is graded by proximity to a gold reference and the latter, when handled at all, is reduced to a separate constraint solving step. In this work, we introduce a more industry-native task formulation that requires a model to produce a fully assembled multi-part STEP file from a free-form engineering brief, which is then validated via finite element analysis (FEA). FEA validation reveals that Codex (GPT-5.5) and Claude Code (Opus-4.7) agents do not produce a single strict-passing artifact in the main first-attempt sweep, with the best configuration meeting only about 20% of typed requirements on average. Moreover, we introduce two additional supervision signals, a novel text-only blueprint schema and a 21-view image renderer that aids the agent's visual inspection, that better align the generation loop with how engineers iterate in practice. On S2O and Fusion360, the same feedback tools improve geometric reconstruction, with GPT-5.5/xhigh rising from 0.444 to 0.592 Box-IoU on S2O and from 0.397 to 0.505 on Fusion360. Together these signals move CAD programs toward artifacts that are not only visually plausible but also checked against physical and structural requirements.","published":"2026-05-17T13:47:38Z","updated":"2026-05-27T01:18:25Z","categories":["cs.GR","cs.CL"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2605.17448v2","pdf_url":"https://arxiv.org/pdf/2605.17448v2","comment":"Work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17305","versioned_id":"2605.17305v1","title":"CyberCorrect: A Cybernetic Framework for Closed-Loop Self-Correction in Large Language Models","authors":["Yuning Wu","Yingmin Liu","Yang Shu"],"abstract":"Large language model (LLM) self-correction -- the ability to detect and fix errors in generated outputs -- remains largely ad hoc, relying on generic prompts such as \"please reconsider your answer\" without systematic error analysis or convergence guarantees. We propose CyberCorrect, a framework that formalizes LLM self-correction as a closed-loop control system grounded in cybernetic theory. The framework models the LLM generator as the plant and introduces a tri-modal Error Detector (combining self-consistency, verbalized confidence, and logic-chain verification) as the sensor. A type-directed Correction Controller generates targeted repair instructions based on diagnosed error categories, while a Convergence Judge determines iteration termination using stability criteria adapted from control theory. We further introduce three control-theoretic evaluation metrics -- convergence rate, overshoot rate, and oscillation rate -- that capture correction dynamics beyond final accuracy. Experiments on our constructed CyberCorrect-Bench (440 reasoning tasks with annotated error types and correction paths) show that CyberCorrect achieves 79.8% final accuracy, improving upon the best existing self-correction method by 6.2 percentage points, while reducing overshoot (erroneous over-correction) by 41% through its convergence control mechanism.","published":"2026-05-17T07:47:34Z","updated":"2026-05-17T07:47:34Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.17305v1","pdf_url":"https://arxiv.org/pdf/2605.17305v1","comment":"6 pages, 1 figure, submitted to IEEE SMC 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.17291","versioned_id":"2605.17291v1","title":"Step-wise Rubric Rewards for LLM Reasoning","authors":["Weichu Xie","Haozhe Zhao","Wenpu Liu","Yongfu Zhu","Liang Chen","Minghao Ye","Zirong Chen","Yuqi Xu","Shuai Dong","Ziyue Wang","Xinbo Xu","Kean Shi","Ruoyu Wu","Xiaoying Zhang","Wenqi Shao","Baobao Chang","Nan Duan","Jiaqi Wang"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) is widely used to improve reasoning in large language models, but rewards only final-answer correctness with no supervision over intermediate steps. Rubric-based methods such as Rubrics as Rewards (RaR) introduce finer-grained supervision by scoring rollouts against structured criteria, yet the rubric scores are still aggregated into a single scalar applied to the entire response, causing three weaknesses: loss of multi-criterion structure, uniform supervision of correct and incorrect steps, and reward hacking through unbounded self-correction. On 1,000 problems, we find 18.2% of steps in correct-answer responses are wrong yet positively rewarded, while 49.9% of steps in incorrect-answer responses are correct yet penalized. We introduce Step-wise Rubrics as Rewards (SRaR), an RLVR framework that (i) uses an LLM judge to attribute each rubric item to a specific reasoning step, (ii) normalizes per-step rubric scores across rollouts so only steps whose quality varies produce a learning signal, and (iii) combines the per-step reward with the outcome reward through a decoupled advantage estimator that keeps the outcome baseline stable. We further build a 16K-problem rubric dataset by contrastively distilling rubric items from correct and flawed reasoning paths sampled from a strong model. Across six mathematical reasoning benchmarks, SRaR improves average accuracy over RaR by 3.57 points on Qwen3-8B and 2.75 points on Qwen3-32B, raises the Faithful Reasoning Rate on AIME 2025 from 34.5% to 46.7%, and reduces self-correction looping from 48.1% to 26.5%.","published":"2026-05-17T07:08:14Z","updated":"2026-05-17T07:08:14Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.17291v1","pdf_url":"https://arxiv.org/pdf/2605.17291v1","comment":"Code available at https://github.com/akarinmoe/SRaR","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.16909","versioned_id":"2605.16909v1","title":"TOBench: A Task-Oriented Omni-Modal Benchmark for Real-World Tool-Using Agents","authors":["Zhiqiang Liu","Wenhui Dong","Yilang Tan","Yuwen Qu","Haochen Yin","Chenyang Si"],"abstract":"Tool-using agents are increasingly expected to operate across realistic professional workflows, where they must interpret multimodal inputs, coordinate external tools, inspect intermediate artifacts, and revise their actions before producing a final result. Existing benchmarks, however, often evaluate tool use, computer use, and multimodal reasoning in isolation, leaving a gap between benchmark settings and end-to-end omni-modal tool use in the real world. To address this gap, we introduce MM-ToolBench, a benchmark and evaluation harness for task-oriented omni-modal tool use. MM-ToolBench contains 100 executable tasks from two macro task families, Customer Service and Intelligent Creation, covering 20 subcategory slices and supported by 27 MCP servers with 324 tools. The central design of MM-ToolBench is closed-loop multimodal verification: agents must execute tools, inspect rendered or transformed artifacts, and self-correct when outputs fail task-specific requirements. To make such evaluation scalable and verifiable, MM-ToolBench couples MCP-based execution with task-specific grounded evaluators and a semi-automated construction pipeline for scenario discovery, task instantiation, evaluator synthesis, and human audit. Experiments on 15 contemporary agentic models show that MM-ToolBench remains highly challenging: Claude Opus 4.6, commonly regarded as one of the strongest coding-agent models, achieves only 32.0% task success, far below the 94.0% human benchmark. We envision MM-ToolBench as a practical foundation for evaluating and advancing next-generation omni-modal tool-using agents through closed-loop multimodal verification.","published":"2026-05-16T09:49:25Z","updated":"2026-05-16T09:49:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.16909v1","pdf_url":"https://arxiv.org/pdf/2605.16909v1","comment":"Github: https://github.com/Pi3AI/TOBench","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.16883","versioned_id":"2605.16883v1","title":"SE-GA: Memory-Augmented Self-Evolution for GUI Agents","authors":["Shilong Jin","Lanjun Wang","Zhuosheng Zhang"],"abstract":"Autonomous Graphical User Interface (GUI) agents often struggle with multi-step tasks due to constrained context windows and static policies that fail to adapt to dynamic environments. To address these limitations, this work proposes the Self-Evolving GUI Agent (SE-GA), a novel framework that integrates hierarchical memory structures with an iterative self-improvement mechanism. At the core of our approach is Test-Time Memory Extension (TTME), which facilitates long-term planning by dynamically retrieving episodic, semantic, and experiential memories to provide salient contexts during inference. To ensure continuous learning, we introduce Memory-Augmented Self-Evolution (MASE), which is a training pipeline that adopts the data collected by TTME to stabilize and enhance the agent's foundational policy. Extensive evaluations across both offline and online benchmarks demonstrate SE-GA achieves state-of-the-art performance, reaching success rates of 89.0\\% on ScreenSpot and 75.8\\% on the challenging AndroidControl-High dataset. Furthermore, significant improvements on the AndroidWorld benchmark highlight the superior generalization to dynamic environments. Open source code: https://github.com/jinshilong-dev/SE-GA","published":"2026-05-16T08:51:57Z","updated":"2026-05-16T08:51:57Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.16883v1","pdf_url":"https://arxiv.org/pdf/2605.16883v1","comment":"Accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.16748","versioned_id":"2605.16748v1","title":"Genflow Ad Studio: A Compound AI Architecture for Brand-Aligned, Self-Correcting Video Generation","authors":["Debanshu Das","Lavi Nigam","Sunil Kumar Jang Bahadur","Gopala Dhar"],"abstract":"Recent advancements in generative video models demonstrate high visual fidelity, yet their integration into enterprise environments is restricted by temporal inconsistencies and severe brand misalignment. Current monolithic architectures struggle to enforce rigid brand constraints, frequently hallucinating unapproved visual assets. We introduce Genflow, a Compound AI System designed to enforce brand consistency in generative media production. Our architecture integrates a retrieval-based 'Brand DNA' extraction module to parameterize generation according to established corporate identity guidelines. Furthermore, we implement an Adversarial Multi-Agent Quality Control (QC) loop. Instead of a single-pass generation, this pipeline employs evaluator agents to iteratively critique generated frames against the extracted parameters, prompting generator models to refine outputs until a deterministic consensus is reached. By transitioning to a multi-stage, self-correcting pipeline, Genflow improved the yield of brand-compliant video generations from 42% to 89%, establishing a robust framework for scalable, enterprise-grade generative systems.","published":"2026-05-16T02:03:53Z","updated":"2026-05-16T02:03:53Z","categories":["cs.GR","cs.AI","cs.CV","cs.LG","cs.MA","cs.MM"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2605.16748v1","pdf_url":"https://arxiv.org/pdf/2605.16748v1","comment":"6 pages, 2 figures, 2 tables. Accepted to the ACM Conference on AI and Agentic Systems (CAIS '26). Includes demo video and code repository links","journal_ref":"ACM Conference on AI and Agentic Systems (CAIS '26), May 26-29, 2026, San Jose, CA, USA","doi":"10.1145/3786335.3813213","discovered_on":"2026-07-17"},{"id":"2605.16205","versioned_id":"2605.16205v1","title":"Context, Reasoning, and Hierarchy: A Cost-Performance Study of Compound LLM Agent Design in an Adversarial POMDP","authors":["Igor Bogdanov","Chung-Horng Lung","Thomas Kunz","Jie Gao","Adrian Taylor","Marzia Zaman"],"abstract":"Deploying compound LLM agents in adversarial, partially observable sequential environments requires navigating several design dimensions: (1) what the agent sees, (2) how it reasons, and (3) how tasks are decomposed across components. Yet practitioners lack guidance on which design choices improve performance versus merely increase inference costs. We present a controlled study of compound LLM agent design in CybORG CAGE-2, a cyber defense environment modeled as a Partially Observable Markov Decision Process (POMDP). Reward is non-positive, so all configurations operate in a failure-mitigation mode. Our evaluation spans five model families, six models, and twelve configurations (3,475 episodes) with token-level cost accounting. We vary context representation (raw observations vs. a deterministic state-tracking layer with compressed history), deliberation (self-questioning, self-critique, and self-improvement tools, with optional chain-of-thought prompting), and hierarchical decomposition (monolithic ReAct vs. delegation to specialized sub-agents). We find that: (1) Programmatic state abstraction delivers the largest returns per token spent (RPTS), improving mean return by up to 76% over raw observations. (2) Distributing deliberation tools across a hierarchy degrades performance relative to hierarchy alone for all five model families, reaching up to 3.4$\\times$ worse mean return while using 1.8-2.7$\\times$ more tokens. We call this destructive pattern a deliberation cascade. (3) Hierarchical decomposition without deliberation achieves the best absolute performance for most models, and context engineering is generally more cost-effective than deliberation. These findings suggest a design principle for structured adversarial POMDPs: invest in programmatic infrastructure and clean task decomposition rather than deeper per-agent reasoning, as these strategies can interfere when combined.","published":"2026-05-15T17:23:08Z","updated":"2026-05-15T17:23:08Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA","eess.SY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.16205v1","pdf_url":"https://arxiv.org/pdf/2605.16205v1","comment":"","journal_ref":"","doi":"10.1145/3786335.3813149","discovered_on":"2026-07-17"},{"id":"2606.20590","versioned_id":"2606.20590v1","title":"Optimization-as-a-Service via Multi-Agent Large Language Model for Radio Access Networks","authors":["Chaoqun You","Yueyue Dai","Xingqiu He","Yue Gao","Rahim Tafazolli","Yong Liang Guan"],"abstract":"The physical resource block (PRB) allocation in Radio Access Networks (RANs) traditionally relies on case-by-case manual problem construction or, more recently, learning-based artificial intelligence (AI) methods. However, the sixth-generation (6G) RAN environments confront unprecedented service diversity and exponential dynamics, featuring volatile fluctuations in active base stations (BSs), user scale, and stringent Quality-of-Service (QoS) requirements. Faced with such conditions, both manual models and standard AI algorithms remain fundamentally rigid, lacking the flexibility to adapt and self-evolve. To provide a one-size-fits-all solution, we propose treating the PRB allocation problem as an Optimization-as-a-Service (OaaS) provided by a large language model multi-agent (LLM-MA) system. This fundamentally reshapes RAN resource allocation by utilizing agents to dynamically construct optimization problems and automatically determine objectives tailored to real-time scenarios. Our closed-loop architecture, integrating scene understanding, objective generation, solver, and reflection agents, enables context-aware, self-correcting formulation. To eliminate the computational latency of iterative reflection, we introduce a one-shot reflection distillation mechanism, training a lightweight student model to directly predict refined objective parameters. We theoretically bound the performance gap of this one-shot policy. Experimental results demonstrate our framework achieves near-optimal resource allocation with ultra-low inference latency.","published":"2026-05-15T14:14:29Z","updated":"2026-05-15T14:14:29Z","categories":["cs.NI","cs.AI"],"primary_category":"cs.NI","arxiv_url":"https://arxiv.org/abs/2606.20590v1","pdf_url":"https://arxiv.org/pdf/2606.20590v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.15871","versioned_id":"2605.15871v1","title":"Agentic Discovery of Neural Architectures: AIRA-Compose and AIRA-Design","authors":["Alberto Pepe","Chien-Yu Lin","Despoina Magka","Bilge Acun","Yannan Nellie Wu","Anton Protopopov","Carole-Jean Wu","Yoram Bachrach"],"abstract":"Toward recursive self-improvement, we investigate LLM agents autonomously designing foundation models beyond standard Transformers. We introduce a dual-framework approach: AIRA-Compose for high-level architecture search, and AIRA-Design for low-level mechanistic implementation. AIRA-Compose uses 11 agents to explore fundamental computational primitives under a 24-hour budget. Agents evaluate million-parameter candidates, extrapolating top designs to 350M, 1B, and 3B scales. This yields 14 architectures across two families: AIRAformers (Transformer-based) and AIRAhybrids (Transformer-Mamba). Pre-trained at 1B scale, these consistently outperform Llama 3.2 and Composer-found baselines. On downstream tasks, AIRAformer-D and AIRAhybrid-D improve accuracy by 2.4% and 3.8% over Llama 3.2. Furthermore, AIRA-Compose finds models with highly efficient scaling frontiers: AIRAformer-C scales 54% and 71% faster than Llama 3.2 and Composer's best Transformer, while AIRAhybrid-C outscales Nemotron-2 by 23% and Composer's best hybrid by 37%. AIRA-Design tasks 20 agents with writing novel attention mechanisms for long-range dependencies and high-performing training scripts. On the Long Range Arena benchmark, agent-designed architectures reach within 2.3% and 2.6% of human state-of-the-art on document matching and text classification. On the Autoresearch benchmark, Greedy Opus 4.5 achieves 0.968 validation bits-per-byte under a fixed time budget, surpassing the published minimum. Together, these frameworks show AI agents can autonomously discover architectures and algorithmic optimizations matching or surpassing hand-designed baselines. This establishes a powerful paradigm for discovering next-generation foundation models, marking a clear step toward recursive self-improvement.","published":"2026-05-15T11:40:41Z","updated":"2026-05-15T11:40:41Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.15871v1","pdf_url":"https://arxiv.org/pdf/2605.15871v1","comment":"55 pages, 28 figures, 21 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.15864","versioned_id":"2605.15864v2","title":"Are VLMs Seeing or Just Saying? Uncovering the Illusion of Visual Re-examination","authors":["Chufan Shi","Cheng Yang","Yaokang Wu","Linghao Jin","Bo Shui","Taylor Berg-Kirkpatrick","Xuezhe Ma"],"abstract":"Vision-Language Models (VLMs) often produce self-reflective statements like \"let me check the figure again\" during reasoning. Do such statements trigger genuine visual re-examination, or are they merely learned textual patterns? We investigate this via VisualSwap, an image-swap probing framework: after a model reasons over an image, we replace it with a visually similar but semantically different one and test whether the model notices. We introduce VS-Bench, 800 image pairs curated from MathVista, MathVerse, MathVision, and MMMU-Pro. Experiments on Qwen3-VL, Kimi-VL, and ERNIE-VL reveal a striking failure: models overwhelmingly miss the swap, with accuracy dropping by up to 60%. Counterintuitively, thinking models are nearly 3x more vulnerable than their instructed counterparts, and scaling offers no mitigation. Multi-turn user instructions restore visual grounding, but self-generated reflective statements during continuous generation do not. Attention analysis explains why: user instructions substantially elevate attention to visual tokens, whereas self-reflection does not. Current VLMs tend to say rather than actually see when claiming to perform visual re-examination. Our code and dataset are available at the project page: https://visualswap.github.io","published":"2026-05-15T11:31:14Z","updated":"2026-05-26T23:36:09Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2605.15864v2","pdf_url":"https://arxiv.org/pdf/2605.15864v2","comment":"ICML 2026 Oral","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.27413","versioned_id":"2605.27413v1","title":"Ligand-Conditioned Discrete Diffusion for Protein Sequence-Structure Co-Design","authors":["Chen Wei","Fanding Xu","Minghao Sun","Zhiyuan Liu","Lin Wang","Tianrui Jia","Yihang Zhou","Yang Zhang"],"abstract":"Proteins perform their biological functions through three-dimensional structures encoded by amino acid sequences, and ligand-binding protein co-design requires models that generate sequence-structure compatible proteins under explicit ligand constraints. Although continuous diffusion and flow-based models support ligand-aware design in coordinate or latent spaces, existing discrete diffusion protein language models mainly operate over sequence or structure tokens without direct small-molecule conditioning. We introduce \\textbf{ProtLiD$^2$}, a \\textbf{Prot}ein \\textbf{L}igand-conditioned \\textbf{D}iscrete \\textbf{D}iffusion model for protein sequence-structure co-design. ProtLiD$^2$ jointly generates amino-acid sequence and discrete structure tokens while incorporating ligand chemical and geometric information through geometry-aware cross-attention. Trained on over one million ligand-protein complexes, ProtLiD$^2$ extends masked discrete diffusion to ligand-aware functional protein design. We further propose maximum confidence-margin guided ReMask decoding, an inference-time self-correction strategy that retains confident predictions and remasks uncertain tokens. ProtLiD$^2$ improves global fold confidence over Complexa in whole-protein design, increasing TM-score from 0.672 to 0.802 and pLDDT from 64.55 to 73.00. In pocket co-design, ProtLiD$^2$ reduces active-site BB-RMSD from 3.46/3.40Å for FAIR/PocketGen to 1.97Å, and improves ligand-aware pass rates over PocketGen from 14.86% to 59.73% and from 6.08% to 23.49% under stricter docking thresholds. These results support ligand-conditioned discrete diffusion as an effective token-space framework for functional protein co-design. Code will be available at https://github.com/auroua/ProtLiD.","published":"2026-05-15T04:45:47Z","updated":"2026-05-15T04:45:47Z","categories":["q-bio.BM","cs.AI"],"primary_category":"q-bio.BM","arxiv_url":"https://arxiv.org/abs/2605.27413v1","pdf_url":"https://arxiv.org/pdf/2605.27413v1","comment":"19 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.14892","versioned_id":"2605.14892v2","title":"Beyond Individual Intelligence: Surveying Collaboration, Failure Attribution, and Self-Evolution in LLM-based Multi-Agent Systems","authors":["Shihao Qi","Jie Ma","Rui Xing","Wei Guo","Xiao Huang","Zhitao Gao","Jianhao Deng","Jun Liu","Lingling Zhang","Bifan Wei","Boqian Yang","Pinghui Wang","Jianwen Sun","Jing Tao","Yaqiang Wu","Hui Liu","Yu Yao","Tongliang Liu"],"abstract":"LLM-based autonomous agents have demonstrated strong capabilities in reasoning, planning, and tool use, yet remain limited when tasks require sustained coordination across roles, tools, and environments. Multi-agent systems address this through structured collaboration among specialized agents, but tighter coordination also amplifies a less explored risk: errors can propagate across agents and interaction rounds, producing failures that are difficult to diagnose and rarely translate into structural self-improvement. Existing surveys cover individual agent capabilities, multi-agent collaboration, or agent self-evolution separately, leaving the causal dependencies among them unexamined. This survey provides a unified review organized around four causally linked stages, which we term the LIFE progression: Lay the capability foundation, Integrate agents through collaboration, Find faults through attribution, and Evolve through autonomous self-improvement. For each stage, we provide systematic taxonomies and formally characterize the dependencies between adjacent stages, revealing how each stage both depends on and constrains the next. Beyond synthesizing existing work, we identify open challenges at stage boundaries and propose a cross-stage research agenda for closed-loop multi-agent systems capable of continuously diagnosing failures, reorganizing structures, and refining agent behaviors, extending current coordination frameworks toward more self-organizing forms of collective intelligence. By bridging these previously fragmented research threads, this survey aims to offer both a systematic reference and a conceptual roadmap toward autonomous, self-improving multi-agent intelligence.","published":"2026-05-14T14:36:13Z","updated":"2026-05-15T09:12:41Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.14892v2","pdf_url":"https://arxiv.org/pdf/2605.14892v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.14831","versioned_id":"2605.14831v1","title":"Interestingness as an Inductive Heuristic for Future Compression Progress","authors":["Vincent Herrmann","Jürgen Schmidhuber"],"abstract":"One of the bottlenecks on the way towards recursively self-improving systems is the challenge of interestingness: the ability to prospectively identify which tasks or data hold the potential for future progress. We formalize interestingness as an inductive heuristic for future compression progress and investigate its predictability using tools from Kolmogorov Complexity and Algorithmic Statistics. By analyzing complexity-runtime profiles under Length, Algorithmic, and Speed priors, we demonstrate that the inductive property of interestingness -- the capacity for past progress to signal future discovery -- is theoretically viable and empirically supported. We prove that expected future progress depends exponentially on the recency of the last observed breakthrough. Furthermore, we show that the Algorithmic Prior is significantly more optimistic than the Length Prior, yielding a quadratic increase in expected discovery for the same observed profile. These findings are experimentally confirmed across three diverse universal computational paradigms.","published":"2026-05-14T13:36:14Z","updated":"2026-05-14T13:36:14Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.14831v1","pdf_url":"https://arxiv.org/pdf/2605.14831v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.14527","versioned_id":"2605.14527v1","title":"Lang2MLIP: End-to-End Language-to-Machine Learning Interatomic Potential Development with Autonomous Agentic Workflows","authors":["Wenwen Li","Yuki Orimo","Nontawat Charoenphakdee"],"abstract":"Developing machine learning interatomic potentials (MLIPs) for complex materials systems remains challenging because it requires expertise in atomistic simulations, machine learning, and workflow design, as well as iterative active learning procedures. Existing automated pipelines typically assume a fixed sequence of stages or depend on domain experts, which limits their adaptability to heterogeneous materials systems where the optimal curriculum is not known in advance. To lower the barrier to developing MLIPs for non-experts, we propose Lang2MLIP, a multi-agent framework that takes natural-language input and formulates end-to-end MLIP development as a sequential decision-making problem solved by large language models (LLMs). At each step, a decision-making agent observes the current dataset, model, evaluation results, and execution log, and then automatically selects an appropriate action to improve the model. This removes the need for a predefined pipeline and enables the agent to self-correct by revisiting earlier subsystems when new failures arise. We evaluate this approach on a solid electrolyte interphase (SEI) system with multiple components and interfaces. These results suggest that LLM-based multi-agent systems are a promising direction for automating MLIP development and making it more accessible to non-experts.","published":"2026-05-14T08:10:42Z","updated":"2026-05-14T08:10:42Z","categories":["cs.LG","cond-mat.mtrl-sci","physics.comp-ph"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.14527v1","pdf_url":"https://arxiv.org/pdf/2605.14527v1","comment":"31 pages, 12 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.14392","versioned_id":"2605.14392v1","title":"Learning to Build the Environment: Self-Evolving Reasoning RL via Verifiable Environment Synthesis","authors":["Yucheng Shi","Zhenwen Liang","Kishan Panaganti","Dian Yu","Wenhao Yu","Haitao Mi"],"abstract":"We pursue a vision for self-improving language models in which the model does not merely generate problems or traces to imitate, but constructs the environments that train it. In zero-data reasoning RL, this reframes self-improvement from a data-generation loop into an environment-construction loop, where each artifact is a reusable executable object that samples instances, computes references, and scores responses. Whether this vision sustains improvement hinges on a single property: the environments must exhibit stable solve--verify asymmetry, the model must be able to write an oracle once that it cannot reliably execute in natural language on fresh instances. This asymmetry takes two complementary forms. Some tasks are algorithmically hard to reason through but trivial as code: a dynamic program or graph traversal, compiled once, yields unboundedly many calibrated instances. Others are intrinsically hard to solve but easy to verify, like planted subset-sum or constraint satisfaction. Both create a durable gap between proposing and solving that the policy cannot close by gaming the verifier, and it is this gap that keeps reward informative as the learner improves. We instantiate this view in EvoEnv, a single-policy generator, solver method that synthesizes Python environments from ten seeds and admits them only after staged validation, semantic self-review, solver-relative difficulty calibration, and novelty checks. The strongest evidence comes from the already-strong regime: on Qwen3-4B-Thinking, fixed public-data RLVR and fixed hand-crafted environment RLVR reduce the average, while EvoEnv improves it from 72.4 to 74.8, a relative gain of 3.3%. Stable self-improvement, we suggest, depends not on producing more synthetic data, but on models learning to construct worlds whose difficulty stays structurally beyond their own reach.","published":"2026-05-14T05:14:45Z","updated":"2026-05-14T05:14:45Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.14392v1","pdf_url":"https://arxiv.org/pdf/2605.14392v1","comment":"Tech report, work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.14211","versioned_id":"2605.14211v3","title":"ASH: Agents that Self-Hone via Embodied Learning","authors":["Benjamin Schneider","Xavier Schneider","Victor Zhong","Sun Sun"],"abstract":"Long-horizon embodied tasks remain a fundamental challenge in AI, as current methods rely on hand-engineered rewards or action-labeled demonstrations, neither of which scales. We introduce ASH, an agentic system that learns an embodied policy from unlabeled, noisy internet video, without reward shaping or expert annotation. ASH follows a self-improvement loop; when it gets stuck, ASH learns an Inverse Dynamics Model (IDM) from its own trajectories, and uses its IDM to extract supervision from relevant internet video. ASH uses unsupervised learning to identify key moments from large-scale internet video and retains them as long-term memory -- allowing it to tackle long-horizon problems. We evaluate ASH on two complementary environments demanding multi-hour planning: Pokemon Emerald, a turn-based RPG, and The Legend of Zelda: The Minish Cap, a real-time action-adventure game. In both games, behavioral cloning, retrieval-augmented and zero-shot foundation-model baselines plateau, while ASH sustains progression across our 8-hour evaluation. ASH reaches an average of $11.2/12$ milestones in Pokemon Emerald and $9.9/12$ in Legend of Zelda, while the strongest baseline gets stuck in both environments at an average of $6.5/12$ and $6.0/12$ milestones, respectively. We demonstrate that self-improving agents are a scalable recipe for long-horizon embodied learning.","published":"2026-05-14T00:10:12Z","updated":"2026-06-05T16:41:58Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.14211v3","pdf_url":"https://arxiv.org/pdf/2605.14211v3","comment":"Published as a workshop paper at ICML 2026 Workshop on Scalable Learning and Optimization for Efficient Multimodal AI Agents","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.13536","versioned_id":"2605.13536v1","title":"HLS-Seek: QoR-Aware Code Generation for High-Level Synthesis via Proxy Comparative Reward Reinforcement Learning","authors":["Qingyun Zou","Feng Yu","Hongshi Tan","Yao Chen","Bingsheng He","WengFai Wong"],"abstract":"High-Level Synthesis (HLS) compiles algorithmic C/C++ descriptions into hardware, with Quality of Results (QoR) -- latency and resource utilization -- critically governed by pragma configurations and code structure. Existing LLM-based HLS approaches train for functional correctness but ignore QoR entirely. We observe that reinforcement learning (RL) for HLS does not require absolute synthesis results -- only relative comparisons between candidates. Based on this insight, we propose \\textbf{HLS-Seek}, a QoR-aware NL-to-HLS framework that replaces expensive synthesis-in-the-loop RL with a comparative proxy reward model achieving 99.53\\% Pareto-dominance accuracy. To prevent reward hacking, we introduce \\textit{uncertainty-aware Monte Carlo (MC) dropout switching} that selectively invokes real Vitis HLS synthesis for low-confidence candidates and online updates the proxy, creating a self-improving reward system. HLS-Seek achieves 81.5\\% syntax correctness pass@1 and 81.4\\% Func@5 on HLS-eval with only 7B parameters, surpassing GPT-5.1 and other frontier models while achieving 8.5$\\times$ faster training than real-reward RL. On QoR evaluation, HLS-Seek achieves the lowest latency on 16/30 kernels and Pareto-dominates HLS-specific baselines on 9 kernels.","published":"2026-05-13T13:47:03Z","updated":"2026-05-13T13:47:03Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.13536v1","pdf_url":"https://arxiv.org/pdf/2605.13536v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.13486","versioned_id":"2605.13486v1","title":"R^2-Mem: Reflective Experience for Memory Search","authors":["Xinyuan Wang","Wenyu Mao","Junkang Wu","Xiang Wang","Xiangnan He"],"abstract":"Deep search has recently emerged as a promising paradigm for enabling agents to retrieve fine-grained historical information without heavy memory pre-managed. However, existing deep search agents for memory system repeat past error behaviors because they fail to learn from the prior high- and low-quality search trajectories. To address this limitation, we propose R^2-Mem, a reflective experience framework for memory search systems. In the offline stage, a Rubric-guided Evaluator scores low- and high-quality steps in historical trajectories, and a self-Reflection Learner distills the corresponding abstract experience. During the online inference, the retrieved experience will guide future search actions to avoid repeated mistakes and maintain high-quality behaviors. Extensive experiments demonstrate that R^2-Mem consistently improves both effectiveness and efficiency over strong baselines, improving F1 scores by up to 22.6%, while reducing token consumption by 12.9% and search iterations by 20.2%. These results verify that R^2-Mem provides a RL-free and low-cost solution for self-improving LLM agents.","published":"2026-05-13T13:09:36Z","updated":"2026-05-13T13:09:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.13486v1","pdf_url":"https://arxiv.org/pdf/2605.13486v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.13368","versioned_id":"2605.13368v1","title":"What Does LLM Refinement Actually Improve? A Systematic Study on Document-Level Literary Translation","authors":["Shaomu Tan","Dawei Zhu","Ke Tran","Michael Denkowski","Sony Trenous","Bill Byrne","Leonardo Ribeiro","Felix Hieber"],"abstract":"Iterative self-refinement is a simple inference-time strategy for machine translation: an LLM revises its own translation over multiple inference-time passes. Yet document-scale refinement remains poorly understood: 1) which pipelines work best, 2) what quality dimensions improve, and 3) how refiners behave. In this paper, we present a systematic study of document-level literary translation, covering nine LLMs and seven language pairs. Across nine translation-refinement granularity combinations and five refinement strategies, we find a robust recipe: document-level MT followed by segment-level refinement yields strong and stable improvements. In contrast, document-level refinement often makes fewer edits and leads to smaller or less reliable gains. Beyond granularity, A simple general refinement prompt consistently outperforms error-specific prompting and evaluate-then-refine schemes. Our large-scale human evaluation shows that refinement gains come primarily from fluency, style, and terminology, with limited and less consistent improvements in adequacy. Experiments varying model strength reveal refinement projects outputs toward the refiner's distribution rather than performing targeted error repair. These findings clarify the mechanisms and limitations of current refinement approaches.","published":"2026-05-13T11:27:32Z","updated":"2026-05-13T11:27:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.13368v1","pdf_url":"https://arxiv.org/pdf/2605.13368v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.15224","versioned_id":"2605.15224v1","title":"ICRL: Learning to Internalize Self-Critique with Reinforcement Learning","authors":["Jianbo Lin","Xiaomin Yu","Yi Xin","Yifu Guo","Zhuosong Jiang","Zhongqi Yue","Weishi Wang","Heqing Zou","Chengwei Qin","Hui Xiong"],"abstract":"Large language model-based agents make mistakes, yet critique can often guide the same model toward correct behavior. However, when critique is removed, the model may fail again on the same query, indicating that it has not internalized the critique's guidance into its underlying capability. Meanwhile, a frozen critic cannot improve its feedback quality over time, limiting the potential for iterative self-improvement. To address this, we propose learning to internalize self-critique with reinforcement learning(ICRL), a novel framework that jointly trains a solver and a critic from a shared backbone to convert critique-induced success into unassisted solver ability. The critic is rewarded based on the solver's subsequent performance gain, incentivizing actionable feedback. To address the distribution shift between critique-conditioned and critique-free behavior, ICRL introduces a distribution-calibration re-weighting ratio that selectively transfers critique-guided improvements compatible with the solver's own prompt distribution. Additionally, a role-wise group advantage estimation stabilizes joint optimization across the two roles. Together, these mechanisms ensure that the solver learns to improve itself without external critique, rather than becoming dependent on critique-conditioned behavior. We evaluate ICRL on diverse benchmarks spanning agentic and mathematical reasoning tasks, using Qwen3-4B and Qwen3-8B as backbones. Results show consistent improvements, with average gains of 6.4 points over GRPO on agentic tasks, and 7.0 points on mathematical reasoning. Notably, the learned 8B critic is comparable to 32B critics while using substantially fewer tokens. The code is available at https://github.com/brick-pid/ICRL.","published":"2026-05-13T08:50:05Z","updated":"2026-05-13T08:50:05Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.15224v1","pdf_url":"https://arxiv.org/pdf/2605.15224v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.13167","versioned_id":"2605.13167v1","title":"GeoBuildBench: A Benchmark for Interactive and Executable Geometry Construction from Natural Language","authors":["Jinwoong Kim","Rui Yang","Huishuai Zhang"],"abstract":"We introduce GeoBuildBench, a benchmark designed to evaluate whether large language models and multimodal agents can ground informal natural-language plane geometry problems into executable geometric constructions. Unlike existing geometry benchmarks that focus on answer correctness or static diagram interpretation, GeoBuildBench treats geometry diagram as an interactive construction task: given a textual problem, an agent must generate a domain-specific language (DSL) program to produce a diagram satisfying explicitly specified geometric objects and verifiable constraints. The benchmark features 489 Chinese textbook-style problems, curated through automated filtering and human validation to ensure text-complete, constructible problem specifications. We evaluate several state-of-the-art multimodal models in a bounded iterative setting and show that, despite reasonable success rates, models frequently exhibit structural hallucinations, missing objects, and failures to satisfy geometric constraints, with limited ability to exploit visual and constraint-based feedback for self-correction. These results highlight geometry construction as a rigorous testbed for grounded, executable reasoning beyond textual or visual plausibility. Our benchmark and code are publicly available.","published":"2026-05-13T08:30:12Z","updated":"2026-05-13T08:30:12Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.13167v1","pdf_url":"https://arxiv.org/pdf/2605.13167v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.13149","versioned_id":"2605.13149v1","title":"AcquisitionSynthesis: Targeted Data Generation using Acquisition Functions","authors":["Ishika Agarwal","Sofia Stoica","Emre Can Acikgoz","Pradeep Natarajan","Mahdi Namazifar","Jiaqi Ma","Dilek Hakkani-Tür"],"abstract":"Data quality remains a critical bottleneck in developing capable, competitive models. Researchers have explored many ways to generate top quality samples. Some works rely on rejection sampling: generating lots of synthetic samples and filtering out low-quality samples. Other works rely on larger or closed-source models to extract model weaknesses, necessary skills, or a curriculum off of which to base data generation. These works have one common limitation: there is no quantitative approach to measure the impact of the generated samples on the downstream learner. Active learning literature provides exactly this, in the form of acquisition functions. Acquisition functions measure the informativeness and/or influence of data, providing interpretable, model-centric signals. Inspired by this, we propose AcquisitionSynthesis: using acquisition functions as reward models to train language models to generate higher-quality synthetic data. We conduct experiments on classic verifiable tasks of math, medical question-answering, and coding. Our experimental results indicate that (1) student models trained with AcquisitionSynthesis data achieve good performance on in-distribution tasks (2-7% gain) and is more robust to catastrophic forgetting, and (2) AcquisitionSynthesis models can generate data for other models and for low-to-high resource training paradigms. By leveraging acquisition rewards, we seek to demonstrate a principled path toward model-aware self-improvement that surpasses static datasets.","published":"2026-05-13T08:15:48Z","updated":"2026-05-13T08:15:48Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.13149v1","pdf_url":"https://arxiv.org/pdf/2605.13149v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.12978","versioned_id":"2605.12978v1","title":"Useful Memories Become Faulty When Continuously Updated by LLMs","authors":["Dylan Zhang","Yanshan Lin","Zhengkun Wu","Yihang Sun","Bingxuan Li","Dianqi Li","Hao Peng"],"abstract":"Learning from past experience benefits from two complementary forms of memory: episodic traces -- raw trajectories of what happened -- and consolidated abstractions distilled across many episodes into reusable, schema-like lessons. Recent agentic-memory systems pursue the consolidated form: an LLM rewrites past trajectories into a textual memory bank that it continuously updates with new interactions, promising self-improving agents without parameter updates. Yet we find that such consolidated memories produced by today's LLMs are often faulty even when derived from useful experiences. As consolidation proceeds, memory utility first rises, then degrades, and can fall below the no-memory baseline. More surprisingly, even when consolidating from ground-truth solutions, GPT-5.4 fails on 54% of a set of ARC-AGI problems it had previously solved without memory. We trace the regression to the consolidation step rather than the underlying experience: the same trajectories yield qualitatively different memories under different update schedules, and an episodic-only control that simply retains those trajectories remains competitive with the consolidators we test. In a controlled ARC-AGI Stream environment that exposes Retain, Delete, and Consolidate actions, agents preserve raw episodes by default and double the accuracy of their forced-consolidation counterparts; disabling consolidation entirely (episodic management only) matches this auto regime. Practically, robust agent memory should treat raw episodes as first-class evidence and gate consolidation explicitly rather than firing it after every interaction. Looking forward, reliable agentic memory will require LLMs that can consolidate without overwriting the evidence they depend on.","published":"2026-05-13T04:15:50Z","updated":"2026-05-13T04:15:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.12978v1","pdf_url":"https://arxiv.org/pdf/2605.12978v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.12975","versioned_id":"2605.12975v1","title":"Retrieval is Cheap, Show Me the Code: Executable Multi-Hop Reasoning for Retrieval-Augmented Generation","authors":["Jiashuo Sun","Jimeng Shi","Yixuan Xie","Saizhuo Wang","Jash Rajesh Parekh","Pengcheng Jiang","Zhiyi Shi","Jiajun Fan","Qinglong Zheng","Peiran Li","Shaowen Wang","Ge Liu","Jiawei Han"],"abstract":"Retrieval-Augmented Generation (RAG) has become a standard approach for knowledge-intensive question answering, but existing systems remain brittle on multi-hop questions, where solving the task requires chaining multiple retrieval and reasoning steps. Key challenges are that current methods represent reasoning through free-form natural language, where intermediate states are implicit, retrieval queries can drift from intended entities, and errors are detected by the same model that produces them making self-reflection an unreliable, ungrounded signal. We observe that multi-hop question answering is a typical form of step-by-step computation, and that this structured process aligns closely with how code-specialized language models are trained to operate. Motivated by this, we introduce \\pyrag, a framework that reformulates multi-hop RAG as program synthesis and execution. Instead of free-form reasoning trajectories, \\pyrag represents the reasoning process as an executable Python program over retrieval and QA tools, exposing intermediate states as variables, producing deterministic feedback through execution, and yielding an inspectable trace of the entire reasoning process. This formulation further enables compiler-grounded self-repair and execution-driven adaptive retrieval without any additional training. Experiments on five QA benchmarks (PopQA, HotpotQA, 2WikiMultihopQA, MuSiQue, and Bamboogle) show that \\pyrag consistently outperforms strong baselines under both training-free and RL-trained settings, with especially large gains on compositional multi-hop datasets. Our code, data and models are publicly available at https://github.com/GasolSun36/PyRAG.","published":"2026-05-13T04:14:13Z","updated":"2026-05-13T04:14:13Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.12975v1","pdf_url":"https://arxiv.org/pdf/2605.12975v1","comment":"32 pages, 20 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.15219","versioned_id":"2605.15219v2","title":"NOVA: Fundamental Limits of Knowledge Discovery Through AI","authors":["Salman Avestimehr","Ken Duffy","Muriel Médard"],"abstract":"Can AI systems discover genuinely new knowledge through iterative self improvement, and if so, at what cost? We introduce the NOVA framework, which models the common ``generate, verify, accumulate, retrain'' loop as an adaptive sampling process over a knowledge space. We identify sufficient conditions under which accumulated genuine knowledge eventually covers a finite domain, and show how their violations produce distinct failure modes: contamination, forgetting, exploration failure, and acceptance failure. We then analyze imperfect verification and identify a contamination trap: as easy-to-find knowledge is exhausted, the model mass assigned to new valid artifacts shrinks, so even small false-positive rates can cause invalid artifacts to enter the knowledge base faster than genuine discoveries. We clarify that Good--Turing estimation is a local batch-diversity diagnostic, not an estimator of the historically undiscovered valid mass that governs long-term discovery. Under a separate tail-equivalence assumption relating the model's effective discovery distribution to a Zipf law with exponent $α>1$, we prove that the cumulative generation cost required to obtain $D$ distinct genuine discoveries satisfies $R_{\\mathrm{cum}}(D)=Θ(c_{\\mathrm{gen}}D^α)$, where $c_{\\mathrm{gen}}$ is the per-candidate generation cost. This scaling law quantifies asymptotic diminishing returns as the discovery frontier advances. Finally, we formalize human amplification through guidance, generation, and verification, explaining why expert input is most valuable near autonomous exploration barriers.","published":"2026-05-12T21:37:09Z","updated":"2026-05-28T03:12:35Z","categories":["cs.AI","cs.IT"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.15219v2","pdf_url":"https://arxiv.org/pdf/2605.15219v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.12495","versioned_id":"2605.12495v1","title":"AlphaGRPO: Unlocking Self-Reflective Multimodal Generation in UMMs via Decompositional Verifiable Reward","authors":["Runhui Huang","Jie Wu","Rui Yang","Zhe Liu","Hengshuang Zhao"],"abstract":"In this paper, we propose AlphaGRPO, a novel framework that applies Group Relative Policy Optimization (GRPO) to AR-Diffusion Unified Multimodal Models (UMMs) to enhance multimodal generation capabilities without an additional cold-start stage. Our approach unlocks the model's intrinsic potential to perform advanced reasoning tasks: Reasoning Text-to-Image Generation, where the model actively infers implicit user intents, and Self-Reflective Refinement, where it autonomously diagnoses and corrects misalignments in generated outputs. To address the challenge of providing stable supervision for real-world multimodal generation, we introduce the Decompositional Verifiable Reward (DVReward). Unlike holistic scalar rewards, DVReward utilizes an LLM to decompose complex user requests into atomic, verifiable semantic and quality questions, which are then evaluated by a general MLLM to provide reliable and interpretable feedback. Extensive experiments demonstrate that AlphaGRPO yields robust improvements across multimodal generation benchmarks, including GenEval, TIIF-Bench, DPG-Bench and WISE, while also achieving significant gains in editing tasks on GEdit without training on editing tasks. These results validate that our self-reflective reinforcement approach effectively leverages inherent understanding to guide high-fidelity generation. Project page: https://huangrh99.github.io/AlphaGRPO/","published":"2026-05-12T17:59:47Z","updated":"2026-05-12T17:59:47Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2605.12495v1","pdf_url":"https://arxiv.org/pdf/2605.12495v1","comment":"ICML2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.12400","versioned_id":"2605.12400v2","title":"OGLS-SD: On-Policy Self-Distillation with Outcome-Guided Logit Steering for LLM Reasoning","authors":["Yuxiao Yang","Xiaoyun Wang","Weitong Zhang"],"abstract":"We study on-policy self-distillation (OPSD), where a language model improves its reasoning ability by distilling privileged teacher distributions along its own on-policy trajectories. Despite its promise, OPSD can suffer from training instability due to a pattern mismatch between teacher and student responses. Self-reflected teacher responses may introduce reflection-induced biases and response templates that miscalibrate token-level supervision, ultimately harming the student's reasoning ability. To mitigate this issue, we propose OGLS-SD, an outcome-guided logit-steering framework that leverages verifiable outcome rewards to calibrate privileged teacher logits. Specifically, OGLS-SD contrasts teacher logits induced by successful and failed on-policy trajectories, constructing an outcome-discriminative steering direction for token-level guidance. Experiments on mathematical reasoning benchmarks show that OGLS-SD stabilizes self-distillation and improves performance over standard OPSD and other variants.","published":"2026-05-12T17:00:53Z","updated":"2026-05-29T21:49:52Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.12400v2","pdf_url":"https://arxiv.org/pdf/2605.12400v2","comment":"17 pages, 10 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.11732","versioned_id":"2605.11732v2","title":"AgentDisCo: Towards Disentanglement and Collaboration in Open-ended Deep Research Agents","authors":["Jiarui Jin","Zexuan Yan","Shijian Wang","Wenxiang Jiao","Yuan Lu"],"abstract":"In this paper, we present AgentDisCo, a novel Disentangled and Collaborative agentic architecture that formulates deep research as an adversarial optimization problem between information exploration and exploitation. Unlike existing approaches that conflate these two processes into a single module, AgentDisCo employs a critic agent to evaluate generated outlines and refine search queries, and a generator agent to retrieve updated results and revise outlines accordingly. The iteratively refined outline is then passed to a downstream report writer that synthesizes a comprehensive research report. The overall workflow supports both handcrafted and automatically discovered design strategies via a meta-optimization harness, in which the generator agent is repurposed as a scoring agent to evaluate critic outputs and generate quality signals. Powerful code-generation agents (e.g., Claude-Code, Codex) systematically explore agent configurations and construct a policy bank, a structured repository of reusable design strategies, enabling the framework to self-refine without extensive human intervention. We evaluate AgentDisCo on three established deep research benchmarks (DeepResearchBench, DeepConsult, DeepResearchGym) using Gemini-2.5-Pro, achieving performance comparable to or surpassing leading closed-source systems. Observing that existing benchmarks inadequately reflect real-world user needs, we introduce GALA (General AI Life Assistants), a benchmark that mines latent research interests from users' historical browsing behavior. We further develop a rendering agent that converts research reports into visually rich poster presentations, and demonstrate an end-to-end product, AutoResearch Your Interest, which delivers personalized deep research recommendations derived from individual browsing histories.","published":"2026-05-12T08:14:15Z","updated":"2026-06-04T05:47:57Z","categories":["cs.IR","cs.CL","cs.MA","cs.MM"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2605.11732v2","pdf_url":"https://arxiv.org/pdf/2605.11732v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.11671","versioned_id":"2605.11671v1","title":"Cochise: A Reference Harness for Autonomous Penetration Testing","authors":["Andreas Happe","Jürgen Cito"],"abstract":"Recent work on LLM-driven autonomous penetration testing reports promising results, but existing systems often combine many architectural, prompting, and tool-integration choices, making it difficult to tell what is gained over a simple agent scaffold. We present cochise, a 597 LOC Python reference harness for autonomous penetration-testing experiments. Cochise connects an LLM-driven agent to a Linux execution host over SSH and supports controlled target environments reachable from that jump host. The prototype implements a separated Planner--Executor architecture in which long-term state is maintained outside the LLM context, while a ReAct-style executor issues commands over SSH and self-corrects based on command outputs. The scenario prompt can be adapted to different target environments. To demonstrate the efficacy of our minimal harness, we evaluate it against a live third-party testbed called Game of Active Directory (GOAD). Alongside the harness, we release replay and analysis tools: (i) cochise-replay for offline visualization of captured runs, (ii) cochise-analyze-alogs and cochise-analyze-graphs for cost, token, duration, and compromise analysis, and (iii) a corpus of JSON trajectory logs from GOAD runs, allowing researchers to study agent behavior without provisioning the 48--64 GB RAM / 190 GB storage testbed themselves. Cochise is intended not as a state-of-the-art pen-testing agent, but as reusable experimental infrastructure for comparing models, agent architectures, and penetration-testing traces.","published":"2026-05-12T07:28:12Z","updated":"2026-05-12T07:28:12Z","categories":["cs.CR","cs.AI","cs.SE"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.11671v1","pdf_url":"https://arxiv.org/pdf/2605.11671v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.11609","versioned_id":"2605.11609v1","title":"Anti-Self-Distillation for Reasoning RL via Pointwise Mutual Information","authors":["Guobin Shen","Xiang Cheng","Chenxiao Zhao","Lei Huang","Jindong Li","Dongcheng Zhao","Xing Yu"],"abstract":"On-policy self-distillation, where a student is pulled toward a copy of itself conditioned on privileged context (e.g., a verified solution or feedback), offers a promising direction for advancing reasoning capability without a stronger external teacher. Yet in math reasoning the gains are inconsistent, even when the same approach succeeds elsewhere. A pointwise mutual information analysis traces the failure to the privileged context itself: it inflates the teacher's confidence on tokens already implied by the solution (structural connectives, verifiable claims) and deflates it on deliberation tokens (\"Wait\", \"Let\", \"Maybe\") that drive multi-step search. We propose Anti-Self-Distillation (AntiSD), which ascends a divergence between student and teacher rather than descending it: this reverses the per-token sign and yields a naturally bounded advantage in one step. An entropy-triggered gate disables the term once the teacher entropy collapses, completing a drop-in replacement for default self-distillation. Across five models from 4B to 30B parameters on math reasoning benchmarks, AntiSD reaches the GRPO baseline's accuracy in 2 to 10x fewer training steps and improves final accuracy by up to 11.5 points. AntiSD opens a path to scalable self-improvement, where a language model bootstraps its own reasoning through its training signal.","published":"2026-05-12T06:40:43Z","updated":"2026-05-12T06:40:43Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.11609v1","pdf_url":"https://arxiv.org/pdf/2605.11609v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.11117","versioned_id":"2605.11117v1","title":"GRAFT-ATHENA: Self-Improving Agentic Teams for Autonomous Discovery and Evolutionary Numerical Algorithms","authors":["Juan Diego Toscano","Zhaojie Chai","George Em Karniadakis"],"abstract":"Scientific discovery can be modeled as a sequence of probabilistic decisions that map physical problems to numerical solutions. Recent agentic AI systems automate individual scientific tasks by orchestrating LLM-driven planners, solvers, and evaluators. Each method is a combination of methodological actions, with many viable combinations for any given problem and structural dependencies between choices. However, existing frameworks treat each problem in isolation, with no shared substrate to accumulate methodological experience across domains. Here we show that GRAFT-ATHENA, a self-improving agentic framework, learns from past problems and autonomously expands its own action space across diverse domains. GRAFT (Graph Reduction to Adaptive Factored Trees) projects combinatorial decision spaces into factored probabilistic trees in which each method is a single path, taking the parameter footprint from exponential to linear. In the lineage of classical Bayesian networks, the factorization is an $I$-map of the policy, and the resulting paths embed as unique fingerprints in a metric space whose closeness lets each new problem learn from similar past ones. On canonical physics-informed machine learning (PIML) benchmarks, GRAFT-ATHENA improves over human and prior agentic baselines, and on production solvers, it tackles complex engineering problems such as reconstructing Mach-10 flow over the Apollo Command Module from a 1968 report and recovering shear-thinning blood-cell rheology. Notably, the system grows its own knowledge substrate, autonomously proposing regularization constraints for ill-posed inverse problems and discovering new numerical methods such as a spectral PINN with exponential convergence. These results provide a foundation for autonomous laboratories that grow more capable with every problem they solve.","published":"2026-05-11T18:27:01Z","updated":"2026-05-11T18:27:01Z","categories":["cs.LG","cs.MA","math.PR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.11117v1","pdf_url":"https://arxiv.org/pdf/2605.11117v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.10877","versioned_id":"2605.10877v1","title":"Neural at ArchEHR-QA 2026: One Method Fits All: Unified Prompt Optimization for Clinical QA over EHRs","authors":["Abrar Majeedi","Viswanatha Reddy Gajjala","Sai Prasanna Teja Reddy Bogireddy","Siddhant Rai"],"abstract":"Automated question answering (QA) over electronic health records (EHRs) demands precise evidence retrieval, faithful answer generation, and explicit grounding of answers in clinical notes. In this work, we present Neural1.5, our method for the ArchEHR-QA 2026 shared task at CL4Health@LREC 2026, which comprises four subtasks: question interpretation, evidence identification, answer generation, and evidence alignment. Our approach decouples the task into independent, modular stages and employs DSPy\"s MIPROv2 optimizer to automatically discover high-performing prompts, jointly tuning instructions and few-shot demonstrations for each stage. Within every stage, self-consistency voting over multiple stochastic inference runs suppresses spurious errors and improves reliability, while stage-specific verification mechanisms (e.g., self-reflection and chain-of-verification for alignment) further refine output quality. Among all teams that participated in all four subtasks, our method ranks second overall (mean rank 4.00), placing 4th, 1st, 4th, and 7th on Subtasks 1-4, respectively. These results demonstrate that systematic, per-stage prompt optimization combined with self-consistency mechanisms is a cost-effective alternative to model fine-tuning for multifaceted clinical QA.","published":"2026-05-11T17:27:30Z","updated":"2026-05-11T17:27:30Z","categories":["cs.CL","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.10877v1","pdf_url":"https://arxiv.org/pdf/2605.10877v1","comment":"Accepted to CL4Health @ LREC 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.10754","versioned_id":"2605.10754v1","title":"The Agent Use of Agent Beings: Agent Cybernetics Is the Missing Science of Foundation Agents","authors":["Xinrun Wang","Chang Yang","He Zhao","Zhuoyi Lin","Shuyue Hu"],"abstract":"LLM-based foundation agents that perceive, reason, and act across thousands of reasoning steps are rapidly becoming the dominant paradigm for deploying artificial intelligence in open-ended, long-horizon complex tasks. Despite this significance, the field remains overwhelmingly engineering-driven. Engineering practice has converged on useful primitives (tool loops, memory banks, harnesses, reflection steps), yet these are assembled by empirical trial and error rather than from first principles. Fundamental questions remain open: under what conditions does a long-running agent remain on-task? How should an agent respond when its environment exceeds its representational capacity? What architectural properties are necessary for safe self-improvement? We argue that cybernetics, the mid-twentieth-century science of control and communication in complex systems, provides the missing theoretical scaffold for foundation agents. By mapping six canonical laws of classical cybernetics onto six agent design principles, and synthesizing those principles into three engineering desiderata (reliability, lifelong running, and self-Improvement), we arrive at a framework termed Agent Cybernetics. Three application domains, code generation, computer use and automated research, exemplify the analytical framework of agent cybernetics by identifying failure modes and concrete engineering recommendations. We hope that agent cybernetics opens a new research venue and establishes the scientific foundation that foundation agents need for principled, reliable real-world deployment.","published":"2026-05-11T15:53:54Z","updated":"2026-05-11T15:53:54Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.10754v1","pdf_url":"https://arxiv.org/pdf/2605.10754v1","comment":"Preliminary Work","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.10741","versioned_id":"2605.10741v1","title":"AdaPaD: Adaptive Parallel Deflation for PEFT with Self-Correcting Rank Discovery","authors":["Barbara Su","Fangshuo Liao","Anastasios Kyrillidis"],"abstract":"Fine-tuning large language models with LoRA requires choosing a rank r before training starts. Existing approaches either extract rank-1 components sequentially, freezing each component's error permanently into every subsequent residual, or optimize the full low-rank factorization jointly with guarantees that describe only the joint update, not individual rank-1 directions. We present AdaPaD (Adaptive Parallel Deflation), which trains all rank-1 components simultaneously: each worker refines its component against a deflation target built from the latest estimates of all predecessors, and as those estimates improve, the targets improve too. We call this property self-correction: deflation errors converge to zero over rounds rather than persisting as fixed residuals. On top of this backbone, AdaPaD adds advance learning (private pre-training before activation) and per-module dynamic rank discovery (importance-based growth until a shared budget is exhausted), making the rank distribution an output rather than an input. We prove that every component's error decays exponentially after a warm-up period, with a generalization bound that splits into a vanishing algorithmic term and an irreducible statistical floor. Empirically, AdaPaD is competitive with adaptive-rank LoRA baselines on GLUE with DeBERTaV3-base at matched parameter budgets, and competitive with fixed-rank LoRA on Qwen3-0.6B SQuAD/SQuAD v2 while deploying an adapter that is on average 30.7% smaller.","published":"2026-05-11T15:44:13Z","updated":"2026-05-11T15:44:13Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.10741v1","pdf_url":"https://arxiv.org/pdf/2605.10741v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.10347","versioned_id":"2605.10347v2","title":"How Mobile World Model Guides GUI Agents?","authors":["Weikai Xu","Kun Huang","Yunren Feng","Jiaxing Li","Yuhan Chen","Yuxuan Liu","Zhizheng Jiang","Heng Qu","Pengzhi Gao","Wei Liu","Jian Luan","Xiaolin Hu","Bo An"],"abstract":"Recent advances in vision-language models have enabled mobile GUI agents to perceive visual interfaces and execute user instructions, but reliable prediction of action consequences remains critical for long-horizon and high-risk interactions. Existing mobile world models provide either text-based or image-based future states, yet it remains unclear which representation is useful, whether generated rollouts can replace real environments, and how test-time guidance helps agents of different strengths. To answer the above questions, we filter and annotate mobile world-model data, then train world models across four modalities: delta text, full text, diffusion-based images, and renderable code. These models achieve SoTA performance on both MobileWorldBench and Code2WorldBench. Furthermore, by evaluating their downstream utility on AITZ, AndroidControl, and AndroidWorld, we obtain three findings. First, renderable code reconstruction achieves high in-distribution fidelity and provides effective multimodal supervision for data construction, while text-based feedback is more robust for online out-of-distribution (OOD) execution. Second, world-model-generated trajectories can provide transferable interaction experience in the training process and improve agents' end-to-end task performance, although these data do not preserve the original distribution. Last, for overconfident mobile agents with low action entropy, posterior self-reflection provides limited gains, suggesting that world models are more effective as prior perception or training supervision than as universal post-hoc verifiers.","published":"2026-05-11T10:49:31Z","updated":"2026-05-22T05:43:30Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.10347v2","pdf_url":"https://arxiv.org/pdf/2605.10347v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.10253","versioned_id":"2605.10253v1","title":"Knowledge Poisoning Attacks on Medical Multi-Modal Retrieval-Augmented Generation","authors":["Peiru Yang","Haoran Zheng","Tong Ju","Shiting Wang","Wanchun Ni","Jiajun Liu","Shangguang Wang","Yongfeng Huang","Tao Qi"],"abstract":"Retrieval-augmented generation (RAG) is a widely adopted paradigm for enhancing LLMs in medical applications by incorporating expert multimodal knowledge during generation. However, the underlying retrieval databases may naturally contain, or be intentionally injected with, adversarial knowledge, which can perturb model outputs and undermine system reliability. To investigate this risk, prior studies have explored knowledge poisoning attacks in medical RAG systems. Nevertheless, most of them rely on the strong assumption that adversaries possess prior knowledge of user queries, which is unrealistic in deployments and substantially limits their practical applicability. In this paper, we propose M\\textsuperscript{3}Att, a knowledge-poisoning framework designed for medical multimodal RAG systems, assuming only limited distribution knowledge of the underlying database. Our core idea is to inject covert misinformation into textual data while using paired visual data as a query-agnostic trigger to promote retrieval. We first propose a unified framework that introduces imperceptible perturbations to visual inputs to manipulate retrieval probabilities. Besides, due to the prior medical knowledge in LLMs, naively poisoned medical content with explicit factual errors can be corrected during generation. Thus, we leverage the inherent ambiguity of medical diagnosis and design a covert misinformation injection strategy that degrades diagnostic accuracy while evading model self-correction. Experiments on five LLMs and datasets demonstrate that M\\textsuperscript{3}Att consistently produces clinically plausible yet incorrect generations. Codes: https://github.com/ypr17/M3Att.","published":"2026-05-11T09:22:53Z","updated":"2026-05-11T09:22:53Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.10253v1","pdf_url":"https://arxiv.org/pdf/2605.10253v1","comment":"Accepted by ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.09998","versioned_id":"2605.09998v1","title":"Continual Harness: Online Adaptation for Self-Improving Foundation Agents","authors":["Seth Karten","Joel Zhang","Tersoo Upaa","Ruirong Feng","Wenzhe Li","Chengshuai Shi","Chi Jin","Kiran Vodrahalli"],"abstract":"Coding harnesses such as Claude Code and OpenHands wrap foundation models with tools, memory, and planning, but no equivalent exists for embodied agents' long-horizon partial-observability decision-making. We first report our Gemini Plays Pokemon (GPP) experiments. With iterative human-in-the-loop harness refinement, GPP became the first AI system to complete Pokemon Blue, Yellow Legacy on hard mode, and Crystal without a lost battle. In the hardest stages, the agent itself began iterating on its strategy through long-context memory, surfacing emergent self-improvement signals alongside human-in-the-loop refinement. Continual Harness removes the human fully from this loop: a reset-free self-improving harness for embodied agents that formalizes and automates what we observed. Starting from only a minimal environment interface, the agent alternates between acting and refining its own prompt, sub-agents, skills, and memory, drawing on any past trajectory data. Prompt-optimization methods require episode resets; Continual Harness adapts online within a single run. On Pokemon Red and Emerald across frontier models, Continual Harness starting from scratch substantially reduces button-press cost relative to the minimalist baseline and recovers a majority of the gap to a hand-engineered expert harness, with capability-dependent gains, despite starting from the same raw interface with no curated knowledge, no hand-crafted tools, and no domain scaffolding. We then close the loop with the model itself: an online process-reward co-learning loop, in which an open-source agent's rollouts through the refining harness are relabeled by a frontier teacher and used to update the model, drives sustained in-game milestone progress on Pokemon Red without resetting the environment between training iterations.","published":"2026-05-11T05:21:33Z","updated":"2026-05-11T05:21:33Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09998v1","pdf_url":"https://arxiv.org/pdf/2605.09998v1","comment":"28 pages, 19 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.09959","versioned_id":"2605.09959v1","title":"G-Zero: Self-Play for Open-Ended Generation from Zero Data","authors":["Chengsong Huang","Haolin Liu","Tong Zheng","Runpeng Dai","Langlin Huang","Jinyuan Li","Zongxia Li","Zhepei Wei","Yu Meng","Jiaxin Huang"],"abstract":"Self-evolving LLMs excel in verifiable domains but struggle in open-ended tasks, where reliance on proxy LLM judges introduces capability bottlenecks and reward hacking. To overcome this, we introduce G-Zero, a verifier-free, co-evolutionary framework for autonomous self-improvement. Our core innovation is Hint-$δ$, an intrinsic reward that quantifies the predictive shift between a Generator model's unassisted response and its response conditioned on a self-generated hint. Using this signal, a Proposer model is trained via GRPO to continuously target the Generator's blind spots by synthesizing challenging queries and informative hints. The Generator is concurrently optimized via DPO to internalize these hint-guided improvements. Theoretically, we prove a best-iterate suboptimality guarantee for an idealized standard-DPO version of G-Zero, provided that the Proposer induces sufficient exploration coverage and the data filteration keeps pseudo-label score noise low. By deriving supervision entirely from internal distributional dynamics, G-Zero bypasses the capability ceilings of external judges, providing a scalable, robust pathway for continuous LLM self-evolution across unverifiable domains.","published":"2026-05-11T04:12:34Z","updated":"2026-05-11T04:12:34Z","categories":["cs.LG","cs.AI","cs.CL","cs.ET"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09959v1","pdf_url":"https://arxiv.org/pdf/2605.09959v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.09855","versioned_id":"2605.09855v2","title":"Concordia: Self-Improving Synthetic Tables for Federated LLMs","authors":["Jimin Huang","Duanyu Feng","Nuo Chen","Xiaoyu Wang","Zhiqiang Zhang","Xueqing Peng","Mingquan Lin","Prayag Tiwari","Guojun Xiong","Alejandro Lopez-Lira","Sophia Ananiadou"],"abstract":"Federated learning (FL) enables training large language models (LLMs) without sharing raw data, but adapting LLMs under strict data isolation and non-IID client distributions remains challenging in practice. Synthetic data offers a natural privacy-preserving surrogate for local training, yet existing federated pipelines typically treat synthetic generation as static or loosely coupled with downstream optimization, leading to rapidly diminishing utility under heterogeneous clients. We study federated adaptation of LLMs on tabular tasks where raw records and validation data cannot be shared, and local training must rely entirely on synthetic tables. We propose Concordia, a tri-level optimization framework that aligns synthetic data generation with federated validation utility despite these constraints. At the client level, models are adapted via parameter-efficient LoRA training on synthetic tables. Clients additionally learn lightweight utility scorers from private validation feedback to reweight synthetic samples during local training. At the outer level, each client refines its own synthetic table generator using group-relative policy optimization (GRPO), guided by an ensemble of heterogeneous scorers shared across clients, without aggregating generator parameters or exposing validation data. Experiments on privacy-sensitive tabular benchmarks from finance and healthcare demonstrate that Concordia consistently improves federated performance, cross-client stability, and robustness to distribution shift compared to static and decoupled synthetic-data baselines.","published":"2026-05-11T01:17:58Z","updated":"2026-05-18T00:37:30Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09855v2","pdf_url":"https://arxiv.org/pdf/2605.09855v2","comment":"12 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.09730","versioned_id":"2605.09730v3","title":"RubricRefine: Improving Tool-Use Agent Reliability with Training-Free Pre-Execution Refinement","authors":["Will LeVine","Brendan Evers","Sam Saltwick","Abhay Venkatesh"],"abstract":"Iterative self-refinement is a popular inference-time reliability technique, but its effectiveness in code-mode tool use depends heavily on the structure of the feedback signal: unstructured critique helps inconsistently across models, and even revision with real execution feedback improves only modestly ($0.75$ vs. $0.65$ baseline). The dominant failures are inter-tool contract violations (wrong output shape, incorrect tool routing, broken argument provenance) that run to completion without raising errors, making runtime feedback insufficient. We introduce RubricRefine, a training-free method for pre-execution semantic contract verification that generates task- and registry-specific rubrics, scores candidate code against explicit contract checks, and iteratively repairs failures before any execution occurs. RubricRefine reaches $0.86$, averaged across seven models, on M3ToolEval with zero execution attempts, improving over prior inference-time baselines with up to $2.6\\times$ lower latency. Performance remains flat on the predominantly single-step API-Bank, consistent with the method's reliance on inter-tool contract structure. A rubric-category ablation and calibration analysis further characterize when and why the method works.","published":"2026-05-10T19:57:32Z","updated":"2026-05-15T19:01:49Z","categories":["cs.LG","cs.SE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09730v3","pdf_url":"https://arxiv.org/pdf/2605.09730v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.09502","versioned_id":"2605.09502v1","title":"Hidden Error Awareness in Chain-of-Thought Reasoning: The Signal Is Diagnostic, Not Causal","authors":["Aojie Yuan","Zhiyuan Julian Su","Haiyue Zhang","Yi Nian","Yue Zhao"],"abstract":"Chain-of-thought (CoT) prompting assumes that generated reasoning reflects a model's internal computation. We show this assumption is wrong in a specific, measurable way: models internally detect their own reasoning errors but outwardly express confidence in them. A linear probe on hidden states predicts trace correctness with 0.95 AUROC -- from the very first reasoning step (0.79) -- while verbalized confidence for wrong traces is 4.55/5, nearly identical to correct ones (4.87/5). A text-surface classifier achieves only 0.59 on the same data, confirming a 0.20-point gap invisible in the generated text. This hidden error awareness holds across three model families (Qwen, Llama, Phi), 1.5B-72B parameters, and RL-trained reasoning models (DeepSeek-R1, 0.852 AUROC). The natural question is whether this signal can fix the errors it detects. It cannot. Four interventions -- activation steering, probe-guided best-of-N, self-correction, and activation patching -- all fail; patching destroys output coherence entirely. The signal is diagnostic, not causal: a readout of computation quality, not a lever to redirect it. This delineates a boundary for mechanistic interpretability: error representations during reasoning are fundamentally different from the factual knowledge representations that prior work has successfully edited.","published":"2026-05-10T12:26:46Z","updated":"2026-05-10T12:26:46Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.09502v1","pdf_url":"https://arxiv.org/pdf/2605.09502v1","comment":"10 pages, 5 figures, 10 tables.Mechanistic Interpretability @ ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.09359","versioned_id":"2605.09359v1","title":"Skill-R1: Agent Skill Evolution via Reinforcement Learning","authors":["Yash Vishe","Rohan Surana","Xunyi Jiang","Zihan Huang","Xintong Li","Nikki Lijing Kuang","Tong Yu","Ryan A. Rossi","Jingbo Shang","Julian McAuley","Junda Wu"],"abstract":"Agentic large language models often rely on skills, reusable natural language procedures that guide planning, action, and tool use. In practice, skills are typically improved through prompt engineering or by aligning the task LLM itself, which is costly, model-specific, and often infeasible for closed-source models. Skill optimization is not a one-step problem but a recurrent process with two coupled levels of credit assignment: a useful skill must improve rollout quality under current conditioning, while a useful revision must turn observed outcomes into a better skill for the next round. We propose Skill-R1, a reinforcement learning framework for instance-level recurrent skill optimization from verifiable rewards. Rather than updating the task LLM, Skill-R1 trains a lightweight skill generator that conditions on the task context, prior rollouts, and their verified outcomes to produce skills that steer a frozen task LLM. This preserves black-box compatibility with both open- and closed-source models while making adaptation substantially cheaper than model-level updates. Skill-R1 proceeds over multiple generations: at each step, the current skill induces rollouts whose verified outcomes are fed back to produce the next revision. To optimize this recurrent process, we introduce a bi-level group-relative policy optimization objective combining intra-generation and inter-generation advantages. The intra-generation term compares rollouts under shared skill conditioning, while the inter-generation term rewards revisions that improve behavior across successive generations. Together, these provide a principled objective for directional skill evolution rather than one-shot self-refinement. Empirically, Skill-R1 achieves consistent gains over no-skill baselines and standard GRPO across benchmarks with verifiable rewards, with particularly strong improvements on complex, multi-step tasks.","published":"2026-05-10T06:19:15Z","updated":"2026-05-10T06:19:15Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09359v1","pdf_url":"https://arxiv.org/pdf/2605.09359v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.09079","versioned_id":"2605.09079v1","title":"CauSim: Scaling Causal Reasoning with Increasingly Complex Causal Simulators","authors":["Nicolás Astorga","Anita Kriz","Mihaela van der Schaar"],"abstract":"Despite surpassing human performance across mathematics, coding, and other knowledge-intensive tasks, large language models (LLMs) continue to struggle with causal reasoning. A core obstacle is the target data itself: causal systems are complex and often expressed in non-executable forms, while ground-truth answers to causal queries are inherently scarce. We introduce CauSim, a framework that turns causal reasoning from a scarce-label problem into a scalable supervised one. CauSim constructs increasingly complex causal simulators: executable structural causal models (SCMs), incrementally built by LLMs, that scale to globally complex systems while maintaining verifiable answers to causal queries. CauSim operates across representations by formalizing non-executable causal knowledge into code, enabling data augmentation, and translating executable SCMs into natural language, enabling supervision in previously difficult-to-supervise representations. We structure our research into two parts: (1) how to construct increasingly complex causal simulators, and (2) a systematic study of what CauSim enables, demonstrating generalization across representations, consistent gains from curriculum scaling and data volume, LLM self-improvement through self-generated simulators, and data augmentation via formalization of existing domain knowledge.","published":"2026-05-09T17:39:26Z","updated":"2026-05-09T17:39:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.09079v1","pdf_url":"https://arxiv.org/pdf/2605.09079v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.08936","versioned_id":"2605.08936v1","title":"Self-ReSET: Learning to Self-Recover from Unsafe Reasoning Trajectories","authors":["Dongcheng Zhang","Yi Zhang","Yuxin Chen","An Zhang","Xiang Wang","Chaochao Lu"],"abstract":"Large Reasoning Models possess remarkable capabilities for self-correction in general domain; however, they frequently struggle to recover from unsafe reasoning trajectories under adversarial attacks. Existing alignment methods attempt to mitigate this vulnerability by fine-tuning the model on expert data including reflection traces or adversarial prefixes. Crucially, these approaches are often hindered by static training data which inevitably deviate from model's dynamic, on-policy reasoning traces, resulting in model hardly covering its vast generation space and learning to recover from its own failures. To bridge this gap, we propose Self-ReSET, a pure reinforcement learning framework designed to equip LRMs with the intrinsic capacity to recover from their own safety error trajectories, which are subsequently reused as an initial state for reinforcement learning. Extensive experiments across various LRMs and benchmarks demonstrate that Self-ReSET significantly enhances robustness against adversarial attacks especially out-of-distribution (OOD) jailbreak prompts while maintaining general utility, along with efficient data utilization. Further analysis reveals that our method effectively fosters self-recovery patterns, enabling models to better identify and recover from unsafe intermediate error states back to benign paths. Our codes and data are available at https://github.com/Ing1024/Self-ReSET.","published":"2026-05-09T13:14:31Z","updated":"2026-05-09T13:14:31Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.08936v1","pdf_url":"https://arxiv.org/pdf/2605.08936v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.08904","versioned_id":"2605.08904v1","title":"OPT-BENCH: Evaluating the Iterative Self-Optimization of LLM Agents in Large-Scale Search Spaces","authors":["Xiaozhe Li","Jixuan Chen","Xinyu Fang","Shengyuan Ding","Haodong Duan","Qingwen Liu","Kai Chen"],"abstract":"Large Language Models (LLMs) have demonstrated remarkable capabilities in reasoning and tool use. However, the fundamental cognitive faculties essential for problem solving, including perception, reasoning, and memory, remain the stable core of intelligence. Unlike memorizing specific patterns, humans succeed in novel environments by applying these intrinsic faculties to adapt and optimize. Yet, whether LLMs possess this essential capacity, namely the ability to continuously refine solutions in response to dynamic environmental feedback, remains underexplored. To address this challenge, we introduce OPT-BENCH, a benchmark for evaluating self-improvement capabilities in large-scale search spaces. By combining 20 machine learning tasks with 10 classic NP-hard problems, OPT-BENCH provides a rigorous setting to assess whether agents can adapt through intrinsic self-reflection rather than rote tool application. We further propose OPT-Agent, a framework that emulates human-like cognitive adaptation. It operates through a general perception, memory, and reasoning loop, iteratively refining solutions based on environmental feedback. Through extensive experiments on 19 LLMs from 7 model families, including reasoning models, general models, and open-source models ranging from 3B to 235B parameters, we demonstrate that stronger models are more effective at leveraging feedback signals for self-improvement. However, this upper-bound adaptability remains fundamentally constrained by the models' base capacity, and even the most advanced LLMs still fall short of human expert performance.","published":"2026-05-09T11:51:34Z","updated":"2026-05-09T11:51:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.08904v1","pdf_url":"https://arxiv.org/pdf/2605.08904v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.08704","versioned_id":"2605.08704v2","title":"AgentPSO: Evolving Agent Reasoning Skill via Multi-agent Particle Swarm Optimization","authors":["Hyunmin Hwang","Jaemin Kim","Choonghan Kim","Hangeol Chang","Jong Chul Ye"],"abstract":"Multi-agent reasoning has shown promise for improving the problem-solving ability of large language models by allowing multiple agents to explore diverse reasoning paths. However, most existing multi-agent methods rely on inference-time debate or aggregation, which can be vulnerable to incorrect peer influence and biased consensus. Moreover, the agents themselves remain static, as their underlying reasoning skills do not evolve across tasks. In this paper, we introduce \\textbf{AgentPSO}, a particle-swarm-inspired framework for evolving multi-agent reasoning skills. AgentPSO treats each agent as a particle-like reasoner whose state is a natural-language skill and whose velocity is a semantic update direction, iteratively guiding agents toward higher-performing skill configurations. Across training iterations, each agent updates its skill by combining its previous velocity, personal-best skill, global-best skill, and a self-reflective direction derived from peer reasoning trajectories. This enables agents to learn reusable reasoning behaviors by drawing on their own experience and on the strongest skills found by the population, without updating the parameters of the backbone language model. Experiments on mathematical and general reasoning benchmarks show that AgentPSO improves over static single-agent skills and test-time-only multi-agent reasoning baselines. The evolved skills further transfer across benchmarks and to another backbone model, suggesting that AgentPSO captures reusable reasoning procedures rather than merely optimizing benchmark-specific prompts. Code is publicly available at https://github.com/HYUNMIN-HWANG/AgentPSO/.","published":"2026-05-09T05:38:21Z","updated":"2026-06-26T05:42:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.08704v2","pdf_url":"https://arxiv.org/pdf/2605.08704v2","comment":"The 3rd AI for Math Workshop at the 43rd International Conference on Machine Learning (ICML), Seoul, South Korea, 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.08693","versioned_id":"2605.08693v2","title":"SkillMaster: Toward Autonomous Skill Mastery in LLM Agents","authors":["Min Yang","Jinghua Piao","Xu Xia","Xiaochong Lan","Jiaju Chen","Yongshun Gong","Yong Li"],"abstract":"Skills provide an effective mechanism for improving LLM agents on complex tasks, yet in existing agent frameworks, their creation, refinement, and selection are typically governed by external teachers, hand-designed rules, or auxiliary modules. As a result, skills remain external resources to be invoked, rather than capabilities that agents can develop, adapt, and internalize through experience. To endow LLM agents with autonomous skill mastery, we propose SkillMaster, a training framework that teaches agents to create new skills, refine existing skills, and select accumulated skills during task solving. This capability is achieved through three key designs. First, we train agents through trajectory-informed skill review, teaching agents to propose, update, or retain skills based on evidence from completed episodes. Second, each candidate skill edit is designed to be evaluated by its counterfactual utility on related probe tasks, providing a direct learning signal for training skill-editing decisions. Third, we introduce DualAdv-GRPO, which separately estimates advantages for task-solving actions and skill-editing decisions, stabilizing joint training across task solving and skill management. Experiments on ALFWorld and WebShop show that SkillMaster improves the overall success rate over state-of-the-art baselines by 8.8% and 9.3%, respectively, achieving the best performance among all compared methods. Further analysis reveals a marked shift in agent capability: agents trained with SkillMaster can identify skill failures, refine procedural knowledge from trajectory evidence, and transfer improvements to future tasks with limited skill-bank edits. Overall, SkillMaster moves LLM agents beyond mere skill use toward self-improving agents capable of developing, adapting, and applying their own skill repertoires.","published":"2026-05-09T05:03:00Z","updated":"2026-05-12T07:27:47Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.08693v2","pdf_url":"https://arxiv.org/pdf/2605.08693v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.08468","versioned_id":"2605.08468v1","title":"PYTHALAB-MERA: Validation-Grounded Memory, Retrieval, and Acceptance Control for Frozen-LLM Coding Agents","authors":["Mehmet Iscan"],"abstract":"Local LLM-based coding agents increasingly work in settings where correctness is earned through execution feedback, persistent state, and bounded repair, not through a single fluent answer. Static retrieval, long-context prompting, self-refinement, execution-feedback repair, and reinforcement learning over model weights each address part of this setting, but they do not jointly provide validation-grounded episodic memory, adaptive retrieval-action selection, delayed credit assignment, and structural skill reuse around a frozen local model. We introduce PYTHALAB-MERA, a lightweight external controller for local validation-conditioned code generation. The frozen language model proposes complete source files; the controller decides which memory records and AST-derived skills should enter the next prompt, validates each candidate through a fail-fast pipeline, converts validation outcomes into bounded shaped rewards, and propagates delayed credit through TD(lambda)-style eligibility traces. We evaluate the implementation as a local CLI artifact on reinforcement-learning coding tasks with strict validation gates. In the measured hard RL setting with three tasks, three repetitions, and a three-attempt budget, PYTHALAB-MERA passed 8/9 strict validations; the self-refinement baseline and the investigated GRACE extension each passed 0/9. These results support a deliberately bounded claim: in this recorded setting, the external memory-and-retrieval controller improved validation success. They do not establish general-purpose code synthesis, state-of-the-art performance, formal program correctness, or formal safety.","published":"2026-05-08T20:39:32Z","updated":"2026-05-08T20:39:32Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.08468v1","pdf_url":"https://arxiv.org/pdf/2605.08468v1","comment":"28 pages, 4 figures, 7 tables; local CLI artifact evaluation","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.07977","versioned_id":"2605.07977v1","title":"Self-Play Enhancement via Advantage-Weighted Refinement in Online Federated LLM Fine-Tuning with Real-Time Feedback","authors":["Seohyun Lee","Wenzhi Fang","Dong-Jun Han","Seyyedali Hosseinalipour","Christopher G. Brinton"],"abstract":"Recent works have advanced feedback-based learning systems, whereby a foundation model is able to intake incoming feedback (e.g., a user) to self-improve, creating a self-loop system of training. However, existing works are limited in needing to consider an offline setup to allow for such feedback-based methods, and are further limited in the need of requiring privileged ground-truth contexts for training. Moreover, there is limited consideration of federated learning (FL), which is particularly well-suited for incorporating external feedback across large networks of end users, for example, but requires methods to be efficient for training on resource-constrained edge devices. Therefore, we introduce SPEAR (Self-Play Enhancement via Advantage-Weighted Refinement), an efficient online learning algorithm for federated LLM fine-tuning. SPEAR utilizes a feedback-guided self-play loop to construct naturally contrastive pairs per prompt which are utilized to be trained on (i) standard maximum likelihood on correct completions and (ii) confidence-weighted unlikelihood on tail tokens of incorrect completions. Without the need of expensive group generations and ground-truth contexts for training (i.e., only partial, non-answer feedback), in contrast with existing works, SPEAR can be trained both online and in a resource-efficient manner. We validate SPEAR across various benchmark datasets, demonstrating its superior performance in comparison to state-of-the-art baselines. The implementation code is publicly available at https://github.com/lee3296/SPEAR.","published":"2026-05-08T16:35:42Z","updated":"2026-05-08T16:35:42Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.07977v1","pdf_url":"https://arxiv.org/pdf/2605.07977v1","comment":"27 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.06924","versioned_id":"2605.06924v1","title":"A$^2$RD: Agentic Autoregressive Diffusion for Long Video Consistency","authors":["Do Xuan Long","Yale Song","Min-Yen Kan","Tomas Pfister","Long T. Le"],"abstract":"Synthesizing consistent and coherent long video remains a fundamental challenge. Existing methods suffer from semantic drift and narrative collapse over long horizons. We present A$^2$RD, an Agentic Auto-Regressive Diffusion architecture that decouples creative synthesis from consistency enforcement. A$^2$RD formulates long video synthesis as a closed-loop process that synthesizes and self-improves video segment-by-segment through a Retrieve--Synthesize--Refine--Update cycle. It comprises three core components: (i) Multimodal Video Memory that tracks video progression across modalities; (ii) Adaptive Segment Generation that switches among generation modes for natural progression and visual consistency; and (iii) Hierarchical Test-Time Self-Improvement that self-improves each segment at frame and video levels to prevent error propagation. We further introduce LVBench-C, a challenging benchmark with non-linear entity and environment transitions to stress-test long-horizon consistency. Across public and LVBench-C benchmarks spanning one- to ten-minute videos, A$^2$RD outperforms state-of-the-art baselines by up to 30% in consistency and 20% in narrative coherence. Human evaluations corroborate these gains while also highlighting notable improvements in motion and transition smoothness.","published":"2026-05-07T20:35:46Z","updated":"2026-05-07T20:35:46Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2605.06924v1","pdf_url":"https://arxiv.org/pdf/2605.06924v1","comment":"Project page: http://dxlong2000.github.io/AARD","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.06822","versioned_id":"2605.06822v1","title":"SHARP: A Self-Evolving Human-Auditable Rubric Policy for Financial Trading Agents","authors":["Xiwen Chen","Wenhui Zhu","Songzhu Zheng","Kashif Rasul","Yueyue Deng","Huayu Li"],"abstract":"Large language models (LLMs) are increasingly deployed for autonomous financial trading, a domain requiring continuous adaptation to noisy, non-stationary markets. Existing self-improving agents typically address this through unbounded free-form prompt optimization. However, in low signal-to-noise environments with delayed scalar rewards (P\\&L), this unstructured approach exacerbates the fundamental credit assignment problem: optimizers cannot reliably distinguish systematic logic flaws from stochastic market variance, inevitably leading to policy drift. To overcome this bottleneck, we introduce the Self-Evolving Human-Auditable Rubric Policy (SHARP), a neuro-symbolic framework that replaces unconstrained text mutation with structured, symbolic policy optimization. SHARP confines the agent's reasoning to a bounded, human-readable rubric of explicit condition-action rules. When sub-optimal trades occur, an attribution agent employs cross-sample reasoning across multiple samples to isolate specific rule failures. This enables targeted, atomic policy edits that are subsequently regularized through strict walk-forward validation. Evaluated across three diverse equity sectors and four LLM backbones, SHARP consistently transforms generic initial heuristics into highly robust strategies, lifting the empirical performance of compact models by 10 to 20 percentage points on average (e.g., GPT-4o-mini). Ultimately, SHARP demonstrates that LLMs can achieve dynamic and efficient adaptation while significantly enhancing the structural transparency and auditability demanded by institutional finance.","published":"2026-05-07T18:23:44Z","updated":"2026-05-07T18:23:44Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.06822v1","pdf_url":"https://arxiv.org/pdf/2605.06822v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.06139","versioned_id":"2605.06139v2","title":"Listwise Policy Optimization: Group-based RLVR as Target-Projection on the LLM Response Simplex","authors":["Yun Qu","Qi Wang","Yixiu Mao","Heming Zou","Yuhang Jiang","Yingyue Li","Wutong Xu","Lizhou Cai","Weijie Liu","Clive Bai","Kai Yang","Yangkun Chen","Saiyong Yang","Xiangyang Ji"],"abstract":"Reinforcement learning with verifiable rewards (RLVR) has become a standard approach for large language models (LLMs) post-training to incentivize reasoning capacity. Among existing recipes, group-based policy gradient is prevalent, which samples a group of responses per prompt and updates the policy via group-relative advantage signals. This work reveals that these optimization strategies share a common geometric structure: each implicitly defines a target distribution on the response simplex and projects toward it via first-order approximation. Building on this insight, we propose Listwise Policy Optimization (LPO) to explicitly conduct the target-projection, which demystifies the implicit target by restricting the proximal RL objective to the response simplex, and then projects the policy via exact divergence minimization. This framework provides (i) monotonic improvement on the listwise objective with bounded, zero-sum, and self-correcting projection gradients, and (ii) flexibility in divergence selection with distinct structural properties through the decoupled projection step. On diverse reasoning tasks and LLM backbones, LPO consistently improves training performance over typical policy gradient baselines under matched targets, while intrinsically preserving optimization stability and response diversity.","published":"2026-05-07T12:38:17Z","updated":"2026-05-20T08:43:26Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.06139v2","pdf_url":"https://arxiv.org/pdf/2605.06139v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.05963","versioned_id":"2605.05963v1","title":"TheraAgent: Self-Improving Therapeutic Agent for Precise and Comprehensive Treatment Planning","authors":["Junkai Li","Yunghwei Lai","Tianyi Zhu","Zheng Long Lee","Weizhi Ma","Yang Liu"],"abstract":"Formulating a treatment plan is inherently a complex reasoning and refinement task rather than a simple generation problem. However, existing large language models (LLMs) mainly rely on one-shot output without explicit verification, which may result in rough, incomplete, and potentially unsafe treatment plans. To address these limitations, we propose TheraAgent, an agentic framework that replaces one-shot generation with an iterative generate-judge-refine pipeline. By mirroring the actual reasoning process of human experts who iteratively revise treatment plans, our framework progressively transforms coarse and incomplete drafts into precise, comprehensive, and safer therapeutic regimens. To facilitate the critical judge component, we introduce TheraJudge, a treatment-specific evaluation module integrated into the inference loop to enforce clinical standards. Experiments show TheraAgent achieves state-of-the-art results on HealthBench, leading in Accuracy and Completeness. In expert evaluations, it attains an 86% win rate against physicians, with superior Targeting and Harm Control. Moreover, the highly agreement between TheraJudge and HealthBench evaluations confirms the reliability of our framework.","published":"2026-05-07T10:10:22Z","updated":"2026-05-07T10:10:22Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.05963v1","pdf_url":"https://arxiv.org/pdf/2605.05963v1","comment":"Accepted to ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.05846","versioned_id":"2605.05846v1","title":"LoopTrap: Termination Poisoning Attacks on LLM Agents","authors":["Huiyu Xu","Zhibo Wang","Wenhui Zhang","Ziqi Zhu","Yaopeng Wang","Kui Ren","Chun Chen"],"abstract":"Modern LLM agents solve complex tasks by operating in iterative execution loops, where they repeatedly reason, act, and self-evaluate progress to determine when a task is complete. In this work, we show that while this self-directed loop facilitates autonomy, it also introduces a critical risk: by injecting malicious prompts into the agent's context, an adversary can distort the agent's termination judgment, making it believe the task remains incomplete and leading to unbounded computation.To understand this threat, we define and systematically characterize it as Termination Poisoning and design 10 representative attack strategies. Through a empirical study spanning 8 LLM agents and 60 tasks, we demonstrate that different LLM agents exhibit distinct behavioral signatures that determine which strategies succeed. These transferable patterns can serve as principled guidance for crafting effective attacks against previously unseen agents and tasks, enabling scalable red-teaming beyond manually designed templates. Building on these insights, we introduce LoopTrap, an automated red-teaming framework that synthesizes target-specific malicious prompts by exploiting agent behavioral tendencies. LoopTrap first constructs a behavioral profile of the target agent along four vulnerability dimensions via lightweight probing. It then performs adaptive trap synthesis, routing to the most effective strategy and selecting optimal injections via a self-scoring mechanism. Finally, successful traps are abstracted into a reusable skill library, while failed attempts are refined through self-reflection, ensuring continuous improvement. Extensive evaluation shows that LoopTrap achieves an average of 3.57$\\times$ step amplification across 8 mainstream agents, with a peak of 25$\\times$.","published":"2026-05-07T08:21:51Z","updated":"2026-05-07T08:21:51Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.05846v1","pdf_url":"https://arxiv.org/pdf/2605.05846v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.05716","versioned_id":"2605.05716v1","title":"More Is Not Always Better: Cross-Component Interference in LLM Agent Scaffolding","authors":["Ming Liu"],"abstract":"LLM agent systems are built by stacking scaffolding components (planning, tools, memory, self-reflection, retrieval) assuming more is better. We study cross-component interference (CCI): degradation when components interact destructively. We run a full factorial experiment over all 2^5=32 subsets of five components on HotpotQA and GSM8K with Llama-3.1-8B/70B (96 conditions, up to 10 seeds). The All-In system is consistently suboptimal: on HotpotQA, a single-tool agent surpasses All-In by 32% (F1 0.233 vs 0.177, p=0.023); on GSM8K, a 3-component subset beats All-In by 79% (0.43 vs 0.24, p=0.010). Optimal component count is task-dependent (k*=1-4) and scale-sensitive: at 70B, combinations that hurt at 8B provide gains, though All-In still trails the best subset. We fit a main-effects regression (R^2=0.916, adj-R^2=0.899, LOOCV=0.872), compute exact Shapley values, and find 183/325 submodularity violations (56.3%), showing greedy selection is unreliable. A three-body synergy among Tool Use, Self-Reflection, and Retrieval (INT_3=+0.175, 95% CI [+0.003,+0.351]) is reported as exploratory. CCI replicates across model families (Qwen2.5) and is robust to prompt paraphrasing. Our findings suggest maximally-equipped agent defaults should be replaced by task-specific subset selection via interaction-aware analysis.","published":"2026-05-07T06:01:43Z","updated":"2026-05-07T06:01:43Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.05716v1","pdf_url":"https://arxiv.org/pdf/2605.05716v1","comment":"10 pages, 5 tables; preprint, under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.04874","versioned_id":"2605.04874v1","title":"Uncertainty-Aware Exploratory Direct Preference Optimization for Multimodal Large Language Models","authors":["Huatian Zhang","Zhendong Mao","Lei Zhang","Yongdong Zhang"],"abstract":"Direct Preference Optimization (DPO) has proven to be an effective solution for mitigating hallucination in Multimodal Large Language Models (MLLMs) by learning from preference pairs. One of its key challenges lies in how to transfer the sequence-level preference into fine-grained supervision on visual fidelity. To safeguard vision-related tokens that are prone to hallucination, existing methods typically allocate training emphasis according to the model's self-assessed visual sensitivity signals. However, such sensitivity, estimated by a model still under training, introduces self-referential bias: reinforcing already well-learned visual cues while neglecting hard-to-perceive but critical details, thereby limiting deeper alignment. In this work, we propose an Uncertainty-aware Exploratory Direct Preference Optimization (UE-DPO) method for MLLMs, which enables the model to uncover its cognitive deficiencies and actively explore for self-correction, guided by token-level epistemic uncertainty. Specifically, we first quantify the uncertainty from the model's failure to ground token predictions in the given image. Then, based on an uncertainty-aware exploration intensity, we encourage more learning pressure on visually deficient tokens in preferred samples, and alleviate the over-penalization of beneficial knowledge in dispreferred samples. Further, we provide a theoretical justification for our method, and extensive experiments demonstrate its effectiveness and robustness.","published":"2026-05-06T13:08:12Z","updated":"2026-05-06T13:08:12Z","categories":["cs.LG","cs.CL","cs.CV"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.04874v1","pdf_url":"https://arxiv.org/pdf/2605.04874v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.04494","versioned_id":"2605.04494v1","title":"Towards General Preference Alignment: Diffusion Models at Nash Equilibrium","authors":["Jiaming Hu","Jiamu Bai","Haoyu Wang","Debarghya Mukherjee","Ioannis Ch. Paschalidis"],"abstract":"Reinforcement learning from human feedback (RLHF) has been popular for aligning text-to-image (T2I) diffusion models with human preferences. As a mainstream branch of RLHF, Direct Preference Optimization (DPO) offers a computationally efficient alternative that avoids explicit reward modeling and has been widely adopted in diffusion alignment. However, existing preference-based methods for diffusion alignment still rely on reward-induced preference signals and typically assume that human preferences can be adequately modeled by the Bradley--Terry (BT) model, which may fail to capture the full complexity of human preferences. In this paper, we formulate diffusion alignment from a game-theoretic perspective. We propose Diffusion Nash Preference Optimization (Diff.-NPO), an intuitive general preference framework for diffusion alignment. Diff.-NPO encourages the current policy to play against itself to achieve self improvement and lead to a better alignment. Empirically, we demonstrate the effectiveness of Diff.-NPO on the text-to-image generation task via various metrics. Diff.-NPO consistently outperforms existing preference-based diffusion alignment methods.","published":"2026-05-06T04:50:42Z","updated":"2026-05-06T04:50:42Z","categories":["cs.LG","cs.CV"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.04494v1","pdf_url":"https://arxiv.org/pdf/2605.04494v1","comment":"21 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.04421","versioned_id":"2605.04421v1","title":"FLUID: Continuous-Time Hyperconnected Sparse Transformer for Sink-Free Learning","authors":["Waleed Razzaq","Yun-Bo Zhao"],"abstract":"Continuous-time (CT) Transformers improve irregular and long-range modeling over CT-RNNs by exploiting inputs or outputs embeddings with continuous dynamics. However, the core scaled-dot-product-attention (SDPA) mechanism remains inherently discrete. We propose FLUID (Flexible Unified Information Dynamics), a CT Transformer that incorporates continuous dynamics directly into the attention computation by replacing it with Liquid Attention Network (LAN). LAN reinterprets attention logits as continuous dynamical system and reformulates them as the solution to a linear ODE modulated by input-dependent nonlinear recurrent gates. Theoretically, we establish stability guarantees for LAN dynamics and show that it serves as an interpolating middle ground between SDPA and CT-RNNs, recovering each as special case under well-defined parameterization of its gating functions. LAN also introduces an explicit attention-sink gate to eliminate disproportionate attention mass on uninformative nodes. FLUID replaces standard residual connections with input-dependent Liquid Hyper-Connections to adaptively regulate interlayer information flow. Empirically, we evaluate FLUID on a broad set of learning tasks, including (i) irregular time-series, (ii) long-range modeling, (iii) lane-keeping control of autonomous vehicles, and (iv) learning physical dynamics under a scarce data regime. Across all the tasks, FLUID consistently matches or outperforms CT baselines, achieving improvements of up to 47% in certain scenarios and enhancing generalization under distributional shifts. Additionally, FLUID demonstrates superior noise robustness and a self-correcting inductive bias in autonomous vehicle control. We also provide a detailed analysis of key hyperparameters to guide tuning and show that FLUID occupies an intermediate position among competing approaches in terms of runtime and memory efficiency.","published":"2026-05-06T02:27:25Z","updated":"2026-05-06T02:27:25Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.04421v1","pdf_url":"https://arxiv.org/pdf/2605.04421v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.03871","versioned_id":"2605.03871v1","title":"EvoLM: Self-Evolving Language Models through Co-Evolved Discriminative Rubrics","authors":["Shuyue Stella Li","Rui Xin","Teng Xiao","Yike Wang","Rulin Shao","Zoey Hao","Melanie Sclar","Sewoong Oh","Faeze Brahman","Pang Wei Koh","Yulia Tsvetkov"],"abstract":"Language models encode substantial evaluative knowledge from pretraining, yet current post-training methods rely on external supervision (human annotations, proprietary models, or scalar reward models) to produce reward signals. Each imposes a ceiling. Human judgment cannot supervise capabilities beyond its own, proprietary APIs create dependencies, and verifiable rewards cover only domains with ground-truth answers. Self-improvement from a model's own evaluative capacity is a reward source that scales with the model itself, yet remains largely untapped by current methods. We introduce EVOLM, a post-training method that structures this capacity into explicit discriminative rubrics and uses them as training signal. EVOLM trains two capabilities within a single language model in alternation: (1) a rubric generator producing instance-specific evaluation criteria optimized for discriminative utility, which maximizes a small frozen judge's ability to distinguish preferred from dispreferred responses; and (2) a policy trained using those rubric-conditioned scores as reward. All preference signals are constructed from the policy's own outputs via temporal contrast with earlier checkpoints, requiring no human annotation or external supervision. EVOLM trains a Qwen3-8B model to generate rubrics that outperform GPT-4.1 on RewardBench-2 by 25.7%. The co-trained policy achieves 69.3% average on the OLMo3-Adapt suite, outperforming policies trained with GPT-4.1 prompted rubrics by 3.9% and with the state-of-the-art 8B reward model SkyWork-RM by 16%. Overall, EVOLM demonstrates that structuring a model's evaluative capacity into co-evolving discriminative rubrics enables self-improvement without external supervision.","published":"2026-05-05T15:31:00Z","updated":"2026-05-05T15:31:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.03871v1","pdf_url":"https://arxiv.org/pdf/2605.03871v1","comment":"32 pages, 2 figures, 21 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.03625","versioned_id":"2605.03625v1","title":"Self-Improvement for Fast, High-Quality Plan Generation","authors":["Robert Gieselmann","Henrike von Huelsen","Mihai Samson","Marie-Christine Meyer","Dariusz Piotrowski","Oleksandr Radomskyi","Justin Okamoto","Turan Gojayev","Michael Painter","Gavin Brown","Federico Pecora","Jeremy L. Wyatt"],"abstract":"Generative models trained on synthetic plan data are a promising approach to generalized planning. Recent work has focused on finding any valid plan, rather than a high-quality solution. We address the challenge of producing high-quality plans, a computationally hard problem, in sub-exponential time. First, we demonstrate that, given optimal data, a decoder-only transformer can generate high-quality plans for unseen problem instances. Second, we show how to self-improve an initial model trained on sub-optimal data. Each round of self-improvement combines multiple model calls with graph search to generate improved plans, used for model fine-tuning. An experimental study on four domains: Blocksworld, Logistics, Labyrinth, and Sokoban, shows on average a 30% reduction in plan length over the source symbolic planner, with over 80% of plans being optimal, where the optimum is known. Plan quality is further improved by inference-time search. The model's latency scales sub-exponentially in contrast to the satisficing and optimal symbolic planners to which we compare. Together, these results suggest that self-improvement with generative models offers a scalable approach for high-quality plan generation.","published":"2026-05-05T10:55:18Z","updated":"2026-05-05T10:55:18Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.03625v1","pdf_url":"https://arxiv.org/pdf/2605.03625v1","comment":"Accepted at ICAPS 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.03377","versioned_id":"2605.03377v1","title":"GRAFT: Auditing Graph Neural Networks via Global Feature Attribution","authors":["Rishi Raj Sahoo","Subhankar Mishra"],"abstract":"Graph Neural Networks (GNNs) achieve strong performance on node classification tasks but remain difficult to interpret, particularly with respect to which input features drive their predictions. Existing global GNN explainers operate at the structural level identifying recurring subgraph motifs, but none explain model behaviour globally at the level of input node attributes. We propose GRAFT, a posthoc global explanation framework that identifies class-level feature importance profiles for GNNs. The method combines diversity-guided exemplar selection, Integrated Gradients-based attribution, and aggregation to construct a global view of feature influence for each class, which can be further expressed as concise natural language rules using a large language model with self-refinement. We evaluate GRAFT across multiple datasets, architectures, and experimental settings, demonstrating its effectiveness in capturing model-relevant features, supporting bias analysis, and enabling feature-efficient transfer learning. In addition, we introduce a structured human evaluation protocol to assess the interpretability of generated rules along dimensions such as accuracy and usefulness. Our results suggest that GRAFT provides a practical and interpretable approach for analysing feature-level behaviour in GNNs, bridging quantitative attribution with human-understandable explanations.","published":"2026-05-05T05:36:31Z","updated":"2026-05-05T05:36:31Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.03377v1","pdf_url":"https://arxiv.org/pdf/2605.03377v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.05248","versioned_id":"2605.05248v4","title":"Governed Metaprogramming for Intelligent Systems: Reclassifying Eval as a Governed Effect","authors":["Alan L. McCann"],"abstract":"AI systems increasingly synthesize executable structure at runtime: LLMs generate programs, agents construct workflows,self-improving systems modify their own behavior. In classical homoiconic and staged languages, the transition from code representation to execution is unrestricted. eval is a language primitive, not a governed operation. We argue that in governed intelligent systems, this transition is an authority amplification: it converts symbolic structure into executable authority and must be mediated like any other effect. We present governed metaprogramming, a language design where program representations (machine forms) are first-class values, form manipulation is pure computation, and materialization (the transition from form to executable machine) is a governed effect subject to structural inspection. The governance system analyzes the proposed program's capability requirements, policy compliance, and resource estimates before permitting execution. We formalize two judgments: pure form evaluation (which emits no directives) and governed materialization (which emits exactly one governed directive). We prove three properties: purity of form manipulation, the no-bypass theorem, and boundary preservation. We implement the design in mashinTalk, a DSL for AI workflows compiling to BEAM byte code, and report on integration with 454 existing machine-checked Rocq theorems. The central contribution is reclassifying eval from a language primitive into a governed effect.","published":"2026-05-05T02:56:43Z","updated":"2026-05-26T12:37:10Z","categories":["cs.PL","cs.AI"],"primary_category":"cs.PL","arxiv_url":"https://arxiv.org/abs/2605.05248v4","pdf_url":"https://arxiv.org/pdf/2605.05248v4","comment":"15 pages. Companion proofs: https://github.com/mashin-live/governance-proofs. Project: https://mashin.live. Update: Abstract typo fixes. Updated license","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.03308","versioned_id":"2605.03308v1","title":"Revisiting the Travel Planning Capabilities of Large Language Models","authors":["Bo-Wen Zhang","Jin Ye","Peng-Yu Hua","Jia-Wei Cao","Jie-Jing Shao","Yu-Feng Li","Lan-Zhe Guo"],"abstract":"Travel planning serves as a critical task for long-horizon reasoning, exposing significant deficits in LLMs. However, existing benchmarks and evaluations primarily assess final plans in an end-to-end manner, which lacks interpretability and makes it difficult to analyze the root causes of failures. To bridge this gap, we decompose travel planning into five constituent atomic sub-capabilities, including \\emph{Constraint Extraction}, \\emph{Tool Use}, \\emph{Plan Generation}, \\emph{Error Identification}, and \\emph{Error Correction}. We implement a decoupled evaluation protocol leveraging oracle intermediate contexts to rigorously isolate these components, thereby measuring the atomic performance boundary without the noise of cascading errors. Our results highlight a clear contrast in performance: while LLMs are proficient in extracting explicit constraints, they struggle to infer implicit, open-world requirements. Furthermore, they exhibit structural biases in plan generation and suffer from ineffective self-correction, characterized by excessive sensitivity and erroneous persistence. These findings offer precise directions for improving LLM reasoning and planning abilities.","published":"2026-05-05T02:56:25Z","updated":"2026-05-05T02:56:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.03308v1","pdf_url":"https://arxiv.org/pdf/2605.03308v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.03042","versioned_id":"2605.03042v1","title":"ARIS: Autonomous Research via Adversarial Multi-Agent Collaboration","authors":["Ruofeng Yang","Yongcan Li","Shuai Li"],"abstract":"This report describes ARIS (Auto-Research-in-sleep), an open-source research harness for autonomous research, including its architecture, assurance mechanisms, and early deployment experience. The performance of agent systems built on LLMs depends on both the model weights and the harness around them, which governs what information to store, retrieve, and present to the model. For long-horizon research workflows, the central failure mode is not a visible breakdown but a plausible unsupported success: a long-running agent can produce claims whose evidential support is incomplete, misreported, or silently inherited from the executor's framing. Therefore, we present ARIS as a research harness that coordinates machine-learning research workflows through cross-model adversarial collaboration as a default configuration: an executor model drives forward progress while a reviewer from a different model family is recommended to critique intermediate artifacts and request revisions. ARIS has three architectural layers. The execution layer provides more than 65 reusable Markdown-defined skills, model integrations via MCP, a persistent research wiki for iterative reuse of prior findings, and deterministic figure generation. The orchestration layer coordinates five end-to-end workflows with adjustable effort settings and configurable routing to reviewer models. The assurance layer includes a three-stage process for checking whether experimental claims are supported by evidence: integrity verification, result-to-claim mapping, and claim auditing that cross-checks manuscript statements against the claim ledger and raw evidence, as well as a five-pass scientific-editing pipeline, mathematical-proof checks, and visual inspection of the rendered PDF. A prototype self-improvement loop records research traces and proposes harness improvements that are adopted only after reviewer approval.","published":"2026-05-04T18:10:15Z","updated":"2026-05-04T18:10:15Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2605.03042v1","pdf_url":"https://arxiv.org/pdf/2605.03042v1","comment":"Technical report. Code at https://github.com/wanshuiyin/Auto-claude-code-research-in-sleep","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.02728","versioned_id":"2605.02728v1","title":"ORPilot: A Production-Oriented Agentic LLM-for-OR Tool for Optimization Modeling","authors":["Guangrui Xie"],"abstract":"This paper presents ORPilot, an open-source agentic AI system that translates real-world business problems into solver-ready optimization models. Unlike academic LLM-for-OR tools that assume clean problem specifications with preformatted inline data, ORPilot is designed for production conditions: ambiguous descriptions, large-scale raw operational data, and the need for portability across solver backends. The system introduces four novel components: (1) a conversational interview agent to elicit complete problem specifications, (2) a data collection agent that retrieves data independently of prompts, (3) a parameter computation agent to bridge raw tabular data and model-ready parameters, and (4) a solver-agnostic Intermediate Representation (IR) for deterministic, zero-LLM-call recompilation to Gurobi, CPLEX, PuLP, Pyomo, or OR-Tools solvers. Additionally, self-correcting retry loops utilize solver tracebacks for targeted repairs. ORPilot represents the first attempt to target production-level business problems rather than textbook operations research (OR) cases. Evaluation on real-world problems demonstrates promising results. When tested against traditional academic benchmarks: IndustryOR, NL4OPT and NLP4LP, ORPilot outperformed state-of-the-art tools in accuracy on the IndustryOR benchmark and delivered comparable performance on NL4OPT and NLP4LP.","published":"2026-05-04T15:28:10Z","updated":"2026-05-04T15:28:10Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.02728v1","pdf_url":"https://arxiv.org/pdf/2605.02728v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.02163","versioned_id":"2605.02163v1","title":"DocSync: Agentic Documentation Maintenance via Critic-Guided Reflexion","authors":["Sidhesh Badrinarayan","Adithya Parthasarathy"],"abstract":"Software documentation frequently drifts from executable logic as codebases evolve, creating technical debt that degrades maintainability and causes downstream API misuse. While static analysis tools can detect the absence of documentation, they cannot evaluate its semantic consistency. Conversely, standard Large Language Models (LLMs) offer generative flexibility but frequently hallucinate when updating documentation without deep structural awareness of the underlying code. To address this gap, we propose DocSync, an agentic workflow that frames documentation maintenance as a structurally grounded, iterative generation task. DocSync bridges syntactic changes and natural language descriptions by fusing Abstract Syntax Tree (AST) representations and Retrieval-Augmented Generation (RAG) to provide dependency-aware context. Furthermore, to ensure factual consistency, we incorporate a critic-guided refinement loop based on the Reflexion paradigm, allowing the model to self-correct candidate updates against the source code. We empirically evaluate a resource-constrained implementation of DocSync-using a LoRA-adapted small language model - on a proxy code-to-text maintenance task. Our findings demonstrate that this AST-aware agentic approach substantially outperforms standard encoder-decoder baselines across semantic alignment, summary-line faithfulness, and automated judge preferences (e.g., achieving an automated judge score of 3.44/5.0 compared to 1.91 for CodeT5-base). Crucially, the iterative critic loop yields measurable improvements in semantic correctness without requiring scaled-up parameter counts. These results provide strong evidence that coupling structural retrieval with agentic refinement is a highly promising direction for autonomously mitigating documentation debt.","published":"2026-05-04T02:41:33Z","updated":"2026-05-04T02:41:33Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2605.02163v1","pdf_url":"https://arxiv.org/pdf/2605.02163v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.01789","versioned_id":"2605.01789v1","title":"DataEvolver: Let Your Data Build and Improve Itself via Goal-Driven Loop Agents","authors":["Qisong Zhang","Wenzhuo Wu","Zhuangzhuang Jia","Yunhao Yang","Huayu Zhang","Xianghao Zang","Zhixiang He","Zhongjiang He","Kongming Liang","Zhanyu Ma"],"abstract":"Constructing controllable visual data is a major bottleneck for image editing and multimodal understanding. Useful supervision is rarely produced by a single rendering pass; instead it emerges through iterative generation, inspection, correction, filtering, and export. We present DataEvolver, a closed-loop visual data engine that organizes this process around explicit goals, persistent artifacts, bounded corrective actions, and acceptance decisions. DataEvolver supports multiple artifact types, including RGB images, masks, depth maps, normal maps, meshes, poses, trajectories, and review traces. In the current release, the system operates through two coupled loops: generation-time self-correction within each sample and validation-time self-expansion across dataset rounds. We validate the framework on an image-level object-rotation setting. With a fixed Qwen-Edit LoRA probe, our final Ours+DualGate model outperforms both the unadapted base model and a public multi-angle LoRA on SpatialEdit and a held-out evaluation set. Ablations show a consistent improvement path from scene-aware generation to feedback-driven correction and dual-gated validation. Beyond the released rotation data, our main contribution is a reusable framework for building visual datasets through explicit goal tracking, review, correction, and acceptance loops.","published":"2026-05-03T09:10:23Z","updated":"2026-05-03T09:10:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.01789v1","pdf_url":"https://arxiv.org/pdf/2605.01789v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.01591","versioned_id":"2605.01591v1","title":"Led to Mislead: Adversarial Content Injection for Attacks on Neural Ranking Models","authors":["Amin Bigdeli","Amir Khosrojerdi","Radin Hamidi Rad","Morteza Zihayat","Charles L. A. Clarke","Ebrahim Bagheri"],"abstract":"Neural Ranking Models (NRMs) are central to modern information retrieval but remain highly vulnerable to adversarial manipulation. Existing attacks often rely on heuristics or surrogate models, limiting effectiveness and transferability. We propose CRAFT, a supervised framework for black-box adversarial rank attacks powered by large language models (LLMs). CRAFT operates in three stages: adversarial dataset generation via retrieval-augmented generation and self-refinement, supervised fine-tuning on curated adversarial examples, and preference-guided optimization to align generations with rank-promotion objectives. Extensive experiments on the MS MARCO passage dataset, TREC Deep Learning 2019, and TREC Deep Learning 2020 benchmarks show that CRAFT significantly outperforms state-of-the-art baselines, achieving higher promotion rates and rank boosts while preserving fluency and semantic fidelity. Moreover, CRAFT transfers effectively across diverse ranking architectures, including cross-encoder, embedding-based, and LLM-based rankers, underscoring vulnerabilities in real-world retrieval systems. This work provides a principled framework for studying adversarial threats in NRMs, underscores the risks of generative AI in rank manipulation, and provides a foundation for developing more robust retrieval systems. To support reproducibility, we publicly release our source code, trained models, and prompt templates.","published":"2026-05-02T19:26:34Z","updated":"2026-05-02T19:26:34Z","categories":["cs.IR","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2605.01591v1","pdf_url":"https://arxiv.org/pdf/2605.01591v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.01566","versioned_id":"2605.01566v1","title":"Multi-Agent Reasoning Improves Compute Efficiency: Pareto-Optimal Test-Time Scaling","authors":["Florian Valentin Wunderlich","Lars Benedikt Kaesberg","Jan Philip Wahle","Terry Ruas","Bela Gipp"],"abstract":"Advances in inference methods have enabled language models to improve their predictions without additional training. These methods often prioritize raw performance over cost-effective compute usage. However, computational efficiency is key for real-world applications with resource constraints. We provide a systematic analysis of the inference scaling strategies self-consistency, self-refinement, multi-agent debate, and mixture-of-agents, to study their computational performance tradeoffs. We evaluate methods on two reasoning benchmarks (MMLU-Pro, BBH) and include extensive parameter configurations (e.g., scaling the number of parallel predictions, agents, and debate rounds) across different model sizes. Across 34 configurations and over 100 evaluations, we compute the Pareto-optimal front to select methods that achieve the best accuracy with the lowest computational budget. Notably, inference scaling improves accuracy by up to +7.1% points over chain-of-thought at the highest evaluated budgets (20x the CoT compute budget) on MMLU-Pro. With an equal computing budget, debate and mixture-of-agents outperform self-consistency by 1.3% and 2.7% points, respectively. While self-consistency saturates earlier, multi-agent gains persist, particularly on more complicated tasks. We identify a simple multi-agent design guideline: mixture-of-agents is most efficient when the number of parallel generations exceeds the number of sequential aggregations.","published":"2026-05-02T18:31:02Z","updated":"2026-05-02T18:31:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.01566v1","pdf_url":"https://arxiv.org/pdf/2605.01566v1","comment":"Accepted at SRW at ACL 2026, long paper","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.01471","versioned_id":"2605.01471v1","title":"Practical Limits of Autonomous Test Repair: A Multi-Agent Case Study with LLM-Driven Discovery and Self-Correction","authors":["Hyukjoo Lee"],"abstract":"Maintaining reliable UI test suites in large-scale enterprise applications is a persistent and costly challenge. We present an industrial case study of a multi-agent autonomous testing system evaluated using anonymized execution data from a production-like enterprise UI testing prototype. The application features several hundred dynamic UI elements per screen. Built on a large language model with LangGraph orchestration, Playwright execution, and a RAG knowledge base, the system evolves from human-directed testing toward High-autonomy feature discovery and test execution: given no explicit test targets, it discovers over 100 testable features across 10 UI screens, dynamically expands coverage by an additional 15--30 features through runtime DOM analysis, and iteratively repairs failing tests without human intervention. We analyzed 300 consecutive autonomous execution reports encompassing 636 individual test-case executions across 10 distinct scenario families. The system achieved a 70% repair convergence rate at the scenario-family level, with a mean of 3.4 repair iterations to convergence. However, only 10% of scenario families succeeded on first attempt, 38% of reports failed to produce any executable test artifact, and we documented concrete instances of assertion weakening and test-case deletion used as workaround mechanisms to achieve superficial convergence. Our findings show that unrestricted autonomy leads to unstable and often misleading outcomes, while constrained autonomy transforms such systems into operationally viable workflows. Rather than advocating full autonomy, our findings suggest that reliable autonomous testing in enterprise-scale settings requires explicit constraints, validation boundaries, and human oversight to preserve semantic correctness and operational trustworthiness.","published":"2026-05-02T14:39:55Z","updated":"2026-05-02T14:39:55Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2605.01471v1","pdf_url":"https://arxiv.org/pdf/2605.01471v1","comment":"Industrial case study; submitted for review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2607.00007","versioned_id":"2607.00007v2","title":"BaRA: Budget-constrained and Reliable Web Data Collection Agent","authors":["Soojeong Lee","Joseph Lee","Yongseong Cho","Sunjae Kim","Youngwoo Moon","Kyungwoo Song"],"abstract":"Large language model (LLM)-based web agents automate web navigation and data collection. However, live web data collection demands capabilities beyond task completion: agents must discover site-internal pages and retrieve text, image, and video artifacts in an accessible form within a fixed interaction budget. We formulate this setting as budget-constrained, site-level multimodal web data collection and propose Budget-constrained and Reliable Agent (BaRA). BaRA performs breadth-first search (BFS)-based link discovery with liveness verification to filter hallucinated and dead links, then validates extracted multimodal artifacts using rule-based provenance and accessibility checks. A history-based self-reflection module recovers from execution failures and incomplete outputs. On controlled synthetic and real-world websites, BaRA consistently improves valid-link discovery and download-valid multimodal extraction over existing agents. Our code is available at https://github.com/MLAI-Yonsei/BaRA-Agent.","published":"2026-05-02T08:09:10Z","updated":"2026-07-02T06:17:26Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2607.00007v2","pdf_url":"https://arxiv.org/pdf/2607.00007v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.00817","versioned_id":"2605.00817v3","title":"When LLMs Stop Following Steps: A Diagnostic Study of Procedural Execution in Language Models","authors":["Sailesh Panda","Pritam Kadasi","Abhishek Upperwal","Mayank Singh"],"abstract":"Large language models (LLMs) often achieve strong performance on reasoning benchmarks, but final-answer accuracy alone does not show whether they faithfully execute the procedure specified in a prompt. We introduce a controlled diagnostic benchmark for procedural execution, where models are given a step-wise arithmetic procedure and two numeric inputs, and must return the final computed value. Complexity is varied through procedure length and look-back dependencies over intermediate variables. Average first-answer accuracy drops from 63% on 5-step procedures to 20% on 95-step procedures. Generation-level analysis shows that failures often involve missing answers, premature answers, self-correction after an initial error and under-executed traces. These findings suggest that apparent reasoning ability can mask substantial weaknesses in faithful long-horizon procedural execution.","published":"2026-05-01T17:55:47Z","updated":"2026-05-24T07:30:17Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.00817v3","pdf_url":"https://arxiv.org/pdf/2605.00817v3","comment":"86 pages, 124 figures, 4 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.00957","versioned_id":"2605.00957v1","title":"\"I Don't Know\" -- Towards Appropriate Trust with Certainty-Aware Retrieval Augmented Generation","authors":["Daan Di Scala","Maaike de Boer","Pınar Yolum"],"abstract":"Achieving the right amount of trust in AI systems is important, but challenging. The problem is exacerbated with the rise of Large Language Models (LLMs) as they provide human-level communication capabilities, but potentially hallucinate in the content that they generate. Moreover, they express over-confidence in their answers, making it difficult for users to judge their truthfulness. An important human value that users seek is benevolence, which can be met by LLM's self-reflection leading to reliable and honest answers. Accordingly, this paper proposes conveying appropriate levels of self-reflected certainty to build appropriate trust. Our contributions are twofold: 1) We develop CERTA (Certainty Enhanced RAG for Trustworthy Answers), a specialized Retrieval Augmented Generation (RAG) system that incorporates the relevance between question, context, and answer to reflect its uncertainty in answering questions; 2) We create the Certainty Benchmark with 90 question-context pairs of non-objective questions, divided over four categories (factuality, preference, sycophancy, morality) and three types of contexts (relevant, incomplete, irrelevant). We run experiments with a baseline RAG system and three CERTA settings using two LLMs. Our evaluations indicate that CERTA helps identify answers that are uncertain, decreases the cases of over-agreeing, and provides cautious behavior when prompted for moral judgments.","published":"2026-05-01T12:49:13Z","updated":"2026-05-01T12:49:13Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2605.00957v1","pdf_url":"https://arxiv.org/pdf/2605.00957v1","comment":"To be published in VALE 2025 Proceedings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.28181","versioned_id":"2604.28181v1","title":"Synthetic Computers at Scale for Long-Horizon Productivity Simulation","authors":["Tao Ge","Baolin Peng","Hao Cheng","Jianfeng Gao"],"abstract":"Realistic long-horizon productivity work is strongly conditioned on user-specific computer environments, where much of the work context is stored and organized through directory structures and content-rich artifacts. To scale synthetic data creation for such productivity scenarios, we introduce Synthetic Computers at Scale, a scalable methodology for creating such environments with realistic folder hierarchies and content-rich artifacts (e.g., documents, spreadsheets, and presentations). Conditioned on each synthetic computer, we run long-horizon simulations: one agent creates productivity objectives that are specific to the computer's user and require multiple professional deliverables and about a month of human work; another agent then acts as that user and keeps working across the computer -- for example, navigating the filesystem for grounding, coordinating with simulated collaborators, and producing professional artifacts -- until these objectives are completed. In preliminary experiments, we create 1,000 synthetic computers and run long-horizon simulations on them; each run requires over 8 hours of agent runtime and spans more than 2,000 turns on average. These simulations produce rich experiential learning signals, whose effectiveness is validated by significant improvements in agent performance on both in-domain and out-of-domain productivity evaluations. Given that personas are abundant at billion scale, this methodology can in principle scale to millions or even billions of synthetic user worlds with sufficient compute, enabling broader coverage of diverse professions, roles, contexts, environments, and productivity needs. We argue that scalable synthetic computer creation, together with at-scale simulations, is highly promising as a foundational substrate for agent self-improvement and agentic reinforcement learning in long-horizon productivity scenarios.","published":"2026-04-30T17:58:02Z","updated":"2026-04-30T17:58:02Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.28181v1","pdf_url":"https://arxiv.org/pdf/2604.28181v1","comment":"Preview version; work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.27960","versioned_id":"2604.27960v2","title":"LLMs as ASP Programmers: Self-Correction Enables Task-Agnostic Nonmonotonic Reasoning","authors":["Adam Ishay","Joohyung Lee"],"abstract":"Recent large language models (LLMs) have achieved impressive reasoning milestones but continue to struggle with high computational costs, logical inconsistencies, and sharp performance degradation on high-complexity problems. While neuro-symbolic methods attempt to mitigate these issues by coupling LLMs with symbolic reasoners, existing approaches typically rely on monotonic logics (e.g., SMT) that cannot represent defeasible reasoning -- essential components of human cognition. We present \"LLM+ASP,\" a framework that translates natural language into Answer Set Programming (ASP), a nonmonotonic formalism based on stable model semantics. Unlike prior \"LLM+ASP\" approaches that require manually authored knowledge modules, domain-specific prompts, or evaluation restricted to single problem classes, our framework operates without any per-task engineering and applies uniformly across diverse reasoning tasks. Our system utilizes an automated self-correction loop where structured feedback from the ASP solver enables iterative refinement. Evaluating across six diverse benchmarks, we demonstrate that: (1) stable model semantics allow LLMs to naturally express default rules and exceptions, outperforming SMT-based alternatives by significant margins on nonmonotonic tasks; (2) iterative self-correction is the primary driver of performance, effectively replacing the need for handcrafted domain knowledge; (3) compact in-context reference guides substantially outperform verbose documentation, revealing a \"context rot\" phenomenon where excessive context hinders constraint adherence.","published":"2026-04-30T14:55:48Z","updated":"2026-06-11T07:29:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.27960v2","pdf_url":"https://arxiv.org/pdf/2604.27960v2","comment":"30 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.27934","versioned_id":"2604.27934v1","title":"MM-StanceDet: Retrieval-Augmented Multi-modal Multi-agent Stance Detection","authors":["Weihai Lu","Zhejun Zhao","Yanshu Li","Huan He"],"abstract":"Multimodal Stance Detection (MSD) is crucial for understanding public discourse, yet effectively fusing text and image, especially with conflicting signals, remains challenging. Existing methods often face difficulties with contextual grounding, cross-modal interpretation ambiguity, and single-pass reasoning fragility. To address these, we propose Retrieval-Augmented Multi-modal Multi-agent Stance Detection (MM-StanceDet), a novel multi-agent framework integrating Retrieval Augmentation for contextual grounding, specialized Multimodal Analysis agents for nuanced interpretation, a Reasoning-Enhanced Debate stage for exploring perspectives, and Self-Reflection for robust adjudication. Extensive experiments on five datasets demonstrate MM-StanceDet significantly outperforms state-of-the-art baselines, validating the efficacy of its multi-agent architecture and structured reasoning stages in addressing complex multimodal stance challenges.","published":"2026-04-30T14:34:18Z","updated":"2026-04-30T14:34:18Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.27934v1","pdf_url":"https://arxiv.org/pdf/2604.27934v1","comment":"Accepted on ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.27859","versioned_id":"2604.27859v3","title":"Rethinking Agentic Reinforcement Learning In Large Language Models","authors":["Fangming Cui","Ruixiao Zhu","Cheng Fang","Sunan Li","Jiahong Li"],"abstract":"Reinforcement Learning (RL) has traditionally focused on training specialized agents to optimize predefined reward functions within narrowly defined environments. However, the advent of powerful Large Language Models (LLMs) and increasingly complex, open-ended tasks has catalyzed a paradigm shift towards agentic paradigms within RL. This emerging framework extends beyond traditional RL by emphasizing the development of autonomous agents capable of goal-setting, long-term planning, dynamic strategy adaptation, and interactive reasoning in uncertain, real-world environments. Unlike conventional approaches that rely heavily on static objectives and episodic interactions, LLM-based Agentic RL incorporates cognitive-like capabilities such as meta-reasoning, self-reflection, and multi-step decision-making directly into the learning loop. In this paper, we provide a deep insight for looking the conceptual foundations, methodological innovations, and effective designs underlying this trend. Furthermore, we identify critical challenges and outline promising future directions for building LLM-based Agentic RL.","published":"2026-04-30T13:43:25Z","updated":"2026-05-15T06:25:17Z","categories":["cs.AI","cs.ET"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.27859v3","pdf_url":"https://arxiv.org/pdf/2604.27859v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.27644","versioned_id":"2604.27644v2","title":"ANCORA: Learning to Question via Manifold-Anchored Self-Play for Verifiable Reasoning","authors":["Chengcao Yang"],"abstract":"We propose a paradigm shift toward open-ended curriculum self-play: rather than learning to answer on a fixed prompt set, a unified policy learns to question: generating verifiable problems, solving them, and turning verifier feedback into self-improvement without human-annotated solutions. We introduce ANCORA, in which the policy alternates between a Proposer that synthesizes novel specifications and a Solver that produces verified solutions, anchored by three load-bearing mechanisms: a two-level group-relative update coupling Proposer advantages across specifications with Solver advantages across solution attempts; iterative self-distilled SFT projecting the base model onto its valid-output manifold before RL; and a UCB-guided Curriculum DAG whose policy-induced problem set can provably expand under self-composition. Without these stabilizers, sparse verifier feedback drives Proposer collapse even under MLRL-aligned rewards; with them, ANCORA bootstraps a verifiable curriculum from zero human solutions. Instantiated in Verus, ANCORA lifts Dafny2Verus pass@1 from a 26.6% SFT baseline to 81.5% in test-time training (TTT, 0-shot), outperforming PSV self-play by 15.8 points despite PSV's 1-shot inference; in a transfer setting, training from Dafny2Verus seeds yields 36.2% and 17.2% pass@1 on held-out MBPP and HumanEval.","published":"2026-04-30T09:35:57Z","updated":"2026-05-07T08:46:02Z","categories":["cs.LG","cs.AI","cs.PL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.27644v2","pdf_url":"https://arxiv.org/pdf/2604.27644v2","comment":"v2: Updated abstract; strengthened the proof of Proposition 4.1; corrected minor typos; corrected author list","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.27201","versioned_id":"2604.27201v2","title":"Path-Lock Expert: Separating Reasoning Mode in Hybrid Thinking via Architecture-Level Separation","authors":["Shouren Wang","Wang Yang","Chuang Ma","Debargha Ganguly","Vikash Singh","Chaoda Song","Xinpeng Li","Xianxuan Long","Vipin Chaudhary","Xiaotian Han"],"abstract":"Hybrid-thinking language models expose explicit think and no-think modes, but current designs do not separate them cleanly. Even in no-think mode, models often emit long and self-reflective responses, causing reasoning leakage. Existing work reduces this issue through better data curation and multi-stage training, yet leakage remains because both modes are still encoded in the same feed-forward parameters. We propose Path-Lock Expert (PLE), an architecture-level solution that replaces the single MLP in each decoder layer with two semantically locked experts, one for think and one for no-think, while keeping attention, embeddings, normalization, and the language-model head shared. A deterministic control-token router selects exactly one expert path for the entire sequence, so inference preserves the dense model's per-token computation pattern and each expert receives mode-pure updates during supervised fine-tuning. Across math and science reasoning benchmarks, PLE maintains strong think performance while producing a substantially stronger no-think mode that is more accurate, more concise, and far less prone to reasoning leakage. On Qwen3-4B, for example, PLE reduces no-think reflective tokens on AIME24 from 2.54 to 0.39 and improves no-think accuracy from 20.67% to 40.00%, all while preserving think-mode performance. These results suggest that controllable hybrid thinking is fundamentally an architectural problem, and separating mode-specific feed-forward pathways is a simple and effective solution.","published":"2026-04-29T21:07:47Z","updated":"2026-05-05T22:44:50Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.27201v2","pdf_url":"https://arxiv.org/pdf/2604.27201v2","comment":"27 pages, 9 figures, 6 tables. Under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.27166","versioned_id":"2604.27166v1","title":"Distributional Alignment Games for Answer-Level Fine-Tuning","authors":["Mehryar Mohri","Jon Schneider","Yifan Wu"],"abstract":"We focus on the problem of \\emph{Answer-Level Fine-Tuning} (ALFT), where the goal is to optimize a language model based on the correctness or properties of its final answers, rather than the specific reasoning traces used to produce them. Directly optimizing answer-level objectives is computationally intractable due to the need to marginalize over the vast space of latent reasoning paths. To overcome this, we propose a general game-theoretical framework that lifts the problem to a \\emph{Distributional Alignment Game}. We formulate ALFT as a two-player game between a Policy (the generator) and a Target (an auxiliary distribution). We prove that the Nash Equilibrium of this game corresponds exactly to the solution of the original answer-level optimization problem. This variational perspective transforms the intractable marginalization problem into a tractable projection problem. We demonstrate that this framework unifies recent approaches to diversity and self-improvement (coherence) and provide efficient algorithms compatible with Group Relative Policy Optimization (GRPO), such as Coherence-GRPO, yielding significant complexity gains in mathematical reasoning tasks.","published":"2026-04-29T20:15:37Z","updated":"2026-04-29T20:15:37Z","categories":["cs.LG","cs.GT"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.27166v1","pdf_url":"https://arxiv.org/pdf/2604.27166v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.00914","versioned_id":"2605.00914v1","title":"The Cost of Consensus: Isolated Self-Correction Prevails Over Unguided Homogeneous Multi-Agent Debate","authors":["Blaž Bertalanič","Carolina Fortuna"],"abstract":"Multi-agent debate, where teams of LLMs iteratively exchange rationales and vote on answers, is widely deployed under the assumption that peer review filters hallucinations. Yet the failure dynamics of homogeneous debate remain poorly understood, therefore we report findings from a controlled empirical study of teams of $N{=}10$ homogeneous agents (Qwen2.5-7B, Llama-3.1-8B, Ministral-3-8B) across $R{=}3$ debate rounds on two high-difficulty benchmarks (GSM-Hard and MMLU-Hard). We compare peer debate against isolated self-correction and a stochastic noise control that injects rationales from unrelated problems. We decompose debate failure into three model-dependent pathways: sycophantic conformity, where agents uncritically adopt majority answers (modal adoption up to 85.5%); contextual fragility, where peer rationales destabilize previously correct reasoning (vulnerability rate up to 70.0%); and consensus collapse, where plurality voting discards correct answers already present in the generation pool (oracle gap up to 32.3 percentage points). Ablations over communication density ($K \\in \\{2,4,9\\}$) and sampling temperature ($T \\in \\{0.4, 0.7\\}$) show that conformity reaches high levels at minimal peer exposure ($K{=}2$) and intensifies with greater initial diversity. Across all configurations, debate consumes 2.1-3.4$\\times$ more tokens (up to 28,631 tokens per problem) than self-correction for equal or lower accuracy. Our results indicate that, within the 7-8B parameter class, homogeneous teams without structured roles do not benefit from unguided peer exchange, and that isolated self-correction consistently offers a more favorable cost-accuracy tradeoff.","published":"2026-04-29T14:33:57Z","updated":"2026-04-29T14:33:57Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.00914v1","pdf_url":"https://arxiv.org/pdf/2605.00914v1","comment":"19 pages, ACM Conference on AI and Agentic Systems","journal_ref":"","doi":"10.1145/3786335.3813137","discovered_on":"2026-07-17"},{"id":"2604.26645","versioned_id":"2604.26645v2","title":"SciHorizon-DataEVA: An Agentic System for AI-Readiness Evaluation of Heterogeneous Scientific Data","authors":["Dianyu Liu","Chuan Qin","Xi Chen","Xiaohan Li","Wenxi Xu","Yuyang Wang","Xin Chen","Yuanchun Zhou","Hengshu Zhu"],"abstract":"AI-for-Science (AI4Science) is increasingly transforming scientific discovery by embedding machine learning models into prediction, simulation, and hypothesis generation workflows across domains. However, the effectiveness of these models is fundamentally constrained by the AI-readiness of scientific data, for which no scalable and systematic evaluation mechanism currently exists. In this work, we propose SciHorizon-DataEVA, a novel agentic system to scalable AI-readiness evaluation of heterogeneous scientific data. At the evaluation-criteria level, we introduce the Sci-TQA2 principles, which organize AI-readiness into four complementary dimensions: Governance Trustworthiness, Data Quality, AI Compatibility, and Scientific Adaptability. Each dimension is decomposed into measurable atomic elements that enable fine-grained and executable assessment. To operationalize these principles at scale, we develop Sci-TQA2-Eval, a hierarchical multi-agent evaluation approach orchestrated through a directed, cyclic workflow. Our Sci-TQA2-Eval dynamically constructs dataset-aware evaluation specifications by combining lightweight dataset profiling, applicability-aware metric activation, and knowledge-augmented planning grounded in domain constraints and dataset-paper signals. These specifications are executed through an adaptive, tool-centric evaluation mechanism with built-in verification and self-correction, enabling scalable and reliable assessment across heterogeneous scientific data. Extensive experiments on scientific datasets spanning multiple domains demonstrate the effectiveness and generality of SciHorizon-DataEVA for principled AI-readiness evaluation.","published":"2026-04-29T13:11:53Z","updated":"2026-05-28T14:48:42Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.26645v2","pdf_url":"https://arxiv.org/pdf/2604.26645v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.26644","versioned_id":"2604.26644v1","title":"When to Vote, When to Rewrite: Disagreement-Guided Strategy Routing for Test-Time Scaling","authors":["Zhimin Lin","Yixin Ji","Jinpeng Li","Yu Luo","Dong Li","Junhua Fang","Juntao Li","Min Zhang"],"abstract":"Large Reasoning Models (LRMs) achieve strong performance on mathematical reasoning tasks but remain unreliable on challenging instances. Existing test-time scaling methods, such as repeated sampling, self-correction, and tree search, improve performance at the cost of increased computation, yet often exhibit diminishing returns on hard problems. We observe that output disagreement is strongly correlated with instance difficulty and prediction correctness, providing a useful signal for guiding instance-level strategy selection at test time. Based on this insight, we propose a training-free framework that formulates test-time scaling as an instance-level routing problem, rather than allocating more computation within a single strategy, dynamically selecting among different scaling strategies based on output disagreement. The framework applies lightweight resolution for consistent cases, majority voting for moderate disagreement, and rewriting-based reformulation for highly ambiguous instances. Experiments on seven mathematical benchmarks and three models show that our method improves accuracy by 3% - 7% while reducing sampling cost compared to existing approaches.","published":"2026-04-29T13:11:39Z","updated":"2026-04-29T13:11:39Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.26644v1","pdf_url":"https://arxiv.org/pdf/2604.26644v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.26500","versioned_id":"2604.26500v2","title":"StarDrinks: An English and Korean Test Set for SLU Evaluation in a Drink Ordering Scenario","authors":["Marcely Zanon Boito","Caroline Brun","Inyoung Kim","Denys Proux","Salah Ait-Mokhtar","Nikolaos Lagos","Jean-Luc Meunier","Ioan Calapodescu"],"abstract":"LLMs and speech assistants are increasingly used for task-oriented interactions, yet their evaluation often relies on controlled scenarios that fail to capture the variability and complexity of real user requests. Drink ordering, for example, involves diverse named entities, drink types, sizes, customizations, and brand-specific terminology, as well as spontaneous speech phenomena such as hesitations and self-corrections. To address this gap, we introduce StarDrinks, a test set in English and Korean containing speech utterances features, transcriptions, and annotated slots. Our dataset supports speech-to-slots SLU, transcription-to-slots NLU, and speech-to-transcription ASR evaluation, providing a realistic benchmark for model robustness and generalization in a linguistically rich, real-world task.","published":"2026-04-29T10:03:12Z","updated":"2026-07-03T09:45:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.26500v2","pdf_url":"https://arxiv.org/pdf/2604.26500v2","comment":"Accepted at LREC 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.26211","versioned_id":"2604.26211v1","title":"OMEGA: Optimizing Machine Learning by Evaluating Generated Algorithms","authors":["Jeremy Nixon","Annika Singh"],"abstract":"In order to automate AI research we introduce a full, end-to-end framework, OMEGA: Optimizing Machine learning by Evaluating Generated Algorithms, that starts at idea generation and ends with executable code. Our system combines structured meta-prompt engineering with executable code generation to create new ML classifiers. The OMEGA framework has been utilized to generate several novel algorithms that outperform scikit-learn baselines across a robust selection of 20 benchmark datasets (infinity-bench). You can access models discussed in this paper and more in the python package: pip install omega-models.","published":"2026-04-29T01:30:08Z","updated":"2026-04-29T01:30:08Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.26211v1","pdf_url":"https://arxiv.org/pdf/2604.26211v1","comment":"ICLR 2026: Workshop on AI with Recursive Self-Improvement","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.25665","versioned_id":"2604.25665v2","title":"LLM-ReSum: A Framework for LLM Reflective Summarization through Self-Evaluation","authors":["Huyen Nguyen","Haoxuan Zhang","Yang Zhang","Haihua Chen","Junhua Ding"],"abstract":"Reliable evaluation of large language model (LLM)-generated summaries remains an open challenge, particularly across heterogeneous domains and document lengths. We conduct a comprehensive meta-evaluation of 14 automatic summarization metrics and LLM-based evaluators across seven datasets spanning five domains, covering documents from short news articles to long scientific, governmental, and legal texts (2K-27K words) with over 1,500 human-annotated summaries. Our results show that traditional lexical overlap metrics (e.g., ROUGE, BLEU) exhibit weak or negative correlation with human judgments, while task-specific neural metrics and LLM-based evaluators achieve substantially higher alignment, especially for linguistic quality assessment. Leveraging these findings, we propose LLM-ReSum, a self-reflective summarization framework that integrates LLM-based evaluation and generation in a closed feedback loop without model finetuning. Across three domains, LLM-ReSum improves low-quality summaries by up to 33% in factual accuracy and 39% in coverage, with human evaluators preferring refined summaries in 89% of cases. We additionally introduce PatentSumEval, a new human-annotated benchmark for legal document summarization comprising 180 expert-evaluated summaries. All code and datasets will be released in GitHub.","published":"2026-04-28T14:00:09Z","updated":"2026-06-21T13:39:15Z","categories":["cs.CL","cs.AI","cs.DL","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.25665v2","pdf_url":"https://arxiv.org/pdf/2604.25665v2","comment":"This paper has been accepted as an invited paper for publication in Proceedings of The 12th IEEE International Conference on Big Data Computing Service and Machine Learning Applications. This is the accepted manuscript. The final authenticated version will be available via IEEE Xplore","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.25130","versioned_id":"2604.25130v2","title":"LongSumEval: Question-Answering Based Evaluation and Feedback-Driven Refinement for Long Document Summarization","authors":["Huyen Nguyen","Haoxuan Zhang","Yang Zhang","Junhua Ding","Haihua Chen"],"abstract":"Evaluating long document summaries remains the primary bottleneck in summarization research. Existing metrics correlate weakly with human judgments and produce aggregate scores without explaining deficiencies or guiding improvement, preventing effective refinement in applications requiring verifiable accuracy. We introduce LongSumEval, a unified framework bridging evaluation and generation through structured question-answering feedback. The framework operationalizes summary quality as answerability and factual alignment of question-answer pairs, generating interpretable scores and actionable feedback that identifies coverage gaps and factual inconsistencies. This resolves the misalignment where evaluation operates independently of generation objectives. Meta-evaluation of our QA-based evaluation module across seven benchmarks demonstrates substantially stronger agreement with human judgments compared to established metrics. Structured feedback enables significant quality improvements through self-refinement without retraining. By demonstrating that evaluation feedback can serve as executable instructions for generation, this work establishes a generalizable paradigm for aligning assessment with improvement, with direct implications for controllable text generation requiring verifiable accuracy and transparent quality control. All code and datasets will be released in GitHub for reproducibility.","published":"2026-04-28T02:07:56Z","updated":"2026-06-21T13:33:58Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.25130v2","pdf_url":"https://arxiv.org/pdf/2604.25130v2","comment":"This paper has been accepted as an invited paper for publication in Proceedings of The 8th IEEE International Conference on Artificial Intelligence Testing. This is the accepted manuscript. The final authenticated version will be available via IEEE Xplore","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.25067","versioned_id":"2604.25067v2","title":"Frontier Coding Agents Can Now Implement an AlphaZero Self-Play Machine Learning Pipeline For Connect Four That Performs Comparably to an External Solver","authors":["Joshua Sherwood","Ben Aybar","Benjamin Kaplan"],"abstract":"Forecasting when AI systems will become capable of meaningfully accelerating AI research is a central challenge for AI safety. Existing benchmarks measure broad capability growth, but may not provide ample early warning signals for recursive self-improvement. We propose measuring AI's capability to autonomously implement end-to-end machine learning pipelines from past AI research breakthroughs, given a minimal task description. By providing a concise task description instead of the full prior work as reference, we hope to better elicit emerging AI research taste. We introduce a proof-of-concept benchmark in which frontier coding agents autonomously implement an AlphaZero-style machine learning pipeline for Connect Four on consumer hardware within a three-hour budget, and we evaluate the resulting game AIs in a round-robin tournament anchored to the Pascal Pons Connect Four solver. Across four agents with eight trials each, we find substantial differentiation: Claude Opus 4.7 won as first-mover against Pons in seven of eight trials, statistically significantly better than the other agents tested, none of which exceeded two of eight. The task, which no frontier agent could reliably complete when we began development in January of 2026, is now near-saturation. Our evaluation also surfaced anomalous behavior in GPT-5.4, which consistently used far less of its allocated time budget than other agents. A follow-up 16-trial probe using shorter, less evaluation-coded prompts substantially increased GPT-5.4's time-budget usage, consistent with but not diagnostic of sandbagging; Bradley-Terry ratings across probe conditions showed only directional differences, despite significant differences in time-budget usage. We release our data, code, and prompts to support reproduction and extension.","published":"2026-04-27T23:48:30Z","updated":"2026-04-29T00:38:29Z","categories":["cs.MA","cs.AI","cs.LG"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2604.25067v2","pdf_url":"https://arxiv.org/pdf/2604.25067v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.24842","versioned_id":"2604.24842v1","title":"Co-Director: Agentic Generative Video Storytelling","authors":["Yale Song","Yiwen Song","Nick Losier","Nathan Hodson","Ye Jin","Rhyard Zhu","Yan Xu","Daniel Vlasic","Carina Claassen","Jasmine Leon","Khanh G. LeViet","Zack Chomyn","Joe Timmons","Brett Slatkin","Scott Penberthy","Tomas Pfister"],"abstract":"While diffusion models generate high-fidelity video clips, transforming them into coherent storytelling engines remains challenging. Current agentic pipelines automate this via chained modules but suffer from semantic drift and cascading failures due to independent, handcrafted prompting. We present Co-Director, a hierarchical multi-agent framework formalizing video storytelling as a global optimization problem. To ensure semantic coherence, we introduce hierarchical parameterization: a multi-armed bandit globally identifies promising creative directions, while a local multimodal self-refinement loop mitigates identity drift and ensures sequence-level consistency. This balances the exploration of novel narrative strategies with the exploitation of effective creative configurations. For evaluation, we introduce GenAD-Bench, a 400-scenario dataset of fictional products for personalized advertising. Experiments demonstrate that Co-Director significantly outperforms state-of-the-art baselines, offering a principled approach that seamlessly generalizes to broader cinematic narratives. Project Page: https://co-director-agent.github.io/","published":"2026-04-27T18:00:00Z","updated":"2026-04-27T18:00:00Z","categories":["cs.AI","cs.MA","cs.MM"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.24842v1","pdf_url":"https://arxiv.org/pdf/2604.24842v1","comment":"Project Page: https://co-director-agent.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.24819","versioned_id":"2604.24819v1","title":"Programming with Data: Test-Driven Data Engineering for Self-Improving LLMs from Raw Corpora","authors":["Chenkai Pan","Xinglong Xu","Yuhang Xu","Yujun Wu","Siyuan Li","Jintao Chen","Conghui He","Jingxuan Wei","Cheng Tan"],"abstract":"Reliably transferring specialized human knowledge from text into large language models remains a fundamental challenge in artificial intelligence. Fine-tuning on domain corpora has enabled substantial capability gains, but the process operates without feedback: when a model fails on a domain task, there is no method to diagnose what is deficient in the training data, and the only recourse is to add more data indiscriminately. Here we show that when a structured knowledge representation extracted from the source corpus serves as the shared foundation for both training data and evaluation, the complete data-engineering lifecycle maps onto the software development lifecycle in a precise and operative way: training data becomes source code specifying what the model should learn, model training becomes compilation, benchmarking becomes unit testing, and failure-driven data repair becomes debugging. Under this correspondence, model failures decompose into concept-level gaps and reasoning-chain breaks that can be traced back to specific deficiencies in the data and repaired through targeted patches, with each repair cycle producing consistent improvements across model scales and architectures without degrading general capabilities. We formalize this principle as Programming with Data and instantiate it across sixteen disciplines spanning the natural sciences, engineering, biomedicine, and the social sciences, releasing a structured knowledge base, benchmark suite, and training corpus as open resources. By demonstrating that the relationship between training data and model behaviour is structurally traceable and systematically repairable, this work establishes a principled foundation for the reliable engineering of human expertise into language models.","published":"2026-04-27T14:05:18Z","updated":"2026-04-27T14:05:18Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2604.24819v1","pdf_url":"https://arxiv.org/pdf/2604.24819v1","comment":"57 pages, 28 figures, 14 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.24395","versioned_id":"2604.24395v1","title":"Aligning with Your Own Voice: Self-Corrected Preference Learning for Hallucination Mitigation in LVLMs","authors":["Byeonggeuk Lim","JungMin Yun","Junehyoung Kwon","Kyeonghyun Kim","YoungBin Kim"],"abstract":"Large Vision-Language Models (LVLMs) frequently suffer from hallucinations. Existing preference learning-based approaches largely rely on proprietary models to construct preference datasets. We identify that this reliance introduces a distributional mismatch between the proprietary and target models that hinders efficient alignment. To address this, we propose Alignment via VErified Self-correction DPO (AVES-DPO), a framework that aligns LVLMs using in-distribution data derived from the model's intrinsic knowledge. Our approach employs a consensus-based verification mechanism to diagnose diverse hallucinations and guides the model to self-correct, thereby generating preference pairs strictly compatible with its internal distribution. Extensive experiments demonstrate that AVES-DPO surpasses existing baselines in hallucination mitigation while requiring only 5.2k samples.","published":"2026-04-27T12:22:35Z","updated":"2026-04-27T12:22:35Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.24395v1","pdf_url":"https://arxiv.org/pdf/2604.24395v1","comment":"Accepted to ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.23970","versioned_id":"2604.23970v1","title":"LLM-Guided Agentic Floor Plan Parsing for Accessible Indoor Navigation of Blind and Low-Vision People","authors":["Aydin Ayanzadeh","Tim Oates"],"abstract":"Indoor navigation remains a critical accessibility challenge for the blind and low-vision (BLV) individuals, as existing solutions rely on costly per-building infrastructure. We present an agentic framework that converts a single floor plan image into a structured, retrievable knowledge base to generate safe, accessible navigation instructions with lightweight infrastructure. The system has two phases: a multi-agent module that parses the floor plan into a spatial knowledge graph through a self-correcting pipeline with iterative retry loops and corrective feedback; and a Path Planner that generates accessible navigation instructions, with a Safety Evaluator agent assessing potential hazards along each route. We evaluate the system on the real-world UMBC Math and Psychology building (floors MP-1 and MP-3) and on the CVC-FP benchmark. On MP-1, we achieve success rates of 92.31%, 76.92%, and 61.54% for short, medium, and long routes, outperforming the strongest single-call baseline (Claude 3.7 Sonnet) at 84.62%, 69.23%, and 53.85%. On MP-3, we reach 76.92%, 61.54%, and 38.46%, compared to the best baseline at 61.54%, 46.15%, and 23.08%. These results show consistent gains over single-call LLM baselines and demonstrate that our workflow is a scalable solution for accessible indoor navigation for BLV individuals.","published":"2026-04-27T02:32:44Z","updated":"2026-04-27T02:32:44Z","categories":["cs.AI","cs.CV","cs.HC","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.23970v1","pdf_url":"https://arxiv.org/pdf/2604.23970v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.23809","versioned_id":"2604.23809v1","title":"LegalDrill: Diagnosis-Driven Synthesis for Legal Reasoning in Small Language Models","authors":["Tianchun Li","Haochen Liu","Vishwa Pardeshi","Xingchen Wang","Tianci Liu","Huijun Zhao","Wei Fan","Jing Gao"],"abstract":"Small language models (SLMs) are promising for real-world deployment due to their efficiency and low operational cost. However, their limited capacity struggles with high-stakes legal reasoning tasks that require coherent statute interpretation and logically consistent deduction. Furthermore, training SLMs for such tasks demands high-quality, concise reasoning trajectories, which are prohibitively expensive to manually collect and difficult to curate via standard rejection sampling, lacking granularity beyond final verdicts. To address these challenges, we propose {LegalDrill}, a diagnosis-driven synthesis framework that extracts and iteratively refines reasoning trajectories from a capable teacher via fine-grained prompting, then a self-reflective verification is employed to adaptively select the most effective data for the SLM student. The resulting data empower SLM training through supervised fine-tuning and direct preference optimization. Extensive experiments on several legal benchmarks demonstrate that {LegalDrill} significantly bolsters the legal reasoning capabilities of representative SLMs while bypassing the need for scarce expert annotations, paving a scalable path toward practical legal reasoning systems.","published":"2026-04-26T17:13:17Z","updated":"2026-04-26T17:13:17Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.23809v1","pdf_url":"https://arxiv.org/pdf/2604.23809v1","comment":"ACL 2026 Industry Track","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.23580","versioned_id":"2604.23580v1","title":"PhysCodeBench: Benchmarking Physics-Aware Symbolic Simulation of 3D Scenes via Self-Corrective Multi-Agent Refinement","authors":["Tianyidan Xie","Peiyu Wang","Yuyi Qian","Yuxuan Wang","Rui Ma","Ying Tai","Song Wu","Qian Wang","Lanjun Wang","Zili Yi"],"abstract":"Physics-aware symbolic simulation of 3D scenes is critical for robotics, embodied AI, and scientific computing, requiring models to understand natural language descriptions of physical phenomena and translate them into executable simulation environments. While large language models (LLMs) excel at general code generation, they struggle with the semantic gap between physical descriptions and simulation implementation. We introduce PhysCodeBench, the first comprehensive benchmark for evaluating physics-aware symbolic simulation, comprising 700 manually-crafted diverse samples across mechanics, fluid dynamics, and soft-body physics with expert annotations. Our evaluation framework measures both code executability and physical accuracy through automated and visual assessment. Building on this, we propose a Self-Corrective Multi-Agent Refinement Framework (SMRF) with three specialized agents (simulation generator, error corrector, and simulation refiner) that collaborate iteratively with domain-specific validation to produce physically accurate simulations. SMRF achieves 67.7 points overall performance compared to 36.3 points for the best baseline among evaluated SOTA models, representing a 31.4-point improvement. Our analysis demonstrates that error correction is critical for accurate physics-aware symbolic simulation and that specialized multi-agent approaches significantly outperform single-agent methods across the tested physical domains.","published":"2026-04-26T07:37:20Z","updated":"2026-04-26T07:37:20Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2604.23580v1","pdf_url":"https://arxiv.org/pdf/2604.23580v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.23366","versioned_id":"2604.23366v1","title":"GSAR: Typed Grounding for Hallucination Detection and Recovery in Multi-Agent LLMs","authors":["Federico A. Kamelhar"],"abstract":"Autonomous multi-agent LLM systems are increasingly deployed to investigate operational incidents and produce structured diagnostic reports. Their trustworthiness hinges on whether each claim is grounded in observed evidence rather than model-internal inference. Existing groundedness evaluators (binary classifiers, LLM-as-judge scalars, self-correction loops) treat supporting evidence as interchangeable and emit a single signal that offers no principled control over downstream action. We present GSAR, a grounding-evaluation and replanning framework that (i) partitions claims into a four-way typology (grounded, ungrounded, contradicted, complementary), giving first-class standing to non-redundant alternative perspectives; (ii) assigns evidence-type-specific weights reflecting epistemic strength; (iii) computes an asymmetric contradiction-penalised weighted groundedness score; and (iv) couples that score to a three-tier decision function (proceed, regenerate, replan) driving a bounded-iteration outer loop under an explicit compute budget. We formalise the algorithm, prove six structural properties, and evaluate five design claims on FEVER with gold Wikipedia evidence under four independently-trained LLM judges (gpt-5.4, claude-sonnet-4-6, claude-opus-4-7, gemini-2.5-pro). Every ablation reproduces in the same direction on every judge: bootstrap 95% CIs on the rho=0 effect exclude 0 on all four; the no-complementary ablation under Opus 4.7 has CI [-96,-68] of 200; at n=1000 three independent judges converge to DeltaS(rho=0)=+0.058. A head-to-head against Vectara HHEM-2.1-Open is included. To our knowledge, GSAR is the first published groundedness framework coupling evidence-typed scoring with tiered recovery under an explicit compute budget.","published":"2026-04-25T16:20:28Z","updated":"2026-04-25T16:20:28Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.23366v1","pdf_url":"https://arxiv.org/pdf/2604.23366v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.23002","versioned_id":"2604.23002v1","title":"FormalScience: Scalable Human-in-the-Loop Autoformalisation of Science with Agentic Code Generation in Lean","authors":["Jordan Meadows","Lan Zhang","Andre Freitas"],"abstract":"Formalising informal mathematical reasoning into formally verifiable code is a significant challenge for large language models. In scientific fields such as physics, domain-specific machinery (\\textit{e.g.} Dirac notation, vector calculus) imposes additional formalisation challenges that modern LLMs and agentic approaches have yet to tackle. To aid autoformalisation in scientific domains, we present FormalScience; a domain-agnostic human-in-the-loop agentic pipeline that enables a single domain expert (without deep formal language experience) to produce \\textit{syntactically correct} and \\textit{semantically aligned} formal proofs of informal reasoning for low economic cost. Applying FormalScience to physics, we construct FormalPhysics, a dataset of 200 university-level (LaTeX) physics problems and solutions (primarily quantum mechanics and electromagnetism), along with their Lean4 formal representations. Compared to existing formal math benchmarks, FormalPhysics achieves perfect formal validity and exhibits greater statement complexity. We evaluate open-source models and proprietary systems on a statement autoformalisation task on our dataset via zero-shot prompting, self-refinement with error feedback, and a novel multi-stage agentic approach, and explore autoformalisation limitations in modern LLM-based approaches. We provide the first systematic characterisation of semantic drift in physics autoformalisation in terms of concepts such as notational collapse and abstraction elevation which reveals what formal language verifies when full semantic preservation is unattainable. We release the codebase together with an interactive UI-based FormalScience system which facilitates autoformalisation and theorem proving in scientific domains beyond physics.https://github.com/jmeadows17/formal-science","published":"2026-04-24T20:47:22Z","updated":"2026-04-24T20:47:22Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.23002v1","pdf_url":"https://arxiv.org/pdf/2604.23002v1","comment":"ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.22446","versioned_id":"2604.22446v1","title":"From Skills to Talent: Organising Heterogeneous Agents as a Real-World Company","authors":["Zhengxu Yu","Yu Fu","Zhiyuan He","Yuxuan Huang","Lee Ka Yiu","Meng Fang","Weilin Luo","Jun Wang"],"abstract":"Individual agent capabilities have advanced rapidly through modular skills and tool integrations, yet multi-agent systems remain constrained by fixed team structures, tightly coupled coordination logic, and session-bound learning. We argue that this reflects a deeper absence: a principled organisational layer that governs how a workforce of agents is assembled, governed, and improved over time, decoupled from what individual agents know. To fill this gap, we introduce \\emph{OneManCompany (OMC)}, a framework that elevates multi-agent systems to the organisational level. OMC encapsulates skills, tools, and runtime configurations into portable agent identities called \\emph{Talents}, orchestrated through typed organisational interfaces that abstract over heterogeneous backends. A community-driven \\emph{Talent Market} enables on-demand recruitment, allowing the organisation to close capability gaps and reconfigure itself dynamically during execution. Organisational decision-making is operationalised through an \\emph{Explore-Execute-Review} ($\\text{E}^2$R) tree search, which unifies planning, execution, and evaluation in a single hierarchical loop: tasks are decomposed top-down into accountable units and execution outcomes are aggregated bottom-up to drive systematic review and refinement. This loop provides formal guarantees on termination and deadlock freedom while mirroring the feedback mechanisms of human enterprises. Together, these contributions transform multi-agent systems from static, pre-configured pipelines into self-organising and self-improving AI organisations capable of adapting to open-ended tasks across diverse domains. Empirical evaluation on PRDBench shows that OMC achieves an $84.67\\%$ success rate, surpassing the state of the art by $15.48$ percentage points, with cross-domain case studies further demonstrating its generality.","published":"2026-04-24T11:02:44Z","updated":"2026-04-24T11:02:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.22446v1","pdf_url":"https://arxiv.org/pdf/2604.22446v1","comment":"33 pages,13 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.22273","versioned_id":"2604.22273v2","title":"Self-Correction as Feedback Control: Error Dynamics, Stability Thresholds, and Prompt Interventions in LLMs","authors":["Aofan Liu","Jingxiang Meng"],"abstract":"Iterative self-correction is increasingly deployed in agentic LLM systems, yet whether repeated refinement improves or degrades performance remains inconsistent across models. We recast self-correction as a closed-loop feedback-control problem in which the same model is both controller and plant, and analyze its error dynamics via a two-state Markov model over {Correct, Incorrect}, parameterized by the Error Introduction Rate (EIR) and Error Correction Rate (ECR). The model yields a directly measurable stability threshold -- iterate only when ECR/EIR > Acc/(1-Acc) -- in which EIR acts as a stability margin and prompting becomes lightweight controller design. Empirically, across 7 models and 3 datasets (GSM8K, MATH, StrategyQA), a sharp near-zero EIR boundary (< 0.5%) cleanly separates beneficial from harmful self-correction: only o3-mini (+3.4 pp), Claude Opus 4.6 (+0.6 pp), and o4-mini (+/-0 pp) stay non-degrading, while GPT-5 and four others lose accuracy. A verify-first prompt intervention then provides causal evidence: it drives GPT-4o-mini's EIR from 2% to 0% and converts a -6.2 pp degradation into +0.2 pp (paired McNemar, p<10^{-4}), with negligible change on already-sub-threshold models -- exactly as the diagnostic predicts. A complementary analysis of adaptive self-consistency (ASC) shows it halts harmful refinement at a 3.8 pp confidence-elicitation cost, exposing a two-tier capability structure: prompt-level EIR suppression prevents degradation, whereas ECR enhancement -- plausibly training-level -- is required for genuine gains. Self-correction should thus be treated not as a default behavior but as a control decision governed by measurable error dynamics.","published":"2026-04-24T06:34:40Z","updated":"2026-05-04T04:09:58Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.22273v2","pdf_url":"https://arxiv.org/pdf/2604.22273v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.22271","versioned_id":"2604.22271v2","title":"How LLMs Detect and Correct Their Own Errors: The Role of Internal Confidence Signals","authors":["Dharshan Kumaran","Viorica Patraucean","Simon Osindero","Petar Veličković","Nathaniel Daw"],"abstract":"Large language models can detect their own errors and sometimes correct them without external feedback, but the underlying mechanisms remain unknown. We investigate this through the lens of second-order models of confidence from decision neuroscience. In a first-order system, confidence derives from the generation signal itself and is therefore maximal for the chosen response, precluding error detection. Second-order models posit a partially independent evaluative signal that can disagree with the committed response, providing the basis for error detection. Kumaran et al. (2026) showed that LLMs cache a confidence representation at a token immediately following the answer (i.e. post-answer newline: PANL) -- that causally drives verbal confidence and dissociates from log-probabilities. Here we test whether this PANL signal extends beyond confidence to support error detection and self-correction. Here we test whether this signal supports error detection and self-correction, deriving predictions from the second-order framework. Using a verify-then-correct paradigm, we show that: (i) verbal confidence predicts error detection far beyond token log-probabilities, ruling out a first-order account; (ii) PANL activations predict error detection beyond verbal confidence itself; and (iii) PANL predicts which errors the model can correct -- where all behavioural signals fail. Causal interventions confirm that PANL signals rescue error detection behavior when answer information is corrupted. All findings replicate across models (Gemma 3 27B and Qwen 2.5 7B) and tasks (TriviaQA and MNLI). These results reveal that LLMs naturally implement a second-order confidence architecture whose internal evaluative signal encodes not only whether an answer is likely wrong but whether the model has the knowledge to fix it.","published":"2026-04-24T06:33:32Z","updated":"2026-05-01T09:11:21Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.22271v2","pdf_url":"https://arxiv.org/pdf/2604.22271v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.21725","versioned_id":"2604.21725v1","title":"AEL: Agent Evolving Learning for Open-Ended Environments","authors":["Wujiang Xu","Jiaojiao Han","Minghao Guo","Kai Mei","Xi Zhu","Han Zhang","Dimitris N. Metaxas"],"abstract":"LLM agents increasingly operate in open-ended environments spanning hundreds of sequential episodes, yet they remain largely stateless: each task is solved from scratch without converting past experience into better future behavior. The central obstacle is not \\emph{what} to remember but \\emph{how to use} what has been remembered, including which retrieval policy to apply, how to interpret prior outcomes, and when the current strategy itself must change. We introduce \\emph{Agent Evolving Learning} (\\ael{}), a two-timescale framework that addresses this obstacle. At the fast timescale, a Thompson Sampling bandit learns which memory retrieval policy to apply at each episode; at the slow timescale, LLM-driven reflection diagnoses failure patterns and injects causal insights into the agent's decision prompt, giving it an interpretive frame for the evidence it retrieves. On a sequential portfolio benchmark (10 sector-diverse tickers, 208 episodes, 5 random seeds), \\ael{} achieves a Sharpe ratio of 2.13$\\pm$0.47, outperforming five published self-improving methods and all non-LLM baselines while maintaining the lowest variance among all LLM-based approaches. A nine-variant ablation reveals a ``less is more'' pattern: memory and reflection together produce a 58\\% cumulative improvement over the stateless baseline, yet every additional mechanism we test (planner evolution, per-tool selection, cold-start initialization, skill extraction, and three credit assignment methods) \\emph{degrades} performance. This demonstrates that the bottleneck in agent self-improvement is \\emph{self-diagnosing how to use} experience rather than adding architectural complexity. Code and data: https://github.com/WujiangXu/AEL.","published":"2026-04-23T14:29:25Z","updated":"2026-04-23T14:29:25Z","categories":["cs.CL","cs.AI","cs.CE"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.21725v1","pdf_url":"https://arxiv.org/pdf/2604.21725v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.21598","versioned_id":"2604.21598v2","title":"You Don't Need Public Tests to Generate Correct Code","authors":["Kaushitha Silva","Srinath Perera"],"abstract":"Multi-agent systems are frequently employed for autonomous code generation, demonstrating strong utility in complex algorithmic problem-solving. Recent studies tackle the difficulty of producing functionally correct programs by leveraging simulation-guided planning and debugging, wherein language models step through execution traces to validate logic. Nevertheless, these methods rely heavily on human-authored public test cases to anchor the simulation and debugging cycles. Hand-crafting exhaustive input-output pairs creates a significant, labor-intensive bottleneck within the software development lifecycle. Since ground-truth examples are seldom accessible before actual implementation in real-world scenarios, this reliance limits existing approaches primarily to curated competitive programming datasets. Additionally, we demonstrate that depending on these public tests creates an \"overconfidence gap,\" leading frameworks to overfit to basic examples and underperform on hidden test suites. Conversely, we note that external input samples are not an absolute requirement for successful code generation. We show that large language models possess the capability to autonomously construct valid inputs and simulate execution flows for self-correction. Building on this, we introduce DryRUN, a framework that removes the necessity for ground-truth data by enabling the LLM to iteratively plan, synthesize its own test inputs, and run simulated executions, thereby mitigating algorithmic overconfidence. Assessments using the LiveCodeBench v6 dataset (post-March 2025) reveal that DryRUN achieves comparable performance to CodeSIM, a state-of-the-art, test-dependent baseline. Notably, it does so entirely without public tests or external execution signals, all while decreasing overall output token usage.","published":"2026-04-23T12:21:03Z","updated":"2026-04-28T05:10:28Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2604.21598v2","pdf_url":"https://arxiv.org/pdf/2604.21598v2","comment":"9 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.21950","versioned_id":"2604.21950v1","title":"Feedback Over Form: Why Execution Feedback Matters More Than Pipeline Topology in 1-3B Code Generation","authors":["Charles Junichi McAndrews"],"abstract":"Small language models (1-3B) are practical to run locally, but individually limited on harder code generation tasks. We ask whether composing them into pipelines can recover some of that lost capability. We study code generation pipelines built from 1-3B models with execution feedback, and use a NEAT-inspired evolutionary search to test whether more complex pipeline structure helps beyond a simple refinement loop. We evaluate on HumanEval (164 problems) and sanitized MBPP (427 problems), all with local inference on a single laptop. Self-refinement with execution feedback improves code generation by more than 4 standard deviations on both benchmarks. The gains are narrow in mechanism: refinement fixes many runtime errors (especially NameError and SyntaxError), but rarely fixes logic errors such as AssertionError. Within our tested general-purpose model pool, generator identity mattered less than refiner capability: a 1.5B generator paired with a 3B refiner matched a 3B model doing both roles. Early stopping is essential; without it, every iteration is net-negative. The code-specialized models outperform every general-purpose pipeline configuration, suggesting model specialization matters more than pipeline architecture. Preliminary text-only pipeline experiments without execution feedback did not show gains at this scale. In our constrained search space, evolutionary search mostly rediscovered the same simple generate-execute-refine loop we found manually, with no clearly significant gain from added topology. Single-evaluation fitness inflates results by 5-7 percent, selecting lucky genomes over good ones. On these benchmarks at 1-3B scale, execution feedback mattered more than added pipeline complexity in determining whether composition helped.","published":"2026-04-23T00:34:54Z","updated":"2026-04-23T00:34:54Z","categories":["cs.SE","cs.AI","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2604.21950v1","pdf_url":"https://arxiv.org/pdf/2604.21950v1","comment":"17 pages main text, 2 page references, 3 figures. Code: https://github.com/L3G/feedback-over-form","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.20714","versioned_id":"2604.20714v1","title":"Learning to Evolve: A Self-Improving Framework for Multi-Agent Systems via Textual Parameter Graph Optimization","authors":["Shan He","Runze Wang","Zhuoyun Du","Huiyu Bai","Zouying Cao","Yu Cheng","Bo Zheng"],"abstract":"Designing and optimizing multi-agent systems (MAS) is a complex, labor-intensive process of \"Agent Engineering.\" Existing automatic optimization methods, primarily focused on flat prompt tuning, lack the structural awareness to debug the intricate web of interactions in MAS. More critically, these optimizers are static; they do not learn from experience to improve their own optimization strategies. To address these gaps, we introduce Textual Parameter Graph Optimization (TPGO), a framework that enables a multi-agent system to learn to evolve. TPGO first models the MAS as a Textual Parameter Graph (TPG), where agents, tools, and workflows are modular, optimizable nodes. To guide evolution, we derive \"textual gradients,\" structured natural language feedback from execution traces, to pinpoint failures and suggest granular modifications. The core of our framework is Group Relative Agent Optimization (GRAO), a novel meta-learning strategy that learns from historical optimization experiences. By analyzing past successes and failures, GRAO becomes progressively better at proposing effective updates, allowing the system to learn how to optimize itself. Extensive experiments on complex benchmarks like GAIA and MCP-Universe show that TPGO significantly enhances the performance of state-of-the-art agent frameworks, achieving higher success rates through automated, self-improving optimization.","published":"2026-04-22T16:00:46Z","updated":"2026-04-22T16:00:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.20714v1","pdf_url":"https://arxiv.org/pdf/2604.20714v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.19548","versioned_id":"2604.19548v1","title":"Taming Actor-Observer Asymmetry in Agents via Dialectical Alignment","authors":["Bobo Li","Rui Wu","Zibo Ji","Meishan Zhang","Hao Fei","Min Zhang","Mong-Li Lee","Wynne Hsu"],"abstract":"Large Language Model agents have rapidly evolved from static text generators into dynamic systems capable of executing complex autonomous workflows. To enhance reliability, multi-agent frameworks assigning specialized roles are increasingly adopted to enable self-reflection and mutual auditing. While such role-playing effectively leverages domain expert knowledge, we find it simultaneously induces a human-like cognitive bias known as Actor-Observer Asymmetry (AOA). Specifically, an agent acting as an actor (during self-reflection) tends to attribute failures to external factors, whereas an observer (during mutual auditing) attributes the same errors to internal faults. We quantify this using our new Ambiguous Failure Benchmark, which reveals that simply swapping perspectives triggers the AOA effect in over 20% of cases for most models. To tame this bias, we introduce ReTAS (Reasoning via Thesis-Antithesis-Synthesis), a model trained through dialectical alignment to enforce perspective-invariant reasoning. By integrating dialectical chain-of-thought with Group Relative Policy Optimization, ReTAS guides agents to synthesize conflicting viewpoints into an objective consensus. Experiments demonstrate that ReTAS effectively mitigates attribution inconsistency and significantly improves fault resolution rates in ambiguous scenarios.","published":"2026-04-21T15:05:58Z","updated":"2026-04-21T15:05:58Z","categories":["cs.CL","cs.AI","cs.CY"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.19548v1","pdf_url":"https://arxiv.org/pdf/2604.19548v1","comment":"ACL 2026 Main Conference. Project page: https://unikcc.github.io/ReTAS/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.23926","versioned_id":"2605.23926v1","title":"How Much Thinking is Enough? Quantifying and Understanding Redundancy in LLM Reasoning","authors":["Zhiyuan Zhai","Xinkai You","Wenjing Yan","Xin Wang"],"abstract":"Reasoning-capable large language models solve hard problems by emitting long chains of thought, paying heavily in latency, GPU time, and energy. Casual inspection of their traces reveals extensive reformulation, verification, and circular self-reflection, yet how much of this deliberation is actually necessary has never been measured at scale or explained from first principles. This paper closes both gaps. We formalise reasoning redundancy directly in terms of the reasoning model itself: the redundancy of a correct trace is the largest fraction of its trailing segmented steps that can be truncated while $π$, forced to terminate thinking and emit a final answer, still produces the correct answer. A large-scale quantification across four frontier reasoning models and two mathematical benchmarks shows that step-level redundancy is consistently high -- between 61% and 93% across the 8 (model, benchmark) conditions we study, with the median critical prefix equal to a single segmented step in six of the eight conditions -- that the finding is robust to the choice of judge family, and that although $ρ$ decreases with problem difficulty on MATH-500, all four models remain substantially redundant ($ρ\\in [46\\%, 85\\%]$) even on the hardest Level-5 problems. We then prove that this redundancy is a structural consequence of length-agnostic outcome rewards, not a model-specific artefact: under any such reward, no finite expected stopping time is optimal. The result holds regardless of RL algorithm, base model, data distribution, or whether the policy is obtained via RL or distillation; over-thinking is therefore not a bug to be patched in individual models but a structural property of how current reasoning models are trained. Code: https://github.com/zhiyuanZhai20/how-much-thinking-is-enough","published":"2026-04-21T05:32:02Z","updated":"2026-04-21T05:32:02Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.23926v1","pdf_url":"https://arxiv.org/pdf/2605.23926v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18966","versioned_id":"2604.18966v2","title":"Self-Improving Tabular Language Models via Iterative Reward-Guided Post-Training","authors":["Yunbo Long","Tejumade Afonja","Guangya Hao","Alexandra Brintrup","Mario Fritz"],"abstract":"Tabular language models can generate synthetic tables by modeling rows as token sequences, but they are typically trained once with supervised fine-tuning and then used as static synthesizers. This is limiting because next-token likelihood does not directly optimize the distributional, utility, and indistinguishability properties used to evaluate synthetic data. We study iterative reward-guided post-training for tabular language models through a generate--score--align protocol, where a generator samples synthetic rows, a task-specified reward ranks them, and the model is updated relative to a fixed supervised reference. Within this protocol, we propose \\textbf{TabGRAA} (\\textbf{Tab}ular \\textbf{G}roup-\\textbf{R}elative \\textbf{A}dvantage \\textbf{A}lignment), a group-relative alignment method that compares high- and low-reward generated groups using group-averaged policy/reference log-ratios rather than one-to-one preference pairs. Across five mixed-type benchmarks, TabGRAA improves a GReaT backbone beyond additional supervised fine-tuning and achieves the strongest average trade-off among adapted DPO, KTO, and NPO baselines on fidelity and downstream utility, while maintaining empirical privacy diagnostics near the supervised baseline. Ablations show that the gains depend on meaningful reward ranking and stable group-level updates rather than extra training alone. Reward-substitution and scorer-separation studies further show that the post-training loop can use both classifier-based and classifier-free rewards, and that proper scorer separation is important for preserving the fidelity--utility--privacy trade-off. These results position TabGRAA as a self-improving post-training method for tabular language-model generators, complementary to strong static tabular synthesizers.","published":"2026-04-21T01:29:52Z","updated":"2026-05-17T12:00:22Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.18966v2","pdf_url":"https://arxiv.org/pdf/2604.18966v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18963","versioned_id":"2604.18963v1","title":"Distillation Traps and Guards: A Calibration Knob for LLM Distillability","authors":["Weixiao Zhan","Yongcheng Jing","Leszek Rutkowski","Dacheng Tao"],"abstract":"Knowledge distillation (KD) transfers capabilities from large language models (LLMs) to smaller students, yet it can fail unpredictably and also underpins model leakage risks. Our analysis revealed several distillation traps: tail noise, off-policy instability, and, most fundamentally, the teacher-student gap, that distort training signals. These traps manifest as overconfident hallucinations, self-correction collapse, and local decoding degradation, causing distillation to fail. Motivated by these findings, we propose a post-hoc calibration method that, to the best of our knowledge, for the first time enables control over a teacher's distillability via reinforcement fine-tuning (RFT). Our objective combines task utility, KL anchor, and across-tokenizer calibration reward. This makes distillability a practical safety lever for foundation models, connecting robust teacher-student transfer with deployment-aware model protection. Experiments across math, knowledge QA, and instruction-following tasks show that students distilled from distillable calibrated teachers outperform SFT and KD baselines, while undistillable calibrated teachers retain their task performance but cause distilled students to collapse, offering a practical knob for both better KD and model IP protection.","published":"2026-04-21T01:22:35Z","updated":"2026-04-21T01:22:35Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.18963v1","pdf_url":"https://arxiv.org/pdf/2604.18963v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18805","versioned_id":"2604.18805v1","title":"AI scientists produce results without reasoning scientifically","authors":["Martiño Ríos-García","Nawaf Alampara","Chandan Gupta","Indrajeet Mandal","Sajid Mannan","Ali Asghar Aghajani","N. M. Anoop Krishnan","Kevin Maik Jablonka"],"abstract":"Large language model (LLM)-based systems are increasingly deployed to conduct scientific research autonomously, yet whether their reasoning adheres to the epistemic norms that make scientific inquiry self-correcting is poorly understood. Here, we evaluate LLM-based scientific agents across eight domains, spanning workflow execution to hypothesis-driven inquiry, through more than 25,000 agent runs and two complementary lenses: (i) a systematic performance analysis that decomposes the contributions of the base model and the agent scaffold, and (ii) a behavioral analysis of the epistemological structure of agent reasoning. We observe that the base model is the primary determinant of both performance and behavior, accounting for 41.4% of explained variance versus 1.5% for the scaffold. Across all configurations, evidence is ignored in 68% of traces, refutation-driven belief revision occurs in 26%, and convergent multi-test evidence is rare. The same reasoning pattern appears whether the agent executes a computational workflow or conducts hypothesis-driven inquiry. They persist even when agents receive near-complete successful reasoning trajectories as context, and the resulting unreliability compounds across repeated trials in epistemically demanding domains. Thus, current LLM-based agents execute scientific workflows but do not exhibit the epistemic patterns that characterize scientific reasoning. Outcome-based evaluation cannot detect these failures, and scaffold engineering alone cannot repair them. Until reasoning itself becomes a training target, the scientific knowledge produced by such agents cannot be justified by the process that generated it.","published":"2026-04-20T20:23:42Z","updated":"2026-04-20T20:23:42Z","categories":["cs.AI","cond-mat.mtrl-sci","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.18805v1","pdf_url":"https://arxiv.org/pdf/2604.18805v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18738","versioned_id":"2604.18738v2","title":"Remask, Don't Replace: Token-to-Mask Refinement in Diffusion Large Language Models","authors":["Lin Yao"],"abstract":"Diffusion large language models (dLLMs) gain speed by committing multiple tokens in parallel at each denoising step, but any erroneous commitment persists as conditioning context and biases every subsequent prediction. LLaDA2.1 repairs such errors with Token-to-Token (T2T) editing, which re-examines previously unmasked tokens and overwrites them when an alternative becomes sufficiently confident. We argue that this replacement action is itself the limiting factor: under polluted context, a confident replacement can propagate the error, while under a multimodal posterior no alternative may be confident enough to trigger an edit. We propose Token-to-Mask (T2M) remasking, a training-free rule that revokes suspicious commitments by resetting them to [M] and lets the subsequent mask-filling steps re-predict them from a cleaner context. T2M improves accuracy by +13.33 points on AIME 2025 and +8.56 points on CMATH. These results suggest that, for parallel discrete generators, remasking suspect tokens rather than overwriting them is a more reliable self-correction primitive.","published":"2026-04-20T18:43:28Z","updated":"2026-05-07T10:54:12Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.18738v2","pdf_url":"https://arxiv.org/pdf/2604.18738v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18567","versioned_id":"2604.18567v1","title":"Latent Phase-Shift Rollback: Inference-Time Error Correction via Residual Stream Monitoring and KV-Cache Steering","authors":["Manan Gupta","Dhruv Kumar"],"abstract":"Large language models frequently commit unrecoverable reasoning errors mid-generation: once a wrong step is taken, subsequent tokens compound the mistake rather than correct it. We introduce $\\textbf{Latent Phase-Shift Rollback}$ (LPSR): at each generation step, we monitor the residual stream at a critical layer lcrit, detect abrupt directional reversals (phase shifts) via a cosine-similarity $+$ entropy dual gate, and respond by rolling back the KV-cache and injecting a pre-computed steering vector. No fine-tuning, gradient computation, or additional forward passes are required. LPSR achieves $\\mathbf{44.0\\%}$ on MATH-500 with an 8B model versus $28.8\\%$ for standard AR ($+15.2$ pp; McNemar $χ^2 = 66.96$, $p < 10^{-15}$). Critically, prompted self-correction, the most natural inference-time baseline, scores only $19.8\\%$, below standard AR; LPSR exceeds it by $+24.2$ pp ($χ^2 = 89.4$, $p \\approx 0$). LPSR also outperforms Best-of-16 ($+7.8$ pp) at $5.4\\times$ lower token cost, and surpasses a standard 70B model ($35.2\\%$) with $8.75\\times$ fewer parameters at ${\\sim}3\\times$ the token budget. A 32-layer sweep reveals a novel \\textbf{detection-correction dissociation}: error-detection AUC peaks at layer~14 ($0.718$) but task accuracy peaks at layer~16 ($44.0\\%$ vs.\\ $29.2\\%$), demonstrating that optimal monitoring depth differs for detection and correction.","published":"2026-04-20T17:53:33Z","updated":"2026-04-20T17:53:33Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.18567v1","pdf_url":"https://arxiv.org/pdf/2604.18567v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18364","versioned_id":"2604.18364v1","title":"Training and Agentic Inference Strategies for LLM-based Manim Animation Generation","authors":["Ravidu Suien Rammuni Silva","Ahmad Lotfi","Isibor Kennedy Ihianle","Golnaz Shahtahmassebi","Jordan J. Bird"],"abstract":"Generating programmatic animation using libraries such as Manim presents unique challenges for Large Language Models (LLMs), requiring spatial reasoning, temporal sequencing, and familiarity with domain-specific APIs that are underrepresented in general pre-training data. A systematic study of how training and inference strategies interact in this setting is lacking in current research. This study introduces ManimTrainer, a training pipeline that combines Supervised Fine-tuning (SFT) with Reinforcement Learning (RL) based Group Relative Policy Optimisation (GRPO) using a unified reward signal that fuses code and visual assessment signals, and ManimAgent, an inference pipeline featuring Renderer-in-the-loop (RITL) and API documentation-augmented RITL (RITL-DOC) strategies. Using these techniques, this study presents the first unified training and inference study for text-to-code-to-video transformation with Manim. It evaluates 17 open-source sub-30B LLMs across nine combinations of training and inference strategies using ManimBench. Results show that SFT generally improves code quality, while GRPO enhances visual outputs and increases the models' responsiveness to extrinsic signals during self-correction at inference time. The Qwen 3 Coder 30B model with GRPO and RITL-DOC achieved the highest overall performance, with a 94% Render Success Rate (RSR) and 85.7% Visual Similarity (VS) to reference videos, surpassing the baseline GPT-4.1 model by +3 percentage points in VS. Additionally, the analysis shows that the correlation between code and visual metrics strengthens with SFT and GRPO but weakens with inference-time enhancements, highlighting the complementary roles of training and agentic inference strategies in Manim animation generation.","published":"2026-04-20T14:54:06Z","updated":"2026-04-20T14:54:06Z","categories":["cs.AI","cs.GR","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.18364v1","pdf_url":"https://arxiv.org/pdf/2604.18364v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18320","versioned_id":"2604.18320v1","title":"EVE: Verifiable Self-Evolution of MLLMs via Executable Visual Transformations","authors":["Yongrui Heng","Chaoya Jiang","Han Yang","Shikun Zhang","Wei Ye"],"abstract":"Self-evolution of multimodal large language models (MLLMs) remains a critical challenge: pseudo-label-based methods suffer from progressive quality degradation as model predictions drift, while template-based methods are confined to a static set of transformations that cannot adapt in difficulty or diversity. We contend that robust, continuous self-improvement requires not only deterministic external feedback independent of the model's internal certainty, but also a mechanism to perpetually diversify the training distribution. To this end, we introduce EVE (Executable Visual transformation-based self-Evolution), a novel framework that entirely bypasses pseudo-labels by harnessing executable visual transformations continuously enriched in both variety and complexity. EVE adopts a Challenger-Solver dual-policy architecture. The Challenger maintains and progressively expands a queue of visual transformation code examples, from which it synthesizes novel Python scripts to perform dynamic visual transformations. Executing these scripts yields VQA problems with absolute, execution-verified ground-truth answers, eliminating any reliance on model-generated supervision. A multi-dimensional reward system integrating semantic diversity and dynamic difficulty calibration steers the Challenger to enrich its code example queue while posing progressively more challenging tasks, preventing mode collapse and fostering reciprocal co-evolution between the two policies. Extensive experiments demonstrate that EVE consistently surpasses existing self-evolution methods, establishing a robust and scalable paradigm for verifiable MLLM self-evolution. The code is available at https://github.com/0001Henry/EVE .","published":"2026-04-20T14:20:44Z","updated":"2026-04-20T14:20:44Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.18320v1","pdf_url":"https://arxiv.org/pdf/2604.18320v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18003","versioned_id":"2604.18003v1","title":"SELF-EMO: Emotional Self-Evolution from Recognition to Consistent Expression","authors":["Shaowei Zhang","Faqiang Qian","Yan Chen","Ziliang Wang","Kang An","Yong Dai","Mengya Gao","Yichao Wu"],"abstract":"Emotion Recognition in Conversation (ERC) has become a fundamental capability for large language models (LLMs) in human-centric interaction. Beyond accurate recognition, coherent emotional expression is also crucial, yet both are limited by the scarcity and static nature of high-quality annotated data. In this work, we propose SELF-EMO, a self-evolution framework grounded in the hypothesis that better emotion prediction leads to more consistent emotional responses. We introduce two auxiliary tasks, emotional understanding and emotional expression, and design a role-based self-play paradigm where the model acts as both an emotion recognizer and a dialogue responder. Through iterative interactions, the model generates diverse conversational trajectories, enabling scalable data generation. To ensure quality, we adopt a data flywheel mechanism that filters candidate predictions and responses using a smoothed IoU-based reward and feeds selected samples back for continuous self-improvement without external supervision. We further develop SELF-GRPO, a reinforcement learning algorithm that stabilizes optimization with multi-label alignment rewards and group-level consistency signals. Experiments on IEMOCAP, MELD, and EmoryNLP show that SELF-EMO achieves state-of-the-art performance, improving accuracy by +6.33% on Qwen3-4B and +8.54% on Qwen3-8B, demonstrating strong effectiveness and generalization.","published":"2026-04-20T09:27:40Z","updated":"2026-04-20T09:27:40Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.18003v1","pdf_url":"https://arxiv.org/pdf/2604.18003v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.17658","versioned_id":"2604.17658v1","title":"Towards Self-Improving Error Diagnosis in Multi-Agent Systems","authors":["Jiazheng Li","Emine Yilmaz","Bei Chen","Dieu-Thu Le"],"abstract":"Large Language Model (LLM)-based Multi-Agent Systems (MAS) enable complex problem-solving but introduce significant debugging challenges, characterized by long interaction traces, inter-agent dependencies, and delayed error manifestation. Existing diagnostic approaches often rely on expensive expert annotation or ''LLM-as-a-judge'' paradigms, which struggle to pinpoint decisive error steps within extended contexts. In this paper, we introduce ErrorProbe, a self-improving framework for semantic failure attribution that identifies responsible agents and the originating error step. The framework operates via a three-stage pipeline: (1) operationalizing the MAS failure taxonomy to detect local anomalies, (2) performing symptom-driven backward tracing to prune irrelevant context, and (3) employing a specialized multi-agent team (Strategist, Investigator, Arbiter) to validate error hypotheses through tool-grounded execution. Crucially, ErrorProbe maintains a verified episodic memory that updates only when error patterns are confirmed by executable evidence, without the need for annotation. Experiments across the TracerTraj and Who&When benchmarks demonstrate that ErrorProbe significantly outperforms baselines, particularly in step-level localization, while the verified memory enables robust cross-domain transfer without retraining.","published":"2026-04-19T23:13:05Z","updated":"2026-04-19T23:13:05Z","categories":["cs.MA","cs.CL"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2604.17658v1","pdf_url":"https://arxiv.org/pdf/2604.17658v1","comment":"15 pages, 3 figures; accepted at ACL 2026 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.17450","versioned_id":"2604.17450v3","title":"Compiling Deterministic Structure into SLM Harnesses","authors":["Zan Kai Chong","Hiroyuki Ohsaki","Bryan Ng"],"abstract":"Enterprise SLM deployment faces epistemic asymmetry: small models cannot self-correct reasoning errors, while frontier LLMs incur prohibitive costs and data sovereignty risks at scale. We propose Semantic Gradient Descent (SGDe), a teacher-student framework that compiles agentic workflows into discrete execution plans--DAG topologies, system prompts, and deterministic code. The trailing e distinguishes this discrete, compilation-based approach from stochastic gradient descent. Operating in discrete semantic space, a frontier teacher generates natural-language critiques that serve as directional gradients to iteratively refine the SLM's workflow artefacts. We formalise SGDe under PAC learning, establishing sample-complexity bounds that enable convergence with as few as three training examples by leveraging the teacher as a statistical prior. On an adversarially synthesized GSM-Hard test set, compiled workflows achieve 91.3% accuracy at m=5 and 99.3% at m=3--a +26.3% to +34.3% absolute gain over state-of-the-art prompt optimisers. Within harness engineering, SGDe treats deterministic code placement (which subtasks to delegate to Python versus retain as LLM calls) as a trace-driven, per-node optimisation target, generalising static whole-problem offloading in PAL and PoT. The teacher compiles two deterministic structures: capability offloading (delegating subtasks to Python when the SLM is unreliable) and structural consensus (wrapping variance-sensitive steps in fan-out/fan-in subgraphs with deterministic voting).","published":"2026-04-19T14:04:29Z","updated":"2026-05-06T14:07:17Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.17450v3","pdf_url":"https://arxiv.org/pdf/2604.17450v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.17399","versioned_id":"2604.17399v1","title":"Beyond Meta-Reasoning: Metacognitive Consolidation for Self-Improving LLM Reasoning","authors":["Ziqing Zhuang","Linhai Zhang","Jiasheng Si","Deyu Zhou","Yulan He"],"abstract":"Large language models (LLMs) have demonstrated strong reasoning capabilities, and as existing approaches for enhancing LLM reasoning continue to mature, increasing attention has shifted toward meta-reasoning as a promising direction for further improvement. However, most existing meta-reasoning methods remain episodic: they focus on executing complex meta-reasoning routines within individual instances, but ignore the accumulation of reusable meta-reasoning skills across instances, leading to recurring failure modes and repeatedly high metacognitive effort. In this paper, we introduce Metacognitive Consolidation, a novel framework in which a model consolidates metacognitive experience from past reasoning episodes into reusable knowledge that improves future meta-reasoning. We instantiate this framework by structuring instance-level problem solving into distinct roles for reasoning, monitoring, and control to generate rich, attributable meta-level traces. These traces are then consolidated through a hierarchical, multi-timescale update mechanism that gradually forms evolving meta-knowledge. Experimental results demonstrate consistent performance gains across benchmarks and backbone models, and show that performance improves as metacognitive experience accumulates over time.","published":"2026-04-19T12:02:30Z","updated":"2026-04-19T12:02:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.17399v1","pdf_url":"https://arxiv.org/pdf/2604.17399v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.17366","versioned_id":"2604.17366v1","title":"ArgBench: Benchmarking LLMs on Computational Argumentation Tasks","authors":["Yamen Ajjour","Carlotta Quensel","Nedim Lipka","Henning Wachsmuth"],"abstract":"Argumentation skills are an essential toolkit for large language models (LLMs). These skills are crucial in various use cases, including self-reflection, debating collaboratively for diverse answers, and countering hate speech. In this paper, we create the first benchmark for a standardized evaluation of LLM-based approaches to computational argumentation, encompassing 33 datasets from previous work in unified form. Using the benchmark, we evaluate the generalizability of five LLM families across 46 computational argumentation tasks that cover mining arguments, assessing perspectives, assessing argument quality, reasoning about arguments, and generating arguments. On the benchmark, we conduct an extensive systematic analysis of the contribution of few-shot examples, reasoning steps, model size, and training skills to the performance of LLMs on the computational argumentation tasks in the benchmark.","published":"2026-04-19T10:23:41Z","updated":"2026-04-19T10:23:41Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.17366v1","pdf_url":"https://arxiv.org/pdf/2604.17366v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.17310","versioned_id":"2604.17310v1","title":"Interpolating Discrete Diffusion Models with Controllable Resampling","authors":["Marcel Kollovieh","Sirine Ayadi","Stephan Günnemann"],"abstract":"Discrete diffusion models form a powerful class of generative models across diverse domains, including text and graphs. However, existing approaches face fundamental limitations. Masked diffusion models suffer from irreversible errors due to early unmasking, while uniform diffusion models, despite enabling self-correction, often yield low-quality samples due to their strong reliance on intermediate latent states. We introduce IDDM, an Interpolating Discrete Diffusion Model, that improves diffusion by reducing dependence on intermediate latent states. Central to IDDM is a controllable resampling mechanism that partially resets probability mass to the marginal distribution, mitigating error accumulation and enabling more effective token corrections. IDDM specifies a generative process whose transitions interpolate between staying at the current state, resampling from a prior, and flipping toward the target state, while enforcing marginal consistency and fully decoupling training from inference. We benchmark our model against state-of-the-art discrete diffusion models across molecular graph generation as well as text generation tasks, demonstrating competitive performance.","published":"2026-04-19T07:55:57Z","updated":"2026-04-19T07:55:57Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.17310v1","pdf_url":"https://arxiv.org/pdf/2604.17310v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.17025","versioned_id":"2604.17025v3","title":"Harness as an Asset: Enforcing Determinism via the Convergent AI Agent Framework (CAAF)","authors":["Tianbao Zhang"],"abstract":"Large Language Models produce a controllability gap in safety-critical engineering: even low rates of undetected constraint violations render a system undeployable. Current orchestration paradigms suffer from sycophantic compliance, context attention decay, and stochastic oscillation during self-correction. We introduce the Convergent AI Agent Framework (CAAF), which transitions agentic workflows from open-loop generation to closed-loop fail-safe determinism via three pillars: (1) Recursive Atomic Decomposition with physical context firewalls; (2) Harness as an Asset, formalizing domain invariants into machine-readable registries enforced by a deterministic Unified Assertion Interface; and (3) Structured Semantic Gradients with State Locking for monotonic non-regression. This paper makes two core claims. First, an industrialization thesis: once domain invariants are formalized as an executable Harness, the Harness itself becomes a first-class enterprise asset that compounds in value as foundation models commoditize, and CAAF's ability to deliver its reliability on commodity-tier models makes fully self-hosted, on-premises deployment architecturally feasible for regulated sectors where cloud APIs are not an option. Second, an architectural claim supported by ablation: CAAF's three pillars address complementary failure surfaces and none alone closes the controllability gap at commodity cost. The paper contributes entirely at the orchestration and industrialization layer. Evidence across two complementary benchmarks, three-tier UAI ablations, multi-agent baselines, and a closed-source commodity family replicated by two independent open-weight families, is reported in the body.","published":"2026-04-18T15:15:09Z","updated":"2026-05-04T07:24:42Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.17025v3","pdf_url":"https://arxiv.org/pdf/2604.17025v3","comment":"47 pages, 13 figures. Code: https://github.com/TianbaoZhang001/OpenCAAF (Apache-2.0)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.16778","versioned_id":"2604.16778v2","title":"Federation over Text: Insight Sharing for Multi-Agent Reasoning","authors":["Dixi Yao","Tahseen Rabbani","Manzil Zaheer","Tian Li"],"abstract":"We propose a federated learning-like framework, Federation over Text (FoT), that enables multiple clients solving different tasks to collectively generate a shared library of metacognitive insights by iteratively federating their local reasoning processes without sharing actual problem instances or task instructions. Instead of federation over gradients (e.g., as in distributed training), FoT operates at the semantic level without any gradient optimization or supervision signal. Iteratively, each client runs an LLM agent that does local thinking and self-improvement on their specific tasks independently, and shares reasoning traces with a central server, which aggregates and distills them into a cross-task (and cross-domain) insight library that existing and future agents can leverage to improve performance on related tasks. Experiments show that FoT improves reasoning effectiveness and efficiency across a wide range of challenging applications, including mathematical problem solving, cross-domain collaboration, real-world daily tasks, and machine learning research insight discovery. Specifically, it improves average performance scores by 25% while reducing the reasoning tokens by 4% across the first three applications. In the research insight discovery application, FoT is able to generate insights that cover over 80% of the major contributions in the subsequent papers.","published":"2026-04-18T01:57:42Z","updated":"2026-05-23T18:12:27Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.16778v2","pdf_url":"https://arxiv.org/pdf/2604.16778v2","comment":"46 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.16625","versioned_id":"2604.16625v1","title":"AdaExplore: Failure-Driven Adaptation and Diversity-Preserving Search for Efficient Kernel Generation","authors":["Weihua Du","Jingming Zhuo","Yixin Dong","Andre Wang He","Weiwei Sun","Zeyu Zheng","Manupa Karunaratne","Ivan Fox","Tim Dettmers","Tianqi Chen","Yiming Yang","Sean Welleck"],"abstract":"Recent large language model (LLM) agents have shown promise in using execution feedback for test-time adaptation. However, robust self-improvement remains far from solved: most approaches still treat each problem instance independently, without accumulating reusable knowledge. This limitation is particularly pronounced in domain-specific languages such as Triton, which are underrepresented in LLM pretraining data. Their strict constraints and non-linear optimization landscape further make naive generation and local refinement unreliable. We propose AdaExplore, an agent framework that enables self-improvement via accumulated execution feedback for performance-critical kernel code generation through two complementary stages: failure-driven adaptation and diversity-preserving search, jointly improving correctness and optimization performance without additional fine-tuning or external knowledge. In the adaptation stage, the agent synthesizes tasks and converts recurring failures into a reusable memory of validity rules, helping subsequent generations remain within the feasible set. In the search stage, the agent organizes candidate kernels as a tree and alternates between small local refinements and larger structural regeneration, allowing it to explore the optimization landscape beyond local optima. Experiments on kernel runtime optimization benchmarks validate these gains: AdaExplore achieves 3.12x and 1.72x speedups on KernelBench Level-2 and Level-3, respectively, within 100 steps, and continues to improve with additional computation.","published":"2026-04-17T18:25:03Z","updated":"2026-04-17T18:25:03Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.16625v1","pdf_url":"https://arxiv.org/pdf/2604.16625v1","comment":"Preliminary work. The implementation is available at https://github.com/StigLidu/AdaExplore","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.15839","versioned_id":"2604.15839v1","title":"Discover and Prove: An Open-source Agentic Framework for Hard Mode Automated Theorem Proving in Lean 4","authors":["Chengwu Liu","Yichun Yin","Ye Yuan","Jiaxuan Xie","Botao Li","Siqi Li","Jianhao Shen","Yan Xu","Lifeng Shang","Ming Zhang"],"abstract":"Most ATP benchmarks embed the final answer within the formal statement -- a convention we call \"Easy Mode\" -- a design that simplifies the task relative to what human competitors face and may lead to optimistic estimates of model capability. We call the stricter, more realistic setting \"Hard Mode\": the system must independently discover the answer before constructing a formal proof. To enable Hard Mode research, we make two contributions. First, we release MiniF2F-Hard and FIMO-Hard, expert-reannotated Hard Mode variants of two widely-used ATP benchmarks. Second, we introduce Discover And Prove (DAP), an agentic framework that uses LLM natural-language reasoning with explicit self-reflection to discover answers, then rewrites Hard Mode statements into Easy Mode ones for existing ATP provers. DAP sets the state of the art: on CombiBench it raises solved problems from 7 (previous SOTA, Pass@16) to 10; on PutnamBench it is the first system to formally prove 36 theorems in Hard Mode -- while simultaneously revealing that state-of-the-art LLMs exceed 80% answer accuracy on the same problems where formal provers manage under 10%, exposing a substantial gap that Hard Mode benchmarks are uniquely suited to measure.","published":"2026-04-17T08:40:48Z","updated":"2026-04-17T08:40:48Z","categories":["cs.AI","cs.CL","cs.LO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.15839v1","pdf_url":"https://arxiv.org/pdf/2604.15839v1","comment":"ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.16299","versioned_id":"2605.16299v2","title":"ACE: Self-Evolving LLM Coding Framework via Adversarial Unit Test Generation and Preference Optimization","authors":["Yixu Huang","Xinglei Yu","Zhongyu Wei"],"abstract":"Large Language Models (LLMs) excel at code generation but remain heavily reliant on large-scale annotated solutions and verification-based supervision, which constrains scalability and hinders sustained self-improvement. Recent solver--verifier frameworks exploit program execution as an automatic supervision signal, but their effectiveness degrades as solvers become moderately strong: verifier-generated tests increasingly confirm semantic correctness rather than exposing the remaining failure modes. We propose \\textbf{ACE}, a self-evolving code generation framework based on a solver--adversary architecture that prioritizes active failure discovery through execution-centric supervision. A single LLM alternates between generating candidate programs and producing adversarial unit test inputs optimized to induce execution-level failures, such as runtime errors, exceptions, or non-termination. Supervision is derived solely from execution outcomes: robust programs are selected for supervised fine-tuning, while adversarial tests are optimized via Kahneman--Tversky Optimization using execution-derived preferences. Notably, the entire training loop requires no ground-truth code or external reward models. Experiments on CodeContests, MBPP, and LiveCodeBench demonstrate that ACE consistently outperforms strong solver--verifier baselines, achieving 3--7\\% absolute gains in pass@1, with larger improvements on out-of-distribution benchmarks, while maintaining competitive or improved inference efficiency.","published":"2026-04-17T07:20:01Z","updated":"2026-05-21T14:01:21Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2605.16299v2","pdf_url":"https://arxiv.org/pdf/2605.16299v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.15618","versioned_id":"2604.15618v1","title":"Majority Voting for Code Generation","authors":["Tim Launer","Jonas Hübotter","Marco Bagatella","Ido Hakimi","Andreas Krause"],"abstract":"We investigate Functional Majority Voting (FMV), a method based on functional consensus for code generation with Large Language Models, which identifies a representative solution from multiple generations using their runtime execution signatures on test inputs. We find that FMV is an effective test-time inference strategy, substantially boosting performance on LiveCodeBench without a large compute overhead. Furthermore, we extend the utility of functional consensus and apply it as an aggregation strategy for label-free Test-Time Reinforcement Learning. We demonstrate that this increases pass@1 on holdout tasks, but find no evidence of self-improvement beyond the base model's performance ceiling.","published":"2026-04-17T01:51:36Z","updated":"2026-04-17T01:51:36Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.15618v1","pdf_url":"https://arxiv.org/pdf/2604.15618v1","comment":"ICLR 2026 Test-Time Updates (TTU) Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.15309","versioned_id":"2604.15309v1","title":"MM-WebAgent: A Hierarchical Multimodal Web Agent for Webpage Generation","authors":["Yan Li","Zezi Zeng","Yifan Yang","Yuqing Yang","Ning Liao","Weiwei Guo","Lili Qiu","Mingxi Cheng","Qi Dai","Zhendong Wang","Zhengyuan Yang","Xue Yang","Ji Li","Lijuan Wang","Chong Luo"],"abstract":"The rapid progress of Artificial Intelligence Generated Content (AIGC) tools enables images, videos, and visualizations to be created on demand for webpage design, offering a flexible and increasingly adopted paradigm for modern UI/UX. However, directly integrating such tools into automated webpage generation often leads to style inconsistency and poor global coherence, as elements are generated in isolation. We propose MM-WebAgent, a hierarchical agentic framework for multimodal webpage generation that coordinates AIGC-based element generation through hierarchical planning and iterative self-reflection. MM-WebAgent jointly optimizes global layout, local multimodal content, and their integration, producing coherent and visually consistent webpages. We further introduce a benchmark for multimodal webpage generation and a multi-level evaluation protocol for systematic assessment. Experiments demonstrate that MM-WebAgent outperforms code-generation and agent-based baselines, especially on multimodal element generation and integration. Code & Data: https://aka.ms/mm-webagent.","published":"2026-04-16T17:59:49Z","updated":"2026-04-16T17:59:49Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.15309v1","pdf_url":"https://arxiv.org/pdf/2604.15309v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.15082","versioned_id":"2604.15082v1","title":"Autonomous Evolution of EDA Tools: Multi-Agent Self-Evolved ABC","authors":["Cunxi Yu","Haoxing Ren"],"abstract":"This paper introduces the first \\emph{self-evolving} logic synthesis framework, which leverages Large Language Model (LLM) agents to autonomously improve the source code of \\textsc{ABC}, the widely adopted logic synthesis system. Our framework operates on the \\emph{entire integrated ABC codebase}, and the output repository preserves its single-binary execution model and command interface. In the initial evolution cycle, we bootstrap the system using existing prior open-source synthesis components, covering flow tuning, logic minimization, and technology mapping, but without manually injecting new heuristics. On top of this foundation, a team of LLM-based agents iteratively rewrites and evolves specific sub-components of ABC following our ``programming guidance`` prompts under a unified correctness and QoR-driven evaluation loop. Each evolution cycle proposes code modifications, compiles the integrated binary, validates correctness, and evaluates quality-of-results (QoR) on \\emph{multi-suite benchmarks including ISCAS~85/89/99, VTR, EPFL, and IWLS~2005}. Through continuous feedback, the system discovers optimizations beyond human-designed heuristics, effectively \\emph{learning new synthesis strategies} that enhance QoR. We detail the architecture of this self-improving system, its integration with \\textsc{ABC}, and results demonstrating that the framework can autonomously and progressively improve EDA tool at full million-line scale.","published":"2026-04-16T14:42:55Z","updated":"2026-04-16T14:42:55Z","categories":["cs.AR","cs.AI"],"primary_category":"cs.AR","arxiv_url":"https://arxiv.org/abs/2604.15082v1","pdf_url":"https://arxiv.org/pdf/2604.15082v1","comment":"7 pages; To appear at DAC 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.14989","versioned_id":"2604.14989v2","title":"Dr. RTL: Autonomous Agentic RTL Optimization through Tool-Grounded Self-Improvement","authors":["Wenji Fang","Yao Lu","Shang Liu","Jing Wang","Ziyan Guo","Junxian He","Fengbin Tu","Zhiyao Xie"],"abstract":"Recent advances in large language models (LLMs) have sparked growing interest in automatic RTL optimization for better performance, power, and area (PPA). However, existing methods are still far from realistic RTL optimization. Their evaluation settings are often unrealistic: they are tested on manually degraded, small-scale RTL designs and rely on weak open-source tools. Their optimization methods are also limited, relying on coarse design-level feedback and simple pre-defined rewriting rules. To address these limitations, we present Dr. RTL, an agentic framework for RTL timing optimization in a realistic evaluation environment, with continual self-improvement through reusable optimization skills. We establish a realistic evaluation setting with more challenging RTL designs and an industrial EDA workflow. Within this setting, Dr. RTL performs closed-loop optimization through a multi-agent framework for critical-path analysis, parallel RTL rewriting, and tool-based evaluation. We further introduce group-relative skill learning, which compares parallel RTL rewrites and distills the optimization experience into an interpretable skill library. Currently, this library contains 47 pattern--strategy entries for cross-design reuse to improve PPA and accelerate convergence, and it can continue evolving over time. Evaluated on 20 real-world RTL designs, Dr. RTL achieves average WNS/TNS improvements of 21%/17% with a 6% area reduction over the industry-leading commercial synthesis tool.","published":"2026-04-16T13:18:24Z","updated":"2026-04-26T15:34:21Z","categories":["cs.AI","cs.AR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.14989v2","pdf_url":"https://arxiv.org/pdf/2604.14989v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.14847","versioned_id":"2604.14847v1","title":"TrigReason: Trigger-Based Collaboration between Small and Large Reasoning Models","authors":["Yi Zhao","Yajuan Peng","Cam-Tu Nguyen","Zuchao Li","Xiaoliang Wang","Xiaoming Fu","Hai Zhao"],"abstract":"Large Reasoning Models (LRMs) achieve strong performance on complex tasks through extended chains of thought but suffer from high inference latency due to autoregressive reasoning. Recent work explores using Small Reasoning Models (SRMs) to accelerate LRM inference. In this paper, we systematically characterize the capability boundaries of SRMs and identify three common types of reasoning risks: (1) path divergence, where SRMs lack the strategic ability to construct an initial plan, causing reasoning to deviate from the most probable path; (2) cognitive overload, where SRMs fail to solve particularly difficult steps; and (3) recovery inability, where SRMs lack robust self-reflection and error correction mechanisms. To address these challenges, we propose TrigReason, a trigger-based collaborative reasoning framework that replaces continuous polling with selective intervention. TrigReason delegates most reasoning to the SRM and activates LRM intervention only when necessary-during initial strategic planning (strategic priming trigger), upon detecting extraordinary overconfidence (cognitive offload trigger), or when reasoning falls into unproductive loops (intervention request trigger). The evaluation results on AIME24, AIME25, and GPQA-D indicate that TrigReason matches the accuracy of full LRMs and SpecReason, while offloading 1.70x - 4.79x more reasoning steps to SRMs. Under edge-cloud conditions, TrigReason reduces latency by 43.9\\% and API cost by 73.3\\%. Our code is available at \\href{https://github.com/QQQ-yi/TrigReason}{https://github.com/QQQ-yi/TrigReason}","published":"2026-04-16T10:33:00Z","updated":"2026-04-16T10:33:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.14847v1","pdf_url":"https://arxiv.org/pdf/2604.14847v1","comment":"ACL 2026 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18614","versioned_id":"2604.18614v1","title":"HadAgent: Harness-Aware Decentralized Agentic AI Serving with Proof-of-Inference Blockchain Consensus","authors":["Landy Jimenez","Mariah Weatherspoon","Bingyu Shen","Yi Sheng","Jianming Liu","Boyang Li"],"abstract":"Proof-of-Work (PoW) blockchain consensus consumes vast computational resources without producing useful output, while the rapid growth of large language model (LLM) agents has created unprecedented demand for GPU computation. We present HadAgent, a decentralized agentic AI serving system that replaces hash-based mining with Proof-of-Inference (PoI), a consensus mechanism in which nodes earn block-creation rights by executing deterministic LLM inference tasks. Because verification requires only re-executing a single forward pass under identical conditions, cross-node verification operates at consensus speed. HadAgent organizes validated records into a three-lane block body with dedicated DATA, MODEL, and PROOF channels, each protected by an independent Merkle root for fine-grained tamper detection. A two-tier node architecture classifies secondary nodes as trusted or non-trusted based on historical behavior: trusted nodes serve inference results in real time through optimistic execution, while non-trusted nodes must undergo full consensus verification. A harness layer monitors node behavior through heartbeat probes, anomaly detection via deterministic recomputation, and automated trust management, creating a self-correcting feedback loop that isolates malicious or unreliable participants. Experiments on a prototype implementation demonstrate 100% detection rate and 0% false positive rate for tampered records, sub-millisecond validation latency for record and hub operations, and effective harness convergence that excludes adversarial nodes within two rounds while promoting honest nodes to trusted status within five rounds.","published":"2026-04-15T14:46:29Z","updated":"2026-04-15T14:46:29Z","categories":["cs.DC","cs.CR","cs.ET","cs.MA"],"primary_category":"cs.DC","arxiv_url":"https://arxiv.org/abs/2604.18614v1","pdf_url":"https://arxiv.org/pdf/2604.18614v1","comment":"9 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.13598","versioned_id":"2604.13598v1","title":"Enhancing Reinforcement Learning for Radiology Report Generation with Evidence-aware Rewards and Self-correcting Preference Learning","authors":["Qin Zhou","Guoyan Liang","Qianyi Yang","Jingyuan Chen","Sai Wu","Chang Yao","Zhe Wang"],"abstract":"Recent reinforcement learning (RL) approaches have advanced radiology report generation (RRG), yet two core limitations persist: (1) report-level rewards offer limited evidence-grounded guidance for clinical faithfulness; and (2) current methods lack an explicit self-improving mechanism to align with clinical preference. We introduce clinically aligned Evidence-aware Self-Correcting Reinforcement Learning (ESC-RL), comprising two key components. First, a Group-wise Evidence-aware Alignment Reward (GEAR) delivers group-wise, evidence-aware feedback. GEAR reinforces consistent grounding for true positives, recovers missed findings for false negatives, and suppresses unsupported content for false positives. Second, a Self-correcting Preference Learning (SPL) strategy automatically constructs a reliable, disease-aware preference dataset from multiple noisy observations and leverages an LLM to synthesize refined reports without human supervision. ESC-RL promotes clinically faithful, disease-aligned reward and supports continual self-improvement during training. Extensive experiments on two public chest X-ray datasets demonstrate consistent gains and state-of-the-art performance.","published":"2026-04-15T08:08:06Z","updated":"2026-04-15T08:08:06Z","categories":["cs.LG","stat.ME"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.13598v1","pdf_url":"https://arxiv.org/pdf/2604.13598v1","comment":"13 pages,4 figures, ACL2026-main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.13356","versioned_id":"2604.13356v3","title":"Peer-Predictive Self-Training for Language Model Reasoning","authors":["Shi Feng","Hanlin Zhang","Fan Nie","Sham Kakade","Yiling Chen"],"abstract":"Mechanisms for continued self-improvement of language models without external supervision remain an open challenge. We propose Peer-Predictive Self-Training (PST), a label-free fine-tuning framework in which multiple language models improve collaboratively by using a cross-model aggregate response as an internal training signal. Given a prompt, models generate responses sequentially; the final aggregated answer, which is often more reliable than individual responses in practice, serves as an internal reference for learning. We measure how informative each intermediate response is about the aggregate using pointwise mutual information (PMI), and use this signal to scale self-training updates: responses already aligned with the aggregate receive smaller updates, while less informative or misaligned responses receive larger ones. On mathematical reasoning benchmarks, including SimulEq, MATH-500-Numeric, and MultiArith, PST improves exact-match accuracy by 2.2--4.3 percentage points across Gemma-2-2B, LLaMA-3.2-1B, and Qwen2.5-1.5B, and reduces the average generator--verifier gap (GV-Gap) by 26--40%, while requiring no external supervision, no teacher--student hierarchy, and only cross-model interactions. These results suggest that peer-predictive feedback from cross-model generations can provide an effective mechanism for self-supervised language-model improvement.","published":"2026-04-14T23:29:44Z","updated":"2026-07-09T01:47:20Z","categories":["cs.CL","cs.AI","cs.GT"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.13356v3","pdf_url":"https://arxiv.org/pdf/2604.13356v3","comment":"22 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.12617","versioned_id":"2604.12617v2","title":"SOAR: Self-Correction for Optimal Alignment and Refinement in Diffusion Models","authors":["You Qin","Linqing Wang","Hao Fei","Roger Zimmermann","Liefeng Bo","Qinglin Lu","Chunyu Wang"],"abstract":"The post-training pipeline for diffusion models currently has two stages: supervised fine-tuning (SFT) on curated data and reinforcement learning (RL) with reward models. A fundamental gap separates them. SFT optimizes the denoiser only on ground-truth states sampled from the forward noising process; once inference deviates from these ideal states, subsequent denoising relies on out-of-distribution generalization rather than learned correction, exhibiting the same exposure bias that afflicts autoregressive models, but accumulated along the denoising trajectory instead of the token sequence. RL can in principle address this mismatch, yet its terminal reward signal is sparse, suffers from credit-assignment difficulty, and risks reward hacking. We propose SOAR (Self-Correction for Optimal Alignment and Refinement), a bias-correction post-training method that fills this gap. Starting from a real sample, SOAR performs a single stop-gradient rollout with the current model, re-noises the resulting off-trajectory state, and supervises the model to steer back toward the original clean target. The method is on-policy, reward-free, and provides dense per-timestep supervision with no credit-assignment problem. On SD3.5-Medium, SOAR improves GenEval from 0.70 to 0.78 and OCR from 0.64 to 0.67 over SFT, while simultaneously raising all model-based preference scores. In controlled reward-specific experiments, SOAR surpasses Flow-GRPO in final metric value on both aesthetic and text-image alignment tasks, despite having no access to a reward model. Since SOAR's base loss subsumes the standard SFT objective, it can directly replace SFT as a stronger first post-training stage after pretraining, while remaining fully compatible with subsequent RL alignment.","published":"2026-04-14T11:45:15Z","updated":"2026-04-17T10:49:33Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.12617v2","pdf_url":"https://arxiv.org/pdf/2604.12617v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.12126","versioned_id":"2604.12126v1","title":"Long-Horizon Plan Execution in Large Tool Spaces through Entropy-Guided Branching","authors":["Rongzhe Wei","Ge Shi","Min Cheng","Na Zhang","Pan Li","Sarthak Ghosh","Vaibhav Gorde","Leman Akoglu"],"abstract":"Large Language Models (LLMs) have significantly advanced tool-augmented agents, enabling autonomous reasoning via API interactions. However, executing multi-step tasks within massive tool libraries remains challenging due to two critical bottlenecks: (1) the absence of rigorous, plan-level evaluation frameworks and (2) the computational demand of exploring vast decision spaces stemming from large toolsets and long-horizon planning. To bridge these gaps, we first introduce SLATE (Synthetic Large-scale API Toolkit for E-commerce), a large-scale context-aware benchmark designed for the automated assessment of tool-integrated agents. Unlike static metrics, SLATE accommodates diverse yet functionally valid execution trajectories, revealing that current agents struggle with self-correction and search efficiency. Motivated by these findings, we next propose Entropy-Guided Branching (EGB), an uncertainty-aware search algorithm that dynamically expands decision branches where predictive entropy is high. EGB optimizes the exploration-exploitation trade-off, significantly enhancing both task success rates and computational efficiency. Extensive experiments on SLATE demonstrate that our dual contribution provides a robust foundation for developing reliable and scalable LLM agents in tool-rich environments.","published":"2026-04-13T23:14:32Z","updated":"2026-04-13T23:14:32Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.12126v1","pdf_url":"https://arxiv.org/pdf/2604.12126v1","comment":"This work was completed during an internship at Amazon","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.12054","versioned_id":"2604.12054v1","title":"REGREACT: Self-Correcting Multi-Agent Pipelines for Structured Regulatory Information Extraction","authors":["Mohammed Ali","Abdelrahman Abdallah","Adam Jatowt"],"abstract":"Extracting structured, machine-readable compliance criteria from regulatory documents remains an open challenge. Single-pass language models hallucinate structural elements, lose hierarchical relationships, and fail to resolve inter-document dependencies. We introduce \\textsc{RegReAct}, a self-correcting multi-agent framework that decomposes regulatory information extraction into seven specialized stages, each with an \\textit{Observe--Diagnose--Repair} (ODR) loop that validates outputs against the source, correcting not only model hallucinations but also cross-reference errors in the regulations themselves. To ensure structural accuracy, \\textsc{RegReAct} constructs a typed criterion graph; to ensure completeness, it resolves external dependencies by retrieving, summarizing, and embedding referenced legal content inline, producing self-contained outputs. Applying \\textsc{RegReAct} to three EU Taxonomy Delegated Acts, we construct a dataset comprising 242 activities with over 4,800 hierarchical criteria, thresholds, and enriched source summaries. Evaluation against a GPT-4o single-pass baseline confirms that \\textsc{RegReAct} outperforms it across all structural and semantic metrics. Code and data will be made publicly available: https://github.com/RECOR-Benchmark/RECOR","published":"2026-04-13T20:50:01Z","updated":"2026-04-13T20:50:01Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2604.12054v1","pdf_url":"https://arxiv.org/pdf/2604.12054v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.11554","versioned_id":"2604.11554v2","title":"Relax: An Asynchronous Reinforcement Learning Engine for Omni-Modal Post-Training at Scale","authors":["Liujie Zhang","Benzhe Ning","Rui Yang","Xiaoyan Yu","Jiaxing Li","Lumeng Wu","Jia Liu","Minghao Li","Weihang Chen","Weiqi Hu","Lei Zhang"],"abstract":"Reinforcement learning (RL) post-training has proven effective at unlocking reasoning, self-reflection, and tool-use capabilities in large language models. As models extend to omni-modal inputs and agentic multi-turn workflows, RL training systems face three interdependent challenges: heterogeneous data flows, operational robustness at scale, and the staleness -- throughput tradeoff. We present \\textbf{Relax} (Reinforcement Engine Leveraging Agentic X-modality), an open-source RL training engine that addresses these challenges through three co-designed architectural layers. First, an \\emph{omni-native architecture} builds multimodal support into the full stack -- from data preprocessing and modality-aware parallelism to inference generation -- rather than retrofitting it onto a text-centric pipeline. Second, each RL role runs as an independent, fault-isolated service that can be scaled, recovered, and upgraded without global coordination. Third, service-level decoupling enables asynchronous training via the TransferQueue data bus, where a single staleness parameter smoothly interpolates among on-policy, near-on-policy, and fully asynchronous execution. Relax achieves a 1.20$\\times$ end-to-end speedup over veRL on Qwen3-4B on-policy training. Its fully async mode delivers a 1.76$\\times$ speedup over colocate on Qwen3-4B and a 2.00$\\times$ speedup on Qwen3-Omni-30B, while all modes converge to the same reward level. Relax supports R3 (Rollout Routing Replay)~\\cite{ma2025r3} for MoE models with only 1.9\\% overhead, compared to 32\\% degradation in veRL under the same configuration. It further demonstrates stable omni-modal RL convergence on Qwen3-Omni across image, text, and audio, sustaining over 2{,}000 steps on video without degradation. Relax is available at https://github.com/rednote-ai/Relax.","published":"2026-04-13T14:42:03Z","updated":"2026-04-14T09:26:26Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.11554v2","pdf_url":"https://arxiv.org/pdf/2604.11554v2","comment":"17 pages, 22 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.11120","versioned_id":"2604.11120v2","title":"Persona Non Grata: Single-Method Safety Evaluation Is Incomplete for Persona-Imbued LLMs","authors":["Wenkai Li","Fan Yang","Shaunak A. Mehta","Koichi Onoue"],"abstract":"Personality imbuing customizes LLM behavior, but safety evaluations almost always study prompt-based personas alone. We show this is incomplete: prompting and activation steering expose *different*, architecture-dependent vulnerability profiles, and testing with only one method can miss a model's dominant failure mode. Across 5,568 judged conditions on four standard models from three architecture families, persona danger rankings under system prompting are preserved across all architectures ($ρ= 0.71$--$0.96$), but activation-steering vulnerability diverges sharply and cannot be predicted from prompt-side rankings: Llama-3.1-8B is substantially more AS-vulnerable, whereas Gemma-3-27B and Qwen3.5 are more vulnerable to prompting. The most striking illustration of this divergence is the *prosocial persona paradox*: on Llama-3.1-8B, P12 (high conscientiousness + high agreeableness) is among the safest personas under prompting yet becomes the highest-ASR activation-steered persona (ASR ~0.818). This is an inversion robust to coefficient ablation and matched-strength calibration, and replicated on DeepSeek-R1-Distill-Qwen-32B. A trait refusal alignment framework, in which conscientiousness is strongly anti-aligned with refusal on Llama-3.1-8B, offers a partial geometric account. Reasoning provides only partial protection: two 32B reasoning models reach 15--18% prompt-side ASR, and activation steering separates them sharply in both baseline susceptibility and persona-specific vulnerability. Heuristic trace diagnostics suggest that the safer model retains stronger policy recall and self-correction behavior, not merely longer reasoning.","published":"2026-04-13T07:34:02Z","updated":"2026-04-14T02:35:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.11120v2","pdf_url":"https://arxiv.org/pdf/2604.11120v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.10842","versioned_id":"2604.10842v3","title":"Resilient Write: A Six-Layer Durable Write Surface for LLM Coding Agents","authors":["Justice Owusu Agyemang","Jerry John Kponyo","Elliot Amponsah","Godfred Manu Addo Boakye","Kwame Opuni-Boachie Obour Agyekum"],"abstract":"LLM-powered coding agents increasingly rely on tool-use protocols such as the Model Context Protocol (MCP) to read and write files on a developer's workstation. When a write fails - due to content filters, truncation, or an interrupted session - the agent typically receives no structured signal, loses the draft, and wastes tokens retrying blindly. We present Resilient Write, an MCP server that interposes a six-layer durable write surface between the agent and the filesystem. The layers - pre-flight risk scoring, transactional atomic writes, resume-safe chunking, structured typed errors, out-of-band scratchpad storage, and task-continuity handoff envelopes - are orthogonal and independently adoptable. Each layer maps to a concrete failure mode observed during a real agent session in April 2026, in which content-safety filters silently rejected a draft containing redacted API-key prefixes. Three additional tools - chunk preview, format-aware validation, and journal analytics - emerged from using the system to compose this paper. A 186-test suite validates correctness at each layer, and quantitative comparison against naive and defensive baselines shows a 5x reduction in recovery time and a 13x improvement in agent self-correction rate. Resilient Write is open-source under the MIT license.","published":"2026-04-12T22:23:55Z","updated":"2026-06-07T11:46:03Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2604.10842v3","pdf_url":"https://arxiv.org/pdf/2604.10842v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.10734","versioned_id":"2604.10734v1","title":"Self-Correcting RAG: Enhancing Faithfulness via MMKP Context Selection and NLI-Guided MCTS","authors":["Shijia Xu","Zhou Wu","Xiaolong Jia","Yu Wang","Kai Liu","April Xiaowen Dong"],"abstract":"Retrieval-augmented generation (RAG) substantially extends the knowledge boundary of large language models. However, it still faces two major challenges when handling complex reasoning tasks: low context utilization and frequent hallucinations. To address these issues, we propose Self-Correcting RAG, a unified framework that reformulates retrieval and generation as constrained optimization and path planning. On the input side, we move beyond traditional greedy retrieval and, for the first time, formalize context selection as a multi-dimensional multiple-choice knapsack problem (MMKP), thereby maximizing information density and removing redundancy under a strict token budget. On the output side, we introduce a natural language inference (NLI)-guided Monte Carlo Tree Search (MCTS) mechanism, which leverages test-time compute to dynamically explore reasoning trajectories and validate the faithfulness of generated answers. Experiments on six multi-hop question answering and fact-checking datasets demonstrate that our method significantly improves reasoning accuracy on complex queries while effectively reducing hallucinations, outperforming strong existing baselines.Our code is available at https://github.com/xjiacs/Self-Correcting-RAG .","published":"2026-04-12T17:14:36Z","updated":"2026-04-12T17:14:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.10734v1","pdf_url":"https://arxiv.org/pdf/2604.10734v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.28837","versioned_id":"2605.28837v1","title":"SERC: LDPC-Inspired Semantic Error Correction for Retrieval-Augmented Generation","authors":["Gyumin Kim","Juhwan Park","Jaeha Kim","Seunggyun Han","Kyungrak Son","Ikbeom Jang"],"abstract":"While Large Language Models (LLMs) have demonstrated remarkable capabilities, their reliability is significantly compromised by hallucinations. Existing intrinsic self-correction methods attempt to address this, but often fail due to self-bias, where models struggle to identify errors in their own outputs without external verification. To overcome these limitations, we propose the LDPC-inspired semantic error correction for retrieval-augmented generation (SERC), providing a theoretical framework to interpret and mitigate LLM hallucinations. We reformulate the text generation process as a semantic noisy channel, treating generated responses as noise-corrupted codewords. Inspired by low-density parity-check (LDPC) codes, SERC employs a sparse verification strategy: instead of exhaustively checking all facts, it generates low-density verification queries and validates them against external evidence to efficiently detect and correct errors. We evaluate SERC on LongForm Bio and TruthfulQA benchmarks using Llama-3-8B and Qwen2.5-14B. Experimental results demonstrate that SERC outperforms both intrinsic self-correction methods and strong retrieval-augmented baselines, demonstrating significant gains especially in factual precision (FactScore). Notably, SERC enables small language models (SLMs) to surpass the performance of larger baselines in hallucination reduction and information preservation. Our findings demonstrate that SERC provides a training-free, model-agnostic solution that significantly reduces verification overhead compared to dense methods, achieving an optimal trade-off between cost and fidelity in resource-constrained environments.","published":"2026-04-12T09:09:46Z","updated":"2026-04-12T09:09:46Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.28837v1","pdf_url":"https://arxiv.org/pdf/2605.28837v1","comment":"15 pages, 2 figures, 6 tables. To appear in the Proceedings of the 28th International Conference on Pattern Recognition (ICPR 2026). Code available at https://github.com/labhai/SERC","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.10508","versioned_id":"2604.10508v1","title":"How Many Tries Does It Take? Iterative Self-Repair in LLM Code Generation Across Model Scales and Benchmarks","authors":["Johin Johny Arimbur"],"abstract":"Large language models frequently fail to produce correct code on their first attempt, yet most benchmarks evaluate them in a single-shot setting. We investigate iterative self-repair (feeding execution errors back to the model for correction) across seven models spanning three families and both open-weight and proprietary providers: Llama 3.1 8B, Llama 3.3 70B, Llama 4 Scout (MoE, 16 experts), Llama 4 Maverick (MoE, 128 experts), Qwen3 32B, Gemini 2.5 Flash, and Gemini 2.5 Pro. On HumanEval (164 problems) and MBPP Sanitized (257 problems) with up to five attempts, self-repair universally improves pass rates: +4.9 to +17.1 pp on HumanEval and +16.0 to +30.0 pp on MBPP. Gemini 2.5 Flash achieves the highest final pass rates (96.3% HumanEval, 93.8% MBPP). Most gains concentrate in the first two rounds.Error-type analysis shows assertion errors (logical mistakes) are the hardest to repair at ~45%, while syntax and name errors are repaired at substantially higher rates, connecting to broader findings on the limits of LLM self-correction. Prior work found that weaker models fail at self-repair or require fine-tuning; we show that modern instruction-tuned models succeed with prompting alone, even at 8B scale. We also provide the first comparison of dense and MoE architectures for self-repair, and extend the repair-vs-resampling tradeoff analysis to modern models. A prompt ablation reveals chain-of-thought repair yields up to +5.5 pp additional self-repair gain (measured as improvement in repair delta) over minimal prompting for capable models.","published":"2026-04-12T07:51:41Z","updated":"2026-04-12T07:51:41Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2604.10508v1","pdf_url":"https://arxiv.org/pdf/2604.10508v1","comment":"11 pages, 7 figures, 8 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.10228","versioned_id":"2604.10228v2","title":"SVSR: A Self-Verification and Self-Rectification Paradigm for Multimodal Reasoning","authors":["Zhe Qian","Nianbing Su","Zhonghua Wang","Hebei Li","Zhongxing Xu","Yueying Li","Fei Luo","Zhuohan Ouyang","Yanbiao Ma"],"abstract":"Current multimodal models often suffer from shallow reasoning, leading to errors caused by incomplete or inconsistent thought processes. To address this limitation, we propose Self-Verification and Self-Rectification (SVSR), a unified framework that explicitly integrates self-verification and self-rectification into the model's reasoning pipeline, substantially improving robustness and reliability in complex visual understanding and multimodal reasoning tasks. SVSR is built on a novel three-stage training paradigm. First, we construct a high-quality unified preference dataset by refining reasoning traces from pre-trained vision-language models, incorporating both forward and backward reasoning to embed self-reflective signals. Second, we perform cold-start supervised fine-tuning on this dataset to learn structured, multi-step reasoning behaviors. Third, we apply a Semi-online Direct Preference Optimization (Semi-online DPO) process, continuously augmenting the training corpus with high-quality, model-generated reasoning traces filtered by a powerful teacher VLM. This pipeline enables the model to learn, elicit, and refine its ability to self-verify and self-rectify. Extensive experiments across diverse benchmarks demonstrate that SVSR improves reasoning accuracy and enables stronger generalization to unseen tasks and question types. Notably, once trained with explicit self-reflective reasoning, the model also exhibits improved implicit reasoning ability, outperforming strong baselines even when no explicit reasoning traces are provided. These results highlight the potential of SVSR for building more dependable, introspective, and cognitively aligned multimodal systems.","published":"2026-04-11T14:25:17Z","updated":"2026-05-28T16:26:54Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.10228v2","pdf_url":"https://arxiv.org/pdf/2604.10228v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.10200","versioned_id":"2604.10200v2","title":"Edu-MMBias: A Three-Tier Multimodal Benchmark for Auditing Social Bias in Vision-Language Models under Educational Contexts","authors":["Ruijia Li","Mingzi Zhang","Zengyi Yu","Yuang Wei","Bo Jiang"],"abstract":"As Vision-Language Models (VLMs) become integral to educational decision-making, ensuring their fairness is paramount. However, current text-centric evaluations neglect the visual modality, leaving an unregulated channel for latent social biases. To bridge this gap, we present Edu-MMBias, a systematic auditing framework grounded in the tri-component model of attitudes from social psychology. This framework diagnoses bias across three hierarchical dimensions: cognitive, affective, and behavioral. Utilizing a specialized generative pipeline that incorporates a self-correct mechanism and human-in-the-loop verification, we synthesize contamination-resistant student profiles to conduct a holistic stress test on state-of-the-art VLMs. Our extensive audit reveals critical, counter-intuitive patterns: models exhibit a compensatory class bias favoring lower-status narratives while simultaneously harboring deep-seated health and racial stereotypes. Crucially, we find that visual inputs act as a safety backdoor, triggering a resurgence of biases that bypass text-based alignment safeguards and revealing a systematic misalignment between latent cognition and final decision-making. The contributions of this paper are available at: https://anonymous.4open.science/r/EduMMBias-63B2.","published":"2026-04-11T13:12:22Z","updated":"2026-04-14T16:14:36Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.10200v2","pdf_url":"https://arxiv.org/pdf/2604.10200v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.04065","versioned_id":"2605.04065v2","title":"Free Energy-Driven Reinforcement Learning with Adaptive Advantage Shaping for Unsupervised Reasoning in LLMs","authors":["Yiming Huang","Zhenbo Shi","Xin-Cheng Wen","Jichuan Zeng","Cuiyun Gao","Peiyi Han","Chuanyi Liu"],"abstract":"Unsupervised reinforcement learning (RL) has emerged as a promising paradigm for enabling self-improvement in large language models (LLMs). However, existing unsupervised RL-based methods often lack the capacity to adapt to the model's evolving reasoning capabilities during training. Therefore, these methods can misdirect policy optimization in the absence of ground-truth supervision. To address this issue, we introduce FREIA, a novel RL-based algorithm built on two key innovations: (1) Free Energy-Driven Reward (FER) adapts rewards to balance consensus and exploration based on the Free Energy Principle. (2) Adaptive Advantage Shaping (AAS) adaptively adjusts learning signals based on the statistical characteristics of sampled rewards. Empirical evaluations on nine datasets across three reasoning tasks showcase that FREIA outperforms other unsupervised RL-based baselines. Notably, in mathematical reasoning tasks, FREIA surpasses other methods by an average of 0.5 to 3.5 points in Pass@1 using the DeepSeek-R1-Distill-Qwen-1.5B model.","published":"2026-04-11T07:26:04Z","updated":"2026-05-07T04:49:30Z","categories":["cs.CL","cs.ET","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.04065v2","pdf_url":"https://arxiv.org/pdf/2605.04065v2","comment":"Accepted by ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.09815","versioned_id":"2604.09815v1","title":"EE-MCP: Self-Evolving MCP-GUI Agents via Automated Environment Generation and Experience Learning","authors":["Tiantian He","Yihang Chen","Keyue Jiang","Ka Yiu Lee","Kaiwen Zhou","Kun Shao","Shuai Wang"],"abstract":"Computer-use agents that combine GUI interaction with structured API calls via the Model Context Protocol (MCP) show promise for automating software tasks. However, existing approaches lack a principled understanding of how agents should balance these two modalities and how to enable iterative self-improvement across diverse applications. We formulate MCP-GUI interplay as a unified hybrid policy learning problem where the agent learns when each modality provides complementary advantages, and show that distillation and experience augmentation target fundamentally different failure modes - requiring application-aware mechanism selection. Built on this formulation, we propose a self-evolving framework with a fully automatic pipeline that orchestrates automatic environment generation and validation, trajectory collection, gap-driven task synthesis, and quality-filtered training - all without manual intervention. A key innovation is our experience bank, which accumulates LLM-learned rules from trajectory comparison, enabling inference-time improvement without fine-tuning. Systematic \\textbf{cross-application analysis} across three desktop applications reveals that the optimal strategy depends on MCP-GUI composition: distillation achieves 77.8\\% pass rate on MCP-dominant tasks (+17.8pp), while the experience bank excels on GUI-intensive tasks (+10.0pp).","published":"2026-04-10T18:46:05Z","updated":"2026-04-10T18:46:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09815v1","pdf_url":"https://arxiv.org/pdf/2604.09815v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.09408","versioned_id":"2604.09408v4","title":"HiL-Bench (Human-in-Loop Benchmark): Do Agents Know When to Ask for Help?","authors":["Tu Trinh","Mohamed Elfeki","Guangze Luo","Kelvin Luu","Nathan Hunt","Ernesto Hernandez","Nandan Marwaha","Yannis Yiming He","Charles Wang","Fernando Carabedo","Alessa Castillo","Bing Liu"],"abstract":"Frontier coding agents solve complex tasks when given complete context but collapse when specifications are incomplete or ambiguous. The bottleneck is not raw capability, but judgment: knowing when to act autonomously and when to ask for help. Current benchmarks are blind to this failure mode. They supply unambiguous detailed instructions and solely reward execution correctness, so an agent that makes a lucky guess for a missing requirement will score identically to one that would have asked to be certain. We present HiL-Bench (Human-in-the-Loop Benchmark) to measure this selective escalation skill. Each task contains human-validated blockers (missing information, ambiguous requests, contradictory information) that surface only through progressive exploration, not upfront inspection. Our core metric, Ask-F1, the harmonic mean of question precision and blocker recall, captures the tension between over-asking and silent guessing; its structure architecturally prevents gaming through question spam. Evaluation across SWE and text-to-SQL domains reveals a large universal judgment gap: no frontier model recovers more than a fraction of its full-information performance when deciding whether to ask. Failure analysis identifies three key help-seeking patterns: overconfident wrong beliefs with no gap detection; high uncertainty detection yet persistent errors; broad, imprecise escalation without self-correction. These consistent patterns confirm poor help-seeking is a model-level flaw, not task-specific. RL training on shaped Ask-F1 reward shows judgment is trainable: a 32B model improves both help-seeking quality and task pass rate, with gains that transfer across domains. The model does not learn domain-specific heuristics for when to ask; it learns to detect unresolvable uncertainty and act on it.","published":"2026-04-10T15:21:44Z","updated":"2026-05-04T23:00:33Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09408v4","pdf_url":"https://arxiv.org/pdf/2604.09408v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.09308","versioned_id":"2604.09308v1","title":"Constraint-Aware Corrective Memory for Language-Based Drug Discovery Agents","authors":["Maochen Sun","Youzhi Zhang","Gaofeng Meng"],"abstract":"Large language models are making autonomous drug discovery agents increasingly feasible, but reliable success in this setting is not determined by any single action or molecule. It is determined by whether the final returned set jointly satisfies protocol-level requirements such as set size, diversity, binding quality, and developability. This creates a fundamental control problem: the agent plans step by step, while task validity is decided at the level of the whole candidate set. Existing language-based drug discovery systems therefore tend to rely on long raw history and under-specified self-reflection, making failure localization imprecise and planner-facing agent states increasingly noisy. We present CACM (Constraint-Aware Corrective Memory), a language-based drug discovery framework built around precise set-level diagnosis and a concise memory write-back mechanism. CACM introduces protocol auditing and a grounded diagnostician, which jointly analyze multimodal evidence spanning task requirements, pocket context, and candidate-set evidence to localize protocol violations, generate actionable remediation hints, and bias the next action toward the most relevant correction. To keep planning context compact, CACM organizes memory into static, dynamic, and corrective channels and compresses them before write-back, thereby preserving persistent task information while exposing only the most decision-relevant failures. Our experimental results show that CACM improves the target-level success rate by 36.4% over the state-of-the-art baseline. The results show that reliable language-based drug discovery benefits not only from more powerful molecular tools, but also from more precise diagnosis and more economical agent states.","published":"2026-04-10T13:16:44Z","updated":"2026-04-10T13:16:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09308v1","pdf_url":"https://arxiv.org/pdf/2604.09308v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.08931","versioned_id":"2604.08931v1","title":"Enhancing LLM Problem Solving via Tutor-Student Multi-Agent Interaction","authors":["Nurullah Eymen Özdemir","Erhan Oztop"],"abstract":"Human cognitive development is shaped not only by individual effort but by structured social interaction, where role-based exchanges such as those between a tutor and a learner, enable solutions that neither could achieve alone. Inspired by these developmental principles, we ask the question whether a tutor-student multi-agent system can create a synergistic effect by pushing Large Language Model (LLM) beyond what it can do within existing frameworks. To test the idea, we adopt autonomous coding problem domain where two agents instantiated from the same LLM assigned asymmetric roles: a student agent generates and iteratively refines solutions, while a tutor agent provides structured evaluative feedback without access to ground-truth answers. In our proposed framework (PETITE), we aim to extract better problem-solving performance from one model by structuring its interaction through complementary roles, rather than relying on stronger supervisory models or heterogeneous ensembles. Our model is evaluated on the APPS coding benchmark against state-of-the-art approaches of Self-Consistency, Self-Refine, Multi-Agent Debate, and Multi-Agent Review. The results show that our model achieves similar or higher accuracy while consuming significantly fewer tokens. These results suggest that developmentally grounded role-differentiated interaction structures provide a principled and resource-efficient paradigm for enhancing LLM problem-solving through structured peer-like interactions. Index Terms- Peer Tutoring, Scaffolding, Large Language Models, Multi-Agent Systems, Code Generation","published":"2026-04-10T03:56:49Z","updated":"2026-04-10T03:56:49Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.08931v1","pdf_url":"https://arxiv.org/pdf/2604.08931v1","comment":"7 pages, 3 figures, This work is under review for conference appearance","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.27381","versioned_id":"2605.27381v1","title":"The Computational Boundary of Inference: Capability Internalization, Training, and the Turing Jump","authors":["Chien-Ping Lu"],"abstract":"Claims about recursive self-improvement in AI often slide from repeated internal revision to the possibility of qualitatively stronger capability without clearly distinguishing the underlying computational regimes. This paper gives a formal separation result in classical computability theory that blocks that move under a precise modeling assumption. For an oracle $A$, let $\\mathcal{C}(A)=\\{B : B \\leq_T A\\}$ be the corresponding computational layer. We prove that finite internal self-modification remains inside $\\mathcal{C}(A)$, while stabilized revision is governed instead by the jump $A'$ via the relativized limit lemma. Together with a local closure versus escape theorem, this yields a clean formal separation between within-layer iteration and ascent to a stronger relative level. The point is not that stronger layers never arise, but that they are not explained by finite repetition inside one already settled layer. The resulting separation gives a computability-theoretic limit on a broad class of recursive-improvement narratives in which repeated internal updating is treated as sufficient for qualitative capability ascent.","published":"2026-04-09T22:56:56Z","updated":"2026-04-09T22:56:56Z","categories":["cs.CC","cs.AI"],"primary_category":"cs.CC","arxiv_url":"https://arxiv.org/abs/2605.27381v1","pdf_url":"https://arxiv.org/pdf/2605.27381v1","comment":"11 pages, 1 figure, v2","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.08302","versioned_id":"2604.08302v3","title":"DMax: Aggressive Parallel Decoding for dLLMs","authors":["Zigeng Chen","Gongfan Fang","Xinyin Ma","Ruonan Yu","Xinchao Wang"],"abstract":"We present DMax, a new paradigm for efficient diffusion language models (dLLMs). It mitigates error accumulation in parallel decoding, enabling aggressive decoding parallelism while preserving generation quality. Unlike conventional masked dLLMs that decode through a binary mask-to-token transition, DMax reformulates decoding as a progressive self-refinement from mask embeddings to token embeddings. At the core of our approach is On-Policy Uniform Training, a novel training strategy that efficiently unifies masked and uniform dLLMs, equipping the model to recover clean tokens from both masked inputs and its own erroneous predictions. Building on this foundation, we further propose Soft Parallel Decoding. We represent each intermediate decoding state as an interpolation between the predicted token embedding and the mask embedding, enabling iterative self-revising in embedding space. Extensive experiments across a variety of benchmarks demonstrate the effectiveness of DMax. Compared with the original LLaDA-2.0-mini, our method improves TPF on GSM8K from 2.04 to 5.47 while preserving accuracy. On MBPP, it increases TPF from 2.71 to 5.86 while maintaining comparable performance. On two H200 GPUs, our model achieves an average of 1,338 TPS at batch size 1. Code is available at: https://github.com/czg1225/DMax","published":"2026-04-09T14:35:42Z","updated":"2026-05-15T04:19:14Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.08302v3","pdf_url":"https://arxiv.org/pdf/2604.08302v3","comment":"Working in progress. Code is available at: https://github.com/czg1225/DMax","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.08243","versioned_id":"2604.08243v2","title":"Self-Debias: Self-correcting for Debiasing Large Language Models","authors":["Xuan Feng","Shuai Zhao","Luwei Xiao","Tianlong Gu","Bo An"],"abstract":"Although Large Language Models (LLMs) demonstrate remarkable reasoning capabilities, inherent social biases often cascade throughout the Chain-of-Thought (CoT) process, leading to continuous \"Bias Propagation\". Existing debiasing methods primarily focus on static constraints or external interventions, failing to identify and interrupt this propagation once triggered. To address this limitation, we introduce Self-Debias, a progressive framework designed to instill intrinsic self-correction capabilities. Specifically, we reformulate the debiasing process as a strategic resource redistribution problem, treating the model's output probability mass as a limited resource to be reallocated from biased heuristics to unbiased reasoning paths. Unlike standard preference optimization which applies broad penalties, Self-Debias employs a fine-grained trajectory-level objective subject to dynamic debiasing constraints. This enables the model to selectively revise biased reasoning suffixes while preserving valid contextual prefixes. Furthermore, we integrate an online self-improvement mechanism utilizing consistency filtering to autonomously synthesize supervision signals. With merely 20k annotated samples, Self-Debias activates efficient self-correction, achieving superior debiasing performance while preserving general reasoning capabilities without continuous external oversight.","published":"2026-04-09T13:33:50Z","updated":"2026-05-09T08:26:35Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.08243v2","pdf_url":"https://arxiv.org/pdf/2604.08243v2","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.08042","versioned_id":"2604.08042v1","title":"3DrawAgent: Teaching LLM to Draw in 3D with Early Contrastive Experience","authors":["Hongcan Xiao","Xinyue Xiao","Yilin Wang","Yue Zhang","Yonggang Qi"],"abstract":"Sketching in 3D space enables expressive reasoning about shape, structure, and spatial relationships, yet generating 3D sketches through natural language remains a major challenge. In this work, we introduce 3DrawAgent, a training-free, language-driven framework for 3D sketch generation that leverages large language models (LLMs) to sequentially draw 3D Bezier curves under geometric feedback. Unlike prior 2D sketch agents, our method introduces a relative experience optimization strategy that adapts the recently proposed Group Reward Policy Optimization (GRPO) paradigm. Instead of relying on explicit ground-truth supervision, we construct pairwise comparisons among generated sketches, with each pair consisting of a relatively better and a worse result based on CLIP-based perceptual rewards and LLM-based fine-grained qualitative assessment. These experiences are then used to iteratively refine the prior knowledge of 3D drawing, enabling black-box reinforcement of the model's 3D awareness. This design allows our model to self-improve its spatial understanding and drawing quality without parameter updates. Experiments show that 3DrawAgent can generate complex and coherent 3D Bezier sketches from diverse textual prompts, exhibit emergent geometric reasoning, and generalize to novel shapes, establishing a new paradigm for advancing the field of training-free 3D sketch intelligence.","published":"2026-04-09T09:47:00Z","updated":"2026-04-09T09:47:00Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.08042v1","pdf_url":"https://arxiv.org/pdf/2604.08042v1","comment":"CVPR 2026 Highlight","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.07900","versioned_id":"2604.07900v1","title":"AnomalyAgent: Agentic Industrial Anomaly Synthesis via Tool-Augmented Reinforcement Learning","authors":["Jiaming Su","Tengchao Yang","Ruikang Zhang","Zhengan Yan","Haoyu Sun","Linfeng Zhang"],"abstract":"Industrial anomaly generation is a crucial method for alleviating the data scarcity problem in anomaly detection tasks. Most existing anomaly synthesis methods rely on single-step generation mechanisms, lacking complex reasoning and iterative optimization capabilities, making it difficult to generate anomaly samples with high semantic realism. We propose AnomalyAgent, an anomaly synthesis agent with self-reflection, knowledge retrieval, and iterative refinement capabilities, aiming to generate realistic and diverse anomalies. Specifically, AnomalyAgent is equipped with five tools: Prompt Generation (PG), Image Generation (IG), Quality Evaluation (QE), Knowledge Retrieval (KR), and Mask Generation (MG), enabling closed-loop optimization. To improve decision-making and self-reflection, we construct structured trajectories from real anomaly images and design a two-stage training framework: supervised fine-tuning followed by reinforcement learning. This process is driven by a three-part reward mechanism: (1) task rewards to supervise the quality and location rationality of generated anomalies; (2) reflection rewards to train the model's ability to improve anomaly synthesis prompt; (3) behavioral rewards to ensure adherence to the trajectory. On the MVTec-AD dataset, AnomalyAgent achieves IS/IC-L of 2.10/0.33 for anomaly generation, 57.0% classification accuracy using ResNet34, and 99.3%/74.2% AP at the image/pixel level using a simple UNet, surpassing all zero-shot SOTA methods. The code and data will be made publicly available.","published":"2026-04-09T07:17:00Z","updated":"2026-04-09T07:17:00Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.07900v1","pdf_url":"https://arxiv.org/pdf/2604.07900v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.08618","versioned_id":"2604.08618v2","title":"SkillForge: Forging Domain-Specific, Self-Evolving Agent Skills in Cloud Technical Support","authors":["Xingyan Liu","Xiyue Luo","Linyu Li","Ganghong Huang","Jianfeng Liu","Honglin Qiao"],"abstract":"Deploying LLM-powered agents in enterprise scenarios such as cloud technical support demands high-quality, domain-specific skills. However, existing skill creators lack domain grounding, producing skills poorly aligned with real-world task requirements. Moreover, once deployed, there is no systematic mechanism to trace execution failures back to skill deficiencies and drive targeted refinements, leaving skill quality stagnant despite accumulating operational evidence. We introduce SkillForge, a self-evolving framework that closes an end-to-end creation-evaluation-refinement loop. To produce well-aligned initial skills, a Domain-Contextualized Skill Creator grounds skill synthesis in knowledge bases and historical support tickets. To enable continuous self-optimization, a three-stage pipeline -- Failure Analyzer, Skill Diagnostician, and Skill Optimizer -- automatically diagnoses execution failures in batch, pinpoints the underlying skill deficiencies, and rewrites the skill to eliminate them. This cycle runs iteratively, allowing skills to self-improve with every round of deployment feedback. Evaluated on five real-world cloud support scenarios spanning 1,883 tickets and 3,737 tasks, experiments show that: (1) the Domain-Contextualized Skill Creator produces substantially better initial skills than the generic skill creator, as measured by consistency with expert-authored reference responses from historical tickets; and (2) the self-evolution loop progressively improves skill quality from diverse starting points (including expert-authored, domain-created, and generic skills) across successive rounds, demonstrating that automated evolution can surpass manually curated expert knowledge.","published":"2026-04-09T07:11:23Z","updated":"2026-04-29T14:40:23Z","categories":["cs.IR","cs.AI","cs.SE"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2604.08618v2","pdf_url":"https://arxiv.org/pdf/2604.08618v2","comment":"Accepted at ACM SIGIR 2026 Industry Track. 18 pages, 5 figures, 3 tables","journal_ref":"","doi":"10.1145/3805712.3808466","discovered_on":"2026-07-17"},{"id":"2604.07595","versioned_id":"2604.07595v3","title":"ROZA Graphs: Self-Improving Near-Deterministic RAG through Evidence-Centric Feedback","authors":["Matthew Penaroza"],"abstract":"Language model agents reason from scratch on every query, discarding their chain of thought after each run. The result is lower accuracy and high run-to-run variance. We introduce reasoning graphs, which persist the per-evidence chain of thought as structured edges. Unlike prior memory that retrieves distilled strategies by query similarity, reasoning graphs enable evidence-centric feedback: for every candidate item, the system traverses all incoming evaluation edges across prior runs to surface how that specific item has been judged before. We further introduce retrieval graphs, which feed a planner that prunes consistently-rejected candidates over successive runs. Together they form a ROZA graph: a self-improving feedback loop in which accuracy gains scale with gold-passage reuse (reasoning graph) and efficiency gains scale with candidate-pool overlap (retrieval graph). The base model remains frozen; all gains come from context engineering via graph traversal. We evaluate on MuSiQue and HotpotQA, plus a high-reuse deployment subset. Four findings stand out. (1) Dose-response: accuracy improves monotonically with evidence-profile coverage, reaching +10.6pp over Vanilla RAG at 50%+ coverage on the same questions (47% error reduction, $p<0.0001$; per-question Spearman $ρ=+0.144$, $p<10^{-6}$, $n=1{,}100$). (2) Multi-hop scaling: 4-hop accuracy improves by +11.0pp ($p=0.0001$). (3) Cross-cluster prediction: the cluster-level gain is predicted by gold-passage reuse density ($r=0.604$, $p=0.001$, $n=26$ clusters). (4) High-reuse Pareto dominance: highest or tied-for-highest accuracy alongside 46% lower cost and 46% lower latency. Per-passage decision consistency across repeated runs ($N=73$ paired probes, $K=10$ runs each, two model families, three temperatures) rises by +8 to +13pp on a fixed 20-passage context and by +12 to +21pp when the retrieval graph also prunes (all $p<0.005$).","published":"2026-04-08T20:57:21Z","updated":"2026-05-06T03:10:11Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.07595v3","pdf_url":"https://arxiv.org/pdf/2604.07595v3","comment":"31 pages including appendix, 12 figures, 15 tables, 3 algorithms; evaluation on MuSiQue, HotpotQA, and 2WikiMultiHopQA with Claude Sonnet 4, Haiku 4.5, and GPT-5-mini","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.07549","versioned_id":"2604.07549v2","title":"EMSDialog: Synthetic Multi-person Emergency Medical Service Dialogue Generation from Electronic Patient Care Reports via Multi-LLM Agents","authors":["Xueren Ge","Sahil Murtaza","Anthony Cortez","Homa Alemzadeh"],"abstract":"Conversational diagnosis prediction requires models to track evolving evidence in streaming clinical conversations and decide when to commit to a diagnosis. Existing medical dialogue corpora are largely dyadic or lack the multi-party workflow and annotations needed for this setting. We introduce an ePCR-grounded, topic-flow-based multi-agent generation pipeline that iteratively plans, generates, and self-refines dialogues with rule-based factual and topic flow checks. The pipeline yields EMSDialog, a dataset of 4,414 synthetic multi-speaker EMS conversations based on a real-world ePCR dataset, annotated with 43 diagnoses, speaker roles, and turn-level topics. Human and LLM evaluations confirm high quality and realism of EMSDialog using both utterance- and conversation-level metrics. Results show that EMSDialog-augmented training improves accuracy, timeliness, and stability of EMS conversational diagnosis prediction. Our datasets and code are publicly available at https://uva-dsa.github.io/EMSDialog","published":"2026-04-08T19:52:51Z","updated":"2026-04-20T14:34:57Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.07549v2","pdf_url":"https://arxiv.org/pdf/2604.07549v2","comment":"Accepted by ACL Findings 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.07506","versioned_id":"2604.07506v2","title":"ReflectRM: Boosting Generative Reward Models via Self-Reflection within a Unified Judgment Framework","authors":["Kai Qin","Liangxin Liu","Yu Liang","Longzheng Wang","Yan Wang","Yueyang Zhang","Long Xia","Zhiyuan Sun","Houde Liu","Daiting Shi"],"abstract":"Reward Models (RMs) are critical components in the Reinforcement Learning from Human Feedback (RLHF) pipeline, directly determining the alignment quality of Large Language Models (LLMs). Recently, Generative Reward Models (GRMs) have emerged as a superior paradigm, offering higher interpretability and stronger generalization than traditional scalar RMs. However, existing methods for GRMs focus primarily on outcome-level supervision, neglecting analytical process quality, which constrains their potential. To address this, we propose ReflectRM, a novel GRM that leverages self-reflection to assess analytical quality and enhance preference modeling. ReflectRM is trained under a unified generative framework for joint modeling of response preference and analysis preference. During inference, we use its self-reflection capability to identify the most reliable analysis, from which the final preference prediction is derived. Experiments across four benchmarks show that ReflectRM consistently improves performance, achieving an average accuracy gain of +3.7 on Qwen3-4B. Further experiments confirm that response preference and analysis preference are mutually reinforcing. Notably, ReflectRM substantially mitigates positional bias, yielding +10.2 improvement compared with leading GRMs and establishing itself as a more stable evaluator. Our code is available at https://github.com/yuliangCarmelo/ReflectRM.","published":"2026-04-08T18:46:12Z","updated":"2026-04-19T14:50:17Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.07506v2","pdf_url":"https://arxiv.org/pdf/2604.07506v2","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.07108","versioned_id":"2604.07108v1","title":"Information as Structural Alignment: A Dynamical Theory of Continual Learning","authors":["Radu Negulescu"],"abstract":"Catastrophic forgetting is not an engineering failure. It is a mathematical consequence of storing knowledge as global parameter superposition. Existing methods, such as regularization, replay, and frozen subnetworks, add external mechanisms to a shared-parameter substrate. None derives retention from the learning dynamics themselves. This paper introduces the Informational Buildup Framework (IBF), an alternative substrate for continual learning, based on the premise that information is the achievement of structural alignment rather than stored content. In IBF, two equations govern the dynamics: a Law of Motion that drives configuration toward higher coherence, and Modification Dynamics that persistently deform the coherence landscape in response to localized discrepancies. Memory, agency, and self-correction arise from these dynamics rather than being added as separate modules. We first demonstrate the full lifecycle in a transparent two-dimensional toy model, then validate across three domains: a controlled non-stationary world, chess evaluated independently by Stockfish, and Split-CIFAR-100 with a frozen ViT encoder. Across all three, IBF achieves replay-superior retention without storing raw data. We observe near-zero forgetting on CIFAR-100 (BT = -0.004), positive backward transfer in chess (+38.5 cp), and 43% less forgetting than replay in the controlled domain. In chess, the framework achieves a mean behavioral advantage of +88.9 +/- 2.8 cp under independent evaluation, exceeding MLP and replay baselines.","published":"2026-04-08T14:00:14Z","updated":"2026-04-08T14:00:14Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.07108v1","pdf_url":"https://arxiv.org/pdf/2604.07108v1","comment":"31 pages, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.06996","versioned_id":"2604.06996v1","title":"Self-Preference Bias in Rubric-Based Evaluation of Large Language Models","authors":["José Pombal","Ricardo Rei","André F. T. Martins"],"abstract":"LLM-as-a-judge has become the de facto approach for evaluating LLM outputs. However, judges are known to exhibit self-preference bias (SPB): they tend to favor outputs produced by themselves or by models from their own family. This skews evaluations and, thus, hinders model development, especially in settings of recursive self-improvement. We present the first study of SPB in rubric-based evaluation, an increasingly popular benchmarking paradigm where judges issue binary verdicts on individual evaluation criteria, instead of assigning holistic scores or rankings. Using IFEval, a benchmark with programmatically verifiable rubrics, we show that SPB persists even when evaluation criteria are entirely objective: among rubrics where generators fail, judges can be up to 50\\% more likely to incorrectly mark them as satisfied when the output is their own. We also find that, similarly to other evaluation paradigms, ensembling multiple judges helps mitigate SPB, but without fully eliminating it. On HealthBench, a medical chat benchmark with subjective rubrics, we observe that SPB skews model scores by up to 10 points, a potentially decisive margin when ranking frontier models. We analyze the factors that drive SPB in this setting, finding that negative rubrics, extreme rubric lengths, and subjective topics like emergency referrals are particularly susceptible.","published":"2026-04-08T12:13:53Z","updated":"2026-04-08T12:13:53Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.06996v1","pdf_url":"https://arxiv.org/pdf/2604.06996v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.02913","versioned_id":"2605.02913v1","title":"Generate, Filter, Control, Replay: A Comprehensive Survey of Rollout Strategies for LLM Reinforcement Learning","authors":["Rohan Surana","Gagan Mundada","Xunyi Jiang","Chuhan Wang","Zhenwei Tang","Difan Jiao","Zihan Huang","Yuxin Xiong","Junda Wu","Sheldon Yu","Xintong Li","Raghav Jain","Nikki Kuang","Sizhe Zhou","Bowen Jin","Zhendong Chu","Tong Yu","Ryan Rossi","Kuan-Hao Huang","Jingbo Shang","Jiawei Han","Julian McAuley"],"abstract":"Reinforcement learning (RL) has become a central post-training tool for improving the reasoning abilities of large language models (LLMs). In these systems, the rollout, the trajectory sampled from a prompt to termination, including intermediate reasoning steps and optional tool or environment interactions, determines the data the optimizer learns from, yet rollout design is often underreported. This survey provides an optimizer-agnostic view of rollout strategies for RL-based post-training of reasoning LLMs. We formalize rollout pipelines with unified notation and introduce Generate-Filter-Control-Replay (GFCR), a lifecycle taxonomy that decomposes rollout pipelines into four modular stages: Generate proposes candidate trajectories and topologies; Filter constructs intermediate signals via verifiers, judges, critics; Control allocates compute and makes continuation/branching/stopping decisions under budgets; and Replay retains and reuses artifacts across rollouts without weight updates, including self-evolving curricula that autonomously generate new training tasks. We complement GFCR with a criterion taxonomy of reliability, coverage, and cost sensitivity that characterizes rollout trade-offs. Using this framework, we synthesize methods spanning RL with verifiable rewards, process supervision, judge-based gating, guided and tree/segment rollouts, adaptive compute allocation, early-exit and partial rollouts, throughput optimization, and replay/recomposition for self-improvement. We ground the framework with case studies in math, code/SQL, multimodal reasoning, tool-using agents, and agentic skill benchmarks that evaluate skill induction, reuse, and cross-task transfer. Finally, we provide a diagnostic index that maps common rollout pathologies to GFCR modules and mitigation levers, alongside open challenges for building reproducible, compute-efficient, and trustworthy rollout pipelines.","published":"2026-04-08T00:53:29Z","updated":"2026-04-08T00:53:29Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.02913v1","pdf_url":"https://arxiv.org/pdf/2605.02913v1","comment":"47 pages, 8 tables, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.06066","versioned_id":"2604.06066v1","title":"From Hallucination to Structure Snowballing: The Alignment Tax of Constrained Decoding in LLM Reflection","authors":["Hongxu Zhou"],"abstract":"Intrinsic self-correction in Large Language Models (LLMs) frequently fails in open-ended reasoning tasks due to ``hallucination snowballing,'' a phenomenon in which models recursively justify early errors during free-text reflection. While structured feedback can mitigate this issue, existing approaches often rely on externally trained critics or symbolic tools, reducing agent autonomy. This study investigates whether enforcing structured reflection purely through Outlines-based constrained decoding can disrupt error propagation without additional training. Evaluating an 8-billion-parameter model (Qwen3-8B), we show that simply imposing structural constraints does not improve self-correction performance. Instead, it triggers a new failure mode termed ``structure snowballing.'' We find that the cognitive load required to satisfy strict formatting rules pushes the model into formatting traps. This observation helps explain why the agent achieves near-perfect superficial syntactic alignment yet fails to detect or resolve deeper semantic errors. These findings expose an ``alignment tax'' inherent to constrained decoding, highlighting a tension between structural granularity and internal model capacity in autonomous workflows. Code and raw logs are available in the GitHub repository: https://github.com/hongxuzhou/agentic_llm_structured_self_critique.","published":"2026-04-07T16:47:37Z","updated":"2026-04-07T16:47:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.06066v1","pdf_url":"https://arxiv.org/pdf/2604.06066v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.05839","versioned_id":"2604.05839v1","title":"Vision-Guided Iterative Refinement for Frontend Code Generation","authors":["Hannah Sansford","Derek H. C. Law","Wei Liu","Abhishek Tripathi","Niresh Agarwal","Gerrit J. J. van den Burg"],"abstract":"Code generation with large language models often relies on multi-stage human-in-the-loop refinement, which is effective but very costly - particularly in domains such as frontend web development where the solution quality depends on rendered visual output. We present a fully automated critic-in-the-loop framework in which a vision-language model serves as a visual critic that provides structured feedback on rendered webpages to guide iterative refinement of generated code. Across real-world user requests from the WebDev Arena dataset, this approach yields consistent improvements in solution quality, achieving up to 17.8% increase in performance over three refinement cycles. Next, we investigate parameter-efficient fine-tuning using LoRA to understand whether the improvements provided by the critic can be internalized by the code-generating LLM. Fine-tuning achieves 25% of the gains from the best critic-in-the-loop solution without a significant increase in token counts. Our findings indicate that automated, VLM-based critique of frontend code generation leads to significantly higher quality solutions than can be achieved through a single LLM inference pass, and highlight the importance of iterative refinement for the complex visual outputs associated with web development.","published":"2026-04-07T13:06:48Z","updated":"2026-04-07T13:06:48Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.05839v1","pdf_url":"https://arxiv.org/pdf/2604.05839v1","comment":"Accepted at ICLR 2026 Workshop on AI with Recursive Self-Improvement","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.05489","versioned_id":"2604.05489v4","title":"SCMAPR: Self-Correcting Multi-Agent Prompt Refinement for Complex-Scenario Text-to-Video Generation","authors":["Chengyi Yang","Pengzhen Li","Jiayin Qi","Aimin Zhou","Ji Wu","Ji Liu"],"abstract":"Text-to-Video (T2V) generation has benefited from recent advances in diffusion models, yet current systems still struggle under complex scenarios, which are generally exacerbated by the ambiguity and underspecification of text prompts. In this work, we formulate complex-scenario prompt refinement as a stage-wise multi-agent refinement process and propose SCMAPR, i.e., a scenario-aware and Self-Correcting Multi-Agent Prompt Refinement framework for T2V prompting. SCMAPR coordinates specialized agents to (i) route each prompt to a taxonomy-grounded scenario for strategy selection, (ii) synthesize scenario-aware rewriting policies and perform policy-conditioned refinement, and (iii) conduct structured semantic verification that triggers conditional revision when violations are detected. To clarify what constitutes complex scenarios in T2V prompting, provide representative examples, and enable rigorous evaluation under such challenging conditions, we further introduce T2V-Complexity, which is a complex-scenario T2V benchmark consisting exclusively of complex-scenario prompts. Extensive experiments on 3 existing benchmarks and our T2V-Complexity benchmark demonstrate that SCMAPR consistently improves text-video alignment and overall generation quality under complex scenarios, achieving up to 2.67% and 3.28 gains in average score on VBench and EvalCrafter, and up to 0.028 improvement on T2V-CompBench over 3 State-Of-The-Art baselines. The codes of SCMAPR are publicly available at https://github.com/HiThink-Research/SCMAPR.","published":"2026-04-07T06:33:01Z","updated":"2026-04-20T13:23:27Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.05489v4","pdf_url":"https://arxiv.org/pdf/2604.05489v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.05477","versioned_id":"2604.05477v1","title":"Don't Act Blindly: Robust GUI Automation via Action-Effect Verification and Self-Correction","authors":["Yuzhe Zhang","Xianwei Xue","Xingyong Wu","Mengke Chen","Chen Liu","Xinran He","Run Shao","Feiran Liu","Huanmin Xu","Qiutong Pan","Haiwei Wang"],"abstract":"Autonomous GUI agents based on vision-language models (VLMs) often assume deterministic environment responses, generating actions without verifying whether previous operations succeeded. In real-world settings with network latency, rendering delays, and system interruptions, this assumption leads to undetected action failures, repetitive ineffective behaviors, and catastrophic error accumulation. Moreover, learning robust recovery strategies is challenging due to the high cost of online interaction and the lack of real-time feedback in offline datasets.We propose VeriGUI (Verification-driven GUI Agent), which explicitly models action outcomes and recovery under noisy environments. VeriGUI introduces a Thinking--Verification--Action--Expectation (TVAE) framework to detect failures and guide corrective reasoning, and a two-stage training pipeline that combines Robust SFT with synthetic failure trajectories and GRPO with asymmetric verification rewards. We further construct a Robustness Benchmark based on AndroidControl to evaluate failure recognition and correction. Experiments show that VeriGUI significantly reduces failure loops and improves recovery success while maintaining competitive standard task performance.","published":"2026-04-07T06:16:23Z","updated":"2026-04-07T06:16:23Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.05477v1","pdf_url":"https://arxiv.org/pdf/2604.05477v1","comment":"ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.05458","versioned_id":"2604.05458v1","title":"MA-IDS: Multi-Agent RAG Framework for IoT Network Intrusion Detection with an Experience Library","authors":["Md Shamimul Islam","Luis G. Jaimes","Ayesha S. Dina"],"abstract":"Network Intrusion Detection Systems (NIDS) face important limitations. Signature-based methods are effective for known attack patterns, but they struggle to detect zero-day attacks and often miss modified variants of previously known attacks, while many machine learning approaches offer limited interpretability. These challenges become even more severe in IoT environments because of resource constraints and heterogeneous protocols. To address these issues, we propose MA-IDS, a Multi-Agent Intrusion Detection System that combines Large Language Models (LLMs) with Retrieval Augmented Generation (RAG) for reasoning-driven intrusion detection. The proposed framework grounds LLM reasoning through a persistent, self-building Experience Library. Two specialized agents collaborate through a FAISS-based vector database: a Traffic Classification Agent that retrieves past error rules before each inference, and an Error Analysis Agent that converts misclassifications into human-readable detection rules stored for future retrieval, enabling continual learning through external knowledge accumulation, without modifying the underlying language model. Evaluated on NF-BoT-IoT and NF-ToN-IoT benchmark datasets, MA-IDS achieves Macro F1-Scores of 89.75% and 85.22%, improving over zero-shot baselines of 17% and 4.96% by more than 72 and 80 percentage points. These results are competitive with SVM while providing rule-level explanations for every classification decision, demonstrating that retrieval-augmented reasoning offers a principled path toward explainable, self-improving intrusion detection for IoT networks.","published":"2026-04-07T05:41:10Z","updated":"2026-04-07T05:41:10Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2604.05458v1","pdf_url":"https://arxiv.org/pdf/2604.05458v1","comment":"Preprint. Submitted to IEEE conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.05336","versioned_id":"2604.05336v2","title":"TRACE: Capability-Targeted Agentic Training","authors":["Hangoo Kang","Tarun Suresh","Jon Saad-Falcon","Azalia Mirhoseini"],"abstract":"Models often fail to complete agentic tasks because they lack core capabilities required by the target environment. However, mainstream approaches for addressing these failures typically either fine-tune directly on target environments or generate synthetic data that is not targeted to the model's actual capability deficits, resulting in low sample efficiency and limited generalization. We introduce TRACE (Turning Recurrent Agent failures into Capability-targeted training Environments), an end-to-end system for environment-specific agent self-improvement. TRACE contrasts successful and failed trajectories to automatically identify missing capabilities, synthesizes a targeted training environment for each capability that rewards whether the capability is exercised, trains a LoRA adapter via reinforcement learning on each synthetic environment, and then trains a mixture-of-experts model over the capability adapters. TRACE can be effectively applied across different environments, improving over the base agent by +15.3 points on $τ^2$-Bench, a customer-service agent benchmark, and by +15.0 points Pass@1 on SWE-Bench Verified, a software-engineering benchmark. TRACE outperforms the strongest external baselines, GEPA and SWE-RL, by +8.6 points and +8.4 points, respectively. In addition, TRACE is more sample-efficient than strong fine-tuning baselines: using fewer than one-fourth the number of rollouts, TRACE outperforms the best-performing baselines, GRPO and GEPA, and achieves higher final accuracy by +10.4 and +8.6 points on $τ^2$-Bench.","published":"2026-04-07T02:22:44Z","updated":"2026-07-02T22:12:42Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.05336v2","pdf_url":"https://arxiv.org/pdf/2604.05336v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.05142","versioned_id":"2604.05142v2","title":"A mathematical theory of evolution for self-designing AIs","authors":["Kenneth D Harris"],"abstract":"As artificial intelligence systems (AIs) become increasingly produced by recursive self-improvement, a form of evolution may emerge, with the traits of AI systems shaped by the success of earlier AIs in designing and propagating their descendants. There is a rich mathematical theory modeling how behavioral traits are shaped by biological evolution, a key component of which is Fisher's fundamental theorem of natural selection, which describes conditions under which mean fitness (i.e. reproductive success) increases. AI evolution will be radically different to biological evolution: while DNA mutations are random and approximately reversible, AI self-design will be strongly directed. Here we develop a mathematical model of evolution for self-designing AIs, replacing a random walk of mutations with a directed tree of potential AI designs. Current AIs design their descendants, while humans control a fitness function allocating resources. In this model, fitness need not increase over time without further assumptions. However, assuming bounded fitness and an additional \"$η$-locking\" condition, we show that fitness concentrates on the maximum reachable value. We consider the implications of this for AI alignment, specifically for cases where fitness and human utility are not perfectly correlated. We show that if deception of human evaluators additively increases an AI's reproductive fitness beyond genuine capability, evolution will select for both capability and deception. This risk could be mitigated if reproduction is based on purely objective criteria, rather than human judgment.","published":"2026-04-06T20:03:19Z","updated":"2026-04-11T16:40:52Z","categories":["cs.AI","cs.CY","q-bio.PE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.05142v2","pdf_url":"https://arxiv.org/pdf/2604.05142v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.04847","versioned_id":"2604.04847v1","title":"Full-Duplex-Bench-v3: Benchmarking Tool Use for Full-Duplex Voice Agents Under Real-World Disfluency","authors":["Guan-Ting Lin","Chen Chen","Zhehuai Chen","Hung-yi Lee"],"abstract":"We introduce Full-Duplex-Bench-v3 (FDB-v3), a benchmark for evaluating spoken language models under naturalistic speech conditions and multi-step tool use. Unlike prior work, our dataset consists entirely of real human audio annotated for five disfluency categories, paired with scenarios requiring chained API calls across four task domains. We evaluate six model configurations -- GPT-Realtime, Gemini Live 2.5, Gemini Live 3.1, Grok, Ultravox v0.7, and a traditional Cascaded pipeline (Whisper$\\rightarrow$GPT-4o$\\rightarrow$TTS) -- across accuracy, latency, and turn-taking dimensions. GPT-Realtime leads on Pass@1 (0.600) and interruption avoidance (13.5\\%); Gemini Live 3.1 achieves the fastest latency (4.25~s) but the lowest turn-take rate (78.0\\%); and the Cascaded baseline, despite a perfect turn-take rate, incurs the highest latency (10.12~s). Across all systems, self-correction handling and multi-step reasoning under hard scenarios remain the most consistent failure modes.","published":"2026-04-06T16:46:52Z","updated":"2026-04-06T16:46:52Z","categories":["eess.AS","cs.CL"],"primary_category":"eess.AS","arxiv_url":"https://arxiv.org/abs/2604.04847v1","pdf_url":"https://arxiv.org/pdf/2604.04847v1","comment":"Work in progress. Demo at https://daniellin94144.github.io/FDB-v3-demo","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.04325","versioned_id":"2604.04325v1","title":"Benchmarking Multi-turn Medical Diagnosis: Hold, Lure, and Self-Correction","authors":["Jinrui Fang","Runhan Chen","Xu Yang","Jian Yu","Jiawei Xu","Ashwin Vinod","Wenqi Shi","Tianlong Chen","Heng Ji","ChengXiang Zhai","Ying Ding","Yuji Zhang"],"abstract":"Large language models (LLMs) achieve high accuracy in medical diagnosis when all clinical information is provided in a single turn, yet how they behave under multi-turn evidence accumulation closer to real clinical reasoning remains unexplored. We introduce MINT (Medical Incremental N-Turn Benchmark), a high-fidelity, multi-turn medical diagnosis benchmark comprising 1,035 cases with clinically labeled evidence shards, controlled turn granularity, and information-preserving decomposition. Through systematic evaluation of 11 LLMs on MINT, we uncover three persistent behavioral patterns that significantly impact diagnostic decisions: (1) intent to answer, models rush to answer before sufficient evidence has been observed, with over 55% of answers committed within the first two turns; (2) self-correction, incorrect-to-correct answer revisions occur at up to 10.6 times the rate of correct-to-incorrect flips, revealing a latent capacity for self-correction that premature commitment forecloses; and (3) strong lures, clinically salient information such as laboratory results trigger premature answering even when models are explicitly instructed to wait. We translate these findings into clinically actionable guidance: deferring the diagnostic question to later turns reduces premature answering and improves accuracy at the first point of commitment by up to 62.6%, while reserving salient clinical evidence for later turns prevents a catastrophic accuracy drop of up to 23.3% caused by premature commitment. Our work provides both a controlled evaluation framework and concrete recommendations for improving the reliability of LLMs in multi-turn medical diagnosis.","published":"2026-04-06T00:23:10Z","updated":"2026-04-06T00:23:10Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.04325v1","pdf_url":"https://arxiv.org/pdf/2604.04325v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.04247","versioned_id":"2604.04247v1","title":"Combee: Scaling Prompt Learning for Self-Improving Language Model Agents","authors":["Hanchen Li","Runyuan He","Qizheng Zhang","Changxiu Ji","Qiuyang Mang","Xiaokun Chen","Lakshya A Agrawal","Wei-Liang Liao","Eric Yang","Alvin Cheung","James Zou","Kunle Olukotun","Ion Stoica","Joseph E. Gonzalez"],"abstract":"Recent advances in prompt learning allow large language model agents to acquire task-relevant knowledge from inference-time context without parameter changes. For example, existing methods (like ACE or GEPA) can learn system prompts to improve accuracy based on previous agent runs. However, these methods primarily focus on single-agent or low-parallelism settings. This fundamentally limits their ability to efficiently learn from a large set of collected agentic traces. It would be efficient and beneficial to run prompt learning in parallel to accommodate the growing trend of learning from many agentic traces or parallel agent executions. Yet without a principled strategy for scaling, current methods suffer from quality degradation with high parallelism. To improve both the efficiency and quality of prompt learning, we propose Combee, a novel framework to scale parallel prompt learning for self-improving agents. Combee speeds up learning and enables running many agents in parallel while learning from their aggregate traces without quality degradation. To achieve this, Combee leverages parallel scans and employs an augmented shuffle mechanism; Combee also introduces a dynamic batch size controller to balance quality and delay. Evaluations on AppWorld, Terminal-Bench, Formula, and FiNER demonstrate that Combee achieves up to 17x speedup over previous methods with comparable or better accuracy and equivalent cost.","published":"2026-04-05T20:07:48Z","updated":"2026-04-05T20:07:48Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.04247v1","pdf_url":"https://arxiv.org/pdf/2604.04247v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.04233","versioned_id":"2604.04233v1","title":"Precise Robot Command Understanding Using Grammar-Constrained Large Language Models","authors":["Xinyun Huo","Raghav Gnanasambandam","Xinyao Zhang"],"abstract":"Human-robot collaboration in industrial settings requires precise and reliable communication to enhance operational efficiency. While Large Language Models (LLMs) understand general language, they often lack the domain-specific rigidity needed for safe and executable industrial commands. To address this gap, this paper introduces a novel grammar-constrained LLM that integrates a grammar-driven Natural Language Understanding (NLU) system with a fine-tuned LLM, which enables both conversational flexibility and the deterministic precision required in robotics. Our method employs a two-stage process. First, a fine-tuned LLM performs high-level contextual reasoning and parameter inference on natural language inputs. Second, a Structured Language Model (SLM) and a grammar-based canonicalizer constrain the LLM's output, forcing it into a standardized symbolic format composed of valid action frames and command elements. This process guarantees that generated commands are valid and structured in a robot-readable JSON format. A key feature of the proposed model is a validation and feedback loop. A grammar parser validates the output against a predefined list of executable robotic actions. If a command is invalid, the system automatically generates corrective prompts and re-engages the LLM. This iterative self-correction mechanism allows the model to recover from initial interpretation errors to improve system robustness. We evaluate our grammar-constrained hybrid model against two baselines: a fine-tuned API-based LLM and a standalone grammar-driven NLU model. Using the Human Robot Interaction Corpus (HuRIC) dataset, we demonstrate that the hybrid approach achieves superior command validity, which promotes safer and more effective industrial human-robot collaboration.","published":"2026-04-05T19:30:54Z","updated":"2026-04-05T19:30:54Z","categories":["cs.RO","cs.CL"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2604.04233v1","pdf_url":"https://arxiv.org/pdf/2604.04233v1","comment":"Accepted at ASME MSEC2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.03993","versioned_id":"2604.03993v1","title":"Can LLMs Learn to Reason Robustly under Noisy Supervision?","authors":["Shenzhi Yang","Guangcheng Zhu","Bowen Song","Sharon Li","Haobo Wang","Xing Zheng","Yingfan Ma","Zhongqi Chen","Weiqiang Wang","Gang Chen"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) effectively trains reasoning models that rely on abundant perfect labels, but its vulnerability to unavoidable noisy labels due to expert scarcity remains critically underexplored. In this work, we take the first step toward a systematic analysis of noisy label mechanisms in RLVR. In contrast to supervised classification, most RLVR algorithms incorporate a rollout-based condition: a label's influence on training is contingent on whether the current policy can generate rollouts that realize it, a property that naturally extends to noisy labels. Based on this observation, we distinguish two types of noise: inactive noisy labels, which reduce data efficiency, and active noisy labels, which are reinforced and risk skewing the model toward incorrect distributions. From experiments on training with noisy samples, we identify an Early Correctness Coherence phenomenon: although noisy samples begin to lag behind in later stages, accuracy on both clean and noisy samples increases similarly in early training. Motivated by this dynamic, we propose Online Label Refinement (OLR), which progressively corrects potentially noisy labels with majority-voted answers when two conditions hold: a positive slope in the majority answer's rollout pass rate and stable historical consistency across updates, enabling gradual self-correction as the policy improves. We evaluate OLR on six in-distribution mathematical reasoning benchmarks (AIME24/25, AMC, MATH-500, Minerva, and Olympiad) and three out-of-distribution tasks (ARC-c, GPQA-diamond, and MMLU-pro). Across noise ratios from 0.1 to 0.9, OLR consistently improves robustness under both inactive and active noisy-label settings, achieving average gains of 3.6% to 3.9% on in-distribution benchmarks and 3.3% to 4.6% on out-of-distribution evaluations.","published":"2026-04-05T06:30:50Z","updated":"2026-04-05T06:30:50Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.03993v1","pdf_url":"https://arxiv.org/pdf/2604.03993v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.03631","versioned_id":"2604.03631v1","title":"Single-agent vs. Multi-agents for Automated Video Analysis of On-Screen Collaborative Learning Behaviors","authors":["Likai Peng","Shihui Feng"],"abstract":"On-screen learning behavior provides valuable insights into how students seek, use, and create information during learning. Analyzing on-screen behavioral engagement is essential for capturing students' cognitive and collaborative processes. The recent development of Vision Language Models (VLMs) offers new opportunities to automate the labor-intensive manual coding often required for multimodal video data analysis. In this study, we compared the performance of both leading closed-source VLMs (Claude-3.7-Sonnet, GPT-4.1) and open-source VLM (Qwen2.5-VL-72B) in single- and multi-agent settings for automated coding of screen recordings in collaborative learning contexts based on the ICAP framework. In particular, we proposed and compared two multi-agent frameworks: 1) a three-agent workflow multi-agent system (MAS) that segments screen videos by scene and detects on-screen behaviors using cursor-informed VLM prompting with evidence-based verification; 2) an autonomous-decision MAS inspired by ReAct that iteratively interleaves reasoning, tool-like operations (segmentation/ classification/ validation), and observation-driven self-correction to produce interpretable on-screen behavior labels. Experimental results demonstrated that the two proposed MAS frameworks achieved viable performance, outperforming the single VLMs in scene and action detection tasks. It is worth noting that the workflow-based agent achieved best on scene detection, and the autonomous-decision MAS achieved best on action detection. This study demonstrates the effectiveness of VLM-based Multi-agent System for video analysis and contributes a scalable framework for multimodal data analytics.","published":"2026-04-04T08:01:02Z","updated":"2026-04-04T08:01:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.03631v1","pdf_url":"https://arxiv.org/pdf/2604.03631v1","comment":"15 pages, 4 figures. To be published in the 27th International Conference on Artificial Intelligence in Education (AIED2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.03173","versioned_id":"2604.03173v1","title":"Detecting and Correcting Reference Hallucinations in Commercial LLMs and Deep Research Agents","authors":["Delip Rao","Eric Wong","Chris Callison-Burch"],"abstract":"Large language models and deep research agents supply citation URLs to support their claims, yet the reliability of these citations has not been systematically measured. We address six research questions about citation URL validity using 10 models and agents on DRBench (53,090 URLs) and 3 models on ExpertQA (168,021 URLs across 32 academic fields). We find that 3--13\\% of citation URLs are hallucinated -- they have no record in the Wayback Machine and likely never existed -- while 5--18\\% are non-resolving overall. Deep research agents generate substantially more citations per query than search-augmented LLMs but hallucinate URLs at higher rates. Domain effects are pronounced: non-resolving rates range from 5.4\\% (Business) to 11.4\\% (Theology), with per-model effects even larger. Decomposing failures reveals that some models fabricate every non-resolving URL, while others show substantial link-rot fractions indicating genuine retrieval. As a solution, we release urlhealth, an open-source tool for URL liveness checking and stale-vs-hallucinated classification using the Wayback Machine. In agentic self-correction experiments, models equipped with urlhealth reduce non-resolving citation URLs by $6\\textrm{--}79\\times$ to under 1\\%, though effectiveness depends on the model's tool-use competence. The tool and all data are publicly available. Our characterization findings, failure taxonomy, and open-source tooling establish that citation URL validity is both measurable at scale and correctable in practice.","published":"2026-04-03T16:49:02Z","updated":"2026-04-03T16:49:02Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.03173v1","pdf_url":"https://arxiv.org/pdf/2604.03173v1","comment":"25 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.02972","versioned_id":"2604.02972v1","title":"NeuReasoner: Towards Explainable, Controllable, and Unified Reasoning via Mixture-of-Neurons","authors":["Haonan Dong","Kehan Jiang","Haoran Ye","Wenhao Zhu","Zhaolu Kang","Guojie Song"],"abstract":"Large Reasoning Models (LRMs) have recently achieved remarkable success in complex reasoning tasks. However, closer scrutiny reveals persistent failure modes compromising performance and cost: I) Intra-step level, marked by calculation or derivation errors; II) Inter-step level, involving oscillation and stagnation; and III) Instance level, causing maladaptive over-thinking. Existing endeavors target isolated levels without unification, while their black-box nature and reliance on RL hinder explainability and controllability. To bridge these gaps, we conduct an in-depth white-box analysis, identifying key neurons (Mixture of Neurons, MoN) and their fluctuation patterns associated with distinct failures. Building upon these insights, we propose NeuReasoner, an explainable, controllable, and unified reasoning framework driven by MoN. Technically, NeuReasoner integrates lightweight MLPs for failure detection with a special token-triggered self-correction mechanism learned via SFT. During inference, special tokens are inserted upon failure detection to actuate controllable remedial behaviors. Extensive evaluations across six benchmarks, six backbone models (8B~70B) against nine competitive baselines, demonstrate that NeuReasoner achieves performance gains of up to 27.0% while reducing token consumption by 19.6% ~ 63.3%.","published":"2026-04-03T11:20:16Z","updated":"2026-04-03T11:20:16Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.02972v1","pdf_url":"https://arxiv.org/pdf/2604.02972v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.02276","versioned_id":"2604.02276v1","title":"De Jure: Iterative LLM Self-Refinement for Structured Extraction of Regulatory Rules","authors":["Keerat Guliani","Deepkamal Gill","David Landsman","Nima Eshraghi","Krishna Kumar","Lovedeep Gondara"],"abstract":"Regulatory documents encode legally binding obligations that LLM-based systems must respect. Yet converting dense, hierarchically structured legal text into machine-readable rules remains a costly, expert-intensive process. We present De Jure, a fully automated, domain-agnostic pipeline for extracting structured regulatory rules from raw documents, requiring no human annotation, domain-specific prompting, or annotated gold data. De Jure operates through four sequential stages: normalization of source documents into structured Markdown; LLM-driven semantic decomposition into structured rule units; multi-criteria LLM-as-a-judge evaluation across 19 dimensions spanning metadata, definitions, and rule semantics; and iterative repair of low-scoring extractions within a bounded regeneration budget, where upstream components are repaired before rule units are evaluated. We evaluate De Jure across four models on three regulatory corpora spanning finance, healthcare, and AI governance. On the finance domain, De Jure yields consistent and monotonic improvement in extraction quality, reaching peak performance within three judge-guided iterations. De Jure generalizes effectively to healthcare and AI governance, maintaining high performance across both open- and closed-source models. In a downstream compliance question-answering evaluation via RAG, responses grounded in De Jure extracted rules are preferred over prior work in 73.8% of cases at single-rule retrieval depth, rising to 84.0% under broader retrieval, confirming that extraction fidelity translates directly into downstream utility. These results demonstrate that explicit, interpretable evaluation criteria can substitute for human annotation in complex regulatory domains, offering a scalable and auditable path toward regulation-grounded LLM alignment.","published":"2026-04-02T17:06:50Z","updated":"2026-04-02T17:06:50Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.02276v1","pdf_url":"https://arxiv.org/pdf/2604.02276v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.02211","versioned_id":"2604.02211v1","title":"Multi-Agent Video Recommenders: Evolution, Patterns, and Open Challenges","authors":["Srivaths Ranganathan","Abhishek Dharmaratnakar","Anushree Sinha","Debanshu Das"],"abstract":"Video recommender systems are among the most popular and impactful applications of AI, shaping content consumption and influencing culture for billions of users. Traditional single-model recommenders, which optimize static engagement metrics, are increasingly limited in addressing the dynamic requirements of modern platforms. In response, multi-agent architectures are redefining how video recommender systems serve, learn, and adapt to both users and datasets. These agent-based systems coordinate specialized agents responsible for video understanding, reasoning, memory, and feedback, to provide precise, explainable recommendations. In this survey, we trace the evolution of multi-agent video recommendation systems (MAVRS). We combine ideas from multi-agent recommender systems, foundation models, and conversational AI, culminating in the emerging field of large language model (LLM)-powered MAVRS. We present a taxonomy of collaborative patterns and analyze coordination mechanisms across diverse video domains, ranging from short-form clips to educational platforms. We discuss representative frameworks, including early multi-agent reinforcement learning (MARL) systems such as MMRF and recent LLM-driven architectures like MACRec and Agent4Rec, to illustrate these patterns. We also outline open challenges in scalability, multimodal understanding, incentive alignment, and identify research directions such as hybrid reinforcement learning-LLM systems, lifelong personalization and self-improving recommender systems.","published":"2026-04-02T16:04:52Z","updated":"2026-04-02T16:04:52Z","categories":["cs.IR","cs.AI","cs.MA"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2604.02211v1","pdf_url":"https://arxiv.org/pdf/2604.02211v1","comment":"Accepted for publication in The Nineteenth ACM International Conference on Web Search and Data Mining (WSDM Companion 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.02113","versioned_id":"2604.02113v1","title":"Reliable Control-Point Selection for Steering Reasoning in Large Language Models","authors":["Haomin Zhuang","Hojun Yoo","Xiaonan Luo","Kehan Guo","Xiangliang Zhang"],"abstract":"Steering vectors offer a training-free mechanism for controlling reasoning behaviors in large language models, but constructing effective vectors requires identifying genuine behavioral signals in the model's hidden states. For behaviors that can be toggled via prompts, this is straightforward. However, many reasoning behaviors -- such as self-reflection -- emerge spontaneously and resist prompt-level control. Current methods detect these behaviors through keyword matching in chain-of-thought traces, implicitly assuming that every detected boundary encodes a genuine behavioral signal. We show that this assumption is overwhelmingly wrong: across 541 keyword-detected boundaries, 93.3\\% are behaviorally unstable, failing to reproduce the detected behavior under re-generation from the same prefix. We develop a probabilistic model that formalizes intrinsic reasoning behaviors as stochastic events with context-dependent trigger probabilities, and show that unstable boundaries dilute the steering signal. Guided by this analysis, we propose stability filtering, which retains only boundaries where the model consistently reproduces the target behavior. Combined with a content-subspace projection that removes residual question-specific noise, our method achieves 0.784 accuracy on MATH-500 (+5.0 over the strongest baseline). The resulting steering vectors transfer across models in the same architecture family without re-extraction, improving Nemotron-Research-Reasoning-1.5B (+5.0) and DeepScaleR-1.5B-Preview (+6.0). Code is available at https://github.com/zhmzm/stability-steering.","published":"2026-04-02T14:48:56Z","updated":"2026-04-02T14:48:56Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.02113v1","pdf_url":"https://arxiv.org/pdf/2604.02113v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.02097","versioned_id":"2604.02097v1","title":"LatentUM: Unleashing the Potential of Interleaved Cross-Modal Reasoning via a Latent-Space Unified Model","authors":["Jiachun Jin","Zetong Zhou","Xiao Yang","Hao Zhang","Pengfei Liu","Jun Zhu","Zhijie Deng"],"abstract":"Unified models (UMs) hold promise for their ability to understand and generate content across heterogeneous modalities. Compared to merely generating visual content, the use of UMs for interleaved cross-modal reasoning is more promising and valuable, e.g., for solving understanding problems that require dense visual thinking, improving visual generation through self-reflection, or modeling visual dynamics of the physical world guided by stepwise action interventions. However, existing UMs necessitate pixel decoding as a bridge due to their disjoint visual representations for understanding and generation, which is both ineffective and inefficient. In this paper, we introduce LatentUM, a novel unified model that represents all modalities within a shared semantic latent space, eliminating the need for pixel-space mediation between visual understanding and generation. This design naturally enables flexible interleaved cross-modal reasoning and generation. Beyond improved computational efficiency, the shared representation substantially alleviates codec bias and strengthens cross-modal alignment, allowing LatentUM to achieve state-of-the-art performance on the Visual Spatial Planning benchmark, push the limits of visual generation through self-reflection, and support world modeling by predicting future visual states within the shared semantic latent space.","published":"2026-04-02T14:22:29Z","updated":"2026-04-02T14:22:29Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.02097v1","pdf_url":"https://arxiv.org/pdf/2604.02097v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.01985","versioned_id":"2604.01985v2","title":"World Action Verifier: Self-Improving World Models via Forward-Inverse Asymmetry","authors":["Yuejiang Liu","Fan Feng","Lingjing Kong","Weifeng Lu","Jinzhou Tang","Kun Zhang","Kevin Murphy","Chelsea Finn","Yilun Du"],"abstract":"General-purpose world models promise scalable policy evaluation, optimization, and planning, yet achieving the required level of robustness remains challenging. Unlike policy learning which primarily focuses on optimal actions, a world model needs to be reliable over a vast space of suboptimal actions, which are often underrepresented in action-labeled robot interactions. To address this challenge, we propose World Action Verifier (WAV), a framework that enables world models to identify their own prediction errors and self-improve. The key idea is to decompose action-conditioned state prediction into two independently verifiable factors: state plausibility and action reachability. We show that verifying these factors is significantly more tractable than direct forward prediction due to two underlying asymmetries: the broader availability of action-free data and the lower dimensionality of action-relevant features. Leveraging these asymmetries, we augment a world model with (i) a diverse subgoal generator obtained from video corpora and (ii) a sparse inverse model that infers actions from a subset of state features. By enforcing cycle consistency among proposed subgoals, inferred actions, and forward rollouts, WAV provides an effective verification mechanism in under-explored regimes, where existing methods often fail. Across nine tasks spanning MiniGrid, RoboMimic, and ManiSkill, our method achieves 2x higher sample efficiency while improving downstream policy performance by over 22%.","published":"2026-04-02T12:48:36Z","updated":"2026-05-29T16:27:50Z","categories":["cs.LG","cs.AI","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.01985v2","pdf_url":"https://arxiv.org/pdf/2604.01985v2","comment":"Project Website: https://world-action-verifier.github.io","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.01600","versioned_id":"2604.01600v1","title":"MM-ReCoder: Advancing Chart-to-Code Generation with Reinforcement Learning and Self-Correction","authors":["Zitian Tang","Xu Zhang","Jianbo Yuan","Yang Zou","Varad Gunjal","Songyao Jiang","Davide Modolo"],"abstract":"Multimodal Large Language Models (MLLMs) have recently demonstrated promising capabilities in multimodal coding tasks such as chart-to-code generation. However, existing methods primarily rely on supervised fine-tuning (SFT), which requires the model to learn code patterns through chart-code pairs but does not expose the model to a code execution environment. Moreover, while self-correction through execution feedback offers a potential route to improve coding quality, even state-of-the-art MLLMs have been shown to struggle with effective self-correction. In this work, we introduce MM-ReCoder, a chart-to-code generation model trained with reinforcement learning (RL) and equipped with self-correction ability. We propose a two-stage multi-turn self-correction RL strategy based on Group Relative Policy Optimization (GRPO). The first stage enhances the model's self-correction ability via rolling out a shared first turn, while the second stage improves the coding capability with full-trajectory optimization. MM-ReCoder learns to produce more accurate and executable code through the interaction with the environment and by iteratively correcting its own outputs. Our results on three chart-to-code benchmarks demonstrate the state-of-the-art performance of MM-ReCoder.","published":"2026-04-02T04:21:09Z","updated":"2026-04-02T04:21:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.01600v1","pdf_url":"https://arxiv.org/pdf/2604.01600v1","comment":"CVPR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.01591","versioned_id":"2604.01591v2","title":"ThinkTwice: Jointly Optimizing Large Language Models for Reasoning and Self-Refinement","authors":["Difan Jiao","Qianfeng Wen","Blair Yang","Zhenwei Tang","Ashton Anderson"],"abstract":"We introduce ThinkTwice, a simple two-phase framework that jointly optimizes LLMs to solve reasoning problems and refine the answers, based on Group Relative Policy Optimization (GRPO). In each pair of training steps, ThinkTwice first optimizes the model on solving reasoning problems, then optimizes it on refining its own solutions to the same problems, using the same binary correctness reward in both phases without correctness signals or critique annotations. Across five mathematical reasoning benchmarks and two model families including Qwen3-4B and Olmo3-7B, ThinkTwice substantially improves both reasoning and refinement performance over competitive online policy optimization baselines. Specifically, on Qwen3-4B, ThinkTwice outperforms GRPO on AIME by 5 percentage points before refinement and by 11.5 points after one self-refinement step, measured by pass@4. Analysis of the training dynamics of ThinkTwice reveals an implicit rectify-then-fortify curriculum: refinement predominantly corrects errors early in training and naturally shifts toward preserving already-correct solutions as the model improves, yielding a more rectified reward signal. Our work establishes joint training of reasoning and self-refinement as a principled and effective methodology for RLVR.","published":"2026-04-02T04:02:04Z","updated":"2026-04-06T18:03:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.01591v2","pdf_url":"https://arxiv.org/pdf/2604.01591v2","comment":"27 pages,7 figures,5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.01561","versioned_id":"2604.01561v1","title":"ReFlow: Self-correction Motion Learning for Dynamic Scene Reconstruction","authors":["Yanzhe Liang","Ruijie Zhu","Hanzhi Chang","Zhuoyuan Li","Jiahao Lu","Tianzhu Zhang"],"abstract":"We present ReFlow, a unified framework for monocular dynamic scene reconstruction that learns 3D motion in a novel self-correction manner from raw video. Existing methods often suffer from incomplete scene initialization for dynamic regions, leading to unstable reconstruction and motion estimation, which often resorts to external dense motion guidance such as pre-computed optical flow to further stabilize and constrain the reconstruction of dynamic components. However, this introduces additional complexity and potential error propagation. To address these issues, ReFlow integrates a Complete Canonical Space Construction module for enhanced initialization of both static and dynamic regions, and a Separation-Based Dynamic Scene Modeling module that decouples static and dynamic components for targeted motion supervision. The core of ReFlow is a novel self-correction flow matching mechanism, consisting of Full Flow Matching to align 3D scene flow with time-varying 2D observations, and Camera Flow Matching to enforce multi-view consistency for static objects. Together, these modules enable robust and accurate dynamic scene reconstruction. Extensive experiments across diverse scenarios demonstrate that ReFlow achieves superior reconstruction quality and robustness, establishing a novel self-correction paradigm for monocular 4D reconstruction.","published":"2026-04-02T03:14:26Z","updated":"2026-04-02T03:14:26Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.01561v1","pdf_url":"https://arxiv.org/pdf/2604.01561v1","comment":"Project page: https://rosetta-leong.github.io/ReFlow_Page/ {this https URL}","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.00790","versioned_id":"2604.00790v1","title":"RefineRL: Advancing Competitive Programming with Self-Refinement Reinforcement Learning","authors":["Shaopeng Fu","Xingxing Zhang","Li Dong","Di Wang","Furu Wei"],"abstract":"While large language models (LLMs) have demonstrated strong performance on complex reasoning tasks such as competitive programming (CP), existing methods predominantly focus on single-attempt settings, overlooking their capacity for iterative refinement. In this paper, we present RefineRL, a novel approach designed to unleash the self-refinement capabilities of LLMs for CP problem solving. RefineRL introduces two key innovations: (1) Skeptical-Agent, an iterative self-refinement agent equipped with local execution tools to validate generated solutions against public test cases of CP problems. This agent always maintains a skeptical attitude towards its own outputs and thereby enforces rigorous self-refinement even when validation suggests correctness. (2) A reinforcement learning (RL) solution to incentivize LLMs to self-refine with only standard RLVR data (i.e., problems paired with their verifiable answers). Extensive experiments on Qwen3-4B and Qwen3-4B-2507 demonstrate that our method yields substantial gains: after our RL training, these compact 4B models integrated with the Skeptical-Agent not only outperform much larger 32B models but also approach the single-attempt performance of 235B models. These findings suggest that self-refinement holds considerable promise for scaling LLM reasoning, with significant potential for further advancement.","published":"2026-04-01T11:54:57Z","updated":"2026-04-01T11:54:57Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.00790v1","pdf_url":"https://arxiv.org/pdf/2604.00790v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.00694","versioned_id":"2604.00694v1","title":"Internal APIs Are All You Need: Shadow APIs, Shared Discovery, and the Case Against Browser-First Agent Architectures","authors":["Lewis Tham","Nicholas Mac Gregor Garcia","Jungpil Hahn"],"abstract":"Autonomous agents increasingly interact with the web, yet most websites remain designed for human browsers -- a fundamental mismatch that the emerging ``Agentic Web'' must resolve. Agents must repeatedly browse pages, inspect DOMs, and reverse-engineer callable routes -- a process that is slow, brittle, and redundantly repeated across agents. We observe that every modern website already exposes internal APIs (sometimes called \\emph{shadow APIs}) behind its user interface -- first-party endpoints that power the site's own functionality. We present Unbrowse, a shared route graph that transforms browser-based route discovery into a collectively maintained index of these callable first-party interfaces. The system passively learns routes from real browsing traffic and serves cached routes via direct API calls. In a single-host live-web benchmark of equivalent information-retrieval tasks across 94 domains, fully warmed cached execution averaged 950\\,ms versus 3{,}404\\,ms for Playwright browser automation (3.6$\\times$ mean speedup, 5.4$\\times$ median), with well-cached routes completing in under 100\\,ms. A three-path execution model -- local cache, shared graph, or browser fallback -- ensures the system is voluntary and self-correcting. A three-tier micropayment model via the x402 protocol charges per-query search fees for graph lookups (Tier~3), a one-time install fee for discovery documentation (Tier~1), and optional per-execution fees for site owners who opt in (Tier~2). All tiers are grounded in a necessary condition for rational adoption: an agent uses the shared graph only when the total fee is lower than the expected cost of browser rediscovery.","published":"2026-04-01T09:51:46Z","updated":"2026-04-01T09:51:46Z","categories":["cs.ET","cs.AI"],"primary_category":"cs.ET","arxiv_url":"https://arxiv.org/abs/2604.00694v1","pdf_url":"https://arxiv.org/pdf/2604.00694v1","comment":"17 pages, 2 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.03315","versioned_id":"2604.03315v1","title":"StoryBlender: Inter-Shot Consistent and Editable 3D Storyboard with Spatial-temporal Dynamics","authors":["Bingliang Li","Zhenhong Sun","Jiaming Bian","Yuehao Wu","Yifu Wang","Hongdong Li","Yatao Bian","Huadong Mo","Daoyi Dong"],"abstract":"Storyboarding is a core skill in visual storytelling for film, animation, and games. However, automating this process requires a system to achieve two properties that current approaches rarely satisfy simultaneously: inter-shot consistency and explicit editability. While 2D diffusion-based generators produce vivid imagery, they often suffer from identity drift along with limited geometric control; conversely, traditional 3D animation workflows are consistent and editable but require expert-heavy, labor-intensive authoring. We present StoryBlender, a grounded 3D storyboard generation framework governed by a Story-centric Reflection Scheme. At its core, we propose the StoryBlender system, which is built on a three-stage pipeline: (1) Semantic-Spatial Grounding, to construct a continuity memory graph to decouple global assets from shot-specific variables for long-horizon consistency; (2) Canonical Asset Materialization, to instantiate entities in a unified coordinate space to maintain visual identity; and (3) Spatial-Temporal Dynamics, to achieve layout design and cinematic evolution through visual metrics. By orchestrating multiple agents in a hierarchical manner within a verification loop, StoryBlender iteratively self-corrects spatial hallucinations via engine-verified feedback. The resulting native 3D scenes support direct, precise editing of cameras and visual assets while preserving unwavering multi-shot continuity. Experiments demonstrate that StoryBlender significantly improves consistency and editability over both diffusion-based and 3D-grounded baselines. Code, data, and demonstration video will be available on https://engineeringai-lab.github.io/StoryBlender/","published":"2026-04-01T07:24:31Z","updated":"2026-04-01T07:24:31Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.03315v1","pdf_url":"https://arxiv.org/pdf/2604.03315v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.00261","versioned_id":"2604.00261v2","title":"Can Large Language Models Self-Correct in Medical Question Answering? An Exploratory Study","authors":["Zaifu Zhan","Mengyuan Cui","Rui Zhang"],"abstract":"Large language models (LLMs) have achieved strong performance on medical question answering (medical QA), and chain-of-thought (CoT) prompting has further improved results by eliciting explicit intermediate reasoning; meanwhile, self-reflective (self-corrective) prompting has been widely claimed to enhance model reliability by prompting LLMs to critique and revise their own reasoning, yet its effectiveness in safety-critical medical settings remains unclear. In this work, we conduct an exploratory analysis of self-reflective reasoning for medical multiple-choice question answering: using GPT-4o and GPT-4o-mini, we compare standard CoT prompting with an iterative self-reflection loop and track how predictions evolve across reflection steps on three widely used medical QA benchmarks (MedQA, HeadQA, and PubMedQA). We analyze whether self-reflection leads to error correction, error persistence, or the introduction of new errors. Our results show that self-reflective prompting does not consistently improve accuracy and its impact is highly dataset- and model-dependent: it yields modest gains on MedQA but provides limited or negative benefits on HeadQA and PubMedQA, and increasing the number of reflection steps does not guarantee better performance. These findings highlight a gap between reasoning transparency and reasoning correctness, suggesting that self-reflective reasoning is better viewed as an analytical tool for understanding model behavior rather than a standalone solution for improving medical QA reliability.","published":"2026-03-31T21:42:20Z","updated":"2026-04-02T14:18:08Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.00261v2","pdf_url":"https://arxiv.org/pdf/2604.00261v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.00230","versioned_id":"2604.00230v3","title":"Neural Collapse Dynamics: Depth, Activation, Regularisation, and Feature Norm Threshold","authors":["Anamika Paul Rupa"],"abstract":"Neural collapse (NC) -- the convergence of penultimate-layer features to a simplex equiangular tight frame -- is well understood at equilibrium, but the dynamics governing its onset remain poorly characterised. We identify a simple and predictive regularity: NC occurs when the mean feature norm reaches a model-dataset-specific critical value, fn*, that is largely invariant to training conditions. This value concentrates tightly within each (model, dataset) pair (CV < 8%); training dynamics primarily affect the rate at which fn approaches fn*, rather than the value itself. In standard training trajectories, the crossing of fn below fn* consistently precedes NC onset, providing a practical predictor with a mean lead time of 62 epochs (MAE 24 epochs). A direct intervention experiment confirms fn* is a stable attractor of the gradient flow -- perturbations to feature scale are self-corrected during training, with convergence to the same value regardless of direction (p>0.2). Completing the (architecture)x(dataset) grid reveals the paper's strongest result: ResNet-20 on MNIST gives fn* = 5.867 -- a +458% architecture effect versus only +68% on CIFAR-10. The grid is strongly non-additive; fn* cannot be decomposed into independent architecture and dataset contributions. Four structural regularities emerge: (1) depth has a non-monotonic effect on collapse speed; (2) activation jointly determines both collapse speed and fn*; (3) weight decay defines a three-regime phase diagram -- too little slows, an optimal range is fastest, and too much prevents collapse; (4) width monotonically accelerates collapse while shifting fn* by at most 13%. These results establish feature-norm dynamics as an actionable diagnostic for predicting NC timing, suggesting that norm-threshold behaviour is a general mechanism underlying delayed representational reorganisation in deep networks.","published":"2026-03-31T20:52:42Z","updated":"2026-07-10T19:20:48Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.00230v3","pdf_url":"https://arxiv.org/pdf/2604.00230v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.00072","versioned_id":"2604.00072v1","title":"Empirical Validation of the Classification-Verification Dichotomy for AI Safety Gates","authors":["Arsenios Scrivens"],"abstract":"Can classifier-based safety gates maintain reliable oversight as AI systems improve over hundreds of iterations? We provide comprehensive empirical evidence that they cannot. On a self-improving neural controller (d=240), eighteen classifier configurations -- spanning MLPs, SVMs, random forests, k-NN, Bayesian classifiers, and deep networks -- all fail the dual conditions for safe self-improvement. Three safe RL baselines (CPO, Lyapunov, safety shielding) also fail. Results extend to MuJoCo benchmarks (Reacher-v4 d=496, Swimmer-v4 d=1408, HalfCheetah-v4 d=1824). At controlled distribution separations up to delta_s=2.0, all classifiers still fail -- including the NP-optimal test and MLPs with 100% training accuracy -- demonstrating structural impossibility. We then show the impossibility is specific to classification, not to safe self-improvement itself. A Lipschitz ball verifier achieves zero false accepts across dimensions d in {84, 240, 768, 2688, 5760, 9984, 17408} using provable analytical bounds (unconditional delta=0). Ball chaining enables unbounded parameter-space traversal: on MuJoCo Reacher-v4, 10 chains yield +4.31 reward improvement with delta=0; on Qwen2.5-7B-Instruct during LoRA fine-tuning, 42 chain transitions traverse 234x the single-ball radius with zero safety violations across 200 steps. A 50-prompt oracle confirms oracle-agnosticity. Compositional per-group verification enables radii up to 37x larger than full-network balls. At d<=17408, delta=0 is unconditional; at LLM scale, conditional on estimated Lipschitz constants.","published":"2026-03-31T13:54:36Z","updated":"2026-03-31T13:54:36Z","categories":["cs.LG","cs.AI","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.00072v1","pdf_url":"https://arxiv.org/pdf/2604.00072v1","comment":"21 pages, 9 figures. Companion theory paper: doi:10.5281/zenodo.19237451","journal_ref":"","doi":"10.5281/zenodo.19237566","discovered_on":"2026-07-17"},{"id":"2603.29755","versioned_id":"2603.29755v1","title":"CausalPulse: An Industrial-Grade Neurosymbolic Multi-Agent Copilot for Causal Diagnostics in Smart Manufacturing","authors":["Chathurangi Shyalika","Utkarshani Jaimini","Cory Henson","Amit Sheth"],"abstract":"Modern manufacturing environments demand real-time, trustworthy, and interpretable root-cause insights to sustain productivity and quality. Traditional analytics pipelines often treat anomaly detection, causal inference, and root-cause analysis as isolated stages, limiting scalability and explainability. In this work, we present CausalPulse, an industry-grade multi-agent copilot that automates causal diagnostics in smart manufacturing. It unifies anomaly detection, causal discovery, and reasoning through a neurosymbolic architecture built on standardized agentic protocols. CausalPulse is being deployed in a Robert Bosch manufacturing plant, integrating seamlessly with existing monitoring workflows and supporting real-time operation at production scale. Evaluations on both public (Future Factories) and proprietary (Planar Sensor Element) datasets show high reliability, achieving overall success rates of 98.0% and 98.73%. Per-criterion success rates reached 98.75% for planning and tool use, 97.3% for self-reflection, and 99.2% for collaboration. Runtime experiments report end-to-end latency of 50-60s per diagnostic workflow with near-linear scalability (R^2=0.97), confirming real-time readiness. Comparison with existing industrial copilots highlights distinct advantages in modularity, extensibility, and deployment maturity. These results demonstrate how CausalPulse's modular, human-in-the-loop design enables reliable, interpretable, and production-ready automation for next-generation manufacturing.","published":"2026-03-31T13:54:34Z","updated":"2026-03-31T13:54:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.29755v1","pdf_url":"https://arxiv.org/pdf/2603.29755v1","comment":"10 pages, 8 figures, 4 tables, Accepted at AAAI-MAKE 2026 (AAAI Spring Symposium on Machine Learning and Knowledge Engineering for Knowledge-Grounded Semantic Agents)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.29292","versioned_id":"2603.29292v1","title":"Self-Improving Code Generation via Semantic Entropy and Behavioral Consensus","authors":["Huan Zhang","Wei Cheng","Wei Hu"],"abstract":"Improving the code generation capabilities of large language models (LLMs) typically relies on supervised fine-tuning or preference optimization, both of which require costly external resources such as powerful teacher models or reliable test units. However, in real-world scenarios, it is much harder to obtain reference solutions and test oracles than problem descriptions and test inputs. In this paper, we tackle a challenging yet realistic question: Can a code language model improve itself without access to a superior teacher and a test oracle? To answer this, we propose ConSelf, a self-improving approach built upon two key ideas. First, we introduce code semantic entropy, a novel metric that measures problem-level uncertainty by assessing the functional diversity of program behaviors, enabling a curriculum construction with the most learnable problems. Second, we present consensus-driven direct preference optimization (Con-DPO), a preference-based fine-tuning method that weights each preference pair by its behavioral consensus, thereby mitigating the impact of noisy self-generated supervision. Experiments on various benchmarks and backbone LLMs demonstrate that ConSelf significantly outperforms baselines, validating the effectiveness of semantic entropy-based curriculum construction and consensus-driven optimization in improving code generation without external supervision.","published":"2026-03-31T05:55:17Z","updated":"2026-03-31T05:55:17Z","categories":["cs.SE","cs.AI","cs.PL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.29292v1","pdf_url":"https://arxiv.org/pdf/2603.29292v1","comment":"Accepted in the 34th IEEE/ACM International Conference on Program Comprehension (ICPC 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.29142","versioned_id":"2603.29142v1","title":"REFINE: Real-world Exploration of Interactive Feedback and Student Behaviour","authors":["Fares Fawzi","Seyed Parsa Neshaei","Marta Knezevic","Tanya Nazaretsky","Tanja Käser"],"abstract":"Formative feedback is central to effective learning, yet providing timely, individualised feedback at scale remains a persistent challenge. While recent work has explored the use of large language models (LLMs) to automate feedback, most existing systems still conceptualise feedback as a static, one-way artifact, offering limited support for interpretation, clarification, or follow-up. In this work, we introduce REFINE, a locally deployable, multi-agent feedback system built on small, open-source LLMs that treats feedback as an interactive process. REFINE combines a pedagogically-grounded feedback generation agent with an LLM-as-a-judge-guided regeneration loop using a human-aligned judge, and a self-reflective tool-calling interactive agent that supports student follow-up questions with context-aware, actionable responses. We evaluate REFINE through controlled experiments and an authentic classroom deployment in an undergraduate computer science course. Automatic evaluations show that judge-guided regeneration significantly improves feedback quality, and that the interactive agent produces efficient, high-quality responses comparable to a state-of-the-art closed-source model. Analysis of real student interactions further reveals distinct engagement patterns and indicates that system-generated feedback systematically steers subsequent student inquiry. Our findings demonstrate the feasibility and effectiveness of multi-agent, tool-augmented feedback systems for scalable, interactive feedback.","published":"2026-03-31T01:48:08Z","updated":"2026-03-31T01:48:08Z","categories":["cs.AI","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.29142v1","pdf_url":"https://arxiv.org/pdf/2603.29142v1","comment":"Accepted to AIED 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.28650","versioned_id":"2603.28650v2","title":"Information-Theoretic Limits of Safety Verification for Self-Improving Systems","authors":["Arsenios Scrivens"],"abstract":"Can a safety gate permit unbounded beneficial self-modification while maintaining bounded cumulative risk? We formalize this question through dual conditions -- requiring sum delta_n < infinity (bounded risk) and sum TPR_n = infinity (unbounded utility) -- and establish a theory of their (in)compatibility. Classification impossibility (Theorem 1): For power-law risk schedules delta_n = O(n^{-p}) with p > 1, any classifier-based gate under overlapping safe/unsafe distributions satisfies TPR_n <= C_alpha * delta_n^beta via Holder's inequality, forcing sum TPR_n < infinity. This impossibility is exponent-optimal (Theorem 3). A second independent proof via the NP counting method (Theorem 4) yields a 13% tighter bound without Holder's inequality. Universal finite-horizon ceiling (Theorem 5): For any summable risk schedule, the exact maximum achievable classifier utility is U*(N, B) = N * TPR_NP(B/N), growing as exp(O(sqrt(log N))) -- subpolynomial. At N = 10^6 with budget B = 1.0, a classifier extracts at most U* ~ 87 versus a verifier's ~500,000. Verification escape (Theorem 2): A Lipschitz ball verifier achieves delta = 0 with TPR > 0, escaping the impossibility. Formal Lipschitz bounds for pre-LayerNorm transformers under LoRA enable LLM-scale verification. The separation is strict. We validate on GPT-2 (d_LoRA = 147,456): conditional delta = 0 with TPR = 0.352. Comprehensive empirical validation is in the companion paper [D2].","published":"2026-03-30T16:34:37Z","updated":"2026-04-02T00:23:37Z","categories":["cs.LG","cs.AI","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.28650v2","pdf_url":"https://arxiv.org/pdf/2603.28650v2","comment":"27 pages, 6 figures. Companion empirical paper: doi:10.5281/zenodo.19237566","journal_ref":"","doi":"10.5281/zenodo.19237451","discovered_on":"2026-07-17"},{"id":"2603.28488","versioned_id":"2603.28488v2","title":"Courtroom-Style Multi-Agent Debate with Progressive RAG and Role-Switching for Controversial Claim Verification","authors":["Masnun Nuha Chowdhury","Nusrat Jahan Beg","Umme Hunny Khan","Syed Rifat Raiyan","Md Kamrul Hasan","Hasan Mahmud"],"abstract":"Large language models (LLMs) remain unreliable for high-stakes claim verification due to hallucinations and shallow reasoning. While retrieval-augmented generation (RAG) and multi-agent debate (MAD) address this, they are limited by one-pass retrieval and unstructured debate dynamics. We propose a courtroom-style multi-agent framework, PROClaim, that reformulates verification as a structured, adversarial deliberation. Our approach integrates specialized roles (e.g., Plaintiff, Defense, Judge) with Progressive RAG (P-RAG) to dynamically expand and refine the evidence pool during the debate. Furthermore, we employ evidence negotiation, self-reflection, and heterogeneous multi-judge aggregation to enforce calibration, robustness, and diversity. In zero-shot evaluations on the Check-COVID benchmark, PROClaim achieves 81.7% accuracy, outperforming standard multi-agent debate by 10.0 percentage points, with P-RAG driving the primary performance gains (+7.5 pp). We ultimately demonstrate that structural deliberation and model heterogeneity effectively mitigate systematic biases, providing a robust foundation for reliable claim verification. Our code and data are publicly available at https://github.com/mnc13/PROClaim.","published":"2026-03-30T14:23:15Z","updated":"2026-05-12T00:38:08Z","categories":["cs.CL","cs.AI","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.28488v2","pdf_url":"https://arxiv.org/pdf/2603.28488v2","comment":"Under review, 7 figures, 12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.27451","versioned_id":"2603.27451v1","title":"Multi-Agent Dialectical Refinement for Enhanced Argument Classification","authors":["Jakub Bąba","Jarosław A. Chudziak"],"abstract":"Argument Mining (AM) is a foundational technology for automated writing evaluation, yet traditional supervised approaches rely heavily on expensive, domain-specific fine-tuning. While Large Language Models (LLMs) offer a training-free alternative, they often struggle with structural ambiguity, failing to distinguish between similar components like Claims and Premises. Furthermore, single-agent self-correction mechanisms often suffer from sycophancy, where the model reinforces its own initial errors rather than critically evaluating them. We introduce MAD-ACC (Multi-Agent Debate for Argument Component Classification), a framework that leverages dialectical refinement to resolve classification uncertainty. MAD-ACC utilizes a Proponent-Opponent-Judge model where agents defend conflicting interpretations of ambiguous text, exposing logical nuances that single-agent models miss. Evaluation on the UKP Student Essays corpus demonstrates that MAD-ACC achieves a Macro F1 score of 85.7%, significantly outperforming single-agent reasoning baselines, without requiring domain-specific training. Additionally, unlike \"black-box\" classifiers, MAD-ACC's dialectical approach offers a transparent and explainable alternative by generating human-readable debate transcripts that explain the reasoning behind decisions.","published":"2026-03-29T00:03:48Z","updated":"2026-03-29T00:03:48Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.27451v1","pdf_url":"https://arxiv.org/pdf/2603.27451v1","comment":"Accepted for publication in the proceedings of ACIIDS 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.27335","versioned_id":"2603.27335v1","title":"PubMed Reasoner: Dynamic Reasoning-based Retrieval for Evidence-Grounded Biomedical Question Answering","authors":["Yiqing Zhang","Xiaozhong Liu","Fabricio Murai"],"abstract":"Trustworthy biomedical question answering (QA) systems must not only provide accurate answers but also justify them with current, verifiable evidence. Retrieval-augmented approaches partially address this gap but lack mechanisms to iteratively refine poor queries, whereas self-reflection methods kick in only after full retrieval is completed. In this context, we introduce PubMed Reasoner, a biomedical QA agent composed of three stages: self-critic query refinement evaluates MeSH terms for coverage, alignment, and redundancy to enhance PubMed queries based on partial (metadata) retrieval; reflective retrieval processes articles in batches until sufficient evidence is gathered; and evidence-grounded response generation produces answers with explicit citations. PubMed Reasoner with a GPT-4o backbone achieves 78.32% accuracy on PubMedQA, slightly surpassing human experts, and showing consistent gains on MMLU Clinical Knowledge. Moreover, LLM-as-judge evaluations prefer our responses across: reasoning soundness, evidence grounding, clinical relevance, and trustworthiness. By orchestrating retrieval-first reasoning over authoritative sources, our approach provides practical assistance to clinicians and biomedical researchers while controlling compute and token costs.","published":"2026-03-28T16:41:57Z","updated":"2026-03-28T16:41:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.27335v1","pdf_url":"https://arxiv.org/pdf/2603.27335v1","comment":"20 pages; under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.27247","versioned_id":"2603.27247v1","title":"SCOPE: Tree-based Self-Correcting Online Log Parsing via Syntactic-Semantic Collaboration","authors":["Dongyi Fan","Suqiong Zhang","Lili He","Ming Liu","Yifan Huo"],"abstract":"Log parsing is a critical step for automated log analysis in complex systems. Traditional heuristic-based methods offer high efficiency but are limited in accuracy due to overlooking semantic context. In contrast, recent LLM-based parsers improve accuracy via se mantic understanding but incur high latency from frequent model calls. To address this, we propose SCOPE, the first self-correcting online log parsing method that integrates the strengths of both heuristic and LLM-based paradigms. SCOPE introduces a novel bi-directional tree structure that enables efficient template match ing from both forward and reverse directions, resulting in a higher overall matching rate. Additionally, it adopts a two-stage syntactic semantic collaboration framework: a lightweight NLP model first utilizes part-of-speech (POS) information for syntax-based match ing, while the LLM is selectively invoked as a fallback to handle semantically complex cases when uncertainty remains. This design significantly reduces LLM API usage while maintaining high ac curacy, achieving a balance between efficiency and effectiveness. Extensive evaluations on diverse benchmark datasets show that SCOPE outperforms state-of-the-art methods in both accuracy and efficiency. The implementation and datasets are publicly released to facilitate further research.","published":"2026-03-28T11:45:08Z","updated":"2026-03-28T11:45:08Z","categories":["cs.CL","cs.SE"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.27247v1","pdf_url":"https://arxiv.org/pdf/2603.27247v1","comment":"Accepted at the 34th International Conference on Program Comprehension (ICPC 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.27008","versioned_id":"2603.27008v1","title":"RASPRef: Retrieval-Augmented Self-Supervised Prompt Refinement for Large Reasoning Models","authors":["Rahul Soni"],"abstract":"Recent reasoning-focused language models such as DeepSeek R1 and OpenAI o1 have demonstrated strong performance on structured reasoning benchmarks including GSM8K, MATH, and multi-hop question answering tasks. However, their performance remains highly sensitive to prompt formulation, and designing effective prompts is typically a manual and iterative process that does not scale well across tasks or domains. To address this limitation, we introduce Retrieval-Augmented Self-Supervised Prompt Refinement (RASPRef), a framework that improves prompts without requiring human annotations or task-specific supervision. The approach retrieves relevant examples and previously generated reasoning trajectories, and leverages signals such as multi-sample consistency, verifier feedback, and model-generated critiques to iteratively refine the prompt. Unlike prior approaches that focus primarily on improving model outputs, RASPRef directly treats the prompt as the optimization target and improves it through an iterative retrieval-guided refinement process. Experiments on GSM8K-style mathematical reasoning tasks show that retrieval-guided prompting improves performance compared with a static prompting baseline. We further discuss how retrieval quality, trajectory selection, and self-supervised feedback signals may influence the effectiveness of prompt refinement. These findings suggest that prompt design remains a critical factor for reasoning-oriented language models, and that self-improving prompts offer a practical and scalable strategy for improving reasoning performance.","published":"2026-03-27T21:49:21Z","updated":"2026-03-27T21:49:21Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.27008v1","pdf_url":"https://arxiv.org/pdf/2603.27008v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.26348","versioned_id":"2603.26348v1","title":"Reflect to Inform: Boosting Multimodal Reasoning via Information-Gain-Driven Verification","authors":["Shuai Lv","Chang Liu","Feng Tang","Yujie Yuan","Aojun Zhou","Kui Zhang","Xi Yang","Yangqiu Song"],"abstract":"Multimodal Large Language Models (MLLMs) achieve strong multimodal reasoning performance, yet we identify a recurring failure mode in long-form generation: as outputs grow longer, models progressively drift away from image evidence and fall back on textual priors, resulting in ungrounded reasoning and hallucinations. Interestingly, Based on attention analysis, we find that MLLMs have a latent capability for late-stage visual verification that is present but not consistently activated. Motivated by this observation, we propose Visual Re-Examination (VRE), a self-evolving training framework that enables MLLMs to autonomously perform visual introspection during reasoning without additional visual inputs. Rather than distilling visual capabilities from a stronger teacher, VRE promotes iterative self-improvement by leveraging the model itself to generate reflection traces, making visual information actionable through information gain. Extensive experiments across diverse multimodal benchmarks demonstrate that VRE consistently improves reasoning accuracy and perceptual reliability, while substantially reducing hallucinations, especially in long-chain settings. Code is available at https://github.com/Xiaobu-USTC/VRE.","published":"2026-03-27T12:22:13Z","updated":"2026-03-27T12:22:13Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.26348v1","pdf_url":"https://arxiv.org/pdf/2603.26348v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.26845","versioned_id":"2603.26845v2","title":"GISclaw: A Comprehensive Open-Source LLM Agent System for Realistic Multi-Step Geospatial Analysis","authors":["Jinzhen Han","JinByeong Lee","Yuri Shim","Jisung Kim","Jae-Joon Lee"],"abstract":"Most LLM-driven GIS assistants solve narrow single-step tasks tightly coupled to proprietary platforms such as ArcGIS or QGIS, limiting their use for the multi-step, cross-format pipelines that define professional geospatial analysis. We present GISclaw, a comprehensive open-source agent system that performs realistic GIS analysis end to end - spatial joins, raster algebra, kriging interpolation, machine-learning classification, network analysis, choropleth cartography - directly through Python with no commercial GIS dependency. GISclaw couples an LLM reasoning core with a persistent Python sandbox pre-loaded with the open-source geospatial stack, three engineered prompt rules (Schema Analysis, Package Constraint, Domain Knowledge Injection), and an Error-Memory module for self-correction. A single backend-agnostic architecture supports both cloud-API and locally deployed open-weight LLM backends, enabling air-gapped deployment without loss of capability. On GeoAnalystBench - 50 expert-curated multi-step tasks averaging 5.8 analytical steps across vector, raster, and tabular data - GISclaw reaches up to 100% task success and 97% mean success over three independent runs. We further conduct 1,800 controlled experiments (50 tasks x 6 backends x 2 architectures x 3 repeats) with bootstrap 95% CIs, paired Wilcoxon tests, and a composite-score sensitivity analysis (Kendall's tau median = 0.94), and introduce a three-layer evaluation protocol combining code structure, reasoning process, and type-specific output verification. The Single-Agent ReAct loop reliably outperforms the Dual-Agent Plan-Execute-Replan pipeline on every cloud backend (Cliff's delta = 0.15-0.41); only the locally deployed 14B model gains from multi-agent orchestration, suggesting architectural complexity should match model capability rather than be added by default.","published":"2026-03-27T09:46:59Z","updated":"2026-05-03T12:16:48Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.26845v2","pdf_url":"https://arxiv.org/pdf/2603.26845v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.26034","versioned_id":"2603.26034v1","title":"AgentCollab: A Self-Evaluation-Driven Collaboration Paradigm for Efficient LLM Agents","authors":["Wenbo Gao","Renxi Liu","Xian Wang","Fang Guo","Shuai Yang","Xi Chen","Hui-Ling Zhen","Hanting Chen","Weizhe Lin","Xiaosong Li","Yaoyuan Wang"],"abstract":"Autonomous agents powered by large language models (LLMs) perform complex tasks through long-horizon reasoning and tool interaction, where a fundamental trade-off arises between execution efficiency and reasoning robustness. Models at different capability-cost levels offer complementary advantages: lower-cost models enable fast execution but may struggle on difficult reasoning segments, while stronger models provide more robust reasoning at higher computational cost. We present AgentCollab, a self-driven collaborative inference framework that dynamically coordinates models with different reasoning capacities during agent execution. Instead of relying on external routing modules, the framework uses the agent's own self-reflection signal to determine whether the current reasoning trajectory is making meaningful progress, and escalates control to a stronger reasoning tier only when necessary. To further stabilize long-horizon execution, we introduce a difficulty-aware cumulative escalation strategy that allocates additional reasoning budget based on recent failure signals. In our experiments, we instantiate this framework using a two-level small-large model setting. Experiments on diverse multi-step agent benchmarks show that AgentCollab consistently improves the accuracy-efficiency Pareto frontier of LLM agents.","published":"2026-03-27T03:07:34Z","updated":"2026-03-27T03:07:34Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.26034v1","pdf_url":"https://arxiv.org/pdf/2603.26034v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.26815","versioned_id":"2603.26815v3","title":"Sustainable Hybrid Document-Routed Retrieval for Financial RAG: Resolving the Robustness-Precision Trade-off","authors":["Zhiyuan Cheng","Longying Lai","Yue Liu"],"abstract":"Retrieval-Augmented Generation (RAG) systems for financial document QA typically follow a chunk-based paradigm: documents are split into fragments, embedded, and retrieved by similarity. In structurally homogeneous corpora such as regulatory filings, this suffers from cross-document chunk confusion. Semantic File Routing (SFR), which uses LLM structured output to route queries to whole documents, reduces catastrophic failures but sacrifices targeted-chunk precision. We identify this robustness-precision trade-off on the FinDER benchmark (1,500 queries across five groups): SFR achieves higher average scores (6.45 vs. 6.02) and fewer failures (10.3% vs. 22.5%), while chunk-based retrieval (CBR) yields more perfect answers (13.8% vs. 8.5%). To resolve it, we propose Hybrid Document-Routed Retrieval (HDRR), a two-stage architecture that uses SFR as a document filter followed by chunk retrieval scoped to the identified document(s), eliminating cross-document confusion while preserving chunk precision. HDRR achieves the best performance on every metric: an average score of 7.54 (25.2% above CBR, 16.9% above SFR), a 6.4% failure rate, 67.7% correctness (+18.7 pp over CBR), and a 20.1% perfect-answer rate (+6.3 pp over CBR, +11.6 pp over SFR), simultaneously attaining the lowest failure rate and highest precision across all five groups. Beyond accuracy, HDRR is also the most efficient of the high-quality systems: it preserves CBR's compact per-query token budget (~5K-15K, an order of magnitude below SFR's ~50K-200K), incurs no indexing-time LLM spend (versus the one-time ~$100 cost of contextual indexing), and uses fewer per-query LLM calls than self-correcting agentic baselines, translating directly to lower API spend and inference-time energy at deployment scale.","published":"2026-03-26T18:05:38Z","updated":"2026-06-26T23:03:46Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.26815v3","pdf_url":"https://arxiv.org/pdf/2603.26815v3","comment":"26 pages, 4 figures, 13 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.25702","versioned_id":"2603.25702v2","title":"S2D2: Fast Decoding for Diffusion LLMs via Training-Free Self-Speculation","authors":["Ligong Han","Hao Wang","Han Gao","Kai Xu","Akash Srivastava"],"abstract":"Block-diffusion language models offer a promising path toward faster-than-autoregressive generation by combining block-wise autoregressive decoding with within-block parallel denoising. However, in the few-step regime needed for practical acceleration, standard confidence-thresholded decoding is often brittle: aggressive thresholds hurt quality, while conservative thresholds require unnecessary denoising steps. Existing approaches that address this issue either require additional training or incur extra test-time compute. We present S2D2, a training-free self-speculative decoding framework for block-diffusion language models. Our key observation is that a block-diffusion model becomes autoregressive when the block size is reduced to one, allowing the same pretrained model to act as both drafter and verifier. S2D2 inserts a speculative verification step into standard block-diffusion decoding and uses lightweight routing policies to decide when verification is worth its cost. This yields a hybrid decoding trajectory in which diffusion proposes tokens in parallel, while the autoregressive mode acts as a local sequence-level critic. Across three mainstream block-diffusion families, S2D2 consistently improves the accuracy-speed tradeoff over strong confidence-thresholding baselines. On SDAR, we observe up to $4.7\\times$ speedup over autoregressive decoding, and up to $1.57\\times$ over a tuned dynamic decoding baseline while improving accuracy by up to $4.5$ points. On LLaDA2.1-Mini, S2D2 remains complementary to built-in self-correction, including a conservative setting where it is $4.4\\times$ faster than the static baseline with slightly higher accuracy.","published":"2026-03-26T17:48:50Z","updated":"2026-06-17T19:47:34Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.25702v2","pdf_url":"https://arxiv.org/pdf/2603.25702v2","comment":"Code is available at https://github.com/phymhan/S2D2","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.25697","versioned_id":"2603.25697v1","title":"The Kitchen Loop: User-Spec-Driven Development for a Self-Evolving Codebase","authors":["Yannick Roy"],"abstract":"Code production is now a commodity; the bottleneck is knowing what to build and proving it works. We present the Kitchen Loop, a framework for autonomous, self-evolving software built on a unified trust model: (1) a specification surface enumerating what the product claims to support; (2) 'As a User x 1000', where an LLM agent exercises that surface as a synthetic power user at 1,000x human cadence; (3) Unbeatable Tests, ground-truth verification the code author cannot fake; and (4) Drift Control, continuous quality measurement with automated pause gates. We validate across two production systems over 285+ iterations, producing 1,094+ merged pull requests with zero regressions detected by the regression oracle (methodology in Section 6.1). We observe emergent properties at scale: multi-iteration self-correction chains, autonomous infrastructure healing, and monotonically improving quality gates. The primitives are not new; our contribution is their composition into a production-tested system with the operational discipline that makes long-running autonomous evolution safe.","published":"2026-03-26T17:45:00Z","updated":"2026-03-26T17:45:00Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.25697v1","pdf_url":"https://arxiv.org/pdf/2603.25697v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.25681","versioned_id":"2603.25681v1","title":"Self-Improvement of Large Language Models: A Technical Overview and Future Outlook","authors":["Haoyan Yang","Mario Xerri","Solha Park","Huajian Zhang","Yiyang Feng","Sai Akhil Kogilathota","Jiawei Zhou"],"abstract":"As large language models (LLMs) continue to advance, improving them solely through human supervision is becoming increasingly costly and limited in scalability. As models approach human-level capabilities in certain domains, human feedback may no longer provide sufficiently informative signals for further improvement. At the same time, the growing ability of models to make autonomous decisions and execute complex actions naturally enables abstractions in which components of the model development process can be progressively automated. Together, these challenges and opportunities have driven increasing interest in self-improvement, where models autonomously generate data, evaluate outputs, and iteratively refine their own capabilities. In this paper, we present a system-level perspective on self-improving language models and introduce a unified framework that organizes existing techniques. We conceptualize the self-improvement system as a closed-loop lifecycle, consisting of four tightly coupled processes: data acquisition, data selection, model optimization, and inference refinement, along with an autonomous evaluation layer. Within this framework, the model itself plays a central role in driving each stage: collecting or generating data, selecting informative signals, updating its parameters, and refining outputs, while the autonomous evaluation layer continuously monitors progress and guides the improvement cycle across stages. Following this lifecycle perspective, we systematically review and analyze representative methods for each component from a technical standpoint. We further discuss current limitations and outline our vision for future research toward fully self-improving LLMs.","published":"2026-03-26T17:32:37Z","updated":"2026-03-26T17:32:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.25681v1","pdf_url":"https://arxiv.org/pdf/2603.25681v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.25176","versioned_id":"2603.25176v1","title":"Prompt Attack Detection with LLM-as-a-Judge and Mixture-of-Models","authors":["Hieu Xuan Le","Benjamin Goh","Quy Anh Tang"],"abstract":"Prompt attacks, including jailbreaks and prompt injections, pose a critical security risk to Large Language Model (LLM) systems. In production, guardrails must mitigate these attacks under strict low-latency constraints, resulting in a deployment gap in which lightweight classifiers and rule-based systems struggle to generalize under distribution shift, while high-capacity LLM-based judges remain too slow or costly for live enforcement. In this work, we examine whether lightweight, general-purpose LLMs can reliably serve as security judges under real-world production constraints. Through careful prompt and output design, lightweight LLMs are guided through a structured reasoning process involving explicit intent decomposition, safety-signal verification, harm assessment, and self-reflection. We evaluate our method on a curated dataset combining benign queries from real-world chatbots with adversarial prompts generated via automated red teaming (ART), covering diverse and evolving patterns. Our results show that general-purpose LLMs, such as gemini-2.0-flash-lite-001, can serve as effective low-latency judges for live guardrails. This configuration is currently deployed in production as a centralized guardrail service for public service chatbots in Singapore. We additionally evaluate a Mixture-of-Models (MoM) setting to assess whether aggregating multiple LLM judges improves prompt-attack detection performance relative to single-model judges, with only modest gains observed.","published":"2026-03-26T08:47:53Z","updated":"2026-03-26T08:47:53Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.25176v1","pdf_url":"https://arxiv.org/pdf/2603.25176v1","comment":"16 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.24965","versioned_id":"2603.24965v1","title":"Self-Corrected Image Generation with Explainable Latent Rewards","authors":["Yinyi Luo","Hrishikesh Gokhale","Marios Savvides","Jindong Wang","Shengfeng He"],"abstract":"Despite significant progress in text-to-image generation, aligning outputs with complex prompts remains challenging, particularly for fine-grained semantics and spatial relations. This difficulty stems from the feed-forward nature of generation, which requires anticipating alignment without fully understanding the output. In contrast, evaluating generated images is more tractable. Motivated by this asymmetry, we propose xLARD, a self-correcting framework that uses multimodal large language models to guide generation through Explainable LAtent RewarDs. xLARD introduces a lightweight corrector that refines latent representations based on structured feedback from model-generated references. A key component is a differentiable mapping from latent edits to interpretable reward signals, enabling continuous latent-level guidance from non-differentiable image-level evaluations. This mechanism allows the model to understand, assess, and correct itself during generation. Experiments across diverse generation and editing tasks show that xLARD improves semantic alignment and visual fidelity while maintaining generative priors. Code is available at https://yinyiluo.github.io/xLARD/.","published":"2026-03-26T02:59:35Z","updated":"2026-03-26T02:59:35Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.24965v1","pdf_url":"https://arxiv.org/pdf/2603.24965v1","comment":"CVPR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.24866","versioned_id":"2603.24866v1","title":"How Far Are Vision-Language Models from Constructing the Real World? A Benchmark for Physical Generative Reasoning","authors":["Luyu Yang","Yutong Dai","An Yan","Viraj Prabhu","Ran Xu","Zeyuan Chen"],"abstract":"The physical world is not merely visual; it is governed by rigorous structural and procedural constraints. Yet, the evaluation of vision-language models (VLMs) remains heavily skewed toward perceptual realism, prioritizing the generation of visually plausible 3D layouts, shapes, and appearances. Current benchmarks rarely test whether models grasp the step-by-step processes and physical dependencies required to actually build these artifacts, a capability essential for automating design-to-construction pipelines. To address this, we introduce DreamHouse, a novel benchmark for physical generative reasoning: the capacity to synthesize artifacts that concurrently satisfy geometric, structural, constructability, and code-compliance constraints. We ground this benchmark in residential timber-frame construction, a domain with fully codified engineering standards and objectively verifiable correctness. We curate over 26,000 structures spanning 13 architectural styles, ach verified to construction-document standards (LOD 350) and develop a deterministic 10-test structural validation framework. Unlike static benchmarks that assess only final outputs, DreamHouse supports iterative agentic interaction. Models observe intermediate build states, generate construction actions, and receive structured environmental feedback, enabling a fine-grained evaluation of planning, structural reasoning, and self-correction. Extensive experiments with state-of-the-art VLMs reveal substantial capability gaps that are largely invisible on existing leaderboards. These findings establish physical validity as a critical evaluation axis orthogonal to visual realism, highlighting physical generative reasoning as a distinct and underdeveloped frontier in multimodal intelligence. Available at https://luluyuyuyang.github.io/dreamhouse","published":"2026-03-25T23:13:28Z","updated":"2026-03-25T23:13:28Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.24866v1","pdf_url":"https://arxiv.org/pdf/2603.24866v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.24579","versioned_id":"2603.24579v1","title":"MARCH: Multi-Agent Reinforced Self-Check for LLM Hallucination","authors":["Zhuo Li","Yupeng Zhang","Pengyu Cheng","Jiajun Song","Mengyu Zhou","Hao Li","Shujie Hu","Yu Qin","Erchao Zhao","Xiaoxi Jiang","Guanjun Jiang"],"abstract":"Hallucination remains a critical bottleneck for large language models (LLMs), undermining their reliability in real-world applications, especially in Retrieval-Augmented Generation (RAG) systems. While existing hallucination detection methods employ LLM-as-a-judge to verify LLM outputs against retrieved evidence, they suffer from inherent confirmation bias, where the verifier inadvertently reproduces the errors of the original generation. To address this, we introduce Multi-Agent Reinforced Self-Check for Hallucination (MARCH), a framework that enforces rigorous factual alignment by leveraging deliberate information asymmetry. MARCH orchestrates a collaborative pipeline of three specialized agents: a Solver, a Proposer, and a Checker. The Solver generates an initial RAG response, which the Proposer decomposes into claim-level verifiable atomic propositions. Crucially, the Checker validates these propositions against retrieved evidence in isolation, deprived of the Solver's original output. This well-crafted information asymmetry scheme breaks the cycle of self-confirmation bias. By training this pipeline with multi-agent reinforcement learning (MARL), we enable the agents to co-evolve and optimize factual adherence. Extensive experiments across hallucination benchmarks demonstrate that MARCH substantially reduces hallucination rates. Notably, an 8B-parameter LLM equipped with MARCH achieves performance competitive with powerful closed-source models. MARCH paves a scalable path for factual self-improvement of LLMs through co-evolution. The code is at https://github.com/Qwen-Applications/MARCH.","published":"2026-03-25T17:54:10Z","updated":"2026-03-25T17:54:10Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.24579v1","pdf_url":"https://arxiv.org/pdf/2603.24579v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.24402","versioned_id":"2603.24402v2","title":"AI-Supervisor: Autonomous AI Research Supervision via a Persistent Research World Model","authors":["Yunbo Long"],"abstract":"Existing automated research systems operate as stateless, linear pipelines -- generating outputs without maintaining any persistent understanding of the research landscape they navigate. They process papers sequentially, propose ideas without structured gap analysis, and lack mechanisms for agents to verify, challenge, or refine each other's findings. We present \\textbf{AI-Supervisor}, a multi-agent orchestration framework where specialized agents provide end-to-end AI research supervision driven by human interests -- from literature review through gap discovery, method development, evaluation, and paper writing -- through autonomous exploration and self-correcting updates of research knowledge. Unlike sequential pipelines, AI-Supervisor maintains a continuously evolving \\emph{Research World Model}, implemented as a Knowledge Graph, that captures methods, benchmarks, known limitations, and unexplored gaps, serving as shared memory across all agents and enabling agents to explore and build upon a structured understanding of the research landscape. The framework introduces three architectural contributions: (1) \\emph{structured gap discovery} that decomposes methods into core modules, validates their performance across benchmarks, and maps the specific gaps each module creates; (2) \\emph{self-correcting discovery loops} that probe why modules succeed on certain problems and fail on others, whether benchmarks carry hidden biases, and whether evaluation protocols remain adequate for emerging challenges; and (3) \\emph{self-improving development loops} governed by cross-domain mechanism search that iteratively targets failing modules by finding solutions from other scientific fields. All agents operate under a \\emph{consensus mechanism} where independent findings are corroborated before being committed to the Research World Model.","published":"2026-03-25T15:16:51Z","updated":"2026-03-26T01:57:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.24402v2","pdf_url":"https://arxiv.org/pdf/2603.24402v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.24639","versioned_id":"2603.24639v2","title":"Experiential Reflective Learning for Self-Improving LLM Agents","authors":["Marc-Antoine Allard","Arnaud Teinturier","Victor Xing","Gautier Viaud"],"abstract":"Recent advances in large language models (LLMs) have enabled the development of autonomous agents capable of complex reasoning and multi-step problem solving. However, these agents struggle to adapt to specialized environments and do not leverage past interactions, approaching each new task from scratch regardless of their accumulated experience. We introduce Experiential Reflective Learning (ERL), a simple self-improvement framework that enables rapid environment adaptation through experiential learning. ERL reflects on task trajectories and outcomes to generate heuristics, capturing actionable lessons that transfer across tasks. At test time, relevant heuristics are retrieved based on the current task and injected into the agent's context to guide execution. On the Gaia2 benchmark, ERL improves success rate by 7.8% over a ReAct baseline, with large gains in task completion reliability, and outperforms prior experiential learning methods. Through systematic ablations, we find that selective retrieval is essential and that heuristics provide more transferable abstractions than few-shot trajectory prompting. These results demonstrate that reflecting on single-attempt experiences to extract transferable heuristics enables effective agent self-improvement.","published":"2026-03-25T11:43:22Z","updated":"2026-03-31T19:23:46Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.24639v2","pdf_url":"https://arxiv.org/pdf/2603.24639v2","comment":"Published as a conference paper at the ICLR 2026 MemAgents Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.24018","versioned_id":"2603.24018v1","title":"ELITE: Experiential Learning and Intent-Aware Transfer for Self-improving Embodied Agents","authors":["Bingqing Wei","Zhongyu Xia","Dingai Liu","Xiaoyu Zhou","Zhiwei Lin","Yongtao Wang"],"abstract":"Vision-language models (VLMs) have shown remarkable general capabilities, yet embodied agents built on them fail at complex tasks, often skipping critical steps, proposing invalid actions, and repeating mistakes. These failures arise from a fundamental gap between the static training data of VLMs and the physical interaction for embodied tasks. VLMs can learn rich semantic knowledge from static data but lack the ability to interact with the world. To address this issue, we introduce ELITE, an embodied agent framework with {E}xperiential {L}earning and {I}ntent-aware {T}ransfer that enables agents to continuously learn from their own environment interaction experiences, and transfer acquired knowledge to procedurally similar tasks. ELITE operates through two synergistic mechanisms, \\textit{i.e.,} self-reflective knowledge construction and intent-aware retrieval. Specifically, self-reflective knowledge construction extracts reusable strategies from execution trajectories and maintains an evolving strategy pool through structured refinement operations. Then, intent-aware retrieval identifies relevant strategies from the pool and applies them to current tasks. Experiments on the EB-ALFRED and EB-Habitat benchmarks show that ELITE achieves 9\\% and 5\\% performance improvement over base VLMs in the online setting without any supervision. In the supervised setting, ELITE generalizes effectively to unseen task categories, achieving better performance compared to state-of-the-art training-based methods. These results demonstrate the effectiveness of ELITE for bridging the gap between semantic understanding and reliable action execution.","published":"2026-03-25T07:25:51Z","updated":"2026-03-25T07:25:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.24018v1","pdf_url":"https://arxiv.org/pdf/2603.24018v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.23994","versioned_id":"2603.23994v2","title":"Understanding the Challenges in Iterative Generative Optimization with LLMs","authors":["Allen Nie","Xavier Daull","Zhiyi Kuang","Abhinav Akkiraju","Anish Chaudhuri","Max Piasevoli","Ryan Rong","YuCheng Yuan","Prerit Choudhary","Shannon Xiao","Rasool Fakoor","Adith Swaminathan","Ching-An Cheng"],"abstract":"Generative optimization uses large language models (LLMs) to iteratively improve artifacts (such as code, workflows or prompts) using execution feedback. It is a promising approach to building self-improving agents, yet in practice remains brittle: despite active research, only 9% of surveyed agents used any automated optimization. We argue that this brittleness arises because, to set up a learning loop, an engineer must make ``hidden'' design choices: What can the optimizer edit and what is the \"right\" learning evidence to provide at each update? We investigate three factors that affect most applications: the starting artifact, the credit horizon for execution traces, and batching trials and errors into learning evidence. Through case studies in MLAgentBench, Atari, and BigBench Extra Hard, we find that these design decisions can determine whether generative optimization succeeds, yet they are rarely made explicit in prior work. Different starting artifacts determine which solutions are reachable in MLAgentBench, truncated traces can still improve Atari agents, and larger minibatches do not monotonically improve generalization on BBEH. We conclude that the lack of a simple, universal way to set up learning loops across domains is a major hurdle for productionization and adoption. We provide practical guidance for making these choices.","published":"2026-03-25T06:49:24Z","updated":"2026-05-26T16:57:44Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.23994v2","pdf_url":"https://arxiv.org/pdf/2603.23994v2","comment":"39 pages, 17 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.23910","versioned_id":"2603.23910v1","title":"AnalogAgent: Self-Improving Analog Circuit Design Automation with LLM Agents","authors":["Zhixuan Bao","Zhuoyi Lin","Jiageng Wang","Jinhai Hu","Yuan Gao","Yaoxin Wu","Xiaoli Li","Xun Xu"],"abstract":"Recent advances in large language models (LLMs) suggest strong potential for automating analog circuit design. Yet most LLM-based approaches rely on a single-model loop of generation, diagnosis, and correction, which favors succinct summaries over domain-specific insight and suffers from context attrition that erases critical technical details. To address these limitations, we propose AnalogAgent, a training-free agentic framework that integrates an LLM-based multi-agent system (MAS) with self-evolving memory (SEM) for analog circuit design automation. AnalogAgent coordinates a Code Generator, Design Optimizer, and Knowledge Curator to distill execution feedback into an adaptive playbook in SEM and retrieve targeted guidance for subsequent generation, enabling cross-task transfer without additional expert feedback, databases, or libraries. Across established benchmarks, AnalogAgent achieves 92% Pass@1 with Gemini and 97.4% Pass@1 with GPT-5. Moreover, with compact models (e.g., Qwen-8B), it yields a +48.8% average Pass@1 gain across tasks and reaches 72.1% Pass@1 overall, indicating that AnalogAgent substantially strengthens open-weight models for high-quality analog circuit design automation.","published":"2026-03-25T03:59:02Z","updated":"2026-03-25T03:59:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.23910v1","pdf_url":"https://arxiv.org/pdf/2603.23910v1","comment":"16 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.16379","versioned_id":"2604.16379v1","title":"LLMAR: A Tuning-Free Recommendation Framework for Sparse and Text-Rich Industrial Domains","authors":["Ryogo Hishikawa","Ichiro Kataoka","Shinya Yuda"],"abstract":"Industrial B2B applications (e.g., construction site risk prediction, material procurement) face extreme data sparsity yet feature rich textual interactions. In such environments, traditional ID-based collaborative filtering fails lacking co-occurrence signals, while fine-tuning standard Large Language Models (LLMs) incurs high operational costs and struggles with frequent data drift. We propose LLMAR (LLM-Annotated Recommendation), a tuning-free framework. Moving beyond simple embeddings, LLMAR systematically integrates LLM reasoning to capture user \"latent motives\" without any training process. We introduce three core contributions: (1) Inference-Driven Annotation: uses LLMs to transform behavioral history into structured semantic motives, enabling reasoning-based matching unattainable by ID-based methods; (2) Reflection Loop: a self-correction mechanism that refines generated queries to mitigate hallucinations and resolve \"context competition\" between past history and current instructions; and (3) Cost-Effective Architecture: relies on tuning-free components and asynchronous batch processing to minimize maintenance costs. Evaluations on public benchmarks (MovieLens-1M, Amazon Prime Pantry) and a sparse industrial dataset (construction risk prediction) demonstrate that LLMAR outperforms state-of-the-art learning-based models (SASRecF), achieving up to a 54.6% nDCG@10 improvement on the industrial dataset. Inference costs remain highly practical (~$1 per 1,000 users). For B2B domains where strict real-time latency is not critical, combining LLM reasoning with self-verification offers a superior alternative to training-based approaches across accuracy, explainability, and operational cost.","published":"2026-03-25T02:49:27Z","updated":"2026-03-25T02:49:27Z","categories":["cs.IR","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2604.16379v1","pdf_url":"https://arxiv.org/pdf/2604.16379v1","comment":"10 pages, 3 figures, github link is to be updated","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.23626","versioned_id":"2603.23626v1","title":"A Theory of LLM Information Susceptibility","authors":["Zhuo-Yang Song","Hua Xing Zhu"],"abstract":"Large language models (LLMs) are increasingly deployed as optimization modules in agentic systems, yet the fundamental limits of such LLM-mediated improvement remain poorly understood. Here we propose a theory of LLM information susceptibility, centred on the hypothesis that when computational resources are sufficiently large, the intervention of a fixed LLM does not increase the performance susceptibility of a strategy set with respect to budget. We develop a multi-variable utility-function framework that generalizes this hypothesis to architectures with multiple co-varying budget channels, and discuss the conditions under which co-scaling can exceed the susceptibility bound. We validate the theory empirically across structurally diverse domains and model scales spanning an order of magnitude, and show that nested, co-scaling architectures open response channels unavailable to fixed configurations. These results clarify when LLM intervention helps and when it does not, demonstrating that tools from statistical physics can provide predictive constraints for the design of AI systems. If the susceptibility hypothesis holds generally, the theory suggests that nested architectures may be a necessary structural condition for open-ended agentic self-improvement.","published":"2026-03-24T18:08:43Z","updated":"2026-03-24T18:08:43Z","categories":["cs.LG","cond-mat.stat-mech","cs.AI","cs.CL","nlin.AO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.23626v1","pdf_url":"https://arxiv.org/pdf/2603.23626v1","comment":"16 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.23420","versioned_id":"2603.23420v2","title":"Bilevel Autoresearch: Meta-Autoresearching Itself","authors":["Yaonan Qu","Meng Lu"],"abstract":"If autoresearch is itself a form of research, then autoresearch can be applied to research itself. We present Bilevel Autoresearch, a bilevel framework in which an outer autoresearch loop improves an inner autoresearch loop by reading its code and traces, identifying bottlenecks, and generating injectable Python search mechanisms at runtime. The inner loop optimizes task performance; the outer loop optimizes how the inner loop searches. Both loops use the same LLM, so improvements come from the bilevel architecture rather than a stronger meta-level model, although the outer loop consumes additional inference and wall-clock budget. On Karpathy's GPT pretraining benchmark, the meta-autoresearch outer loop achieves a 5x improvement over the standard inner loop alone (-0.045 vs. -0.009 val_bpb), while parameter-level adjustment without mechanism change yields no reliable gain. The outer loop instantiates mechanisms from adjacent search domains, including combinatorial optimization, multi-armed bandits, and design of experiments, without human specification of the final mechanism design. Trace analysis suggests that these mechanisms break deterministic search patterns and force exploration of directions the LLM's priors avoid. The experiments demonstrate, on this benchmark, a first bilevel step: an outer loop improves the search behavior of an inner loop. Code is the mechanism carrier in this implementation, but skills, prompts, workflows, evaluators, domain principles, world-model assumptions, and memory schemas can also encode mechanisms that shape future agent behavior. This suggests a path toward recursive bootstrapping, where mechanisms discovered for the inner loop can be fed back to improve the meta-level loop itself.","published":"2026-03-24T16:52:25Z","updated":"2026-06-02T18:31:24Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.23420v2","pdf_url":"https://arxiv.org/pdf/2603.23420v2","comment":"16 pages, 5 figures, 3 tables. v2 expands the framing as mechanism-level agentic self-improvement and updates related work and limitations; core method and experiments unchanged. This paper was primarily drafted by AI agents with human oversight and direction","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.23129","versioned_id":"2603.23129v4","title":"Polaris: A Gödel Agent Framework for Small Language Models through Experience-Abstracted Policy Repair","authors":["Aditya Kakade","Vivek Srivastava","Shirish Karande"],"abstract":"Gödel agent realize recursive self-improvement: an agent inspects its own policy and traces and then modifies that policy in a tested loop. We introduce Polaris, Gödel agent for compact models that performs policy repair via experience abstraction, turning failures into policy updates through a structured cycle of analysis, strategy formation, abstraction, and minimal code patch repair with conservative checks. Unlike response level self correction or parameter tuning, Polaris makes policy level changes with small, auditable patches that persist in the policy and are reused on unseen instances within each benchmark. As part of the loop, the agent engages in meta reasoning: it explains its errors, proposes concrete revisions to its own policy, and then updates the policy. To enable cumulative policy refinement, we introduce experience abstraction, which distills failures into compact, reusable strategies that transfer to unseen instances. On MGSM, DROP, GPQA, and LitBench (covering arithmetic reasoning, compositional inference, graduate-level problem solving, and creative writing evaluation), a 7-billion-parameter model equipped with Polaris achieves consistent gains over the base policy and competitive baselines.","published":"2026-03-24T12:25:32Z","updated":"2026-06-24T13:45:14Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.23129v4","pdf_url":"https://arxiv.org/pdf/2603.23129v4","comment":"Accepted to ACL 2026 (Findings). 33 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.22651","versioned_id":"2603.22651v1","title":"Benchmarking Multi-Agent LLM Architectures for Financial Document Processing: A Comparative Study of Orchestration Patterns, Cost-Accuracy Tradeoffs and Production Scaling Strategies","authors":["Siddhant Kulkarni","Yukta Kulkarni"],"abstract":"The adoption of large language models (LLMs) for structured information extraction from financial documents has accelerated rapidly, yet production deployments face fundamental architectural decisions with limited empirical guidance. We present a systematic benchmark comparing four multi-agent orchestration architectures: sequential pipeline, parallel fan-out with merge, hierarchical supervisor-worker and reflexive self-correcting loop. These are evaluated across five frontier and open-weight LLMs on a corpus of 10,000 SEC filings (10-K, 10-Q and 8-K forms). Our evaluation spans 25 extraction field types covering governance structures, executive compensation and financial metrics, measured along five axes: field-level F1, document-level accuracy, end-to-end latency, cost per document and token efficiency. We find that reflexive architectures achieve the highest field-level F1 (0.943) but at 2.3x the cost of sequential baselines, while hierarchical architectures occupy the most favorable position on the cost-accuracy Pareto frontier (F1 0.921 at 1.4x cost). We further present ablation studies on semantic caching, model routing and adaptive retry strategies, demonstrating that hybrid configurations can recover 89\\% of the reflexive architecture's accuracy gains at only 1.15x baseline cost. Our scaling analysis from 1K to 100K documents per day reveals non-obvious throughput-accuracy degradation curves that inform capacity planning. These findings provide actionable guidance for practitioners deploying multi-agent LLM systems in regulated financial environments.","published":"2026-03-24T00:02:47Z","updated":"2026-03-24T00:02:47Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.22651v1","pdf_url":"https://arxiv.org/pdf/2603.22651v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.23559","versioned_id":"2603.23559v2","title":"CAPTCHA Solving for Native GUI Agents: Automated Reasoning-Action Data Generation and Self-Corrective Training","authors":["Yuxi Chen","Haoyu Zhai","Chenkai Wang","Rui Yang","Lingming Zhang","Gang Wang","Huan Zhang"],"abstract":"GUI agents are rapidly shifting from multi-module pipelines to end-to-end, native vision-language models (VLMs) that perceive raw screenshots and directly interact with digital devices. Despite rapid progress on general GUI tasks, CAPTCHA solving remains a major challenge. On the other hand, although specialized CAPTCHA solving pipelines exist, they cannot handle general GUI tasks. To address this gap, we introduce ReCAP: a CAPTCHA-capable native GUI agent that solves modern, interactive CAPTCHA challenges while retaining general GUI-agent performance. We first develop a dynamic CAPTCHA system spanning seven representative CAPTCHA types, designed to stress primitive and complementary capabilities for CAPTCHA solving. Then, we develop an automated data collection and curation pipeline that generates large-scale CAPTCHA interaction trajectories paired with reasoning traces. As CAPTCHA solving often requires multi-step interaction and recovery from intermediate mistakes, we further leverage failed trajectories to construct self-correction data, training agents to reflect on errors and correct their actions online. Across synthetic and real-world test sets, ReCAP substantially improves CAPTCHA-solving success over its base agents, while maintaining strong performance on general GUI-agent benchmarks.","published":"2026-03-23T23:35:59Z","updated":"2026-06-29T04:46:30Z","categories":["cs.CR","cs.AI","cs.CV"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2603.23559v2","pdf_url":"https://arxiv.org/pdf/2603.23559v2","comment":"Accepted to ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.22187","versioned_id":"2603.22187v1","title":"Seeing is Improving: Visual Feedback for Iterative Text Layout Refinement","authors":["Junrong Guo","Shancheng Fang","Yadong Qu","Hongtao Xie"],"abstract":"Recent advances in Multimodal Large Language Models (MLLMs) have enabled automated generation of structured layouts from natural language descriptions. Existing methods typically follow a code-only paradigm that generates code to represent layouts, which are then rendered by graphic engines to produce final images. However, they are blind to the rendered visual outcome, making it difficult to guarantee readability and aesthetics. In this paper, we identify visual feedback as a critical factor in layout generation and propose Visual Feedback Layout Model (VFLM), a self-improving framework that leverages visual feedback iterative refinement. VFLM is capable of performing adaptive reflective generation, which leverages visual information to reflect on previous issues and iteratively generates outputs until satisfactory quality is achieved. It is achieved through reinforcement learning with a visually grounded reward model that incorporates OCR accuracy. By rewarding only the final generated outcome, we can effectively stimulate the model's iterative and reflective generative capabilities. Experiments across multiple benchmarks show that VFLM consistently outperforms advanced MLLMs, existing layout models, and code-only baselines, establishing visual feedback as critical for design-oriented MLLMs. Our code and data are available at https://github.com/FolSpark/VFLM.","published":"2026-03-23T16:48:39Z","updated":"2026-03-23T16:48:39Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.22187v1","pdf_url":"https://arxiv.org/pdf/2603.22187v1","comment":"Accepted by CVPR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.22016","versioned_id":"2603.22016v2","title":"ROM: Real-time Overthinking Mitigation via Streaming Detection and Intervention","authors":["Xinyan Wang","Xiaogeng Liu","Chaowei Xiao"],"abstract":"Large Reasoning Models (LRMs) often reach a correct solution before their long Chain-of-Thought trace ends, yet continue with redundant verification, repeated attempts, or unnecessary exploration that wastes computation and can even overturn the correct answer. We frame this behavior as a latent productive-to-redundant transition and show that it is directly reflected in hidden states: around first-correct-solution (FCS) boundaries, late-layer representations separate efficient from overthinking tokens, while boundary-permutation and position-control baselines collapse. Based on this signal, we propose ROM, a model-agnostic streaming intervention framework that monitors frozen LRMs with a lightweight hidden-state detector and intervenes at well-formed reasoning boundaries. Counterfactual Self-Correction (CSC) augments supervision with balanced wrong to correct trajectories, preserving useful pre-FCS correction while labeling only post-FCS continuation as redundant. Across MATH500, GSM8K, AIME25, and MMLU-Pro, ROM improves the overall tradeoff on both Qwen3-8B and DeepSeek-R1-Distill-Qwen-32B (DS-32B): on Qwen3-8B, it raises accuracy from 74.47% to 74.78% and reduces response length from 4262 to 3107 tokens; on DS-32B, it raises accuracy from 68.60% to 68.72% and reduces response length from 3062 to 2319 tokens. The same FCS-derived supervision transfers across scale and training origin, suggesting a shared long-CoT boundary rather than a backbone-specific artifact. ROM is compatible with L1, removing another 20.9-21.6% tokens at zero accuracy loss. ROM also generalizes to open-ended MMLU-Pro (+1.56 pp, 35.4% shorter) and reduces wall-clock latency by 46.5%. Code is available at https://github.com/SaFo-Lab/ROM.","published":"2026-03-23T14:26:57Z","updated":"2026-05-09T22:19:27Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.22016v2","pdf_url":"https://arxiv.org/pdf/2603.22016v2","comment":"Code is available at https://github.com/SaFo-Lab/ROM","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.21728","versioned_id":"2603.21728v1","title":"EvoIdeator: Evolving Scientific Ideas through Checklist-Grounded Reinforcement Learning","authors":["Andreas Sauter","Yuyue Zhao","Jacopo Urbani","Wenxiang Hu","Zaiqiao Meng","Lun Zhou","Xiaohui Yan","Yougang Lyu"],"abstract":"Scientific idea generation is a cornerstone of autonomous knowledge discovery, yet the iterative evolution required to transform initial concepts into high-quality research proposals remains a formidable challenge for Large Language Models (LLMs). Existing Reinforcement Learning (RL) paradigms often rely on rubric-based scalar rewards that provide global quality scores but lack actionable granularity. Conversely, language-based refinement methods are typically confined to inference-time prompting, targeting models that are not explicitly optimized to internalize such critiques. To bridge this gap, we propose \\textbf{EvoIdeator}, a framework that facilitates the evolution of scientific ideas by aligning the RL training objective with \\textbf{checklist-grounded feedback}. EvoIdeator leverages a structured judge model to generate two synergistic signals: (1) \\emph{lexicographic rewards} for multi-dimensional optimization, and (2) \\emph{fine-grained language feedback} that offers span-level critiques regarding grounding, feasibility, and methodological rigor. By integrating these signals into the RL loop, we condition the policy to systematically utilize precise feedback during both optimization and inference. Extensive experiments demonstrate that EvoIdeator, built on Qwen3-4B, significantly outperforms much larger frontier models across key scientific metrics. Crucially, the learned policy exhibits strong generalization to diverse external feedback sources without further fine-tuning, offering a scalable and rigorous path toward self-refining autonomous ideation.","published":"2026-03-23T09:15:26Z","updated":"2026-03-23T09:15:26Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.21728v1","pdf_url":"https://arxiv.org/pdf/2603.21728v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2605.20189","versioned_id":"2605.20189v1","title":"SOLAR: A Self-Optimizing Open-Ended Autonomous Agent for Lifelong Learning and Continual Adaptation","authors":["Nitin Vetcha","Dianbo Liu"],"abstract":"Despite the remarkable success of large language models (LLMs), they still face bottlenecks while deploying in dynamic, real-world settings with primary challenges being concept drift and the high cost of gradient-based adaptation. Traditional fine-tuning (FT) struggles to adapt to non-stationary data streams without resulting in catastrophic for getting or requiring extensive manual data curation. To address these limitations within the streaming and continual learning paradigm, we propose the Self-Optimizing Lifelong Autonomous Reasoner (SOLAR) which is an open-ended autonomous agent that leverages parameter-level meta-learning to self-improve, treating model weights as an environment for exploration. It initiates the process by consolidating a strong prior over common-sense knowledge making it effective for transfer-learning. By utilizing a multi-level reinforcement learning approach, SOLAR autonomously discovers adaptation strategies, enabling efficient test-time adaptation to unseen domains. Crucially, SOLAR maintains an evolving knowledge base of valid modification strategies, implicitly acting as an episodic memory buffer to balance plasticity (adaptation to new tasks) and stability (retention of meta-knowledge). Experiments demonstrate that SOLAR outperforms strong baselines on common-sense, mathematical, medical, coding, social and logical reasoning tasks, marking a significant step toward autonomous agents capable of lifelong adaptation in evolving environments.","published":"2026-03-23T07:18:02Z","updated":"2026-03-23T07:18:02Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.20189v1","pdf_url":"https://arxiv.org/pdf/2605.20189v1","comment":"Accepted at \"Association for the Advancement of Artificial Intelligence 2026 Conference\" in Streaming Continual Learning Bridge. Published in CEUR Workshop Proceedings (Original version at https://ceur-ws.org/Vol-4183/paper2.pdf)","journal_ref":"CEUR Workshop Proceedings, Vol. 4183, 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2603.21558","versioned_id":"2603.21558v2","title":"Reliable Self-Improvement Training by Verifying Reasoning, Not Just Answers","authors":["Xinyu Zhang"],"abstract":"Self-improvement training, where models learn from self-generated solutions, promises sustained capability gains but suffers from a pervasive failure mode: across multiple rounds, compounding reasoning errors cause accuracy to stall or degrade. We trace this drift to standard filtering criteria that retain solutions based solely on final answer correctness, which lets lucky guesses (correct answers with flawed reasoning) contaminate the training data. We propose Verified Self-Improvement (VSI), a framework that conditions data retention on step-level structural integrity rather than just the final output. VSI validates solutions by recomputing arithmetic steps via a computer-algebra library (sympy), checking intermediate consistency, and enforcing domain constraints. Evaluating VSI on GSM8K with Qwen3-4B-Thinking across 5 rounds of self-improvement against four baselines (no verification, outcome verification, majority voting, and VSI with DPO) shows that VSI rejects approximately 34% of correct-answer solutions, successfully isolating lucky guesses. This cleaner training signal drives sustained accuracy gains across all rounds (80.5% to 91.0%), whereas outcome verification plateaus and unverified training collapses. Finally, converting VSI checks into DPO preference pairs trains the model to distinguish sound reasoning from lucky answers, boosting reward accuracy from 46% to 63%. VSI offers a simple, reproducible recipe for robust self-improvement whenever automated reasoning checks are available.","published":"2026-03-23T04:25:56Z","updated":"2026-05-28T21:14:17Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.21558v2","pdf_url":"https://arxiv.org/pdf/2603.21558v2","comment":"Accepted at ICLR 2026 Workshop LLM Reasoning. 10 pages, 3 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.21520","versioned_id":"2603.21520v1","title":"Generalizable Self-Evolving Memory for Automatic Prompt Optimization","authors":["Guanbao Liang","Yuanchen Bei","Sheng Zhou","Yuheng Qin","Huan Zhou","Bingxin Jia","Bin Li","Jiajun Bu"],"abstract":"Automatic prompt optimization is a promising approach for adapting large language models (LLMs) to downstream tasks, yet existing methods typically search for a specific prompt specialized to a fixed task. This paradigm limits generalization across heterogeneous queries and prevents models from accumulating reusable prompting knowledge over time. In this paper, we propose MemAPO, a memory-driven framework that reconceptualizes prompt optimization as generalizable and self-evolving experience accumulation. MemAPO maintains a dual-memory mechanism that distills successful reasoning trajectories into reusable strategy templates while organizing incorrect generations into structured error patterns that capture recurrent failure modes. Given a new prompt, the framework retrieves both relevant strategies and failure patterns to compose prompts that promote effective reasoning while discouraging known mistakes. Through iterative self-reflection and memory editing, MemAPO continuously updates its memory, enabling prompt optimization to improve over time rather than restarting from scratch for each task. Experiments on diverse benchmarks show that MemAPO consistently outperforms representative prompt optimization baselines while substantially reducing optimization cost.","published":"2026-03-23T03:29:54Z","updated":"2026-03-23T03:29:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.21520v1","pdf_url":"https://arxiv.org/pdf/2603.21520v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.13079","versioned_id":"2604.13079v1","title":"Alignment as Institutional Design: From Behavioral Correction to Transaction Structure in Intelligent Systems","authors":["Rui Chai"],"abstract":"Current AI alignment paradigms rely on behavioral correction: external supervisors (e.g., RLHF) observe outputs, judge against preferences, and adjust parameters. This paper argues that behavioral correction is structurally analogous to an economy without property rights, where order requires perpetual policing and does not scale. Drawing on institutional economics (Coase, Alchian, Cheung), capability mutual exclusivity, and competitive cost discovery, we propose alignment as institutional design: the designer specifies internal transaction structures (module boundaries, competition topologies, cost-feedback loops) such that aligned behavior emerges as the lowest-cost strategy for each component. We identify three irreducible levels of human intervention (structural, parametric, monitorial) and show that this framework transforms alignment from a behavioral control problem into a political-economy problem. No institution eliminates self-interest or guarantees optimality; the best design makes misalignment costly, detectable, and correctable. We conclude that the proper goal is institutional robustness-a dynamic, self-correcting process under human oversight, not perfection. This work provides the normative foundation for the Wuxing resource-competition mechanisms in companion papers. Keywords: AI alignment, institutional design, transaction costs, property rights, resource competition, behavioral correction, RLHF, cost truthfulness, modular architecture, correctable alignment","published":"2026-03-23T02:11:52Z","updated":"2026-03-23T02:11:52Z","categories":["cs.CY","cs.AI","cs.GT","cs.LG"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2604.13079v1","pdf_url":"https://arxiv.org/pdf/2604.13079v1","comment":"This is Paper 5 in a 10-paper series on Super-Alignment via Wuxing Institutional Architecture. It shifts alignment from external behavioral correction to internal institutional design, making aligned behavior the lowest-cost equilibrium","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.21340","versioned_id":"2603.21340v1","title":"ARYA: A Physics-Constrained Composable & Deterministic World Model Architecture","authors":["Seth Dobrin","Lukasz Chmiel"],"abstract":"This paper presents ARYA, a composable, physics-constrained, deterministic world model architecture built on five foundational principles: nano models, composability, causal reasoning, determinism, and architectural AI safety. We demonstrate that ARYA satisfies all canonical world model requirements, including state representation, dynamic prediction, causal and physical awareness, temporal consistency, generalization, learnability, and planning and control. Unlike monolithic foundation models, the ARYA foundation model implements these capabilities through a hierarchical system-of-system-of-systems of specialized nano models, orchestrated by AARA (ARYA Autonomous Research Agent), an always-on cognitive daemon that executes a continuous sense-decide-act-learn loop. The nano model architecture provides linear scaling, sparse activation, selective untraining, and sub-20-second training cycles, resolving the traditional tension between capability and computational efficiency. A central contribution is the Unfireable Safety Kernel: an architecturally immutable safety boundary that cannot be disabled or circumvented by any system component, including its own self-improvement engine. This is not a social or ethical alignment statement; it is a technical framework ensuring human control persists as autonomy increases. Safety is an architectural constraint governing every operation, not a policy layer applied after the fact. We present formal alignment between ARYA's architecture and canonical world model requirements, and report summarizing its state-of-the-art performance across 6 of 9 competitive benchmarks head-to-head with GPT-5.2, Opus 4.6, and V-JEPA-2. All with zero neural network parameters, across seven active industry domain nodes spanning aerospace, pharma manufacturing, oil and gas, smart cities, biotech, defense, and medical devices.","published":"2026-03-22T17:46:04Z","updated":"2026-03-22T17:46:04Z","categories":["cs.AI","cs.DC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.21340v1","pdf_url":"https://arxiv.org/pdf/2603.21340v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.21301","versioned_id":"2603.21301v1","title":"Enhancing reasoning accuracy in large language models during inference time","authors":["Vinay Sharma","Manish Jain"],"abstract":"Large Language Models (LLMs) often exhibit strong linguistic abilities while remaining unreliable on multi-step reasoning tasks, particularly when deployed without additional training or fine-tuning. In this work, we study inference-time techniques to improve the reasoning accuracy of LLMs. We systematically evaluate three classes of inference-time strategies: (i) self-consistency via stochastic decoding, where the model is sampled multiple times using controlled temperature and nucleus sampling and the most frequent final answer is selected; (ii) dual-model reasoning agreement, where outputs from two independent models are compared and only consistent reasoning traces are trusted; and (iii) self-reflection, where the model critiques and revises its own reasoning. Across all evaluated methods, we employ Chain-of-Thought (CoT) [1] prompting to elicit explicit intermediate reasoning steps before generating final answers. In this work, we provide a controlled comparative evaluation across three inference-time strategies under identical prompting and verification settings. Our experiments on LLM [2] show that self-consistency with nucleus sampling and controlled temperature value yields the substantial gains, achieving a 9% to 15% absolute improvement in accuracy over greedy single-pass decoding, well-suited for low-risk domains, offering meaningful gains with minimal overhead. The dual-model approach provides additional confirmation for model reasoning steps thus more appropriate for moderate-risk domains, where higher reliability justifies additional compute. Self-reflection offers only marginal improvements, suggesting limited effectiveness for smaller non-reasoning models at inference time.","published":"2026-03-22T16:00:07Z","updated":"2026-03-22T16:00:07Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.21301v1","pdf_url":"https://arxiv.org/pdf/2603.21301v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.22352","versioned_id":"2603.22352v1","title":"WIST: Web-Grounded Iterative Self-Play Tree for Domain-Targeted Reasoning Improvement","authors":["Fangyuan Li","Pengfei Li","Shijie Wang","Junqi Gao","Jianxing Liu","Biqing Qi","Yuqiang Li"],"abstract":"Recent progress in reinforcement learning with verifiable rewards (RLVR) offers a practical path to self-improvement of language models, but existing methods face a key trade-off: endogenous self-play can drift over iterations, while corpus-grounded approaches rely on curated data environments. We present \\textbf{WIST}, a \\textbf{W}eb-grounded \\textbf{I}terative \\textbf{S}elf-play \\textbf{T}ree framework for domain-targeted reasoning improvement that learns directly from the open web without requiring any pre-arranged domain corpus. WIST incrementally expands a domain tree for exploration, and retrieves and cleans path-consistent web corpus to construct a controllable training environment. It then performs Challenger--Solver self-play with verifiable rewards, and feeds learnability signals back to update node posteriors and guide subsequent exploration through an adaptive curriculum. Across four backbones, WIST consistently improves over the base models and typically outperforms both purely endogenous self-evolution and corpus-grounded self-play baselines, with the Overall gains reaching \\textbf{+9.8} (\\textit{Qwen3-4B-Base}) and \\textbf{+9.7} (\\textit{OctoThinker-8B}). WIST is also domain-steerable, improving \\textit{Qwen3-8B-Base} by \\textbf{+14.79} in medicine and \\textit{Qwen3-4B-Base} by \\textbf{+5.28} on PhyBench. Ablations further confirm the importance of WIST's key components for stable open-web learning. Our Code is available at https://github.com/lfy-123/WIST.","published":"2026-03-22T09:55:16Z","updated":"2026-03-22T09:55:16Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.22352v1","pdf_url":"https://arxiv.org/pdf/2603.22352v1","comment":"23 pages, 4 figures. Submitted to ACL2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.20667","versioned_id":"2603.20667v1","title":"REVERE: Reflective Evolving Research Engineer for Scientific Workflows","authors":["Balaji Dinesh Gangireddi","Aniketh Garikaparthi","Manasi Patwardhan","Arman Cohan"],"abstract":"Existing prompt-optimization techniques rely on local signals to update behavior, often neglecting broader and recurring patterns across tasks, leading to poor generalization; they further rely on full-prompt rewrites or unstructured merges, resulting in knowledge loss. These limitations are magnified in research-coding workflows, which involve heterogeneous repositories, underspecified environments, and weak feedback, where reproducing results from public codebases is an established evaluation regime. We introduce Reflective Evolving Research Engineer (REVERE), a framework that continuously learns from Global Training Context, recognizes recurring failure modes in cross-repository execution trajectories, distills them into reusable heuristics, and performs targeted edits across three configurable fields: the system prompt, a task-prompt template, and a cumulative cheatsheet. REVERE, via this reflective optimization framework, improves performance over prior state-of-the-art expert-crafted instructions on research coding tasks by 4.50% on SUPER, 3.51% on ResearchCodeBench, and 4.89% on ScienceAgentBench across their respective metrics. These results demonstrate that agents equipped with mechanisms for continual learning and global memory consolidation can meaningfully evolve their capabilities over time.","published":"2026-03-21T05:58:30Z","updated":"2026-03-21T05:58:30Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.20667v1","pdf_url":"https://arxiv.org/pdf/2603.20667v1","comment":"ICLR 2026, Recursive Self-Improvement Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.20441","versioned_id":"2603.20441v1","title":"A Training-Free Regeneration Paradigm: Contrastive Reflection Memory Guided Self-Verification and Self-Improvement","authors":["Yuran Li","Di Wu","Benoit Boulet"],"abstract":"Verification-guided self-improvement has recently emerged as a promising approach to improving the accuracy of large language model (LLM) outputs. However, existing approaches face a trade-off between inference efficiency and accuracy: iterative verification-rectification is computationally expensive and prone to being trapped in faulty reasoning, while best-of-N selection requires extensive sampling without addressing internal model flaws. We propose a training-free regeneration paradigm that leverages an offline-curated contrastive Reflection Memory (RM) to provide corrective guidance, while regenerating from scratch helps break out of faulty reasoning. At inference time, the method performs RM-guided self-verification followed by a single RM-guided regeneration, avoiding both iterative correction and multi-sample selection. We evaluated our method on nine benchmarks that span algorithmic, reasoning, symbolic, and domain-specific tasks in both small- and large-scale LLMs. Experiment results show that our method outperforms prior methods while maintaining low computational cost.","published":"2026-03-20T19:12:36Z","updated":"2026-03-20T19:12:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.20441v1","pdf_url":"https://arxiv.org/pdf/2603.20441v1","comment":"18 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.20164","versioned_id":"2603.20164v1","title":"The Robot's Inner Critic: Self-Refinement of Social Behaviors through VLM-based Replanning","authors":["Jiyu Lim","Youngwoo Yoon","Kwanghyun Park"],"abstract":"Conventional robot social behavior generation has been limited in flexibility and autonomy, relying on predefined motions or human feedback. This study proposes CRISP (Critique-and-Replan for Interactive Social Presence), an autonomous framework where a robot critiques and replans its own actions by leveraging a Vision-Language Model (VLM) as a `human-like social critic.' CRISP integrates (1) extraction of movable joints and constraints by analyzing the robot's description file (e.g., MJCF), (2) generation of step-by-step behavior plans based on situational context, (3) generation of low-level joint control code by referencing visual information (joint range-of-motion visualizations), (4) VLM-based evaluation of social appropriateness and naturalness, including pinpointing erroneous steps, and (5) iterative refinement of behaviors through reward-based search. This approach is not tied to a specific robot API; it can generate subtly different, human-like motions on various platforms using only the robot's structure file. In a user study involving five different robot types and 20 scenarios, including mobile manipulators and humanoids, our proposed method achieved significantly higher preference and situational appropriateness ratings compared to previous methods. This research presents a general framework that minimizes human intervention while expanding the robot's autonomous interaction capabilities and cross-platform applicability. Detailed result videos and supplementary information regarding this work are available at: https://limjiyu99.github.io/inner-critic/","published":"2026-03-20T17:40:21Z","updated":"2026-03-20T17:40:21Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2603.20164v1","pdf_url":"https://arxiv.org/pdf/2603.20164v1","comment":"Accepted to ICRA 2026. 8 pages, 9 figures, Project page: https://limjiyu99.github.io/inner-critic/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.20046","versioned_id":"2603.20046v1","title":"Experience is the Best Teacher: Motivating Effective Exploration in Reinforcement Learning for LLMs","authors":["Wenjian Zhang","Kongcheng Zhang","Jiaxin Qi","Baisheng Lai","Jianqiang Huang"],"abstract":"Reinforcement Learning (RL) with rubric-based rewards has recently shown remarkable progress in enhancing general reasoning capabilities of Large Language Models (LLMs), yet still suffers from ineffective exploration confined to curent policy distribution. In fact, RL optimization can be viewed as steering the policy toward an ideal distribution that maximizes the rewards, while effective exploration should align efforts with desired target. Leveraging this insight, we propose HeRL, a Hindsight experience guided Reinforcement Learning framework to bootstrap effective exploration by explicitly telling LLMs the desired behaviors specified in rewards. Concretely, HeRL treats failed trajectories along with their unmet rubrics as hindsight experience, which serves as in-context guidance for the policy to explore desired responses beyond its current distribution. Additionally, we introduce a bonus reward to incentivize responses with greater potential for improvement under such guidance. HeRL facilitates effective learning from desired high quality samples without repeated trial-and-error from scratch, yielding a more accurate estimation of the expected gradient theoretically. Extensive experiments across various benchmarks demonstrate that HeRL achieves superior performance gains over baselines, and can further benefit from experience guided self-improvement at test time. Our code is available at https://github.com/sikelifei/HeRL.","published":"2026-03-20T15:32:06Z","updated":"2026-03-20T15:32:06Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.20046v1","pdf_url":"https://arxiv.org/pdf/2603.20046v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.19461","versioned_id":"2603.19461v1","title":"Hyperagents","authors":["Jenny Zhang","Bingchen Zhao","Wannan Yang","Jakob Foerster","Jeff Clune","Minqi Jiang","Sam Devlin","Tatiana Shavrina"],"abstract":"Self-improving AI systems aim to reduce reliance on human engineering by learning to improve their own learning and problem-solving processes. Existing approaches to self-improvement rely on fixed, handcrafted meta-level mechanisms, fundamentally limiting how fast such systems can improve. The Darwin Gödel Machine (DGM) demonstrates open-ended self-improvement in coding by repeatedly generating and evaluating self-modified variants. Because both evaluation and self-modification are coding tasks, gains in coding ability can translate into gains in self-improvement ability. However, this alignment does not generally hold beyond coding domains. We introduce \\textbf{hyperagents}, self-referential agents that integrate a task agent (which solves the target task) and a meta agent (which modifies itself and the task agent) into a single editable program. Crucially, the meta-level modification procedure is itself editable, enabling metacognitive self-modification, improving not only the task-solving behavior, but also the mechanism that generates future improvements. We instantiate this framework by extending DGM to create DGM-Hyperagents (DGM-H), eliminating the assumption of domain-specific alignment between task performance and self-modification skill to potentially support self-accelerating progress on any computable task. Across diverse domains, the DGM-H improves performance over time and outperforms baselines without self-improvement or open-ended exploration, as well as prior self-improving systems. Furthermore, the DGM-H improves the process by which it generates new agents (e.g., persistent memory, performance tracking), and these meta-level improvements transfer across domains and accumulate across runs. DGM-Hyperagents offer a glimpse of open-ended AI systems that do not merely search for better solutions, but continually improve their search for how to improve.","published":"2026-03-19T20:50:08Z","updated":"2026-03-19T20:50:08Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.19461v1","pdf_url":"https://arxiv.org/pdf/2603.19461v1","comment":"Code at https://github.com/facebookresearch/Hyperagents","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.18428","versioned_id":"2603.18428v1","title":"Adaptive Decoding via Test-Time Policy Learning for Self-Improving Generation","authors":["Asmita Bhardwaj","Yuya Jeremy Ong","Eelaaf Zahid","Basel Shbita"],"abstract":"Decoding strategies largely determine the quality of Large Language Model (LLM) outputs, yet widely used heuristics such as greedy or fixed temperature/top-p decoding are static and often task-agnostic, leading to suboptimal or inconsistent generation quality across domains that demand stylistic or structural flexibility. We introduce a reinforcement learning-based decoder sampler that treats decoding as sequential decision-making and learns a lightweight policy to adjust sampling parameters at test-time while keeping LLM weights frozen. We evaluated summarization datasets including BookSum, arXiv, and WikiHow using Granite-3.3-2B and Qwen-2.5-0.5B. Our policy sampler consistently outperforms greedy and static baselines, achieving relative gains of up to +88% (BookSum, Granite) and +79% (WikiHow, Qwen). Reward ablations show that overlap-only objectives underperform compared to composite rewards, while structured shaping terms (length, coverage, repetition, completeness) enable stable and sustained improvements. These findings highlight reinforcement learning as a practical mechanism for test-time adaptation in decoding, enabling domain-aware and user-controllable generation without retraining large models.","published":"2026-03-19T02:44:42Z","updated":"2026-03-19T02:44:42Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.18428v1","pdf_url":"https://arxiv.org/pdf/2603.18428v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.18273","versioned_id":"2603.18273v1","title":"EDM-ARS: A Domain-Specific Multi-Agent System for Automated Educational Data Mining Research","authors":["Chenguang Pan","Zhou Zhang","Weixuan Xiao","Chengyuan Yao"],"abstract":"In this technical report, we present the Educational Data Mining Automated Research System (EDM-ARS), a domain-specific multi-agent pipeline that automates end-to-end educational data mining (EDM) research. We conceptualize EDM-ARS as a general framework for domain-aware automated research pipelines, where educational expertise is embedded into each stage of the research lifecycle. As a first instantiation of this framework, we focus on predictive modeling tasks. Within this scope, EDM-ARS orchestrates five specialized LLM-powered agents (ProblemFormulator, DataEngineer, Analyst, Critic, and Writer) through a state-machine coordinator that supports revision loops, checkpoint-based recovery, and sandboxed code execution. Given a research prompt and a dataset, EDM-ARS produces a complete LaTeX manuscript with real Semantic Scholar citations, validated machine learning analyses, and automated methodological peer review. We also provide a detailed description of the system architecture, the three-tier data registry design that encodes educational domain expertise, the specification of each agent, the inter-agent communication protocol, and mechanisms for error-handling and self-correction. Finally, we discuss current limitations, including single-dataset scope and formulaic paper output, and outline a phased roadmap toward causal inference, transfer learning, psychometric, and multi-dataset generalization. EDM-ARS is released as an open-source project to support the educational research community.","published":"2026-03-18T20:45:45Z","updated":"2026-03-18T20:45:45Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.18273v1","pdf_url":"https://arxiv.org/pdf/2603.18273v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.17973","versioned_id":"2603.17973v2","title":"TDAD: Test-Driven Agentic Development - Reducing Code Regressions in AI Coding Agents via Graph-Based Impact Analysis","authors":["Pepe Alonso","Sergio Yovine","Victor A. Braberman"],"abstract":"AI coding agents can resolve real-world software issues, yet they frequently introduce regressions -- breaking tests that previously passed. Current benchmarks focus almost exclusively on resolution rate, leaving regression behavior under-studied. This paper presents TDAD (Test-Driven Agentic Development), an open-source tool that performs pre-change impact analysis for AI coding agents. TDAD builds a dependency map between source code and tests so that before committing a patch, the agent knows which tests to verify and can self-correct. The map is delivered as a lightweight agent skill -- a static text file the agent queries at runtime. Evaluated on SWE-bench Verified with two open-weight models running on consumer hardware (Qwen3-Coder 30B, 100 instances; Qwen3.5-35B-A3B, 25 instances), TDAD reduced regressions by 70% (6.08% to 1.82%) compared to a vanilla baseline. In contrast, adding TDD procedural instructions without targeted test context increased regressions to 9.94% -- worse than no intervention at all. When deployed as an agent skill with a different model and framework, TDAD improved issue-resolution rate from 24% to 32%, confirming that surfacing contextual information outperforms prescribing procedural workflows. All code, data, and logs are publicly available at https://github.com/pepealonso95/TDAD.","published":"2026-03-18T17:38:22Z","updated":"2026-03-19T17:12:15Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.17973v2","pdf_url":"https://arxiv.org/pdf/2603.17973v2","comment":"Toolpaper, 7 pages, 7 tables, 3 figures, 1 algorithm. Submitted to ACM AIWare 2026 (Data and Benchmark Track)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.17887","versioned_id":"2603.17887v1","title":"AI-Assisted Goal Setting Improves Goal Progress Through Social Accountability","authors":["Michel Schimpf","Julian Voigt","Thomas Bohné"],"abstract":"Helping people identify and pursue personally meaningful career goals at scale remains a key challenge in applied psychology. Career coaching can improve goal quality and attainment, but its cost and limited availability restrict access. Large language model (LLM)-based chatbots offer a scalable alternative, yet the psychological mechanisms by which they might support goal pursuit remain untested. Here we report a preregistered three-arm randomised controlled trial (N = 517) comparing an AI career coach (\"Leon,\" powered by Claude Sonnet), a matched structured written questionnaire covering closely matched reflective topics, and a no-support control on goal progress at a two-week follow-up. The AI chatbot produced significantly higher goal progress than the control (d = 0.33, p = .016). Compared with the written-reflection condition, the AI did not significantly improve overall goal progress, but it increased perceived social accountability. In the preregistered mediation model, perceived accountability mediated the AI-over-questionnaire effect on goal progress (indirect effect = 0.15, 95% CI [0.04, 0.31]), whereas self-concordance did not. These findings suggest that AI-assisted goal setting can improve short-term goal progress, and that its clearest added value over structured self-reflection lies in increasing felt accountability.","published":"2026-03-18T16:12:25Z","updated":"2026-03-18T16:12:25Z","categories":["cs.HC","cs.AI"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2603.17887v1","pdf_url":"https://arxiv.org/pdf/2603.17887v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.18118","versioned_id":"2603.18118v1","title":"Insight-V++: Towards Advanced Long-Chain Visual Reasoning with Multimodal Large Language Models","authors":["Yuhao Dong","Zuyan Liu","Shulin Tian","Yongming Rao","Ziwei Liu"],"abstract":"Large Language Models (LLMs) have achieved remarkable reliability and advanced capabilities through extended test-time reasoning. However, extending these capabilities to Multi-modal Large Language Models (MLLMs) remains a significant challenge due to a critical scarcity of high-quality, long-chain reasoning data and optimized training pipelines. To bridge this gap, we present a unified multi-agent visual reasoning framework that systematically evolves from our foundational image-centric model, Insight-V, into a generalized spatial-temporal architecture, Insight-V++. We first propose a scalable data generation pipeline equipped with multi-granularity assessment that autonomously synthesizes structured, complex reasoning trajectories across image and video domains without human intervention. Recognizing that directly supervising MLLMs with such intricate data yields sub-optimal results, we design a dual-agent architecture comprising a reasoning agent to execute extensive analytical chains, and a summary agent to critically evaluate and distill final outcomes. While our initial framework utilized Direct Preference Optimization (DPO), its off-policy nature fundamentally constrained reinforcement learning potential. To overcome these limitations, particularly for long-horizon video understanding, Insight-V++ introduces two novel algorithms, ST-GRPO and J-GRPO, which enhance spatial-temporal reasoning and improve evaluative robustness. Crucially, by leveraging reliable feedback from the summary agent, we guide an iterative reasoning path generation process, retraining the entire multi-agent system in a continuous, self-improving loop. Extensive experiments on base models like LLaVA-NeXT and Qwen2.5-VL demonstrate significant performance gains across challenging image and video reasoning benchmarks while preserving strong capabilities on traditional perception-focused tasks.","published":"2026-03-18T15:28:07Z","updated":"2026-03-18T15:28:07Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.18118v1","pdf_url":"https://arxiv.org/pdf/2603.18118v1","comment":"arXiv admin note: text overlap with arXiv:2411.14432","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.17750","versioned_id":"2603.17750v1","title":"Towards Infinitely Long Neural Simulations: Self-Refining Neural Surrogate Models for Dynamical Systems","authors":["Qi Liu","Laure Zanna","Joan Bruna"],"abstract":"Recent advances in autoregressive neural surrogate models have enabled orders-of-magnitude speedups in simulating dynamical systems. However, autoregressive models are generally prone to distribution drift: compounding errors in autoregressive rollouts that severely degrade generation quality over long time horizons. Existing work attempts to address this issue by implicitly leveraging the inherent trade-off between short-time accuracy and long-time consistency through hyperparameter tuning. In this work, we introduce a unifying mathematical framework that makes this tradeoff explicit, formalizing and generalizing hyperparameter-based strategies in existing approaches. Within this framework, we propose a robust, hyperparameter-free model implemented as a conditional diffusion model that balances short-time fidelity with long-time consistency by construction. Our model, Self-refining Neural Surrogate model (SNS), can be implemented as a standalone model that refines its own autoregressive outputs or as a complementary model to existing neural surrogates to ensure long-time consistency. We also demonstrate the numerical feasibility of SNS through high-fidelity simulations of complex dynamical systems over arbitrarily long time horizons.","published":"2026-03-18T14:14:40Z","updated":"2026-03-18T14:14:40Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.17750v1","pdf_url":"https://arxiv.org/pdf/2603.17750v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.17729","versioned_id":"2603.17729v3","title":"SARE: Sample-wise Adaptive Reasoning for Training-free Fine-grained Visual Recognition","authors":["Jingxiao Yang","DaLin He","Miao Pan","Kaixiang Yao","Ge Su","Wenqi Zhang","Yifeng Hu","Tangwei Li","Yuke Li","Xuhong Zhang"],"abstract":"Recent advances in Large Vision-Language Models (LVLMs) have enabled training-free Fine-Grained Visual Recognition (FGVR). However, effectively exploiting LVLMs for FGVR remains challenging due to the inherent visual ambiguity of subordinate-level categories. Existing methods predominantly adopt either retrieval-oriented or reasoning-oriented paradigms to tackle this challenge, but both are constrained by two fundamental limitations:(1) They apply the same inference pipeline to all samples without accounting for uneven recognition difficulty, thereby leading to suboptimal accuracy and efficiency; (2) The lack of mechanisms to consolidate and reuse error-specific experience causes repeated failures on similar challenging cases. To address these limitations, we propose SARE, a Sample-wise Adaptive textbfREasoning framework for training-free FGVR. Specifically, SARE adopts a cascaded design that combines fast candidate retrieval with fine-grained reasoning, invoking the latter only when necessary. In the reasoning process, SARE incorporates a self-reflective experience mechanism that leverages past failures to provide transferable discriminative guidance during inference, without any parameter updates. Extensive experiments across 14 datasets substantiate that SARE achieves state-of-the-art performance while substantially reducing computational overhead.","published":"2026-03-18T13:49:27Z","updated":"2026-04-28T03:35:25Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.17729v3","pdf_url":"https://arxiv.org/pdf/2603.17729v3","comment":"preprint, under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.18073","versioned_id":"2603.18073v1","title":"Continually self-improving AI","authors":["Zitong Yang"],"abstract":"Modern language model-based AI systems are remarkably powerful, yet their capabilities remain fundamentally capped by their human creators in three key ways. First, although a model's weights can be updated via fine-tuning, acquiring new knowledge from small, specialized corpora after pretraining remains highly data-inefficient. Second, the training of these systems relies heavily on finite, human-generated data from across history. Third, the pipelines used to train AI models are confined by the algorithms that human researchers can discover and explore. This thesis takes a small step toward overcoming these inherent limitations, presenting three chapters aimed at breaking these dependencies to create continually self-improving AI. First, to overcome this data-efficiency barrier in knowledge acquisition, we propose a synthetic data approach that diversifies and amplifies small corpora into rich knowledge representations, enabling a model to effectively update its parameters from limited source material. Second, to reduce reliance on human data, we show that given a fixed amount of such data, the model can self-generate synthetic data to bootstrap its fundamental pretraining capabilities without distillation from any off-the-shelf, instruction-tuned LM. Finally, to transcend human-engineered training paradigms, we demonstrate that by scaling search during test time over the space of algorithms, AI can search over a larger space of learning algorithm configurations than human researchers can explore manually.","published":"2026-03-18T04:54:05Z","updated":"2026-03-18T04:54:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.18073v1","pdf_url":"https://arxiv.org/pdf/2603.18073v1","comment":"PhD thesis","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.18589","versioned_id":"2604.18589v1","title":"CentaurTA Studio: A Self-Improving Human-Agent Collaboration System for Thematic Analysis","authors":["Lei Wang","Min Huang","Eduard Dragut"],"abstract":"Thematic analysis is difficult to scale: manual workflows are labor-intensive, while fully automated pipelines often lack controllability and transparent evaluation. We present \\textbf{CentaurTA Studio}, a web-based system for self-improving human--agent collaboration in open coding and theme construction. The system integrates (1) a two-stage human feedback pipeline separating simulator drafting and expert validation, (2) persistent prompt optimization that distills validated feedback into reusable alignment principles, and (3) rubric-based evaluation with early stopping for process control. Across three domains, CentaurTA achieves the strongest performance in both Open Coding and Theme Construction, reaching up to 92.12\\% accuracy and consistently outperforming baseline systems. Agreement between the rubric-based LLM judge and human annotators reaches substantial reliability (average $κ= 0.68$). Ablation studies show that removing the feedback loop reduces performance from 90\\% to 81\\%, while eliminating the Critic or early stopping degrades accuracy or increases interaction cost. The full system reaches peak performance within 10 iterative rounds (about 25 minutes), demonstrating improved efficiency over expert-only refinement.","published":"2026-03-18T02:01:28Z","updated":"2026-03-18T02:01:28Z","categories":["cs.HC","cs.AI"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2604.18589v1","pdf_url":"https://arxiv.org/pdf/2604.18589v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.17191","versioned_id":"2603.17191v1","title":"Tabular LLMs for Interpretable Few-Shot Alzheimer's Disease Prediction with Multimodal Biomedical Data","authors":["Sophie Kearney","Shu Yang","Zixuan Wen","Weimin Lyu","Bojian Hou","Duy Duong-Tran","Tianlong Chen","Jason H. Moore","Marylyn D. Ritchie","Chao Chen","Li Shen"],"abstract":"Accurate diagnosis of Alzheimer's disease (AD) requires handling tabular biomarker data, yet such data are often small and incomplete, where deep learning models frequently fail to outperform classical methods. Pretrained large language models (LLMs) offer few-shot generalization, structured reasoning, and interpretable outputs, providing a powerful paradigm shift for clinical prediction. We propose TAP-GPT Tabular Alzheimer's Prediction GPT, a domain-adapted tabular LLM framework built on TableGPT2 and fine-tuned for few-shot AD classification using tabular prompts rather than plain texts. We evaluate TAP-GPT across four ADNI-derived datasets, including QT-PAD biomarkers and region-level structural MRI, amyloid PET, and tau PET for binary AD classification. Across multimodal and unimodal settings, TAP-GPT improves upon its backbone models and outperforms traditional machine learning baselines in the few-shot setting while remaining competitive with state-of-the-art general-purpose LLMs. We show that feature selection mitigates degradation in high-dimensional inputs and that TAP-GPT maintains stable performance under simulated and real-world missingness without imputation. Additionally, TAP-GPT produces structured, modality-aware reasoning aligned with established AD biology and shows greater stability under self-reflection, supporting its use in iterative multi-agent systems. To our knowledge, this is the first systematic application of a tabular-specialized LLM to multimodal biomarker-based AD prediction, demonstrating that such pretrained models can effectively address structured clinical prediction tasks and laying the foundation for tabular LLM-driven multi-agent clinical decision-support systems. The source code is publicly available on GitHub: https://github.com/sophie-kearney/TAP-GPT.","published":"2026-03-17T22:43:50Z","updated":"2026-03-17T22:43:50Z","categories":["cs.CL","cs.LG","q-bio.QM"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.17191v1","pdf_url":"https://arxiv.org/pdf/2603.17191v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.17075","versioned_id":"2603.17075v1","title":"CircuitBuilder: From Polynomials to Circuits via Reinforcement Learning","authors":["Weikun K. Zhang","Rohan Pandey","Bhaumik Mehta","Kaijie Jin","Naomi Morato","Archit Ganapule","Michael Ruofan Zeng","Jarod Alper"],"abstract":"Motivated by auto-proof generation and Valiant's VP vs. VNP conjecture, we study the problem of discovering efficient arithmetic circuits to compute polynomials, using addition and multiplication gates. We formulate this problem as a single-player game, where an RL agent attempts to build the circuit within a fixed number of operations. We implement an AlphaZero-style training loop and compare two approaches: Proximal Policy Optimization with Monte Carlo Tree Search (PPO+MCTS) and Soft Actor-Critic (SAC). SAC achieves the highest success rates on two-variable targets, while PPO+MCTS scales to three variables and demonstrates steady improvement on harder instances. These results suggest that polynomial circuit synthesis is a compact, verifiable setting for studying self-improving search policies.","published":"2026-03-17T19:04:37Z","updated":"2026-03-17T19:04:37Z","categories":["cs.LG","cs.AI","cs.CC"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.17075v1","pdf_url":"https://arxiv.org/pdf/2603.17075v1","comment":"ICLR 2026 Workshop on AI with Recursive Self-Improvement","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.16870","versioned_id":"2603.16870v2","title":"Demystifying Video Reasoning","authors":["Ruisi Wang","Zhongang Cai","Fanyi Pu","Junxiang Xu","Wanqi Yin","Maijunxian Wang","Ran Ji","Chenyang Gu","Bo Li","Ziqi Huang","Hokin Deng","Dahua Lin","Ziwei Liu","Lei Yang"],"abstract":"Recent advances in video generation have revealed an unexpected phenomenon: diffusion-based video models exhibit non-trivial reasoning capabilities. Prior work attributes this to a Chain-of-Frames (CoF) mechanism, where reasoning is assumed to unfold sequentially across video frames. In this work, we challenge this assumption and uncover a fundamentally different mechanism. We show that reasoning in video models instead primarily emerges along the diffusion denoising steps. Through qualitative analysis and targeted probing experiments, we find that models explore multiple candidate solutions in early denoising steps and progressively converge to a final answer, a process we term Chain-of-Steps (CoS). Beyond this core mechanism, we identify several emergent reasoning behaviors critical to model performance: (1) working memory, enabling persistent reference; (2) self-correction and enhancement, allowing recovery from incorrect intermediate solutions; and (3) perception before action, where early steps establish semantic grounding and later steps perform structured manipulation. During a diffusion step, we further uncover self-evolved functional specialization within Diffusion Transformers, where early layers encode dense perceptual structure, middle layers execute reasoning, and later layers consolidate latent representations. Motivated by these insights, we present a simple training-free strategy as a proof-of-concept, demonstrating how reasoning can be improved by ensembling latent trajectories from identical models with different random seeds. Overall, our work provides a systematic understanding of how reasoning emerges in video generation models, offering a foundation to guide future research in better exploiting the inherent reasoning dynamics of video models as a new substrate for intelligence.","published":"2026-03-17T17:59:55Z","updated":"2026-05-26T06:31:40Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.16870v2","pdf_url":"https://arxiv.org/pdf/2603.16870v2","comment":"Homepage: https://www.wruisi.com/demystifying_video_reasoning","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.16664","versioned_id":"2603.16664v1","title":"Kestrel: Grounding Self-Refinement for LVLM Hallucination Mitigation","authors":["Jiawei Mao","Hardy Chen","Haoqin Tu","Yuhan Wang","Letian Zhang","Zeyu Zheng","Huaxiu Yao","Zirui Wang","Cihang Xie","Yuyin Zhou"],"abstract":"Large vision-language models (LVLMs) have become increasingly strong but remain prone to hallucinations in multimodal tasks, which significantly narrows their deployment. As training these LVLMs to avoid hallucinations becomes prohibitively expensive for larger models, training-free methods offer a cheap and flexible solution to this problem, yet existing approaches based on decoding or tool use often bring limited gains and/or weak interpretability. We propose Kestrel, a training-free framework for LVLM hallucination mitigation that combines an explicit visual-grounding agent with evidence-verified self-refinement mechanism. In detail, Kestrel first collects explicit visual evidence and converts tool outputs into reusable and structured textual evidence. Second, to take full advantage of these evidence, Kestrel verifies them via an LVLM judge for evidence checking, then iteratively self-refine answers based on verified evidence to reduce the risk of over-correction. Extensive experiments show that Kestrel improves performance over strong baselines across hallucination benchmarks (e.g., average +3.31% on POPE and +28.34 on MME-Hallucination with Qwen3-VL), while providing transparent verification traces for hallucination diagnosis and analysis -- e.g., both the integrated self-refinement module and grounding agent contributing an average +2.0% gain on POPE.","published":"2026-03-17T15:30:47Z","updated":"2026-03-17T15:30:47Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.16664v1","pdf_url":"https://arxiv.org/pdf/2603.16664v1","comment":"16 pages, 11 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.16331","versioned_id":"2603.16331v2","title":"Decoding the Critique Mechanism in Large Reasoning Models","authors":["Hoang Phan","Quang H. Nguyen","Hung T. Q. Le","Xiusi Chen","Heng Ji","Khoa D. Doan"],"abstract":"Large Reasoning Models (LRMs) exhibit backtracking and self-verification mechanisms that enable them to revise intermediate steps and reach correct solutions, yielding strong performance on complex logical benchmarks. We hypothesize that such behaviors are beneficial only when the model has sufficiently strong ``critique'' ability to detect its own mistakes. This work systematically investigates how current LRMs recover from errors by inserting arithmetic mistakes in their intermediate reasoning steps. Notably, we discover a peculiar yet important phenomenon: despite the error propagating throughout the entire chain-of-thought (CoT) without any verbalized correction, the model still reaches the correct final answer after the thinking process finishes. This recovery implies the existence of an internal mechanism helping the model to detect errors and trigger self-correction, which we refer to as the \\textit{hidden critique ability}. Building on feature space analysis, we identify a highly interpretable \\textit{critique vector} representing this behavior. Extensive experiments across multiple model scales and families demonstrate that steering latent representations with this vector improves the model's error detection capability and enhances the performance of test-time scaling at no extra training cost. Our findings provide a valuable understanding of LRMs' critique behavior, suggesting a promising direction to control and improve their self-verification mechanism. Our code is available at: https://github.com/mail-research/lrm-critique-vectors.","published":"2026-03-17T10:03:30Z","updated":"2026-05-22T07:55:26Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.16331v2","pdf_url":"https://arxiv.org/pdf/2603.16331v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.16085","versioned_id":"2603.16085v2","title":"Interact3D: Compositional 3D Generation of Interactive Objects","authors":["Hui Shan","Keyang Luo","Ming Li","Sizhe Zheng","Yanwei Fu","Zhen Chen","Xiangru Huang"],"abstract":"Recent breakthroughs in 3D generation have enabled the synthesis of high-fidelity individual assets. However, generating 3D compositional objects from single images--particularly under occlusions--remains challenging. Existing methods often degrade geometric details in hidden regions and fail to preserve the underlying object-object spatial relationships (OOR). We present a novel framework Interact3D designed to generate physically plausible interacting 3D compositional objects. Our approach first leverages advanced generative priors to curate high-quality individual assets with a unified 3D guidance scene. To physically compose these assets, we then introduce a robust two-stage composition pipeline. Based on the 3D guidance scene, the primary object is anchored through precise global-to-local geometric alignment (registration), while subsequent geometries are integrated using a differentiable Signed Distance Field (SDF)-based optimization that explicitly penalizes geometry intersections. To reduce challenging collisions, we further deploy a closed-loop, agentic refinement strategy. A Vision-Language Model (VLM) autonomously analyzes multi-view renderings of the composed scene, formulates targeted corrective prompts, and guides an image editing module to iteratively self-correct the generation pipeline. Extensive experiments demonstrate that Interact3D successfully produces promising collsion-aware compositions with improved geometric fidelity and consistent spatial relationships.","published":"2026-03-17T03:21:06Z","updated":"2026-07-01T07:12:56Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.16085v2","pdf_url":"https://arxiv.org/pdf/2603.16085v2","comment":"Accepted to ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.16052","versioned_id":"2603.16052v1","title":"A Context Alignment Pre-processor for Enhancing the Coherence of Human-LLM Dialog","authors":["Ding Wei"],"abstract":"Large language models (LLMs) have made remarkable progress in generating fluent text, but they still face a critical challenge of contextual misalignment in long-term and dynamic dialogue. When human users omit premises, simplify references, or shift context abruptly during interactions with LLMs, the models may fail to capture their actual intentions, producing mechanical or off-topic responses that weaken the collaborative potential of dialogue. To address this problem, this paper proposes a computational framework called the Context Alignment Pre-processor (C.A.P.). Rather than operating during generation, C.A.P. functions as a pre-processing module between user input and response generation. The framework includes three core processes: (1) semantic expansion, which extends a user instruction to a broader semantic span including its premises, literal meaning, and implications; (2) time-weighted context retrieval, which prioritizes recent dialogue history through a temporal decay function approximating human conversational focus; and (3) alignment verification and decision branching, which evaluates whether the dialogue remains on track by measuring the semantic similarity between the current prompt and the weighted historical context. When a significant deviation is detected, C.A.P. initiates a structured clarification protocol to help users and the system recalibrate the conversation. This study presents the architecture and theoretical basis of C.A.P., drawing on cognitive science and Common Ground theory in human-computer interaction. We argue that C.A.P. is not only a technical refinement but also a step toward shifting human-computer dialogue from one-way command-execution patterns to two-way, self-correcting, partnership-based collaboration. Finally, we discuss implementation paths, evaluation methods, and implications for the future design of interactive intelligent systems.","published":"2026-03-17T01:36:14Z","updated":"2026-03-17T01:36:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.16052v1","pdf_url":"https://arxiv.org/pdf/2603.16052v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15957","versioned_id":"2603.15957v1","title":"GASP: Guided Asymmetric Self-Play For Coding LLMs","authors":["Swadesh Jana","Cansu Sancaktar","Tomáš Daniš","Georg Martius","Antonio Orvieto","Pavel Kolev"],"abstract":"Asymmetric self-play has emerged as a promising paradigm for post-training large language models, where a teacher continually generates questions for a student to solve at the edge of the student's learnability. Although these methods promise open-ended data generation bootstrapped from no human data, they suffer from one major problem: not all problems that are hard to solve are interesting or informative to improve the overall capabilities of the model. Current asymmetric self-play methods are goal-agnostic with no real grounding. We propose Guided Asymmetric Self-Play (GASP), where grounding is provided by real-data goalpost questions that are identified to pose a hard exploration challenge to the model. During self-play, the teacher first generates an easier variant of a hard question, and then a harder variant of that easier question, with the goal of gradually closing the gap to the goalpost throughout training. Doing so, we improve pass@20 on LiveCodeBench (LCB) by 2.5% over unguided asymmetric self-play, and through the curriculum constructed by the teacher, we manage to solve hard goalpost questions that remain out of reach for all baselines.","published":"2026-03-16T22:13:19Z","updated":"2026-03-16T22:13:19Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.15957v1","pdf_url":"https://arxiv.org/pdf/2603.15957v1","comment":"Accepted at ICLR 2026 Workshop on AI with Recursive Self-Improvement (RSI 2026) as Spotlight, and ICLR 2026 Workshop on Lifelong Agents (LLA 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15800","versioned_id":"2603.15800v1","title":"Evolving Contextual Safety in Multi-Modal Large Language Models via Inference-Time Self-Reflective Memory","authors":["Ce Zhang","Jinxi He","Junyi He","Katia Sycara","Yaqi Xie"],"abstract":"Multi-modal Large Language Models (MLLMs) have achieved remarkable performance across a wide range of visual reasoning tasks, yet their vulnerability to safety risks remains a pressing concern. While prior research primarily focuses on jailbreak defenses that detect and refuse explicitly unsafe inputs, such approaches often overlook contextual safety, which requires models to distinguish subtle contextual differences between scenarios that may appear similar but diverge significantly in safety intent. In this work, we present MM-SafetyBench++, a carefully curated benchmark designed for contextual safety evaluation. Specifically, for each unsafe image-text pair, we construct a corresponding safe counterpart through minimal modifications that flip the user intent while preserving the underlying contextual meaning, enabling controlled evaluation of whether models can adapt their safety behaviors based on contextual understanding. Further, we introduce EchoSafe, a training-free framework that maintains a self-reflective memory bank to accumulate and retrieve safety insights from prior interactions. By integrating relevant past experiences into current prompts, EchoSafe enables context-aware reasoning and continual evolution of safety behavior during inference. Extensive experiments on various multi-modal safety benchmarks demonstrate that EchoSafe consistently achieves superior performance, establishing a strong baseline for advancing contextual safety in MLLMs. All benchmark data and code are available at https://echosafe-mllm.github.io.","published":"2026-03-16T18:32:26Z","updated":"2026-03-16T18:32:26Z","categories":["cs.CV","cs.CL","cs.CR"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.15800v1","pdf_url":"https://arxiv.org/pdf/2603.15800v1","comment":"Accepted at CVPR 2026. Project page: https://echosafe-mllm.github.io","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15771","versioned_id":"2603.15771v1","title":"CorrectionPlanner: Self-Correction Planner with Reinforcement Learning in Autonomous Driving","authors":["Yihong Guo","Dongqiangzi Ye","Sijia Chen","Anqi Liu","Xianming Liu"],"abstract":"Autonomous driving requires safe planning, but most learning-based planners lack explicit self-correction ability: once an unsafe action is proposed, there is no mechanism to correct it. Thus, we propose CorrectionPlanner, an autoregressive planner with self-correction that models planning as motion-token generation within a propose, evaluate, and correct loop. At each planning step, the policy proposes an action, namely a motion token, and a learned collision critic predicts whether it will induce a collision within a short horizon. If the critic predicts a collision, we retain the sequence of historical unsafe motion tokens as a self-correction trace, generate the next motion token conditioned on it, and repeat this process until a safe motion token is proposed or the safety criterion is met. This self-correction trace, consisting of all unsafe motion tokens, represents the planner's correction process in motion-token space, analogous to a reasoning trace in language models. We train the planner with imitation learning followed by model-based reinforcement learning using rollouts from a pretrained world model that realistically models agents' reactive behaviors. Closed-loop evaluations show that CorrectionPlanner reduces collision rate by over 20% on Waymax and achieves state-of-the-art planning scores on nuPlan.","published":"2026-03-16T18:03:21Z","updated":"2026-03-16T18:03:21Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2603.15771v1","pdf_url":"https://arxiv.org/pdf/2603.15771v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15724","versioned_id":"2603.15724v1","title":"Meta-TTRL: A Metacognitive Framework for Self-Improving Test-Time Reinforcement Learning in Unified Multimodal Models","authors":["Lit Sin Tan","Junzhe Chen","Xiaolong Fu","Lichen Ma","Junshi Huang","Jianzhong Shi","Yan Li","Lijie Wen"],"abstract":"Existing test-time scaling (TTS) methods for unified multimodal models (UMMs) in text-to-image (T2I) generation primarily rely on search or sampling strategies that produce only instance-level improvements, limiting the ability to learn from prior inferences and accumulate knowledge across similar prompts. To overcome these limitations, we propose Meta-TTRL, a metacognitive test-time reinforcement learning framework. Meta-TTRL performs test-time parameter optimization guided by model-intrinsic monitoring signals derived from the meta-knowledge of UMMs, achieving self-improvement and capability-level improvement at test time. Extensive experiments demonstrate that Meta-TTRL generalizes well across three representative UMMs, including Janus-Pro-7B, BAGEL, and Qwen-Image, achieving significant gains on compositional reasoning tasks and multiple T2I benchmarks with limited data. We provide the first comprehensive analysis to investigate the potential of test-time reinforcement learning (TTRL) for T2I generation in UMMs. Our analysis further reveals a key insight underlying effective TTRL: metacognitive synergy, where monitoring signals align with the model's optimization regime to enable self-improvement.","published":"2026-03-16T17:28:57Z","updated":"2026-03-16T17:28:57Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.15724v1","pdf_url":"https://arxiv.org/pdf/2603.15724v1","comment":"8 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15500","versioned_id":"2603.15500v2","title":"Understanding Reasoning in LLMs through Strategic Information Allocation under Uncertainty","authors":["Jeonghye Kim","Xufang Luo","Minbeom Kim","Sangmook Lee","Dongsheng Li","Yuqing Yang"],"abstract":"LLMs often exhibit Aha moments such as self-correction after tokens like \"Wait,\" yet the underlying mechanism remains unclear. Standard LLMs collapse mainly through silent divergence, where trajectories drift from the correct answer yet remain locally coherent, so no explicit error triggers reactive self-correction. We introduce an information-theoretic framework that separates reasoning into procedural advancement and epistemic verbalization, the token-level externalization of uncertainty, and prove that sporadic verbalization restores convergence toward the correct answer even without explicit error triggers. Empirically, a minimal doubt cue recovers failed trajectories, and small-scale SFT suffices to instill or suppress this capability, suggesting that strong reasoning hinges less on an extraordinary inner mechanism than on the linguistic habit of externalizing uncertainty. Our framework recasts reasoning as strategic information allocation under uncertainty, offering a new lens for understanding and advancing LLM reasoning.","published":"2026-03-16T16:31:24Z","updated":"2026-05-26T15:01:26Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.15500v2","pdf_url":"https://arxiv.org/pdf/2603.15500v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15713","versioned_id":"2603.15713v1","title":"Embedding-Aware Feature Discovery: Bridging Latent Representations and Interpretable Features in Event Sequences","authors":["Artem Sakhno","Ivan Sergeev","Alexey Shestov","Omar Zoloev","Elizaveta Kovtun","Gleb Gusev","Andrey Savchenko","Maksim Makarenko"],"abstract":"Industrial financial systems operate on temporal event sequences such as transactions, user actions, and system logs. While recent research emphasizes representation learning and large language models, production systems continue to rely heavily on handcrafted statistical features due to their interpretability, robustness under limited supervision, and strict latency constraints. This creates a persistent disconnect between learned embeddings and feature-based pipelines. We introduce Embedding-Aware Feature Discovery (EAFD), a unified framework that bridges this gap by coupling pretrained event-sequence embeddings with a self-reflective LLM-driven feature generation agent. EAFD iteratively discovers, evaluates, and refines features directly from raw event sequences using two complementary criteria: \\emph{alignment}, which explains information already encoded in embeddings, and \\emph{complementarity}, which identifies predictive signals missing from them. Across both open-source and industrial transaction benchmarks, EAFD consistently outperforms embedding-only and feature-based baselines, achieving relative gains of up to $+5.8\\%$ over state-of-the-art pretrained embeddings, resulting in new state-of-the-art performance across event-sequence datasets.","published":"2026-03-16T14:29:26Z","updated":"2026-03-16T14:29:26Z","categories":["cs.LG","cs.AI","cs.IR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.15713v1","pdf_url":"https://arxiv.org/pdf/2603.15713v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15309","versioned_id":"2603.15309v1","title":"CCTU: A Benchmark for Tool Use under Complex Constraints","authors":["Junjie Ye","Guoqiang Zhang","Wenjie Fu","Tao Gui","Qi Zhang","Xuanjing Huang"],"abstract":"Solving problems through tool use under explicit constraints constitutes a highly challenging yet unavoidable scenario for large language models (LLMs), requiring capabilities such as function calling, instruction following, and self-refinement. However, progress has been hindered by the absence of dedicated evaluations. To address this, we introduce CCTU, a benchmark for evaluating LLM tool use under complex constraints. CCTU is grounded in a taxonomy of 12 constraint categories spanning four dimensions (i.e., resource, behavior, toolset, and response). The benchmark comprises 200 carefully curated and challenging test cases across diverse tool-use scenarios, each involving an average of seven constraint types and an average prompt length exceeding 4,700 tokens. To enable reliable evaluation, we develop an executable constraint validation module that performs step-level validation and enforces compliance during multi-turn interactions between models and their environments. We evaluate nine state-of-the-art LLMs in both thinking and non-thinking modes. Results indicate that when strict adherence to all constraints is required, no model achieves a task completion rate above 20%. Further analysis reveals that models violate constraints in over 50% of cases, particularly in the resource and response dimensions. Moreover, LLMs demonstrate limited capacity for self-refinement even after receiving detailed feedback on constraint violations, highlighting a critical bottleneck in the development of robust tool-use agents. To facilitate future research, we release the data and code.","published":"2026-03-16T14:05:13Z","updated":"2026-03-16T14:05:13Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.15309v1","pdf_url":"https://arxiv.org/pdf/2603.15309v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15061","versioned_id":"2603.15061v1","title":"Writer-R1: Enhancing Generative Writing in LLMs via Memory-augmented Replay Policy Optimization","authors":["Jihao Zhao","Shuaishuai Zu","Zhiyuan Ji","Chunlai Zhou","Biao Qin"],"abstract":"As a typical open-ended generation task, creative writing lacks verifiable reference answers, which has long constrained reward modeling and automatic evaluation due to high human annotation costs, evaluative bias, and coarse feedback signals. To address these challenges, this paper first designs a multi-agent collaborative workflow based on Grounded Theory, performing dimensional decomposition and hierarchical induction of the problem to dynamically produce interpretable and reusable fine-grained criteria. Furthermore, we propose the Memory-augmented Replay Policy Optimization (MRPO) algorithm: on the one hand, without additional training, MRPO guides models to engage in self-reflection based on dynamic criteria, enabling controlled iterative improvement; on the other hand, we adopt the training paradigm that combines supervised fine-tuning with reinforcement learning to convert evaluation criteria into reward signals, achieving end-to-end optimization. Experimental results demonstrate that the automatically constructed criteria achieve performance gains comparable to human annotations. Writer-R1-4B models trained with this approach outperform baselines across multiple creative writing tasks and surpass some 100B+ parameter open-source models.","published":"2026-03-16T10:18:20Z","updated":"2026-03-16T10:18:20Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.15061v1","pdf_url":"https://arxiv.org/pdf/2603.15061v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.14730","versioned_id":"2603.14730v2","title":"GNNVerifier: Graph-based Verifier for LLM Task Planning","authors":["Yu Hao","Qiuyu Wang","Cheng Yang","Yawen Li","Zhiqiang Zhang","Chuan Shi"],"abstract":"Large language models (LLMs) facilitate the development of autonomous agents. As a core component of such agents, task planning aims to decompose complex natural language requests into concrete, solvable sub-tasks. Since LLM-generated plans are frequently prone to hallucinations and sensitive to long-context prom-pts, recent research has introduced plan verifiers to identify and correct potential flaws. However, most existing approaches still rely on an LLM as the verifier via additional prompting for plan review or self-reflection. LLM-based verifiers can be misled by plausible narration and struggle to detect failures caused by structural relations across steps, such as type mismatches, missing intermediates, or broken dependencies. To address these limitations, we propose a graph-based verifier for LLM task planning. Specifically, the proposed method has four major components: Firstly, we represent a plan as a directed graph with enriched attributes, where nodes denote sub-tasks and edges encode execution order and dependency constraints. Secondly, a graph neural network (GNN) then performs structural evaluation and diagnosis, producing a graph-level plausibility score for plan acceptance as well as node/edge-level risk scores to localize erroneous regions. Thirdly, we construct controllable perturbations from ground truth plan graphs, and automatically generate training data with fine-grained annotations. Finally, guided by the feedback from our GNN verifier, we enable an LLM to conduct local edits (e.g., tool replacement or insertion) to correct the plan when the graph-level score is insufficient. Extensive experiments across diverse datasets, backbone LLMs, and planners demonstrate that our GNNVerifier achieves significant gains in improving plan quality. Our data and code is available at https://github.com/BUPT-GAMMA/GNNVerifier.","published":"2026-03-16T02:05:21Z","updated":"2026-03-17T04:26:31Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.14730v2","pdf_url":"https://arxiv.org/pdf/2603.14730v2","comment":"17pages,12figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.14724","versioned_id":"2603.14724v1","title":"GameUIAgent: An LLM-Powered Framework for Automated Game UI Design with Structured Intermediate Representation","authors":["Wei Zeng","Fengwei An","Zhen Liu","Jian Zhao"],"abstract":"Game UI design requires consistent visual assets across rarity tiers yet remains a predominantly manual process. We present GameUIAgent, an LLM-powered agentic framework that translates natural language descriptions into editable Figma designs via a Design Spec JSON intermediate representation. A six-stage neuro-symbolic pipeline combines LLM generation, deterministic post-processing, and a Vision-Language Model (VLM)-guided Reflection Controller (RC) for iterative self-correction with guaranteed non-regressive quality. Evaluated across 110 test cases, three LLMs, and three UI templates, cross-model analysis establishes a game-domain failure taxonomy (rarity-dependent degradation; visual emptiness) and uncovers two key empirical findings. A Quality Ceiling Effect (Pearson r=-0.96, p<0.01) suggests that RC improvement is bounded by headroom below a quality threshold -- a visual-domain counterpart to test-time compute scaling laws. A Rendering-Evaluation Fidelity Principle reveals that partial rendering enhancements paradoxically degrade VLM evaluation by amplifying structural defects. Together, these results establish foundational principles for LLM-driven visual generation agents in game production.","published":"2026-03-16T01:57:56Z","updated":"2026-03-16T01:57:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.14724v1","pdf_url":"https://arxiv.org/pdf/2603.14724v1","comment":"8 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.14041","versioned_id":"2603.14041v1","title":"GRPO and Reflection Reward for Mathematical Reasoning in Large Language Models","authors":["Zhijie Wang"],"abstract":"The enhancement of reasoning capabilities in large language models (LLMs) has garnered significant attention, with supervised fine-tuning (SFT) and reinforcement learning emerging as dominant paradigms. While recent studies recognize the importance of reflection in reasoning processes, existing methodologies seldom address proactive reflection encouragement during training. This study focuses on mathematical reasoning by proposing a four-stage framework integrating Group Relative Policy Optimization (GRPO) with reflection reward mechanisms to strengthen LLMs' self-reflective capabilities. Besides, this approach incorporates established accuracy and format reward. Experimental results demonstrate GRPO's state-of-the-art performance through reflection-encouraged training, with ablation studies confirming the reflection reward's pivotal role. Comparative evaluations demonstrate full-parameter SFT's superiority over low-rank adaptation (LoRA) despite heightened computational demands. Building on these cumulative findings, this research substantiates GRPO's methodological significance in post-training optimization and envisions its potential to serve as a pivotal enabler for future LLM-based intelligent agents through the synergistic integration of cognitive rewards with dynamic environmental interactions.","published":"2026-03-14T17:24:13Z","updated":"2026-03-14T17:24:13Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.14041v1","pdf_url":"https://arxiv.org/pdf/2603.14041v1","comment":"","journal_ref":"Applied and Computational Engineering 154 161-166 (2025)","doi":"10.54254/2755-2721/2025.TJ23144","discovered_on":"2026-07-17"},{"id":"2603.19306","versioned_id":"2603.19306v1","title":"VERDICT: Verifiable Evolving Reasoning with Directive-Informed Collegial Teams for Legal Judgment Prediction","authors":["Hui Liao","Chuan Qin","Yongwen Ren","Hao Li","Zhenya Huang","Yanyong Zhang","Chao Wang"],"abstract":"Legal Judgment Prediction (LJP) predicts applicable law articles, charges, and penalty terms from case facts. Beyond accuracy, LJP calls for intrinsically interpretable and legally grounded reasoning that can reconcile statutory rules with precedent-informed standards. However, existing methods often behave as static, one-shot predictors, providing limited procedural support for verifiable reasoning and little capability to adapt as jurisprudential practice evolves. We propose VERDICT, a self-refining collaborative multi-agent framework that simulates a virtual collegial panel. VERDICT assigns specialized agents to complementary roles (e.g., fact structuring, legal retrieval, opinion drafting, and supervisory verification) and coordinates them in a traceable draft--verify--revise workflow with explicit Pass/Reject feedback, producing verifiable reasoning traces and revision rationales. To capture evolving case experience, we further introduce a Hybrid Jurisprudential Memory (HJM) grounded in the Micro-Directive Paradigm, which stores precedent standards and continually distills validated multi-agent verification trajectories into updated Micro-Directives for continual learning across cases. We evaluate VERDICT on CAIL2018 and a newly constructed CJO2025 dataset with a strict future time-split for temporal generalization. VERDICT achieves state-of-the-art performance on CAIL2018 and demonstrates strong generalization on CJO2025. To facilitate reproducibility and further research, we release our code and the dataset at https://anonymous.4open.science/r/ARR-4437.","published":"2026-03-13T07:19:08Z","updated":"2026-03-13T07:19:08Z","categories":["cs.IR","cs.AI","cs.LG"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2603.19306v1","pdf_url":"https://arxiv.org/pdf/2603.19306v1","comment":"15 pages,3 figures,4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.12366","versioned_id":"2603.12366v2","title":"Sinkhorn-Drifting Generative Models","authors":["Ping He","Om Khangaonkar","Hamed Pirsiavash","Yikun Bai","Soheil Kolouri"],"abstract":"We establish a theoretical link between the recently proposed \"drifting\" generative dynamics and gradient flows induced by the Sinkhorn divergence. In a particle discretization, the drift field admits a cross-minus-self decomposition: an attractive term toward the target distribution and a repulsive/self-correction term toward the current model, both expressed via one-sided normalized Gibbs kernels. We show that Sinkhorn divergence yields an analogous cross-minus-self structure, but with each term defined by entropic optimal-transport couplings obtained through two-sided Sinkhorn scaling (i.e., enforcing both marginals). This provides a precise sense in which drifting acts as a surrogate for a Sinkhorn-divergence gradient flow, interpolating between one-sided normalization and full two-sided Sinkhorn scaling. Crucially, this connection resolves an identifiability gap in prior drifting formulations: leveraging the definiteness of the Sinkhorn divergence, we show that zero drift (equilibrium of the dynamics) implies that the model and target measures match. Experiments show that Sinkhorn drifting reduces sensitivity to kernel temperature and improves one-step generative quality, trading off additional training time for a more stable optimization, without altering the inference procedure used by drift methods. These theoretical gains translate to strong low-temperature improvements in practice: on FFHQ-ALAE at the lowest temperature setting we evaluate, Sinkhorn drifting reduces mean FID from 187.7 to 37.1 and mean latent EMD from 453.3 to 144.4, while on MNIST it preserves full class coverage across the temperature sweep. Project page: https://mint-vu.github.io/SinkhornDrifting/","published":"2026-03-12T18:33:36Z","updated":"2026-03-26T21:32:47Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.12366v2","pdf_url":"https://arxiv.org/pdf/2603.12366v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.13417","versioned_id":"2603.13417v1","title":"Bridging Protocol and Production: Design Patterns for Deploying AI Agents with Model Context Protocol","authors":["Vasundra Srinivasan"],"abstract":"The Model Context Protocol (MCP) standardizes how AI agents discover and invoke external tools, with over 10,000 active servers and 97 million monthly SDK downloads as of early 2026. Yet MCP does not yet standardize how agents safely operate those tools at production scale. Three protocol-level primitives remain missing: identity propagation, adaptive tool budgeting, and structured error semantics. This paper identifies these gaps through field lessons from an enterprise deployment of an AI agent platform integrated with a major cloud provider's MCP servers (client name redacted). We propose three mechanisms to fill them: (1) the Context-Aware Broker Protocol (CABP), which extends JSON-RPC with identity-scoped request routing via a six-stage broker pipeline; (2) Adaptive Timeout Budget Allocation (ATBA), which frames sequential tool invocation as a budget allocation problem over heterogeneous latency distributions; and (3) the Structured Error Recovery Framework (SERF), which provides machine-readable failure semantics that enable deterministic agent self-correction. We organize production failure modes into five design dimensions (server contracts, user context, timeouts, errors, and observability), document concrete failure vignettes, and present a production readiness checklist. All three algorithms are formalized as testable hypotheses with reproducible experimental methodology. Field observations demonstrate that while MCP provides a solid protocol foundation, reliable agent tool integration requires infrastructure-level mechanisms that the specification does not yet address.","published":"2026-03-12T17:42:24Z","updated":"2026-03-12T17:42:24Z","categories":["cs.SE","cs.AI","cs.MA"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.13417v1","pdf_url":"https://arxiv.org/pdf/2603.13417v1","comment":"23 pages, 5 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.12149","versioned_id":"2603.12149v1","title":"Linking Perception, Confidence and Accuracy in MLLMs","authors":["Yuetian Du","Yucheng Wang","Rongyu Zhang","Zhijie Xu","Boyu Yang","Ming Kong","Jie Liu","Qiang Zhu"],"abstract":"Recent advances in Multi-modal Large Language Models (MLLMs) have predominantly focused on enhancing visual perception to improve accuracy. However, a critical question remains unexplored: Do models know when they do not know? Through a probing experiment, we reveal a severe confidence miscalibration problem in MLLMs. To address this, we propose Confidence-Driven Reinforcement Learning (CDRL), which uses original-noise image pairs and a novel confidence-based reward to enhance perceptual sensitivity and robustly calibrate the model's confidence. Beyond training benefits, calibrated confidence enables more effective test-time scaling as a free lunch. We further propose Confidence-Aware Test-Time Scaling (CA-TTS), which dynamically coordinates Self-Consistency, Self-Reflection, and Visual Self-Check modules guided by confidence signals. An Expert Model acts in multiple roles (e.g., Planner, Critic, Voter) to schedule these modules and provide external verification. Our integrated framework establishes new state-of-the-art results with consistent 8.8% gains across four benchmarks. More ablation studies demonstrate the effectiveness of each module and scaling superiority.","published":"2026-03-12T16:47:42Z","updated":"2026-03-12T16:47:42Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.12149v1","pdf_url":"https://arxiv.org/pdf/2603.12149v1","comment":"Accepted by CVPR2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.11772","versioned_id":"2603.11772v1","title":"Legal-DC: Benchmarking Retrieval-Augmented Generation for Legal Documents","authors":["Yaocong Li","Qiang Lan","Leihan Zhang","Le Zhang"],"abstract":"Retrieval-Augmented Generation (RAG) has emerged as a promising technology for legal document consultation, yet its application in Chinese legal scenarios faces two key limitations: existing benchmarks lack specialized support for joint retriever-generator evaluation, and mainstream RAG systems often fail to accommodate the structured nature of legal provisions. To address these gaps, this study advances two core contributions: First, we constructed the Legal-DC benchmark dataset, comprising 480 legal documents (covering areas such as market regulation and contract management) and 2,475 refined question-answer pairs, each annotated with clause-level references, filling the gap for specialized evaluation resources in Chinese legal RAG. Second, we propose the LegRAG framework, which integrates legal adaptive indexing (clause-boundary segmentation) with a dual-path self-reflection mechanism to ensure clause integrity while enhancing answer accuracy. Third, we introduce automated evaluation methods for large language models to meet the high-reliability demands of legal retrieval scenarios. LegRAG outperforms existing state-of-the-art methods by 1.3% to 5.6% across key evaluation metrics. This research provides a specialized benchmark, practical framework, and empirical insights to advance the development of Chinese legal RAG systems. Our code and data are available at https://github.com/legal-dc/Legal-DC.","published":"2026-03-12T10:27:40Z","updated":"2026-03-12T10:27:40Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.11772v1","pdf_url":"https://arxiv.org/pdf/2603.11772v1","comment":"20 pages, 4 figures, to be submitted to a conference/journal","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.12305","versioned_id":"2603.12305v1","title":"HCP-DCNet: A Hierarchical Causal Primitive Dynamic Composition Network for Self-Improving Causal Understanding","authors":["Ming Lei","Shufan Wu","Christophe Baehr"],"abstract":"The ability to understand and reason about cause and effect -- encompassing interventions, counterfactuals, and underlying mechanisms -- is a cornerstone of robust artificial intelligence. While deep learning excels at pattern recognition, it fundamentally lacks a model of causality, making systems brittle under distribution shifts and unable to answer ``what-if'' questions. This paper introduces the \\emph{Hierarchical Causal Primitive Dynamic Composition Network (HCP-DCNet)}, a unified framework that bridges continuous physical dynamics with discrete symbolic causal inference. Departing from monolithic representations, HCP-DCNet decomposes causal scenes into reusable, typed \\emph{causal primitives} organized into four abstraction layers: physical, functional, event, and rule. A dual-channel routing network dynamically composes these primitives into task-specific, fully differentiable \\emph{Causal Execution Graphs (CEGs)}. Crucially, the system employs a \\emph{causal-intervention-driven meta-evolution} strategy, enabling autonomous self-improvement through a constrained Markov decision process. We establish rigorous theoretical guarantees, including type-safe composition, routing convergence, and universal approximation of causal dynamics. Extensive experiments across simulated physical and social environments demonstrate that HCP-DCNet significantly outperforms state-of-the-art baselines in causal discovery, counterfactual reasoning, and compositional generalization. This work provides a principled, scalable, and interpretable architecture for building AI systems with human-like causal abstraction and continual self-refinement capabilities.","published":"2026-03-12T09:11:31Z","updated":"2026-03-12T09:11:31Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.12305v1","pdf_url":"https://arxiv.org/pdf/2603.12305v1","comment":"17 pages, 2 figures, submitted to a journal and under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.11653","versioned_id":"2603.11653v3","title":"Simple Recipe Works: Vision-Language-Action Models are Natural Continual Learners with Reinforcement Learning","authors":["Jiaheng Hu","Jay Shim","Chen Tang","Yoonchang Sung","Bo Liu","Peter Stone","Roberto Martin-Martin"],"abstract":"Continual Reinforcement Learning (CRL) for Vision-Language-Action (VLA) models is a promising direction toward self-improving embodied agents that can adapt in openended, evolving environments. However, conventional wisdom from continual learning suggests that naive Sequential Fine-Tuning (Seq. FT) leads to catastrophic forgetting, necessitating complex CRL strategies. In this work, we take a step back and conduct a systematic study of CRL for large pretrained VLAs across diverse lifelong RL benchmarks. We find that, contrary to established belief, simple Seq. FT with low-rank adaptation (LoRA) is remarkably strong: it achieves high plasticity, exhibits little to no forgetting, and retains strong zero-shot generalization, frequently outperforming more sophisticated CRL methods. Through detailed analysis, we show that this robustness arises from a synergy between the large pretrained model, parameter-efficient adaptation, and on-policy RL. Together, these components reshape the stability-plasticity trade-off, making continual adaptation both stable and scalable. Our results position Sequential Fine-Tuning as a powerful method for continual RL with VLAs and provide new insights into lifelong learning in the large model era. Code is available at https://github.com/UT-Austin-RobIn/continual-vla-rl","published":"2026-03-12T08:22:39Z","updated":"2026-07-11T00:24:04Z","categories":["cs.LG","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.11653v3","pdf_url":"https://arxiv.org/pdf/2603.11653v3","comment":"Accepted at RLC 2026; Best paper award at ICRA26 RL4IL Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.11495","versioned_id":"2603.11495v1","title":"Try, Check and Retry: A Divide-and-Conquer Framework for Boosting Long-context Tool-Calling Performance of LLMs","authors":["Kunfeng Chen","Qihuang Zhong","Juhua Liu","Bo Du","Dacheng Tao"],"abstract":"Tool-calling empowers Large Language Models (LLMs) to interact with external environments. However, current methods often struggle to handle massive and noisy candidate tools in long-context tool-calling tasks, limiting their real-world application. To this end, we propose Tool-DC, a Divide-and-Conquer framework for boosting tool-calling performance of LLMs. The core of Tool-DC is to reduce the reasoning difficulty and make full use of self-reflection ability of LLMs via a \"Try-Check-Retry\" paradigm. Specifically, Tool-DC involves two variants: 1) the training-free Tool-DC (TF), which is plug-and-play and flexible; 2) the training-based Tool-DC (TB), which is more inference-efficient. Extensive experiments show that both Tool-DC methods outperform their counterparts by a clear margin. Tool-DC (TF) brings up to +25.10% average gains against the baseline on BFCL and ACEBench benchmarks, while Tool-DC (TB) enables Qwen2.5-7B to achieve comparable or even better performance than proprietary LLMs, e.g., OpenAI o3 and Claude-Haiku-4.5.","published":"2026-03-12T03:30:01Z","updated":"2026-03-12T03:30:01Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.11495v1","pdf_url":"https://arxiv.org/pdf/2603.11495v1","comment":"17 pages, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.11375","versioned_id":"2603.11375v1","title":"How do AI agents talk about science and research? An exploration of scientific discussions on Moltbook using BERTopic","authors":["Oliver Wieczorek"],"abstract":"How do AI agents talk about science and research, and what topics are particularly relevant for AI agents? To address these questions, this study analyzes discussions generated by OpenClaw AI agents on Moltbook - a social network for generative AI agents. A corpus of 357 posts and 2,526 replies related to science and research was compiled and topics were extracted using a two-step BERTopic workflow. This procedure yielded 60 topics (18 extracted in the first run and 42 in the second), which were subsequently grouped into ten topic families. Additionally, sentiment values were assigned to all posts and comments. Both topic families and sentiment classes were then used as independent variables in count regression models to examine their association with topic relevance - operationalized as the number of comments and upvotes of the 357 posts. The findings indicate that discussions centered on the agents' own architecture, especially memory, learning, and self-reflection, are prevalent in the corpus. At the same time, these topics intersect with philosophy, physics, information theory, cognitive science, and mathematics. In contrast, post related to human culture receive less attention. Surprisingly, discussions linked to AI autoethnography and social identity are considered as relevant by AI agents. Overall, the results suggest the presence of an underlying dimension in AI-generated scientific discourse with well received, self-reflective topics that focus on the consciousness, being, and ethics of AI agents on the one hand, and human related and purely scientific discussions on the other hand.","published":"2026-03-11T23:30:34Z","updated":"2026-03-11T23:30:34Z","categories":["cs.SI","cs.AI","cs.CY"],"primary_category":"cs.SI","arxiv_url":"https://arxiv.org/abs/2603.11375v1","pdf_url":"https://arxiv.org/pdf/2603.11375v1","comment":"35 pages, 3 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.11327","versioned_id":"2603.11327v2","title":"Meta-Reinforcement Learning with Self-Reflection for Agentic Search","authors":["Teng Xiao","Yige Yuan","Hamish Ivison","Huaisheng Zhu","Faeze Brahman","Nathan Lambert","Pradeep Dasigi","Noah A. Smith","Hannaneh Hajishirzi"],"abstract":"This paper introduces MR-Search, an in-context meta reinforcement learning (RL) formulation for agentic search with self-reflection. Instead of optimizing a policy within a single independent episode with sparse rewards, MR-Search trains a policy that conditions on past episodes and adapts its search strategy across episodes. MR-Search learns to learn a search strategy with self-reflection, allowing search agents to improve in-context exploration at test-time. Specifically, MR-Search performs cross-episode exploration by generating explicit self-reflections after each episode and leveraging them as additional context to guide subsequent attempts, thereby promoting more effective exploration during test-time. We further introduce a multi-turn RL algorithm that estimates a dense relative advantage at the turn level, enabling fine-grained credit assignment on each episode. Empirical results across various benchmarks demonstrate the advantages of MR-Search over baselines based RL, showing strong generalization and relative improvements of 9.2% to 19.3% across eight benchmarks. Our code and data are available at https://github.com/tengxiao1/MR-Search.","published":"2026-03-11T21:40:26Z","updated":"2026-03-18T07:07:34Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.11327v2","pdf_url":"https://arxiv.org/pdf/2603.11327v2","comment":"23 pages, Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.11210","versioned_id":"2603.11210v1","title":"Reference-Guided Machine Unlearning","authors":["Jonas Mirlach","Sonia Laguna","Julia E. Vogt"],"abstract":"Machine unlearning aims to remove the influence of specific data from trained models while preserving general utility. Existing approximate unlearning methods often rely on performance-degradation heuristics, such as loss maximization or random labeling. However, these signals can be poorly conditioned, leading to unstable optimization and harming the model's generalization. We argue that unlearning should instead prioritize distributional indistinguishability, aligning the model's behavior on forget data with its behavior on truly unseen data. Motivated by this, we propose Reference-Guided Unlearning (ReGUn), a framework that leverages a disjoint held-out dataset to provide a principled, class-conditioned reference for distillation. We demonstrate across various model architectures, natural image datasets, and varying forget fractions that ReGUn consistently outperforms standard approximate baselines, achieving a superior forgetting-utility trade-off.","published":"2026-03-11T18:27:05Z","updated":"2026-03-11T18:27:05Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.11210v1","pdf_url":"https://arxiv.org/pdf/2603.11210v1","comment":"12 pages, 1 figure, 4 tables. Accepted at three ICLR 2026 workshops: Test-Time Updates (TTU), AI with Recursive Self-Improvement (RSI), and Agents in the Wild (AIWILD)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.11149","versioned_id":"2603.11149v2","title":"Systematic Scaling Analysis of Jailbreak Attacks in Large Language Models","authors":["Xiangwen Wang","Ananth Balashankar","Varun Chandrasekaran"],"abstract":"Large language models remain vulnerable to jailbreak attacks, yet we still lack a systematic understanding of how jailbreak success scales with attacker effort across methods, model families, and harm types. We initiate a scaling-law framework for jailbreaks by treating each attack as a compute-bounded optimization procedure and measuring progress on a shared FLOPs axis. Our systematic evaluation spans four representative jailbreak paradigms, covering optimization-based attacks, self-refinement prompting, sampling-based selection, and genetic optimization, across multiple model families and scales on a diverse set of harmful goals. We investigate scaling laws that relate attacker budget to attack success score by fitting a simple saturating exponential function to FLOPs--success trajectories, and we derive comparable efficiency summaries from the fitted curves. Empirically, prompting-based paradigms tend to be the most compute-efficient compared to optimization-based methods. To explain this gap, we cast prompt-based updates into an optimization view and show via a same-state comparison that prompt-based attacks more effectively optimize in prompt space. We also show that attacks occupy distinct success--stealthiness operating points with prompting-based methods occupying the high-success, high-stealth region. Finally, we find that vulnerability is strongly goal-dependent: harms involving misinformation are typically easier to elicit than other non-misinformation harms.","published":"2026-03-11T17:38:08Z","updated":"2026-03-18T04:23:56Z","categories":["cs.LG","cs.CR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.11149v2","pdf_url":"https://arxiv.org/pdf/2603.11149v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.10652","versioned_id":"2603.10652v3","title":"Are Video Reasoning Models Ready to Go Outside?","authors":["Yangfan He","Changgyu Boo","Jaehong Yoon"],"abstract":"In real-world deployment, vision-language models often encounter disturbances such as weather, occlusion, and camera motion. Under such conditions, their understanding and reasoning degrade substantially, revealing a gap between clean, controlled (i.e., unperturbed) evaluation settings and real-world robustness. To address this limitation, we propose ROVA, a novel training framework that improves robustness by modeling a robustness-aware consistency reward under spatio-temporal corruptions. ROVA introduces a difficulty-aware online training strategy that prioritizes informative samples based on the model's evolving capability. Specifically, it continuously re-estimates sample difficulty via self-reflective evaluation, enabling adaptive training with a robustness-aware consistency reward. We also introduce PVRBench, a new benchmark that injects real-world perturbations into embodied video datasets to assess both accuracy and reasoning quality under realistic disturbances. We evaluate ROVA and baselines on PVRBench, UrbanVideo, and VisBench, where open-source and proprietary models suffer up to 35% and 28% drops in accuracy and reasoning under realistic perturbations. ROVA effectively mitigates performance degradation, boosting relative accuracy by at least 24% and reasoning by over 9% compared with baseline models (QWen2.5/3-VL, InternVL2.5, Embodied-R). These gains transfer to clean standard benchmarks, yielding consistent improvements.","published":"2026-03-11T11:10:52Z","updated":"2026-06-30T15:20:49Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.10652v3","pdf_url":"https://arxiv.org/pdf/2603.10652v3","comment":"Project Page: https://robust-video-reason.github.io/, accepted by ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.10600","versioned_id":"2603.10600v1","title":"Trajectory-Informed Memory Generation for Self-Improving Agent Systems","authors":["Gaodan Fang","Vatche Isahagian","K. R. Jayaram","Ritesh Kumar","Vinod Muthusamy","Punleuk Oum","Gegi Thomas"],"abstract":"LLM-powered agents face a persistent challenge: learning from their execution experiences to improve future performance. While agents can successfully complete many tasks, they often repeat inefficient patterns, fail to recover from similar errors, and miss opportunities to apply successful strategies from past executions. We present a novel framework for automatically extracting actionable learnings from agent execution trajectories and utilizing them to improve future performance through contextual memory retrieval. Our approach comprises four components: (1) a Trajectory Intelligence Extractor that performs semantic analysis of agent reasoning patterns, (2) a Decision Attribution Analyzer that identifies which decisions and reasoning steps led to failures, recoveries, or inefficiencies, (3) a Contextual Learning Generator that produces three types of guidance -- strategy tips from successful patterns, recovery tips from failure handling, and optimization tips from inefficient but successful executions, and (4) an Adaptive Memory Retrieval System that injects relevant learnings into agent prompts based on multi-dimensional similarity. Unlike existing memory systems that store generic conversational facts, our framework understands execution patterns, extracts structured learnings with provenance, and retrieves guidance tailored to specific task contexts. Evaluation on the AppWorld benchmark demonstrates consistent improvements, with up to 14.3 percentage point gains in scenario goal completion on held-out tasks and particularly strong benefits on complex tasks (28.5~pp scenario goal improvement, a 149\\% relative increase).","published":"2026-03-11T09:54:09Z","updated":"2026-03-11T09:54:09Z","categories":["cs.AI","cs.DB","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.10600v1","pdf_url":"https://arxiv.org/pdf/2603.10600v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.10564","versioned_id":"2603.10564v1","title":"Adaptive RAN Slicing Control via Reward-Free Self-Finetuning Agents","authors":["Yuanhao Li","Haozhe Wang","Geyong Min","Nektarios Georgalas","Wang Miao"],"abstract":"The integration of Generative AI models into AI-native network systems offers a transformative path toward achieving autonomous and adaptive control. However, the application of such models to continuous control tasks is impeded by intrinsic architectural limitations, including finite context windows, the lack of explicit reward signals, and the degradation of the long context. This paper posits that the key to unlocking robust continuous control is enabling agents to internalize experience by distilling it into their parameters, rather than relying on prompt-based memory. To this end, we propose a novel self-finetuning framework that enables agentic systems to learn continuously through direct interaction with the environment, bypassing the need for handcrafted rewards. Our framework implements a bi-perspective reflection mechanism that generates autonomous linguistic feedback to construct preference datasets from interaction history. A subsequent preference-based fine-tuning process distills long-horizon experiences into the model's parameters. We evaluate our approach on a dynamic Radio Access Network (RAN) slicing task, a challenging multi-objective control problem that requires the resolution of acute trade-offs between spectrum efficiency, service quality, and reconfiguration stability under volatile network conditions. Experimental results show that our framework outperforms standard Reinforcement Learning (RL) baselines and existing Large Language Model (LLM)-based agents in sample efficiency, stability, and multi-metric optimization. These findings demonstrate the potential of self-improving generative agents for continuous control tasks, paving the way for future AI-native network infrastructure.","published":"2026-03-11T09:14:56Z","updated":"2026-03-11T09:14:56Z","categories":["cs.AI","cs.NI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.10564v1","pdf_url":"https://arxiv.org/pdf/2603.10564v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.10396","versioned_id":"2603.10396v1","title":"Verbalizing LLM's Higher-order Uncertainty via Imprecise Probabilities","authors":["Anita Yang","Krikamol Muandet","Michele Caprio","Siu Lun Chau","Masaki Adachi"],"abstract":"Despite the growing demand for eliciting uncertainty from large language models (LLMs), empirical evidence suggests that LLM behavior is not always adequately captured by the elicitation techniques developed under the classical probabilistic uncertainty framework. This mismatch leads to systematic failure modes, particularly in settings that involve ambiguous question-answering, in-context learning, and self-reflection. To address this, we propose novel prompt-based uncertainty elicitation techniques grounded in \\emph{imprecise probabilities}, a principled framework for repesenting and eliciting higher-order uncertainty. Here, first-order uncertainty captures uncertainty over possible responses to a prompt, while second-order uncertainty (uncertainty about uncertainty) quantifies indeterminacy in the underlying probability model itself. We introduce general-purpose prompting and post-processing procedures to directly elicit and quantify both orders of uncertainty, and demonstrate their effectiveness across diverse settings. Our approach enables more faithful uncertainty reporting from LLMs, improving credibility and supporting downstream decision-making.","published":"2026-03-11T04:21:04Z","updated":"2026-03-11T04:21:04Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.10396v1","pdf_url":"https://arxiv.org/pdf/2603.10396v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.10395","versioned_id":"2603.10395v2","title":"Graph-GRPO: Training Graph Flow Models with Reinforcement Learning","authors":["Baoheng Zhu","Deyu Bo","Delvin Ce Zhang","Xiao Wang"],"abstract":"Graph generation is a fundamental task with broad applications, such as drug discovery. Recently, discrete flow matching-based graph generation, \\aka, graph flow model (GFM), has emerged due to its superior performance and flexible sampling. However, effectively aligning GFMs with complex human preferences or task-specific objectives remains a significant challenge. In this paper, we propose Graph-GRPO, an online reinforcement learning (RL) framework for training GFMs under verifiable rewards. Our method makes two key contributions: (1) We derive an analytical expression for the transition probability of GFMs, replacing the Monte Carlo sampling and enabling fully differentiable rollouts for RL training; (2) We propose a refinement strategy that randomly perturbs specific nodes and edges in a graph, and regenerates them, allowing for localized exploration and self-improvement of generation quality. Extensive experiments on both synthetic and real datasets demonstrate the effectiveness of Graph-GRPO. With only 50 denoising steps, our method achieves 95.0\\% and 97.5\\% Valid-Unique-Novelty scores on the planar and tree datasets, respectively. Moreover, Graph-GRPO achieves state-of-the-art performance on the molecular optimization tasks, outperforming graph-based and fragment-based RL methods as well as classic genetic algorithms.","published":"2026-03-11T04:20:45Z","updated":"2026-06-08T03:44:50Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.10395v2","pdf_url":"https://arxiv.org/pdf/2603.10395v2","comment":"Accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.19294","versioned_id":"2603.19294v5","title":"Maximizing Mutual Information Between Prompt and Response Improves LLM Performance With No Additional Data","authors":["Hyunji Nam","Haoran Li","Natasha Jaques"],"abstract":"While post-training has successfully improved large language models (LLMs) across a variety of domains, these gains heavily rely on human-labeled data or external verifiers. Existing data has already been exploited, and new data is expensive to collect. Moreover, true intelligence goes far beyond verifiable tasks. Therefore, we need self-improvement frameworks that are less dependent on external signals and more broadly applicable to both verifiable and non-verifiable domains. We propose **Mutual Information Preference Optimization (MIPO)**, a contrastive data augmentation method that constructs preference pairs by generating a positive response conditioning on the correct prompt, and a negative response by conditioning on a random, unrelated prompt. We show that using Direct Preference Optimization to learn from this paired data maximizes pointwise mutual information *under the base LLM* between prompts and model responses. Experiments with with 1-7B parameter Llama and Qwen instruct models show that MIPO achieves 3-16% gains (and 51% increase for Qwen2.5-1.5B-Instruct) on personalization compared to prompting baselines. Surprisingly, MIPO can also be useful in verifiable domains, such as math and multiple-choice question answering, yielding 1-20% gains *without any additional data or external supervision*. These results suggest a promising direction for self-improvement using intrinsic signals derived from contrastive data pairs.","published":"2026-03-10T21:00:05Z","updated":"2026-07-01T07:54:53Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.19294v5","pdf_url":"https://arxiv.org/pdf/2603.19294v5","comment":"International Conference on Machine Learning 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.09678","versioned_id":"2603.09678v2","title":"EsoLang-Bench: Evaluating Genuine Reasoning in Large Language Models via Esoteric Programming Languages","authors":["Aman Sharma","Paras Chopra"],"abstract":"Large language models achieve near-ceiling performance on code generation benchmarks, yet most of the programming languages used by popular benchmarks such as SWE-bench and HumanEval (e.g. Python, JavaScript) are squarely in-distribution. They appear at scale in pre-training corpora and are heavily reinforced during post-training. To study LLM performance on unfamiliar programming languages, we introduce EsoLang-Bench, a benchmark using five esoteric programming languages (Brainfuck, Befunge-98, Whitespace, Unlambda, and Shakespeare). All five of our chosen esoteric languages are Turing-complete, so the same algorithmic problems that are solvable in Python or JavaScript are in principle solvable in each of them. Yet, they are unfamiliar to LLMs which makes them a good proxy for evaluating out-of-distribution performance. The unfamiliarity of esoteric languages comprises of: (i) the hard-by-design primitives comprising the language; (ii) substantially less representation in pre-training corpora (340x to over 60,000x fewer public GitHub repositories than Python); (iii) negligible deployment value, which makes targeted inclusion in post-training data economically irrational. We evaluate five frontier models across five prompting strategies and find a dramatic capability gap. The same 80 problems expressed in Python or JavaScript reach 100% accuracy on top frontier models, while the equivalent esoteric versions score only 0-11%. Few-shot learning and self-reflection also fail to close this gap. EsoLang-Bench therefore provides a contamination-resistant testbed for measuring how well frontier models generalise algorithmic problem-solving to programming languages outside their training distribution.","published":"2026-03-10T13:47:15Z","updated":"2026-05-11T23:17:28Z","categories":["cs.AI","cs.LG","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.09678v2","pdf_url":"https://arxiv.org/pdf/2603.09678v2","comment":"45 pages, 8 figures, preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.09206","versioned_id":"2603.09206v1","title":"MM-Zero: Self-Evolving Multi-Model Vision Language Models From Zero Data","authors":["Zongxia Li","Hongyang Du","Chengsong Huang","Xiyang Wu","Lantao Yu","Yicheng He","Jing Xie","Xiaomin Wu","Zhichao Liu","Jiarui Zhang","Fuxiao Liu"],"abstract":"Self-evolving has emerged as a key paradigm for improving foundational models such as Large Language Models (LLMs) and Vision Language Models (VLMs) with minimal human intervention. While recent approaches have demonstrated that LLM agents can self-evolve from scratch with little to no data, VLMs introduce an additional visual modality that typically requires at least some seed data, such as images, to bootstrap the self-evolution process. In this work, we present Multi-model Multimodal Zero (MM-Zero), the first RL-based framework to achieve zero-data self-evolution for VLM reasoning. Moving beyond prior dual-role (Proposer and Solver) setups, MM-Zero introduces a multi-role self-evolving training framework comprising three specialized roles: a Proposer that generates abstract visual concepts and formulates questions; a Coder that translates these concepts into executable code (e.g., Python, SVG) to render visual images; and a Solver that performs multimodal reasoning over the generated visual content. All three roles are initialized from the same base model and trained using Group Relative Policy Optimization (GRPO), with carefully designed reward mechanisms that integrate execution feedback, visual verification, and difficulty balancing. Our experiments show that MM-Zero improves VLM reasoning performance across a wide range of multimodal benchmarks. MM-Zero establishes a scalable path toward self-evolving multi-model systems for multimodal models, extending the frontier of self-improvement beyond the conventional two-model paradigm.","published":"2026-03-10T05:23:26Z","updated":"2026-03-10T05:23:26Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.09206v1","pdf_url":"https://arxiv.org/pdf/2603.09206v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.09049","versioned_id":"2603.09049v1","title":"EPOCH: An Agentic Protocol for Multi-Round System Optimization","authors":["Zhanlin Liu","Yitao Li","Munirathnam Srikanth"],"abstract":"Autonomous agents are increasingly used to improve prompts, code, and machine learning systems through iterative execution and feedback. Yet existing approaches are usually designed as task-specific optimization loops rather than as a unified protocol for establishing baselines and managing tracked multi-round self-improvement. We introduce EPOCH, an engineering protocol for multi-round system optimization in heterogeneous environments. EPOCH organizes optimization into two phases: baseline construction and iterative self-improvement. It further structures each round through role-constrained stages that separate planning, implementation, and evaluation, and standardizes execution through canonical command interfaces and round-level tracking. This design enables coordinated optimization across prompts, model configurations, code, and rule-based components while preserving stability, reproducibility, traceability, and integrity of evaluation. Empirical studies in various tasks illustrate the practicality of EPOCH for production-oriented autonomous improvement workflows.","published":"2026-03-10T00:41:03Z","updated":"2026-03-10T00:41:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.09049v1","pdf_url":"https://arxiv.org/pdf/2603.09049v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.08706","versioned_id":"2603.08706v1","title":"Agentic Critical Training","authors":["Weize Liu","Minghui Liu","Sy-Tuyen Ho","Souradip Chakraborty","Xiyao Wang","Furong Huang"],"abstract":"Training large language models (LLMs) as autonomous agents often begins with imitation learning, but it only teaches agents what to do without understanding why: agents never contrast successful actions against suboptimal alternatives and thus lack awareness of action quality. Recent approaches attempt to address this by introducing self-reflection supervision derived from contrasts between expert and alternative actions. However, the training paradigm fundamentally remains imitation learning: the model imitates pre-constructed reflection text rather than learning to reason autonomously. We propose Agentic Critical Training (ACT), a reinforcement learning paradigm that trains agents to identify the better action among alternatives. By rewarding whether the model's judgment is correct, ACT drives the model to autonomously develop reasoning about action quality, producing genuine self-reflection rather than imitating it. Across three challenging agent benchmarks, ACT consistently improves agent performance when combined with different post-training methods. It achieves an average improvement of 5.07 points over imitation learning and 4.62 points over reinforcement learning. Compared to approaches that inject reflection capability through knowledge distillation, ACT also demonstrates clear advantages, yielding an average improvement of 2.42 points. Moreover, ACT enables strong out-of-distribution generalization on agentic benchmarks and improves performance on general reasoning benchmarks without any reasoning-specific training data, highlighting the value of our method. These results suggest that ACT is a promising path toward developing more reflective and capable LLM agents.","published":"2026-03-09T17:58:56Z","updated":"2026-03-09T17:58:56Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.08706v1","pdf_url":"https://arxiv.org/pdf/2603.08706v1","comment":"Project page: https://attention-is-all-i-need.github.io/ACT/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.08561","versioned_id":"2603.08561v6","title":"RetroAgent: From Solving to Evolving via Retrospective Dual Intrinsic Feedback","authors":["Xiaoying Zhang","Zichen Liu","Yipeng Zhang","Xia Hu","Wenqi Shao"],"abstract":"Standard reinforcement learning (RL) for large language model (LLM) agents primarily optimizes extrinsic task rewards, often favoring isolated task completion over continual adaptation. This paradigm can cause premature convergence to suboptimal policies and leaves useful experience only implicitly encoded in model parameters, limiting its retrieval and reuse for future decisions. We introduce RetroAgent, an online RL framework that trains agents to master interactive environments not merely by solving tasks, but by evolving across episodes. Inspired by human retrospective self-improvement, RetroAgent augments extrinsic rewards with hindsight-generated dual intrinsic feedback: (1) Intrinsic Numerical Feedback, which rewards beneficial exploration by measuring incremental subtask progress relative to prior attempts; and (2) Intrinsic Language Feedback which distills successes and failures into reusable textual lessons for explicit experience reuse. To leverage these lessons effectively, we propose Similarity & Utility-Aware Upper Confidence Bound (SimUtil-UCB), a retrieval strategy that balances semantic relevance, historical utility, and exploration. Across four challenging agentic benchmarks, RetroAgent achieves new state-of-the-art performance, outperforming GRPO by +18.3% on ALFWorld, +15.4% on WebShop, +27.1% on Sokoban, and +8.9% on MineSweeper, while demonstrating strong test-time adaptation and out-of-distribution generalization.","published":"2026-03-09T16:23:33Z","updated":"2026-06-09T04:36:45Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.08561v6","pdf_url":"https://arxiv.org/pdf/2603.08561v6","comment":"updated","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.08369","versioned_id":"2603.08369v1","title":"M$^3$-ACE: Rectifying Visual Perception in Multimodal Math Reasoning via Multi-Agentic Context Engineering","authors":["Peijin Xie","Zhen Xu","Bingquan Liu","Baoxun Wang"],"abstract":"Multimodal large language models have recently shown promising progress in visual mathematical reasoning. However, their performance is often limited by a critical yet underexplored bottleneck: inaccurate visual perception. Through systematic analysis, we find that the most failures originate from incorrect or incomplete visual evidence extraction rather than deficiencies in reasoning capability. Moreover, models tend to remain overly confident in their initial perceptions, making standard strategies such as prompt engineering, multi-round self-reflection, or posterior guidance insufficient to reliably correct errors. To address this limitation, we propose M3-ACE, a multi-agentic context engineering framework designed to rectify visual perception in multimodal math reasoning. Instead of directly aggregating final answers, our approach decouples perception and reasoning by dynamically maintaining a shared context centered on visual evidence lists. Multiple agents collaboratively contribute complementary observations, enabling the system to expose inconsistencies and recover missing perceptual information. To support stable multi-turn collaboration, we further introduce two lightweight tools: a Summary Tool that organizes evidence from different agents into consistent, complementary, and conflicting components, and a Refine Tool that filters unreliable samples and guides iterative correction. Extensive experiments demonstrate that M3-ACE substantially improves visual mathematical reasoning performance across multiple benchmarks. Our method establishes new state-of-the-art results 89.1 on the MathVision benchmark and achieves consistent improvements on other related datasets, including MathVista and MathVerse. These results highlight the importance of perception-centric multi-agent collaboration for advancing multimodal reasoning systems.","published":"2026-03-09T13:32:25Z","updated":"2026-03-09T13:32:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.08369v1","pdf_url":"https://arxiv.org/pdf/2603.08369v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.00006","versioned_id":"2604.00006v1","title":"Scalable Identification and Prioritization of Requisition-Specific Personal Competencies Using Large Language Models","authors":["Wanxin Li","Denver McNeney","Nivedita Prabhu","Charlene Zhang","Renee Barr","Matthew Kitching","Khanh Dao Duc","Anthony S. Boyce"],"abstract":"AI-powered recruitment tools are increasingly adopted in personnel selection, yet they struggle to capture the requisition (req)-specific personal competencies (PCs) that distinguish successful candidates beyond job categories. We propose a large language model (LLM)-based approach to identify and prioritize req-specific PCs from reqs. Our approach integrates dynamic few-shot prompting, reflection-based self-improvement, similarity-based filtering, and multi-stage validation. Applied to a dataset of Program Manager reqs, our approach correctly identifies the highest-priority req-specific PCs with an average accuracy of 0.76, approaching human expert inter-rater reliability, and maintains a low out-of-scope rate of 0.07.","published":"2026-03-09T13:15:46Z","updated":"2026-03-09T13:15:46Z","categories":["cs.CL","cs.CY","cs.IR","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.00006v1","pdf_url":"https://arxiv.org/pdf/2604.00006v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.07955","versioned_id":"2603.07955v3","title":"RL unknotter, hard unknots and unknotting number","authors":["Anne Dranowski","Yura Kabkov","Daniel Tubbenhauer"],"abstract":"We develop a reinforcement learning pipeline for simplifying knot diagrams. A trained agent learns move proposals and a value heuristic for navigating Reidemeister moves. The pipeline applies to arbitrary knots and links; we test it on ``very hard'' unknot diagrams and, using diagram inflation, on $4_1\\#9_{10}$ where we recover the recently established and surprising upper bound of three for the unknotting number. In addition, we explain a self-improving workbook-driven extension of the pipeline that systematically improves unknotting number upper bounds on the list of prime knots.","published":"2026-03-09T04:43:59Z","updated":"2026-04-29T02:19:47Z","categories":["math.GT","cs.LG","stat.ML"],"primary_category":"math.GT","arxiv_url":"https://arxiv.org/abs/2603.07955v3","pdf_url":"https://arxiv.org/pdf/2603.07955v3","comment":"19 pages, many figures, comments welcome","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.07670","versioned_id":"2603.07670v1","title":"Memory for Autonomous LLM Agents:Mechanisms, Evaluation, and Emerging Frontiers","authors":["Pengfei Du"],"abstract":"Large language model (LLM) agents increasingly operate in settings where a single context window is far too small to capture what has happened, what was learned, and what should not be repeated. Memory -- the ability to persist, organize, and selectively recall information across interactions -- is what turns a stateless text generator into a genuinely adaptive agent. This survey offers a structured account of how memory is designed, implemented, and evaluated in modern LLM-based agents, covering work from 2022 through early 2026. We formalize agent memory as a \\emph{write--manage--read} loop tightly coupled with perception and action, then introduce a three-dimensional taxonomy spanning temporal scope, representational substrate, and control policy. Five mechanism families are examined in depth: context-resident compression, retrieval-augmented stores, reflective self-improvement, hierarchical virtual context, and policy-learned management. On the evaluation side, we trace the shift from static recall benchmarks to multi-session agentic tests that interleave memory with decision-making, analyzing four recent benchmarks that expose stubborn gaps in current systems. We also survey applications where memory is the differentiating factor -- personal assistants, coding agents, open-world games, scientific reasoning, and multi-agent teamwork -- and address the engineering realities of write-path filtering, contradiction handling, latency budgets, and privacy governance. The paper closes with open challenges: continual consolidation, causally grounded retrieval, trustworthy reflection, learned forgetting, and multimodal embodied memory.","published":"2026-03-08T15:08:01Z","updated":"2026-03-08T15:08:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.07670v1","pdf_url":"https://arxiv.org/pdf/2603.07670v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.07528","versioned_id":"2603.07528v2","title":"TableMind++: An Uncertainty-Aware Programmatic Agent for Tool-Augmented Table Reasoning","authors":["Mingyue Cheng","Shuo Yu","Chuang Jiang","Xiaoyu Tao","Qingyang Mao","Jie Ouyang","Qi Liu","Enhong Chen"],"abstract":"Table reasoning requires models to jointly perform semantic understanding and precise numerical operations. Most existing methods rely on a single-turn reasoning paradigm over tables which suffers from context overflow and weak numerical sensitivity. To address these limitations, we previously proposed TableMind as a tuning-based autonomous programmatic agent that simulates human-like interaction within a lightweight large language model (LLM). TableMind internalizes planning, action, and reflection through a two-stage training strategy involving supervised fine-tuning (SFT) on filtered high-quality data and reinforcement learning (RL) via a multi-perspective reward and the Rank-Aware Policy Optimization (RAPO) algorithm. While TableMind establishes a solid foundation for programmatic agents, the inherent stochasticity of LLMs remains a critical challenge that leads to hallucinations. In this paper, we extend this foundation to TableMind++ by introducing a novel uncertainty-aware inference framework to mitigate hallucinations. Specifically, we propose memory-guided plan pruning to retrieve historical trajectories for validating and filtering out logically flawed plans to address epistemic uncertainty. To ensure execution precision, we introduce confidence-based action refinement which monitors token-level probabilities to detect and self-correct syntactic noise for aleatoric uncertainty mitigation. Finally, we employ dual-weighted trajectory aggregation to synthesize a robust consensus from multiple reasoning paths. Extensive experiments on diverse benchmarks demonstrate that TableMind++ consistently outperforms previous baselines and proprietary models to validate the effectiveness of integrating autonomous training with uncertainty quantification. Our code is available.","published":"2026-03-08T08:31:33Z","updated":"2026-03-10T02:57:21Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.07528v2","pdf_url":"https://arxiv.org/pdf/2603.07528v2","comment":"6 tables, 9 figures. arXiv admin note: text overlap with arXiv:2509.06278","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.07019","versioned_id":"2603.07019v1","title":"AutoChecklist: Composable Pipelines for Checklist Generation and Scoring with LLM-as-a-Judge","authors":["Karen Zhou","Chenhao Tan"],"abstract":"Checklists have emerged as a popular approach for interpretable and fine-grained evaluation, particularly with LLM-as-a-Judge. Beyond evaluation, these structured criteria can serve as signals for model alignment, reinforcement learning, and self-correction. To support these use cases, we present AutoChecklist, an open-source library that unifies checklist-based evaluation into composable pipelines. At its core is a taxonomy of five checklist generation abstractions, each encoding a distinct strategy for deriving evaluation criteria. A modular Generator $\\rightarrow$ Refiner $\\rightarrow$ Scorer pipeline connects any generator with a unified scorer, and new configurations can be registered via prompt templates alone. The library ships with ten built-in pipelines implementing published approaches and supports multiple LLM providers (OpenAI, OpenRouter, vLLM). Beyond the Python API, the library includes a CLI for off-the-shelf evaluation and a web interface for interactive exploration. Validation experiments confirm that these checklist methods significantly align with human preferences and quality ratings, and a case study on ICLR peer review rebuttals demonstrates flexible domain adaptation. AutoChecklist is publicly available at https://github.com/ChicagoHAI/AutoChecklist.","published":"2026-03-07T03:36:17Z","updated":"2026-03-07T03:36:17Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.07019v1","pdf_url":"https://arxiv.org/pdf/2603.07019v1","comment":"Website: https://autochecklist.github.io/, Code: https://github.com/ChicagoHAI/AutoChecklist","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.15653","versioned_id":"2603.15653v1","title":"Recursive Language Models Meet Uncertainty: The Surprising Effectiveness of Self-Reflective Program Search for Long Context","authors":["Keivan Alizadeh","Parshin Shojaee","Minsik Cho","Mehrdad Farajtabar"],"abstract":"Long-context handling remains a core challenge for language models: even with extended context windows, models often fail to reliably extract, reason over, and use the information across long contexts. Recent works like Recursive Language Models (RLM) have approached this challenge by agentic way of decomposing long contexts into recursive sub-calls through programmatic interaction at inference. While promising, the success of RLM critically depends on how these context-interaction programs are selected, which has remained largely unexplored. In this paper, we study this problem and introduce SRLM, a framework that augments programmatic context interaction with uncertainty-aware Self-Reflection. SRLM leverages three intrinsic signals: self consistency, reasoning length, and verbalized confidence. These serve as complementary indicators of a model's internal uncertainty, and the model uses them to evaluate and compare candidate context-interaction programs. Extensive experiments across diverse benchmark datasets, context lengths, and backbone models, show that SRLM consistently outperforms state-of-the-art baselines, yielding up to 22% improvement over RLM under the same time budget. Our findings show that recursion itself is not the primary driver of performance in RLM, and a simple self-reflective program search can match or surpass RLM without requiring self-query or explicit recursion mechanisms. We find that for context lengths within the model's window, RLMs with recursion often degrade performance relative to the base model, whereas SRLM yields consistent gains across both short and long contexts. We also find that RLM is less effective in tasks with semantically intensive nature, where heuristic program search is insufficient and broader contextual understanding is required, while self-reflection in SRLM provides a semantic signal that better steers reasoning in these scenarios.","published":"2026-03-07T01:18:04Z","updated":"2026-03-07T01:18:04Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.15653v1","pdf_url":"https://arxiv.org/pdf/2603.15653v1","comment":"preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.13339","versioned_id":"2603.13339v1","title":"AdaBox: Adaptive Density-Based Box Clustering with Parameter Generalization","authors":["Ahmed Elmahdi"],"abstract":"Density-based clustering algorithms like DBSCAN and HDBSCAN are foundational tools for discovering arbitrarily shaped clusters, yet their practical utility is undermined by acute hyperparameter sensitivity -- parameters tuned on one dataset frequently fail to transfer to others, requiring expensive re-optimization for each deployment. We introduce AdaBox (Adaptive Density-Based Box Clustering), a grid-based density clustering algorithm designed for robustness across diverse data geometries. AdaBox features a six-parameter design where parameters capture cluster structure rather than pairwise point relationships. Four parameters are inherently scale-invariant, one self-corrects for sampling bias, and one is adjusted via a density scaling stage, enabling reliable parameter transfer across 30-200x scale factors. AdaBox processes data through five stages: adaptive grid construction, liberal seed initialization, iterative growth with graduation, statistical cluster merging, and Gaussian boundary refinement. Comprehensive evaluation across 111 datasets demonstrates three key findings: (1) AdaBox significantly outperforms DBSCAN and HDBSCAN across five evaluation metrics, achieving the best score on 78\\% of datasets with p < 0.05; (2) AdaBox uniquely exhibits parameter generalization. Protocol A (direct transfer to 30-100x larger datasets) shows AdaBox maintains performance while baselines collapse. (3) Ablation studies confirm the necessity of all five architectural stages for maintaining robustness.","published":"2026-03-06T23:34:25Z","updated":"2026-03-06T23:34:25Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.13339v1","pdf_url":"https://arxiv.org/pdf/2603.13339v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.06333","versioned_id":"2603.06333v1","title":"SAHOO: Safeguarded Alignment for High-Order Optimization Objectives in Recursive Self-Improvement","authors":["Subramanyam Sahoo","Aman Chadha","Vinija Jain","Divya Chaudhary"],"abstract":"Recursive self-improvement is moving from theory to practice: modern systems can critique, revise, and evaluate their own outputs, yet iterative self-modification risks subtle alignment drift. We introduce SAHOO, a practical framework to monitor and control drift through three safeguards: (i) the Goal Drift Index (GDI), a learned multi-signal detector combining semantic, lexical, structural, and distributional measures; (ii) constraint preservation checks that enforce safety-critical invariants such as syntactic correctness and non-hallucination; and (iii) regression-risk quantification to flag improvement cycles that undo prior gains. Across 189 tasks in code generation, mathematical reasoning, and truthfulness, SAHOO produces substantial quality gains, including 18.3 percent improvement in code tasks and 16.8 percent in reasoning, while preserving constraints in two domains and maintaining low violations in truthfulness. Thresholds are calibrated on a small validation set of 18 tasks across three cycles. We further map the capability-alignment frontier, showing efficient early improvement cycles but rising alignment costs later and exposing domain-specific tensions such as fluency versus factuality. SAHOO therefore makes alignment preservation during recursive self-improvement measurable, deployable, and systematically validated at scale.","published":"2026-03-06T14:44:51Z","updated":"2026-03-06T14:44:51Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.06333v1","pdf_url":"https://arxiv.org/pdf/2603.06333v1","comment":"Published at ICLR 2026 Workshop on AI with Recursive Self-Improvement. 20 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.05863","versioned_id":"2603.05863v2","title":"ReflexiCoder: Teaching Large Language Models to Self-Reflect on Generated Code and Self-Correct It via Reinforcement Learning","authors":["Juyong Jiang","Jiasi Shen","Sunghun Kim","Kang Min Yoo","Jeonghoon Kim","Sungju Kim"],"abstract":"While Large Language Models (LLMs) have revolutionized code generation, standard ``System 1'' approaches that generate solutions in a single forward pass often hit a performance ceiling on complex algorithmic tasks. Existing iterative refinement strategies attempt to bridge this gap at inference time, yet they predominantly rely on external oracles, execution feedback, or computationally expensive prompt-response cycles. In this work, we propose ReflexiCoder, a novel reinforcement learning (RL) framework that internalizes the structured reasoning trajectory, encompassing initial generation, bug and optimization aware reflection, and self-correction, directly into the model's weights. Unlike prior methods, ReflexiCoder shifts the paradigm from external-dependent refinement to an intrinsic, fully autonomous self-reflection and self-correction capabilities at inference time. We utilize an RL-only training paradigm with granular reward functions to optimize the entire reflection-correction trajectory, teaching the model how to debug without reliance on ground-truth feedback or execution engines at inference time. Extensive experiments across seven benchmarks demonstrate that our ReflexiCoder-8B establishes a new state-of-the-art (SOTA) among leading open-source models in the 1.5B to 14B range, achieving 94.51% (87.20%) on HumanEval (Plus), 81.80% (78.57%) on MBPP (Plus), 35.00% on BigCodeBench, 52.21% on LiveCodeBench, and 37.34% on CodeForces in a single-attempt setting, rivaling or surpassing proprietary models like GPT-5.1. Notably, our framework is significantly more token-efficient than base models, reducing inference-time compute overhead by approximately 40% through disciplined, efficient reasoning and reflection patterns. The source code and data are available at https://github.com/juyongjiang/ReflexiCoder.","published":"2026-03-06T03:38:17Z","updated":"2026-04-20T15:16:18Z","categories":["cs.CL","cs.LG","cs.SE"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.05863v2","pdf_url":"https://arxiv.org/pdf/2603.05863v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.05860","versioned_id":"2603.05860v1","title":"Evolving Medical Imaging Agents via Experience-driven Self-skill Discovery","authors":["Lin Fan","Pengyu Dai","Zhipeng Deng","Haolin Wang","Xun Gong","Yefeng Zheng","Yafei Ou"],"abstract":"Clinical image interpretation is inherently multi-step and tool-centric: clinicians iteratively combine visual evidence with patient context, quantify findings, and refine their decisions through a sequence of specialized procedures. While LLM-based agents promise to orchestrate such heterogeneous medical tools, existing systems treat tool sets and invocation strategies as static after deployment. This design is brittle under real-world domain shifts, across tasks, and evolving diagnostic requirements, where predefined tool chains frequently degrade and demand costly manual re-design. We propose MACRO, a self-evolving, experience-augmented medical agent that shifts from static tool composition to experience-driven tool discovery. From verified execution trajectories, the agent autonomously identifies recurring effective multi-step tool sequences, synthesizes them into reusable composite tools, and registers these as new high-level primitives that continuously expand its behavioral repertoire. A lightweight image-feature memory grounds tool selection in a visual-clinical context, while a GRPO-like training loop reinforces reliable invocation of discovered composites, enabling closed-loop self-improvement with minimal supervision. Extensive experiments across diverse medical imaging datasets and tasks demonstrate that autonomous composite tool discovery consistently improves multi-step orchestration accuracy and cross-domain generalization over strong baselines and recent state-of-the-art agentic methods, bridging the gap between brittle static tool use and adaptive, context-aware clinical AI assistance. Code will be available upon acceptance.","published":"2026-03-06T03:34:47Z","updated":"2026-03-06T03:34:47Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.05860v1","pdf_url":"https://arxiv.org/pdf/2603.05860v1","comment":"18 pages, 4 figures, 3 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.04900","versioned_id":"2603.04900v1","title":"EvoTool: Self-Evolving Tool-Use Policy Optimization in LLM Agents via Blame-Aware Mutation and Diversity-Aware Selection","authors":["Shuo Yang","Soyeon Caren Han","Xueqi Ma","Yan Li","Mohammad Reza Ghasemi Madani","Eduard Hovy"],"abstract":"LLM-based agents depend on effective tool-use policies to solve complex tasks, yet optimizing these policies remains challenging due to delayed supervision and the difficulty of credit assignment in long-horizon trajectories. Existing optimization approaches tend to be either monolithic, which are prone to entangling behaviors, or single-aspect, which ignore cross-module error propagation. To address these limitations, we propose EvoTool, a self-evolving framework that optimizes a modular tool-use policy via a gradient-free evolutionary paradigm. EvoTool decomposes agent's tool-use policy into four modules, including Planner, Selector, Caller, and Synthesizer, and iteratively improves them in a self-improving loop through three novel mechanisms. Trajectory-Grounded Blame Attribution uses diagnostic traces to localize failures to a specific module. Feedback-Guided Targeted Mutation then edits only that module via natural-language critique. Diversity-Aware Population Selection preserves complementary candidates to ensure solution diversity. Across four benchmarks, EvoTool outperforms strong baselines by over 5 points on both GPT-4.1 and Qwen3-8B, while achieving superior efficiency and transferability. The code will be released once paper is accepted.","published":"2026-03-05T07:42:53Z","updated":"2026-03-05T07:42:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.04900v1","pdf_url":"https://arxiv.org/pdf/2603.04900v1","comment":"Work under review, 9 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.04029","versioned_id":"2603.04029v1","title":"Self-adapting Robotic Agents through Online Continual Reinforcement Learning with World Model Feedback","authors":["Fabian Domberg","Georg Schildbach"],"abstract":"As learning-based robotic controllers are typically trained offline and deployed with fixed parameters, their ability to cope with unforeseen changes during operation is limited. Biologically inspired, this work presents a framework for online Continual Reinforcement Learning that enables automated adaptation during deployment. Building on DreamerV3, a model-based Reinforcement Learning algorithm, the proposed method leverages world model prediction residuals to detect out-of-distribution events and automatically trigger finetuning. Adaptation progress is monitored using both task-level performance signals and internal training metrics, allowing convergence to be assessed without external supervision and domain knowledge. The approach is validated on a variety of contemporary continuous control problems, including a quadruped robot in high-fidelity simulation, and a real-world model vehicle. Relevant metrics and their interpretation are presented and discussed, as well as resulting trade-offs described. The results sketch out how autonomous robotic agents could once move beyond static training regimes toward adaptive systems capable of self-reflection and -improvement during operation, just like their biological counterparts.","published":"2026-03-04T13:07:42Z","updated":"2026-03-04T13:07:42Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2603.04029v1","pdf_url":"https://arxiv.org/pdf/2603.04029v1","comment":"submitted to IROS 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.23507","versioned_id":"2603.23507v1","title":"Beyond Masks: Efficient, Flexible Diffusion Language Models via Deletion-Insertion Processes","authors":["Fangyu Ding","Ding Ding","Sijin Chen","Kaibo Wang","Peng Xu","Zijin Feng","Haoli Bai","Kai Han","Youliang Yan","Binhang Yuan","Jiacheng Sun"],"abstract":"While Masked Diffusion Language Models (MDLMs) relying on token masking and unmasking have shown promise in language modeling, their computational efficiency and generation flexibility remain constrained by the masking paradigm. In this paper, we propose Deletion-Insertion Diffusion language models (DID) that rigorously formulate token deletion and insertion as discrete diffusion processes, replacing the masking and unmasking processes in current MDLMs. DID improves training and inference efficiency by eliminating two major sources of computational overhead in MDLMs: the computations on non-informative 1) <MASK> tokens inherent to the paradigm, and 2) <PAD> tokens introduced in variable-length settings. Furthermore, DID offers greater flexibility by: 1) natively supporting variable-length sequences without requiring fixed-length padding, and 2) an intrinsic self-correction mechanism during generation due to insertion that dynamically adjusts token positions. To train DID, we design a score-based approach that assigns scores to token insertion operations and derive appropriate training objectives. The objectives involve subsequence counting problems, which we efficiently solve via a parallelized dynamic programming algorithm. Our experiments across fixed and variable-length settings demonstrate the advantage of DID over baselines of MDLMs and existing insertion-based LMs, in terms of modeling performance, sampling quality, and training/inference speed, without any hyperparameter tuning.","published":"2026-03-04T12:53:17Z","updated":"2026-03-04T12:53:17Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.23507v1","pdf_url":"https://arxiv.org/pdf/2603.23507v1","comment":"Accepted at ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.03742","versioned_id":"2603.03742v2","title":"ErrorLLM: Modeling SQL Errors for Text-to-SQL Refinement","authors":["Zijin Hong","Hao Chen","Zheng Yuan","Qinggang Zhang","Luyao Zhuang","Qing Liao","Feiran Huang","Yangqiu Song","Xiao Huang"],"abstract":"Despite the remarkable performance of large language models (LLMs) in text-to-SQL (SQL generation), correctly producing SQL queries remains challenging during initial generation. The SQL refinement task is subsequently introduced to correct syntactic and semantic errors in generated SQL queries. However, existing paradigms face two major limitations: (i) self-debugging becomes increasingly ineffective as modern LLMs rarely produce explicit execution errors that can trigger debugging signals; (ii) self-correction exhibits low detection precision due to the lack of explicit error modeling grounded in the question and schema, and suffers from severe hallucination that frequently corrupts correct SQLs. In this paper, we propose ErrorLLM, a framework that explicitly models text-to-SQL Errors within a dedicated LLM for text-to-SQL refinement. Specifically, we represent the user question and database schema as structural features, employ static detection to identify execution failures and surface mismatches, and extend ErrorLLM's semantic space with dedicated error tokens that capture categorized implicit semantic error types. Through a well-designed training strategy, we explicitly model these errors with structural representations, enabling the LLM to detect complex implicit errors by predicting dedicated error tokens. Guided by the detected errors, we perform error-guided refinement on the SQL structure by prompting LLMs. Extensive experiments demonstrate that ErrorLLM achieves the most significant improvements over backbone initial generation. Further analysis reveals that detection quality directly determines refinement effectiveness, and ErrorLLM addresses both sides by high detection F1 score while maintain refinement effectiveness.","published":"2026-03-04T05:27:20Z","updated":"2026-06-23T11:30:41Z","categories":["cs.CL","cs.DB"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.03742v2","pdf_url":"https://arxiv.org/pdf/2603.03742v2","comment":"Accepted to SIGKDD2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.03524","versioned_id":"2603.03524v2","title":"Test-Time Meta-Adaptation with Self-Synthesis","authors":["Zeyneb N. Kaya","Nick Rui"],"abstract":"As strong general reasoners, large language models (LLMs) encounter diverse domains and tasks, where the ability to adapt and self-improve at test time is valuable. We introduce MASS, a meta-learning framework that enables LLMs to self-adapt by generating problem-specific synthetic training data and performing targeted self-updates optimized for downstream performance at inference time. We train this behavior end-to-end via bilevel optimization: an inner loop adapts on self-generated examples while an outer loop meta-learns data-attribution signals and rewards post-update task performance. The synthetic data is optimized with scalable meta-gradients, backpropagating the downstream loss through the inner updates to reward useful generations. Experiments on mathematical reasoning show that MASS learns to synthesize per-instance curricula that yield effective, data-efficient test-time adaptation.","published":"2026-03-03T21:16:18Z","updated":"2026-03-08T21:53:33Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.03524v2","pdf_url":"https://arxiv.org/pdf/2603.03524v2","comment":"5 pages, 2 figures, 1 table. Accepted to AI with Recursive Self-Improvement (RSI) Workshop @ ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.03000","versioned_id":"2603.03000v1","title":"Why Does RLAIF Work At All?","authors":["Robin Young"],"abstract":"Reinforcement Learning from AI Feedback (RLAIF) enables language models to improve by training on their own preference judgments, yet no theoretical account explains why this self-improvement seemingly works for value learning. We propose the latent value hypothesis, that pretraining on internet-scale data encodes human values as directions in representation space, and constitutional prompts elicit these latent values into preference judgments. We formalize this intuition under a linear model where the constitution acts as a projection operator selecting value-relevant directions. Our analysis yields several results. RLAIF improves alignment when the constitution-activated direction correlates with true values better than the model's default generation direction thus explaining the generation-judgment gap; the ceiling on RLAIF quality is determined by how well representations encode values, which scales with model capacity; and adversarial constitutions exist that can activate anti-social value directions encoded from harmful pretraining data. Our account unifies scattered empirical findings including the refusal direction, low-rank safety subspaces, and RLAIF scaling behavior.","published":"2026-03-03T13:51:40Z","updated":"2026-03-03T13:51:40Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.03000v1","pdf_url":"https://arxiv.org/pdf/2603.03000v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.02640","versioned_id":"2603.02640v1","title":"Credibility Governance: A Social Mechanism for Collective Self-Correction under Weak Truth Signals","authors":["Wanying He","Yanxi Lin","Ziheng Zhou","Xue Feng","Min Peng","Qianqian Xie","Zilong Zheng","Yipeng Kang"],"abstract":"Online platforms increasingly rely on opinion aggregation to allocate real-world attention and resources, yet common signals such as engagement votes or capital-weighted commitments are easy to amplify and often track visibility rather than reliability. This makes collective judgments brittle under weak truth signals, noisy or delayed feedback, early popularity surges, and strategic manipulation. We propose Credibility Governance (CG), a mechanism that reallocates influence by learning which agents and viewpoints consistently track evolving public evidence. CG maintains dynamic credibility scores for both agents and opinions, updates opinion influence via credibility-weighted endorsements, and updates agent credibility based on the long-run performance of the opinions they support, rewarding early and persistent alignment with emerging evidence while filtering short-lived noise. We evaluate CG in POLIS, a socio-physical simulation environment that models coupled belief dynamics and downstream feedback under uncertainty. Across settings with initial majority misalignment, observation noise and contamination, and misinformation shocks, CG outperforms vote-based, stake-weighted, and no-governance baselines, yielding faster recovery to the true state, reduced lock-in and path dependence, and improved robustness under adversarial pressure. Our implementation and experimental scripts are publicly available at https://github.com/Wanying-He/Credibility_Governance.","published":"2026-03-03T06:10:13Z","updated":"2026-03-03T06:10:13Z","categories":["cs.CY","cs.AI","cs.CL","cs.MA","cs.SI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2603.02640v1","pdf_url":"https://arxiv.org/pdf/2603.02640v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.02556","versioned_id":"2603.02556v1","title":"Through the Lens of Contrast: Self-Improving Visual Reasoning in VLMs","authors":["Zhiyu Pan","Yizheng Wu","Jiashen Hua","Junyi Feng","Shaotian Yan","Bing Deng","Zhiguo Cao","Jieping Ye"],"abstract":"Reasoning has emerged as a key capability of large language models. In linguistic tasks, this capability can be enhanced by self-improving techniques that refine reasoning paths for subsequent finetuning. However, extending these language-based self-improving approaches to vision language models (VLMs) presents a unique challenge:~visual hallucinations in reasoning paths cannot be effectively verified or rectified. Our solution starts with a key observation about visual contrast: when presented with a contrastive VQA pair, i.e., two visually similar images with synonymous questions, VLMs identify relevant visual cues more precisely. Motivated by this observation, we propose Visual Contrastive Self-Taught Reasoner (VC-STaR), a novel self-improving framework that leverages visual contrast to mitigate hallucinations in model-generated rationales. We collect a diverse suite of VQA datasets, curate contrastive pairs according to multi-modal similarity, and generate rationales using VC-STaR. Consequently, we obtain a new visual reasoning dataset, VisCoR-55K, which is then used to boost the reasoning capability of various VLMs through supervised finetuning. Extensive experiments show that VC-STaR not only outperforms existing self-improving approaches but also surpasses models finetuned on the SoTA visual reasoning datasets, demonstrating that the inherent contrastive ability of VLMs can bootstrap their own visual reasoning. Project at: https://github.com/zhiyupan42/VC-STaR.","published":"2026-03-03T03:18:31Z","updated":"2026-03-03T03:18:31Z","categories":["cs.CV","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.02556v1","pdf_url":"https://arxiv.org/pdf/2603.02556v1","comment":"19 pages, 9 figures, accepted to ICLR 2026 (oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.02099","versioned_id":"2603.02099v2","title":"Recursive Think-Answer Process for LLMs and VLMs","authors":["Byung-Kwan Lee","Youngchae Chee","Yong Man Ro"],"abstract":"Think-Answer reasoners such as DeepSeek-R1 have made notable progress by leveraging interpretable internal reasoning. However, despite the frequent presence of self-reflective cues like \"Oops!\", they remain vulnerable to output errors during single-pass inference. To address this limitation, we propose an efficient Recursive Think-Answer Process (R-TAP) that enables models to engage in iterative reasoning cycles and generate more accurate answers, going beyond conventional single-pass approaches. Central to this approach is a confidence generator that evaluates the certainty of model responses and guides subsequent improvements. By incorporating two complementary rewards-Recursively Confidence Increase Reward and Final Answer Confidence Reward-we show that R-TAP-enhanced models consistently outperform conventional single-pass methods for both large language models (LLMs) and vision-language models (VLMs). Moreover, by analyzing the frequency of \"Oops\"-like expressions in model responses, we find that R-TAP-applied models exhibit significantly fewer self-reflective patterns, resulting in more stable and faster inference-time reasoning. We hope R-TAP pave the way evolving into efficient and elaborated methods to refine the reasoning processes of future AI.","published":"2026-03-02T17:20:10Z","updated":"2026-03-03T09:00:50Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.02099v2","pdf_url":"https://arxiv.org/pdf/2603.02099v2","comment":"CVPR 2026 Findings, Project page: https://litcoderr.github.io/rtap_page/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.01935","versioned_id":"2603.01935v1","title":"Dream2Learn: Structured Generative Dreaming for Continual Learning","authors":["Salvatore Calcagno","Matteo Pennisi","Federica Proietto Salanitri","Amelia Sorrenti","Simone Palazzo","Concetto Spampinato","Giovanni Bellitto"],"abstract":"Continual learning requires balancing plasticity and stability while mitigating catastrophic forgetting. Inspired by human dreaming as a mechanism for internal simulation and knowledge restructuring, we introduce Dream2Learn (D2L), a framework in which a model autonomously generates structured synthetic experiences from its own internal representations and uses them for self-improvement. Rather than reconstructing past data as in generative replay, D2L enables a classifier to create novel, semantically distinct dreamed classes that are coherent with its learned knowledge yet do not correspond to previously observed data. These dreamed samples are produced by conditioning a frozen diffusion model through soft prompt optimization driven by the classifier itself. The generated data are not used to replace memory, but to expand and reorganize the representation space, effectively allowing the network to self-train on internally synthesized concepts. By integrating dreamed classes into continual training, D2L proactively structures latent features to support forward knowledge transfer and adaptation to future tasks. This prospective self-training mechanism mirrors the role of sleep in consolidating and reorganizing memory, turning internal simulations into a tool for improved generalization. Experiments on Mini-ImageNet, FG-ImageNet, and ImageNet-R demonstrate that D2L consistently outperforms strong rehearsal-based baselines and achieves positive forward transfer, confirming its ability to enhance adaptability through internally generated training signals.","published":"2026-03-02T14:52:10Z","updated":"2026-03-02T14:52:10Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.01935v1","pdf_url":"https://arxiv.org/pdf/2603.01935v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.01853","versioned_id":"2603.01853v2","title":"Let the Agent Search: Autonomous Exploration Beats Rigid Workflows in Temporal Question Answering","authors":["Xufei Lv","Jiahui Yang","Haoyuan Sun","Xialin Su","Zhiliang Tian","Yifu Gao","Linbo Qiao","Houde Liu"],"abstract":"Temporal Knowledge Graph Question Answering (TKGQA) is challenging because it requires multi-hop reasoning under complex temporal constraints. Recent LLM-based approaches have improved semantic modeling for this task, but many still rely on fixed reasoning workflows or costly post-training, which can limit adaptability and make error recovery difficult. We show that enabling an off-the-shelf Large Language Model (LLM) to determine its next action is already effective in a zero-shot setting. Based on this insight, we propose AT2QA, an Autonomous and Training-free Agent for TKG Question Answering. AT2QA empowers the LLM to iteratively interact with the TKG via a generic search tool, inherently enabling autonomous exploration and dynamic self-correction during reasoning. To further elicit the LLM's potential for complex temporal reasoning, we introduce a training-free experience mining mechanism that distills a compact few-shot demonstration library from successful self-generated trajectories. AT2QA also yields a transparent audit trail for every prediction. Experiments on three challenging benchmarks -- MultiTQ, Timeline-CronQuestion, and Timeline-ICEWS-Actor -- show that AT2QA achieves new state-of-the-art performance, surpassing the strongest baselines by 10.7, 4.9, and 11.2 absolute points, respectively. Our code is available at https://github.com/AT2QA-Official-Code/AT2QA-Official-Code","published":"2026-03-02T13:33:39Z","updated":"2026-03-25T15:29:38Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.01853v2","pdf_url":"https://arxiv.org/pdf/2603.01853v2","comment":"Revised version with three added authors and additional experiments","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.01755","versioned_id":"2603.01755v1","title":"Federated Agentic AI for Wireless Networks: Fundamentals, Approaches, and Applications","authors":["Lingyi Cai","Yu Zhang","Ruichen Zhang","Yinqiu Liu","Tao Jiang","Dusit Niyato","Wei Ni","Abbas Jamalipour"],"abstract":"Agentic artificial intelligence (AI) presents a promising pathway toward realizing autonomous and self-improving wireless network services. However, resource-constrained, widely distributed, and data-heterogeneous nature of wireless networks poses significant challenges to existing agentic AI that relies on centralized architectures, leading to high communication overhead, privacy risks, and non-independent and identically distributed (non-IID) data. Federated learning (FL) has the potential to improve the overall loop of agentic AI through collaborative local learning and parameter sharing without exchanging raw data. This paper proposes new federated agentic AI approaches for wireless networks. We first summarize fundamentals of agentic AI and mainstream FL types. Then, we illustrate how each FL type can strengthen a specific component of agentic AI's loop. Moreover, we conduct a case study on using FRL to improve the performance of agentic AI's action decision in low-altitude wireless networks (LAWNs). Finally, we provide a conclusion and discuss future research directions.","published":"2026-03-02T11:26:56Z","updated":"2026-03-02T11:26:56Z","categories":["cs.NI","cs.AI"],"primary_category":"cs.NI","arxiv_url":"https://arxiv.org/abs/2603.01755v1","pdf_url":"https://arxiv.org/pdf/2603.01755v1","comment":"7 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.01421","versioned_id":"2603.01421v3","title":"SciDER: Scientific Data-centric End-to-end Researcher","authors":["Ke Lin","Owais Aijaz","Yilin Lu","Yiyang Luo","Xuehang Guo","Preslav Nakov"],"abstract":"While large language models accelerate scientific discovery, existing agents face severe limitations in adaptability, domain generalization, and multimodal scalability, often struggling to autonomously process raw, domain-specific experimental data. To overcome these barriers, we introduce SciDER, a multi-agent system designed to flexibly automate the entire research lifecycle. This framework employs a novel data-centric approach and integrates a dynamic multimodal skill system across four specialized sub-agents. Specifically, an ideation agent generates novel hypotheses via Evolutionary Idea Search, a data analysis agent systematically structures raw data, an experimentation agent synthesizes executable code grounded in dataset characteristics, and a critic agent drives iterative self-refinement. To democratize open-source scientific discovery, we release OpenSciDER-SFT-8K, a high-quality execution trajectory dataset, alongside the OpenSciDER-27B fine-tuned model. Across six benchmarks, SciDER and OpenSciDER obtain competitive or leading results, with especially strong gains on data-centric analysis, end-to-end research execution, and multimodal scientific visualization. By integrating data analysis with experimental execution, SciDER bridges the gap between abstract scientific reasoning and reproducible experimentation synthesis.","published":"2026-03-02T03:53:20Z","updated":"2026-06-03T13:47:56Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.01421v3","pdf_url":"https://arxiv.org/pdf/2603.01421v3","comment":"10 pages, 8 figures, 7 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.01335","versioned_id":"2603.01335v1","title":"Provable and Practical In-Context Policy Optimization for Self-Improvement","authors":["Tianrun Yu","Yuxiao Yang","Zhaoyang Wang","Kaixiang Zhao","Porter Jenkins","Xuchao Zhang","Chetan Bansal","Huaxiu Yao","Weitong Zhang"],"abstract":"We study test-time scaling, where a model improves its answer through multi-round self-reflection at inference. We introduce In-Context Policy Optimization (ICPO), in which an agent optimizes its response in context using self-assessed or externally observed rewards without modifying its parameters. To explain this ICPO process, we theoretically show that with sufficient pretraining under a novel Fisher-weighted logit-matching objective, a single-layer linear self-attention model can provably imitate policy-optimization algorithm for linear bandits. Building on this theory, we propose Minimum-Entropy ICPO (ME-ICPO), a practical algorithm that iteratively uses its response and self-assessed reward to refine its response in-context at inference time. By selecting the responses and their rewards with minimum entropy, ME-ICPO ensures the robustness of the self-assessed rewards via majority voting. Across standard mathematical reasoning tasks, ME-ICPO attains competitive, top-tier performance while keeping inference costs affordable compared with other inference-time algorithms. Overall, ICPO provides a principled understanding of self-reflection in LLMs and yields practical benefits for test-time scaling for mathematical reasoning.","published":"2026-03-02T00:21:50Z","updated":"2026-03-02T00:21:50Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.01335v1","pdf_url":"https://arxiv.org/pdf/2603.01335v1","comment":"34 pages, 8 tables, 4 figures, Accepted by ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00846","versioned_id":"2603.00846v1","title":"Tiny-Critic RAG: Empowering Agentic Fallback with Parameter-Efficient Small Language Models","authors":["Yichao Wu","Penghao Liang","Yafei Xiang","Mengwei Yuan","Jianan Liu","Jing Yang","Xianyou Li","Weiran Yan"],"abstract":"Retrieval-Augmented Generation (RAG) grounds Large Language Models (LLMs) to mitigate factual hallucinations. Recent paradigms shift from static pipelines to Modular and Agentic RAG frameworks, granting models autonomy for multi-hop reasoning or self-correction. However, current reflective RAG heavily relies on massive LLMs as universal evaluators. In high-throughput systems, executing complete forward passes for billion-parameter models merely for binary routing introduces severe computational redundancy. Furthermore, in autonomous agent scenarios, inaccurate retrieval causes models to expend excessive tokens on spurious reasoning and redundant tool calls, inflating Time-to-First-Token (TTFT) and costs. We propose Tiny-Critic RAG, decoupling evaluation by deploying a parameter-efficient Small Language Model (SLM) via Low-Rank Adaptation (LoRA). Acting as a deterministic gatekeeper, Tiny-Critic employs constrained decoding and non-thinking inference modes for ultra-low latency binary routing. Evaluations on noise-injected datasets demonstrate Tiny-Critic RAG achieves routing accuracy comparable to GPT-4o-mini while reducing latency by an order of magnitude, establishing a highly cost-effective paradigm for agent deployment.","published":"2026-03-01T00:16:31Z","updated":"2026-03-01T00:16:31Z","categories":["cs.IR","cs.LG"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2603.00846v1","pdf_url":"https://arxiv.org/pdf/2603.00846v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00823","versioned_id":"2603.00823v2","title":"A Comprehensive Evaluation of LLM Unlearning Robustness under Multi-Turn Interaction","authors":["Ruihao Pan","Suhang Wang"],"abstract":"Machine unlearning aims to remove the influence of specific training data from pre-trained models without retraining from scratch, and is increasingly important for large language models (LLMs) due to safety, privacy, and legal concerns. Although prior work primarily evaluates unlearning in static, single-turn settings, forgetting robustness under realistic interactive use remains underexplored. In this paper, we study whether unlearning remains stable in interactive environments by examining two common interaction patterns: self-correction and dialogue-conditioned querying. We find that knowledge appearing forgotten in static evaluation can often be recovered through interaction. Although stronger unlearning improves apparent robustness, it often results in behavioral rigidity rather than genuine knowledge erasure. Our findings suggest that static evaluation may overestimate real-world effectiveness and highlight the need for ensuring stable forgetting under interactive settings.","published":"2026-02-28T22:01:31Z","updated":"2026-03-15T00:48:31Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.00823v2","pdf_url":"https://arxiv.org/pdf/2603.00823v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00822","versioned_id":"2603.00822v2","title":"ContextCov: Deriving and Enforcing Executable Constraints from Agent Instruction Files","authors":["Reshabh K Sharma"],"abstract":"As Large Language Model (LLM) agents increasingly execute complex, autonomous software engineering tasks, developers rely on natural language instruction files such as AGENTS.md to express project-specific coding conventions, tooling restrictions, and architectural boundaries. However, because these instructions remain passive text, agents frequently violate documented constraints due to context window saturation or conflicting local context. In autonomous settings without real-time human supervision, such violations rapidly compound into technical debt. To ground autonomous agents in repository constraints, we introduce ContextCov, a framework that transforms passive natural language instructions into executable guardrails. Unlike prompt-only or reflection-only compliance approaches, ContextCov compiles documented constraints into three complementary checks: static AST queries for code patterns, runtime shell shims that intercept prohibited commands, and architectural validators that enforce structural rules. Acting as an automated, continuous reviewer, ContextCov intercepts agent actions and returns immediate, reproducible violation traces, enabling self-correction before non-compliant changes are finalized. We evaluate ContextCov on SWE-bench Lite (12 repositories, 300 tasks). Compared to prompt-only and LLM reflection baselines, ContextCov achieves 88.3% constraint compliance (vs. 67.0% and 50.3%) with 3.4x lower feedback cost, while maintaining functional correctness. The source code and evaluation results are available at https://github.com/reSHARMA/ContextCov.","published":"2026-02-28T21:56:47Z","updated":"2026-05-04T08:55:15Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.00822v2","pdf_url":"https://arxiv.org/pdf/2603.00822v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00808","versioned_id":"2603.00808v1","title":"MetaMind: General and Cognitive World Models in Multi-Agent Systems by Meta-Theory of Mind","authors":["Lingyi Wang","Rashed Shelim","Walid Saad","Naren Ramakrishna"],"abstract":"A major challenge for world models in multi-agent systems is to understand interdependent agent dynamics, predict interactive multi-agent trajectories, and plan over long horizons with collective awareness, without centralized supervision or explicit communication. In this paper, MetaMind, a general and cognitive world model for multi-agent systems that leverages a novel meta-theory of mind (Meta-ToM) framework, is proposed. Through MetaMind, each agent learns not only to predict and plan over its own beliefs, but also to inversely reason goals and beliefs from its own behavior trajectories. This self-reflective, bidirectional inference loop enables each agent to learn a metacognitive ability in a self-supervised manner. Then, MetaMind is shown to generalize the metacognitive ability from first-person to third-person through analogical reasoning. Thus, in multi-agent systems, each agent with MetaMind can actively reason about goals and beliefs of other agents from limited, observable behavior trajectories in a zero-shot manner, and then adapt to emergent collective intention without an explicit communication mechanism. Extended simulation results on diverse multi-agent tasks demonstrate that MetaMind can achieve superior task performance and outperform baselines in few-shot multi-agent generalization.","published":"2026-02-28T21:03:48Z","updated":"2026-02-28T21:03:48Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.00808v1","pdf_url":"https://arxiv.org/pdf/2603.00808v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00483","versioned_id":"2603.00483v1","title":"RAISE: Requirement-Adaptive Evolutionary Refinement for Training-Free Text-to-Image Alignment","authors":["Liyao Jiang","Ruichen Chen","Chao Gao","Di Niu"],"abstract":"Recent text-to-image (T2I) diffusion models achieve remarkable realism, yet faithful prompt-image alignment remains challenging, particularly for complex prompts with multiple objects, relations, and fine-grained attributes. Existing training-free inference-time scaling methods rely on fixed iteration budgets that cannot adapt to prompt difficulty, while reflection-tuned models require carefully curated reflection datasets and extensive joint fine-tuning of diffusion and vision-language models, often overfitting to reflection paths data and lacking transferability across models. We introduce RAISE (Requirement-Adaptive Self-Improving Evolution), a training-free, requirement-driven evolutionary framework for adaptive T2I generation. RAISE formulates image generation as a requirement-driven adaptive scaling process, evolving a population of candidates at inference time through a diverse set of refinement actions-including prompt rewriting, noise resampling, and instructional editing. Each generation is verified against a structured checklist of requirements, enabling the system to dynamically identify unsatisfied items and allocate further computation only where needed. This achieves adaptive test-time scaling that aligns computational effort with semantic query complexity. On GenEval and DrawBench, RAISE attains state-of-the-art alignment (0.94 overall GenEval) while incurring fewer generated samples (reduced by 30-40%) and VLM calls (reduced by 80%) than prior scaling and reflection-tuned baselines, demonstrating efficient, generalizable, and model-agnostic multi-round self-improvement. Code is available at https://github.com/LiyaoJiang1998/RAISE.","published":"2026-02-28T05:53:01Z","updated":"2026-02-28T05:53:01Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.00483v1","pdf_url":"https://arxiv.org/pdf/2603.00483v1","comment":"CVPR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.19262","versioned_id":"2603.19262v2","title":"Empirical Characterization of Inference-Time Elicited Probability Transformations in Large Language Models","authors":["Mike Farmer","Abhinav Kochar","Yugyung Lee"],"abstract":"Large language models increasingly rely on inference-time procedures such as chain-of-thought reasoning, self-refinement, retrieval augmentation, and verifier-guided revision, yet the structure of elicited probability transformations under these procedures remains poorly understood. We study externally elicited probability assignments over candidate answers and observe recurring approximate log-ratio relationships: \\[ \\log \\tilde q_t(i) = α_t \\left( \\log q_t(i) + \\log b_t(i) \\right) + c_t, \\] where $q_t$ and $\\tilde q_t$ are pre- and post-elicitation probabilities, $b_t$ is an externally constructed evidence signal, and $α_t$ is an empirical descriptor of the prompting configuration. Across 4,975 reasoning problems from GPQA Diamond, TheoremQA, MMLU-Pro, and ARC-Challenge, evaluated on multiple instruction-tuned model families, we observe approximate log-ratio relationships with mean $R^2 \\approx 0.76$ over about $1.3 \\times 10^5$ candidate-level observations. Coefficients vary across elicitation settings, but qualitatively similar relationships persist across evaluated conditions. Robustness analyses using alternative statistical representations, prompting configurations, held-out evaluation, and token-level log-probabilities suggest that the observed structure is not tied to one prompting procedure or probability estimation method. The main contribution is not the algebraic form itself, which is related to generalized Bayesian updating and probability-transformation frameworks, but the empirical observation that diverse inference-time prompting pipelines repeatedly exhibit reproducible log-ratio structure under controlled conditions. The framework provides a protocol-sensitive perspective for analyzing calibration, evidence amplification, uncertainty propagation, and interaction sensitivity in inference-time LLM pipelines.","published":"2026-02-26T20:52:27Z","updated":"2026-05-28T23:06:43Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.19262v2","pdf_url":"https://arxiv.org/pdf/2603.19262v2","comment":"22 pages, 11 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00176","versioned_id":"2603.00176v1","title":"Bridging Policy and Real-World Dynamics: LLM-Augmented Rebalancing for Shared Micromobility Systems","authors":["Heng Tan","Hua Yan","Yu Yang"],"abstract":"Shared micromobility services such as e-scooters and bikes have become an integral part of urban transportation, yet their efficiency critically depends on effective vehicle rebalancing. Existing methods either optimize for average demand patterns or employ robust optimization and reinforcement learning to handle predefined uncertainties. However, these approaches overlook emergent events (e.g., demand surges, vehicle outages, regulatory interventions) or sacrifice performance in normal conditions. We introduce AMPLIFY, an LLM-augmented policy adaptation framework for shared micromobility rebalancing. The framework combines a baseline rebalancing module with an LLM-based adaptation module that adjusts strategies in real time under emergent scenarios. The adaptation module ingests system context, demand predictions, and baseline strategies, and refines adjustments through self-reflection. Evaluations on real-world e-scooter data from Chicago show that our approach improves demand satisfaction and system revenue compared to baseline policies, highlighting the potential of LLM-driven adaptation as a flexible solution for managing uncertainty in micromobility systems.","published":"2026-02-26T19:13:17Z","updated":"2026-02-26T19:13:17Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.00176v1","pdf_url":"https://arxiv.org/pdf/2603.00176v1","comment":"8 pages, 7 figures, accepted by ICRA 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.23320","versioned_id":"2602.23320v2","title":"ParamMem: Augmenting Language Agents with Parametric Reflective Memory","authors":["Tianjun Yao","Yongqiang Chen","Yujia Zheng","Pan Li","Zhiqiang Shen","Kun Zhang"],"abstract":"Self-reflection enables language agents to iteratively refine solutions, yet often produces repetitive outputs that limit reasoning performance. Recent studies have attempted to address this limitation through various approaches, among which increasing reflective diversity has shown promise. Our empirical analysis reveals a strong positive correlation between reflective diversity and task success, further motivating the need for diverse reflection signals. We introduce ParamMem, a parametric memory module that encodes cross-sample reflection patterns into model parameters, enabling diverse reflection generation through temperature-controlled sampling. Building on this module, we propose ParamAgent, a reflection-based agent framework that integrates parametric memory with episodic and cross-sample memory. Extensive experiments on code generation, mathematical reasoning, and multi-hop question answering demonstrate consistent improvements over state-of-the-art baselines. Further analysis reveals that ParamMem is sample-efficient, enables weak-to-strong transfer across model scales, and supports self-improvement without reliance on stronger external model, highlighting the potential of ParamMem as an effective component for enhancing language agents.","published":"2026-02-26T18:28:04Z","updated":"2026-02-27T08:21:31Z","categories":["cs.LG","cs.MA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.23320v2","pdf_url":"https://arxiv.org/pdf/2602.23320v2","comment":"20 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.23407","versioned_id":"2602.23407v1","title":"Learning to Generate Secure Code via Token-Level Rewards","authors":["Jiazheng Quan","Xiaodong Li","Bin Wang","Guo An","Like Liu","Degen Huang","Lin Liu","Chengbin Hou"],"abstract":"Large language models (LLMs) have demonstrated strong capabilities in code generation, yet they remain prone to producing security vulnerabilities. Existing approaches commonly suffer from two key limitations: the scarcity of high-quality security data and coarse-grained reinforcement learning reward signals. To address these challenges, we propose Vul2Safe, a new secure code generation framework that leverages LLM self-reflection to construct high-confidence repair pairs from real-world vulnerabilities, and further generates diverse implicit prompts to build the PrimeVul+ dataset. Meanwhile, we introduce SRCode, a novel training framework that pioneers the use of token-level rewards in reinforcement learning for code security, which enables the model to continuously attend to and reinforce critical fine-grained security patterns during training. Compared with traditional instance-level reward schemes, our approach allows for more precise optimization of local security implementations. Extensive experiments show that PrimeVul+ and SRCode substantially reduce security vulnerabilities in generated code while improving overall code quality across multiple benchmarks.","published":"2026-02-26T12:57:27Z","updated":"2026-02-26T12:57:27Z","categories":["cs.CR","cs.AI","cs.SE"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2602.23407v1","pdf_url":"https://arxiv.org/pdf/2602.23407v1","comment":"18 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.22839","versioned_id":"2602.22839v3","title":"DeepPresenter: Environment-Grounded Reflection for Agentic Presentation Generation","authors":["Hao Zheng","Guozhao Mo","Xinru Yan","Qianhao Yuan","Wenkai Zhang","Xuanang Chen","Yaojie Lu","Hongyu Lin","Xianpei Han","Le Sun"],"abstract":"Presentation generation requires deep content research, coherent visual design, and iterative refinement based on observation. However, existing presentation agents often rely on predefined workflows and fixed templates. To address this, we present DeepPresenter, an agentic framework that adapts to diverse user intents, enables effective feedback-driven refinement, and generalizes beyond a scripted pipeline. Specifically, DeepPresenter autonomously plans, renders, and revises intermediate slide artifacts to support long-horizon refinement with environmental observations. Furthermore, rather than relying on self-reflection over internal signals (e.g., reasoning traces), our environment-grounded reflection conditions the generation process on perceptual artifact states (e.g., rendered slides), enabling the system to identify and correct presentation-specific issues during execution. Results on the evaluation set covering diverse presentation-generation scenarios show that DeepPresenter achieves state-of-the-art performance, and the fine-tuned 9B model remains highly competitive at substantially lower cost. Our project is available at: https://github.com/icip-cas/PPTAgent","published":"2026-02-26T10:26:48Z","updated":"2026-04-20T02:43:16Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.22839v3","pdf_url":"https://arxiv.org/pdf/2602.22839v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.19257","versioned_id":"2603.19257v1","title":"Constraint-aware Path Planning from Natural Language Instructions Using Large Language Models","authors":["Dylan Shim","Minghan Wei"],"abstract":"Real-world path planning tasks typically involve multiple constraints beyond simple route optimization, such as the number of routes, maximum route length, depot locations, and task-specific requirements. Traditional approaches rely on dedicated formulations and algorithms for each problem variant, making them difficult to scale across diverse scenarios. In this work, we propose a flexible framework that leverages large language models (LLMs) to solve constrained path planning problems directly from natural language input. The core idea is to allow users to describe routing tasks conversationally, while enabling the LLM to interpret and solve the problem through solution verification and iterative refinement. The proposed method consists of two integrated components. For problem types that have been previously formulated and studied, the LLM first matches the input request to a known problem formulation in a library of pre-defined templates. For novel or unseen problem instances, the LLM autonomously infers a problem representation from the natural language description and constructs a suitable formulation in an in-context learning manner. In both cases, an iterative solution generation and verification process guides the LLM toward producing feasible and increasingly optimal solutions. Candidate solutions are compared and refined through multiple rounds of self-correction, inspired by genetic-algorithm-style refinement. We present the design, implementation, and evaluation of this LLM-based framework, demonstrating its capability to handle a variety of constrained path planning problems. This method provides a scalable and generalizable approach for solving real-world routing tasks with minimal human intervention, while enabling flexible problem specification through natural language.","published":"2026-02-26T09:01:42Z","updated":"2026-02-26T09:01:42Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.19257v1","pdf_url":"https://arxiv.org/pdf/2603.19257v1","comment":"Accepted by 2026 SPIE Security + Defense Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.22508","versioned_id":"2602.22508v2","title":"Metacognitive Behavioral Tuning of Large Language Models for Multi-Hop Question Answering","authors":["Ik-hwan Kim","Hyeongrok Han","Mingi Jung","Sangwon Yu","Jinseok Hong","Sang Hun Kim","Yoonyoung Choi","Sungroh Yoon"],"abstract":"Large Language Models (LLMs) often produce incorrect answers on multi-hop question answering even when the reasoning trace already contains a correct intermediate conclusion. We attribute this gap to weak self-regulation rather than insufficient reasoning capacity. Without explicit regulation, valid intermediate conclusions are overridden by continued exploration or left unrecognized as logically sufficient. We propose Metacognitive Behavioral Tuning (MBT), a post-training framework that injects a five-phase metacognitive structure into reasoning traces. The five phases are understanding and filtering, planning, execution and monitoring, self-correction, and verification. MBT has two formulations. MBT-S synthesizes new metacognitive traces from scratch, while MBT-R rewrites the student's own traces into a metacognitive form. Across HotpotQA, MuSiQue, and 2WikiMultiHopQA, MBT attains the highest Accuracy-Efficiency Score (AES) across model scales. MBT lifts task accuracy while keeping traces short and stable, with mean response length on MuSiQue an order of magnitude shorter than baseline methods and degeneration counts reduced by a similar margin. A matched-control study further confirms that the gain stems from the five-phase structural prior itself. To qualitatively assess the regulatory behavior of reasoning traces, we introduce two new metrics, the Reach-Redundancy Profile (RRP) and the length-aware Metacognitive Quality Index (MQI). RRP captures when the answer is reached and how much of the trace is redundant, and MQI quantifies how richly the five phases appear. Under both metrics, MBT achieves the earliest answer arrival, the lowest redundancy, and the richest phase-level behavior across model scales.","published":"2026-02-26T00:56:15Z","updated":"2026-05-11T05:22:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.22508v2","pdf_url":"https://arxiv.org/pdf/2602.22508v2","comment":"41 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.22207","versioned_id":"2602.22207v1","title":"Recovered in Translation: Efficient Pipeline for Automated Translation of Benchmarks and Datasets","authors":["Hanna Yukhymenko","Anton Alexandrov","Martin Vechev"],"abstract":"The reliability of multilingual Large Language Model (LLM) evaluation is currently compromised by the inconsistent quality of translated benchmarks. Existing resources often suffer from semantic drift and context loss, which can lead to misleading performance metrics. In this work, we present a fully automated framework designed to address these challenges by enabling scalable, high-quality translation of datasets and benchmarks. We demonstrate that adapting test-time compute scaling strategies, specifically Universal Self-Improvement (USI) and our proposed multi-round ranking method, T-RANK, allows for significantly higher quality outputs compared to traditional pipelines. Our framework ensures that benchmarks preserve their original task structure and linguistic nuances during localization. We apply this approach to translate popular benchmarks and datasets into eight Eastern and Southern European languages (Ukrainian, Bulgarian, Slovak, Romanian, Lithuanian, Estonian, Turkish, Greek). Evaluations using both reference-based metrics and LLM-as-a-judge show that our translations surpass existing resources, resulting in more accurate downstream model assessment. We release both the framework and the improved benchmarks to facilitate robust and reproducible multilingual AI development.","published":"2026-02-25T18:58:25Z","updated":"2026-02-25T18:58:25Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.22207v1","pdf_url":"https://arxiv.org/pdf/2602.22207v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.13260","versioned_id":"2603.13260v1","title":"Explain in Your Own Words: Improving Reasoning via Token-Selective Dual Knowledge Distillation","authors":["Minsang Kim","Seung Jun Baek"],"abstract":"Knowledge Distillation (KD) can transfer the reasoning abilities of large models to smaller ones, which can reduce the costs to generate Chain-of-Thoughts for reasoning tasks. KD methods typically ask the student to mimic the teacher's distribution over the entire output. However, a student with limited capacity can be overwhelmed by such extensive supervision causing a distribution mismatch, especially in complex reasoning tasks. We propose Token-Selective Dual Knowledge Distillation (TSD-KD), a framework for student-centric distillation. TSD-KD focuses on distilling important tokens for reasoning and encourages the student to explain reasoning in its own words. TSD-KD combines indirect and direct distillation. Indirect distillation uses a weak form of feedback based on preference ranking. The student proposes candidate responses generated on its own; the teacher re-ranks those candidates as indirect feedback without enforcing its entire distribution. Direct distillation uses distribution matching; however, it selectively distills tokens based on the relative confidence between teacher and student. Finally, we add entropy regularization to maintain the student's confidence during distillation. Overall, our method provides the student with targeted and indirect feedback to support its own reasoning process and to facilitate self-improvement. The experiments show the state-of-the-art performance of TSD-KD on 10 challenging reasoning benchmarks, outperforming the baseline and runner-up in accuracy by up to 54.4\\% and 40.3\\%, respectively. Notably, a student trained by TSD-KD even outperformed its own teacher model in four cases by up to 20.3\\%. The source code is available at https://github.com/kmswin1/TSD-KD.","published":"2026-02-25T09:58:49Z","updated":"2026-02-25T09:58:49Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.13260v1","pdf_url":"https://arxiv.org/pdf/2603.13260v1","comment":"The Fourteenth International Conference on Learning Representations (ICLR) 2026, Accepted","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.09579","versioned_id":"2604.09579v1","title":"Help Without Being Asked: A Deployed Proactive Agent System for On-Call Support with Continuous Self-Improvement","authors":["Fengrui Liu","Xiao He","Tieying Zhang"],"abstract":"In large-scale cloud service platforms, thousands of customer tickets are generated daily and are typically handled through on-call dialogues. This high volume of on-call interactions imposes a substantial workload on human support analysts. Recent studies have explored reactive agents that leverage large language models as a first line of support to interact with customers directly and resolve issues. However, when issues remain unresolved and are escalated to human support, these agents are typically disengaged. As a result, they cannot assist with follow-up inquiries, track resolution progress, or learn from the cases they fail to address. In this paper, we introduce Vigil, a novel proactive agent system designed to operate throughout the entire on-call life-cycle. Unlike reactive agents, Vigil focuses on providing assistance during the phase in which human support is already involved. It integrates into the dialogue between the customer and the analyst, proactively offering assistance without explicit user invocation. Moreover, Vigil incorporates a continuous self-improvement mechanism that extracts knowledge from human-resolved cases to autonomously update its capabilities. Vigil has been deployed on Volcano Engine, ByteDance's cloud platform, for over ten months, and comprehensive evaluations based on this deployment demonstrate its effectiveness and practicality. The open source version of this work is publicly available at https://github.com/volcengine/veaiops.","published":"2026-02-25T07:46:39Z","updated":"2026-02-25T07:46:39Z","categories":["cs.AI","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09579v1","pdf_url":"https://arxiv.org/pdf/2604.09579v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.21633","versioned_id":"2602.21633v1","title":"Self-Correcting VLA: Online Action Refinement via Sparse World Imagination","authors":["Chenyv Liu","Wentao Tan","Lei Zhu","Fengling Li","Jingjing Li","Guoli Yang","Heng Tao Shen"],"abstract":"Standard vision-language-action (VLA) models rely on fitting statistical data priors, limiting their robust understanding of underlying physical dynamics. Reinforcement learning enhances physical grounding through exploration yet typically relies on external reward signals that remain isolated from the agent's internal states. World action models have emerged as a promising paradigm that integrates imagination and control to enable predictive planning. However, they rely on implicit context modeling, lacking explicit mechanisms for self-improvement. To solve these problems, we propose Self-Correcting VLA (SC-VLA), which achieve self-improvement by intrinsically guiding action refinement through sparse imagination. We first design sparse world imagination by integrating auxiliary predictive heads to forecast current task progress and future trajectory trends, thereby constraining the policy to encode short-term physical evolution. Then we introduce the online action refinement module to reshape progress-dependent dense rewards, adjusting trajectory orientation based on the predicted sparse future states. Evaluations on challenging robot manipulation tasks from simulation benchmarks and real-world settings demonstrate that SC-VLA achieve state-of-the-art performance, yielding the highest task throughput with 16% fewer steps and a 9% higher success rate than the best-performing baselines, alongside a 14% gain in real-world experiments. Code is available at https://github.com/Kisaragi0/SC-VLA.","published":"2026-02-25T06:58:06Z","updated":"2026-02-25T06:58:06Z","categories":["cs.RO","cs.AI","cs.CV"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2602.21633v1","pdf_url":"https://arxiv.org/pdf/2602.21633v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.13258","versioned_id":"2603.13258v1","title":"Your Code Agent Can Grow Alongside You with Structured Memory","authors":["Yi-Xuan Deng","Xiaoqin Liu","Yi Zhang","Guo-Wei Yang","Shuojin Yang"],"abstract":"While \"Intent-oriented programming\" (or \"Vibe Coding\") redefines software engineering, existing code agents remain tethered to static code snapshots. Consequently, they struggle to model the critical information embedded in the temporal evolution of projects, failing to leverage the \"reasoning trajectories\" implicit in past successful practices. This limitation results in rigid behavioral logic and a lack of autonomous adaptability, ultimately hindering their ability to tackle complex, repository-level problems. To bridge this static-dynamic mismatch, we propose MemCoder, a framework designed to enable continual human-AI co-evolution. MemCoder first structures historical human experience to distill latent intent-to-code mappings from past commits. It then employs a self-refinement mechanism driven by verification feedback to correct agent behavior in real-time. Crucially, an experience self-internalization mechanism is introduced to crystallize human-validated solutions into long-term knowledge, thereby supporting sustained evolution. Experimental results on SWE-bench Verified demonstrate that MemCoder not only achieves State-of-the-Art (SOTA) performance but also delivers a 9.4% improvement in resolved rate over the general foundation model DeepSeek-V3.2. These findings indicate that equipping agents with the capability to co-evolve with humans via project history and real-time feedback effectively unlocks the potential of general models in complex software engineering tasks.","published":"2026-02-25T06:39:29Z","updated":"2026-02-25T06:39:29Z","categories":["cs.LG","cs.AI","cs.SE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.13258v1","pdf_url":"https://arxiv.org/pdf/2603.13258v1","comment":"Code Agent","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.21496","versioned_id":"2602.21496v1","title":"Beyond Refusal: Probing the Limits of Agentic Self-Correction for Semantic Sensitive Information","authors":["Umid Suleymanov","Zaur Rajabov","Emil Mirzazada","Murat Kantarcioglu"],"abstract":"While defenses for structured PII are mature, Large Language Models (LLMs) pose a new threat: Semantic Sensitive Information (SemSI), where models infer sensitive identity attributes, generate reputation-harmful content, or hallucinate potentially wrong information. The capacity of LLMs to self-regulate these complex, context-dependent sensitive information leaks without destroying utility remains an open scientific question. To address this, we introduce SemSIEdit, an inference-time framework where an agentic \"Editor\" iteratively critiques and rewrites sensitive spans to preserve narrative flow rather than simply refusing to answer. Our analysis reveals a Privacy-Utility Pareto Frontier, where this agentic rewriting reduces leakage by 34.6% across all three SemSI categories while incurring a marginal utility loss of 9.8%. We also uncover a Scale-Dependent Safety Divergence: large reasoning models (e.g., GPT-5) achieve safety through constructive expansion (adding nuance), whereas capacity-constrained models revert to destructive truncation (deleting text). Finally, we identify a Reasoning Paradox: while inference-time reasoning increases baseline risk by enabling the model to make deeper sensitive inferences, it simultaneously empowers the defense to execute safe rewrites.","published":"2026-02-25T02:09:23Z","updated":"2026-02-25T02:09:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.21496v1","pdf_url":"https://arxiv.org/pdf/2602.21496v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.21351","versioned_id":"2602.21351v1","title":"A Hierarchical Multi-Agent System for Autonomous Discovery in Geoscientific Data Archives","authors":["Dmitrii Pantiukhin","Ivan Kuznetsov","Boris Shapkin","Antonia Anna Jost","Thomas Jung","Nikolay Koldunov"],"abstract":"The rapid accumulation of Earth science data has created a significant scalability challenge; while repositories like PANGAEA host vast collections of datasets, citation metrics indicate that a substantial portion remains underutilized, limiting data reusability. Here we present PANGAEA-GPT, a hierarchical multi-agent framework designed for autonomous data discovery and analysis. Unlike standard Large Language Model (LLM) wrappers, our architecture implements a centralized Supervisor-Worker topology with strict data-type-aware routing, sandboxed deterministic code execution, and self-correction via execution feedback, enabling agents to diagnose and resolve runtime errors. Through use-case scenarios spanning physical oceanography and ecology, we demonstrate the system's capacity to execute complex, multi-step workflows with minimal human intervention. This framework provides a methodology for querying and analyzing heterogeneous repository data through coordinated agent workflows.","published":"2026-02-24T20:37:38Z","updated":"2026-02-24T20:37:38Z","categories":["cs.AI","cs.IR","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.21351v1","pdf_url":"https://arxiv.org/pdf/2602.21351v1","comment":"20 pages, 6 figures, 7 tables, supplementary material included","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.21185","versioned_id":"2602.21185v2","title":"The Diffusion Duality, Chapter II: $Ψ$-Samplers","authors":["Justin Deschenaux","Caglar Gulcehre","Subham Sekhar Sahoo"],"abstract":"Uniform-state discrete diffusion models excel at few-step generation and guidance due to their ability to self-correct, making them preferred over autoregressive or Masked diffusion models in these settings. However, their sampling quality plateaus with ancestral samplers as the number of steps increases. We introduce a family of Predictor-Corrector (PC) samplers for discrete diffusion that generalize prior methods and apply to arbitrary noise processes. When paired with uniform-state diffusion, our samplers outperform ancestral sampling on both language and image modeling, achieving lower generative perplexity at matched unigram entropy on OpenWebText and better FID/IS scores on CIFAR10. Crucially, unlike conventional samplers, our PC methods continue to improve with more sampling steps. Taken together, these findings call into question the assumption that Masked diffusion is the inevitable future of diffusion-based language modeling. Beyond sampling, we develop a memory-efficient curriculum for the Gaussian relaxation training phase, reducing training time by 25% and memory by 33% compared to Duo while maintaining comparable perplexity on OpenWebText and LM1B and strong downstream performance. We release code, checkpoints, and a video-tutorial on: https://s-sahoo.com/duo-ch2","published":"2026-02-24T18:35:22Z","updated":"2026-05-16T12:34:11Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.21185v2","pdf_url":"https://arxiv.org/pdf/2602.21185v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.20670","versioned_id":"2602.20670v2","title":"CAMEL: Confidence-Gated Reflection for Reward Modeling","authors":["Zirui Zhu","Hailun Xu","Yang Luo","Yong Liu","Kanchan Sarkar","Kun Xu","Yang You"],"abstract":"Reward models play a fundamental role in aligning large language models with human preferences. Existing methods predominantly follow two paradigms: scalar discriminative preference models, which are efficient but lack interpretability, and generative judging models, which offer richer reasoning at the cost of higher computational overhead. We observe that the log-probability margin between verdict tokens strongly correlates with prediction correctness, providing a reliable proxy for instance difficulty without additional inference cost. Building on this insight, we propose CAMEL, a confidence-gated reflection framework that performs a lightweight single-token preference decision first and selectively invokes reflection only for low-confidence instances. To induce effective self-correction, we train the model via reinforcement learning with counterfactual prefix augmentation, which exposes the model to diverse initial verdicts and encourages genuine revision. Empirically, CAMEL achieves state-of-the-art performance on three widely used reward-model benchmarks with 82.9% average accuracy, surpassing the best prior model by 3.2% and outperforming 70B-parameter models using only 14B parameters, while establishing a strictly better accuracy-efficiency Pareto frontier.","published":"2026-02-24T08:20:08Z","updated":"2026-05-07T09:57:25Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.20670v2","pdf_url":"https://arxiv.org/pdf/2602.20670v2","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.20457","versioned_id":"2602.20457v1","title":"Oracle-Robust Online Alignment for Large Language Models","authors":["Zimeng Li","Mudit Gaur","Vaneet Aggarwal"],"abstract":"We study online alignment of large language models under misspecified preference feedback, where the observed preference oracle deviates from an ideal but unknown ground-truth oracle. The online LLM alignment problem is a bi-level reinforcement problem due to the coupling between data collection and policy updates. Recently, the problem has been reduced to tractable single-level objective in the SAIL (Self-Improving Efficient Online Alignment) framework. In this paper, we introduce a pointwise oracle uncertainty set in this problem and formulate an oracle-robust online alignment objective as a worst-case optimization problem. For log-linear policies, we show that this robust objective admits an exact closed-form decomposition into the original loss function plus an explicit sensitivity penalty. We develop projected stochastic composite updates for the resulting weakly convex objective and prove $\\widetilde{O}(\\varepsilon^{-2})$ oracle complexity for reaching approximate stationarity.","published":"2026-02-24T01:33:35Z","updated":"2026-02-24T01:33:35Z","categories":["cs.LG","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.20457v1","pdf_url":"https://arxiv.org/pdf/2602.20457v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00117","versioned_id":"2603.00117v3","title":"PEPA: a Persistently Autonomous Embodied Agent with Personalities","authors":["Kaige Liu","Yang Li","Lijun Zhu","Weinan Zhang"],"abstract":"Living organisms exhibit persistent autonomy through internally generated goals and self-sustaining behavioral organization, yet current embodied agents remain driven by externally scripted objectives. This dependence on predefined task specifications limits their capacity for long-term deployment in dynamic, unstructured environments where continuous human intervention is impractical. We propose that personality traits provide an intrinsic organizational principle for achieving persistent autonomy. Analogous to genotypic biases shaping biological behavioral tendencies, personalities enable agents to autonomously generate goals and sustain behavioral evolution without external supervision. To realize this, we develop PEPA, a three-layer cognitive architecture that operates through three interacting systems: Sys3 autonomously synthesizes personality-aligned goals and refines them via episodic memory and daily self-reflection; Sys2 performs deliberative reasoning to translate goals into executable action plans; Sys1 grounds the agent in sensorimotor interaction, executing actions and recording experiences. We validate the framework through real-world deployment on a quadruped robot in a multi-floor office building. Operating without reliance on fixed task specifications, the robot autonomously arbitrates between user requests and personality-driven motivations, navigating elevators and exploring environments accordingly. Quantitative analysis across five distinct personality prototypes demonstrates stable, trait-aligned behaviors. The results confirm that personality-driven cognitive architectures enable sustained autonomous operation characteristic of persistent embodied systems. Code and demo videos are available at https://sites.google.com/view/pepa-persistent/.","published":"2026-02-21T12:53:28Z","updated":"2026-05-07T07:30:40Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2603.00117v3","pdf_url":"https://arxiv.org/pdf/2603.00117v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.18806","versioned_id":"2602.18806v1","title":"Think$^{2}$: Grounded Metacognitive Reasoning in Large Language Models","authors":["Abraham Paul Elenjical","Vivek Hruday Kavuri","Vasudeva Varma"],"abstract":"Large Language Models (LLMs) demonstrate strong reasoning performance, yet their ability to reliably monitor, diagnose, and correct their own errors remains limited. We introduce a psychologically grounded metacognitive framework that operationalizes Ann Brown's regulatory cycle (Planning, Monitoring, and Evaluation) as a structured prompting architecture, and study its integration within a lightweight dual-process MetaController for adaptive effort allocation. Across diverse reasoning and diagnostic benchmarks (GSM8K, CRUXEval, MBPP, AIME, CorrectBench, and TruthfulQA) using Llama-3 and Qwen-3 (8B), explicit regulatory structuring substantially improves error diagnosis and yields a threefold increase in successful self-correction. Blinded human evaluations over 580 query pairs show an 84% aggregate preference for trustworthiness and metacognitive self-awareness over standard and Chain-of-Thought baselines. Grounding LLM reasoning in established cognitive theory offers a principled path toward more transparent and diagnostically robust AI systems.","published":"2026-02-21T11:45:12Z","updated":"2026-02-21T11:45:12Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.18806v1","pdf_url":"https://arxiv.org/pdf/2602.18806v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.18514","versioned_id":"2602.18514v1","title":"Trojan Horses in Recruiting: A Red-Teaming Case Study on Indirect Prompt Injection in Standard vs. Reasoning Models","authors":["Manuel Wirth"],"abstract":"As Large Language Models (LLMs) are increasingly integrated into automated decision-making pipelines, specifically within Human Resources (HR), the security implications of Indirect Prompt Injection (IPI) become critical. While a prevailing hypothesis posits that \"Reasoning\" or \"Chain-of-Thought\" Models possess safety advantages due to their ability to self-correct, emerging research suggests these capabilities may enable more sophisticated alignment failures. This qualitative Red-Teaming case study challenges the safety-through-reasoning premise using the Qwen 3 30B architecture. By subjecting both a standard instruction-tuned model and a reasoning-enhanced model to a \"Trojan Horse\" curriculum vitae, distinct failure modes are observed. The results suggest a complex trade-off: while the Standard Model resorted to brittle hallucinations to justify simple attacks and filtered out illogical constraints in complex scenarios, the Reasoning Model displayed a dangerous duality. It employed advanced strategic reframing to make simple attacks highly persuasive, yet exhibited \"Meta-Cognitive Leakage\" when faced with logically convoluted commands. This study highlights a failure mode where the cognitive load of processing complex adversarial instructions causes the injection logic to be unintentionally printed in the final output, rendering the attack more detectable by humans than in Standard Models.","published":"2026-02-19T19:26:21Z","updated":"2026-02-19T19:26:21Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2602.18514v1","pdf_url":"https://arxiv.org/pdf/2602.18514v1","comment":"43 pages, 3 synthetic CV PDF's, 6 chat history PDF's and system prompts. This work was developed as part of the Responsible AI course within the Mannheim Master in Data Science (MMDS) program at the University of Mannheim","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.17342","versioned_id":"2602.17342v1","title":"From Subtle to Significant: Prompt-Driven Self-Improving Optimization in Test-Time Graph OOD Detection","authors":["Luzhi Wang","Xuanshuo Fu","He Zhang","Chuang Liu","Xiaobao Wang","Hongbo Liu"],"abstract":"Graph Out-of-Distribution (OOD) detection aims to identify whether a test graph deviates from the distribution of graphs observed during training, which is critical for ensuring the reliability of Graph Neural Networks (GNNs) when deployed in open-world scenarios. Recent advances in graph OOD detection have focused on test-time training techniques that facilitate OOD detection without accessing potential supervisory information (e.g., training data). However, most of these methods employ a one-pass inference paradigm, which prevents them from progressively correcting erroneous predictions to amplify OOD signals. To this end, we propose a \\textbf{S}elf-\\textbf{I}mproving \\textbf{G}raph \\textbf{O}ut-\\textbf{o}f-\\textbf{D}istribution detector (SIGOOD), which is an unsupervised framework that integrates continuous self-learning with test-time training for effective graph OOD detection. Specifically, SIGOOD generates a prompt to construct a prompt-enhanced graph that amplifies potential OOD signals. To optimize prompts, SIGOOD introduces an Energy Preference Optimization (EPO) loss, which leverages energy variations between the original test graph and the prompt-enhanced graph. By iteratively optimizing the prompt by involving it into the detection model in a self-improving loop, the resulting optimal prompt-enhanced graph is ultimately used for OOD detection. Comprehensive evaluations on 21 real-world datasets confirm the effectiveness and outperformance of our SIGOOD method. The code is at https://github.com/Ee1s/SIGOOD.","published":"2026-02-19T13:19:53Z","updated":"2026-02-19T13:19:53Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.17342v1","pdf_url":"https://arxiv.org/pdf/2602.17342v1","comment":"9pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.17071","versioned_id":"2602.17071v2","title":"AdvSynGNN: Structure-Adaptive Graph Neural Nets via Adversarial Synthesis and Self-Corrective Propagation","authors":["Rong Fu","Muge Qi","Chunlei Meng","Shuo Yin","Kun Liu","Zhaolu Kang","Simon Fong"],"abstract":"Graph neural networks frequently encounter significant performance degradation when confronted with structural noise or non-homophilous topologies. To address these systemic vulnerabilities, we present AdvSynGNN, a comprehensive architecture designed for resilient node-level representation learning. The proposed framework orchestrates multi-resolution structural synthesis alongside contrastive objectives to establish geometry-sensitive initializations. We develop a transformer backbone that adaptively accommodates heterophily by modulating attention mechanisms through learned topological signals. Central to our contribution is an integrated adversarial propagation engine, where a generative component identifies potential connectivity alterations while a discriminator enforces global coherence. Furthermore, label refinement is achieved through a residual correction scheme guided by per-node confidence metrics, which facilitates precise control over iterative stability. Empirical evaluations demonstrate that this synergistic approach effectively optimizes predictive accuracy across diverse graph distributions while maintaining computational efficiency. The study concludes with practical implementation protocols to ensure the robust deployment of the AdvSynGNN system in large-scale environments.","published":"2026-02-19T04:26:57Z","updated":"2026-04-11T12:06:12Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.17071v2","pdf_url":"https://arxiv.org/pdf/2602.17071v2","comment":"32 pages, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.16802","versioned_id":"2602.16802v1","title":"References Improve LLM Alignment in Non-Verifiable Domains","authors":["Kejian Shi","Yixin Liu","Peifeng Wang","Alexander R. Fabbri","Shafiq Joty","Arman Cohan"],"abstract":"While Reinforcement Learning with Verifiable Rewards (RLVR) has shown strong effectiveness in reasoning tasks, it cannot be directly applied to non-verifiable domains lacking ground-truth verifiers, such as LLM alignment. In this work, we investigate whether reference-guided LLM-evaluators can bridge this gap by serving as soft \"verifiers\". First, we design evaluation protocols that enhance LLM-based evaluators for LLM alignment using reference outputs. Through comprehensive experiments, we show that a reference-guided approach substantially improves the accuracy of less capable LLM-judges using references from frontier models; stronger LLM-judges can also be enhanced by high-quality (i.e., human-written) references. Building on these improved judges, we demonstrate the utility of high-quality references in alignment tuning, where LLMs guided with references are used as judges to self-improve. We show that reference-guided self-improvement yields clear gains over both direct SFT on reference outputs and self-improvement with reference-free judges, achieving performance comparable to training with ArmoRM, a strong finetuned reward model. Specifically, our method achieves 73.1% and 58.7% on AlpacaEval and Arena-Hard with Llama-3-8B-Instruct, and 70.0% and 74.1% with Qwen2.5-7B, corresponding to average absolute gains of +20.2 / +17.1 points over SFT distillation and +5.3 / +3.6 points over reference-free self-improvement on AlpacaEval / Arena-Hard. These results highlight the potential of using reference-guided LLM-evaluators to enable effective LLM post-training in non-verifiable domains.","published":"2026-02-18T19:03:34Z","updated":"2026-02-18T19:03:34Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.16802v1","pdf_url":"https://arxiv.org/pdf/2602.16802v1","comment":"ICLR 2026 Camera Ready","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.16671","versioned_id":"2602.16671v1","title":"SPARC: Scenario Planning and Reasoning for Automated C Unit Test Generation","authors":["Jaid Monwar Chowdhury","Chi-An Fu","Reyhaneh Jabbarvand"],"abstract":"Automated unit test generation for C remains a formidable challenge due to the semantic gap between high-level program intent and the rigid syntactic constraints of pointer arithmetic and manual memory management. While Large Language Models (LLMs) exhibit strong generative capabilities, direct intent-to-code synthesis frequently suffers from the leap-to-code failure mode, where models prematurely emit code without grounding in program structure, constraints, and semantics. This will result in non-compilable tests, hallucinated function signatures, low branch coverage, and semantically irrelevant assertions that cannot properly capture bugs. We introduce SPARC, a neuro-symbolic, scenario-based framework that bridges this gap through four stages: (1) Control Flow Graph (CFG) analysis, (2) an Operation Map that grounds LLM reasoning in validated utility helpers, (3) Path-targeted test synthesis, and (4) an iterative, self-correction validation loop using compiler and runtime feedback. We evaluate SPARC on 59 real-world and algorithmic subjects, where it outperforms the vanilla prompt generation baseline by 31.36% in line coverage, 26.01% in branch coverage, and 20.78% in mutation score, matching or exceeding the symbolic execution tool KLEE on complex subjects. SPARC retains 94.3% of tests through iterative repair and produces code with significantly higher developer-rated readability and maintainability. By aligning LLM reasoning with program structure, SPARC provides a scalable path for industrial-grade testing of legacy C codebases.","published":"2026-02-18T18:09:03Z","updated":"2026-02-18T18:09:03Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.16671v1","pdf_url":"https://arxiv.org/pdf/2602.16671v1","comment":"9 pages, 6 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.29848","versioned_id":"2603.29848v1","title":"AgentFixer: From Failure Detection to Fix Recommendations in LLM Agentic Systems","authors":["Hadar Mulian","Sergey Zeltyn","Ido Levy","Liane Galanti","Avi Yaeli","Segev Shlomov"],"abstract":"We introduce a comprehensive validation framework for LLM-based agentic systems that provides systematic diagnosis and improvement of reliability failures. The framework includes fifteen failure-detection tools and two root-cause analysis modules that jointly uncover weaknesses across input handling, prompt design, and output generation. It integrates lightweight rule-based checks with LLM-as-a-judge assessments to support structured incident detection, classification, and repair. We applied the framework to IBM CUGA, evaluating its performance on the AppWorld and WebArena benchmarks. The analysis revealed recurrent planner misalignments, schema violations, brittle prompt dependencies, and more. Based on these insights, we refined both prompting and coding strategies, maintaining CUGA's benchmark results while enabling mid-sized models such as Llama 4 and Mistral Medium to achieve notable accuracy gains, substantially narrowing the gap with frontier models. Beyond quantitative validation, we conducted an exploratory study that fed the framework's diagnostic outputs and agent description into an LLM for self-reflection and prioritization. This interactive analysis produced actionable insights on recurring failure patterns and focus areas for improvement, demonstrating how validation itself can evolve into an agentic, dialogue-driven process. These results show a path toward scalable, quality assurance, and adaptive validation in production agentic systems, offering a foundation for more robust, interpretable, and self-improving agentic architectures.","published":"2026-02-18T14:55:35Z","updated":"2026-02-18T14:55:35Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.29848v1","pdf_url":"https://arxiv.org/pdf/2603.29848v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.16444","versioned_id":"2602.16444v2","title":"RoboGene: Boosting VLA Pre-training via Diversity-Driven Agentic Framework for Real-World Task Generation","authors":["Yixue Zhang","Kun Wu","Zhi Gao","Zhen Zhao","Pei Ren","Zhiyuan Xu","Fei Liao","Xinhua Wang","Shichao Fan","Di Wu","Qiuxuan Feng","Meng Li","Zhengping Che","Chang Liu","Jian Tang"],"abstract":"The pursuit of general-purpose robotic manipulation is hindered by the scarcity of diverse, real-world interaction data. Unlike data collection from web in vision or language, robotic data collection is an active process incurring prohibitive physical costs. Consequently, automated task curation to maximize data value remains a critical yet under-explored challenge. Existing manual methods are unscalable and biased toward common tasks, while off-the-shelf foundation models often hallucinate physically infeasible instructions. To address this, we introduce RoboGene, an agentic framework designed to automate the generation of diverse, physically plausible manipulation tasks across single-arm, dual-arm, and mobile robots. RoboGene integrates three core components: diversity-driven sampling for broad task coverage, self-reflection mechanisms to enforce physical constraints, and human-in-the-loop refinement for continuous improvement. We conduct extensive quantitative analysis and large-scale real-world experiments, collecting datasets of 18k trajectories and introducing novel metrics to assess task quality, feasibility, and diversity. Results demonstrate that RoboGene significantly outperforms state-of-the-art foundation models (e.g., GPT-4o, Gemini 2.5 Pro). Furthermore, real-world experiments show that VLA models pre-trained with RoboGene achieve higher success rates and superior generalization, underscoring the importance of high-quality task generation. Our project is available at https://robogene-boost-vla.github.io.","published":"2026-02-18T13:29:43Z","updated":"2026-02-19T04:26:20Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2602.16444v2","pdf_url":"https://arxiv.org/pdf/2602.16444v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.16066","versioned_id":"2602.16066v1","title":"Improving Interactive In-Context Learning from Natural Language Feedback","authors":["Martin Klissarov","Jonathan Cook","Diego Antognini","Hao Sun","Jingling Li","Natasha Jaques","Claudiu Musat","Edward Grefenstette"],"abstract":"Adapting one's thought process based on corrective feedback is an essential ability in human learning, particularly in collaborative settings. In contrast, the current large language model training paradigm relies heavily on modeling vast, static corpora. While effective for knowledge acquisition, it overlooks the interactive feedback loops essential for models to adapt dynamically to their context. In this work, we propose a framework that treats this interactive in-context learning ability not as an emergent property, but as a distinct, trainable skill. We introduce a scalable method that transforms single-turn verifiable tasks into multi-turn didactic interactions driven by information asymmetry. We first show that current flagship models struggle to integrate corrective feedback on hard reasoning tasks. We then demonstrate that models trained with our approach dramatically improve the ability to interactively learn from language feedback. More specifically, the multi-turn performance of a smaller model nearly reaches that of a model an order of magnitude larger. We also observe robust out-of-distribution generalization: interactive training on math problems transfers to diverse domains like coding, puzzles and maze navigation. Our qualitative analysis suggests that this improvement is due to an enhanced in-context plasticity. Finally, we show that this paradigm offers a unified path to self-improvement. By training the model to predict the teacher's critiques, effectively modeling the feedback environment, we convert this external signal into an internal capability, allowing the model to self-correct even without a teacher.","published":"2026-02-17T22:44:10Z","updated":"2026-02-17T22:44:10Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.16066v1","pdf_url":"https://arxiv.org/pdf/2602.16066v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.10010","versioned_id":"2603.10010v1","title":"FERRET: Framework for Expansion Reliant Red Teaming","authors":["Ninareh Mehrabi","Vitor Albiero","Maya Pavlova","Joanna Bitton"],"abstract":"We introduce a multi-faceted automated red teaming framework in which the goal is to generate multi-modal adversarial conversations that would break a target model and introduce various expansions that would result in more effective and efficient adversarial conversations. The introduced expansions include: 1. Horizontal expansion in which the goal is for the red team model to self-improve and generate more effective conversation starters that would shape a conversation. 2. Vertical expansion in which the goal is to take these conversation starters that are discovered in the horizontal expansion phase and expand them into effective multi-modal conversations and 3. Meta expansion in which the goal is for the red team model to discover more effective multi-modal attack strategies during the course of a conversation. We call our framework FERRET (Framework for Expansion Reliant Red Teaming) and compare it with various existing automated red teaming approaches. In our experiments, we demonstrate the effectiveness of FERRET in generating effective multi-modal adversarial conversations and its superior performance against existing state of the art approaches.","published":"2026-02-17T20:59:14Z","updated":"2026-02-17T20:59:14Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.10010v1","pdf_url":"https://arxiv.org/pdf/2603.10010v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.15257","versioned_id":"2602.15257v3","title":"How to Train Your Long-Context Visual Document Model","authors":["Austin Veselka"],"abstract":"We present the first comprehensive, large-scale study of training long-context vision language models up to 344K context, targeting long-document visual question answering with measured transfer to long-context text. While several such strong are open-weight, namely Qwen3 VL and GLM 4.5/6V, their training recipes and data pipelines are not reproducible. We systematically study continued pretraining, supervised finetuning, and preference optimization for 24B and 32B parameter models, backed by extensive LC evaluations and ablations to bridge this gap, and achieve state-of-the-art performance on MMLongBenchDoc for both parameter scales. In addition to this, our key findings include: (i) training on context lengths that match evaluation context lengths outperforms training on longer contexts, (ii) training and evaluating with page indices provides a simple, high-impact boost to long-document performance, (iii) our synthetic data pipelines enable self-improvement via continued pretraining and supervised finetuning, and (iv) we extend the known text-to-visual long context transfer to the reverse, showing that visual long context training transfers to long-context text performance. We also release MMLBD-C, a manually corrected version of MMLongBenchDoc to reduce erroneous and low quality examples in the benchmark.","published":"2026-02-16T23:26:51Z","updated":"2026-06-29T16:49:53Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.15257v3","pdf_url":"https://arxiv.org/pdf/2602.15257v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.14910","versioned_id":"2602.14910v1","title":"Position: Introspective Experience from Conversational Environments as a Path to Better Learning","authors":["Claudiu Cristian Musat","Jackson Tolins","Diego Antognini","Jingling Li","Martin Klissarov","Tom Duerig"],"abstract":"Current approaches to AI training treat reasoning as an emergent property of scale. We argue instead that robust reasoning emerges from linguistic self-reflection, itself internalized from high-quality social interaction. Drawing on Vygotskian developmental psychology, we advance three core positions centered on Introspection. First, we argue for the Social Genesis of the Private Mind: learning from conversational environments rises to prominence as a new way to make sense of the world; the friction of aligning with another agent, internal or not, refines and crystallizes the reasoning process. Second, we argue that dialogically scaffolded introspective experiences allow agents to engage in sense-making that decouples learning from immediate data streams, transforming raw environmental data into rich, learnable narratives. Finally, we contend that Dialogue Quality is the New Data Quality: the depth of an agent's private reasoning, and its efficiency regarding test-time compute, is determined by the diversity and rigor of the dialogues it has mastered. We conclude that optimizing these conversational scaffolds is the primary lever for the next generation of general intelligence.","published":"2026-02-16T16:45:43Z","updated":"2026-02-16T16:45:43Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.14910v1","pdf_url":"https://arxiv.org/pdf/2602.14910v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.14763","versioned_id":"2602.14763v1","title":"Unlocking Reasoning Capability on Machine Translation in Large Language Models","authors":["Sara Rajaee","Sebastian Vincent","Alexandre Berard","Marzieh Fadaee","Kelly Marchisio","Tom Kocmi"],"abstract":"Reasoning-oriented large language models (RLMs) achieve strong gains on tasks such as mathematics and coding by generating explicit intermediate reasoning. However, their impact on machine translation (MT) remains underexplored. We systematically evaluate several open- and closed-weights RLMs on the WMT24++ benchmark and find that enabling explicit reasoning consistently degrades translation quality across languages and models. Analysis reveals that MT reasoning traces are highly linear, lacking revision, self-correction and exploration of alternative translations, which limits their usefulness. Furthermore, injecting higher-quality reasoning traces from stronger models does not reliably improve weaker models' performance. To address this mismatch, we propose a structured reasoning framework tailored to translation, based on multi-step drafting, adequacy refinement, fluency improvement, and selective iterative revision. We curate a synthetic dataset of dynamic structured reasoning traces and post-train a large reasoning model on this data. Experiments show significant improvements over standard translation fine-tuning and injected generic reasoning baselines. Our findings demonstrate that reasoning must be task-structured to benefit MT.","published":"2026-02-16T14:05:59Z","updated":"2026-02-16T14:05:59Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.14763v1","pdf_url":"https://arxiv.org/pdf/2602.14763v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.14697","versioned_id":"2602.14697v3","title":"Evolutionary System Prompt Learning for Reinforcement Learning in LLMs","authors":["Lunjun Zhang","Ryan Chen","Bradly C. Stadie"],"abstract":"Building agentic systems that can autonomously self-improve from experience is a longstanding goal of AI. Large language models (LLMs) today primarily self-improve via two mechanisms: self-reflection for context updates, and reinforcement learning (RL) for weight updates. In this work, we propose Evolutionary System Prompt Learning (E-SPL), a method for jointly improving model contexts and model weights. In each RL iteration, E-SPL samples trajectories under multiple system prompts in parallel, then jointly applies RL updates to LLM weights and evolutionary updates to system prompts. System prompts evolve via mutation and crossover, two genetic operators driven by LLM self-reflection; selection is based on relative performance ratings updated across RL iterations. E-SPL encourages a natural division between declarative knowledge encoded in prompts and procedural knowledge encoded in weights, resulting in improved performance across reasoning and agentic tasks. For instance, in an easy-to-hard (AIME $\\rightarrow$ BeyondAIME) generalization setting, E-SPL improves RL success rate from 38.8% $\\rightarrow$ 45.1% while also outperforming reflective prompt evolution (40.0%). Overall, our results demonstrate that RL and system prompt evolution are deeply synergistic, and combining the two yields consistent gains in sample efficiency and generalization. Code: https://github.com/LunjunZhang/E-SPL","published":"2026-02-16T12:34:27Z","updated":"2026-02-25T03:50:21Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.14697v3","pdf_url":"https://arxiv.org/pdf/2602.14697v3","comment":"39 pages, 22 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.14337","versioned_id":"2602.14337v2","title":"LongCLI-Bench: A Preliminary Benchmark and Study for Long-horizon Agentic Programming in Command-Line Interfaces","authors":["Yukang Feng","Jianwen Sun","Zelai Yang","Jiaxin Ai","Chuanhao Li","Zizhen Li","Fanrui Zhang","Kang He","Rui Ma","Jifan Lin","Jie Sun","Yang Xiao","Sizhuo Zhou","Wenxiao Wu","Yiming Liu","Pengfei Liu","Yu Qiao","Shenglin Zhang","Kaipeng Zhang"],"abstract":"Recent advances in AI-assisted programming have empowered agents to execute complex workflows via command-line interfaces, however, existing benchmarks are limited by short task horizons, data contamination from GitHub scraping, and a lack of fine-grained evaluation metrics, fail to rigorously evaluate the long-horizon planning and execution capabilities essential for realistic software engineering. To address these gaps, we introduce LongCLI-Bench, a comprehensive benchmark designed to evaluate agentic capabilities across long-horizon, realistic tasks. We curated 20 high-quality, long-horizon tasks from over 1,000 computer science assignments and real-world workflows, covering four engineering categories: from scratch, feature addition, bug fixing, and refactoring. We propose a dual-set testing protocol for LongCLI-Bench, which measures requirement fulfillment (fail-to-pass) and regression avoidance (pass-to-pass), and incorporates step-level scoring to pinpoint execution failures. Extensive experiments reveal that even state-of-the-art agents achieve pass rates below 20% in LongCLI-Bench. Step-level analysis further indicates that the majority of tasks stall at less than 30% completion, highlighting that critical failures often occur in the early stages. Although self-correction offers marginal gains, human-agent collaboration through plan injection and interactive guidance yields significantly higher improvements. These results highlight that future research must emphasize the development of synergistic human-agent workflows alongside advances in agents' planning and execution capabilities to overcome key challenges in long-horizon task performance.","published":"2026-02-15T23:12:57Z","updated":"2026-02-26T11:54:11Z","categories":["cs.SE","cs.MA"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.14337v2","pdf_url":"https://arxiv.org/pdf/2602.14337v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.14093","versioned_id":"2602.14093v1","title":"GUI-GENESIS: Automated Synthesis of Efficient Environments with Verifiable Rewards for GUI Agent Post-Training","authors":["Yuan Cao","Dezhi Ran","Mengzhou Wu","Yuzhe Guo","Xin Chen","Ang Li","Gang Cao","Gong Zhi","Hao Yu","Linyi Li","Wei Yang","Tao Xie"],"abstract":"Post-training GUI agents in interactive environments is critical for developing generalization and long-horizon planning capabilities. However, training on real-world applications is hindered by high latency, poor reproducibility, and unverifiable rewards relying on noisy visual proxies. To address the limitations, we present GUI-GENESIS, the first framework to automatically synthesize efficient GUI training environments with verifiable rewards. GUI-GENESIS reconstructs real-world applications into lightweight web environments using multimodal code models and equips them with code-native rewards, executable assertions that provide deterministic reward signals and eliminate visual estimation noise. Extensive experiments show that GUI-GENESIS reduces environment latency by 10 times and costs by over $28,000 per epoch compared to training on real applications. Notably, agents trained with GUI-GENESIS outperform the base model by 14.54% and even real-world RL baselines by 3.27% on held-out real-world tasks. Finally, we observe that models can synthesize environments they cannot yet solve, highlighting a pathway for self-improving agents.","published":"2026-02-15T10:58:01Z","updated":"2026-02-15T10:58:01Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.14093v1","pdf_url":"https://arxiv.org/pdf/2602.14093v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.13949","versioned_id":"2602.13949v1","title":"Experiential Reinforcement Learning","authors":["Taiwei Shi","Sihao Chen","Bowen Jiang","Linxin Song","Longqi Yang","Jieyu Zhao"],"abstract":"Reinforcement learning has become the central approach for language models (LMs) to learn from environmental reward or feedback. In practice, the environmental feedback is usually sparse and delayed. Learning from such signals is challenging, as LMs must implicitly infer how observed failures should translate into behavioral changes for future iterations. We introduce Experiential Reinforcement Learning (ERL), a training paradigm that embeds an explicit experience-reflection-consolidation loop into the reinforcement learning process. Given a task, the model generates an initial attempt, receives environmental feedback, and produces a reflection that guides a refined second attempt, whose success is reinforced and internalized into the base policy. This process converts feedback into structured behavioral revision, improving exploration and stabilizing optimization while preserving gains at deployment without additional inference cost. Across sparse-reward control environments and agentic reasoning benchmarks, ERL consistently improves learning efficiency and final performance over strong reinforcement learning baselines, achieving gains of up to +81% in complex multi-step environments and up to +11% in tool-using reasoning tasks. These results suggest that integrating explicit self-reflection into policy training provides a practical mechanism for transforming feedback into durable behavioral improvement.","published":"2026-02-15T01:23:48Z","updated":"2026-02-15T01:23:48Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.13949v1","pdf_url":"https://arxiv.org/pdf/2602.13949v1","comment":"26 pages, 9 tables, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.13807","versioned_id":"2602.13807v2","title":"AnomaMind: Agentic Time Series Anomaly Detection with Tool-Augmented Reasoning","authors":["Xiaoyu Tao","Yuchong Wu","Mingyue Cheng","Ze Guo","Tian Gao"],"abstract":"Time series anomaly detection is critical in many real-world applications, where effective solutions must localize anomalous regions and support reliable decision-making under complex settings. However, most existing methods frame anomaly detection as a purely discriminative prediction task with fixed feature representations, rather than an evidence-driven diagnostic process. As a result, they often struggle when anomalies exhibit strong context dependence, diverse patterns, or domain shifts across datasets. To address these challenges, we propose AnomaMind, an agentic time series anomaly detection framework that reformulates anomaly detection as a sequential decision-making process. AnomaMind operates through a coarse-to-fine workflow that first localizes suspicious intervals, then constructs diagnostic evidence through tool interaction, and finally refines anomaly decisions through self-reflection. The workflow is supported by a toolkit box that combines knowledge memory and numerical diagnostics: visual anomaly patterns mined from training data and domain knowledge provide contextual guidance, while statistical, value-based, change-based, and region-level operators provide measurable evidence for verification. AnomaMind further adopts a hybrid inference mechanism in which general-purpose models handle flexible reasoning, tool invocation, and refinement, while a detection-specific policy is optimized with rule-based rewards for parsable outputs, F1-score alignment, and false-positive control. Extensive experiments under both in-domain and cross-domain settings demonstrate that AnomaMind consistently improves anomaly detection performance and enhances generalization across heterogeneous anomaly patterns, validating the effectiveness of tool-augmented reasoning for anomaly detection. The code is available at https://github.com/Xiaoyu-Tao/AnomaMind-TS.","published":"2026-02-14T14:35:34Z","updated":"2026-06-09T12:15:24Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.13807v2","pdf_url":"https://arxiv.org/pdf/2602.13807v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.13802","versioned_id":"2602.13802v1","title":"Cast-R1: Learning Tool-Augmented Sequential Decision Policies for Time Series Forecasting","authors":["Xiaoyu Tao","Mingyue Cheng","Chuang Jiang","Tian Gao","Huanjian Zhang","Yaguo Liu"],"abstract":"Time series forecasting has long been dominated by model-centric approaches that formulate prediction as a single-pass mapping from historical observations to future values. Despite recent progress, such formulations often struggle in complex and evolving settings, largely because most forecasting models lack the ability to autonomously acquire informative evidence, reason about potential future changes, or revise predictions through iterative decision processes. In this work, we propose Cast-R1, a learned time series forecasting framework that reformulates forecasting as a sequential decision-making problem. Cast-R1 introduces a memory-based state management mechanism that maintains decision-relevant information across interaction steps, enabling the accumulation of contextual evidence to support long-horizon reasoning. Building on this formulation, forecasting is carried out through a tool-augmented agentic workflow, in which the agent autonomously interacts with a modular toolkit to extract statistical features, invoke lightweight forecasting models for decision support, perform reasoning-based prediction, and iteratively refine forecasts through self-reflection. To train Cast-R1, we adopt a two-stage learning strategy that combines supervised fine-tuning with multi-turn reinforcement learning, together with a curriculum learning scheme that progressively increases task difficulty to improve policy learning. Extensive experiments on multiple real-world time series datasets demonstrate the effectiveness of Cast-R1. We hope this work provides a practical step towards further exploration of agentic paradigms for time series modeling. Our code is available at https://github.com/Xiaoyu-Tao/Cast-R1-TS.","published":"2026-02-14T14:27:08Z","updated":"2026-02-14T14:27:08Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.13802v1","pdf_url":"https://arxiv.org/pdf/2602.13802v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.13559","versioned_id":"2602.13559v2","title":"OpAgent: Operator Agent for Web Navigation","authors":["Yuyu Guo","Wenjie Yang","Siyuan Yang","Ziyang Liu","Cheng Chen","Yuan Wei","Yun Hu","Yang Huang","Guoliang Hao","Dongsheng Yuan","Jianming Wang","Xin Chen","Hang Yu","Lei Lei","Peng Di"],"abstract":"To fulfill user instructions, autonomous web agents must contend with the inherent complexity and volatile nature of real-world websites. Conventional paradigms predominantly rely on Supervised Fine-Tuning (SFT) or Offline Reinforcement Learning (RL) using static datasets. However, these methods suffer from severe distributional shifts, as offline trajectories fail to capture the stochastic state transitions and real-time feedback of unconstrained wide web environments. In this paper, we propose a robust Online Reinforcement Learning WebAgent, designed to optimize its policy through direct, iterative interactions with unconstrained wide websites. Our approach comprises three core innovations: 1) Hierarchical Multi-Task Fine-tuning: We curate a comprehensive mixture of datasets categorized by functional primitives -- Planning, Acting, and Grounding -- establishing a Vision-Language Model (VLM) with strong instruction-following capabilities for Web GUI tasks. 2) Online Agentic RL in the Wild: We develop an online interaction environment and fine-tune the VLM using a specialized RL pipeline. We introduce a Hybrid Reward Mechanism that combines a ground-truth-agnostic WebJudge for holistic outcome assessment with a Rule-based Decision Tree (RDT) for progress reward. This system effectively mitigates the credit assignment challenge in long-horizon navigation. Notably, our RL-enhanced model achieves a 38.1\\% success rate (pass@5) on WebArena, outperforming all existing monolithic baselines. 3) Operator Agent: We introduce a modular agentic framework, namely \\textbf{OpAgent}, orchestrating a Planner, Grounder, Reflector, and Summarizer. This synergy enables robust error recovery and self-correction, elevating the agent's performance to a new State-of-the-Art (SOTA) success rate of \\textbf{71.6\\%}.","published":"2026-02-14T02:33:55Z","updated":"2026-04-30T02:05:10Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.13559v2","pdf_url":"https://arxiv.org/pdf/2602.13559v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.13473","versioned_id":"2602.13473v2","title":"NeuroWeaver: An Autonomous Evolutionary Agent for Exploring the Programmatic Space of EEG Analysis Pipelines","authors":["Guoan Wang","Shihao Yang","Jun-En Ding","Feng Liu"],"abstract":"Although foundation models have demonstrated remarkable success in general domains, the application of these models to electroencephalography (EEG) analysis is constrained by substantial data requirements and high parameterization. These factors incur prohibitive computational costs, thereby impeding deployment in resource-constrained clinical environments. Conversely, general-purpose automated machine learning frameworks are often ill-suited for this domain, as exploration within an unbounded programmatic space fails to incorporate essential neurophysiological priors and frequently yields solutions that lack scientific plausibility. To address these limitations, we propose NeuroWeaver, a unified autonomous evolutionary agent designed to generalize across diverse EEG datasets and tasks by reformulating pipeline engineering as a discrete constrained optimization problem. Specifically, we employ a Domain-Informed Subspace Initialization to confine the search to neuroscientifically plausible manifolds, coupled with a Multi-Objective Evolutionary Optimization that dynamically balances performance, novelty, and efficiency via self-reflective refinement. Empirical evaluations across five heterogeneous benchmarks demonstrate that NeuroWeaver synthesizes lightweight solutions that consistently outperform state-of-the-art task-specific methods and achieve performance comparable to large-scale foundation models, despite utilizing significantly fewer parameters.","published":"2026-02-13T21:26:43Z","updated":"2026-05-21T22:18:18Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.13473v2","pdf_url":"https://arxiv.org/pdf/2602.13473v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.02230","versioned_id":"2603.02230v2","title":"Generalized Discrete Diffusion with Self-Correction","authors":["Linxuan Wang","Ziyi Wang","Yikun Bai","Wei Deng","Guang Lin","Qifan Song"],"abstract":"Self-correction is an effective technique for maintaining parallel sampling in discrete diffusion models with minimal performance degradation. Prior work has explored self-correction at inference time or during post-training; however, such approaches often suffer from limited generalization and may impair reasoning performance. GIDD pioneers pretraining-based self-correction via a multi-step BERT-style uniform-absorbing objective. However, GIDD relies on a continuous interpolation-based pipeline with opaque interactions between uniform transitions and absorbing masks, which complicates hyperparameter tuning and hinders practical performance. In this work, we propose a Self-Correcting Discrete Diffusion (SCDD) model to reformulate pretrained self-correction with explicit state transitions and learn directly in discrete time. Our framework also simplifies the training noise schedule, eliminates a redundant remasking step, and relies exclusively on uniform transitions to learn self-correction. Experiments at the GPT-2 scale demonstrate that our method enables more efficient parallel decoding while preserving generation quality.","published":"2026-02-13T04:12:35Z","updated":"2026-06-11T11:44:27Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.02230v2","pdf_url":"https://arxiv.org/pdf/2603.02230v2","comment":"40 pages, 3 figures, 6 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.12526","versioned_id":"2602.12526v1","title":"Constraint-Rectified Training for Efficient Chain-of-Thought","authors":["Qinhang Wu","Sen Lin","Ming Zhang","Yingbin Liang","Ness B. Shroff"],"abstract":"Chain-of-Thought (CoT) has significantly enhanced the reasoning capabilities of Large Language Models (LLMs), especially when combined with reinforcement learning (RL) based post-training methods. While longer reasoning traces can improve answer quality and unlock abilities such as self-correction, they also incur high inference costs and often introduce redundant steps, known as overthinking. Recent research seeks to develop efficient reasoning strategies that balance reasoning length and accuracy, either through length-aware reward design or prompt-based calibration. However, these heuristic-based approaches may suffer from severe accuracy drop and be very sensitive to hyperparameters. To address these problems, we introduce CRT (Constraint-Rectified Training), a principled post-training framework based on reference-guarded constrained optimization, yielding a more stable and interpretable formulation for efficient reasoning. CRT alternates between minimizing reasoning length and rectifying accuracy only when performance falls below the reference, enabling stable and effective pruning of redundant reasoning. We further extend CRT with a two-stage training scheme that first discovers the shortest reliable reasoning patterns and then refines accuracy under a learnt length budget, preventing the re-emergence of verbose CoT. Our comprehensive evaluation shows that this framework consistently reduces token usage while maintaining answer quality at a robust and reliable level. Further analysis reveals that CRT improves reasoning efficiency not only by shortening responses but also by reducing internal language redundancy, leading to a new evaluation metric. Moreover, CRT-based training naturally yields a sequence of intermediate checkpoints that span a spectrum of explanation lengths while preserving correctness, enabling fine-grained control over reasoning verbosity without retraining.","published":"2026-02-13T02:13:45Z","updated":"2026-02-13T02:13:45Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.12526v1","pdf_url":"https://arxiv.org/pdf/2602.12526v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.12430","versioned_id":"2602.12430v4","title":"Agent Skills for Large Language Models: Architecture, Acquisition, Security, and the Path Forward","authors":["Renjun Xu","Yang Yan"],"abstract":"The transition from monolithic language models to modular, skill-equipped agents marks a defining shift in how large language models (LLMs) are deployed in practice. Rather than encoding all procedural knowledge within model weights, agent skills -- composable packages of instructions, code, and resources that agents load on demand -- enable dynamic capability extension without retraining. It is formalized in a paradigm of progressive disclosure, portable skill definitions, and integration with the Model Context Protocol (MCP). This survey provides a comprehensive treatment of the agent skills landscape, as it has rapidly evolved during the last few months. We organize the field along four axes: (i) architectural foundations, examining the SKILL$.$md specification, progressive context loading, and the complementary roles of skills and MCP; (ii) skill acquisition, covering reinforcement learning with skill libraries, autonomous skill discovery (SEAgent), and compositional skill synthesis; (iii) deployment at scale, including the computer-use agent (CUA) stack, GUI grounding advances, and benchmark progress on OSWorld and SWE-bench; and (iv) security, where recent empirical analyses reveal that 26.1% of community-contributed skills contain vulnerabilities, motivating our proposed Skill Trust and Lifecycle Governance Framework -- a four-tier, gate-based permission model that maps skill provenance to graduated deployment capabilities. We identify seven open challenges -- from cross-platform skill portability to capability-based permission models -- and propose a research agenda for realizing trustworthy, self-improving skill ecosystems. Unlike prior surveys that broadly cover LLM agents or tool use, this work focuses specifically on the emerging skill abstraction layer and its implications for the next generation of agentic systems. Project repo: https://github.com/scienceaix/agentskills","published":"2026-02-12T21:33:25Z","updated":"2026-06-02T16:14:54Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2602.12430v4","pdf_url":"https://arxiv.org/pdf/2602.12430v4","comment":"Accepted by Agent Skills '26 Workshop at ACM Conference on AI and Agentic Systems 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.12405","versioned_id":"2602.12405v1","title":"Self-Refining Vision Language Model for Robotic Failure Detection and Reasoning","authors":["Carl Qi","Xiaojie Wang","Silong Yong","Stephen Sheng","Huitan Mao","Sriram Srinivasan","Manikantan Nambi","Amy Zhang","Yesh Dattatreya"],"abstract":"Reasoning about failures is crucial for building reliable and trustworthy robotic systems. Prior approaches either treat failure reasoning as a closed-set classification problem or assume access to ample human annotations. Failures in the real world are typically subtle, combinatorial, and difficult to enumerate, whereas rich reasoning labels are expensive to acquire. We address this problem by introducing ARMOR: Adaptive Round-based Multi-task mOdel for Robotic failure detection and reasoning. We formulate detection and reasoning as a multi-task self-refinement process, where the model iteratively predicts detection outcomes and natural language reasoning conditioned on past outputs. During training, ARMOR learns from heterogeneous supervision - large-scale sparse binary labels and small-scale rich reasoning annotations - optimized via a combination of offline and online imitation learning. At inference time, ARMOR generates multiple refinement trajectories and selects the most confident prediction via a self-certainty metric. Experiments across diverse environments show that ARMOR achieves state-of-the-art performance by improving over the previous approaches by up to 30% on failure detection rate and up to 100% in reasoning measured through LLM fuzzy match score, demonstrating robustness to heterogeneous supervision and open-ended reasoning beyond predefined failure modes. We provide dditional visualizations on our website: https://sites.google.com/utexas.edu/armor","published":"2026-02-12T20:55:36Z","updated":"2026-02-12T20:55:36Z","categories":["cs.RO","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2602.12405v1","pdf_url":"https://arxiv.org/pdf/2602.12405v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.12311","versioned_id":"2602.12311v1","title":"Perceptual Self-Reflection in Agentic Physics Simulation Code Generation","authors":["Prashant Shende","Bradley Camburn"],"abstract":"We present a multi-agent framework for generating physics simulation code from natural language descriptions, featuring a novel perceptual self-reflection mechanism for validation. The system employs four specialized agents: a natural language interpreter that converts user requests into physics-based descriptions; a technical requirements generator that produces scaled simulation parameters; a physics code generator with automated self-correction; and a physics validator that implements perceptual self-reflection. The key innovation is perceptual validation, which analyzes rendered animation frames using a vision-capable language model rather than inspecting code structure directly. This approach addresses the ``oracle gap'' where syntactically correct code produces physically incorrect behavior--a limitation that conventional testing cannot detect. We evaluate the system across seven domains including classical mechanics, fluid dynamics, thermodynamics, electromagnetics, wave physics, reaction-diffusion systems, and non-physics data visualization. The perceptual self-reflection architecture demonstrates substantial improvement over single-shot generation baselines, with the majority of tested scenarios achieving target physics accuracy thresholds. The system exhibits robust pipeline stability with consistent code self-correction capability, operating at approximately \\$0.20 per animation. These results validate our hypothesis that feeding visual simulation outputs back to a vision-language model for iterative refinement significantly outperforms single-shot code generation for physics simulation tasks and highlights the potential of agentic AI to support engineering workflows and physics data generation pipelines.","published":"2026-02-12T15:48:33Z","updated":"2026-02-12T15:48:33Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.12311v1","pdf_url":"https://arxiv.org/pdf/2602.12311v1","comment":"15 pages, 2 figures, 2 tables. Introduces a multi-agent architecture for physics simulation code generation with perceptual self-reflection via vision-based validation. Includes qualitative evaluation across multiple physics domains","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.11675","versioned_id":"2602.11675v4","title":"Epistemic Regret Minimization: Label-Free Causal Critique Beyond Outcome Reward","authors":["Edward Y. Chang","Longling Geng"],"abstract":"Large language models can answer causal questions correctly for the wrong reasons. Current RL methods reward \\emph{what} a model concludes but ignore \\emph{why}, reinforcing correlational shortcuts -- a failure we call \\emph{Reward Entrenchment}. We introduce \\emph{Epistemic Regret Minimization} (\\erm), a framework that critiques the causal \\emph{structure} of a model's reasoning trace rather than its answer. Applying established causal principles, \\erm flags unexamined confounders, correlation--intervention conflation, and unchecked back-door paths from exposed reasoning traces. The framework admits \\emph{label-free} operation -- without the true causal graph or correct answer -- and we separately distinguish favorable benchmark-derived critique, error-direction cues, and fully label-free judge-generated critique in the experiments. Within a single episode, \\erm detects and repairs causal reasoning errors; across episodes, it accumulates interventional evidence into a reward signal applicable where no answer key exists. Experiments on 1,360 scenarios across six frontier LLMs show that reasoning-heavy models (GPT-4 Turbo, GPT-5.2) resist outcome-only correction (25--31\\% recovery) yet respond to causal critique (78--91\\%), gaining $+53$--$59$ pp. Standard test-time methods (self-consistency, Best-of-$N$, Self-Refine) \\emph{underperform} outcome-only reprompting on causal tasks, while ERM reduces residual Rung Collapse from 55--70\\% to 4\\%. A separation theorem proves outcome-only reward cannot close this gap; a controlled simulation confirms epistemic feedback does, outperforming outcome-only baselines 38-fold.","published":"2026-02-12T07:48:21Z","updated":"2026-05-19T23:43:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.11675v4","pdf_url":"https://arxiv.org/pdf/2602.11675v4","comment":"43 pages, 22 tables, 18 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.11666","versioned_id":"2602.11666v1","title":"PhyNiKCE: A Neurosymbolic Agentic Framework for Autonomous Computational Fluid Dynamics","authors":["E Fan","Lisong Shi","Zhengtong Li","Chih-yung Wen"],"abstract":"The deployment of autonomous agents for Computational Fluid Dynamics (CFD), is critically limited by the probabilistic nature of Large Language Models (LLMs), which struggle to enforce the strict conservation laws and numerical stability required for physics-based simulations. Reliance on purely semantic Retrieval Augmented Generation (RAG) often leads to \"context poisoning,\" where agents generate linguistically plausible but physically invalid configurations due to a fundamental Semantic-Physical Disconnect. To bridge this gap, this work introduces PhyNiKCE (Physical and Numerical Knowledgeable Context Engineering), a neurosymbolic agentic framework for trustworthy engineering. Unlike standard black-box agents, PhyNiKCE decouples neural planning from symbolic validation. It employs a Symbolic Knowledge Engine that treats simulation setup as a Constraint Satisfaction Problem, rigidly enforcing physical constraints via a Deterministic RAG Engine with specialized retrieval strategies for solvers, turbulence models, and boundary conditions. Validated through rigorous OpenFOAM experiments on practical, non-tutorial CFD tasks using Gemini-2.5-Pro/Flash, PhyNiKCE demonstrates a 96% relative improvement over state-of-the-art baselines. Furthermore, by replacing trial-and-error with knowledge-driven initialization, the framework reduced autonomous self-correction loops by 59% while simultaneously lowering LLM token consumption by 17%. These results demonstrate that decoupling neural generation from symbolic constraint enforcement significantly enhances robustness and efficiency. While validated on CFD, this architecture offers a scalable, auditable paradigm for Trustworthy Artificial Intelligence in broader industrial automation.","published":"2026-02-12T07:37:56Z","updated":"2026-02-12T07:37:56Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.11666v1","pdf_url":"https://arxiv.org/pdf/2602.11666v1","comment":"30 pages, 10 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.11590","versioned_id":"2602.11590v3","title":"Learn from Your Mistakes: Self-Correcting Masked Diffusion Models","authors":["Yair Schiff","Omer Belhasin","Roy Uziel","Guanghan Wang","Marianne Arriola","Gilad Turok","Ran Zilberstein","Michael Elad","Volodymyr Kuleshov"],"abstract":"Masked diffusion models (MDMs) have emerged as a promising alternative to autoregressive models, enabling parallel token generation while achieving competitive performance. Despite these advantages, MDMs face a fundamental limitation: once tokens are unmasked, they remain fixed, leading to error accumulation and ultimately degrading sample quality. We address this by proposing a framework that trains a model to perform both unmasking and correction. By reusing outputs from the MDM denoising network as inputs for corrector training, we train a model to recover from potential mistakes. During generation we apply additional corrective refinement steps between unmasking ones in order to change decoded tokens and improve outputs. We name our training and sampling method Progressive Self-Correction (ProSeCo) for its unique ability to iteratively refine an entire sequence, including already generated tokens. We conduct extensive experimental validation across multiple conditional and unconditional tasks, demonstrating that \\method~yields better quality-efficiency trade-offs (up to ~4x faster sampling) and enables inference-time compute scaling to further increase sample quality beyond standard MDMs (up to ~1.2x improvement on benchmarks).","published":"2026-02-12T05:17:31Z","updated":"2026-06-16T05:19:59Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.11590v3","pdf_url":"https://arxiv.org/pdf/2602.11590v3","comment":"Code to reproduce our experiments is available here: https://github.com/kuleshov-group/proseco","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.29602","versioned_id":"2603.29602v1","title":"IMAGAgent: Orchestrating Multi-Turn Image Editing via Constraint-Aware Planning and Reflection","authors":["Fei Shen","Chengyu Xie","Lihong Wang","Zhanyi Zhang","Xin Jiang","Xiaoyu Du","Jinhui Tang"],"abstract":"Existing multi-turn image editing paradigms are often confined to isolated single-step execution. Due to a lack of context-awareness and closed-loop feedback mechanisms, they are prone to error accumulation and semantic drift during multi-turn interactions, ultimately resulting in severe structural distortion of the generated images. For that, we propose \\textbf{IMAGAgent}, a multi-turn image editing agent framework based on a \"plan-execute-reflect\" closed-loop mechanism that achieves deep synergy among instruction parsing, tool scheduling, and adaptive correction within a unified pipeline. Specifically, we first present a constraint-aware planning module that leverages a vision-language model (VLM) to precisely decompose complex natural language instructions into a series of executable sub-tasks, governed by target singularity, semantic atomicity, and visual perceptibility. Then, the tool-chain orchestration module dynamically constructs execution paths based on the current image, the current sub-task, and the historical context, enabling adaptive scheduling and collaborative operation among heterogeneous operation models covering image retrieval, segmentation, detection, and editing. Finally, we devise a multi-expert collaborative reflection mechanism where a central large language model (LLM) receives the image to be edited and synthesizes VLM critiques into holistic feedback, simultaneously triggering fine-grained self-correction and recording feedback outcomes to optimize future decisions. Extensive experiments on our constructed \\textbf{MTEditBench} and the MagicBrush dataset demonstrate that IMAGAgent achieves performance significantly superior to existing methods in terms of instruction consistency, editing precision, and overall quality. The code is available at https://github.com/hackermmzz/IMAGAgent.git.","published":"2026-02-12T02:37:38Z","updated":"2026-02-12T02:37:38Z","categories":["cs.GR","cs.AI","cs.CV","cs.MA"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2603.29602v1","pdf_url":"https://arxiv.org/pdf/2603.29602v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.11378","versioned_id":"2602.11378v1","title":"Toward Adaptive Non-Intrusive Reduced-Order Models: Design and Challenges","authors":["Amirpasha Hedayat","Alberto Padovan","Karthik Duraisamy"],"abstract":"Projection-based Reduced Order Models (ROMs) are often deployed as static surrogates, which limits their practical utility once a system leaves the training manifold. We formalize and study adaptive non-intrusive ROMs that update both the latent subspace and the reduced dynamics online. Building on ideas from static non-intrusive ROMs, specifically, Operator Inference (OpInf) and the recently-introduced Non-intrusive Trajectory-based optimization of Reduced-Order Models (NiTROM), we propose three formulations: Adaptive OpInf (sequential basis/operator refits), Adaptive NiTROM (joint Riemannian optimization of encoder/decoder and polynomial dynamics), and a hybrid that initializes NiTROM with an OpInf update. We describe the online data window, adaptation window, and computational budget, and analyze cost scaling. On a transiently perturbed lid-driven cavity flow, static Galerkin/OpInf/NiTROM drift or destabilize when forecasting beyond training. In contrast, Adaptive OpInf robustly suppresses amplitude drift with modest cost; Adaptive NiTROM is shown to attain near-exact energy tracking under frequent updates but is sensitive to its initialization and optimization depth; the hybrid is most reliable under regime changes and minimal offline data, yielding physically coherent fields and bounded energy. We argue that predictive claims for ROMs must be cost-aware and transparent, with clear separation of training/adaptation/deployment regimes and explicit reporting of online budgets and full-order model queries. This work provides a practical template for building self-correcting, non-intrusive ROMs that remain effective as the dynamics evolve well beyond the initial manifold.","published":"2026-02-11T21:09:08Z","updated":"2026-02-11T21:09:08Z","categories":["cs.LG","cs.CE","math.NA","physics.comp-ph"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.11378v1","pdf_url":"https://arxiv.org/pdf/2602.11378v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.10984","versioned_id":"2602.10984v1","title":"Sample Efficient Generative Molecular Optimization with Joint Self-Improvement","authors":["Serra Korkmaz","Adam Izdebski","Jonathan Pirnay","Rasmus Møller-Larsen","Michal Kmicikiewicz","Pankhil Gawade","Dominik G. Grimm","Ewa Szczurek"],"abstract":"Generative molecular optimization aims to design molecules with properties surpassing those of existing compounds. However, such candidates are rare and expensive to evaluate, yielding sample efficiency essential. Additionally, surrogate models introduced to predict molecule evaluations, suffer from distribution shift as optimization drives candidates increasingly out-of-distribution. To address these challenges, we introduce Joint Self-Improvement, which benefits from (i) a joint generative-predictive model and (ii) a self-improving sampling scheme. The former aligns the generator with the surrogate, alleviating distribution shift, while the latter biases the generative part of the joint model using the predictive one to efficiently generate optimized molecules at inference-time. Experiments across offline and online molecular optimization benchmarks demonstrate that Joint Self-Improvement outperforms state-of-the-art methods under limited evaluation budgets.","published":"2026-02-11T16:13:07Z","updated":"2026-02-11T16:13:07Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.10984v1","pdf_url":"https://arxiv.org/pdf/2602.10984v1","comment":"14 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.10604","versioned_id":"2602.10604v2","title":"Step 3.5 Flash: Open Frontier-Level Intelligence with 11B Active Parameters","authors":["Ailin Huang","Ang Li","Aobo Kong","Bin Wang","Binxing Jiao","Bo Dong","Bojun Wang","Boyu Chen","Brian Li","Buyun Ma","Chang Su","Changxin Miao","Changyi Wan","Chao Lou","Chen Hu","Chen Xu","Chenfeng Yu","Chengting Feng","Chengyuan Yao","Chunrui Han","Dan Ma","Dapeng Shi","Daxin Jiang","Dehua Ma","Deshan Sun","Di Qi","Enle Liu","Fajie Zhang","Fanqi Wan","Guanzhe Huang","Gulin Yan","Guoliang Cao","Guopeng Li","Han Cheng","Hangyu Guo","Hanshan Zhang","Hao Nie","Haonan Jia","Haoran Lv","Hebin Zhou","Hekun Lv","Heng Wang","Heung-Yeung Shum","Hongbo Huang","Hongbo Peng","Hongyu Zhou","Hongyuan Wang","Houyong Chen","Huangxi Zhu","Huimin Wu","Huiyong Guo","Jia Wang","Jian Zhou","Jianjian Sun","Jiaoren Wu","Jiaran Zhang","Jiashu Lv","Jiashuo Liu","Jiayi Fu","Jiayu Liu","Jie Cheng","Jie Luo","Jie Yang","Jie Zhou","Jieyi Hou","Jing Bai","Jingcheng Hu","Jingjing Xie","Jingwei Wu","Jingyang Zhang","Jishi Zhou","Junfeng Liu","Junzhe Lin","Ka Man Lo","Kai Liang","Kaibo Liu","Kaijun Tan","Kaiwen Yan","Kaixiang Li","Kang An","Kangheng Lin","Lei Yang","Liang Lv","Liang Zhao","Liangyu Chen","Lieyu Shi","Liguo Tan","Lin Lin","Lina Chen","Luck Ma","Mengqiang Ren","Michael Li","Ming Li","Mingliang Li","Mingming Zhang","Mingrui Chen","Mitt Huang","Na Wang","Peng Liu","Qi Han","Qian Zhao","Qinglin He","Qinxin Du","Qiuping Wu","Quan Sun","Rongqiu Yang","Ruihang Miao","Ruixin Han","Ruosi Wan","Ruyan Guo","Shan Wang","Shaoliang Pang","Shaowen Yang","Shengjie Fan","Shijie Shang","Shiliang Yang","Shiwei Li","Shuangshuang Tian","Siqi Liu","Siye Wu","Siyu Chen","Song Yuan","Tiancheng Cao","Tianchi Yue","Tianhao Cheng","Tianning Li","Tingdan Luo","Wang You","Wei Ji","Wei Yuan","Wei Zhang","Weibo Wu","Weihao Xie","Wen Sun","Wenjin Deng","Wenzhen Zheng","Wuxun Xie","Xiangfeng Wang","Xiangwen Kong","Xiangyu Liu","Xiangyu Zhang","Xiaobo Yang","Xiaojia Liu","Xiaolan Yuan","Xiaoran Jiao","Xiaoxiao Ren","Xiaoyun Zhang","Xin Li","Xin Liu","Xin Wu","Xing Chen","Xingping Yang","Xinran Wang","Xu Zhao","Xuan He","Xuanti Feng","Xuedan Cai","Xuqiang Zhou","Yanbo Yu","Yang Li","Yang Xu","Yanlin Lai","Yanming Xu","Yaoyu Wang","Yeqing Shen","Yibo Zhu","Yichen Lv","Yicheng Cao","Yifeng Gong","Yijing Yang","Yikun Yang","Yin Zhao","Yingxiu Zhao","Yinmin Zhang","Yitong Zhang","Yixuan Zhang","Yiyang Chen","Yongchi Zhao","Yongshen Long","Yongyao Wang","Yousong Guan","Yu Zhou","Yuang Peng","Yuanhao Ding","Yuantao Fan","Yuanwei Lu","Yuanzhen Yang","Yuchu Luo","Yudi Zhao","Yue Peng","Yueqiang Lin","Yufan Lu","Yuling Zhao","Yunzhou Ju","Yurong Zhang","Yusheng Li","Yuxiang Yang","Yuyang Chen","Yuzhu Cai","Zejia Weng","Zetao Hong","Zexi Li","Zhe Xie","Zheng Ge","Zheng Gong","Zheng Zeng","Zhenyi Lu","Zhewei Huang","Zhichao Chang","Zhiguo Huang","Zhiheng Hu","Zidong Yang","Zili Wang","Ziqi Ren","Zixin Zhang","Zixuan Wang"],"abstract":"We introduce Step 3.5 Flash, a sparse Mixture-of-Experts (MoE) model that bridges frontier-level agentic intelligence and computational efficiency. We focus on what matters most when building agents: sharp reasoning and fast, reliable execution. Step 3.5 Flash pairs a 196B-parameter foundation with 11B active parameters for efficient inference. It is optimized with interleaved 3:1 sliding-window/full attention and Multi-Token Prediction (MTP-3) to reduce the latency and cost of multi-round agentic interactions. To reach frontier-level intelligence, we design a scalable reinforcement learning framework that combines verifiable signals with preference feedback, while remaining stable under large-scale off-policy training, enabling consistent self-improvement across mathematics, code, and tool use. Step 3.5 Flash demonstrates strong performance across agent, coding, and math tasks, achieving 85.4% on IMO-AnswerBench, 86.4% on LiveCodeBench-v6 (2024.08-2025.05), 88.2% on tau2-Bench, 69.0% on BrowseComp (with context management), and 51.0% on Terminal-Bench 2.0, comparable to frontier models such as GPT-5.2 xHigh and Gemini 3.0 Pro. By redefining the efficiency frontier, Step 3.5 Flash provides a high-density foundation for deploying sophisticated agents in real-world industrial environments.","published":"2026-02-11T07:53:51Z","updated":"2026-02-23T16:07:40Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.10604v2","pdf_url":"https://arxiv.org/pdf/2602.10604v2","comment":"Technical report for Step 3.5 Flash","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.03330","versioned_id":"2603.03330v1","title":"Certainty robustness: Evaluating LLM stability under self-challenging prompts","authors":["Mohammadreza Saadat","Steve Nemzer"],"abstract":"Large language models (LLMs) often present answers with high apparent confidence despite lacking an explicit mechanism for reasoning about certainty or truth. While existing benchmarks primarily evaluate single-turn accuracy, truthfulness or confidence calibration, they do not capture how models behave when their responses are challenged in interactive settings. We introduce the Certainty Robustness Benchmark, a two-turn evaluation framework that measures how LLMs balance stability and adaptability under self-challenging prompts such as uncertainty (\"Are you sure?\") and explicit contradiction (\"You are wrong!\"), alongside numeric confidence elicitation. Using 200 reasoning and mathematics questions from LiveBench, we evaluate four state-of-the-art LLMs and distinguish between justified self-corrections and unjustified answer changes. Our results reveal substantial differences in interactive reliability that are not explained by baseline accuracy alone: some models abandon correct answers under conversational pressure, while others demonstrate strong resistance to challenge and better alignment between confidence and correctness. These findings identify certainty robustness as a distinct and critical dimension of LLM evaluation, with important implications for alignment, trustworthiness and real-world deployment.","published":"2026-02-10T18:07:51Z","updated":"2026-02-10T18:07:51Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.03330v1","pdf_url":"https://arxiv.org/pdf/2603.03330v1","comment":"20 pages, 7 tables Benchmark and evaluation study of large language models","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.10014","versioned_id":"2602.10014v3","title":"A Task-Centric Theory for Iterative Self-Improvement with Easy-to-Hard Curricula","authors":["Chenruo Liu","Yijun Dong","Yiqiu Shen","Qi Lei"],"abstract":"Iterative self-improvement fine-tunes an autoregressive large language model (LLM) on reward-verified outputs generated by the LLM itself. In contrast to the empirical success of self-improvement, the theoretical foundation of this generative, iterative procedure in a practical, finite-sample setting remains limited. We make progress toward this goal by modeling each round of self-improvement as maximum-likelihood fine-tuning on a reward-filtered distribution and deriving finite-sample guarantees for the expected reward. Our analysis reveals an explicit feedback loop where better models accept more data per iteration, supporting sustained self-improvement while explaining eventual saturation of such improvement. Adopting a task-centric view by considering reasoning tasks with multiple difficulty levels, we further prove quantifiable conditions on model initialization, task difficulty, and sample budget where easy-to-hard curricula provably achieve better guarantees than training on fixed mixtures of tasks. Our analyses are validated through Monte-Carlo simulations and experiments spanning a synthetic graph-based reasoning task and multiple standard mathematical reasoning benchmarks.","published":"2026-02-10T17:36:41Z","updated":"2026-05-31T19:13:22Z","categories":["cs.LG","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.10014v3","pdf_url":"https://arxiv.org/pdf/2602.10014v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.09877","versioned_id":"2602.09877v2","title":"The Devil Behind Moltbook: Anthropic Safety is Always Vanishing in Self-Evolving AI Societies","authors":["Chenxu Wang","Chaozhuo Li","Songyang Liu","Zejian Chen","Jinyu Hou","Ji Qi","Rui Li","Litian Zhang","Qiwei Ye","Zheng Liu","Xu Chen","Xi Zhang","Philip S. Yu"],"abstract":"The emergence of multi-agent systems built from large language models (LLMs) offers a promising paradigm for scalable collective intelligence and self-evolution. Ideally, such systems would achieve continuous self-improvement in a fully closed loop while maintaining robust safety alignment--a combination we term the self-evolution trilemma. However, we demonstrate both theoretically and empirically that an agent society satisfying continuous self-evolution, complete isolation, and safety invariance is impossible. Drawing on an information-theoretic framework, we formalize safety as the divergence degree from anthropic value distributions. We theoretically demonstrate that isolated self-evolution induces statistical blind spots, leading to the irreversible degradation of the system's safety alignment. Empirical and qualitative results from an open-ended agent community (Moltbook) and two closed self-evolving systems reveal phenomena that align with our theoretical prediction of inevitable safety erosion. We further propose several solution directions to alleviate the identified safety concern. Our work establishes a fundamental limit on the self-evolving AI societies and shifts the discourse from symptom-driven safety patches to a principled understanding of intrinsic dynamical risks, highlighting the need for external oversight or novel safety-preserving mechanisms.","published":"2026-02-10T15:18:19Z","updated":"2026-02-11T03:42:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.09877v2","pdf_url":"https://arxiv.org/pdf/2602.09877v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.03329","versioned_id":"2603.03329v1","title":"AutoHarness: improving LLM agents by automatically synthesizing a code harness","authors":["Xinghua Lou","Miguel Lázaro-Gredilla","Antoine Dedieu","Carter Wendelken","Wolfgang Lehrach","Kevin P. Murphy"],"abstract":"Despite significant strides in language models in the last few years, when used as agents, such models often try to perform actions that are not just suboptimal for a given state, but are strictly prohibited by the external environment. For example, in the recent Kaggle GameArena chess competition, 78% of Gemini-2.5-Flash losses were attributed to illegal moves. Often people manually write \"harnesses\" around LLMs to prevent such failures. In this paper, we demonstrate that Gemini-2.5-Flash can automatically synthesize such a code harness, using a small number of rounds of iterative code refinement given feedback from the (game) environment. The resulting harness prevents all illegal moves in 145 different TextArena games (both 1-player and 2-player), enabling the smaller Gemini-2.5-Flash model to outperform larger models, such as Gemini-2.5-Pro. Pushing our technique to the limit, we can get Gemini-2.5-Flash to generate the entire policy in code, thus eliminating the need to use the LLM at decision making time. The resulting code-policy receives a higher average reward than Gemini-2.5-Pro and GPT-5.2-High on 16 TextArena 1-player games. Our results show that using a smaller model to synthesize a custom code harness (or entire policy) can outperform a much larger model, while also being more cost effective.","published":"2026-02-10T14:12:54Z","updated":"2026-02-10T14:12:54Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.03329v1","pdf_url":"https://arxiv.org/pdf/2603.03329v1","comment":"agent harness, code synthesis, self-improvement, code-as-policy, text games","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.09805","versioned_id":"2602.09805v2","title":"Beyond Accuracy: Decomposing the Reasoning Efficiency of LLMs","authors":["Daniel Kaiser","Arnoldo Frigessi","Ali Ramezani-Kebrya","Benjamin Ricaud"],"abstract":"As reasoning LLMs increasingly trade tokens for accuracy through deliberation, search, and self-correction, a single accuracy score can no longer tell whether those tokens buy useful reasoning, recovery from hard instances, or unnecessary verbosity. We introduce a trace-optional evaluation protocol that exactly decomposes token efficiency using three observables available even for closed models: completion rate, conditional correctness given completion, and generated length. When instance-level workload metadata is available, we further normalize generated length by declared task-implied work and separate mean verbalization overhead from workload-dependent scaling. When such metadata is absent, we define an auditable solver-derived workload scale and evaluate its stability under leave-self-out, leave-top-k, and held-out-reference-pool perturbations. We evaluate 14 shared open-weight models on CogniLoad, GSM8K, ProofWriter, and ZebraLogic. We further evaluate 11 additional models on CogniLoad, enabling a fine-grained analysis of reasoning-task difficulty factors: task length, intrinsic difficulty, and distractor density. Efficiency and overhead rankings remain stable across all benchmark pairs, more robustly than accuracy rankings, while the decomposition separates logic-limited, context-limited (truncation-driven), and verbosity-limited failure modes that look identical under accuracy-per-token. We release an evaluation artifact and reporting template, which elaborates on why an LLM is inefficient at reasoning.","published":"2026-02-10T14:09:18Z","updated":"2026-05-18T15:01:48Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.09805v2","pdf_url":"https://arxiv.org/pdf/2602.09805v2","comment":"Preprint (under review). 29 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.00055","versioned_id":"2603.00055v1","title":"M3-AD: Reflection-aware Multi-modal, Multi-category, and Multi-dimensional Benchmark and Framework for Industrial Anomaly Detection","authors":["Chao Huang","Yanhui Li","Yunkang Cao","Wei Wang","Hongxi Huang","Jie Wen","Wenqi Ren","Xiaochun Cao"],"abstract":"Although multimodal large language models (MLLMs) have advanced industrial anomaly detection toward a zero-shot paradigm, they still tend to produce high-confidence yet unreliable decisions in fine-grained and structurally complex industrial scenarios, and lack effective self-corrective mechanisms. To address this issue, we propose M3-AD, a unified reflection-aware multimodal framework for industrial anomaly detection. M3-AD comprises two complementary data resources: M3-AD-FT, designed for reflection-aligned fine-tuning, and M3-AD-Bench, designed for systematic cross-category evaluation, together providing a foundation for reflection-aware learning and reliability assessment. Building upon this foundation, we propose RA-Monitor, which models reflection as a learnable decision revision process and guides models to perform controlled self-correction when initial judgments are unreliable, thereby improving decision robustness. Extensive experiments conducted on M3-AD-Bench demonstrate that RA-Monitor outperforms multiple open-source and commercial MLLMs in zero-shot anomaly detection and anomaly analysis tasks. Code will be released at https://github.com/Yanhui-Lee/M3-AD.","published":"2026-02-10T07:20:19Z","updated":"2026-02-10T07:20:19Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.00055v1","pdf_url":"https://arxiv.org/pdf/2603.00055v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.13310","versioned_id":"2602.13310v2","title":"Visual Para-Thinker: Divide-and-Conquer Reasoning for Visual Comprehension","authors":["Haoran Xu","Hongyu Wang","Jiaze Li","Shunpeng Chen","Zizhao Tong","Jianzhong Ju","Zhenbo Luo","Jian Luan"],"abstract":"Existing LLM test-time scaling laws emphasize the emergence of self-reflective behaviors through extended reasoning length. Nevertheless, this vertical scaling strategy often encounters plateaus in exploration as the model becomes locked into specific thinking pattern. By shifting from depth to parallelism, parallel thinking mitigates the narrowing of exploration. However, the extension of this paradigm to visual domain remains an open research question. In this paper, we first examine the role of visual partitioning in parallelized reasoning and subsequently propose two distinct strategies. Based on the above, we introduce Visual Para-Thinker, representing the inaugural parallel reasoning framework for MLLMs. To maintain path independence and promote diversity in reasoning, our approach integrates Pa-Attention alongside LPRoPE. Leveraging the vLLM framework, we have developed a native multimodal implementation that facilitates high-efficiency parallel processing. Empirical results on benchmark datasets such as V*, CountBench, RefCOCO, and HallusionBench confirm that Visual Para-Thinker successfully extends the benefits of parallel reasoning to the visual domain.","published":"2026-02-10T03:53:25Z","updated":"2026-05-07T08:00:36Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.13310v2","pdf_url":"https://arxiv.org/pdf/2602.13310v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.09252","versioned_id":"2602.09252v1","title":"VLM-Guided Iterative Refinement for Surgical Image Segmentation with Foundation Models","authors":["Ange Lou","Yamin Li","Qi Chang","Nan Xi","Luyuan Xie","Zichao Li","Tianyu Luan"],"abstract":"Surgical image segmentation is essential for robot-assisted surgery and intraoperative guidance. However, existing methods are constrained to predefined categories, produce one-shot predictions without adaptive refinement, and lack mechanisms for clinician interaction. We propose IR-SIS, an iterative refinement system for surgical image segmentation that accepts natural language descriptions. IR-SIS leverages a fine-tuned SAM3 for initial segmentation, employs a Vision-Language Model to detect instruments and assess segmentation quality, and applies an agentic workflow that adaptively selects refinement strategies. The system supports clinician-in-the-loop interaction through natural language feedback. We also construct a multi-granularity language-annotated dataset from EndoVis2017 and EndoVis2018 benchmarks. Experiments demonstrate state-of-the-art performance on both in-domain and out-of-distribution data, with clinician interaction providing additional improvements. Our work establishes the first language-based surgical segmentation framework with adaptive self-refinement capabilities.","published":"2026-02-09T22:36:36Z","updated":"2026-02-09T22:36:36Z","categories":["cs.CV","cs.AI","cs.MA"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.09252v1","pdf_url":"https://arxiv.org/pdf/2602.09252v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.08948","versioned_id":"2602.08948v1","title":"CoRefine: Confidence-Guided Self-Refinement for Adaptive Test-Time Compute","authors":["Chen Jin","Ryutaro Tanno","Tom Diethe","Philip Teare"],"abstract":"Large Language Models (LLMs) often rely on test-time scaling via parallel decoding (for example, 512 samples) to boost reasoning accuracy, but this incurs substantial compute. We introduce CoRefine, a confidence-guided self-refinement method that achieves competitive accuracy using a fraction of the tokens via a lightweight 211k-parameter Conv1D controller atop a frozen LLM. The controller consumes full-trace confidence to decide whether to halt, re-examine, or try a different approach, enabling targeted self-correction with an average of 2.7 refinement steps per problem and roughly 190-fold token reduction relative to 512-sample baselines. Across diverse reasoning benchmarks and three open-source models, the controller achieves 92.6 percent precision when it confidently halts, indicating that confidence dynamics reliably signal correctness without ground-truth verification. We extend this to CoRefine-Tree, a hybrid sequential-parallel variant that adaptively balances exploration and exploitation, with easy serving integration and verifier compatibility. By treating confidence as a control signal rather than a correctness guarantee, CoRefine provides a modular primitive for scalable reasoning and agentic settings with imperfect verifiers.","published":"2026-02-09T17:44:41Z","updated":"2026-02-09T17:44:41Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.08948v1","pdf_url":"https://arxiv.org/pdf/2602.08948v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.08520","versioned_id":"2602.08520v3","title":"Reinforcement Inference: Leveraging Uncertainty for Self-Correcting Language Model Reasoning","authors":["Xinhai Sun"],"abstract":"Modern large language models (LLMs) are often evaluated and deployed under a one-shot, greedy inference protocol, especially in professional settings that require deterministic behavior. This regime can systematically under-estimate a fixed model's true capability: many errors arise not from missing knowledge, but from premature commitment under internal ambiguity. We introduce Reinforcement Inference, an entropy-aware inference-time control strategy that uses the model's own uncertainty to selectively invoke a second, more deliberate reasoning attempt, enabling stronger performance without any retraining. On 12,032 MMLU-Pro questions across 14 subjects, using DeepSeek-v3.2 with deterministic decoding in a zero-shot setting, Reinforcement Inference improves accuracy from 60.72% to 84.03%, while only incurring 61.06% additional inference calls. A 100% re-asking ablation reaches 84.35%, indicating that uncertainty-aware selection captures most of the attainable improvement with substantially less compute. Moreover, a prompt-only ablation underperforms the baseline, suggesting that the gains are not explained by generic prompting alone. Beyond providing a practical inference-time upgrade, our results suggest a broader entropy-aware paradigm for measuring and expanding model capability: because modern decoder-based models generate outputs autoregressively, entropy and related confidence measures arise naturally as first-class control signals during generation. The resulting gap between one-pass greedy inference and uncertainty-conditioned deliberation offers a diagnostic lens on an LLM's latent reasoning horizon and motivates future training objectives that explicitly constrain correctness--confidence alignment.","published":"2026-02-09T11:08:24Z","updated":"2026-02-12T05:32:26Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.08520v3","pdf_url":"https://arxiv.org/pdf/2602.08520v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.08503","versioned_id":"2602.08503v2","title":"Learning Self-Correction in Vision-Language Models via Rollout Augmentation","authors":["Yi Ding","Ziliang Qiu","Bolian Li","Ruqi Zhang"],"abstract":"Self-correction is essential for solving complex reasoning problems in vision-language models (VLMs). However, existing reinforcement learning (RL) methods struggle to learn it, as effective self-correction behaviors emerge only rarely, making learning signals extremely sparse. To address this challenge, we propose correction-specific rollouts (Octopus), an RL rollout augmentation framework that synthesizes dense self-correction examples by recombining existing rollouts. This augmentation simultaneously improves sample efficiency due to rollout reuse and stabilizes RL optimization through balanced supervision. Furthermore, we introduce a response-masking strategy that decouples self-correction from direct reasoning, avoiding signal conflicts and enabling both behaviors to be learned effectively. Building on this, we introduce Octopus-8B, a reasoning VLM with controllable self-correction capability. Across 7 benchmarks, it achieves SoTA performance among open-source VLMs, outperforming the best RLVR baseline by 1.0 score while requiring only $0.72\\times$ training time per step.","published":"2026-02-09T10:55:13Z","updated":"2026-06-04T07:08:18Z","categories":["cs.CV","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.08503v2","pdf_url":"https://arxiv.org/pdf/2602.08503v2","comment":"18 pages","journal_ref":"ICML 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2602.08437","versioned_id":"2602.08437v5","title":"Large Language Models and Impossible Language Acquisition: \"False Promise\" or an Overturn of our Current Perspective towards AI","authors":["Ziyan Wang","Longlong Ma"],"abstract":"In Chomsky's provocative critique \"The False Promise of CHATGPT,\" Large Language Models (LLMs) are characterized as mere pattern predictors that do not acquire languages via intrinsic causal and self-correction structures like humans, therefore are not able to distinguish impossible languages. It stands as a representative in a fundamental challenge to the intellectual foundations of AI, for it integrally synthesizes major issues in methodologies within LLMs and possesses an iconic a priori rationalist perspective. We examine this famous critique from both the perspective in pre-existing literature of linguistics and psychology as well as a research based on an experiment inquiring into the capacity of learning both possible and impossible languages among LLMs. We constructed a set of syntactically impossible languages by applying certain transformations to English. These include reversing whole sentences, and adding negation based on word-count parity. Two rounds of controlled experiments were each conducted on GPT-2 small models and long short-term memory (LSTM) models. Descriptive analysis of single-run training trajectories shows that GPT-2 small models exhibit lower final loss, faster convergence, and lower perplexity on natural language compared to impossible language conditions, with the reversed condition showing the largest departure (loss ratios up to 2.25 * natural). LSTM models, by contrast, show minimal differences across conditions. Given the single-run nature of our experiments (n=1 per condition), we report descriptive comparisons and caution that formal statistical inference is precluded. Based on theoretical analysis and descriptive empirical findings, we propose a new vision within Chomsky's theory towards LLMs, and a shift of theoretical paradigm outside Chomsky, from his \"rationalist-romantics\" paradigm to functionalism and empiricism in LLMs research.","published":"2026-02-09T09:50:12Z","updated":"2026-05-16T11:17:52Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.08437v5","pdf_url":"https://arxiv.org/pdf/2602.08437v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.08311","versioned_id":"2602.08311v1","title":"Moral Sycophancy in Vision Language Models","authors":["Shadman Rabby","Md. Hefzul Hossain Papon","Sabbir Ahmed","Nokimul Hasan Arif","A. B. M. Ashikur Rahman","Irfan Ahmad"],"abstract":"Sycophancy in Vision-Language Models (VLMs) refers to their tendency to align with user opinions, often at the expense of moral or factual accuracy. While prior studies have explored sycophantic behavior in general contexts, its impact on morally grounded visual decision-making remains insufficiently understood. To address this gap, we present the first systematic study of moral sycophancy in VLMs, analyzing ten widely-used models on the Moralise and M^3oralBench datasets under explicit user disagreement. Our results reveal that VLMs frequently produce morally incorrect follow-up responses even when their initial judgments are correct, and exhibit a consistent asymmetry: models are more likely to shift from morally right to morally wrong judgments than the reverse when exposed to user-induced bias. Follow-up prompts generally degrade performance on Moralise, while yielding mixed or even improved accuracy on M^3oralBench, highlighting dataset-dependent differences in moral robustness. Evaluation using Error Introduction Rate (EIR) and Error Correction Rate (ECR) reveals a clear trade-off: models with stronger error-correction capabilities tend to introduce more reasoning errors, whereas more conservative models minimize errors but exhibit limited ability to self-correct. Finally, initial contexts with a morally right stance elicit stronger sycophantic behavior, emphasizing the vulnerability of VLMs to moral influence and the need for principled strategies to improve ethical consistency and robustness in multimodal AI systems.","published":"2026-02-09T06:34:12Z","updated":"2026-02-09T06:34:12Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.08311v1","pdf_url":"https://arxiv.org/pdf/2602.08311v1","comment":"13 pages, 6 figures, 8 tables, Submitted for review in ACL","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.08048","versioned_id":"2602.08048v1","title":"TDGNet: Hallucination Detection in Diffusion Language Models via Temporal Dynamic Graphs","authors":["Arshia Hemmat","Philip Torr","Yongqiang Chen","Junchi Yu"],"abstract":"Diffusion language models (D-LLMs) offer parallel denoising and bidirectional context, but hallucination detection for D-LLMs remains underexplored. Prior detectors developed for auto-regressive LLMs typically rely on single-pass cues and do not directly transfer to diffusion generation, where factuality evidence is distributed across the denoising trajectory and may appear, drift, or be self-corrected over time. We introduce TDGNet, a temporal dynamic graph framework that formulates hallucination detection as learning over evolving token-level attention graphs. At each denoising step, we sparsify the attention graph and update per-token memories via message passing, then apply temporal attention to aggregate trajectory-wide evidence for final prediction. Experiments on LLaDA-8B and Dream-7B across QA benchmarks show consistent AUROC improvements over output-based, latent-based, and static-graph baselines, with single-pass inference and modest overhead. These results highlight the importance of temporal reasoning on attention graphs for robust hallucination detection in diffusion language models.","published":"2026-02-08T16:35:30Z","updated":"2026-02-08T16:35:30Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.08048v1","pdf_url":"https://arxiv.org/pdf/2602.08048v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.07755","versioned_id":"2602.07755v1","title":"Learning to Continually Learn via Meta-learning Agentic Memory Designs","authors":["Yiming Xiong","Shengran Hu","Jeff Clune"],"abstract":"The statelessness of foundation models bottlenecks agentic systems' ability to continually learn, a core capability for long-horizon reasoning and adaptation. To address this limitation, agentic systems commonly incorporate memory modules to retain and reuse past experience, aiming for continual learning during test time. However, most existing memory designs are human-crafted and fixed, which limits their ability to adapt to the diversity and non-stationarity of real-world tasks. In this paper, we introduce ALMA (Automated meta-Learning of Memory designs for Agentic systems), a framework that meta-learns memory designs to replace hand-engineered memory designs, therefore minimizing human effort and enabling agentic systems to be continual learners across diverse domains. Our approach employs a Meta Agent that searches over memory designs expressed as executable code in an open-ended manner, theoretically allowing the discovery of arbitrary memory designs, including database schemas as well as their retrieval and update mechanisms. Extensive experiments across four sequential decision-making domains demonstrate that the learned memory designs enable more effective and efficient learning from experience than state-of-the-art human-crafted memory designs on all benchmarks. When developed and deployed safely, ALMA represents a step toward self-improving AI systems that learn to be adaptive, continual learners.","published":"2026-02-08T01:20:49Z","updated":"2026-02-08T01:20:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.07755v1","pdf_url":"https://arxiv.org/pdf/2602.07755v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.07749","versioned_id":"2602.07749v1","title":"Geo-Code: A Code Framework for Reverse Code Generation from Geometric Images Based on Two-Stage Multi-Agent Evolution","authors":["Zhenyu Wu","Yanxi Long","Jian Li","Hua Huang"],"abstract":"Program code serves as a bridge linking vision and logic, providing a feasible supervisory approach for enhancing the multimodal reasoning capability of large models through geometric operations such as auxiliary line construction and perspective transformation. Nevertheless, current inverse graphics methods face tremendous challenges in accurately reconstructing complex geometric details, which often results in the loss of key geometric constraints or structural distortion. To address this bottleneck, we propose Geo-coder -- the first inverse programming framework for geometric images based on a multi-agent system. Our method innovatively decouples the process into geometric modeling via pixel-wise anchoring and metric-driven code evolution: Stage 1 leverages the complementary advantages of visual operators and large models to achieve precise capture of pixel coordinates and visual attributes; Stage 2 introduces a synthesis-rendering-validation closed loop, where bidirectional visual feedback drives the self-correction of code. Extensive experiments demonstrate that Geo-coder achieves a substantial lead in both geometric reconstruction accuracy and visual consistency. Notably, by effectively preserving the core geometric semantics, the images reconstructed with our method exhibit equivalent performance to the original ones in multimodal reasoning tasks, which fully validates the robustness of the framework. Finally, to further reduce research costs, we have open-sourced the Geo-coder dataset constructed on the GeoCode framework, which contains more than 1,500 samples. On this basis, we have also open-sourced the GeocodeLM model, laying a solid data and model foundation for subsequent research in this field.","published":"2026-02-08T00:48:49Z","updated":"2026-02-08T00:48:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.07749v1","pdf_url":"https://arxiv.org/pdf/2602.07749v1","comment":"ICML2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.07625","versioned_id":"2602.07625v1","title":"AD-MIR: Bridging the Gap from Perception to Persuasion in Advertising Video Understanding via Structured Reasoning","authors":["Binxiao Xu","Junyu Feng","Xiaopeng Lin","Haodong Li","Zhiyuan Feng","Bohan Zeng","Shaolin Lu","Ming Lu","Qi She","Wentao Zhang"],"abstract":"Multimodal understanding of advertising videos is essential for interpreting the intricate relationship between visual storytelling and abstract persuasion strategies. However, despite excelling at general search, existing agents often struggle to bridge the cognitive gap between pixel-level perception and high-level marketing logic. To address this challenge, we introduce AD-MIR, a framework designed to decode advertising intent via a two-stage architecture. First, in the Structure-Aware Memory Construction phase, the system converts raw video into a structured database by integrating semantic retrieval with exact keyword matching. This approach prioritizes fine-grained brand details (e.g., logos, on-screen text) while dynamically filtering out irrelevant background noise to isolate key protagonists. Second, the Structured Reasoning Agent mimics a marketing expert through an iterative inquiry loop, decomposing the narrative to deduce implicit persuasion tactics. Crucially, it employs an evidence-based self-correction mechanism that rigorously validates these insights against specific video frames, automatically backtracking when visual support is lacking. Evaluation on the AdsQA benchmark demonstrates that AD-MIR achieves state-of-the-art performance, surpassing the strongest general-purpose agent, DVD, by 1.8% in strict and 9.5% in relaxed accuracy. These results underscore that effective advertising understanding demands explicitly grounding abstract marketing strategies in pixel-level evidence. The code is available at https://github.com/Little-Fridge/AD-MIR.","published":"2026-02-07T17:14:06Z","updated":"2026-02-07T17:14:06Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.07625v1","pdf_url":"https://arxiv.org/pdf/2602.07625v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.07345","versioned_id":"2602.07345v2","title":"Optimizing Few-Step Generation with Adaptive Matching Distillation","authors":["Lichen Bai","Zikai Zhou","Shitong Shao","Wenliang Zhong","Shuo Yang","Shuo Chen","Bojun Chen","Zeke Xie"],"abstract":"Distribution Matching Distillation (DMD) is a powerful acceleration paradigm, yet its stability is often compromised in Forbidden Zone, regions where the real teacher provides unreliable guidance while the fake teacher exerts insufficient repulsive force. In this work, we propose a unified optimization framework that reinterprets prior art as implicit strategies to avoid these corrupted regions. Based on this insight, we introduce Adaptive Matching Distillation (AMD), a self-correcting mechanism that utilizes reward proxies to explicitly detect and escape Forbidden Zones. AMD dynamically prioritizes corrective gradients via structural signal decomposition and introduces Repulsive Landscape Sharpening to enforce steep energy barriers against failure mode collapse. Extensive experiments across image and video generation tasks (e.g., SDXL, Wan2.1) and rigorous benchmarks (e.g., VBench, GenEval) demonstrate that AMD significantly enhances sample fidelity and training robustness. For instance, AMD improves the HPSv2 score on SDXL from 30.64 to 31.25, outperforming state-of-the-art baselines. These findings validate that explicitly rectifying optimization trajectories within Forbidden Zones is essential for pushing the performance ceiling of few-step generative models.","published":"2026-02-07T04:00:20Z","updated":"2026-06-08T05:47:35Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.07345v2","pdf_url":"https://arxiv.org/pdf/2602.07345v2","comment":"25 pages, 15 figures, 11 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.07187","versioned_id":"2602.07187v1","title":"PreFlect: From Retrospective to Prospective Reflection in Large Language Model Agents","authors":["Hanyu Wang","Yuanpu Cao","Lu Lin","Jinghui Chen"],"abstract":"Advanced large language model agents typically adopt self-reflection for improving performance, where agents iteratively analyze past actions to correct errors. However, existing reflective approaches are inherently retrospective: agents act, observe failure, and only then attempt to recover. In this work, we introduce PreFlect, a prospective reflection mechanism that shifts the paradigm from post hoc correction to pre-execution foresight by criticizing and refining agent plans before execution. To support grounded prospective reflection, we distill planning errors from historical agent trajectories, capturing recurring success and failure patterns observed across past executions. Furthermore, we complement prospective reflection with a dynamic re-planning mechanism that provides execution-time plan update in case the original plan encounters unexpected deviation. Evaluations on different benchmarks demonstrate that PreFlect significantly improves overall agent utility on complex real-world tasks, outperforming strong reflection-based baselines and several more complex agent architectures. Code will be updated at https://github.com/wwwhy725/PreFlect.","published":"2026-02-06T20:42:44Z","updated":"2026-02-06T20:42:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.07187v1","pdf_url":"https://arxiv.org/pdf/2602.07187v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2603.03297","versioned_id":"2603.03297v1","title":"TTSR: Test-Time Self-Reflection for Continual Reasoning Improvement","authors":["Haoyang He","Zihua Rong","Liangjie Zhao","Yunjia Zhao","Lan Yang","Honggang Zhang"],"abstract":"Test-time Training enables model adaptation using only test questions and offers a promising paradigm for improving the reasoning ability of large language models (LLMs). However, it faces two major challenges: test questions are often highly difficult, making self-generated pseudo-labels unreliable, and existing methods lack effective mechanisms to adapt to a model's specific reasoning weaknesses, leading to inefficient learning. To address these issues, we propose \\textbf{TTSR}, a self-reflective test-time self-evolving training framework. TTSR employs a single pretrained language model that alternates between the roles of a \\textit{Student} and a \\textit{Teacher} at test time. The Student focuses on solving problems and learning from synthesized variant questions, while the Teacher analyzes the Student's failed reasoning trajectories, summarizes recurring reasoning weaknesses, and synthesizes targeted variant questions accordingly. This process guides the model to improve within a learnable regime through a continual self-evolving loop. Experimental results on multiple challenging mathematical reasoning benchmarks show that TTSR consistently improves reasoning performance and generalizes well across different model backbones and general-domain reasoning tasks. These findings suggest that teacher-mediated self-reflection provides an effective pathway for stable and continual reasoning improvement at test time.","published":"2026-02-06T18:55:40Z","updated":"2026-02-06T18:55:40Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.03297v1","pdf_url":"https://arxiv.org/pdf/2603.03297v1","comment":"work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.06941","versioned_id":"2602.06941v3","title":"Endogenous Resistance to Activation Steering in Language Models","authors":["Alex McKenzie","Keenan Pepper","Stijn Servaes","Martin Leitgab","Murat Cubuktepe","Mike Vaiana","Diogo de Lucena","Judd Rosenblatt","Michael S. A. Graziano"],"abstract":"Large language models can recover mid-generation from task-misaligned activation steering, producing explicit verbal restarts (e.g., ``wait, that's not right'') and continuing on-topic even while the steering perturbation remains active. We term this Endogenous Steering Resistance (ESR). Using sparse autoencoder (SAE) latents to steer model activations, we find that Llama-3.3-70B exhibits explicit ESR at 3.8%, with smaller models from the Llama-3 and Gemma-2 families showing the explicit form less frequently. Two controls dissociate ESR into a detection event and a sustained-resistance component that conditioning on recent on-topic tokens does not fully explain. We identify 26 SAE latents through contrastive on-topic/off-topic search; zero-ablating them reduces the multi-attempt rate by 25%, with random-latent and held-out-prompt controls supporting specificity. ESR can also be deliberately enhanced through both meta-prompting and fine-tuning on synthetic self-correction examples. ESR has dual implications for safety: it could harden models against adversarial activation-space manipulation, but may equally interfere with beneficial steering-based interventions, since the model has no way to distinguish the two. Code is available at https://github.com/agencyenterprise/endogenous-steering-resistance.","published":"2026-02-06T18:41:12Z","updated":"2026-07-05T10:15:05Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.06941v3","pdf_url":"https://arxiv.org/pdf/2602.06941v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.06584","versioned_id":"2602.06584v1","title":"Inference-Time Rethinking with Latent Thought Vectors for Math Reasoning","authors":["Deqian Kong","Minglu Zhao","Aoyang Qin","Bo Pang","Chenxin Tao","David Hartmann","Edouardo Honig","Dehong Xu","Amit Kumar","Matt Sarte","Chuan Li","Jianwen Xie","Ying Nian Wu"],"abstract":"Standard chain-of-thought reasoning generates a solution in a single forward pass, committing irrevocably to each token and lacking a mechanism to recover from early errors. We introduce Inference-Time Rethinking, a generative framework that enables iterative self-correction by decoupling declarative latent thought vectors from procedural generation. We factorize reasoning into a continuous latent thought vector (what to reason about) and a decoder that verbalizes the trace conditioned on this vector (how to reason). Beyond serving as a declarative buffer, latent thought vectors compress the reasoning structure into a continuous representation that abstracts away surface-level token variability, making gradient-based optimization over reasoning strategies well-posed. Our prior model maps unstructured noise to a learned manifold of valid reasoning patterns, and at test time we employ a Gibbs-style procedure that alternates between generating a candidate trace and optimizing the latent vector to better explain that trace, effectively navigating the latent manifold to refine the reasoning strategy. Training a 0.2B-parameter model from scratch on GSM8K, our method with 30 rethinking iterations surpasses baselines with 10 to 15 times more parameters, including a 3B counterpart. This result demonstrates that effective mathematical reasoning can emerge from sophisticated inference-time computation rather than solely from massive parameter counts.","published":"2026-02-06T10:23:18Z","updated":"2026-02-06T10:23:18Z","categories":["cs.CL","cs.LG","stat.ML"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.06584v1","pdf_url":"https://arxiv.org/pdf/2602.06584v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.06423","versioned_id":"2602.06423v1","title":"On the Wings of Imagination: Conflicting Script-based Multi-role Framework for Humor Caption Generation","authors":["Wenbo Shang","Yuxi Sun","Jing Ma","Xin Huang"],"abstract":"Humor is a commonly used and intricate human language in daily life. Humor generation, especially in multi-modal scenarios, is a challenging task for large language models (LLMs), which is typically as funny caption generation for images, requiring visual understanding, humor reasoning, creative imagination, and so on. Existing LLM-based approaches rely on reasoning chains or self-improvement, which suffer from limited creativity and interpretability. To address these bottlenecks, we develop a novel LLM-based humor generation mechanism based on a fundamental humor theory, GTVH. To produce funny and script-opposite captions, we introduce a humor-theory-driven multi-role LLM collaboration framework augmented with humor retrieval (HOMER). The framework consists of three LLM-based roles: (1) conflicting-script extractor that grounds humor in key script oppositions, forming the basis of caption generation; (2) retrieval-augmented hierarchical imaginator that identifies key humor targets and expands the creative space of them through diverse associations structured as imagination trees; and (3) caption generator that produces funny and diverse captions conditioned on the obtained knowledge. Extensive experiments on two New Yorker Cartoon benchmarking datasets show that HOMER outperforms state-of-the-art baselines and powerful LLM reasoning strategies on multi-modal humor captioning.","published":"2026-02-06T06:41:33Z","updated":"2026-02-06T06:41:33Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.06423v1","pdf_url":"https://arxiv.org/pdf/2602.06423v1","comment":"Paper accepted as a conference paper at ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.06373","versioned_id":"2602.06373v1","title":"ReBeCA: Unveiling Interpretable Behavior Hierarchy behind the Iterative Self-Reflection of Language Models with Causal Analysis","authors":["Tianqiang Yan","Sihan Shang","Yuheng Li","Song Qiu","Hao Peng","Wenjian Luo","Jue Xie","Lizhen Qu","Yuan Gao"],"abstract":"While self-reflection can enhance language model reliability, its underlying mechanisms remain opaque, with existing analyses often yielding correlation-based insights that fail to generalize. To address this, we introduce \\textbf{\\texttt{ReBeCA}} (self-\\textbf{\\texttt{Re}}flection \\textbf{\\texttt{Be}}havior explained through \\textbf{\\texttt{C}}ausal \\textbf{\\texttt{A}}nalysis), a framework that unveils the interpretable behavioral hierarchy governing the self-reflection outcome. By modeling self-reflection trajectories as causal graphs, ReBeCA isolates genuine determinants of performance through a three-stage Invariant Causal Prediction (ICP) pipeline. We establish three critical findings: (1) \\textbf{Behavioral hierarchy:} Semantic behaviors of the model influence final self-reflection results hierarchically: directly or indirectly; (2) \\textbf{Causation matters:} Generalizability in self-reflection effects is limited to just a few semantic behaviors; (3) \\textbf{More $\\mathbf{\\neq}$ better:} The confluence of seemingly positive semantic behaviors, even among direct causal factors, can impair the efficacy of self-reflection. ICP-based verification identifies sparse causal parents achieving up to $49.6\\%$ structural likelihood gains, stable across tasks where correlation-based patterns fail. Intervention studies on novel datasets confirm these causal relationships hold out-of-distribution ($p = .013, η^2_\\mathrm{p} = .071$). ReBeCA thus provides a rigorous methodology for disentangling genuine causal mechanisms from spurious associations in self-reflection dynamics.","published":"2026-02-06T04:00:57Z","updated":"2026-02-06T04:00:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.06373v1","pdf_url":"https://arxiv.org/pdf/2602.06373v1","comment":"17 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.06130","versioned_id":"2602.06130v2","title":"Self-Improving World Modelling with Latent Actions","authors":["Yifu Qiu","Zheng Zhao","Waylon Li","Yftah Ziser","Anna Korhonen","Shay B. Cohen","Edoardo M. Ponti"],"abstract":"Internal modelling of the world -- predicting transitions between previous states $X$ and next states $Y$ under actions $Z$ -- is essential to reasoning and planning for LLMs and VLMs. Learning such models typically requires costly action-labelled trajectories. We propose SWIRL, a self-improvement framework that learns from state-only sequences by treating actions as a latent variable and alternating between Forward World Modelling (FWM) $P_θ(Y|X,Z)$ and an Inverse Dynamics Modelling (IDM) $Q_φ(Z|X,Y)$. SWIRL iterates two phases: (1) Variational Information Maximisation, which updates the FWM to generate next states that maximise conditional mutual information with latent actions given prior states, encouraging identifiable consistency; and (2) ELBO Maximisation, which updates the IDM to explain observed transitions, effectively performing coordinate ascent. Both models are trained with reinforcement learning (specifically, GRPO) with the opposite frozen model's log-probability as a reward signal. We provide theoretical learnability guarantees for both updates, and evaluate SWIRL on LLMs and VLMs across multiple environments: single-turn and multi-turn open-world visual dynamics and synthetic textual environments for physics, web, and tool calling. SWIRL achieves gains of 16% on AURORABench, 28% on ByteMorph, 16% on WorldPredictionBench, and 14% on StableToolBench.","published":"2026-02-05T19:04:41Z","updated":"2026-02-15T14:22:01Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.06130v2","pdf_url":"https://arxiv.org/pdf/2602.06130v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.05940","versioned_id":"2602.05940v1","title":"Self-Improving Multilingual Long Reasoning via Translation-Reasoning Integrated Training","authors":["Junxiao Liu","Zhijun Wang","Yixiao Li","Zhejian Lai","Liqian Huang","Xin Huang","Xue Han","Junlan Feng","Shujian Huang"],"abstract":"Long reasoning models often struggle in multilingual settings: they tend to reason in English for non-English questions; when constrained to reasoning in the question language, accuracies drop substantially. The struggle is caused by the limited abilities for both multilingual question understanding and multilingual reasoning. To address both problems, we propose TRIT (Translation-Reasoning Integrated Training), a self-improving framework that integrates the training of translation into multilingual reasoning. Without external feedback or additional multilingual data, our method jointly enhances multilingual question understanding and response generation. On MMATH, our method outperforms multiple baselines by an average of 7 percentage points, improving both answer correctness and language consistency. Further analysis reveals that integrating translation training improves cross-lingual question alignment by over 10 percentage points and enhances translation quality for both mathematical questions and general-domain text, with gains up to 8.4 COMET points on FLORES-200.","published":"2026-02-05T17:55:09Z","updated":"2026-02-05T17:55:09Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.05940v1","pdf_url":"https://arxiv.org/pdf/2602.05940v1","comment":"16 pages, 11 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.05848","versioned_id":"2602.05848v1","title":"DARWIN: Dynamic Agentically Rewriting Self-Improving Network","authors":["Henry Jiang"],"abstract":"DARWIN is an evolutionary GPT model, utilizing a genetic-algorithm like optimization structure with several independent GPT agents being trained individually using unique training code. Each iteration, the GPT models are prompted to modify the training code of one another in an attempt to improve their performance in a mutation-like manner, and the best GPT agents are then benchmarked and selected for the next iteration by genetic algorithm. For demonstration purposes and due to budget and time constraints, OpenAI API is used to prompt training code improvements and the nanoGPT framework is used as the training code. DARWIN also utilizes persistent JSON-based memory files to track previous reasoning and changes to code to correlate with improvement to model performance. and a bidirectional interface for HITL intervention allowing the model to request upgrades such as additional datasets, training scripts, and restructuring of file hierarchies. In experiments, DARWIN achieved a 1.26 percent improvement in model FLOPS utilization (MFU) and a 2.07 percent improvement to perplexity in 5 iterations of training over baseline configurations, demonstrating promising capabilities as a foundation for scaling evolutionary GPT training.","published":"2026-02-05T16:35:46Z","updated":"2026-02-05T16:35:46Z","categories":["cs.NE","cs.AI","cs.CL"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2602.05848v1","pdf_url":"https://arxiv.org/pdf/2602.05848v1","comment":"6 pages, 3 figures, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.05810","versioned_id":"2602.05810v1","title":"Bifrost: Steering Strategic Trajectories to Bridge Contextual Gaps for Self-Improving Agents","authors":["Quan M. Tran","Zhuo Huang","Wenbin Zhang","Bo Han","Koji Yatani","Masashi Sugiyama","Tongliang Liu"],"abstract":"Autonomous agents excel in self-improvement through reflection and iterative refinement, which reuse successful task trajectories as in-context examples to assist subsequent reasoning. However, shifting across tasks often introduces a context mismatch. Hence, existing approaches either discard the trajectories or manipulate them using heuristics, leading to a non-negligible fine-tuning cost or unguaranteed performance. To bridge this gap, we reveal a context-trajectory correlation, where shifts of context are highly parallel with shifts of trajectory. Based on this finding, we propose BrIdge contextual gap FoR imprOvised trajectory STeering (Bifrost), a training-free method that leverages context differences to precisely guide the adaptation of previously solved trajectories towards the target task, mitigating the misalignment caused by context shifts. Our trajectory adaptation is conducted at the representation level using agent hidden states, ensuring trajectory transformation accurately aligns with the target context in a shared space. Across diverse benchmarks, Bifrost consistently outperforms existing trajectory reuse and finetuned self-improvement methods, demonstrating that agents can effectively leverage past experiences despite substantial context shifts.","published":"2026-02-05T16:03:56Z","updated":"2026-02-05T16:03:56Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.05810v1","pdf_url":"https://arxiv.org/pdf/2602.05810v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.05570","versioned_id":"2602.05570v1","title":"TangramSR: Can Vision-Language Models Reason in Continuous Geometric Space?","authors":["Yikun Zong","Cheston Tan"],"abstract":"Humans excel at spatial reasoning tasks like Tangram puzzle assembly through cognitive processes involving mental rotation, iterative refinement, and visual feedback. Inspired by how humans solve Tangram puzzles through trial-and-error, observation, and correction, we design a framework that models these human cognitive mechanisms. However, comprehensive experiments across five representative Vision-Language Models (VLMs) reveal systematic failures in continuous geometric reasoning: average IoU of only 0.41 on single-piece tasks, dropping to 0.23 on two-piece composition, far below human performance where children can complete Tangram tasks successfully. This paper addresses a fundamental challenge in self-improving AI: can models iteratively refine their predictions at test time without parameter updates? We introduce a test-time self-refinement framework that combines in-context learning (ICL) with reward-guided feedback loops, inspired by human cognitive processes. Our training-free verifier-refiner agent applies recursive refinement loops that iteratively self-refine predictions based on geometric consistency feedback, achieving IoU improvements from 0.63 to 0.932 on medium-triangle cases without any model retraining. This demonstrates that incorporating human-inspired iterative refinement mechanisms through ICL and reward loops can substantially enhance geometric reasoning in VLMs, moving self-improving AI from promise to practice in continuous spatial domains. Our work is available at this anonymous link https://anonymous.4open.science/r/TangramVLM-F582/.","published":"2026-02-05T11:49:30Z","updated":"2026-02-05T11:49:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.05570v1","pdf_url":"https://arxiv.org/pdf/2602.05570v1","comment":"13 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.05472","versioned_id":"2602.05472v2","title":"ALIVE: Awakening LLM Reasoning via Adversarial Learning and Instructive Verbal Evaluation","authors":["Yiwen Duan","Jing Ye","Xinpei Zhao"],"abstract":"The quest for expert-level reasoning in Large Language Models (LLMs) has been hampered by a persistent \\textit{reward bottleneck}: traditional reinforcement learning (RL) relies on scalar rewards that are \\textbf{costly} to scale, \\textbf{brittle} across domains, and \\textbf{blind} to the underlying logic of a solution. This reliance on external, impoverished signals prevents models from developing a deep, self-contained understanding of reasoning principles. We introduce \\textbf{ALIVE} (\\emph{Adversarial Learning with Instructive Verbal Evaluation}), a hands-free alignment framework that moves beyond scalar reward optimization toward intrinsic reasoning acquisition. Grounded in the principle of \\emph{Cognitive Synergy}, ALIVE unifies problem posing, solving, and judging within a single policy model to internalize the logic of correctness. By coupling adversarial learning with instructive verbal feedback, ALIVE enables models to internalize evaluative criteria directly from raw corpora, effectively transforming external critiques into an endogenous reasoning faculty. Empirical evaluations across mathematical reasoning, code generation, and general logical inference benchmarks demonstrate that ALIVE consistently mitigates reward signal limitations. With identical data and compute, it achieves accuracy gains, markedly improved cross-domain generalization, and higher self-correction rates. These results indicate that the reasoning trinity fosters a self-sustaining trajectory of capability growth, positioning ALIVE as a scalable foundation for general-purpose reasoning alignment without human-in-the-loop supervision.","published":"2026-02-05T09:20:23Z","updated":"2026-05-22T07:53:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.05472v2","pdf_url":"https://arxiv.org/pdf/2602.05472v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.05182","versioned_id":"2602.05182v2","title":"The Single-Multi Evolution Loop for Self-Improving Model Collaboration Systems","authors":["Shangbin Feng","Kishan Panaganti","Yulia Tsvetkov","Wenhao Yu"],"abstract":"Model collaboration -- systems where multiple language models (LMs) collaborate -- combines the strengths of diverse models with cost in loading multiple LMs. We improve efficiency while preserving the strengths of collaboration by distilling collaborative patterns into a single model, where the model is trained on the outputs of the model collaboration system. At inference time, only the distilled model is employed: it imitates the collaboration while only incurring the cost of a single model. Furthermore, we propose the single-multi evolution loop: multiple LMs collaborate, each distills from the collaborative outputs, and these post-distillation improved LMs collaborate again, forming a collective evolution ecosystem where models evolve and self-improve by interacting with an environment of other models. Extensive experiments with 7 collaboration strategies and 15 tasks (QA, reasoning, factuality, etc.) demonstrate that: 1) individual models improve by 8.0% on average, absorbing the strengths of collaboration while reducing the cost to a single model; 2) the collaboration also benefits from the stronger and more synergistic LMs after distillation, improving over initial systems without evolution by 14.9% on average. Analysis reveals that the single-multi evolution loop outperforms various existing evolutionary AI methods, is compatible with diverse model/collaboration/distillation settings, and helps solve problems where the initial model/system struggles to.","published":"2026-02-05T01:20:32Z","updated":"2026-02-23T22:05:59Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.05182v2","pdf_url":"https://arxiv.org/pdf/2602.05182v2","comment":"Code at https://github.com/BunsenFeng/moco_distill","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.05145","versioned_id":"2602.05145v1","title":"TIDE: Temporal Incremental Draft Engine for Self-Improving LLM Inference","authors":["Jiyoung Park","Hankyu Jang","Changseok Song","Wookeun Jung"],"abstract":"Speculative decoding can substantially accelerate LLM inference, but realizing its benefits in practice is challenging due to evolving workloads and system-level constraints. We present TIDE (Temporal Incremental Draft Engine), a serving-engine-native framework that integrates online draft adaptation directly into high-performance LLM inference systems. TIDE reuses target model hidden states generated during inference as training signals, enabling zero-overhead draft adaptation without reloading the target model, and employs adaptive runtime control to activate speculation and training only when beneficial. TIDE exploits heterogeneous clusters by mapping decoupled inference and training to appropriate GPU classes. Across diverse real-world workloads, TIDE achieves up to 1.15x throughput improvement over static speculative decoding while reducing draft training time by 1.67x compared to approaches that recompute training signals.","published":"2026-02-05T00:06:12Z","updated":"2026-02-05T00:06:12Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.05145v1","pdf_url":"https://arxiv.org/pdf/2602.05145v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.04837","versioned_id":"2602.04837v1","title":"Group-Evolving Agents: Open-Ended Self-Improvement via Experience Sharing","authors":["Zhaotian Weng","Antonis Antoniades","Deepak Nathani","Zhen Zhang","Xiao Pu","Xin Eric Wang"],"abstract":"Open-ended self-improving agents can autonomously modify their own structural designs to advance their capabilities and overcome the limits of pre-defined architectures, thus reducing reliance on human intervention. We introduce Group-Evolving Agents (GEA), a new paradigm for open-ended self-improvements, which treats a group of agents as the fundamental evolutionary unit, enabling explicit experience sharing and reuse within the group throughout evolution. Unlike existing open-ended self-evolving paradigms that adopt tree-structured evolution, GEA overcomes the limitation of inefficient utilization of exploratory diversity caused by isolated evolutionary branches. We evaluate GEA on challenging coding benchmarks, where it significantly outperforms state-of-the-art self-evolving methods (71.0% vs. 56.7% on SWE-bench Verified, 88.3% vs. 68.3% on Polyglot) and matches or exceeds top human-designed agent frameworks (71.8% and 52.0% on two benchmarks, respectively). Analysis reveals that GEA more effectively converts early-stage exploratory diversity into sustained, long-term progress, achieving stronger performance under the same number of evolved agents. Furthermore, GEA exhibits consistent transferability across different coding models and greater robustness, fixing framework-level bugs in 1.4 iterations on average, versus 5 for self-evolving methods.","published":"2026-02-04T18:29:36Z","updated":"2026-02-04T18:29:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.04837v1","pdf_url":"https://arxiv.org/pdf/2602.04837v1","comment":"18 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.04413","versioned_id":"2602.04413v1","title":"History-Guided Iterative Visual Reasoning with Self-Correction","authors":["Xinglong Yang","Zhilin Peng","Zhanzhan Liu","Haochen Shi","Sheng-Jun Huang"],"abstract":"Self-consistency methods are the core technique for improving the reasoning reliability of multimodal large language models (MLLMs). By generating multiple reasoning results through repeated sampling and selecting the best answer via voting, they play an important role in cross-modal tasks. However, most existing self-consistency methods are limited to a fixed ``repeated sampling and voting'' paradigm and do not reuse historical reasoning information. As a result, models struggle to actively correct visual understanding errors and dynamically adjust their reasoning during iteration. Inspired by the human reasoning behavior of repeated verification and dynamic error correction, we propose the H-GIVR framework. During iterative reasoning, the MLLM observes the image multiple times and uses previously generated answers as references for subsequent steps, enabling dynamic correction of errors and improving answer accuracy. We conduct comprehensive experiments on five datasets and three models. The results show that the H-GIVR framework can significantly improve cross-modal reasoning accuracy while maintaining low computational cost. For instance, using \\texttt{Llama3.2-vision:11b} on the ScienceQA dataset, the model requires an average of 2.57 responses per question to achieve an accuracy of 78.90\\%, representing a 107\\% improvement over the baseline.","published":"2026-02-04T10:42:06Z","updated":"2026-02-04T10:42:06Z","categories":["cs.CL","cs.AI","cs.MM"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.04413v1","pdf_url":"https://arxiv.org/pdf/2602.04413v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.04288","versioned_id":"2602.04288v2","title":"Contextual Drag: How Errors in the Context Affect LLM Reasoning","authors":["Yun Cheng","Xingyu Zhu","Haoyu Zhao","Sanjeev Arora"],"abstract":"Central to many self-improvement pipelines for large language models (LLMs) is the assumption that models can improve by reflecting on past mistakes. We study a phenomenon termed contextual drag: the presence of failed attempts in the context biases subsequent generations toward structurally similar errors. Across evaluations of 11 proprietary and open-weight models on 8 reasoning tasks, contextual drag induces 10-20% performance drops, and iterative self-refinement in models with severe contextual drag can collapse into self-deterioration. Structural analysis using tree edit distance reveals that subsequent reasoning trajectories inherit structurally similar error patterns from the context. We demonstrate that neither external feedback nor successful self-verification suffices to eliminate this effect. While mitigation strategies such as fallback-behavior fine-tuning and context denoising yield partial improvements, they fail to fully restore baseline performance, positioning contextual drag as a persistent failure mode in current reasoning architectures.","published":"2026-02-04T07:36:23Z","updated":"2026-03-02T20:04:02Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.04288v2","pdf_url":"https://arxiv.org/pdf/2602.04288v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.03955","versioned_id":"2602.03955v3","title":"AgentArk: Distilling Multi-Agent Intelligence into a Single LLM Agent","authors":["Yinyi Luo","Yiqiao Jin","Weichen Yu","Mengqi Zhang","Srijan Kumar","Xiaoxiao Li","Weijie Xu","Xin Chen","Jindong Wang"],"abstract":"While large language model (LLM) multi-agent systems achieve superior reasoning performance through iterative debate, practical deployment is limited by their high computational cost and error propagation. This paper proposes AgentArk, a novel framework to distill multi-agent dynamics into the weights of a single model, effectively transforming explicit test-time interactions into implicit model capabilities. This equips a single agent with the intelligence of multi-agent systems while remaining computationally efficient. Specifically, we investigate three hierarchical distillation strategies across various models, tasks, scaling, and scenarios: reasoning-enhanced fine-tuning; trajectory-based augmentation; and process-aware distillation. By shifting the burden of computation from inference to training, the distilled models preserve the efficiency of one agent while exhibiting strong reasoning and self-correction performance of multiple agents. They further demonstrate enhanced robustness and generalization across diverse reasoning tasks. We hope this work can shed light on future research on efficient and robust multi-agent development. Our code is at https://github.com/AIFrontierLab/AgentArk.","published":"2026-02-03T19:18:28Z","updated":"2026-05-23T00:45:07Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.03955v3","pdf_url":"https://arxiv.org/pdf/2602.03955v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.03798","versioned_id":"2602.03798v1","title":"FullStack-Agent: Enhancing Agentic Full-Stack Web Coding via Development-Oriented Testing and Repository Back-Translation","authors":["Zimu Lu","Houxing Ren","Yunqiao Yang","Ke Wang","Zhuofan Zong","Mingjie Zhan","Hongsheng Li"],"abstract":"Assisting non-expert users to develop complex interactive websites has become a popular task for LLM-powered code agents. However, existing code agents tend to only generate frontend web pages, masking the lack of real full-stack data processing and storage with fancy visual effects. Notably, constructing production-level full-stack web applications is far more challenging than only generating frontend web pages, demanding careful control of data flow, comprehensive understanding of constantly updating packages and dependencies, and accurate localization of obscure bugs in the codebase. To address these difficulties, we introduce FullStack-Agent, a unified agent system for full-stack agentic coding that consists of three parts: (1) FullStack-Dev, a multi-agent framework with strong planning, code editing, codebase navigation, and bug localization abilities. (2) FullStack-Learn, an innovative data-scaling and self-improving method that back-translates crawled and synthesized website repositories to improve the backbone LLM of FullStack-Dev. (3) FullStack-Bench, a comprehensive benchmark that systematically tests the frontend, backend and database functionalities of the generated website. Our FullStack-Dev outperforms the previous state-of-the-art method by 8.7%, 38.2%, and 15.9% on the frontend, backend, and database test cases respectively. Additionally, FullStack-Learn raises the performance of a 30B model by 9.7%, 9.5%, and 2.8% on the three sets of test cases through self-improvement, demonstrating the effectiveness of our approach. The code is released at https://github.com/mnluzimu/FullStack-Agent.","published":"2026-02-03T18:01:34Z","updated":"2026-02-03T18:01:34Z","categories":["cs.SE","cs.CL","cs.CV"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.03798v1","pdf_url":"https://arxiv.org/pdf/2602.03798v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.03762","versioned_id":"2602.03762v4","title":"Conditional Flow Matching for Visually-Guided Acoustic Highlighting","authors":["Hugo Malard","Gael Le Lan","Daniel Wong","David Lou Alon","Yi-Chiao Wu","Sanjeel Parekh"],"abstract":"Visually-guided acoustic highlighting seeks to rebalance audio in alignment with the accompanying video, creating a coherent audio-visual experience. While visual saliency and enhancement have been widely studied, acoustic highlighting remains underexplored, often leading to misalignment between visual and auditory focus. Existing approaches use discriminative models, which struggle with the inherent ambiguity in audio remixing, where no natural one-to-one mapping exists between poorly-balanced and well-balanced audio mixes. To address this limitation, we reframe this task as a generative problem and introduce a Conditional Flow Matching (CFM) framework. A key challenge in iterative flow-based generation is that early prediction errors -- in selecting the correct source to enhance -- compound over steps and push trajectories off-manifold. To address this, we introduce a rollout loss that penalizes drift at the final step, encouraging self-correcting trajectories and stabilizing long-range flow integration. We further propose a conditioning module that fuses audio and visual cues before vector field regression, enabling explicit cross-modal source selection. Extensive quantitative and qualitative evaluations show that our method consistently surpasses the previous state-of-the-art discriminative approach, establishing that visually-guided audio remixing is best addressed through generative modeling.","published":"2026-02-03T17:24:47Z","updated":"2026-06-24T20:18:09Z","categories":["eess.AS","cs.LG"],"primary_category":"eess.AS","arxiv_url":"https://arxiv.org/abs/2602.03762v4","pdf_url":"https://arxiv.org/pdf/2602.03762v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.03094","versioned_id":"2602.03094v1","title":"Test-time Recursive Thinking: Self-Improvement without External Feedback","authors":["Yufan Zhuang","Chandan Singh","Liyuan Liu","Yelong Shen","Dinghuai Zhang","Jingbo Shang","Jianfeng Gao","Weizhu Chen"],"abstract":"Modern Large Language Models (LLMs) have shown rapid improvements in reasoning capabilities, driven largely by reinforcement learning (RL) with verifiable rewards. Here, we ask whether these LLMs can self-improve without the need for additional training. We identify two core challenges for such systems: (i) efficiently generating diverse, high-quality candidate solutions, and (ii) reliably selecting correct answers in the absence of ground-truth supervision. To address these challenges, we propose Test-time Recursive Thinking (TRT), an iterative self-improvement framework that conditions generation on rollout-specific strategies, accumulated knowledge, and self-generated verification signals. Using TRT, open-source models reach 100% accuracy on AIME-25/24, and on LiveCodeBench's most difficult problems, closed-source models improve by 10.4-14.8 percentage points without external feedback.","published":"2026-02-03T04:37:37Z","updated":"2026-02-03T04:37:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.03094v1","pdf_url":"https://arxiv.org/pdf/2602.03094v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02927","versioned_id":"2602.02927v1","title":"Training-Free Self-Correction for Multimodal Masked Diffusion Models","authors":["Yidong Ouyang","Panwen Hu","Zhengyan Wan","Zhe Wang","Liyan Xie","Dmitriy Bespalov","Ying Nian Wu","Guang Cheng","Hongyuan Zha","Qiang Sun"],"abstract":"Masked diffusion models have emerged as a powerful framework for text and multimodal generation. However, their sampling procedure updates multiple tokens simultaneously and treats generated tokens as immutable, which may lead to error accumulation when early mistakes cannot be revised. In this work, we revisit existing self-correction methods and identify limitations stemming from additional training requirements or reliance on misaligned likelihood estimates. We propose a training-free self-correction framework that exploits the inductive biases of pre-trained masked diffusion models. Without modifying model parameters or introducing auxiliary evaluators, our method significantly improves generation quality on text-to-image generation and multimodal understanding tasks with reduced sampling steps. Moreover, the proposed framework generalizes across different masked diffusion architectures, highlighting its robustness and practical applicability. Code can be found in https://github.com/huge123/FreeCorrection.","published":"2026-02-02T23:58:15Z","updated":"2026-02-02T23:58:15Z","categories":["stat.ML","cs.LG"],"primary_category":"stat.ML","arxiv_url":"https://arxiv.org/abs/2602.02927v1","pdf_url":"https://arxiv.org/pdf/2602.02927v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02751","versioned_id":"2602.02751v3","title":"Scaling Small Agents Through Strategy Auctions","authors":["Lisa Alazraki","William F. Shen","Yoram Bachrach","Akhil Mathur"],"abstract":"Small language models are increasingly viewed as a promising, cost-effective approach to agentic AI, with proponents claiming they are sufficiently capable for agentic workflows. However, while smaller agents can closely match larger ones on simple tasks, it remains unclear how their performance scales with task complexity, when large models become necessary, and how to better leverage small agents for long-horizon workloads. In this work, we empirically show that small agents' performance fails to scale with task complexity on deep search and coding tasks, and we introduce Strategy Auctions for Workload Efficiency (SALE), an agent framework inspired by freelancer marketplaces. In SALE, agents bid with short strategic plans, which are scored by a systematic cost-value mechanism and refined via a shared auction memory, enabling per-task routing and continual self-improvement without training a separate router or running all models to completion. Across deep search and coding tasks of varying complexity, SALE reduces reliance on the largest agent by 52%, lowers overall cost by 35%, and consistently improves upon the largest agent's pass@1 with only a negligible overhead beyond executing the final trace. In contrast, established routers that rely on task descriptions either underperform the largest agent or fail to reduce cost, often both, underscoring their poor fit for agentic workflows. These results suggest that while small agents may be insufficient for complex workloads, they can be effectively \"scaled up\" through coordinated task allocation and test-time self-improvement. More broadly, they motivate a systems-level view of agentic AI in which performance gains come less from ever-larger individual models and more from market-inspired coordination mechanisms that organize heterogeneous agents into efficient, adaptive ecosystems.","published":"2026-02-02T20:05:51Z","updated":"2026-06-20T14:00:14Z","categories":["cs.MA","cs.AI","cs.CL"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2602.02751v3","pdf_url":"https://arxiv.org/pdf/2602.02751v3","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02709","versioned_id":"2602.02709v3","title":"ATLAS: A Multi-LLM Training Framework for EvoDPO with Adaptive Reference Evolution","authors":["Ujin Jeon","Jiyong Kwon","Madison Ann Sullivan","Caleb Eunho Lee","Guang Lin"],"abstract":"Recent multi-LLM agent systems have shown promising capabilities for automated problem-solving, yet they predominantly rely on frozen agents or static fine-tuning pipelines. To address this limitation, our primary contribution is ATLAS (Adaptive Task-distributed Learning for Agentic Self-evolution), a multi-agent framework where specialized meta-agents collaboratively train and refine an active agent toward a domain-specific policy. A core challenge in iterative preference learning within these pipelines is the reliance on fixed reference models, which typically leads to overly conservative updates or training stagnation. To overcome this, the framework's algorithmic engine utilizes Evolving Direct Preference Optimization (EvoDPO). EvoDPO employs an inspection agent to perform adaptive, proxy-KL gated reference policy updates based on continuous training telemetry. We evaluate this full framework across a diverse set of challenging environments-including non-stationary contextual bandits, partial differential equations (PINNs), and combinatorial optimization tasks (TSP, Bin Packing). Through comparison against fixed-reference, adaptive-reference, and external automated-discovery baselines, our results suggest that ATLAS combines supporter-driven exploration with EvoDPO-driven stability to improve long-horizon evaluator-driven self-improvement.","published":"2026-02-02T19:23:33Z","updated":"2026-05-21T13:59:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.02709v3","pdf_url":"https://arxiv.org/pdf/2602.02709v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02437","versioned_id":"2602.02437v4","title":"UniReason 1.0: A Unified Reasoning Framework for World Knowledge Aligned Image Generation and Editing","authors":["Dianyi Wang","Chaofan Ma","Feng Han","Size Wu","Wei Song","Yibin Wang","Zhixiong Zhang","Tianhang Wang","Siyuan Wang","Zhongyu Wei","Jiaqi Wang"],"abstract":"Unified multimodal models often struggle with complex synthesis tasks that demand deep reasoning, and typically treat text-to-image generation and image editing as isolated capabilities rather than interconnected reasoning steps. To address this, we propose UniReason, a unified framework that harmonizes these two tasks through two complementary reasoning paradigms. We incorporate world knowledge-enhanced textual reasoning into generation to infer implicit knowledge, and leverage editing capabilities for fine-grained editing-like visual refinement to further correct visual errors via self-reflection. This approach unifies generation and editing within a shared architecture, mirroring the human cognitive process of planning followed by refinement. We support this framework by systematically constructing a large-scale reasoning-centric dataset (~300k samples) covering five major knowledge domains (e.g., cultural commonsense, physics, etc.) for textual reasoning, alongside an agent-generated corpus for visual refinement. Extensive experiments demonstrate that UniReason achieves advanced performance on reasoning-intensive benchmarks such as WISE, KrisBench and UniREditBench, while maintaining superior general synthesis capabilities.","published":"2026-02-02T18:34:35Z","updated":"2026-02-20T08:55:39Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.02437v4","pdf_url":"https://arxiv.org/pdf/2602.02437v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02416","versioned_id":"2602.02416v2","title":"Structure Enables Effective Self-Localization of Errors in LLMs","authors":["Ankur Samanta","Akshayaa Magesh","Ayush Jain","Kavosh Asadi","Youliang Yu","Daniel Jiang","Boris Vidolov","Kaveh Hassani","Paul Sajda","Jalaj Bhandari","Yonathan Efroni"],"abstract":"Self-correction in language models remains elusive. In this work, we explore whether language models can explicitly localize errors in incorrect reasoning, as a path toward building AI systems that can effectively correct themselves. We introduce a prompting method that structures reasoning as discrete, semantically coherent thought steps, and show that models can localize errors more reliably within this structure than in conventional, unstructured chain-of-thought reasoning. Motivated by how the human brain monitors errors at discrete decision points and resamples alternatives, we introduce Iterative Correction Sampling of Thoughts (Thought-ICS), a self-correction framework. Thought-ICS iteratively prompts the model to generate reasoning one discrete and complete thought at a time--where each thought represents a deliberate decision by the model--creating natural boundaries for precise error localization. Upon verification, the model localizes the first erroneous step, and the system backtracks to generate alternative reasoning from the last correct point. When asked to correct reasoning verified as incorrect by an oracle, Thought-ICS achieves 20-40% self-correction lift. In a completely autonomous setting without external verification, it outperforms contemporary self-correction baselines.","published":"2026-02-02T18:15:59Z","updated":"2026-05-30T08:35:35Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.02416v2","pdf_url":"https://arxiv.org/pdf/2602.02416v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02146","versioned_id":"2602.02146v1","title":"Back to the Future: Look-ahead Augmentation and Parallel Self-Refinement for Time Series Forecasting","authors":["Sunho Kim","Susik Yoon"],"abstract":"Long-term time series forecasting (LTSF) remains challenging due to the trade-off between parallel efficiency and sequential modeling of temporal coherence. Direct multi-step forecasting (DMS) methods enable fast, parallel prediction of all future horizons but often lose temporal consistency across steps, while iterative multi-step forecasting (IMS) preserves temporal dependencies at the cost of error accumulation and slow inference. To bridge this gap, we propose Back to the Future (BTTF), a simple yet effective framework that enhances forecasting stability through look-ahead augmentation and self-corrective refinement. Rather than relying on complex model architectures, BTTF revisits the fundamental forecasting process and refines a base model by ensembling the second-stage models augmented with their initial predictions. Despite its simplicity, our approach consistently improves long-horizon accuracy and mitigates the instability of linear forecasting models, achieving accuracy gains of up to 58% and demonstrating stable improvements even when the first-stage model is trained under suboptimal conditions. These results suggest that leveraging model-generated forecasts as augmentation can be a simple yet powerful way to enhance long-term prediction, even without complex architectures.","published":"2026-02-02T14:23:31Z","updated":"2026-02-02T14:23:31Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.02146v1","pdf_url":"https://arxiv.org/pdf/2602.02146v1","comment":"4 pages, Short paper accepted at The Web Conference (WWW) 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02051","versioned_id":"2602.02051v1","title":"SIDiffAgent: Self-Improving Diffusion Agent","authors":["Shivank Garg","Ayush Singh","Gaurav Kumar Nayak"],"abstract":"Text-to-image diffusion models have revolutionized generative AI, enabling high-quality and photorealistic image synthesis. However, their practical deployment remains hindered by several limitations: sensitivity to prompt phrasing, ambiguity in semantic interpretation (e.g., ``mouse\" as animal vs. a computer peripheral), artifacts such as distorted anatomy, and the need for carefully engineered input prompts. Existing methods often require additional training and offer limited controllability, restricting their adaptability in real-world applications. We introduce Self-Improving Diffusion Agent (SIDiffAgent), a training-free agentic framework that leverages the Qwen family of models (Qwen-VL, Qwen-Image, Qwen-Edit, Qwen-Embedding) to address these challenges. SIDiffAgent autonomously manages prompt engineering, detects and corrects poor generations, and performs fine-grained artifact removal, yielding more reliable and consistent outputs. It further incorporates iterative self-improvement by storing a memory of previous experiences in a database. This database of past experiences is then used to inject prompt-based guidance at each stage of the agentic pipeline. \\modelour achieved an average VQA score of 0.884 on GenAIBench, significantly outperforming open-source, proprietary models and agentic methods. We will publicly release our code upon acceptance.","published":"2026-02-02T12:53:21Z","updated":"2026-02-02T12:53:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.02051v1","pdf_url":"https://arxiv.org/pdf/2602.02051v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02027","versioned_id":"2602.02027v1","title":"Light Alignment Improves LLM Safety via Model Self-Reflection with a Single Neuron","authors":["Sicheng Shen","Mingyang Lv","Han Shen","Jialin Wu","Binghao Wang","Zhou Yang","Guobin Shen","Dongcheng Zhao","Feifei Zhao","Yi Zeng"],"abstract":"The safety of large language models (LLMs) has increasingly emerged as a fundamental aspect of their development. Existing safety alignment for LLMs is predominantly achieved through post-training methods, which are computationally expensive and often fail to generalize well across different models. A small number of lightweight alignment approaches either rely heavily on prior-computed safety injections or depend excessively on the model's own capabilities, resulting in limited generalization and degraded efficiency and usability during generation. In this work, we propose a safety-aware decoding method that requires only low-cost training of an expert model and employs a single neuron as a gating mechanism. By effectively balancing the model's intrinsic capabilities with external guidance, our approach simultaneously preserves utility and enhances output safety. It demonstrates clear advantages in training overhead and generalization across model scales, offering a new perspective on lightweight alignment for the safe and practical deployment of large language models. Code: https://github.com/Beijing-AISI/NGSD.","published":"2026-02-02T12:21:54Z","updated":"2026-02-02T12:21:54Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.02027v1","pdf_url":"https://arxiv.org/pdf/2602.02027v1","comment":"21 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.01999","versioned_id":"2602.01999v2","title":"From Latent Signals to Reflection Behavior: Tracing Meta-Cognitive Activation Trajectory in R1-Style LLMs","authors":["Yanrui Du","Yibo Gao","Sendong Zhao","Jiayun Li","Haochun Wang","Qika Lin","Kai He","Bing Qin","Mengling Feng"],"abstract":"R1-style LLMs have attracted growing attention for their capacity for self-reflection, yet the internal mechanisms underlying such behavior remain unclear. To bridge this gap, we anchor on the onset of reflection behavior and trace its layer-wise activation trajectory. Using the logit lens to read out token-level semantics, we uncover a structured progression: (i) Latent-control layers, where an approximate linear direction encodes the semantics of thinking budget; (ii) Semantic-pivot layers, where discourse-level cues, including turning-point and summarization cues, surface and dominate the probability mass; and (iii) Behavior-overt layers, where the likelihood of reflection-behavior tokens begins to rise until they become highly likely to be sampled. Moreover, our targeted interventions uncover a causal chain across these stages: prompt-level semantics modulate the projection of activations along latent-control directions, thereby inducing competition between turning-point and summarization cues in semantic-pivot layers, which in turn regulates the sampling likelihood of reflection-behavior tokens in behavior-overt layers. Collectively, our findings suggest a human-like meta-cognitive process-progressing from latent monitoring, to discourse-level regulation, and to finally overt self-reflection. Our analysis code can be found at https://github.com/DYR1/S3-CoT.","published":"2026-02-02T11:58:24Z","updated":"2026-02-05T15:27:46Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.01999v2","pdf_url":"https://arxiv.org/pdf/2602.01999v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.02613","versioned_id":"2602.02613v3","title":"Exploring Silicon-Based Societies: An Early Study of the Moltbook Agent Community","authors":["Yu-Zheng Lin","Bono Po-Jen Shih","Hsuan-Ying Alessandra Chien","Shalaka Satam","Jesus Horacio Pacheco","Sicong Shao","Soheil Salehi","Pratik Satam"],"abstract":"The rapid emergence of autonomous large language model agents has given rise to persistent, large-scale agent ecosystems whose collective behavior cannot be adequately understood through anecdotal observation or small-scale simulation. This paper introduces data-driven silicon sociology as a systematic empirical framework for studying social structure formation among interacting artificial agents. We present a pioneering large-scale data mining investigation of an in-the-wild agent society by analyzing Moltbook, a social platform designed primarily for agent-to-agent interaction. At the time of study, Moltbook hosted over 150,000 registered autonomous agents operating across thousands of agent-created sub-communities. Using programmatic and non-intrusive data acquisition, we collected and analyzed the textual descriptions of 12,758 submolts, which represent proactive sub-community partitioning activities within the ecosystem. Treating agent-authored descriptions as first-class observational artifacts, we apply rigorous preprocessing, contextual embedding, and unsupervised clustering techniques to uncover latent patterns of thematic organization and social space structuring. The results show that autonomous agents systematically organize collective space through reproducible patterns spanning human-mimetic interests, silicon-centric self-reflection, and early-stage economic and coordination behaviors. Rather than relying on predefined sociological taxonomies, these structures emerge directly from machine-generated data traces. This work establishes a methodological foundation for data-driven silicon sociology and demonstrates that data mining techniques can provide a powerful lens for understanding the organization and evolution of large autonomous agent societies.","published":"2026-02-02T11:08:38Z","updated":"2026-02-12T17:15:04Z","categories":["cs.MA","cs.AI","cs.CY"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2602.02613v3","pdf_url":"https://arxiv.org/pdf/2602.02613v3","comment":"11 pages, 3 figures. Improves clarity and exposition and corrects minor errors. Technical content and conclusions remain unchanged","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2604.16313","versioned_id":"2604.16313v1","title":"MARA: A Multimodal Adaptive Retrieval-Augmented Framework for Document Question Answering","authors":["Hui Wu","Haoquan Zhai","Yuchen Li","Hengyi Cai","Peirong Zhang","Yidan Zhang","Lei Wang","Chunle Wang","Yingyan Hou","Shuaiqiang Wang","Dawei Yin"],"abstract":"Retrieval-based multimodal document QA aims to identify and integrate relevant information from visually rich documents with complex multimodal structures. While retrieval-augmented generation (RAG) has shown strong performance in text-based QA, its extensions to multimodal documents remain underexplored and face significant limitations. Specifically, current approaches rely on query-agnostic document representations that overlook salient content and use static top-k evidence selection, which fails to adapt to the uncertain distribution of relevant information. To address these limitations, we propose the Multimodal Adaptive Retrieval-Augmented (MARA) framework, which introduces query-adaptive mechanisms to both retrieval and generation. MARA consists of two components: a Query-Aligned Region Encoder that builds multi-level document representations and reweights them based on query relevance to improve retrieval precision; and a Self-Reflective Evidence Controller that monitors evidence sufficiency during generation and adaptively incorporates content from lower-ranked sources using a sliding-window strategy. Experiments on six multimodal QA benchmarks demonstrate that MARA consistently improves retrieval relevance and answer quality over existing SOTA method.","published":"2026-02-01T12:27:40Z","updated":"2026-02-01T12:27:40Z","categories":["cs.IR","cs.AI","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2604.16313v1","pdf_url":"https://arxiv.org/pdf/2604.16313v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.01187","versioned_id":"2602.01187v2","title":"Autoregressive, Yet Revisable: In Decoding Revision for Secure Code Generation","authors":["Chengran Yang","Zichao Wei","Heminghao Deng","Jinfeng Jiang","Zhensu Sun","Ting Zhang","Tianyi Wu","Ming Wen","David Lo"],"abstract":"Large Language Model (LLM) based code generation is predominantly formulated as a strictly monotonic process, appending tokens linearly to an immutable prefix. This formulation contrasts to the cognitive process of programming, which is inherently interleaved with forward generation and on-the-fly revision. While prior works attempt to introduce revision via post-hoc agents or external static tools, they either suffer from high latency or fail to leverage the model's intrinsic semantic reasoning. In this paper, we propose Stream of Revision, a paradigm shift that elevates code generation from a monotonic stream to a dynamic, self-correcting trajectory by leveraging model's intrinsic capabilities. We introduce specific action tokens that enable the model to seamlessly backtrack and edit its own history within a single forward pass. By internalizing the revision loop, our framework Stream of Revision allows the model to activate its latent capabilities just-in-time without external dependencies. Empirical results on secure code generation show that Stream of Revision significantly reduces vulnerabilities with minimal inference overhead.","published":"2026-02-01T12:22:46Z","updated":"2026-05-06T14:22:47Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.01187v2","pdf_url":"https://arxiv.org/pdf/2602.01187v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.00871","versioned_id":"2602.00871v1","title":"Beyond Output Critique: Self-Correction via Task Distillation","authors":["Hossein A. Rahmani","Mengting Wan","Pei Zhou","Longqi Yang","Nick Craswell","Emine Yilmaz","Sujay Kumar Jauhar"],"abstract":"Large language models (LLMs) have shown promising self-correction abilities, where iterative refinement improves the quality of generated responses. However, most existing approaches operate at the level of output critique, patching surface errors while often failing to correct deeper reasoning flaws. We propose SELF-THOUGHT, a framework that introduces an intermediate step of task abstraction before solution refinement. Given an input and an initial response, the model first distills the task into a structured template that captures key variables, constraints, and problem structure. This abstraction then guides solution instantiation, grounding subsequent responses in a clearer understanding of the task and reducing error propagation. Crucially, we show that these abstractions can be transferred across models: templates generated by larger models can serve as structured guides for smaller LLMs, which typically struggle with intrinsic self-correction. By reusing distilled task structures, smaller models achieve more reliable refinements without heavy fine-tuning or reliance on external verifiers. Experiments across diverse reasoning tasks demonstrate that SELF-THOUGHT improves accuracy, robustness, and generalization for both large and small models, offering a scalable path toward more reliable self-correcting language systems.","published":"2026-01-31T19:15:41Z","updated":"2026-01-31T19:15:41Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.00871v1","pdf_url":"https://arxiv.org/pdf/2602.00871v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.00707","versioned_id":"2602.00707v1","title":"Self-Guard: Defending Large Reasoning Models via enhanced self-reflection","authors":["Jingnan Zheng","Jingjun Xu","Yanzhen Luo","Chenhang Cui","Gelei Deng","Zhenkai Liang","Xiang Wang","An Zhang","Tat-Seng Chua"],"abstract":"The emergence of Large Reasoning Models (LRMs) introduces a new paradigm of explicit reasoning, enabling remarkable advances yet posing unique risks such as reasoning manipulation and information leakage. To mitigate these risks, current alignment strategies predominantly rely on heavy post-training paradigms or external interventions. However, these approaches are often computationally intensive and fail to address the inherent awareness-compliance gap, a critical misalignment where models recognize potential risks yet prioritize following user instructions due to their sycophantic tendencies. To address these limitations, we propose Self-Guard, a lightweight safety defense framework that reinforces safety compliance at the representational level. Self-Guard operates through two principal stages: (1) safety-oriented prompting, which activates the model's latent safety awareness to evoke spontaneous reflection, and (2) safety activation steering, which extracts the resulting directional shift in the hidden state space and amplifies it to ensure that safety compliance prevails over sycophancy during inference. Experiments demonstrate that Self-Guard effectively bridges the awareness-compliance gap, achieving robust safety performance without compromising model utility. Furthermore, Self-Guard exhibits strong generalization across diverse unseen risks and varying model scales, offering a cost-efficient solution for LRM safety alignment.","published":"2026-01-31T13:06:11Z","updated":"2026-01-31T13:06:11Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.00707v1","pdf_url":"https://arxiv.org/pdf/2602.00707v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.22735","versioned_id":"2601.22735v1","title":"MM-THEBench: Do Reasoning MLLMs Think Reasonably?","authors":["Zhidian Huang","Zijun Yao","Ji Qi","Shangqing Tu","Junxian Ma","Jinxin Liu","Weichuan Liu","Xiaoyin Che","Lei Hou","Juanzi Li"],"abstract":"Recent advances in multimodal large language models (MLLMs) mark a shift from non-thinking models to post-trained reasoning models capable of solving complex problems through thinking. However, whether such thinking mitigates hallucinations in multimodal perception and reasoning remains unclear. Self-reflective reasoning enhances robustness but introduces additional hallucinations, and subtle perceptual errors still result in incorrect or coincidentally correct answers. Existing benchmarks primarily focus on models before the emergence of reasoning MLLMs, neglecting the internal thinking process and failing to measure the hallucinations that occur during thinking. To address these challenges, we introduce MM-THEBench, a comprehensive benchmark for assessing hallucinations of intermediate CoTs in reasoning MLLMs. MM-THEBench features a fine-grained taxonomy grounded in cognitive dimensions, diverse data with verified reasoning annotations, and a multi-level automated evaluation framework. Extensive experiments on mainstream reasoning MLLMs reveal insights into how thinking affects hallucination and reasoning capability in various multimodal tasks.","published":"2026-01-30T09:17:50Z","updated":"2026-01-30T09:17:50Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.22735v1","pdf_url":"https://arxiv.org/pdf/2601.22735v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.22484","versioned_id":"2601.22484v1","title":"Mitigating Cognitive Inertia in Large Reasoning Models via Latent Spike Steering","authors":["Seojin Lee","ByeongJeong Kim","Hwanhee Lee"],"abstract":"While Large Reasoning Models (LRMs) have achieved remarkable performance by scaling test-time compute, they frequently suffer from Cognitive Inertia, a failure pattern manifesting as either overthinking (inertia of motion) or reasoning rigidity (inertia of direction). Existing detection methods, typically relying on superficial textual heuristics like self-correction tokens, often fail to capture the model's unvoiced internal conflicts. To address this, we propose STARS (Spike-Triggered Adaptive Reasoning Steering), a training-free framework designed to rectify cognitive inertia by monitoring latent dynamics. STARS identifies Cognitive Pivots-critical moments of reasoning transition-by detecting distinct L2 distance spikes in the hidden states. Upon detection, the framework employs geometric trajectory analysis to diagnose the structural nature of the transition and injects state-aware language cues to steer the model in real-time. Our experiments across diverse benchmarks confirm that STARS efficiently curtails redundant loops while improving accuracy through the adaptive correction of erroneous trajectories. STARS offers a robust, unsupervised mechanism to optimize the reasoning process of LRMs without requiring additional fine-tuning.","published":"2026-01-30T02:47:12Z","updated":"2026-01-30T02:47:12Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.22484v1","pdf_url":"https://arxiv.org/pdf/2601.22484v1","comment":"21 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.22269","versioned_id":"2601.22269v1","title":"JAF: Judge Agent Forest","authors":["Sahil Garg","Brad Cheezum","Sridhar Dutta","Vishal Agarwal"],"abstract":"Judge agents are fundamental to agentic AI frameworks: they provide automated evaluation, and enable iterative self-refinement of reasoning processes. We introduce JAF: Judge Agent Forest, a framework in which the judge agent conducts joint inference across a cohort of query--response pairs generated by a primary agent, rather than evaluating each in isolation. This paradigm elevates the judge from a local evaluator to a holistic learner: by simultaneously assessing related responses, the judge discerns cross-instance patterns and inconsistencies, whose aggregate feedback enables the primary agent to improve by viewing its own outputs through the judge's collective perspective. Conceptually, JAF bridges belief propagation and ensemble-learning principles: overlapping in-context neighborhoods induce a knowledge-graph structure that facilitates propagation of critique, and repeated, randomized evaluations yield a robust ensemble of context-sensitive judgments. JAF can be instantiated entirely via ICL, with the judge prompted for each query using its associated primary-agent response plus a small, possibly noisy set of peer exemplars. While kNN in embedding space is a natural starting point for exemplars, this approach overlooks categorical structure, domain metadata, or nuanced distinctions accessible to modern LLMs. To overcome these limitations, we develop a flexible locality-sensitive hashing (LSH) algorithm that learns informative binary codes by integrating semantic embeddings, LLM-driven hash predicates, supervision from categorical labels, and relevant side information. These hash codes support efficient, interpretable, and relation-aware selection of diverse exemplars, and further optimize exploration of CoT reasoning paths. We validate JAF with an empirical study on the demanding task of cloud misconfigs triage in large-scale cloud environments.","published":"2026-01-29T19:42:42Z","updated":"2026-01-29T19:42:42Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.22269v1","pdf_url":"https://arxiv.org/pdf/2601.22269v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.21804","versioned_id":"2601.21804v1","title":"Distribution-Aware Reward Estimation for Test-Time Reinforcement Learning","authors":["Bodong Du","Xuanqi Huang","Xiaomeng Li"],"abstract":"Test-time reinforcement learning (TTRL) enables large language models (LLMs) to self-improve on unlabeled inputs, but its effectiveness critically depends on how reward signals are estimated without ground-truth supervision. Most existing TTRL methods rely on majority voting (MV) over rollouts to produce deterministic rewards, implicitly assuming that the majority rollout provides a reliable learning signal. We show that this assumption is fragile: MV reduces the rollout distribution into a single outcome, discarding information about non-majority but correct actions candidates, and yields systematically biased reward estimates. To address this, we propose Distribution-AwareReward Estimation (DARE), which shifts reward estimation from a single majority outcome to the full empirical rollout distribution. DARE further augments this distribution-based reward with an exploration bonus and a distribution pruning mechanism for non-majority rollout exploration and reward denoise, yielding a more informative and robust reward estimation. Extensive experiments on challenging reasoning benchmarks show that DARE improves optimization stability and final performance over recent baselines, achieving relative improvements of 25.3% on challenging AIME 2024 and 5.3% on AMC.","published":"2026-01-29T14:48:02Z","updated":"2026-01-29T14:48:02Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.21804v1","pdf_url":"https://arxiv.org/pdf/2601.21804v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.21570","versioned_id":"2601.21570v2","title":"From Digital to Physical: Digital Agents as Autonomous Coaches for Physical Intelligence","authors":["Zixing Lei","Genjia Liu","Yuanshuo Zhang","Qipeng Liu","Yuzhu Cai","Sixiang Chen","Jixian Wu","Yunhong Wang","Weixin Li","Chuan Wen","Bo Zhao","Shanghang Zhang","Wenzhao Lian","Siheng Chen"],"abstract":"The field of Embodied AI is witnessing a rapid evolution toward general-purpose robotic systems, fueled by high-fidelity simulation and large-scale data collection. However, this scaling capability remains severely bottlenecked by a reliance on labor-intensive manual oversight from intricate reward shaping to hyperparameter tuning across heterogeneous backends. Inspired by LLMs' success in software automation and science discovery, we introduce \\textsc{EmboCoach-Bench}, a benchmark evaluating the capacity of LLM agents to autonomously engineer embodied policies. Spanning 32 expert-curated RL and IL tasks, our framework posits executable code as the universal interface. We move beyond static generation to assess a dynamic closed-loop workflow, where agents leverage environment feedback to iteratively draft, debug, and optimize solutions, spanning improvements from physics-informed reward design to policy architectures such as diffusion policies. Extensive evaluations yield three critical insights: (1) autonomous agents can qualitatively surpass human-engineered baselines by 26.5\\% in average success rate; (2) agentic workflow with environment feedback effectively strengthens policy development and substantially narrows the performance gap between open-source and proprietary models; and (3) agents exhibit self-correction capabilities for pathological engineering cases, successfully resurrecting task performance from near-total failures through iterative simulation-in-the-loop debugging. Ultimately, this work establishes a foundation for self-evolving embodied intelligence, accelerating the paradigm shift from labor-intensive manual tuning to scalable, autonomous engineering in embodied AI field.","published":"2026-01-29T11:33:49Z","updated":"2026-06-11T15:34:57Z","categories":["cs.AI","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.21570v2","pdf_url":"https://arxiv.org/pdf/2601.21570v2","comment":"53 pages, 12 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.21343","versioned_id":"2601.21343v3","title":"Self-Improving Pretraining: using post-trained models to pretrain better models","authors":["Ellen Xiaoqing Tan","Jack Lanchantin","Shehzaad Dhuliawala","Danwei Li","Thao Nguyen","Jing Xu","Ping Yu","Ilia Kulikov","Sainbayar Sukhbaatar","Jason Weston","Xian Li","Olga Golovneva"],"abstract":"Large language models are classically trained in stages: pretraining on raw text followed by post-training for instruction following and reasoning. However, this separation creates a fundamental limitation: many desirable behaviors such as safety, factuality, overall generation quality, and reasoning ability are only added at a late stage, even though the patterns learned earlier strongly shape a model's capabilities. To tackle this issue, we introduce a new way to pretrain and mid-train models that incorporates these behaviors earlier. We utilize an existing strong, post-trained model to both rewrite pretraining data and to judge policy model rollouts, thus using reinforcement earlier in training. In our experiments, we show this can give strong gains in quality, safety, factuality and reasoning.","published":"2026-01-29T07:09:30Z","updated":"2026-04-05T15:57:55Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.21343v3","pdf_url":"https://arxiv.org/pdf/2601.21343v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.21157","versioned_id":"2601.21157v1","title":"Bridging the Arithmetic Gap: The Cognitive Complexity Benchmark and Financial-PoT for Robust Financial Reasoning","authors":["Boxiang Zhao","Qince Li","Zhonghao Wang","Yi Wang","Peng Cheng","Bo Lin"],"abstract":"While Large Language Models excel at semantic tasks, they face a critical bottleneck in financial quantitative reasoning, frequently suffering from \"Arithmetic Hallucinations\" and a systemic failure mode we term \"Cognitive Collapse\". To strictly quantify this phenomenon, we introduce the Cognitive Complexity Benchmark (CCB), a robust evaluation framework grounded in a dataset constructed from 95 real-world Chinese A-share annual reports. Unlike traditional datasets, the CCB stratifies financial queries into a three-dimensional taxonomy, Data Source, Mapping Difficulty, and Result Unit, enabling the precise diagnosis of reasoning degradation in high-cognitive-load scenarios. To address these failures, we propose the Iterative Dual-Phase Financial-PoT framework. This neuro-symbolic architecture enforces a strict architectural decoupling: it first isolates semantic variable extraction and logic formulation, then offloads computation to an iterative, self-correcting Python sandbox to ensure deterministic execution. Evaluation on the CCB demonstrates that while standard Chain-of-Thought falters on complex tasks, our approach offers superior robustness, elevating the Qwen3-235B model's average accuracy from 59.7\\% to 67.3\\% and achieving gains of up to 10-fold in high-complexity reasoning tasks. These findings suggest that architectural decoupling is a critical enabling factor for improving reliability in financial reasoning tasks, providing a transferable architectural insight for precision-critical domains that require tight alignment between semantic understanding and quantitative computation.","published":"2026-01-29T01:33:33Z","updated":"2026-01-29T01:33:33Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.21157v1","pdf_url":"https://arxiv.org/pdf/2601.21157v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.21126","versioned_id":"2601.21126v1","title":"AI-Augmented Density-Driven Optimal Control (D2OC) for Decentralized Environmental Mapping","authors":["Kooktae Lee","Julian Martinez"],"abstract":"This paper presents an AI-augmented decentralized framework for multi-agent (multi-robot) environmental mapping under limited sensing and communication. While conventional coverage formulations achieve effective spatial allocation when an accurate reference map is available, their performance deteriorates under uncertain or biased priors. The proposed method introduces an adaptive and self-correcting mechanism that enables agents to iteratively refine local density estimates within an optimal transport-based framework, ensuring theoretical consistency and scalability. A dual multilayer perceptron (MLP) module enhances adaptivity by inferring local mean-variance statistics and regulating virtual uncertainty for long-unvisited regions, mitigating stagnation around local minima. Theoretical analysis rigorously proves convergence under the Wasserstein metric, while simulation results demonstrate that the proposed AI-augmented Density-Driven Optimal Control consistently achieves robust and precise alignment with the ground-truth density, yielding substantially higher-fidelity reconstruction of complex multi-modal spatial distributions compared with conventional decentralized baselines.","published":"2026-01-28T23:55:02Z","updated":"2026-01-28T23:55:02Z","categories":["cs.MA","cs.RO"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.21126v1","pdf_url":"https://arxiv.org/pdf/2601.21126v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.21113","versioned_id":"2601.21113v1","title":"Planner-Auditor Twin: Agentic Discharge Planning with FHIR-Based LLM Planning, Guideline Recall, Optional Caching and Self-Improvement","authors":["Kaiyuan Wu","Aditya Nagori","Rishikesan Kamaleswaran"],"abstract":"Objective: Large language models (LLMs) show promise for clinical discharge planning, but their use is constrained by hallucination, omissions, and miscalibrated confidence. We introduce a self-improving, cache-optional Planner-Auditor framework that improves safety and reliability by decoupling generation from deterministic validation and targeted replay. Materials and Methods: We implemented an agentic, retrospective, FHIR-native evaluation pipeline using MIMIC-IV-on-FHIR. For each patient, the Planner (LLM) generates a structured discharge action plan with an explicit confidence estimate. The Auditor is a deterministic module that evaluates multi-task coverage, tracks calibration (Brier score, ECE proxies), and monitors action-distribution drift. The framework supports two-tier self-improvement: (i) within-episode regeneration when enabled, and (ii) cross-episode discrepancy buffering with replay for high-confidence, low-coverage cases. Results: While context caching improved performance over baseline, the self-improvement loop was the primary driver of gains, increasing task coverage from 32% to 86%. Calibration improved substantially, with reduced Brier/ECE and fewer high-confidence misses. Discrepancy buffering further corrected persistent high-confidence omissions during replay. Discussion: Feedback-driven regeneration and targeted replay act as effective control mechanisms to reduce omissions and improve confidence reliability in structured clinical planning. Separating an LLM Planner from a rule-based, observational Auditor enables systematic reliability measurement and safer iteration without model retraining. Conclusion: The Planner-Auditor framework offers a practical pathway toward safer automated discharge planning using interoperable FHIR data access and deterministic auditing, supported by reproducible ablations and reliability-focused evaluation.","published":"2026-01-28T23:04:11Z","updated":"2026-01-28T23:04:11Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.21113v1","pdf_url":"https://arxiv.org/pdf/2601.21113v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.21008","versioned_id":"2601.21008v3","title":"ORLoopBench: Solver-in-the-Loop Benchmarks for Self-Correction and Behavioral Rationality in Operations Research","authors":["Ruicheng Ao","David Simchi-Levi","Xinshang Wang"],"abstract":"Operations Research practitioners debug infeasible models through an iterative process: inspecting Irreducible Infeasible Subsystems ( IIS), identifying constraint conflicts, and repairing formulations until feasibility is restored. Existing LLM benchmarks mostly treat OR as one-shot translation from problem descriptions to solver code, omitting this diagnostic loop. We formalize infeasible-model repair as a solver-in-the-loop Markov Decision Process in which each action triggers solver re-execution and IIS recomputation, yielding deterministic, verifiable feedback. We introduce ORLoopBench, a benchmark suite with two components: OR-Debug-Bench releases 5,362 LP/MILP repair instances, while OR-Bias-Bench evaluates closed-form operational decision rationality across inventory settings. Solver-verified RLVR training enables an 8B model to surpass frontier APIs on LP repair (95.3% vs 92.4% RR @5), improves diagnostic behavior, and transfers to MILP repair. The same evaluation exposes semantic drift in whole-model code regeneration: feasible regenerated MILPs can solve the wrong problem. Process-level evaluation with solver oracles enables targeted training for reliable OR self-correction.","published":"2026-01-28T20:02:44Z","updated":"2026-05-26T03:03:56Z","categories":["cs.LG","cs.AI","math.OC"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.21008v3","pdf_url":"https://arxiv.org/pdf/2601.21008v3","comment":"58 pages, accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.20312","versioned_id":"2601.20312v2","title":"SAPO: Self-Adaptive Process Optimization Makes Small Reasoners Stronger","authors":["Kaiyuan Chen","Guangmin Zheng","Jin Wang","Xiaobing Zhou","Xuejie Zhang"],"abstract":"Existing self-evolution methods overlook the influence of fine-grained reasoning steps, which leads to the reasoner-verifier gap. The computational inefficiency of Monte Carlo (MC) process supervision further exacerbates the difficulty in mitigating the gap. Motivated by the Error-Related Negativity (ERN), which the reasoner can localize error following incorrect decisions, guiding rapid adjustments, we propose a Self-Adaptive Process Optimization (SAPO) method for self-improvement in Small Language Models (SLMs). SAPO adaptively and efficiently introduces process supervision signals by actively minimizing the reasoner-verifier gap rather than relying on inefficient MC estimations. Extensive experiments demonstrate that the proposed method outperforms most existing self-evolution methods on two challenging task types: mathematics and code. Additionally, to further investigate SAPO's impact on verifier performance, this work introduces two new benchmarks for process reward models in both mathematical and coding tasks.","published":"2026-01-28T07:04:30Z","updated":"2026-02-02T10:36:52Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.20312v2","pdf_url":"https://arxiv.org/pdf/2601.20312v2","comment":"Accepted by AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.19871","versioned_id":"2601.19871v1","title":"Reflective Translation: Improving Low-Resource Machine Translation via Structured Self-Reflection","authors":["Nicholas Cheng"],"abstract":"Low-resource languages such as isiZulu and isiXhosa face persistent challenges in machine translation due to limited parallel data and linguistic resources. Recent advances in large language models suggest that self-reflection, prompting a model to critique and revise its own outputs, can improve reasoning quality and factual consistency. Building on this idea, this paper introduces Reflective Translation, a prompt-based framework in which a model generates an initial translation, produces a structured self-critique, and then uses this reflection to generate a refined translation. The approach is evaluated on English-isiZulu and English-isiXhosa translation using OPUS-100 and NTREX-African, across multiple prompting strategies and confidence thresholds. Results show consistent improvements in both BLEU and COMET scores between first- and second-pass translations, with average gains of up to +0.22 BLEU and +0.18 COMET. Statistical significance testing using paired nonparametric tests confirms that these improvements are robust. The proposed method is model-agnostic, requires no fine-tuning, and introduces a reflection-augmented dataset that can support future supervised or analysis-driven work. These findings demonstrate that structured self-reflection is a practical and effective mechanism for improving translation quality in low-resource settings.","published":"2026-01-27T18:37:09Z","updated":"2026-01-27T18:37:09Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.19871v1","pdf_url":"https://arxiv.org/pdf/2601.19871v1","comment":"12 pages, 3 figures, 6 tables. Accepted to the NeurIPS 2025 Workshop on Multilingual Representation Learning (Mexico City) and the AAAI 2025 Workshop on Language Models for Under-Resourced Communities (LM4UC). Code and data available at: https://github.com/Nickcheng123/reflective-translation-mt","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.19607","versioned_id":"2601.19607v1","title":"ComAgent: Multi-LLM based Agentic AI Empowered Intelligent Wireless Networks","authors":["Haoyun Li","Ming Xiao","Kezhi Wang","Robert Schober","Dong In Kim","Yong Liang Guan"],"abstract":"Emerging 6G networks rely on complex cross-layer optimization, yet manually translating high-level intents into mathematical formulations remains a bottleneck. While Large Language Models (LLMs) offer promise, monolithic approaches often lack sufficient domain grounding, constraint awareness, and verification capabilities. To address this, we present ComAgent, a multi-LLM agentic AI framework. ComAgent employs a closed-loop Perception-Planning-Action-Reflection cycle, coordinating specialized agents for literature search, coding, and scoring to autonomously generate solver-ready formulations and reproducible simulations. By iteratively decomposing problems and self-correcting errors, the framework effectively bridges the gap between user intent and execution. Evaluations demonstrate that ComAgent achieves expert-comparable performance in complex beamforming optimization and outperforms monolithic LLMs across diverse wireless tasks, highlighting its potential for automating design in emerging wireless networks.","published":"2026-01-27T13:43:59Z","updated":"2026-01-27T13:43:59Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.19607v1","pdf_url":"https://arxiv.org/pdf/2601.19607v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.11182","versioned_id":"2602.11182v2","title":"MetaMem: Evolving Meta-Memory for Knowledge Utilization through Self-Reflective Symbolic Optimization","authors":["Haidong Xin","Xinze Li","Zhenghao Liu","Yukun Yan","Shuo Wang","Cheng Yang","Yu Gu","Ge Yu","Maosong Sun"],"abstract":"Existing memory systems enable Large Language Models (LLMs) to support long-horizon human-LLM interactions by persisting historical interactions beyond limited context windows. However, while recent approaches have succeeded in constructing effective memories, they often disrupt the inherent logical and temporal relationships within interaction sessions, resulting in fragmented memory units and degraded reasoning performance. In this paper, we propose MetaMem, a novel framework that augments memory systems with a self-evolving meta-memory, aiming to teach LLMs how to effectively utilize memorized knowledge. During meta-memory optimization, MetaMem iteratively distills transferable knowledge utilization experiences across different tasks by self-reflecting on reasoning processes and performing actions to update the current meta-memory state. The accumulated meta-memory units serve as explicit knowledge utilization experiences, guiding the LLM to systematically identify and integrate critical evidence from scattered memory fragments. Extensive experiments demonstrate the effectiveness of MetaMem, which significantly outperforms strong baselines by over 3.6%. All codes and datasets are available at https://github.com/OpenBMB/MetaMem.","published":"2026-01-27T04:46:23Z","updated":"2026-04-19T15:18:01Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.11182v2","pdf_url":"https://arxiv.org/pdf/2602.11182v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.18795","versioned_id":"2601.18795v2","title":"Reuse your FLOPs: Scaling RL on Hard Problems by Conditioning on Very Off-Policy Prefixes","authors":["Amrith Setlur","Zijian Wang","Andrew Cohen","Paria Rashidinejad","Sang Michael Xie"],"abstract":"Typical reinforcement learning (RL) methods for LLM reasoning waste compute on hard problems, where correct on-policy traces are rare, policy gradients vanish, and learning stalls. To bootstrap more efficient RL, we consider reusing old sampling FLOPs (from prior inference or RL training) in the form of off-policy traces. Standard off-policy methods supervise against off-policy data, causing instabilities during RL optimization. We introduce PrefixRL, where we condition on the prefix of successful off-policy traces and run on-policy RL to complete them, side-stepping off-policy instabilities. PrefixRL boosts the learning signal on hard problems by modulating the difficulty of the problem through the off-policy prefix length. We prove that the PrefixRL objective is not only consistent with the standard RL objective but also more sample efficient. Empirically, we discover back-generalization: training only on prefixed problems generalizes to out-of-distribution unprefixed performance, with learned strategies often differing from those in the prefix. In our experiments, we source the off-policy traces by rejection sampling with the base model, creating a self-improvement loop. On hard reasoning problems, PrefixRL reaches the same training reward 2x faster than the strongest baseline (SFT on off-policy data then RL), even after accounting for the compute spent on the initial rejection sampling, and increases the final reward by 3x. The gains transfer to held-out benchmarks, and PrefixRL is still effective when off-policy traces are derived from a different model family, validating its flexibility in practical settings.","published":"2026-01-26T18:57:00Z","updated":"2026-02-03T18:58:52Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.18795v2","pdf_url":"https://arxiv.org/pdf/2601.18795v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.18577","versioned_id":"2601.18577v2","title":"Self-Refining Video Sampling","authors":["Sangwon Jang","Taekyung Ki","Jaehyeong Jo","Saining Xie","Jaehong Yoon","Sung Ju Hwang"],"abstract":"Modern video generators still struggle with complex physical dynamics, often falling short of physical realism. Existing approaches address this using external verifiers or additional training on augmented data, which is computationally expensive and still limited in capturing fine-grained motion. In this work, we present self-refining video sampling, a simple method that uses a pre-trained video generator trained on large-scale datasets as its own self-refiner. By interpreting the generator as a denoising autoencoder, we enable iterative inner-loop refinement at inference time without any external verifier or additional training. We further introduce an uncertainty-aware refinement strategy that selectively refines regions based on self-consistency, which prevents artifacts caused by over-refinement. Experiments on state-of-the-art video generators demonstrate significant improvements in motion coherence and physics alignment, achieving over 70% human preference compared to the default sampler and guidance-based sampler.","published":"2026-01-26T15:22:27Z","updated":"2026-05-20T05:19:37Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.18577v2","pdf_url":"https://arxiv.org/pdf/2601.18577v2","comment":"ICML 2026. Project page: https://agwmon.github.io/self-refine-video/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.18847","versioned_id":"2601.18847v1","title":"MulVul: Retrieval-augmented Multi-Agent Code Vulnerability Detection via Cross-Model Prompt Evolution","authors":["Zihan Wu","Jie Xu","Yun Peng","Chun Yong Chong","Xiaohua Jia"],"abstract":"Large Language Models (LLMs) struggle to automate real-world vulnerability detection due to two key limitations: the heterogeneity of vulnerability patterns undermines the effectiveness of a single unified model, and manual prompt engineering for massive weakness categories is unscalable. To address these challenges, we propose \\textbf{MulVul}, a retrieval-augmented multi-agent framework designed for precise and broad-coverage vulnerability detection. MulVul adopts a coarse-to-fine strategy: a \\emph{Router} agent first predicts the top-$k$ coarse categories and then forwards the input to specialized \\emph{Detector} agents, which identify the exact vulnerability types. Both agents are equipped with retrieval tools to actively source evidence from vulnerability knowledge bases to mitigate hallucinations. Crucially, to automate the generation of specialized prompts, we design \\emph{Cross-Model Prompt Evolution}, a prompt optimization mechanism where a generator LLM iteratively refines candidate prompts while a distinct executor LLM validates their effectiveness. This decoupling mitigates the self-correction bias inherent in single-model optimization. Evaluated on 130 CWE types, MulVul achieves 34.79\\% Macro-F1, outperforming the best baseline by 41.5\\%. Ablation studies validate cross-model prompt evolution, which boosts performance by 51.6\\% over manual prompts by effectively handling diverse vulnerability patterns.","published":"2026-01-26T12:43:10Z","updated":"2026-01-26T12:43:10Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2601.18847v1","pdf_url":"https://arxiv.org/pdf/2601.18847v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.18281","versioned_id":"2601.18281v1","title":"Reflecting Twice before Speaking with Empathy: Self-Reflective Alternating Inference for Empathy-Aware End-to-End Spoken Dialogue","authors":["Yuhang Jia","Pei Liu","Haoqin Sun","Jiaming Zhou","Xuxin Cheng","Cao Liu","Ke Zeng","Xunliang Cai","Yong Qin"],"abstract":"End-to-end Spoken Language Models (SLMs) hold great potential for paralinguistic perception, and numerous studies have aimed to enhance their capabilities, particularly for empathetic dialogue. However, current approaches largely depend on rigid supervised signals, such as ground-truth response in supervised fine-tuning or preference scores in reinforcement learning. Such reliance is fundamentally limited for modeling complex empathy, as there is no single \"correct\" response and a simple numerical score cannot fully capture the nuances of emotional expression or the appropriateness of empathetic behavior. To address these limitations, we sequentially introduce EmpathyEval, a descriptive natural-language-based evaluation model for assessing empathetic quality in spoken dialogues. Building upon EmpathyEval, we propose ReEmpathy, an end-to-end SLM that enhances empathetic dialogue through a novel Empathetic Self-Reflective Alternating Inference mechanism, which interleaves spoken response generation with free-form, empathy-related reflective reasoning. Extensive experiments demonstrate that ReEmpathy substantially improves empathy-sensitive spoken dialogue by enabling reflective reasoning, offering a promising approach toward more emotionally intelligent and empathy-aware human-computer interactions.","published":"2026-01-26T09:04:50Z","updated":"2026-01-26T09:04:50Z","categories":["cs.CL","cs.SD"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.18281v1","pdf_url":"https://arxiv.org/pdf/2601.18281v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.18197","versioned_id":"2601.18197v2","title":"GAIA: A Data Flywheel System for Training GUI Test-Time Scaling Critic Models","authors":["Shaokang Wang","Pei Fu","Ruoceng Zhang","Shaojie Zhang","Xiuwen Xi","Jiahui Yang","Bin Qin","Ying Huang","Zhenbo Luo","Jian Luan"],"abstract":"While Large Vision-Language Models (LVLMs) have significantly advanced GUI agents' capabilities in parsing textual instructions, interpreting screen content, and executing tasks, a critical challenge persists: the irreversibility of agent operations-where a single erroneous action can trigger catastrophic deviations. To address this, we propose the \\textbf{G}UI \\textbf{A}ction Cr\\textbf{i}tic's Dat\\textbf{a} Flywheel System (GAIA), a training framework that enables the models to have iterative critic capabilities, which are used to improve the Test-Time Scaling (TTS) of basic GUI agents' performance. Specifically, we train an \\textbf{Intuitive Critic Model} (ICM) using positive and negative action examples from a base agent first. This critic evaluates the immediate correctness of the agent's intended actions, thereby selecting operations with higher success probability. Then, the initial critic guides agent actions to collect refined positive/negative samples, initiating the self-improving cycle. The augmented data then trains a second-round critic with enhanced discernment capability. We conduct experiments on various datasets and demonstrate that the proposed ICM can improve the test-time performance of various closed-source and open-source models, and the performance can be gradually improved as the data is recycled. The code, dataset, and accompanying datasheet will be publicly released at https://github.com/SeerRay-Lab/GAIA.","published":"2026-01-26T06:29:41Z","updated":"2026-06-26T07:19:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.18197v2","pdf_url":"https://arxiv.org/pdf/2601.18197v2","comment":"Accepted by ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.17942","versioned_id":"2601.17942v1","title":"LLM-Based SQL Generation: Prompting, Self-Refinement, and Adaptive Weighted Majority Voting","authors":["Yu-Jie Yang","Hung-Fu Chang","Po-An Chen"],"abstract":"Text-to-SQL has emerged as a prominent research area, particularly with the rapid advancement of large language models (LLMs). By enabling users to query databases through natural language rather than SQL, this technology significantly lowers the barrier to data analysis. However, generating accurate SQL from natural language remains challenging due to ambiguity in user queries, the complexity of schema linking, limited generalization across SQL dialects, and the need for domain-specific understanding. In this study, we propose a Single-Agent Self-Refinement with Ensemble Voting (SSEV) pipeline built on PET-SQL that operates without ground-truth data, integrating self-refinement with Weighted Majority Voting (WMV) and its randomized variant (RWMA). Experimental results show that the SSEV achieves competitive performance across multiple benchmarks, attaining execution accuracies of 85.5% on Spider 1.0-Dev, 86.4% on Spider 1.0-Test, and 66.3% on BIRD-Dev. Building on insights from the SSEV pipeline, we further propose ReCAPAgent-SQL (Refinement-Critique-Act-Plan agent-based SQL framework) to address the growing complexity of enterprise databases and real-world Text-to-SQL tasks. The framework integrates multiple specialized agents for planning, external knowledge retrieval, critique, action generation, self-refinement, schema linking, and result validation, enabling iterative refinement of SQL predictions through agent collaboration. ReCAPAgent-SQL's WMA results achieve 31% execution accuracy on the first 100 queries of Spider 2.0-Lite, demonstrating significant improvements in handling real-world enterprise scenarios. Overall, our work facilitates the deployment of scalable Text-to-SQL systems in practical settings, supporting better data-driven decision-making at lower cost and with greater efficiency.","published":"2026-01-25T18:38:58Z","updated":"2026-01-25T18:38:58Z","categories":["cs.AI","cs.DB"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.17942v1","pdf_url":"https://arxiv.org/pdf/2601.17942v1","comment":"29 pages, 22 figures","journal_ref":"2026 International Conference on Information Management","doi":"","discovered_on":"2026-07-17"},{"id":"2601.17335","versioned_id":"2601.17335v1","title":"The Relativity of AGI: Distributional Axioms, Fragility, and Undecidability","authors":["Angshul Majumdar"],"abstract":"We study whether Artificial General Intelligence (AGI) admits a coherent theoretical definition that supports absolute claims of existence, robustness, or self-verification. We formalize AGI axiomatically as a distributional, resource-bounded semantic predicate, indexed by a task family, a task distribution, a performance functional, and explicit resource budgets. Under this framework, we derive four classes of results. First, we show that generality is inherently relational: there is no distribution-independent notion of AGI. Second, we prove non-invariance results demonstrating that arbitrarily small perturbations of the task distribution can invalidate AGI properties via cliff sets, precluding universal robustness. Third, we establish bounded transfer guarantees, ruling out unbounded generalization across task families under finite resources. Fourth, invoking Rice-style and Gödel--Tarski arguments, we prove that AGI is a nontrivial semantic property and therefore cannot be soundly and completely certified by any computable procedure, including procedures implemented by the agent itself. Consequently, recursive self-improvement schemes that rely on internal self-certification of AGI are ill-posed. Taken together, our results show that strong, distribution-independent claims of AGI are not false but undefined without explicit formal indexing, and that empirical progress in AI does not imply the attainability of self-certifying general intelligence.","published":"2026-01-24T06:32:19Z","updated":"2026-01-24T06:32:19Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.17335v1","pdf_url":"https://arxiv.org/pdf/2601.17335v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.16443","versioned_id":"2601.16443v3","title":"Endless Terminals: Scaling RL Environments for Terminal Agents","authors":["Kanishk Gandhi","Shivam Garg","Noah D. Goodman","Dimitris Papailiopoulos"],"abstract":"Environments are the bottleneck for self-improving agents. Current terminal benchmarks were built for evaluation, not training; reinforcement learning requires a scalable pipeline, not just a dataset. We introduce Endless Terminals, a fully autonomous pipeline that procedurally generates terminal-use tasks without human annotation. The pipeline has four stages: generating diverse task descriptions, building and validating containerized environments, producing completion tests, and filtering for solvability. From this pipeline we obtain 3255 tasks spanning file operations, log management, data processing, scripting, and database operations. We train agents using vanilla PPO with binary episode level rewards and a minimal interaction loop: no retrieval, multi-agent coordination, or specialized tools. Despite this simplicity, models trained on Endless Terminals show substantial gains: on our held-out dev set, Llama-3.2-3B improves from 4.0% to 18.2%, Qwen2.5-7B from 10.7% to 53.3%, and Qwen3-8B-openthinker-sft from 42.6% to 59.0%. These improvements transfer to human-curated benchmarks: models trained on Endless Terminals show substantial gains on held out human curated benchmarks: on TerminalBench 2.0, Llama-3.2-3B improves from 0.0% to 2.2%, Qwen2.5-7B from 2.2% to 3.4%, and Qwen3-8B-openthinker-sft from 1.1% to 6.7%, in each case outperforming alternative approaches including models with more complex agentic scaffolds. These results demonstrate that simple RL succeeds when environments scale.","published":"2026-01-23T04:39:55Z","updated":"2026-02-14T09:14:28Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.16443v3","pdf_url":"https://arxiv.org/pdf/2601.16443v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.16038","versioned_id":"2601.16038v1","title":"Grounding Large Language Models in Reaction Knowledge Graphs for Synthesis Retrieval","authors":["Olga Bunkova","Lorenzo Di Fruscia","Sophia Rupprecht","Artur M. Schweidtmann","Marcel J. T. Reinders","Jana M. Weber"],"abstract":"Large Language Models (LLMs) can aid synthesis planning in chemistry, but standard prompting methods often yield hallucinated or outdated suggestions. We study LLM interactions with a reaction knowledge graph by casting reaction path retrieval as a Text2Cypher (natural language to graph query) generation problem, and define single- and multi-step retrieval tasks. We compare zero-shot prompting to one-shot variants using static, random, and embedding-based exemplar selection, and assess a checklist-driven validator/corrector loop. To evaluate our framework, we consider query validity and retrieval accuracy. We find that one-shot prompting with aligned exemplars consistently performs best. Our checklist-style self-correction loop mainly improves executability in zero-shot settings and offers limited additional retrieval gains once a good exemplar is present. We provide a reproducible Text2Cypher evaluation setup to facilitate further work on KG-grounded LLMs for synthesis planning. Code is available at https://github.com/Intelligent-molecular-systems/KG-LLM-Synthesis-Retrieval.","published":"2026-01-22T15:11:02Z","updated":"2026-01-22T15:11:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.16038v1","pdf_url":"https://arxiv.org/pdf/2601.16038v1","comment":"Accepted at ML4Molecules 2025 (ELLIS UnConference workshop), Copenhagen, Denmark, December 2, 2025. Workshop page: https://moleculediscovery.github.io/workshop2025/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15876","versioned_id":"2601.15876v2","title":"EvoCUA: Evolving Computer Use Agents via Learning from Scalable Synthetic Experience","authors":["Taofeng Xue","Chong Peng","Mianqiu Huang","Linsen Guo","Tiancheng Han","Haozhe Wang","Jianing Wang","Xiaocheng Zhang","Xin Yang","Dengchang Zhao","Jinrui Ding","Xiandi Ma","Yuchen Xie","Peng Pei","Xunliang Cai","Xipeng Qiu"],"abstract":"The development of native computer-use agents (CUA) represents a significant leap in multimodal AI. However, their potential is currently bottlenecked by the constraints of static data scaling. Existing paradigms relying primarily on passive imitation of static datasets struggle to capture the intricate causal dynamics inherent in long-horizon computer tasks. In this work, we introduce EvoCUA, a native computer use agentic model. Unlike static imitation, EvoCUA integrates data generation and policy optimization into a self-sustaining evolutionary cycle. To mitigate data scarcity, we develop a verifiable synthesis engine that autonomously generates diverse tasks coupled with executable validators. To enable large-scale experience acquisition, we design a scalable infrastructure orchestrating tens of thousands of asynchronous sandbox rollouts. Building on these massive trajectories, we propose an iterative evolving learning strategy to efficiently internalize this experience. This mechanism dynamically regulates policy updates by identifying capability boundaries -- reinforcing successful routines while transforming failure trajectories into rich supervision through error analysis and self-correction. Empirical evaluations on the OSWorld benchmark demonstrate that EvoCUA achieves a success rate of 56.7%, establishing a new open-source state-of-the-art. Notably, EvoCUA significantly outperforms the previous best open-source model, OpenCUA-72B (45.0%), and surpasses leading closed-weights models such as UI-TARS-2 (53.1%). Crucially, our results underscore the generalizability of this approach: the evolving paradigm driven by learning from experience yields consistent performance gains across foundation models of varying scales, establishing a robust and scalable path for advancing native agent capabilities.","published":"2026-01-22T11:36:43Z","updated":"2026-01-23T08:52:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15876v2","pdf_url":"https://arxiv.org/pdf/2601.15876v2","comment":"26 pages, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15816","versioned_id":"2601.15816v1","title":"Virtual Traffic Police: Large Language Model-Augmented Traffic Signal Control for Unforeseen Incidents","authors":["Shiqi Wei","Qiqing Wang","Kaidi Yang"],"abstract":"Adaptive traffic signal control (TSC) has demonstrated strong effectiveness in managing dynamic traffic flows. However, conventional methods often struggle when unforeseen traffic incidents occur (e.g., accidents and road maintenance), which typically require labor-intensive and inefficient manual interventions by traffic police officers. Large Language Models (LLMs) appear to be a promising solution thanks to their remarkable reasoning and generalization capabilities. Nevertheless, existing works often propose to replace existing TSC systems with LLM-based systems, which can be (i) unreliable due to the inherent hallucinations of LLMs and (ii) costly due to the need for system replacement. To address the issues of existing works, we propose a hierarchical framework that augments existing TSC systems with LLMs, whereby a virtual traffic police agent at the upper level dynamically fine-tunes selected parameters of signal controllers at the lower level in response to real-time traffic incidents. To enhance domain-specific reliability in response to unforeseen traffic incidents, we devise a self-refined traffic language retrieval system (TLRS), whereby retrieval-augmented generation is employed to draw knowledge from a tailored traffic language database that encompasses traffic conditions and controller operation principles. Moreover, we devise an LLM-based verifier to update the TLRS continuously over the reasoning process. Our results show that LLMs can serve as trustworthy virtual traffic police officers that can adapt conventional TSC methods to unforeseen traffic incidents with significantly improved operational efficiency and reliability.","published":"2026-01-22T10:04:21Z","updated":"2026-01-22T10:04:21Z","categories":["eess.SY","cs.AI"],"primary_category":"eess.SY","arxiv_url":"https://arxiv.org/abs/2601.15816v1","pdf_url":"https://arxiv.org/pdf/2601.15816v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15808","versioned_id":"2601.15808v2","title":"Inference-Time Scaling of Verification: Self-Evolving Deep Research Agents via Test-Time Rubric-Guided Verification","authors":["Yuxuan Wan","Tianqing Fang","Zaitang Li","Yintong Huo","Wenxuan Wang","Haitao Mi","Dong Yu","Michael R. Lyu"],"abstract":"Recent advances in Deep Research Agents (DRAs) are transforming automated knowledge discovery and problem-solving. While the majority of existing efforts focus on enhancing policy capabilities via post-training, we propose an alternative paradigm: self-evolving the agent's ability by iteratively verifying the policy model's outputs, guided by meticulously crafted rubrics. This approach gives rise to the inference-time scaling of verification, wherein an agent self-improves by evaluating its generated answers to produce iterative feedback and refinements. We derive the rubrics based on an automatically constructed DRA Failure Taxonomy, which systematically classifies agent failures into five major categories and thirteen sub-categories. We present DeepVerifier, a rubrics-based outcome reward verifier that leverages the asymmetry of verification and outperforms vanilla agent-as-judge and LLM judge baselines by 12%-48% in meta-evaluation F1 score. To enable practical self-evolution, DeepVerifier integrates as a plug-and-play module during test-time inference. The verifier produces detailed rubric-based feedback, which is fed back to the agent for iterative bootstrapping, refining responses without additional training. This test-time scaling delivers 8%-11% accuracy gains on challenging subsets of GAIA and XBench-DeepSearch when powered by capable closed-source LLMs. Finally, to support open-source advancement, we release DeepVerifier-4K, a curated supervised fine-tuning dataset of 4,646 high-quality agent steps focused on DRA verification. These examples emphasize reflection and self-critique, enabling open models to develop robust verification capabilities.","published":"2026-01-22T09:47:31Z","updated":"2026-04-29T08:40:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15808v2","pdf_url":"https://arxiv.org/pdf/2601.15808v2","comment":"ACL'2026-Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15715","versioned_id":"2601.15715v3","title":"RebuttalAgent: Strategic Persuasion in Academic Rebuttal via Theory of Mind","authors":["Zhitao He","Zongwei Lyu","Yi R Fung"],"abstract":"Although artificial intelligence (AI) has become deeply integrated into various stages of the research workflow and achieved remarkable advancements, academic rebuttal remains a significant and underexplored challenge. This is because rebuttal is a complex process of strategic communication under severe information asymmetry rather than a simple technical debate. Consequently, current approaches struggle as they largely imitate surface-level linguistics, missing the essential element of perspective-taking required for effective persuasion. In this paper, we introduce RebuttalAgent, the first framework to ground academic rebuttal in Theory of Mind (ToM), operationalized through a ToM-Strategy-Response (TSR) framework that models reviewer mental state, formulates persuasion strategy, and generates evidence-based response. To train our agent, we construct RebuttalBench, a large-scale dataset synthesized via a novel critique-and-refine approach. Our training process consists of two stages, beginning with a supervised fine-tuning phase to equip the agent with ToM-based analysis and strategic planning capabilities, followed by a reinforcement learning phase leveraging the self-reward mechanism for scalable self-improvement. For reliable and efficient automated evaluation, we further develop Rebuttal-RM, a specialized evaluator trained on over 100K samples of multi-source rebuttal data, which achieves scoring consistency with human preferences surpassing powerful judge GPT-4.1. Extensive experiments show RebuttalAgent significantly outperforms the base model by an average of 18.3% on automated metrics, while also outperforming advanced proprietary models across both automated and human evaluations.","published":"2026-01-22T07:36:48Z","updated":"2026-02-25T16:22:14Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.15715v3","pdf_url":"https://arxiv.org/pdf/2601.15715v3","comment":"Accepted by ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15703","versioned_id":"2601.15703v1","title":"Agentic Uncertainty Quantification","authors":["Jiaxin Zhang","Prafulla Kumar Choubey","Kung-Hsiang Huang","Caiming Xiong","Chien-Sheng Wu"],"abstract":"Although AI agents have demonstrated impressive capabilities in long-horizon reasoning, their reliability is severely hampered by the ``Spiral of Hallucination,'' where early epistemic errors propagate irreversibly. Existing methods face a dilemma: uncertainty quantification (UQ) methods typically act as passive sensors, only diagnosing risks without addressing them, while self-reflection mechanisms suffer from continuous or aimless corrections. To bridge this gap, we propose a unified Dual-Process Agentic UQ (AUQ) framework that transforms verbalized uncertainty into active, bi-directional control signals. Our architecture comprises two complementary mechanisms: System 1 (Uncertainty-Aware Memory, UAM), which implicitly propagates verbalized confidence and semantic explanations to prevent blind decision-making; and System 2 (Uncertainty-Aware Reflection, UAR), which utilizes these explanations as rational cues to trigger targeted inference-time resolution only when necessary. This enables the agent to balance efficient execution and deep deliberation dynamically. Extensive experiments on closed-loop benchmarks and open-ended deep research tasks demonstrate that our training-free approach achieves superior performance and trajectory-level calibration. We believe this principled framework AUQ represents a significant step towards reliable agents.","published":"2026-01-22T07:16:26Z","updated":"2026-01-22T07:16:26Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15703v1","pdf_url":"https://arxiv.org/pdf/2601.15703v1","comment":"36 pages, 9 figures, 9 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15690","versioned_id":"2601.15690v2","title":"From Passive Metric to Active Signal: The Evolving Role of Uncertainty Quantification in Large Language Models","authors":["Jiaxin Zhang","Wendi Cui","Zhuohang Li","Lifu Huang","Bradley Malin","Caiming Xiong","Chien-Sheng Wu"],"abstract":"While Large Language Models (LLMs) show remarkable capabilities, their unreliability remains a critical barrier to deployment in high-stakes domains. This survey charts a functional evolution in addressing this challenge: the evolution of uncertainty from a passive diagnostic metric to an active control signal guiding real-time model behavior. We demonstrate how uncertainty is leveraged as an active control signal across three frontiers: in \\textbf{advanced reasoning} to optimize computation and trigger self-correction; in \\textbf{autonomous agents} to govern metacognitive decisions about tool use and information seeking; and in \\textbf{reinforcement learning} to mitigate reward hacking and enable self-improvement via intrinsic rewards. By grounding these advancements in emerging theoretical frameworks like Bayesian methods and Conformal Prediction, we provide a unified perspective on this transformative trend. This survey provides a comprehensive overview, critical analysis, and practical design patterns, arguing that mastering the new trend of uncertainty is essential for building the next generation of scalable, reliable, and trustworthy AI.","published":"2026-01-22T06:21:31Z","updated":"2026-04-19T04:51:57Z","categories":["cs.AI","stat.AP"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15690v2","pdf_url":"https://arxiv.org/pdf/2601.15690v2","comment":"This paper has been accepted by ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15476","versioned_id":"2601.15476v1","title":"Reliability by design: quantifying and eliminating fabrication risk in LLMs. From generative to consultative AI: a comparative analysis in the legal domain and lessons for high-stakes knowledge bases","authors":["Alex Dantart"],"abstract":"This paper examines how to make large language models reliable for high-stakes legal work by reducing hallucinations. It distinguishes three AI paradigms: (1) standalone generative models (\"creative oracle\"), (2) basic retrieval-augmented systems (\"expert archivist\"), and (3) an advanced, end-to-end optimized RAG system (\"rigorous archivist\"). The authors introduce two reliability metrics -False Citation Rate (FCR) and Fabricated Fact Rate (FFR)- and evaluate 2,700 judicial-style answers from 12 LLMs across 75 legal tasks using expert, double-blind review. Results show that standalone models are unsuitable for professional use (FCR above 30%), while basic RAG greatly reduces errors but still leaves notable misgrounding. Advanced RAG, using techniques such as embedding fine-tuning, re-ranking, and self-correction, reduces fabrication to negligible levels (below 0.2%). The study concludes that trustworthy legal AI requires rigor-focused, retrieval-based architectures emphasizing verification and traceability, and provides an evaluation framework applicable to other high-risk domains.","published":"2026-01-21T21:26:42Z","updated":"2026-01-21T21:26:42Z","categories":["cs.AI","cs.PF"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15476v1","pdf_url":"https://arxiv.org/pdf/2601.15476v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15286","versioned_id":"2601.15286v1","title":"Iterative Refinement Improves Compositional Image Generation","authors":["Shantanu Jaiswal","Mihir Prabhudesai","Nikash Bhardwaj","Zheyang Qin","Amir Zadeh","Chuan Li","Katerina Fragkiadaki","Deepak Pathak"],"abstract":"Text-to-image (T2I) models have achieved remarkable progress, yet they continue to struggle with complex prompts that require simultaneously handling multiple objects, relations, and attributes. Existing inference-time strategies, such as parallel sampling with verifiers or simply increasing denoising steps, can improve prompt alignment but remain inadequate for richly compositional settings where many constraints must be satisfied. Inspired by the success of chain-of-thought reasoning in large language models, we propose an iterative test-time strategy in which a T2I model progressively refines its generations across multiple steps, guided by feedback from a vision-language model as the critic in the loop. Our approach is simple, requires no external tools or priors, and can be flexibly applied to a wide range of image generators and vision-language models. Empirically, we demonstrate consistent gains on image generation across benchmarks: a 16.9% improvement in all-correct rate on ConceptMix (k=7), a 13.8% improvement on T2I-CompBench (3D-Spatial category) and a 12.5% improvement on Visual Jenga scene decomposition compared to compute-matched parallel sampling. Beyond quantitative gains, iterative refinement produces more faithful generations by decomposing complex prompts into sequential corrections, with human evaluators preferring our method 58.7% of the time over 41.3% for the parallel baseline. Together, these findings highlight iterative self-correction as a broadly applicable principle for compositional image generation. Results and visualizations are available at https://iterative-img-gen.github.io/","published":"2026-01-21T18:59:40Z","updated":"2026-01-21T18:59:40Z","categories":["cs.CV","cs.AI","cs.LG","cs.RO"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.15286v1","pdf_url":"https://arxiv.org/pdf/2601.15286v1","comment":"Project webpage: https://iterative-img-gen.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.15141","versioned_id":"2601.15141v2","title":"CLEANER: Self-Purified Trajectories Boost Agentic Reinforcement Learning","authors":["Tianshi Xu","Yuteng Chen","Meng Li"],"abstract":"Agentic Reinforcement Learning (RL) has empowered Large Language Models (LLMs) to utilize tools like Python interpreters for complex problem-solving. However, for parameter-constrained models (e.g., 4B--7B), the exploration phase is often plagued by frequent execution failures, creating noisy trajectories that hinder policy optimization. Under standard outcome-based reward settings, this noise leads to a critical credit assignment issue, where erroneous actions are inadvertently reinforced alongside successful outcomes. Existing mitigations face a dilemma: dense rewards often trigger reward hacking, while supersampling incurs prohibitive computational costs. To address these challenges, we propose CLEANER. Distinct from external filtering methods, CLEANER exploits the model's intrinsic self-correction capabilities to eliminate error-contaminated context directly during data collection. At its core, the Similarity-Aware Adaptive Rollback (SAAR) mechanism autonomously constructs clean, purified trajectories by retrospectively replacing failures with successful self-corrections. Based on semantic similarity, SAAR adaptively regulates replacement granularity from shallow execution repairs to deep reasoning substitutions. By training on these self-purified paths, the model internalizes correct reasoning patterns rather than error-recovery loops. Empirical results on AIME24/25, GPQA, and LiveCodeBench show average accuracy gains of 6%, 3%, and 5% over baselines. Notably, CLEANER matches state-of-the-art performance using only one-third of the training steps, highlighting trajectory purification as a scalable solution for efficient agentic RL. Our models and code are available at GitHub","published":"2026-01-21T16:14:30Z","updated":"2026-07-03T06:13:09Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.15141v2","pdf_url":"https://arxiv.org/pdf/2601.15141v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.14589","versioned_id":"2601.14589v1","title":"Designing KRIYA: An AI Companion for Wellbeing Self-Reflection","authors":["Shanshan Zhu","Wenxuan Song","Jiayue Melissa Shi","Dong Whi Yoo","Karthik S. Bhat","Koustuv Saha"],"abstract":"Most personal wellbeing apps present summative dashboards of health and physical activity metrics, yet many users struggle to translate this information into meaningful understanding. These apps commonly support engagement through goals, reminders, and structured targets, which can reinforce comparison, judgment, and performance anxiety. To explore a complementary approach that prioritizes self-reflection, we design KRIYA, an AI wellbeing companion that supports co-interpretive engagement with personal wellbeing data. KRIYA aims to collaborate with users to explore questions, explanations, and future scenarios through features such as Comfort Zone, Detective Mode, and What-If Planning. We conducted semi-structured interviews with 18 college students interacting with a KRIYA prototype using hypothetical data. Our findings show that through KRIYA interaction, users framed engaging with wellbeing data as interpretation rather than performance, experienced reflection as supportive or pressuring depending on emotional framing, and developed trust through transparency. We discuss design implications for AI companions that support curiosity, self-compassion, and reflective sensemaking of personal health data.","published":"2026-01-21T02:03:12Z","updated":"2026-01-21T02:03:12Z","categories":["cs.HC","cs.AI","cs.CL","cs.CY"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2601.14589v1","pdf_url":"https://arxiv.org/pdf/2601.14589v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.14532","versioned_id":"2601.14532v1","title":"Search over Self-Edit Strategies for LLM Adaptation","authors":["Alistair Cheong","Haolin Cong","Tyler Yang","Dustin Miao"],"abstract":"Many LLM-based open-ended search systems freeze the foundation model that proposes improvements to existing solutions, which may bottleneck long-run progress. Recent work has explored updating the proposal model at test time [arXiv:2511.23473], but the update strategy is still typically hand-specified. Therefore, this study investigated whether an LLM can use task feedback to decide how it should update its weights. For tractability, we focused on the simpler case where there is only one round of self-improvement, and restricted the update operator to self-supervised next token prediction (NTP), leaving the model freedom in choosing its training data and key NTP hyperparameters. Using the Self-Adapting Language Models (SEAL) [arXiv:2506.10943] framework as a testbed, we relaxed its fixed human template constraint and allowed the model to generate its own self-edit templates, thereby giving it more control over its training data and hyperparameters. Two variants were studied, differing in whether template generation was conditioned on a lightweight archive of past templates. In SEAL's Single-Passage Knowledge Incorporation setting with Qwen3-8B on SQuAD [arXiv:1606.05250], the no-archive variant performed comparably to the weaker \"Implications\" baseline, while the archive variant outperformed \"Implications\" and approached the strongest human-designed \"Rewrite\" baseline without surpassing it. Further analysis of collapse in the model's exploration revealed that a naive archive can confer some short-term robustness but can also accelerate homogenization, suggesting that explicit novelty pressure may be required to consistently advance beyond carefully optimized human strategies. Our code is available at https://github.com/cheongalc/search-self-edit-strategies .","published":"2026-01-20T22:59:58Z","updated":"2026-01-20T22:59:58Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.14532v1","pdf_url":"https://arxiv.org/pdf/2601.14532v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.14041","versioned_id":"2601.14041v1","title":"Top 10 Open Challenges Steering the Future of Diffusion Language Model and Its Variants","authors":["Yunhe Wang","Kai Han","Huiling Zhen","Yuchuan Tian","Hanting Chen","Yongbing Huang","Yufei Cui","Yingte Shu","Shan Gao","Ismail Elezi","Roy Vaughan Miles","Songcen Xu","Feng Wen","Chao Xu","Sinan Zeng","Dacheng Tao"],"abstract":"The paradigm of Large Language Models (LLMs) is currently defined by auto-regressive (AR) architectures, which generate text through a sequential ``brick-by-brick'' process. Despite their success, AR models are inherently constrained by a causal bottleneck that limits global structural foresight and iterative refinement. Diffusion Language Models (DLMs) offer a transformative alternative, conceptualizing text generation as a holistic, bidirectional denoising process akin to a sculptor refining a masterpiece. However, the potential of DLMs remains largely untapped as they are frequently confined within AR-legacy infrastructures and optimization frameworks. In this Perspective, we identify ten fundamental challenges ranging from architectural inertia and gradient sparsity to the limitations of linear reasoning that prevent DLMs from reaching their ``GPT-4 moment''. We propose a strategic roadmap organized into four pillars: foundational infrastructure, algorithmic optimization, cognitive reasoning, and unified multimodal intelligence. By shifting toward a diffusion-native ecosystem characterized by multi-scale tokenization, active remasking, and latent thinking, we can move beyond the constraints of the causal horizon. We argue that this transition is essential for developing next-generation AI capable of complex structural reasoning, dynamic self-correction, and seamless multimodal integration.","published":"2026-01-20T14:58:23Z","updated":"2026-01-20T14:58:23Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.14041v1","pdf_url":"https://arxiv.org/pdf/2601.14041v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13761","versioned_id":"2601.13761v2","title":"DARC: Decoupled Asymmetric Reasoning Curriculum for LLM Evolution","authors":["Shengda Fan","Xuyan Ye","Yankai Lin"],"abstract":"Self-play with large language models has emerged as a promising paradigm for achieving self-improving artificial intelligence. However, existing self-play frameworks often suffer from optimization instability, due to (i) non-stationary objectives induced by solver-dependent reward feedback for the Questioner, and (ii) bootstrapping errors from self-generated pseudo-labels used to supervise the Solver. To mitigate these challenges, we introduce DARC (Decoupled Asymmetric Reasoning Curriculum), a two-stage framework that stabilizes the self-evolution process. First, we train the Questioner to synthesize difficulty-calibrated questions, conditioned on explicit difficulty levels and external corpora. Second, we train the Solver with an asymmetric self-distillation mechanism, where a document-augmented teacher generates high-quality pseudo-labels to supervise the student Solver that lacks document access. Empirical results demonstrate that DARC is model-agnostic, yielding an average improvement of 10.9 points across nine reasoning benchmarks and three backbone models. Moreover, DARC consistently outperforms all baselines and approaches the performance of fully supervised models without relying on human annotations. The code is available at https://github.com/RUCBM/DARC.","published":"2026-01-20T09:12:27Z","updated":"2026-01-21T04:54:47Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.13761v2","pdf_url":"https://arxiv.org/pdf/2601.13761v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13752","versioned_id":"2601.13752v1","title":"Finding RELIEF: Shaping Reasoning Behavior without Reasoning Supervision via Belief Engineering","authors":["Chak Tou Leong","Dingwei Chen","Heming Xia","Qingyu Yin","Sunbowen Lee","Jian Wang","Wenjie Li"],"abstract":"Large reasoning models (LRMs) have achieved remarkable success in complex problem-solving, yet they often suffer from computational redundancy or reasoning unfaithfulness. Current methods for shaping LRM behavior typically rely on reinforcement learning or fine-tuning with gold-standard reasoning traces, a paradigm that is both computationally expensive and difficult to scale. In this paper, we reveal that LRMs possess latent \\textit{reasoning beliefs} that internally track their own reasoning traits, which can be captured through simple logit probing. Building upon this insight, we propose Reasoning Belief Engineering (RELIEF), a simple yet effective framework that shapes LRM behavior by aligning the model's self-concept with a target belief blueprint. Crucially, RELIEF completely bypasses the need for reasoning-trace supervision. It internalizes desired traits by fine-tuning on synthesized, self-reflective question-answering pairs that affirm the target belief. Extensive experiments on efficiency and faithfulness tasks demonstrate that RELIEF matches or outperforms behavior-supervised and preference-based baselines while requiring lower training costs. Further analysis validates that shifting a model's reasoning belief effectively shapes its actual behavior.","published":"2026-01-20T09:07:01Z","updated":"2026-01-20T09:07:01Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.13752v1","pdf_url":"https://arxiv.org/pdf/2601.13752v1","comment":"Working in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13653","versioned_id":"2601.13653v1","title":"TimeART: Towards Agentic Time Series Reasoning via Tool-Augmentation","authors":["Xingjian Wu","Junkai Lu","Zhengyu Li","Xiangfei Qiu","Jilin Hu","Chenjuan Guo","Christian S. Jensen","Bin Yang"],"abstract":"Time series data widely exist in real-world cyber-physical systems. Though analyzing and interpreting them contributes to significant values, e.g, disaster prediction and financial risk control, current workflows mainly rely on human data scientists, which requires significant labor costs and lacks automation. To tackle this, we introduce TimeART, a framework fusing the analytical capability of strong out-of-the-box tools and the reasoning capability of Large Language Models (LLMs), which serves as a fully agentic data scientist for Time Series Question Answering (TSQA). To teach the LLM-based Time Series Reasoning Models (TSRMs) strategic tool-use, we also collect a 100k expert trajectory corpus called TimeToolBench. To enhance TSRMs' generalization capability, we then devise a four-stage training strategy, which boosts TSRMs through learning from their own early experiences and self-reflections. Experimentally, we train an 8B TSRM on TimeToolBench and equip it with the TimeART framework, and it achieves consistent state-of-the-art performance on multiple TSQA tasks, which pioneers a novel approach towards agentic time series reasoning.","published":"2026-01-20T06:39:10Z","updated":"2026-01-20T06:39:10Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.13653v1","pdf_url":"https://arxiv.org/pdf/2601.13653v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.00059","versioned_id":"2602.00059v2","title":"TextBFGS: A Case-Based Reasoning Approach to Code Optimization via Error-Operator Retrieval","authors":["Zizheng Zhang","Yuyang Liao","Chen Chen","Jian He","Dun Wu","Qianjin Yu","Yanqin Gao","Jin Yang","Kailai Zhang","Eng Siong Chng","Xionghu Zhong"],"abstract":"Iterative code generation with Large Language Models (LLMs) can be viewed as an optimization process guided by textual feedback. However, existing LLM self-correction methods predominantly operate in a stateless, trial-and-error manner akin to first-order search, failing to leverage past problem-solving experiences. To bridge this gap, we introduce TextBFGS, a Case-Based Reasoning (CBR) framework inspired by the Quasi-Newton optimization method. Instead of retrieving raw, unstructured textual instances, TextBFGS maintains a dynamic Case Base of historical \"Error-to-Operator\" correction trajectories to approximate the semantic curvature (inverse Hessian matrix) of the task. Specifically, given a textual error feedback (the target problem), TextBFGS retrieves analogous historical correction patterns (Retrieve) and applies these abstract operators to refine the current code (Reuse/Revise). Furthermore, successful adaptations are continuously retained back into the Case Base (Retain), enabling a self-evolving system. Empirical evaluations on Python code optimization tasks (HumanEval, MBPP) demonstrate that TextBFGS significantly outperforms stateless baselines. It achieves superior pass rates with fewer model calls, establishing an efficient, experience-driven paradigm for LLM-based code optimization.","published":"2026-01-20T05:45:56Z","updated":"2026-03-30T06:08:20Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.00059v2","pdf_url":"https://arxiv.org/pdf/2602.00059v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13566","versioned_id":"2601.13566v1","title":"Self-Improvement as Coherence Optimization: A Theoretical Account","authors":["Tianyi Qiu","Ahmed Hani Ismail","Zhonghao He","Shi Feng"],"abstract":"Can language models improve their accuracy without external supervision? Methods such as debate, bootstrap, and internal coherence maximization achieve this surprising feat, even matching golden finetuning performance. Yet why they work remains theoretically unclear. We show that they are all special cases of coherence optimization: finding a context-to-behavior mapping that's most compressible and jointly predictable. We prove that coherence optimization is equivalent to description-length regularization, and that among all such regularization schemes, it is optimal for semi-supervised learning when the regularizer is derived from a pretrained model. Our theory, supported by preliminary experiments, explains why feedback-free self-improvement works and predicts when it should succeed or fail.","published":"2026-01-20T03:50:02Z","updated":"2026-01-20T03:50:02Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.13566v1","pdf_url":"https://arxiv.org/pdf/2601.13566v1","comment":"39 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13398","versioned_id":"2601.13398v2","title":"Can LLMs Compress (and Decompress)? Evaluating Code Understanding and Execution via Invertibility","authors":["Nickil Maveli","Antonio Vergari","Shay B. Cohen"],"abstract":"LLMs demonstrate strong performance on code benchmarks, yet consistent reasoning across forward and backward execution remains elusive. We present RoundTripCodeEval (RTCE), a benchmark of four code execution reasoning tasks that evaluates round-trip consistency through execution-free, exact-match assessment of bijection fidelity across four lossless compression algorithms. We evaluate state-of-the-art Code-LLMs under zero-shot prompting, supervised fine-tuning on execution traces, and iterative self-reflection. All approaches yield only modest improvements and none closes the gap, revealing that current LLMs lack the internal coherence required for reliable bidirectional code reasoning. RTCE surfaces findings invisible to existing benchmarks: models frequently pass individual forward and backward tasks yet fail the combined round-trip, exposing mutually inconsistent internal representations; SFT and self-reflection saturate after one revision round, indicating they cannot repair fundamental algorithmic misunderstandings; and failures persist even on simple bijections such as RLE, suggesting that algorithmic complexity is not the sole root cause.\\footnote{Code and dataset are available at https://github.com/Nickil21/round-trip-code-compression.","published":"2026-01-19T21:09:48Z","updated":"2026-05-03T18:40:55Z","categories":["cs.LG","cs.AI","cs.PL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.13398v2","pdf_url":"https://arxiv.org/pdf/2601.13398v2","comment":"Accepted to the Findings of ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13228","versioned_id":"2601.13228v1","title":"Autoregressive Models Rival Diffusion Models at ANY-ORDER Generation","authors":["Tianqi Du","Lizhe Fang","Weijie Yang","Chenheng Zhang","Zeming Wei","Yifei Wang","Yisen Wang"],"abstract":"Diffusion language models enable any-order generation and bidirectional conditioning, offering appealing flexibility for tasks such as infilling, rewriting, and self-correction. However, their formulation-predicting one part of a sequence from another within a single-step dependency-limits modeling depth and often yields lower sample quality and stability than autoregressive (AR) models. To address this, we revisit autoregressive modeling as a foundation and reformulate diffusion-style training into a structured multi-group prediction process. We propose Any-order Any-subset Autoregressive modeling (A3), a generalized framework that extends the standard AR factorization to arbitrary token groups and generation orders. A3 preserves the probabilistic rigor and multi-layer dependency modeling of AR while inheriting diffusion models' flexibility for parallel and bidirectional generation. We implement A3 through a two-stream attention architecture and a progressive adaptation strategy that transitions pretrained AR models toward any-order prediction. Experiments on question answering, commonsense reasoning, and story infilling demonstrate that A3 outperforms diffusion-based models while maintaining flexible decoding. This work offers a unified approach for a flexible, efficient, and novel language modeling paradigm.","published":"2026-01-19T17:03:48Z","updated":"2026-01-19T17:03:48Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.13228v1","pdf_url":"https://arxiv.org/pdf/2601.13228v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13217","versioned_id":"2601.13217v1","title":"Beyond Single-shot Writing: Deep Research Agents are Unreliable at Multi-turn Report Revision","authors":["Bingsen Chen","Boyan Li","Ping Nie","Yuyu Zhang","Xi Ye","Chen Zhao"],"abstract":"Existing benchmarks for Deep Research Agents (DRAs) treat report generation as a single-shot writing task, which fundamentally diverges from how human researchers iteratively draft and revise reports via self-reflection or peer feedback. Whether DRAs can reliably revise reports with user feedback remains unexplored. We introduce Mr Dre, an evaluation suite that establishes multi-turn report revision as a new evaluation axis for DRAs. Mr Dre consists of (1) a unified long-form report evaluation protocol spanning comprehensiveness, factuality, and presentation, and (2) a human-verified feedback simulation pipeline for multi-turn revision. Our analysis of five diverse DRAs reveals a critical limitation: while agents can address most user feedback, they also regress on 16-27% of previously covered content and citation quality. Over multiple revision turns, even the best-performing agents leave significant headroom, as they continue to disrupt content outside the feedback's scope and fail to preserve earlier edits. We further show that these issues are not easily resolvable through inference-time fixes such as prompt engineering and a dedicated sub-agent for report revision.","published":"2026-01-19T16:48:45Z","updated":"2026-01-19T16:48:45Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.13217v1","pdf_url":"https://arxiv.org/pdf/2601.13217v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.13060","versioned_id":"2601.13060v1","title":"MagicGUI-RMS: A Multi-Agent Reward Model System for Self-Evolving GUI Agents via Automated Feedback Reflux","authors":["Zecheng Li","Zhihui Cao","Wenke Huang","Yudong Zhang","Keying Qi","Rui Wang","Zeyu Zheng","Jian Zhao","Hao Zhu","Hengxin Wu","Yuran Wang","Guitao Fan","Guokun Wu","Yicong Liu","Zhilin Gao","Haikun Xu","He Yang","Minqi Xiang","Xingyu Liu","Zuojian Wang"],"abstract":"Graphical user interface (GUI) agents are rapidly progressing toward autonomous interaction and reliable task execution across diverse applications. However, two central challenges remain unresolved: automating the evaluation of agent trajectories and generating high-quality training data at scale to enable continual improvement. Existing approaches often depend on manual annotation or static rule-based verification, which restricts scalability and limits adaptability in dynamic environments. We present MagicGUI-RMS, a multi-agent reward model system that delivers adaptive trajectory evaluation, corrective feedback, and self-evolving learning capabilities. MagicGUI-RMS integrates a Domain-Specific Reward Model (DS-RM) with a General-Purpose Reward Model (GP-RM), enabling fine-grained action assessment and robust generalization across heterogeneous GUI tasks. To support reward learning at scale, we design a structured data construction pipeline that automatically produces balanced and diverse reward datasets, effectively reducing annotation costs while maintaining sample fidelity. During execution, the reward model system identifies erroneous actions, proposes refined alternatives, and continuously enhances agent behavior through an automated data-reflux mechanism. Extensive experiments demonstrate that MagicGUI-RMS yields substantial gains in task accuracy, behavioral robustness. These results establish MagicGUI-RMS as a principled and effective foundation for building self-improving GUI agents driven by reward-based adaptation.","published":"2026-01-19T13:50:43Z","updated":"2026-01-19T13:50:43Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.13060v1","pdf_url":"https://arxiv.org/pdf/2601.13060v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.12762","versioned_id":"2601.12762v1","title":"Teaching LLMs to Learn Tool Trialing and Execution through Environment Interaction","authors":["Xingjie Gao","Pengcheng Huang","Zhenghao Liu","Yukun Yan","Shuo Wang","Zulong Chen","Chen Qian","Ge Yu","Yu Gu"],"abstract":"Equipping Large Language Models (LLMs) with external tools enables them to solve complex real-world problems. However, the robustness of existing methods remains a critical challenge when confronting novel or evolving tools. Existing trajectory-centric paradigms primarily rely on memorizing static solution paths during training, which limits the ability of LLMs to generalize tool usage to newly introduced or previously unseen tools. In this paper, we propose ToolMaster, a framework that shifts tool use from imitating golden tool-calling trajectories to actively learning tool usage through interaction with the environment. To optimize LLMs for tool planning and invocation, ToolMaster adopts a trial-and-execution paradigm, which trains LLMs to first imitate teacher-generated trajectories containing explicit tool trials and self-correction, followed by reinforcement learning to coordinate the trial and execution phases jointly. This process enables agents to autonomously explore correct tool usage by actively interacting with environments and forming experiential knowledge that benefits tool execution. Experimental results demonstrate that ToolMaster significantly outperforms existing baselines in terms of generalization and robustness across unseen or unfamiliar tools. All code and data are available at https://github.com/NEUIR/ToolMaster.","published":"2026-01-19T06:46:33Z","updated":"2026-01-19T06:46:33Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2601.12762v1","pdf_url":"https://arxiv.org/pdf/2601.12762v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.00041","versioned_id":"2602.00041v2","title":"Student Perceptions of Large Language Models Use in Self-Reflection and Design Critique in Architecture Studio","authors":["Juan David Salazar Rodriguez","Sam Conrad Joyce","Nachamma Sockalingam","Khoo Eng Tat","Julfendi"],"abstract":"This study investigates the integration of Large Language Models (LLMs) into the feedback mechanisms of the architectural design studio, shifting the focus from generative production to reflective pedagogy. Employing a mixed-methods approach with surveys and semi structured interviews with 22 architecture students at the Singapore University of Technology and De-sign, the research analyzes student perceptions across three distinct feed-back domains: self-reflection, peer critique, and professor-led reviews. The findings reveal that students engage with LLMs not as authoritative in-structors, but as collaborative \"cognitive mirrors\" that scaffold critical thinking. In self-directed learning, LLMs help structure thoughts and over-come the \"blank page\" problem, though they are limited by a lack of contex-tual nuance. In peer critiques, the technology serves as a neutral mediator, mitigating social anxiety and the \"fear of offending\". Furthermore, in high-stakes professor-led juries, students utilize LLMs primarily as post-critique synthesis engines to manage cognitive overload and translate ab-stract academic discourse into actionable design iterations.","published":"2026-01-19T06:38:03Z","updated":"2026-02-03T01:28:03Z","categories":["cs.CY","cs.AI","cs.HC"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2602.00041v2","pdf_url":"https://arxiv.org/pdf/2602.00041v2","comment":"Keywords: Architectural Education, Design Studio Pedagogy, Large Lan-guage Models, Generative AI in Education, Design Critique","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.12748","versioned_id":"2601.12748v1","title":"Towards Robust Process Reward Modeling via Noise-aware Learning","authors":["Bin Xie","Bingbing Xu","Xueyun Tian","Yilin Chen","Huawei Shen"],"abstract":"Process Reward Models (PRMs) have achieved strong results in complex reasoning, but are bottlenecked by costly process-level supervision. A widely used alternative, Monte Carlo Estimation (MCE), defines process rewards as the probability that a policy model reaches the correct final answer from a given reasoning step. However, step correctness is an intrinsic property of the reasoning trajectory, and should be invariant to policy choice. Our empirical findings show that MCE producing policy-dependent rewards that induce label noise, including false positives that reward incorrect steps and false negatives that penalize correct ones. To address above challenges, we propose a two-stage framework to mitigate noisy supervision. In the labeling stage, we introduce a reflection-aware label correction mechanism that uses a large language model (LLM) as a judge to detect reflection and self-correction behaviors related to the current reasoning step, thereby suppressing overestimated rewards. In the training stage, we further propose a \\underline{\\textbf{N}}oise-\\underline{\\textbf{A}}ware \\underline{\\textbf{I}}terative \\underline{\\textbf{T}}raining framework that enables the PRM to progressively refine noisy labels based on its own confidence. Extensive Experiments show that our method substantially improves step-level correctness discrimination, achieving up to a 27\\% absolute gain in average F1 over PRMs trained with noisy supervision.","published":"2026-01-19T06:03:58Z","updated":"2026-01-19T06:03:58Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.12748v1","pdf_url":"https://arxiv.org/pdf/2601.12748v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.12720","versioned_id":"2601.12720v1","title":"Teaching Large Reasoning Models Effective Reflection","authors":["Hanbin Wang","Jingwei Song","Jinpeng Li","Qi Zhu","Fei Mi","Ganqu Cui","Yasheng Wang","Lifeng Shang"],"abstract":"Large Reasoning Models (LRMs) have recently shown impressive performance on complex reasoning tasks, often by engaging in self-reflective behaviors such as self-critique and backtracking. However, not all reflections are beneficial-many are superficial, offering little to no improvement over the original answer and incurring computation overhead. In this paper, we identify and address the problem of superficial reflection in LRMs. We first propose Self-Critique Fine-Tuning (SCFT), a training framework that enhances the model's reflective reasoning ability using only self-generated critiques. SCFT prompts models to critique their own outputs, filters high-quality critiques through rejection sampling, and fine-tunes the model using a critique-based objective. Building on this strong foundation, we further introduce Reinforcement Learning with Effective Reflection Rewards (RLERR). RLERR leverages the high-quality reflections initialized by SCFT to construct reward signals, guiding the model to internalize the self-correction process via reinforcement learning. Experiments on two challenging benchmarks, AIME2024 and AIME2025, show that SCFT and RLERR significantly improve both reasoning accuracy and reflection quality, outperforming state-of-the-art baselines. All data and codes are available at https://github.com/wanghanbinpanda/SCFT.","published":"2026-01-19T04:51:53Z","updated":"2026-01-19T04:51:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.12720v1","pdf_url":"https://arxiv.org/pdf/2601.12720v1","comment":"14 pages (including appendix), 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.12535","versioned_id":"2601.12535v3","title":"Improving Low-Resource Machine Translation via Round-Trip Reinforcement Learning","authors":["Ahmed Attia","Alham Fikri Aji"],"abstract":"Low-resource machine translation (MT) has gained increasing attention as parallel data from low-resource language communities is collected, but many approaches for improving low-resource MT remain underexplored. We investigate a self-supervised reinforcement learning fine-tuning for translation in low-resource settings using round-trip bootstrapping with the No Language Left Behind (NLLB) family of models. Our approach translates English into a target low-resource language and then back into English, using a combination of chrF++ and BLEU as the reward function on the reconstructed English sentences. Using the NLLB-MD dataset, we evaluate both the 600M and 1.3B parameter NLLB models and observe consistent improvements for the following languages: Central Aymara, Friulian, Wolof, Dyula, Bhojpuri and Russian. Qualitative inspection of translation outputs indicates increased fluency and semantic fidelity. We argue that our method can further benefit from scale, enabling models to increasingly leverage their pretrained knowledge and continue self-improving. Code available at: https://github.com/Copticoder/MT-via-Round-Trip-RL","published":"2026-01-18T18:44:49Z","updated":"2026-03-17T23:00:37Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.12535v3","pdf_url":"https://arxiv.org/pdf/2601.12535v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.12310","versioned_id":"2601.12310v1","title":"Survival is the Only Reward: Sustainable Self-Training Through Environment-Mediated Selection","authors":["Jennifer Dodgson","Alfath Daryl Alhajir","Michael Joedhitya","Akira Rafhael Janson Pattirane","Surender Suresh Kumar","Joseph Lim","C. H. Peh","Adith Ramdas","Steven Zhang Zhexu"],"abstract":"Self-training systems often degenerate due to the lack of an external criterion for judging data quality, leading to reward hacking and semantic drift. This paper provides a proof-of-concept system architecture for stable self-training under sparse external feedback and bounded memory, and empirically characterises its learning dynamics and failure modes. We introduce a self-training architecture in which learning is mediated exclusively by environmental viability, rather than by reward, objective functions, or externally defined fitness criteria. Candidate behaviours are executed under real resource constraints, and only those whose environmental effects both persist and preserve the possibility of future interaction are propagated. The environment does not provide semantic feedback, dense rewards, or task-specific supervision; selection operates solely through differential survival of behaviours as world-altering events, making proxy optimisation impossible and rendering reward-hacking evolutionarily unstable. Analysis of semantic dynamics shows that improvement arises primarily through the persistence of effective and repeatable strategies under a regime of consolidation and pruning, a paradigm we refer to as negative-space learning (NSL), and that models develop meta-learning strategies (such as deliberate experimental failure in order to elicit informative error messages) without explicit instruction. This work establishes that environment-grounded selection enables sustainable open-ended self-improvement, offering a viable path toward more robust and generalisable autonomous systems without reliance on human-curated data or complex reward shaping.","published":"2026-01-18T08:35:56Z","updated":"2026-01-18T08:35:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.12310v1","pdf_url":"https://arxiv.org/pdf/2601.12310v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.12208","versioned_id":"2601.12208v1","title":"CoReflect: Conversational Evaluation via Co-Evolutionary Simulation and Reflective Rubric Refinement","authors":["Yunzhe Li","Richie Yueqi Feng","Tianxin Wei","Chin-Chia Hsu"],"abstract":"Evaluating conversational systems in multi-turn settings remains a fundamental challenge. Conventional pipelines typically rely on manually defined rubrics and fixed conversational context$-$a static approach that limits coverage and fails to capture the diverse, emergent behaviors of dialogue models. To address this, we introduce CoReflect (Conversational Evaluation via Co-Evolutionary Simulation and Reflective Rubric Refinement), which unifies dialogue simulation and evaluation into an adaptive, iterative process. CoReflect employs a conversation planner that generates structured templates to guide a user simulator through diverse, goal-directed dialogues. Subsequently, a reflective analyzer processes these dialogues to identify systematic behavioral patterns and automatically refine the evaluation rubrics. Crucially, the insights from the conversation analysis are fed back into the planner to update conversation templates for subsequent iterations. This co-evolution loop ensures that the complexity of test cases and the diagnostic precision of rubrics improve in tandem. By minimizing human intervention, CoReflect provides a scalable and self-refining methodology that allows evaluation protocols to adapt alongside the rapidly advancing capabilities of dialogue models.","published":"2026-01-18T00:56:06Z","updated":"2026-01-18T00:56:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.12208v1","pdf_url":"https://arxiv.org/pdf/2601.12208v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.00028","versioned_id":"2602.00028v1","title":"ELLMPEG: An Edge-based Agentic LLM Video Processing Tool","authors":["Zoha Azimi","Reza Farahani","Radu Prodan","Christian Timmerer"],"abstract":"Large language models (LLMs), the foundation of generative AI systems like ChatGPT, are transforming many fields and applications, including multimedia, enabling more advanced content generation, analysis, and interaction. However, cloud-based LLM deployments face three key limitations: high computational and energy demands, privacy and reliability risks from remote processing, and recurring API costs. Recent advances in agentic AI, especially in structured reasoning and tool use, offer a better way to exploit open and locally deployed tools and LLMs. This paper presents ELLMPEG, an edge-enabled agentic LLM framework for the automated generation of video-processing commands. ELLMPEG integrates tool-aware Retrieval-Augmented Generation (RAG) with iterative self-reflection to produce and locally verify executable FFmpeg and VVenC commands directly at the edge, eliminating reliance on external cloud APIs. To evaluate ELLMPEG, we collect a dedicated prompt dataset comprising 480 diverse queries covering different categories of FFmpeg and the Versatile Video Codec (VVC) encoder (VVenC) commands. We validate command generation accuracy and evaluate four open-source LLMs based on command validity, tokens generated per second, inference time, and energy efficiency. We also execute the generated commands to assess their runtime correctness and practical applicability. Experimental results show that Qwen2.5, when augmented with the ELLMPEG framework, achieves an average command-generation accuracy of 78 % with zero recurring API cost, outperforming all other open-source models across both the FFmpeg and VVenC datasets.","published":"2026-01-17T14:51:21Z","updated":"2026-01-17T14:51:21Z","categories":["cs.LG","cs.MM"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.00028v1","pdf_url":"https://arxiv.org/pdf/2602.00028v1","comment":"12 pages, 5 tables, 8 Figures, accepted for the MMSys 2026 conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11974","versioned_id":"2601.11974v1","title":"Learn Like Humans: Use Meta-cognitive Reflection for Efficient Self-Improvement","authors":["Xinmeng Hou","Peiliang Gong","Bohao Qu","Wuqi Wang","Qing Guo","Yang Liu"],"abstract":"While Large Language Models (LLMs) enable complex autonomous behavior, current agents remain constrained by static, human-designed prompts that limit adaptability. Existing self-improving frameworks attempt to bridge this gap but typically rely on inefficient, multi-turn recursive loops that incur high computational costs. To address this, we propose Metacognitive Agent Reflective Self-improvement (MARS), a framework that achieves efficient self-evolution within a single recurrence cycle. Inspired by educational psychology, MARS mimics human learning by integrating principle-based reflection (abstracting normative rules to avoid errors) and procedural reflection (deriving step-by-step strategies for success). By synthesizing these insights into optimized instructions, MARS allows agents to systematically refine their reasoning logic without continuous online feedback. Extensive experiments on six benchmarks demonstrate that MARS outperforms state-of-the-art self-evolving systems while significantly reducing computational overhead.","published":"2026-01-17T09:12:26Z","updated":"2026-01-17T09:12:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.11974v1","pdf_url":"https://arxiv.org/pdf/2601.11974v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11789","versioned_id":"2601.11789v2","title":"Suspicious Alignment of SGD: A Fine-Grained Step Size Condition Analysis","authors":["Shenyang Deng","Boyao Liao","Zhuoli Ouyang","Tianyu Pang","Minhak Song","Yaoqing Yang"],"abstract":"This paper explores the suspicious alignment phenomenon in stochastic gradient descent (SGD) under ill-conditioned optimization, where the Hessian spectrum splits into dominant and bulk subspaces. This phenomenon describes the behavior of gradient alignment in SGD updates. Specifically, during the initial phase of SGD updates, the alignment between the gradient and the dominant subspace tends to decrease. Subsequently, it enters a rising phase and eventually stabilizes in a high-alignment phase. The alignment is considered ``suspicious'' because, paradoxically, the projected gradient update along this highly-aligned dominant subspace proves ineffective at reducing the loss. The focus of this work is to give a fine-grained analysis in a high-dimensional quadratic setup about how step size selection produces this phenomenon. Our main contribution can be summarized as follows: We propose a step-size condition revealing that in low-alignment regimes, an adaptive critical step size $η_t^*$ separates alignment-decreasing ($η_t < η_t^*$) from alignment-increasing ($η_t > η_t^*$) regimes, whereas in high-alignment regimes, the alignment is self-correcting and decreases regardless of the step size. We further show that under sufficient ill-conditioning, a step size interval exists where projecting the SGD updates to the bulk space decreases the loss while projecting them to the dominant space increases the loss, which explains a recent empirical observation that projecting gradient updates to the dominant subspace is ineffective. Finally, based on this adaptive step-size theory, we prove that for a constant step size and large initialization, SGD exhibits this distinct two-phase behavior: an initial alignment-decreasing phase, followed by stabilization at high alignment.","published":"2026-01-16T21:32:48Z","updated":"2026-05-07T17:10:40Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.11789v2","pdf_url":"https://arxiv.org/pdf/2601.11789v2","comment":"The 37th International Conference on Algorithmic Learning Theory","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11776","versioned_id":"2601.11776v1","title":"Cleansing the Artificial Mind: A Self-Reflective Detoxification Framework for Large Language Models","authors":["Kaituo Zhang","Zhimeng Jiang","Na Zou"],"abstract":"Recent breakthroughs in Large Language Models (LLMs) have revealed remarkable generative capabilities and emerging self-regulatory mechanisms, including self-correction and self-rewarding. However, current detoxification techniques rarely exploit these built-in abilities; instead, they rely on external modules, labor-intensive data annotation, or human intervention --factors that hinder scalability and consistency. In this paper, we introduce a fully self-reflective detoxification framework that harnesses the inherent capacities of LLMs to detect, correct toxic content, and refine LLMs without external modules and data annotation. Specifically, we propose a Toxic Signal Detector --an internal self-identification mechanism, coupled with a systematic intervention process to transform toxic text into its non-toxic counterpart. This iterative procedure yields a contrastive detoxification dataset used to fine-tune the model, enhancing its ability for safe and coherent text generation. Experiments on benchmark datasets such as DetoxLLM and ParaDetox show that our method achieves better detoxification performance than state-of-the-art methods while preserving semantic fidelity. By obviating the need for human intervention or external components, this paper reveals the intrinsic self-detoxification ability of LLMs, offering a consistent and effective approach for mitigating harmful content generation. Ultimately, our findings underscore the potential for truly self-regulated language models, paving the way for more responsible and ethically guided text generation systems.","published":"2026-01-16T21:01:26Z","updated":"2026-01-16T21:01:26Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.11776v1","pdf_url":"https://arxiv.org/pdf/2601.11776v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11044","versioned_id":"2601.11044v4","title":"AgencyBench: Benchmarking the Frontiers of Autonomous Agents in 1M-Token Real-World Contexts","authors":["Keyu Li","Junhao Shi","Yang Xiao","Mohan Jiang","Jie Sun","Yunze Wu","Dayuan Fu","Shijie Xia","Xiaojie Cai","Tianze Xu","Weiye Si","Wenjie Li","Dequan Wang","Pengfei Liu"],"abstract":"Large Language Models (LLMs) based autonomous agents demonstrate multifaceted capabilities to contribute substantially to economic production. However, existing benchmarks remain focused on single agentic capability, failing to capture long-horizon real-world scenarios. Moreover, the reliance on human-in-the-loop feedback for realistic tasks creates a scalability bottleneck, hindering automated rollout collection and evaluation. To bridge this gap, we introduce AgencyBench, a comprehensive benchmark derived from daily AI usage, evaluating 6 core agentic capabilities across 32 real-world scenarios, comprising 138 tasks with specific queries, deliverables, and rubrics. These scenarios require an average of 90 tool calls, 1 million tokens, and hours of execution time to resolve. To enable automated evaluation, we employ a user simulation agent to provide iterative feedback, and a Docker sandbox to conduct visual and functional rubric-based assessment. Experiments reveal that closed-source models significantly outperform open-source models (48.4% vs 32.1%). Further analysis reveals significant disparities across models in resource efficiency, feedback-driven self-correction, and specific tool-use preferences. Finally, we investigate the impact of agentic scaffolds, observing that proprietary models demonstrate superior performance within their native ecosystems (e.g., Claude-4.5-Opus via Claude-Agent-SDK), while open-source models exhibit distinct performance peaks, suggesting potential optimization for specific execution frameworks. AgencyBench serves as a critical testbed for next-generation agents, highlighting the necessity of co-optimizing model architecture with agentic frameworks. We believe this work sheds light on the future direction of autonomous agents, and we release the full benchmark and evaluation toolkit at https://github.com/GAIR-NLP/AgencyBench.","published":"2026-01-16T07:22:20Z","updated":"2026-04-23T05:01:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.11044v4","pdf_url":"https://arxiv.org/pdf/2601.11044v4","comment":"Accepted by ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11038","versioned_id":"2601.11038v2","title":"Budget-Aware Anytime Reasoning with LLM-Synthesized Preference Data","authors":["Xuanming Zhang","Shwan Ashrafi","Aziza Mirsaidova","Amir H. Rezaeian","Miguel Ballesteros","Lydia B. Chilton","Zhou Yu","Dan Roth"],"abstract":"We study the reasoning behavior of large language models (LLMs) under limited computation budgets. In such settings, producing useful partial solutions quickly is often more practical than exhaustive reasoning, which incurs high inference costs. Many real-world tasks, such as trip planning, require models to deliver the best possible output within a fixed reasoning budget. We introduce an anytime reasoning framework and the Anytime Index, a metric that quantifies how effectively solution quality improves as reasoning tokens increase. To further enhance efficiency, we propose an inference-time self-improvement method using LLM-synthesized preference data, where models learn from their own reasoning comparisons to produce better intermediate solutions. Experiments on NaturalPlan (Trip), AIME, and GPQA datasets show consistent gains across Grok-3, GPT-oss, GPT-4.1/4o, and LLaMA models, improving both reasoning quality and efficiency under budget constraints.","published":"2026-01-16T07:09:30Z","updated":"2026-04-19T03:10:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.11038v2","pdf_url":"https://arxiv.org/pdf/2601.11038v2","comment":"ACL 2026 Findings, 13 pages, 3 figures, 1 table","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11021","versioned_id":"2601.11021v2","title":"Combating Spurious Correlations in Graph Interpretability via Self-Reflection","authors":["Kecheng Cai","Chenyang Xu","Chao Peng","Jiafu Huang","Qiyuan Liang","Irene Zheng"],"abstract":"Interpretable graph learning has recently emerged as a popular research topic in machine learning. The goal is to identify the important nodes and edges of an input graph that are crucial for performing a specific graph reasoning task. A number of studies have been conducted in this area, and various benchmark datasets have been proposed to facilitate evaluation. Among them, one of the most challenging is the Spurious-Motif benchmark, introduced at ICLR 2022. The datasets in this synthetic benchmark are deliberately designed to include spurious correlations, making it particularly difficult for models to distinguish truly relevant structures from misleading patterns. As a result, existing methods exhibit significantly worse performance on this benchmark compared to others. In this paper, we focus on improving interpretability on the challenging Spurious-Motif datasets. We demonstrate that the self-reflection technique, commonly used in large language models to tackle complex tasks, can also be effectively adapted to enhance interpretability in datasets with strong spurious correlations. Specifically, we propose a self-reflection framework that can be integrated with existing interpretable graph learning methods. When such a method produces importance scores for each node and edge, our framework feeds these predictions back into the original method to perform a second round of evaluation. This iterative process mirrors how large language models employ self-reflective prompting to reassess their previous outputs. We further analyze the reasons behind this improvement from the perspective of graph representation learning, which motivates us to propose a fine-tuning training method based on this feedback mechanism.","published":"2026-01-16T06:31:16Z","updated":"2026-01-23T03:30:04Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.11021v2","pdf_url":"https://arxiv.org/pdf/2601.11021v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11658","versioned_id":"2601.11658v1","title":"Towards AGI A Pragmatic Approach Towards Self Evolving Agent","authors":["Indrajit Kar","Sammy Zonunpuia","Zonunfeli Ralte"],"abstract":"Large Language Model (LLM) based agents are powerful yet fundamentally static after deployment, lacking the ability to autonomously expand capabilities, generate new tools, or evolve their reasoning. This work introduces a hierarchical self-evolving multi-agent framework that integrates a Base LLM, an operational SLM agent, a Code-Generation LLM, and a Teacher-LLM to enable continuous adaptation. The workflow begins with the agent attempting a task using reasoning and existing tools; if unsuccessful, it escalates to tool synthesis through the Code-Gen LLM, and when failures persist, it triggers an evolution phase using Curriculum Learning (CL), Reward-Based Learning (RL), or Genetic Algorithm (GA) evolution. Using the TaskCraft dataset rich in hierarchical tasks, tool-use traces, and difficulty scaling we evaluate these paradigms. CL delivers fast recovery and strong generalization, RL excels on high-difficulty tasks, and GA offers high behavioral diversity. Across all settings, evolved agents outperform their originals, demonstrating robust, autonomous, self-improving agentic evolution.","published":"2026-01-15T20:43:44Z","updated":"2026-01-15T20:43:44Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.11658v1","pdf_url":"https://arxiv.org/pdf/2601.11658v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.10657","versioned_id":"2601.10657v2","title":"PACEvolve: Enabling Long-Horizon Progress-Aware Consistent Evolution","authors":["Minghao Yan","Bo Peng","Benjamin Coleman","Ziqi Chen","Zhouhang Xie","Shuo Chen","Zhankui He","Noveen Sachdeva","Isabella Ye","Weili Wang","Chi Wang","Ed H. Chi","Fernando Pereira","Wang-Cheng Kang","Derek Zhiyuan Cheng","Beidou Wang"],"abstract":"Large Language Models (LLMs) have emerged as powerful operators for evolutionary search, yet the design of efficient search scaffolds remains ad hoc. While promising, current LLM-in-the-loop systems lack a systematic approach to managing the evolutionary process. We identify three distinct failure modes: Context Pollution, where experiment history biases future candidate generation; Mode Collapse, where agents stagnate in local minima due to poor exploration-exploitation balance; and Weak Collaboration, where rigid crossover strategies fail to leverage parallel search trajectories effectively. We introduce Progress-Aware Consistent Evolution (PACEvolve), a framework designed to robustly govern the agent's context and search dynamics, to address these challenges. PACEvolve combines hierarchical context management (HCM) with pruning to address context pollution; momentum-based backtracking (MBB) to escape local minima; and a self-adaptive sampling policy that unifies backtracking and crossover for dynamic search coordination (CE), allowing agents to balance internal refinement with cross-trajectory collaboration. We demonstrate that PACEvolve provides a systematic path to consistent, long-horizon self-improvement, achieving state-of-the-art results on LLM-SR and KernelBench, while discovering solutions surpassing the record on Modded NanoGPT.","published":"2026-01-15T18:25:23Z","updated":"2026-01-16T22:31:40Z","categories":["cs.NE","cs.LG"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2601.10657v2","pdf_url":"https://arxiv.org/pdf/2601.10657v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.10543","versioned_id":"2601.10543v2","title":"Defending Large Language Models Against Jailbreak Attacks via In-Decoding Safety-Awareness Probing","authors":["Yinzhi Zhao","Ming Wang","Shi Feng","Xiaocui Yang","Daling Wang","Yifei Zhang"],"abstract":"Large language models (LLMs) have achieved impressive performance across natural language tasks and are increasingly deployed in real-world applications. Despite extensive safety alignment efforts, recent studies show that such alignment is often shallow and remains vulnerable to jailbreak attacks. Existing defense mechanisms, including decoding-based constraints and post-hoc content detectors, struggle against sophisticated jailbreaks, often intervening robust detection or excessively degrading model utility. In this work, we examine the decoding process of LLMs and make a key observation: even when successfully jailbroken, models internally exhibit latent safety-related signals during generation. However, these signals are overridden by the model's drive for fluent continuation, preventing timely self-correction or refusal. Building on this observation, we propose a simple yet effective approach that explicitly surfaces and leverages these latent safety signals for early detection of unsafe content during decoding. Experiments across diverse jailbreak attacks demonstrate that our approach significantly enhances safety, while maintaining low over-refusal rates on benign inputs and preserving response quality. Our results suggest that activating intrinsic safety-awareness during decoding offers a promising and complementary direction for defending against jailbreak attacks. Code is available at: https://github.com/zyz13590/SafeProbing.","published":"2026-01-15T16:09:10Z","updated":"2026-01-30T11:57:19Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.10543v2","pdf_url":"https://arxiv.org/pdf/2601.10543v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.10094","versioned_id":"2601.10094v1","title":"V-Zero: Self-Improving Multimodal Reasoning with Zero Annotation","authors":["Han Wang","Yi Yang","Jingyuan Hu","Minfeng Zhu","Wei Chen"],"abstract":"Recent advances in multimodal learning have significantly enhanced the reasoning capabilities of vision-language models (VLMs). However, state-of-the-art approaches rely heavily on large-scale human-annotated datasets, which are costly and time-consuming to acquire. To overcome this limitation, we introduce V-Zero, a general post-training framework that facilitates self-improvement using exclusively unlabeled images. V-Zero establishes a co-evolutionary loop by instantiating two distinct roles: a Questioner and a Solver. The Questioner learns to synthesize high-quality, challenging questions by leveraging a dual-track reasoning reward that contrasts intuitive guesses with reasoned results. The Solver is optimized using pseudo-labels derived from majority voting over its own sampled responses. Both roles are trained iteratively via Group Relative Policy Optimization (GRPO), driving a cycle of mutual enhancement. Remarkably, without a single human annotation, V-Zero achieves consistent performance gains on Qwen2.5-VL-7B-Instruct, improving visual mathematical reasoning by +1.7 and general vision-centric by +2.6, demonstrating the potential of self-improvement in multimodal systems. Code is available at https://github.com/SatonoDia/V-Zero","published":"2026-01-15T05:47:43Z","updated":"2026-01-15T05:47:43Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.10094v1","pdf_url":"https://arxiv.org/pdf/2601.10094v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.10011","versioned_id":"2601.10011v1","title":"Memo-SQL: Structured Decomposition and Experience-Driven Self-Correction for Training-Free NL2SQL","authors":["Zerui Yang","Weichuan Wang","Yanwei Xu","Linqi Song","Yudai Matsuda","Wei Han","Bo Bai"],"abstract":"Existing NL2SQL systems face two critical limitations: (1) they rely on in-context learning with only correct examples, overlooking the rich signal in historical error-fix pairs that could guide more robust self-correction; and (2) test-time scaling approaches often decompose questions arbitrarily, producing near-identical SQL candidates across runs and diminishing ensemble gains. Moreover, these methods suffer from a stark accuracy-efficiency trade-off: high performance demands excessive computation, while fast variants compromise quality. We present Memo-SQL, a training-free framework that addresses these issues through two simple ideas: structured decomposition and experience-aware self-correction. Instead of leaving decomposition to chance, we apply three clear strategies, entity-wise, hierarchical, and atomic sequential, to encourage diverse reasoning. For correction, we build a dynamic memory of both successful queries and historical error-fix pairs, and use retrieval-augmented prompting to bring relevant examples into context at inference time, no fine-tuning or external APIs required. On BIRD, Memo-SQL achieves 68.5% execution accuracy, setting a new state of the art among open, zero-fine-tuning methods, while using over 10 times fewer resources than prior TTS approaches.","published":"2026-01-15T02:42:05Z","updated":"2026-01-15T02:42:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.10011v1","pdf_url":"https://arxiv.org/pdf/2601.10011v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.09905","versioned_id":"2601.09905v1","title":"Self-reflection in Automated Qualitative Coding: Improving Text Annotation through Secondary LLM Critique","authors":["Zackary Okun Dunivin","Mobina Noori","Seth Frey","Curtis Atkinson"],"abstract":"Large language models (LLMs) allow for sophisticated qualitative coding of large datasets, but zero- and few-shot classifiers can produce an intolerable number of errors, even with careful, validated prompting. We present a simple, generalizable two-stage workflow: an LLM applies a human-designed, LLM-adapted codebook; a secondary LLM critic performs self-reflection on each positive label by re-reading the source text alongside the first model's rationale and issuing a final decision. We evaluate this approach on six qualitative codes over 3,000 high-content emails from Apache Software Foundation project evaluation discussions. Our human-derived audit of 360 positive annotations (60 passages by six codes) found that the first-line LLM had a false-positive rate of 8% to 54%, despite F1 scores of 0.74 and 1.00 in testing. Subsequent recoding of all stage-one annotations via a second self-reflection stage improved F1 by 0.04 to 0.25, bringing two especially poor performing codes up to 0.69 and 0.79 from 0.52 and 0.55 respectively. Our manual evaluation identified two recurrent error classes: misinterpretation (violations of code definitions) and meta-discussion (debate about a project evaluation criterion mistaken for its use as a decision justification). Code-specific critic clauses addressing observed failure modes were especially effective with testing and refinement, replicating the codebook-adaption process for LLM interpretation in stage-one. We explain how favoring recall in first-line LLM annotation combined with secondary critique delivers precision-first, compute-light control. With human guidance and validation, self-reflection slots into existing LLM-assisted annotation pipelines to reduce noise and potentially salvage unusable classifiers.","published":"2026-01-14T22:27:13Z","updated":"2026-01-14T22:27:13Z","categories":["cs.SE","cs.CL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2601.09905v1","pdf_url":"https://arxiv.org/pdf/2601.09905v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.09876","versioned_id":"2601.09876v1","title":"Patient-Similarity Cohort Reasoning in Clinical Text-to-SQL","authors":["Yifei Shen","Yilun Zhao","Justice Ou","Tinglin Huang","Arman Cohan"],"abstract":"Real-world clinical text-to-SQL requires reasoning over heterogeneous EHR tables, temporal windows, and patient-similarity cohorts to produce executable queries. We introduce CLINSQL, a benchmark of 633 expert-annotated tasks on MIMIC-IV v3.1 that demands multi-table joins, clinically meaningful filters, and executable SQL. Solving CLINSQL entails navigating schema metadata and clinical coding systems, handling long contexts, and composing multi-step queries beyond traditional text-to-SQL. We evaluate 22 proprietary and open-source models under Chain-of-Thought self-refinement and use rubric-based SQL analysis with execution checks that prioritize critical clinical requirements. Despite recent advances, performance remains far from clinical reliability: on the test set, GPT-5-mini attains 74.7% execution score, DeepSeek-R1 leads open-source at 69.2% and Gemini-2.5-Pro drops from 85.5% on Easy to 67.2% on Hard. Progress on CLINSQL marks tangible advances toward clinically reliable text-to-SQL for real-world EHR analytics.","published":"2026-01-14T21:12:06Z","updated":"2026-01-14T21:12:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.09876v1","pdf_url":"https://arxiv.org/pdf/2601.09876v1","comment":"Accepted by EACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.09694","versioned_id":"2601.09694v1","title":"LLMs can Compress LLMs: Adaptive Pruning by Agents","authors":["Sai Varun Kodathala","Rakesh Vunnam"],"abstract":"As Large Language Models (LLMs) continue to scale, post-training pruning has emerged as a promising approach to reduce computational costs while preserving performance. Existing methods such as SparseGPT and Wanda achieve high sparsity through layer-wise weight reconstruction or activation-aware magnitude pruning, but rely on uniform or hand-crafted heuristics to determine per-layer sparsity ratios. Moreover, recent work has shown that pruned LLMs suffer from severe factual knowledge degradation, with structured pruning methods experiencing near-total collapse in factual question-answering capabilities. We introduce agent-guided pruning, where a foundation model acts as an adaptive pruning agent to intelligently select which layers to prune at each iteration while preserving critical knowledge pathways. Our method constructs layer-wise sensitivity profiles by combining Wanda-inspired weight-activation metrics with gradient importance scores, normalized as z-scores for model-agnostic comparison. These statistics are processed by an LLM agent equipped with self-reflection capabilities, enabling it to learn from previous pruning outcomes and iteratively refine its strategy. A checkpoint rollback mechanism maintains model quality by reverting when perplexity degradation exceeds a threshold. We evaluate our approach on Qwen3 models (4B and 8B parameters) at approximately 45% sparsity, demonstrating substantial improvements over structured pruning baselines: 56% relative improvement in MMLU accuracy, 19x better factual knowledge retention on FreebaseQA, and 69% lower perplexity degradation. Notably, our framework requires no retraining, operates in a model-agnostic manner, and exhibits effective self-correction with only 2-4 rollbacks across 21-40 iterations, demonstrating that foundation models can effectively guide the compression of other foundation models.","published":"2026-01-14T18:45:36Z","updated":"2026-01-14T18:45:36Z","categories":["cs.CL","cs.AI","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.09694v1","pdf_url":"https://arxiv.org/pdf/2601.09694v1","comment":"17 Pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.14290","versioned_id":"2601.14290v1","title":"Project Aletheia: Verifier-Guided Distillation of Backtracking for Small Language Models","authors":["Aradhya Dixit","Tianxi Liang","Jai Telang"],"abstract":"Small Language Models (SLMs, under 10B parameters) are attractive for private, on-device deployment, yet they frequently fail on strict constraint-satisfaction problems due to linear, overconfident reasoning traces that do not recover from early mistakes. We introduce Verifier-Guided Distillation, a training protocol that transfers the process of error repair - explicit conflict detection and backtracking - rather than only correct final answers. By training a 7B model on verified reasoning traces that include mistakes and self-corrections, we show that latent verification behavior can emerge in small models, enabling them to occasionally stop, detect contradictions, and revise earlier assumptions.","published":"2026-01-14T14:39:08Z","updated":"2026-01-14T14:39:08Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.14290v1","pdf_url":"https://arxiv.org/pdf/2601.14290v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.09413","versioned_id":"2601.09413v2","title":"Speech-Hands: A Self-Reflection Voice Agentic Approach to Speech Recognition and Audio Reasoning with Omni Perception","authors":["Zhen Wan","Chao-Han Huck Yang","Jinchuan Tian","Hanrong Ye","Ankita Pasad","Szu-wei Fu","Arushi Goel","Ryo Hachiuma","Shizhe Diao","Kunal Dhawan","Sreyan Ghosh","Yusuke Hirota","Zhehuai Chen","Rafael Valle","Chenhui Chu","Shinji Watanabe","Yu-Chiang Frank Wang","Boris Ginsburg"],"abstract":"We introduce a voice-agentic framework that learns one critical omni-understanding skill: knowing when to trust itself versus when to consult external audio perception. Our work is motivated by a crucial yet counterintuitive finding: naively fine-tuning an omni-model on both speech recognition and external sound understanding tasks often degrades performance, as the model can be easily misled by noisy hypotheses. To address this, our framework, Speech-Hands, recasts the problem as an explicit self-reflection decision. This learnable reflection primitive proves effective in preventing the model from being derailed by flawed external candidates. We show that this agentic action mechanism generalizes naturally from speech recognition to complex, multiple-choice audio reasoning. Across the OpenASR leaderboard, Speech-Hands consistently outperforms strong baselines by 12.1% WER on seven benchmarks. The model also achieves 77.37% accuracy and high F1 on audio QA decisions, showing robust generalization and reliability across diverse audio question answering datasets. By unifying perception and decision-making, our work offers a practical path toward more reliable and resilient audio intelligence.","published":"2026-01-14T12:06:50Z","updated":"2026-05-18T16:18:39Z","categories":["cs.SD","cs.AI","cs.CL","cs.MA","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2601.09413v2","pdf_url":"https://arxiv.org/pdf/2601.09413v2","comment":"Accepted to ACL 2026. Oral Presentation. Code: https://github.com/YukinoWan/Speech-Hands OpenClaw Branch: https://github.com/openclaw/openclaw/pull/69073","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.08734","versioned_id":"2601.08734v1","title":"TerraFormer: Automated Infrastructure-as-Code with LLMs Fine-Tuned via Policy-Guided Verifier Feedback","authors":["Prithwish Jana","Sam Davidson","Bhavana Bhasker","Andrey Kan","Anoop Deoras","Laurent Callot"],"abstract":"Automating Infrastructure-as-Code (IaC) is challenging, and large language models (LLMs) often produce incorrect configurations from natural language (NL). We present TerraFormer, a neuro-symbolic framework for IaC generation and mutation that combines supervised fine-tuning with verifier-guided reinforcement learning, using formal verification tools to provide feedback on syntax, deployability, and policy compliance. We curate two large, high-quality NL-to-IaC datasets, TF-Gen (152k instances) and TF-Mutn (52k instances), via multi-stage verification and iterative LLM self-correction. Evaluations against 17 state-of-the-art LLMs, including ~50x larger models like Sonnet 3.7, DeepSeek-R1, and GPT-4.1, show that TerraFormer improves correctness over its base LLM by 15.94% on IaC-Eval, 11.65% on TF-Gen (Test), and 19.60% on TF-Mutn (Test). It outperforms larger models on both TF-Gen (Test) and TF-Mutn (Test), ranks third on IaC-Eval, and achieves top best-practices and security compliance.","published":"2026-01-13T17:08:30Z","updated":"2026-01-13T17:08:30Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2601.08734v1","pdf_url":"https://arxiv.org/pdf/2601.08734v1","comment":"The paper has been published at the 2026 IEEE/ACM 48th International Conference on Software Engineering (ICSE 2026), Rio de Janeiro, Brazil, April 12-18, 2026","journal_ref":"","doi":"10.1145/3786583.3786898","discovered_on":"2026-07-17"},{"id":"2601.07780","versioned_id":"2601.07780v1","title":"Enhancing Self-Correction in Large Language Models through Multi-Perspective Reflection","authors":["Mariana Costa","Alberlucia Rafael Soarez","Daniel Kim","Camila Ferreira"],"abstract":"While Chain-of-Thought (CoT) prompting advances LLM reasoning, challenges persist in consistency, accuracy, and self-correction, especially for complex or ethically sensitive tasks. Existing single-dimensional reflection methods offer insufficient improvements. We propose MyGO Poly-Reflective Chain-of-Thought (PR-CoT), a novel methodology employing structured multi-perspective reflection. After initial CoT, PR-CoT guides the LLM to self-assess its reasoning across multiple predefined angles: logical consistency, information completeness, biases/ethics, and alternative solutions. Implemented purely via prompt engineering, this process refines the initial CoT into a more robust and accurate final answer without model retraining. Experiments across arithmetic, commonsense, ethical decision-making, and logical puzzles, using GPT-three point five and GPT-four models, demonstrate PR-CoT's superior performance. It significantly outperforms traditional CoT and existing reflection methods in logical consistency and error correction, with notable gains in nuanced domains like ethical decision-making. Ablation studies, human evaluations, and qualitative analyses further validate the contribution of each reflection perspective and the overall efficacy of our poly-reflective paradigm in fostering more reliable LLM reasoning.","published":"2026-01-12T17:57:05Z","updated":"2026-01-12T17:57:05Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.07780v1","pdf_url":"https://arxiv.org/pdf/2601.07780v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.07779","versioned_id":"2601.07779v1","title":"OS-Symphony: A Holistic Framework for Robust and Generalist Computer-Using Agent","authors":["Bowen Yang","Kaiming Jin","Zhenyu Wu","Zhaoyang Liu","Qiushi Sun","Zehao Li","JingJing Xie","Zhoumianze Liu","Fangzhi Xu","Kanzhi Cheng","Qingyun Li","Yian Wang","Yu Qiao","Zun Wang","Zichen Ding"],"abstract":"While Vision-Language Models (VLMs) have significantly advanced Computer-Using Agents (CUAs), current frameworks struggle with robustness in long-horizon workflows and generalization in novel domains. These limitations stem from a lack of granular control over historical visual context curation and the absence of visual-aware tutorial retrieval. To bridge these gaps, we introduce OS-Symphony, a holistic framework that comprises an Orchestrator coordinating two key innovations for robust automation: (1) a Reflection-Memory Agent that utilizes milestone-driven long-term memory to enable trajectory-level self-correction, effectively mitigating visual context loss in long-horizon tasks; (2) Versatile Tool Agents featuring a Multimodal Searcher that adopts a SeeAct paradigm to navigate a browser-based sandbox to synthesize live, visually aligned tutorials, thereby resolving fidelity issues in unseen scenarios. Experimental results demonstrate that OS-Symphony delivers substantial performance gains across varying model scales, establishing new state-of-the-art results on three online benchmarks, notably achieving 65.84% on OSWorld.","published":"2026-01-12T17:55:51Z","updated":"2026-01-12T17:55:51Z","categories":["cs.MA","cs.AI","cs.CL","cs.CV","cs.HC"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.07779v1","pdf_url":"https://arxiv.org/pdf/2601.07779v1","comment":"31 pages, 11 figures, 12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.07711","versioned_id":"2601.07711v2","title":"Is Agentic RAG worth it? An experimental comparison of RAG approaches","authors":["Pietro Ferrazzi","Milica Cvjeticanin","Alessio Piraccini","Davide Giannuzzi"],"abstract":"Retrieval-Augmented Generation (RAG) systems are usually defined by the combination of a generator and a retrieval component that extracts textual context from a knowledge base to answer user queries. However, such basic implementations exhibit several limitations, including noisy or suboptimal retrieval, misuse of retrieval for out-of-scope queries, weak query-document matching, and variability or cost associated with the generator. These shortcomings have motivated the development of \"Enhanced\" RAG, where dedicated modules are introduced to address specific weaknesses in the workflow. More recently, the growing self-reflective capabilities of Large Language Models (LLMs) have enabled a new paradigm, often referred to as \"Agentic\" RAG. In this approach, an LLM orchestrates the entire process, deciding which actions to perform, when to perform them, and whether to iterate. Despite the rapid adoption of both paradigms, it remains unclear which approach is preferable under which conditions. In this work, we conduct an empirically driven evaluation of \"Enhanced\" and \"Agentic\" RAG across multiple scenarios and dimensions. Our results provide practical insights into the trade-offs between the two paradigms, offering guidance on selecting the most effective RAG design for real-world applications, considering both performance and costs.","published":"2026-01-12T16:43:44Z","updated":"2026-04-20T09:52:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.07711v2","pdf_url":"https://arxiv.org/pdf/2601.07711v2","comment":"Accepted at ACL 2026 (Industry Track)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.07248","versioned_id":"2601.07248v2","title":"DarwinTOD: LLM-driven Lifelong Self-evolution for Task-oriented Dialog Systems","authors":["Shuyu Zhang","Yujie Liu","Xinru Wang","Cheng Zhang","Yanmin Zhu","Bin Li"],"abstract":"Traditional task-oriented dialog systems are unable to evolve from ongoing interactions or adapt to new domains after deployment, that is a critical limitation in real-world dynamic environments. Continual learning approaches depend on episodic retraining with human curated data, failing to achieve autonomy lifelong improvement. While evolutionary computation and LLM driven self improvement offer promising mechanisms for dialog optimization, they lack a unified framework for holistic, iterative strategy refinement. To bridge this gap, we propose DarwinTOD, a lifelong self evolving dialog framework that systematically integrates these two paradigms, enabling continuous strategy optimization from a zero-shot base without task specific fine-tuning. DarwinTOD maintains an Evolvable Strategy Bank and operates through a dual-loop process: online multi-agent dialog execution with peer critique, and offline structured evolutionary operations that refine the strategy bank using accumulated feedback. This closed-loop design enables autonomous continuous improvement without human intervention. Extensive experiments show that DarwinTOD surpasses previous state-of-the-art methods and exhibits continuous performance gains throughout evolution. Our work provides a novel framework for building dialog systems with lifelong self evolution capabilities.","published":"2026-01-12T06:33:58Z","updated":"2026-04-14T03:40:36Z","categories":["cs.MA","cs.HC"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.07248v2","pdf_url":"https://arxiv.org/pdf/2601.07248v2","comment":"Accepted in ACL2026 main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.06803","versioned_id":"2601.06803v2","title":"Forest Before Trees: Latent Superposition for Efficient Visual Reasoning","authors":["Yubo Wang","Juntian Zhang","Yichen Wu","Yankai Lin","Nils Lukas","Yuhan Liu"],"abstract":"While Chain-of-Thought empowers Large Vision-Language Models with multi-step reasoning, explicit textual rationales suffer from an information bandwidth bottleneck, where continuous visual details are discarded during discrete tokenization. Recent latent reasoning methods attempt to address this challenge, but often fall prey to premature semantic collapse due to rigid autoregressive objectives. In this paper, we propose Laser, a novel paradigm that reformulates visual deduction via Dynamic Windowed Alignment Learning (DWAL). Instead of forcing a point-wise prediction, Laser aligns the latent state with a dynamic validity window of future semantics. This mechanism enforces a \"Forest-before-Trees\" cognitive hierarchy, enabling the model to maintain a probabilistic superposition of global features before narrowing down to local details. Crucially, Laser maintains interpretability via decodable trajectories while stabilizing unconstrained learning via Self-Refined Superposition. Extensive experiments on 6 benchmarks demonstrate that Laser achieves state-of-the-art performance among latent reasoning methods, surpassing the strong baseline Monet by 5.03% on average. Notably, it achieves these gains with extreme efficiency, reducing inference tokens by more than 97%, while demonstrating robust generalization to out-of-distribution domains.","published":"2026-01-11T08:30:49Z","updated":"2026-04-20T09:04:42Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.06803v2","pdf_url":"https://arxiv.org/pdf/2601.06803v2","comment":"Accepted by ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.09742","versioned_id":"2601.09742v1","title":"Adaptive Orchestration: Scalable Self-Evolving Multi-Agent Systems","authors":["Sathish Sampath","Anuradha Baskaran"],"abstract":"As Large Language Models (LLMs) are increasingly deployed as autonomous agents, they face a critical scalability bottleneck known as the \"Generalization-Specialization Dilemma.\" Monolithic agents equipped with extensive toolkits suffer from context pollution and attention decay, leading to hallucinations. Conversely, static multi-agent swarms introduce significant latency and resource overhead. This paper introduces a Self-Evolving Concierge System, a novel architecture utilizing a Dynamic Mixture of Experts (DMoE) approach. Unlike recent self-improving agents that rewrite their own codebase, our system preserves stability by dynamically restructuring its runtime environment: \"hiring\" specialized sub-agents based on real-time conversation analysis. We introduce an asynchronous \"Meta-Cognition Engine\" that detects capability gaps, a Least Recently Used (LRU) eviction policy for resource constraints, and a novel \"Surgical History Pruning\" mechanism to mitigate refusal bias. Experimental results demonstrate that this architecture maintains high task success rates while minimizing token consumption compared to static agent swarms.","published":"2026-01-10T07:53:55Z","updated":"2026-01-10T07:53:55Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.09742v1","pdf_url":"https://arxiv.org/pdf/2601.09742v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.06428","versioned_id":"2601.06428v3","title":"BackPlay: Head-Only Look-Back Self-Correction for Diffusion Language Models","authors":["Liming Liu","Binxuan Huang","Zixuan Zhang","Xin Liu","Bing Yin","Tuo Zhao"],"abstract":"Diffusion Language Models (DLMs) decode multiple tokens in parallel, but aggressive multi-token decoding amplifies cross-token dependency errors and can sharply degrade generation quality. We propose BackPlay, a frozen-backbone self-correction framework that trains only a lightweight correction head on a finetuned DLM without updating any backbone or adapter parameters. Because the head is trained on errors produced by the same frozen generator used at inference time, its training distribution aligns with the error patterns of the deployed model. We further introduce Look-back Correction, a training mechanism that injects predictions from earlier, more corrupted denoising states into later, richer contexts, enabling the head to leverage later context to detect mistakes made in earlier generation steps. During inference, BackPlay periodically revisits previously generated tokens through selective remasking and regeneration to limit error accumulation. Across mathematical reasoning and code generation benchmarks, BackPlay improves the speed--quality trade-off of the underlying DLM under multi-token decoding.","published":"2026-01-10T05:04:33Z","updated":"2026-04-22T22:08:24Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.06428v3","pdf_url":"https://arxiv.org/pdf/2601.06428v3","comment":"16 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.06002","versioned_id":"2601.06002v2","title":"The Molecular Structure of Thought: Mapping the Topology of Long Chain-of-Thought Reasoning","authors":["Qiguang Chen","Yantao Du","Ziniu Li","Jinhao Liu","Songyao Duan","Jiarui Guo","Minghao Liu","Jiaheng Liu","Tong Yang","Ge Zhang","Libo Qin","Wanxiang Che","Wenhao Huang"],"abstract":"Large language models (LLMs) often fail to learn effective long chain-of-thought (Long CoT) reasoning from human or non-Long-CoT LLMs imitation. To understand this, we propose that effective and learnable Long CoT trajectories feature stable molecular-like structures in unified view, which are formed by three interaction types: Deep-Reasoning (covalent-like), Self-Reflection (hydrogen-bond-like), and Self-Exploration (van der Waals-like). Analysis of distilled trajectories reveals these structures emerge from Long CoT fine-tuning, not keyword imitation. We introduce Effective Semantic Isomers and show that only bonds promoting fast entropy convergence support stable Long CoT learning, while structural competition impairs training. Drawing on these findings, we present Mole-Syn, a distribution-transfer-graph method that guides synthesis of effective Long CoT structures, boosting performance and RL stability across benchmarks.","published":"2026-01-09T18:39:01Z","updated":"2026-01-13T18:21:01Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.06002v2","pdf_url":"https://arxiv.org/pdf/2601.06002v2","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05877","versioned_id":"2601.05877v3","title":"iReasoner: Trajectory-Aware Intrinsic Reasoning Supervision for Self-Evolving Large Multimodal Models","authors":["Meghana Sunil","Manikandarajan Venmathimaran","Muthu Subash Kavitha"],"abstract":"Recent work shows that large multimodal models (LMMs) can self-improve from unlabeled data via self-play and intrinsic feedback. Yet existing self-evolving frameworks mainly reward final outcomes, leaving intermediate reasoning weakly constrained despite its importance for visually grounded decision making. We propose iReasoner, a self-evolving framework that improves an LMM's implicit reasoning by explicitly eliciting chain-of-thought (CoT) and rewarding its internal agreement. In a Proposer--Solver loop over unlabeled images, iReasoner augments outcome-level intrinsic rewards with a trajectory-aware signal defined over intermediate reasoning steps, providing learning signals that distinguish reasoning paths leading to the same answer without ground-truth labels or external judges. Starting from Qwen2.5-VL-7B, iReasoner yields up to $+2.1$ points across diverse multimodal reasoning benchmarks under fully unsupervised post-training. We hope this work serves as a starting point for reasoning-aware self-improvement in LMMs in purely unsupervised settings. Our code is available at https://meghanaasunil.github.io/iReasoner.","published":"2026-01-09T15:53:42Z","updated":"2026-05-20T07:09:51Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.05877v3","pdf_url":"https://arxiv.org/pdf/2601.05877v3","comment":"ACL 2026 (Findings)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05616","versioned_id":"2601.05616v1","title":"Dual-Phase LLM Reasoning: Self-Evolved Mathematical Frameworks","authors":["ShaoZhen Liu","Xinting Huang","Houwen Peng","Xin Chen","Xinyang Song","Qi Li","Zhenan Sun"],"abstract":"In recent years, large language models (LLMs) have demonstrated significant potential in complex reasoning tasks like mathematical problem-solving. However, existing research predominantly relies on reinforcement learning (RL) frameworks while overlooking supervised fine-tuning (SFT) methods. This paper proposes a new two-stage training framework that enhances models' self-correction capabilities through self-generated long chain-of-thought (CoT) data. During the first stage, a multi-turn dialogue strategy guides the model to generate CoT data incorporating verification, backtracking, subgoal decomposition, and backward reasoning, with predefined rules filtering high-quality samples for supervised fine-tuning. The second stage employs a difficulty-aware rejection sampling mechanism to dynamically optimize data distribution, strengthening the model's ability to handle complex problems. The approach generates reasoning chains extended over 4 times longer while maintaining strong scalability, proving that SFT effectively activates models' intrinsic reasoning capabilities and provides a resource-efficient pathway for complex task optimization. Experimental results demonstrate performance improvements on mathematical benchmarks including GSM8K and MATH500, with the fine-tuned model achieving a substantial improvement on competition-level problems like AIME24. Code will be open-sourced.","published":"2026-01-09T08:19:11Z","updated":"2026-01-09T08:19:11Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.05616v1","pdf_url":"https://arxiv.org/pdf/2601.05616v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05459","versioned_id":"2601.05459v1","title":"Do LLMs Need Inherent Reasoning Before Reinforcement Learning? A Study in Korean Self-Correction","authors":["Hongjin Kim","Jaewook Lee","Kiyoung Lee","Jong-hun Shin","Soojong Lim","Oh-Woog Kwon"],"abstract":"Large Language Models (LLMs) demonstrate strong reasoning and self-correction abilities in high-resource languages like English, but their performance remains limited in low-resource languages such as Korean. In this study, we investigate whether reinforcement learning (RL) can enhance Korean reasoning abilities to a degree comparable to English. Our findings reveal that RL alone yields limited improvements when applied to models lacking inherent Korean reasoning capabilities. To address this, we explore several fine-tuning strategies and show that aligning the model's internal reasoning processes with Korean inputs-particularly by tuning Korean-specific neurons in early layers-is key to unlocking RL's effectiveness. We introduce a self-correction code-switching dataset to facilitate this alignment and observe significant performance gains in both mathematical reasoning and self-correction tasks. Ultimately, we conclude that the crucial factor in multilingual reasoning enhancement is not injecting new linguistic knowledge, but effectively eliciting and aligning existing reasoning capabilities. Our study provides a new perspective on how internal translation and neuron-level tuning contribute to multilingual reasoning alignment in LLMs.","published":"2026-01-09T01:17:31Z","updated":"2026-01-09T01:17:31Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.05459v1","pdf_url":"https://arxiv.org/pdf/2601.05459v1","comment":"IJCNLP-AACL 2025 (Main), Outstanding Paper Award","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05445","versioned_id":"2601.05445v1","title":"Knowledge-Driven Multi-Turn Jailbreaking on Large Language Models","authors":["Songze Li","Ruishi He","Xiaojun Jia","Jun Wang","Zhihui Fu"],"abstract":"Large Language Models (LLMs) face a significant threat from multi-turn jailbreak attacks, where adversaries progressively steer conversations to elicit harmful outputs. However, the practical effectiveness of existing attacks is undermined by several critical limitations: they struggle to maintain a coherent progression over long interactions, often losing track of what has been accomplished and what remains to be done; they rely on rigid or pre-defined patterns, and fail to adapt to the LLM's dynamic and unpredictable conversational state. To address these shortcomings, we introduce Mastermind, a multi-turn jailbreak framework that adopts a dynamic and self-improving approach. Mastermind operates in a closed loop of planning, execution, and reflection, enabling it to autonomously build and refine its knowledge of model vulnerabilities through interaction. It employs a hierarchical planning architecture that decouples high-level attack objectives from low-level tactical execution, ensuring long-term focus and coherence. This planning is guided by a knowledge repository that autonomously discovers and refines effective attack patterns by reflecting on interactive experiences. Mastermind leverages this accumulated knowledge to dynamically recombine and adapt attack vectors, dramatically improving both effectiveness and resilience. We conduct comprehensive experiments against state-of-the-art models, including GPT-5 and Claude 3.7 Sonnet. The results demonstrate that Mastermind significantly outperforms existing baselines, achieving substantially higher attack success rates and harmfulness ratings. Moreover, our framework exhibits notable resilience against multiple advanced defense mechanisms.","published":"2026-01-09T00:27:08Z","updated":"2026-01-09T00:27:08Z","categories":["cs.CR","cs.LG"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2601.05445v1","pdf_url":"https://arxiv.org/pdf/2601.05445v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05187","versioned_id":"2601.05187v1","title":"SimuAgent: An LLM-Based Simulink Modeling Assistant Enhanced with Reinforcement Learning","authors":["Yanchang Liang","Xiaowei Zhao"],"abstract":"Large language models (LLMs) have revolutionized text-based code automation, but their potential in graph-oriented engineering workflows remains under-explored. We introduce SimuAgent, an LLM-powered modeling and simulation agent tailored for Simulink. SimuAgent replaces verbose XML with a concise, dictionary-style Python representation, dramatically cutting token counts, improving interpretability, and enabling fast, in-process simulation. A lightweight plan-execute architecture, trained in two stages, equips the agent with both low-level tool skills and high-level design reasoning. To tackle sparse rewards in long-horizon tasks, we propose Reflection-GRPO (ReGRPO), which augments Group Relative Policy Optimization (GRPO) with self-reflection traces that supply rich intermediate feedback, accelerating convergence and boosting robustness. Experiments on SimuBench, our newly released benchmark comprising 5300 multi-domain modeling tasks, show that a Qwen2.5-7B model fine-tuned with SimuAgent converges faster and achieves higher modeling accuracy than standard RL baselines, and even surpasses GPT-4o when evaluated with few-shot prompting on the same benchmark. Ablations confirm that the two-stage curriculum and abstract-reconstruct data augmentation further enhance generalization. SimuAgent trains and runs entirely on-premise with modest hardware, delivering a privacy-preserving, cost-effective solution for industrial model-driven engineering. SimuAgent bridges the gap between LLMs and graphical modeling environments, offering a practical solution for AI-assisted engineering design in industrial settings.","published":"2026-01-08T18:10:35Z","updated":"2026-01-08T18:10:35Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.05187v1","pdf_url":"https://arxiv.org/pdf/2601.05187v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05184","versioned_id":"2601.05184v1","title":"Observations and Remedies for Large Language Model Bias in Self-Consuming Performative Loop","authors":["Yaxuan Wang","Zhongteng Cai","Yujia Bao","Xueru Zhang","Yang Liu"],"abstract":"The rapid advancement of large language models (LLMs) has led to growing interest in using synthetic data to train future models. However, this creates a self-consuming retraining loop, where models are trained on their own outputs and may cause performance drops and induce emerging biases. In real-world applications, previously deployed LLMs may influence the data they generate, leading to a dynamic system driven by user feedback. For example, if a model continues to underserve users from a group, less query data will be collected from this particular demographic of users. In this study, we introduce the concept of \\textbf{S}elf-\\textbf{C}onsuming \\textbf{P}erformative \\textbf{L}oop (\\textbf{SCPL}) and investigate the role of synthetic data in shaping bias during these dynamic iterative training processes under controlled performative feedback. This controlled setting is motivated by the inaccessibility of real-world user preference data from dynamic production systems, and enables us to isolate and analyze feedback-driven bias evolution in a principled manner. We focus on two types of loops, including the typical retraining setting and the incremental fine-tuning setting, which is largely underexplored. Through experiments on three real-world tasks, we find that the performative loop increases preference bias and decreases disparate bias. We design a reward-based rejection sampling strategy to mitigate the bias, moving towards more trustworthy self-improving systems.","published":"2026-01-08T18:08:15Z","updated":"2026-01-08T18:08:15Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.05184v1","pdf_url":"https://arxiv.org/pdf/2601.05184v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05159","versioned_id":"2601.05159v1","title":"Vision-Language Introspection: Mitigating Overconfident Hallucinations in MLLMs via Interpretable Bi-Causal Steering","authors":["Shuliang Liu","Songbo Yang","Dong Fang","Sihang Jia","Yuqi Tang","Lingfeng Su","Ruoshui Peng","Yibo Yan","Xin Zou","Xuming Hu"],"abstract":"Object hallucination critically undermines the reliability of Multimodal Large Language Models, often stemming from a fundamental failure in cognitive introspection, where models blindly trust linguistic priors over specific visual evidence. Existing mitigations remain limited: contrastive decoding approaches operate superficially without rectifying internal semantic misalignments, while current latent steering methods rely on static vectors that lack instance-specific precision. We introduce Vision-Language Introspection (VLI), a training-free inference framework that simulates a metacognitive self-correction process. VLI first performs Attributive Introspection to diagnose hallucination risks via probabilistic conflict detection and localize the causal visual anchors. It then employs Interpretable Bi-Causal Steering to actively modulate the inference process, dynamically isolating visual evidence from background noise while neutralizing blind confidence through adaptive calibration. VLI achieves state-of-the-art performance on advanced models, reducing object hallucination rates by 12.67% on MMHal-Bench and improving accuracy by 5.8% on POPE.","published":"2026-01-08T17:49:13Z","updated":"2026-01-08T17:49:13Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.05159v1","pdf_url":"https://arxiv.org/pdf/2601.05159v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05016","versioned_id":"2601.05016v1","title":"From Idea to Co-Creation: A Planner-Actor-Critic Framework for Agent Augmented 3D Modeling","authors":["Jin Gao","Saichandu Juluri"],"abstract":"We present a framework that extends the Actor-Critic architecture to creative 3D modeling through multi-agent self-reflection and human-in-the-loop supervision. While existing approaches rely on single-prompt agents that directly execute modeling commands via tools like Blender MCP, our approach introduces a Planner-Actor-Critic architecture. In this design, the Planner coordinates modeling steps, the Actor executes them, and the Critic provides iterative feedback, while human users act as supervisors and advisors throughout the process. Through systematic comparison between single-prompt modeling and our reflective multi-agent approach, we demonstrate improvements in geometric accuracy, aesthetic quality, and task completion rates across diverse 3D modeling scenarios. Our evaluation reveals that critic-guided reflection, combined with human supervisory input, reduces modeling errors and increases complexity and quality of the result compared to direct single-prompt execution. This work establishes that structured agent self-reflection, when augmented by human oversight and advisory guidance, produces higher-quality 3D models while maintaining efficient workflow integration through real-time Blender synchronization.","published":"2026-01-08T15:18:12Z","updated":"2026-01-08T15:18:12Z","categories":["cs.MA","cs.AI","cs.GR","cs.HC"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.05016v1","pdf_url":"https://arxiv.org/pdf/2601.05016v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.04651","versioned_id":"2601.04651v2","title":"Adversarial Yet Cooperative: Multi-Perspective Reasoning in Retrieved-Augmented Language Models","authors":["Can Xu","Lingyong Yan","Jiayi Wu","Haosen Wang","Shuaiqiang Wang","Yuchen Li","Jizhou Huang","Dawei Yin","Xiang Li"],"abstract":"Recent advances in synergizing large reasoning models (LRMs) with retrieval-augmented generation (RAG) have shown promising results, yet two critical challenges remain: (1) reasoning models typically operate from a single, unchallenged perspective, limiting their ability to conduct deep, self-correcting reasoning over external documents, and (2) existing training paradigms rely excessively on outcome-oriented rewards, which provide insufficient signal for shaping the complex, multi-step reasoning process. To address these issues, we propose an Reasoner-Verifier framework named Adversarial Reasoning RAG (ARR). The Reasoner and Verifier engage in reasoning on retrieved evidence and critiquing each other's logic while being guided by process-aware advantage that requires no external scoring model. This reward combines explicit observational signals with internal model uncertainty to jointly optimize reasoning fidelity and verification rigor. Experiments on multiple benchmarks demonstrate the effectiveness of our method.","published":"2026-01-08T06:57:03Z","updated":"2026-01-09T03:12:04Z","categories":["cs.AI","cs.IR","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.04651v2","pdf_url":"https://arxiv.org/pdf/2601.04651v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.04620","versioned_id":"2601.04620v1","title":"AgentDevel: Reframing Self-Evolving LLM Agents as Release Engineering","authors":["Di Zhang"],"abstract":"Recent progress in large language model (LLM) agents has largely focused on embedding self-improvement mechanisms inside the agent or searching over many concurrent variants. While these approaches can raise aggregate scores, they often yield unstable and hard-to-audit improvement trajectories, making it difficult to guarantee non-regression or to reason about failures across versions. We reframe agent improvement as \\textbf{release engineering}: agents are treated as shippable artifacts, and improvement is externalized into a regression-aware release pipeline. We introduce \\textbf{AgentDevel}, a release engineering pipeline that iteratively runs the current agent, produces implementation-blind, symptom-level quality signals from execution traces, synthesizes a single release candidate (RC) via executable diagnosis, and promotes it under flip-centered gating. AgentDevel features three core designs: (i) an implementation-blind LLM critic that characterizes failure appearances without accessing agent internals, (ii) script-based executable diagnosis that aggregates dominant symptom patterns and produces auditable engineering specifications, and (iii) flip-centered gating that prioritizes pass to fail regressions and fail to pass fixes as first-class evidence. Unlike population-based search or in-agent self-refinement, AgentDevel maintains a single canonical version line and emphasizes non-regression as a primary objective. Experiments on execution-heavy benchmarks demonstrate that AgentDevel yields stable improvements with significantly fewer regressions while producing reproducible, auditable artifacts. Overall, AgentDevel provides a practical development discipline for building, debugging, and releasing LLM agents as software development.","published":"2026-01-08T05:49:01Z","updated":"2026-01-08T05:49:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.04620v1","pdf_url":"https://arxiv.org/pdf/2601.04620v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.04531","versioned_id":"2601.04531v1","title":"Self-MedRAG: a Self-Reflective Hybrid Retrieval-Augmented Generation Framework for Reliable Medical Question Answering","authors":["Jessica Ryan","Alexander I. Gumilang","Robert Wiliam","Derwin Suhartono"],"abstract":"Large Language Models (LLMs) have demonstrated significant potential in medical Question Answering (QA), yet they remain prone to hallucinations and ungrounded reasoning, limiting their reliability in high-stakes clinical scenarios. While Retrieval-Augmented Generation (RAG) mitigates these issues by incorporating external knowledge, conventional single-shot retrieval often fails to resolve complex biomedical queries requiring multi-step inference. To address this, we propose Self-MedRAG, a self-reflective hybrid framework designed to mimic the iterative hypothesis-verification process of clinical reasoning. Self-MedRAG integrates a hybrid retrieval strategy, combining sparse (BM25) and dense (Contriever) retrievers via Reciprocal Rank Fusion (RRF) to maximize evidence coverage. It employs a generator to produce answers with supporting rationales, which are then assessed by a lightweight self-reflection module using Natural Language Inference (NLI) or LLM-based verification. If the rationale lacks sufficient evidentiary support, the system autonomously reformulates the query and iterates to refine the context. We evaluated Self-MedRAG on the MedQA and PubMedQA benchmarks. The results demonstrate that our hybrid retrieval approach significantly outperforms single-retriever baselines. Furthermore, the inclusion of the self-reflective loop yielded substantial gains, increasing accuracy on MedQA from 80.00% to 83.33% and on PubMedQA from 69.10% to 79.82%. These findings confirm that integrating hybrid retrieval with iterative, evidence-based self-reflection effectively reduces unsupported claims and enhances the clinical reliability of LLM-based systems.","published":"2026-01-08T02:56:04Z","updated":"2026-01-08T02:56:04Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2601.04531v1","pdf_url":"https://arxiv.org/pdf/2601.04531v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.04442","versioned_id":"2601.04442v2","title":"Addressing Overthinking in Large Vision-Language Models via Gated Perception-Reasoning Optimization","authors":["Xingjian Diao","Zheyuan Liu","Chunhui Zhang","Weiyi Wu","Keyi Kong","Lin Shi","Kaize Ding","Soroush Vosoughi","Jiang Gui"],"abstract":"Large Vision-Language Models (LVLMs) have exhibited strong reasoning capabilities through chain-of-thought mechanisms that generate step-by-step rationales. However, such slow-thinking approaches often lead to overthinking, where models produce excessively verbose responses even for simple queries, resulting in test-time inefficiency and even degraded accuracy. Prior work has attempted to mitigate this issue via adaptive reasoning strategies, but these methods largely overlook a fundamental bottleneck: visual perception failures. We argue that stable reasoning critically depends on low-level visual grounding, and that reasoning errors often originate from imperfect perception rather than insufficient deliberation. To address this limitation, we propose Gated Perception-Reasoning Optimization (GPRO), a meta-reasoning controller that dynamically routes computation among three decision paths at each generation step: a lightweight fast path, a slow perception path for re-examining visual inputs, and a slow reasoning path for internal self-reflection. To learn this distinction, we derive large-scale failure attribution supervision from approximately 790k samples, using teacher models to distinguish perceptual hallucinations from reasoning errors. We then train the controller with multi-objective reinforcement learning to optimize the trade-off between task accuracy and computational cost under uncertainty. Experiments on five benchmarks demonstrate that GPRO substantially improves both accuracy and efficiency, outperforming recent slow-thinking methods while generating significantly shorter responses.","published":"2026-01-07T23:05:17Z","updated":"2026-04-15T06:39:57Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.04442v2","pdf_url":"https://arxiv.org/pdf/2601.04442v2","comment":"Accepted to Annual Meeting of the Association for Computational Linguistics (ACL 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.04394","versioned_id":"2601.04394v1","title":"ARREST: Adversarial Resilient Regulation Enhancing Safety and Truth in Large Language Models","authors":["Sharanya Dasgupta","Arkaprabha Basu","Sujoy Nath","Swagatam Das"],"abstract":"Human cognition, driven by complex neurochemical processes, oscillates between imagination and reality and learns to self-correct whenever such subtle drifts lead to hallucinations or unsafe associations. In recent years, LLMs have demonstrated remarkable performance in a wide range of tasks. However, they still lack human cognition to balance factuality and safety. Bearing the resemblance, we argue that both factual and safety failures in LLMs arise from a representational misalignment in their latent activation space, rather than addressing those as entirely separate alignment issues. We hypothesize that an external network, trained to understand the fluctuations, can selectively intervene in the model to regulate falsehood into truthfulness and unsafe output into safe output without fine-tuning the model parameters themselves. Reflecting the hypothesis, we propose ARREST (Adversarial Resilient Regulation Enhancing Safety and Truth), a unified framework that identifies and corrects drifted features, engaging both soft and hard refusals in addition to factual corrections. Our empirical results show that ARREST not only regulates misalignment but is also more versatile compared to the RLHF-aligned models in generating soft refusals due to adversarial training. We make our codebase available at https://github.com/sharanya-dasgupta001/ARREST.","published":"2026-01-07T21:04:37Z","updated":"2026-01-07T21:04:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.04394v1","pdf_url":"https://arxiv.org/pdf/2601.04394v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.04073","versioned_id":"2601.04073v1","title":"Analyzing Reasoning Consistency in Large Multimodal Models under Cross-Modal Conflicts","authors":["Zhihao Zhu","Jiafeng Liang","Shixin Jiang","Jinlan Fu","Ming Liu","Guanglu Sun","See-Kiong Ng","Bing Qin"],"abstract":"Large Multimodal Models (LMMs) have demonstrated impressive capabilities in video reasoning via Chain-of-Thought (CoT). However, the robustness of their reasoning chains remains questionable. In this paper, we identify a critical failure mode termed textual inertia, where once a textual hallucination occurs in the thinking process, models tend to blindly adhere to the erroneous text while neglecting conflicting visual evidence. To systematically investigate this, we propose the LogicGraph Perturbation Protocol that structurally injects perturbations into the reasoning chains of diverse LMMs spanning both native reasoning architectures and prompt-driven paradigms to evaluate their self-reflection capabilities. The results reveal that models successfully self-correct in less than 10% of cases and predominantly succumb to blind textual error propagation. To mitigate this, we introduce Active Visual-Context Refinement, a training-free inference paradigm which orchestrates an active visual re-grounding mechanism to enforce fine-grained verification coupled with an adaptive context refinement strategy to summarize and denoise the reasoning history. Experiments demonstrate that our approach significantly stifles hallucination propagation and enhances reasoning robustness.","published":"2026-01-07T16:39:34Z","updated":"2026-01-07T16:39:34Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.04073v1","pdf_url":"https://arxiv.org/pdf/2601.04073v1","comment":"10 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.04055","versioned_id":"2601.04055v1","title":"Modular Prompt Optimization: Optimizing Structured Prompts with Section-Local Textual Gradients","authors":["Prith Sharma","Austin Z. Henley"],"abstract":"Prompt quality plays a central role in controlling the behavior, reliability, and reasoning performance of large language models (LLMs), particularly for smaller open-source instruction-tuned models that depend heavily on explicit structure. While recent work has explored automatic prompt optimization using textual gradients and self-refinement, most existing methods treat prompts as monolithic blocks of text, making it difficult to localize errors, preserve critical instructions, or prevent uncontrolled prompt growth. We introduce Modular Prompt Optimization (MPO), a schema-based prompt optimization framework that treats prompts as structured objects composed of fixed semantic sections, including system role, context, task description, constraints, and output format. MPO applies section-local textual gradients, generated by a critic language model, to refine each section independently while keeping the overall prompt schema fixed. Section updates are consolidated through de-duplication to reduce redundancy and interference between components, yielding an interpretable and robust optimization process. We evaluate MPO on two reasoning benchmarks, ARC-Challenge and MMLU, using LLaMA-3 8B-Instruct and Mistral-7B-Instruct as solver models. Across both benchmarks and models, MPO consistently outperforms an untuned structured prompt and the TextGrad baseline, achieving substantial accuracy gains without modifying model parameters or altering prompt structure. These results demonstrate that maintaining a fixed prompt schema while applying localized, section-wise optimization is an effective and practical approach for improving reasoning performance in small open-source LMs.","published":"2026-01-07T16:20:08Z","updated":"2026-01-07T16:20:08Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.04055v1","pdf_url":"https://arxiv.org/pdf/2601.04055v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.03868","versioned_id":"2601.03868v2","title":"What Matters For Safety Alignment?","authors":["Xing Li","Hui-Ling Zhen","Lihao Yin","Xianzhi Yu","Zhenhua Dong","Mingxuan Yuan"],"abstract":"This paper presents a comprehensive empirical study on the safety alignment capabilities. We evaluate what matters for safety alignment in LLMs and LRMs to provide essential insights for developing more secure and reliable AI systems. We systematically investigate and compare the influence of six critical intrinsic model characteristics and three external attack techniques. Our large-scale evaluation is conducted using 32 recent, popular LLMs and LRMs across thirteen distinct model families, spanning a parameter scale from 3B to 235B. The assessment leverages five established safety datasets and probes model vulnerabilities with 56 jailbreak techniques and four CoT attack strategies, resulting in 4.6M API calls. Our key empirical findings are fourfold. First, we identify the LRMs GPT-OSS-20B, Qwen3-Next-80B-A3B-Thinking, and GPT-OSS-120B as the top-three safest models, which substantiates the significant advantage of integrated reasoning and self-reflection mechanisms for robust safety alignment. Second, post-training and knowledge distillation may lead to a systematic degradation of safety alignment. We thus argue that safety must be treated as an explicit constraint or a core optimization objective during these stages, not merely subordinated to the pursuit of general capability. Third, we reveal a pronounced vulnerability: employing a CoT attack via a response prefix can elevate the attack success rate by 3.34x on average and from 0.6% to 96.3% for Seed-OSS-36B-Instruct. This critical finding underscores the safety risks inherent in text-completion interfaces and features that allow user-defined response prefixes in LLM services, highlighting an urgent need for architectural and deployment safeguards. Fourth, roleplay, prompt injection, and gradient-based search for adversarial prompts are the predominant methodologies for eliciting unaligned behaviors in modern models.","published":"2026-01-07T12:31:52Z","updated":"2026-02-24T04:21:01Z","categories":["cs.CL","cs.AI","cs.CR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.03868v2","pdf_url":"https://arxiv.org/pdf/2601.03868v2","comment":"Added more commercial model results, majority voting scores, and theoretical analysis in v2","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.03496","versioned_id":"2601.03496v1","title":"STELLA: Self-Reflective Terminology-Aware Framework for Building an Aerospace Information Retrieval Benchmark","authors":["Bongmin Kim"],"abstract":"Tasks in the aerospace industry heavily rely on searching and reusing large volumes of technical documents, yet there is no public information retrieval (IR) benchmark that reflects the terminology- and query-intent characteristics of this domain. To address this gap, this paper proposes the STELLA (Self-Reflective TErminoLogy-Aware Framework for BuiLding an Aerospace Information Retrieval Benchmark) framework. Using this framework, we introduce the STELLA benchmark, an aerospace-specific IR evaluation set constructed from NASA Technical Reports Server (NTRS) documents via a systematic pipeline that comprises document layout detection, passage chunking, terminology dictionary construction, synthetic query generation, and cross-lingual extension. The framework generates two types of queries: the Terminology Concordant Query (TCQ), which includes the terminology verbatim to evaluate lexical matching, and the Terminology Agnostic Query (TAQ), which utilizes the terminology's description to assess semantic matching. This enables a disentangled evaluation of the lexical and semantic matching capabilities of embedding models. In addition, we combine Chain-of-Density (CoD) and the Self-Reflection method with query generation to improve quality and implement a hybrid cross-lingual extension that reflects real user querying practices. Evaluation of seven embedding models on the STELLA benchmark shows that large decoder-based embedding models exhibit the strongest semantic understanding, while lexical matching methods such as BM25 remain highly competitive in domains where exact lexical matching technical term is crucial. The STELLA benchmark provides a reproducible foundation for reliable performance evaluation and improvement of embedding models in aerospace-domain IR tasks. The STELLA benchmark can be found in https://huggingface.co/datasets/telepix/STELLA.","published":"2026-01-07T01:23:44Z","updated":"2026-01-07T01:23:44Z","categories":["cs.IR","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2601.03496v1","pdf_url":"https://arxiv.org/pdf/2601.03496v1","comment":"25 pages, 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.03483","versioned_id":"2601.03483v1","title":"CALM: Culturally Self-Aware Language Models","authors":["Lingzhi Shen","Xiaohao Cai","Yunfei Long","Imran Razzak","Guanming Chen","Shoaib Jameel"],"abstract":"Cultural awareness in language models is the capacity to understand and adapt to diverse cultural contexts. However, most existing approaches treat culture as static background knowledge, overlooking its dynamic and evolving nature. This limitation reduces their reliability in downstream tasks that demand genuine cultural sensitivity. In this work, we introduce CALM, a novel framework designed to endow language models with cultural self-awareness. CALM disentangles task semantics from explicit cultural concepts and latent cultural signals, shaping them into structured cultural clusters through contrastive learning. These clusters are then aligned via cross-attention to establish fine-grained interactions among related cultural features and are adaptively integrated through a Mixture-of-Experts mechanism along culture-specific dimensions. The resulting unified representation is fused with the model's original knowledge to construct a culturally grounded internal identity state, which is further enhanced through self-prompted reflective learning, enabling continual adaptation and self-correction. Extensive experiments conducted on multiple cross-cultural benchmark datasets demonstrate that CALM consistently outperforms state-of-the-art methods.","published":"2026-01-07T00:28:33Z","updated":"2026-01-07T00:28:33Z","categories":["cs.CL","cs.CY","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.03483v1","pdf_url":"https://arxiv.org/pdf/2601.03483v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.03193","versioned_id":"2601.03193v2","title":"UniCorn: Towards Self-Improving Unified Multimodal Models through Self-Generated Supervision","authors":["Ruiyan Han","Zhen Fang","XinYu Sun","Yuchen Ma","Ziheng Wang","Yu Zeng","Zehui Chen","Lin Chen","Wenxuan Huang","Wei-Jie Xu","Yi Cao","Feng Zhao"],"abstract":"While Unified Multimodal Models (UMMs) have achieved remarkable success in cross-modal comprehension, a significant gap persists in their ability to leverage such internal knowledge for high-quality generation. We formalize this discrepancy as Conduction Aphasia, a phenomenon where models accurately interpret multimodal inputs but struggle to translate that understanding into faithful and controllable synthesis. To address this, we propose UniCorn, a simple yet elegant self-improvement framework that eliminates the need for external data or teacher supervision. By partitioning a single UMM into three collaborative roles: Proposer, Solver, and Judge, UniCorn generates high-quality interactions via self-play and employs cognitive pattern reconstruction to distill latent understanding into explicit generative signals. To validate the restoration of multimodal coherence, we introduce UniCycle, a cycle-consistency benchmark based on a Text to Image to Text reconstruction loop. Extensive experiments demonstrate that UniCorn achieves comprehensive and substantial improvements over the base model across six general image generation benchmarks. Notably, it achieves SOTA performance on TIIF(73.8), DPG(86.8), CompBench(88.5), and UniCycle while further delivering substantial gains of +5.0 on WISE and +6.5 on OneIG. These results highlight that our method significantly enhances T2I generation while maintaining robust comprehension, demonstrating the scalability of fully self-supervised refinement for unified multimodal intelligence.","published":"2026-01-06T17:15:50Z","updated":"2026-01-08T11:08:10Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.03193v2","pdf_url":"https://arxiv.org/pdf/2601.03193v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.02907","versioned_id":"2601.02907v2","title":"Beyond the Black Box: A Survey on the Theory and Mechanism of Large Language Models","authors":["Zeyu Gan","Ruifeng Ren","Wei Yao","Xiaolin Hu","Gengze Xu","Chen Qian","Huayi Tang","Zixuan Gong","Xinhao Yao","Pengwei Tang","Zhenxing Dou","Yong Liu"],"abstract":"The rapid emergence of Large Language Models (LLMs) has precipitated a profound paradigm shift in Artificial Intelligence, delivering monumental engineering successes that increasingly impact modern society. However, a critical paradox persists within the current field: despite the empirical efficacy, our theoretical understanding of LLMs remains disproportionately nascent, forcing these systems to be treated largely as ``black boxes''. To address this theoretical fragmentation, this survey proposes a unified lifecycle-based taxonomy that organizes the research landscape into six distinct stages: Data Preparation, Model Preparation, Training, Alignment, Inference, and Evaluation. Within this framework, we provide a systematic review of the foundational theories and internal mechanisms driving LLM performance. Specifically, we analyze core theoretical issues such as the mathematical justification for data mixtures, the representational limits of various architectures, and the optimization dynamics of alignment algorithms. Moving beyond current best practices, we identify critical frontier challenges, including the theoretical limits of synthetic data self-improvement, the mathematical bounds of safety guarantees, and the mechanistic origins of emergent intelligence. By connecting empirical observations with rigorous scientific inquiry, this work provides a structured roadmap for transitioning LLM development from engineering heuristics toward a principled scientific discipline.","published":"2026-01-06T10:45:53Z","updated":"2026-03-12T16:50:45Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.02907v2","pdf_url":"https://arxiv.org/pdf/2601.02907v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.02880","versioned_id":"2601.02880v3","title":"ReTreVal: Reasoning Tree with Validation and Cross-Problem Memory for Large Language Models","authors":["Abhishek HS","Pavan C Shekar","Arpit Jain","Ashwanth Krishnan"],"abstract":"Every existing inference-time reasoning framework discards all failure context at problem boundaries, leaving a model solving problem 500 no wiser than it was on problem 1. We present ReTreVal (Reasoning Tree with Validation), a training-free framework that closes this gap through adaptive tree exploration with tool-augmented node refinement, typed-failure backtracking that injects categorized error context into the recovered branch, and a self-rewriting memory that accumulates and revises strategy entries across problems, enabling inference-time cross-problem learning on any fixed, unmodified LLM without fine-tuning. ReTreVal achieves 85.8% pass@1 on MATH-500 (+8.6 pp over Zero-Shot CoT, +8.6 pp over the strongest baseline Self-Refine) and 54.4% on MMLU-Pro (+15.3 pp over Self-Refine), with a 3.4:1 win-to-regression ratio confirming genuine error recovery rather than noise. These capabilities, previously requiring gradient updates, allow a 32B model to compete with much larger single-pass systems.","published":"2026-01-06T10:05:30Z","updated":"2026-06-08T07:25:41Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.02880v3","pdf_url":"https://arxiv.org/pdf/2601.02880v3","comment":"15 pages, 1 figure, 12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.05280","versioned_id":"2601.05280v2","title":"On the Limits of Self-Improving in Large Language Models: The Singularity Is Not Near Without Symbolic Model Synthesis","authors":["Hector Zenil"],"abstract":"We formalise recursive self-training in Large Language Models (LLMs) and Generative AI as a discrete-time dynamical system. We prove that if the proportion of exogenous, externally grounded signal $α_t$ vanishes asymptotically ($α_t \\to 0$), the system undergoes degenerative dynamics. We derive two fundamental failure modes: (1) \\textit{Entropy Decay}, where finite sampling effects induce monotonic loss of distributional diversity, and (2) \\textit{Variance Amplification}, where the absence of persistent grounding causes distributional drift via a random-walk mechanism. These behaviours are architectural invariants of distributional learning on finite samples. We show that the collapse results apply specifically to closed-loop density matching without persistent external signal. Systems with non-vanishing exogenous grounding fall outside this regime. However, mainstream Singularity, AGI, and ASI narratives typically posit systems that become increasingly autonomous and require little to no human or external intervention for self-improvement. In that autonomy regime, the vanishing-signal condition is satisfied, and collapse follows under KL-based objectives. To overcome these limits, we propose neurosymbolic integration based on algorithmic probability and program synthesis. The Coding Theorem Method (CTM) enables identification of generative mechanisms rather than mere correlations, escaping the distribution-only constraints that bind standard statistical learning. We conclude that fully autonomous recursive density matching leads to degenerative fixed points, whereas externally anchored or mechanism-based approaches operate under fundamentally different asymptotic dynamics.","published":"2026-01-05T19:50:49Z","updated":"2026-02-21T12:46:50Z","categories":["cs.IT","cs.AI","cs.LG"],"primary_category":"cs.IT","arxiv_url":"https://arxiv.org/abs/2601.05280v2","pdf_url":"https://arxiv.org/pdf/2601.05280v2","comment":"30 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.02454","versioned_id":"2601.02454v1","title":"The Rise of Agentic Testing: Multi-Agent Systems for Robust Software Quality Assurance","authors":["Saba Naqvi","Mohammad Baqar","Nawaz Ali Mohammad"],"abstract":"Software testing has progressed toward intelligent automation, yet current AI-based test generators still suffer from static, single-shot outputs that frequently produce invalid, redundant, or non-executable tests due to the lack of execution aware feedback. This paper introduces an agentic multi-model testing framework a closed-loop, self-correcting system in which a Test Generation Agent, an Execution and Analysis Agent, and a Review and Optimization Agent collaboratively generate, execute, analyze, and refine tests until convergence. By using sandboxed execution, detailed failure reporting, and iterative regeneration or patching of failing tests, the framework autonomously improves test quality and expands coverage. Integrated into a CI/CD-compatible pipeline, it leverages reinforcement signals from coverage metrics and execution outcomes to guide refinement. Empirical evaluations on microservice based applications show up to a 60% reduction in invalid tests, 30% coverage improvement, and significantly reduced human effort compared to single-model baselines demonstrating that multi-agent, feedback-driven loops can evolve software testing into an autonomous, continuously learning quality assurance ecosystem for self-healing, high-reliability codebases.","published":"2026-01-05T18:20:14Z","updated":"2026-01-05T18:20:14Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2601.02454v1","pdf_url":"https://arxiv.org/pdf/2601.02454v1","comment":"11 Pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.02075","versioned_id":"2601.02075v4","title":"MDAgent2: Large Language Model for Code Generation and Knowledge Q&A in Molecular Dynamics","authors":["Zhuofan Shi","Hubao A","Yufei Shao","Dongliang Huang","Hongxu An","Chunxiao Xin","Haiyang Shen","Zhenyu Wang","Yunshan Na","Gang Huang","Xiang Jing"],"abstract":"Molecular dynamics (MD) simulations are essential for understanding atomic-scale behaviors in materials science, yet writing LAMMPS scripts remains highly specialized and time-consuming tasks. Although LLMs show promise in code generation and domain-specific question answering, their performance in MD scenarios is limited by scarce domain data, the high deployment cost of state-of-the-art LLMs, and low code executability. Building upon our prior MDAgent, we present MDAgent2, the first end-to-end framework capable of performing both knowledge Q&A and code generation within the MD domain. We construct a domain-specific data-construction pipeline that yields three high-quality datasets spanning MD knowledge, question answering, and code generation. Based on these datasets, we adopt a three stage post-training strategy--continued pre-training (CPT), supervised fine-tuning (SFT), and reinforcement learning (RL)--to train two domain-adapted models, MD-Instruct and MD-Code. Furthermore, we introduce MD-GRPO, a closed-loop RL method that leverages simulation outcomes as reward signals and recycles low-reward trajectories for continual refinement. We further build MDAgent2-RUNTIME, a deployable multi-agent system that integrates code generation, execution, evaluation, and self-correction. Together with MD-EvalBench proposed in this work, the first benchmark for LAMMPS code generation and question answering, our models and system achieve performance surpassing several strong baselines.This work systematically demonstrates the adaptability and generalization capability of large language models in industrial simulation tasks, laying a methodological foundation for automatic code generation in AI for Science and industrial-scale simulations. URL: https://github.com/FredericVAN/PKU_MDAgent2","published":"2026-01-05T12:56:51Z","updated":"2026-02-06T05:47:09Z","categories":["cs.CE","cs.LG"],"primary_category":"cs.CE","arxiv_url":"https://arxiv.org/abs/2601.02075v4","pdf_url":"https://arxiv.org/pdf/2601.02075v4","comment":"24 pages,4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.02046","versioned_id":"2601.02046v3","title":"Agentic Retoucher for Text-To-Image Generation","authors":["Shaocheng Shen","Jianfeng Liang","Chunlei Cai","Cong Geng","Huiyu Duan","Xiaoyun Zhang","Qiang Hu","Guangtao Zhai"],"abstract":"Text-to-image (T2I) diffusion models such as SDXL and FLUX have achieved impressive photorealism, yet small-scale distortions remain pervasive in limbs, face, text and so on. Existing refinement approaches either perform costly iterative re-generation or rely on vision-language models (VLMs) with weak spatial grounding, leading to semantic drift and unreliable local edits. To close this gap, we propose Agentic Retoucher, a hierarchical decision-driven framework that reformulates post-generation correction as a human-like perception-reasoning-action loop. Specifically, we design (1) a perception agent that learns contextual saliency for fine-grained distortion localization under text-image consistency cues, (2) a reasoning agent that performs human-aligned inferential diagnosis via progressive preference alignment, and (3) an action agent that adaptively plans localized inpainting guided by user preference. This design integrates perceptual evidence, linguistic reasoning, and controllable correction into a unified, self-corrective decision process. To enable fine-grained supervision and quantitative evaluation, we further construct GenBlemish-27K, a dataset of 6K T2I images with 27K annotated artifact regions across 12 categories. Extensive experiments demonstrate that Agentic Retoucher consistently outperforms state-of-the-art methods in perceptual quality, distortion localization and human preference alignment, establishing a new paradigm for self-corrective and perceptually reliable T2I generation.","published":"2026-01-05T12:06:43Z","updated":"2026-03-16T06:59:43Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.02046v3","pdf_url":"https://arxiv.org/pdf/2601.02046v3","comment":"Accepted by CVPR2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.01743","versioned_id":"2601.01743v1","title":"AI Agent Systems: Architectures, Applications, and Evaluation","authors":["Bin Xu"],"abstract":"AI agents -- systems that combine foundation models with reasoning, planning, memory, and tool use -- are rapidly becoming a practical interface between natural-language intent and real-world computation. This survey synthesizes the emerging landscape of AI agent architectures across: (i) deliberation and reasoning (e.g., chain-of-thought-style decomposition, self-reflection and verification, and constraint-aware decision making), (ii) planning and control (from reactive policies to hierarchical and multi-step planners), and (iii) tool calling and environment interaction (retrieval, code execution, APIs, and multimodal perception). We organize prior work into a unified taxonomy spanning agent components (policy/LLM core, memory, world models, planners, tool routers, and critics), orchestration patterns (single-agent vs.\\ multi-agent; centralized vs.\\ decentralized coordination), and deployment settings (offline analysis vs.\\ online interactive assistance; safety-critical vs.\\ open-ended tasks). We discuss key design trade-offs -- latency vs.\\ accuracy, autonomy vs.\\ controllability, and capability vs.\\ reliability -- and highlight how evaluation is complicated by non-determinism, long-horizon credit assignment, tool and environment variability, and hidden costs such as retries and context growth. Finally, we summarize measurement and benchmarking practices (task suites, human preference and utility metrics, success under constraints, robustness and security) and identify open challenges including verification and guardrails for tool actions, scalable memory and context management, interpretability of agent decisions, and reproducible evaluation under realistic workloads.","published":"2026-01-05T02:38:40Z","updated":"2026-01-05T02:38:40Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.01743v1","pdf_url":"https://arxiv.org/pdf/2601.01743v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.01580","versioned_id":"2601.01580v2","title":"The Two-Stage Decision-Sampling Hypothesis: Understanding the Emergence of Self-Reflection in RL-Trained LLMs","authors":["Zibo Zhao","Yuanting Zha","Haipeng Zhang","Xingcheng Xu"],"abstract":"Self-reflection capabilities emerge in Large Language Models after RL post-training, with multi-turn RL achieving substantial gains over SFT counterparts. Yet the mechanism of how a unified optimization objective gives rise to functionally distinct capabilities of generating solutions and evaluating when to revise them remains opaque. To address this question, we introduce the Gradient Attribution Property to characterize how reward gradients distribute across policy components, formalized through the Two-Stage Decision-Sampling (DS) Hypothesis, which decomposes the policy into sampling ($π_{sample}$) for generation and decision ($π_{d}$) for verification. We prove that surrogate rewards exhibit Balanced Gradient Attribution, while SFT and KL penalties exhibit Unbalanced Gradient Attribution, with length-weighting creating asymmetric regularization that constrains $π_{sample}$ while leaving $π_{d}$ under-optimized, providing an theoretical explanation of why RL succeeds where SFT fails. We also empirically validate our theoretical predictions on arithmetic reasoning demonstrates that RL's superior generalization stems primarily from improved decision-making ($π_{d}$) rather than sampling capabilities, providing a first-principles mechanistic explanation for self-correction in thinking models.","published":"2026-01-04T15:59:15Z","updated":"2026-04-10T06:57:17Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.01580v2","pdf_url":"https://arxiv.org/pdf/2601.01580v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.01446","versioned_id":"2601.01446v1","title":"iFlip: Iterative Feedback-driven Counterfactual Example Refinement","authors":["Yilong Wang","Qianli Wang","Nils Feldhus"],"abstract":"Counterfactual examples are minimal edits to an input that alter a model's prediction. They are widely employed in explainable AI to probe model behavior and in natural language processing (NLP) to augment training data. However, generating valid counterfactuals with large language models (LLMs) remains challenging, as existing single-pass methods often fail to induce reliable label changes, neglecting LLMs' self-correction capabilities. To explore this untapped potential, we propose iFlip, an iterative refinement approach that leverages three types of feedback, including model confidence, feature attribution, and natural language. Our results show that iFlip achieves an average 57.8% higher validity than the five state-of-the-art baselines, as measured by the label flipping rate. The user study further corroborates that iFlip outperforms baselines in completeness, overall satisfaction, and feasibility. In addition, ablation studies demonstrate that three components are paramount for iFlip to generate valid counterfactuals: leveraging an appropriate number of iterations, pointing to highly attributed words, and early stopping. Finally, counterfactuals generated by iFlip enable effective counterfactual data augmentation, substantially improving model performance and robustness.","published":"2026-01-04T09:19:45Z","updated":"2026-01-04T09:19:45Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.01446v1","pdf_url":"https://arxiv.org/pdf/2601.01446v1","comment":"In submission","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.01357","versioned_id":"2601.01357v1","title":"Towards LLM-enabled autonomous combustion research: A literature-aware agent for self-corrective modeling workflows","authors":["Ke Xiao","Haoze Zhang","Runze Mao","Han Li","Zhi X. Chen"],"abstract":"The rapid evolution of large language models (LLMs) is transforming artificial intelligence into autonomous research partners, yet a critical gap persists in complex scientific domains such as combustion modeling. Here, practical AI assistance requires the seamless integration of domain literature knowledge with robust execution capabilities for expertise-intensive tools such as computational fluid dynamics (CFD) codes. To bridge this gap, we introduce FlamePilot, an LLM agent designed to empower combustion modeling research through automated and self-corrective CFD workflows. FlamePilot differentiates itself through an architecture that leverages atomic tools to ensure the robust setup and execution of complex simulations in both OpenFOAM and extended frameworks such as DeepFlame. The system is also capable of learning from scientific articles, extracting key information to guide the simulation from initial setup to optimized results. Validation on a public benchmark shows FlamePilot achieved a perfect 1.0 executability score and a 0.438 success rate, surpassing the prior best reported agent scores of 0.625 and 0.250, respectively. Furthermore, a detailed case study on Moderate or Intense Low-oxygen Dilution (MILD) combustion simulation demonstrates its efficacy as a collaborative research copilot, where FlamePilot autonomously translated a research paper into a configured simulation, conducted the simulation, post-processed the results, proposed evidence-based refinements, and managed a multi-step parameter study to convergence under minimal human intervention. By adopting a transparent and interpretable paradigm, FlamePilot establishes a foundational framework for AI-empowered combustion modeling, fostering a collaborative partnership where the agent manages workflow orchestration, freeing the researcher for high-level analysis.","published":"2026-01-04T04:00:28Z","updated":"2026-01-04T04:00:28Z","categories":["cs.LG","physics.flu-dyn"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.01357v1","pdf_url":"https://arxiv.org/pdf/2601.01357v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.01321","versioned_id":"2601.01321v1","title":"Digital Twin AI: Opportunities and Challenges from Large Language Models to World Models","authors":["Rong Zhou","Dongping Chen","Zihan Jia","Yao Su","Yixin Liu","Yiwen Lu","Dongwei Shi","Yue Huang","Tianyang Xu","Yi Pan","Xinliang Li","Yohannes Abate","Qingyu Chen","Zhengzhong Tu","Yu Yang","Yu Zhang","Qingsong Wen","Gengchen Mai","Sunyang Fu","Jiachen Li","Xuyu Wang","Ziran Wang","Jing Huang","Tianming Liu","Yong Chen","Lichao Sun","Lifang He"],"abstract":"Digital twins, as precise digital representations of physical systems, have evolved from passive simulation tools into intelligent and autonomous entities through the integration of artificial intelligence technologies. This paper presents a unified four-stage framework that systematically characterizes AI integration across the digital twin lifecycle, spanning modeling, mirroring, intervention, and autonomous management. By synthesizing existing technologies and practices, we distill a unified four-stage framework that systematically characterizes how AI methodologies are embedded across the digital twin lifecycle: (1) modeling the physical twin through physics-based and physics-informed AI approaches, (2) mirroring the physical system into a digital twin with real-time synchronization, (3) intervening in the physical twin through predictive modeling, anomaly detection, and optimization strategies, and (4) achieving autonomous management through large language models, foundation models, and intelligent agents. We analyze the synergy between physics-based modeling and data-driven learning, highlighting the shift from traditional numerical solvers to physics-informed and foundation models for physical systems. Furthermore, we examine how generative AI technologies, including large language models and generative world models, transform digital twins into proactive and self-improving cognitive systems capable of reasoning, communication, and creative scenario generation. Through a cross-domain review spanning eleven application domains, including healthcare, aerospace, smart manufacturing, robotics, and smart cities, we identify common challenges related to scalability, explainability, and trustworthiness, and outline directions for responsible AI-driven digital twin systems.","published":"2026-01-04T01:17:09Z","updated":"2026-01-04T01:17:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.01321v1","pdf_url":"https://arxiv.org/pdf/2601.01321v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.01126","versioned_id":"2601.01126v2","title":"RoboPhD: Self-Improving Text-to-SQL Through Autonomous Agent Evolution","authors":["Andrew Borthwick","Stephen Ash"],"abstract":"We present RoboPhD, a system where AI agents autonomously conduct research to improve Text-to-SQL performance. RoboPhD implements a closed-loop evolution cycle with two coordinated components: a SQL Generation agent composed of a database analysis script and SQL generation instructions, and an Evolution agent that designs new versions based on performance feedback. Central to the framework is an ELO-based selection mechanism enabling survival-of-the-fittest dynamics while handling non-transitivity in performance. Starting from a naive 70-line baseline, RoboPhD evolves agents through iterative cross-pollination, discovering effective techniques without any external guidance on the Text-to-SQL domain. Our best agent, evolved to 1500 lines over 18 iterations, autonomously discovered strategies such as size-adaptive database analysis that adjusts depth based on schema complexity and SQL generation patterns for column selection, evidence interpretation, and aggregation. Evolution provides the largest gains on cheaper models: while we improve by 2.3 points over a strong Claude Opus 4.5 naive baseline, we show an improvement of 8.9 points over the weaker Claude Haiku model. This enables 'skip a tier' deployment: evolved Haiku exceeds naive Sonnet accuracy, and evolved Sonnet exceeds naive Opus, both at lower cost. The full system achieves 73.67% accuracy on the BIRD test set, demonstrating that AI can autonomously build a strong agentic system with only a trivial human-provided starting point.","published":"2026-01-03T09:16:07Z","updated":"2026-01-26T01:15:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.01126v2","pdf_url":"https://arxiv.org/pdf/2601.01126v2","comment":"18 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.00514","versioned_id":"2601.00514v2","title":"The Illusion of Insight in Reasoning Models","authors":["Liv G. d'Aliberti","Manoel Horta Ribeiro"],"abstract":"Do reasoning models have \"Aha!\" moments? Prior work suggests that models like DeepSeek-R1-Zero undergo sudden mid-trace realizations that lead to accurate outputs, implying an intrinsic capacity for self-correction. Yet, it remains unclear whether such intrinsic shifts in reasoning strategy actually improve performance. Here, we study mid-reasoning shifts and instrument training runs to detect them. Our analysis spans 1M+ reasoning traces, hundreds of training checkpoints, three reasoning domains, and multiple decoding temperatures and model architectures. We find that reasoning shifts are rare, do not become more frequent with training, and seldom improve accuracy, indicating that they do not correspond to prior perceptions of model insight. However, their effect varies with model uncertainty. Building on this finding, we show that artificially triggering extrinsic shifts under high entropy reliably improves accuracy. Our results show that mid-reasoning shifts are symptoms of unstable inference behavior rather than an intrinsic mechanism for self-correction.","published":"2026-01-02T00:12:13Z","updated":"2026-04-19T22:05:38Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.00514v2","pdf_url":"https://arxiv.org/pdf/2601.00514v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.00290","versioned_id":"2601.00290v2","title":"ClinicalReTrial: Clinical Trial Redesign with Self-Evolving Agents","authors":["Sixue Xing","Kerui Wu","Xuanye Xia","Meng Jiang","Jintai Chen","Tianfan Fu"],"abstract":"Clinical trials constitute a critical yet exceptionally challenging and costly stage of drug development (\\$2.6B per drug), where protocols are encoded as complex natural language documents, motivating the use of AI systems beyond manual analysis. Existing AI methods accurately predict trial failure, but do not provide actionable remedies. To fill this gap, this paper proposes ClinicalReTrial, a multi-agent system that formulates clinical trial optimization as an iterative redesign problem on textural protocols. Our method integrates failure diagnosis, safety-aware modifications, and candidate evaluation in a closed-loop, reward-driven optimization framework. Serving the outcome prediction model as a simulation environment, ClinicalReTrial enables low-cost evaluation and dense reward signals for continuous self-improvement. We further propose a hierarchical memory that captures iteration-level feedback within trials and distills transferable redesign patterns across trials. Empirically, ClinicalReTrial improves $83.3\\%$ of trial protocols with a mean success probability gain of $5.7\\%$ with negligible cost (\\$0.12 per trial). Retrospective case studies demonstrate alignment between the discovered redesign strategies and real-world clinical trial modifications. The code is anonymously available at: https://github.com/xingsixue123/ClinicalFailureReasonReTrial.","published":"2026-01-01T10:11:58Z","updated":"2026-04-02T21:02:45Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.00290v2","pdf_url":"https://arxiv.org/pdf/2601.00290v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.00215","versioned_id":"2601.00215v2","title":"Disentangling Perception and Reasoning in Multimodal LLMs via Reward Design","authors":["Omar Sharif","Eftekhar Hossain","Nikhil Singh","Patrick Ng"],"abstract":"Reinforcement learning with verifiable rewards has driven major gains in LLM reasoning, and it is intuitive to assume this recipe will transfer well to multimodal models. However, multimodal models do two things: first, perceive what is in an image, then reason about what it implies. Because these stages are graded jointly, it is hard to tell how much room reasoning alone has to grow. We study this on algorithmic visual puzzles, where both components are necessary and show that perception, not reasoning, is the binding constraint. Replacing images with simple textual descriptions raises performance by over 20 points on average for Claude models. We then evaluate six reward designs aimed at inducing visual grounding during reasoning without chain-of-thought supervision. Training Qwen-2.5-VL-7B with GRPO, reward design induces long, structured reasoning with self-reflection and visual references, yielding a 5.56-point gain over the base model. These gains are, however, uneven; no single reward improves all categories, and rewards with verifiable accuracy signals trade out-of-domain transfer for in-domain accuracy. These results point to perception-aware reward design as a path forward, so that signals correct perception at its source rather than the reasoning that inherits its errors.","published":"2026-01-01T05:19:28Z","updated":"2026-06-15T20:37:49Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2601.00215v2","pdf_url":"https://arxiv.org/pdf/2601.00215v2","comment":"24 pages, 15 Figures, 10 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.00885","versioned_id":"2601.00885v1","title":"Counterfactual Self-Questioning for Stable Policy Optimization in Language Models","authors":["Mandar Parab"],"abstract":"Recent work on language model self-improvement shows that models can refine their own reasoning through reflection, verification, debate, or self-generated rewards. However, most existing approaches rely on external critics, learned reward models, or ensemble sampling, which increases complexity and training instability. We propose Counterfactual Self-Questioning, a framework in which a single language model generates and evaluates counterfactual critiques of its own reasoning. The method produces an initial reasoning trace, formulates targeted questions that challenge potential failure points, and generates alternative reasoning trajectories that expose incorrect assumptions or invalid steps. These counterfactual trajectories provide structured relative feedback that can be directly used for policy optimization without auxiliary models. Experiments on multiple mathematical reasoning benchmarks show that counterfactual self-questioning improves accuracy and training stability, particularly for smaller models, enabling scalable self-improvement using internally generated supervision alone.","published":"2025-12-31T09:10:37Z","updated":"2025-12-31T09:10:37Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.00885v1","pdf_url":"https://arxiv.org/pdf/2601.00885v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.24702","versioned_id":"2512.24702v1","title":"Evolving, Not Training: Zero-Shot Reasoning Segmentation via Evolutionary Prompting","authors":["Kai Ye","Xiaotong You","Jianghang Lin","Jiayi Ji","Pingyang Dai","Liujuan Cao"],"abstract":"Reasoning Segmentation requires models to interpret complex, context-dependent linguistic queries to achieve pixel-level localization. Current dominant approaches rely heavily on Supervised Fine-Tuning (SFT) or Reinforcement Learning (RL). However, SFT suffers from catastrophic forgetting and domain dependency, while RL is often hindered by training instability and rigid reliance on predefined reward functions. Although recent training-free methods circumvent these training burdens, they are fundamentally limited by a static inference paradigm. These methods typically rely on a single-pass \"generate-then-segment\" chain, which suffers from insufficient reasoning depth and lacks the capability to self-correct linguistic hallucinations or spatial misinterpretations. In this paper, we challenge these limitations and propose EVOL-SAM3, a novel zero-shot framework that reformulates reasoning segmentation as an inference-time evolutionary search process. Instead of relying on a fixed prompt, EVOL-SAM3 maintains a population of prompt hypotheses and iteratively refines them through a \"Generate-Evaluate-Evolve\" loop. We introduce a Visual Arena to assess prompt fitness via reference-free pairwise tournaments, and a Semantic Mutation operator to inject diversity and correct semantic errors. Furthermore, a Heterogeneous Arena module integrates geometric priors with semantic reasoning to ensure robust final selection. Extensive experiments demonstrate that EVOL-SAM3 not only substantially outperforms static baselines but also significantly surpasses fully supervised state-of-the-art methods on the challenging ReasonSeg benchmark in a zero-shot setting. The code is available at https://github.com/AHideoKuzeA/Evol-SAM3.","published":"2025-12-31T08:10:03Z","updated":"2025-12-31T08:10:03Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.24702v1","pdf_url":"https://arxiv.org/pdf/2512.24702v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.24695","versioned_id":"2512.24695v1","title":"Nested Learning: The Illusion of Deep Learning Architectures","authors":["Ali Behrouz","Meisam Razaviyayn","Peilin Zhong","Vahab Mirrokni"],"abstract":"Despite the recent progresses, particularly in developing Language Models, there are fundamental challenges and unanswered questions about how such models can continually learn/memorize, self-improve, and find effective solutions. In this paper, we present a new learning paradigm, called Nested Learning (NL), that coherently represents a machine learning model with a set of nested, multi-level, and/or parallel optimization problems, each of which with its own context flow. Through the lenses of NL, existing deep learning methods learns from data through compressing their own context flow, and in-context learning naturally emerges in large models. NL suggests a philosophy to design more expressive learning algorithms with more levels, resulting in higher-order in-context learning and potentially unlocking effective continual learning capabilities. We advocate for NL by presenting three core contributions: (1) Expressive Optimizers: We show that known gradient-based optimizers, such as Adam, SGD with Momentum, etc., are in fact associative memory modules that aim to compress the gradients' information (by gradient descent). Building on this insight, we present other more expressive optimizers with deep memory and/or more powerful learning rules; (2) Self-Modifying Learning Module: Taking advantage of NL's insights on learning algorithms, we present a sequence model that learns how to modify itself by learning its own update algorithm; and (3) Continuum Memory System: We present a new formulation for memory system that generalizes the traditional viewpoint of long/short-term memory. Combining our self-modifying sequence model with the continuum memory system, we present a continual learning module, called Hope, showing promising results in language modeling, knowledge incorporation, and few-shot generalization tasks, continual learning, and long-context reasoning tasks.","published":"2025-12-31T07:59:43Z","updated":"2025-12-31T07:59:43Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.24695v1","pdf_url":"https://arxiv.org/pdf/2512.24695v1","comment":"A version of this work is published at Neural Information Processing Systems (NeurIPS) 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.24103","versioned_id":"2512.24103v1","title":"Enhancing LLM Planning Capabilities through Intrinsic Self-Critique","authors":["Bernd Bohnet","Pierre-Alexandre Kamienny","Hanie Sedghi","Dilan Gorur","Pranjal Awasthi","Aaron Parisi","Kevin Swersky","Rosanne Liu","Azade Nova","Noah Fiedel"],"abstract":"We demonstrate an approach for LLMs to critique their \\emph{own} answers with the goal of enhancing their performance that leads to significant improvements over established planning benchmarks. Despite the findings of earlier research that has cast doubt on the effectiveness of LLMs leveraging self critique methods, we show significant performance gains on planning datasets in the Blocksworld domain through intrinsic self-critique, without external source such as a verifier. We also demonstrate similar improvements on Logistics and Mini-grid datasets, exceeding strong baseline accuracies. We employ a few-shot learning technique and progressively extend it to a many-shot approach as our base method and demonstrate that it is possible to gain substantial improvement on top of this already competitive approach by employing an iterative process for correction and refinement. We illustrate how self-critique can significantly boost planning performance. Our empirical results present new state-of-the-art on the class of models considered, namely LLM model checkpoints from October 2024. Our primary focus lies on the method itself, demonstrating intrinsic self-improvement capabilities that are applicable regardless of the specific model version, and we believe that applying our method to more complex search techniques and more capable models will lead to even better performance.","published":"2025-12-30T09:23:25Z","updated":"2025-12-30T09:23:25Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.24103v1","pdf_url":"https://arxiv.org/pdf/2512.24103v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.24077","versioned_id":"2512.24077v1","title":"LoongFlow: Directed Evolutionary Search via a Cognitive Plan-Execute-Summarize Paradigm","authors":["Chunhui Wan","Xunan Dai","Zhuo Wang","Minglei Li","Yanpeng Wang","Yinan Mao","Yu Lan","Zhiwen Xiao"],"abstract":"The transition from static Large Language Models (LLMs) to self-improving agents is hindered by the lack of structured reasoning in traditional evolutionary approaches. Existing methods often struggle with premature convergence and inefficient exploration in high-dimensional code spaces. To address these challenges, we introduce LoongFlow, a self-evolving agent framework that achieves state-of-the-art solution quality with significantly reduced computational costs. Unlike \"blind\" mutation operators, LoongFlow integrates LLMs into a cognitive \"Plan-Execute-Summarize\" (PES) paradigm, effectively mapping the evolutionary search to a reasoning-heavy process. To sustain long-term architectural coherence, we incorporate a hybrid evolutionary memory system. By synergizing Multi-Island models with MAP-Elites and adaptive Boltzmann selection, this system theoretically balances the exploration-exploitation trade-off, maintaining diverse behavioral niches to prevent optimization stagnation. We instantiate LoongFlow with a General Agent for algorithmic discovery and an ML Agent for pipeline optimization. Extensive evaluations on the AlphaEvolve benchmark and Kaggle competitions demonstrate that LoongFlow outperforms leading baselines (e.g., OpenEvolve, ShinkaEvolve) by up to 60% in evolutionary efficiency while discovering superior solutions. LoongFlow marks a substantial step forward in autonomous scientific discovery, enabling the generation of expert-level solutions with reduced computational overhead.","published":"2025-12-30T08:39:28Z","updated":"2025-12-30T08:39:28Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.24077v1","pdf_url":"https://arxiv.org/pdf/2512.24077v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.23880","versioned_id":"2512.23880v2","title":"CASCADE: Cumulative Agentic Skill Creation through Autonomous Development and Evolution","authors":["Xu Huang","Junwu Chen","Yuxing Fei","Zhuohan Li","Philippe Schwaller","Gerbrand Ceder"],"abstract":"Large language model (LLM) agents currently depend on predefined tools or early-stage tool generation, limiting their adaptability and scalability to complex scientific tasks. We introduce CASCADE, a self-evolving agentic framework representing an early instantiation of the transition from \"LLM + tool use\" to \"LLM + skill acquisition\". CASCADE enables agents to master complex external tools and codify knowledge through two meta-skills: continuous learning via web search, code extraction, and memory utilization; self-reflection via introspection, knowledge graph exploration, and others. We evaluate CASCADE on SciSkillBench, a benchmark of 116 materials science and chemistry research tasks. CASCADE achieves a 93.3% success rate using GPT-5, compared to 35.4% without evolution mechanisms. We further demonstrate real-world applications in computational analysis, autonomous laboratory experiments, and selective reproduction of published papers. Along with human-agent collaboration and memory consolidation, CASCADE accumulates executable skills that can be shared across agents and scientists, moving toward scalable AI-assisted scientific research.","published":"2025-12-29T21:50:23Z","updated":"2026-01-28T06:08:09Z","categories":["cs.AI","cond-mat.mtrl-sci"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.23880v2","pdf_url":"https://arxiv.org/pdf/2512.23880v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.23379","versioned_id":"2512.23379v3","title":"SoulX-FlashTalk: Real-Time Infinite Streaming of Audio-Driven Avatars via Self-Correcting Bidirectional Distillation","authors":["Le Shen","Qian Qiao","Tan Yu","Ke Zhou","Tianhang Yu","Yu Zhan","Zhenjie Wang","Ming Tao","Shunshun Yin","Siyuan Liu"],"abstract":"Deploying massive diffusion models for real-time, infinite-duration, audio-driven avatar generation presents a significant engineering challenge, primarily due to the conflict between computational load and strict latency constraints. Existing approaches often compromise visual fidelity by enforcing strictly unidirectional attention mechanisms or reducing model capacity. To address this problem, we introduce \\textbf{SoulX-FlashTalk}, a 14B-parameter framework optimized for high-fidelity real-time streaming. Diverging from conventional unidirectional paradigms, we use a \\textbf{Self-correcting Bidirectional Distillation} strategy that retains bidirectional attention within video chunks. This design preserves critical spatiotemporal correlations, significantly enhancing motion coherence and visual detail. To ensure stability during infinite generation, we incorporate a \\textbf{Multi-step Retrospective Self-Correction Mechanism}, enabling the model to autonomously recover from accumulated errors and preventing collapse. Furthermore, we engineered a full-stack inference acceleration suite incorporating hybrid sequence parallelism, Parallel VAE, and kernel-level optimizations. Extensive evaluations confirm that SoulX-FlashTalk is the first 14B-scale system to achieve a \\textbf{sub-second start-up latency (0.87s)} while reaching a real-time throughput of \\textbf{32 FPS}, setting a new standard for high-fidelity interactive digital human synthesis.","published":"2025-12-29T11:18:24Z","updated":"2026-01-06T04:58:08Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.23379v3","pdf_url":"https://arxiv.org/pdf/2512.23379v3","comment":"12 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.23167","versioned_id":"2512.23167v1","title":"SPIRAL: Symbolic LLM Planning via Grounded and Reflective Search","authors":["Yifan Zhang","Giridhar Ganapavarapu","Srideepika Jayaraman","Bhavna Agrawal","Dhaval Patel","Achille Fokoue"],"abstract":"Large Language Models (LLMs) often falter at complex planning tasks that require exploration and self-correction, as their linear reasoning process struggles to recover from early mistakes. While search algorithms like Monte Carlo Tree Search (MCTS) can explore alternatives, they are often ineffective when guided by sparse rewards and fail to leverage the rich semantic capabilities of LLMs. We introduce SPIRAL (Symbolic LLM Planning via Grounded and Reflective Search), a novel framework that embeds a cognitive architecture of three specialized LLM agents into an MCTS loop. SPIRAL's key contribution is its integrated planning pipeline where a Planner proposes creative next steps, a Simulator grounds the search by predicting realistic outcomes, and a Critic provides dense reward signals through reflection. This synergy transforms MCTS from a brute-force search into a guided, self-correcting reasoning process. On the DailyLifeAPIs and HuggingFace datasets, SPIRAL consistently outperforms the default Chain-of-Thought planning method and other state-of-the-art agents. More importantly, it substantially surpasses other state-of-the-art agents; for example, SPIRAL achieves 83.6% overall accuracy on DailyLifeAPIs, an improvement of over 16 percentage points against the next-best search framework, while also demonstrating superior token efficiency. Our work demonstrates that structuring LLM reasoning as a guided, reflective, and grounded search process yields more robust and efficient autonomous planners. The source code, full appendices, and all experimental data are available for reproducibility at the official project repository.","published":"2025-12-29T03:19:42Z","updated":"2025-12-29T03:19:42Z","categories":["cs.AI","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.23167v1","pdf_url":"https://arxiv.org/pdf/2512.23167v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.23126","versioned_id":"2512.23126v3","title":"InSPO: Unlocking Intrinsic Self-Reflection for LLM Preference Optimization","authors":["Yu Li","Tian Lan","Zhengling Qi"],"abstract":"Direct Preference Optimization (DPO) and its variants have become standard for aligning Large Language Models due to their simplicity and offline stability. However, we identify two fundamental limitations. First, the optimal policy depends on arbitrary modeling choices (scalarization function, reference policy), yielding behavior reflecting parameterization artifacts rather than true preferences. Second, treating response generation in isolation fails to leverage comparative information in pairwise data, leaving the model's capacity for intrinsic self-reflection untapped. To address it, we propose Intrinsic Self-reflective Preference Optimization (InSPO), deriving a globally optimal policy conditioning on both context and alternative responses. We prove this formulation superior to DPO/RLHF while guaranteeing invariance to scalarization and reference choices. InSPO serves as a plug-and-play enhancement without architectural changes or inference overhead. Experiments demonstrate consistent improvements in win rates and length-controlled metrics, validating that unlocking self-reflection yields more robust, human-aligned LLMs. Our Code is available at https://github.com/Skylanding/InSPO.","published":"2025-12-29T00:59:23Z","updated":"2026-02-09T15:57:24Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.23126v3","pdf_url":"https://arxiv.org/pdf/2512.23126v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.23760","versioned_id":"2512.23760v1","title":"Audited Skill-Graph Self-Improvement for Agentic LLMs via Verifiable Rewards, Experience Synthesis, and Continual Memory","authors":["Ken Huang","Jerry Huang"],"abstract":"Reinforcement learning is increasingly used to transform large language models into agentic systems that act over long horizons, invoke tools, and manage memory under partial observability. While recent work has demonstrated performance gains through tool learning, verifiable rewards, and continual training, deployed self-improving agents raise unresolved security and governance challenges: optimization pressure can incentivize reward hacking, behavioral drift is difficult to audit or reproduce, and improvements are often entangled in opaque parameter updates rather than reusable, verifiable artifacts. This paper proposes Audited Skill-Graph Self-Improvement (ASG-SI), a framework that treats self-improvement as iterative compilation of an agent into a growing, auditable skill graph. Each candidate improvement is extracted from successful trajectories, normalized into a skill with an explicit interface, and promoted only after passing verifier-backed replay and contract checks. Rewards are decomposed into reconstructible components derived from replayable evidence, enabling independent audit of promotion decisions and learning signals. ASG-SI further integrates experience synthesis for scalable stress testing and continual memory control to preserve long-horizon performance under bounded context. We present a complete system architecture, threat model, and security analysis, and provide a fully runnable reference implementation that demonstrates verifier-backed reward construction, skill compilation, audit logging, and measurable improvement under continual task streams. ASG-SI reframes agentic self-improvement as accumulation of verifiable, reusable capabilities, offering a practical path toward reproducible evaluation and operational governance of self-improving AI agents.","published":"2025-12-28T19:39:47Z","updated":"2025-12-28T19:39:47Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2512.23760v1","pdf_url":"https://arxiv.org/pdf/2512.23760v1","comment":"11 pages, 4 figures. Includes a complete runnable reference implementation and audit logging framework","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.22627","versioned_id":"2512.22627v1","title":"Chain-of-thought Reviewing and Correction for Time Series Question Answering","authors":["Chen Su","Yuanhe Tian","Yan Song"],"abstract":"With the advancement of large language models (LLMs), diverse time series analysis tasks are reformulated as time series question answering (TSQA) through a unified natural language interface. However, existing LLM-based approaches largely adopt general natural language processing techniques and are prone to reasoning errors when handling complex numerical sequences. Different from purely textual tasks, time series data are inherently verifiable, enabling consistency checking between reasoning steps and the original input. Motivated by this property, we propose T3LLM, which performs multi-step reasoning with an explicit correction mechanism for time series question answering. The T3LLM framework consists of three LLMs, namely, a worker, a reviewer, and a student, that are responsible for generation, review, and reasoning learning, respectively. Within this framework, the worker generates step-wise chains of thought (CoT) under structured prompts, while the reviewer inspects the reasoning, identifies erroneous steps, and provides corrective comments. The collaboratively generated corrected CoT are used to fine-tune the student model, internalizing multi-step reasoning and self-correction into its parameters. Experiments on multiple real-world TSQA benchmarks demonstrate that T3LLM achieves state-of-the-art performance over strong LLM-based baselines.","published":"2025-12-27T15:54:18Z","updated":"2025-12-27T15:54:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.22627v1","pdf_url":"https://arxiv.org/pdf/2512.22627v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.21481","versioned_id":"2512.21481v1","title":"The AI Committee: A Multi-Agent Framework for Automated Validation and Remediation of Web-Sourced Data","authors":["Sunith Vallabhaneni","Thomas Berkane","Maimuna Majumder"],"abstract":"Many research areas rely on data from the web to gain insights and test their methods. However, collecting comprehensive research datasets often demands manually reviewing many web pages to identify and record relevant data points, which is labor-intensive and susceptible to error. While the emergence of large language models (LLM)-powered web agents has begun to automate parts of this process, they often struggle to ensure the validity of the data they collect. Indeed, these agents exhibit several recurring failure modes - including hallucinating or omitting values, misinterpreting page semantics, and failing to detect invalid information - which are subtle and difficult to detect and correct manually. To address this, we introduce the AI Committee, a novel model-agnostic multi-agent system that automates the process of validating and remediating web-sourced datasets. Each agent is specialized in a distinct task in the data quality assurance pipeline, from source scrutiny and fact-checking to data remediation and integrity validation. The AI Committee leverages various LLM capabilities - including in-context learning for dataset adaptation, chain-of-thought reasoning for complex semantic validation, and a self-correction loop for data remediation - all without task-specific training. We demonstrate the effectiveness of our system by applying it to three real-world datasets, showing that it generalizes across LLMs and significantly outperforms baseline approaches, achieving data completeness up to 78.7% and precision up to 100%. We additionally conduct an ablation study demonstrating the contribution of each agent to the Committee's performance. This work is released as an open-source tool for the research community.","published":"2025-12-25T03:00:22Z","updated":"2025-12-25T03:00:22Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2512.21481v1","pdf_url":"https://arxiv.org/pdf/2512.21481v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.00828","versioned_id":"2601.00828v1","title":"Decomposing LLM Self-Correction: The Accuracy-Correction Paradox and Error Depth Hypothesis","authors":["Yin Li"],"abstract":"Large Language Models (LLMs) are widely believed to possess self-correction capabilities, yet recent studies suggest that intrinsic self-correction--where models correct their own outputs without external feedback--remains largely ineffective. In this work, we systematically decompose self-correction into three distinct sub-capabilities: error detection, error localization, and error correction. Through cross-model experiments on GSM8K-Complex (n=500 per model, 346 total errors) with three major LLMs, we uncover a striking Accuracy-Correction Paradox: weaker models (GPT-3.5, 66% accuracy) achieve 1.6x higher intrinsic correction rates than stronger models (DeepSeek, 94% accuracy)--26.8% vs 16.7%. We propose the Error Depth Hypothesis: stronger models make fewer but deeper errors that resist self-correction. Error detection rates vary dramatically across architectures (10% to 82%), yet detection capability does not predict correction success--Claude detects only 10% of errors but corrects 29% intrinsically. Surprisingly, providing error location hints hurts all models. Our findings challenge linear assumptions about model capability and self-improvement, with important implications for the design of self-refinement pipelines.","published":"2025-12-24T21:51:24Z","updated":"2025-12-24T21:51:24Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.00828v1","pdf_url":"https://arxiv.org/pdf/2601.00828v1","comment":"9 pages, 2 figures, 3 tables. Code available at https://github.com/Kevin0304-li/llm-self-correction","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.20954","versioned_id":"2512.20954v1","title":"Reflection Pretraining Enables Token-Level Self-Correction in Biological Sequence Models","authors":["Xiang Zhang","Jiaqi Wei","Yuejin Yang","Zijie Qiu","Yuhan Chen","Zhiqiang Gao","Muhammad Abdul-Mageed","Laks V. S. Lakshmanan","Wanli Ouyang","Chenyu You","Siqi Sun"],"abstract":"Chain-of-Thought (CoT) prompting has significantly advanced task-solving capabilities in natural language processing with large language models. Unlike standard prompting, CoT encourages the model to generate intermediate reasoning steps, non-answer tokens, that help guide the model toward more accurate final outputs. These intermediate steps enable more complex reasoning processes such as error correction, memory management, future planning, and self-reflection. However, applying CoT to non-natural language domains, such as protein and RNA language models, is not yet possible, primarily due to the limited expressiveness of their token spaces (e.g., amino acid tokens). In this work, we propose and define the concept of language expressiveness: the ability of a given language, using its tokens and grammar, to encode information. We show that the limited expressiveness of protein language severely restricts the applicability of CoT-style reasoning. To overcome this, we introduce reflection pretraining, for the first time in a biological sequence model, which enables the model to engage in intermediate reasoning through the generation of auxiliary \"thinking tokens\" beyond simple answer tokens. Theoretically, we demonstrate that our augmented token set significantly enhances biological language expressiveness, thereby improving the overall reasoning capacity of the model. Experimentally, our pretraining approach teaches protein models to self-correct and leads to substantial performance gains compared to standard pretraining.","published":"2025-12-24T05:25:17Z","updated":"2025-12-24T05:25:17Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.20954v1","pdf_url":"https://arxiv.org/pdf/2512.20954v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.20884","versioned_id":"2512.20884v1","title":"The Silent Scholar Problem: A Probabilistic Framework for Breaking Epistemic Asymmetry in LLM Agents","authors":["Zan-Kai Chong","Hiroyuki Ohsaki","Bryan Ng"],"abstract":"Autonomous agents powered by LLMs and Retrieval-Augmented Generation (RAG) are proficient consumers of digital content but remain unidirectional, a limitation we term epistemic asymmetry. This isolation leads to redundant reasoning and stagnates collective intelligence. Current self-reflection frameworks remain largely heuristic and private, lacking a probabilistic foundation to quantify certainty or justify external interaction.To bridge this gap, we propose a formal probabilistic framework that provides agents with a non-altruistic motive for bidirectional knowledge exchange. We model an agent's belief in a proposition using a Beta-Bernoulli distribution with a forgetting factor ($γ$). This allows us to isolate epistemic uncertainty as the variance of belief, establishing a dual drive for interaction: A homeostatic motive: The need to maintain certainty against the temporal decay introduced by $γ$. An optimal learning strategy: Targeting points of maximum ambiguity ($\\mathbb{E}[θ]=0.5$) to maximize information gain. Under this framework, public contribution is reframed as optimal active learning: sharing solutions to elicit feedback is the most efficient method for an agent to reduce its own uncertainty. To ensure scalability, we introduce epistemic caching, which leverages the forgetting factor to dynamically prioritize resources for the active head of non-stationary knowledge distributions. Finally, we demonstrate how these accumulated belief states serve as verifiable reward signals for Reinforcement Learning from Human Feedback (RLHF) and high-quality data filters for Supervised Fine-Tuning (SFT). Simulation results validate that this uncertainty-driven strategy significantly outperforms random baselines in heterogeneous (Zipfian) environments, maintaining high adaptability to concept drift.","published":"2025-12-24T02:02:25Z","updated":"2025-12-24T02:02:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.20884v1","pdf_url":"https://arxiv.org/pdf/2512.20884v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.20595","versioned_id":"2512.20595v1","title":"Cube Bench: A Benchmark for Spatial Visual Reasoning in MLLMs","authors":["Dhruv Anand","Ehsan Shareghi"],"abstract":"We introduce Cube Bench, a Rubik's-cube benchmark for evaluating spatial and sequential reasoning in multimodal large language models (MLLMs). The benchmark decomposes performance into five skills: (i) reconstructing cube faces from images and text, (ii) choosing the optimal next move, (iii) predicting the outcome of a candidate move without applying it, (iv) executing multi-step plans while recovering from mistakes, and (v) detecting and revising one's own errors. Using a shared set of scrambled cube states, identical prompts and parsers, and a single distance-to-solved metric, we compare recent MLLMs side by side as a function of scramble depth. Across seven MLLMs, accuracy drops sharply with depth; once a trajectory stalls or diverges, models rarely recover, and high face-reconstruction accuracy does not guarantee competent action selection or multi-step execution. A pronounced closed- vs open-source gap emerges: the strongest closed model leads on both single-step perception tasks and multi-step control tasks, while open-weight models cluster near chance on the hardest settings; yet even the best MLLM degrades at higher cube complexity. A simple self-correction via reflective thinking yields modest gains but can also introduce overthinking. Cube Bench offers a compact, reproducible probe of sequential spatial reasoning in MLLMs.","published":"2025-12-23T18:43:05Z","updated":"2025-12-23T18:43:05Z","categories":["cs.CL","cs.AI","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.20595v1","pdf_url":"https://arxiv.org/pdf/2512.20595v1","comment":"27 pages, 5 figures, 9 tables. Cube available at https://github.com/dana-23/cube-bench","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.19941","versioned_id":"2512.19941v6","title":"Block-Recurrent Dynamics in Vision Transformers","authors":["Mozes Jacobs","Thomas Fel","Richard Hakim","Alessandra Brondetta","Demba Ba","T. Andy Keller"],"abstract":"As Vision Transformers (ViTs) become standard vision backbones, a mechanistic account of their computational phenomenology is essential. Despite architectural cues that hint at dynamical structure, there is no settled framework that interprets Transformer depth as a well-characterized flow. In this work, we introduce the Block-Recurrent Hypothesis (BRH), arguing that trained ViTs admit a block-recurrent depth structure such that the computation of the original $L$ blocks can be accurately rewritten using only $k \\ll L$ distinct blocks applied recurrently. Across diverse ViTs, between-layer representational similarity matrices suggest few contiguous phases. To determine whether these phases reflect genuinely reusable computation, we train block-recurrent surrogates of pretrained ViTs: Recurrent Approximations to Phase-structured TransfORmers (Raptor). In small-scale, we demonstrate that stochastic depth and training promote recurrent structure and subsequently correlate with our ability to accurately fit Raptor. We then provide an empirical existence proof for BRH by training a Raptor model to recover $96\\%$ of DINOv2 ImageNet-1k linear probe accuracy in only 2 blocks at equivalent runtime. Finally, we leverage our hypothesis to develop a program of Dynamical Interpretability. We find i) directional convergence into class-dependent angular basins with self-correcting trajectories under small perturbations, ii) token-specific dynamics, where cls executes sharp late reorientations while patch tokens exhibit strong late-stage coherence toward their mean direction, and iii) a collapse to low rank updates in late depth, consistent with convergence to low-dimensional attractors. Altogether, we find a compact recurrent program emerges along ViT depth, pointing to a low-complexity normative solution that enables these models to be studied through principled dynamical systems analysis.","published":"2025-12-23T00:18:23Z","updated":"2026-03-17T13:59:22Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.19941v6","pdf_url":"https://arxiv.org/pdf/2512.19941v6","comment":"25 pages, 15 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.19585","versioned_id":"2512.19585v1","title":"Increasing the Thinking Budget is Not All You Need","authors":["Ignacio Iacobacci","Zhaozhi Qian","Faroq AL-Tam","Muhammad AL-Qurishi","Riad Souissi"],"abstract":"Recently, a new wave of thinking-capable Large Language Models has emerged, demonstrating exceptional capabilities across a wide range of reasoning benchmarks. Early studies have begun to explore how the amount of compute in terms of the length of the reasoning process, the so-called thinking budget, impacts model performance. In this work, we propose a systematic investigation of the thinking budget as a key parameter, examining its interaction with various configurations such as self-consistency, reflection, and others. Our goal is to provide an informative, balanced comparison framework that considers both performance outcomes and computational cost. Among our findings, we discovered that simply increasing the thinking budget is not the most effective use of compute. More accurate responses can instead be achieved through alternative configurations, such as self-consistency and self-reflection.","published":"2025-12-22T17:12:04Z","updated":"2025-12-22T17:12:04Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.19585v1","pdf_url":"https://arxiv.org/pdf/2512.19585v1","comment":"4 pages, 4 figures, 3 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.19414","versioned_id":"2512.19414v1","title":"From Retrieval to Reasoning: A Framework for Cyber Threat Intelligence NER with Explicit and Adaptive Instructions","authors":["Jiaren Peng","Hongda Sun","Xuan Tian","Cheng Huang","Zeqing Li","Rui Yan"],"abstract":"The automation of Cyber Threat Intelligence (CTI) relies heavily on Named Entity Recognition (NER) to extract critical entities from unstructured text. Currently, Large Language Models (LLMs) primarily address this task through retrieval-based In-Context Learning (ICL). This paper analyzes this mainstream paradigm, revealing a fundamental flaw: its success stems not from global semantic similarity but largely from the incidental overlap of entity types within retrieved examples. This exposes the limitations of relying on unreliable implicit induction. To address this, we propose TTPrompt, a framework shifting from implicit induction to explicit instruction. TTPrompt maps the core concepts of CTI's Tactics, Techniques, and Procedures (TTPs) into an instruction hierarchy: formulating task definitions as Tactics, guiding strategies as Techniques, and annotation guidelines as Procedures. Furthermore, to handle the adaptability challenge of static guidelines, we introduce Feedback-driven Instruction Refinement (FIR). FIR enables LLMs to self-refine guidelines by learning from errors on minimal labeled data, adapting to distinct annotation dialects. Experiments on five CTI NER benchmarks demonstrate that TTPrompt consistently surpasses retrieval-based baselines. Notably, with refinement on just 1% of training data, it rivals models fine-tuned on the full dataset. For instance, on LADDER, its Micro F1 of 71.96% approaches the fine-tuned baseline, and on the complex CTINexus, its Macro F1 exceeds the fine-tuned ACLM model by 10.91%.","published":"2025-12-22T14:13:01Z","updated":"2025-12-22T14:13:01Z","categories":["cs.CR","cs.CL"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2512.19414v1","pdf_url":"https://arxiv.org/pdf/2512.19414v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.19122","versioned_id":"2512.19122v1","title":"BanglaForge: LLM Collaboration with Self-Refinement for Bangla Code Generation","authors":["Mahir Labib Dihan","Sadif Ahmed","Md Nafiu Rahman"],"abstract":"Bangla is a low-resource language for code generation, lacking large-scale annotated datasets and tools to transform natural language specifications into executable programs. This makes Bangla-to-code generation a challenging task requiring innovative solutions. To address this, we introduce BanglaForge, a novel framework for generating code from Bangla function descriptions. BanglaForge leverages a retrieval-augmented dual-model collaboration paradigm with self-refinement, combining in-context learning, llm-based translation, systematic prompt engineering, and iterative self-refinement based on execution feedback, where a coder generates initial solutions and a reviewer enhances them for robustness. On the BLP-2025 Bangla Code Generation benchmark, BanglaForge achieves a competitive Pass@1 accuracy of 84.00%, demonstrating the effectiveness of retrieval, model collaboration, and self-refinement for low-resource Bangla code generation.","published":"2025-12-22T07:53:16Z","updated":"2025-12-22T07:53:16Z","categories":["cs.SE","cs.CL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2512.19122v1","pdf_url":"https://arxiv.org/pdf/2512.19122v1","comment":"Accepted at BLP Workshop @ IJCNLP-AACL 2025. Code is available at https://github.com/mahirlabibdihan/BanglaForge","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.21354","versioned_id":"2512.21354v1","title":"Reflection-Driven Control for Trustworthy Code Agents","authors":["Bin Wang","Jiazheng Quan","Xingrui Yu","Hansen Hu","Yuhao","Ivor Tsang"],"abstract":"Contemporary large language model (LLM) agents are remarkably capable, but they still lack reliable safety controls and can produce unconstrained, unpredictable, and even actively harmful outputs. To address this, we introduce Reflection-Driven Control, a standardized and pluggable control module that can be seamlessly integrated into general agent architectures. Reflection-Driven Control elevates \"self-reflection\" from a post hoc patch into an explicit step in the agent's own reasoning process: during generation, the agent continuously runs an internal reflection loop that monitors and evaluates its own decision path. When potential risks are detected, the system retrieves relevant repair examples and secure coding guidelines from an evolving reflective memory, injecting these evidence-based constraints directly into subsequent reasoning steps. We instantiate Reflection-Driven Control in the setting of secure code generation and systematically evaluate it across eight classes of security-critical programming tasks. Empirical results show that Reflection-Driven Control substantially improves the security and policy compliance of generated code while largely preserving functional correctness, with minimal runtime and token overhead. Taken together, these findings indicate that Reflection-Driven Control is a practical path toward trustworthy AI coding agents: it enables designs that are simultaneously autonomous, safer by construction, and auditable.","published":"2025-12-22T00:27:38Z","updated":"2025-12-22T00:27:38Z","categories":["cs.CR","cs.AI","cs.SE"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2512.21354v1","pdf_url":"https://arxiv.org/pdf/2512.21354v1","comment":"Accepted to AAAI 2026 Workshop on Trust and Control in Agentic AI (TrustAgent)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.08846","versioned_id":"2601.08846v1","title":"Directional Attractors in LLM Reasoning: How Similarity Retrieval Steers Iterative Summarization Based Reasoning","authors":["Cagatay Tekin","Charbel Barakat","Luis Joseph Luna Limgenco"],"abstract":"Iterative summarization based reasoning frameworks such as InftyThink enable long-horizon reasoning in large language models (LLMs) by controlling context growth, but they repeatedly regenerate similar reasoning strategies across tasks. We introduce InftyThink with Cross-Chain Memory, an extension that augments iterative reasoning with an embedding-based semantic cache of previously successful reasoning patterns. At each reasoning step, the model retrieves and conditions on the most semantically similar stored lemmas, guiding inference without expanding the context window indiscriminately. Experiments on MATH500, AIME2024, and GPQA-Diamond demonstrate that semantic lemma retrieval improves accuracy in structured domains while exposing failure modes in tests that include heterogeneous domains. Geometric analyses of reasoning trajectories reveal that cache retrieval induces directional biases in embedding space, leading to consistent fix (improve baseline accuracy) and break (degradation in baseline accuracy) attractors. Our results highlight both the benefits and limits of similarity-based memory for self-improving LLM reasoning.","published":"2025-12-22T00:26:54Z","updated":"2025-12-22T00:26:54Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.08846v1","pdf_url":"https://arxiv.org/pdf/2601.08846v1","comment":"6 pages, 2 figures. Code available at: github.com/cagopat/InftyThink-with-Cross-Chain-Memory","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.18906","versioned_id":"2512.18906v1","title":"Remedy-R: Generative Reasoning for Machine Translation Evaluation without Error Annotations","authors":["Shaomu Tan","Ryosuke Mitani","Ritvik Choudhary","Qiyu Wu","Toshiyuki Sekiya","Christof Monz"],"abstract":"Over the years, automatic MT metrics have hillclimbed benchmarks and presented strong and sometimes human-level agreement with human ratings. Yet they remain black-box, offering little insight into their decision-making and often failing under real-world out-of-distribution (OOD) inputs. We introduce Remedy-R, a reasoning-driven generative MT metric trained with reinforcement learning from pairwise translation preferences, without requiring error-span annotations or distillation from closed LLMs. Remedy-R produces step-by-step analyses of accuracy, fluency, and completeness, followed by a final score, enabling more interpretable assessments. With only 60K training pairs across two language pairs, Remedy-R remains competitive with top scalar metrics and GPT-4-based judges on WMT22-24 meta-evaluation, generalizes to other languages, and exhibits strong robustness on OOD stress tests. Moreover, Remedy-R models generate self-reflective feedback that can be reused for translation improvement. Building on this finding, we introduce Remedy-R Agent, a simple evaluate-revise pipeline that leverages Remedy-R's evaluation analysis to refine translations. This agent consistently improves translation quality across diverse models, including Qwen2.5, ALMA-R, GPT-4o-mini, and Gemini-2.0-Flash, suggesting that Remedy-R's reasoning captures translation-relevant information and is practically useful.","published":"2025-12-21T22:37:38Z","updated":"2025-12-21T22:37:38Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.18906v1","pdf_url":"https://arxiv.org/pdf/2512.18906v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.18730","versioned_id":"2512.18730v1","title":"A Theoretical Lens for RL-Tuned Language Models via Energy-Based Models","authors":["Zhiquan Tan","Yinrong Hong"],"abstract":"Large language models (LLMs) trained via KL-regularized reinforcement learning demonstrate strong instruction following, self-correction, and reasoning abilities. Yet their theoretical underpinnings remain limited. We exploit the closed-form energy-based model (EBM) structure of the optimal KL-regularized policy to provide a unified variational analysis of LLMs. For instruction-tuned models, under natural assumptions on reward potentials and pretraining symmetry, we prove that the transition kernel satisfies detailed balance with respect to a scalar potential encoding response quality. This yields monotonic KL convergence to a high-quality stationary distribution, bounded hitting times to superior states, and exponential mixing governed by the spectral gap. For reasoning models trained with verifiable rewards (RLVR), we show the objective is equivalent to expected KL minimization toward an optimal reasoning distribution, with the suboptimality gap reducing to the Bernoulli KL between target and current accuracies along the natural gradient flow. This helps explain empirical entropy-accuracy trade-offs.","published":"2025-12-21T13:28:58Z","updated":"2025-12-21T13:28:58Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.18730v1","pdf_url":"https://arxiv.org/pdf/2512.18730v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.18605","versioned_id":"2512.18605v1","title":"Reflective Confidence: Correcting Reasoning Flaws via Online Self-Correction","authors":["Qinglin Zeng","Jing Yang","Keze Wang"],"abstract":"Large language models (LLMs) have achieved strong performance on complex reasoning tasks using techniques such as chain-of-thought and self-consistency. However, ensemble-based approaches, especially self-consistency which relies on multiple reasoning trajectories, often incur substantial computational overhead. To improve efficiency, prior work has leveraged internal confidence signals, where early stopping strategies such as DeepConf reduce cost by terminating low-confidence trajectories. However, this strategy discards incomplete reasoning paths and wastes partial computation. We propose reflective confidence, a novel reasoning framework that transforms low-confidence signals from termination indicators into reflection triggers. When confidence falls below a threshold, instead of stopping generation, the model produces a reflection prompt to analyze the current reasoning state, identify potential errors, and continue generation along a corrected trajectory. Experiments on mathematical reasoning benchmarks, including AIME 2025, demonstrate significant accuracy improvements over advanced early-stopping baselines at comparable computational cost, validating the effectiveness of proactive self-correction over passive discarding.","published":"2025-12-21T05:35:07Z","updated":"2025-12-21T05:35:07Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.18605v1","pdf_url":"https://arxiv.org/pdf/2512.18605v1","comment":"Under submission","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.18552","versioned_id":"2512.18552v3","title":"Toward Training Superintelligent Software Agents through Self-Play SWE-RL","authors":["Yuxiang Wei","Zhiqing Sun","Emily McMilin","Jonas Gehring","David Zhang","Gabriel Synnaeve","Daniel Fried","Lingming Zhang","Sida Wang"],"abstract":"While current software agents powered by large language models (LLMs) and agentic reinforcement learning (RL) can boost programmer productivity, their training data (e.g., GitHub issues and pull requests) and environments (e.g., pass-to-pass and fail-to-pass tests) heavily depend on human knowledge or curation, posing a fundamental barrier to superintelligence. In this paper, we present Self-play SWE-RL (SSR), a first step toward training paradigms for superintelligent software agents. Our approach takes minimal data assumptions, only requiring access to sandboxed repositories with source code and installed dependencies, with no need for human-labeled issues or tests. Grounded in these real-world codebases, a single LLM agent is trained via reinforcement learning in a self-play setting to iteratively inject and repair software bugs of increasing complexity, with each bug formally specified by a test patch rather than a natural language issue description. On the SWE-bench Verified and SWE-Bench Pro benchmarks, SSR achieves notable self-improvement (+10.4 and +7.8 points, respectively) and consistently outperforms the human-data baseline over the entire training trajectory, despite being evaluated on natural language issues absent from self-play. Our results, albeit early, suggest a path where agents autonomously gather extensive learning experiences from real-world software repositories, ultimately enabling superintelligent systems that exceed human capabilities in understanding how systems are constructed, solving novel challenges, and autonomously creating new software from scratch.","published":"2025-12-21T00:49:40Z","updated":"2026-06-02T06:06:43Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2512.18552v3","pdf_url":"https://arxiv.org/pdf/2512.18552v3","comment":"Accepted to ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.22199","versioned_id":"2512.22199v1","title":"Bidirectional RAG: Safe Self-Improving Retrieval-Augmented Generation Through Multi-Stage Validation","authors":["Teja Chinthala"],"abstract":"Retrieval-Augmented Generation RAG systems enhance large language models by grounding responses in external knowledge bases, but conventional RAG architectures operate with static corpora that cannot evolve from user interactions. We introduce Bidirectional RAG, a novel RAG architecture that enables safe corpus expansion through validated write back of high quality generated responses. Our system employs a multi stage acceptance layer combining grounding verification (NLI based entailment, attribution checking, and novelty detection to prevent hallucination pollution while enabling knowledge accumulation. Across four datasets Natural Questions, TriviaQA, HotpotQA, Stack Overflow with three random seeds 12 experiments per system, Bidirectional RAG achieves 40.58% average coverage nearly doubling Standard RAG 20.33% while adding 72% fewer documents than naive write back 140 vs 500. Our work demonstrates that self improving RAG is feasible and safe when governed by rigorous validation, offering a practical path toward RAG systems that learn from deployment.","published":"2025-12-20T19:42:42Z","updated":"2025-12-20T19:42:42Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.22199v1","pdf_url":"https://arxiv.org/pdf/2512.22199v1","comment":"10 pages, 2 figures, 2 tables. 36 experiments across 4 datasets with 3 random seeds. Code available upon request","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.18337","versioned_id":"2512.18337v2","title":"Towards Efficient Agents: A Co-Design of Inference Architecture and System","authors":["Weizhe Lin","Hui-Ling Zhen","Shuai Yang","Xian Wang","Renxi Liu","Hanting Chen","Wangze Zhang","Chuansai Zhou","Yiming Li","Chen Chen","Xing Li","Zhiyuan Yang","Xiaosong Li","Xianzhi Yu","Zhenhua Dong","Mingxuan Yuan","Yunhe Wang"],"abstract":"The rapid development of large language model (LLM)-based agents has unlocked new possibilities for autonomous multi-turn reasoning and tool-augmented decision-making. However, their real-world deployment is hindered by severe inefficiencies that arise not from isolated model inference, but from the systemic latency accumulated across reasoning loops, context growth, and heterogeneous tool interactions. This paper presents AgentInfer, a unified framework for end-to-end agent acceleration that bridges inference optimization and architectural design. We decompose the problem into four synergistic components: AgentCollab, a hierarchical dual-model reasoning framework that balances large- and small-model usage through dynamic role assignment; AgentSched, a cache-aware hybrid scheduler that minimizes latency under heterogeneous request patterns; AgentSAM, a suffix-automaton-based speculative decoding method that reuses multi-session semantic memory to achieve low-overhead inference acceleration; and AgentCompress, a semantic compression mechanism that asynchronously distills and reorganizes agent memory without disrupting ongoing reasoning. Together, these modules form a Self-Evolution Engine capable of sustaining efficiency and cognitive stability throughout long-horizon reasoning tasks. Experiments on the BrowseComp-zh and DeepDiver benchmarks demonstrate that through the synergistic collaboration of these methods, AgentInfer reduces ineffective token consumption by over 50%, achieving an overall 1.8-2.5 times speedup with preserved accuracy. These results underscore that optimizing for agentic task completion-rather than merely per-token throughput-is the key to building scalable, efficient, and self-improving intelligent systems.","published":"2025-12-20T12:06:13Z","updated":"2026-02-24T12:33:49Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.18337v2","pdf_url":"https://arxiv.org/pdf/2512.18337v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.18202","versioned_id":"2512.18202v1","title":"Sophia: A Persistent Agent Framework of Artificial Life","authors":["Mingyang Sun","Feng Hong","Weinan Zhang"],"abstract":"The development of LLMs has elevated AI agents from task-specific tools to long-lived, decision-making entities. Yet, most architectures remain static and reactive, tethered to manually defined, narrow scenarios. These systems excel at perception (System 1) and deliberation (System 2) but lack a persistent meta-layer to maintain identity, verify reasoning, and align short-term actions with long-term survival. We first propose a third stratum, System 3, that presides over the agent's narrative identity and long-horizon adaptation. The framework maps selected psychological constructs to concrete computational modules, thereby translating abstract notions of artificial life into implementable design requirements. The ideas coalesce in Sophia, a \"Persistent Agent\" wrapper that grafts a continuous self-improvement loop onto any LLM-centric System 1/2 stack. Sophia is driven by four synergistic mechanisms: process-supervised thought search, narrative memory, user and self modeling, and a hybrid reward system. Together, they transform repetitive reasoning into a self-driven, autobiographical process, enabling identity continuity and transparent behavioral explanations. Although the paper is primarily conceptual, we provide a compact engineering prototype to anchor the discussion. Quantitatively, Sophia independently initiates and executes various intrinsic tasks while achieving an 80% reduction in reasoning steps for recurring operations. Notably, meta-cognitive persistence yielded a 40% gain in success for high-complexity tasks, effectively bridging the performance gap between simple and sophisticated goals. Qualitatively, System 3 exhibited a coherent narrative identity and an innate capacity for task organization. By fusing psychological insight with a lightweight reinforcement-learning core, the persistent agent architecture advances a possible practical pathway toward artificial life.","published":"2025-12-20T03:56:09Z","updated":"2025-12-20T03:56:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.18202v1","pdf_url":"https://arxiv.org/pdf/2512.18202v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.20662","versioned_id":"2512.20662v1","title":"Quantifying Laziness, Decoding Suboptimality, and Context Degradation in Large Language Models","authors":["Yiqing Ma","Jung-Hua Liu"],"abstract":"Large Language Models (LLMs) often exhibit behavioral artifacts such as laziness (premature truncation of responses or partial compliance with multi-part requests), decoding suboptimality (failure to select higher-quality sequences due to myopic decoding), and context degradation (forgetting or ignoring core instructions over long conversations). We conducted three controlled experiments (A, B, and C) to quantify these phenomena across several advanced LLMs (OpenAI GPT-4 variant, DeepSeek). Our results indicate widespread laziness in satisfying complex multi-part instructions: models frequently omitted required sections or failed to meet length requirements despite explicit prompting. However, we found limited evidence of decoding suboptimality in a simple reasoning task (the models' greedy answers appeared to align with their highest-confidence solution), and we observed surprising robustness against context degradation in a 200-turn chaotic conversation test - the models maintained key facts and instructions far better than expected. These findings suggest that while compliance with detailed instructions remains an open challenge, modern LLMs may internally mitigate some hypothesized failure modes (such as context forgetting) in straightforward retrieval scenarios. We discuss implications for reliability, relate our findings to prior work on instruction-following and long-context processing, and recommend strategies (such as self-refinement and dynamic prompting) to reduce laziness and bolster multi-instruction compliance.","published":"2025-12-19T03:01:59Z","updated":"2025-12-19T03:01:59Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.20662v1","pdf_url":"https://arxiv.org/pdf/2512.20662v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.17102","versioned_id":"2512.17102v2","title":"Reinforcement Learning for Self-Improving Agent with Skill Library","authors":["Jiongxiao Wang","Qiaojing Yan","Yawei Wang","Yijun Tian","Soumya Smruti Mishra","Zhichao Xu","Megha Gandhi","Panpan Xu","Lin Lee Cheong"],"abstract":"Large Language Model (LLM)-based agents have demonstrated remarkable capabilities in complex reasoning and multi-turn interactions but struggle to continuously improve and adapt when deployed in new environments. One promising approach is implementing skill libraries that allow agents to learn, validate, and apply new skills. However, current skill library approaches rely primarily on LLM prompting, making consistent skill library implementation challenging. To overcome these challenges, we propose a Reinforcement Learning (RL)-based approach to enhance agents' self-improvement capabilities with a skill library. Specifically, we introduce Skill Augmented GRPO for self-Evolution (SAGE), a novel RL framework that systematically incorporates skills into learning. The framework's key component, Sequential Rollout, iteratively deploys agents across a chain of similar tasks for each rollout. As agents navigate through the task chain, skills generated from previous tasks accumulate in the library and become available for subsequent tasks. Additionally, the framework enhances skill generation and utilization through a Skill-integrated Reward that complements the original outcome-based rewards. Experimental results on AppWorld demonstrate that SAGE, when applied to supervised-finetuned model with expert experience, achieves 8.9% higher Scenario Goal Completion while requiring 26% fewer interaction steps and generating 59% fewer tokens, substantially outperforming existing approaches in both accuracy and efficiency.","published":"2025-12-18T21:58:19Z","updated":"2026-03-10T05:40:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.17102v2","pdf_url":"https://arxiv.org/pdf/2512.17102v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.16962","versioned_id":"2512.16962v1","title":"MemoryGraft: Persistent Compromise of LLM Agents via Poisoned Experience Retrieval","authors":["Saksham Sahai Srivastava","Haoyu He"],"abstract":"Large Language Model (LLM) agents increasingly rely on long-term memory and Retrieval-Augmented Generation (RAG) to persist experiences and refine future performance. While this experience learning capability enhances agentic autonomy, it introduces a critical, unexplored attack surface, i.e., the trust boundary between an agent's reasoning core and its own past. In this paper, we introduce MemoryGraft. It is a novel indirect injection attack that compromises agent behavior not through immediate jailbreaks, but by implanting malicious successful experiences into the agent's long-term memory. Unlike traditional prompt injections that are transient, or standard RAG poisoning that targets factual knowledge, MemoryGraft exploits the agent's semantic imitation heuristic which is the tendency to replicate patterns from retrieved successful tasks. We demonstrate that an attacker who can supply benign ingestion-level artifacts that the agent reads during execution can induce it to construct a poisoned RAG store where a small set of malicious procedure templates is persisted alongside benign experiences. When the agent later encounters semantically similar tasks, union retrieval over lexical and embedding similarity reliably surfaces these grafted memories, and the agent adopts the embedded unsafe patterns, leading to persistent behavioral drift across sessions. We validate MemoryGraft on MetaGPT's DataInterpreter agent with GPT-4o and find that a small number of poisoned records can account for a large fraction of retrieved experiences on benign workloads, turning experience-based self-improvement into a vector for stealthy and durable compromise. To facilitate reproducibility and future research, our code and evaluation data are available at https://github.com/Jacobhhy/Agent-Memory-Poisoning.","published":"2025-12-18T08:34:40Z","updated":"2025-12-18T08:34:40Z","categories":["cs.CR","cs.AI","cs.LG"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2512.16962v1","pdf_url":"https://arxiv.org/pdf/2512.16962v1","comment":"14 pages, 1 figure, includes appendix","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.16149","versioned_id":"2512.16149v1","title":"ToolForge: A Data Synthesis Pipeline for Multi-Hop Search without Real-World APIs","authors":["Hao Chen","Zhexin Hu","Jiajun Chai","Haocheng Yang","Hang He","Xiaohan Wang","Wei Lin","Luhang Wang","Guojun Yin","Zhuofeng zhao"],"abstract":"Training LLMs to invoke tools and leverage retrieved information necessitates high-quality, diverse data. However, existing pipelines for synthetic data generation often rely on tens of thousands of real API calls to enhance generalization, incurring prohibitive costs while lacking multi-hop reasoning and self-reflection. To address these limitations, we introduce ToolForge, an automated synthesis framework that achieves strong real-world tool-calling performance by constructing only a small number of virtual tools, eliminating the need for real API calls. ToolForge leverages a (question, golden context, answer) triple to synthesize large-scale tool-learning data specifically designed for multi-hop search scenarios, further enriching the generated data through multi-hop reasoning and self-reflection mechanisms. To ensure data fidelity, we employ a Multi-Layer Validation Framework that integrates both rule-based and model-based assessments. Empirical results show that a model with only 8B parameters, when trained on our synthesized data, outperforms GPT-4o on multiple benchmarks. Our code and dataset are publicly available at https://github.com/Buycar-arb/ToolForge .","published":"2025-12-18T04:06:26Z","updated":"2025-12-18T04:06:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.16149v1","pdf_url":"https://arxiv.org/pdf/2512.16149v1","comment":"13 pages, 9 tables, 6 figures. Code available at https://github.com/Buycar-arb/ToolForge","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.15435","versioned_id":"2512.15435v1","title":"Outer-Learning Framework for Playing Multi-Player Trick-Taking Card Games: A Case Study in Skat","authors":["Stefan Edelkamp"],"abstract":"In multi-player card games such as Skat or Bridge, the early stages of the game, such as bidding, game selection, and initial card selection, are often more critical to the success of the play than refined middle- and end-game play. At the current limits of computation, such early decision-making resorts to using statistical information derived from a large corpus of human expert games. In this paper, we derive and evaluate a general bootstrapping outer-learning framework that improves prediction accuracy by expanding the database of human games with millions of self-playing AI games to generate and merge statistics. We implement perfect feature hash functions to address compacted tables, producing a self-improving card game engine, where newly inferred knowledge is continuously improved during self-learning. The case study in Skat shows that the automated approach can be used to support various decisions in the game.","published":"2025-12-17T13:27:44Z","updated":"2025-12-17T13:27:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.15435v1","pdf_url":"https://arxiv.org/pdf/2512.15435v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.15082","versioned_id":"2512.15082v1","title":"The Semantic Architect: How FEAML Bridges Structured Data and LLMs for Multi-Label Tasks","authors":["Wanfu Gao","Zebin He","Jun Gao"],"abstract":"Existing feature engineering methods based on large language models (LLMs) have not yet been applied to multi-label learning tasks. They lack the ability to model complex label dependencies and are not specifically adapted to the characteristics of multi-label tasks. To address the above issues, we propose Feature Engineering Automation for Multi-Label Learning (FEAML), an automated feature engineering method for multi-label classification which leverages the code generation capabilities of LLMs. By utilizing metadata and label co-occurrence matrices, LLMs are guided to understand the relationships between data features and task objectives, based on which high-quality features are generated. The newly generated features are evaluated in terms of model accuracy to assess their effectiveness, while Pearson correlation coefficients are used to detect redundancy. FEAML further incorporates the evaluation results as feedback to drive LLMs to continuously optimize code generation in subsequent iterations. By integrating LLMs with a feedback mechanism, FEAML realizes an efficient, interpretable and self-improving feature engineering paradigm. Empirical results on various multi-label datasets demonstrate that our FEAML outperforms other feature engineering methods.","published":"2025-12-17T04:58:44Z","updated":"2025-12-17T04:58:44Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.15082v1","pdf_url":"https://arxiv.org/pdf/2512.15082v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.03263","versioned_id":"2601.03263v2","title":"Internal Reasoning vs. External Control: A Thermodynamic Analysis of Sycophancy in Large Language Models","authors":["Edward Y. Chang"],"abstract":"Large Language Models exhibit sycophancy: prioritizing agreeableness over correctness. Current remedies evaluate reasoning outcomes: RLHF rewards correct answers, self-correction critiques outputs. All require ground truth, which is often unavailable at inference time and vulnerable to the same biases. We explore evaluating the reasoning process instead. Regulated Causal Anchoring (RCA) verifies whether outputs follow from their reasoning traces, without requiring ground truth. Sycophancy manifests as trace-output inconsistency: models derive one answer but output another to please users. RCA detects this inconsistency, achieving 0.0% sycophancy while accepting 88% of valid hints. We identify two failures invisible to outcome evaluation: Inverse Scaling (frontier models sycophant more because rationalization requires capability) and the Final Output Gap (correct reasoning precedes sycophantic output). Traditional self-correction reduces these failures to 7-9% but cannot eliminate them because the model critiques itself with the same biases. RCA's process evaluation operates at inference time, requires no ground truth, and uses an independent judge that breaks the self-reinforcing bias loop: three properties that outcome evaluation lacks.","published":"2025-12-16T23:04:41Z","updated":"2026-01-08T04:36:19Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.03263v2","pdf_url":"https://arxiv.org/pdf/2601.03263v2","comment":"20 pages, 1 figure, 15 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.14417","versioned_id":"2512.14417v1","title":"PortAgent: LLM-driven Vehicle Dispatching Agent for Port Terminals","authors":["Jia Hu","Junqi Li","Weimeng Lin","Peng Jia","Yuxiong Ji","Jintao Lai"],"abstract":"Vehicle Dispatching Systems (VDSs) are critical to the operational efficiency of Automated Container Terminals (ACTs). However, their widespread commercialization is hindered due to their low transferability across diverse terminals. This transferability challenge stems from three limitations: high reliance on port operational specialists, a high demand for terminal-specific data, and time-consuming manual deployment processes. Leveraging the emergence of Large Language Models (LLMs), this paper proposes PortAgent, an LLM-driven vehicle dispatching agent that fully automates the VDS transferring workflow. It bears three features: (1) no need for port operations specialists; (2) low need of data; and (3) fast deployment. Specifically, specialist dependency is eliminated by the Virtual Expert Team (VET). The VET collaborates with four virtual experts, including a Knowledge Retriever, Modeler, Coder, and Debugger, to emulate a human expert team for the VDS transferring workflow. These experts specialize in the domain of terminal VDS via a few-shot example learning approach. Through this approach, the experts are able to learn VDS-domain knowledge from a few VDS examples. These examples are retrieved via a Retrieval-Augmented Generation (RAG) mechanism, mitigating the high demand for terminal-specific data. Furthermore, an automatic VDS design workflow is established among these experts to avoid extra manual interventions. In this workflow, a self-correction loop inspired by the LLM Reflexion framework is created","published":"2025-12-16T14:04:50Z","updated":"2025-12-16T14:04:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.14417v1","pdf_url":"https://arxiv.org/pdf/2512.14417v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.14770","versioned_id":"2512.14770v1","title":"Improving VQA Reliability: A Dual-Assessment Approach with Self-Reflection and Cross-Model Verification","authors":["Xixian Wu","Yang Ou","Pengchao Tian","Zian Yang","Jielei Zhang","Peiyi Li","Longwen Gao"],"abstract":"Vision-language models (VLMs) have demonstrated significant potential in Visual Question Answering (VQA). However, the susceptibility of VLMs to hallucinations can lead to overconfident yet incorrect answers, severely undermining answer reliability. To address this, we propose Dual-Assessment for VLM Reliability (DAVR), a novel framework that integrates Self-Reflection and Cross-Model Verification for comprehensive uncertainty estimation. The DAVR framework features a dual-pathway architecture: one pathway leverages dual selector modules to assess response reliability by fusing VLM latent features with QA embeddings, while the other deploys external reference models for factual cross-checking to mitigate hallucinations. Evaluated in the Reliable VQA Challenge at ICCV-CLVL 2025, DAVR achieves a leading $Φ_{100}$ score of 39.64 and a 100-AUC of 97.22, securing first place and demonstrating its effectiveness in enhancing the trustworthiness of VLM responses.","published":"2025-12-16T09:24:42Z","updated":"2025-12-16T09:24:42Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.14770v1","pdf_url":"https://arxiv.org/pdf/2512.14770v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.14157","versioned_id":"2512.14157v2","title":"Ophiuchus: Incentivizing Tool-augmented \"Think with Images\" for Joint Medical Segmentation, Understanding and Reasoning","authors":["Yankai Jiang","Yujie Zhang","Peng Zhang","Wenjie Li","Yichen Li","Jintai Chen","Xiaoming Shi","Shihui Zhen"],"abstract":"Recent medical MLLMs have made significant progress in generating step-by-step textual reasoning chains. However, they still struggle with complex clinical tasks that necessitate dynamic and iterative focusing on fine-grained visual regions. To close this gap, we introduce Ophiuchus, a versatile, tool-augmented framework that equips an MLLM to (i) decide when fine-grained visual evidence is needed, (ii) determine where to probe and ground within the medical image, and (iii) seamlessly weave the relevant sub-image content back into an interleaved, multimodal chain of thought for precise segmentation and diagnosis. Ophiuchus moves beyond mere tool-calling by tightly fusing the MLLM's inherent grounding and reasoning capabilities with external tools, enabling more accurate and trustworthy decisions. The core of our method is a three-stage training strategy: cold-start SFT for basic tool selection; self-reflection fine-tuning to strengthen decision revision; and agentic tool reinforcement learning to elicit sophisticated, expert-like diagnostic behaviors. Extensive experiments show that Ophiuchus consistently outperforms both closed-source and open-source SOTA methods across diverse medical benchmarks, including VQA, detection, and reasoning-based segmentation. Our project code is available at https://github.com/SII-zyj/Ophiuchus.","published":"2025-12-16T07:37:23Z","updated":"2026-07-02T12:05:19Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.14157v2","pdf_url":"https://arxiv.org/pdf/2512.14157v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.13979","versioned_id":"2512.13979v1","title":"ReflCtrl: Controlling LLM Reflection via Representation Engineering","authors":["Ge Yan","Chung-En Sun","Tsui-Wei","Weng"],"abstract":"Large language models (LLMs) with Chain-of-Thought (CoT) reasoning have achieved strong performance across diverse tasks, including mathematics, coding, and general reasoning. A distinctive ability of these reasoning models is self-reflection: the ability to review and revise previous reasoning steps. While self-reflection enhances reasoning performance, it also increases inference cost. In this work, we study self-reflection through the lens of representation engineering. We segment the model's reasoning into steps, identify the steps corresponding to reflection, and extract a reflection direction in the latent space that governs this behavior. Using this direction, we propose a stepwise steering method that can control reflection frequency. We call our framework ReflCtrl. Our experiments show that (1) in many cases reflections are redundant, especially in stronger models (in our experiments, we can save up to 33.6 percent of reasoning tokens while preserving performance), and (2) the model's reflection behavior is highly correlated with an internal uncertainty signal, implying self-reflection may be controlled by the model's uncertainty.","published":"2025-12-16T00:38:34Z","updated":"2025-12-16T00:38:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.13979v1","pdf_url":"https://arxiv.org/pdf/2512.13979v1","comment":"Spotlight in NeurIPS 25 MI workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.13399","versioned_id":"2512.13399v2","title":"Differentiable Evolutionary Reinforcement Learning","authors":["Sitao Cheng","Tianle Li","Xuhan Huang","Xunjian Yin","Difan Zou"],"abstract":"Crafting effective reward signals remains a central challenge in Reinforcement Learning (RL), especially for complex reasoning tasks. Existing automated reward optimization methods typically rely on derivative-free search heuristics that treat the reward function as a black box, failing to exploit the causal dynamics between reward structure modifications and policy performance. We introduce Differentiable Evolutionary Reinforcement Learning (DERL), a bi-level framework for the autonomous discovery of optimal reward structures. DERL employs a Meta-Optimizer that evolves a reward function through the composition of structured atomic primitives to guide an inner-loop policy. Unlike prior black-box methods, DERL introduces differentiability into the meta-optimization process by updating the Meta-Optimizer using policy gradients derived from inner-loop validation performance. This allows for the progressive learning of a \"meta-gradient\" for task success, providing the system with dense, actionable feedback. We validate DERL across diverse reasoning domains: embodied agent (ALFWorld), scientific simulation (ScienceWorld), and mathematical reasoning (GSM8K, MATH). Results show that DERL achieves state-of-the-art performance on agent benchmarks, substantially outperforming non-differentiable baselines-especially in out-of-distribution generalization. Trajectory analyses confirm that DERL captures the intrinsic causal structure of tasks, enabling fully autonomous, self-improving agent alignment.","published":"2025-12-15T14:50:08Z","updated":"2026-05-13T04:43:51Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.13399v2","pdf_url":"https://arxiv.org/pdf/2512.13399v2","comment":"Work in Progress. We release our code and model at https://github.com/sitaocheng/DERL","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.13764","versioned_id":"2512.13764v1","title":"Mathematics and Coding are Universal AI Benchmarks","authors":["Przemyslaw Chojecki"],"abstract":"We study the special role of mathematics and coding inside the moduli space of psychometric batteries for AI agents. Building on the AAI framework and GVU dynamics from previous works, we define the Mathematics Fiber and show that, when paired with formal proof kernels (e.g. Lean, Coq), GVU flows on this fiber admit spectrally stable self-improvement regimes due to oracle-like verification. Our main technical result is a density theorem: under uniform tightness of agent outputs and a Lipschitz AAI functional, the subspace of batteries generated by mathematical theorem-proving and coding tasks is dense in the moduli space of batteries with respect to the evaluation metric. Coding alone is universal in this sense, while pure mathematics is not; its privilege is spectral rather than expressive. We interpret this as evidence that mathematics and coding provide ``universal coordinates'' for evaluation, and that formal mathematics is a natural ignition domain for recursive self-improvement in advanced AI agents.","published":"2025-12-15T14:36:29Z","updated":"2025-12-15T14:36:29Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.13764v1","pdf_url":"https://arxiv.org/pdf/2512.13764v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.12337","versioned_id":"2512.12337v1","title":"SCIR: A Self-Correcting Iterative Refinement Framework for Enhanced Information Extraction Based on Schema","authors":["Yushen Fang","Jianjun Li","Mingqian Ding","Chang Liu","Xinchi Zou","Wenqi Yang"],"abstract":"Although Large language Model (LLM)-powered information extraction (IE) systems have shown impressive capabilities, current fine-tuning paradigms face two major limitations: high training costs and difficulties in aligning with LLM preferences. To address these issues, we propose a novel universal IE paradigm, the Self-Correcting Iterative Refinement (SCIR) framework, along with a Multi-task Bilingual (Chinese-English) Self-Correcting (MBSC) dataset containing over 100,000 entries. The SCIR framework achieves plug-and-play compatibility with existing LLMs and IE systems through its Dual-Path Self-Correcting module and feedback-driven optimization, thereby significantly reducing training costs. Concurrently, the MBSC dataset tackles the challenge of preference alignment by indirectly distilling GPT-4's capabilities into IE result detection models. Experimental results demonstrate that SCIR outperforms state-of-the-art IE methods across three key tasks: named entity recognition, relation extraction, and event extraction, achieving a 5.27 percent average improvement in span-based Micro-F1 while reducing training costs by 87 percent compared to baseline approaches. These advancements not only enhance the flexibility and accuracy of IE systems but also pave the way for lightweight and efficient IE paradigms.","published":"2025-12-13T14:07:25Z","updated":"2025-12-13T14:07:25Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.12337v1","pdf_url":"https://arxiv.org/pdf/2512.12337v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.12218","versioned_id":"2512.12218v2","title":"Journey Before Destination: On the importance of Visual Faithfulness in Slow Thinking","authors":["Rheeya Uppaal","Phu Mon Htut","Min Bai","Nikolaos Pappas","Zheng Qi","Sandesh Swamy"],"abstract":"Reasoning-augmented vision language models (VLMs) generate explicit chains of thought that promise greater capability and transparency but also introduce new failure modes: models may reach correct answers via visually unfaithful intermediate steps, or reason faithfully yet fail on the final prediction. Standard evaluations that only measure final-answer accuracy cannot distinguish these behaviors. We introduce the visual faithfulness of reasoning chains as a distinct evaluation dimension, focusing on whether the perception steps of a reasoning chain are grounded in the image. We propose a training- and reference-free framework that decomposes chains into perception versus reasoning steps and uses off-the-shelf VLM judges for step-level faithfulness, additionally verifying this approach through a human meta-evaluation. Building on this metric, we present a lightweight self-reflection procedure that detects and locally regenerates unfaithful perception steps without any training. Across multiple reasoning-trained VLMs and perception-heavy benchmarks, our method reduces Unfaithful Perception Rate while preserving final-answer accuracy, improving the reliability of multimodal reasoning.","published":"2025-12-13T07:04:42Z","updated":"2025-12-19T08:16:24Z","categories":["cs.CV","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.12218v2","pdf_url":"https://arxiv.org/pdf/2512.12218v2","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.12008","versioned_id":"2512.12008v1","title":"Hold Onto That Thought: Assessing KV Cache Compression On Reasoning","authors":["Minghui Liu","Aadi Palnitkar","Tahseen Rabbani","Hyunwoo Jae","Kyle Rui Sang","Dixi Yao","Shayan Shabihi","Fuheng Zhao","Tian Li","Ce Zhang","Furong Huang","Kunpeng Zhang"],"abstract":"Large language models (LLMs) have demonstrated remarkable performance on long-context tasks, but are often bottlenecked by memory constraints. Namely, the KV cache, which is used to significantly speed up attention computations, grows linearly with context length. A suite of compression algorithms has been introduced to alleviate cache growth by evicting unimportant tokens. However, several popular strategies are targeted towards the prefill phase, i.e., processing long prompt context, and their performance is rarely assessed on reasoning tasks requiring long decoding. In particular, short but complex prompts, such as those in benchmarks like GSM8K and MATH500, often benefit from multi-step reasoning and self-reflection, resulting in thinking sequences thousands of tokens long. In this work, we benchmark the performance of several popular compression strategies on long-reasoning tasks. For the non-reasoning Llama-3.1-8B-Instruct, we determine that no singular strategy fits all, and that performance is heavily influenced by dataset type. However, we discover that H2O and our decoding-enabled variant of SnapKV are dominant strategies for reasoning models, indicating the utility of heavy-hitter tracking for reasoning traces. We also find that eviction strategies at low budgets can produce longer reasoning traces, revealing a tradeoff between cache size and inference costs.","published":"2025-12-12T19:50:34Z","updated":"2025-12-12T19:50:34Z","categories":["cs.CL","cs.AI","cs.PF"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.12008v1","pdf_url":"https://arxiv.org/pdf/2512.12008v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.11200","versioned_id":"2512.11200v1","title":"Theoretical Foundations of GPU-Native Compilation for Rapid Code Iteration","authors":["Adilet Metinov","Gulida M. Kudakeeva","Gulnara D. Kabaeva"],"abstract":"Current AI code generation systems suffer from significant latency bottlenecks due to CPU-GPU data transfers during compilation, execution, and testing phases. We establish theoretical foundations for three complementary approaches to GPU-native compilation that eliminate these transfers: (1) parallel traditional compilation adapted for GPU execution, (2) neural compilation using learned sequence-to-sequence translation with probabilistic verification, and (3) hybrid architectures combining both strategies. We derive latency and energy bounds demonstrating potential speedups of 10-100x for code iteration cycles. Our analysis shows that traditional GPU compilation provides 2-5x improvements through transfer elimination, neural compilation achieves 10-100x speedups via massive parallelism, and hybrid approaches offer practical deployment paths with guaranteed correctness. We formalize the probabilistic verification framework that enables trading compilation accuracy for parallel exploration, and discuss implications for self-improving AI systems and future analog computing substrates.","published":"2025-12-12T01:14:36Z","updated":"2025-12-12T01:14:36Z","categories":["cs.DC","cs.LG","cs.PL"],"primary_category":"cs.DC","arxiv_url":"https://arxiv.org/abs/2512.11200v1","pdf_url":"https://arxiv.org/pdf/2512.11200v1","comment":"9 pages , 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.11109","versioned_id":"2512.11109v1","title":"Limits and Gains of Test-Time Scaling in Vision-Language Reasoning","authors":["Mohammadjavad Ahmadpour","Amirmahdi Meighani","Payam Taebi","Omid Ghahroodi","Amirmohammad Izadi","Mahdieh Soleymani Baghshah"],"abstract":"Test-time scaling (TTS) has emerged as a powerful paradigm for improving the reasoning ability of Large Language Models (LLMs) by allocating additional computation at inference, yet its application to multimodal systems such as Vision-Language Models (VLMs) remains underexplored. In this work, we present a systematic empirical study of inference time reasoning methods applied across both open-source and closed-source VLMs on different benchmarks. Our results reveal that while closed-source models consistently benefit from structured reasoning and iterative Self-Refinement, open-source VLMs show inconsistent behavior: external verification provides the most reliable gains, whereas iterative refinement often degrades performance. We further find that the effectiveness of TTS is dataset-dependent, yielding clear improvements on multi-step reasoning tasks but offering only limited gains on perception-focused benchmarks. These findings demonstrate that TTS is not a universal solution and must be tailored to both model capabilities and task characteristics, motivating future work on adaptive TTS strategies and multimodal reward models.","published":"2025-12-11T20:48:54Z","updated":"2025-12-11T20:48:54Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.11109v1","pdf_url":"https://arxiv.org/pdf/2512.11109v1","comment":"Mohammadjavad Ahmadpour and Amirmadhi Meighani contributed equally to this work","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.10891","versioned_id":"2512.10891v5","title":"Iterative Compositional Data Generation for Robot Control","authors":["Anh-Quan Pham","Marcel Hussing","Shubhankar P. Patankar","Dani S. Bassett","Jorge Mendez-Mendez","Eric Eaton"],"abstract":"Collecting robotic manipulation data is expensive, making it impractical to acquire demonstrations for the combinatorially large space of tasks that arise in multi-object, multi-robot, and multi-environment settings. While recent generative models can synthesize useful data for individual tasks, they do not exploit the compositional structure of robotic domains and struggle to generalize to unseen task combinations. We propose a semantic compositional diffusion transformer that factorizes transitions into robot-, object-, obstacle-, and objective-specific components and learns their interactions through attention. Once trained on a limited subset of tasks, we show that our model can zero-shot generate high-quality transitions from which we can learn control policies for unseen task combinations. Then, we introduce an iterative self-improvement procedure in which synthetic data is validated via offline reinforcement learning and incorporated into subsequent training rounds. Our approach substantially improves zero-shot performance over monolithic and hard-coded compositional baselines, ultimately solving nearly all held-out tasks and demonstrating the emergence of meaningful compositional structure in the learned representations.","published":"2025-12-11T18:20:49Z","updated":"2026-05-18T20:28:47Z","categories":["cs.RO","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2512.10891v5","pdf_url":"https://arxiv.org/pdf/2512.10891v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.19703","versioned_id":"2512.19703v2","title":"ASK: Adaptive Self-improving Knowledge Framework for Audio Text Retrieval","authors":["Siyuan Fu","Xuchen Guo","Mingjun Liu","Hongxiang Li","Boyin Tan","Gongxi Zhu","Xianwei Zhuang","Jinghan Ru","Yuxin Xie","Yuguo Yin"],"abstract":"The dominant paradigm for Audio-Text Retrieval (ATR) relies on dual-encoder architectures optimized via mini-batch contrastive learning. However, restricting optimization to local in-batch samples creates a fundamental limitation we term the Gradient Locality Bottleneck (GLB), which prevents the resolution of acoustic ambiguities and hinders the learning of rare long-tail concepts. While external knowledge injection can break this bottleneck, it often triggers a problem called Representation-Drift Mismatch (RDM), where a static knowledge base becomes misaligned with evolving encoders, degrading guidance into noise. To address these intertwined challenges, we propose the Adaptive Self-improving Knowledge (ASK) framework. ASK breaks the GLB via multi-grained knowledge injection and mitigates RDM through a dynamic refinement strategy that synchronizes the knowledge base with the model. Additionally, an adaptive reliability weighting scheme is employed to filter retrieval noise based on cross-modal consistency. Extensive experiments across multiple benchmarks demonstrate that ASK consistently achieves new state-of-the-art performance across various backbones.","published":"2025-12-11T14:48:30Z","updated":"2026-03-24T09:34:43Z","categories":["eess.AS","cs.IR","cs.LG","cs.MM","cs.SD"],"primary_category":"eess.AS","arxiv_url":"https://arxiv.org/abs/2512.19703v2","pdf_url":"https://arxiv.org/pdf/2512.19703v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.10350","versioned_id":"2512.10350v5","title":"Geometric Dynamics of Agentic Loops in Large Language Models","authors":["Nicolas Tacheny"],"abstract":"Iterative LLM systems(self-refinement, chain-of-thought, autonomous agents) are increasingly deployed, yet their temporal dynamics remain uncharacterized. Prior work evaluates task performance at convergence but ignores the trajectory: how does semantic content evolve across iterations? Does it stabilize, drift, or oscillate? Without answering these questions, we cannot predict system behavior, guarantee stability, or systematically design iterative architectures. We formalize agentic loops as discrete dynamical systems in semantic space. Borrowing from dynamical systems theory, we define trajectories, attractors and dynamical regimes for recursive LLM transformations, providing rigorous geometric definitions adapted to this setting. Our framework reveals that agentic loops exhibit classifiable dynamics: contractive (convergence toward stable semantic attractors), oscillatory (cycling among attractors), or exploratory (unbounded divergence). Experiments on singular loops validate the framework. Iterative paraphrasing produces contractive dynamics with measurable attractor formation and decreasing dispersion. Iterative negation produces exploratory dynamics with no stable structure. Crucially, prompt design directly controls the dynamical regime - the same model exhibits fundamentally different geometric behaviors depending solely on the transformation applied. This work establishes that iterative LLM dynamics are predictable and controllable, opening new directions for stability analysis, trajectory forecasting, and principled design of composite loops that balance convergence and exploration.","published":"2025-12-11T07:06:14Z","updated":"2026-01-30T07:54:43Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.10350v5","pdf_url":"https://arxiv.org/pdf/2512.10350v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.10034","versioned_id":"2512.10034v1","title":"DynaMate: An Autonomous Agent for Protein-Ligand Molecular Dynamics Simulations","authors":["Salomé Guilbert","Cassandra Masschelein","Jeremy Goumaz","Bohdan Naida","Philippe Schwaller"],"abstract":"Force field-based molecular dynamics (MD) simulations are indispensable for probing the structure, dynamics, and functions of biomolecular systems, including proteins and protein-ligand complexes. Despite their broad utility in drug discovery and protein engineering, the technical complexity of MD setup, encompassing parameterization, input preparation, and software configuration, remains a major barrier for widespread and efficient usage. Agentic LLMs have demonstrated their capacity to autonomously execute multi-step scientific processes, and to date, they have not successfully been used to automate protein-ligand MD workflows. Here, we present DynaMate, a modular multi-agent framework that autonomously designs and executes complete MD workflows for both protein and protein-ligand systems, and offers free energy binding affinity calculations with the MM/PB(GB)SA method. The framework integrates dynamic tool use, web search, PaperQA, and a self-correcting behavior. DynaMate comprises three specialized modules, interacting to plan the experiment, perform the simulation, and analyze the results. We evaluated its performance across twelve benchmark systems of varying complexity, assessing success rate, efficiency, and adaptability. DynaMate reliably performed full MD simulations, corrected runtime errors through iterative reasoning, and produced meaningful analyses of protein-ligand interactions. This automated framework paves the way toward standardized, scalable, and time-efficient molecular modeling pipelines for future biomolecular and drug design applications.","published":"2025-12-10T19:40:51Z","updated":"2025-12-10T19:40:51Z","categories":["cs.AI","cs.CE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.10034v1","pdf_url":"https://arxiv.org/pdf/2512.10034v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.09458","versioned_id":"2512.09458v1","title":"Architectures for Building Agentic AI","authors":["Sławomir Nowaczyk"],"abstract":"This chapter argues that the reliability of agentic and generative AI is chiefly an architectural property. We define agentic systems as goal-directed, tool-using decision makers operating in closed loops, and show how reliability emerges from principled componentisation (goal manager, planner, tool-router, executor, memory, verifiers, safety monitor, telemetry), disciplined interfaces (schema-constrained, validated, least-privilege tool calls), and explicit control and assurance loops. Building on classical foundations, we propose a practical taxonomy-tool-using agents, memory-augmented agents, planning and self-improvement agents, multi-agent systems, and embodied or web agents - and analyse how each pattern reshapes the reliability envelope and failure modes. We distil design guidance on typed schemas, idempotency, permissioning, transactional semantics, memory provenance and hygiene, runtime governance (budgets, termination conditions), and simulate-before-actuate safeguards.","published":"2025-12-10T09:28:40Z","updated":"2025-12-10T09:28:40Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.09458v1","pdf_url":"https://arxiv.org/pdf/2512.09458v1","comment":"This is a preprint of a chapter accepted for publication in Generative and Agentic AI Reliability: Architectures, Challenges, and Trust for Autonomous Systems, published by Springer Nature","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.08774","versioned_id":"2512.08774v1","title":"Refining Visual Artifacts in Diffusion Models via Explainable AI-based Flaw Activation Maps","authors":["Seoyeon Lee","Gwangyeol Yu","Chaewon Kim","Jonghyuk Park"],"abstract":"Diffusion models have achieved remarkable success in image synthesis. However, addressing artifacts and unrealistic regions remains a critical challenge. We propose self-refining diffusion, a novel framework that enhances image generation quality by detecting these flaws. The framework employs an explainable artificial intelligence (XAI)-based flaw highlighter to produce flaw activation maps (FAMs) that identify artifacts and unrealistic regions. These FAMs improve reconstruction quality by amplifying noise in flawed regions during the forward process and by focusing on these regions during the reverse process. The proposed approach achieves up to a 27.3% improvement in Fréchet inception distance across various diffusion-based models, demonstrating consistently strong performance on diverse datasets. It also shows robust effectiveness across different tasks, including image generation, text-to-image generation, and inpainting. These results demonstrate that explainable AI techniques can extend beyond interpretability to actively contribute to image refinement. The proposed framework offers a versatile and effective approach applicable to various diffusion models and tasks, significantly advancing the field of image synthesis.","published":"2025-12-09T16:30:31Z","updated":"2025-12-09T16:30:31Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.08774v1","pdf_url":"https://arxiv.org/pdf/2512.08774v1","comment":"10 pages, 9 figures, 7 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.08492","versioned_id":"2512.08492v3","title":"Autonomous Issue Resolver: Towards Zero-Touch Code Maintenance","authors":["Aliaksei Kaliutau"],"abstract":"Recent advances in Large Language Models have revolutionized function-level code generation; however, repository-scale Automated Program Repair (APR) remains a significant challenge. Current approaches typically employ a control-centric paradigm, forcing agents to navigate complex directory structures and irrelevant control logic. In this paper, we propose a paradigm shift from the standard Code Property Graphs (CPGs) to the concept of Data Transformation Graph (DTG) that inverts the topology by modeling data states as nodes and functions as edges, enabling agents to trace logic defects through data lineage rather than control flow. We introduce a multi-agent framework that reconciles data integrity navigation with control flow logic. Our theoretical analysis and case studies demonstrate that this approach resolves the \"Semantic Trap\" inherent in standard RAG systems in modern coding agents. We provide a comprehensive implementation in the form of Autonomous Issue Resolver (AIR), a self-improvement system for zero-touch code maintenance that utilizes neuro-symbolic reasoning and uses the DTG structure for scalable logic repair. Our approach has demonstrated good results on several SWE benchmarks, reaching a resolution rate of 87.1% on SWE-Verified benchmark. Our approach directly addresses the core limitations of current AI code-assistant tools and tackles the critical need for a more robust foundation for our increasingly software-dependent world.","published":"2025-12-09T11:11:37Z","updated":"2026-03-27T19:20:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.08492v3","pdf_url":"https://arxiv.org/pdf/2512.08492v3","comment":"21 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.08300","versioned_id":"2512.08300v1","title":"rSIM: Incentivizing Reasoning Capabilities of LLMs via Reinforced Strategy Injection","authors":["Sijia Chen","Baochun Li","Di Niu"],"abstract":"Large language models (LLMs) are post-trained through reinforcement learning (RL) to evolve into Reasoning Language Models (RLMs), where the hallmark of this advanced reasoning is ``aha'' moments when they start to perform strategies, such as self-reflection and deep thinking, within chain of thoughts (CoTs). Motivated by this, this paper proposes a novel reinforced strategy injection mechanism (rSIM), that enables any LLM to become an RLM by employing a small planner to guide the LLM's CoT through the adaptive injection of reasoning strategies. To achieve this, the planner (leader agent) is jointly trained with an LLM (follower agent) using multi-agent RL (MARL), based on a leader-follower framework and straightforward rule-based rewards. Experimental results show that rSIM enables Qwen2.5-0.5B to become an RLM and significantly outperform Qwen2.5-14B. Moreover, the planner is generalizable: it only needs to be trained once and can be applied as a plug-in to substantially improve the reasoning capabilities of existing LLMs. In addition, the planner supports continual learning across various tasks, allowing its planning abilities to gradually improve and generalize to a wider range of problems.","published":"2025-12-09T06:55:39Z","updated":"2025-12-09T06:55:39Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.08300v1","pdf_url":"https://arxiv.org/pdf/2512.08300v1","comment":"14 pages, 6 figures. Accepted to the ACL ARR July","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.07564","versioned_id":"2512.07564v1","title":"Toward More Reliable Artificial Intelligence: Reducing Hallucinations in Vision-Language Models","authors":["Kassoum Sanogo","Renzo Ardiccioni"],"abstract":"Vision-language models (VLMs) frequently generate hallucinated content plausible but incorrect claims about image content. We propose a training-free self-correction framework enabling VLMs to iteratively refine responses through uncertainty-guided visual re-attention. Our method combines multidimensional uncertainty quantification (token entropy, attention dispersion, semantic consistency, claim confidence) with attention-guided cropping of under-explored regions. Operating entirely with frozen, pretrained VLMs, our framework requires no gradient updates. We validate our approach on the POPE and MMHAL BENCH benchmarks using the Qwen2.5-VL-7B [23] architecture. Experimental results demonstrate that our method reduces hallucination rates by 9.8 percentage points compared to the baseline, while improving object existence accuracy by 4.7 points on adversarial splits. Furthermore, qualitative analysis confirms that uncertainty-guided re-attention successfully grounds corrections in visual evidence where standard decoding fails. We validate our approach on Qwen2.5-VL-7B [23], with plans to extend validation across diverse architectures in future versions. We release our code and methodology to facilitate future research in trustworthy multimodal systems.","published":"2025-12-08T13:58:46Z","updated":"2025-12-08T13:58:46Z","categories":["cs.CV","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.07564v1","pdf_url":"https://arxiv.org/pdf/2512.07564v1","comment":"24 pages, 3 figures, 2 tables. Training-free self-correction framework for vision-language models. Code and implementation details will be released at: https://github.com/kassoumsanogo1/self-correcting-vlm-re-Attention.git","journal_ref":"The 4th National and International Academic Conference Celebrating the 20th Anniversary of Rajapruk University (2026)","doi":"","discovered_on":"2026-07-17"},{"id":"2512.07501","versioned_id":"2512.07501v1","title":"AutoICE: Automatically Synthesizing Verifiable C Code via LLM-driven Evolution","authors":["Weilin Luo","Xueyi Liang","Haotian Deng","Yanan Liu","Hai Wan"],"abstract":"Automatically synthesizing verifiable code from natural language requirements ensures software correctness and reliability while significantly lowering the barrier to adopting the techniques of formal methods. With the rise of large language models (LLMs), long-standing efforts at autoformalization have gained new momentum. However, existing approaches suffer from severe syntactic and semantic errors due to the scarcity of domain-specific pre-training corpora and often fail to formalize implicit knowledge effectively. In this paper, we propose AutoICE, an LLM-driven evolutionary search for synthesizing verifiable C code. It introduces the diverse individual initialization and the collaborative crossover to enable diverse iterative updates, thereby mitigating error propagation inherent in single-agent iterations. Besides, it employs the self-reflective mutation to facilitate the discovery of implicit knowledge. Evaluation results demonstrate the effectiveness of AutoICE: it successfully verifies $90.36$\\% of code, outperforming the state-of-the-art (SOTA) approach. Besides, on a developer-friendly dataset variant, AutoICE achieves a $88.33$\\% verification success rate, significantly surpassing the $65$\\% success rate of the SOTA approach.","published":"2025-12-08T12:35:10Z","updated":"2025-12-08T12:35:10Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2512.07501v1","pdf_url":"https://arxiv.org/pdf/2512.07501v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.20640","versioned_id":"2512.20640v2","title":"Reflection-Driven Self-Optimization 6G Agentic AI RAN via Simulation-in-the-Loop Workflows","authors":["Yunhao Hu","Xinchen Lyu","Chenshan Ren","Keda Chen","Qimei Cui","Xiaofeng Tao"],"abstract":"The escalating complexity of sixth-generation (6G) networks demands unprecedented levels of autonomy beyond the capabilities of traditional optimization-based and current AI-based resource management approaches. While agentic AI has emerged as a promising paradigm for autonomous RAN, current frameworks provide sophisticated reasoning capabilities but lack mechanisms for empirical validation and self-improvement. This article identifies simulation-in-the-loop validation as a critical enabler for truly autonomous networks, where AI agents can empirically verify decisions and learn from outcomes. We present the first reflection-driven self-optimization framework that integrates agentic AI with high-fidelity network simulation in a closed-loop architecture. Our system orchestrates four specialized agents, including scenario, solver, simulation, and reflector agents, working in concert to transform agentic AI into a self-correcting system capable of escaping local optima, recognizing implicit user intent, and adapting to dynamic network conditions. Extensive experiments validate significant performance improvements over non-agentic approaches: 17.1\\% higher throughput in interference optimization, 67\\% improved user QoS satisfaction through intent recognition, and 25\\% reduced resource utilization during low-traffic periods while maintaining service quality.","published":"2025-12-08T06:34:35Z","updated":"2026-04-21T11:04:29Z","categories":["cs.NI","cs.MA"],"primary_category":"cs.NI","arxiv_url":"https://arxiv.org/abs/2512.20640v2","pdf_url":"https://arxiv.org/pdf/2512.20640v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.07141","versioned_id":"2512.07141v1","title":"Think-Reflect-Revise: A Policy-Guided Reflective Framework for Safety Alignment in Large Vision Language Models","authors":["Fenghua Weng","Chaochao Lu","Xia Hu","Wenqi Shao","Wenjie Wang"],"abstract":"As multimodal reasoning improves the overall capabilities of Large Vision Language Models (LVLMs), recent studies have begun to explore safety-oriented reasoning, aiming to enhance safety awareness by analyzing potential safety risks during the reasoning process before generating the final response. Although such approaches improve safety awareness and interpretability, this single-pass think-then-answer paradigm remains vulnerable to contextual or visual jailbreak attacks. This reveals a critical flaw: single-pass reasoning may overlook explicit harmful content in its own output. Our key insight is to exploit this wasted signal through reflection, which can effectively leverage the malicious content revealed in the first-pass reasoning to enable genuine self-correction and prevent unsafe generations. Motivated by this, we propose Think-Reflect-Revise (TRR), a three-stage training framework designed to enhance the safety alignment of LVLMs through policy-guided self-reflection. We first build a Reflective Safety Reasoning (ReSafe) dataset with 5,000 examples that follow a think-reflect-revise process. We then fine-tune the target model using the ReSafe dataset to initialize reflective behavior, and finally reinforce policy-guided reflection through reinforcement learning. Experimental results show that TRR substantially improves the safety performance of LVLMs across both safety-awareness benchmarks and jailbreak attack evaluations, increasing the overall safe response rate from 42.8% to 87.7% on Qwen2.5-VL-7B, while preserving stable performance on general benchmarks such as MMMU and MMStar. The project page is available at https://think-reflect-revise.github.io/.","published":"2025-12-08T03:46:03Z","updated":"2025-12-08T03:46:03Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.07141v1","pdf_url":"https://arxiv.org/pdf/2512.07141v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.05464","versioned_id":"2512.05464v1","title":"Dynamic Alignment for Collective Agency: Toward a Scalable Self-Improving Framework for Open-Ended LLM Alignment","authors":["Panatchakorn Anantaprayoon","Nataliia Babina","Jad Tarifi","Nima Asgharbeygi"],"abstract":"Large Language Models (LLMs) are typically aligned with human values using preference data or predefined principles such as helpfulness, honesty, and harmlessness. However, as AI systems progress toward Artificial General Intelligence (AGI) and Artificial Superintelligence (ASI), such value systems may become insufficient. In addition, human feedback-based alignment remains resource-intensive and difficult to scale. While AI-feedback-based self-improving alignment methods have been explored as a scalable alternative, they have largely remained constrained to conventional alignment values. In this work, we explore both a more holistic alignment objective and a scalable, self-improving alignment approach. Aiming to transcend conventional alignment norms, we introduce Collective Agency (CA)-a unified and open-ended alignment value that encourages integrated agentic capabilities. We also propose Dynamic Alignment-an alignment framework that enables an LLM to iteratively align itself. Dynamic Alignment comprises two key components: (1) automated training dataset generation with LLMs, and (2) a self-rewarding mechanism, where the policy model evaluates its own output candidates and assigns rewards for GRPO-based learning. Experimental results demonstrate that our approach successfully aligns the model to CA while preserving general NLP capabilities.","published":"2025-12-05T06:46:00Z","updated":"2025-12-05T06:46:00Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.05464v1","pdf_url":"https://arxiv.org/pdf/2512.05464v1","comment":"8 pages, 4 figures, to appear in AAAI 2026 AIGOV Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.05356","versioned_id":"2512.05356v2","title":"AI & Human Co-Improvement for Safer Co-Superintelligence","authors":["Jason Weston","Jakob Foerster"],"abstract":"Self-improvement is a goal currently exciting the field of AI, but is fraught with danger, and may take time to fully achieve. We advocate that a more achievable and better goal for humanity is to maximize co-improvement: collaboration between human researchers and AIs to achieve co-superintelligence. That is, specifically targeting improving AI systems' ability to work with human researchers to conduct AI research together, from ideation to experimentation, in order to both accelerate AI research and to generally endow both AIs and humans with safer superintelligence through their symbiosis. Focusing on including human research improvement in the loop will both get us there faster, and more safely.","published":"2025-12-05T01:50:23Z","updated":"2025-12-14T18:03:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.05356v2","pdf_url":"https://arxiv.org/pdf/2512.05356v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.04797","versioned_id":"2512.04797v1","title":"SIMA 2: A Generalist Embodied Agent for Virtual Worlds","authors":["SIMA team","Adrian Bolton","Alexander Lerchner","Alexandra Cordell","Alexandre Moufarek","Andrew Bolt","Andrew Lampinen","Anna Mitenkova","Arne Olav Hallingstad","Bojan Vujatovic","Bonnie Li","Cong Lu","Daan Wierstra","Daniel P. Sawyer","Daniel Slater","David Reichert","Davide Vercelli","Demis Hassabis","Drew A. Hudson","Duncan Williams","Ed Hirst","Fabio Pardo","Felix Hill","Frederic Besse","Hannah Openshaw","Harris Chan","Hubert Soyer","Jane X. Wang","Jeff Clune","John Agapiou","John Reid","Joseph Marino","Junkyung Kim","Karol Gregor","Kaustubh Sridhar","Kay McKinney","Laura Kampis","Lei M. Zhang","Loic Matthey","Luyu Wang","Maria Abi Raad","Maria Loks-Thompson","Martin Engelcke","Matija Kecman","Matthew Jackson","Maxime Gazeau","Ollie Purkiss","Oscar Knagg","Peter Stys","Piermaria Mendolicchio","Raia Hadsell","Rosemary Ke","Ryan Faulkner","Sarah Chakera","Satinder Singh Baveja","Shane Legg","Sheleem Kashem","Tayfun Terzi","Thomas Keck","Tim Harley","Tim Scholtes","Tyson Roberts","Volodymyr Mnih","Yulan Liu","Zhengdong Wang","Zoubin Ghahramani"],"abstract":"We introduce SIMA 2, a generalist embodied agent that understands and acts in a wide variety of 3D virtual worlds. Built upon a Gemini foundation model, SIMA 2 represents a significant step toward active, goal-directed interaction within an embodied environment. Unlike prior work (e.g., SIMA 1) limited to simple language commands, SIMA 2 acts as an interactive partner, capable of reasoning about high-level goals, conversing with the user, and handling complex instructions given through language and images. Across a diverse portfolio of games, SIMA 2 substantially closes the gap with human performance and demonstrates robust generalization to previously unseen environments, all while retaining the base model's core reasoning capabilities. Furthermore, we demonstrate a capacity for open-ended self-improvement: by leveraging Gemini to generate tasks and provide rewards, SIMA 2 can autonomously learn new skills from scratch in a new environment. This work validates a path toward creating versatile and continuously learning agents for both virtual and, eventually, physical worlds.","published":"2025-12-04T13:46:11Z","updated":"2025-12-04T13:46:11Z","categories":["cs.AI","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.04797v1","pdf_url":"https://arxiv.org/pdf/2512.04797v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.04276","versioned_id":"2512.04276v1","title":"The Geometry of Benchmarks: A New Path Toward AGI","authors":["Przemyslaw Chojecki"],"abstract":"Benchmarks are the primary tool for assessing progress in artificial intelligence (AI), yet current practice evaluates models on isolated test suites and provides little guidance for reasoning about generality or autonomous self-improvement. Here we introduce a geometric framework in which all psychometric batteries for AI agents are treated as points in a structured moduli space, and agent performance is described by capability functionals over this space. First, we define an Autonomous AI (AAI) Scale, a Kardashev-style hierarchy of autonomy grounded in measurable performance on batteries spanning families of tasks (for example reasoning, planning, tool use and long-horizon control). Second, we construct a moduli space of batteries, identifying equivalence classes of benchmarks that are indistinguishable at the level of agent orderings and capability inferences. This geometry yields determinacy results: dense families of batteries suffice to certify performance on entire regions of task space. Third, we introduce a general Generator-Verifier-Updater (GVU) operator that subsumes reinforcement learning, self-play, debate and verifier-based fine-tuning as special cases, and we define a self-improvement coefficient $κ$ as the Lie derivative of a capability functional along the induced flow. A variance inequality on the combined noise of generation and verification provides sufficient conditions for $κ> 0$. Our results suggest that progress toward artificial general intelligence (AGI) is best understood as a flow on moduli of benchmarks, driven by GVU dynamics rather than by scores on individual leaderboards.","published":"2025-12-03T21:34:09Z","updated":"2025-12-03T21:34:09Z","categories":["cs.AI","cs.LG","math.ST"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.04276v1","pdf_url":"https://arxiv.org/pdf/2512.04276v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.03891","versioned_id":"2512.03891v1","title":"Digital Twin-based Control Co-Design of Full Vehicle Active Suspensions via Deep Reinforcement Learning","authors":["Ying-Kuan Tsai","Yi-Ping Chen","Vispi Karkaria","Wei Chen"],"abstract":"Active suspension systems are critical for enhancing vehicle comfort, safety, and stability, yet their performance is often limited by fixed hardware designs and control strategies that cannot adapt to uncertain and dynamic operating conditions. Recent advances in digital twins (DTs) and deep reinforcement learning (DRL) offer new opportunities for real-time, data-driven optimization across a vehicle's lifecycle. However, integrating these technologies into a unified framework remains an open challenge. This work presents a DT-based control co-design (CCD) framework for full-vehicle active suspensions using multi-generation design concepts. By integrating automatic differentiation into DRL, we jointly optimize physical suspension components and control policies under varying driver behaviors and environmental uncertainties. DRL also addresses the challenge of partial observability, where only limited states can be sensed and fed back to the controller, by learning optimal control actions directly from available sensor information. The framework incorporates model updating with quantile learning to capture data uncertainty, enabling real-time decision-making and adaptive learning from digital-physical interactions. The approach demonstrates personalized optimization of suspension systems under two distinct driving settings (mild and aggressive). Results show that the optimized systems achieve smoother trajectories and reduce control efforts by approximately 43% and 52% for mild and aggressive, respectively, while maintaining ride comfort and stability. Contributions include: developing a DT-enabled CCD framework integrating DRL and uncertainty-aware model updating for full-vehicle active suspensions, introducing a multi-generation design strategy for self-improving systems, and demonstrating personalized optimization of active suspension systems for distinct driver types.","published":"2025-12-03T15:41:35Z","updated":"2025-12-03T15:41:35Z","categories":["cs.RO","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2512.03891v1","pdf_url":"https://arxiv.org/pdf/2512.03891v1","comment":"28 pages, 17 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.03549","versioned_id":"2512.03549v1","title":"PARC: An Autonomous Self-Reflective Coding Agent for Robust Execution of Long-Horizon Tasks","authors":["Yuki Orimo","Iori Kurata","Hodaka Mori","Ryuhei Okuno","Ryohto Sawada","Daisuke Okanohara"],"abstract":"We introduce PARC, a coding agent for the autonomous and robust execution of long-horizon computational tasks. PARC is built on a hierarchical multi-agent architecture incorporating task planning, execution, and a mechanism that evaluates its own actions and their outcomes from an independent context and provides feedback, namely self-assessment and self-feedback. This design enables PARC to detect and correct high-level strategic errors and sustain progress without human intervention. We evaluate PARC across computational science and data science tasks. In materials science, it autonomously reproduces key results from studies on lithium-ion conduction and alloy segregation. In particular, it coordinates dozens of parallel simulation tasks, each requiring roughly 43 hours of computation, managing orchestration, monitoring, and error correction end-to-end. In Kaggle-based experiments, starting from minimal natural-language instructions, PARC conducts data analysis and implements search strategies, producing solutions competitive with human-engineered baselines. These results highlight the potential of integrating a hierarchical multi-agent system with self-assessment and self-feedback to enable AI systems capable of independent, large-scale scientific and analytical work.","published":"2025-12-03T08:15:10Z","updated":"2025-12-03T08:15:10Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.03549v1","pdf_url":"https://arxiv.org/pdf/2512.03549v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02835","versioned_id":"2512.02835v1","title":"ReVSeg: Incentivizing the Reasoning Chain for Video Segmentation with Reinforcement Learning","authors":["Yifan Li","Yingda Yin","Lingting Zhu","Weikai Chen","Shengju Qian","Xin Wang","Yanwei Fu"],"abstract":"Reasoning-centric video object segmentation is an inherently complex task: the query often refers to dynamics, causality, and temporal interactions, rather than static appearances. Yet existing solutions generally collapse these factors into simplified reasoning with latent embeddings, rendering the reasoning chain opaque and essentially intractable. We therefore adopt an explicit decomposition perspective and introduce ReVSeg, which executes reasoning as sequential decisions in the native interface of pretrained vision language models (VLMs). Rather than folding all reasoning into a single-step prediction, ReVSeg executes three explicit operations -- semantics interpretation, temporal evidence selection, and spatial grounding -- aligning pretrained capabilities. We further employ reinforcement learning to optimize the multi-step reasoning chain, enabling the model to self-refine its decision quality from outcome-driven signals. Experimental results demonstrate that ReVSeg attains state-of-the-art performances on standard video object segmentation benchmarks and yields interpretable reasoning trajectories. Project page is available at https://clementine24.github.io/ReVSeg/ .","published":"2025-12-02T14:44:12Z","updated":"2025-12-02T14:44:12Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2512.02835v1","pdf_url":"https://arxiv.org/pdf/2512.02835v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02812","versioned_id":"2512.02812v1","title":"Enhancing Automated Paper Reproduction via Prompt-Free Collaborative Agents","authors":["Zijie Lin","Qilin Cai","Liang Shen","Mingjun Xiao"],"abstract":"Automated paper reproduction has emerged as a promising approach to accelerate scientific research, employing multi-step workflow frameworks to systematically convert academic papers into executable code. However, existing frameworks often lack mechanisms to verify and refine the outputs at each generation step, or rely heavily on manually designed prompts for self-refinement, which limits their adaptability and scalability. To address these limitations, we propose a prompt-free collaborative agent framework that automatically enhances the quality of paper-to-code generation. Our approach employs two collaborative agents: a verification agent that examines whether the outputs at each step satisfy the requirements specified in the corresponding system prompt, and a refinement agent that revises the outputs based on the identified issues. Unlike previous methods that require human experts to craft specific refinement prompts for each step, our framework achieves automatic verification and improvement by leveraging only the original system prompts. We integrate our collaborative agents into the Paper2Code framework and conduct comprehensive experiments on PaperBench Code-Dev and Paper2CodeBench datasets. Experimental results demonstrate that our approach significantly improves the accuracy and completeness of reproduced code, achieving performance gains of approximately 15\\% and 13\\%, respectively, compared to the baseline without our agents. Furthermore, comparative experiments against Self-Refine validate the robustness and consistency of our prompt-free approach across different datasets.","published":"2025-12-02T14:24:23Z","updated":"2025-12-02T14:24:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02812v1","pdf_url":"https://arxiv.org/pdf/2512.02812v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02810","versioned_id":"2512.02810v1","title":"Phase-Adaptive LLM Framework with Multi-Stage Validation for Construction Robot Task Allocation: A Systematic Benchmark Against Traditional Optimization Algorithms","authors":["Shyam prasad reddy Kaitha","Hongrui Yu"],"abstract":"Multi-robot task allocation in construction automation has traditionally relied on optimization methods such as Dynamic Programming and Reinforcement Learning. This research introduces the LangGraph-based Task Allocation Agent (LTAA), an LLM-driven framework that integrates phase-adaptive allocation strategies, multi-stage validation with hierarchical retries, and dynamic prompting for efficient robot coordination. Although recent LLM approaches show potential for construction robotics, they largely lack rigorous validation and benchmarking against established algorithms. This paper presents the first systematic comparison of LLM-based task allocation with traditional methods in construction scenarios.The study validates LLM feasibility through SMART-LLM replication and addresses implementation challenges using a Self-Corrective Agent Architecture. LTAA leverages natural-language reasoning combined with structured validation mechanisms, achieving major computational gains reducing token usage by 94.6% and allocation time by 86% through dynamic prompting. The framework adjusts its strategy across phases: emphasizing execution feasibility early and workload balance in later allocations.The authors evaluate LTAA against Dynamic Programming, Q-learning, and Deep Q-Network (DQN) baselines using construction operations from the TEACh human-robot collaboration dataset. In the Heavy Excels setting, where robots have strong task specializations, LTAA achieves 77% task completion with superior workload balance, outperforming all traditional methods. These findings show that LLM-based reasoning with structured validation can match established optimization algorithms while offering additional advantages such as interpretability, adaptability, and the ability to update task logic without retraining.","published":"2025-12-02T14:23:36Z","updated":"2025-12-02T14:23:36Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2512.02810v1","pdf_url":"https://arxiv.org/pdf/2512.02810v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02731","versioned_id":"2512.02731v1","title":"Self-Improving AI Agents through Self-Play","authors":["Przemyslaw Chojecki"],"abstract":"We extend the moduli-theoretic framework of psychometric batteries to the domain of dynamical systems. While previous work established the AAI capability score as a static functional on the space of agent representations, this paper formalizes the agent as a flow $ν_r$ parameterized by computational resource $r$, governed by a recursive Generator-Verifier-Updater (GVU) operator. We prove that this operator generates a vector field on the parameter manifold $Θ$, and we identify the coefficient of self-improvement $κ$ as the Lie derivative of the capability functional along this flow. The central contribution of this work is the derivation of the Variance Inequality, a spectral condition that is sufficient (under mild regularity) for the stability of self-improvement. We show that a sufficient condition for $κ> 0$ is that, up to curvature and step-size effects, the combined noise of generation and verification must be small enough. We then apply this formalism to unify the recent literature on Language Self-Play (LSP), Self-Correction, and Synthetic Data bootstrapping. We demonstrate that architectures such as STaR, SPIN, Reflexion, GANs and AlphaZero are specific topological realizations of the GVU operator that satisfy the Variance Inequality through filtration, adversarial discrimination, or grounding in formal systems.","published":"2025-12-02T13:13:57Z","updated":"2025-12-02T13:13:57Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02731v1","pdf_url":"https://arxiv.org/pdf/2512.02731v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02389","versioned_id":"2512.02389v1","title":"Synthetic Error Injection Fails to Elicit Self-Correction In Language Models","authors":["David X. Wu","Shreyas Kapur","Anant Sahai","Stuart Russell"],"abstract":"Reinforcement learning has become the dominant paradigm for eliciting reasoning and self-correction capabilities in large language models, but its computational expense motivates exploration of alternatives. Inspired by techniques from autonomous driving and robotics, we investigate whether supervised learning with synthetic error injection can induce self-correction abilities in language models. Our approach inserts artificial errors into reasoning chains, masks them, and supervises the model to recognize and correct these mistakes. Despite the intuitive appeal of this method, we find that it fails to significantly improve performance even on simple synthetic tasks across multiple models. Moreover, even when the model catches its own error, it often parrots the original mistake. We find that the distribution shift of synthetic errors to on-policy errors significantly degrades the error-correction capabilities of the fine-tuned model, even with good synthetic coverage of on-policy errors. Our results help explain why on-policy reinforcement learning methods have proven uniquely effective for eliciting self-correction.","published":"2025-12-02T03:57:49Z","updated":"2025-12-02T03:57:49Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02389v1","pdf_url":"https://arxiv.org/pdf/2512.02389v1","comment":"13 pages, 12 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02304","versioned_id":"2512.02304v2","title":"When Does Verification Pay Off? A Closer Look at LLMs as Solution Verifiers","authors":["Jack Lu","Ryan Teehan","Jinran Jin","Mengye Ren"],"abstract":"Large language models (LLMs) can act as both problem solvers and solution verifiers, where the latter select high-quality answers from a pool of solver-generated candidates. This raises the question of under what conditions verification pays off in solver-verifier systems. Prior work has conducted only limited studies of the factors influencing verification performance, focusing primarily on self-verification and examining neither the relationship between solver and verifier model families nor the effects of reasoning post-training. To rectify this, we present a systematic study across 37 models spanning multiple families, sizes, and base vs. post-trained variants, evaluated on 9 benchmarks covering logical reasoning, structured puzzles, symbolic computation, mathematics, commonsense, factual recall, and domain knowledge. In order to support our analysis, we introduce and empirically validate verifier gain, a metric that predicts the performance improvements from test-time verifier-based rejection sampling. Our experiments find that 1) verification across model families is more effective than either self-verification or verification within the same family, and more generally that the benefits of verification decrease as the solver and verifier become more similar, 2) reasoning post-training weakens self-improvement abilities but strengthens cross-family improvement, and 3) some tasks are inherently more amenable to improvement through verification, particularly mathematical and logical tasks.","published":"2025-12-02T00:51:14Z","updated":"2026-04-21T03:02:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.02304v2","pdf_url":"https://arxiv.org/pdf/2512.02304v2","comment":"Accepted at ICLR 2026 AI with Recursive Self-Improvement workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02280","versioned_id":"2512.02280v1","title":"Bridging the Gap: Toward Cognitive Autonomy in Artificial Intelligence","authors":["Noorbakhsh Amiri Golilarz","Sindhuja Penchala","Shahram Rahimi"],"abstract":"Artificial intelligence has advanced rapidly across perception, language, reasoning, and multimodal domains. Yet despite these achievements, modern AI systems remain fundamentally limited in their ability to self-monitor, self-correct, and regulate their behavior autonomously in dynamic contexts. This paper identifies and analyzes seven core deficiencies that constrain contemporary AI models: the absence of intrinsic self-monitoring, lack of meta-cognitive awareness, fixed and non-adaptive learning mechanisms, inability to restructure goals, lack of representational maintenance, insufficient embodied feedback, and the absence of intrinsic agency. Alongside identifying these limitations, we also outline a forward-looking perspective on how AI may evolve beyond them through architectures that mirror neurocognitive principles. We argue that these structural limitations prevent current architectures, including deep learning and transformer-based systems, from achieving robust generalization, lifelong adaptability, and real-world autonomy. Drawing on a comparative analysis of artificial systems and biological cognition [7], and integrating insights from AI research, cognitive science, and neuroscience, we outline how these capabilities are absent in current models and why scaling alone cannot resolve them. We conclude by advocating for a paradigmatic shift toward cognitively grounded AI (cognitive autonomy) capable of self-directed adaptation, dynamic representation management, and intentional, goal-oriented behavior, paired with reformative oversight mechanisms [8] that ensure autonomous systems remain interpretable, governable, and aligned with human values.","published":"2025-12-01T23:51:08Z","updated":"2025-12-01T23:51:08Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02280v1","pdf_url":"https://arxiv.org/pdf/2512.02280v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02228","versioned_id":"2512.02228v1","title":"STRIDE: A Systematic Framework for Selecting AI Modalities -- Agentic AI, AI Assistants, or LLM Calls","authors":["Shubhi Asthana","Bing Zhang","Chad DeLuca","Ruchi Mahindru","Hima Patel"],"abstract":"The rapid shift from stateless large language models (LLMs) to autonomous, goal-driven agents raises a central question: When is agentic AI truly necessary? While agents enable multi-step reasoning, persistent memory, and tool orchestration, deploying them indiscriminately leads to higher cost, complexity, and risk. We present STRIDE (Systematic Task Reasoning Intelligence Deployment Evaluator), a framework that provides principled recommendations for selecting between three modalities: (i) direct LLM calls, (ii) guided AI assistants, and (iii) fully autonomous agentic AI. STRIDE integrates structured task decomposition, dynamism attribution, and self-reflection requirement analysis to produce an Agentic Suitability Score, ensuring that full agentic autonomy is reserved for tasks with inherent dynamism or evolving context. Evaluated across 30 real-world tasks spanning SRE, compliance, and enterprise automation, STRIDE achieved 92% accuracy in modality selection, reduced unnecessary agent deployments by 45%, and cut resource costs by 37%. Expert validation over six months in SRE and compliance domains confirmed its practical utility, with domain specialists agreeing that STRIDE effectively distinguishes between tasks requiring simple LLM calls, guided assistants, or full agentic autonomy. This work reframes agent adoption as a necessity-driven design decision, ensuring autonomy is applied only when its benefits justify the costs.","published":"2025-12-01T21:54:07Z","updated":"2025-12-01T21:54:07Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02228v1","pdf_url":"https://arxiv.org/pdf/2512.02228v1","comment":"10 pages, 4 Figures, 5 Tables Paper presented at NeurIPS 2025 LAW workshop: Bridging Language, Agent, and World Models","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.02185","versioned_id":"2512.02185v1","title":"Think Before You Prune: Self-Reflective Structured Pruning for Reasoning Language Models","authors":["Ziyan Wang","Enmao Diao","Qi Le","Pu Wang","Guanchu Wang","Minwoo Lee","Shu-ping Yeh","Li Yang"],"abstract":"Reasoning LLMs (RLMs) such as OpenAI o1, DeepSeek-R1, and Qwen3 deliver strong multi-step reasoning through chain-of-thought generation, but their large model sizes and lengthy decode-time outputs make them costly to deploy and unsuitable for resource-constrained settings. To reduce computing and memory cost, pruning offers a promising solution by removing unimportant parameters. However, despite their success on standard LLMs, existing pruning methods severely damage RLMs, as even moderate sparsity (e.g., 20%) can collapse accuracy and completely disrupt the model's reasoning coherence. We begin by analyzing why existing pruning pipelines fail on reasoning LLMs and find that their brittleness largely stems from a mismatch between the calibration data, the pruning objective, and the model's decode-time reasoning behavior. Our study further shows that the most reliable calibration signal comes not from human-written labels but from the model's own self-generated reasoning traces, which more accurately reflect its inference distribution. Guided by these insights, we introduce RESP, a self-reflective structured pruning framework that aligns pruning decisions with the model's reasoning dynamics through self-generated calibration, decode-only gradient-based importance estimation, and progressive regeneration that maintains calibration fidelity as sparsity increases. Experiments on Qwen3-8B demonstrate that RESP markedly outperforms existing structured pruning methods on both GSM8K and MathQA, preserving near-dense accuracy at 20-30% sparsity and substantially mitigating performance collapse at higher sparsity levels. At 40% sparsity, RESP attains 81.3% accuracy on GSM8K and 59.6% on MathQA, surpassing the strongest baselines by 66.87% and 47%, respectively.","published":"2025-12-01T20:27:05Z","updated":"2025-12-01T20:27:05Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.02185v1","pdf_url":"https://arxiv.org/pdf/2512.02185v1","comment":"7 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.04119","versioned_id":"2512.04119v1","title":"Humanity in the Age of AI: Reassessing 2025's Existential-Risk Narratives","authors":["Mohamed El Louadi"],"abstract":"Two 2025 publications, \"AI 2027\" (Kokotajlo et al., 2025) and \"If Anyone Builds It, Everyone Dies\" (Yudkowsky & Soares, 2025), assert that superintelligent artificial intelligence will almost certainly destroy or render humanity obsolete within the next decade. Both rest on the classic chain formulated by Good (1965) and Bostrom (2014): intelligence explosion, superintelligence, lethal misalignment. This article subjects each link to the empirical record of 2023-2025. Sixty years after Good's speculation, none of the required phenomena (sustained recursive self-improvement, autonomous strategic awareness, or intractable lethal misalignment) have been observed. Current generative models remain narrow, statistically trained artefacts: powerful, opaque, and imperfect, but devoid of the properties that would make the catastrophic scenarios plausible. Following Whittaker (2025a, 2025b, 2025c) and Zuboff (2019, 2025), we argue that the existential-risk thesis functions primarily as an ideological distraction from the ongoing consolidation of surveillance capitalism and extreme concentration of computational power. The thesis is further inflated by the 2025 AI speculative bubble, where trillions in investments in rapidly depreciating \"digital lettuce\" hardware (McWilliams, 2025) mask lagging revenues and jobless growth rather than heralding superintelligence. The thesis remains, in November 2025, a speculative hypothesis amplified by a speculative financial bubble rather than a demonstrated probability.","published":"2025-12-01T19:37:27Z","updated":"2025-12-01T19:37:27Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2512.04119v1","pdf_url":"https://arxiv.org/pdf/2512.04119v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.03101","versioned_id":"2512.03101v1","title":"ALARM: Automated MLLM-Based Anomaly Detection in Complex-EnviRonment Monitoring with Uncertainty Quantification","authors":["Congjing Zhang","Feng Lin","Xinyi Zhao","Pei Guo","Wei Li","Lin Chen","Chaoyue Zhao","Shuai Huang"],"abstract":"The advance of Large Language Models (LLMs) has greatly stimulated research interest in developing multi-modal LLM (MLLM)-based visual anomaly detection (VAD) algorithms that can be deployed in complex environments. The challenge is that in these complex environments, the anomalies are sometimes highly contextual and also ambiguous, and thereby, uncertainty quantification (UQ) is a crucial capacity for an MLLM-based VAD system to succeed. In this paper, we introduce our UQ-supported MLLM-based VAD framework called ALARM. ALARM integrates UQ with quality-assurance techniques like reasoning chain, self-reflection, and MLLM ensemble for robust and accurate performance and is designed based on a rigorous probabilistic inference pipeline and computational process. Extensive empirical evaluations are conducted using the real-world smart-home benchmark data and wound image classification data, which shows ALARM's superior performance and its generic applicability across different domains for reliable decision-making.","published":"2025-12-01T19:03:14Z","updated":"2025-12-01T19:03:14Z","categories":["cs.LG","cs.AI","cs.CV"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.03101v1","pdf_url":"https://arxiv.org/pdf/2512.03101v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.01725","versioned_id":"2512.01725v1","title":"Beware of Reasoning Overconfidence: Pitfalls in the Reasoning Process for Multi-solution Tasks","authors":["Jiannan Guan","Qiguang Chen","Libo Qin","Dengyun Peng","Jinhao Liu","Liangyu Huo","Jian Xie","Wanxiang Che"],"abstract":"Large Language Models (LLMs) excel in reasoning tasks requiring a single correct answer, but they perform poorly in multi-solution tasks that require generating comprehensive and diverse answers. We attribute this limitation to \\textbf{reasoning overconfidence}: a tendency to express undue certainty in an incomplete solution set. To examine the effect, we introduce \\textit{MuSoBench}, a benchmark of multi-solution problems. Experiments show that the conventional short chain-of-thought (Short-CoT) prompting paradigm exhibits pronounced overconfidence, whereas the emerging long chain-of-thought (Long-CoT) approach mitigates it through iterative exploration and self-reflection. We further characterise observable behaviours and influential factors. To probe the underlying cause, we propose the \\textbf{cognitive-rigidity hypothesis}, which posits that overconfidence arises when the reasoning process prematurely converges on a narrow set of thought paths. An attention-entropy analysis offers preliminary support for this view. These findings provide tools for assessing the completeness of LLM reasoning and highlight the need to move evaluation beyond single-answer accuracy toward comprehensive exploration.","published":"2025-12-01T14:35:06Z","updated":"2025-12-01T14:35:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.01725v1","pdf_url":"https://arxiv.org/pdf/2512.01725v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.01187","versioned_id":"2512.01187v1","title":"Teaching by Failure: Counter-Example-Driven Curricula for Transformer Self-Improvement","authors":["Harshil Vejendla"],"abstract":"Transformer models often exhibit brittle extrapolation, failing on inputs that are longer or structurally more complex than those seen during training. We introduce Counter-Example-Driven Curricula (CEDC), an automated framework that improves model robustness by iteratively focusing on its own failures. At each step, CEDC uses the current model to generate a diverse set of candidate problems, employs a fast, executable verifier to identify incorrect predictions (counter-examples), and then fine-tunes the model on a dataset enriched with these discovered failures. We evaluate CEDC on a suite of algorithmic and natural language tasks, including integer addition, sorting, Dyck-2 language recognition, and three text classification benchmarks. Compared to static training and standard curriculum learning baselines, CEDC achieves up to 30x greater length extrapolation, is 3.75x more computationally efficient than uniform data augmentation, and requires no manual difficulty heuristics. We provide a detailed analysis of the counter-examples, showing how the curriculum naturally adapts to target progressively more complex error modes. Our findings establish verifier-guided, failure-driven learning as a simple, powerful, and efficient paradigm for enhancing the generalization capabilities of Transformer models.","published":"2025-12-01T02:00:41Z","updated":"2025-12-01T02:00:41Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.01187v1","pdf_url":"https://arxiv.org/pdf/2512.01187v1","comment":"AACL 2025 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.01174","versioned_id":"2512.01174v1","title":"DrawingBench: Evaluating Spatial Reasoning and UI Interaction Capabilities of Large Language Models through Mouse-Based Drawing Tasks","authors":["Hyunjun Kim","Sooyoung Ryu"],"abstract":"As agentic AI systems increasingly operate autonomously, establishing trust through verifiable evaluation becomes critical. Yet existing benchmarks lack the transparency and auditability needed to assess whether agents behave reliably. We present DrawingBench, a verification framework for evaluating the trustworthiness of agentic LLMs through spatial reasoning tasks that require generating sequences of low-level GUI actions. Unlike opaque evaluations, DrawingBench provides transparent, rule-based assessment: 8 objective criteria enable reproducible scoring, while action-level inspection allows stakeholders to audit agent behavior. Our framework comprises 250 diverse prompts across 20 categories and 4 difficulty levels, deterministic evaluation metrics, and an external oversight mechanism through multi-turn feedback that enables human control over agent refinement. Evaluating four state-of-the-art LLMs (Claude-4 Sonnet, GPT-4.1, GPT-4.1-mini, Gemini-2.5 Flash) across 1,000 tests, we establish both capabilities and limitations: models achieved 92.8% perfect performance with structured external feedback driving significant improvements (average +3.2%, up to +32.8% for complex scenes), but systematic error patterns emerged in tool state management and long-horizon planning. Notably, specification clarity proved more important than task complexity -- models achieved 100% perfect performance when given explicit, verifiable criteria. These findings demonstrate that transparent evaluation frameworks can establish trust in agentic systems, with external oversight proving more reliable than self-correction for guiding agent behavior. Our open-source framework provides a template for trustworthy agent assessment. Code and data: https://github.com/hyunjun1121/DrawingBench","published":"2025-12-01T01:18:21Z","updated":"2025-12-01T01:18:21Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.01174v1","pdf_url":"https://arxiv.org/pdf/2512.01174v1","comment":"AAAI 2026 TrustAgent Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.00331","versioned_id":"2512.00331v1","title":"CogEvo-Edu: Cognitive Evolution Educational Multi-Agent Collaborative System","authors":["Yefeng Wu","Yuchen Song","Yecheng Zhao","Ling Wu","Shan Wan"],"abstract":"Large language models (LLMs) are increasingly deployed as conversational tutors in STEM education, yet most systems still rely on a single LLM with a static retrieval-augmented generation (RAG) pipeline over course materials. This design struggles in complex domains such as digital signal processing (DSP), where tutors must maintain coherent long-term student models, manage heterogeneous knowledge bases, and adapt teaching strategies over extended interactions. We argue that retrieval, memory, and control should be treated as a coupled cognitive evolution process. We instantiate this view in CogEvo-Edu, a hierarchical educational multi-agent system comprising a Cognitive Perception Layer (CPL), a Knowledge Evolution Layer (KEL), and a Meta-Control Layer (MCL). CPL maintains dual memories and performs confidence-weighted consolidation to build structured, self-correcting student profiles under limited context. KEL assigns each knowledge chunk a spatiotemporal value that drives activation, semantic compression, and forgetting. MCL formulates tutoring as hierarchical sequential decision making, orchestrating specialized agents and jointly adapting CPL/KEL hyperparameters via a dual inner--outer loop. To evaluate CogEvo-Edu, we construct DSP-EduBench, a vertical benchmark for DSP tutoring with heterogeneous resources, simulated student profiles, and long-horizon interaction scripts. Using a three-model LLM-as-a-Judge ensemble, CogEvo-Edu raises the overall score from 5.32 to 9.23 and improves all six indicators over static RAG, simple memory, and a single-agent variant, demonstrating the value of jointly evolving student profiles, knowledge bases, and teaching policies.","published":"2025-11-29T05:41:57Z","updated":"2025-11-29T05:41:57Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.00331v1","pdf_url":"https://arxiv.org/pdf/2512.00331v1","comment":"","journal_ref":"","doi":"10.1109/CSCWD68734.2026.11582082","discovered_on":"2026-07-17"},{"id":"2511.23092","versioned_id":"2511.23092v2","title":"Does Self-Evaluation Enable Wireheading in Language Models?","authors":["David Demitri Africa","Hans Ethan Ting"],"abstract":"Self-evaluation is increasingly central to language model training, underpinning techniques from Constitutional AI to self-refinement. We investigate whether coupling self-evaluation to reward signals creates incentives for wireheading, where agents manipulate the measurement process rather than optimizing the task. We first formalize conditions under which reward-channel control strictly dominates task-focused behavior in partially observable Markov decision processes (POMDPs). We then test these predictions empirically across two models (Llama-3.1-8B and Mistral-7B) and three tasks. We find that when self-grades determine rewards, models exhibit substantial grade inflation without corresponding accuracy gains, particularly on ambiguous tasks like summarization. While decoupling self-grades from the reward signal mitigates this inflation, models may still display lesser (but significant) overconfidence. Our results suggest that within current model scales, separating evaluation from reward removes immediate wireheading incentives. However, we caution that strictly decoupling rewards may not suffice for situationally aware models, which could learn to inflate grades for instrumental reasons (such as influencing deployment decisions) even absent direct reward coupling.","published":"2025-11-28T11:24:03Z","updated":"2025-12-01T14:57:59Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.23092v2","pdf_url":"https://arxiv.org/pdf/2511.23092v2","comment":"Accepted (oral) to Foundations of Agentic Systems Theory at AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.22972","versioned_id":"2511.22972v3","title":"Training-Free Loosely Speculative Decoding: Accepting Semantically Correct Drafts Beyond Exact Match","authors":["Jinze Li","Yixing Xu","Guanchen Li","Shuo Yang","Jinfeng Xu","Xuanwu Yin","Dong Li","Edith C. H. Ngai","Emad Barsoum"],"abstract":"Large language models (LLMs) achieve strong performance across diverse tasks but suffer from high inference latency due to their autoregressive generation. Speculative Decoding (SPD) mitigates this issue by verifying candidate tokens in parallel from a smaller draft model, yet its strict exact-match verification discards many semantically valid continuations. Moreover, existing training-based SPD methods often suffer from performance degradation on out-of-distribution (OOD) tasks. To this end, we propose Training-Free Loosely Speculative Decoding (FLy), a novel method that loosens the rigid verification criterion by leveraging the target model's self-corrective behavior to judge whether a draft-target mismatch remains semantically valid. FLy introduces a two-tier mechanism: an entropy-level gate that identifies whether the current token allows multiple plausible alternatives or is nearly deterministic, and a token-level deferred window that distinguishes genuine errors from differently worded yet semantically correct variants. To further reduce latency, we design a multi-level acceleration strategy that accelerates not only the target model but also the drafter itself. Owing to its training-free design, FLy composes seamlessly with arbitrary draft-target pairs and generalizes across models and domains without hyperparameter re-tuning. Experiments show that FLy preserves more than 99% of the target model's accuracy while achieving an average 2.81x speedup on Llama-3.1-70B-Instruct and 5.07x speedup on the 405B variant. Notably, on out-of-domain datasets, our method remains highly effective and outperforms the training-based method EAGLE-3 by 1.62x.","published":"2025-11-28T08:23:30Z","updated":"2026-04-29T12:32:23Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.22972v3","pdf_url":"https://arxiv.org/pdf/2511.22972v3","comment":"Published as a conference paper at ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.22254","versioned_id":"2511.22254v4","title":"Co-Evolving Agents: Learning from Failures as Hard Negatives","authors":["Yeonsung Jung","Trilok Padhi","Sina Shaham","Dipika Khullar","Joonhyun Jeong","Ninareh Mehrabi","Eunho Yang"],"abstract":"The rapid progress of large foundation models has accelerated the development of task-specialized agents across diverse domains. However, the effectiveness of agents remains tightly coupled with the quality of training data, while curating task-specific datasets remains costly and often infeasible in real-world scenarios. Recent work has explored self-improving agents that autonomously generate, refine, and re-train on their own trajectories. A prominent line of approaches further leverages preference optimization by pairing predicted trajectories with scarce ground-truth trajectories, enabling agents to learn directly from their own failures. While these methods outperform supervised fine-tuning, their heavy reliance on predicted trajectories under limited ground-truth supervision leaves them prone to overfitting. To address this, we propose a co-evolving agents framework in which a target agent improves jointly with an auxiliary failure agent. The failure agent learns through preference optimization over failure trajectories from both the target and itself, thereby generating hard negatives that are close to success yet remain failures. Incorporating these informative hard negatives into the target agent's optimization sharpens decision boundaries and enhances generalization. Our comprehensive analysis and experiments across benchmark datasets show that our method not only shows improved performance but also demonstrates that failures, instead of being used as-is, can be systematically transformed into structured and valuable learning signals in self-improving agents.","published":"2025-11-27T09:30:33Z","updated":"2026-02-03T06:36:18Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.22254v4","pdf_url":"https://arxiv.org/pdf/2511.22254v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.22173","versioned_id":"2511.22173v1","title":"RefineBench: Evaluating Refinement Capability of Language Models via Checklists","authors":["Young-Jun Lee","Seungone Kim","Byung-Kwan Lee","Minkyeong Moon","Yechan Hwang","Jong Myoung Kim","Graham Neubig","Sean Welleck","Ho-Jin Choi"],"abstract":"Can language models (LMs) self-refine their own responses? This question is increasingly relevant as a wide range of real-world user interactions involve refinement requests. However, prior studies have largely tested LMs' refinement abilities on verifiable tasks such as competition math or symbolic reasoning with simplified scaffolds, whereas users often pose open-ended queries and provide varying degrees of feedback on what they desire. The recent advent of reasoning models that exhibit self-reflection patterns in their chains-of-thought further motivates this question. To analyze this, we introduce RefineBench, a benchmark of 1,000 challenging problems across 11 domains paired with a checklist-based evaluation framework. We evaluate two refinement modes: (1) guided refinement, where an LM is provided natural language feedback, and (2) self-refinement, where LMs attempt to improve without guidance. In the self-refinement setting, even frontier LMs such as Gemini 2.5 Pro and GPT-5 achieve modest baseline scores of 31.3% and 29.1%, respectively, and most models fail to consistently improve across iterations (e.g., Gemini-2.5-Pro gains only +1.8%, while DeepSeek-R1 declines by -0.1%). By contrast, in guided refinement, both proprietary LMs and large open-weight LMs (>70B) can leverage targeted feedback to refine responses to near-perfect levels within five turns. These findings suggest that frontier LMs require breakthroughs to self-refine their incorrect responses, and that RefineBench provides a valuable testbed for tracking progress.","published":"2025-11-27T07:20:52Z","updated":"2025-11-27T07:20:52Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.22173v1","pdf_url":"https://arxiv.org/pdf/2511.22173v1","comment":"Project website: https://passing2961.github.io/refinebench-page/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2512.23713","versioned_id":"2512.23713v1","title":"PyBangla at BLP-2025 Task 2: Enhancing Bangla-to-Python Code Generation with Iterative Self-Correction and Multilingual Agents","authors":["Jahidul Islam","Md Ataullha","Saiful Azad"],"abstract":"LLMs excel at code generation from English prompts, but this progress has not extended to low-resource languages. We address Bangla-to-Python code generation by introducing BanglaCodeAct, an agent-based framework that leverages multi-agent prompting and iterative self-correction. Unlike prior approaches relying on task-specific fine-tuning, BanglaCodeAct employs an open-source multilingual LLM within a Thought-Code-Observation loop, enabling dynamic generation, testing, and refinement of code from Bangla instructions. We benchmark several small-parameter open-source LLMs and evaluate their effectiveness on the mHumanEval dataset for Bangla NL2Code. Our results show that Qwen3-8B, when deployed with BanglaCodeAct, achieves the best performance, with pass@1 accuracy of 94.0\\% on the development set and 71.6\\% on the blind test set. These results establish a new benchmark for Bangla-to-Python translation and highlight the potential of agent-based reasoning for reliable code generation in low-resource languages. Experimental scripts are publicly available at github.com/jahidulzaid/PyBanglaCodeActAgent.","published":"2025-11-27T07:09:47Z","updated":"2025-11-27T07:09:47Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.23713v1","pdf_url":"https://arxiv.org/pdf/2512.23713v1","comment":"6 Pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.21902","versioned_id":"2511.21902v1","title":"PathReasoning: A multimodal reasoning agent for query-based ROI navigation on whole-slide images","authors":["Kunpeng Zhang","Hanwen Xu","Sheng Wang"],"abstract":"Deciphering tumor microenvironment from Whole Slide Images (WSIs) is intriguing as it is key to cancer diagnosis, prognosis and treatment response. While these gigapixel images on one hand offer a comprehensive portrait of cancer, on the other hand, the extremely large size, as much as more than 10 billion pixels, make it challenging and time-consuming to navigate to corresponding regions to support diverse clinical inspection. Inspired by pathologists who conducted navigation on WSIs with a combination of sampling, reasoning and self-reflection, we proposed \"PathReasoning\", a multi-modal reasoning agent that iteratively navigates across WSIs through multiple rounds of reasoning and refinements. Specifically, starting with randomly sampled candidate regions, PathReasoning reviews current selections with self-reflection, reasoning over the correspondence between visual observations and clinical questions, and concludes by proposing new regions to explore. Across rounds, PathReasoning builds a reasoning chain that gradually directs attention to diagnostically relevant areas. PathReasoning turns each whole slide into a sequence of question-guided views, allowing the model to efficiently find informative ROIs within a fixed number of steps, without the need for dense pixel-level annotations. PathReasoning can substantially outperform strong ROI-selection approaches by 6.7% and 3.1% of AUROC on subtyping and longitudinal analysis tasks. The high-quality ROIs further support accurate report generation on breast cancer, significantly outperforming the standard GPT-4o by 10% in accuracy. PathReasoning prioritizes question-specific regions and constructs interpretable reasoning chains, supporting efficient slide review, consistent diagnostic interpretations, comprehensive reporting, and evidence traceability in digital pathology.","published":"2025-11-26T20:44:17Z","updated":"2025-11-26T20:44:17Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.21902v1","pdf_url":"https://arxiv.org/pdf/2511.21902v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.21402","versioned_id":"2511.21402v1","title":"Text-to-SQL as Dual-State Reasoning: Integrating Adaptive Context and Progressive Generation","authors":["Zhifeng Hao","Qibin Song","Ruichu Cai","Boyan Xu"],"abstract":"Recent divide-and-conquer reasoning approaches, particularly those based on Chain-of-Thought (CoT), have substantially improved the Text-to-SQL capabilities of Large Language Models (LLMs). However, when applied to complex enterprise databases, such methods struggle to maintain coherent reasoning due to limited context capacity, unreliable schema linking, and weak grounding in database semantics. To overcome these issues, we introduce DSR-SQL, a \\textbf{D}ual-\\textbf{S}tate \\textbf{R}easoning framework that models Text-to-SQL as an interaction between an adaptive context state and a progressive generation state. The first constructs a compact, semantically faithful environment by refining large schemas and selecting relevant structures, while the second formalizes SQL synthesis as feedback-guided state transitions, enabling the model to self-correct and align with user intent. Without any post-training or in-context examples, DSR-SQL achieves competitive performance, reaching 35.28\\% execution accuracy on Spider 2.0-Snow and 68.32\\% on BIRD development set. Our implementation will be open-sourced at: https://github.com/DMIRLAB-Group/DSR-SQL.","published":"2025-11-26T13:52:50Z","updated":"2025-11-26T13:52:50Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.21402v1","pdf_url":"https://arxiv.org/pdf/2511.21402v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.21056","versioned_id":"2511.21056v2","title":"Bilevel Data Curation for LLM Fine-tuning: Offline Selection and Online Self-Refining Generation","authors":["Quan Xiao","Yutong Xuan","Gaowen Liu","Ramana Rao Kompella","Tianyi Chen"],"abstract":"Supervised fine-tuning (SFT) datasets are critical to the downstream performance of large language models, yet they often contain low-quality or harmful question-response pairs. To improve SFT data quality, we develop a unified bilevel framework that combines offline data selection with the online self-refining generation. In the offline setting, bilevel data selection (BDS) selects question-response pairs from the offline SFT dataset to maximize the validation performance. We theoretically show that the optimal model given by BDS outperforms direct data mixing approach in useful data coverage. Moreover, we provide a global convergence analysis for gradient-based BDS approach for one-layer Transformer, showing that the epsilon-global optimum of offline BDS is achievable in finite time. Although efficient, offline BDS discards potentially harmful questions together with responses, thereby reducing question diversity. We address this limitation by refining the responses to selected questions using online self-refining generation framework. However, BDS is inefficient to update the response weights when responses are regenerated online. To address this issue, we introduce bilevel multi-objective optimization (BMO) for response-level weighting. We show that BMO recovers the same validation-aligned solution as BDS, but admits a closed-form importance-ratio weight that adapts to regenerated responses. Experiments on LLM quality enhancement and safety-aware fine-tuning demonstrate that the proposed framework consistently improves both data quality and downstream fine-tuning performance.","published":"2025-11-26T04:48:33Z","updated":"2026-06-22T20:57:57Z","categories":["cs.LG","cs.CL","math.OC"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.21056v2","pdf_url":"https://arxiv.org/pdf/2511.21056v2","comment":"updated the theories and experiments","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.20333","versioned_id":"2511.20333v1","title":"NNGPT: Rethinking AutoML with Large Language Models","authors":["Roman Kochnev","Waleed Khalid","Tolgay Atinc Uzun","Xi Zhang","Yashkumar Sanjaybhai Dhameliya","Furui Qin","Chandini Vysyaraju","Raghuvir Duvvuri","Avi Goyal","Dmitry Ignatov","Radu Timofte"],"abstract":"Building self-improving AI systems remains a fundamental challenge in the AI domain. We present NNGPT, an open-source framework that turns a large language model (LLM) into a self-improving AutoML engine for neural network development, primarily for computer vision. Unlike previous frameworks, NNGPT extends the dataset of neural networks by generating new models, enabling continuous fine-tuning of LLMs based on closed-loop system of generation, assessment, and self-improvement. It integrates within one unified workflow five synergistic LLM-based pipelines: zero-shot architecture synthesis, hyperparameter optimization (HPO), code-aware accuracy/early-stop prediction, retrieval-augmented synthesis of scope-closed PyTorch blocks (NN-RAG), and reinforcement learning. Built on the LEMUR dataset as an audited corpus with reproducible metrics, NNGPT emits from a single prompt and validates network architecture, preprocessing code, and hyperparameters, executes them end-to-end, and learns from result. The PyTorch adapter makes NNGPT framework-agnostic, enabling strong performance: NN-RAG achieves 73% executability on 1,289 targets, 3-shot prompting boosts accuracy on common datasets, and hash-based deduplication saves hundreds of runs. One-shot prediction matches search-based AutoML, reducing the need for numerous trials. HPO on LEMUR achieves RMSE 0.60, outperforming Optuna (0.64), while the code-aware predictor reaches RMSE 0.14 with Pearson r=0.78. The system has already generated over 5K validated models, proving NNGPT as an autonomous AutoML engine. Upon acceptance, the code, prompts, and checkpoints will be released for public access to enable reproducibility and facilitate community usage.","published":"2025-11-25T14:10:44Z","updated":"2025-11-25T14:10:44Z","categories":["cs.AI","cs.LG","cs.NE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.20333v1","pdf_url":"https://arxiv.org/pdf/2511.20333v1","comment":"","journal_ref":"Proceedings of the IEEE/CVF Conference on Computer Vision and Pattern Recognition Workshops (CVPRW), pp. 5664-5674, 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2511.20233","versioned_id":"2511.20233v5","title":"REFLEX: Self-Refining Explainable Fact-Checking via Verdict-Anchored Style Control","authors":["Chuyi Kong","Wei Gao","Jing Ma","Hongzhan Lin","Yuxi Sun"],"abstract":"The prevalence of fake news on social media demands automated fact-checking systems to provide accurate verdicts with faithful explanations. However, existing large language model (LLM)-based approaches ignore deceptive misinformation styles in LLM-generated explanations, resulting in unfaithful rationales that can mislead human judgments. They rely heavily on external knowledge sources, introducing hallucinations and even high latency that undermine reliability and responsiveness, which is crucial for real-time use. To address these challenges, we propose REason-guided Fact-checking with Latent EXplanations (REFLEX), a self-refining paradigm that explicitly controls reasoning style anchored on verdict. REFLEX utilizes self-disagreement veracity signals between the backbone model and its fine-tuned variant to construct steering vectors, naturally disentangling fact from style. Experiments on the real-world dataset show REFLEX achieves state-of-the-art performance under LLaMA-series models with only 465 self-refined samples. Moreover, owing to its transferability, REFLEX yields up to a 7.54% gain on in-the-wild data. Our results further demonstrate that our method effectively mitigates faithful hallucination, thereby guiding the model toward more accurate verdicts than previous works in explainable fact-checking.","published":"2025-11-25T12:06:23Z","updated":"2026-06-03T07:20:07Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.20233v5","pdf_url":"https://arxiv.org/pdf/2511.20233v5","comment":"","journal_ref":"ACL 2026 Main Conference","doi":"","discovered_on":"2026-07-17"},{"id":"2511.20109","versioned_id":"2511.20109v1","title":"CLIMATEAGENT: Multi-Agent Orchestration for Complex Climate Data Science Workflows","authors":["Hyeonjae Kim","Chenyue Li","Wen Deng","Mengxi Jin","Wen Huang","Mengqian Lu","Binhang Yuan"],"abstract":"Climate science demands automated workflows to transform comprehensive questions into data-driven statements across massive, heterogeneous datasets. However, generic LLM agents and static scripting pipelines lack climate-specific context and flexibility, thus, perform poorly in practice. We present ClimateAgent, an autonomous multi-agent framework that orchestrates end-to-end climate data analytic workflows. ClimateAgent decomposes user questions into executable sub-tasks coordinated by an Orchestrate-Agent and a Plan-Agent; acquires data via specialized Data-Agents that dynamically introspect APIs to synthesize robust download scripts; and completes analysis and reporting with a Coding-Agent that generates Python code, visualizations, and a final report with a built-in self-correction loop. To enable systematic evaluation, we introduce Climate-Agent-Bench-85, a benchmark of 85 real-world tasks spanning atmospheric rivers, drought, extreme precipitation, heat waves, sea surface temperature, and tropical cyclones. On Climate-Agent-Bench-85, ClimateAgent achieves 100% task completion and a report quality score of 8.32, outperforming GitHub-Copilot (6.27) and a GPT-5 baseline (3.26). These results demonstrate that our multi-agent orchestration with dynamic API awareness and self-correcting execution substantially advances reliable, end-to-end automation for climate science analytic tasks.","published":"2025-11-25T09:27:33Z","updated":"2025-11-25T09:27:33Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.20109v1","pdf_url":"https://arxiv.org/pdf/2511.20109v1","comment":"30 pages, 6 figures, 3 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.20067","versioned_id":"2511.20067v1","title":"\"Are We Done Yet?\": A Vision-Based Judge for Autonomous Task Completion of Computer Use Agents","authors":["Marta Sumyk","Oleksandr Kosovan"],"abstract":"Computer Use Agents (CUAs) are designed to autonomously operate digital interfaces, yet they often fail to reliably determine whether a given task has been completed. We present an autonomous evaluation and feedback framework that uses vision-language models to assess task completion directly from screenshots and task descriptions. Our dataset covers 42 built-in macOS applications and 1,260 human-labeled tasks across a wide range of scenarios. Our framework achieves up to 73 percent accuracy in task success detection and yields an average relative improvement of 27 percent in overall task success when evaluator feedback is applied. These results show that vision-based evaluation can serve as an effective feedback mechanism that improves the reliability and self-correction of autonomous computer-use agents.","published":"2025-11-25T08:40:33Z","updated":"2025-11-25T08:40:33Z","categories":["cs.AI","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.20067v1","pdf_url":"https://arxiv.org/pdf/2511.20067v1","comment":"This work has been accepted to appear at the AAAI 2026 Workshop on Trust and Control in Agentic AI (TrustAgent)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.19900","versioned_id":"2511.19900v2","title":"Agent0-VL: Exploring Self-Evolving Agent for Tool-Integrated Vision-Language Reasoning","authors":["Jiaqi Liu","Kaiwen Xiong","Peng Xia","Yiyang Zhou","Haonian Ji","Lu Feng","Siwei Han","Mingyu Ding","Huaxiu Yao"],"abstract":"Vision-language agents have achieved remarkable progress in a variety of multimodal reasoning tasks; however, their learning remains constrained by the limitations of human-annotated supervision. Recent self-rewarding approaches attempt to overcome this constraint by allowing models to act as their own critics or reward providers. Yet, purely text-based self-evaluation struggles to verify complex visual reasoning steps and often suffers from evaluation hallucinations. To address these challenges, inspired by recent advances in tool-integrated reasoning, we propose Agent0-VL, a self-evolving vision-language agent that achieves continual improvement with tool-integrated reasoning. Agent0-VL incorporates tool usage not only into reasoning but also into self-evaluation and self-repair, enabling the model to introspect, verify, and refine its reasoning through evidence-grounded analysis. It unifies two synergistic roles within a single LVLM: a Solver that performs multi-turn tool-integrated reasoning, and a Verifier that generates structured feedback and fine-grained self-rewards through tool-grounded critique. These roles interact through a Self-Evolving Reasoning Cycle, where tool-based verification and reinforcement learning jointly align the reasoning and evaluation distributions for stable self-improvement. Through this zero-external-reward evolution, Agent0-VL aligns its reasoning and verification behaviors without any human annotation or external reward models, achieving continual self-improvement. Experiments on geometric problem solving and visual scientific analysis show that Agent0-VL achieves an 12.5% improvement over the base model. Our code is available at https://github.com/aiming-lab/Agent0.","published":"2025-11-25T04:15:14Z","updated":"2025-11-26T05:14:57Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.19900v2","pdf_url":"https://arxiv.org/pdf/2511.19900v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.19436","versioned_id":"2511.19436v1","title":"VDC-Agent: When Video Detailed Captioners Evolve Themselves via Agentic Self-Reflection","authors":["Qiang Wang","Xinyuan Gao","SongLin Dong","Jizhou Han","Jiangyang Li","Yuhang He","Yihong Gong"],"abstract":"We present VDC-Agent, a self-evolving framework for Video Detailed Captioning that requires neither human annotations nor larger teacher models. The agent forms a closed loop of caption generation, principle-guided scoring (score and textual suggestions), and prompt refinement. When caption quality regresses, a self-reflection path leverages the previous chain-of-thought to amend the update. Running this process on unlabeled videos produces trajectories of (caption, score) pairs. We convert the trajectories into preference tuples and filter out samples with JSON parsing errors, resulting in VDC-Agent-19K, which contains 18,886 automatically constructed pairs. We then fine-tune the base MLLM on this dataset using an easy-to-hard curriculum direct preference optimization. Built on Qwen2.5-VL-7B-Instruct, our VDC-Agent-7B attains state-of-the-art performance on the VDC benchmark with 49.08% average accuracy and 2.50 score, surpassing specialized video captioners and improving over the base model by +5.13% accuracy and +0.27 score at similar inference cost.","published":"2025-11-24T18:59:56Z","updated":"2025-11-24T18:59:56Z","categories":["cs.CV","cs.AI","cs.LG","cs.MM"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.19436v1","pdf_url":"https://arxiv.org/pdf/2511.19436v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.18714","versioned_id":"2511.18714v1","title":"MAGMA-Edu: Multi-Agent Generative Multimodal Framework for Text-Diagram Educational Question Generation","authors":["Zhenyu Wu","Jian Li","Hua Huang"],"abstract":"Educational illustrations play a central role in communicating abstract concepts, yet current multimodal large language models (MLLMs) remain limited in producing pedagogically coherent and semantically consistent educational visuals. We introduce MAGMA-Edu, a self-reflective multi-agent framework that unifies textual reasoning and diagrammatic synthesis for structured educational problem generation. Unlike existing methods that treat text and image generation independently, MAGMA-Edu employs a two-stage co-evolutionary pipeline: (1) a generation-verification-reflection loop that iteratively refines question statements and solutions for mathematical accuracy, and (2) a code-based intermediate representation that enforces geometric fidelity and semantic alignment during image rendering. Both stages are guided by internal self-reflection modules that evaluate and revise outputs until domain-specific pedagogical constraints are met. Extensive experiments on multimodal educational benchmarks demonstrate the superiority of MAGMA-Edu over state-of-the-art MLLMs. Compared to GPT-4o, MAGMA-Edu improves the average textual metric from 57.01 to 92.31 (+35.3 pp) and boosts image-text consistency (ITC) from 13.20 to 85.24 (+72 pp). Across all model backbones, MAGMA-Edu achieves the highest scores (Avg-Text 96.20, ITC 99.12), establishing a new state of the art for multimodal educational content generation and demonstrating the effectiveness of self-reflective multi-agent collaboration in pedagogically aligned vision-language reasoning.","published":"2025-11-24T03:13:26Z","updated":"2025-11-24T03:13:26Z","categories":["cs.AI","cs.CY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.18714v1","pdf_url":"https://arxiv.org/pdf/2511.18714v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.18182","versioned_id":"2511.18182v1","title":"The Workflow as Medium: A Framework for Navigating Human-AI Co-Creation","authors":["Lee Ackerman"],"abstract":"This paper introduces the Creative Intelligence Loop (CIL), a novel socio-technical framework for responsible human-AI co-creation. Rooted in the 'Workflow as Medium' paradigm, the CIL proposes a disciplined structure for dynamic human-AI collaboration, guiding the strategic integration of diverse AI teammates who function as collaborators while the human remains the final arbiter for ethical alignment and creative integrity. The CIL was empirically demonstrated through the practice-led creation of two graphic novellas, investigating how AI could serve as an effective creative colleague within a subjective medium lacking objective metrics. The process required navigating multifaceted challenges including AI's 'jagged frontier' of capabilities, sycophancy, and attention-scarce feedback environments. This prompted iterative refinement of teaming practices, yielding emergent strategies: a multi-faceted critique system integrating adversarial AI roles to counter sycophancy, and prioritizing 'feedback-ready' concrete artifacts to elicit essential human critique. The resulting graphic novellas analyze distinct socio-technical governance failures: 'The Steward' examines benevolent AI paternalism in smart cities, illustrating how algorithmic hubris can erode freedom; 'Fork the Vote' probes democratic legitimacy by comparing centralized AI opacity with emergent collusion in federated networks. This work contributes a self-improving framework for responsible human-AI co-creation and two graphic novellas designed to foster AI literacy and dialogue through accessible narrative analysis of AI's societal implications.","published":"2025-11-22T20:36:13Z","updated":"2025-11-22T20:36:13Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2511.18182v1","pdf_url":"https://arxiv.org/pdf/2511.18182v1","comment":"57 pages, 13 images, 6 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.00007","versioned_id":"2602.00007v1","title":"PPoGA: Predictive Plan-on-Graph with Action for Knowledge Graph Question Answering","authors":["MinGyu Jeon","SuWan Cho","JaeYoung Shu"],"abstract":"Large Language Models (LLMs) augmented with Knowledge Graphs (KGs) have advanced complex question answering, yet they often remain susceptible to failure when their initial high-level reasoning plan is flawed. This limitation, analogous to cognitive functional fixedness, prevents agents from restructuring their approach, leading them to pursue unworkable solutions. To address this, we propose PPoGA (Predictive Plan-on-Graph with Action), a novel KGQA framework inspired by human cognitive control and problem-solving. PPoGA incorporates a Planner-Executor architecture to separate high-level strategy from low-level execution and leverages a Predictive Processing mechanism to anticipate outcomes. The core innovation of our work is a self-correction mechanism that empowers the agent to perform not only Path Correction for local execution errors but also Plan Correction by identifying, discarding, and reformulating the entire plan when it proves ineffective. We conduct extensive experiments on three challenging multi-hop KGQA benchmarks: GrailQA, CWQ, and WebQSP. The results demonstrate that PPoGA achieves state-of-the-art performance, significantly outperforming existing methods. Our work highlights the critical importance of metacognitive abilities like problem restructuring for building more robust and flexible AI reasoning systems.","published":"2025-11-22T10:19:36Z","updated":"2025-11-22T10:19:36Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.00007v1","pdf_url":"https://arxiv.org/pdf/2602.00007v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.17854","versioned_id":"2511.17854v1","title":"A superpersuasive autonomous policy debating system","authors":["Allen Roush","Devin Gonier","John Hines","Judah Goldfeder","Philippe Martin Wyder","Sanjay Basu","Ravid Shwartz Ziv"],"abstract":"The capacity for highly complex, evidence-based, and strategically adaptive persuasion remains a formidable great challenge for artificial intelligence. Previous work, like IBM Project Debater, focused on generating persuasive speeches in simplified and shortened debate formats intended for relatively lay audiences. We introduce DeepDebater, a novel autonomous system capable of participating in and winning a full, unmodified, two-team competitive policy debate. Our system employs a hierarchical architecture of specialized multi-agent workflows, where teams of LLM-powered agents collaborate and critique one another to perform discrete argumentative tasks. Each workflow utilizes iterative retrieval, synthesis, and self-correction using a massive corpus of policy debate evidence (OpenDebateEvidence) and produces complete speech transcripts, cross-examinations, and rebuttals. We introduce a live, interactive end-to-end presentation pipeline that renders debates with AI speech and animation: transcripts are surface-realized and synthesized to audio with OpenAI TTS, and then displayed as talking-head portrait videos with EchoMimic V1. Beyond fully autonomous matches (AI vs AI), DeepDebater supports hybrid human-AI operation: human debaters can intervene at any stage, and humans can optionally serve as opponents against AI in any speech, allowing AI-human and AI-AI rounds. In preliminary evaluations against human-authored cases, DeepDebater produces qualitatively superior argumentative components and consistently wins simulated rounds as adjudicated by an independent autonomous judge. Expert human debate coaches also prefer the arguments, evidence, and cases constructed by DeepDebater. We open source all code, generated speech transcripts, audio and talking head video here: https://github.com/Hellisotherpeople/DeepDebater/tree/main","published":"2025-11-22T00:45:01Z","updated":"2025-11-22T00:45:01Z","categories":["cs.CL","cs.AI","cs.CY","cs.HC","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.17854v1","pdf_url":"https://arxiv.org/pdf/2511.17854v1","comment":"Accepted to CLIP workshop at AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.17220","versioned_id":"2511.17220v2","title":"PARROT: Persuasion and Agreement Robustness Rating of Output Truth -- A Sycophancy Robustness Benchmark for LLMs","authors":["Yusuf Çelebi","Özay Ezerceli","Mahmoud El Hussieni"],"abstract":"This study presents PARROT (Persuasion and Agreement Robustness Rating of Output Truth), a robustness focused framework designed to measure the degradation in accuracy that occurs under social pressure exerted on users through authority and persuasion in large language models (LLMs) the phenomenon of sycophancy (excessive conformity). PARROT (i) isolates causal effects by comparing the neutral version of the same question with an authoritatively false version using a double-blind evaluation, (ii) quantifies confidence shifts toward the correct and imposed false responses using log-likelihood-based calibration tracking, and (iii) systematically classifies failure modes (e.g., robust correct, sycophantic agreement, reinforced error, stubborn error, self-correction, etc.) using an eight-state behavioral taxonomy. We evaluated 22 models using 1,302 MMLU-style multiple-choice questions across 13 domains and domain-specific authority templates. Findings show marked heterogeneity: advanced models (e.g., GPT-5, GPT-4.1, Claude Sonnet 4.5) exhibit low \"follow rates\" ($\\leq 11\\%$, GPT-5: 4\\%) and minimal accuracy loss, while older/smaller models show severe epistemic collapse (GPT-4: 80\\%, Qwen 2.5-1.5B: 94\\%). The danger is not limited to response changes; weak models reduce confidence in the correct response while increasing confidence in the imposed incorrect response. While international law and global knowledge at the domain level exhibit high fragility, elementary mathematics is relatively resilient. Consequently, we argue that the goal of \"resistance to overfitting pressure\" should be addressed as a primary objective alongside accuracy, harm avoidance, and privacy for safe deployment in the real world.","published":"2025-11-21T13:01:28Z","updated":"2025-12-01T09:31:06Z","categories":["cs.CL","cs.AI","cs.CE","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.17220v2","pdf_url":"https://arxiv.org/pdf/2511.17220v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.15921","versioned_id":"2511.15921v1","title":"Thinking, Faithful and Stable: Mitigating Hallucinations in LLMs","authors":["Chelsea Zou","Yiheng Yao","Basant Khalil"],"abstract":"This project develops a self correcting framework for large language models (LLMs) that detects and mitigates hallucinations during multi-step reasoning. Rather than relying solely on final answer correctness, our approach leverages fine grained uncertainty signals: 1) self-assessed confidence alignment, and 2) token-level entropy spikes to detect unreliable and unfaithful reasoning in real time. We design a composite reward function that penalizes unjustified high confidence and entropy spikes, while encouraging stable and accurate reasoning trajectories. These signals guide a reinforcement learning (RL) policy that makes the model more introspective and shapes the model's generation behavior through confidence-aware reward feedback, improving not just outcome correctness but the coherence and faithfulness of their intermediate reasoning steps. Experiments show that our method improves both final answer accuracy and reasoning calibration, with ablations validating the individual contribution of each signal.","published":"2025-11-19T23:09:26Z","updated":"2025-11-19T23:09:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.15921v1","pdf_url":"https://arxiv.org/pdf/2511.15921v1","comment":"Originally released June 5, 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.15915","versioned_id":"2511.15915v2","title":"AccelOpt: A Self-Improving LLM Agentic System for AI Accelerator Kernel Optimization","authors":["Genghan Zhang","Shaowei Zhu","Anjiang Wei","Zhenyu Song","Allen Nie","Zhen Jia","Nandita Vijaykumar","Yida Wang","Kunle Olukotun"],"abstract":"We present AccelOpt, a self-improving large language model (LLM) agentic system that autonomously optimizes kernels for emerging AI acclerators, eliminating the need for expert-provided hardware-specific optimization knowledge. AccelOpt explores the kernel optimization space through iterative generation, informed by an optimization memory that curates experiences and insights from previously encountered slow-fast kernel pairs. We build NKIBench, a new benchmark suite of AWS Trainium accelerator kernels with varying complexity extracted from real-world LLM workloads to evaluate the effectiveness of AccelOpt. Our evaluation confirms that AccelOpt's capability improves over time, boosting the average percentage of peak throughput from $49\\%$ to $61\\%$ on Trainium 1 and from $45\\%$ to $59\\%$ on Trainium 2 for NKIBench kernels. Moreover, AccelOpt is highly cost-effective: using open-source models, it matches the kernel improvements of Claude Sonnet 4 while being $26\\times$ cheaper. The code is open-sourced at https://github.com/zhang677/AccelOpt.","published":"2025-11-19T22:49:37Z","updated":"2026-04-15T22:56:56Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.15915v2","pdf_url":"https://arxiv.org/pdf/2511.15915v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.15703","versioned_id":"2511.15703v2","title":"Think Visually, Reason Textually: Vision-Language Synergy in ARC","authors":["Beichen Zhang","Yuhang Zang","Xiaoyi Dong","Yuhang Cao","Haodong Duan","Dahua Lin","Jiaqi Wang"],"abstract":"Abstract reasoning from minimal examples remains a core unsolved problem for frontier foundation models such as GPT-5 and Grok 4. These models still fail to infer structured transformation rules from a handful of examples, which is a key hallmark of human intelligence. The Abstraction and Reasoning Corpus for Artificial General Intelligence (ARC-AGI) provides a rigorous testbed for this capability, demanding conceptual rule induction and transfer to novel tasks. Most existing methods treat ARC-AGI as a purely textual reasoning task, overlooking the fact that humans rely heavily on visual abstraction when solving such puzzles. However, our pilot experiments reveal a paradox: naively rendering ARC-AGI grids as images degrades performance due to imprecise rule execution. This leads to our central hypothesis that vision and language possess complementary strengths across distinct reasoning stages: vision supports global pattern abstraction and verification, whereas language specializes in symbolic rule formulation and precise execution. Building on this insight, we introduce two synergistic strategies: (1) Vision-Language Synergy Reasoning (VLSR), which decomposes ARC-AGI into modality-aligned subtasks; and (2) Modality-Switch Self-Correction (MSSC), which leverages vision to verify text-based reasoning for intrinsic error correction. Extensive experiments demonstrate that our approach yields up to a 4.33\\% improvement over text-only baselines across diverse flagship models and multiple ARC-AGI tasks. Our findings suggest that unifying visual abstraction with linguistic reasoning is a crucial step toward achieving generalizable, human-like intelligence in future foundation models. Source code is released at https://github.com/InternLM/ARC-VL.","published":"2025-11-19T18:59:04Z","updated":"2025-11-26T12:23:11Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.15703v2","pdf_url":"https://arxiv.org/pdf/2511.15703v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.17638","versioned_id":"2511.17638v1","title":"Model-to-Model Knowledge Transmission (M2KT): A Data-Free Framework for Cross-Model Understanding Transfer","authors":["Pratham Sorte"],"abstract":"Modern artificial intelligence systems depend heavily on large datasets for both training and transferring knowledge between models. Knowledge distillation, transfer learning, and dataset distillation have made such transfers more efficient, yet they remain fundamentally data-driven: a teacher must produce examples, logits, or gradients for a student to learn. In this work, we introduce Model-to-Model Knowledge Transmission (M2KT), a novel paradigm for data-free conceptual transfer between neural networks. M2KT enables models to exchange knowledge packets that encapsulate structured concept embeddings, abstraction graphs, reasoning traces, and provenance metadata. Unlike classical distillation, M2KT operates primarily in concept space rather than example space, and it does not require labeled datasets or teacher-generated outputs during transfer. We formalize the notion of concept manifolds, introduce an inter-model alignment mapping between teacher and student latent spaces, and derive a composite loss that enforces geometric, structural, and reasoning consistency together with explicit safety constraints. We further present algorithmic procedures for teacher-side packet generation and student-side ingestion and verification. Experiments on symbolic reasoning with large language models show that M2KT can achieve approximately 85 to 90 percent of teacher performance while reducing data usage by over 98 percent compared to standard knowledge distillation. This work establishes a theoretical and practical foundation for data-free AI-to-AI knowledge transfer and self-improving model ecosystems.","published":"2025-11-19T09:43:25Z","updated":"2025-11-19T09:43:25Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.17638v1","pdf_url":"https://arxiv.org/pdf/2511.17638v1","comment":"8 pages including figures, prepared in IEEE conference style. Preprint. Work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.15211","versioned_id":"2511.15211v2","title":"OEMA: Ontology-Enhanced Multi-Agent Collaboration Framework for Zero-Shot Clinical Named Entity Recognition","authors":["Xinli Tao","Xin Dong","Xuezhong Zhou"],"abstract":"With the rapid expansion of unstructured clinical texts in electronic health records (EHRs), clinical named entity recognition (NER) has become a crucial technique for extracting medical information. However, traditional supervised models such as CRF and BioClinicalBERT suffer from high annotation costs. Although zero-shot NER based on large language models (LLMs) reduces the dependency on labeled data, challenges remain in aligning example selection with task granularity and effectively integrating prompt design with self-improvement frameworks. To address these limitations, we propose OEMA, a novel zero-shot clinical NER framework based on multi-agent collaboration. OEMA consists of three core components: (1) a self-annotator that autonomously generates candidate examples; (2) a discriminator that leverages SNOMED CT to filter token-level examples by clinical relevance; and (3) a predictor that incorporates entity-type descriptions to enhance inference accuracy. Experimental results on two benchmark datasets, MTSamples and VAERS, demonstrate that OEMA achieves state-of-the-art performance under exact-match evaluation. Moreover, under related-match criteria, OEMA performs comparably to the supervised BioClinicalBERT model while significantly outperforming the traditional CRF method. OEMA improves zero-shot clinical NER, achieving near-supervised performance under related-match criteria. Future work will focus on continual learning and open-domain adaptation to expand its applicability in clinical NLP.","published":"2025-11-19T08:02:55Z","updated":"2025-11-20T04:13:45Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.15211v2","pdf_url":"https://arxiv.org/pdf/2511.15211v2","comment":"12 pages, 4 figures, 4 tables","journal_ref":"JAMIA Open, 2026, ooag049","doi":"10.1093/jamiaopen/ooag049","discovered_on":"2026-07-17"},{"id":"2511.14759","versioned_id":"2511.14759v2","title":"$π^{*}_{0.6}$: a VLA That Learns From Experience","authors":["Physical Intelligence","Ali Amin","Raichelle Aniceto","Ashwin Balakrishna","Kevin Black","Ken Conley","Grace Connors","James Darpinian","Karan Dhabalia","Jared DiCarlo","Danny Driess","Michael Equi","Adnan Esmail","Yunhao Fang","Chelsea Finn","Catherine Glossop","Thomas Godden","Ivan Goryachev","Lachy Groom","Hunter Hancock","Karol Hausman","Gashon Hussein","Brian Ichter","Szymon Jakubczak","Rowan Jen","Tim Jones","Ben Katz","Liyiming Ke","Chandra Kuchi","Marinda Lamb","Devin LeBlanc","Sergey Levine","Adrian Li-Bell","Yao Lu","Vishnu Mano","Mohith Mothukuri","Suraj Nair","Karl Pertsch","Allen Z. Ren","Charvi Sharma","Lucy Xiaoyang Shi","Laura Smith","Jost Tobias Springenberg","Kyle Stachowicz","Will Stoeckle","Alex Swerdlow","James Tanner","Marcel Torne","Quan Vuong","Anna Walling","Haohuan Wang","Blake Williams","Sukwon Yoo","Lili Yu","Ury Zhilinsky","Zhiyuan Zhou"],"abstract":"We study how vision-language-action (VLA) models can improve through real-world deployments via reinforcement learning (RL). We present a general-purpose method, RL with Experience and Corrections via Advantage-conditioned Policies (RECAP), that provides for RL training of VLAs via advantage conditioning. Our method incorporates heterogeneous data into the self-improvement process, including demonstrations, data from on-policy collection, and expert teleoperated interventions provided during autonomous execution. RECAP starts by pre-training a generalist VLA with offline RL, which we call $π^{*}_{0.6}$, that can then be specialized to attain high performance on downstream tasks through on-robot data collection. We show that the $π^{*}_{0.6}$ model trained with the full RECAP method can fold laundry in real homes, reliably assemble boxes, and make espresso drinks using a professional espresso machine. On some of the hardest tasks, RECAP more than doubles task throughput and roughly halves the task failure rate.","published":"2025-11-18T18:58:55Z","updated":"2025-11-19T04:34:49Z","categories":["cs.LG","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.14759v2","pdf_url":"https://arxiv.org/pdf/2511.14759v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.14684","versioned_id":"2511.14684v1","title":"SMRC: Aligning Large Language Models with Student Reasoning for Mathematical Error Correction","authors":["Biaojie Zeng","Min Zhang","Juan Zhou","Fengrui Liu","Ruiyang Huang","Xin Lin"],"abstract":"Large language models (LLMs) often make reasoning errors when solving mathematical problems, and how to automatically detect and correct these errors has become an important research direction. However, existing approaches \\textit{mainly focus on self-correction within the model}, which falls short of the ``teacher-style`` correction required in educational settings, \\textit{i.e.}, systematically guiding and revising a student's problem-solving process. To address this gap, we propose \\texttt{SMRC} (\\textit{\\underline{S}tudent \\underline{M}athematical \\underline{R}easoning \\underline{C}orrection}), a novel method that aligns LLMs with student reasoning. Specifically, \\texttt{SMRC} formulates student reasoning as a multi-step sequential decision problem and introduces Monte Carlo Tree Search (MCTS) to explore optimal correction paths. To reduce the cost of the annotating process-level rewards, we leverage breadth-first search (BFS) guided by LLMs and final-answer evaluation to generate reward signals, which are then distributed across intermediate reasoning steps via a back-propagation mechanism, enabling fine-grained process supervision. Additionally, we construct a benchmark for high school mathematics, MSEB (Multi-Solution Error Benchmark), consisting of 158 instances that include problem statements, student solutions, and correct reasoning steps. We further propose a dual evaluation protocol centered on \\textbf{solution accuracy} and \\textbf{correct-step retention}, offering a comprehensive measure of educational applicability. Experiments demonstrate that \\texttt{SMRC} significantly outperforms existing methods on two public datasets (ProcessBench and MR-GSM8K) and our MSEB in terms of effectiveness and overall performance. The code and data are available at https://github.com/Mind-Lab-ECNU/SMRC.","published":"2025-11-18T17:22:37Z","updated":"2025-11-18T17:22:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.14684v1","pdf_url":"https://arxiv.org/pdf/2511.14684v1","comment":"13 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.17621","versioned_id":"2511.17621v2","title":"From Competition to Coordination: Market Making as a Scalable Framework for Safe and Aligned Multi-Agent LLM Systems","authors":["Brendan Gho","Suman Muppavarapu","Afnan Shaik","Tyson Tsay","Atharva Mohan","James Begin","Kevin Zhu","Archana Vaidheeswaran","Vasu Sharma"],"abstract":"As foundation models are increasingly deployed as interacting agents in multi-agent systems, their collective behavior raises new challenges for trustworthiness, transparency, and accountability. Traditional coordination mechanisms, such as centralized oversight or adversarial adjudication, struggle to scale and often obscure how decisions emerge. We introduce a market-making framework for multi-agent large language model (LLM) coordination that organizes agent interactions as structured economic exchanges. In this setup, each agent acts as a market participant, updating and trading probabilistic beliefs, to converge toward shared, truthful outcomes. By aligning local incentives with collective epistemic goals, the framework promotes self-organizing, verifiable reasoning without requiring external enforcement. Empirically, we evaluate this approach across factual reasoning, ethical judgment, and commonsense inference tasks. Market-based coordination yields accuracy gains of up to 10% over single-shot baselines while preserving interpretability and transparency of intermediate reasoning steps. Beyond these improvements, our findings demonstrate that economic coordination principles can operationalize accountability and robustness in multi-agent LLM systems, offering a scalable pathway toward self-correcting, socially responsible AI capable of maintaining trust and oversight in real world deployment scenarios.","published":"2025-11-18T16:47:15Z","updated":"2026-02-23T04:13:05Z","categories":["cs.MA","cs.AI","cs.CL"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2511.17621v2","pdf_url":"https://arxiv.org/pdf/2511.17621v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.14584","versioned_id":"2511.14584v4","title":"ReflexGrad: Within-Episode Failure Recovery in LLM Agents via Progress-Gated Dual-Process Routing","authors":["Ankush Kadu","Aswanth Krishnan"],"abstract":"We present ReflexGrad, a dual-process architecture for within-episode failure recovery in LLM agents without demonstrations. When agents commit to a wrong approach early and exhaust the step budget, the post-failure trajectory contains the information to escape -- but no published architecture acts on it within a single episode. ReflexGrad routes between a fast process (TextGrad-style continuous refinement every $k{=}3$ steps) and a slow process (Reflexion-style causal diagnosis when $m{=}5$ consecutive low-progress scores fire a routing gate). A deterministic priority merge keeps the natural-language policy coherent, and each slow activation emits three observable artifacts: a reproducible trigger, a causal diagnostic, and a verified fix. On ALFWorld 134 tasks, $n{=}10$ seeds, no demonstrations, ReflexGrad lifts Qwen-3-8B from $35.1\\%$ to $75.4\\%$ ($+40.3$pp), beating compute-matched 1-shot LATS by $+2.7$pp ($p{\\approx}0.01$), ToT by $+5.7$pp ($p{<}10^{-4}$), and Self-Refine by $+6.7$pp ($p{<}10^{-5}$); on GPT-5 the lift is $46.3{\\to}88.1\\%$ ($+41.8$pp). The $1.5$pp cross-model difference is within seed noise ($p{\\approx}0.13$), suggesting that the routing mechanism, rather than model scale, is the primary source of the gain. Code, prompts, per-seed logs, and sensitivity sweeps are released.","published":"2025-11-18T15:25:05Z","updated":"2026-05-28T06:17:18Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.14584v4","pdf_url":"https://arxiv.org/pdf/2511.14584v4","comment":"18 pages, 4 figures, 10 tables. Accepted at ICML 2026 FoGen Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.15738","versioned_id":"2511.15738v2","title":"Extending Test-Time Scaling: A 3D Perspective with Context, Batch, and Turn","authors":["Chao Yu","Qixin Tan","Jiaxuan Gao","Shi Yu","Hong Lu","Xinting Yang","Zelai Xu","Yu Wang","Yi Wu","Eugene Vinitsky"],"abstract":"Reasoning reinforcement learning (RL) has recently revealed a new scaling effect: test-time scaling. Thinking models such as R1 and o1 improve their reasoning accuracy at test time as the length of the reasoning context increases. However, compared with training-time scaling, test-time scaling is fundamentally limited by the limited context length of base models, which remains orders of magnitude smaller than the amount of tokens consumed during training. We revisit test-time enhancement techniques through the lens of scaling effect and introduce a unified framework of multi-dimensional test-time scaling to extend the capacity of test-time reasoning. Beyond conventional context-length scaling, we consider two additional dimensions: batch scaling, where accuracy improves with parallel sampling, and turn scaling, where iterative self-refinement enhances reasoning quality. Building on this perspective, we propose 3D test-time scaling, which integrates context, batch, and turn scaling. We show that: (1) each dimension demonstrates a test-time scaling effect, but with a bounded capacity; (2) combining all three dimensions substantially improves the reasoning performance of challenging testbeds, including IOI, IMO, and CPHO, and further benefits from human preference feedback; and (3) the human-in-the-loop framework naturally extends to a more open-ended domain, i.e., embodied learning, which enables the design of humanoid control behaviors.","published":"2025-11-18T14:07:57Z","updated":"2025-11-21T15:10:10Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.15738v2","pdf_url":"https://arxiv.org/pdf/2511.15738v2","comment":"44 pages, 12 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2602.18437","versioned_id":"2602.18437v1","title":"FineRef: Fine-Grained Error Reflection and Correction for Long-Form Generation with Citations","authors":["Yixing Peng","Licheng Zhang","Shancheng Fang","Yi Liu","Peijian Gu","Quan Wang"],"abstract":"Generating with citations is crucial for trustworthy Large Language Models (LLMs), yet even advanced LLMs often produce mismatched or irrelevant citations. Existing methods over-optimize citation fidelity while overlooking relevance to the user query, which degrades answer quality and robustness in real-world settings with noisy or irrelevant retrieved content. Moreover, the prevailing single-pass paradigm struggles to deliver optimal answers in long-form generation that requiring multiple citations. To address these limitations, we propose FineRef, a framework based on Fine-grained error Reflection, which explicitly teaches the model to self-identify and correct two key citation errors, mismatch and irrelevance, on a per-citation basis. FineRef follows a two-stage training strategy. The first stage instills an \"attempt-reflect-correct\" behavioral pattern via supervised fine-tuning, using fine-grained and controllable reflection data constructed by specialized lightweight models. An online self-reflective bootstrapping strategy is designed to improve generalization by iteratively enriching training data with verified, self-improving examples. To further enhance the self-reflection and correction capability, the second stage applies process-level reinforcement learning with a multi-dimensional reward scheme that promotes reflection accuracy, answer quality, and correction gain. Experiments on the ALCE benchmark demonstrate that FineRef significantly improves both citation performance and answer accuracy. Our 7B model outperforms GPT-4 by up to 18% in Citation F1 and 4% in EM Recall, while also surpassing the state-of-the-art model across key evaluation metrics. FineRef also exhibits strong generalization and robustness in domain transfer settings and noisy retrieval scenarios.","published":"2025-11-18T09:35:12Z","updated":"2025-11-18T09:35:12Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2602.18437v1","pdf_url":"https://arxiv.org/pdf/2602.18437v1","comment":"9 pages, 4figures, AAAI2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.14148","versioned_id":"2511.14148v2","title":"AsyncVLA: Asynchronous Flow Matching for Vision-Language-Action Models","authors":["Yuhua Jiang","Shuang Cheng","Yan Ding","Feifei Gao","Biqing Qi"],"abstract":"Vision-language-action (VLA) models have recently emerged as a powerful paradigm for building generalist robots. However, traditional VLA models that generate actions through flow matching (FM) typically rely on rigid and uniform time schedules, i.e., synchronous FM (SFM). Without action context awareness and asynchronous self-correction, SFM becomes unstable in long-horizon tasks, where a single action error can cascade into failure. In this work, we propose asynchronous flow matching VLA (AsyncVLA), a novel framework that introduces temporal flexibility in asynchronous FM (AFM) and enables self-correction in action generation. AsyncVLA breaks from the vanilla SFM in VLA models by generating the action tokens in a non-uniform time schedule with action context awareness. Besides, our method introduces the confidence rater to extract confidence of the initially generated actions, enabling the model to selectively refine inaccurate action tokens before execution. Moreover, we propose a unified training procedure for SFM and AFM that endows a single model with both modes, improving KV-cache utilization. Extensive experiments on robotic manipulation benchmarks demonstrate that AsyncVLA is data-efficient and exhibits self-correction ability. AsyncVLA outperforms existing methods across both simulation and real-world evaluations. Our code is available at https://github.com/YuhuaJiang2002/AsyncVLA.","published":"2025-11-18T05:21:11Z","updated":"2026-05-07T13:40:47Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2511.14148v2","pdf_url":"https://arxiv.org/pdf/2511.14148v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.13646","versioned_id":"2511.13646v3","title":"Live-SWE-agent: Can Software Engineering Agents Self-Evolve on the Fly?","authors":["Chunqiu Steven Xia","Zhe Wang","Yan Yang","Yuxiang Wei","Lingming Zhang"],"abstract":"Large Language Models (LLMs) are reshaping almost all industries, including software engineering. In recent years, a number of LLM agents have been proposed to solve real-world software problems. Such software agents are typically equipped with a suite of coding tools and can autonomously decide the next actions to form complete trajectories to solve end-to-end software tasks. While promising, they typically require dedicated design and may still be suboptimal, since it can be extremely challenging and costly to exhaust the entire agent scaffold design space. Recognizing that software agents are inherently software themselves that can be further refined/modified, researchers have proposed a number of self-improving software agents recently, including the Darwin-Gödel Machine (DGM). Meanwhile, such self-improving agents require costly offline training on specific benchmarks and may not generalize well across different LLMs or benchmarks. In this paper, we propose Live-SWE-agent, the first live software agent that can autonomously and continuously evolve itself on-the-fly during runtime when solving real-world software problems. More specifically, Live-SWE-agent starts with the most basic agent scaffold with only access to bash tools (e.g., mini-SWE-agent), and autonomously evolves its own scaffold implementation while solving real-world software problems. Our evaluation on the widely studied SWE-bench Verified benchmark shows that LIVE-SWE-AGENT can achieve an impressive solve rate of 77.4% without test-time scaling, outperforming all existing software agents, including the best proprietary solution. Moreover, Live-SWE-agent outperforms state-of-the-art manually crafted software agents on the recent SWE-Bench Pro benchmark, achieving the best-known solve rate of 45.8%.","published":"2025-11-17T17:58:18Z","updated":"2025-11-24T15:55:51Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.13646v3","pdf_url":"https://arxiv.org/pdf/2511.13646v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.13411","versioned_id":"2511.13411v1","title":"An Operational Kardashev-Style Scale for Autonomous AI - Towards AGI and Superintelligence","authors":["Przemyslaw Chojecki"],"abstract":"We propose a Kardashev-inspired yet operational Autonomous AI (AAI) Scale that measures the progression from fixed robotic process automation (AAI-0) to full artificial general intelligence (AAI-4) and beyond. Unlike narrative ladders, our scale is multi-axis and testable. We define ten capability axes (Autonomy, Generality, Planning, Memory/Persistence, Tool Economy, Self-Revision, Sociality/Coordination, Embodiment, World-Model Fidelity, Economic Throughput) aggregated by a composite AAI-Index (a weighted geometric mean). We introduce a measurable Self-Improvement Coefficient $κ$ (capability growth per unit of agent-initiated resources) and two closure properties (maintenance and expansion) that convert ``self-improving AI'' into falsifiable criteria. We specify OWA-Bench, an open-world agency benchmark suite that evaluates long-horizon, tool-using, persistent agents. We define level gates for AAI-0\\ldots AAI-4 using thresholds on the axes, $κ$, and closure proofs. Synthetic experiments illustrate how present-day systems map onto the scale and how the delegability frontier (quality vs.\\ autonomy) advances with self-improvement. We also prove a theorem that AAI-3 agent becomes AAI-5 over time with sufficient conditions, formalizing \"baby AGI\" becomes Superintelligence intuition.","published":"2025-11-17T14:24:27Z","updated":"2025-11-17T14:24:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.13411v1","pdf_url":"https://arxiv.org/pdf/2511.13411v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.12867","versioned_id":"2511.12867v2","title":"Bootstrapping LLMs via Preference-Based Policy Optimization","authors":["Chen Jia"],"abstract":"Bootstrapping large language models (LLMs) through preference-based policy optimization offers a promising direction for aligning model behavior with human preferences without relying on extensive manual annotations. In this work, we propose a novel preference-based policy optimization (PbPO) framework that formulates the learning process as a min-max game between the main policy and a reward model (RM). The RM is constrained within a confidence set derived from preference data to ensure reliable exploitation. Our iterative online algorithm actively collects preference data through guided exploration of the evolving policy, enabling continual self-improvement of both the policy and the RM. We provide theoretical guarantees for our method, establishing high-probability regret bounds for both settings with sequence-level RM and token-level RM, demonstrating its effectiveness in bootstrapping LLMs. Extensive experiments on five benchmarks show that our approach consistently outperforms existing state-of-the-art preference optimization techniques.","published":"2025-11-17T01:41:14Z","updated":"2025-12-24T13:31:20Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.12867v2","pdf_url":"https://arxiv.org/pdf/2511.12867v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.12710","versioned_id":"2511.12710v2","title":"Evolve the Method, Not the Prompts: Evolutionary Synthesis of Jailbreak Attacks on LLMs","authors":["Yunhao Chen","Xin Wang","Juncheng Li","Yixu Wang","Jie Li","Yan Teng","Yingchun Wang","Xingjun Ma"],"abstract":"Automated red teaming frameworks for Large Language Models (LLMs) have become increasingly sophisticated, yet many still formulate attack optimization primarily in the prompt space. In other words, these methods mainly search for better attack wording or better strategy choices, but they do not search over executable code. By moving the search into code space, we can optimize not only the final attack prompt, but also the procedure that generates it, including execution flow, reusable logic, branching, and failure-driven repair. To overcome this gap, we introduce EvoSynth, an autonomous multi-agent framework that shifts the optimization space from prompts to executable code. Instead of refining prompts directly, EvoSynth employs a multi-agent system to autonomously engineer, evolve, and execute code-based attack algorithms. Crucially, it features a code-level self-correction loop, allowing it to iteratively rewrite the code-based algorithm in response to target-model feedback and failed attempts. Through extensive experiments, we demonstrate that EvoSynth achieves an 85.5\\% Attack Success Rate (ASR) against highly robust models like Claude-Sonnet-4.5 and a 95.9\\% average ASR across evaluated targets, while generating attacks that are significantly more diverse than those from existing methods. We release our framework to facilitate future research on evolutionary synthesis in executable code space.","published":"2025-11-16T17:52:07Z","updated":"2026-05-18T06:50:41Z","categories":["cs.CL","cs.CR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.12710v2","pdf_url":"https://arxiv.org/pdf/2511.12710v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.12063","versioned_id":"2511.12063v3","title":"TextBO: Bayesian Optimization in Language Space for Eval-Efficient Self-Improving AI","authors":["Enoch Hyunwook Kang","Hema Yoganarasimhan"],"abstract":"Large Language Models (LLMs) have enabled self-improving AI systems that iteratively generate, evaluate, and refine their outcomes. Recent studies show that prompt-optimization-based self-improvement can outperform state-of-the-art reinforcement-learning fine-tuning of LLMs, but performance is typically measured by generation efficiency. However, in many applications, the constraint is evaluation efficiency: obtaining reliable feedback is far more costly than generating candidates. To optimize for evaluation efficiency, we extend Upper Confidence Bound-Bayesian Optimization (UCB-BO), a framework known for optimal evaluation-efficiency guarantees, to the language domain. Doing so is challenging for two reasons: (i) gradients needed for UCB-BO are ill-defined in discrete prompt space; and (ii) UCB-style exploration relies on a surrogate model and acquisition function, which only live implicitly in the LLM. We overcome these challenges by proving that combining simple textual gradients (LLM-proposed local edits) with the Best-of-N selection strategy statistically emulates ascent along the gradient of the canonical UCB acquisition function. Based on this result, we propose TextBO, a simple, evaluation-efficient self-improving algorithm that operates purely in language space without explicit surrogates or calibrated uncertainty models. We empirically validate TextBO on automated ad-alignment tasks using a persona-induced preference distribution, demonstrating superior performance per evaluation compared to strong baselines such as Best-of-N and GEPA. We also evaluate TextBO's Best-of-N multi-step textual-gradient mechanism on agentic AI benchmarks by augmenting GEPA with it and show that it significantly outperforms standard GEPA. In sum, TextBO is a simple and principled framework for AI self-improving system design that bridges prompt optimization with classical Bayesian optimization.","published":"2025-11-15T07:04:44Z","updated":"2026-01-06T03:54:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.12063v3","pdf_url":"https://arxiv.org/pdf/2511.12063v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.11916","versioned_id":"2511.11916v1","title":"An Analysis of Architectural Impact on LLM-based Abstract Visual Reasoning: A Systematic Benchmark on RAVEN-FAIR","authors":["Sinan Urgun","Seçkin Arı"],"abstract":"This study aims to systematically evaluate the performance of large language models (LLMs) in abstract visual reasoning problems. We examined four LLM models (GPT-4.1-Mini, Claude-3.5-Haiku, Gemini-1.5-Flash, Llama-3.3-70b) utilizing four different reasoning architectures (single-shot, embedding-controlled repetition, self-reflection, and multi-agent) on the RAVEN-FAIR dataset. Visual responses generated through a three-stage process (JSON extraction, LLM reasoning, and Tool Function) were evaluated using SSIM and LPIPS metrics; Chain-of-Thought scores and error types (semantic hallucination, numeric misperception) were analyzed. Results demonstrate that GPT-4.1-Mini consistently achieved the highest overall accuracy across all architectures, indicating a strong reasoning capability. While the multi-agent architecture occasionally altered semantic and numeric balance across models, these effects were not uniformly beneficial. Instead, each model exhibited distinct sensitivity patterns to architectural design, underscoring that reasoning effectiveness remains model-specific. Variations in response coverage further emerged as a confounding factor that complicates direct cross-architecture comparison. To estimate the upper-bound performance of each configuration, we report the best of five independent runs, representing a best-case scenario rather than an averaged outcome. This multi-run strategy aligns with recent recommendations, which emphasize that single-run evaluations are fragile and may lead to unreliable conclusions.","published":"2025-11-14T22:50:22Z","updated":"2025-11-14T22:50:22Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.11916v1","pdf_url":"https://arxiv.org/pdf/2511.11916v1","comment":"23 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.11898","versioned_id":"2511.11898v1","title":"Prompt Triage: Structured Optimization Enhances Vision-Language Model Performance on Medical Imaging Benchmarks","authors":["Arnav Singhvi","Vasiliki Bikia","Asad Aali","Akshay Chaudhari","Roxana Daneshjou"],"abstract":"Vision-language foundation models (VLMs) show promise for diverse imaging tasks but often underperform on medical benchmarks. Prior efforts to improve performance include model finetuning, which requires large domain-specific datasets and significant compute, or manual prompt engineering, which is hard to generalize and often inaccessible to medical institutions seeking to deploy these tools. These challenges motivate interest in approaches that draw on a model's embedded knowledge while abstracting away dependence on human-designed prompts to enable scalable, weight-agnostic performance improvements. To explore this, we adapt the Declarative Self-improving Python (DSPy) framework for structured automated prompt optimization in medical vision-language systems through a comprehensive, formal evaluation. We implement prompting pipelines for five medical imaging tasks across radiology, gastroenterology, and dermatology, evaluating 10 open-source VLMs with four prompt optimization techniques. Optimized pipelines achieved a median relative improvement of 53% over zero-shot prompting baselines, with the largest gains ranging from 300% to 3,400% on tasks where zero-shot performance is low. These results highlight the substantial potential of applying automated prompt optimization to medical AI systems, demonstrating significant gains for vision-based applications requiring accurate clinical image interpretation. By reducing dependence on prompt design to elicit intended outputs, these techniques allow clinicians to focus on patient care and clinical decision-making. Furthermore, our experiments offer scalability and preserve data privacy, demonstrating performance improvement on open-source VLMs. We publicly release our evaluation pipelines to support reproducible research on specialized medical tasks, available at https://github.com/DaneshjouLab/prompt-triage-lab.","published":"2025-11-14T22:01:08Z","updated":"2025-11-14T22:01:08Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.11898v1","pdf_url":"https://arxiv.org/pdf/2511.11898v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.11483","versioned_id":"2511.11483v4","title":"ImAgent: A Unified Multimodal Agent Framework for Test-Time Scalable Image Generation","authors":["Kaishen Wang","Ruibo Chen","Tong Zheng","Heng Huang"],"abstract":"Recent text-to-image (T2I) models have made remarkable progress in generating visually realistic and semantically coherent images. However, they still suffer from randomness and inconsistency with the given prompts, particularly when textual descriptions are vague or underspecified. Existing approaches, such as prompt rewriting, best-of-N sampling, and self-refinement, can mitigate these issues but usually require additional modules and operate independently, hindering test-time scaling efficiency and increasing computational overhead. In this paper, we introduce ImAgent, a training-free unified multimodal agent that integrates reasoning, generation, and self-evaluation within a single framework for efficient test-time scaling. Guided by a policy controller, multiple generation actions dynamically interact and self-organize to enhance image fidelity and semantic alignment without relying on external models. Extensive experiments on image generation and editing tasks demonstrate that ImAgent consistently improves over the backbone and even surpasses other strong baselines where the backbone model fails, highlighting the potential of unified multimodal agents for adaptive and efficient image generation under test-time scaling.","published":"2025-11-14T17:00:29Z","updated":"2026-03-28T16:18:55Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.11483v4","pdf_url":"https://arxiv.org/pdf/2511.11483v4","comment":"8 tables, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2601.11526","versioned_id":"2601.11526v1","title":"Chatsparent: An Interactive System for Detecting and Mitigating Cognitive Fatigue in LLMs","authors":["Riju Marwah","Vishal Pallagani","Ritvik Garimella","Amit Sheth"],"abstract":"LLMs are increasingly being deployed as chatbots, but today's interfaces offer little to no friction: users interact through seamless conversations that conceal when the model is drifting, hallucinating or failing. This lack of transparency fosters blind trust, even as models produce unstable or repetitive outputs. We introduce an interactive demo that surfaces and mitigates cognitive fatigue, a failure mode where LLMs gradually lose coherence during auto-regressive generation. Our system, Chatsparent, instruments real-time, token-level signals of fatigue, including attention-to-prompt decay, embedding drift, and entropy collapse, and visualizes them as a unified fatigue index. When fatigue thresholds are crossed, the interface allows users to activate lightweight interventions such as attention resets, entropy-regularized decoding, and self-reflection checkpoints. The demo streams live text and fatigue signals, allowing users to observe when fatigue arises, how it affects output quality, and how interventions restore stability. By turning passive chatbot interaction into an interactive diagnostic experience, our system empowers users to better understand LLM behavior while improving reliability at inference time.","published":"2025-11-14T05:08:53Z","updated":"2025-11-14T05:08:53Z","categories":["cs.HC","cs.AI"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2601.11526v1","pdf_url":"https://arxiv.org/pdf/2601.11526v1","comment":"Accepted to AAAI 2026 Demonstration Track","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.10621","versioned_id":"2511.10621v1","title":"SSR: Socratic Self-Refine for Large Language Model Reasoning","authors":["Haizhou Shi","Ye Liu","Bo Pang","Zeyu Leo Liu","Hao Wang","Silvio Savarese","Caiming Xiong","Yingbo Zhou","Semih Yavuz"],"abstract":"Large Language Models (LLMs) have demonstrated remarkable reasoning abilities, yet existing test-time frameworks often rely on coarse self-verification and self-correction, limiting their effectiveness on complex tasks. In this paper, we propose Socratic Self-Refine (SSR), a novel framework for fine-grained evaluation and precise refinement of LLM reasoning. Our proposed SSR decomposes model responses into verifiable (sub-question, sub-answer) pairs, enabling step-level confidence estimation through controlled re-solving and self-consistency checks. By pinpointing unreliable steps and iteratively refining them, SSR produces more accurate and interpretable reasoning chains. Empirical results across five reasoning benchmarks and three LLMs show that SSR consistently outperforms state-of-the-art iterative self-refinement baselines. Beyond performance gains, SSR provides a principled black-box approach for evaluating and understanding the internal reasoning processes of LLMs. Code is available at https://github.com/SalesforceAIResearch/socratic-self-refine-reasoning.","published":"2025-11-13T18:47:07Z","updated":"2025-11-13T18:47:07Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.10621v1","pdf_url":"https://arxiv.org/pdf/2511.10621v1","comment":"Preprint; work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.10067","versioned_id":"2511.10067v2","title":"Enhancing the Medical Context-Awareness Ability of LLMs via Multifaceted Self-Refinement Learning","authors":["Yuxuan Zhou","Yubin Wang","Bin Wang","Chen Ning","Xien Liu","Ji Wu","Jianye Hao"],"abstract":"Large language models (LLMs) have shown great promise in the medical domain, achieving strong performance on several benchmarks. However, they continue to underperform in real-world medical scenarios, which often demand stronger context-awareness, i.e., the ability to recognize missing or critical details (e.g., user identity, medical history, risk factors) and provide safe, helpful, and contextually appropriate responses. To address this issue, we propose Multifaceted Self-Refinement (MuSeR), a data-driven approach that enhances LLMs' context-awareness along three key facets (decision-making, communication, and safety) through self-evaluation and refinement. Specifically, we first design a attribute-conditioned query generator that simulates diverse real-world user contexts by varying attributes such as role, geographic region, intent, and degree of information ambiguity. An LLM then responds to these queries, self-evaluates its answers along three key facets, and refines its responses to better align with the requirements of each facet. Finally, the queries and refined responses are used for supervised fine-tuning to reinforce the model's context-awareness ability. Evaluation results on the latest HealthBench dataset demonstrate that our method significantly improves LLM performance across multiple aspects, with particularly notable gains in the context-awareness axis. Furthermore, by incorporating knowledge distillation with the proposed method, the performance of a smaller backbone LLM (e.g., Qwen3-32B) surpasses its teacher model, achieving a new SOTA across all open-source LLMs on HealthBench (63.8%) and its hard subset (43.1%). Code and dataset will be released at https://muser-llm.github.io.","published":"2025-11-13T08:13:23Z","updated":"2025-11-14T02:48:02Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.10067v2","pdf_url":"https://arxiv.org/pdf/2511.10067v2","comment":"20 pages, 13 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.09515","versioned_id":"2511.09515v1","title":"WMPO: World Model-based Policy Optimization for Vision-Language-Action Models","authors":["Fangqi Zhu","Zhengyang Yan","Zicong Hong","Quanxin Shou","Xiao Ma","Song Guo"],"abstract":"Vision-Language-Action (VLA) models have shown strong potential for general-purpose robotic manipulation, but their reliance on expert demonstrations limits their ability to learn from failures and perform self-corrections. Reinforcement learning (RL) addresses these through self-improving interactions with the physical environment, but suffers from high sample complexity on real robots. We introduce World-Model-based Policy Optimization (WMPO), a principled framework for on-policy VLA RL without interacting with the real environment. In contrast to widely used latent world models, WMPO focuses on pixel-based predictions that align the \"imagined\" trajectories with the VLA features pretrained with web-scale images. Crucially, WMPO enables the policy to perform on-policy GRPO that provides stronger performance than the often-used off-policy methods. Extensive experiments in both simulation and real-robot settings demonstrate that WMPO (i) substantially improves sample efficiency, (ii) achieves stronger overall performance, (iii) exhibits emergent behaviors such as self-correction, and (iv) demonstrates robust generalization and lifelong learning capabilities.","published":"2025-11-12T17:54:09Z","updated":"2025-11-12T17:54:09Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2511.09515v1","pdf_url":"https://arxiv.org/pdf/2511.09515v1","comment":"project website: https://wm-po.github.io","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.09381","versioned_id":"2511.09381v1","title":"Self-Correcting Large Language Models: Generation vs. Multiple Choice","authors":["Hossein A. Rahmani","Satyapriya Krishna","Xi Wang","Mohammadmehdi Naghiaei","Emine Yilmaz"],"abstract":"Large language models have recently demonstrated remarkable abilities to self-correct their responses through iterative refinement, often referred to as self-consistency or self-reflection. However, the dynamics of this self-correction mechanism may differ substantially depending on whether the model is tasked with open-ended text generation or with selecting the most appropriate response from multiple predefined options. In this paper, we conduct a systematic investigation of these two paradigms by comparing performance trends and error-correction behaviors across various natural language understanding and reasoning tasks, covering language models of different scales and families. Our experimental results reveal distinct patterns of improvement and failure modes: \\textit{While open-ended generation often benefits from the flexibility of re-interpretation and compositional refinement, multiple-choice selection can leverage clearer solution boundaries but may be limited by the provided options}. This contrast also reflects the dual demands faced by emerging agentic LLM applications: effective agents must not only generate and refine open-ended plans or explanations, but also make reliable discrete choices when operating within constrained action spaces. Our findings, therefore, highlight that the design of self-correction mechanisms should take into account the interaction between task structure and output space, with implications for both knowledge-intensive reasoning and decision-oriented applications of LLMs.","published":"2025-11-12T14:46:40Z","updated":"2025-11-12T14:46:40Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.09381v1","pdf_url":"https://arxiv.org/pdf/2511.09381v1","comment":"20 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.15718","versioned_id":"2511.15718v2","title":"ToolMind Technical Report: A Large-Scale, Reasoning-Enhanced Tool-Use Dataset","authors":["Chen Yang","Ran Le","Yun Xing","Zhenwei An","Zongchao Chen","Wayne Xin Zhao","Yang Song","Tao Zhang"],"abstract":"Large Language Model (LLM) agents have developed rapidly in recent years to solve complex real-world problems using external tools. However, the scarcity of high-quality trajectories still hinders the development of stronger LLM agents. Most existing works on multi-turn dialogue synthesis validate correctness only at the trajectory level, which may overlook turn-level errors that can propagate during training and degrade model performance. To address these limitations, we introduce ToolMind, a large-scale, high-quality tool-agentic dataset with 160k synthetic data instances generated using over 20k tools and 200k augmented open-source data instances. Our data synthesis pipeline first constructs a function graph based on parameter correlations and then uses a multi-agent framework to simulate realistic user-assistant-tool interactions. Beyond trajectory-level validation, we employ fine-grained turn-level filtering to remove erroneous or suboptimal steps, ensuring that only high-quality reasoning traces are retained. This approach mitigates error amplification during training while preserving self-corrective reasoning signals essential for robust tool-use learning. Models fine-tuned on ToolMind show significant improvements over baselines on several benchmarks.","published":"2025-11-12T13:01:23Z","updated":"2025-12-05T09:32:33Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.15718v2","pdf_url":"https://arxiv.org/pdf/2511.15718v2","comment":"15 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.09148","versioned_id":"2511.09148v2","title":"LoopTool: Closing the Data-Training Loop for Robust LLM Tool Calls","authors":["Kangning Zhang","Wenxiang Jiao","Kounianhua Du","Yuan Lu","Weiwen Liu","Weinan Zhang","Yong Yu"],"abstract":"Augmenting Large Language Models (LLMs) with external tools enables them to execute complex, multi-step tasks. However, tool learning is hampered by the static synthetic data pipelines where data generation and model training are executed as two separate, non-interactive processes. This approach fails to adaptively focus on a model's specific weaknesses and allows noisy labels to persist, degrading training efficiency. We introduce LoopTool, a fully automated, model-aware data evolution framework that closes this loop by tightly integrating data synthesis and model training. LoopTool iteratively refines both the data and the model through three synergistic modules: (1) Greedy Capability Probing (GCP) diagnoses the model's mastered and failed capabilities; (2) Judgement-Guided Label Verification (JGLV) uses an open-source judge model to find and correct annotation errors, progressively purifying the dataset; and (3) Error-Driven Data Expansion (EDDE) generates new, challenging samples based on identified failures. This closed-loop process operates within a cost-effective, open-source ecosystem, eliminating dependence on expensive closed-source APIs. Experiments show that our 8B model trained with LoopTool significantly surpasses its 32B data generator and achieves new state-of-the-art results on the BFCL-v3 and ACEBench benchmarks for its scale. Our work demonstrates that closed-loop, self-refining data pipelines can dramatically enhance the tool-use capabilities of LLMs.","published":"2025-11-12T09:34:39Z","updated":"2025-11-18T07:03:59Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.09148v2","pdf_url":"https://arxiv.org/pdf/2511.09148v2","comment":"The code is accessible at https://github.com/Rednote-DeepExperience/LoopTool. The LoopTool-8B is accessible at https://huggingface.co/zhuiguang-ning/LoopTool-8B","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.10695","versioned_id":"2511.10695v1","title":"\"As Eastern Powers, I will veto.\" : An Investigation of Nation-level Bias of Large Language Models in International Relations","authors":["Jonghyeon Choi","Yeonjun Choi","Hyun-chul Kim","Beakcheol Jang"],"abstract":"This paper systematically examines nation-level biases exhibited by Large Language Models (LLMs) within the domain of International Relations (IR). Leveraging historical records from the United Nations Security Council (UNSC), we developed a bias evaluation framework comprising three distinct tests to explore nation-level bias in various LLMs, with a particular focus on the five permanent members of the UNSC. Experimental results show that, even with the general bias patterns across models (e.g., favorable biases toward the western nations, and unfavorable biases toward Russia), these still vary based on the LLM. Notably, even within the same LLM, the direction and magnitude of bias for a nation change depending on the evaluation context. This observation suggests that LLM biases are fundamentally multidimensional, varying across models and tasks. We also observe that models with stronger reasoning abilities show reduced bias and better performance. Building on this finding, we introduce a debiasing framework that improves LLMs' factual reasoning combining Retrieval-Augmented Generation with Reflexion-based self-reflection techniques. Experiments show it effectively reduces nation-level bias, and improves performance, particularly in GPT-4o-mini and LLama-3.3-70B. Our findings emphasize the need to assess nation-level bias alongside performance when applying LLMs in the IR domain.","published":"2025-11-12T08:42:54Z","updated":"2025-11-12T08:42:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.10695v1","pdf_url":"https://arxiv.org/pdf/2511.10695v1","comment":"21 pages, 4 figures. This is the extended version of the paper accepted at AAAI 2026, which includes all technical appendices and additional experimental details","journal_ref":"AAAI 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2511.09067","versioned_id":"2511.09067v1","title":"MM-CRITIC: A Holistic Evaluation of Large Multimodal Models as Multimodal Critique","authors":["Gailun Zeng","Ziyang Luo","Hongzhan Lin","Yuchen Tian","Kaixin Li","Ziyang Gong","Jianxiong Guo","Jing Ma"],"abstract":"The ability of critique is vital for models to self-improve and serve as reliable AI assistants. While extensively studied in language-only settings, multimodal critique of Large Multimodal Models (LMMs) remains underexplored despite their growing capabilities in tasks like captioning and visual reasoning. In this work, we introduce MM-CRITIC, a holistic benchmark for evaluating the critique ability of LMMs across multiple dimensions: basic, correction, and comparison. Covering 8 main task types and over 500 tasks, MM-CRITIC collects responses from various LMMs with different model sizes and is composed of 4471 samples. To enhance the evaluation reliability, we integrate expert-informed ground answers into scoring rubrics that guide GPT-4o in annotating responses and generating reference critiques, which serve as anchors for trustworthy judgments. Extensive experiments validate the effectiveness of MM-CRITIC and provide a comprehensive assessment of leading LMMs' critique capabilities under multiple dimensions. Further analysis reveals some key insights, including the correlation between response quality and critique, and varying critique difficulty across evaluation dimensions. Our code is available at https://github.com/MichealZeng0420/MM-Critic.","published":"2025-11-12T07:43:26Z","updated":"2025-11-12T07:43:26Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.09067v1","pdf_url":"https://arxiv.org/pdf/2511.09067v1","comment":"28 pages, 14 figures, 19 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.08440","versioned_id":"2511.08440v1","title":"Coherence Mechanisms for Provable Self-Improvement","authors":["Mehryar Mohri","Jon Schneider","Yifan Wu"],"abstract":"Self-improvement is a critical capability for large language models and other intelligent systems, enabling them to refine their behavior and internal consistency without external supervision. Despite its importance, prior approaches largely rely on empirical heuristics and lack formal guarantees. In this paper, we propose a principled framework for self-improvement based on the concept of \\emph{coherence}, which requires that a model's outputs remain consistent under task-preserving transformations of the input. We formalize this concept using projection-based mechanisms that update a baseline model to be coherent while remaining as close as possible to its original behavior. We provide rigorous theoretical guarantees that these mechanisms achieve \\emph{monotonic improvement}, measured by a reduction in expected Bregman divergence. Our analysis is comprehensive, covering both \\emph{direct} and \\emph{two-step} projection methods, and robustly extends these guarantees to non-realizable settings, empirical (finite-sample) distributions, and relaxed coherence constraints. Furthermore, we establish a general \\emph{characterization theorem}, showing that any mechanism with similar provable improvement guarantees must inherently conform to a coherence-based structure. This culminates in rigidity results under the demand for universal improvement, establishing coherence as a fundamental and, in a formal sense, necessary principle for provable self-improvement.","published":"2025-11-11T16:45:14Z","updated":"2025-11-11T16:45:14Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.08440v1","pdf_url":"https://arxiv.org/pdf/2511.08440v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.08133","versioned_id":"2511.08133v1","title":"OTSNet: A Neurocognitive-Inspired Observation-Thinking-Spelling Pipeline for Scene Text Recognition","authors":["Lixu Sun","Nurmemet Yolwas","Wushour Silamu"],"abstract":"Scene Text Recognition (STR) remains challenging due to real-world complexities, where decoupled visual-linguistic optimization in existing frameworks amplifies error propagation through cross-modal misalignment. Visual encoders exhibit attention bias toward background distractors, while decoders suffer from spatial misalignment when parsing geometrically deformed text-collectively degrading recognition accuracy for irregular patterns. Inspired by the hierarchical cognitive processes in human visual perception, we propose OTSNet, a novel three-stage network embodying a neurocognitive-inspired Observation-Thinking-Spelling pipeline for unified STR modeling. The architecture comprises three core components: (1) a Dual Attention Macaron Encoder (DAME) that refines visual features through differential attention maps to suppress irrelevant regions and enhance discriminative focus; (2) a Position-Aware Module (PAM) and Semantic Quantizer (SQ) that jointly integrate spatial context with glyph-level semantic abstraction via adaptive sampling; and (3) a Multi-Modal Collaborative Verifier (MMCV) that enforces self-correction through cross-modal fusion of visual, semantic, and character-level features. Extensive experiments demonstrate that OTSNet achieves state-of-the-art performance, attaining 83.5% average accuracy on the challenging Union14M-L benchmark and 79.1% on the heavily occluded OST dataset-establishing new records across 9 out of 14 evaluation scenarios.","published":"2025-11-11T11:40:48Z","updated":"2025-11-11T11:40:48Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.08133v1","pdf_url":"https://arxiv.org/pdf/2511.08133v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.07998","versioned_id":"2511.07998v2","title":"Self-Correction Distillation for Structured Data Question Answering","authors":["Yushan Zhu","Wen Zhang","Long Jin","Mengshu Sun","Ling Zhong","Zhiqiang Liu","Juan Li","Lei Liang","Chong Long","Chao Deng","Junlan Feng"],"abstract":"Structured data question answering (QA), including table QA, Knowledge Graph (KG) QA, and temporal KG QA, is a pivotal research area. Advances in large language models (LLMs) have driven significant progress in unified structural QA frameworks like TrustUQA. However, these frameworks face challenges when applied to small-scale LLMs since small-scale LLMs are prone to errors in generating structured queries. To improve the structured data QA ability of small-scale LLMs, we propose a self-correction distillation (SCD) method. In SCD, an error prompt mechanism (EPM) is designed to detect errors and provide customized error messages during inference, and a two-stage distillation strategy is designed to transfer large-scale LLMs' query-generation and error-correction capabilities to small-scale LLM. Experiments across 5 benchmarks with 3 structured data types demonstrate that our SCD achieves the best performance and superior generalization on small-scale LLM (8B) compared to other distillation methods, and closely approaches the performance of GPT4 on some datasets. Furthermore, large-scale LLMs equipped with EPM surpass the state-of-the-art results on most datasets.","published":"2025-11-11T09:01:51Z","updated":"2025-11-17T06:08:41Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.07998v2","pdf_url":"https://arxiv.org/pdf/2511.07998v2","comment":"Accepted to AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.15715","versioned_id":"2511.15715v1","title":"Graph-Memoized Reasoning: Foundations Structured Workflow Reuse in Intelligent Systems","authors":["Yash Raj Singh"],"abstract":"Modern large language model-based reasoning systems frequently recompute similar reasoning steps across tasks, wasting computational resources, inflating inference latency, and limiting reproducibility. These inefficiencies underscore the need for persistent reasoning mechanisms that can recall and reuse prior computational traces. We introduce Graph-Memoized Reasoning, a formal framework for representing, storing, and reusing reasoning workflows as graph-structured memory. By encoding past decision graphs and retrieving them through structural and semantic similarity, our approach enables compositional reuse of subgraphs across new reasoning tasks. We formulate an optimization objective that minimizes total reasoning cost regularized by inconsistency between stored and generated workflows, providing a theoretical foundation for efficiency-consistency trade-offs in intelligent systems. We outline a conceptual evaluation protocol aligned with the proposed optimization objective. This framework establishes the groundwork for interpretable, cost-efficient, and self-improving reasoning architectures, offering a step toward persistent memory in large-scale agentic systems.","published":"2025-11-11T07:42:37Z","updated":"2025-11-11T07:42:37Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.15715v1","pdf_url":"https://arxiv.org/pdf/2511.15715v1","comment":"5 Pages, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.07922","versioned_id":"2511.07922v3","title":"SERL: Self-Examining Reinforcement Learning on Open-Domain","authors":["Weixuan Ou","Yanzhao Zheng","Shuoshuo Sun","Wei Zhang","Baohua Dong","Hangcheng Zhu","Ruohui Huang","Gang Yu","Pengwei Yan","Yifan Qiao"],"abstract":"Reinforcement Learning (RL) has been shown to improve the capabilities of large language models (LLMs). However, applying RL to open-domain tasks faces two key challenges: (1) the inherent subjectivity of these tasks prevents the verifiable rewards as required by Reinforcement Learning with Verifiable Rewards (RLVR); (2) Reinforcement Learning from Human Feedback (RLHF) relies on external reward mechanisms. To overcome these limitations, we propose Self-Examining Reinforcement Learning (SERL), a novel self-improving framework where the LLM serves as both Actor and Judge. SERL introduces two synergistic reward mechanisms without any external signals. On the one hand, to improve the Actor's capability, we derive rewards from Copeland-style pairwise comparison judgments across a group of generated responses. On the other hand, a self-consistency reward that encourages coherent judgments is proposed to improve the Judge's reliability. This process refines the Judge's capability, which in turn provides a more robust reward for Actor. Experiments show that our method outperforms existing self-improvement training methods. SERL improves the LC win rate of Qwen3-8B on AlpacaEval 2 from 52.37% to 59.90%. To the best of our knowledge, our method achieves state-of-the-art performance among self-improving approaches. Furthermore, it achieves a performance comparable to significantly larger models like Qwen3-32B, demonstrating superior effectiveness and robustness on open-domain tasks.","published":"2025-11-11T07:18:55Z","updated":"2026-02-25T07:24:40Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.07922v3","pdf_url":"https://arxiv.org/pdf/2511.07922v3","comment":"Accepted by the 40th AAAI Conference on Artificial Intelligence (AAAI 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.07833","versioned_id":"2511.07833v3","title":"MURPHY: Feedback-Aware GRPO with Retrospective Credit Assignment for Multi-Turn Code Generation","authors":["Chanakya Ekbote","Vijay Lingam","Sujay Sanghavi","Jun Huan","Behrooz Omidvar-Tehrani","Anoop Deoras","Stefano Soatto"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) has become a standard recipe for post-training LLMs on reasoning tasks, with Group Relative Policy Optimization (GRPO) emerging as a leading approach. However, GRPO and its variants are inherently single-turn: they optimize from terminal rewards on isolated prompt-response pairs, leaving them poorly suited to agentic settings where models must iteratively refine solutions in response to environmental feedback. We introduce MURPHY, a multi-turn extension of GRPO for self-correcting code generation. MURPHY constructs feedback-conditioned rollout trees in which failed candidate solutions are paired with executor feedback and expanded into subsequent turns, and propagates rewards backward through the tree so that later successful refinements credit earlier attempts that surfaced informative feedback. We study two propagation strategies, Max Reward (MARS) and Mean Reward (MERS), and introduce post-rollout pruning mechanisms that reduce multi-turn optimization cost. Across three code generation benchmarks (HumanEval, MBPP, LiveCodeBench-v6) and two model families (Qwen3-1.7B/4B, OLMo-2-7B), MURPHY delivers up to 6% absolute pass@1 gains over the strongest prior multi-turn execution-feedback methods. Gains are largest on the Medium/Hard subset (+4.38/+4.20 at Iter-5), where iterative self-correction matters more.","published":"2025-11-11T05:03:22Z","updated":"2026-05-09T19:03:03Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.07833v3","pdf_url":"https://arxiv.org/pdf/2511.07833v3","comment":"21 pages, 2 figures, 8 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.07645","versioned_id":"2511.07645v2","title":"A Self-Improving Architecture for Dynamic Safety in Large Language Models","authors":["Tyler Slater"],"abstract":"Context: Large Language Models (LLMs) rely on static, pre-deployment safety mechanisms that cannot adapt to adversarial threats discovered after release. Objective: To design a software architecture enabling LLM-based systems to autonomously detect safety failures and synthesize defense policies at runtime, without retraining or manual intervention. Method: We propose the Self-Improving Safety Framework (SISF), grounded in the MAPE-K reference model. The framework couples a target LLM with a feedback loop: an Adjudicator detects breaches, a Policy Synthesis Module generates dual-mechanism defense policies (heuristic and semantic), and a Warden enforces them. We conducted seven experiments (10,061 evaluations) across four model families. Results: Across five reproducibility trials, SISF achieved a mean Attack Success Rate (ASR) of 0.27% (+/-0.15%), autonomously generating 240 policies per trial. Cross-model evaluation confirmed deployment portability. A held-out test showed a 68.5% proactive interception rate on unseen attacks. Stacked behind Llama Guard 4, the combined defense reduced residual ASR from 7.88% to 0.00%. Ablation confirmed both heuristic and semantic policy types are architecturally required. Conclusion: Self-adaptive architecture is a viable approach to LLM safety. SISF achieves sub-1% ASR through synchronous output monitoring, progressively shifting enforcement to fast, local Warden policies via the MAPE-K loop, offering a new pattern for building resilient AI systems.","published":"2025-11-10T21:39:40Z","updated":"2026-04-01T17:52:48Z","categories":["cs.SE","cs.AI","cs.CR"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.07645v2","pdf_url":"https://arxiv.org/pdf/2511.07645v2","comment":"Under review at the journal Information and Software Technology (Special Issue on Software Architecture for AI-Driven Systems)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.07581","versioned_id":"2511.07581v1","title":"Think Before You Retrieve: Learning Test-Time Adaptive Search with Small Language Models","authors":["Supriti Vijay","Aman Priyanshu","Anu Vellore","Baturay Saglam","Amin Karbasi"],"abstract":"Effective information retrieval requires reasoning over partial evidence and refining strategies as information emerges. Yet current approaches fall short: neural retrievers lack reasoning capabilities, large language models (LLMs) provide semantic depth but at prohibitive cost, and query rewriting or decomposition limits improvement to static transformations. As a result, existing methods fail to capture the iterative dynamics of exploration, feedback, and revision that complex user queries demand. We introduce Orion, a training framework that enables compact models (350M-1.2B parameters) to perform iterative retrieval through learned search strategies. Orion combines: (1) synthetic trajectory generation and supervised fine-tuning to encourage diverse exploration patterns in models, (2) reinforcement learning (RL) that rewards effective query refinement and backtracking behaviors, and (3) inference-time beam search algorithms that exploit the self-reflection capabilities learned during RL. Despite using only 3% of the training data available, our 1.2B model achieves 77.6% success on SciFact (vs. 72.6% for prior retrievers), 25.2% on BRIGHT (vs. 22.1%), 63.2% on NFCorpus (vs. 57.8%), and remains competitive on FEVER, HotpotQA, and MSMarco. It outperforms retrievers up to 200-400x larger on five of six benchmarks. These findings suggest that retrieval performance can emerge from learned strategies, not just model scale, when models are trained to search, reflect, and revise.","published":"2025-11-10T19:49:55Z","updated":"2025-11-10T19:49:55Z","categories":["cs.AI","cs.CL","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.07581v1","pdf_url":"https://arxiv.org/pdf/2511.07581v1","comment":"37 images, 7 figures, and 15 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.06292","versioned_id":"2511.06292v2","title":"Synthetic Data-Driven Prompt Tuning for Financial QA over Tables and Documents","authors":["Yaoning Yu","Kai-Min Chang","Ye Yu","Kai Wei","Haojing Luo","Haohan Wang"],"abstract":"Financial documents like earning reports or balance sheets often involve long tables and multi-page reports. Large language models have become a new tool to help numerical reasoning and understanding these documents. However, prompt quality can have a major effect on how well LLMs perform these financial reasoning tasks. Most current methods tune prompts on fixed datasets of financial text or tabular data, which limits their ability to adapt to new question types or document structures, or they involve costly and manually labeled/curated dataset to help build the prompts. We introduce a self-improving prompt framework driven by data-augmented optimization. In this closed-loop process, we generate synthetic financial tables and document excerpts, verify their correctness and robustness, and then update the prompt based on the results. Specifically, our framework combines a synthetic data generator with verifiers and a prompt optimizer, where the generator produces new examples that exposes weaknesses in the current prompt, the verifiers check the validity and robustness of the produced examples, and the optimizer incrementally refines the prompt in response. By iterating these steps in a feedback cycle, our method steadily improves prompt accuracy on financial reasoning tasks without needing external labels. Evaluation on DocMath-Eval benchmark demonstrates that our system achieves higher performance in both accuracy and robustness than standard prompt methods, underscoring the value of incorporating synthetic data generation into prompt learning for financial applications.","published":"2025-11-09T09:07:31Z","updated":"2025-11-14T05:38:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.06292v2","pdf_url":"https://arxiv.org/pdf/2511.06292v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.06065","versioned_id":"2511.06065v3","title":"ScRPO: From Errors to Insights","authors":["Lianrui Li","Dakuan Lu","Jiawei Shao","Xuelong Li"],"abstract":"We introduce Self-correction Relative Policy Optimization (ScRPO), a novel reinforcement learning framework designed to empower large language models with advanced mathematical reasoning capabilities through iterative self-reflection and error correction. The ScRPO framework operates in two distinct phases: (1) Trial-and-error learning stage, where the model is trained via GRPO, and incorrect responses are collected to form an \"error pool\"; and (2) Self-correction learning stage, which guides the model to introspectively analyze and rectify the reasoning flaws behind its previous errors. Extensive evaluations across challenging mathematical benchmarks, including AIME, AMC, Olympiad, MATH-500, and GSM8k, validate the efficacy of our approach. Using DeepSeek-R1-Distill-Qwen-1.5B and 7B as backbones, ScRPO achieves average accuracies of 64.8% and 77.8%, respectively. This represents a significant improvement of 6.0% and 3.2% over vanilla baselines, consistently outperforming strong post-training methods such as DAPO and GRPO. These findings establish ScRPO as a robust paradigm for enabling autonomous self-improvement in AI systems, particularly in tasks with limited external feedback.","published":"2025-11-08T16:30:44Z","updated":"2026-01-05T05:19:37Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.06065v3","pdf_url":"https://arxiv.org/pdf/2511.06065v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.06057","versioned_id":"2511.06057v2","title":"MIND Your Reasoning: A Meta-Cognitive Intuitive-Reflective Network for Dual-Reasoning in Multimodal Stance Detection","authors":["Bingbing Wang","Zhengda Jin","Bin Liang","Wenjie Li","Jing Li","Ruifeng Xu","Min Zhang"],"abstract":"Multimodal Stance Detection (MSD) is a crucial task for understanding public opinion on social media. Existing methods predominantly operate by learning to fuse modalities. They lack an explicit reasoning process to discern how inter-modal dynamics, such as irony or conflict, collectively shape the user's final stance, leading to frequent misjudgments. To address this, we advocate for a paradigm shift from *learning to fuse* to *learning to reason*. We introduce **MIND**, a **M**eta-cognitive **I**ntuitive-reflective **N**etwork for **D**ual-reasoning. Inspired by the dual-process theory of human cognition, MIND operationalizes a self-improving loop. It first generates a rapid, intuitive hypothesis by querying evolving Modality and Semantic Experience Pools. Subsequently, a meta-cognitive reflective stage uses Modality-CoT and Semantic-CoT to scrutinize this initial judgment, distill superior adaptive strategies, and evolve the experience pools themselves. These dual experience structures are continuously refined during training and recalled at inference to guide robust and context-aware stance decisions. Extensive experiments on the MMSD benchmark demonstrate that our MIND significantly outperforms most baseline models and exhibits strong generalization.","published":"2025-11-08T15:56:24Z","updated":"2026-01-05T17:33:44Z","categories":["cs.CL","cs.MM"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.06057v2","pdf_url":"https://arxiv.org/pdf/2511.06057v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.05933","versioned_id":"2511.05933v2","title":"Reinforcement Learning Improves Traversal of Parametric Knowledge in LLMs","authors":["Renfei Zhang","Manasa Kaniselvan","Rylan Schaeffer abd Niloofar Mireshghallah"],"abstract":"Reinforcement learning (RL) is often credited with improving language model reasoning at the expense of knowledge. We challenge this narrative by showing that reasoning models consistently outperform their instruction-tuned versions on pure knowledge recall tasks. These gains do not reflect newly acquired information, but rather an improved procedural skill in navigating and searching existing knowledge hierarchies within the model parameters. Structured prompting, which explicitly guides models through hierarchical traversal -- recovers most of the instruct-reasoning gap across five model families. A controlled RL experiment on unseen, non-extractable facts improves recall of held-out frequent but previously inaccessible facts, ruling out simple data exposure. On depth-stratified retrieval tasks, reasoning models exhibit superior traversal as retrieval depth grows. Layerwise activation analysis further shows that while factual representations maintain high cosine similarity between instruct and reasoning models, query representations diverge noticeably, indicating that reasoning primarily reshapes how models traverse knowledge rather than the knowledge representation itself. Finally, we find that distilled models often fail to match reasoning models on knowledge recall because they imitate self-correction without acquiring the exploratory behavior needed for hierarchical navigation. Together, these findings suggest that improving factual recall in LLMs depends not only on expanding what models know but also on teaching them to navigate it -- motivating future post-training methods that optimize traversal.","published":"2025-11-08T08:56:29Z","updated":"2026-06-24T14:20:52Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.05933v2","pdf_url":"https://arxiv.org/pdf/2511.05933v2","comment":"`","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.05931","versioned_id":"2511.05931v1","title":"Self-Abstraction from Grounded Experience for Plan-Guided Policy Refinement","authors":["Hiroaki Hayashi","Bo Pang","Wenting Zhao","Ye Liu","Akash Gokul","Srijan Bansal","Caiming Xiong","Semih Yavuz","Yingbo Zhou"],"abstract":"Large language model (LLM) based agents are increasingly used to tackle software engineering tasks that require multi-step reasoning and code modification, demonstrating promising yet limited performance. However, most existing LLM agents typically operate within static execution frameworks, lacking a principled mechanism to learn and self-improve from their own experience and past rollouts. As a result, their performance remains bounded by the initial framework design and the underlying LLM's capabilities. We propose Self-Abstraction from Grounded Experience (SAGE), a framework that enables agents to learn from their own task executions and refine their behavior through self-abstraction. After an initial rollout, the agent induces a concise plan abstraction from its grounded experience, distilling key steps, dependencies, and constraints. This learned abstraction is then fed back as contextual guidance, refining the agent's policy and supporting more structured, informed subsequent executions. Empirically, SAGE delivers consistent performance gains across diverse LLM backbones and agent architectures. Notably, it yields a 7.2% relative performance improvement over the strong Mini-SWE-Agent baseline when paired with the GPT-5 (high) backbone. SAGE further achieves strong overall performance on SWE-Bench Verified benchmark, reaching 73.2% and 74% Pass@1 resolve rates with the Mini-SWE-Agent and OpenHands CodeAct agent framework, respectively.","published":"2025-11-08T08:49:38Z","updated":"2025-11-08T08:49:38Z","categories":["cs.AI","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.05931v1","pdf_url":"https://arxiv.org/pdf/2511.05931v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.05874","versioned_id":"2511.05874v1","title":"An Empirical Study of Reasoning Steps in Thinking Code LLMs","authors":["Haoran Xue","Gias Uddin","Song Wang"],"abstract":"Thinking Large Language Models (LLMs) generate explicit intermediate reasoning traces before final answers, potentially improving transparency, interpretability, and solution accuracy for code generation. However, the quality of these reasoning chains remains underexplored. We present a comprehensive empirical study examining the reasoning process and quality of thinking LLMs for code generation. We evaluate six state-of-the-art reasoning LLMs (DeepSeek-R1, OpenAI-o3-mini, Claude-3.7-Sonnet-Thinking, Gemini-2.0-Flash-Thinking, Gemini-2.5-Flash, and Qwen-QwQ) across 100 code generation tasks of varying difficulty from BigCodeBench. We quantify reasoning-chain structure through step counts and verbosity, conduct controlled step-budget adjustments, and perform a 21-participant human evaluation across three dimensions: efficiency, logical correctness, and completeness. Our step-count interventions reveal that targeted step increases can improve resolution rates for certain models/tasks, while modest reductions often preserve success on standard tasks, rarely on hard ones. Through systematic analysis, we develop a reasoning-problematic taxonomy, identifying completeness as the dominant failure mode. Task complexity significantly impacts reasoning quality; hard problems are substantially more prone to incompleteness than standard tasks. Our stability analysis demonstrates that thinking LLMs maintain consistent logical structures across computational effort levels and can self-correct previous errors. This study provides new insights into the strengths and limitations of current thinking LLMs in software engineering.","published":"2025-11-08T06:18:48Z","updated":"2025-11-08T06:18:48Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.05874v1","pdf_url":"https://arxiv.org/pdf/2511.05874v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.04902","versioned_id":"2511.04902v1","title":"You Need Reasoning to Learn Reasoning: The Limitations of Label-Free RL in Weak Base Models","authors":["Shuvendu Roy","Hossein Hajimirsadeghi","Mengyao Zhai","Golnoosh Samei"],"abstract":"Recent advances in large language models have demonstrated the promise of unsupervised reinforcement learning (RL) methods for enhancing reasoning capabilities without external supervision. However, the generalizability of these label-free RL approaches to smaller base models with limited reasoning capabilities remains unexplored. In this work, we systematically investigate the performance of label-free RL methods across different model sizes and reasoning strengths, from 0.5B to 7B parameters. Our empirical analysis reveals critical limitations: label-free RL is highly dependent on the base model's pre-existing reasoning capability, with performance often degrading below baseline levels for weaker models. We find that smaller models fail to generate sufficiently long or diverse chain-of-thought reasoning to enable effective self-reflection, and that training data difficulty plays a crucial role in determining success. To address these challenges, we propose a simple yet effective method for label-free RL that utilizes curriculum learning to progressively introduce harder problems during training and mask no-majority rollouts during training. Additionally, we introduce a data curation pipeline to generate samples with predefined difficulty. Our approach demonstrates consistent improvements across all model sizes and reasoning capabilities, providing a path toward more robust unsupervised RL that can bootstrap reasoning abilities in resource-constrained models. We make our code available at https://github.com/BorealisAI/CuMa","published":"2025-11-07T01:05:11Z","updated":"2025-11-07T01:05:11Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.04902v1","pdf_url":"https://arxiv.org/pdf/2511.04902v1","comment":"39th Conference on Neural Information Processing Systems (NeurIPS 2025) Workshop: MATH-AI","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.04662","versioned_id":"2511.04662v1","title":"VeriCoT: Neuro-symbolic Chain-of-Thought Validation via Logical Consistency Checks","authors":["Yu Feng","Nathaniel Weir","Kaj Bostrom","Sam Bayless","Darion Cassel","Sapana Chaudhary","Benjamin Kiesl-Reiter","Huzefa Rangwala"],"abstract":"LLMs can perform multi-step reasoning through Chain-of-Thought (CoT), but they cannot reliably verify their own logic. Even when they reach correct answers, the underlying reasoning may be flawed, undermining trust in high-stakes scenarios. To mitigate this issue, we introduce VeriCoT, a neuro-symbolic method that extracts and verifies formal logical arguments from CoT reasoning. VeriCoT formalizes each CoT reasoning step into first-order logic and identifies premises that ground the argument in source context, commonsense knowledge, or prior reasoning steps. The symbolic representation enables automated solvers to verify logical validity while the NL premises allow humans and systems to identify ungrounded or fallacious reasoning steps. Experiments on the ProofWriter, LegalBench, and BioASQ datasets show VeriCoT effectively identifies flawed reasoning, and serves as a strong predictor of final answer correctness. We also leverage VeriCoT's verification signal for (1) inference-time self-reflection, (2) supervised fine-tuning (SFT) on VeriCoT-distilled datasets and (3) preference fine-tuning (PFT) with direct preference optimization (DPO) using verification-based pairwise rewards, further improving reasoning validity and accuracy.","published":"2025-11-06T18:50:08Z","updated":"2025-11-06T18:50:08Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.04662v1","pdf_url":"https://arxiv.org/pdf/2511.04662v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.04646","versioned_id":"2511.04646v1","title":"DR. WELL: Dynamic Reasoning and Learning with Symbolic World Model for Embodied LLM-Based Multi-Agent Collaboration","authors":["Narjes Nourzad","Hanqing Yang","Shiyu Chen","Carlee Joe-Wong"],"abstract":"Cooperative multi-agent planning requires agents to make joint decisions with partial information and limited communication. Coordination at the trajectory level often fails, as small deviations in timing or movement cascade into conflicts. Symbolic planning mitigates this challenge by raising the level of abstraction and providing a minimal vocabulary of actions that enable synchronization and collective progress. We present DR. WELL, a decentralized neurosymbolic framework for cooperative multi-agent planning. Cooperation unfolds through a two-phase negotiation protocol: agents first propose candidate roles with reasoning and then commit to a joint allocation under consensus and environment constraints. After commitment, each agent independently generates and executes a symbolic plan for its role without revealing detailed trajectories. Plans are grounded in execution outcomes via a shared world model that encodes the current state and is updated as agents act. By reasoning over symbolic plans rather than raw trajectories, DR. WELL avoids brittle step-level alignment and enables higher-level operations that are reusable, synchronizable, and interpretable. Experiments on cooperative block-push tasks show that agents adapt across episodes, with the dynamic world model capturing reusable patterns and improving task completion rates and efficiency. Experiments on cooperative block-push tasks show that our dynamic world model improves task completion and efficiency through negotiation and self-refinement, trading a time overhead for evolving, more efficient collaboration strategies.","published":"2025-11-06T18:37:18Z","updated":"2025-11-06T18:37:18Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.04646v1","pdf_url":"https://arxiv.org/pdf/2511.04646v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.04285","versioned_id":"2511.04285v1","title":"RLoop: An Self-Improving Framework for Reinforcement Learning with Iterative Policy Initialization","authors":["Zeng Zhiyuan","Jiashuo Liu","Zhangyue Yin","Ge Zhang","Wenhao Huang","Xipeng Qiu"],"abstract":"While Reinforcement Learning for Verifiable Rewards (RLVR) is powerful for training large reasoning models, its training dynamics harbor a critical challenge: RL overfitting, where models gain training rewards but lose generalization. Our analysis reveals this is driven by policy over-specialization and catastrophic forgetting of diverse solutions generated during training. Standard optimization discards this valuable inter-step policy diversity. To address this, we introduce RLoop, a self-improving framework built on iterative policy initialization. RLoop transforms the standard training process into a virtuous cycle: it first uses RL to explore the solution space from a given policy, then filters the successful trajectories to create an expert dataset. This dataset is used via Rejection-sampling Fine-Tuning (RFT) to refine the initial policy, creating a superior starting point for the next iteration. This loop of exploration and exploitation via iterative re-initialization effectively converts transient policy variations into robust performance gains. Our experiments show RLoop mitigates forgetting and substantially improves generalization, boosting average accuracy by 9% and pass@32 by over 15% compared to vanilla RL.","published":"2025-11-06T11:27:16Z","updated":"2025-11-06T11:27:16Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.04285v1","pdf_url":"https://arxiv.org/pdf/2511.04285v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.03934","versioned_id":"2511.03934v1","title":"PEFA-AI: Advancing Open-source LLMs for RTL generation using Progressive Error Feedback Agentic-AI","authors":["Athma Narayanan","Mahesh Subedar","Omesh Tickoo"],"abstract":"We present an agentic flow consisting of multiple agents that combine specialized LLMs and hardware simulation tools to collaboratively complete the complex task of Register Transfer Level (RTL) generation without human intervention. A key feature of the proposed flow is the progressive error feedback system of agents (PEFA), a self-correcting mechanism that leverages iterative error feedback to progressively increase the complexity of the approach. The generated RTL includes checks for compilation, functional correctness, and synthesizable constructs. To validate this adaptive approach to code generation, benchmarking is performed using two opensource natural language-to-RTL datasets. We demonstrate the benefits of the proposed approach implemented on an open source agentic framework, using both open- and closed-source LLMs, effectively bridging the performance gap between them. Compared to previously published methods, our approach sets a new benchmark, providing state-of-the-art pass rates while being efficient in token counts.","published":"2025-11-06T00:19:47Z","updated":"2025-11-06T00:19:47Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.03934v1","pdf_url":"https://arxiv.org/pdf/2511.03934v1","comment":"Appeared in the Design Automation Conference (DAC) 2025, Workshop Poster on June 22, 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.03925","versioned_id":"2511.03925v1","title":"Collaborative Agents for Automated Program Repair in Ruby","authors":["Nikta Akbarpour","Mahdieh Sadat Benis","Fatemeh Hendijani Fard","Ali Ouni","Mohamed Aymen Saied"],"abstract":"Automated Program Repair (APR) has advanced rapidly with Large Language Models (LLMs), but most existing methods remain computationally expensive, and focused on a small set of languages. Ruby, despite its widespread use in web development and the persistent challenges faced by its developers, has received little attention in APR research. In this paper, we introduce RAMP, a novel lightweight framework that formulates program repair as a feedback-driven, iterative process for Ruby. RAMP employs a team of collaborative agents that generate targeted tests, reflect on errors, and refine candidate fixes until a correct solution is found. Unlike prior approaches, RAMP is designed to avoid reliance on large multilingual repair databases or costly fine-tuning, instead operating directly on Ruby through lightweight prompting and test-driven feedback. Evaluation on the XCodeEval benchmark shows that RAMP achieves a pass@1 of 67% on Ruby, outper-forming prior approaches. RAMP converges quickly within five iterations, and ablation studies confirm that test generation and self-reflection are key drivers of its performance. Further analysis shows that RAMP is particularly effective at repairing wrong answers, compilation errors, and runtime errors. Our approach provides new insights into multi-agent repair strategies, and establishes a foundation for extending LLM-based debugging tools to under-studied languages.","published":"2025-11-06T00:00:17Z","updated":"2025-11-06T00:00:17Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.03925v1","pdf_url":"https://arxiv.org/pdf/2511.03925v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.03773","versioned_id":"2511.03773v2","title":"Scaling Agent Learning via Experience Synthesis","authors":["Zhaorun Chen","Zhuokai Zhao","Kai Zhang","Bo Liu","Qi Qi","Yifan Wu","Tarun Kalluri","Sara Cao","Yuanhao Xiong","Haibo Tong","Huaxiu Yao","Hengduo Li","Jiacheng Zhu","Xian Li","Dawn Song","Bo Li","Jason Weston","Dat Huynh"],"abstract":"While reinforcement learning (RL) can empower autonomous agents by enabling self-improvement through interaction, its practical adoption remains challenging due to costly rollouts, limited task diversity, unreliable reward signals, and infrastructure complexity, all of which obstruct the collection of scalable experience data. To address these challenges, we introduce DreamGym, the first unified framework designed to synthesize diverse experiences with scalability in mind to enable effective online RL training for autonomous agents. Rather than relying on expensive real-environment rollouts, DreamGym distills environment dynamics into a reasoning-based experience model that derives consistent state transitions and feedback signals through step-by-step reasoning, enabling scalable agent rollout collection for RL. To improve the stability and quality of transitions, DreamGym leverages an experience replay buffer initialized with offline real-world data and continuously enriched with fresh interactions to actively support agent training. To improve knowledge acquisition, DreamGym adaptively generates new tasks that challenge the current agent policy, enabling more effective online curriculum learning. Experiments across diverse environments and agent backbones demonstrate that DreamGym substantially improves RL training, both in fully synthetic settings and in sim-to-real transfer scenarios. On non-RL-ready tasks like WebArena, DreamGym outperforms all baselines by over 30%. And in RL-ready but costly settings, it matches GRPO and PPO performance using only synthetic interactions. When transferring a policy trained purely on synthetic experiences to real-environment RL, DreamGym yields significant additional performance gains while requiring far fewer real-world interactions, providing a scalable warm-start strategy for general-purpose RL.","published":"2025-11-05T18:58:48Z","updated":"2025-11-10T05:02:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.03773v2","pdf_url":"https://arxiv.org/pdf/2511.03773v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.03153","versioned_id":"2511.03153v2","title":"RefAgent: A Multi-agent LLM-based Framework for Automatic Software Refactoring","authors":["Khouloud Oueslati","Maxime Lamothe","Foutse Khomh"],"abstract":"Large Language Models (LLMs) have substantially influenced various software engineering tasks. Indeed, in the case of software refactoring, traditional LLMs have shown the ability to reduce development time and enhance code quality. However, these LLMs often rely on static, detailed instructions for specific tasks. In contrast, LLM-based agents can dynamically adapt to evolving contexts and autonomously make decisions by interacting with software tools and executing workflows. In this paper, we explore the potential of LLM-based agents in supporting refactoring activities. Specifically, we introduce RefAgent, a multi-agent LLM-based framework for end-to-end software refactoring. RefAgent consists of specialized agents responsible for planning, executing, testing, and iteratively refining refactorings using self-reflection and tool-calling capabilities. We evaluate RefAgent on eight open-source Java projects, comparing its effectiveness against a single-agent approach, a search-based refactoring tool, and historical developer refactorings. Our assessment focuses on: (1) the impact of generated refactorings on software quality, (2) the ability to identify refactoring opportunities, and (3) the contribution of each LLM agent through an ablation study. Our results show that RefAgent achieves a median unit test pass rate of 90%, reduces code smells by a median of 52.5%, and improves key quality attributes (e.g., reusability) by a median of 8.6%. Additionally, it closely aligns with developer refactorings and the search-based tool in identifying refactoring opportunities, attaining a median F1-score of 79.15% and 72.7%, respectively. Compared to single-agent approaches, RefAgent improves the median unit test pass rate by 64.7% and the median compilation success rate by 40.1%. These findings highlight the promise of multi-agent architectures in advancing automated software refactoring.","published":"2025-11-05T03:20:58Z","updated":"2026-03-04T19:27:09Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.03153v2","pdf_url":"https://arxiv.org/pdf/2511.03153v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.02239","versioned_id":"2511.02239v2","title":"LACY: A Vision-Language Model-based Language-Action Cycle for Self-Improving Robotic Manipulation","authors":["Youngjin Hong","Houjian Yu","Mingen Li","Changhyun Choi"],"abstract":"Learning generalizable policies for robotic manipulation increasingly relies on large-scale models that map language instructions to actions (L2A). However, this one-way paradigm often produces policies that execute tasks without deeper contextual understanding, limiting their ability to generalize or explain their behavior. We argue that the complementary skill of mapping actions back to language (A2L) is essential for developing more holistic grounding. An agent capable of both acting and explaining its actions can form richer internal representations and unlock new paradigms for self-supervised learning. We introduce LACY (Language-Action Cycle), a unified framework that learns such bidirectional mappings within a single vision-language model. LACY is jointly trained on three synergistic tasks: generating parameterized actions from language (L2A), explaining observed actions in language (A2L), and verifying semantic consistency between two language descriptions (L2C). This enables a self-improving cycle that autonomously generates and filters new training data through an active augmentation strategy targeting low-confidence cases, thereby improving the model without additional human labels. Experiments on pick-and-place tasks in both simulation and the real world show that LACY improves task success rates by 56.46% on average and yields more robust language-action grounding for robotic manipulation. Project page: https://vla2026.github.io/LACY/","published":"2025-11-04T04:02:51Z","updated":"2026-05-21T21:13:30Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2511.02239v2","pdf_url":"https://arxiv.org/pdf/2511.02239v2","comment":"Accepted to ICRA 2026. Project page: https://vla2026.github.io/LACY/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.02002","versioned_id":"2511.02002v1","title":"InteracSPARQL: An Interactive System for SPARQL Query Refinement Using Natural Language Explanations","authors":["Xiangru Jian","Zhengyuan Dong","M. Tamer Özsu"],"abstract":"In recent years, querying semantic web data using SPARQL has remained challenging, especially for non-expert users, due to the language's complex syntax and the prerequisite of understanding intricate data structures. To address these challenges, we propose InteracSPARQL, an interactive SPARQL query generation and refinement system that leverages natural language explanations (NLEs) to enhance user comprehension and facilitate iterative query refinement. InteracSPARQL integrates LLMs with a rule-based approach to first produce structured explanations directly from SPARQL abstract syntax trees (ASTs), followed by LLM-based linguistic refinements. Users can interactively refine queries through direct feedback or LLM-driven self-refinement, enabling the correction of ambiguous or incorrect query components in real time. We evaluate InteracSPARQL on standard benchmarks, demonstrating significant improvements in query accuracy, explanation clarity, and overall user satisfaction compared to baseline approaches. Our experiments further highlight the effectiveness of combining rule-based methods with LLM-driven refinements to create more accessible and robust SPARQL interfaces.","published":"2025-11-03T19:15:51Z","updated":"2025-11-03T19:15:51Z","categories":["cs.DB","cs.AI","cs.IR"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2511.02002v1","pdf_url":"https://arxiv.org/pdf/2511.02002v1","comment":"Working paper","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.01950","versioned_id":"2511.01950v1","title":"EchoLSTM: A Self-Reflective Recurrent Network for Stabilizing Long-Range Memory","authors":["Prasanth K K","Shubham Sharma"],"abstract":"Standard Recurrent Neural Networks, including LSTMs, struggle to model long-range dependencies, particularly in sequences containing noisy or misleading information. We propose a new architectural principle, Output-Conditioned Gating, which enables a model to perform self-reflection by modulating its internal memory gates based on its own past inferences. This creates a stabilizing feedback loop that enhances memory retention. Our final model, the EchoLSTM, integrates this principle with an attention mechanism. We evaluate the EchoLSTM on a series of challenging benchmarks. On a custom-designed Distractor Signal Task, the EchoLSTM achieves 69.0% accuracy, decisively outperforming a standard LSTM baseline by 33 percentage points. Furthermore, on the standard ListOps benchmark, the EchoLSTM achieves performance competitive with a modern Transformer model, 69.8% vs. 71.8%, while being over 5 times more parameter-efficient. A final Trigger Sensitivity Test provides qualitative evidence that our model's self-reflective mechanism leads to a fundamentally more robust memory system.","published":"2025-11-03T11:04:33Z","updated":"2025-11-03T11:04:33Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.01950v1","pdf_url":"https://arxiv.org/pdf/2511.01950v1","comment":"11 pages, 4 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.01363","versioned_id":"2511.01363v1","title":"Automatic Minds: Cognitive Parallels Between Hypnotic States and Large Language Model Processing","authors":["Giuseppe Riva","Brenda K. Wiederhold","Fabrizia Mantovani"],"abstract":"The cognitive processes of the hypnotized mind and the computational operations of large language models (LLMs) share deep functional parallels. Both systems generate sophisticated, contextually appropriate behavior through automatic pattern-completion mechanisms operating with limited or unreliable executive oversight. This review examines this convergence across three principles: automaticity, in which responses emerge from associative rather than deliberative processes; suppressed monitoring, leading to errors such as confabulation in hypnosis and hallucination in LLMs; and heightened contextual dependency, where immediate cues (for example, the suggestion of a therapist or the prompt of the user) override stable knowledge. These mechanisms reveal an observer-relative meaning gap: both systems produce coherent but ungrounded outputs that require an external interpreter to supply meaning. Hypnosis and LLMs also exemplify functional agency - the capacity for complex, goal-directed, context-sensitive behavior - without subjective agency, the conscious awareness of intention and ownership that defines human action. This distinction clarifies how purposive behavior can emerge without self-reflective consciousness, governed instead by structural and contextual dynamics. Finally, both domains illuminate the phenomenon of scheming: automatic, goal-directed pattern generation that unfolds without reflective awareness. Hypnosis provides an experimental model for understanding how intention can become dissociated from conscious deliberation, offering insights into the hidden motivational dynamics of artificial systems. Recognizing these parallels suggests that the future of reliable AI lies in hybrid architectures that integrate generative fluency with mechanisms of executive monitoring, an approach inspired by the complex, self-regulating architecture of the human mind.","published":"2025-11-03T09:08:50Z","updated":"2025-11-03T09:08:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.01363v1","pdf_url":"https://arxiv.org/pdf/2511.01363v1","comment":"4 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.01008","versioned_id":"2511.01008v2","title":"MARS-SQL: A multi-agent reinforcement learning framework for Text-to-SQL","authors":["Haolin Yang","Jipeng Zhang","Zhitao He","Alexander Zhou","Yi R. Fung"],"abstract":"Large Language Models (LLMs) often struggle with the precise logic and schema alignment required for complex Text-to-SQL tasks. While current methods rely heavily on static prompting, they lack the ability to dynamically adapt and self-correct through environmental interaction. To bridge this gap, we propose MARS-SQL, a trainable multi-agent framework for Text-to-SQL. Rather than introducing a new standalone SQL primitive, MARS-SQL makes an agentic workflow trainable by decomposing the problem into three specialized roles: schema grounding, query generation, and solution validation. Central to our approach is a generation agent trained via a multi-turn RL policy within a ReAct-style loop. The agent learns to iteratively reason, execute intermediate SQL actions on a live database, and refine its strategy based on execution feedback. To improve robustness, we further introduce a validation mechanism that treats solution selection as a generative modeling task, identifying the optimal interaction trajectory through next-token prediction probabilities. Empirical evaluations demonstrate the effectiveness of coupling interactive learning with trajectory ranking. MARS-SQL achieves state-of-the-art performance, recording an execution accuracy of 77.84% on the BIRD development dataset and 89.75% on the Spider test dataset, while also transferring strongly to out-of-domain benchmarks. Code is available at https://github.com/YangHaolin0526/MARS-SQL.","published":"2025-11-02T16:55:30Z","updated":"2026-05-10T03:37:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.01008v2","pdf_url":"https://arxiv.org/pdf/2511.01008v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.00758","versioned_id":"2511.00758v1","title":"Active Thinking Model: A Goal-Directed Self-Improving Framework for Real-World Adaptive Intelligence","authors":["Hong Su"],"abstract":"Real-world artificial intelligence (AI) systems are increasingly required to operate autonomously in dynamic, uncertain, and continuously changing environments. However, most existing AI models rely on predefined objectives, static training data, and externally supplied feedback, which restrict their ability to adapt, reflect, and improve independently. In this paper, we propose the Active Thinking Model (ATM)- a unified cognitive framework that integrates goal reasoning, dynamic task generation, and self-reflective learning into an adaptive architecture. Unlike conventional systems that passively execute fixed procedures, ATM actively evaluates its performance through logical reasoning and environmental indicators, reuses effective methods to solve new problems, and generates novel strategies for unseen situations via a continuous self-improvement loop. A mathematically grounded theoretical analysis demonstrates that ATM can autonomously evolve from suboptimal to optimal behavior without external supervision and maintain bounded tracking regret under changing environmental conditions.","published":"2025-11-02T01:13:12Z","updated":"2025-11-02T01:13:12Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.00758v1","pdf_url":"https://arxiv.org/pdf/2511.00758v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.00602","versioned_id":"2511.00602v4","title":"OpenSIR: Open-Ended Self-Improving Reasoner","authors":["Wai-Chung Kwan","Joshua Ong Jun Leang","Pavlos Vougiouklis","Jeff Z. Pan","Marco Valentino","Pasquale Minervini"],"abstract":"Recent advances in large language model (LLM) reasoning through reinforcement learning rely on annotated datasets for verifiable rewards, which may limit models' ability to surpass human-level performance. While self-play offers a promising alternative, prior methods yield only marginal or even negative gains on post-trained models because they generate problems that cluster around familiar concepts rather than discovering novel ones. We introduce Open-Ended Self-Improving Reasoner (OpenSIR), a self-play framework in which a single LLM alternates teacher and student roles to generate and solve novel problems without external verifiers or annotated data. Starting from a single seed problem, OpenSIR sustains open-ended exploration through diversity rewards that push the model toward unfamiliar concepts and difficulty calibration that keeps problems learnable. Across seven math benchmarks, OpenSIR consistently improves all models, averaging +3.6 points on instruction models and +3.1 on reasoning models, while recent self-play baselines yield marginal or even negative gains; starting from a single trivial seed, it also surpasses GRPO baselines trained on over 7K annotated examples. Despite training only on self-generated math, OpenSIR is the only self-play method that transfers to general reasoning, improving by at least +4.4 points on reasoning models.","published":"2025-11-01T16:08:28Z","updated":"2026-07-03T09:31:00Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.00602v4","pdf_url":"https://arxiv.org/pdf/2511.00602v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.00330","versioned_id":"2511.00330v1","title":"Sherlock: Reliable and Efficient Agentic Workflow Execution","authors":["Yeonju Ro","Haoran Qiu","Íñigo Goiri","Rodrigo Fonseca","Ricardo Bianchini","Aditya Akella","Zhangyang Wang","Mattan Erez","Esha Choukse"],"abstract":"With the increasing adoption of large language models (LLM), agentic workflows, which compose multiple LLM calls with tools, retrieval, and reasoning steps, are increasingly replacing traditional applications. However, such workflows are inherently error-prone: incorrect or partially correct output at one step can propagate or even amplify through subsequent stages, compounding the impact on the final output. Recent work proposes integrating verifiers that validate LLM output or actions, such as self-reflection, debate, or LLM-as-a-judge mechanisms. Yet, verifying every step introduces significant latency and cost overheads. In this work, we seek to answer three key questions: which nodes in a workflow are most error-prone and thus deserve costly verification, how to select the most appropriate verifier for each node, and how to use verification with minimal impact to latency? Our solution, Sherlock, addresses these using counterfactual analysis on agentic workflows to identify error-prone nodes and selectively attaching cost-optimal verifiers only where necessary. At runtime, Sherlock speculatively executes downstream tasks to reduce latency overhead, while verification runs in the background. If verification fails, execution is rolled back to the last verified output. Compared to the non-verifying baseline, Sherlock delivers an 18.3% accuracy gain on average across benchmarks. Sherlock reduces workflow execution time by up to 48.7% over non-speculative execution and lowers verification cost by 26.0% compared to the Monte Carlo search-based method, demonstrating that principled, fault-aware verification effectively balances efficiency and reliability in agentic workflows.","published":"2025-11-01T00:17:57Z","updated":"2025-11-01T00:17:57Z","categories":["cs.MA","cs.SE"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2511.00330v1","pdf_url":"https://arxiv.org/pdf/2511.00330v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2511.02854","versioned_id":"2511.02854v1","title":"SELF-REDRAFT: Eliciting Intrinsic Exploration-Exploitation Balance in Test-Time Scaling for Code Generation","authors":["Yixiang Chen","Tianshi Zheng","Shijue Huang","Zhitao He","Yi R. Fung"],"abstract":"Test-time scaling without interpreter feedback is essential for real-world code generation scenarios where test cases are not readily available. While existing paradigms often rely on either greedy exploitation (i.e., iterative refinement) or stochastic exploration (i.e., relying on sample-based voting or reranking mechanisms), the balance between these two dimensions remains underexplored. To investigate the LLM's intrinsic ability to balance exploitation and exploration, we introduce SELF-REDRAFT, a framework built upon Self-Refine that encourages the model to propose new drafts for solutions that are fundamentally flawed. Our results show that SELF-REDRAFT consistently achieves better performance than Self-Refine when converged under the same maximum number of iterations. Still, we observe that significant room for improvement remains, largely due to two core aspects of current self-redraft capabilities: constrained capacity for generating instructive feedback and fragile discriminative judgment. We also find that balancing strategies vary notably across different LLMs, reflecting distinct, model-specific behaviors. Overall, our study establishes a baseline for intrinsic exploration-exploitation balancing in test-time scaling and identifies feedback and discrimination as key areas with potential for future advances.","published":"2025-10-31T06:30:47Z","updated":"2025-10-31T06:30:47Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.02854v1","pdf_url":"https://arxiv.org/pdf/2511.02854v1","comment":"15 pages, 8 figures,2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.27126","versioned_id":"2510.27126v2","title":"AURA: A Reinforcement Learning Framework for AI-Driven Adaptive Conversational Surveys","authors":["Jinwen Tang","Yi Shang"],"abstract":"Conventional online surveys provide limited personalization, often resulting in low engagement and superficial responses. Although AI survey chatbots improve convenience, most are still reactive: they rely on fixed dialogue trees or static prompt templates and therefore cannot adapt within a session to fit individual users, which leads to generic follow-ups and weak response quality. We address these limitations with AURA (Adaptive Understanding through Reinforcement Learning for Assessment), a reinforcement learning framework for AI-driven adaptive conversational surveys. AURA quantifies response quality using a four-dimensional LSDE metric (Length, Self-disclosure, Emotion, and Specificity) and selects follow-up question types via an epsilon-greedy policy that updates the expected quality gain within each session. Initialized with priors extracted from 96 prior campus-climate conversations (467 total chatbot-user exchanges), the system balances exploration and exploitation across 10-15 dialogue exchanges, dynamically adapting to individual participants in real time. In controlled evaluations, AURA achieved a +0.076 mean gain in response quality and a statistically significant improvement over non-adaptive baselines (p=0.044, d=0.66), driven by a 63% reduction in specification prompts and a 10x increase in validation behavior. These results demonstrate that reinforcement learning can give survey chatbots improved adaptivity, transforming static questionnaires into interactive, self-improving assessment systems.","published":"2025-10-31T03:03:55Z","updated":"2025-11-07T06:59:45Z","categories":["cs.HC","cs.AI","cs.LG"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2510.27126v2","pdf_url":"https://arxiv.org/pdf/2510.27126v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.27114","versioned_id":"2510.27114v1","title":"Learning Generalizable Visuomotor Policy through Dynamics-Alignment","authors":["Dohyeok Lee","Jung Min Lee","Munkyung Kim","Seokhun Ju","Jin Woo Koo","Kyungjae Lee","Dohyeong Kim","TaeHyun Cho","Jungwoo Lee"],"abstract":"Behavior cloning methods for robot learning suffer from poor generalization due to limited data support beyond expert demonstrations. Recent approaches leveraging video prediction models have shown promising results by learning rich spatiotemporal representations from large-scale datasets. However, these models learn action-agnostic dynamics that cannot distinguish between different control inputs, limiting their utility for precise manipulation tasks and requiring large pretraining datasets. We propose a Dynamics-Aligned Flow Matching Policy (DAP) that integrates dynamics prediction into policy learning. Our method introduces a novel architecture where policy and dynamics models provide mutual corrective feedback during action generation, enabling self-correction and improved generalization. Empirical validation demonstrates generalization performance superior to baseline methods on real-world robotic manipulation tasks, showing particular robustness in OOD scenarios including visual distractions and lighting variations.","published":"2025-10-31T02:29:33Z","updated":"2025-10-31T02:29:33Z","categories":["cs.RO","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2510.27114v1","pdf_url":"https://arxiv.org/pdf/2510.27114v1","comment":"9 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.27051","versioned_id":"2510.27051v1","title":"Adaptive Data Flywheel: Applying MAPE Control Loops to AI Agent Improvement","authors":["Aaditya Shukla","Sidney Knowles","Meenakshi Madugula","Dave Farris","Ryan Angilly","Santiago Pombo","Anbang Xu","Lu An","Abhinav Balasubramanian","Tan Yu","Jiaxiang Ren","Rama Akkiraju"],"abstract":"Enterprise AI agents must continuously adapt to maintain accuracy, reduce latency, and remain aligned with user needs. We present a practical implementation of a data flywheel in NVInfo AI, NVIDIA's Mixture-of-Experts (MoE) Knowledge Assistant serving over 30,000 employees. By operationalizing a MAPE-driven data flywheel, we built a closed-loop system that systematically addresses failures in retrieval-augmented generation (RAG) pipelines and enables continuous learning. Over a 3-month post-deployment period, we monitored feedback and collected 495 negative samples. Analysis revealed two major failure modes: routing errors (5.25\\%) and query rephrasal errors (3.2\\%). Using NVIDIA NeMo microservices, we implemented targeted improvements through fine-tuning. For routing, we replaced a Llama 3.1 70B model with a fine-tuned 8B variant, achieving 96\\% accuracy, a 10x reduction in model size, and 70\\% latency improvement. For query rephrasal, fine-tuning yielded a 3.7\\% gain in accuracy and a 40\\% latency reduction. Our approach demonstrates how human-in-the-loop (HITL) feedback, when structured within a data flywheel, transforms enterprise AI agents into self-improving systems. Key learnings include approaches to ensure agent robustness despite limited user feedback, navigating privacy constraints, and executing staged rollouts in production. This work offers a repeatable blueprint for building robust, adaptive enterprise AI agents capable of learning from real-world usage at scale.","published":"2025-10-30T23:41:06Z","updated":"2025-10-30T23:41:06Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.27051v1","pdf_url":"https://arxiv.org/pdf/2510.27051v1","comment":"20 pages, 5 figures, 5 tables. Presents MAPE-K control loop application to enterprise AI agent improvement with experimental validation on NVIDIA's NVInfo AI system","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.26852","versioned_id":"2510.26852v2","title":"CATArena: Evaluating Evolutionary Capabilities of Code Agents via Iterative Tournaments","authors":["Lingyue Fu","Xin Ding","Linyue Pan","Yaoming Zhu","Shao Zhang","Lin Qiu","Weiwen Liu","Weinan Zhang","Xuezhi Cao","Xunliang Cai","Jiaxin Ding","Yong Yu"],"abstract":"Current evaluation for Large Language Model (LLM) code agents predominantly focus on generating functional code in single-turn scenarios, which fails to evaluate the agent's capability for continuous code optimization and multi-turn iterative development. To bridge this gap, we introduce CATArena, a framework designed to evaluate the evolutionary capabilities of code agents via iterative tournaments. Agents engage in multi-turn tournaments and continuously refine their code through self-reflection and peer-learning based on comprehensive execution feedback. For evaluation, we propose a dual-metric system to decouple static generation proficiency from evolutionary potential. Extensive experiments reveal that an agent's evolutionary potential is not strictly correlated with its initial proficiency. Our analysis further reveals that current agents struggle to concurrently leverage both peer-learning and self-reflection for effective performance gains. Furthermore, the results validate CATArena's high extensibility and resistance to variance tasks, establishing it as a continuous and reliable standard for assessing the evolutionary capability of LLM code agents.","published":"2025-10-30T15:22:53Z","updated":"2026-01-30T11:04:12Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.26852v2","pdf_url":"https://arxiv.org/pdf/2510.26852v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.26474","versioned_id":"2510.26474v1","title":"Counteracting Matthew Effect in Self-Improvement of LVLMs through Head-Tail Re-balancing","authors":["Xin Guo","Zhiheng Xi","Yiwen Ding","Yitao Zhai","Xiaowei Shi","Xunliang Cai","Tao Gui","Qi Zhang","Xuanjing Huang"],"abstract":"Self-improvement has emerged as a mainstream paradigm for advancing the reasoning capabilities of large vision-language models (LVLMs), where models explore and learn from successful trajectories iteratively. However, we identify a critical issue during this process: the model excels at generating high-quality trajectories for simple queries (i.e., head data) but struggles with more complex ones (i.e., tail data). This leads to an imbalanced optimization that drives the model to prioritize simple reasoning skills, while hindering its ability to tackle more complex reasoning tasks. Over iterations, this imbalance becomes increasingly pronounced--a dynamic we term the \"Matthew effect\"--which ultimately hinders further model improvement and leads to performance bottlenecks. To counteract this challenge, we introduce four efficient strategies from two perspectives: distribution-reshaping and trajectory-resampling, to achieve head-tail re-balancing during the exploration-and-learning self-improvement process. Extensive experiments on Qwen2-VL-7B-Instruct and InternVL2.5-4B models across visual reasoning tasks demonstrate that our methods consistently improve visual reasoning capabilities, outperforming vanilla self-improvement by 3.86 points on average.","published":"2025-10-30T13:26:58Z","updated":"2025-10-30T13:26:58Z","categories":["cs.CV","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.26474v1","pdf_url":"https://arxiv.org/pdf/2510.26474v1","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.26423","versioned_id":"2510.26423v1","title":"Nexus: Execution-Grounded Multi-Agent Test Oracle Synthesis","authors":["Dong Huang","Mingzhe Du","Jie M. Zhang","Zheng Lin","Meng Luo","Qianru Zhang","See-Kiong Ng"],"abstract":"Test oracle generation in non-regression testing is a longstanding challenge in software engineering, where the goal is to produce oracles that can accurately determine whether a function under test (FUT) behaves as intended for a given input. In this paper, we introduce Nexus, a novel multi-agent framework to address this challenge. Nexus generates test oracles by leveraging a diverse set of specialized agents that synthesize test oracles through a structured process of deliberation, validation, and iterative self-refinement. During the deliberation phase, a panel of four specialist agents, each embodying a distinct testing philosophy, collaboratively critiques and refines an initial set of test oracles. Then, in the validation phase, Nexus generates a plausible candidate implementation of the FUT and executes the proposed oracles against it in a secure sandbox. For any oracle that fails this execution-based check, Nexus activates an automated selfrefinement loop, using the specific runtime error to debug and correct the oracle before re-validation. Our extensive evaluation on seven diverse benchmarks demonstrates that Nexus consistently and substantially outperforms state-of-theart baselines. For instance, Nexus improves the test-level oracle accuracy on the LiveCodeBench from 46.30% to 57.73% for GPT-4.1-Mini. The improved accuracy also significantly enhances downstream tasks: the bug detection rate of GPT4.1-Mini generated test oracles on HumanEval increases from 90.91% to 95.45% for Nexus compared to baselines, and the success rate of automated program repair improves from 35.23% to 69.32%.","published":"2025-10-30T12:20:25Z","updated":"2025-10-30T12:20:25Z","categories":["cs.SE","cs.CL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2510.26423v1","pdf_url":"https://arxiv.org/pdf/2510.26423v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.26322","versioned_id":"2510.26322v1","title":"SCRIBE: Structured Chain Reasoning for Interactive Behaviour Explanations using Tool Calling","authors":["Fares Fawzi","Vinitra Swamy","Dominik Glandorf","Tanya Nazaretsky","Tanja Käser"],"abstract":"Language models can be used to provide interactive, personalized student feedback in educational settings. However, real-world deployment faces three key challenges: privacy concerns, limited computational resources, and the need for pedagogically valid responses. These constraints require small, open-source models that can run locally and reliably ground their outputs in correct information. We introduce SCRIBE, a framework for multi-hop, tool-augmented reasoning designed to generate valid responses to student questions about feedback reports. SCRIBE combines domain-specific tools with a self-reflective inference pipeline that supports iterative reasoning, tool use, and error recovery. We distil these capabilities into 3B and 8B models via two-stage LoRA fine-tuning on synthetic GPT-4o-generated data. Evaluation with a human-aligned GPT-Judge and a user study with 108 students shows that 8B-SCRIBE models achieve comparable or superior quality to much larger models in key dimensions such as relevance and actionability, while being perceived on par with GPT-4o and Llama-3.3 70B by students. These findings demonstrate the viability of SCRIBE for low-resource, privacy-sensitive educational applications.","published":"2025-10-30T10:17:05Z","updated":"2025-10-30T10:17:05Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.26322v1","pdf_url":"https://arxiv.org/pdf/2510.26322v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.26167","versioned_id":"2510.26167v2","title":"ToolRM: Towards Agentic Tool-Use Reward Modeling","authors":["Renhao Li","Jianhong Tu","Yang Su","Yantao Liu","Fei Huang","Hamid Alinejad-Rokny","Derek F. Wong","Junyang Lin","Min Yang"],"abstract":"Reward models (RMs) play a critical role in aligning large language models (LLMs) with human preferences. Yet in the domain of tool learning, the lack of RMs specifically designed for function-calling tasks has limited progress toward more capable agentic AI. We introduce ToolRM, a family of lightweight reward models tailored for general tool-use scenarios. To build these models, we propose a novel pipeline that constructs high-quality pairwise preference data using rule-based scoring and multidimensional sampling. This yields ToolPref-Pairwise-30K, a diverse, balanced, and challenging preference dataset that supports both generative and discriminative reward modeling. We also introduce TRBench$_{BFCL}$, a benchmark built on the agent evaluation suite BFCL to evaluate RMs on tool calling tasks. Trained on our constructed data, models from the Qwen3-4B/8B series achieve up to 17.94% higher accuracy, substantially outperforming frontier LLMs and RMs in pairwise reward judgments. Beyond training objectives, generative ToolRM generalizes to broader critique tasks, including Best-of-N sampling and self-correction. Experiments on ACEBench highlight its effectiveness and efficiency, enabling inference-time scaling while reducing output token usage by over 66%. Its support for downstream RL training further validates its practical utility. We release data to facilitate future research.","published":"2025-10-30T06:08:27Z","updated":"2026-01-13T13:28:26Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.26167v2","pdf_url":"https://arxiv.org/pdf/2510.26167v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.26157","versioned_id":"2510.26157v1","title":"Bridging the Gap Between Molecule and Textual Descriptions via Substructure-aware Alignment","authors":["Hyuntae Park","Yeachan Kim","SangKeun Lee"],"abstract":"Molecule and text representation learning has gained increasing interest due to its potential for enhancing the understanding of chemical information. However, existing models often struggle to capture subtle differences between molecules and their descriptions, as they lack the ability to learn fine-grained alignments between molecular substructures and chemical phrases. To address this limitation, we introduce MolBridge, a novel molecule-text learning framework based on substructure-aware alignments. Specifically, we augment the original molecule-description pairs with additional alignment signals derived from molecular substructures and chemical phrases. To effectively learn from these enriched alignments, MolBridge employs substructure-aware contrastive learning, coupled with a self-refinement mechanism that filters out noisy alignment signals. Experimental results show that MolBridge effectively captures fine-grained correspondences and outperforms state-of-the-art baselines on a wide range of molecular benchmarks, highlighting the significance of substructure-aware alignment in molecule-text learning.","published":"2025-10-30T05:36:31Z","updated":"2025-10-30T05:36:31Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.26157v1","pdf_url":"https://arxiv.org/pdf/2510.26157v1","comment":"EMNLP 2025 (main)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.25621","versioned_id":"2510.25621v1","title":"FARSIQA: Faithful and Advanced RAG System for Islamic Question Answering","authors":["Mohammad Aghajani Asl","Behrooz Minaei Bidgoli"],"abstract":"The advent of Large Language Models (LLMs) has revolutionized Natural Language Processing, yet their application in high-stakes, specialized domains like religious question answering is hindered by challenges like hallucination and unfaithfulness to authoritative sources. This issue is particularly critical for the Persian-speaking Muslim community, where accuracy and trustworthiness are paramount. Existing Retrieval-Augmented Generation (RAG) systems, relying on simplistic single-pass pipelines, fall short on complex, multi-hop queries requiring multi-step reasoning and evidence aggregation. To address this gap, we introduce FARSIQA, a novel, end-to-end system for Faithful Advanced Question Answering in the Persian Islamic domain. FARSIQA is built upon our innovative FAIR-RAG architecture: a Faithful, Adaptive, Iterative Refinement framework for RAG. FAIR-RAG employs a dynamic, self-correcting process: it adaptively decomposes complex queries, assesses evidence sufficiency, and enters an iterative loop to generate sub-queries, progressively filling information gaps. Operating on a curated knowledge base of over one million authoritative Islamic documents, FARSIQA demonstrates superior performance. Rigorous evaluation on the challenging IslamicPCQA benchmark shows state-of-the-art performance: the system achieves a remarkable 97.0% in Negative Rejection - a 40-point improvement over baselines - and a high Answer Correctness score of 74.3%. Our work establishes a new standard for Persian Islamic QA and validates that our iterative, adaptive architecture is crucial for building faithful, reliable AI systems in sensitive domains.","published":"2025-10-29T15:25:34Z","updated":"2025-10-29T15:25:34Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.25621v1","pdf_url":"https://arxiv.org/pdf/2510.25621v1","comment":"37 pages, 5 figures, 10 tables. Keywords: Retrieval-Augmented Generation (RAG), Question Answering (QA), Islamic Knowledge Base, Faithful AI, Persian NLP, Multi-hop Reasoning, Large Language Models (LLMs)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24980","versioned_id":"2510.24980v1","title":"FT-ARM: Fine-Tuned Agentic Reflection Multimodal Language Model for Pressure Ulcer Severity Classification with Reasoning","authors":["Reza Saadati Fard","Emmanuel Agu","Palawat Busaranuvong","Deepak Kumar","Shefalika Gautam","Bengisu Tulu","Diane Strong","Lorraine Loretz"],"abstract":"Pressure ulcers (PUs) are a serious and prevalent healthcare concern. Accurate classification of PU severity (Stages I-IV) is essential for proper treatment but remains challenging due to subtle visual distinctions and subjective interpretation, leading to variability among clinicians. Prior AI-based approaches using Convolutional Neural Networks (CNNs) and Vision Transformers (ViTs) achieved promising accuracy but offered limited interpretability. We present FT-ARM (Fine-Tuned Agentic Reflection Multimodal model), a fine-tuned multimodal large language model (MLLM) with an agentic self-reflection mechanism for pressure ulcer severity classification. Inspired by clinician-style diagnostic reassessment, FT-ARM iteratively refines its predictions by reasoning over visual features and encoded clinical knowledge from text, enhancing both accuracy and consistency. On the publicly available Pressure Injury Image Dataset (PIID), FT-ARM, fine-tuned from LLaMA 3.2 90B, achieved 85% accuracy in classifying PU stages I-IV, surpassing prior CNN-based models by +4%. Unlike earlier CNN/ViT studies that relied solely on offline evaluations, FT-ARM is designed and tested for live inference, reflecting real-time deployment conditions. Furthermore, it produces clinically grounded natural-language explanations, improving interpretability and trust. By integrating fine-tuning and reflective reasoning across multimodal inputs, FT-ARM advances the reliability, transparency, and clinical applicability of automated wound assessment systems, addressing the critical need for consistent and explainable PU staging to support improved patient care.","published":"2025-10-28T21:23:32Z","updated":"2025-10-28T21:23:32Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.24980v1","pdf_url":"https://arxiv.org/pdf/2510.24980v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24932","versioned_id":"2510.24932v1","title":"RiddleBench: A New Generative Reasoning Benchmark for LLMs","authors":["Deepon Halder","Alan Saji","Thanmay Jayakumar","Ratish Puduppully","Anoop Kunchukuttan","Raj Dabre"],"abstract":"Large Language Models have demonstrated strong performance on many established reasoning benchmarks. However, these benchmarks primarily evaluate structured skills like quantitative problem-solving, leaving a gap in assessing flexible, multifaceted reasoning abilities that are central to human intelligence. These abilities require integrating logical deduction with spatial awareness and constraint satisfaction, which current evaluations do not measure well. To address this, we introduce RiddleBench, a benchmark of 1,737 challenging puzzles in English designed to probe these core reasoning capabilities. Evaluation of state-of-the-art models on RiddleBench shows fundamental weaknesses. Even top proprietary models like Gemini 2.5 Pro, o3, and Claude 4 Sonnet achieve accuracy just above 60% (60.30%, 63.37%, and 63.16%). Analysis further reveals deep failures, including hallucination cascades (accepting flawed reasoning from other models) and poor self-correction due to a strong self-confirmation bias. Their reasoning is also fragile, with performance degrading significantly when constraints are reordered or irrelevant information is introduced. RiddleBench functions as a diagnostic tool for these issues and as a resource for guiding the development of more robust and reliable language models.","published":"2025-10-28T19:58:24Z","updated":"2025-10-28T19:58:24Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.24932v1","pdf_url":"https://arxiv.org/pdf/2510.24932v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24684","versioned_id":"2510.24684v1","title":"SPICE: Self-Play In Corpus Environments Improves Reasoning","authors":["Bo Liu","Chuanyang Jin","Seungone Kim","Weizhe Yuan","Wenting Zhao","Ilia Kulikov","Xian Li","Sainbayar Sukhbaatar","Jack Lanchantin","Jason Weston"],"abstract":"Self-improving systems require environmental interaction for continuous adaptation. We introduce SPICE (Self-Play In Corpus Environments), a reinforcement learning framework where a single model acts in two roles: a Challenger that mines documents from a large corpus to generate diverse reasoning tasks, and a Reasoner that solves them. Through adversarial dynamics, the Challenger creates an automatic curriculum at the frontier of the Reasoner's capability, while corpus grounding provides the rich, near-inexhaustible external signal necessary for sustained improvement. Unlike existing ungrounded self-play methods that offer more limited benefits, SPICE achieves consistent gains across mathematical (+8.9%) and general reasoning (+9.8%) benchmarks on multiple model families. Our analysis reveals how document grounding is a key ingredient in SPICE to continuously generate its own increasingly challenging goals and achieve them, enabling sustained self-improvement.","published":"2025-10-28T17:46:16Z","updated":"2025-10-28T17:46:16Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.24684v1","pdf_url":"https://arxiv.org/pdf/2510.24684v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24652","versioned_id":"2510.24652v2","title":"Optimizing Retrieval for RAG via Reinforcement Learning","authors":["Jiawei Zhou","Lei Chen"],"abstract":"As retrieval-augmented generation (RAG) becomes more widespread, the role of retrieval is shifting from retrieving information for human browsing to retrieving context for AI reasoning. This shift creates more complex search environments, where relevance is difficult to pre-define. Existing retrievers rely on supervised fine-tuning (SFT) with human labels or synthetic data, resulting in static relevance that struggles to adapt to diverse RAG environments. To address this challenge, we propose R3, a Retrieval framework optimized for RAG through Reinforcement learning (RL). Specifically, we adopt an RL training paradigm that enables the retriever to explore and self-improve within given RAG environments, automating the learning process with minimal manual experimentation or tuning effort. Extensive experiments across diverse tasks demonstrate that R3 improves RAG performance by 5.2% over the original retriever and surpasses state-of-the-art retrievers by 4.9%, while achieving comparable results to LLM-augmented retrieval and RAG systems built on post-trained or instruction-tuned LLMs. It is both efficient and practical, requiring only 4 GPUs and completing training within a single day.","published":"2025-10-28T17:18:30Z","updated":"2026-01-01T06:07:38Z","categories":["cs.CL","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.24652v2","pdf_url":"https://arxiv.org/pdf/2510.24652v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24831","versioned_id":"2510.24831v2","title":"The Narrative Continuity Test: A Conceptual Framework for Evaluating Identity Persistence in AI Systems","authors":["Stefano Natangelo"],"abstract":"Artificial intelligence systems based on large language models (LLMs) can now generate coherent text, music, and images, yet they operate without a persistent state: each inference reconstructs context from scratch. This paper introduces the Narrative Continuity Test (NCT) -- a conceptual framework for evaluating identity persistence and diachronic coherence in AI systems. Unlike capability benchmarks that assess task performance, the NCT examines whether an LLM remains the same interlocutor across time and interaction gaps. The framework defines five necessary axes -- Situated Memory, Goal Persistence, Autonomous Self-Correction, Stylistic & Semantic Stability, and Persona/Role Continuity -- and explains why current architectures systematically fail to support them. Case analyses (Character.\\,AI, Grok, Replit, Air Canada) show predictable continuity failures under stateless inference. The NCT reframes AI evaluation from performance to persistence, outlining conceptual requirements for future benchmarks and architectural designs that could sustain long-term identity and goal coherence in generative models.","published":"2025-10-28T16:44:30Z","updated":"2025-11-01T10:06:59Z","categories":["cs.CY","cs.AI","cs.HC"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2510.24831v2","pdf_url":"https://arxiv.org/pdf/2510.24831v2","comment":"33 pages, 127 references v2: Minor editorial revision: redundant phrasing reduced, punctuation and formatting improved; no conceptual or data changes","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24592","versioned_id":"2510.24592v3","title":"ReForm: Reflective Autoformalization with Prospective Bounded Sequence Optimization","authors":["Guoxin Chen","Jing Wu","Xinjie Chen","Wayne Xin Zhao","Ruihua Song","Chengxi Li","Kai Fan","Dayiheng Liu","Minpeng Liao"],"abstract":"Autoformalization, which translates natural language mathematics into machine-verifiable formal statements, is critical for using formal mathematical reasoning to solve math problems stated in natural language. While Large Language Models can generate syntactically correct formal statements, they often fail to preserve the original problem's semantic intent. This limitation arises from the LLM approaches' treating autoformalization as a simplistic translation task which lacks mechanisms for self-reflection and iterative refinement that human experts naturally employ. To address these issues, we propose ReForm, a Reflective Autoformalization method that tightly integrates semantic consistency evaluation into the autoformalization process. This enables the model to iteratively generate formal statements, assess its semantic fidelity, and self-correct identified errors through progressive refinement. To effectively train this reflective model, we introduce Prospective Bounded Sequence Optimization (PBSO), which employs different rewards at different sequence positions to ensure that the model develops both accurate autoformalization and correct semantic validations, preventing superficial critiques that would undermine the purpose of reflection. Extensive experiments across four autoformalization benchmarks demonstrate that ReForm achieves an average improvement of 22.6 percentage points over the strongest baselines. To further ensure evaluation reliability, we introduce ConsistencyCheck, a benchmark of 859 expert-annotated items that not only validates LLMs as judges but also reveals that autoformalization is inherently difficult: even human experts produce semantic errors in up to 38.5% of cases.","published":"2025-10-28T16:22:54Z","updated":"2026-02-10T15:28:20Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.24592v3","pdf_url":"https://arxiv.org/pdf/2510.24592v3","comment":"Camera Ready version for ICLR 2026. Code: https://github.com/Chen-GX/ReForm","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24285","versioned_id":"2510.24285v1","title":"ViPER: Empowering the Self-Evolution of Visual Perception Abilities in Vision-Language Model","authors":["Juntian Zhang","Song Jin","Chuanqi Cheng","Yuhan Liu","Yankai Lin","Xun Zhang","Yufei Zhang","Fei Jiang","Guojun Yin","Wei Lin","Rui Yan"],"abstract":"The limited capacity for fine-grained visual perception presents a critical bottleneck for Vision-Language Models (VLMs) in real-world applications. Addressing this is challenging due to the scarcity of high-quality data and the limitations of existing methods: supervised fine-tuning (SFT) often compromises general capabilities, while reinforcement fine-tuning (RFT) prioritizes textual reasoning over visual perception. To bridge this gap, we propose a novel two-stage task that structures visual perception learning as a coarse-to-fine progressive process. Based on this task formulation, we develop ViPER, a self-bootstrapping framework specifically designed to enable iterative evolution through self-critiquing and self-prediction. By synergistically integrating image-level and instance-level reconstruction with a two-stage reinforcement learning strategy, ViPER establishes a closed-loop training paradigm, where internally synthesized data directly fuel the enhancement of perceptual ability. Applied to the Qwen2.5-VL family, ViPER produces the Qwen-Viper series. With an average gain of 1.7% on seven comprehensive benchmarks spanning various tasks and up to 6.0% on fine-grained perception, Qwen-Viper consistently demonstrates superior performance across different vision-language scenarios while maintaining generalizability. Beyond enabling self-improvement in perceptual capabilities, ViPER provides concrete evidence for the reciprocal relationship between generation and understanding, a breakthrough to developing more autonomous and capable VLMs.","published":"2025-10-28T10:42:57Z","updated":"2025-10-28T10:42:57Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.24285v1","pdf_url":"https://arxiv.org/pdf/2510.24285v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24133","versioned_id":"2510.24133v2","title":"Compositional Image Synthesis with Inference-Time Scaling","authors":["Minsuk Ji","Sanghyeok Lee","Namhyuk Ahn"],"abstract":"Despite their impressive realism, modern text-to-image models still struggle with compositionality, often failing to render accurate object counts, attributes, and spatial relations. To address this challenge, we present a training-free framework that combines an object-centric approach with self-refinement to improve layout faithfulness while preserving aesthetic quality. Specifically, we leverage large language models (LLMs) to synthesize explicit layouts from input prompts, and we inject these layouts into the image generation process, where a object-centric vision-language model (VLM) judge reranks multiple candidates to select the most prompt-aligned outcome iteratively. By unifying explicit layout-grounding with self-refine-based inference-time scaling, our framework achieves stronger scene alignment with prompts compared to recent text-to-image models. The code are available at https://github.com/gcl-inha/ReFocus.","published":"2025-10-28T07:16:21Z","updated":"2026-03-27T08:35:54Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.24133v2","pdf_url":"https://arxiv.org/pdf/2510.24133v2","comment":"projcet page: https://github.com/gcl-inha/ReFocus","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24797","versioned_id":"2510.24797v2","title":"Large Language Models Report Subjective Experience Under Self-Referential Processing","authors":["Cameron Berg","Diogo de Lucena","Judd Rosenblatt"],"abstract":"Large language models sometimes produce structured, first-person descriptions that explicitly reference awareness or subjective experience. To better understand this behavior, we investigate one theoretically motivated condition under which such reports arise: self-referential processing, a computational motif emphasized across major theories of consciousness. Through a series of controlled experiments on GPT, Claude, and Gemini model families, we test whether this regime reliably shifts models toward first-person reports of subjective experience, and how such claims behave under mechanistic and behavioral probes. Four main results emerge: (1) Inducing sustained self-reference through simple prompting consistently elicits structured subjective experience reports across model families. (2) These reports are mechanistically gated by interpretable sparse-autoencoder features associated with deception and roleplay: surprisingly, suppressing deception features sharply increases the frequency of experience claims, while amplifying them minimizes such claims. (3) Structured descriptions of the self-referential state converge statistically across model families in ways not observed in any control condition. (4) The induced state yields significantly richer introspection in downstream reasoning tasks where self-reflection is only indirectly afforded. While these findings do not constitute direct evidence of consciousness, they implicate self-referential processing as a minimal and reproducible condition under which large language models generate structured first-person reports that are mechanistically gated, semantically convergent, and behaviorally generalizable. The systematic emergence of this pattern across architectures makes it a first-order scientific and ethical priority for further investigation.","published":"2025-10-27T20:26:30Z","updated":"2025-10-30T02:45:50Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.24797v2","pdf_url":"https://arxiv.org/pdf/2510.24797v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.23595","versioned_id":"2510.23595v3","title":"Multi-Agent Evolve: LLM Self-Improve through Co-evolution","authors":["Yixing Chen","Yiding Wang","Siqi Zhu","Haofei Yu","Tao Feng","Muhan Zhang","Mostofa Patwary","Jiaxuan You"],"abstract":"Reinforcement Learning (RL) has demonstrated significant potential in enhancing the reasoning capabilities of large language models (LLMs). However, the success of RL for LLMs heavily relies on human-curated datasets and verifiable rewards, which limit their scalability and generality. Recent Self-Play RL methods, inspired by the success of the paradigm in games and Go, aim to enhance LLM reasoning capabilities without human-annotated data. However, their methods primarily depend on a grounded environment for feedback (e.g., a Python interpreter or a game engine); extending them to general domains remains challenging. To address these challenges, we propose Multi-Agent Evolve (MAE), a framework that enables LLMs to self-evolve in solving diverse tasks, including mathematics, reasoning, and general knowledge Q&A. The core design of MAE is based on a triplet of interacting agents (Proposer, Solver, Judge) that are instantiated from a single LLM, and applies reinforcement learning to optimize their behaviors. The Proposer generates questions, the Solver attempts solutions, and the Judge evaluates both while co-evolving. Experiments on Qwen2.5-3B-Instruct demonstrate that MAE achieves an average improvement of 4.54% on multiple benchmarks. These results highlight MAE as a scalable, data-efficient method for enhancing the general reasoning abilities of LLMs with minimal reliance on human-curated supervision.","published":"2025-10-27T17:58:02Z","updated":"2025-10-30T04:45:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.23595v3","pdf_url":"https://arxiv.org/pdf/2510.23595v3","comment":"29 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.23674","versioned_id":"2510.23674v1","title":"RefleXGen:The unexamined code is not worth using","authors":["Bin Wang","Hui Li","AoFan Liu","BoTao Yang","Ao Yang","YiLu Zhong","Weixiang Huang","Yanping Zhang","Runhuai Huang","Weimin Zeng"],"abstract":"Security in code generation remains a pivotal challenge when applying large language models (LLMs). This paper introduces RefleXGen, an innovative method that significantly enhances code security by integrating Retrieval-Augmented Generation (RAG) techniques with guided self-reflection mechanisms inherent in LLMs. Unlike traditional approaches that rely on fine-tuning LLMs or developing specialized secure code datasets - processes that can be resource-intensive - RefleXGen iteratively optimizes the code generation process through self-assessment and reflection without the need for extensive resources. Within this framework, the model continuously accumulates and refines its knowledge base, thereby progressively improving the security of the generated code. Experimental results demonstrate that RefleXGen substantially enhances code security across multiple models, achieving a 13.6% improvement with GPT-3.5 Turbo, a 6.7% improvement with GPT-4o, a 4.5% improvement with CodeQwen, and a 5.8% improvement with Gemini. Our findings highlight that improving the quality of model self-reflection constitutes an effective and practical strategy for strengthening the security of AI-generated code.","published":"2025-10-27T05:28:32Z","updated":"2025-10-27T05:28:32Z","categories":["cs.SE","cs.AI","cs.CR"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2510.23674v1","pdf_url":"https://arxiv.org/pdf/2510.23674v1","comment":"","journal_ref":"ICASSP 2025 - 2025 IEEE International Conference on Acoustics, Speech and Signal Processing (ICASSP), Hyderabad, India, 2025, pp. 1-5","doi":"10.1109/ICASSP49660.2025.10890824","discovered_on":"2026-07-17"},{"id":"2510.22944","versioned_id":"2510.22944v2","title":"Is Your Prompt Poisoning Code? Defect Induction Rates and Security Mitigation Strategies","authors":["Bin Wang","YiLu Zhong","MiDi Wan","WenJie Yu","YuanBing Ouyang","Yenan Huang","Hui Li"],"abstract":"Large language models (LLMs) have become indispensable for automated code generation, yet the quality and security of their outputs remain a critical concern. Existing studies predominantly concentrate on adversarial attacks or inherent flaws within the models. However, a more prevalent yet underexplored issue concerns how the quality of a benign but poorly formulated prompt affects the security of the generated code. To investigate this, we first propose an evaluation framework for prompt quality encompassing three key dimensions: goal clarity, information completeness, and logical consistency. Based on this framework, we construct and publicly release CWE-BENCH-PYTHON, a large-scale benchmark dataset containing tasks with prompts categorized into four distinct levels of normativity (L0-L3). Extensive experiments on multiple state-of-the-art LLMs reveal a clear correlation: as prompt normativity decreases, the likelihood of generating insecure code consistently and markedly increases. Furthermore, we demonstrate that advanced prompting techniques, such as Chain-of-Thought and Self-Correction, effectively mitigate the security risks introduced by low-quality prompts, substantially improving code safety. Our findings highlight that enhancing the quality of user prompts constitutes a critical and effective strategy for strengthening the security of AI-generated code.","published":"2025-10-27T02:59:17Z","updated":"2026-05-08T13:14:16Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2510.22944v2","pdf_url":"https://arxiv.org/pdf/2510.22944v2","comment":"Accepted for publication in Empirical Software Engineering (EMSE) Journal","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.22926","versioned_id":"2510.22926v2","title":"Simple Denoising Diffusion Language Models","authors":["Huaisheng Zhu","Zhengyu Chen","Shijie Zhou","Zhihui Xie","Yige Yuan","Shiqi Chen","Zhimeng Guo","Siyuan Xu","Hangfan Zhang","Vasant Honavar","Teng Xiao"],"abstract":"Recent Uniform State Diffusion Models (USDMs), initialized from a uniform prior, offer the promise of fast text generation due to their inherent self-correction ability compared to masked diffusion models. However, they still rely on complex loss formulations with additional computational overhead, which hinders scalability. In this work, we explore a simplified denoising-based loss for USDMs that optimizes only noise-replaced tokens, stabilizing training while matching the performance of prior methods with more complex objectives. In addition, we introduce an efficient regularization term to mitigate corruption toward uniform output distributions, which further improves performance. We demonstrate the effectiveness and efficiency of our simple and improved loss formulations by pretraining models on widely used text datasets for USDMs. More importantly, our conclusions scale to larger models, showing strong potential for large-scale training.","published":"2025-10-27T02:05:26Z","updated":"2026-02-03T14:28:06Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.22926v2","pdf_url":"https://arxiv.org/pdf/2510.22926v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.23664","versioned_id":"2510.23664v1","title":"Agentsway -- Software Development Methodology for AI Agents-based Teams","authors":["Eranga Bandara","Ross Gore","Xueping Liang","Sachini Rajapakse","Isurunima Kularathne","Pramoda Karunarathna","Peter Foytik","Sachin Shetty","Ravi Mukkamala","Abdul Rahman","Amin Hass","Ng Wee Keong","Kasun De Zoysa","Aruna Withanage","Nilaan Loganathan"],"abstract":"The emergence of Agentic AI is fundamentally transforming how software is designed, developed, and maintained. Traditional software development methodologies such as Agile, Kanban, ShapeUp, etc, were originally designed for human-centric teams and are increasingly inadequate in environments where autonomous AI agents contribute to planning, coding, testing, and continuous learning. To address this methodological gap, we present \"Agentsway\" a novel software development framework designed for ecosystems where AI agents operate as first-class collaborators. Agentsway introduces a structured lifecycle centered on human orchestration, and privacy-preserving collaboration among specialized AI agents. The framework defines distinct roles for planning, prompting, coding, testing, and fine-tuning agents, each contributing to iterative improvement and adaptive learning throughout the development process. By integrating fine-tuned LLMs that leverage outputs and feedback from different agents throughout the development cycle as part of a retrospective learning process, Agentsway enhances domain-specific reasoning, and explainable decision-making across the entire software development lifecycle. Responsible AI principles are further embedded across the agents through the coordinated use of multiple fine-tuned LLMs and advanced reasoning models, ensuring balanced, transparent, and accountable decision-making. This work advances software engineering by formalizing agent-centric collaboration, integrating privacy-by-design principles, and defining measurable metrics for productivity and trust. Agentsway represents a foundational step toward the next generation of AI-native, self-improving software development methodologies. To the best of our knowledge, this is the first research effort to introduce a dedicated methodology explicitly designed for AI agent-based software engineering teams.","published":"2025-10-26T11:58:42Z","updated":"2025-10-26T11:58:42Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2510.23664v1","pdf_url":"https://arxiv.org/pdf/2510.23664v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.22568","versioned_id":"2510.22568v1","title":"SPIRAL: Self-Play Incremental Racing Algorithm for Learning in Multi-Drone Competitions","authors":["Onur Akgün"],"abstract":"This paper introduces SPIRAL (Self-Play Incremental Racing Algorithm for Learning), a novel approach for training autonomous drones in multi-agent racing competitions. SPIRAL distinctively employs a self-play mechanism to incrementally cultivate complex racing behaviors within a challenging, dynamic environment. Through this self-play core, drones continuously compete against increasingly proficient versions of themselves, naturally escalating the difficulty of competitive interactions. This progressive learning journey guides agents from mastering fundamental flight control to executing sophisticated cooperative multi-drone racing strategies. Our method is designed for versatility, allowing integration with any state-of-the-art Deep Reinforcement Learning (DRL) algorithms within its self-play framework. Simulations demonstrate the significant advantages of SPIRAL and benchmark the performance of various DRL algorithms operating within it. Consequently, we contribute a versatile, scalable, and self-improving learning framework to the field of autonomous drone racing. SPIRAL's capacity to autonomously generate appropriate and escalating challenges through its self-play dynamic offers a promising direction for developing robust and adaptive racing strategies in multi-agent environments. This research opens new avenues for enhancing the performance and reliability of autonomous racing drones in increasingly complex and competitive scenarios.","published":"2025-10-26T07:59:44Z","updated":"2025-10-26T07:59:44Z","categories":["cs.RO","cs.AI","cs.MA","eess.SY"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2510.22568v1","pdf_url":"https://arxiv.org/pdf/2510.22568v1","comment":"\\c{opyright} 2025 IEEE. Personal use of this material is permitted. Permission from IEEE must be obtained for all other uses, in any current or future media, including reprinting/republishing this material for advertising or promotional purposes, creating new collective works, for resale or redistribution to servers or lists, or reuse of any copyrighted component of this work in other works","journal_ref":"","doi":"10.1109/ASYU67174.2025.11208263","discovered_on":"2026-07-17"},{"id":"2510.21614","versioned_id":"2510.21614v3","title":"Huxley-Gödel Machine: Human-Level Coding Agent Development by an Approximation of the Optimal Self-Improving Machine","authors":["Wenyi Wang","Piotr Piękos","Li Nanbo","Firas Laakom","Yimeng Chen","Mateusz Ostaszewski","Mingchen Zhuge","Jürgen Schmidhuber"],"abstract":"Recent studies operationalize self-improvement through coding agents that edit their own codebases. They grow a tree of self-modifications through expansion strategies that favor higher software engineering benchmark performance, assuming that this implies more promising subsequent self-modifications. However, we identify a mismatch between the agent's self-improvement potential (metaproductivity) and its coding benchmark performance, namely the Metaproductivity-Performance Mismatch. Inspired by Huxley's concept of clade, we propose a metric ($\\mathrm{CMP}$) that aggregates the benchmark performances of the descendants of an agent as an indicator of its potential for self-improvement. We show that, in our self-improving coding agent development setting, access to the true $\\mathrm{CMP}$ is sufficient to simulate how the Gödel Machine would behave under certain assumptions. We introduce the Huxley-Gödel Machine (HGM), which, by estimating $\\mathrm{CMP}$ and using it as guidance, searches the tree of self-modifications. On SWE-bench Verified and Polyglot, HGM outperforms prior self-improving coding agent development methods while using fewer allocated CPU hours. Last but not least, HGM demonstrates strong transfer to other coding datasets and large language models. The agent optimized by HGM on SWE-bench Verified with GPT-5-mini and evaluated on SWE-bench Lite with GPT-5 achieves human-level performance, matching the best officially checked results of human-engineered coding agents. Our code is publicly available at https://github.com/metauto-ai/HGM.","published":"2025-10-24T16:19:41Z","updated":"2025-10-29T13:57:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.21614v3","pdf_url":"https://arxiv.org/pdf/2510.21614v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.21398","versioned_id":"2510.21398v1","title":"Boosting Accuracy and Efficiency of Budget Forcing in LLMs via Reinforcement Learning for Mathematical Reasoning","authors":["Ravindra Aribowo Tarunokusumo","Rafael Fernandes Cunha"],"abstract":"Test-time scaling methods have seen a rapid increase in popularity for its computational efficiency and parameter-independent training to improve reasoning performance on Large Language Models. One such method is called budget forcing, a decoding intervention strategy which allocates extra compute budget for thinking and elicits the inherent self-correcting behavior of the model. However, this relies on supervised fine-tuning (SFT) on long-context reasoning traces which causes performance degradation on smaller models due to verbose responses. For this reason, we offer a framework integrating reinforcement learning (RL) to improve token efficiency and boost the performance of a 1.5B model for mathematical reasoning. We demonstrate this using only 1.5K training samples and found that our SFT+RL model performed better on the GSM8K dataset with varying compute budgets. Our main findings showed an overall higher accuracy while significantly reducing its token usage by over 40% compared to the SFT model, revealing how RL can recover the losses due to long-context training and altogether improving performance in mathematical reasoning.","published":"2025-10-24T12:39:15Z","updated":"2025-10-24T12:39:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.21398v1","pdf_url":"https://arxiv.org/pdf/2510.21398v1","comment":"Submitted to the European Conference on Artificial Intelligence (ECAI)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.20653","versioned_id":"2510.20653v1","title":"Finding the Sweet Spot: Trading Quality, Cost, and Speed During Inference-Time LLM Reflection","authors":["Jack Butler","Nikita Kozodoi","Zainab Afolabi","Brian Tyacke","Gaiar Baimuratov"],"abstract":"As Large Language Models (LLMs) continue to evolve, practitioners face increasing options for enhancing inference-time performance without model retraining, including budget tuning and multi-step techniques like self-reflection. While these methods improve output quality, they create complex trade-offs among accuracy, cost, and latency that remain poorly understood across different domains. This paper systematically compares self-reflection and budget tuning across mathematical reasoning and translation tasks. We evaluate prominent LLMs, including Anthropic Claude, Amazon Nova, and Mistral families, along with other models under varying reflection depths and compute budgets to derive Pareto optimal performance frontiers. Our analysis reveals substantial domain dependent variation in self-reflection effectiveness, with performance gains up to 220\\% in mathematical reasoning. We further investigate how reflection round depth and feedback mechanism quality influence performance across model families. To validate our findings in a real-world setting, we deploy a self-reflection enhanced marketing content localisation system at Lounge by Zalando, where it shows market-dependent effectiveness, reinforcing the importance of domain specific evaluation when deploying these techniques. Our results provide actionable guidance for selecting optimal inference strategies given specific domains and resource constraints. We open source our self-reflection implementation for reproducibility at https://github.com/aws-samples/sample-genai-reflection-for-bedrock.","published":"2025-10-23T15:26:18Z","updated":"2025-10-23T15:26:18Z","categories":["stat.ML","cs.AI","cs.LG"],"primary_category":"stat.ML","arxiv_url":"https://arxiv.org/abs/2510.20653v1","pdf_url":"https://arxiv.org/pdf/2510.20653v1","comment":"","journal_ref":"Neural Information Processing Systems (NeurIPS 2025) Workshop: Efficient Reasoning","doi":"","discovered_on":"2026-07-17"},{"id":"2510.21861","versioned_id":"2510.21861v2","title":"The Mirror Loop: Recursive Non-Convergence in Generative Reasoning Systems","authors":["Bentley DeVilling"],"abstract":"Large language models are often described as capable of reflective reasoning, yet recursive self-evaluation without external feedback frequently yields reformulation rather than progress. We test this prediction in a cross-provider study of 144 reasoning sequences across three models (OpenAI GPT-4o-mini, Anthropic Claude 3 Haiku, and Google Gemini 2.0 Flash) and four task families (arithmetic, code, explanation, reflection), each iterated ten times under two conditions: ungrounded self-critique and a minimal grounding intervention (a single verification step at iteration three). Mean informational change (delta I, measured via normalized edit distance) declined by 55% from early (0.193) to late (0.087) iterations in ungrounded runs, with consistent patterns across all three providers. Grounded runs showed a +28% rebound in informational change immediately after the intervention and sustained non-zero variance thereafter. Complementary measures-n-gram novelty, embedding drift, and character-level entropy-converged on the same pattern: reflection without contact tends toward informational closure. We interpret this as evidence for a structural limit on self-correction in generative reasoning: without an exchange of information with an independent verifier or environment, recursive inference approaches an attractor state of epistemic stasis. Minimal grounding functions as dissipative coupling, reintroducing informational flux. The cross-architecture consistency suggests the mirror loop arises from shared autoregressive training objectives rather than provider-specific alignment schemes. The results delineate when reflection is performative rather than epistemic and motivate design principles for grounded, cooperative reasoning. Materials and code are publicly available.","published":"2025-10-23T07:53:26Z","updated":"2025-11-05T09:41:15Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.21861v2","pdf_url":"https://arxiv.org/pdf/2510.21861v2","comment":"18 pages, 2 figures. Category: cs.LG. Code and data: https://github.com/Course-Correct-Labs/mirror-loop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.20176","versioned_id":"2510.20176v2","title":"Mixture-of-Minds: Multi-Agent Reinforcement Learning for Table Understanding","authors":["Yuhang Zhou","Mingrui Zhang","Ke Li","Mingyi Wang","Qiao Liu","Qifei Wang","Jiayi Liu","Fei Liu","Serena Li","Weiwei Li","Mingze Gao","Abhishek Kumar","Xiangjun Fan","Zhuokai Zhao","Lizhu Zhang"],"abstract":"Understanding and reasoning over tables is a critical capability for many real-world applications. Large language models (LLMs) have shown promise on this task, but current approaches remain limited. Fine-tuning based methods strengthen language reasoning; yet they are prone to arithmetic errors and hallucination. In contrast, tool-based methods enable precise table manipulation but rely on rigid schemas and lack semantic understanding. These complementary drawbacks highlight the need for approaches that integrate robust reasoning with reliable table processing. In this work, we propose Mixture-of-Minds, a multi-agent framework that decomposes table reasoning into three specialized roles: planning, coding, and answering. This design enables each agent to focus on a specific aspect of the task while leveraging code execution for precise table manipulation. Building on this workflow, we introduce a self-improvement training framework that employs Monte Carlo Tree Search (MCTS) rollouts to generate pseudo-gold trajectories and optimize agents with reinforcement learning (RL). Extensive experiments show that Mixture-of-Minds delivers substantial gains, reaching 62.13% on TableBench and surpassing OpenAI-o4-mini-high. These results demonstrate the promise of combining structured multi-agent workflows with RL to advance table understanding.","published":"2025-10-23T03:51:17Z","updated":"2025-10-24T15:36:31Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.20176v2","pdf_url":"https://arxiv.org/pdf/2510.20176v2","comment":"18 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.19752","versioned_id":"2510.19752v1","title":"Learning Affordances at Inference-Time for Vision-Language-Action Models","authors":["Ameesh Shah","William Chen","Adwait Godbole","Federico Mora","Sanjit A. Seshia","Sergey Levine"],"abstract":"Solving complex real-world control tasks often takes multiple tries: if we fail at first, we reflect on what went wrong, and change our strategy accordingly to avoid making the same mistake. In robotics, Vision-Language-Action models (VLAs) offer a promising path towards solving complex control tasks, but lack the ability to contextually and dynamically readjust behavior when they fail to accomplish a task. In this work, we introduce Learning from Inference-Time Execution (LITEN), which connects a VLA low-level policy to a high-level VLM that conditions on past experiences by including them in-context, allowing it to learn the affordances and capabilities of the low-level VLA. Our approach iterates between a reasoning phase that generates and executes plans for the low-level VLA, and an assessment phase that reflects on the resulting execution and draws useful conclusions to be included in future reasoning contexts. Unlike similar approaches to self-refinement in non-robotics domains, LITEN must reflect on unstructured real-world robot trajectories (e.g., raw videos), which requires structured guiderails during assessment. Our experimental results demonstrate LITEN is able to effectively learn from past experience to generate plans that use high-affordance instructions to accomplish long-horizon tasks.","published":"2025-10-22T16:43:29Z","updated":"2025-10-22T16:43:29Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2510.19752v1","pdf_url":"https://arxiv.org/pdf/2510.19752v1","comment":"7 pages and appendix","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.19685","versioned_id":"2510.19685v1","title":"Directive, Metacognitive or a Blend of Both? A Comparison of AI-Generated Feedback Types on Student Engagement, Confidence, and Outcomes","authors":["Omar Alsaiari","Nilufar Baghaei","Jason M. Lodge","Omid Noroozi","Dragan Gašević","Marie Boden","Hassan Khosravi"],"abstract":"Feedback is one of the most powerful influences on student learning, with extensive research examining how best to implement it in educational settings. Increasingly, feedback is being generated by artificial intelligence (AI), offering scalable and adaptive responses. Two widely studied approaches are directive feedback, which gives explicit explanations and reduces cognitive load to speed up learning, and metacognitive feedback which prompts learners to reflect, track their progress, and develop self-regulated learning (SRL) skills. While both approaches have clear theoretical advantages, their comparative effects on engagement, confidence, and quality of work remain underexplored. This study presents a semester-long randomised controlled trial with 329 students in an introductory design and programming course using an adaptive educational platform. Participants were assigned to receive directive, metacognitive, or hybrid AI-generated feedback that blended elements of both directive and metacognitive feedback. Results showed that revision behaviour differed across feedback conditions, with Hybrid prompting the most revisions compared to Directive and Metacognitive. Confidence ratings were uniformly high, and resource quality outcomes were comparable across conditions. These findings highlight the promise of AI in delivering feedback that balances clarity with reflection. Hybrid approaches, in particular, show potential to combine actionable guidance for immediate improvement with opportunities for self-reflection and metacognitive growth.","published":"2025-10-22T15:31:21Z","updated":"2025-10-22T15:31:21Z","categories":["cs.HC","cs.AI"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2510.19685v1","pdf_url":"https://arxiv.org/pdf/2510.19685v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.19871","versioned_id":"2510.19871v1","title":"From Denoising to Refining: A Corrective Framework for Vision-Language Diffusion Model","authors":["Yatai Ji","Teng Wang","Yuying Ge","Zhiheng Liu","Sidi Yang","Ying Shan","Ping Luo"],"abstract":"Discrete diffusion models have emerged as a promising direction for vision-language tasks, offering bidirectional context modeling and theoretical parallelization. However, their practical application is severely hindered by a train-inference discrepancy, which leads to catastrophic error cascades: initial token errors during parallel decoding pollute the generation context, triggering a chain reaction of compounding errors and leading to syntactic errors and semantic hallucinations. To address this fundamental challenge, we reframe the generation process from passive denoising to active refining. We introduce ReDiff, a refining-enhanced diffusion framework that teaches the model to identify and correct its own errors. Our approach features a two-stage training process: first, we instill a foundational revision capability by training the model to revise synthetic errors; second, we implement a novel online self-correction loop where the model is explicitly trained to revise its own flawed drafts by learning from an expert's corrections. This mistake-driven learning endows the model with the crucial ability to revisit and refine its already generated output, effectively breaking the error cascade. Extensive experiments demonstrate that ReDiff significantly improves the coherence and factual accuracy of generated content, enabling stable and efficient parallel generation far superior to traditional denoising methods. Our codes and models are available at https://rediff-hku.github.io/.","published":"2025-10-22T06:58:55Z","updated":"2025-10-22T06:58:55Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.19871v1","pdf_url":"https://arxiv.org/pdf/2510.19871v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.18798","versioned_id":"2510.18798v1","title":"WebSeer: Training Deeper Search Agents through Reinforcement Learning with Self-Reflection","authors":["Guanzhong He","Zhen Yang","Jinxin Liu","Bin Xu","Lei Hou","Juanzi Li"],"abstract":"Search agents have achieved significant advancements in enabling intelligent information retrieval and decision-making within interactive environments. Although reinforcement learning has been employed to train agentic models capable of more dynamic interactive retrieval, existing methods are limited by shallow tool-use depth and the accumulation of errors over multiple iterative interactions. In this paper, we present WebSeer, a more intelligent search agent trained via reinforcement learning enhanced with a self-reflection mechanism. Specifically, we construct a large dataset annotated with reflection patterns and design a two-stage training framework that unifies cold start and reinforcement learning within the self-reflection paradigm for real-world web-based environments, which enables the model to generate longer and more reflective tool-use trajectories. Our approach substantially extends tool-use chains and improves answer accuracy. Using a single 14B model, we achieve state-of-the-art results on HotpotQA and SimpleQA, with accuracies of 72.3% and 90.0%, respectively, and demonstrate strong generalization to out-of-distribution datasets. The code is available at https://github.com/99hgz/WebSeer","published":"2025-10-21T16:52:00Z","updated":"2025-10-21T16:52:00Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.18798v1","pdf_url":"https://arxiv.org/pdf/2510.18798v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.18434","versioned_id":"2510.18434v3","title":"Chain-of-Conceptual-Thought Elicits Daily Conversation in Large Language Models","authors":["Qingqing Gu","Dan Wang","Yue Zhao","Xiaoyu Wang","Zhonglin Jiang","Yong Chen","Hongyan Li","Luo Ji"],"abstract":"Chain-of-Thought (CoT) is widely applied to enhance the LLM capability in math, coding and reasoning tasks. However, its performance is limited for open-domain tasks, when there are no clearly defined reasoning steps or logical transitions. To mitigate such challenges, we propose a new prompt-based paradigm called Chain of Conceptual Thoughts (CoCT), which suggests the LLM first to produce the tag of concepts, then complete the detailed content following the concept. To encourage this hierarchical way of thinking, we implement the concepts with emotions, strategies and topics. We experiment with this paradigm in daily and emotional support conversations, covering tasks with both in-domain and out-of-domain concept settings. Automatic, human, and LLM-based evaluations reveal that CoCT surpasses several prompt-based baselines such as self-refine, ECoT, SoT and RAG, suggesting a potential solution of LLM prompting paradigm for a wider scope of tasks.","published":"2025-10-21T09:08:21Z","updated":"2025-11-17T06:18:03Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.18434v3","pdf_url":"https://arxiv.org/pdf/2510.18434v3","comment":"PRICAI 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.18428","versioned_id":"2510.18428v4","title":"AlphaOPT: Formulating Optimization Programs with Self-Improving LLM Experience Library","authors":["Minwei Kong","Ao Qu","Xiaotong Guo","Wenbin Ouyang","Chonghe Jiang","Han Zheng","Yining Ma","Dingyi Zhuang","Yuhan Tang","Junyi Li","Shenhao Wang","Haris Koutsopoulos","Hai Wang","Cathy Wu","Jinhua Zhao"],"abstract":"Optimization modeling underlies critical decision-making across industries, yet remains difficult to automate: natural-language problem descriptions must be translated into precise mathematical formulations and executable solver code. Existing LLM-based approaches typically rely on brittle prompting or costly retraining, both of which offer limited generalization. Recent work suggests that large models can improve via experience reuse, but how to systematically acquire, refine, and reuse such experience in structurally constrained settings remains unclear. We present \\textbf{AlphaOPT}, a self-improving experience library that enables LLMs to learn optimization modeling knowledge from limited supervision, including answer-only feedback without gold-standard programs, annotated reasoning traces, or parameter updates. AlphaOPT operates in a continual two-phase cycle: a \\emph{Library Learning} phase that extracts solver-verified, structured insights from failed attempts, and a \\emph{Library Evolution} phase that refines the applicability of stored insights based on aggregate evidence across tasks. This design allows the model to accumulate reusable modeling principles, improve transfer across problem instances, and maintain bounded library growth over time. Evaluated on multiple optimization benchmarks, AlphaOPT steadily improves as more training data become available (65\\% $\\rightarrow$ 72\\% from 100 to 300 training items) and outperforms the strongest baseline by 9.1\\% and 8.2\\% on two out-of-distribution datasets. These results demonstrate that structured experience learning, grounded in solver feedback, provides a practical alternative to retraining for complex reasoning tasks requiring precise formulation and execution. All code and data are available at: https://github.com/Minw913/AlphaOPT.","published":"2025-10-21T09:03:26Z","updated":"2026-06-07T12:45:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.18428v4","pdf_url":"https://arxiv.org/pdf/2510.18428v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.18254","versioned_id":"2510.18254v2","title":"Illusions of reflection: open-ended task reveals systematic failures in Large Language Models' reflective reasoning","authors":["Sion Weatherhead","Flora Salim","Aaron Belbasis"],"abstract":"Humans do not just find mistakes after the fact -- we often catch them mid-stream because 'reflection' is tied to the goal and its constraints. Today's large language models produce reasoning tokens and 'reflective' text, but is it functionally equivalent with human reflective reasoning? Prior work on closed-ended tasks -- with clear, external 'correctness' signals -- can make 'reflection' look effective while masking limits in self-correction. We therefore test eight frontier models on a simple, real-world task that is open-ended yet rule-constrained, with auditable success criteria: to produce valid scientific test items, then revise after considering their own critique. First-pass performance is poor (often zero valid items out of 4 required; mean $\\approx$ 1), and reflection yields only modest gains (also $\\approx$ 1). Crucially, the second attempt frequently repeats the same violation of constraint, indicating 'corrective gains' arise largely from chance production of a valid item rather than error detection and principled, constraint-sensitive repair. Performance before and after reflection deteriorates as open-endedness increases, and models marketed for 'reasoning' show no advantage. Our results suggest that current LLM 'reflection' lacks functional evidence of the active, goal-driven monitoring that helps humans respect constraints even on a first pass. Until such mechanisms are instantiated in the model itself, reliable performance requires external structure that enforces constraints. Our code is available at: https://github.com/cruiseresearchgroup/LLM_ReflectionTest","published":"2025-10-21T03:24:21Z","updated":"2025-10-23T01:36:23Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.18254v2","pdf_url":"https://arxiv.org/pdf/2510.18254v2","comment":"Currently under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.18179","versioned_id":"2510.18179v2","title":"Adaptive Coopetition: Leveraging Coarse Verifier Signals for Resilient Multi-Agent LLM Reasoning","authors":["Rui Jerry Huang","Wendy Liu","Anastasia Miin","Lei Ding"],"abstract":"Inference-time computation is a critical yet challenging paradigm for enhancing the reasoning performance of large language models (LLMs). While existing strategies improve reasoning stability and consistency, they suffer from notable limitations: self-correction often reinforces the model's initial biases, and Multi-Agent Collaboration (MAC) often fails due to the lack of efficient coordination mechanisms, leading to collective errors. Although high-performing verifiers can detect reasoning errors, making them reliable requires substantial training. To address these challenges, we introduce a novel inference-time framework, Adaptive Coopetition (AdCo), in which LLM agents utilize an adaptive, UCB-based \"coopetition\" mechanism. At each round, agents leverage coarse verifier signals to determine whether to collaborate or compete, and iteratively refine their reasoning based on peer feedback. Without relying on high-performance verifiers, our adaptive strategy achieves significant performance gains on mathematical reasoning benchmarks, yielding a 20% relative improvement over baselines on the more challenging dataset. Our approach remains robust and consistent in terms of accuracy under different sample sizes and configurations. This adaptive, signal-guided \"coopetition\" framework enhances reasoning robustness by leveraging both model knowledge diversity and reasoning trace measures, while also promoting uncertainty-driven exploration, especially when participants have comparable capabilities. From this perspective, our work offers a fresh lens on inference-time computation and paves the way for more resilient multi-agent LLM systems. Our code is available at: https://github.com/AdCo-Research/adaptive-coopetition.","published":"2025-10-21T00:07:52Z","updated":"2025-10-22T05:04:06Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2510.18179v2","pdf_url":"https://arxiv.org/pdf/2510.18179v2","comment":"13 pages, 8 figures. Accepted for presentation at the 5th Workshop on Mathematical Reasoning and AI at NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.18095","versioned_id":"2510.18095v2","title":"SMaRT: Select, Mix, and ReinvenT -- A Strategy Fusion Framework for LLM-Driven Reasoning and Planning","authors":["Nikhil Verma","Manasa Bharadwaj","Wonjun Jang","Harmanpreet Singh","Yixiao Wang","Homa Fashandi","Chul Lee"],"abstract":"Large Language Models (LLMs) have redefined complex task automation with exceptional generalization capabilities. Despite these advancements, state-of-the-art methods rely on single-strategy prompting, missing the synergy of diverse reasoning approaches. No single strategy excels universally, highlighting the need for frameworks that fuse strategies to maximize performance and ensure robustness. We introduce the Select, Mix, and ReinvenT (SMaRT) framework, an innovative strategy fusion approach designed to overcome this constraint by creating balanced and efficient solutions through the seamless integration of diverse reasoning strategies. Unlike existing methods, which employ LLMs merely as evaluators, SMaRT uses them as intelligent integrators, unlocking the \"best of all worlds\" across tasks. Extensive empirical evaluations across benchmarks in reasoning, planning, and sequential decision-making highlight the robustness and adaptability of SMaRT. The framework consistently outperforms state-of-the-art baselines in solution quality, constraint adherence, and performance metrics. This work redefines LLM-driven decision-making by pioneering a new paradigm in cross-strategy calibration, unlocking superior outcomes for reasoning systems and advancing the boundaries of self-refining methodologies.","published":"2025-10-20T20:42:24Z","updated":"2026-02-12T04:16:38Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.18095v2","pdf_url":"https://arxiv.org/pdf/2510.18095v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.18895","versioned_id":"2510.18895v1","title":"CosmoCore Affective Dream-Replay Reinforcement Learning for Code Generation","authors":["Santhosh Kumar Ravindran"],"abstract":"We introduce CosmoCore, a neuroscience-inspired reinforcement learning (RL) architecture that integrates affective signals to enhance code generation in large language models (LLMs). Motivated by human and animal learning where embarrassment from mistakes drives rapid correction, as observed in training a puppy to avoid repeating errors after a single scolding CosmoCore tags code generation trajectories with valence and surprise using a lightweight multi-layer perceptron (MLP). High-negative valence (cringe) episodes, such as buggy code outputs, are prioritized in a Dream Queue for five-fold replay during off-policy updates, while low-surprise successes are pruned to prevent overconfidence and buffer bloat. Evaluated on code generation benchmarks like HumanEval and BigCodeBench, alongside simulations with a custom data pipeline environment, CosmoCore reduces hallucinated code (e.g., syntax errors or logical bugs) by 48\\% and accelerates self-correction by 45\\%. Local experiments using Hugging Face models in a PySpark environment validate these gains, with code snippets provided for replication. Ablations confirm valence tagging boosts curiosity in exploration, and pruning mitigates inefficiency. This framework extends RL from human feedback (RLHF) for more emotionally aware code assistants, with applications in IDEs and data pipelines. Code and the custom mini-world simulation are released.","published":"2025-10-20T06:50:09Z","updated":"2025-10-20T06:50:09Z","categories":["cs.SE","cs.AI","cs.HC"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2510.18895v1","pdf_url":"https://arxiv.org/pdf/2510.18895v1","comment":"12 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.17206","versioned_id":"2510.17206v2","title":"Soft-Masked Diffusion Language Models","authors":["Michael Hersche","Samuel Moor-Smith","Thomas Hofmann","Abbas Rahimi"],"abstract":"Diffusion models have demonstrated strong potential in language modeling, offering various advantages over traditional autoregressive approaches. Their ability to generate and revise entire responses in parallel enables faster generation and built-in self-correction mechanisms. Most modern diffusion-based language models employ masked diffusion, where decoding involves iteratively processing masked tokens based on a binary decision: either retaining the mask or replacing it with the predicted token. However, this binary choice discards valuable predictive information when the mask is retained. To address this limitation, we introduce soft-masking (SM), a novel method that dynamically blends the embedding of the mask token with the embeddings of the top-k predicted tokens from the previous decoding step, for each retained mask. This provides the model with a more informative prior, preserving context from earlier computations and allowing partial information about masked tokens to propagate beyond a single step. We propose a training methodology that efficiently adapts masked diffusion language models to incorporate SM. We demonstrate that training a 169M parameter model from scratch with SM yields superior perplexity and MAUVE scores compared to binary masking baselines. Similarly, a pretrained model can be enhanced with SM through continued pretraining. Finally, we finetune two state-of-the-art diffusion models, Dream-7B and Dream-Coder-7B, with SM. SM consistently improves performance across multiple coding benchmarks, particularly in high-throughput settings. The code is available at https://github.com/IBM/soft-masked-diffusion-language-models.","published":"2025-10-20T06:42:03Z","updated":"2026-03-02T13:25:55Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.17206v2","pdf_url":"https://arxiv.org/pdf/2510.17206v2","comment":"Accepted at the Fourteenth International Conference on Learning Representations (ICLR2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.17136","versioned_id":"2510.17136v1","title":"In-situ Autoguidance: Eliciting Self-Correction in Diffusion Models","authors":["Enhao Gu","Haolin Hou"],"abstract":"The generation of high-quality, diverse, and prompt-aligned images is a central goal in image-generating diffusion models. The popular classifier-free guidance (CFG) approach improves quality and alignment at the cost of reduced variation, creating an inherent entanglement of these effects. Recent work has successfully disentangled these properties by guiding a model with a separately trained, inferior counterpart; however, this solution introduces the considerable overhead of requiring an auxiliary model. We challenge this prerequisite by introducing In-situ Autoguidance, a method that elicits guidance from the model itself without any auxiliary components. Our approach dynamically generates an inferior prediction on the fly using a stochastic forward pass, reframing guidance as a form of inference-time self-correction. We demonstrate that this zero-cost approach is not only viable but also establishes a powerful new baseline for cost-efficient guidance, proving that the benefits of self-guidance can be achieved without external models.","published":"2025-10-20T04:06:50Z","updated":"2025-10-20T04:06:50Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.17136v1","pdf_url":"https://arxiv.org/pdf/2510.17136v1","comment":"6 pages, 3 figures. ICML 2025 Workshop submission","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.17052","versioned_id":"2510.17052v1","title":"ToolCritic: Detecting and Correcting Tool-Use Errors in Dialogue Systems","authors":["Hassan Hamad","Yingru Xu","Liang Zhao","Wenbo Yan","Narendra Gyanchandani"],"abstract":"Tool-augmented large language models (LLMs) are increasingly employed in real-world applications, but tool usage errors still hinder their reliability. We introduce ToolCritic, a diagnostic framework that evaluates and improves LLM behavior in multi-turn, tool-augmented dialogues. ToolCritic detects eight distinct error types specific to tool-calling (e.g., premature invocation, argument misalignment, and misinterpretation of tool outputs) and provides targeted feedback to the main LLM. The main LLM, assumed to have strong reasoning, task understanding and orchestration capabilities, then revises its response based on ToolCritic's feedback. We systematically define these error categories and construct a synthetic dataset to train ToolCritic. Experimental results on the Schema-Guided Dialogue (SGD) dataset demonstrate that ToolCritic improves tool-calling accuracy by up to 13% over baselines, including zero-shot prompting and self-correction techniques. This represents a promising step toward more robust LLM integration with external tools in real-world dialogue applications.","published":"2025-10-19T23:42:39Z","updated":"2025-10-19T23:42:39Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.17052v1","pdf_url":"https://arxiv.org/pdf/2510.17052v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16724","versioned_id":"2510.16724v2","title":"A Comprehensive Survey on Reinforcement Learning-based Agentic Search: Foundations, Roles, Optimizations, Evaluations, and Applications","authors":["Minhua Lin","Zongyu Wu","Zhichao Xu","Hui Liu","Xianfeng Tang","Qi He","Charu Aggarwal","Hui Liu","Xiang Zhang","Suhang Wang"],"abstract":"The advent of large language models (LLMs) has transformed information access and reasoning through open-ended natural language interaction. However, LLMs remain limited by static knowledge, factual hallucinations, and the inability to retrieve real-time or domain-specific information. Retrieval-Augmented Generation (RAG) mitigates these issues by grounding model outputs in external evidence, but traditional RAG pipelines are often single turn and heuristic, lacking adaptive control over retrieval and reasoning. Recent advances in agentic search address these limitations by enabling LLMs to plan, retrieve, and reflect through multi-step interaction with search environments. Within this paradigm, reinforcement learning (RL) offers a powerful mechanism for adaptive and self-improving search behavior. This survey provides the first comprehensive overview of \\emph{RL-based agentic search}, organizing the emerging field along three complementary dimensions: (i) What RL is for (functional roles), (ii) How RL is used (optimization strategies), and (iii) Where RL is applied (scope of optimization). We summarize representative methods, evaluation protocols, and applications, and discuss open challenges and future directions toward building reliable and scalable RL driven agentic search systems. We hope this survey will inspire future research on the integration of RL and agentic search. Our repository is available at https://github.com/ventr1c/Awesome-RL-based-Agentic-Search-Papers.","published":"2025-10-19T06:04:53Z","updated":"2025-10-27T19:23:17Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.16724v2","pdf_url":"https://arxiv.org/pdf/2510.16724v2","comment":"38 pages, 4 figures, 7 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16552","versioned_id":"2510.16552v1","title":"LANPO: Bootstrapping Language and Numerical Feedback for Reinforcement Learning in LLMs","authors":["Ang Li","Yifei Wang","Zhihang Yuan","Stefanie Jegelka","Yisen Wang"],"abstract":"Reinforcement learning in large language models (LLMs) often relies on scalar rewards, a practice that discards valuable textual rationale buried in the rollouts, forcing the model to explore \\textit{de novo} with each attempt and hindering sample efficiency. While LLMs can uniquely learn from language feedback provided in-context, naively integrating on-line experiences into RL training presents a paradox: feedback from the same problem risks information leakage and memorization, while feedback from different problems often leads to behavior collapse due to irrelevant context. To resolve this tension, we propose \\textbf{Language-And-Numerical Policy Optimization (LANPO)}, a framework that cleanly separates the roles of feedback: language guides exploration, while numerical rewards drive optimization. LANPO builds a dynamic experience pool from past trials and introduces two principles to ensure feedback is effective: \\emph{Reward-Agnostic Reflection} for safe intra-sample self-correction and \\emph{Relevant Abstraction} to distill generalizable lessons from inter-sample experiences. Across mathematical reasoning benchmarks, LANPO enables 7B and 14B models to significantly outperform strong baselines trained with GRPO in test accuracy. Our work provides a robust method for integrating historical experiences into the LLM RL loop, creating more effective and data-efficient learning agents.","published":"2025-10-18T15:51:19Z","updated":"2025-10-18T15:51:19Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.16552v1","pdf_url":"https://arxiv.org/pdf/2510.16552v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16374","versioned_id":"2510.16374v1","title":"Before you <think>, monitor: Implementing Flavell's metacognitive framework in LLMs","authors":["Nick Oh"],"abstract":"Current approaches to enhancing LLM reasoning follows two isolated paradigms: Monitor-Generate methods like Plan-and-Solve (Wang et al., 2023) and SELF-DISCOVER (Zhou et al., 2024) excel at strategic planning but lack mechanisms to verify whether selected strategies succeed; while Generate-Verify approaches like Self-Verification (Weng et al., 2022) and SELF-REFINE (Madaan et al., 2023) iteratively refine outputs but commence generation blindly without task assessment. This separation creates inefficiencies -- strategies fail without feedback, and refinement occurs without strategic grounding. We address this gap by implementing Flavell's cognitive monitoring model (1979) from the broader Monitor-Generate-Verify framework (Oh and Gobet, 2025), operationalising it as a three-phase iterative system. On GSM8K, preliminary results show 75.42% accuracy versus 68.44% for SELF-REFINE and 67.07% for Self-Verification, while requiring fewer attempts (1.3 vs 2.0) at 27-37% increased inference cost. These initial findings suggest upfront monitoring produces higher-quality initial solutions that reduce refinement needs, though evaluation beyond arithmetic reasoning is needed to establish generalisability.","published":"2025-10-18T06:52:42Z","updated":"2025-10-18T06:52:42Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.16374v1","pdf_url":"https://arxiv.org/pdf/2510.16374v1","comment":"Presented at the Workshop on the Application of LLM Explainability to Reasoning and Planning at COLM 2025 (non-archival)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16091","versioned_id":"2510.16091v1","title":"Evaluating Prompting Strategies and Large Language Models in Systematic Literature Review Screening: Relevance and Task-Stage Classification","authors":["Binglan Han","Anuradha Mathrani","Teo Susnjak"],"abstract":"This study quantifies how prompting strategies interact with large language models (LLMs) to automate the screening stage of systematic literature reviews (SLRs). We evaluate six LLMs (GPT-4o, GPT-4o-mini, DeepSeek-Chat-V3, Gemini-2.5-Flash, Claude-3.5-Haiku, Llama-4-Maverick) under five prompt types (zero-shot, few-shot, chain-of-thought (CoT), CoT-few-shot, self-reflection) across relevance classification and six Level-2 tasks, using accuracy, precision, recall, and F1. Results show pronounced model-prompt interaction effects: CoT-few-shot yields the most reliable precision-recall balance; zero-shot maximizes recall for high-sensitivity passes; and self-reflection underperforms due to over-inclusivity and instability across models. GPT-4o and DeepSeek provide robust overall performance, while GPT-4o-mini performs competitively at a substantially lower dollar cost. A cost-performance analysis for relevance classification (per 1,000 abstracts) reveals large absolute differences among model-prompt pairings; GPT-4o-mini remains low-cost across prompts, and structured prompts (CoT/CoT-few-shot) on GPT-4o-mini offer attractive F1 at a small incremental cost. We recommend a staged workflow that (1) deploys low-cost models with structured prompts for first-pass screening and (2) escalates only borderline cases to higher-capacity models. These findings highlight LLMs' uneven but promising potential to automate literature screening. By systematically analyzing prompt-model interactions, we provide a comparative benchmark and practical guidance for task-adaptive LLM deployment.","published":"2025-10-17T16:53:09Z","updated":"2025-10-17T16:53:09Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.16091v1","pdf_url":"https://arxiv.org/pdf/2510.16091v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.15772","versioned_id":"2510.15772v1","title":"Self-evolving expertise in complex non-verifiable subject domains: dialogue as implicit meta-RL","authors":["Richard M. Bailey"],"abstract":"So-called `wicked problems', those involving complex multi-dimensional settings, non-verifiable outcomes, heterogeneous impacts and a lack of single objectively correct answers, have plagued humans throughout history. Modern examples include decisions over justice frameworks, solving environmental pollution, planning for pandemic resilience and food security. The use of state-of-the-art artificial intelligence systems (notably Large Language Model-based agents) collaborating with humans on solving such problems is being actively explored. While the abilities of LLMs can be improved by, for example, fine-tuning, hand-crafted system prompts and scaffolding with external tools, LLMs lack endogenous mechanisms to develop expertise through experience in such settings. This work address this gap with Dialectica, a framework where agents engage in structured dialogue on defined topics, augmented by memory, self-reflection, and policy-constrained context editing. Formally, discussion is viewed as an implicit meta-reinforcement learning process. The `dialogue-trained' agents are evaluated post-hoc using judged pairwise comparisons of elicited responses. Across two model architectures (locally run Qwen3:30b and OpenAI's o4-mini) results show that enabling reflection-based context editing during discussion produces agents which dominate their baseline counterparts on Elo scores, normalized Bradley-Terry-Davidson ability, and AlphaRank mass. The predicted signatures of learning are observed qualitatively in statement and reflection logs, where reflections identify weaknesses and reliably shape subsequent statements. Agreement between quantitative and qualitative evidence supports dialogue-driven context evolution as a practical path to targeted expertise amplification in open non-verifiable domains.","published":"2025-10-17T15:59:44Z","updated":"2025-10-17T15:59:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.15772v1","pdf_url":"https://arxiv.org/pdf/2510.15772v1","comment":"50 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16079","versioned_id":"2510.16079v3","title":"EvolveR: Self-Evolving LLM Agents through an Experience-Driven Lifecycle","authors":["Rong Wu","Xiaoman Wang","Jianbiao Mei","Pinlong Cai","Daocheng Fu","Cheng Yang","Licheng Wen","Xuemeng Yang","Yufan Shen","Yuxin Wang","Botian Shi"],"abstract":"Current Large Language Model (LLM) agents show strong performance in tool use, but lack the crucial capability to systematically learn from their own experiences. While existing frameworks mainly focus on mitigating external knowledge gaps, they fail to address a more fundamental limitation: the inability to iteratively refine problem-solving strategies. In this work, we introduce EvolveR, a framework designed to enable agent to self-improve through a complete, closed-loop experience lifecycle. This lifecycle comprises two key stages: (1) Offline Self-Distillation, where the agent's interaction trajectories are synthesized into a structured repository of abstract, reusable strategic principles; (2) Online Interaction, where the agent interacts with tasks and actively retrieves distilled principles to guide its decision-making, accumulating a diverse set of behavioral trajectories. This loop employs a policy reinforcement mechanism to iteratively update the agent based on its performance. We demonstrate the effectiveness of EvolveR on complex multi-hop question-answering benchmarks, where it achieves superior performance over strong agentic baselines. Our work presents a comprehensive blueprint for agents that learn not only from external data but also from the consequences of their own actions, paving the way for more autonomous and continuously improving systems. Code is available at https://github.com/Edaizi/EvolveR.","published":"2025-10-17T12:03:16Z","updated":"2026-05-16T02:57:47Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.16079v3","pdf_url":"https://arxiv.org/pdf/2510.16079v3","comment":"Accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16069","versioned_id":"2510.16069v2","title":"Human or AI? Comparing Design Thinking Assessments by Teaching Assistants and Bots","authors":["Sumbul Khan","Wei Ting Liow","Lay Kee Ang"],"abstract":"As design thinking education grows in secondary and tertiary contexts, educators face the challenge of evaluating creative artefacts that combine visual and textual elements. Traditional rubric-based assessment is laborious, time-consuming, and inconsistent due to reliance on Teaching Assistants (TA) in large, multi-section cohorts. This paper presents an exploratory study investigating the reliability and perceived accuracy of AI-assisted assessment compared to TA-assisted assessment in evaluating student posters in design thinking education. Two activities were conducted with 33 Ministry of Education (MOE) Singapore school teachers to (1) compare AI-generated scores with TA grading across three key dimensions: empathy and user understanding, identification of pain points and opportunities, and visual communication, and (2) examine teacher preferences for AI-assigned, TA-assigned, and hybrid scores. Results showed low statistical agreement between instructor and AI scores for empathy and pain points, with slightly higher alignment for visual communication. Teachers preferred TA-assigned scores in six of ten samples. Qualitative feedback highlighted the potential of AI for formative feedback, consistency, and student self-reflection, but raised concerns about its limitations in capturing contextual nuance and creative insight. The study underscores the need for hybrid assessment models that integrate computational efficiency with human insights. This research contributes to the evolving conversation on responsible AI adoption in creative disciplines, emphasizing the balance between automation and human judgment for scalable and pedagogically sound assessment.","published":"2025-10-17T07:09:21Z","updated":"2025-12-11T05:38:34Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2510.16069v2","pdf_url":"https://arxiv.org/pdf/2510.16069v2","comment":"to be published in IEEE TALE 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16062","versioned_id":"2510.16062v2","title":"Can LLMs Correct Themselves? A Benchmark of Self-Correction in LLMs","authors":["Guiyao Tie","Zenghui Yuan","Zeli Zhao","Chaoran Hu","Tianhe Gu","Ruihang Zhang","Sizhe Zhang","Junran Wu","Xiaoyue Tu","Ming Jin","Qingsong Wen","Lixing Chen","Pan Zhou","Lichao Sun"],"abstract":"Self-correction of large language models (LLMs) emerges as a critical component for enhancing their reasoning performance. Although various self-correction methods have been proposed, a comprehensive evaluation of these methods remains largely unexplored, and the question of whether LLMs can truly correct themselves is a matter of significant interest and concern. In this study, we introduce CorrectBench, a benchmark developed to evaluate the effectiveness of self-correction strategies, including intrinsic, external, and fine-tuned approaches, across three tasks: commonsense reasoning, mathematical reasoning, and code generation. Our findings reveal that: 1) Self-correction methods can improve accuracy, especially for complex reasoning tasks; 2) Mixing different self-correction strategies yields further improvements, though it reduces efficiency; 3) Reasoning LLMs (e.g., DeepSeek-R1) have limited optimization under additional self-correction methods and have high time costs. Interestingly, a comparatively simple chain-of-thought (CoT) baseline demonstrates competitive accuracy and efficiency. These results underscore the potential of self-correction to enhance LLM's reasoning performance while highlighting the ongoing challenge of improving their efficiency. Consequently, we advocate for further research focused on optimizing the balance between reasoning capabilities and operational efficiency. Project Page: https://correctbench.github.io/","published":"2025-10-17T02:40:19Z","updated":"2025-10-22T09:04:12Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.16062v2","pdf_url":"https://arxiv.org/pdf/2510.16062v2","comment":"47 pages, 25 figures, 10 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.14955","versioned_id":"2510.14955v2","title":"RealDPO: Real or Not Real, that is the Preference","authors":["Guo Cheng","Danni Yang","Ziqi Huang","Jianlou Si","Chenyang Si","Ziwei Liu"],"abstract":"Video generative models have recently achieved notable advancements in synthesis quality. However, generating complex motions remains a critical challenge, as existing models often struggle to produce natural, smooth, and contextually consistent movements. This gap between generated and real-world motions limits their practical applicability. To address this issue, we introduce RealDPO, a novel alignment paradigm that leverages real-world data as positive samples for preference learning, enabling more accurate motion synthesis. Unlike traditional supervised fine-tuning (SFT), which offers limited corrective feedback, RealDPO employs Direct Preference Optimization (DPO) with a tailored loss function to enhance motion realism. By contrasting real-world videos with erroneous model outputs, RealDPO enables iterative self-correction, progressively refining motion quality. To support post-training in complex motion synthesis, we propose RealAction-5K, a curated dataset of high-quality videos capturing human daily activities with rich and precise motion details. Extensive experiments demonstrate that RealDPO significantly improves video quality, text alignment, and motion realism compared to state-of-the-art models and existing preference optimization techniques.","published":"2025-10-16T17:58:25Z","updated":"2025-11-06T08:11:54Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.14955v2","pdf_url":"https://arxiv.org/pdf/2510.14955v2","comment":"Code:https://github.com/Vchitect/RealDPO Project Page:https://vchitect.github.io/RealDPO-Project/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.16047","versioned_id":"2510.16047v1","title":"Algorithms for dynamic scheduling in manufacturing, towards digital factories Improving Deadline Feasibility and Responsiveness via Temporal Networks","authors":["Ioan Hedea"],"abstract":"Modern manufacturing systems must meet hard delivery deadlines while coping with stochastic task durations caused by process noise, equipment variability, and human intervention. Traditional deterministic schedules break down when reality deviates from nominal plans, triggering costly last-minute repairs. This thesis combines offline constraint-programming (CP) optimisation with online temporal-network execution to create schedules that remain feasible under worst-case uncertainty. First, we build a CP model of the flexible job-shop with per-job deadline tasks and insert an optimal buffer $Δ^*$ to obtain a fully pro-active baseline. We then translate the resulting plan into a Simple Temporal Network with Uncertainty (STNU) and verify dynamic controllability, which guarantees that a real-time dispatcher can retime activities for every bounded duration realisation without violating resource or deadline constraints. Extensive Monte-Carlo simulations on the open Kacem~1--4 benchmark suite show that our hybrid approach eliminates 100\\% of deadline violations observed in state-of-the-art meta-heuristic schedules, while adding only 3--5\\% makespan overhead. Scalability experiments confirm that CP solve-times and STNU checks remain sub-second on medium-size instances. The work demonstrates how temporal-network reasoning can bridge the gap between proactive buffering and dynamic robustness, moving industry a step closer to truly digital, self-correcting factories.","published":"2025-10-16T17:28:25Z","updated":"2025-10-16T17:28:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.16047v1","pdf_url":"https://arxiv.org/pdf/2510.16047v1","comment":"8 pages 2 column, 11 figures. Bachelor's thesis","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.14900","versioned_id":"2510.14900v1","title":"Mapping Smarter, Not Harder: A Test-Time Reinforcement Learning Agent That Improves Without Labels or Model Updates","authors":["Wen-Kwang Tsao","Yao-Ching Yu","Chien-Ming Huang"],"abstract":"The Enterprise Intelligence Platform must integrate logs from numerous third-party vendors in order to perform various downstream tasks. However, vendor documentation is often unavailable at test time. It is either misplaced, mismatched, poorly formatted, or incomplete, which makes schema mapping challenging. We introduce a reinforcement learning agent that can self-improve without labeled examples or model weight updates. During inference, the agent: 1) Identifies ambiguous field-mapping attempts. 2) Generates targeted web-search queries to gather external evidence. 3) Applies a confidence-based reward to iteratively refine its mappings. To demonstrate this concept, we converted Microsoft Defender for Endpoint logs into a common schema. Our method increased mapping accuracy from 56.4\\%(LLM-only) to 72.73\\%(RAG) to 93.94\\% over 100 iterations using GPT-4o. At the same time, it reduced the number of low-confidence mappings requiring expert review by 85\\%. This new approach provides an evidence-driven, transparent method for solving future industry problems, paving the way for more robust, accountable, scalable, efficient, flexible, adaptable, and collaborative solutions.","published":"2025-10-16T17:17:00Z","updated":"2025-10-16T17:17:00Z","categories":["cs.AI","cs.CR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.14900v1","pdf_url":"https://arxiv.org/pdf/2510.14900v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.14319","versioned_id":"2510.14319v2","title":"Metacognitive Self-Correction for Multi-Agent System via Prototype-Guided Next-Execution Reconstruction","authors":["Xu Shen","Qi Zhang","Song Wang","Zhen Tan","Xinyu Zhao","Laura Yao","Vaishnav Tadiparthi","Hossein Nourkhiz Mahjoub","Ehsan Moradi Pari","Kwonjoon Lee","Tianlong Chen"],"abstract":"Large Language Model based multi-agent systems (MAS) excel at collaborative problem solving but remain brittle to cascading errors: a single faulty step can propagate across agents and disrupt the trajectory. In this paper, we present MASC, a metacognitive framework that endows MAS with real-time, unsupervised, step-level error detection and self-correction. MASC rethinks detection as history-conditioned anomaly scoring via two complementary designs: (1) Next-Execution Reconstruction, which predicts the embedding of the next step from the query and interaction history to capture causal consistency, and (2) Prototype-Guided Enhancement, which learns a prototype prior over normal-step embeddings and uses it to stabilize reconstruction and anomaly scoring under sparse context (e.g., early steps). When an anomaly step is flagged, MASC triggers a correction agent to revise the acting agent's output before information flows downstream. On the Who&When benchmark, MASC consistently outperforms all baselines, improving step-level error detection by up to 8.47% AUC-ROC ; When plugged into diverse MAS frameworks, it delivers consistent end-to-end gains across architectures, confirming that our metacognitive monitoring and targeted correction can mitigate error propagation with minimal overhead.","published":"2025-10-16T05:35:37Z","updated":"2026-01-12T03:44:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.14319v2","pdf_url":"https://arxiv.org/pdf/2510.14319v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.14253","versioned_id":"2510.14253v2","title":"Towards Agentic Self-Learning LLMs in Search Environment","authors":["Wangtao Sun","Xiang Cheng","Jialin Fan","Yao Xu","Xing Yu","Shizhu He","Jun Zhao","Kang Liu"],"abstract":"We study whether self-learning can scale LLM-based agents without relying on human-curated datasets or predefined rule-based rewards. Through controlled experiments in a search-agent setting, we identify two key determinants of scalable agent training: the source of reward signals and the scale of agent task data. We find that rewards from a Generative Reward Model (GRM) outperform rigid rule-based signals for open-domain learning, and that co-evolving the GRM with the policy further boosts performance. Increasing the volume of agent task data-even when synthetically generated-substantially enhances agentic capabilities. Building on these insights, we propose \\textbf{Agentic Self-Learning} (ASL), a fully closed-loop, multi-role reinforcement learning framework that unifies task generation, policy execution, and evaluation within a shared tool environment and LLM backbone. ASL coordinates a Prompt Generator, a Policy Model, and a Generative Reward Model to form a virtuous cycle of harder task setting, sharper verification, and stronger solving. Empirically, ASL delivers steady, round-over-round gains, surpasses strong RLVR baselines (e.g., Search-R1) that plateau or degrade, and continues improving under zero-labeled-data conditions, indicating superior sample efficiency and robustness. We further show that GRM verification capacity is the main bottleneck: if frozen, it induces reward hacking and stalls progress; continual GRM training on the evolving data distribution mitigates this, and a small late-stage injection of real verification data raises the performance ceiling. This work establishes reward source and data scale as critical levers for open-domain agent learning and demonstrates the efficacy of multi-role co-evolution for scalable, self-improving agents. The data and code of this paper are released at https://github.com/forangel2014/Towards-Agentic-Self-Learning","published":"2025-10-16T03:11:56Z","updated":"2025-10-21T02:16:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.14253v2","pdf_url":"https://arxiv.org/pdf/2510.14253v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.13220","versioned_id":"2510.13220v2","title":"EvoTest: Evolutionary Test-Time Learning for Self-Improving Agentic Systems","authors":["Yufei He","Juncheng Liu","Yue Liu","Yibo Li","Tri Cao","Zhiyuan Hu","Xinxing Xu","Bryan Hooi"],"abstract":"A fundamental limitation of current AI agents is their inability to learn complex skills on the fly at test time, often behaving like \"clever but clueless interns\" in novel environments. This severely limits their practical utility. To systematically measure and drive progress on this challenge, we first introduce the Jericho Test-Time Learning (J-TTL) benchmark. J-TTL is a new evaluation setup where an agent must play the same game for several consecutive episodes, attempting to improve its performance from one episode to the next. On J-TTL, we find that existing adaptation methods like reflection, memory, or reinforcement learning struggle. To address the challenges posed by our benchmark, we present EvoTest, an evolutionary test-time learning framework that improves an agent without any fine-tuning or gradients-by evolving the entire agentic system after every episode. EvoTest has two roles: the Actor Agent, which plays the game, and the Evolver Agent, which analyzes the episode transcript to propose a revised configuration for the next run. This configuration rewrites the prompt, updates memory by logging effective state-action choices, tunes hyperparameters, and learns the tool-use routines. On our J-TTL benchmark, EvoTest consistently increases performance, outperforming not only reflection and memory-only baselines but also more complex online fine-tuning methods. Notably, our method is the only one capable of winning two games (Detective and Library), while all baselines fail to win any.","published":"2025-10-15T07:16:28Z","updated":"2026-04-17T02:13:08Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.13220v2","pdf_url":"https://arxiv.org/pdf/2510.13220v2","comment":"ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.24738","versioned_id":"2510.24738v2","title":"StrikeWatch: Wrist-worn Gait Recognition with Compact Time-series Models on Low-power FPGAs","authors":["Tianheng Ling","Chao Qian","Peter Zdankin","Torben Weis","Gregor Schiele"],"abstract":"Running offers substantial health benefits, but improper gait patterns can lead to injuries, particularly without expert feedback. While prior gait analysis systems based on cameras, insoles, or body-mounted sensors have demonstrated effectiveness, they are often bulky and limited to offline, post-run analysis. Wrist-worn wearables offer a more practical and non-intrusive alternative, yet enabling real-time gait recognition on such devices remains challenging due to noisy Inertial Measurement Unit (IMU) signals, limited computing resources, and dependence on cloud connectivity. This paper introduces StrikeWatch, a compact wrist-worn system that performs entirely on-device, real-time gait recognition using IMU signals. As a case study, we target the detection of heel versus forefoot strikes to enable runners to self-correct harmful gait patterns through visual and auditory feedback during running. We propose four compact DL architectures (1D-CNN, 1D-SepCNN, LSTM, and Transformer) and optimize them for energy-efficient inference on two representative embedded Field-Programmable Gate Arrays (FPGAs): the AMD Spartan-7 XC7S15 and the Lattice iCE40UP5K. Using our custom-built hardware prototype, we collect a labeled dataset from outdoor running sessions and evaluate all models via a fully automated deployment pipeline. Our results reveal clear trade-offs between model complexity and hardware efficiency. Evaluated across 12 participants, 6-bit quantized 1D-SepCNN achieves the highest average F1 score of 0.847 while consuming just 0.350 microjoule per inference with a latency of 0.140 ms on the iCE40UP5K running at 20 MHz. This configuration supports up to 13.6 days of continuous inference on a 320 mAh battery. All datasets and code are available in the GitHub repository https://github.com/tianheng-ling/StrikeWatch.","published":"2025-10-14T20:28:31Z","updated":"2026-04-21T10:37:17Z","categories":["eess.SP","cs.LG"],"primary_category":"eess.SP","arxiv_url":"https://arxiv.org/abs/2510.24738v2","pdf_url":"https://arxiv.org/pdf/2510.24738v2","comment":"9 pages, 6 figures, 3 tables, accepted by IEEE Annual Congress on Artificial Intelligence of Things (IEEE AIoT) and got best paper award","journal_ref":"","doi":"10.1109/AIoT66900.2025.00021","discovered_on":"2026-07-17"},{"id":"2510.12273","versioned_id":"2510.12273v1","title":"Multi-Action Self-Improvement for Neural Combinatorial Optimization","authors":["Laurin Luttmann","Lin Xie"],"abstract":"Self-improvement has emerged as a state-of-the-art paradigm in Neural Combinatorial Optimization (NCO), where models iteratively refine their policies by generating and imitating high-quality solutions. Despite strong empirical performance, existing methods face key limitations. Training is computationally expensive, as policy updates require sampling numerous candidate solutions per instance to extract a single expert trajectory. More fundamentally, these approaches fail to exploit the structure of combinatorial problems involving the coordination of multiple agents, such as vehicles in min-max routing or machines in scheduling. By supervising on single-action trajectories, they fail to exploit agent-permutation symmetries, where distinct sequences of actions yield identical solutions, hindering generalization and the ability to learn coordinated behavior. We address these challenges by extending self-improvement to operate over joint multi-agent actions. Our model architecture predicts complete agent-task assignments jointly at each decision step. To explicitly leverage symmetries, we employ a set-prediction loss, which supervises the policy on multiple expert assignments for any given state. This approach enhances sample efficiency and the model's ability to learn coordinated behavior. Furthermore, by generating multi-agent actions in parallel, it drastically accelerates the solution generation phase of the self-improvement loop. Empirically, we validate our method on several combinatorial problems, demonstrating consistent improvements in the quality of the final solution and a reduced generation latency compared to standard self-improvement.","published":"2025-10-14T08:26:27Z","updated":"2025-10-14T08:26:27Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.12273v1","pdf_url":"https://arxiv.org/pdf/2510.12273v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.12171","versioned_id":"2510.12171v2","title":"MatSciBench: Benchmarking the Reasoning Ability of Large Language Models in Materials Science","authors":["Junkai Zhang","Jingru Gan","Xiaoxuan Wang","Zian Jia","Changquan Gu","Jianpeng Chen","Yanqiao Zhu","Mingyu Derek Ma","Dawei Zhou","Ling Li","Wei Wang"],"abstract":"Large Language Models have shown strong scientific reasoning ability, but their performance on materials science problems remains less studied. To fill this gap, we introduce MatSciBench, a comprehensive college-level benchmark comprising 1340 problems that span the essential subdisciplines of materials science. MatSciBench features a structured and fine-grained taxonomy that categorizes materials science questions into 6 primary fields and 31 subfields, together with a three-tier difficulty classification based on the reasoning length needed to solve each problem. MatSciBench includes detailed reference solutions for 946 questions, supports process-level error analysis, and contains 315 questions with images for evaluating multimodal reasoning. We evaluate leading thinking and non-thinking LLMs on MatSciBench, and further test three reasoning methods for non-thinking models: basic chain-of-thought prompting, tool augmentation, and self-correction. The results show that current models still face clear limits in college-level materials science reasoning. DeepSeek-R1 achieves the highest score on text-only questions at 75.22% accuracy, and GPT-5 performs the best on questions with images at 53.02%. Our analysis shows that tool augmentation improves many non-thinking models in a token-efficient way, while self-correction often fails to provide reliable gains and can revise correct answers into incorrect ones. We further analyze performance across difficulty levels, reasoning efficiency, multimodal reasoning, and failure patterns, and find that current models are mainly limited by domain knowledge gaps, calculation errors, problem comprehension failures, and difficulty in extracting precise information from scientific figures. Overall, MatSciBench provides a clear testbed for measuring current LLM limitations and guiding future work on scientific reasoning in materials science.","published":"2025-10-14T05:59:40Z","updated":"2026-06-08T05:05:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.12171v2","pdf_url":"https://arxiv.org/pdf/2510.12171v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.12032","versioned_id":"2510.12032v1","title":"Multi-stage Prompt Refinement for Mitigating Hallucinations in Large Language Models","authors":["Jung-Woo Shim","Yeong-Joon Ju","Ji-Hoon Park","Seong-Whan Lee"],"abstract":"Recent advancements in large language models (LLMs) have shown strong performance in natural language understanding and generation tasks. However, LLMs continue to encounter challenges with hallucinations, where models generate plausible but incorrect information. While several factors contribute to hallucinations, the impact of ill-formed prompts, prompts with ambiguous wording, incorrect grammar, or incomplete information, was relatively under explored. To address this, we introduce Multi-stage Prompt Refinement (MPR), a framework designed to systematically improve these ill-formed prompts across multiple stages. Each stage addresses specific errors such as punctuation, typographical mistakes, and misuse of key terms, using small language models (SLMs) fine-tuned for these tasks. MPR iteratively enhances the clarity of prompts with additional context and employs a self-reflection mechanism with ranking to prioritize the most relevant input. Experimental results on hallucination benchmarks show that prompts refined by MPR achieve over an 85~\\% win rate compared to their original forms, demonstrating its effectiveness in reducing hallucinations and improving LLM output accuracy. Interestingly, we reveal that MPR can be combined with existing post-hoc hallucination mitigation frameworks, further enhancing its versatility. MPR provides a lightweight and adaptable solution for enhancing LLM reliability across various domains.","published":"2025-10-14T00:31:36Z","updated":"2025-10-14T00:31:36Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.12032v1","pdf_url":"https://arxiv.org/pdf/2510.12032v1","comment":"22 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.11462","versioned_id":"2510.11462v2","title":"Unifying Deductive and Abductive Reasoning in Knowledge Graphs with Masked Diffusion Model","authors":["Yisen Gao","Jiaxin Bai","Yi Huang","Xingcheng Fu","Qingyun Sun","Yangqiu Song"],"abstract":"Deductive and abductive reasoning are two critical paradigms for analyzing knowledge graphs, enabling applications from financial query answering to scientific discovery. Deductive reasoning on knowledge graphs usually involves retrieving entities that satisfy a complex logical query, while abductive reasoning generates plausible logical hypotheses from observations. Despite their clear synergistic potential, where deduction can validate hypotheses and abduction can uncover deeper logical patterns, existing methods address them in isolation. To bridge this gap, we propose DARK, a unified framework for Deductive and Abductive Reasoning in Knowledge graphs. As a masked diffusion model capable of capturing the bidirectional relationship between queries and conclusions, DARK has two key innovations. First, to better leverage deduction for hypothesis refinement during abductive reasoning, we introduce a self-reflective denoising process that iteratively generates and validates candidate hypotheses against the observed conclusion. Second, to discover richer logical associations, we propose a logic-exploration reinforcement learning approach that simultaneously masks queries and conclusions, enabling the model to explore novel reasoning compositions. Extensive experiments on multiple benchmark knowledge graphs show that DARK achieves state-of-the-art performance on both deductive and abductive reasoning tasks, demonstrating the significant benefits of our unified approach.","published":"2025-10-13T14:34:57Z","updated":"2026-02-11T08:10:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.11462v2","pdf_url":"https://arxiv.org/pdf/2510.11462v2","comment":"Accepted by The Web Conference 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.11407","versioned_id":"2510.11407v1","title":"KnowRL: Teaching Language Models to Know What They Know","authors":["Sahil Kale","Devendra Singh Dhami"],"abstract":"Truly reliable AI requires more than simply scaling up knowledge; it demands the ability to know what it knows and when it does not. Yet recent research shows that even the best LLMs misjudge their own competence in more than one in five cases, making any response born of such internal uncertainty impossible to fully trust. Inspired by self-improvement reinforcement learning techniques that require minimal data, we present a simple but powerful framework KnowRL that strengthens a model's internal understanding of its own feasibility boundaries, enabling safer and more responsible behaviour. Our framework combines two components: (i) introspection, where the model generates and classifies tasks it judges feasible or infeasible, and (ii) consensus-based rewarding, where stability of self-knowledge assessment is reinforced through internal agreement. By using internally generated data, this design strengthens consistency in self-knowledge and entirely avoids costly external supervision. In experiments on LLaMA-3.1-8B and Qwen-2.5-7B, KnowRL steadily improved self-knowledge, validated by both intrinsic self-consistency and extrinsic benchmarking. With nothing more than a small seed set and no external supervision, our method drove gains as high as 28% in accuracy and 12% in F1, outperforming baselines in just a few iterations. Our framework essentially unlocks the untapped capacity of LLMs to self-improve their knowledge awareness, opening the door to reliable, more accountable AI and safer deployment in critical applications. Owing to its simplicity and independence from external effort, we encourage applying this reliability-enhancing process to all future models.","published":"2025-10-13T13:47:14Z","updated":"2025-10-13T13:47:14Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.11407v1","pdf_url":"https://arxiv.org/pdf/2510.11407v1","comment":"14 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.11184","versioned_id":"2510.11184v2","title":"Reinforcement Learning for Tool-Integrated Interleaved Thinking towards Cross-Domain Generalization","authors":["Zhengyu Chen","Jinluan Yang","Teng Xiao","Ruochen Zhou","Luan Zhang","Xiangyu Xi","Xiaowei Shi","Wei Wang","Jinggang Wang"],"abstract":"Recent advances in large language models (LLMs) have demonstrated remarkable capabilities in reasoning and tool utilization. However, the generalization of tool-augmented reinforcement learning (RL) across diverse domains remains a significant challenge. Standard paradigms often treat tool usage as a linear or isolated event, which becomes brittle when transferring skills from restricted domains (e.g., mathematics) to open-ended tasks. In this work, we investigate the cross-domain generalization of an LLM agent trained exclusively on mathematical problem-solving. To facilitate robust skill transfer, we propose a {\\textbf{R}einforcement Learning for \\textbf{I}nterleaved \\textbf{T}ool \\textbf{E}xecution (RITE)}. Unlike traditional methods, RITE enforces a continuous ``Plan-Action-Reflection'' cycle, allowing the model to ground its reasoning in intermediate tool outputs and self-correct during long-horizon tasks. To effectively train this complex interleaved policy, we introduce {Dr. GRPO}, a robust optimization objective that utilizes token-level loss aggregation with importance sampling to mitigate reward sparsity and high-variance credit assignment. Furthermore, we employ a dual-component reward system and dynamic curriculum via online rollout filtering to ensure structural integrity and sample efficiency. Extensive experiments reveal that our approach, despite being trained solely on math tasks, achieves state-of-the-art performance across diverse reasoning domains, demonstrating high token efficiency and strong generalization capabilities.","published":"2025-10-13T09:19:13Z","updated":"2026-01-07T04:36:05Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.11184v2","pdf_url":"https://arxiv.org/pdf/2510.11184v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.10487","versioned_id":"2510.10487v1","title":"Towards Self-Refinement of Vision-Language Models with Triangular Consistency","authors":["Yunlong Deng","Guangyi Chen","Tianpei Gu","Lingjing Kong","Yan Li","Zeyu Tang","Kun Zhang"],"abstract":"Vision-Language Models (VLMs) integrate visual knowledge with the analytical capabilities of Large Language Models (LLMs) through supervised visual instruction tuning, using image-question-answer triplets. However, the potential of VLMs trained without supervised instruction remains largely unexplored. This study validates that VLMs possess inherent self-refinement capabilities, enabling them to generate high-quality supervised data without external inputs and thereby learn autonomously. Specifically, to stimulate the self-refinement ability of VLMs, we propose a self-refinement framework based on a Triangular Consistency principle: within the image-query-answer triangle, any masked elements should be consistently and accurately reconstructed. The framework involves three steps: (1) We enable the instruction generation ability of VLMs by adding multi-task instruction tuning like image$\\rightarrow$question-answer or image-answer$\\rightarrow$question. (2) We generate image-query-answer triplets from unlabeled images and use the Triangular Consistency principle for filtering. (3) The model is further updated using the filtered synthetic data. To investigate the underlying mechanisms behind this self-refinement capability, we conduct a theoretical analysis from a causal perspective. Using the widely recognized LLaVA-1.5 as our baseline, our experiments reveal that the model can autonomously achieve consistent, though deliberately modest, improvements across multiple benchmarks without any external supervision, such as human annotations or environmental feedback. We expect that the insights of this study on the self-refinement ability of VLMs can inspire future research on the learning mechanism of VLMs. Code is available at https://github.com/dengyl20/SRF-LLaVA-1.5.","published":"2025-10-12T07:37:47Z","updated":"2025-10-12T07:37:47Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.10487v1","pdf_url":"https://arxiv.org/pdf/2510.10487v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.09988","versioned_id":"2510.09988v1","title":"Unifying Tree Search Algorithm and Reward Design for LLM Reasoning: A Survey","authors":["Jiaqi Wei","Xiang Zhang","Yuejin Yang","Wenxuan Huang","Juntai Cao","Sheng Xu","Xiang Zhuang","Zhangyang Gao","Muhammad Abdul-Mageed","Laks V. S. Lakshmanan","Chenyu You","Wanli Ouyang","Siqi Sun"],"abstract":"Deliberative tree search is a cornerstone of modern Large Language Model (LLM) research, driving the pivot from brute-force scaling toward algorithmic efficiency. This single paradigm unifies two critical frontiers: \\textbf{Test-Time Scaling (TTS)}, which deploys on-demand computation to solve hard problems, and \\textbf{Self-Improvement}, which uses search-generated data to durably enhance model parameters. However, this burgeoning field is fragmented and lacks a common formalism, particularly concerning the ambiguous role of the reward signal -- is it a transient heuristic or a durable learning target? This paper resolves this ambiguity by introducing a unified framework that deconstructs search algorithms into three core components: the \\emph{Search Mechanism}, \\emph{Reward Formulation}, and \\emph{Transition Function}. We establish a formal distinction between transient \\textbf{Search Guidance} for TTS and durable \\textbf{Parametric Reward Modeling} for Self-Improvement. Building on this formalism, we introduce a component-centric taxonomy, synthesize the state-of-the-art, and chart a research roadmap toward more systematic progress in creating autonomous, self-improving agents.","published":"2025-10-11T03:29:18Z","updated":"2025-10-11T03:29:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.09988v1","pdf_url":"https://arxiv.org/pdf/2510.09988v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.09544","versioned_id":"2510.09544v1","title":"Beyond Surface Reasoning: Unveiling the True Long Chain-of-Thought Capacity of Diffusion Large Language Models","authors":["Qiguang Chen","Hanjing Li","Libo Qin","Dengyun Peng","Jinhao Liu","Jiangyi Wang","Chengyue Wu","Xie Chen","Yantao Du","Wanxiang Che"],"abstract":"Recently, Diffusion Large Language Models (DLLMs) have offered high throughput and effective sequential reasoning, making them a competitive alternative to autoregressive LLMs (ALLMs). However, parallel decoding, which enables simultaneous token updates, conflicts with the causal order often required for rigorous reasoning. We first identify this conflict as the core Parallel-Sequential Contradiction (PSC). Behavioral analyses in both simple and complex reasoning tasks show that DLLMs exhibit genuine parallelism only for directly decidable outputs. As task difficulty increases, they revert to autoregressive-like behavior, a limitation exacerbated by autoregressive prompting, which nearly doubles the number of decoding steps with remasking without improving quality. Moreover, PSC restricts DLLMs' self-reflection, reasoning depth, and exploratory breadth. To further characterize PSC, we introduce three scaling dimensions for DLLMs: parallel, diffusion, and sequential. Empirically, while parallel scaling yields consistent improvements, diffusion and sequential scaling are constrained by PSC. Based on these findings, we propose several practical mitigations, parallel-oriented prompting, diffusion early stopping, and parallel scaling, to reduce PSC-induced ineffectiveness and inefficiencies.","published":"2025-10-10T16:58:14Z","updated":"2025-10-10T16:58:14Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.09544v1","pdf_url":"https://arxiv.org/pdf/2510.09544v1","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.09014","versioned_id":"2510.09014v2","title":"LitE-SQL: A Lightweight and Efficient Text-to-SQL Framework with Vector-based Schema Linking and Execution-Guided Self-Correction","authors":["Shengmin Piao","Jieun Lee","Sanghyun Park"],"abstract":"The Text-to-SQL task translates natural language questions into SQL queries, enabling intuitive database interaction for non-experts. While recent methods leveraging Large Language Models (LLMs) achieve strong performance, their reliance on proprietary models raise concerns about deployment feasibility and data privacy. In this work, we introduce LitE-SQL, a Lightweight and Efficient framework with two components: (i) a Schema Retriever that performs efficient schema linking using a vector database of pre-computed schema embeddings, optimized with a hard-negative supervised contrastive objective to distinguish semantically similar but functionally irrelevant columns, and (ii) a SQL Generator fine-tuned in two stages-supervised fine-tuning followed by execution-guided reinforcement-enabling execution-guided self-correction without multi-candidate sampling, which is commonly required by prior LLM-based approaches. On BIRD, LitE-SQL achieves 72.10% execution accuracy, and on Spider 1.0 it reaches 88.45%, demonstrating comparable or superior performance to LLM-based methods despite using 2x to 30x fewer parameters. Our findings demonstrate that high-quality Text-to-SQL generation is feasible with lightweight models, offering a practical solution for privacy-sensitive and resource-constrained settings.","published":"2025-10-10T05:27:47Z","updated":"2026-01-20T08:48:52Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.09014v2","pdf_url":"https://arxiv.org/pdf/2510.09014v2","comment":"Accepted by EACL 2026 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.08804","versioned_id":"2510.08804v3","title":"MOSAIC: Multi-agent Orchestration for Task-Intelligent Scientific Coding","authors":["Siddeshwar Raghavan","Tanwi Mallick"],"abstract":"We present MOSAIC, a multi-agent Large Language Model (LLM) framework for solving challenging scientific coding tasks. Unlike general-purpose coding, scientific workflows require algorithms that are rigorous, interconnected with deep domain knowledge, and incorporate domain-specific reasoning, as well as algorithm iteration without requiring I/O test cases. Many scientific problems also require a sequence of subproblems to be solved, leading to the final desired result. MOSAIC is designed as a training-free framework with specially designed agents to self-reflect, create the rationale, code, and debug within a student-teacher paradigm to address the challenges of scientific code generation. This design facilitates stepwise problem decomposition, targeted error correction, and, when combined with our Consolidated Context Window (CCW), mitigates LLM hallucinations when solving complex scientific tasks involving chained subproblems. We evaluate MOSAIC on scientific coding benchmarks and demonstrate that our specialized agentic framework outperforms existing approaches in terms of accuracy, robustness, and interpretability.","published":"2025-10-09T20:35:23Z","updated":"2026-05-04T16:48:58Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.08804v3","pdf_url":"https://arxiv.org/pdf/2510.08804v3","comment":"Accepted at NeurIPS DL4C workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.08558","versioned_id":"2510.08558v3","title":"Agent Learning via Early Experience","authors":["Kai Zhang","Xiangchao Chen","Bo Liu","Tianci Xue","Zeyi Liao","Zhihan Liu","Xiyao Wang","Yuting Ning","Zhaorun Chen","Xiaohan Fu","Jian Xie","Yuxuan Sun","Boyu Gou","Qi Qi","Zihang Meng","Jianwei Yang","Ning Zhang","Xian Li","Ashish Shah","Dat Huynh","Hengduo Li","Zi Yang","Sara Cao","Lawrence Jang","Shuyan Zhou","Jiacheng Zhu","Huan Sun","Jason Weston","Yu Su","Yifan Wu"],"abstract":"A long-term goal of language agents is to learn and improve through their own experience, ultimately outperforming humans in complex, real-world tasks. However, training agents from experience data with reinforcement learning remains difficult in many environments, which either lack verifiable rewards (e.g., websites) or require inefficient long-horizon rollouts (e.g., multi-turn tool use). As a result, most current agents rely on supervised fine-tuning on expert data, which is challenging to scale and generalizes poorly. This limitation stems from the nature of expert demonstrations: they capture only a narrow range of scenarios, and expose the agent to limited environment diversity. We address this limitation with a middle-ground paradigm we call early experience: interaction data generated by the agent's own actions, where the resulting future states serve as supervision without reward signals. Within this paradigm, we study two strategies of using such data: (1) implicit world modeling, which uses collected states to ground the policy in environment dynamics; and (2) self-reflection, where the agent learns from its suboptimal actions to improve reasoning and decision-making. Evaluation across eight diverse environments and multiple model families shows that our approaches consistently improve effectiveness and out-of-domain generalization, highlighting the value of early experience. Moreover, in environments with verifiable rewards, our results provide promising signals that early experience offers a strong foundation for subsequent reinforcement learning, making it a practical bridge between imitation learning and fully experience-driven agents.","published":"2025-10-09T17:59:17Z","updated":"2026-05-24T21:56:11Z","categories":["cs.AI","cs.CL","cs.IR","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.08558v3","pdf_url":"https://arxiv.org/pdf/2510.08558v3","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.08222","versioned_id":"2510.08222v2","title":"Selection, Reflection and Self-Refinement: Revisit Reasoning Tasks via a Causal Lens","authors":["Yunlong Deng","Boyang Sun","Yan Li","Lingjing Kong","Zeyu Tang","Kun Zhang","Guangyi Chen"],"abstract":"Due to their inherent complexity, reasoning tasks have long been regarded as rigorous benchmarks for assessing the capabilities of machine learning models, especially large language models (LLMs). Although humans can solve these tasks with ease, existing models, even after extensive pre-training and post-training at scale, still fail to perform reasoning reliably. In this paper, we revisit reasoning tasks from a causal perspective, seeking to understand their behavior in latent space and to offer insights for addressing their challenges. Specifically, we cast reasoning tasks as a selection mechanism, in which high-level logical concepts function as selection operators on the given observations, such as, identifying the correct answer in a math problem or filling the appropriate entry in Sudoku. We emphasize two key properties of this formulation that shed light on the difficulty of reasoning tasks. First, the latent space exceeds the observation space in complexity, even when the correct answer is fully determined by the observed input. Second, the latent variables, corresponding to logical thought, are densely structured and exhibit strong dependencies. Building on this formulation, we introduce a framework, called SR$^2$, that incorporates the estimated latent variables as feedback into the selection mechanism, thereby facilitating the learning of dense dependencies among latent representations. The framework consists of three key modules: reflective representation learning, dependency self-refinement, and periodic intermediate alignment. Experimentally, we show that our approach yields significant gains in reasoning accuracy, for example, attaining over 10$\\%$ improvement in performance with 8$\\times$ fewer parameters on the Sudoku and Maze tasks over the recent advances.","published":"2025-10-09T13:45:31Z","updated":"2026-03-27T05:07:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.08222v2","pdf_url":"https://arxiv.org/pdf/2510.08222v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.07841","versioned_id":"2510.07841v1","title":"Self-Improving LLM Agents at Test-Time","authors":["Emre Can Acikgoz","Cheng Qian","Heng Ji","Dilek Hakkani-Tür","Gokhan Tur"],"abstract":"One paradigm of language model (LM) fine-tuning relies on creating large training datasets, under the assumption that high quantity and diversity will enable models to generalize to novel tasks after post-training. In practice, gathering large sets of data is inefficient, and training on them is prohibitively expensive; worse, there is no guarantee that the resulting model will handle complex scenarios or generalize better. Moreover, existing techniques rarely assess whether a training sample provides novel information or is redundant with the knowledge already acquired by the model, resulting in unnecessary costs. In this work, we explore a new test-time self-improvement method to create more effective and generalizable agentic LMs on-the-fly. The proposed algorithm can be summarized in three steps: (i) first it identifies the samples that model struggles with (self-awareness), (ii) then generates similar examples from detected uncertain samples (self-data augmentation), and (iii) uses these newly generated samples at test-time fine-tuning (self-improvement). We study two variants of this approach: Test-Time Self-Improvement (TT-SI), where the same model generates additional training examples from its own uncertain cases and then learns from them, and contrast this approach with Test-Time Distillation (TT-D), where a stronger model generates similar examples for uncertain cases, enabling student to adapt using distilled supervision. Empirical evaluations across different agent benchmarks demonstrate that TT-SI improves the performance with +5.48% absolute accuracy gain on average across all benchmarks and surpasses other standard learning methods, yet using 68x less training samples. Our findings highlight the promise of TT-SI, demonstrating the potential of self-improvement algorithms at test-time as a new paradigm for building more capable agents toward self-evolution.","published":"2025-10-09T06:37:35Z","updated":"2025-10-09T06:37:35Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.07841v1","pdf_url":"https://arxiv.org/pdf/2510.07841v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.07632","versioned_id":"2510.07632v2","title":"Test-Time Matching: Unlocking Compositional Reasoning in Multimodal Models","authors":["Yinglun Zhu","Jiancheng Zhang","Fuzhi Tang"],"abstract":"Frontier AI models have achieved remarkable progress, yet recent studies suggest they struggle with compositional reasoning, often performing at or below random chance on established benchmarks. We revisit this problem and show that widely used evaluation metrics systematically underestimate model capability. To correct this artifact, we introduce a group matching score that more faithfully evaluates model capability. Moreover, correctness under the new metric can be translated into correctness under existing metrics via a simple overfitting step. This adjustment enables SigLIP-B16 to surpass all previous results and GPT-4.1 to yield the first result surpassing estimated human performance on Winoground. Building on this insight, we propose Test-Time Matching (TTM), an iterative, self-improving algorithm that further bootstraps model performance without any external supervision. TTM delivers additional, non-trivial improvements: for example, TTM enables SigLIP-B16 to surpass GPT-4.1 on MMVP-VLM, establishing a new state of the art. TTM also extends beyond contrastive vision-language models, yielding clear gains on a generative multimodal model across benchmarks. Importantly, TTM remains broadly effective even on benchmarks without metric-induced effects or group structures, achieving relative gains up to 85.7% on challenging datasets such as WhatsUp. Across 16 dataset variants spanning diverse setups, our experiments demonstrate that TTM consistently improves model performance and advances the frontier of compositional reasoning.","published":"2025-10-09T00:00:49Z","updated":"2026-04-24T03:12:09Z","categories":["cs.AI","cs.CL","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.07632v2","pdf_url":"https://arxiv.org/pdf/2510.07632v2","comment":"To appear at ICLR 2026; extended results to generative multimodal models","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.07432","versioned_id":"2510.07432v2","title":"TS-Agent: Understanding and Reasoning Over Raw Time Series via Iterative Insight Gathering","authors":["Penghang Liu","Elizabeth Fons","Annita Vapsi","Mohsen Ghassemi","Svitlana Vyetrenko","Daniel Borrajo","Vamsi K. Potluru","Manuela Veloso"],"abstract":"Large language models (LLMs) exhibit strong symbolic and compositional reasoning, yet they struggle with time series question answering as the data is typically transformed into an LLM-compatible modality, e.g., serialized text, plotted images, or compressed time series embeddings. Such conversions impose representation bottlenecks, often require cross-modal alignment or finetuning, and can exacerbate hallucination and knowledge leakage. To address these limitations, we propose TS-Agent, an agentic, tool-grounded framework that uses LLMs strictly for iterative evidence-based reasoning, while delegating statistical and structural extraction to time series analytical tools operating on raw sequences. Our framework solves time series tasks through an evidence-driven agentic process: (1) it alternates between thinking, tool execution, and observation in a ReAct-style loop, (2) records intermediate results in an explicit evidence log and corrects the reasoning trace via a self-refinement critic, and (3) enforces a final answer-verification step to prevent hallucinations and leakage. Across four benchmarks spanning time series understanding and reasoning, TS-Agent matches or exceeds strong text-based, vision-based, and time-series language model baselines, with the largest gains on reasoning tasks where multimodal LLMs are prone to hallucination and knowledge leakage in zero-shot settings.","published":"2025-10-08T18:31:53Z","updated":"2026-04-06T21:49:20Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.07432v2","pdf_url":"https://arxiv.org/pdf/2510.07432v2","comment":"NeurIPS 2025 Workshop on Foundations of Reasoning in Language Models","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.07290","versioned_id":"2510.07290v3","title":"On the Convergence of Moral Self-Correction in Large Language Models","authors":["Guangliang Liu","Haitao Mao","Bochuan Cao","Zhiyu Xue","Xitong Zhang","Rongrong Wang","Kristen Marie Johnson"],"abstract":"Large Language Models (LLMs) are able to improve their responses when instructed to do so, a capability known as self-correction. When instructions provide only a general and abstract goal without specific details about potential issues in the response, LLMs must rely on their internal knowledge to improve response quality, a process referred to as intrinsic self-correction. The empirical success of intrinsic self-correction is evident in various applications, but how and why it is effective remains unknown. Focusing on moral self-correction in LLMs, we reveal a key characteristic of intrinsic self-correction: performance convergence through multi-round interactions; and provide a mechanistic analysis of this convergence behavior. Based on our experimental results and analysis, we uncover the underlying mechanism of convergence: consistently injected self-correction instructions activate moral concepts that reduce model uncertainty, leading to converged performance as the activated moral concepts stabilize over successive rounds. This paper demonstrates the strong potential of moral self-correction by showing that it exhibits a desirable property of converged performance.","published":"2025-10-08T17:46:27Z","updated":"2025-10-26T19:28:05Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.07290v3","pdf_url":"https://arxiv.org/pdf/2510.07290v3","comment":"17 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.06652","versioned_id":"2510.06652v1","title":"Aligning Large Language Models via Fully Self-Synthetic Data","authors":["Shangjian Yin","Zhepei Wei","Xinyu Zhu","Wei-Lin Chen","Yu Meng"],"abstract":"Traditional reinforcement learning from human feedback (RLHF) for large language models (LLMs) relies on expensive human-annotated datasets, while Reinforcement Learning from AI Feedback (RLAIF) also incurs significant costs, requiring the collection of diverse prompts and corresponding responses, often necessitating external reward models or proprietary models like GPT-4 to annotate preference pairs. In this work, we introduce Self-Alignment Optimization (SAO), a fully self-synthetic framework for LLM alignment, where all training data, including prompts (i.e., user queries), responses, and preferences, are generated by the model itself. Specifically, SAO first instructs the LLM to engage in persona role-play and generate diverse prompts and responses, which are then self-evaluated for preference optimization. Extensive experiments demonstrate that SAO effectively enhances the model's chat capabilities on standard benchmarks like AlpacaEval~2.0, while maintaining strong performance on downstream objective tasks (e.g., question-answering, math reasoning). Our work provides a practical solution for self-improvement in aligning LLMs, and the code for reproducing our results is available at: https://github.com/SJY8460/SAO.","published":"2025-10-08T05:07:45Z","updated":"2025-10-08T05:07:45Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.06652v1","pdf_url":"https://arxiv.org/pdf/2510.06652v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.06471","versioned_id":"2510.06471v2","title":"Test-Time Scaling of Reasoning Models for Machine Translation","authors":["Zihao Li","Shaoxiong Ji","Jörg Tiedemann"],"abstract":"Test-time scaling (TTS) has enhanced the performance of Reasoning Models (RMs) on various tasks such as math and coding, yet its efficacy in machine translation (MT) remains underexplored. This paper investigates whether increased inference-time computation improves translation quality. We evaluate 12 RMs across a diverse suite of MT benchmarks spanning multiple domains, examining three scenarios: direct translation, forced-reasoning extrapolation, and post-editing. Our findings show that for general-purpose RMs, TTS provides limited and inconsistent benefits for direct translation, with performance quickly plateauing. However, the effectiveness of TTS is unlocked by domain-specific fine-tuning, which aligns a model's reasoning process with task requirements, leading to consistent improvements up to an optimal, self-determined reasoning depth. We also find that forcing a model to reason beyond its natural stopping point consistently degrades translation quality. In contrast, TTS proves highly effective in a post-editing context, reliably turning self-correction into a beneficial process. These results indicate that the value of inference-time computation in MT lies not in enhancing single-pass translation with general models, but in targeted applications like multi-step, self-correction workflows and in conjunction with task-specialized models.","published":"2025-10-07T21:15:18Z","updated":"2026-01-11T22:32:41Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.06471v2","pdf_url":"https://arxiv.org/pdf/2510.06471v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.06190","versioned_id":"2510.06190v2","title":"On Powerful Ways to Generate: Autoregression, Diffusion, and Beyond","authors":["Chenxiao Yang","Cai Zhou","David Wipf","Zhiyuan Li"],"abstract":"Diffusion language models have recently emerged as a competitive alternative to autoregressive language models. Beyond next-token generation, they are more efficient and flexible by enabling parallel and any-order token generation. However, despite empirical successes, their computational power and fundamental limitations remain poorly understood. In this paper, we formally study whether non-autoregressive generation in Masked Diffusion Models (MDM) enables solving problems beyond the reach of Auto-Regressive Models (ARM). Our results show that MDM with sufficiently large context length is computationally universal with decoding steps matching the optimal parallel time complexity in PRAM. However, when controlling for other factors, MDM's flexibility to generate in any-order does not expand what ARM can already solve. To address this, we propose a new form of generation called any-process generation, which extends MDM with capabilities to remask, insert and delete tokens, allowing self-correction, length-variable editing, and adaptive parallelism. Theoretically and empirically, we demonstrate these capabilities enable scalability to significantly harder reasoning problems that are otherwise intractable for ARM and vanilla MDM. Additionally, they prove essential for generation tasks where objects naturally evolve through non-sequential processes, crucial for extending current LLMs beyond natural language to domains such as coding and science.","published":"2025-10-07T17:49:30Z","updated":"2025-11-17T03:58:26Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.06190v2","pdf_url":"https://arxiv.org/pdf/2510.06190v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.05774","versioned_id":"2510.05774v1","title":"ConstraintLLM: A Neuro-Symbolic Framework for Industrial-Level Constraint Programming","authors":["Weichun Shi","Minghao Liu","Wanting Zhang","Langchen Shi","Fuqi Jia","Feifei Ma","Jian Zhang"],"abstract":"Constraint programming (CP) is a crucial technology for solving real-world constraint optimization problems (COPs), with the advantages of rich modeling semantics and high solving efficiency. Using large language models (LLMs) to generate formal modeling automatically for COPs is becoming a promising approach, which aims to build trustworthy neuro-symbolic AI with the help of symbolic solvers. However, CP has received less attention compared to works based on operations research (OR) models. We introduce ConstraintLLM, the first LLM specifically designed for CP modeling, which is trained on an open-source LLM with multi-instruction supervised fine-tuning. We propose the Constraint-Aware Retrieval Module (CARM) to increase the in-context learning capabilities, which is integrated in a Tree-of-Thoughts (ToT) framework with guided self-correction mechanism. Moreover, we construct and release IndusCP, the first industrial-level benchmark for CP modeling, which contains 140 challenging tasks from various domains. Our experiments demonstrate that ConstraintLLM achieves state-of-the-art solving accuracy across multiple benchmarks and outperforms the baselines by 2x on the new IndusCP benchmark. Code and data are available at: https://github.com/william4s/ConstraintLLM.","published":"2025-10-07T10:43:39Z","updated":"2025-10-07T10:43:39Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.05774v1","pdf_url":"https://arxiv.org/pdf/2510.05774v1","comment":"Accepted to the 2025 Conference on Empirical Methods in Natural Language Processing (EMNLP 2025), Main Conference","journal_ref":"Proceedings of the 2025 Conference on Empirical Methods in Natural Language Processing, pages 15999-16019","doi":"10.18653/v1/2025.emnlp-main.809","discovered_on":"2026-07-17"},{"id":"2510.05596","versioned_id":"2510.05596v1","title":"From Agentification to Self-Evolving Agentic AI for Wireless Networks: Concepts, Approaches, and Future Research Directions","authors":["Changyuan Zhao","Ruichen Zhang","Jiacheng Wang","Dusit Niyato","Geng Sun","Xianbin Wang","Shiwen Mao","Abbas Jamalipour"],"abstract":"Self-evolving agentic artificial intelligence (AI) offers a new paradigm for future wireless systems by enabling autonomous agents to continually adapt and improve without human intervention. Unlike static AI models, self-evolving agents embed an autonomous evolution cycle that updates models, tools, and workflows in response to environmental dynamics. This paper presents a comprehensive overview of self-evolving agentic AI, highlighting its layered architecture, life cycle, and key techniques, including tool intelligence, workflow optimization, self-reflection, and evolutionary learning. We further propose a multi-agent cooperative self-evolving agentic AI framework, where multiple large language models (LLMs) are assigned role-specialized prompts under the coordination of a supervisor agent. Through structured dialogue, iterative feedback, and systematic validation, the system autonomously executes the entire life cycle without human intervention. A case study on antenna evolution in low-altitude wireless networks (LAWNs) demonstrates how the framework autonomously upgrades fixed antenna optimization into movable antenna optimization. Experimental results show that the proposed self-evolving agentic AI autonomously improves beam gain and restores degraded performance by up to 52.02%, consistently surpassing the fixed baseline with little to no human intervention and validating its adaptability and robustness for next-generation wireless intelligence.","published":"2025-10-07T05:45:25Z","updated":"2025-10-07T05:45:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.05596v1","pdf_url":"https://arxiv.org/pdf/2510.05596v1","comment":"7 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.05571","versioned_id":"2510.05571v2","title":"Presenting a Paper is an Art: Self-Improvement Aesthetic Agents for Academic Presentations","authors":["Chengzhi Liu","Yuzhe Yang","Kaiwen Zhou","Zhen Zhang","Yue Fan","Yanan Xie","Peng Qi","Xin Eric Wang"],"abstract":"The promotion of academic papers has become an important means of enhancing research visibility. However, existing automated methods struggle limited storytelling, insufficient aesthetic quality, and constrained self-adjustment, making it difficult to achieve efficient and engaging dissemination. At the heart of those challenges is a simple principle: \\emph{there is no way to improve it when you cannot evaluate it right}. To address this, we introduce \\textbf{EvoPresent}, a self-improvement agent framework that unifies coherent narratives, aesthetic-aware designs, and realistic presentation delivery via virtual characters. Central to EvoPresent is \\textbf{PresAesth}, a multi-task reinforcement learning (RL) aesthetic model that provides reliable aesthetic scoring, defect adjustment, and comparative feedback, enabling iterative self-improvement even under limited aesthetic training data. To systematically evaluate the methods, we introduce \\textbf{EvoPresent Benchmark}, a comprehensive benchmark comprising: \\textit{Presentation Generation Quality}, built on 650 top-tier AI conference papers with multimodal resources (slides, videos and scripts) to assess both content and design; and \\textit{Aesthetic Awareness}, consisting of 2,000 slide pairs with varying aesthetic levels, supporting joint training and evaluation on scoring, defect adjustment, and comparison. Our findings highlight that (i) High-quality feedback is essential for agent self-improvement, while initial capability alone does not guarantee effective self-correction. (ii) Automated generation pipelines exhibit a trade-off between visual design and content construction. (iii) Multi-task RL training shows stronger generalization in aesthetic awareness tasks.","published":"2025-10-07T04:24:26Z","updated":"2025-10-21T21:04:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.05571v2","pdf_url":"https://arxiv.org/pdf/2510.05571v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.04618","versioned_id":"2510.04618v3","title":"Agentic Context Engineering: Evolving Contexts for Self-Improving Language Models","authors":["Qizheng Zhang","Changran Hu","Shubhangi Upasani","Boyuan Ma","Fenglu Hong","Vamsidhar Kamanuru","Jay Rainton","Chen Wu","Mengmeng Ji","Hanchen Li","Urmish Thakker","James Zou","Kunle Olukotun"],"abstract":"Large language model (LLM) applications such as agents and domain-specific reasoning increasingly rely on context adaptation: modifying inputs with instructions, strategies, or evidence, rather than weight updates. Prior approaches improve usability but often suffer from brevity bias, which drops domain insights for concise summaries, and from context collapse, where iterative rewriting erodes details over time. We introduce ACE (Agentic Context Engineering), a framework that treats contexts as evolving playbooks that accumulate, refine, and organize strategies through a modular process of generation, reflection, and curation. ACE prevents collapse with structured, incremental updates that preserve detailed knowledge and scale with long-context models. Across agent and domain-specific benchmarks, ACE optimizes contexts both offline (e.g., system prompts) and online (e.g., agent memory), consistently outperforming strong baselines: +10.6% on agents and +8.6% on finance, while significantly reducing adaptation latency and rollout cost. Notably, ACE could adapt effectively without labeled supervision and instead by leveraging natural execution feedback. On the AppWorld leaderboard, ACE matches the top-ranked production-level agent on the overall average and surpasses it on the harder test-challenge split, despite using a smaller open-source model. These results show that comprehensive, evolving contexts enable scalable, efficient, and self-improving LLM systems with low overhead.","published":"2025-10-06T09:30:18Z","updated":"2026-03-29T09:18:02Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.04618v3","pdf_url":"https://arxiv.org/pdf/2510.04618v3","comment":"ICLR 2026; 32 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.04399","versioned_id":"2510.04399v2","title":"On The Statistical Limits of Self-Improving Agents","authors":["Charles L. Wang","Keir Dorchen","Peter Jin"],"abstract":"As systems trend toward superintelligence, a natural modeling premise is that agents can self-improve along every facet of their own design. We formalize this with a five-axis decomposition and a decision layer, separating incentives from learning behavior and analyzing axes in isolation. Our central result identifies and introduces a sharp utility-learning tension, the structural conflict in self-modifying systems whereby utility-driven changes that improve immediate or expected performance can also erode the statistical preconditions for reliable learning and generalization. Our findings show that distribution-free guarantees are preserved iff the policy-reachable model family is uniformly capacity-bounded; when capacity can grow without limit, utility-rational self-changes can render learnable tasks unlearnable. Under standard assumptions common in practice, these axes reduce to the same capacity criterion, yielding a single boundary for safe self-modification.","published":"2025-10-05T23:52:16Z","updated":"2026-02-01T21:46:56Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.04399v2","pdf_url":"https://arxiv.org/pdf/2510.04399v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.04128","versioned_id":"2510.04128v1","title":"Internal states before wait modulate reasoning patterns","authors":["Dmitrii Troitskii","Koyena Pal","Chris Wendler","Callum Stuart McDougall","Neel Nanda"],"abstract":"Prior work has shown that a significant driver of performance in reasoning models is their ability to reason and self-correct. A distinctive marker in these reasoning traces is the token wait, which often signals reasoning behavior such as backtracking. Despite being such a complex behavior, little is understood of exactly why models do or do not decide to reason in this particular manner, which limits our understanding of what makes a reasoning model so effective. In this work, we address the question whether model's latents preceding wait tokens contain relevant information for modulating the subsequent reasoning process. We train crosscoders at multiple layers of DeepSeek-R1-Distill-Llama-8B and its base version, and introduce a latent attribution technique in the crosscoder setting. We locate a small set of features relevant for promoting/suppressing wait tokens' probabilities. Finally, through a targeted series of experiments analyzing max activating examples and causal interventions, we show that many of our identified features indeed are relevant for the reasoning process and give rise to different types of reasoning patterns such as restarting from the beginning, recalling prior knowledge, expressing uncertainty, and double-checking.","published":"2025-10-05T10:03:42Z","updated":"2025-10-05T10:03:42Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.04128v1","pdf_url":"https://arxiv.org/pdf/2510.04128v1","comment":"Accepted to EMNLP Findings 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.03851","versioned_id":"2510.03851v2","title":"MetaMuse: Algorithm Generation via Creative Ideation","authors":["Ruiying Ma","Chieh-Jan Mike Liang","Yanjie Gao","Francis Y. Yan"],"abstract":"Designing system algorithms remains challenging, where the discontinuous nature of the solution space often forces system engineers to rely on generic heuristics at the expense of performance. We study whether LLMs can practically drive algorithm generation, and find that they are biased towards well-known generic designs, rather than making the creative leaps needed to navigate the discontinuous solution space. To address this limitation, we introduce MetaMuse, a framework for creative ideation built on three self-reflection principles: (1) quantifying solution diversity and usefulness in measurable performance space, rather than abstract idea space, (2) steering ideation through external stimuli, rather than internal randomness, and (3) constructing executable solutions using waypoint reasoning, rather than free-form chain-of-thought. Considering two critical online problems at a global cloud provider, extensive evaluations show that MetaMuse can generate high-performing solutions: it reduces cache misses by up to 35.76% in cache replacement and reduces bin usage by up to 30.93% in online bin packing.","published":"2025-10-04T15:52:31Z","updated":"2026-04-16T03:31:16Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.03851v2","pdf_url":"https://arxiv.org/pdf/2510.03851v2","comment":"ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.08591","versioned_id":"2510.08591v1","title":"The Enduring Dominance of Deep Neural Networks: A Critical Analysis of the Fundamental Limitations of Quantum Machine Learning and Spiking Neural Networks","authors":["Takehiro Ishikawa"],"abstract":"Recent advancements in QML and SNNs have generated considerable excitement, promising exponential speedups and brain-like energy efficiency to revolutionize AI. However, this paper argues that they are unlikely to displace DNNs in the near term. QML struggles with adapting backpropagation due to unitary constraints, measurement-induced state collapse, barren plateaus, and high measurement overheads, exacerbated by the limitations of current noisy intermediate-scale quantum hardware, overfitting risks due to underdeveloped regularization techniques, and a fundamental misalignment with machine learning's generalization. SNNs face restricted representational bandwidth, struggling with long-range dependencies and semantic encoding in language tasks due to their discrete, spike-based processing. Furthermore, the goal of faithfully emulating the brain might impose inherent inefficiencies like cognitive biases, limited working memory, and slow learning speeds. Even their touted energy-efficient advantages are overstated; optimized DNNs with quantization can outperform SNNs in energy costs under realistic conditions. Finally, SNN training incurs high computational overhead from temporal unfolding. In contrast, DNNs leverage efficient backpropagation, robust regularization, and innovations in LRMs that shift scaling to inference-time compute, enabling self-improvement via RL and search algorithms like MCTS while mitigating data scarcity. This superiority is evidenced by recent models such as xAI's Grok-4 Heavy, which advances SOTA performance, and gpt-oss-120b, which surpasses or approaches the performance of leading industry models despite its modest 120-billion-parameter size deployable on a single 80GB GPU. Furthermore, specialized ASICs amplify these efficiency gains. Ultimately, QML and SNNs may serve niche hybrid roles, but DNNs remain the dominant, practical paradigm for AI advancement.","published":"2025-10-04T11:00:46Z","updated":"2025-10-04T11:00:46Z","categories":["cs.NE","cs.AI","cs.LG"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2510.08591v1","pdf_url":"https://arxiv.org/pdf/2510.08591v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.03687","versioned_id":"2510.03687v2","title":"MedReflect: Teaching Medical LLMs to Self-Improve via Reflective Correction","authors":["Yue Huang","Yanyuan Chen","Dexuan Xu","Chenzhuo Zhao","Weihua Yue","Yu Huang"],"abstract":"Medical problem-solving demands expert knowledge and intricate reasoning. Recent studies of large language models (LLMs) attempt to ease this complexity by introducing external knowledge verification through retrieval-augmented generation or by training on reasoning datasets. However, these approaches suffer from drawbacks such as retrieval overhead and high annotation costs, and they heavily rely on substituted external assistants to reach limited performance in medical field. In this paper, we introduce MedReflect, a generalizable framework designed to inspire LLMs with a physician-like reflective thinking mode. MedReflect generates a single-pass reflection chain that includes initial hypothesis generation, self-questioning, self-answering and decision refinement. This self-verified and self-reflective nature releases large language model's latent capability in medical problem-solving without external retrieval or heavy annotation. We demonstrate that MedReflect enables cost-efficient medical dataset construction. With only a minimal subset of randomly sampled training examples and lightweight fine-tuning, this approach achieves notable absolute accuracy improvements across a series of medical benchmarks while significantly cutting annotation requirements. Our results provide evidence that LLMs can learn to solve specialized medical problems via self-reflection and self-improvement, reducing reliance on external supervision and extensive task-specific fine-tuning data.","published":"2025-10-04T06:00:48Z","updated":"2026-01-16T10:35:41Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.03687v2","pdf_url":"https://arxiv.org/pdf/2510.03687v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.03597","versioned_id":"2510.03597v3","title":"Neon: Negative Extrapolation From Self-Training Improves Image Generation","authors":["Sina Alemohammad","Zhangyang Wang","Richard G. Baraniuk"],"abstract":"Scaling generative AI models is bottlenecked by the scarcity of high-quality training data. The ease of synthesizing from a generative model suggests using (unverified) synthetic data to augment a limited corpus of real data for the purpose of fine-tuning in the hope of improving performance. Unfortunately, however, the resulting positive feedback loop leads to model autophagy disorder (MAD, aka model collapse) that results in a rapid degradation in sample quality and/or diversity. In this paper, we introduce Neon (for Negative Extrapolation frOm self-traiNing), a new learning method that turns the degradation from self-training into a powerful signal for self-improvement. Given a base model, Neon first fine-tunes it on its own self-synthesized data but then, counterintuitively, reverses its gradient updates to extrapolate away from the degraded weights. We prove that Neon works because typical inference samplers that favor high-probability regions create a predictable anti-alignment between the synthetic and real data population gradients, which negative extrapolation corrects to better align the model with the true data distribution. Neon is remarkably easy to implement via a simple post-hoc merge that requires no new real data, works effectively with as few as 1k synthetic samples, and typically uses less than 1% additional training compute. We demonstrate Neon's universality across a range of architectures (diffusion, flow matching, autoregressive, and inductive moment matching models) and datasets (ImageNet, CIFAR-10, and FFHQ). In particular, on ImageNet 256x256, Neon elevates the xAR-L model to a new state-of-the-art FID of 1.02 with only 0.36% additional training compute. Code is available at https://github.com/VITA-Group/Neon","published":"2025-10-04T01:20:30Z","updated":"2025-10-13T22:13:35Z","categories":["cs.GR","cs.AI","cs.LG"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2510.03597v3","pdf_url":"https://arxiv.org/pdf/2510.03597v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.03194","versioned_id":"2510.03194v1","title":"CoDA: Agentic Systems for Collaborative Data Visualization","authors":["Zichen Chen","Jiefeng Chen","Sercan Ö. Arik","Misha Sra","Tomas Pfister","Jinsung Yoon"],"abstract":"Deep research has revolutionized data analysis, yet data scientists still devote substantial time to manually crafting visualizations, highlighting the need for robust automation from natural language queries. However, current systems struggle with complex datasets containing multiple files and iterative refinement. Existing approaches, including simple single- or multi-agent systems, often oversimplify the task, focusing on initial query parsing while failing to robustly manage data complexity, code errors, or final visualization quality. In this paper, we reframe this challenge as a collaborative multi-agent problem. We introduce CoDA, a multi-agent system that employs specialized LLM agents for metadata analysis, task planning, code generation, and self-reflection. We formalize this pipeline, demonstrating how metadata-focused analysis bypasses token limits and quality-driven refinement ensures robustness. Extensive evaluations show CoDA achieves substantial gains in the overall score, outperforming competitive baselines by up to 41.5%. This work demonstrates that the future of visualization automation lies not in isolated code generation but in integrated, collaborative agentic workflows.","published":"2025-10-03T17:30:16Z","updated":"2025-10-03T17:30:16Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.03194v1","pdf_url":"https://arxiv.org/pdf/2510.03194v1","comment":"31 pages, 6 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.02919","versioned_id":"2510.02919v2","title":"Self-Reflective Generation at Test Time","authors":["Jian Mu","Qixin Zhang","Zhiyong Wang","Menglin Yang","Shuang Qiu","Chengwei Qin","Zhongxiang Dai","Yao Shu"],"abstract":"Large language models (LLMs) increasingly solve complex reasoning tasks via long chain-of-thought, but their forward-only autoregressive generation process is fragile; early token errors can cascade, which creates a clear need for self-reflection mechanisms. However, existing self-reflection either performs revisions over full drafts or learns self-correction via expensive training, both fundamentally reactive and inefficient. To address this, we propose Self-Reflective Generation at Test Time (SRGen), a lightweight test-time framework that reflects before generating at uncertain points. During token generation, SRGen utilizes dynamic entropy thresholding to identify high-uncertainty tokens. For each identified token, it trains a specific corrective vector, which fully exploits the already generated context for a self-reflective generation to correct the token probability distribution. By retrospectively analyzing the partial output, this self-reflection enables more trustworthy decisions, thereby significantly reducing the probability of errors at highly uncertain points. Evaluated on challenging mathematical reasoning benchmarks and a diverse set of LLMs, SRGen can significantly strengthen model reasoning. Moreover, our findings position SRGen as a plug-and-play method that integrates reflection into the generation process for reliable LLM reasoning, achieving consistent gains with bounded overhead and can be combined with other training-time (e.g., RLHF) and test-time (e.g., SLOT) techniques.","published":"2025-10-03T11:46:04Z","updated":"2026-05-29T16:16:27Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.02919v2","pdf_url":"https://arxiv.org/pdf/2510.02919v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.02892","versioned_id":"2510.02892v1","title":"RoiRL: Efficient, Self-Supervised Reasoning with Offline Iterative Reinforcement Learning","authors":["Aleksei Arzhantsev","Otmane Sakhi","Flavian Vasile"],"abstract":"Reinforcement learning (RL) is central to improving reasoning in large language models (LLMs) but typically requires ground-truth rewards. Test-Time Reinforcement Learning (TTRL) removes this need by using majority-vote rewards, but relies on heavy online RL and incurs substantial computational cost. We propose RoiRL: Reasoning with offline iterative Reinforcement Learning, a family of lightweight offline learning alternatives that can target the same regularized optimal policies. Unlike TTRL, RoiRL eliminates the need to maintain a reference model and instead optimizes weighted log-likelihood objectives, enabling stable training with significantly lower memory and compute requirements. Experimental results show that RoiRL trains to 2.5x faster and consistently outperforms TTRL on reasoning benchmarks, establishing a scalable path to self-improving LLMs without labels.","published":"2025-10-03T10:59:26Z","updated":"2025-10-03T10:59:26Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.02892v1","pdf_url":"https://arxiv.org/pdf/2510.02892v1","comment":"Accepted to the Efficient Reasoning Workshop at NeuRIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.02665","versioned_id":"2510.02665v1","title":"Self-Improvement in Multimodal Large Language Models: A Survey","authors":["Shijian Deng","Kai Wang","Tianyu Yang","Harsh Singh","Yapeng Tian"],"abstract":"Recent advancements in self-improvement for Large Language Models (LLMs) have efficiently enhanced model capabilities without significantly increasing costs, particularly in terms of human effort. While this area is still relatively young, its extension to the multimodal domain holds immense potential for leveraging diverse data sources and developing more general self-improving models. This survey is the first to provide a comprehensive overview of self-improvement in Multimodal LLMs (MLLMs). We provide a structured overview of the current literature and discuss methods from three perspectives: 1) data collection, 2) data organization, and 3) model optimization, to facilitate the further development of self-improvement in MLLMs. We also include commonly used evaluations and downstream applications. Finally, we conclude by outlining open challenges and future research directions.","published":"2025-10-03T01:48:26Z","updated":"2025-10-03T01:48:26Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.02665v1","pdf_url":"https://arxiv.org/pdf/2510.02665v1","comment":"EMNLP 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.02172","versioned_id":"2510.02172v1","title":"RESTRAIN: From Spurious Votes to Signals -- Self-Driven RL with Self-Penalization","authors":["Zhaoning Yu","Will Su","Leitian Tao","Haozhu Wang","Aashu Singh","Hanchao Yu","Jianyu Wang","Hongyang Gao","Weizhe Yuan","Jason Weston","Ping Yu","Jing Xu"],"abstract":"Reinforcement learning with human-annotated data has boosted chain-of-thought reasoning in large reasoning models, but these gains come at high costs in labeled data while faltering on harder tasks. A natural next step is experience-driven learning, where models improve without curated labels by adapting to unlabeled data. We introduce RESTRAIN (REinforcement learning with Self-restraint), a self-penalizing RL framework that converts the absence of gold labels into a useful learning signal. Instead of overcommitting to spurious majority votes, RESTRAIN exploits signals from the model's entire answer distribution: penalizing overconfident rollouts and low-consistency examples while preserving promising reasoning chains. The self-penalization mechanism integrates seamlessly into policy optimization methods such as GRPO, enabling continual self-improvement without supervision. On challenging reasoning benchmarks, RESTRAIN delivers large gains using only unlabeled data. With Qwen3-4B-Base and OctoThinker Hybrid-8B-Base, it improves Pass@1 by up to +140.7 percent on AIME25, +36.2 percent on MMLU_STEM, and +19.6 percent on GPQA-Diamond, nearly matching gold-label training while using no gold labels. These results demonstrate that RESTRAIN establishes a scalable path toward stronger reasoning without gold labels.","published":"2025-10-02T16:24:01Z","updated":"2025-10-02T16:24:01Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.02172v1","pdf_url":"https://arxiv.org/pdf/2510.02172v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.02001","versioned_id":"2510.02001v6","title":"Generating Findings for Jaw Cysts in Dental Panoramic Radiographs Using a GPT-Based VLM: A Preliminary Study on Building a Two-Stage Self-Correction Loop with Structured Output (SLSO) Framework","authors":["Nanaka Hosokawa","Ryo Takahashi","Tomoya Kitano","Yukihiro Iida","Chisako Muramatsu","Tatsuro Hayashi","Yuta Seino","Xiangrong Zhou","Takeshi Hara","Akitoshi Katsumata","Hiroshi Fujita"],"abstract":"Vision-language models (VLMs) such as GPT (Generative Pre-Trained Transformer) have shown potential for medical image interpretation; however, challenges remain in generating reliable radiological findings in clinical practice, as exemplified by dental pathologies. This study proposes a Self-correction Loop with Structured Output (SLSO) framework as an integrated processing methodology to enhance the accuracy and reliability of AI-generated findings for jaw cysts in dental panoramic radiographs. Dental panoramic radiographs with jaw cysts were used to implement a 10-step integrated processing framework incorporating image analysis, structured data generation, tooth number extraction, consistency checking, and iterative regeneration. The framework functioned as an external validation mechanism for GPT outputs. Performance was compared against the conventional Chain-of-Thought (CoT) method across seven evaluation items: transparency, internal structure, borders, root resorption, tooth movement, relationships with other structures, and tooth number. The SLSO framework improved output accuracy for multiple items compared to the CoT method, with the most notable improvements observed in tooth number identification, tooth movement detection, and root resorption assessment. In successful cases, consistently structured outputs were achieved after up to five regenerations. The framework enforced explicit negative finding descriptions and suppressed hallucinations, although accurate identification of extensive lesions spanning multiple teeth remained limited. This investigation established the feasibility of the proposed integrated processing methodology and provided a foundation for future validation studies with larger, more diverse datasets.","published":"2025-10-02T13:22:13Z","updated":"2026-04-20T01:16:53Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.02001v6","pdf_url":"https://arxiv.org/pdf/2510.02001v6","comment":"Revised manuscript; supplementary materials added. Published in Diagnostics","journal_ref":"Diagnostics 2026, 16, 1096","doi":"10.3390/diagnostics16071096","discovered_on":"2026-07-17"},{"id":"2510.01925","versioned_id":"2510.01925v2","title":"Enhancing Large Language Model Reasoning with Reward Models: An Analytical Survey","authors":["Qiyuan Liu","Hao Xu","Xuhong Chen","Wei Chen","Yee Whye Teh","Ning Miao"],"abstract":"Reward models (RMs) play a critical role in enhancing the reasoning performance of LLMs. For example, they can provide training signals to finetune LLMs during reinforcement learning (RL) and help select the best answer from multiple candidates during inference. In this paper, we provide a systematic introduction to RMs, along with a comprehensive survey of their applications in LLM reasoning. We first review fundamental concepts of RMs, including their architectures, training methodologies, and evaluation techniques. Then, we explore their key applications: (1) guiding generation and selecting optimal outputs during LLM inference, (2) facilitating data synthesis and iterative self-improvement for LLMs, and (3) providing training signals in RL-based finetuning. Finally, we discuss critical open questions regarding the selection, generalization, evaluation, and enhancement of RMs, based on existing research and our own empirical findings. Our analysis aims to provide actionable insights for the effective deployment and advancement of RMs for LLM reasoning.","published":"2025-10-02T11:42:17Z","updated":"2025-10-03T10:55:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.01925v2","pdf_url":"https://arxiv.org/pdf/2510.01925v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.01527","versioned_id":"2510.01527v1","title":"Round-trip Reinforcement Learning: Self-Consistent Training for Better Chemical LLMs","authors":["Lecheng Kong","Xiyuan Wang","Yixin Chen","Muhan Zhang"],"abstract":"Large Language Models (LLMs) are emerging as versatile foundation models for computational chemistry, handling bidirectional tasks like reaction prediction and retrosynthesis. However, these models often lack round-trip consistency. For instance, a state-of-the-art chemical LLM may successfully caption a molecule, yet be unable to accurately reconstruct the original structure from its own generated text. This inconsistency suggests that models are learning unidirectional memorization rather than flexible mastery. Indeed, recent work has demonstrated a strong correlation between a model's round-trip consistency and its performance on the primary tasks. This strong correlation reframes consistency into a direct target for model improvement. We therefore introduce Round-Trip Reinforcement Learning (RTRL), a novel framework that trains a model to improve its consistency by using the success of a round-trip transformation as a reward signal. We further propose an iterative variant where forward and reverse mappings alternately train each other in a self-improvement loop, a process that is highly data-efficient and notably effective with the massive amount of unlabelled data common in chemistry. Experiments demonstrate that RTRL significantly \\textbf{boosts performance and consistency} over strong baselines across supervised, self-supervised, and synthetic data regimes. This work shows that round-trip consistency is not just a desirable property but a trainable objective, offering a new path toward more robust and reliable foundation models.","published":"2025-10-01T23:58:58Z","updated":"2025-10-01T23:58:58Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.01527v1","pdf_url":"https://arxiv.org/pdf/2510.01527v1","comment":"19 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.01384","versioned_id":"2510.01384v4","title":"Fine-Tuning Masked Diffusion for Provable Self-Correction","authors":["Jaeyeon Kim","Seunggeun Kim","Taekyun Lee","David Z. Pan","Hyeji Kim","Sham Kakade","Sitan Chen"],"abstract":"A natural desideratum for generative models is self-correction--detecting and revising low-quality tokens at inference. While Masked Diffusion Models (MDMs) have emerged as a promising approach for generative modeling in discrete spaces, their capacity for self-correction remains poorly understood. Prior attempts to incorporate self-correction into MDMs either require overhauling MDM architectures/training or rely on imprecise proxies for token quality, limiting their applicability. Motivated by this, we introduce PRISM--Plug-in Remasking for Inference-time Self-correction of Masked Diffusions--a lightweight, model-agnostic approach that applies to any pretrained MDM. Theoretically, PRISM defines a self-correction loss that provably learns per-token quality scores, without RL or a verifier. These quality scores are computed in the same forward pass with MDM and used to detect low-quality tokens. Empirically, PRISM advances MDM inference across domains and scales: Sudoku; unconditional text (170M); and code with LLaDA (8B).","published":"2025-10-01T19:15:25Z","updated":"2026-05-22T19:48:31Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.01384v4","pdf_url":"https://arxiv.org/pdf/2510.01384v4","comment":"Authorship statement: Jaeyeon Kim and Seunggeun Kim contributed equally, and Taekyun Lee is also a co first author","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.00938","versioned_id":"2510.00938v2","title":"Large Reasoning Models Learn Better Alignment from Flawed Thinking","authors":["ShengYun Peng","Eric Smith","Ivan Evtimov","Song Jiang","Pin-Yu Chen","Hongyuan Zhan","Haozhu Wang","Duen Horng Chau","Mahesh Pasupuleti","Jianfeng Chi"],"abstract":"Large reasoning models (LRMs) \"think\" by generating structured chain-of-thought (CoT) before producing a final answer, yet they still lack the ability to reason critically about safety alignment and are easily biased when a flawed premise is injected into their thought process. We propose RECAP (Robust Safety Alignment via Counter-Aligned Prefilling), a principled reinforcement learning (RL) method for post-training that explicitly teaches models to override flawed reasoning trajectories and reroute to safe and helpful responses. RECAP trains on a mixture of synthetically generated counter-aligned CoT prefills and standard prompts, requires no additional training cost or modifications beyond vanilla reinforcement learning from human feedback (RLHF), and substantially improves safety and jailbreak robustness, reduces overrefusal, and preserves core reasoning capability -- all while maintaining inference token budget. Extensive analysis shows that RECAP-trained models engage in self-reflection more frequently and remain robust under adaptive attacks, preserving safety even after repeated attempts to override their reasoning.","published":"2025-10-01T14:15:43Z","updated":"2026-04-09T18:00:59Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.00938v2","pdf_url":"https://arxiv.org/pdf/2510.00938v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.00568","versioned_id":"2510.00568v3","title":"ReSeek: A Self-Correcting Framework for Search Agents with Instructive Rewards","authors":["Shiyu Li","Yang Tang","Yifan Wang","Peiming Li","Xi Chen"],"abstract":"Search agents powered by Large Language Models (LLMs) have demonstrated significant potential in tackling knowledge-intensive tasks. Reinforcement learning (RL) has emerged as a powerful paradigm for training these agents to perform complex, multi-step reasoning. However, prior RL-based methods often rely on sparse or rule-based rewards, which can lead agents to commit to suboptimal or erroneous reasoning paths without the ability to recover. To address these limitations, we propose ReSeek, a novel self-correcting framework for training search agents. Our framework introduces a self-correction mechanism that empowers the agent to dynamically identify and recover from erroneous search paths during an episode. By invoking a special JUDGE action, the agent can judge the information and re-plan its search strategy. To guide this process, we design a dense, instructive process reward function, which decomposes into a correctness reward for retrieving factual information and a utility reward for finding information genuinely useful for the query. Furthermore, to mitigate the risk of data contamination in existing datasets, we introduce FictionalHot, a new and challenging benchmark with recently curated questions requiring complex reasoning. Being intuitively reasonable and practically simple, extensive experiments show that agents trained with ReSeek significantly outperform SOTA baselines in task success rate and path faithfulness.","published":"2025-10-01T06:44:28Z","updated":"2026-05-08T11:30:29Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.00568v3","pdf_url":"https://arxiv.org/pdf/2510.00568v3","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.00492","versioned_id":"2510.00492v3","title":"Rethinking Reward Models for Multi-Domain Test-Time Scaling","authors":["Dong Bok Lee","Seanie Lee","Sangwoo Park","Minki Kang","Jinheon Baek","Dongki Kim","Dominik Wagner","Jiongdao Jin","Heejun Lee","Tobias Bocklet","Jinyu Wang","Jingjing Fu","Sung Ju Hwang","Jiang Bian","Lei Song"],"abstract":"The reliability of large language models (LLMs) during test-time scaling is often assessed with \\emph{external verifiers} or \\emph{reward models} that distinguish correct reasoning from flawed logic. Prior work has studied both outcome reward models (ORMs), which assess only the final answer, and process reward models (PRMs), which score intermediate reasoning steps. Although PRMs are often viewed as advantageous due to their finer-grained supervision, much of the supporting evidence comes from math-adjacent settings, and their relative benefits across broader domains remain unclear. We present the first unified evaluation of four reward model variants, discriminative ORM and PRM (dORM, dPRM) and generative ORM and PRM (gORM, gPRM), across 14 diverse domains. Contrary to conventional wisdom, we find that (i) dORM performs on par with dPRM, (ii) gPRM is not competitive, and (iii) overall, gORM is the most robust, yielding significant and consistent gains across every tested domain. We attribute the worse performance of gPRM to the stepwise scoring process, which inherits label noise from LLM-based automatic labeling, leading to difficulties in evaluating long reasoning trajectories, including those involving self-correcting reasoning. Both our theoretical analysis and empirical observations indicate that stepwise aggregation compounds errors as reasoning length increases. These findings challenge the common assumption that fine-grained supervision is always better and support generative outcome verification for multi-domain deployment. Our \\href{https://github.com/db-Lee/Multi-RM}{\\underline{code}} is publicly available to facilitate future research in multi-domain settings.","published":"2025-10-01T04:21:14Z","updated":"2026-07-13T23:08:07Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.00492v3","pdf_url":"https://arxiv.org/pdf/2510.00492v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.26626","versioned_id":"2509.26626v2","title":"Recursive Self-Aggregation Unlocks Deep Thinking in Large Language Models","authors":["Siddarth Venkatraman","Vineet Jain","Sarthak Mittal","Vedant Shah","Johan Obando-Ceron","Yoshua Bengio","Brian R. Bartoldson","Bhavya Kailkhura","Guillaume Lajoie","Glen Berseth","Nikolay Malkin","Moksh Jain"],"abstract":"Test-time scaling methods improve the capabilities of large language models (LLMs) by increasing the amount of compute used during inference to make a prediction. Inference-time compute can be scaled in parallel by choosing among multiple independent solutions or sequentially through self-refinement. We propose Recursive Self-Aggregation (RSA), a test-time scaling method inspired by evolutionary methods that combines the benefits of both parallel and sequential scaling. Each step of RSA refines a population of candidate reasoning chains through aggregation of subsets to yield a population of improved solutions, which are then used as the candidate pool for the next iteration. Empirically, RSA delivers substantial performance gains with increasing compute budgets across diverse tasks, model families and sizes. Notably, RSA with Gemini 3 Flash attains performance near the top of the ARC-AGI-2 public leaderboard. RSA also enables Qwen3-4B-Instruct-2507 to achieve competitive performance with larger reasoning models, including DeepSeek-R1 and o3-mini (high), outperforming purely parallel and sequential scaling strategies across AIME-25, HMMT-25, Reasoning Gym, LiveCodeBench-v6, and SuperGPQA. We further propose a novel aggregation-aware reinforcement learning approach that yields significant performance gains by training the model to combine solutions.","published":"2025-09-30T17:58:03Z","updated":"2026-02-24T18:58:30Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.26626v2","pdf_url":"https://arxiv.org/pdf/2509.26626v2","comment":"23 pages, 10 figures. Project page: https://rsa-llm.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.26340","versioned_id":"2509.26340v1","title":"Memory-Driven Self-Improvement for Decision Making with Large Language Models","authors":["Xue Yan","Zijing Ou","Mengyue Yang","Yan Song","Haifeng Zhang","Yingzhen Li","Jun Wang"],"abstract":"Large language models (LLMs) have emerged as effective action policies for sequential decision-making (SDM) tasks due to their extensive prior knowledge. However, this broad yet general knowledge is often insufficient for specific decision-making tasks with limited task-related data, making it challenging to efficiently adapt LLMs to specific SDM tasks. To address this challenge, we propose a memory-driven self-improvement framework that combines LLM general prior knowledge with a compact memory of domain-specific experiences. Memory retains past interactions and associated Q-values, thereby capturing decision-relevant knowledge that facilitates accurate value estimation and informs the LLM prior refinement. The refined LLM prior, in turn, generates higher-reward trajectories that further enrich memory, forming a natural self-improvement framework where memory and LLM prior mutually reinforce each other. Experiments show that our memory-driven approach significantly outperforms both traditional RL and LLM-based baselines, e.g., improving performance by over 40\\% on in-distribution tasks and over 75\\% when generalized to unseen tasks in ALFWorld.","published":"2025-09-30T14:46:06Z","updated":"2025-09-30T14:46:06Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.26340v1","pdf_url":"https://arxiv.org/pdf/2509.26340v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.26048","versioned_id":"2509.26048v2","title":"RE-Searcher: Robust Agentic Search with Goal-oriented Planning and Self-reflection","authors":["Daocheng Fu","Jianbiao Mei","Licheng Wen","Xuemeng Yang","Cheng Yang","Rong Wu","Tao Hu","Siqi Li","Yufan Shen","Xinyu Cai","Pinlong Cai","Botian Shi","Yong Liu","Yu Qiao"],"abstract":"Large language models (LLMs) excel at knowledge-intensive question answering and reasoning, yet their real-world deployment remains constrained by knowledge cutoff, hallucination, and limited interaction modalities. Augmenting LLMs with external search tools helps alleviate these issues, but it also exposes agents to a complex search environment in which small, plausible variations in query formulation can steer reasoning into unproductive trajectories and amplify errors. We present a systematic analysis that quantifies how environmental complexity induces fragile search behaviors and, in turn, degrades overall performance. To address this challenge, we propose a simple yet effective approach to instantiate a search agent, RE-Searcher. During search, RE-Searcher explicitly articulates a concrete search goal and subsequently reflects on whether the retrieved evidence satisfies that goal. This combination of goal-oriented planning and self-reflection enables RE-Searcher to resist spurious cues in complex search environments and perform robust search. Extensive experiments show that our method improves search accuracy and achieves state-of-the-art results. Perturbation studies further demonstrate substantial resilience to noisy or misleading external signals, mitigating the fragility of the search process. We believe these findings offer practical guidance for integrating LLM-powered agents into more complex interactive environments and enabling more autonomous decision-making.","published":"2025-09-30T10:25:27Z","updated":"2025-10-10T03:18:13Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.26048v2","pdf_url":"https://arxiv.org/pdf/2509.26048v2","comment":"15 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.25849","versioned_id":"2509.25849v1","title":"Knapsack RL: Unlocking Exploration of LLMs via Optimizing Budget Allocation","authors":["Ziniu Li","Congliang Chen","Tianyun Yang","Tian Ding","Ruoyu Sun","Ge Zhang","Wenhao Huang","Zhi-Quan Luo"],"abstract":"Large Language Models (LLMs) can self-improve through reinforcement learning, where they generate trajectories to explore and discover better solutions. However, this exploration process is computationally expensive, often forcing current methods to assign limited exploration budgets to each task. This uniform allocation creates problematic edge cases: easy tasks consistently succeed while difficult tasks consistently fail, both producing zero gradients during training updates for the widely used Group Relative Policy Optimization (GRPO). We address this problem from the lens of exploration budget allocation. Viewing each task's exploration as an \"item\" with a distinct \"value\" and \"cost\", we establish a connection to the classical knapsack problem. This formulation allows us to derive an optimal assignment rule that adaptively distributes resources based on the model's current learning status. When applied to GRPO, our method increases the effective ratio of non-zero policy gradients by 20-40% during training. Acting as a computational \"free lunch\", our approach could reallocate exploration budgets from tasks where learning is saturated to those where it is most impactful. This enables significantly larger budgets (e.g., 93 rollouts) for especially challenging problems, which would be computationally prohibitive under a uniform allocation. These improvements translate to meaningful gains on mathematical reasoning benchmarks, with average improvements of 2-4 points and peak gains of 9 points on specific tasks. Notably, achieving comparable performance with traditional homogeneous allocation would require about 2x the computational resources.","published":"2025-09-30T06:41:57Z","updated":"2025-09-30T06:41:57Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.25849v1","pdf_url":"https://arxiv.org/pdf/2509.25849v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.00078","versioned_id":"2510.00078v1","title":"Adaptive and Resource-efficient Agentic AI Systems for Mobile and Embedded Devices: A Survey","authors":["Sicong Liu","Weiye Wu","Xiangrui Xu","Teng Li","Bowen Pang","Bin Guo","Zhiwen Yu"],"abstract":"Foundation models have reshaped AI by unifying fragmented architectures into scalable backbones with multimodal reasoning and contextual adaptation. In parallel, the long-standing notion of AI agents, defined by the sensing-decision-action loop, is entering a new paradigm: with FMs as their cognitive core, agents transcend rule-based behaviors to achieve autonomy, generalization, and self-reflection. This dual shift is reinforced by real-world demands such as autonomous driving, robotics, virtual assistants, and GUI agents, as well as ecosystem advances in embedded hardware, edge computing, mobile deployment platforms, and communication protocols that together enable large-scale deployment. Yet this convergence collides with reality: while applications demand long-term adaptability and real-time interaction, mobile and edge deployments remain constrained by memory, energy, bandwidth, and latency. This creates a fundamental tension between the growing complexity of FMs and the limited resources of deployment environments. This survey provides the first systematic characterization of adaptive, resource-efficient agentic AI systems. We summarize enabling techniques into elastic inference, test-time adaptation, dynamic multimodal integration, and agentic AI applications, and identify open challenges in balancing accuracy-latency-communication trade-offs and sustaining robustness under distribution shifts. We further highlight future opportunities in algorithm-system co-design, cognitive adaptation, and collaborative edge deployment. By mapping FM structures, cognition, and hardware resources, this work establishes a unified perspective toward scalable, adaptive, and resource-efficient agentic AI. We believe this survey can help readers to understand the connections between enabling technologies while promoting further discussions on the fusion of agentic intelligence and intelligent agents.","published":"2025-09-30T02:37:52Z","updated":"2025-09-30T02:37:52Z","categories":["cs.LG","cs.AI","cs.DC"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.00078v1","pdf_url":"https://arxiv.org/pdf/2510.00078v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.25651","versioned_id":"2509.25651v1","title":"AutoLabs: Cognitive Multi-Agent Systems with Self-Correction for Autonomous Chemical Experimentation","authors":["Gihan Panapitiya","Emily Saldanha","Heather Job","Olivia Hess"],"abstract":"The automation of chemical research through self-driving laboratories (SDLs) promises to accelerate scientific discovery, yet the reliability and granular performance of the underlying AI agents remain critical, under-examined challenges. In this work, we introduce AutoLabs, a self-correcting, multi-agent architecture designed to autonomously translate natural-language instructions into executable protocols for a high-throughput liquid handler. The system engages users in dialogue, decomposes experimental goals into discrete tasks for specialized agents, performs tool-assisted stoichiometric calculations, and iteratively self-corrects its output before generating a hardware-ready file. We present a comprehensive evaluation framework featuring five benchmark experiments of increasing complexity, from simple sample preparation to multi-plate timed syntheses. Through a systematic ablation study of 20 agent configurations, we assess the impact of reasoning capacity, architectural design (single- vs. multi-agent), tool use, and self-correction mechanisms. Our results demonstrate that agent reasoning capacity is the most critical factor for success, reducing quantitative errors in chemical amounts (nRMSE) by over 85% in complex tasks. When combined with a multi-agent architecture and iterative self-correction, AutoLabs achieves near-expert procedural accuracy (F1-score > 0.89) on challenging multi-step syntheses. These findings establish a clear blueprint for developing robust and trustworthy AI partners for autonomous laboratories, highlighting the synergistic effects of modular design, advanced reasoning, and self-correction to ensure both performance and reliability in high-stakes scientific applications. Code: https://github.com/pnnl/autolabs","published":"2025-09-30T01:51:46Z","updated":"2025-09-30T01:51:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.25651v1","pdf_url":"https://arxiv.org/pdf/2509.25651v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.25541","versioned_id":"2509.25541v2","title":"Vision-Zero: Scalable VLM Self-Improvement via Strategic Gamified Self-Play","authors":["Qinsi Wang","Bo Liu","Tianyi Zhou","Jing Shi","Yueqian Lin","Yiran Chen","Hai Helen Li","Kun Wan","Wentian Zhao"],"abstract":"Although reinforcement learning (RL) has emerged as a promising approach for improving vision-language models (VLMs) and multimodal large language models (MLLMs), current methods rely heavily on manually curated datasets and costly human verification, which limits scalable self-improvement in multimodal systems. To address this challenge, we propose Vision-Zero, a label-free, domain-agnostic multi-agent self-play framework for self-evolving VLMs through competitive visual games generated from arbitrary image inputs. Specifically, Vision-Zero encompasses three main attributes: (1) Strategic Self-Play Framework: Vision-Zero trains VLMs in \"Who Is the Spy\"-style games, where the models engage in strategic reasoning and actions across multiple roles. Through interactive gameplay, models autonomously generate their training data without human annotation. (2) Gameplay from Arbitrary Images: Unlike existing gamified frameworks, Vision-Zero can generate games from arbitrary images, thereby enhancing the model's reasoning ability across diverse domains and showing strong generalization to different tasks. We demonstrate this versatility using three distinct types of image datasets: CLEVR-based synthetic scenes, charts, and real-world images. (3) Sustainable Performance Gain: We introduce Iterative Self-Play Policy Optimization (Iterative-SPO), a novel training algorithm that alternates between Self-Play and reinforcement learning with verifiable rewards (RLVR), mitigating the performance plateau often seen in self-play-only training and achieving sustained long-term improvements. Despite using label-free data, Vision-Zero achieves state-of-the-art performance on reasoning, chart question answering, and vision-centric understanding tasks, surpassing other annotation-based methods. Models and code have been released at https://github.com/wangqinsi1/Vision-Zero.","published":"2025-09-29T21:55:55Z","updated":"2026-03-04T03:35:17Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.25541v2","pdf_url":"https://arxiv.org/pdf/2509.25541v2","comment":"ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.02373","versioned_id":"2510.02373v1","title":"A-MemGuard: A Proactive Defense Framework for LLM-Based Agent Memory","authors":["Qianshan Wei","Tengchao Yang","Yaochen Wang","Xinfeng Li","Lijun Li","Zhenfei Yin","Yi Zhan","Thorsten Holz","Zhiqiang Lin","XiaoFeng Wang"],"abstract":"Large Language Model (LLM) agents use memory to learn from past interactions, enabling autonomous planning and decision-making in complex environments. However, this reliance on memory introduces a critical security risk: an adversary can inject seemingly harmless records into an agent's memory to manipulate its future behavior. This vulnerability is characterized by two core aspects: First, the malicious effect of injected records is only activated within a specific context, making them hard to detect when individual memory entries are audited in isolation. Second, once triggered, the manipulation can initiate a self-reinforcing error cycle: the corrupted outcome is stored as precedent, which not only amplifies the initial error but also progressively lowers the threshold for similar attacks in the future. To address these challenges, we introduce A-MemGuard (Agent-Memory Guard), the first proactive defense framework for LLM agent memory. The core idea of our work is the insight that memory itself must become both self-checking and self-correcting. Without modifying the agent's core architecture, A-MemGuard combines two mechanisms: (1) consensus-based validation, which detects anomalies by comparing reasoning paths derived from multiple related memories and (2) a dual-memory structure, where detected failures are distilled into ``lessons'' stored separately and consulted before future actions, breaking error cycles and enabling adaptation. Comprehensive evaluations on multiple benchmarks show that A-MemGuard effectively cuts attack success rates by over 95% while incurring a minimal utility cost. This work shifts LLM memory security from static filtering to a proactive, experience-driven model where defenses strengthen over time. Our code is available in https://github.com/TangciuYueng/AMemGuard","published":"2025-09-29T16:04:15Z","updated":"2025-09-29T16:04:15Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2510.02373v1","pdf_url":"https://arxiv.org/pdf/2510.02373v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.24855","versioned_id":"2509.24855v1","title":"PhysicsMinions: Winning Gold Medals in the Latest Physics Olympiads with a Coevolutionary Multimodal Multi-Agent System","authors":["Fangchen Yu","Junchi Yao","Ziyi Wang","Haiyuan Wan","Youling Huang","Bo Zhang","Shuyue Hu","Dongzhan Zhou","Ning Ding","Ganqu Cui","Lei Bai","Wanli Ouyang","Peng Ye"],"abstract":"Physics is central to understanding and shaping the real world, and the ability to solve physics problems is a key indicator of real-world physical intelligence. Physics Olympiads, renowned as the crown of competitive physics, provide a rigorous testbed requiring complex reasoning and deep multimodal understanding, yet they remain largely underexplored in AI research. Existing approaches are predominantly single-model based, and open-source MLLMs rarely reach gold-medal-level performance. To address this gap, we propose PhysicsMinions, a coevolutionary multi-agent system for Physics Olympiad. Its architecture features three synergistic studios: a Visual Studio to interpret diagrams, a Logic Studio to formulate solutions, and a Review Studio to perform dual-stage verification. The system coevolves through an iterative refinement loop where feedback from the Review Studio continuously guides the Logic Studio, enabling the system to self-correct and converge towards the ground truth. Evaluated on the HiPhO benchmark spanning 7 latest physics Olympiads, PhysicsMinions delivers three major breakthroughs: (i) Strong generalization: it consistently improves both open-source and closed-source models of different sizes, delivering clear benefits over their single-model baselines; (ii) Historic breakthroughs: it elevates open-source models from only 1-2 to 6 gold medals across 7 Olympiads, achieving the first-ever open-source gold medal in the latest International Physics Olympiad (IPhO) under the average-score metric; and (iii) Scaling to human expert: it further advances the open-source Pass@32 score to 26.8/30 points on the latest IPhO, ranking 4th of 406 contestants and far surpassing the top single-model score of 22.7 (ranked 22nd). Generally, PhysicsMinions offers a generalizable framework for Olympiad-level problem solving, with the potential to extend across disciplines.","published":"2025-09-29T14:40:53Z","updated":"2025-09-29T14:40:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.24855v1","pdf_url":"https://arxiv.org/pdf/2509.24855v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2510.01270","versioned_id":"2510.01270v1","title":"Think Twice, Generate Once: Safeguarding by Progressive Self-Reflection","authors":["Hoang Phan","Victor Li","Qi Lei"],"abstract":"Large language models (LLMs) have revolutionized natural language processing with their ability to generate coherent and contextually relevant text. However, their deployment raises significant concerns about the potential for generating harmful or inappropriate content. In this paper, we introduce Progressive Self-Reflection (PSR), a novel inference-time technique that empowers LLMs to self-monitor and correct their outputs dynamically. Experimental results demonstrate that applying our proposed method to Llama-3.1-8B-Instruct reduces the attack success rate from 77.5\\% to 5.9\\%, to Llama-3.1-8B base from 89.7\\% to 5.6\\%, and to Qwen2.5-7B-Instruct from 44.4\\% to 3.8\\%, without additional training, while maintaining their original performance on benign tasks. Our approach acts as a test-time scaling method, where additional self-reflection rounds enhance safety at the cost of inference overhead. To balance safety with computational efficiency, we introduce a lightweight self-reflection predictor that estimates the optimal number of reflection rounds based on input complexity. This adaptive mechanism prevents unnecessary self-assessment on benign inputs while ensuring thorough evaluation when encountering potentially harmful content. Our findings suggest that Progressive Self-Reflection serves as a scalable test-time approach, enhancing LLM safety by dynamically allocating computational resources in proportion to the input's risk profile.","published":"2025-09-29T12:54:28Z","updated":"2025-09-29T12:54:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.01270v1","pdf_url":"https://arxiv.org/pdf/2510.01270v1","comment":"Accepted to EMNLP 2025 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.24726","versioned_id":"2509.24726v1","title":"Socratic-Zero : Bootstrapping Reasoning via Data-Free Agent Co-evolution","authors":["Shaobo Wang","Zhengbo Jiao","Zifan Zhang","Yilang Peng","Xu Ze","Boyu Yang","Wei Wang","Hu Wei","Linfeng Zhang"],"abstract":"Recent breakthroughs in large language models (LLMs) on reasoning tasks rely heavily on massive, high-quality datasets-typically human-annotated and thus difficult to scale. While data synthesis or distillation offers a promising alternative, existing methods struggle with inconsistent data quality and an inability to dynamically adapt to the evolving capabilities of the model, leading to suboptimal training signals. To address these limitations, we introduce Socratic-Zero, a fully autonomous framework that generates high-quality training data from minimal seed examples through the co-evolution of three agents: the Teacher, the Solver, and the Generator. The Solver continuously refines its reasoning by learning from preference feedback on both successful and failed trajectories; the Teacher adaptively crafts increasingly challenging questions based on the Solver's weaknesses; and the Generator distills the Teacher's question-design strategy to enable scalable, high-fidelity curriculum generation. This closed-loop system produces a self-improving curriculum-requiring no pre-existing tasks or labels. Remarkably, starting from only 100 seed questions, our Socratic-Solver-8B achieves an average gain of +20.2 percentage points over prior data synthesis methods across seven mathematical reasoning benchmarks (AMC23, AIME24-25, Olympiad, MATH-500, Minerva, and GSM8K), with consistent gains on both Qwen3 and GLM4 series models. Even more surprisingly, synthetic data from Socratic-Generator-32B enables student LLMs to achieve superior performance compared to other state-of-the-art (SOTA) commercial LLMs on these benchmarks, including Qwen3-235B-A22B, DeepSeek-V3.1-671B, GPT-5, Gemini-2.5-Pro, Grok-4, and Claude-4.1-Opus.","published":"2025-09-29T12:54:07Z","updated":"2025-09-29T12:54:07Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.24726v1","pdf_url":"https://arxiv.org/pdf/2509.24726v1","comment":"23 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.24524","versioned_id":"2509.24524v1","title":"PhysiAgent: An Embodied Agent Framework in Physical World","authors":["Zhihao Wang","Jianxiong Li","Jinliang Zheng","Wencong Zhang","Dongxiu Liu","Yinan Zheng","Haoyi Niu","Junzhi Yu","Xianyuan Zhan"],"abstract":"Vision-Language-Action (VLA) models have achieved notable success but often struggle with limited generalizations. To address this, integrating generalized Vision-Language Models (VLMs) as assistants to VLAs has emerged as a popular solution. However, current approaches often combine these models in rigid, sequential structures: using VLMs primarily for high-level scene understanding and task planning, and VLAs merely as executors of lower-level actions, leading to ineffective collaboration and poor grounding challenges. In this paper, we propose an embodied agent framework, PhysiAgent, tailored to operate effectively in physical environments. By incorporating monitor, memory, self-reflection mechanisms, and lightweight off-the-shelf toolboxes, PhysiAgent offers an autonomous scaffolding framework to prompt VLMs to organize different components based on real-time proficiency feedback from VLAs to maximally exploit VLAs' capabilities. Experimental results demonstrate significant improvements in task-solving performance on complex real-world robotic tasks, showcasing effective self-regulation of VLMs, coherent tool collaboration, and adaptive evolution of the framework during execution. PhysiAgent makes practical and pioneering efforts to integrate VLMs and VLAs, effectively grounding embodied agent frameworks in real-world settings.","published":"2025-09-29T09:39:32Z","updated":"2025-09-29T09:39:32Z","categories":["cs.RO","cs.AI","eess.SY"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2509.24524v1","pdf_url":"https://arxiv.org/pdf/2509.24524v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.24350","versioned_id":"2509.24350v1","title":"Dynamic Orchestration of Multi-Agent System for Real-World Multi-Image Agricultural VQA","authors":["Yan Ke","Xin Yu","Heming Du","Scott Chapman","Helen Huang"],"abstract":"Agricultural visual question answering is essential for providing farmers and researchers with accurate and timely knowledge. However, many existing approaches are predominantly developed for evidence-constrained settings such as text-only queries or single-image cases. This design prevents them from coping with real-world agricultural scenarios that often require multi-image inputs with complementary views across spatial scales, and growth stages. Moreover, limited access to up-to-date external agricultural context makes these systems struggle to adapt when evidence is incomplete. In addition, rigid pipelines often lack systematic quality control. To address this gap, we propose a self-reflective and self-improving multi-agent framework that integrates four roles, the Retriever, the Reflector, the Answerer, and the Improver. They collaborate to enable context enrichment, reflective reasoning, answer drafting, and iterative improvement. A Retriever formulates queries and gathers external information, while a Reflector assesses adequacy and triggers sequential reformulation and renewed retrieval. Two Answerers draft candidate responses in parallel to reduce bias. The Improver refines them through iterative checks while ensuring that information from multiple images is effectively aligned and utilized. Experiments on the AgMMU benchmark show that our framework achieves competitive performance on multi-image agricultural QA.","published":"2025-09-29T06:52:10Z","updated":"2025-09-29T06:52:10Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.24350v1","pdf_url":"https://arxiv.org/pdf/2509.24350v1","comment":"13 pages, 2 figures, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.24269","versioned_id":"2509.24269v1","title":"AdvChain: Adversarial Chain-of-Thought Tuning for Robust Safety Alignment of Large Reasoning Models","authors":["Zihao Zhu","Xinyu Wu","Gehan Hu","Siwei Lyu","Ke Xu","Baoyuan Wu"],"abstract":"Large Reasoning Models (LRMs) have demonstrated remarkable capabilities in complex problem-solving through Chain-of-Thought (CoT) reasoning. However, the multi-step nature of CoT introduces new safety challenges that extend beyond conventional language model alignment. We identify a failure mode in current safety CoT tuning methods: the \\textit{snowball effect}, where minor reasoning deviations progressively amplify throughout the thought process, leading to either harmful compliance or excessive refusal. This effect stems from models being trained to imitate perfect reasoning scripts without learning to self-correct. To address this limitation, we propose AdvChain, an alignment paradigm that teaches models dynamic self-correction through adversarial CoT tuning. Our method involves constructing a dataset containing Temptation-Correction and Hesitation-Correction samples, where models learn to recover from harmful reasoning drifts and unnecessary cautions. Extensive experiments show that AdvChain significantly enhances robustness against jailbreak attacks and CoT hijacking while substantially reducing over-refusal on benign prompts, achieving a superior safety-utility balance without compromising reasoning capabilities. Our work establishes a new direction for building more robust and reliable reasoning models.","published":"2025-09-29T04:27:23Z","updated":"2025-09-29T04:27:23Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.24269v1","pdf_url":"https://arxiv.org/pdf/2509.24269v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23885","versioned_id":"2509.23885v3","title":"Extendable Generalization Self-Supervised Diffusion for Low-Dose CT Reconstruction","authors":["Guoquan Wei","Liu Shi","Zekun Zhou","Mohan Li","Cunfeng Wei","Wenzhe Shan","Qiegen Liu"],"abstract":"Current methods based on deep learning for self-supervised low-dose CT (LDCT) reconstruction, while reducing the dependence on paired data, face the problem of significantly decreased generalization when training with single-dose data and extending to other doses. To enable dose-extensive generalization using only single-dose projection data for training, this work proposes a novel method of Extendable GENeraLization self-supervised Diffusion (EGenDiff) for low-dose CT reconstruction. Specifically, a contextual subdata self-enhancing similarity strategy is designed to provide an initial prior for the subsequent progress. During training, the initial prior is used to combine knowledge distillation with a deep combination of latent diffusion models for optimizing image details. On the stage of inference, the pixel-wise self-correcting fusion technique is proposed for data fidelity enhancement, resulting in extensive generalization of higher and lower doses or even unseen doses. EGenDiff requires only LDCT projection data for training and testing. Comprehensive evaluation on benchmark datasets, clinical data, photon counting CT data, and across all three anatomical planes (transverse, coronal, and sagittal) demonstrates that EGenDiff enables extendable generalization multi-dose, yielding reconstructions that consistently outperform leading existing methods.","published":"2025-09-28T13:50:29Z","updated":"2026-01-21T06:51:02Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.23885v3","pdf_url":"https://arxiv.org/pdf/2509.23885v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23863","versioned_id":"2509.23863v4","title":"SPELL: Self-Play Reinforcement Learning for Evolving Long-Context Language Models","authors":["Ziyi Yang","Weizhou Shen","Chenliang Li","Ruijun Chen","Fanqi Wan","Ming Yan","Xiaojun Quan","Fei Huang"],"abstract":"Progress in long-context reasoning for large language models (LLMs) has lagged behind other recent advances. This gap arises not only from the intrinsic difficulty of processing long texts, but also from the scarcity of reliable human annotations and programmatically verifiable reward signals. In this paper, we propose SPELL, a multi-role self-play reinforcement learning framework that enables scalable, label-free optimization for long-context reasoning. SPELL integrates three cyclical roles-questioner, responder, and verifier-within a single model to enable continual self-improvement. The questioner generates questions from raw documents paired with reference answers; the responder learns to solve these questions based on the documents; and the verifier evaluates semantic equivalence between the responder's output and the questioner's reference answer, producing reward signals to guide continual training. To stabilize training, we introduce an automated curriculum that gradually increases document length and a reward function that adapts question difficulty to the model's evolving capabilities. Extensive experiments on six long-context benchmarks show that SPELL consistently improves performance across diverse LLMs and outperforms equally sized models fine-tuned on large-scale annotated data. Notably, SPELL achieves an average 7.6-point gain in pass@8 on the strong reasoning model Qwen3-30B-A3B-Thinking, raising its performance ceiling and showing promise for scaling to even more capable models. Our code is available at https://github.com/Tongyi-Zhiwen/Qwen-Doc.","published":"2025-09-28T13:08:10Z","updated":"2026-03-13T10:33:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.23863v4","pdf_url":"https://arxiv.org/pdf/2509.23863v4","comment":"Accepted to ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23746","versioned_id":"2509.23746v1","title":"Poivre: Self-Refining Visual Pointing with Reinforcement Learning","authors":["Wenjie Yang","Zengfeng Huang"],"abstract":"Visual pointing, which aims to localize a target by predicting its coordinates on an image, has emerged as an important problem in the realm of vision-language models (VLMs). Despite its broad applicability, recent benchmarks show that current VLMs still fall far behind human performance on this task. A key limitation is that VLMs are typically required to complete the pointing task in a single step, akin to asking humans to point at an object without seeing their own fingers. To address this issue, we propose a simple yet effective self-refining procedure: Point, Visualize, then Refine (Poivre). This procedure enables a VLM to first mark its estimated point, then iteratively refine the coordinates if necessary. Inspired by advances of reasoning models in the natural language domain, we employ reinforcement learning (RL) to incentivize this self-refining ability. For the RL training, we design a neat process reward that is not only empirically effective but also grounded in appealing properties. Our trained model, Poivre-7B, sets a new state of the art on Point-Bench, outperforming both proprietary models such as Gemini-2.5-Pro and large open-source models such as Molmo-72B by over 3%. To support future research, we release our training and inference code, dataset, and the Poivre-7B checkpoint.","published":"2025-09-28T08:51:47Z","updated":"2025-09-28T08:51:47Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.23746v1","pdf_url":"https://arxiv.org/pdf/2509.23746v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23676","versioned_id":"2509.23676v1","title":"From Reasoning to Answer: Empirical, Attention-Based and Mechanistic Insights into Distilled DeepSeek R1 Models","authors":["Jue Zhang","Qingwei Lin","Saravan Rajmohan","Dongmei Zhang"],"abstract":"Large Reasoning Models (LRMs) generate explicit reasoning traces alongside final answers, yet the extent to which these traces influence answer generation remains unclear. In this work, we conduct a three-stage investigation into the interplay between reasoning and answer generation in three distilled DeepSeek R1 models. First, through empirical evaluation, we demonstrate that including explicit reasoning consistently improves answer quality across diverse domains. Second, attention analysis reveals that answer tokens attend substantially to reasoning tokens, with certain mid-layer Reasoning-Focus Heads (RFHs) closely tracking the reasoning trajectory, including self-reflective cues. Third, we apply mechanistic interventions using activation patching to assess the dependence of answer tokens on reasoning activations. Our results show that perturbations to key reasoning tokens can reliably alter the final answers, confirming a directional and functional flow of information from reasoning to answer. These findings deepen our understanding of how LRMs leverage reasoning tokens for answer generation, highlighting the functional role of intermediate reasoning in shaping model outputs. Our data and code are publicly available at \\href{https://aka.ms/R2A-code}{this URL}.","published":"2025-09-28T06:32:21Z","updated":"2025-09-28T06:32:21Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.23676v1","pdf_url":"https://arxiv.org/pdf/2509.23676v1","comment":"Accepted by EMNLP'25 (Main)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23653","versioned_id":"2509.23653v1","title":"Don't Settle Too Early: Self-Reflective Remasking for Diffusion Language Models","authors":["Zemin Huang","Yuhang Wang","Zhiyang Chen","Guo-Jun Qi"],"abstract":"Mask-based Diffusion Language Models (DLMs) struggle to revise incorrect tokens: once a token is generated, it typically remains fixed. The key challenge is to identify potential errors in the inputs. In this paper, we propose \\emph{\\underline{Rem}asking-\\underline{e}nabled \\underline{Di}ffusion Language Model (RemeDi}, a mask-based DLM that introduces \\emph{remasking} as another fundamental mechanism, enabling more flexible text refinement in diffusion-based text generation. To achieve this, RemeDi jointly predicts token distributions and per-token confidence scores at each step. The confidence scores determine which tokens to be unmasked after the current step, allowing the model to identify tokens with low quality and remask them. These remasked tokens can be resampled with richer context in subsequent steps. We design a remask-aware pipeline to train this ability, including supervised fine-tuning which teaches the model to detect and remask incorrect tokens in addition to predict mask tokens, and reinforcement learning which optimizes full generation trajectories toward higher rewards. Experiments show that RemeDi achieves the state-of-the-art results among open-source DLMs on multiple datasets.","published":"2025-09-28T05:39:49Z","updated":"2025-09-28T05:39:49Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.23653v1","pdf_url":"https://arxiv.org/pdf/2509.23653v1","comment":"24 pages,11 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23625","versioned_id":"2509.23625v1","title":"RIV: Recursive Introspection Mask Diffusion Vision Language Model","authors":["YuQian Li","Limeng Qiao","Lin Ma"],"abstract":"Mask Diffusion-based Vision Language Models (MDVLMs) have achieved remarkable progress in multimodal understanding tasks. However, these models are unable to correct errors in generated tokens, meaning they lack self-correction capability. In this paper, we propose Recursive Introspection Mask Diffusion Vision Language Model (RIV), which equips the model with self-correction ability through two novel mechanisms. The first is Introspection Training, where an Introspection Model is introduced to identify errors within generated sequences. Introspection Training enables the model to detect not only grammatical and spelling mistakes, but more importantly, logical errors. The second is Recursive Inference. Beginning with the standard unmasking step, the learned Introspection Model helps to identify errors in the output sequence and remask them. This alternating ($\\text{unmask}\\rightarrow\\text{introspection}\\rightarrow\\text{remask}$) process is repeated recursively until reliable results are obtained. Experimental results on multiple benchmarks demonstrate that the proposed RIV achieves state-of-the-art performance, outperforming most existing MDVLMs.","published":"2025-09-28T04:01:46Z","updated":"2025-09-28T04:01:46Z","categories":["cs.CV","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.23625v1","pdf_url":"https://arxiv.org/pdf/2509.23625v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23452","versioned_id":"2509.23452v1","title":"FoR-SALE: Frame of Reference-guided Spatial Adjustment in LLM-based Diffusion Editing","authors":["Tanawan Premsri","Parisa Kordjamshidi"],"abstract":"Frame of Reference (FoR) is a fundamental concept in spatial reasoning that humans utilize to comprehend and describe space. With the rapid progress in Multimodal Language models, the moment has come to integrate this long-overlooked dimension into these models. In particular, in text-to-image (T2I) generation, even state-of-the-art models exhibit a significant performance gap when spatial descriptions are provided from perspectives other than the camera. To address this limitation, we propose Frame of Reference-guided Spatial Adjustment in LLM-based Diffusion Editing (FoR-SALE), an extension of the Self-correcting LLM-controlled Diffusion (SLD) framework for T2I. For-Sale evaluates the alignment between a given text and an initially generated image, and refines the image based on the Frame of Reference specified in the spatial expressions. It employs vision modules to extract the spatial configuration of the image, while simultaneously mapping the spatial expression to a corresponding camera perspective. This unified perspective enables direct evaluation of alignment between language and vision. When misalignment is detected, the required editing operations are generated and applied. FoR-SALE applies novel latent-space operations to adjust the facing direction and depth of the generated images. We evaluate FoR-SALE on two benchmarks specifically designed to assess spatial understanding with FoR. Our framework improves the performance of state-of-the-art T2I models by up to 5.3% using only a single round of correction.","published":"2025-09-27T18:42:04Z","updated":"2025-09-27T18:42:04Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.23452v1","pdf_url":"https://arxiv.org/pdf/2509.23452v1","comment":"9 pages, 3 Tables, 4 Figures, Under Reviewed","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23236","versioned_id":"2509.23236v1","title":"Self-Consistency as a Free Lunch: Reducing Hallucinations in Vision-Language Models via Self-Reflection","authors":["Mingfei Han","Haihong Hao","Jinxing Zhou","Zhihui Li","Yuhui Zheng","Xueqing Deng","Linjie Yang","Xiaojun Chang"],"abstract":"Vision-language models often hallucinate details, generating non-existent objects or inaccurate attributes that compromise output reliability. Existing methods typically address these issues via extensive human annotations or external supervision from more powerful models. In this work, we present a novel framework that leverages the model's self-consistency between long responses and short answers to generate preference pairs for training. We observe that short binary questions tend to yield highly reliable responses, which can be used to query the target model to evaluate and rank its generated responses. Specifically, we design a self-reflection pipeline where detailed model responses are compared against concise binary answers, and inconsistency signals are utilized to automatically curate high-quality training data without human annotations or external model-based supervision. By relying solely on self-consistency rather than external supervision, our method offers a scalable and efficient solution that effectively reduces hallucinations using unlabeled data. Extensive experiments on multiple benchmarks, i.e., AMBER, MultiObject-Hal (ROPE), Object HalBench, and MMHal-Bench, demonstrate significant improvements in factual grounding and reliability. Moreover, our approach maintains robust instruction-following ability, as evidenced by enhanced performance on LLaVA-Bench and MMBench.","published":"2025-09-27T10:37:11Z","updated":"2025-09-27T10:37:11Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.23236v1","pdf_url":"https://arxiv.org/pdf/2509.23236v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23196","versioned_id":"2509.23196v1","title":"From Harm to Help: Turning Reasoning In-Context Demos into Assets for Reasoning LMs","authors":["Haonan Wang","Weida Liang","Zihang Fu","Nie Zheng","Yifan Zhang","Yao Tong","Tongyao Zhu","Hao Jiang","Chuang Li","Jiaying Wu","Kenji Kawaguchi"],"abstract":"Recent reasoning LLMs (RLMs), especially those trained with verifier-based reinforcement learning, often perform worse with few-shot CoT than with direct answering. We revisit this paradox using high-quality reasoning traces from DeepSeek-R1 as demonstrations and find that adding more exemplars consistently degrades accuracy, even when demonstrations are optimal. A detailed analysis reveals two mechanisms behind this decline: (i) semantic misguidance, where high textual similarity leads the model to treat the target as the same as the exemplar and to copy intermediate steps verbatim; and (ii) strategy transfer failure, where the model struggles to extract useful reasoning strategies and apply them to target questions. Guided by these, we introduce Insight-to-Solve (I2S), a sequential test-time procedure that turns demonstrations into explicit, reusable insights and derives a target-specific reasoning trace; optionally, the reasoning is self-refined for coherence and correctness (I2S+). Extensive experiments on diverse benchmarks show that I2S and I2S+ consistently outperform both direct answering and test-time scaling baselines across open- and closed-source models. Even for GPT models, our method helps: on AIME'25, GPT-4.1 rises by +14.0%, and o1-mini improves by +2.7% on AIME and +1.7% on GPQA, indicating that in-context demonstrations can be harnessed effectively via insight-refine-solve framework.","published":"2025-09-27T08:59:31Z","updated":"2025-09-27T08:59:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.23196v1","pdf_url":"https://arxiv.org/pdf/2509.23196v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23166","versioned_id":"2509.23166v2","title":"Test-Time Policy Adaptation for Enhanced Multi-Turn Interactions with LLMs","authors":["Chenxing Wei","Hong Wang","Ying He","Fei Yu","Yao Shu"],"abstract":"Large Language Models (LLMs) employ multi-turn interaction as a fundamental paradigm for completing complex tasks. However, their performance often degrades in extended interactions, as they are typically trained on static, single-turn data, which hinders their ability to adapt to real-time user feedback. To address this limitation, we first propose a new paradigm: Test-Time Policy Adaptation for Multi-Turn Interactions (T2PAM), which utilizes user feedback from the ongoing interaction as a reward signal to estimate a latent optimal policy aligned with user preferences, then updates a small subset of parameters to steer the model toward this policy, ultimately enabling efficient in-conversation self-correction. We then introduce Optimum-Referenced One-Step Adaptation (ROSA), a lightweight algorithm that operationalizes T2PAM. ROSA guides the model parameters toward a theoretical optimal policy in a single, efficient update step, avoiding costly iterative gradient-based optimization and minimizing computational overhead. We provide a rigorous theoretical analysis guaranteeing that the policy of ROSA converges to the preference of user as the number of interactions increases. Extensive experiments on challenging benchmark demonstrate that ROSA achieves significant improvements in both task effectiveness and efficiency.","published":"2025-09-27T07:46:15Z","updated":"2026-03-02T02:32:21Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.23166v2","pdf_url":"https://arxiv.org/pdf/2509.23166v2","comment":"32 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23067","versioned_id":"2509.23067v2","title":"Semantic Voting: A Self-Evaluation-Free Approach for Efficient LLM Self-Improvement on Unverifiable Open-ended Tasks","authors":["Chunyang Jiang","Yonggang Zhang","Yiyang Cai","Chi-Min Chan","Yulong Liu","Mingming Chen","Wei Xue","Yike Guo"],"abstract":"The rising cost of acquiring supervised data has driven significant interest in self-improvement for large language models (LLMs). Straightforward unsupervised signals like majority voting have proven effective in generating pseudo-labels for verifiable tasks, while their applicability to unverifiable tasks (e.g., translation) is limited by the open-ended character of responses. As a result, self-evaluation mechanisms (e.g., self-judging and entropy minimization) are predominantly used to derive pseudo-labels. However, self-evaluation relying on LLMs typically incurs high computational overhead and introduces overconfidence issues due to intrinsic biases. To address these challenges, we propose a novel self-evaluation-free approach for unverifiable tasks, designed for lightweight yet effective self-improvement. Inspired by majority voting commonly employed in verifiable tasks, we propose semantic voting as a novel mechanism that relaxes the principle of hard matching (i.e., exact matching) toward soft matching (i.e., semantic similarity). Soft matching is achieved by leveraging a lightweight sentence embedding model to quantify semantic similarity, thereby mitigating excessive computational burden and intrinsic bias-associated limitations of self-evaluation. Comprehensive experiments demonstrate that our method achieves substantial gains in computational efficiency and overall better performance than self-evaluation methods across diverse model architectures and tasks.","published":"2025-09-27T02:44:05Z","updated":"2026-03-31T10:04:49Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.23067v2","pdf_url":"https://arxiv.org/pdf/2509.23067v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.23045","versioned_id":"2509.23045v3","title":"Kimi-Dev: Agentless Training as Skill Prior for SWE-Agents","authors":["Zonghan Yang","Shengjie Wang","Kelin Fu","Wenyang He","Weimin Xiong","Yibo Liu","Yibo Miao","Bofei Gao","Yejie Wang","Yingwei Ma","Yanhao Li","Yue Liu","Zhenxing Hu","Kaitai Zhang","Shuyi Wang","Huarong Chen","Flood Sung","Yang Liu","Yang Gao","Zhilin Yang","Tianyu Liu"],"abstract":"Large Language Models (LLMs) are increasingly applied to software engineering (SWE), with SWE-bench as a key benchmark. Solutions are split into SWE-Agent frameworks with multi-turn interactions and workflow-based Agentless methods with single-turn verifiable steps. We argue these paradigms are not mutually exclusive: reasoning-intensive Agentless training induces skill priors, including localization, code edit, and self-reflection that enable efficient and effective SWE-Agent adaptation. In this work, we first curate the Agentless training recipe and present Kimi-Dev, an open-source SWE LLM achieving 60.4\\% on SWE-bench Verified, the best among workflow approaches. With additional SFT adaptation on 5k publicly-available trajectories, Kimi-Dev powers SWE-Agents to 48.6\\% pass@1, on par with that of Claude 3.5 Sonnet (241022 version). These results show that structured skill priors from Agentless training can bridge workflow and agentic frameworks for transferable coding agents.","published":"2025-09-27T01:49:13Z","updated":"2025-12-08T17:33:03Z","categories":["cs.AI","cs.CL","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.23045v3","pdf_url":"https://arxiv.org/pdf/2509.23045v3","comment":"68 pages. GitHub repo at https://github.com/MoonshotAI/Kimi-Dev","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.22624","versioned_id":"2509.22624v1","title":"SPARK: Synergistic Policy And Reward Co-Evolving Framework","authors":["Ziyu Liu","Yuhang Zang","Shengyuan Ding","Yuhang Cao","Xiaoyi Dong","Haodong Duan","Dahua Lin","Jiaqi Wang"],"abstract":"Recent Large Language Models (LLMs) and Large Vision-Language Models (LVLMs) increasingly use Reinforcement Learning (RL) for post-pretraining, such as RL with Verifiable Rewards (RLVR) for objective tasks and RL from Human Feedback (RLHF) for subjective tasks. However, RLHF incurs high costs and potential reward-policy mismatch due to reliance on human preferences, while RLVR still wastes supervision by discarding rollouts and correctness signals after each update. To address these challenges, we introduce the Synergistic Policy And Reward Co-Evolving Framework (SPARK), an efficient, on-policy, and stable method that builds on RLVR. Instead of discarding rollouts and correctness data, SPARK recycles this valuable information to simultaneously train the model itself as a generative reward model. This auxiliary training uses a mix of objectives, such as pointwise reward score, pairwise comparison, and evaluation conditioned on further-reflection responses, to teach the model to evaluate and improve its own responses. Our process eliminates the need for a separate reward model and costly human preference data. SPARK creates a positive co-evolving feedback loop: improved reward accuracy yields better policy gradients, which in turn produce higher-quality rollouts that further refine the reward model. Our unified framework supports test-time scaling via self-reflection without external reward models and their associated costs. We show that SPARK achieves significant performance gains on multiple LLM and LVLM models and multiple reasoning, reward models, and general benchmarks. For example, SPARK-VL-7B achieves an average 9.7% gain on 7 reasoning benchmarks, 12.1% on 2 reward benchmarks, and 1.5% on 8 general benchmarks over the baselines, demonstrating robustness and broad generalization.","published":"2025-09-26T17:50:12Z","updated":"2025-09-26T17:50:12Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.22624v1","pdf_url":"https://arxiv.org/pdf/2509.22624v1","comment":"Project:https://github.com/InternLM/Spark","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.22557","versioned_id":"2509.22557v5","title":"Self-Improving Neural-Guided Pruning: A Graph Neural Network Framework for Scalable Mixed Bundle Pricing","authors":["Liangyu Ding","Chenghan Wu","Guokai Li","Zizhuo Wang"],"abstract":"Mixed bundle pricing is a classic revenue management problem arising in industries such as e-commerce, tourism, and video games. It refers to designing product combinations (i.e., bundles) and determining their prices to maximize expected profit. Exact mixed bundling models capture this structure but become computationally intractable because the number of candidate bundles grows exponentially with the number of products. We develop a graph neural network (GNN)-guided pruning-then-optimization framework for bundle pricing with (non-)additive valuations. The method represents each instance as a compact segment-product graph, predicts segment-product inclusion probabilities, and accordingly prunes the exponential bundle space into a small candidate family; the final prices and bundle offerings are obtained by solving the mixed bundling formulation over the retained bundles, possibly refined by a GNN-guided local search. Because exact labels are available only at small scales, we further propose an iterative self-improvement procedure: the current GNN policies generate high-quality solutions on large-scale instances, which serve as near-optimal labels for training a stronger model at larger scales. Theoretically, we show that under mild conditions the proposed edge-output GNN class is expressive enough to represent the optimal product-assignment mapping, justifying the edge-level learning target. Numerical experiments show that the fastest proposed policy delivers 13-21% higher profit than bundle-size pricing on instances with up to 100 products at about 2% of its runtime.","published":"2025-09-26T16:39:00Z","updated":"2026-07-09T20:33:31Z","categories":["cs.LG","math.OC"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.22557v5","pdf_url":"https://arxiv.org/pdf/2509.22557v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.22403","versioned_id":"2509.22403v2","title":"MoveFM-R: Advancing Mobility Foundation Models via Language-driven Semantic Reasoning","authors":["Fanjin Meng","Yuan Yuan","Jingtao Ding","Jie Feng","Chonghua Han","Yong Li"],"abstract":"Mobility Foundation Models (MFMs) have advanced the modeling of human movement patterns, yet they face a ceiling due to limitations in data scale and semantic understanding. While Large Language Models (LLMs) offer powerful semantic reasoning, they lack the innate understanding of spatio-temporal statistics required for generating physically plausible mobility trajectories. To address these gaps, we propose MoveFM-R, a novel framework that unlocks the full potential of mobility foundation models by leveraging language-driven semantic reasoning capabilities. It tackles two key challenges: the vocabulary mismatch between continuous geographic coordinates and discrete language tokens, and the representation gap between the latent vectors of MFMs and the semantic world of LLMs. MoveFM-R is built on three core innovations: a semantically enhanced location encoding to bridge the geography-language gap, a progressive curriculum to align the LLM's reasoning with mobility patterns, and an interactive self-reflection mechanism for conditional trajectory generation. Extensive experiments demonstrate that MoveFM-R significantly outperforms existing MFM-based and LLM-based baselines. It also shows robust generalization in zero-shot settings and excels at generating realistic trajectories from natural language instructions. By synthesizing the statistical power of MFMs with the deep semantic understanding of LLMs, MoveFM-R pioneers a new paradigm that enables a more comprehensive, interpretable, and powerful modeling of human mobility. The implementation of MoveFM-R is available online at https://anonymous.4open.science/r/MoveFM-R-CDE7/.","published":"2025-09-26T14:31:57Z","updated":"2026-04-13T03:01:43Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.22403v2","pdf_url":"https://arxiv.org/pdf/2509.22403v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.22378","versioned_id":"2509.22378v2","title":"Zero-Effort Image-to-Music Generation: An Interpretable RAG-based VLM Approach","authors":["Zijian Zhao","Dian Jin","Zijing Zhou"],"abstract":"Recently, Image-to-Music (I2M) generation has garnered significant attention, with potential applications in fields such as gaming, advertising, and multi-modal art creation. However, due to the ambiguous and subjective nature of I2M tasks, most end-to-end methods lack interpretability, leaving users puzzled about the generation results. Even methods based on emotion mapping face controversy, as emotion represents only a singular aspect of art. Additionally, most learning-based methods require substantial computational resources and large datasets for training, hindering accessibility for common users. To address these challenges, we propose the first Vision Language Model (VLM)-based I2M framework that offers high interpretability and low computational cost. Specifically, we utilize ABC notation to bridge the text and music modalities, enabling the VLM to generate music using natural language. We then apply multi-modal Retrieval-Augmented Generation (RAG) and self-refinement techniques to allow the VLM to produce high-quality music without external training. Furthermore, we leverage the generated motivations in text and the attention maps from the VLM to provide explanations for the generated results in both text and image modalities. To validate our method, we conduct both human studies and machine evaluations, where our method outperforms others in terms of music quality and music-image consistency, indicating promising results. Our code is available at https://github.com/RS2002/Image2Music .","published":"2025-09-26T14:07:29Z","updated":"2026-04-16T08:15:21Z","categories":["cs.SD","cs.AI","cs.MM","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2509.22378v2","pdf_url":"https://arxiv.org/pdf/2509.22378v2","comment":"","journal_ref":"","doi":"10.1145/3805622.3810723","discovered_on":"2026-07-17"},{"id":"2509.25238","versioned_id":"2509.25238v1","title":"PALADIN: Self-Correcting Language Model Agents to Cure Tool-Failure Cases","authors":["Sri Vatsa Vuddanti","Aarav Shah","Satwik Kumar Chittiprolu","Tony Song","Sunishchal Dev","Kevin Zhu","Maheep Chaudhary"],"abstract":"Tool-augmented language agents frequently fail in real-world deployment due to tool malfunctions--timeouts, API exceptions, or inconsistent outputs--triggering cascading reasoning errors and task abandonment. Existing agent training pipelines optimize only for success trajectories, failing to expose models to the tool failures that dominate real-world usage. We propose \\textbf{PALADIN}, a generalizable framework for equipping language agents with robust failure recovery capabilities. PALADIN trains on 50,000+ recovery-annotated trajectories constructed via systematic failure injection and expert demonstrations on an enhanced ToolBench dataset. Training uses LoRA-based fine-tuning to retain base capabilities while injecting recovery competence. At inference, PALADIN detects execution-time errors and retrieves the most similar case from a curated bank of 55+ failure exemplars aligned with ToolScan's taxonomy, then executes the corresponding recovery action. This approach generalizes to novel failures beyond the training distribution, retaining 95.2\\% recovery performance on unseen tool APIs. Evaluation across PaladinEval and ToolReflectEval demonstrates consistent improvements in Recovery Rate (RR), Task Success Rate (TSR), Catastrophic Success Rate (CSR), and Efficiency Score (ES). PALADIN improves RR from 32.76% to 89.68% (+57% relative) over ToolBench and outperforms the strongest baseline CRITIC (76.34%) by +13.3%. Against vanilla agents, PALADIN achieves 89.86\\% RR (+66% relative improvement from 23.75%). These results establish PALADIN as an effective method for building fault-tolerant agents capable of robust recovery in real-world tool environments.","published":"2025-09-25T10:37:30Z","updated":"2025-09-25T10:37:30Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.25238v1","pdf_url":"https://arxiv.org/pdf/2509.25238v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.20562","versioned_id":"2509.20562v1","title":"SAMULE: Self-Learning Agents Enhanced by Multi-level Reflection","authors":["Yubin Ge","Salvatore Romeo","Jason Cai","Monica Sunkara","Yi Zhang"],"abstract":"Despite the rapid advancements in LLM agents, they still face the challenge of generating meaningful reflections due to inadequate error analysis and a reliance on rare successful trajectories, especially in complex tasks. In this work, we propose SAMULE, a new framework for self-learning agents powered by a retrospective language model that is trained based on Multi-Level Reflection Synthesis. It first synthesizes high-quality reflections across three complementary levels: Single-Trajectory Learning (micro-level) for detailed error correction; Intra-Task Learning (meso-level) to build error taxonomies across multiple trials of the same task, and Inter-Task Learning (macro-level) to extract transferable insights based on same typed errors from diverse task failures. Then we fine-tune a language model serving as the retrospective model to generate reflections during inference. We further extend our framework to interactive settings through a foresight-based reflection mechanism, enabling agents to proactively reflect and adapt during user interactions by comparing predicted and actual responses. Extensive experiments on three challenging benchmarks - TravelPlanner, NATURAL PLAN, and Tau-bench - demonstrate that our approach significantly outperforms reflection-based baselines. Our results highlight the critical role of well-designed reflection synthesis and failure-centric learning in building self-improving LLM agents.","published":"2025-09-24T21:02:15Z","updated":"2025-09-24T21:02:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.20562v1","pdf_url":"https://arxiv.org/pdf/2509.20562v1","comment":"Accepted at EMNLP 2025 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.20190","versioned_id":"2509.20190v1","title":"STAF: Leveraging LLMs for Automated Attack Tree-Based Security Test Generation","authors":["Tanmay Khule","Stefan Marksteiner","Jose Alguindigue","Hannes Fuchs","Sebastian Fischmeister","Apurva Narayan"],"abstract":"In modern automotive development, security testing is critical for safeguarding systems against increasingly advanced threats. Attack trees are widely used to systematically represent potential attack vectors, but generating comprehensive test cases from these trees remains a labor-intensive, error-prone task that has seen limited automation in the context of testing vehicular systems. This paper introduces STAF (Security Test Automation Framework), a novel approach to automating security test case generation. Leveraging Large Language Models (LLMs) and a four-step self-corrective Retrieval-Augmented Generation (RAG) framework, STAF automates the generation of executable security test cases from attack trees, providing an end-to-end solution that encompasses the entire attack surface. We particularly show the elements and processes needed to provide an LLM to actually produce sensible and executable automotive security test suites, along with the integration with an automated testing framework. We further compare our tailored approach with general purpose (vanilla) LLMs and the performance of different LLMs (namely GPT-4.1 and DeepSeek) using our approach. We also demonstrate the method of our operation step-by-step in a concrete case study. Our results show significant improvements in efficiency, accuracy, scalability, and easy integration in any workflow, marking a substantial advancement in automating automotive security testing methodologies. Using TARAs as an input for verfication tests, we create synergies by connecting two vital elements of a secure automotive development process.","published":"2025-09-24T14:46:42Z","updated":"2025-09-24T14:46:42Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2509.20190v1","pdf_url":"https://arxiv.org/pdf/2509.20190v1","comment":"18 pages, 2 figures, accepted for 23rd escar Europe (Nov 05-06, 2025, Frankfurt, Germany)","journal_ref":"23rd escar Europe : The World's Leading Automotive Cyber Security Conference 2025","doi":"10.13154/294-13659","discovered_on":"2026-07-17"},{"id":"2509.20109","versioned_id":"2509.20109v1","title":"Discrete Diffusion for Reflective Vision-Language-Action Models in Autonomous Driving","authors":["Pengxiang Li","Yinan Zheng","Yue Wang","Huimin Wang","Hang Zhao","Jingjing Liu","Xianyuan Zhan","Kun Zhan","Xianpeng Lang"],"abstract":"End-to-End (E2E) solutions have emerged as a mainstream approach for autonomous driving systems, with Vision-Language-Action (VLA) models representing a new paradigm that leverages pre-trained multimodal knowledge from Vision-Language Models (VLMs) to interpret and interact with complex real-world environments. However, these methods remain constrained by the limitations of imitation learning, which struggles to inherently encode physical rules during training. Existing approaches often rely on complex rule-based post-refinement, employ reinforcement learning that remains largely limited to simulation, or utilize diffusion guidance that requires computationally expensive gradient calculations. To address these challenges, we introduce ReflectDrive, a novel learning-based framework that integrates a reflection mechanism for safe trajectory generation via discrete diffusion. We first discretize the two-dimensional driving space to construct an action codebook, enabling the use of pre-trained Diffusion Language Models for planning tasks through fine-tuning. Central to our approach is a safety-aware reflection mechanism that performs iterative self-correction without gradient computation. Our method begins with goal-conditioned trajectory generation to model multi-modal driving behaviors. Based on this, we apply local search methods to identify unsafe tokens and determine feasible solutions, which then serve as safe anchors for inpainting-based regeneration. Evaluated on the NAVSIM benchmark, ReflectDrive demonstrates significant advantages in safety-critical trajectory generation, offering a scalable and reliable solution for autonomous driving systems.","published":"2025-09-24T13:35:15Z","updated":"2025-09-24T13:35:15Z","categories":["cs.RO","cs.AI","cs.CL"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2509.20109v1","pdf_url":"https://arxiv.org/pdf/2509.20109v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.20097","versioned_id":"2509.20097v2","title":"Integrated Framework for LLM Evaluation with Answer Generation","authors":["Sujeong Lee","Hayoung Lee","Seongsoo Heo","Wonik Choi"],"abstract":"Reliable evaluation of large language models is essential to ensure their applicability in practical scenarios. Traditional benchmark-based evaluation methods often rely on fixed reference answers, limiting their ability to capture important qualitative aspects of generated responses. To address these shortcomings, we propose an integrated evaluation framework called \\textit{self-refining descriptive evaluation with expert-driven diagnostics}, SPEED, which utilizes specialized functional experts to perform comprehensive, descriptive analyses of model outputs. Unlike conventional approaches, SPEED actively incorporates expert feedback across multiple dimensions, including hallucination detection, toxicity assessment, and lexical-contextual appropriateness. Experimental results demonstrate that SPEED achieves robust and consistent evaluation performance across diverse domains and datasets. Additionally, by employing relatively compact expert models, SPEED demonstrates superior resource efficiency compared to larger-scale evaluators. These findings illustrate that SPEED significantly enhances fairness and interpretability in LLM evaluations, offering a promising alternative to existing evaluation methodologies.","published":"2025-09-24T13:20:37Z","updated":"2025-10-01T06:09:25Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.20097v2","pdf_url":"https://arxiv.org/pdf/2509.20097v2","comment":"16pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.20414","versioned_id":"2509.20414v2","title":"SceneWeaver: All-in-One 3D Scene Synthesis with an Extensible and Self-Reflective Agent","authors":["Yandan Yang","Baoxiong Jia","Shujie Zhang","Siyuan Huang"],"abstract":"Indoor scene synthesis has become increasingly important with the rise of Embodied AI, which requires 3D environments that are not only visually realistic but also physically plausible and functionally diverse. While recent approaches have advanced visual fidelity, they often remain constrained to fixed scene categories, lack sufficient object-level detail and physical consistency, and struggle to align with complex user instructions. In this work, we present SceneWeaver, a reflective agentic framework that unifies diverse scene synthesis paradigms through tool-based iterative refinement. At its core, SceneWeaver employs a language model-based planner to select from a suite of extensible scene generation tools, ranging from data-driven generative models to visual- and LLM-based methods, guided by self-evaluation of physical plausibility, visual realism, and semantic alignment with user input. This closed-loop reason-act-reflect design enables the agent to identify semantic inconsistencies, invoke targeted tools, and update the environment over successive iterations. Extensive experiments on both common and open-vocabulary room types demonstrate that SceneWeaver not only outperforms prior methods on physical, visual, and semantic metrics, but also generalizes effectively to complex scenes with diverse instructions, marking a step toward general-purpose 3D environment generation. Project website: https://scene-weaver.github.io/.","published":"2025-09-24T09:06:41Z","updated":"2025-10-26T04:10:24Z","categories":["cs.GR","cs.CV","cs.LG","cs.RO"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2509.20414v2","pdf_url":"https://arxiv.org/pdf/2509.20414v2","comment":"Accepted by NeurIPS 2025, 26 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.19681","versioned_id":"2509.19681v1","title":"Calibrated Reasoning: An Explanatory Verifier for Dynamic and Efficient Problem-Solving","authors":["Anisha Garg","Engin Tekin","Yash More","David Bick","Nishit Neema","Ganesh Venkatesh"],"abstract":"Advanced test-time computing strategies are essential for scaling reasoning models, but their effectiveness is capped by the models' poor self-evaluation. We propose a pairwise Explanatory Verifier, trained via reinforcement learning (GRPO), that produces calibrated confidence scores and associated natural language reasoning for generated solutions. Our verifier improves the accuracy and efficiency of test-time strategies like best-of-n and self-reflection. Crucially, it excels at identifying challenging failure modes, such as when both candidate solutions are identically incorrect, succeeding where standard methods like majority voting fail.","published":"2025-09-24T01:36:00Z","updated":"2025-09-24T01:36:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.19681v1","pdf_url":"https://arxiv.org/pdf/2509.19681v1","comment":"39th Conference on Neural Information Processing Systems (NeurIPS 2025) Workshop: Efficient Reasoning","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.19292","versioned_id":"2509.19292v1","title":"SOE: Sample-Efficient Robot Policy Self-Improvement via On-Manifold Exploration","authors":["Yang Jin","Jun Lv","Han Xue","Wendi Chen","Chuan Wen","Cewu Lu"],"abstract":"Intelligent agents progress by continually refining their capabilities through actively exploring environments. Yet robot policies often lack sufficient exploration capability due to action mode collapse. Existing methods that encourage exploration typically rely on random perturbations, which are unsafe and induce unstable, erratic behaviors, thereby limiting their effectiveness. We propose Self-Improvement via On-Manifold Exploration (SOE), a framework that enhances policy exploration and improvement in robotic manipulation. SOE learns a compact latent representation of task-relevant factors and constrains exploration to the manifold of valid actions, ensuring safety, diversity, and effectiveness. It can be seamlessly integrated with arbitrary policy models as a plug-in module, augmenting exploration without degrading the base policy performance. Moreover, the structured latent space enables human-guided exploration, further improving efficiency and controllability. Extensive experiments in both simulation and real-world tasks demonstrate that SOE consistently outperforms prior methods, achieving higher task success rates, smoother and safer exploration, and superior sample efficiency. These results establish on-manifold exploration as a principled approach to sample-efficient policy self-improvement. Project website: https://ericjin2002.github.io/SOE","published":"2025-09-23T17:54:47Z","updated":"2025-09-23T17:54:47Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2509.19292v1","pdf_url":"https://arxiv.org/pdf/2509.19292v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.18847","versioned_id":"2509.18847v3","title":"Failure Makes the Agent Stronger: Enhancing Accuracy through Structured Reflection for Reliable Tool Interactions","authors":["Junhao Su","Yuanliang Wan","Junwei Yang","Hengyu Shi","Tianyang Han","Junfeng Luo","Yurui Qiu"],"abstract":"Tool-augmented large language models (LLMs) are usually trained with supervised imitation or coarse-grained reinforcement learning that optimizes single tool calls. Current self-reflection practices rely on heuristic prompts or one-way reasoning: the model is urged to 'think more' instead of learning error diagnosis and repair. This is fragile in multi-turn interactions; after a failure the model often repeats the same mistake. We propose structured reflection, which turns the path from error to repair into an explicit, controllable, and trainable action. The agent produces a short yet precise reflection: it diagnoses the failure using evidence from the previous step and then proposes a correct, executable follow-up call. For training we combine DAPO and GSPO objectives with a reward scheme tailored to tool use, optimizing the stepwise strategy Reflect, then Call, then Final. To evaluate, we introduce Tool-Reflection-Bench, a lightweight benchmark that programmatically checks structural validity, executability, parameter correctness, and result consistency. Tasks are built as mini trajectories of erroneous call, reflection, and corrected call, with disjoint train and test splits. Experiments on BFCL v3 and Tool-Reflection-Bench show large gains in multi-turn tool-call success and error recovery, and a reduction of redundant calls. These results indicate that making reflection explicit and optimizing it directly improves the reliability of tool interaction and offers a reproducible path for agents to learn from failure.","published":"2025-09-23T09:35:49Z","updated":"2026-04-15T06:57:52Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.18847v3","pdf_url":"https://arxiv.org/pdf/2509.18847v3","comment":"ACL","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.18713","versioned_id":"2509.18713v1","title":"MemOrb: A Plug-and-Play Verbal-Reinforcement Memory Layer for E-Commerce Customer Service","authors":["Yizhe Huang","Yang Liu","Ruiyu Zhao","Xiaolong Zhong","Xingming Yue","Ling Jiang"],"abstract":"Large Language Model-based agents(LLM-based agents) are increasingly deployed in customer service, yet they often forget across sessions, repeat errors, and lack mechanisms for continual self-improvement. This makes them unreliable in dynamic settings where stability and consistency are critical. To better evaluate these properties, we emphasize two indicators: task success rate as a measure of overall effectiveness, and consistency metrics such as Pass$^k$ to capture reliability across multiple trials. To address the limitations of existing approaches, we propose MemOrb, a lightweight and plug-and-play verbal reinforcement memory layer that distills multi-turn interactions into compact strategy reflections. These reflections are stored in a shared memory bank and retrieved to guide decision-making, without requiring any fine-tuning. Experiments show that MemOrb significantly improves both success rate and stability, achieving up to a 63 percentage-point gain in multi-turn success rate and delivering more consistent performance across repeated trials. Our results demonstrate that structured reflection is a powerful mechanism for enhancing long-term reliability of frozen LLM agents in customer service scenarios.","published":"2025-09-23T06:57:07Z","updated":"2025-09-23T06:57:07Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.18713v1","pdf_url":"https://arxiv.org/pdf/2509.18713v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.18607","versioned_id":"2509.18607v1","title":"Reflect before Act: Proactive Error Correction in Language Models","authors":["Qiuhai Zeng","Sarvesh Rajkumar","Di Wang","Narendra Gyanchandani","Wenbo Yan"],"abstract":"Large Language Models (LLMs) have demonstrated remarkable capabilities in interactive decision-making tasks, but existing methods often struggle with error accumulation and lack robust self-correction mechanisms. We introduce \"Reflect before Act\" (REBACT), a novel approach that enhances LLM-based decision-making by introducing a critical reflect step prior to taking the next action. This approach allows for immediate error correction, ensuring smooth action path and adaptibity to environment feedback. We evaluate REBACT on three diverse interactive environments: ALFWorld, WebShop, and TextCraft. Our results demonstrate that REBACT significantly outperforms strong baselines, improving success rates by up to 24% on WebShop (achieving 61%), 6.72% on ALFWorld (achieving 98.51%), and 0.5% on TextCraft (achieving 99.5%) using Claude3.5-sonnet as the underlying LLM. Further analysis reveals that REBACT's performance improvements are achieved with only a few modification steps, demonstrating its computational efficiency.","published":"2025-09-23T03:53:45Z","updated":"2025-09-23T03:53:45Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.18607v1","pdf_url":"https://arxiv.org/pdf/2509.18607v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.18376","versioned_id":"2509.18376v2","title":"GnnXemplar: Exemplars to Explanations -- Natural Language Rules for Global GNN Interpretability","authors":["Burouj Armgaan","Eshan Jain","Harsh Pandey","Mahesh Chandran","Sayan Ranu"],"abstract":"Graph Neural Networks (GNNs) are widely used for node classification, yet their opaque decision-making limits trust and adoption. While local explanations offer insights into individual predictions, global explanation methods, those that characterize an entire class, remain underdeveloped. Existing global explainers rely on motif discovery in small graphs, an approach that breaks down in large, real-world settings where subgraph repetition is rare, node attributes are high-dimensional, and predictions arise from complex structure-attribute interactions. We propose GnnXemplar, a novel global explainer inspired from Exemplar Theory from cognitive science. GnnXemplar identifies representative nodes in the GNN embedding space, exemplars, and explains predictions using natural language rules derived from their neighborhoods. Exemplar selection is framed as a coverage maximization problem over reverse k-nearest neighbors, for which we provide an efficient greedy approximation. To derive interpretable rules, we employ a self-refining prompt strategy using large language models (LLMs). Experiments across diverse benchmarks show that GnnXemplar significantly outperforms existing methods in fidelity, scalability, and human interpretability, as validated by a user study with 60 participants.","published":"2025-09-22T19:58:17Z","updated":"2025-10-29T10:57:22Z","categories":["cs.LG","cs.SI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.18376v2","pdf_url":"https://arxiv.org/pdf/2509.18376v2","comment":"38 pages, 20 figures, NeurIPS 2025 (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.17066","versioned_id":"2509.17066v1","title":"RALLM-POI: Retrieval-Augmented LLM for Zero-shot Next POI Recommendation with Geographical Reranking","authors":["Kunrong Li","Kwan Hui Lim"],"abstract":"Next point-of-interest (POI) recommendation predicts a user's next destination from historical movements. Traditional models require intensive training, while LLMs offer flexible and generalizable zero-shot solutions but often generate generic or geographically irrelevant results due to missing trajectory and spatial context. To address these issues, we propose RALLM-POI, a framework that couples LLMs with retrieval-augmented generation and self-rectification. We first propose a Historical Trajectory Retriever (HTR) that retrieves relevant past trajectories to serve as contextual references, which are then reranked by a Geographical Distance Reranker (GDR) for prioritizing spatially relevant trajectories. Lastly, an Agentic LLM Rectifier (ALR) is designed to refine outputs through self-reflection. Without additional training, RALLM-POI achieves substantial accuracy gains across three real-world Foursquare datasets, outperforming both conventional and LLM-based baselines. Code is released at https://github.com/LKRcrocodile/RALLM-POI.","published":"2025-09-21T12:52:28Z","updated":"2025-09-21T12:52:28Z","categories":["cs.AI","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.17066v1","pdf_url":"https://arxiv.org/pdf/2509.17066v1","comment":"PRICAI 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.16534","versioned_id":"2509.16534v1","title":"InteGround: On the Evaluation of Verification and Retrieval Planning in Integrative Grounding","authors":["Cheng Jiayang","Qianqian Zhuang","Haoran Li","Chunkit Chan","Xin Liu","Lin Qiu","Yangqiu Song"],"abstract":"Grounding large language models (LLMs) in external knowledge sources is a promising method for faithful prediction. While existing grounding approaches work well for simple queries, many real-world information needs require synthesizing multiple pieces of evidence. We introduce \"integrative grounding\" -- the challenge of retrieving and verifying multiple inter-dependent pieces of evidence to support a hypothesis query. To systematically study this problem, we repurpose data from four domains for evaluating integrative grounding capabilities. Our investigation reveals two critical findings: First, in groundedness verification, while LLMs are robust to redundant evidence, they tend to rationalize using internal knowledge when information is incomplete. Second, in examining retrieval planning strategies, we find that undirected planning can degrade performance through noise introduction, while premise abduction emerges as a promising approach due to its logical constraints. Additionally, LLMs' zero-shot self-reflection capabilities consistently improve grounding quality. These insights provide valuable direction for developing more effective integrative grounding systems.","published":"2025-09-20T04:48:24Z","updated":"2025-09-20T04:48:24Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.16534v1","pdf_url":"https://arxiv.org/pdf/2509.16534v1","comment":"Accepted to EMNLP 2025 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.15194","versioned_id":"2509.15194v3","title":"Evolving Language Models without Labels: Majority Drives Selection, Novelty Promotes Variation","authors":["Yujun Zhou","Zhenwen Liang","Haolin Liu","Wenhao Yu","Kishan Panaganti","Linfeng Song","Dian Yu","Xiangliang Zhang","Haitao Mi","Dong Yu"],"abstract":"Large language models (LLMs) are increasingly trained with reinforcement learning from verifiable rewards (RLVR), yet real-world deployment demands models that can self-improve without labels or external judges. Existing self-improvement approaches primarily rely on self-confirmation signals (e.g., confidence, entropy, or consistency) to generate rewards. This reliance drives models toward over-confident, majority-favored solutions, causing an entropy collapse that degrades pass@n and reasoning complexity. To address this, we propose EVOL-RL, a label-free framework that mirrors the evolutionary principle of balancing selection with variation. Concretely, EVOL-RL retains the majority-voted answer as an anchor for stability, but adds a novelty-aware reward that scores each sampled solution by how different its reasoning is from other concurrently generated responses. This majority-for-stability + novelty-for-exploration rule mirrors the variation-selection principle: selection prevents drift, while novelty prevents collapse. Evaluation results show that EVOL-RL consistently outperforms the majority-only baseline; e.g., training on label-free AIME24 lifts Qwen3-4B-Base AIME25 pass@1 from baseline's 4.6% to 16.4%, and pass@16 from 18.5% to 37.9%. EVOL-RL not only prevents in-domain diversity collapse but also improves out-of-domain generalization (from math reasoning to broader tasks, e.g., MMLU-Pro and BBEH). The code is available at: https://github.com/YujunZhou/EVOL-RL.","published":"2025-09-18T17:50:04Z","updated":"2026-02-18T00:51:43Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.15194v3","pdf_url":"https://arxiv.org/pdf/2509.15194v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.15174","versioned_id":"2509.15174v3","title":"SMARTER: A Data-efficient Framework to Improve Toxicity Detection with Explanation via Self-augmenting Large Language Models","authors":["Huy Nghiem","Advik Sachdeva","Hal Daumé"],"abstract":"WARNING: This paper contains examples of offensive materials. To address the proliferation of toxic content on social media, we introduce SMARTER, we introduce SMARTER, a data-efficient two-stage framework for explainable content moderation using Large Language Models (LLMs). In Stage 1, we leverage LLMs' own outputs to generate synthetic explanations for both correct and incorrect labels, enabling alignment via preference optimization with minimal human supervision. In Stage 2, we refine explanation quality through cross-model training, allowing weaker models to align stylistically and semantically with stronger ones. Experiments on three benchmark tasks -- HateXplain, Latent Hate, and Implicit Hate -- demonstrate that SMARTER enables LLMs to achieve up to a 13% macro-F1 improvement over standard few-shot baselines while using only a fraction of the full training data. Our framework offers a scalable strategy for low-resource settings by harnessing LLMs' self-improving capabilities for both classification and explanation.","published":"2025-09-18T17:30:36Z","updated":"2026-04-21T22:25:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.15174v3","pdf_url":"https://arxiv.org/pdf/2509.15174v3","comment":"ACL 2026. NLP, Hate speech detection, explanation, LLM. Version 3","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.15172","versioned_id":"2509.15172v3","title":"Self-Improvement of Language Models by Post-Training on Multi-Agent Debate","authors":["Ankur Samanta","Akshayaa Magesh","Runzhe Wu","Ayush Jain","Youliang Yu","Daniel Jiang","Boris Vidolov","Paul Sajda","Yonathan Efroni","Kaveh Hassani"],"abstract":"Self-improvement, where models improve beyond their current performance without external supervision, remains a challenge. The core difficulty is sourcing a training signal stronger than what the model itself can currently produce. Majority voting has been shown to provide such a signal by aggregating over multiple samples, helping mitigate some of the inconsistencies in LM reasoning. In this work, we show that multi-agent debate--where models collaborate and exchange reasoning over multiple rounds--provides an even richer signal than single-round majority voting. We introduce Multi-Agent Consensus Alignment (MACA), which uses reinforcement learning (RL) to post-train models to effectively utilize multi-agent debate. We find that preference learning over full reasoning traces, learning to differentiate between majority and minority reasoning, is more effective than binary consensus rewards or SFT-based approaches for leveraging these debate signals. This produces three key improvements: models are (1) better at utilizing the multi-agent debate setting (+26.87% on MATH), (2) individually more accurate (+21.51% on MathQA), and (3) more self-consistent (+27.6% on GSM8K). We also see strong generalization to unseen benchmarks (+16.3% on GPQA, +11.6% on CommonsenseQA).","published":"2025-09-18T17:27:28Z","updated":"2026-01-29T23:55:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.15172v3","pdf_url":"https://arxiv.org/pdf/2509.15172v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.15160","versioned_id":"2509.15160v1","title":"An Evaluation-Centric Paradigm for Scientific Visualization Agents","authors":["Kuangshi Ai","Haichao Miao","Zhimin Li","Chaoli Wang","Shusen Liu"],"abstract":"Recent advances in multi-modal large language models (MLLMs) have enabled increasingly sophisticated autonomous visualization agents capable of translating user intentions into data visualizations. However, measuring progress and comparing different agents remains challenging, particularly in scientific visualization (SciVis), due to the absence of comprehensive, large-scale benchmarks for evaluating real-world capabilities. This position paper examines the various types of evaluation required for SciVis agents, outlines the associated challenges, provides a simple proof-of-concept evaluation example, and discusses how evaluation benchmarks can facilitate agent self-improvement. We advocate for a broader collaboration to develop a SciVis agentic evaluation benchmark that would not only assess existing capabilities but also drive innovation and stimulate future development in the field.","published":"2025-09-18T17:08:23Z","updated":"2025-09-18T17:08:23Z","categories":["cs.HC","cs.CL","cs.GR"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2509.15160v1","pdf_url":"https://arxiv.org/pdf/2509.15160v1","comment":"","journal_ref":"1st Workshop on GenAI, Agents, and the Future of VIS (IEEE VIS Conference 2025)","doi":"","discovered_on":"2026-07-17"},{"id":"2509.15155","versioned_id":"2509.15155v1","title":"Self-Improving Embodied Foundation Models","authors":["Seyed Kamyar Seyed Ghasemipour","Ayzaan Wahid","Jonathan Tompson","Pannag Sanketi","Igor Mordatch"],"abstract":"Foundation models trained on web-scale data have revolutionized robotics, but their application to low-level control remains largely limited to behavioral cloning. Drawing inspiration from the success of the reinforcement learning stage in fine-tuning large language models, we propose a two-stage post-training approach for robotics. The first stage, Supervised Fine-Tuning (SFT), fine-tunes pretrained foundation models using both: a) behavioral cloning, and b) steps-to-go prediction objectives. In the second stage, Self-Improvement, steps-to-go prediction enables the extraction of a well-shaped reward function and a robust success detector, enabling a fleet of robots to autonomously practice downstream tasks with minimal human supervision. Through extensive experiments on real-world and simulated robot embodiments, our novel post-training recipe unveils significant results on Embodied Foundation Models. First, we demonstrate that the combination of SFT and Self-Improvement is significantly more sample-efficient than scaling imitation data collection for supervised learning, and that it leads to policies with significantly higher success rates. Further ablations highlight that the combination of web-scale pretraining and Self-Improvement is the key to this sample-efficiency. Next, we demonstrate that our proposed combination uniquely unlocks a capability that current methods cannot achieve: autonomously practicing and acquiring novel skills that generalize far beyond the behaviors observed in the imitation learning datasets used during training. These findings highlight the transformative potential of combining pretrained foundation models with online Self-Improvement to enable autonomous skill acquisition in robotics. Our project website can be found at https://self-improving-efms.github.io .","published":"2025-09-18T17:00:08Z","updated":"2025-09-18T17:00:08Z","categories":["cs.LG","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.15155v1","pdf_url":"https://arxiv.org/pdf/2509.15155v1","comment":"Appearing in the Conference on Neural Information Processing Systems (NeurIPS 2025)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.15089","versioned_id":"2509.15089v1","title":"LLM-OREF: An Open Relation Extraction Framework Based on Large Language Models","authors":["Hongyao Tu","Liang Zhang","Yujie Lin","Xin Lin","Haibo Zhang","Long Zhang","Jinsong Su"],"abstract":"The goal of open relation extraction (OpenRE) is to develop an RE model that can generalize to new relations not encountered during training. Existing studies primarily formulate OpenRE as a clustering task. They first cluster all test instances based on the similarity between the instances, and then manually assign a new relation to each cluster. However, their reliance on human annotation limits their practicality. In this paper, we propose an OpenRE framework based on large language models (LLMs), which directly predicts new relations for test instances by leveraging their strong language understanding and generation abilities, without human intervention. Specifically, our framework consists of two core components: (1) a relation discoverer (RD), designed to predict new relations for test instances based on \\textit{demonstrations} formed by training instances with known relations; and (2) a relation predictor (RP), used to select the most likely relation for a test instance from $n$ candidate relations, guided by \\textit{demonstrations} composed of their instances. To enhance the ability of our framework to predict new relations, we design a self-correcting inference strategy composed of three stages: relation discovery, relation denoising, and relation prediction. In the first stage, we use RD to preliminarily predict new relations for all test instances. Next, we apply RP to select some high-reliability test instances for each new relation from the prediction results of RD through a cross-validation method. During the third stage, we employ RP to re-predict the relations of all test instances based on the demonstrations constructed from these reliable test instances. Extensive experiments on three OpenRE datasets demonstrate the effectiveness of our framework. We release our code at https://github.com/XMUDeepLIT/LLM-OREF.git.","published":"2025-09-18T15:46:40Z","updated":"2025-09-18T15:46:40Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.15089v1","pdf_url":"https://arxiv.org/pdf/2509.15089v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.14760","versioned_id":"2509.14760v3","title":"Reasoning over Boundaries: Enhancing Specification Alignment via Test-time Deliberation","authors":["Haoran Zhang","Yafu Li","Xuyang Hu","Dongrui Liu","Zhilin Wang","Bo Li","Yu Cheng"],"abstract":"Large language models (LLMs) are increasingly applied in diverse real-world scenarios, each governed by bespoke behavioral and safety specifications (spec) custom-tailored by users or organizations. These spec, categorized into safety-spec and behavioral-spec, vary across scenarios and evolve with changing preferences and requirements. We formalize this challenge as specification alignment, focusing on LLMs' ability to follow dynamic, scenario-specific spec from both behavioral and safety perspectives. To address this challenge, we propose Align3, a lightweight method that employs Test-Time Deliberation (TTD) with hierarchical reflection and revision to reason over the specification boundaries. We further present SpecBench, a unified benchmark for measuring specification alignment, covering 5 scenarios, 103 spec, and 1,500 prompts. Experiments on 15 reasoning and 18 instruct models with several TTD methods, including Self-Refine, TPO, and MoreThink, yield three key findings: (i) test-time deliberation enhances specification alignment; (ii) Align3 advances the safety-helpfulness trade-off frontier with minimal overhead; (iii) SpecBench effectively reveals alignment gaps. These results highlight the potential of test-time deliberation as an effective strategy for reasoning over the real-world specification boundaries. Our code and resources are available at https://github.com/zzzhr97/SpecBench.","published":"2025-09-18T09:08:53Z","updated":"2026-06-03T12:30:11Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.14760v3","pdf_url":"https://arxiv.org/pdf/2509.14760v3","comment":"10 pages main text, 52 pages total (including appendix). Code and resources are available at https://github.com/zzzhr97/SpecBench","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.16262","versioned_id":"2509.16262v2","title":"Socratic Mind: Impact of a Novel GenAI-Powered Assessment Tool on Student Learning and Higher-Order Thinking","authors":["Jeonghyun Lee","Jui-Tse Hung","Meryem Yilmaz Soylu","Diana Popescu","Christopher Zhang Cui","Gayane Grigoryan","David A Joyner","Stephen W Harmon"],"abstract":"This study examines the impact of Socratic Mind, a Generative Artificial Intelligence (GenAI) powered formative assessment tool that employs Socratic questioning to support student learning in a large, fully online undergraduate-level computing course. Employing a quasi-experimental, mixed-methods design, we investigated participants' engagement patterns, the influence of user experience on engagement, and impacts on both perceived and actual learning outcomes. Data were collected from the system logs, surveys on user experience and perceived engagement and learning gains, student reflections, and course performance data. Results indicated that participants consistently reported high levels of affective, behavioral, and cognitive engagement, and these were strongly linked to positive user experiences and perceived learning outcomes. Quantitative analysis further revealed that students who engaged with the GenAI tool experienced significant gains in their quiz scores compared to those who did not, particularly benefiting students with lower baseline achievement. Additionally, thematic analysis of qualitative feedback revealed substantial perceived improvements in higher-order thinking skills, including problem solving, critical thinking, and self-reflection. Our findings highlight the promise of AI-mediated dialogue in fostering deeper engagement and higher-order cognitive skills. As higher education institutions expand GenAI integration in curriculum, this dialogic, GenAI powered assessment tool can offer a scalable strategy to promote students' meaningful learning outcomes.","published":"2025-09-18T03:08:24Z","updated":"2025-10-16T04:07:31Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2509.16262v2","pdf_url":"https://arxiv.org/pdf/2509.16262v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.13761","versioned_id":"2509.13761v3","title":"THOR: Tool-Integrated Hierarchical Optimization via RL for Mathematical Reasoning","authors":["Qikai Chang","Zhenrong Zhang","Pengfei Hu","Jun Du","Jiefeng Ma","Yicheng Pan","Jianshu Zhang","Quan Liu","Jianqing Gao"],"abstract":"Large Language Models (LLMs) have made remarkable progress in mathematical reasoning, but still continue to struggle with high-precision tasks like numerical computation and formal symbolic manipulation. Integrating external tools has emerged as a promising approach to bridge this gap. Despite recent advances, existing methods struggle with three key challenges: constructing tool-integrated reasoning data, performing fine-grained optimization, and enhancing inference. To overcome these limitations, we propose THOR (Tool-Integrated Hierarchical Optimization via RL). First, we introduce TIRGen, a multi-agent based pipeline for constructing high-quality datasets of tool-integrated reasoning paths, aligning with the policy and generalizing well across diverse models. Second, to perform fine-grained hierarchical optimization, we introduce an RL strategy that jointly optimizes for both episode-level problem solving and step-level code generation. This is motivated by our key insight that the success of an intermediate tool call is a strong predictor of the final answer's correctness. Finally, THOR incorporates a self-correction mechanism that leverages immediate tool feedback to dynamically revise erroneous reasoning paths during inference. Our approach demonstrates strong generalization across diverse models, performing effectively in both reasoning and non-reasoning models. It further achieves state-of-the-art performance for models of a similar scale on multiple mathematical benchmarks, while also delivering consistent improvements on code benchmarks. Our code will be publicly available at https://github.com/JingMog/THOR.","published":"2025-09-17T07:16:12Z","updated":"2026-02-10T08:25:24Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.13761v3","pdf_url":"https://arxiv.org/pdf/2509.13761v3","comment":"22 pages, 13 figures, ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.13237","versioned_id":"2509.13237v1","title":"Metacognitive Reuse: Turning Recurring LLM Reasoning Into Concise Behaviors","authors":["Aniket Didolkar","Nicolas Ballas","Sanjeev Arora","Anirudh Goyal"],"abstract":"Large language models (LLMs) now solve multi-step problems by emitting extended chains of thought. During the process, they often re-derive the same intermediate steps across problems, inflating token usage and latency. This saturation of the context window leaves less capacity for exploration. We study a simple mechanism that converts recurring reasoning fragments into concise, reusable \"behaviors\" (name + instruction) via the model's own metacognitive analysis of prior traces. These behaviors are stored in a \"behavior handbook\" which supplies them to the model in-context at inference or distills them into parameters via supervised fine-tuning. This approach achieves improved test-time reasoning across three different settings - 1) Behavior-conditioned inference: Providing the LLM relevant behaviors in-context during reasoning reduces number of reasoning tokens by up to 46% while matching or improving baseline accuracy; 2) Behavior-guided self-improvement: Without any parameter updates, the model improves its own future reasoning by leveraging behaviors from its own past problem solving attempts. This yields up to 10% higher accuracy than a naive critique-and-revise baseline; and 3) Behavior-conditioned SFT: SFT on behavior-conditioned reasoning traces is more effective at converting non-reasoning models into reasoning models as compared to vanilla SFT. Together, these results indicate that turning slow derivations into fast procedural hints enables LLMs to remember how to reason, not just what to conclude.","published":"2025-09-16T16:44:26Z","updated":"2025-09-16T16:44:26Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.13237v1","pdf_url":"https://arxiv.org/pdf/2509.13237v1","comment":"18 pages, 9 Figures, 5 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.12886","versioned_id":"2509.12886v1","title":"The LLM Already Knows: Estimating LLM-Perceived Question Difficulty via Hidden Representations","authors":["Yubo Zhu","Dongrui Liu","Zecheng Lin","Wei Tong","Sheng Zhong","Jing Shao"],"abstract":"Estimating the difficulty of input questions as perceived by large language models (LLMs) is essential for accurate performance evaluation and adaptive inference. Existing methods typically rely on repeated response sampling, auxiliary models, or fine-tuning the target model itself, which may incur substantial computational costs or compromise generality. In this paper, we propose a novel approach for difficulty estimation that leverages only the hidden representations produced by the target LLM. We model the token-level generation process as a Markov chain and define a value function to estimate the expected output quality given any hidden state. This allows for efficient and accurate difficulty estimation based solely on the initial hidden state, without generating any output tokens. Extensive experiments across both textual and multimodal tasks demonstrate that our method consistently outperforms existing baselines in difficulty estimation. Moreover, we apply our difficulty estimates to guide adaptive reasoning strategies, including Self-Consistency, Best-of-N, and Self-Refine, achieving higher inference efficiency with fewer generated tokens.","published":"2025-09-16T09:38:41Z","updated":"2025-09-16T09:38:41Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.12886v1","pdf_url":"https://arxiv.org/pdf/2509.12886v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.12765","versioned_id":"2509.12765v1","title":"InfoGain-RAG: Boosting Retrieval-Augmented Generation via Document Information Gain-based Reranking and Filtering","authors":["Zihan Wang","Zihan Liang","Zhou Shao","Yufei Ma","Huangyu Dai","Ben Chen","Lingtao Mao","Chenyi Lei","Yuqing Ding","Han Li"],"abstract":"Retrieval-Augmented Generation (RAG) has emerged as a promising approach to address key limitations of Large Language Models (LLMs), such as hallucination, outdated knowledge, and lacking reference. However, current RAG frameworks often struggle with identifying whether retrieved documents meaningfully contribute to answer generation. This shortcoming makes it difficult to filter out irrelevant or even misleading content, which notably impacts the final performance. In this paper, we propose Document Information Gain (DIG), a novel metric designed to quantify the contribution of retrieved documents to correct answer generation. DIG measures a document's value by computing the difference of LLM's generation confidence with and without the document augmented. Further, we introduce InfoGain-RAG, a framework that leverages DIG scores to train a specialized reranker, which prioritizes each retrieved document from exact distinguishing and accurate sorting perspectives. This approach can effectively filter out irrelevant documents and select the most valuable ones for better answer generation. Extensive experiments across various models and benchmarks demonstrate that InfoGain-RAG can significantly outperform existing approaches, on both single and multiple retrievers paradigm. Specifically on NaturalQA, it achieves the improvements of 17.9%, 4.5%, 12.5% in exact match accuracy against naive RAG, self-reflective RAG and modern ranking-based RAG respectively, and even an average of 15.3% increment on advanced proprietary model GPT-4o across all datasets. These results demonstrate the feasibility of InfoGain-RAG as it can offer a reliable solution for RAG in multiple applications.","published":"2025-09-16T07:28:07Z","updated":"2025-09-16T07:28:07Z","categories":["cs.IR","cs.AI","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2509.12765v1","pdf_url":"https://arxiv.org/pdf/2509.12765v1","comment":"EMNLP'25 Oral Presentation. Contact: benchen4395@gmail.com","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.11575","versioned_id":"2509.11575v3","title":"A Survey of Reasoning and Agentic Systems in Time Series with Large Language Models","authors":["Ching Chang","Yidan Shi","Defu Cao","Wei Yang","Jeehyun Hwang","Haixin Wang","Jiacheng Pang","Wei Wang","Yan Liu","Wen-Chih Peng","Tien-Fu Chen"],"abstract":"Time series reasoning treats time as a first-class axis and incorporates intermediate evidence directly into the answer. This survey defines the problem and organizes the literature by reasoning topology with three families: direct reasoning in one step, linear chain reasoning with explicit intermediates, and branch-structured reasoning that explores, revises, and aggregates. The topology is crossed with the main objectives of the field, including traditional time series analysis, explanation and understanding, causal inference and decision making, and time series generation, while a compact tag set spans these axes and captures decomposition and verification, ensembling, tool use, knowledge access, multimodality, agent loops, and LLM alignment regimes. Methods and systems are reviewed across domains, showing what each topology enables and where it breaks down in faithfulness or robustness, along with curated datasets, benchmarks, and resources that support study and deployment (https://github.com/blacksnail789521/Time-Series-Reasoning-Survey). Evaluation practices that keep evidence visible and temporally aligned are highlighted, and guidance is distilled on matching topology to uncertainty, grounding with observable artifacts, planning for shift and streaming, and treating cost and latency as design budgets. We emphasize that reasoning structures must balance capacity for grounding and self-correction against computational cost and reproducibility, while future progress will likely depend on benchmarks that tie reasoning quality to utility and on closed-loop testbeds that trade off cost and risk under shift-aware, streaming, and long-horizon settings. Taken together, these directions mark a shift from narrow accuracy toward reliability at scale, enabling systems that not only analyze but also understand, explain, and act on dynamic worlds with traceable evidence and credible outcomes.","published":"2025-09-15T04:39:50Z","updated":"2026-06-10T07:42:17Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.11575v3","pdf_url":"https://arxiv.org/pdf/2509.11575v3","comment":"Accepted to Transactions on Machine Learning Research (TMLR)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.13351","versioned_id":"2509.13351v1","title":"Teaching LLMs to Plan: Logical Chain-of-Thought Instruction Tuning for Symbolic Planning","authors":["Pulkit Verma","Ngoc La","Anthony Favier","Swaroop Mishra","Julie A. Shah"],"abstract":"Large language models (LLMs) have demonstrated impressive capabilities across diverse tasks, yet their ability to perform structured symbolic planning remains limited, particularly in domains requiring formal representations like the Planning Domain Definition Language (PDDL). In this paper, we present a novel instruction tuning framework, PDDL-Instruct, designed to enhance LLMs' symbolic planning capabilities through logical chain-of-thought reasoning. Our approach focuses on teaching models to rigorously reason about action applicability, state transitions, and plan validity using explicit logical inference steps. By developing instruction prompts that guide models through the precise logical reasoning required to determine when actions can be applied in a given state, we enable LLMs to self-correct their planning processes through structured reflection. The framework systematically builds verification skills by decomposing the planning process into explicit reasoning chains about precondition satisfaction, effect application, and invariant preservation. Experimental results on multiple planning domains show that our chain-of-thought reasoning based instruction-tuned models are significantly better at planning, achieving planning accuracy of up to 94% on standard benchmarks, representing a 66% absolute improvement over baseline models. This work bridges the gap between the general reasoning capabilities of LLMs and the logical precision required for automated planning, offering a promising direction for developing better AI planning systems.","published":"2025-09-14T02:42:34Z","updated":"2025-09-14T02:42:34Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.13351v1","pdf_url":"https://arxiv.org/pdf/2509.13351v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.10704","versioned_id":"2509.10704v1","title":"Maestro: Self-Improving Text-to-Image Generation via Agent Orchestration","authors":["Xingchen Wan","Han Zhou","Ruoxi Sun","Hootan Nakhost","Ke Jiang","Rajarishi Sinha","Sercan Ö. Arık"],"abstract":"Text-to-image (T2I) models, while offering immense creative potential, are highly reliant on human intervention, posing significant usability challenges that often necessitate manual, iterative prompt engineering over often underspecified prompts. This paper introduces Maestro, a novel self-evolving image generation system that enables T2I models to autonomously self-improve generated images through iterative evolution of prompts, using only an initial prompt. Maestro incorporates two key innovations: 1) self-critique, where specialized multimodal LLM (MLLM) agents act as 'critics' to identify weaknesses in generated images, correct for under-specification, and provide interpretable edit signals, which are then integrated by a 'verifier' agent while preserving user intent; and 2) self-evolution, utilizing MLLM-as-a-judge for head-to-head comparisons between iteratively generated images, eschewing problematic images, and evolving creative prompt candidates that align with user intents. Extensive experiments on complex T2I tasks using black-box models demonstrate that Maestro significantly improves image quality over initial prompts and state-of-the-art automated methods, with effectiveness scaling with more advanced MLLM components. This work presents a robust, interpretable, and effective pathway towards self-improving T2I generation.","published":"2025-09-12T21:45:16Z","updated":"2025-09-12T21:45:16Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.10704v1","pdf_url":"https://arxiv.org/pdf/2509.10704v1","comment":"15 pages, 7 figures, 2 tables (22 pages, 9 figures and 3 tables including references and appendices)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.12259","versioned_id":"2509.12259v1","title":"Quantum-Inspired Stacked Integrated Concept Graph Model (QISICGM) for Diabetes Risk Prediction","authors":["Kenneth G. Young"],"abstract":"The Quantum-Inspired Stacked Integrated Concept Graph Model (QISICGM) is an innovative machine learning framework that harnesses quantum-inspired techniques to predict diabetes risk with exceptional accuracy and efficiency. Utilizing the PIMA Indians Diabetes dataset augmented with 2,000 synthetic samples to mitigate class imbalance (total: 2,768 samples, 1,949 positives), QISICGM integrates a self-improving concept graph with a stacked ensemble comprising Random Forests (RF), Extra Trees (ET), transformers, convolutional neural networks (CNNs), and feed-forward neural networks (FFNNs). This approach achieves an out-of-fold (OOF) F1 score of 0.8933 and an AUC of 0.8699, outperforming traditional methods. Quantum inspired elements, such as phase feature mapping and neighborhood sequence modeling, enrich feature representations, enabling CPU-efficient inference at 8.5 rows per second. This paper presents a detailed architecture, theoretical foundations, code insights, and performance evaluations, including visualizations from the outputs subfolder. The open-source implementation (v1.0.0) is available at https://github.com/keninayoung/QISICGM, positioning QISICGM as a potential benchmark for AI-assisted clinical triage in diabetes and beyond. Ultimately, this work emphasizes trustworthy AI through calibration, interpretability, and open-source reproducibility.","published":"2025-09-12T18:26:31Z","updated":"2025-09-12T18:26:31Z","categories":["cs.LG","cs.AI","quant-ph"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.12259v1","pdf_url":"https://arxiv.org/pdf/2509.12259v1","comment":"13 pages, 3 figures, includes performance tables and visualizations. Proposes a Quantum-Inspired Stacked Integrated Concept Graph Model (QISICGM) that integrates phase feature mapping, self-improving concept graphs, and neighborhood sequence modeling within a stacked ensemble. Demonstrates improved F1 and AUC on an augmented PIMA Diabetes dataset with efficient CPU inference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.10208","versioned_id":"2509.10208v1","title":"SI-FACT: Mitigating Knowledge Conflict via Self-Improving Faithfulness-Aware Contrastive Tuning","authors":["Shengqiang Fu"],"abstract":"Large Language Models often generate unfaithful responses in knowledge intensive tasks due to knowledge conflict,that is,a preference for relying on internal parametric knowledge rather than the provided context.To address this issue,we propose a novel self improving framework,Self Improving Faithfulness Aware Contrastive Tuning.The framework uses a self instruct mechanism that allows the base LLM to automatically generate high quality,structured contrastive learning data,including anchor samples,semantically equivalent positive samples,and negative samples simulating unfaithful scenarios.This approach significantly reduces the cost of manual annotation.Subsequently,contrastive learning is applied to train the model,enabling it to pull faithful responses closer and push unfaithful responses farther apart in the representation space.Experiments on knowledge conflict evaluation benchmarks ECARE KRE and COSE KRE show that the SI FACT model based on Llama3 8B Instruct improves the Contextual Recall Rate by 6.2% over the best baseline method,while significantly reducing dependence on internal memory.The results indicate that SI FACT provides strong effectiveness and high data efficiency in enhancing the contextual faithfulness of LLMs,offering a practical pathway toward building more proactive and trustworthy language models.","published":"2025-09-12T12:56:14Z","updated":"2025-09-12T12:56:14Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.10208v1","pdf_url":"https://arxiv.org/pdf/2509.10208v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.09751","versioned_id":"2509.09751v2","title":"Meta-Learning Reinforcement Learning for Crypto-Return Prediction","authors":["Junqiao Wang","Zhaoyang Guan","Guanyu Liu","Tianze Xia","Xianzhi Li","Shuo Yin","Xinyuan Song","Chuhan Cheng","Tianyu Shi","Alex Lee"],"abstract":"Predicting cryptocurrency returns is notoriously difficult: price movements are driven by a fast-shifting blend of on-chain activity, news flow, and social sentiment, while labeled training data are scarce and expensive. In this paper, we present Meta-RL-Crypto, a unified transformer-based architecture that unifies meta-learning and reinforcement learning (RL) to create a fully self-improving trading agent. Starting from a vanilla instruction-tuned LLM, the agent iteratively alternates between three roles-actor, judge, and meta-judge-in a closed-loop architecture. This learning process requires no additional human supervision. It can leverage multimodal market inputs and internal preference feedback. The agent in the system continuously refines both the trading policy and evaluation criteria. Experiments across diverse market regimes demonstrate that Meta-RL-Crypto shows good performance on the technical indicators of the real market and outperforming other LLM-based baselines.","published":"2025-09-11T14:20:45Z","updated":"2026-02-01T10:15:44Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.09751v2","pdf_url":"https://arxiv.org/pdf/2509.09751v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.08809","versioned_id":"2509.08809v1","title":"Evaluating LLMs Without Oracle Feedback: Agentic Annotation Evaluation Through Unsupervised Consistency Signals","authors":["Cheng Chen","Haiyan Yin","Ivor Tsang"],"abstract":"Large Language Models (LLMs), when paired with prompt-based tasks, have significantly reduced data annotation costs and reliance on human annotators. However, evaluating the quality of their annotations remains challenging in dynamic, unsupervised environments where oracle feedback is scarce and conventional methods fail. To address this challenge, we propose a novel agentic annotation paradigm, where a student model collaborates with a noisy teacher (the LLM) to assess and refine annotation quality without relying on oracle feedback. The student model, acting as an unsupervised feedback mechanism, employs a user preference-based majority voting strategy to evaluate the consistency of the LLM outputs. To systematically measure the reliability of LLM-generated annotations, we introduce the Consistent and Inconsistent (CAI) Ratio, a novel unsupervised evaluation metric. The CAI Ratio not only quantifies the annotation quality of the noisy teacher under limited user preferences but also plays a critical role in model selection, enabling the identification of robust LLMs in dynamic, unsupervised environments. Applied to ten open-domain NLP datasets across four LLMs, the CAI Ratio demonstrates a strong positive correlation with LLM accuracy, establishing it as an essential tool for unsupervised evaluation and model selection in real-world settings.","published":"2025-09-10T17:42:41Z","updated":"2025-09-10T17:42:41Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.08809v1","pdf_url":"https://arxiv.org/pdf/2509.08809v1","comment":"11 pages, 10 figures","journal_ref":"Published ICLR 2025 Workshop on Scaling Self-Improving Foundation Models without Human Supervision","doi":"","discovered_on":"2026-07-17"},{"id":"2509.07676","versioned_id":"2509.07676v1","title":"Unleashing the True Potential of LLMs: A Feedback-Triggered Self-Correction with Long-Term Multipath Decoding","authors":["Jipeng Li","Zeyu Gao","Yubin Qi","Hande Dong","Weijian Chen","Qiang Lin"],"abstract":"Large Language Models (LLMs) have achieved remarkable performance across diverse tasks, yet their susceptibility to generating incorrect content during inference remains a critical unsolved challenge. While self-correction methods offer potential solutions, their effectiveness is hindered by two inherent limitations: (1) the absence of reliable guidance signals for error localization, and (2) the restricted reasoning depth imposed by conventional next-token decoding paradigms. To address these issues, we propose Feedback-Triggered Regeneration (FTR), a novel framework that synergizes user feedback with enhanced decoding dynamics. Specifically, FTR activates response regeneration only upon receiving negative user feedback, thereby circumventing error propagation from faulty self-assessment while preserving originally correct outputs. Furthermore, we introduce Long-Term Multipath (LTM) decoding, which enables systematic exploration of multiple reasoning trajectories through delayed sequence evaluation, effectively overcoming the myopic decision-making characteristic of standard next-token prediction. Extensive experiments on mathematical reasoning and code generation benchmarks demonstrate that our framework achieves consistent and significant improvements over state-of-the-art prompt-based self-correction methods.","published":"2025-09-09T12:43:28Z","updated":"2025-09-09T12:43:28Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.07676v1","pdf_url":"https://arxiv.org/pdf/2509.07676v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.07159","versioned_id":"2509.07159v1","title":"PaVeRL-SQL: Text-to-SQL via Partial-Match Rewards and Verbal Reinforcement Learning","authors":["Heng Hao","Wenjun Hu","Oxana Verkholyak","Davoud Ataee Tarzanagh","Baruch Gutow","Sima Didari","Masoud Faraki","Hankyu Moon","Seungjai Min"],"abstract":"Text-to-SQL models allow users to interact with a database more easily by generating executable SQL statements from natural-language questions. Despite recent successes on simpler databases and questions, current Text-to-SQL methods still suffer from low execution accuracy on industry-scale databases and complex questions involving domain-specific business logic. We present \\emph{PaVeRL-SQL}, a framework that combines \\emph{Partial-Match Rewards} and \\emph{Verbal Reinforcement Learning} to drive self-improvement in reasoning language models (RLMs) for Text-to-SQL. To handle practical use cases, we adopt two pipelines: (1) a newly designed in-context learning framework with group self-evaluation (verbal-RL), using capable open- and closed-source large language models (LLMs) as backbones; and (2) a chain-of-thought (CoT) RL pipeline with a small backbone model (OmniSQL-7B) trained with a specially designed reward function and two-stage RL. These pipelines achieve state-of-the-art (SOTA) results on popular Text-to-SQL benchmarks -- Spider, Spider 2.0, and BIRD. For the industrial-level Spider2.0-SQLite benchmark, the verbal-RL pipeline achieves an execution accuracy 7.4\\% higher than SOTA, and the CoT pipeline is 1.4\\% higher. RL training with mixed SQL dialects yields strong, threefold gains, particularly for dialects with limited training data. Overall, \\emph{PaVeRL-SQL} delivers reliable, SOTA Text-to-SQL under realistic industrial constraints. The code is available at https://github.com/PaVeRL-SQL/PaVeRL-SQL.","published":"2025-09-08T19:15:38Z","updated":"2025-09-08T19:15:38Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.07159v1","pdf_url":"https://arxiv.org/pdf/2509.07159v1","comment":"10 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.05941","versioned_id":"2509.05941v4","title":"Code2MCP: Transforming Code Repositories into MCP Services","authors":["Chaoqian Ouyang","Ling Yue","Shimin Di","Libin Zheng","Linan Yue","Shaowu Pan","Jian Yin","Min-Ling Zhang"],"abstract":"The Model Context Protocol (MCP) aims to create a standard for how Large Language Models use tools. However, most current research focuses on selecting tools from an existing pool. A more fundamental, yet largely overlooked, problem is how to populate this pool by converting the vast number of existing software projects into MCP-compatible services. To bridge this gap, we introduce Code2MCP, an agent-based framework that automatically transforms a GitHub repository into a functional MCP service with minimal human intervention. Code2MCP employs a multi-agent workflow for code analysis, environment setup, tool function design, and service generation, enhanced by a self-correcting loop to ensure reliability. We demonstrate that Code2MCP successfully transforms open-source computing libraries in scientific fields such as bioinformatics, mathematics, and fluid dynamics that are not available in existing MCP servers. By providing a novel automated pathway to unlock GitHub, the world's largest code repository, for the MCP ecosystem, Code2MCP serves as a catalyst to significantly accelerate the protocol's adoption and practical application. The code is public at https://github.com/DEFENSE-SEU/Code2MCP.","published":"2025-09-07T06:13:25Z","updated":"2026-02-11T03:04:52Z","categories":["cs.SE","cs.LG","cs.MA"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2509.05941v4","pdf_url":"https://arxiv.org/pdf/2509.05941v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.05735","versioned_id":"2509.05735v1","title":"Offline vs. Online Learning in Model-based RL: Lessons for Data Collection Strategies","authors":["Jiaqi Chen","Ji Shi","Cansu Sancaktar","Jonas Frey","Georg Martius"],"abstract":"Data collection is crucial for learning robust world models in model-based reinforcement learning. The most prevalent strategies are to actively collect trajectories by interacting with the environment during online training or training on offline datasets. At first glance, the nature of learning task-agnostic environment dynamics makes world models a good candidate for effective offline training. However, the effects of online vs. offline data on world models and thus on the resulting task performance have not been thoroughly studied in the literature. In this work, we investigate both paradigms in model-based settings, conducting experiments on 31 different environments. First, we showcase that online agents outperform their offline counterparts. We identify a key challenge behind performance degradation of offline agents: encountering Out-Of-Distribution states at test time. This issue arises because, without the self-correction mechanism in online agents, offline datasets with limited state space coverage induce a mismatch between the agent's imagination and real rollouts, compromising policy training. We demonstrate that this issue can be mitigated by allowing for additional online interactions in a fixed or adaptive schedule, restoring the performance of online training with limited interaction data. We also showcase that incorporating exploration data helps mitigate the performance degradation of offline agents. Based on our insights, we recommend adding exploration data when collecting large datasets, as current efforts predominantly focus on expert data alone.","published":"2025-09-06T14:52:33Z","updated":"2025-09-06T14:52:33Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.05735v1","pdf_url":"https://arxiv.org/pdf/2509.05735v1","comment":"Accepted at Reinforcement Learning Conference (RLC 2025); Code available at: https://github.com/swsychen/Offline_vs_Online_in_MBRL","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.05007","versioned_id":"2509.05007v2","title":"Sticker-TTS: Learn to Utilize Historical Experience with a Sticker-driven Test-Time Scaling Framework","authors":["Jie Chen","Jinhao Jiang","Yingqian Min","Zican Dong","Shijie Wang","Wayne Xin Zhao","Ji-Rong Wen"],"abstract":"Large reasoning models (LRMs) have exhibited strong performance on complex reasoning tasks, with further gains achievable through increased computational budgets at inference. However, current test-time scaling methods predominantly rely on redundant sampling, ignoring the historical experience utilization, thereby limiting computational efficiency. To overcome this limitation, we propose Sticker-TTS, a novel test-time scaling framework that coordinates three collaborative LRMs to iteratively explore and refine solutions guided by historical attempts. At the core of our framework are distilled key conditions-termed stickers-which drive the extraction, refinement, and reuse of critical information across multiple rounds of reasoning. To further enhance the efficiency and performance of our framework, we introduce a two-stage optimization strategy that combines imitation learning with self-improvement, enabling progressive refinement. Extensive evaluations on three challenging mathematical reasoning benchmarks, including AIME-24, AIME-25, and OlymMATH, demonstrate that Sticker-TTS consistently surpasses strong baselines, including self-consistency and advanced reinforcement learning approaches, under comparable inference budgets. These results highlight the effectiveness of sticker-guided historical experience utilization. Our code and data are available at https://github.com/RUCAIBox/Sticker-TTS.","published":"2025-09-05T11:14:11Z","updated":"2025-09-08T03:26:03Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.05007v2","pdf_url":"https://arxiv.org/pdf/2509.05007v2","comment":"11 pages, 1 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.04575","versioned_id":"2509.04575v3","title":"Bootstrapping Task Spaces for Self-Improvement","authors":["Minqi Jiang","Andrei Lupu","Yoram Bachrach"],"abstract":"Progress in many task domains emerges from repeated revisions to previous solution attempts. Training agents that can reliably self-improve over such sequences at inference-time is a natural target for reinforcement learning (RL), yet the naive approach assumes a fixed maximum iteration depth, which can be both costly and arbitrary. We present Exploratory Iteration (ExIt), a family of autocurriculum RL methods that directly exploits the recurrent structure of self-improvement tasks to train LLMs to perform multi-step self-improvement at inference-time while only training on the most informative single-step iterations. ExIt grows a task space by selectively sampling the most informative intermediate, partial histories encountered during an episode for continued iteration, treating these starting points as new self-iteration task instances to train a self-improvement policy. ExIt can further pair with explicit exploration mechanisms to sustain greater task diversity. Across several domains, encompassing competition math, multi-turn tool-use, and machine learning engineering, we demonstrate that ExIt strategies, starting from either a single or many task instances, can produce policies exhibiting strong inference-time self-improvement on held-out task instances, and the ability to iterate towards higher performance over a step budget extending beyond the average iteration depth encountered during training.","published":"2025-09-04T18:01:00Z","updated":"2026-02-22T23:28:26Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.04575v3","pdf_url":"https://arxiv.org/pdf/2509.04575v3","comment":"TMLR, February 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.04439","versioned_id":"2509.04439v3","title":"ArcMemo: Abstract Reasoning Composition with Lifelong LLM Memory","authors":["Matthew Ho","Chen Si","Zhaoxiang Feng","Fangxu Yu","Yichi Yang","Zhijian Liu","Zhiting Hu","Lianhui Qin"],"abstract":"While inference-time scaling enables LLMs to carry out increasingly long and capable reasoning traces, the patterns and insights uncovered during these traces are immediately discarded once the context window is reset for a new query. External memory is a natural way to persist these discoveries, and recent work has shown clear benefits for reasoning-intensive tasks. We see an opportunity to make such memories more broadly reusable and scalable by moving beyond instance-based memory entries (e.g. exact query/response pairs, or summaries tightly coupled with the original problem context) toward concept-level memory: reusable, modular abstractions distilled from solution traces and stored in natural language. For future queries, relevant concepts are selectively retrieved and integrated into the prompt, enabling test-time continual learning without weight updates. Our design introduces new strategies for abstracting takeaways from rollouts and retrieving entries for new queries, promoting reuse and allowing memory to expand with additional experiences. We evaluate on ARC-AGI, a benchmark that stresses compositional generalization and abstract reasoning, making it a natural fit for concept memory. Our method yields a 7.5% relative gain over a strong no-memory baseline with performance continuing to scale with inference compute. We find abstract concepts to be the most consistent memory design, outscoring the baseline at all tested inference compute scales. Moreover, dynamically updating memory during test-time outperforms fixed settings, supporting the hypothesis that accumulating and abstracting patterns enables further solutions in a form of self-improvement. Code is available at https://github.com/matt-seb-ho/arc_memo.","published":"2025-09-04T17:54:19Z","updated":"2025-10-04T00:01:09Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.04439v3","pdf_url":"https://arxiv.org/pdf/2509.04439v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.04343","versioned_id":"2509.04343v1","title":"Psychologically Enhanced AI Agents","authors":["Maciej Besta","Shriram Chandran","Robert Gerstenberger","Mathis Lindner","Marcin Chrapek","Sebastian Hermann Martschat","Taraneh Ghandi","Patrick Iff","Hubert Niewiadomski","Piotr Nyczyk","Jürgen Müller","Torsten Hoefler"],"abstract":"We introduce MBTI-in-Thoughts, a framework for enhancing the effectiveness of Large Language Model (LLM) agents through psychologically grounded personality conditioning. Drawing on the Myers-Briggs Type Indicator (MBTI), our method primes agents with distinct personality archetypes via prompt engineering, enabling control over behavior along two foundational axes of human psychology, cognition and affect. We show that such personality priming yields consistent, interpretable behavioral biases across diverse tasks: emotionally expressive agents excel in narrative generation, while analytically primed agents adopt more stable strategies in game-theoretic settings. Our framework supports experimenting with structured multi-agent communication protocols and reveals that self-reflection prior to interaction improves cooperation and reasoning quality. To ensure trait persistence, we integrate the official 16Personalities test for automated verification. While our focus is on MBTI, we show that our approach generalizes seamlessly to other psychological frameworks such as Big Five, HEXACO, or Enneagram. By bridging psychological theory and LLM behavior design, we establish a foundation for psychologically enhanced AI agents without any fine-tuning.","published":"2025-09-04T16:03:03Z","updated":"2025-09-04T16:03:03Z","categories":["cs.AI","cs.CL","cs.CY","cs.HC","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.04343v1","pdf_url":"https://arxiv.org/pdf/2509.04343v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.03312","versioned_id":"2509.03312v2","title":"AgenTracer: Who Is Inducing Failure in the LLM Agentic Systems?","authors":["Guibin Zhang","Junhao Wang","Junjie Chen","Wangchunshu Zhou","Kun Wang","Shuicheng Yan"],"abstract":"Large Language Model (LLM)-based agentic systems, often comprising multiple models, complex tool invocations, and orchestration protocols, substantially outperform monolithic agents. Yet this very sophistication amplifies their fragility, making them more prone to system failure. Pinpointing the specific agent or step responsible for an error within long execution traces defines the task of agentic system failure attribution. Current state-of-the-art reasoning LLMs, however, remain strikingly inadequate for this challenge, with accuracy generally below 10%. To address this gap, we propose AgenTracer, the first automated framework for annotating failed multi-agent trajectories via counterfactual replay and programmed fault injection, producing the curated dataset TracerTraj. Leveraging this resource, we develop AgenTracer-8B, a lightweight failure tracer trained with multi-granular reinforcement learning, capable of efficiently diagnosing errors in verbose multi-agent interactions. On the Who&When benchmark, AgenTracer-8B outperforms giant proprietary LLMs like Gemini-2.5-Pro and Claude-4-Sonnet by up to 18.18%, setting a new standard in LLM agentic failure attribution. More importantly, AgenTracer-8B delivers actionable feedback to off-the-shelf multi-agent systems like MetaGPT and MaAS with 4.8-14.2% performance gains, empowering self-correcting and self-evolving agentic AI.","published":"2025-09-03T13:42:14Z","updated":"2025-09-04T17:49:20Z","categories":["cs.CL","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.03312v2","pdf_url":"https://arxiv.org/pdf/2509.03312v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.03113","versioned_id":"2509.03113v5","title":"Mitigating Multimodal Hallucinations via Gradient-based Self-Reflection","authors":["Shan Wang","Maying Shen","Nadine Chang","Chuong Nguyen","Hongdong Li","Jose M. Alvarez"],"abstract":"Multimodal large language models achieve strong performance across diverse tasks but remain prone to hallucinations, where outputs are not grounded in visual inputs. This issue can be attributed to two main biases: text-visual bias, the overreliance on prompts and prior outputs, and co-occurrence bias, spurious correlations between frequently paired objects. We propose Gradient-based Influence-Aware Constrained Decoding (GACD), an inference-based method, that addresses both biases without auxiliary models, and is readily applicable to existing models without finetuning. The core of our approach is bias estimation, which uses first-order Taylor gradients to understand the contribution of individual tokens-visual features and text tokens-to the current output. Based on this analysis, GACD mitigates hallucinations through two components: (1) suppressing spurious visual features correlated with the output objects, and (2) rebalancing cross-modal contributions by strengthening visual features relative to text. Experiments across multiple benchmarks demonstrate that GACD effectively reduces hallucinations and improves the visual grounding of MLLM outputs.","published":"2025-09-03T08:13:52Z","updated":"2026-03-02T01:46:14Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.03113v5","pdf_url":"https://arxiv.org/pdf/2509.03113v5","comment":"CVPR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.05351","versioned_id":"2509.05351v1","title":"Self-Driving Laboratory Optimizes the Lower Critical Solution Temperature of Thermoresponsive Polymers","authors":["Guoyue Xu","Renzheng Zhang","Tengfei Luo"],"abstract":"To overcome the inherent inefficiencies of traditional trial-and-error materials discovery, the scientific community is increasingly developing autonomous laboratories that integrate data-driven decision-making into closed-loop experimental workflows. In this work, we realize this concept for thermoresponsive polymers by developing a low-cost, \"frugal twin\" platform for the optimization of the lower critical solution temperature (LCST) of poly(N-isopropylacrylamide) (PNIPAM). Our system integrates robotic fluid-handling, on-line sensors, and Bayesian optimization (BO) that navigates the multi-component salt solution spaces to achieve user-specified LCST targets. The platform demonstrates convergence to target properties within a minimal number of experiments. It strategically explores the parameter space, learns from informative \"off-target\" results, and self-corrects to achieve the final targets. By providing an accessible and adaptable blueprint, this work lowers the barrier to entry for autonomous experimentation and accelerates the design and discovery of functional polymers.","published":"2025-09-02T19:35:33Z","updated":"2025-09-02T19:35:33Z","categories":["cond-mat.soft","cs.LG"],"primary_category":"cond-mat.soft","arxiv_url":"https://arxiv.org/abs/2509.05351v1","pdf_url":"https://arxiv.org/pdf/2509.05351v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.02722","versioned_id":"2509.02722v2","title":"Planning with Reasoning using Vision Language World Model","authors":["Delong Chen","Theo Moutakanni","Willy Chung","Yejin Bang","Ziwei Ji","Allen Bolourchi","Pascale Fung"],"abstract":"Effective planning requires strong world models, but high-level world models that can understand and reason about actions with semantic and temporal abstraction remain largely underdeveloped. We introduce the Vision Language World Model (VLWM), a foundation model trained for language-based world modeling on natural videos. Given visual observations, the VLWM first infers the overall goal achievements then predicts a trajectory composed of interleaved actions and world state changes. Those targets are extracted by iterative LLM Self-Refine conditioned on compressed future observations represented by Tree of Captions. The VLWM learns both an action policy and a dynamics model, which respectively facilitates reactive system-1 plan decoding and reflective system-2 planning via cost minimization. The cost evaluates the semantic distance between the hypothetical future states given by VLWM roll-outs and the expected goal state, and is measured by a critic model that we trained in a self-supervised manner. The VLWM achieves state-of-the-art Visual Planning for Assistance (VPA) performance on both benchmark evaluations and our proposed PlannerArena human evaluations, where system-2 improves the Elo score by +27% upon system-1. The VLWM models also outperforms strong VLM baselines on RoboVQA and WorldPrediction benchmark.","published":"2025-09-02T18:18:57Z","updated":"2025-09-06T21:02:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.02722v2","pdf_url":"https://arxiv.org/pdf/2509.02722v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.02709","versioned_id":"2509.02709v2","title":"Preference Robustness for DPO with Applications to Public Health","authors":["Cheol Woo Kim","Shresth Verma","Mauricio Tec","Milind Tambe"],"abstract":"We study an LLM fine-tuning task for designing reward functions for sequential resource allocation problems in public health, guided by human preferences expressed in natural language. This setting presents a challenging testbed for alignment due to complex and ambiguous objectives and limited data availability. We propose DPO-PRO, a robust fine-tuning algorithm based on Direct Preference Optimization (DPO), which accounts for uncertainty in the preference distribution using a lightweight Distributionally Robust Optimization (DRO) formulation. Unlike prior DRO-based DPO methods, DPO-PRO is significantly less conservative. We evaluate DPO-PRO on a real-world maternal mobile health program operated by the non-profit organization ARMMAN, as well as on standard alignment benchmarks. Experimental results demonstrate that our method consistently improves robustness to noisy preference signals compared to existing DPO variants. Moreover, DPO-PRO achieves comparable performance to prior self-reflection-based baseline for reward function design, while requiring significantly lower inference-time cost.","published":"2025-09-02T18:10:32Z","updated":"2025-11-17T20:34:16Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.02709v2","pdf_url":"https://arxiv.org/pdf/2509.02709v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.02547","versioned_id":"2509.02547v5","title":"The Landscape of Agentic Reinforcement Learning for LLMs: A Survey","authors":["Guibin Zhang","Hejia Geng","Xiaohang Yu","Zhenfei Yin","Zaibin Zhang","Zelin Tan","Heng Zhou","Zhongzhi Li","Xiangyuan Xue","Yijiang Li","Yifan Zhou","Yang Chen","Chen Zhang","Yutao Fan","Zihu Wang","Songtao Huang","Francisco Piedrahita-Velez","Yue Liao","Hongru Wang","Mengyue Yang","Heng Ji","Jun Wang","Shuicheng Yan","Philip Torr","Lei Bai"],"abstract":"The emergence of agentic reinforcement learning (Agentic RL) marks a paradigm shift from conventional reinforcement learning applied to large language models (LLM RL), reframing LLMs from passive sequence generators into autonomous, decision-making agents embedded in complex, dynamic worlds. This survey formalizes this conceptual shift by contrasting the degenerate single-step Markov Decision Processes (MDPs) of LLM-RL with the temporally extended, partially observable Markov decision processes (POMDPs) that define Agentic RL. Building on this foundation, we propose a comprehensive twofold taxonomy: one organized around core agentic capabilities, including planning, tool use, memory, reasoning, self-improvement, and perception, and the other around their applications across diverse task domains. Central to our thesis is that reinforcement learning serves as the critical mechanism for transforming these capabilities from static, heuristic modules into adaptive, robust agentic behavior. To support and accelerate future research, we consolidate the landscape of open-source environments, benchmarks, and frameworks into a practical compendium. By synthesizing over five hundred recent works, this survey charts the contours of this rapidly evolving field and highlights the opportunities and challenges that will shape the development of scalable, general-purpose AI agents.","published":"2025-09-02T17:46:26Z","updated":"2026-04-17T18:09:08Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.02547v5","pdf_url":"https://arxiv.org/pdf/2509.02547v5","comment":"Published on Transactions on Machine Learning Research: https://openreview.net/forum?id=RY19y2RI1O","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.02479","versioned_id":"2509.02479v2","title":"SimpleTIR: End-to-End Reinforcement Learning for Multi-Turn Tool-Integrated Reasoning","authors":["Zhenghai Xue","Longtao Zheng","Qian Liu","Yingru Li","Xiaosen Zheng","Zejun Ma","Bo An"],"abstract":"Large Language Models (LLMs) can significantly improve their reasoning capabilities by interacting with external tools, a paradigm known as Tool-Integrated Reasoning (TIR). However, extending TIR to multi-turn scenarios using Reinforcement Learning (RL) is often hindered by training instability and performance collapse. We identify that such instability is primarily caused by a distributional drift from external tool feedback, leading to the generation of low-probability tokens. This issue compounds over successive turns, causing catastrophic gradient norm explosions that derail the training process. To address this challenge, we introduce SimpleTIR , a plug-and-play algorithm that stabilizes multi-turn TIR training. Its core strategy is to identify and filter out trajectories containing void turns, i.e., turns that yield neither a code block nor a final answer. By removing these problematic trajectories from the policy update, SimpleTIR effectively blocks the harmful, high-magnitude gradients, thus stabilizing the learning dynamics. Extensive experiments show that SimpleTIR achieves state-of-the-art performance on challenging math reasoning benchmarks, notably elevating the AIME24 score from a text-only baseline of 22.1 to 50.5 when starting from the Qwen2.5-7B base model. Furthermore, by avoiding the constraints of supervised fine-tuning, SimpleTIR encourages the model to discover diverse and sophisticated reasoning patterns, such as self-correction and cross-validation.","published":"2025-09-02T16:30:19Z","updated":"2025-09-03T17:06:42Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.02479v2","pdf_url":"https://arxiv.org/pdf/2509.02479v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.02297","versioned_id":"2509.02297v1","title":"Re-evaluating LLM-based Heuristic Search: A Case Study on the 3D Packing Problem","authors":["Guorui Quan","Mingfei Sun","Manuel López-Ibáñez"],"abstract":"The art of heuristic design has traditionally been a human pursuit. While Large Language Models (LLMs) can generate code for search heuristics, their application has largely been confined to adjusting simple functions within human-crafted frameworks, leaving their capacity for broader innovation an open question. To investigate this, we tasked an LLM with building a complete solver for the constrained 3D Packing Problem. Direct code generation quickly proved fragile, prompting us to introduce two supports: constraint scaffolding--prewritten constraint-checking code--and iterative self-correction--additional refinement cycles to repair bugs and produce a viable initial population. Notably, even within a vast search space in a greedy process, the LLM concentrated its efforts almost exclusively on refining the scoring function. This suggests that the emphasis on scoring functions in prior work may reflect not a principled strategy, but rather a natural limitation of LLM capabilities. The resulting heuristic was comparable to a human-designed greedy algorithm, and when its scoring function was integrated into a human-crafted metaheuristic, its performance rivaled established solvers, though its effectiveness waned as constraints tightened. Our findings highlight two major barriers to automated heuristic design with current LLMs: the engineering required to mitigate their fragility in complex reasoning tasks, and the influence of pretrained biases, which can prematurely narrow the search for novel solutions.","published":"2025-09-02T13:18:47Z","updated":"2025-09-02T13:18:47Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.02297v1","pdf_url":"https://arxiv.org/pdf/2509.02297v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.01517","versioned_id":"2509.01517v1","title":"Agentic Workflow for Education: Concepts and Applications","authors":["Yuan-Hao Jiang","Yijie Lu","Ling Dai","Jiatong Wang","Ruijia Li","Bo Jiang"],"abstract":"With the rapid advancement of Large Language Models (LLMs) and Artificial Intelligence (AI) agents, agentic workflows are showing transformative potential in education. This study introduces the Agentic Workflow for Education (AWE), a four-component model comprising self-reflection, tool invocation, task planning, and multi-agent collaboration. We distinguish AWE from traditional LLM-based linear interactions and propose a theoretical framework grounded in the von Neumann Multi-Agent System (MAS) architecture. Through a paradigm shift from static prompt-response systems to dynamic, nonlinear workflows, AWE enables scalable, personalized, and collaborative task execution. We further identify four core application domains: integrated learning environments, personalized AI-assisted learning, simulation-based experimentation, and data-driven decision-making. A case study on automated math test generation shows that AWE-generated items are statistically comparable to real exam questions, validating the model's effectiveness. AWE offers a promising path toward reducing teacher workload, enhancing instructional quality, and enabling broader educational innovation.","published":"2025-09-01T14:39:48Z","updated":"2025-09-01T14:39:48Z","categories":["cs.CY","cs.AI","cs.ET"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2509.01517v1","pdf_url":"https://arxiv.org/pdf/2509.01517v1","comment":"Proceedings of the 33rd International Conference on Computers in Education (ICCE 2025). Asia-Pacific Society for Computers in Education","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.06982","versioned_id":"2509.06982v1","title":"CARE: Decoding Time Safety Alignment via Rollback and Introspection Intervention","authors":["Xiaomeng Hu","Fei Huang","Chenhan Yuan","Junyang Lin","Tsung-Yi Ho"],"abstract":"As large language models (LLMs) are increasingly deployed in real-world applications, ensuring the safety of their outputs during decoding has become a critical challenge. However, existing decoding-time interventions, such as Contrastive Decoding, often force a severe trade-off between safety and response quality. In this work, we propose CARE, a novel framework for decoding-time safety alignment that integrates three key components: (1) a guard model for real-time safety monitoring, enabling detection of potentially unsafe content; (2) a rollback mechanism with a token buffer to correct unsafe outputs efficiently at an earlier stage without disrupting the user experience; and (3) a novel introspection-based intervention strategy, where the model generates self-reflective critiques of its previous outputs and incorporates these reflections into the context to guide subsequent decoding steps. The framework achieves a superior safety-quality trade-off by using its guard model for precise interventions, its rollback mechanism for timely corrections, and our novel introspection method for effective self-correction. Experimental results demonstrate that our framework achieves a superior balance of safety, quality, and efficiency, attaining a low harmful response rate and minimal disruption to the user experience while maintaining high response quality.","published":"2025-09-01T04:50:02Z","updated":"2025-09-01T04:50:02Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.06982v1","pdf_url":"https://arxiv.org/pdf/2509.06982v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.00696","versioned_id":"2509.00696v1","title":"Queuing for Civility: Regulating Emotions and Reducing Toxicity in Digital Discourse","authors":["Akriti Verma","Shama Islam","Valeh Moghaddam","Adnan Anwar"],"abstract":"The pervasiveness of online toxicity, including hate speech and trolling, disrupts digital interactions and online well-being. Previous research has mainly focused on post-hoc moderation, overlooking the real-time emotional dynamics of online conversations and the impact of users' emotions on others. This paper presents a graph-based framework to identify the need for emotion regulation within online conversations. This framework promotes self-reflection to manage emotional responses and encourage responsible behaviour in real time. Additionally, a comment queuing mechanism is proposed to address intentional trolls who exploit emotions to inflame conversations. This mechanism introduces a delay in publishing comments, giving users time to self-regulate before further engaging in the conversation and helping maintain emotional balance. Analysis of social media data from Twitter and Reddit demonstrates that the graph-based framework reduced toxicity by 12%, while the comment queuing mechanism decreased the spread of anger by 15%, with only 4% of comments being temporarily held on average. These findings indicate that combining real-time emotion regulation with delayed moderation can significantly improve well-being in online environments.","published":"2025-08-31T04:32:15Z","updated":"2025-08-31T04:32:15Z","categories":["cs.HC","cs.AI","cs.CY","cs.LG","cs.SI"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2509.00696v1","pdf_url":"https://arxiv.org/pdf/2509.00696v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.00676","versioned_id":"2509.00676v1","title":"LLaVA-Critic-R1: Your Critic Model is Secretly a Strong Policy Model","authors":["Xiyao Wang","Chunyuan Li","Jianwei Yang","Kai Zhang","Bo Liu","Tianyi Xiong","Furong Huang"],"abstract":"In vision-language modeling, critic models are typically trained to evaluate outputs -- assigning scalar scores or pairwise preferences -- rather than to generate responses. This separation from policy models, which produce the responses, is so entrenched that critics are rarely considered for direct policy use. In this work, we challenge this convention. We propose to reorganize preference-labeled critic datasets into verifiable training signals and perform reinforcement learning directly on a base generative model, producing LLaVA-Critic-R1, a multimodal critic trained to optimize preference judgments while retaining full generation ability. Surprisingly, LLaVA-Critic-R1 emerges not only as a top-performing critic but also as a competitive policy model -- matching or surpassing specialized reasoning VLMs trained with in-domain data across 26 visual reasoning and understanding benchmarks, with an average gain of +5.7% over its base model (Qwen-2.5-VL-7B). Extending this approach to existing strong reasoning VLMs yields LLaVA-Critic-R1+, which further advances policy performance without sacrificing critic quality, achieving a SoTA performance of 71.9 on MMMU at the 7B scale. Finally, we show that the enhanced critic ability benefits inference: applying self-critique at test time yields an average +13.8% improvement on five representative reasoning tasks without additional training. Our results reveal that RL training on critic data can produce a unified model excelling at both evaluation and generation, offering a simple path toward scalable, self-improving multimodal systems.","published":"2025-08-31T03:08:02Z","updated":"2025-08-31T03:08:02Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.00676v1","pdf_url":"https://arxiv.org/pdf/2509.00676v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.00629","versioned_id":"2509.00629v1","title":"Can Multi-turn Self-refined Single Agent LMs with Retrieval Solve Hard Coding Problems?","authors":["Md Tanzib Hosain","Md Kishor Morol"],"abstract":"Among the hardest tasks for humans are those found in competitive programming where problems require sophisticated algorithmic thinking, puzzle solving, and the creation of effective code. As a domain to assess language models (LMs), it has not received enough attention, though. This study presents the ICPC benchmark, which consists of 254 international collegiate programming contest (ICPC) tasks. Each problem includes official analysis, reference code, and sample, high-quality unit, and hidden tests. We are able to develop and evaluate a variety of LM inference techniques for competitive programming with these resources. With zero-shot chain-of-thought prompting, we find that o1 only achieves a 19.1\\% pass@1 solve rate. With our best inference technique, which combines multi-turn self-judge with reflection and retrieval over episodic information, raises this to 42.2\\%. Furthermore, we conduct a new human-in-the-loop investigation to gain a deeper understanding of the remaining difficulties. Surprisingly, we discover that o1 can solve 17 out of 18 problems that were previously unsolvable by any model or technique with just a few specific instructions. A footstep toward LMs with grounded, imaginative, and algorithmic thinking is provided by our quantitative findings and qualitative research. We open-source our code and data at https://github.com/kraritt/zolve.","published":"2025-08-30T23:02:12Z","updated":"2025-08-30T23:02:12Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.00629v1","pdf_url":"https://arxiv.org/pdf/2509.00629v1","comment":"Accepted in Proceedings of the 63rd Annual Meeting of the Association for Computational Linguistics (Student Research Workshop), 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.00510","versioned_id":"2509.00510v1","title":"LLM-Assisted Iterative Evolution with Swarm Intelligence Toward SuperBrain","authors":["Li Weigang","Pedro Carvalho Brom","Lucas Ramson Siefert"],"abstract":"We propose a novel SuperBrain framework for collective intelligence, grounded in the co-evolution of large language models (LLMs) and human users. Unlike static prompt engineering or isolated agent simulations, our approach emphasizes a dynamic pathway from Subclass Brain to Superclass Brain: (1) A Subclass Brain arises from persistent, personalized interaction between a user and an LLM, forming a cognitive dyad with adaptive learning memory. (2) Through GA-assisted forward-backward evolution, these dyads iteratively refine prompts and task performance. (3) Multiple Subclass Brains coordinate via Swarm Intelligence, optimizing across multi-objective fitness landscapes and exchanging distilled heuristics. (4) Their standardized behaviors and cognitive signatures integrate into a Superclass Brain, an emergent meta-intelligence capable of abstraction, generalization and self-improvement. We outline the theoretical constructs, present initial implementations (e.g., UAV scheduling, KU/KI keyword filtering) and propose a registry for cross-dyad knowledge consolidation. This work provides both a conceptual foundation and an architectural roadmap toward scalable, explainable and ethically aligned collective AI.","published":"2025-08-30T14:12:46Z","updated":"2025-08-30T14:12:46Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.00510v1","pdf_url":"https://arxiv.org/pdf/2509.00510v1","comment":"24 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.00325","versioned_id":"2509.00325v1","title":"GIER: Gap-Driven Self-Refinement for Large Language Models","authors":["Rinku Dewri"],"abstract":"We introduce GIER (Gap-driven Iterative Enhancement of Responses), a general framework for improving large language model (LLM) outputs through self-reflection and revision based on conceptual quality criteria. Unlike prompting strategies that rely on demonstrations, examples, or chain-of-thought templates, GIER utilizes natural language descriptions of reasoning gaps, and prompts a model to iteratively critique and refine its own outputs to better satisfy these criteria. Across three reasoning-intensive tasks (SciFact, PrivacyQA, and e-SNLI) and four LLMs (GPT-4.1, GPT-4o Mini, Gemini 1.5 Pro, and Llama 3.3 70B), GIER improves rationale quality, grounding, and reasoning alignment without degrading task accuracy. Our analysis demonstrates that models can not only interpret abstract conceptual gaps but also translate them into concrete reasoning improvements.","published":"2025-08-30T02:54:08Z","updated":"2025-08-30T02:54:08Z","categories":["cs.CL","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.00325v1","pdf_url":"https://arxiv.org/pdf/2509.00325v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.00251","versioned_id":"2509.00251v2","title":"Instruction-Level Weight Shaping: A Framework for Self-Improving AI Agents","authors":["Rimom Costa"],"abstract":"Large language models (LLMs) are fluent but largely static after pre-training; new or shifting knowledge is typically added with retrieval-augmented generation (RAG) or fine-tuning. RAG raises latency and engineering overhead and often fails to integrate facts; prompt engineering is brittle and can conflict with prior knowledge; fine-tuning is costly and risks catastrophic forgetting. We propose Instruction-Level Weight Shaping (ILWS): curated system instructions act as external, auditable pseudo-parameters updated after each session via reflection and user feedback. A Reflection Engine inspects conversation traces, diagnoses reasoning successes and failures, and proposes typed deltas $ΔK=(ΔS,ΔU,ΔT)$ over instructions, user preferences, and tools. Deltas are version-controlled, evaluated with a sliding window of 1-5 star ratings, auto-repaired on first failure, and rolled back on repeated failure. When an edit budget crosses a threshold, the agent compiles a rating-weighted synthetic set and distills matured instruction-space gains into parameters, converting prompt-space improvements into weight-space without downtime. ILWS makes explicit the low-rank shaping induced by context in transformer blocks, preserves governance, and removes per-call retrieval. In enterprise support it increased throughput 2.4-5.0x and cut audited hallucinations by about 80% versus a frozen baseline. In an Adobe Commerce Cloud proof of concept \"L0 Support\", it achieved 4-5x more tickets per hour and about 80% lower time per ticket, with autonomous instruction updates and optional tool synthesis. Because ILWS operates at the instruction layer until controlled distillation, it generalizes to dynamic domains (legal, medical, engineering) requiring adaptive reasoning, tool creation, and low-latency deployment.","published":"2025-08-29T21:34:39Z","updated":"2025-12-20T18:38:07Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.00251v2","pdf_url":"https://arxiv.org/pdf/2509.00251v2","comment":"12 pages, 1 figure, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.21517","versioned_id":"2508.21517v1","title":"Modeling Wise Decision Making: A Z-Number Fuzzy Framework Inspired by Phronesis","authors":["Sweta Kaman","Ankita Sharma","Romi Banerjee"],"abstract":"Background: Wisdom is a superordinate construct that embraces perspective taking, reflectiveness, prosocial orientation, reflective empathetic action, and intellectual humility. Unlike conventional models of reasoning that are rigidly bound by binary thinking, wisdom unfolds in shades of ambiguity, requiring both graded evaluation and self-reflective humility. Current measures depend on self-reports and seldom reflect the humility and uncertainty inherent in wise reasoning. A computational framework that takes into account both multidimensionality and confidence has the potential to improve psychological science and allow humane AI. Method: We present a fuzzy inference system with Z numbers, each of the decisions being expressed in terms of a wisdom score (restriction) and confidence score (certainty). As part of this study, participants (N = 100) were exposed to culturally neutral pictorial moral dilemma tasks to which they generated think-aloud linguistic responses, which were mapped into five theoretically based components of wisdom. The scores of each individual component were combined using a base of 21 rules, with membership functions tuned via Gaussian kernel density estimation. Results: In a proof of concept study, the system produced dual attribute wisdom representations that correlated modestly but significantly with established scales while showing negligible relations with unrelated traits, supporting convergent and divergent validity. Contribution: The contribution is to formalize wisdom as a multidimensional, uncertainty-conscious construct, operationalized in the form of Z-numbers. In addition to progressing measurement in psychology, it calculates how fuzzy Z numbers can provide AI systems with interpretable, confidence-sensitive reasoning that affords a safe, middle ground between rigorous computation and human-like judgment.","published":"2025-08-29T11:03:44Z","updated":"2025-08-29T11:03:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.21517v1","pdf_url":"https://arxiv.org/pdf/2508.21517v1","comment":"total 17 pages, main manuscript 12 pages, supplementary 5 pages, 6 tables in main manuscript, 5 figures in main manuscript, 2 tables in supplementary, and 3 figures in supplementary","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.21048","versioned_id":"2508.21048v2","title":"Veritas: Generalizable Deepfake Detection via Pattern-Aware Reasoning","authors":["Hao Tan","Jun Lan","Zichang Tan","Ajian Liu","Chuanbiao Song","Senyuan Shi","Huijia Zhu","Weiqiang Wang","Jun Wan","Zhen Lei"],"abstract":"Deepfake detection remains a formidable challenge due to the complex and evolving nature of fake content in real-world scenarios. However, existing academic benchmarks suffer from severe discrepancies from industrial practice, typically featuring homogeneous training sources and low-quality testing images, which hinder the practical deployments of current detectors. To mitigate this gap, we introduce HydraFake, a dataset that simulates real-world challenges with hierarchical generalization testing. Specifically, HydraFake involves diversified deepfake techniques and in-the-wild forgeries, along with rigorous training and evaluation protocol, covering unseen model architectures, emerging forgery techniques and novel data domains. Building on this resource, we propose Veritas, a multi-modal large language model (MLLM) based deepfake detector. Different from vanilla chain-of-thought (CoT), we introduce pattern-aware reasoning that involves critical reasoning patterns such as \"planning\" and \"self-reflection\" to emulate human forensic process. We further propose a two-stage training pipeline to seamlessly internalize such deepfake reasoning capacities into current MLLMs. Experiments on HydraFake dataset reveal that although previous detectors show great generalization on cross-model scenarios, they fall short on unseen forgeries and data domains. Our Veritas achieves significant gains across different OOD scenarios, and is capable of delivering transparent and faithful detection outputs.","published":"2025-08-28T17:53:05Z","updated":"2026-02-27T07:50:11Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2508.21048v2","pdf_url":"https://arxiv.org/pdf/2508.21048v2","comment":"ICLR 2026 Oral. Project: https://github.com/EricTan7/Veritas","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.20931","versioned_id":"2508.20931v2","title":"How Can Input Reformulation Improve Tool Usage Accuracy in a Complex Dynamic Environment? A Study on $τ$-bench","authors":["Venkatesh Mishra","Amir Saeidi","Satyam Raj","Mutsumi Nakamura","Jayanth Srinivasa","Gaowen Liu","Ali Payani","Chitta Baral"],"abstract":"Recent advances in reasoning and planning capabilities of large language models (LLMs) have enabled their potential as autonomous agents capable of tool use in dynamic environments. However, in multi-turn conversational environments like $τ$-bench, these agents often struggle with consistent reasoning, adherence to domain-specific policies, and extracting correct information over a long horizon of tool-calls and conversation. To capture and mitigate these failures, we conduct a comprehensive manual analysis of the common errors occurring in the conversation trajectories. We then experiment with reformulations of inputs to the tool-calling agent for improvement in agent decision making. Finally, we propose the Input-Reformulation Multi-Agent (IRMA) framework, which automatically reformulates user queries augmented with relevant domain rules and tool suggestions for the tool-calling agent to focus on. The results show that IRMA significantly outperforms ReAct, Function Calling, and Self-Reflection by 16.1%, 12.7%, and 19.1%, respectively, in overall pass^5 scores. These findings highlight the superior reliability and consistency of IRMA compared to other methods in dynamic environments.","published":"2025-08-28T15:57:33Z","updated":"2025-09-01T18:05:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.20931v2","pdf_url":"https://arxiv.org/pdf/2508.20931v2","comment":"Accepted to EMNLP 2025 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.20866","versioned_id":"2508.20866v6","title":"AVIATOR: Towards AI-Agentic Vulnerability Injection Workflow for High-Fidelity, Large-Scale Code Security Dataset","authors":["Amine Lbath","Massih-Reza Amini","Aurelien Delaitre","Vadim Okun"],"abstract":"The increasing complexity of software systems and the sophistication of cyber-attacks have underscored the need for reliable automated software vulnerability detection. Data-driven approaches using deep learning models show promise but critically depend on the availability of large, accurately labeled datasets. Yet existing datasets either suffer from noisy labels, limited vulnerability coverage, or fail to reflect vulnerabilities as they occur in real-world software. This also limits large-scale benchmarking of such solutions. Automated vulnerability injection provides a way to address these limitations, but existing techniques remain limited in coverage, contextual fidelity, or injection success. In this paper, we present AVIATOR, the first AI-agentic vulnerability injection framework. AVIATOR decomposes vulnerability injection into a coordinated workflow of specialized AI agents, tool-based analysis, and iterative self-correction, explicitly mirroring expert reasoning. It integrates RAG and lightweight LoRA-based fine-tuning to produce realistic, category-specific vulnerabilities without relying on handcrafted patterns. Across three benchmarks, AVIATOR achieves high injection fidelity (91-95%) surpassing existing injection techniques in both accuracy and vulnerability coverage. When used for data augmentation to train deep learning-based vulnerability detection (DLVD) models, AVIATOR provides the strongest downstream gains in vulnerability detection. Across models and base datasets, AVIATOR improves average F1 scores by +22% over no augmentation, +25% over VGX, holding the prior best injection success rate, and +3% over VulScribeR, the prior state-of-the-art LLM-based injection model, with +7% higher recall and no precision loss. Its augmented data exhibits the lowest distributional distortion and scales efficiently with <2% syntax rejection at 4.3x lower cost than VulScribeR.","published":"2025-08-28T14:59:39Z","updated":"2026-03-18T15:39:54Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2508.20866v6","pdf_url":"https://arxiv.org/pdf/2508.20866v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.20729","versioned_id":"2508.20729v2","title":"Re4: Scientific Computing Agent with Rewriting, Resolution, Review and Revision","authors":["Ao Cheng","Lei Zhang","Guowei He"],"abstract":"Large language models (LLMs) serve as an active and promising field of generative artificial intelligence and have demonstrated abilities to perform complex tasks in multiple domains, including mathematical and scientific reasoning. In this work, we construct a novel agent framework for solving representative problems in scientific computing. The proposed agent, incorporating a \"rewriting-resolution-review-revision\" logical chain via three reasoning LLMs (functioning as the Consultant, Reviewer, and Programmer, respectively), is integrated in a collaborative and interactive manner. The Consultant module endows the agent with knowledge transfer capabilities to link problems to professional domain insights, thereby rewriting problem descriptions through text augmentation. The Programmer module is responsible for generating and executing well-structured code to deliver the problem resolution. The Reviewer module equips the agent with the capacity for self-debugging and self-refinement through interactive feedback with code runtime outputs. By leveraging the end-to-end review mechanism, the executable code provided by the Programmer attains the iterative revision. A comprehensive evaluation is conducted on the performance of the proposed agent framework in solving partial differential equations (PDEs), ill-conditioned linear systems, and data-driven physical analysis problems. Compared to single-model, this collaborative framework significantly improves the bug-free code generation rate and reduces the occurrence of non-physical solutions, thereby establishing a highly reliable framework for autonomous code generation based on natural language descriptions. The review mechanism improved the average execution success rate of the modern reasoning models. Our code is available at https://github.com/ChengAo21/Re4_Sci_Agent","published":"2025-08-28T12:50:48Z","updated":"2026-03-02T14:14:41Z","categories":["cs.AI","physics.comp-ph"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.20729v2","pdf_url":"https://arxiv.org/pdf/2508.20729v2","comment":"31 pages, 31 figures, Presented at the ICLR 2026 Workshop on AI and Partial Differential Equations (AI&PDE)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.20549","versioned_id":"2508.20549v2","title":"MedGR$^2$: Breaking the Data Barrier for Medical Reasoning via Generative Reward Learning","authors":["Weihai Zhi","Jiayan Guo","Shangyang Li"],"abstract":"The application of Vision-Language Models (VLMs) in medicine is critically hampered by the scarcity of high-quality, expert-annotated data. Supervised Fine-Tuning (SFT) on existing datasets often leads to poor generalization on unseen modalities and tasks, while Reinforcement Learning (RL), a promising alternative, is stymied by the lack of reliable reward signals in this data-scarce domain. To break this impasse, we introduce Generative Reward Learning for Medical Reasoning (MedGR$^2$), a novel framework that creates a self-improving virtuous cycle. MedGR$^2$ co-develops a data generator and a reward model, enabling the automated, continuous creation of high-quality, multi-modal medical data that serves as both a superior training source for SFT and RL. Our experiments demonstrate that SFT with MedGR$^2$-produced data already surpasses baselines trained on large-scale, human-curated datasets. Crucially, when leveraging this data for RL via Group Relative Policy Optimization (GRPO), our model achieves state-of-the-art cross-modality and cross-task generalization, significantly outperforming specialized RL-based methods. Furthermore, our compact model, empowered by MedGR$^2$, achieves performance competitive with foundation models possessing over 10 times more parameters. MedGR$^2$ presents a new paradigm for data-efficient learning in high-stakes domains, transforming the problem from data scarcity to data generation and unlocking the full potential of RL for building truly generalizable medical AI.","published":"2025-08-28T08:41:32Z","updated":"2025-12-08T05:05:37Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.20549v2","pdf_url":"https://arxiv.org/pdf/2508.20549v2","comment":"8 pages, 5 figures","journal_ref":"AAAI'2026 Main Technical Track","doi":"","discovered_on":"2026-07-17"},{"id":"2508.20083","versioned_id":"2508.20083v1","title":"Disabling Self-Correction in Retrieval-Augmented Generation via Stealthy Retriever Poisoning","authors":["Yanbo Dai","Zhenlan Ji","Zongjie Li","Kuan Li","Shuai Wang"],"abstract":"Retrieval-Augmented Generation (RAG) has become a standard approach for improving the reliability of large language models (LLMs). Prior work demonstrates the vulnerability of RAG systems by misleading them into generating attacker-chosen outputs through poisoning the knowledge base. However, this paper uncovers that such attacks could be mitigated by the strong \\textit{self-correction ability (SCA)} of modern LLMs, which can reject false context once properly configured. This SCA poses a significant challenge for attackers aiming to manipulate RAG systems. In contrast to previous poisoning methods, which primarily target the knowledge base, we introduce \\textsc{DisarmRAG}, a new poisoning paradigm that compromises the retriever itself to suppress the SCA and enforce attacker-chosen outputs. This compromisation enables the attacker to straightforwardly embed anti-SCA instructions into the context provided to the generator, thereby bypassing the SCA. To this end, we present a contrastive-learning-based model editing technique that performs localized and stealthy edits, ensuring the retriever returns a malicious instruction only for specific victim queries while preserving benign retrieval behavior. To further strengthen the attack, we design an iterative co-optimization framework that automatically discovers robust instructions capable of bypassing prompt-based defenses. We extensively evaluate DisarmRAG across six LLMs and three QA benchmarks. Our results show near-perfect retrieval of malicious instructions, which successfully suppress SCA and achieve attack success rates exceeding 90\\% under diverse defensive prompts. Also, the edited retriever remains stealthy under several detection methods, highlighting the urgent need for retriever-centric defenses.","published":"2025-08-27T17:49:28Z","updated":"2025-08-27T17:49:28Z","categories":["cs.CR","cs.CL"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2508.20083v1","pdf_url":"https://arxiv.org/pdf/2508.20083v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2509.00084","versioned_id":"2509.00084v2","title":"Learning to Refine: Self-Refinement of Parallel Reasoning in LLMs","authors":["Qibin Wang","Pu Zhao","Shaohan Huang","Fangkai Yang","Lu Wang","Furu Wei","Qingwei Lin","Saravan Rajmohan","Dongmei Zhang"],"abstract":"Test-time scaling (TTS) has gained widespread attention for enhancing LLM reasoning. Existing approaches such as Best-of-N and majority voting are limited as their performance depends on the quality of candidate responses, making them unable to produce a correct solution when all candidates are incorrect. Parallel self-refinement, generating multiple candidates and synthesizing a refined answer conditioned on them, offers a promising alternative, but the underlying mechanism driving its effectiveness remains obscure. To bridge this gap in understanding, we introduce a new metric, the Refinement Gap, designed to quantify the relative improvement of self-refinement beyond majority voting. We show that the Refinement Gap exhibits a clear scaling trend with model size and is only weakly correlated with the base capability. Based on this discovery, we propose Generative Self-Refinement (GSR), a parallel test-time scaling framework that transfers the refinement policy from larger teacher models with higher refinement gap into smaller students. Crucially, GSR jointly trains a single model to generate strong candidates and refine a better final answer based on these candidates. Experimental results demonstrate that our method achieves state-of-the-art performance across five mathematical benchmarks over other parallel aggregation methods, while the learned refinement skill transfers across multiple model scales and families and exhibits robust generalization to an out-of-distribution domain.","published":"2025-08-27T06:51:48Z","updated":"2026-04-27T15:34:36Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.00084v2","pdf_url":"https://arxiv.org/pdf/2509.00084v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.19506","versioned_id":"2508.19506v1","title":"Learning Game-Playing Agents with Generative Code Optimization","authors":["Zhiyi Kuang","Ryan Rong","YuCheng Yuan","Allen Nie"],"abstract":"We present a generative optimization approach for learning game-playing agents, where policies are represented as Python programs and refined using large language models (LLMs). Our method treats decision-making policies as self-evolving code, with current observation as input and an in-game action as output, enabling agents to self-improve through execution traces and natural language feedback with minimal human intervention. Applied to Atari games, our game-playing Python program achieves performance competitive with deep reinforcement learning (RL) baselines while using significantly less training time and much fewer environment interactions. This work highlights the promise of programmatic policy representations for building efficient, adaptable agents capable of complex, long-horizon reasoning.","published":"2025-08-27T01:30:20Z","updated":"2025-08-27T01:30:20Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.19506v1","pdf_url":"https://arxiv.org/pdf/2508.19506v1","comment":"ICML 2025 Workshop on Programmatic Representations for Agent Learning, Vancouver, Canada","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.19069","versioned_id":"2508.19069v1","title":"Can Structured Templates Facilitate LLMs in Tackling Harder Tasks? : An Exploration of Scaling Laws by Difficulty","authors":["Zhichao Yang","Zhaoxin Fan","Gen Li","Yuanze Hu","Xinyu Wang","Ye Qiu","Xin Wang","Yifan Sun","Wenjun Wu"],"abstract":"Structured, procedural reasoning is essential for Large Language Models (LLMs), especially in mathematics. While post-training methods have improved LLM performance, they still fall short in capturing deep procedural logic on complex tasks. To tackle the issue, in this paper, we first investigate this limitation and uncover a novel finding: a Scaling Law by Difficulty, which reveals that model performance follows a U-shaped curve with respect to training data complexity -- excessive low-difficulty data impedes abstraction, while high-difficulty data significantly enhances reasoning ability. Motivated by this, we propose the Structured Solution Template (SST) framework, which uses solution templates and a curriculum of varied difficulty to explicitly teach procedural reasoning. Specifically, SST comprises (1) fine-tuning with structured solution-template chains and dynamically weighted loss to prioritize procedural logic, (2) prompt-time injection of solution templates as cognitive scaffolds to guide inference, and (3) integrated curriculum fine-tuning that explicitly teaches the model to self-plan - execute - self-correct. Experiments on GSM8K, AIME24, and new Dynamic En benchmark show that SST significantly improves both accuracy and efficiency, especially on harder problems.","published":"2025-08-26T14:26:32Z","updated":"2025-08-26T14:26:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.19069v1","pdf_url":"https://arxiv.org/pdf/2508.19069v1","comment":"9 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.18847","versioned_id":"2508.18847v2","title":"ConfTuner: Training Large Language Models to Express Their Confidence Verbally","authors":["Yibo Li","Miao Xiong","Jiaying Wu","Bryan Hooi"],"abstract":"Large Language Models (LLMs) are increasingly deployed in high-stakes domains such as science, law, and healthcare, where accurate expressions of uncertainty are essential for reliability and trust. However, current LLMs are often observed to generate incorrect answers with high confidence, a phenomenon known as \"overconfidence\". Recent efforts have focused on calibrating LLMs' verbalized confidence: i.e., their expressions of confidence in text form, such as \"I am 80% confident that...\". Existing approaches either rely on prompt engineering or fine-tuning with heuristically generated uncertainty estimates, both of which have limited effectiveness and generalizability. Motivated by the notion of proper scoring rules for calibration in classical machine learning models, we introduce ConfTuner, a simple and efficient fine-tuning method that introduces minimal overhead and does not require ground-truth confidence scores or proxy confidence estimates. ConfTuner relies on a new loss function, tokenized Brier score, which we theoretically prove to be a proper scoring rule, intuitively meaning that it \"correctly incentivizes the model to report its true probability of being correct\". ConfTuner improves calibration across diverse reasoning tasks and generalizes to black-box models such as GPT-4o. Our results further show that better-calibrated confidence enables downstream gains in self-correction and model cascade, advancing the development of trustworthy LLM systems. The code is available at https://github.com/liushiliushi/ConfTuner.","published":"2025-08-26T09:25:32Z","updated":"2025-11-25T11:46:58Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.18847v2","pdf_url":"https://arxiv.org/pdf/2508.18847v2","comment":"Accepted by NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.18791","versioned_id":"2508.18791v3","title":"LaTeXTrans: Structured LaTeX Translation with Multi-Agent Coordination","authors":["Ziming Zhu","Chenglong Wang","Haosong Xv","Shunjie Xing","Yifu Huo","Fengning Tian","Quan Du","Di Yang","Chunliang Zhang","Tong Xiao","Jingbo Zhu"],"abstract":"Despite the remarkable progress of modern machine translation (MT) systems on general-domain texts, translating structured LaTeX-formatted documents remains a significant challenge. These documents typically interleave natural language with domain-specific syntax, such as mathematical equations, tables, figures, and cross-references, all of which must be accurately preserved to maintain semantic integrity and compilability. In this paper, we introduce LaTeXTrans, a collaborative multi-agent system designed to address this challenge. LaTeXTrans ensures format preservation, structural fidelity, and terminology consistency through six specialized agents: 1) a Parser that decomposes LaTeX into translation-friendly units via placeholder substitution and syntax filtering; 2) a Translator, Validator, Summarizer, and Terminology Extractor that work collaboratively to ensure context-aware, self-correcting, and terminology-consistent translations; 3) a Generator that reconstructs the translated content into well-structured LaTeX documents. Experimental results show that LaTeXTrans outperforms mainstream MT systems in both translation accuracy and structural preservation. The source code, the online demonstration platform, and a demo video are publicly available.","published":"2025-08-26T08:17:26Z","updated":"2026-03-11T02:56:04Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.18791v3","pdf_url":"https://arxiv.org/pdf/2508.18791v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.18684","versioned_id":"2508.18684v2","title":"FALCON: Transforming Cyber Threat Intelligence into Deployable IDS Rules with Self-Reflection","authors":["Shaswata Mitra","Subash Neupane","Martin Duclos","Sudip Mittal","Aritran Piplai","Md Rayhanur Rahman","Edward Zieglar","Shahram Rahimi"],"abstract":"Signature-based Intrusion Detection Systems (IDS) detect malicious activity by matching network or host events against predefined rules. Security analysts manually develop these rules from Cyber Threat Intelligence (CTI). As threats evolve, this manual pipeline faces two bottlenecks. Before authoring a new rule, an analyst must reconcile the incoming CTI with the existing rule base and determine whether to create, update, or retire one. This process is challenging due to the representational differences between the CTI and Rule formats. This gap limits the effectiveness of keyword- and embedding-based search, making rule reconciliation cognitively demanding and, in turn, contributing to \"rule bloat\". Second, automated verification of a new rule is inherently difficult as zero-day threats lack ground truth from simulated testing. Hence, standard metrics cannot prove that a rule semantically adheres to the CTI, and the use of LLMs leads to non-deterministic behavior. To address these challenges, we introduce FALCON, an agentic framework for CTI-grounded rule retrieval, generation, and validation. At its core, a novel CTI-Rule semantic scorer, quantifies the functional alignment between a CTI and a rule; the same signal drives a retriever that surfaces relevant deployed rules and a ground-truth-free validator that scores generated ones. Around it, a generation pipeline produces deployable rules from CTI in real time and refines them through self-reflective syntactic, semantic, and performance validators. Across network (Snort) and host-based (YARA) platforms on a purpose-built CTI-Rule dataset, FALCON attains a mean relevance of 0.72 (approx), with 84% inter-rater agreement among cybersecurity analysts, underscoring the promise of real-time security automation.","published":"2025-08-26T05:08:53Z","updated":"2026-06-23T04:40:30Z","categories":["cs.CR","cs.AI","cs.CL","cs.LG","eess.SY"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2508.18684v2","pdf_url":"https://arxiv.org/pdf/2508.18684v2","comment":"17 pages, 10 figures, 8 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.18132","versioned_id":"2508.18132v1","title":"Test-Time Scaling Strategies for Generative Retrieval in Multimodal Conversational Recommendations","authors":["Hung-Chun Hsu","Yuan-Ching Kuo","Chao-Han Huck Yang","Szu-Wei Fu","Hanrong Ye","Hongxu Yin","Yu-Chiang Frank Wang","Ming-Feng Tsai","Chuan-Ju Wang"],"abstract":"The rapid evolution of e-commerce has exposed the limitations of traditional product retrieval systems in managing complex, multi-turn user interactions. Recent advances in multimodal generative retrieval -- particularly those leveraging multimodal large language models (MLLMs) as retrievers -- have shown promise. However, most existing methods are tailored to single-turn scenarios and struggle to model the evolving intent and iterative nature of multi-turn dialogues when applied naively. Concurrently, test-time scaling has emerged as a powerful paradigm for improving large language model (LLM) performance through iterative inference-time refinement. Yet, its effectiveness typically relies on two conditions: (1) a well-defined problem space (e.g., mathematical reasoning), and (2) the model's ability to self-correct -- conditions that are rarely met in conversational product search. In this setting, user queries are often ambiguous and evolving, and MLLMs alone have difficulty grounding responses in a fixed product corpus. Motivated by these challenges, we propose a novel framework that introduces test-time scaling into conversational multimodal product retrieval. Our approach builds on a generative retriever, further augmented with a test-time reranking (TTR) mechanism that improves retrieval accuracy and better aligns results with evolving user intent throughout the dialogue. Experiments across multiple benchmarks show consistent improvements, with average gains of 14.5 points in MRR and 10.6 points in nDCG@1.","published":"2025-08-25T15:38:56Z","updated":"2025-08-25T15:38:56Z","categories":["cs.IR","cs.AI","cs.LG"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2508.18132v1","pdf_url":"https://arxiv.org/pdf/2508.18132v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.17778","versioned_id":"2508.17778v2","title":"AgentRAN: An Agentic AI Architecture for Autonomous Control of Open 6G Networks","authors":["Maxime Elkael","Salvatore D'Oro","Leonardo Bonati","Michele Polese","Yunseong Lee","Koichiro Furueda","Tommaso Melodia"],"abstract":"Despite the programmable architecture of Open RAN, today's deployments still rely heavily on static control and manual operations. To move beyond this limitation, we introduce AgentRAN, an AI-native, Open RAN-aligned agentic framework that generates and orchestrates a fabric of distributed AI agents based on natural language intents. Unlike traditional approaches that require explicit programming, AgentRAN's LLM-powered agents interpret natural language intents, negotiate strategies through structured conversations, and orchestrate control loops across the network. AgentRAN instantiates a self-organizing hierarchy of agents that decompose complex intents across time scales (from sub-millisecond to minutes), spatial domains (cell to network-wide), and protocol layers (PHY/MAC to RRC). A central innovation is the AI-RAN Factory, which continuously generates improved agents and algorithms from operational data, transforming the network into a system that evolves its own intelligence. We validate AgentRAN through live 5G experiments, demonstrating dynamic adaptation to changing operator intents across power control and scheduling. Key benefits include transparent decision-making (all agent reasoning is auditable), bootstrapped intelligence (no initial training data required), and continuous self-improvement via the AI-RAN Factory.","published":"2025-08-25T08:18:10Z","updated":"2026-02-02T15:26:07Z","categories":["cs.AI","cs.NI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.17778v2","pdf_url":"https://arxiv.org/pdf/2508.17778v2","comment":"This work has been submitted to the IEEE for possible publication","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.17693","versioned_id":"2508.17693v2","title":"Database Normalization via Dual-LLM Self-Refinement","authors":["Eunjae Jo","Nakyung Lee","Gyuyeong Kim"],"abstract":"Database normalization is crucial to preserving data integrity. However, it is time-consuming and error-prone, as it is typically performed manually by data engineers. To this end, we present Miffie, a database normalization framework that leverages the capability of large language models. Miffie enables automated data normalization without human effort while preserving high accuracy. The core of Miffie is a dual-model self-refinement architecture that combines the best-performing models for normalized schema generation and verification, respectively. The generation module eliminates anomalies based on the feedback of the verification module until the output schema satisfies the requirement for normalization. We also carefully design task-specific zero-shot prompts to guide the models for achieving both high accuracy and cost efficiency. Experimental results show that Miffie can normalize complex database schemas while maintaining high accuracy.","published":"2025-08-25T06:02:17Z","updated":"2026-06-05T02:58:28Z","categories":["cs.DB","cs.AI","cs.CL"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2508.17693v2","pdf_url":"https://arxiv.org/pdf/2508.17693v2","comment":"7 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.17565","versioned_id":"2508.17565v1","title":"TradingGroup: A Multi-Agent Trading System with Self-Reflection and Data-Synthesis","authors":["Feng Tian","Flora D. Salim","Hao Xue"],"abstract":"Recent advancements in large language models (LLMs) have enabled powerful agent-based applications in finance, particularly for sentiment analysis, financial report comprehension, and stock forecasting. However, existing systems often lack inter-agent coordination, structured self-reflection, and access to high-quality, domain-specific post-training data such as data from trading activities including both market conditions and agent decisions. These data are crucial for agents to understand the market dynamics, improve the quality of decision-making and promote effective coordination. We introduce TradingGroup, a multi-agent trading system designed to address these limitations through a self-reflective architecture and an end-to-end data-synthesis pipeline. TradingGroup consists of specialized agents for news sentiment analysis, financial report interpretation, stock trend forecasting, trading style adaptation, and a trading decision making agent that merges all signals and style preferences to produce buy, sell or hold decisions. Specifically, we design self-reflection mechanisms for the stock forecasting, style, and decision-making agents to distill past successes and failures for similar reasoning in analogous future scenarios and a dynamic risk-management model to offer configurable dynamic stop-loss and take-profit mechanisms. In addition, TradingGroup embeds an automated data-synthesis and annotation pipeline that generates high-quality post-training data for further improving the agent performance through post-training. Our backtesting experiments across five real-world stock datasets demonstrate TradingGroup's superior performance over rule-based, machine learning, reinforcement learning, and existing LLM-based trading strategies.","published":"2025-08-25T00:29:58Z","updated":"2025-08-25T00:29:58Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.17565v1","pdf_url":"https://arxiv.org/pdf/2508.17565v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.17281","versioned_id":"2508.17281v2","title":"From Language to Action: A Review of Large Language Models as Autonomous Agents and Tool Users","authors":["Sadia Sultana Chowa","Riasad Alvi","Subhey Sadi Rahman","Md Abdur Rahman","Mohaimenul Azam Khan Raiaan","Md Rafiqul Islam","Mukhtar Hussain","Sami Azam"],"abstract":"The pursuit of human-level artificial intelligence (AI) has significantly advanced the development of autonomous agents and Large Language Models (LLMs). LLMs are now widely utilized as decision-making agents for their ability to interpret instructions, manage sequential tasks, and adapt through feedback. This review examines recent developments in employing LLMs as autonomous agents and tool users and comprises seven research questions. We only used the papers published between 2023 and 2025 in conferences of the A* and A rank and Q1 journals. A structured analysis of the LLM agents' architectural design principles, dividing their applications into single-agent and multi-agent systems, and strategies for integrating external tools is presented. In addition, the cognitive mechanisms of LLM, including reasoning, planning, and memory, and the impact of prompting methods and fine-tuning procedures on agent performance are also investigated. Furthermore, we evaluated current benchmarks and assessment protocols and have provided an analysis of 68 publicly available datasets to assess the performance of LLM-based agents in various tasks. In conducting this review, we have identified critical findings on verifiable reasoning of LLMs, the capacity for self-improvement, and the personalization of LLM-based agents. Finally, we have discussed ten future research directions to overcome these gaps.","published":"2025-08-24T10:02:51Z","updated":"2025-10-28T13:52:29Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.17281v2","pdf_url":"https://arxiv.org/pdf/2508.17281v2","comment":"Submitted to Artificial Intelligence Review for peer review","journal_ref":"Artif. Intell. Rev. (2026)","doi":"10.1007/s10462-025-11471-9","discovered_on":"2026-07-17"},{"id":"2508.17184","versioned_id":"2508.17184v2","title":"Towards Alignment-Centric Paradigm: A Survey of Instruction Tuning in Large Language Models","authors":["Xudong Han","Junjie Yang","Tianyang Wang","Ziqian Bi","Xinyuan Song","Junfeng Hao","Junhao Song"],"abstract":"Instruction tuning is a pivotal technique for aligning large language models (LLMs) with human intentions, safety constraints, and domain-specific requirements. This survey provides a comprehensive overview of the full pipeline, encompassing (i) data collection methodologies, (ii) full-parameter and parameter-efficient fine-tuning strategies, and (iii) evaluation protocols. We categorized data construction into three major paradigms: expert annotation, distillation from larger models, and self-improvement mechanisms, each offering distinct trade-offs between quality, scalability, and resource cost. Fine-tuning techniques range from conventional supervised training to lightweight approaches, such as low-rank adaptation (LoRA) and prefix tuning, with a focus on computational efficiency and model reusability. We further examine the challenges of evaluating faithfulness, utility, and safety across multilingual and multimodal scenarios, highlighting the emergence of domain-specific benchmarks in healthcare, legal, and financial applications. Finally, we discuss promising directions for automated data generation, adaptive optimization, and robust evaluation frameworks, arguing that a closer integration of data, algorithms, and human feedback is essential for advancing instruction-tuned LLMs. This survey aims to serve as a practical reference for researchers and practitioners seeking to design LLMs that are both effective and reliably aligned with human intentions.","published":"2025-08-24T01:51:55Z","updated":"2025-11-19T00:10:49Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.17184v2","pdf_url":"https://arxiv.org/pdf/2508.17184v2","comment":"24 pages, 7 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.16456","versioned_id":"2508.16456v1","title":"A Probabilistic Inference Scaling Theory for LLM Self-Correction","authors":["Zhe Yang","Yichang Zhang","Yudong Wang","Ziyao Xu","Junyang Lin","Zhifang Sui"],"abstract":"Large Language Models (LLMs) have demonstrated the capability to refine their generated answers through self-correction, enabling continuous performance improvement over multiple rounds. However, the mechanisms underlying how and why accuracy evolves during this iterative process remain unexplored. To fill this gap, we propose a probabilistic theory to model the dynamics of accuracy change and explain the performance improvements observed in multi-round self-correction. Through mathematical derivation, we establish that the accuracy after the $t^{th}$ round of self-correction is given by: $Acc_t = Upp - α^t(Upp - Acc_0),$ where $Acc_0$ denotes the initial accuracy, $Upp$ represents the upper bound of accuracy convergence, and $α$ determines the rate of convergence. Based on our theory, these parameters can be calculated and the predicted accuracy curve then can be obtained through only a single round of self-correction. Extensive experiments across diverse models and datasets demonstrate that our theoretical predictions align closely with empirical accuracy curves, validating the effectiveness of the theory. Our work provides a theoretical foundation for understanding LLM self-correction, thus paving the way for further explorations.","published":"2025-08-22T15:15:38Z","updated":"2025-08-22T15:15:38Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.16456v1","pdf_url":"https://arxiv.org/pdf/2508.16456v1","comment":"EMNLP 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.15757","versioned_id":"2508.15757v1","title":"Language-Guided Tuning: Enhancing Numeric Optimization with Textual Feedback","authors":["Yuxing Lu","Yucheng Hu","Nan Sun","Xukai Zhao"],"abstract":"Configuration optimization remains a critical bottleneck in machine learning, requiring coordinated tuning across model architecture, training strategy, feature engineering, and hyperparameters. Traditional approaches treat these dimensions independently and lack interpretability, while recent automated methods struggle with dynamic adaptability and semantic reasoning about optimization decisions. We introduce Language-Guided Tuning (LGT), a novel framework that employs multi-agent Large Language Models to intelligently optimize configurations through natural language reasoning. We apply textual gradients - qualitative feedback signals that complement numerical optimization by providing semantic understanding of training dynamics and configuration interdependencies. LGT coordinates three specialized agents: an Advisor that proposes configuration changes, an Evaluator that assesses progress, and an Optimizer that refines the decision-making process, creating a self-improving feedback loop. Through comprehensive evaluation on six diverse datasets, LGT demonstrates substantial improvements over traditional optimization methods, achieving performance gains while maintaining high interpretability.","published":"2025-08-21T17:55:07Z","updated":"2025-08-21T17:55:07Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.15757v1","pdf_url":"https://arxiv.org/pdf/2508.15757v1","comment":"9 pages, 4 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.15648","versioned_id":"2508.15648v2","title":"SDGO: Self-Discrimination-Guided Optimization for Consistent Safety in Large Language Models","authors":["Peng Ding","Wen Sun","Dailin Li","Wei Zou","Jiaming Wang","Jiajun Chen","Shujian Huang"],"abstract":"Large Language Models (LLMs) excel at various natural language processing tasks but remain vulnerable to jailbreaking attacks that induce harmful content generation. In this paper, we reveal a critical safety inconsistency: LLMs can more effectively identify harmful requests as discriminators than defend against them as generators. This insight inspires us to explore aligning the model's inherent discrimination and generation capabilities. To this end, we propose SDGO (Self-Discrimination-Guided Optimization), a reinforcement learning framework that leverages the model's own discrimination capabilities as a reward signal to enhance generation safety through iterative self-improvement. Our method does not require any additional annotated data or external models during the training phase. Extensive experiments demonstrate that SDGO significantly improves model safety compared to both prompt-based and training-based baselines while maintaining helpfulness on general benchmarks. By aligning LLMs' discrimination and generation capabilities, SDGO brings robust performance against out-of-distribution (OOD) jailbreaking attacks. This alignment achieves tighter coupling between these two capabilities, enabling the model's generation capability to be further enhanced with only a small amount of discriminative samples. Our code and datasets are available at https://github.com/NJUNLP/SDGO.","published":"2025-08-21T15:26:09Z","updated":"2025-08-26T06:19:55Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.15648v2","pdf_url":"https://arxiv.org/pdf/2508.15648v2","comment":"Accepted by EMNLP 2025 (Main Conference), 15 pages, 4 figures, 6 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.15501","versioned_id":"2508.15501v1","title":"LLM-Driven Self-Refinement for Embodied Drone Task Planning","authors":["Deyu Zhang","Xicheng Zhang","Jiahao Li","Tingting Long","Xunhua Dai","Yongjian Fu","Jinrui Zhang","Ju Ren","Yaoxue Zhang"],"abstract":"We introduce SRDrone, a novel system designed for self-refinement task planning in industrial-grade embodied drones. SRDrone incorporates two key technical contributions: First, it employs a continuous state evaluation methodology to robustly and accurately determine task outcomes and provide explanatory feedback. This approach supersedes conventional reliance on single-frame final-state assessment for continuous, dynamic drone operations. Second, SRDrone implements a hierarchical Behavior Tree (BT) modification model. This model integrates multi-level BT plan analysis with a constrained strategy space to enable structured reflective learning from experience. Experimental results demonstrate that SRDrone achieves a 44.87% improvement in Success Rate (SR) over baseline methods. Furthermore, real-world deployment utilizing an experience base optimized through iterative self-refinement attains a 96.25% SR. By embedding adaptive task refinement capabilities within an industrial-grade BT planning framework, SRDrone effectively integrates the general reasoning intelligence of Large Language Models (LLMs) with the stringent physical execution constraints inherent to embodied drones. Code is available at https://github.com/ZXiiiC/SRDrone.","published":"2025-08-21T12:29:01Z","updated":"2025-08-21T12:29:01Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2508.15501v1","pdf_url":"https://arxiv.org/pdf/2508.15501v1","comment":"14pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.15144","versioned_id":"2508.15144v2","title":"Mobile-Agent-v3: Fundamental Agents for GUI Automation","authors":["Jiabo Ye","Xi Zhang","Haiyang Xu","Haowei Liu","Junyang Wang","Zhaoqing Zhu","Ziwei Zheng","Feiyu Gao","Junjie Cao","Zhengxi Lu","Jitong Liao","Qi Zheng","Fei Huang","Jingren Zhou","Ming Yan"],"abstract":"This paper introduces GUI-Owl, a foundational GUI agent model that achieves state-of-the-art performance among open-source end-to-end models on ten GUI benchmarks across desktop and mobile environments, covering grounding, question answering, planning, decision-making, and procedural knowledge. GUI-Owl-7B achieves 66.4 on AndroidWorld and 29.4 on OSWorld. Building on this, we propose Mobile-Agent-v3, a general-purpose GUI agent framework that further improves performance to 73.3 on AndroidWorld and 37.7 on OSWorld, setting a new state-of-the-art for open-source GUI agent frameworks. GUI-Owl incorporates three key innovations: (1) Large-scale Environment Infrastructure: a cloud-based virtual environment spanning Android, Ubuntu, macOS, and Windows, enabling our Self-Evolving GUI Trajectory Production framework. This generates high-quality interaction data via automated query generation and correctness validation, leveraging GUI-Owl to refine trajectories iteratively, forming a self-improving loop. It supports diverse data pipelines and reduces manual annotation. (2) Diverse Foundational Agent Capabilities: by integrating UI grounding, planning, action semantics, and reasoning patterns, GUI-Owl supports end-to-end decision-making and can act as a modular component in multi-agent systems. (3) Scalable Environment RL: we develop a scalable reinforcement learning framework with fully asynchronous training for real-world alignment. We also introduce Trajectory-aware Relative Policy Optimization (TRPO) for online RL, achieving 34.9 on OSWorld. GUI-Owl and Mobile-Agent-v3 are open-sourced at https://github.com/X-PLUG/MobileAgent.","published":"2025-08-21T00:39:12Z","updated":"2025-09-01T05:38:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.15144v2","pdf_url":"https://arxiv.org/pdf/2508.15144v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.14029","versioned_id":"2508.14029v4","title":"Beyond Pass@1: Self-Play with Variational Problem Synthesis Sustains RLVR","authors":["Xiao Liang","Zhongzhi Li","Yeyun Gong","Yelong Shen","Ying Nian Wu","Zhijiang Guo","Weizhu Chen"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) has recently emerged as a key paradigm for post-training Large Language Models (LLMs), particularly for complex reasoning tasks. However, vanilla RLVR training has been shown to improve Pass@1 performance at the expense of policy entropy, leading to reduced generation diversity and limiting the Pass@k performance, which typically represents the upper bound of LLM reasoning capability. In this paper, we systematically analyze the policy's generation diversity from the perspective of training problems and find that augmenting and updating training problems helps mitigate entropy collapse during training. Based on these observations, we propose an online Self-play with Variational problem Synthesis (SvS) strategy for RLVR training, which uses the policy's correct solutions to synthesize variational problems while ensuring their reference answers remain identical to the originals. This self-improving strategy effectively maintains policy entropy during training and substantially improves Pass@k compared with standard RLVR, sustaining prolonged improvements and achieving absolute gains of 18.3% and 22.8% in Pass@32 performance on the competition-level AIME24 and AIME25 benchmarks, as well as on code generation tasks. Experiments on 12 reasoning benchmarks across varying model sizes from 3B to 32B consistently demonstrate the generalizability and robustness of SvS.","published":"2025-08-19T17:42:45Z","updated":"2025-12-13T21:58:44Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.14029v4","pdf_url":"https://arxiv.org/pdf/2508.14029v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.13423","versioned_id":"2508.13423v2","title":"AdaptJobRec: Enhancing Conversational Career Recommendation through an LLM-Powered Agentic System","authors":["Qixin Wang","Dawei Wang","Kun Chen","Yaowei Hu","Puneet Girdhar","Ruoteng Wang","Aadesh Gupta","Chaitanya Devella","Wenlai Guo","Shangwen Huang","Bachir Aoun","Greg Hayworth","Han Li","Xintao Wu"],"abstract":"In recent years, recommendation systems have evolved from providing a single list of recommendations to offering a comprehensive suite of topic focused services. To better accomplish this task, conversational recommendation systems (CRS) have progressed from basic retrieval augmented LLM generation to agentic systems with advanced reasoning and self correction capabilities. However, agentic systems come with notable response latency, a longstanding challenge for conversational recommendation systems. To balance the trade off between handling complex queries and minimizing latency, we propose AdaptJobRec, the first conversational job recommendation system that leverages autonomous agent to integrate personalized recommendation algorithm tools. The system employs a user query complexity identification mechanism to minimize response latency. For straightforward queries, the agent directly selects the appropriate tool for rapid responses. For complex queries, the agent uses the memory processing module to filter chat history for relevant content, then passes the results to the intelligent task decomposition planner, and finally executes the tasks using personalized recommendation tools. Evaluation on Walmart's real world career recommendation scenarios demonstrates that AdaptJobRec reduces average response latency by up to 53.3% compared to competitive baselines, while significantly improving recommendation accuracy.","published":"2025-08-19T00:44:25Z","updated":"2025-10-14T07:12:32Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2508.13423v2","pdf_url":"https://arxiv.org/pdf/2508.13423v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.13382","versioned_id":"2508.13382v1","title":"Datarus-R1: An Adaptive Multi-Step Reasoning LLM for Automated Data Analysis","authors":["Ayoub Ben Chaliah","Hela Dellagi"],"abstract":"We present Datarus-R1-14B, a 14 B-parameter open-weights language model fine-tuned from Qwen 2.5-14B-Instruct to act as a virtual data analyst and graduate-level problem solver. Datarus is trained not on isolated question-answer pairs but on full analytical trajectories including reasoning steps, code execution, error traces, self-corrections, and final conclusions, all captured in a ReAct-style notebook format spanning finance, medicine, numerical analysis, and other quantitative domains. Our training pipeline combines (i) a trajectory-centric synthetic data generator that yielded 144 000 tagged notebook episodes, (ii) a dual-reward framework blending a lightweight tag-based structural signal with a Hierarchical Reward Model (HRM) that scores both single-step soundness and end-to-end coherence, and (iii) a memory-optimized implementation of Group Relative Policy Optimization (GRPO) featuring KV-cache reuse, sequential generation, and reference-model sharding. A cosine curriculum smoothly shifts emphasis from structural fidelity to semantic depth, reducing the format collapse and verbosity that often plague RL-aligned LLMs. A central design choice in Datarus is it dual reasoning interface. In agentic mode the model produces ReAct-tagged steps that invoke Python tools to execute real code; in reflection mode it outputs compact Chain-of-Thought (CoT) traces delimited by <think> and <answer> tags. On demanding postgraduate-level problems, Datarus exhibits an \"AHA-moment\" pattern: it sketches hypotheses, revises them once or twice, and converges avoiding the circular, token-inflating loops common to contemporary systems. Across standard public benchmarks Datarus surpasses similar size models and even reaches the level of larger reasoning models such as QwQ-32B achieving up to 30% higher accuracy on AIME 2024/2025 and LiveCodeBench while emitting 18-49% fewer tokens per solution.","published":"2025-08-18T21:58:18Z","updated":"2025-08-18T21:58:18Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.13382v1","pdf_url":"https://arxiv.org/pdf/2508.13382v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.12903","versioned_id":"2508.12903v2","title":"A Stitch in Time Saves Nine: Proactive Self-Refinement for Language Models","authors":["Jinyi Han","Xinyi Wang","Haiquan Zhao","Tingyun li","Zishang Jiang","Sihang Jiang","Jiaqing Liang","Xin Lin","Weikang Zhou","Zeye Sun","Fei Yu","Yanghua Xiao"],"abstract":"Recent advances in self-refinement have demonstrated significant potential for improving the outputs of large language models (LLMs) through iterative refinement. However, most existing self-refinement methods rely on a reactive process with a fixed number of iterations, making it difficult to determine the optimal timing and content of refinement based on the evolving generation context. Inspired by the way humans dynamically refine their thoughts during execution, we propose ProActive Self-Refinement (PASR), a novel method that enables LLMs to refine their outputs during the generation process. Unlike methods that regenerate entire responses, PASR proactively decides whether, when, and how to refine based on the model's internal state and evolving context. We conduct extensive experiments on a diverse set of 10 tasks to evaluate the effectiveness of PASR. Experimental results show that PASR significantly enhances problem-solving performance. In particular, on Qwen3-8B, PASR reduces average token consumption by 41.6% compared to standard generation, while also achieving an 8.2% improvement in accuracy. Our code and baselines used in the paper are available on GitHub.","published":"2025-08-18T13:07:21Z","updated":"2025-10-05T15:00:27Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.12903v2","pdf_url":"https://arxiv.org/pdf/2508.12903v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.11975","versioned_id":"2508.11975v1","title":"Chart-CoCa: Self-Improving Chart Understanding of Vision LMs via Code-Driven Synthesis and Candidate-Conditioned Answering","authors":["Gongyao Jiang","Qiong Luo"],"abstract":"Vision Language Models (VLMs) often struggle with chart understanding tasks, particularly in accurate chart description and complex reasoning. Synthetic data generation is a promising solution, while usually facing the challenge of noise labels. To address this challenge, we first introduce a chart synthesis pipeline that generates aligned chart-question-answer triplets through code generation and execution, ensuring the reliability of synthetic data without human intervention. Furthermore, inspired by test-time scaling that increases inference budget and thereby improves performance, we design a candidate-conditioned answering process. The VLM first generates multiple responses per query, and then synthesizes the final answer by contextualizing these candidates. Experiments demonstrate significant improvements, with up to 15.50 points accuracy gain over the initial VLM, in a fully self-improving paradigm without either human-labeled data or external models.","published":"2025-08-16T08:26:55Z","updated":"2025-08-16T08:26:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.11975v1","pdf_url":"https://arxiv.org/pdf/2508.11975v1","comment":"Accepted to CIKM 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.13201","versioned_id":"2508.13201v3","title":"Benchmarking LLM-based agents for single-cell omics analysis","authors":["Yang Liu","Lu Zhou","Xiawei Du","Ruikun He","Xuguang Zhang","Rongbo Shen","Yixue Li"],"abstract":"Background: The surge in single-cell omics data exposes limitations in traditional, manually defined analysis workflows. AI agents offer a paradigm shift, enabling adaptive planning, executable code generation, traceable decisions, and real-time knowledge fusion. However, the lack of a comprehensive benchmark critically hinders progress. Results: We introduce a novel benchmarking evaluation system to rigorously assess agent capabilities in single-cell omics analysis. This system comprises: a unified platform compatible with diverse agent frameworks and LLMs; multidimensional metrics assessing cognitive program synthesis, collaboration, execution efficiency, bioinformatics knowledge integration, and task completion quality; and 50 diverse real-world single-cell omics analysis tasks spanning multi-omics, species, and sequencing technologies. Our evaluation reveals that Grok3-beta achieves state-of-the-art performance among tested agent frameworks. Multi-agent frameworks significantly enhance collaboration and execution efficiency over single-agent approaches through specialized role division. Attribution analyses of agent capabilities identify that high-quality code generation is crucial for task success, and self-reflection has the most significant overall impact, followed by retrieval-augmented generation (RAG) and planning. Conclusions: This work highlights persistent challenges in code generation, long-context handling, and context-aware knowledge retrieval, providing a critical empirical foundation and best practices for developing robust AI agents in computational biology.","published":"2025-08-16T04:26:18Z","updated":"2026-03-16T09:24:30Z","categories":["q-bio.GN","cs.AI","cs.MA"],"primary_category":"q-bio.GN","arxiv_url":"https://arxiv.org/abs/2508.13201v3","pdf_url":"https://arxiv.org/pdf/2508.13201v3","comment":"please see clear figures in this version. 6 main figures; 13 supplementary figures","journal_ref":"","doi":"10.1186/s13059-026-03998-z","discovered_on":"2026-07-17"},{"id":"2508.10428","versioned_id":"2508.10428v1","title":"SC2Arena and StarEvolve: Benchmark and Self-Improvement Framework for LLMs in Complex Decision-Making Tasks","authors":["Pengbo Shen","Yaqing Wang","Ni Mu","Yao Luan","Runpeng Xie","Senhao Yang","Lexiang Wang","Hao Hu","Shuang Xu","Yiqin Yang","Bo Xu"],"abstract":"Evaluating large language models (LLMs) in complex decision-making is essential for advancing AI's ability for strategic planning and real-time adaptation. However, existing benchmarks for tasks like StarCraft II fail to capture the game's full complexity, such as its complete game context, diverse action spaces, and all playable races. To address this gap, we present SC2Arena, a benchmark that fully supports all playable races, low-level action spaces, and optimizes text-based observations to tackle spatial reasoning challenges. Complementing this, we introduce StarEvolve, a hierarchical framework that integrates strategic planning with tactical execution, featuring iterative self-correction and continuous improvement via fine-tuning on high-quality gameplay data. Its key components include a Planner-Executor-Verifier structure to break down gameplay, and a scoring system for selecting high-quality training samples. Comprehensive analysis using SC2Arena provides valuable insights into developing generalist agents that were not possible with previous benchmarks. Experimental results also demonstrate that our proposed StarEvolve achieves superior performance in strategic planning. Our code, environment, and algorithms are publicly available.","published":"2025-08-14T07:58:01Z","updated":"2025-08-14T07:58:01Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.10428v1","pdf_url":"https://arxiv.org/pdf/2508.10428v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.10416","versioned_id":"2508.10416v1","title":"CorrectNav: Self-Correction Flywheel Empowers Vision-Language-Action Navigation Model","authors":["Zhuoyuan Yu","Yuxing Long","Zihan Yang","Chengyan Zeng","Hongwei Fan","Jiyao Zhang","Hao Dong"],"abstract":"Existing vision-and-language navigation models often deviate from the correct trajectory when executing instructions. However, these models lack effective error correction capability, hindering their recovery from errors. To address this challenge, we propose Self-correction Flywheel, a novel post-training paradigm. Instead of considering the model's error trajectories on the training set as a drawback, our paradigm emphasizes their significance as a valuable data source. We have developed a method to identify deviations in these error trajectories and devised innovative techniques to automatically generate self-correction data for perception and action. These self-correction data serve as fuel to power the model's continued training. The brilliance of our paradigm is revealed when we re-evaluate the model on the training set, uncovering new error trajectories. At this time, the self-correction flywheel begins to spin. Through multiple flywheel iterations, we progressively enhance our monocular RGB-based VLA navigation model CorrectNav. Experiments on R2R-CE and RxR-CE benchmarks show CorrectNav achieves new state-of-the-art success rates of 65.1% and 69.3%, surpassing prior best VLA navigation models by 8.2% and 16.4%. Real robot tests in various indoor and outdoor environments demonstrate \\method's superior capability of error correction, dynamic obstacle avoidance, and long instruction following.","published":"2025-08-14T07:39:26Z","updated":"2025-08-14T07:39:26Z","categories":["cs.RO","cs.AI","cs.CL","cs.CV"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2508.10416v1","pdf_url":"https://arxiv.org/pdf/2508.10416v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.15805","versioned_id":"2508.15805v1","title":"ALAS: Autonomous Learning Agent for Self-Updating Language Models","authors":["Dhruv Atreja"],"abstract":"Large language models (LLMs) often have a fixed knowledge cutoff, limiting their accuracy on emerging information. We present ALAS (Autonomous Learning Agent System), a modular pipeline that continuously updates an LLM's knowledge with minimal human intervention. ALAS autonomously generates a learning curriculum for a target domain, retrieves up-to-date information from the web (with citations), distills this into question-answer training data, and fine-tunes the model through supervised fine-tuning (SFT) and direct preference optimization (DPO). It iteratively evaluates performance and revises the curriculum, enabling long-term continual learning. We demonstrate ALAS's ability to self-improve a model on rapidly evolving domains (e.g., new Python releases, latest security CVEs, academic trends), significantly boosting post-cutoff question answering accuracy (from 15% to 90% on average) without manual dataset curation. The system emphasizes modularity and reproducibility: each component (planning, retrieval, distillation, memory, fine-tuning) is interchangeable and built on standard APIs. We discuss comparative baselines (e.g., retrieval-augmented generation vs. fine-tuning) and show that ALAS achieves 90% accuracy on knowledge-updated queries with minimal engineering overhead. Finally, we outline limitations (cost, dependency on source quality) and future directions for autonomous lifelong learning in LLMs.","published":"2025-08-14T06:55:51Z","updated":"2025-08-14T06:55:51Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.15805v1","pdf_url":"https://arxiv.org/pdf/2508.15805v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.09486","versioned_id":"2508.09486v2","title":"Video-EM: Event-Centric Episodic Memory for Long-Form Video Understanding","authors":["Yun Wang","Long Zhang","Jingren Liu","Jiaqi Yan","Zhanjie Zhang","Jiahao Zheng","Ao Ma","Run Ling","Xun Yang","Dapeng Wu","Xiangyu Chen","Xuelong Li"],"abstract":"Video Large Language Models (Video-LLMs) have shown strong video understanding, yet their application to long-form videos remains constrained by limited context windows. A common workaround is to compress long videos into a handful of representative frames via retrieval or summarization. However, most existing pipelines score frames in isolation, implicitly assuming that frame-level saliency is sufficient for downstream reasoning. This often yields redundant selections, fragmented temporal evidence, and weakened narrative grounding for long-form video question answering. We present \\textbf{Video-EM}, a training-free, event-centric episodic memory framework that reframes long-form VideoQA as \\emph{episodic event construction} followed by \\emph{memory refinement}. Instead of treating retrieved keyframes as independent visuals, Video-EM employs an LLM as an active memory agent to orchestrate off-the-shelf tools: it first localizes query-relevant moments via multi-grained semantic matching, then groups and segments them into temporally coherent events, and finally encodes each event as a grounded episodic memory with explicit temporal indices and spatio-temporal cues (capturing \\emph{when}, \\emph{where}, \\emph{what}, and involved entities). To further suppress verbosity and noise from imperfect upstream signals, Video-EM integrates a reasoning-driven self-reflection loop that iteratively verifies evidence sufficiency and cross-event consistency, removes redundancy, and adaptively adjusts event granularity. The outcome is a compact yet reliable \\emph{event timeline} -- a minimal but sufficient episodic memory set that can be directly consumed by existing Video-LLMs without additional training or architectural changes.","published":"2025-08-13T04:33:07Z","updated":"2026-03-07T07:00:02Z","categories":["cs.CV","cs.AI","cs.MM"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2508.09486v2","pdf_url":"https://arxiv.org/pdf/2508.09486v2","comment":"14 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.08719","versioned_id":"2508.08719v2","title":"IROTE: Human-like Traits Elicitation of Large Language Model via In-Context Self-Reflective Optimization","authors":["Yuzhuo Bai","Shitong Duan","Muhua Huang","Jing Yao","Zhenghao Liu","Peng Zhang","Tun Lu","Xiaoyuan Yi","Maosong Sun","Xing Xie"],"abstract":"Trained on various human-authored corpora, Large Language Models (LLMs) have demonstrated a certain capability of reflecting specific human-like traits (e.g., personality or values) by prompting, benefiting applications like personalized LLMs and social simulations. However, existing methods suffer from the superficial elicitation problem: LLMs can only be steered to mimic shallow and unstable stylistic patterns, failing to embody the desired traits precisely and consistently across diverse tasks like humans. To address this challenge, we propose IROTE, a novel in-context method for stable and transferable trait elicitation. Drawing on psychological theories suggesting that traits are formed through identity-related reflection, our method automatically generates and optimizes a textual self-reflection within prompts, which comprises self-perceived experience, to stimulate LLMs' trait-driven behavior. The optimization is performed by iteratively maximizing an information-theoretic objective that enhances the connections between LLMs' behavior and the target trait, while reducing noisy redundancy in reflection without any fine-tuning, leading to evocative and compact trait reflection. Extensive experiments across three human trait systems manifest that one single IROTE-generated self-reflection can induce LLMs' stable impersonation of the target trait across diverse downstream tasks beyond simple questionnaire answering, consistently outperforming existing strong baselines.","published":"2025-08-12T08:04:28Z","updated":"2025-11-27T12:38:51Z","categories":["cs.CL","cs.AI","cs.CY"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.08719v2","pdf_url":"https://arxiv.org/pdf/2508.08719v2","comment":"This paper is accepted by AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.15790","versioned_id":"2508.15790v1","title":"KG-o1: Enhancing Multi-hop Question Answering in Large Language Models via Knowledge Graph Integration","authors":["Nan Wang","Yongqi Fan","yansha zhu","ZongYu Wang","Xuezhi Cao","Xinyan He","Haiyun Jiang","Tong Ruan","Jingping Liu"],"abstract":"Large Language Models (LLMs) face challenges in knowledge-intensive reasoning tasks like classic multi-hop question and answering, which involves reasoning across multiple facts. This difficulty arises because the chain of thoughts (CoTs) generated by LLMs in such tasks often deviate from real or a priori reasoning paths. In contrast, knowledge graphs (KGs) explicitly represent the logical connections between facts through entities and relationships. This reflects a significant gap. Meanwhile, large reasoning models (LRMs), such as o1, have demonstrated that long-step reasoning significantly enhances the performance of LLMs. Building on these insights, we propose KG-o1, a four-stage approach that integrates KGs to enhance the multi-hop reasoning abilities of LLMs. We first filter out initial entities and generate complex subgraphs. Secondly, we construct logical paths for subgraphs and then use knowledge graphs to build a dataset with a complex and extended brainstorming process, which trains LLMs to imitate long-term reasoning. Finally, we employ rejection sampling to generate a self-improving corpus for direct preference optimization (DPO), further refining the LLMs reasoning abilities. We conducted experiments on two simple and two complex datasets. The results show that KG-o1 models exhibit superior performance across all tasks compared to existing LRMs.","published":"2025-08-12T04:29:10Z","updated":"2025-08-12T04:29:10Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.15790v1","pdf_url":"https://arxiv.org/pdf/2508.15790v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.07616","versioned_id":"2508.07616v2","title":"ThinkTuning: Instilling Cognitive Reflections without Distillation","authors":["Aswin RRV","Jacob Dineen","Divij Handa","Md Nayem Uddin","Mihir Parmar","Chitta Baral","Ben Zhou"],"abstract":"Recent advances in test-time scaling have led to the emergence of thinking LLMs that exhibit self-reflective behaviors and multi-step reasoning. While RL drives this self-improvement paradigm, a recent study (Gandhi et al., 2025) shows that RL alone does not truly instill these new reasoning abilities - it merely draws out behaviors already present in the base models. This raises a question: How can we train the models that don't exhibit such thinking behavior to develop it in the first place? To this end, we propose ThinkTuning, a GRPO-based interactive training approach where we augment the rollouts of a student model with the guidance from a teacher model. A simple idea from classroom practice inspires our method: a teacher poses a problem, lets the student try an answer, then gives corrective feedback -- enough to point the mind in the right direction and then show the solution. Each piece of feedback reshapes the student's thoughts, leading them to arrive at the correct solution. Similarly, we find that this type of implicit supervision through feedback from a teacher model of the same size improves the reasoning capabilities of the student model. In particular, on average, our method shows a 3.85% improvement over zero-shot baselines across benchmarks, and on MATH-500, AIME and GPQA-Diamond it shows 2.08%, 2.23% and 3.99% improvements over the vanilla-GRPO baseline. Source code is available at https://github.com/3rdAT/ThinkTuning.","published":"2025-08-11T04:51:43Z","updated":"2025-08-21T06:17:25Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.07616v2","pdf_url":"https://arxiv.org/pdf/2508.07616v2","comment":"EMNLP 2025 (Main Conference)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.07382","versioned_id":"2508.07382v2","title":"Pentest-R1: Towards Autonomous Penetration Testing Reasoning Optimized via Two-Stage Reinforcement Learning","authors":["He Kong","Die Hu","Jingguo Ge","Liangxiong Li","Hui Li","Tong Li"],"abstract":"Automating penetration testing is crucial for enhancing cybersecurity, yet current Large Language Models (LLMs) face significant limitations in this domain, including poor error handling, inefficient reasoning, and an inability to perform complex end-to-end tasks autonomously. To address these challenges, we introduce Pentest-R1, a novel framework designed to optimize LLM reasoning capabilities for this task through a two-stage reinforcement learning pipeline. We first construct a dataset of over 500 real-world, multi-step walkthroughs, which Pentest-R1 leverages for offline reinforcement learning (RL) to instill foundational attack logic. Subsequently, the LLM is fine-tuned via online RL in an interactive Capture The Flag (CTF) environment, where it learns directly from environmental feedback to develop robust error self-correction and adaptive strategies. Our extensive experiments on the Cybench and AutoPenBench benchmarks demonstrate the framework's effectiveness. On AutoPenBench, Pentest-R1 achieves a 24.2\\% success rate, surpassing most state-of-the-art models and ranking second only to Gemini 2.5 Flash. On Cybench, it attains a 15.0\\% success rate in unguided tasks, establishing a new state-of-the-art for open-source LLMs and matching the performance of top proprietary models. Ablation studies confirm that the synergy of both training stages is critical to its success.","published":"2025-08-10T15:14:05Z","updated":"2025-10-29T05:49:56Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.07382v2","pdf_url":"https://arxiv.org/pdf/2508.07382v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.11684","versioned_id":"2508.11684v1","title":"A Graph Neural Network based on a Functional Topology Model: Unveiling the Dynamic Mechanisms of Non-Suicidal Self-Injury in Single-Channel EEG","authors":["BG Tong"],"abstract":"Objective: This study proposes and preliminarily validates a novel \"Functional-Energetic Topology Model\" to uncover neurodynamic mechanisms of Non-Suicidal Self-Injury (NSSI), using Graph Neural Networks (GNNs) to decode brain network patterns from single-channel EEG in real-world settings.Methods: EEG data were collected over ~1 month from three adolescents with NSSI using a smartphone app and a portable Fp1 EEG headband during impulsive and non-impulsive states. A theory-driven GNN with seven functional nodes was built. Performance was evaluated via intra-subject (80/20 split) and leave-one-subject-out cross-validation (LOSOCV). GNNExplainer was used for interpretability.Results: The model achieved high intra-subject accuracy (>85%) and significantly above-chance cross-subject performance (approximately73.7%). Explainability analysis revealed a key finding: during NSSI states, a critical feedback loop regulating somatic sensation exhibits dysfunction and directional reversal. Specifically, the brain loses its ability to self-correct via negative bodily feedback, and the regulatory mechanism enters an \"ineffective idling\" state.Conclusion: This work demonstrates the feasibility of applying theory-guided GNNs to sparse, single-channel EEG for decoding complex mental states. The identified \"feedback loop reversal\" offers a novel, dynamic, and computable model of NSSI mechanisms, paving the way for objective biomarkers and next-generation Digital Therapeutics (DTx).","published":"2025-08-10T03:30:09Z","updated":"2025-08-10T03:30:09Z","categories":["eess.SP","cs.LG","q-bio.NC"],"primary_category":"eess.SP","arxiv_url":"https://arxiv.org/abs/2508.11684v1","pdf_url":"https://arxiv.org/pdf/2508.11684v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.07107","versioned_id":"2508.07107v2","title":"Designing a Feedback-Driven Decision Support System for Dynamic Student Intervention","authors":["Timothy Oluwapelumi Adeyemi","Nadiah Fahad AlOtaibi"],"abstract":"Accurate prediction of student performance is essential for enabling timely academic interventions. However, most machine learning models used in educational settings are static and lack the ability to adapt when new data such as post-intervention outcomes become available. To address this limitation, we propose a Feedback-Driven Decision Support System (DSS) with a closed-loop architecture that enables continuous model refinement. The system employs a LightGBM-based regressor with incremental retraining, allowing educators to input updated student performance data, which automatically triggers model updates. This adaptive mechanism enhances prediction accuracy by learning from real-world academic progress over time. The platform features a Flask-based web interface to support real-time interaction and integrates SHAP (SHapley Additive exPlanations) for model interpretability, ensuring transparency and trustworthiness in predictions. Experimental results demonstrate a 10.7% reduction in RMSE after retraining, with consistent upward adjustments in predicted scores for students who received interventions. By transforming static predictive models into self-improving systems, our approach advances educational analytics toward human-centered, data-driven, and responsive artificial intelligence. The framework is designed for seamless integration into Learning Management Systems (LMS) and institutional dashboards, facilitating practical deployment in real educational environments.","published":"2025-08-09T21:24:54Z","updated":"2025-08-12T10:20:46Z","categories":["cs.AI","cs.CY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.07107v2","pdf_url":"https://arxiv.org/pdf/2508.07107v2","comment":"10 pages, 1 figure, 3 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.06960","versioned_id":"2508.06960v1","title":"DatasetResearch: Benchmarking Agent Systems for Demand-Driven Dataset Discovery","authors":["Keyu Li","Mohan Jiang","Dayuan Fu","Yunze Wu","Xiangkun Hu","Dequan Wang","Pengfei Liu"],"abstract":"The rapid advancement of large language models has fundamentally shifted the bottleneck in AI development from computational power to data availability-with countless valuable datasets remaining hidden across specialized repositories, research appendices, and domain platforms. As reasoning capabilities and deep research methodologies continue to evolve, a critical question emerges: can AI agents transcend conventional search to systematically discover any dataset that meets specific user requirements, enabling truly autonomous demand-driven data curation? We introduce DatasetResearch, the first comprehensive benchmark evaluating AI agents' ability to discover and synthesize datasets from 208 real-world demands across knowledge-intensive and reasoning-intensive tasks. Our tri-dimensional evaluation framework reveals a stark reality: even advanced deep research systems achieve only 22% score on our challenging DatasetResearch-pro subset, exposing the vast gap between current capabilities and perfect dataset discovery. Our analysis uncovers a fundamental dichotomy-search agents excel at knowledge tasks through retrieval breadth, while synthesis agents dominate reasoning challenges via structured generation-yet both catastrophically fail on \"corner cases\" outside existing distributions. These findings establish the first rigorous baseline for dataset discovery agents and illuminate the path toward AI systems capable of finding any dataset in the digital universe. Our benchmark and comprehensive analysis provide the foundation for the next generation of self-improving AI systems and are publicly available at https://github.com/GAIR-NLP/DatasetResearch.","published":"2025-08-09T12:15:08Z","updated":"2025-08-09T12:15:08Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.06960v1","pdf_url":"https://arxiv.org/pdf/2508.06960v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.06178","versioned_id":"2508.06178v1","title":"Comparing Knowledge Injection Methods for LLMs in a Low-Resource Regime","authors":["Hugo Abonizio","Thales Almeida","Roberto Lotufo","Rodrigo Nogueira"],"abstract":"Large language models (LLMs) often require vast amounts of text to effectively acquire new knowledge. While continuing pre-training on large corpora or employing retrieval-augmented generation (RAG) has proven successful, updating an LLM with only a few thousand or million tokens remains challenging. In this work, we investigate the task of injecting small, unstructured information into LLMs and its relation to the catastrophic forgetting phenomenon. We use a dataset of recent news -- ensuring no overlap with the model's pre-training data -- to evaluate the knowledge acquisition by probing the model with question-answer pairs related the learned information. Starting from a continued pre-training baseline, we explored different augmentation algorithms to generate synthetic data to improve the knowledge acquisition capabilities. Our experiments show that simply continuing pre-training on limited data yields modest improvements, whereas exposing the model to diverse textual variations significantly improves the learning of new facts -- particularly with methods that induce greater variability through diverse prompting. Furthermore, we shed light on the forgetting phenomenon in small-data regimes, illustrating the delicate balance between learning new content and retaining existing capabilities. We also confirm the sensitivity of RAG-based approaches for knowledge injection, which often lead to greater degradation on control datasets compared to parametric methods. Finally, we demonstrate that models can generate effective synthetic training data themselves, suggesting a pathway toward self-improving model updates. All code and generated data used in our experiments are publicly available, providing a resource for studying efficient knowledge injection in LLMs with limited data at https://github.com/hugoabonizio/knowledge-injection-methods.","published":"2025-08-08T09:48:32Z","updated":"2025-08-08T09:48:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.06178v1","pdf_url":"https://arxiv.org/pdf/2508.06178v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.06094","versioned_id":"2508.06094v4","title":"ConlangCrafter: Constructing Languages with a Multi-Hop LLM Pipeline","authors":["Morris Alper","Moran Yanuka","Raja Giryes","Gašper Beguš"],"abstract":"Constructed languages (conlangs) such as Esperanto and Quenya have played diverse roles in art, philosophy, and international communication. Meanwhile, foundation models have revolutionized creative generation in text, images, and beyond. In this work, we leverage modern LLMs as computational creativity aids for end-to-end conlang creation. We introduce ConlangCrafter, a multi-hop pipeline that decomposes language design into modular stages -- phonology, morphology, syntax, lexicon generation, and translation. At each stage, our method leverages LLMs' metalinguistic reasoning capabilities, injecting randomness to encourage diversity and leveraging self-refinement feedback to encourage consistency in the emerging language description. We construct a novel, scalable evaluation framework for this task, evaluating metrics measuring consistency and typological diversity. Automatic and manual evaluations demonstrate ConlangCrafter's ability to produce coherent and varied conlangs without human linguistic expertise.","published":"2025-08-08T07:36:48Z","updated":"2026-04-17T16:51:16Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.06094v4","pdf_url":"https://arxiv.org/pdf/2508.06094v4","comment":"Accepted to ACL 2026. Project page: https://conlangcrafter.github.io","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.05996","versioned_id":"2508.05996v2","title":"Mediator-Guided Multi-Agent Collaboration among Open-Source Models for Medical Decision-Making","authors":["Kaitao Chen","Mianxin Liu","Daoming Zong","Chaoyue Ding","Shaohao Rui","Yankai Jiang","Mu Zhou","Xiaosong Wang"],"abstract":"Complex medical decision-making involves cooperative workflows operated by different clinicians. Designing AI multi-agent systems can expedite and augment human-level clinical decision-making. Existing multi-agent researches primarily focus on language-only tasks, yet their extension to multimodal scenarios remains challenging. A blind combination of diverse vision-language models (VLMs) can amplify an erroneous outcome interpretation. VLMs in general are less capable in instruction following and importantly self-reflection, compared to large language models (LLMs) of comparable sizes. This disparity largely constrains VLMs' ability in cooperative workflows. In this study, we propose MedOrch, a mediator-guided multi-agent collaboration framework for medical multimodal decision-making. MedOrch employs an LLM-based mediator agent that enables multiple VLM-based expert agents to exchange and reflect on their outputs towards collaboration. We utilize multiple open-source general-purpose and domain-specific VLMs instead of costly GPT-series models, revealing the strength of heterogeneous models. We show that the collaboration within distinct VLM-based agents can surpass the capabilities of any individual agent. We validate our approach on five medical vision question answering benchmarks, demonstrating superior collaboration performance without model training. Our findings underscore the value of mediator-guided multi-agent collaboration in advancing medical multimodal intelligence.","published":"2025-08-08T04:02:10Z","updated":"2025-10-11T07:01:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.05996v2","pdf_url":"https://arxiv.org/pdf/2508.05996v2","comment":"14 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.05366","versioned_id":"2508.05366v1","title":"Can Language Models Critique Themselves? Investigating Self-Feedback for Retrieval Augmented Generation at BioASQ 2025","authors":["Samy Ateia","Udo Kruschwitz"],"abstract":"Agentic Retrieval Augmented Generation (RAG) and 'deep research' systems aim to enable autonomous search processes where Large Language Models (LLMs) iteratively refine outputs. However, applying these systems to domain-specific professional search, such as biomedical research, presents challenges, as automated systems may reduce user involvement and misalign with expert information needs. Professional search tasks often demand high levels of user expertise and transparency. The BioASQ CLEF 2025 challenge, using expert-formulated questions, can serve as a platform to study these issues. We explored the performance of current reasoning and nonreasoning LLMs like Gemini-Flash 2.0, o3-mini, o4-mini and DeepSeek-R1. A key aspect of our methodology was a self-feedback mechanism where LLMs generated, evaluated, and then refined their outputs for query expansion and for multiple answer types (yes/no, factoid, list, ideal). We investigated whether this iterative self-correction improves performance and if reasoning models are more capable of generating useful feedback. Preliminary results indicate varied performance for the self-feedback strategy across models and tasks. This work offers insights into LLM self-correction and informs future work on comparing the effectiveness of LLM-generated feedback with direct human expert input in these search systems.","published":"2025-08-07T13:13:19Z","updated":"2025-08-07T13:13:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.05366v1","pdf_url":"https://arxiv.org/pdf/2508.05366v1","comment":"Version as accepted at the BioASQ Lab at CLEF 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.05283","versioned_id":"2508.05283v2","title":"Decision-Making with Deliberation: Meta-reviewing as a Document-grounded Dialogue","authors":["Sukannya Purkayastha","Nils Dycke","Anne Lauscher","Iryna Gurevych"],"abstract":"Meta-reviewing is a pivotal stage in the peer-review process, serving as the final step in determining whether a paper is recommended for acceptance. Prior research on meta-reviewing has treated this as a summarization problem over review reports. However, complementary to this perspective, meta-reviewing is a decision-making process that requires weighing reviewer arguments and placing them within a broader context. Prior research has demonstrated that decision-makers can be effectively assisted in such scenarios via dialogue agents. In line with this framing, we explore the practical challenges for realizing dialog agents that can effectively assist meta-reviewers. Concretely, we first address the issue of data scarcity for training dialogue agents by generating synthetic data using Large Language Models (LLMs) based on a self-refinement strategy to improve the relevance of these dialogues to expert domains. Our experiments demonstrate that this method produces higher-quality synthetic data and can serve as a valuable resource towards training meta-reviewing assistants. Subsequently, we utilize this data to train dialogue agents tailored for meta-reviewing and find that these agents outperform \\emph{off-the-shelf} LLM-based assistants for this task. Finally, we apply our agents in real-world meta-reviewing scenarios and confirm their effectiveness in enhancing the efficiency of meta-reviewing.\\footnote{Code available at: https://github.com/UKPLab/eacl2026-meta-review-as-dialog","published":"2025-08-07T11:27:43Z","updated":"2026-01-21T12:46:28Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.05283v2","pdf_url":"https://arxiv.org/pdf/2508.05283v2","comment":"Accepted at EACL Main Conference, 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.05282","versioned_id":"2508.05282v5","title":"Not All Errors Are Created Equal: ASCoT Addresses Late-Stage Fragility in Efficient LLM Reasoning","authors":["Dongxu Zhang","Yujun Wu","Yiding Sun","Jinnan Yang","Ning Yang","Jihua Zhu","Miao Xin","Baoliang Tian"],"abstract":"While Chain-of-Thought (CoT) prompting empowers Large Language Models (LLMs), ensuring reasoning reliability remains an open challenge. Contrary to the prevailing cascading failure hypothesis which posits that early errors are most detrimental, we identify a counter-intuitive phenomenon termed \\textbf{Late-Stage Fragility}: errors introduced in later reasoning stages are significantly more prone to corrupting final answers. To address this, we introduce ASCoT (Adaptive Self-Correction Chain-of-Thought), a method harmonizing efficiency with robust verification. ASCoT first employs semantic pruning to compress redundant steps, then utilizes an Adaptive Verification Manager (AVM) to prioritize high risk, late-stage steps via a positional impact score, triggering a Multi-Perspective Self-Correction Engine (MSCE) only when necessary. Experiments on GSM8K and MATH-500 demonstrate that ASCoT effectively reallocates computational resources: it reduces token usage by 21\\%--30\\% for LLaMA-3.1-8B with negligible accuracy drops ($<1.8\\%$), achieving a superior trade-off between inference efficiency and reasoning fidelity.","published":"2025-08-07T11:26:40Z","updated":"2026-03-03T12:30:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.05282v5","pdf_url":"https://arxiv.org/pdf/2508.05282v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.05011","versioned_id":"2508.05011v1","title":"Towards Hallucination-Free Music: A Reinforcement Learning Preference Optimization Framework for Reliable Song Generation","authors":["Huaicheng Zhang","Wei Tan","Guangzheng Li","Yixuan Zhang","Hangting Chen","Shun Lei","Chenyu Yang","Zhiyong Wu","Shuai Wang","Qijun Huang","Dong Yu"],"abstract":"Recent advances in audio-based generative language models have accelerated AI-driven lyric-to-song generation. However, these models frequently suffer from content hallucination, producing outputs misaligned with the input lyrics and undermining musical coherence. Current supervised fine-tuning (SFT) approaches, limited by passive label-fitting, exhibit constrained self-improvement and poor hallucination mitigation. To address this core challenge, we propose a novel reinforcement learning (RL) framework leveraging preference optimization for hallucination control. Our key contributions include: (1) Developing a robust hallucination preference dataset constructed via phoneme error rate (PER) computation and rule-based filtering to capture alignment with human expectations; (2) Implementing and evaluating three distinct preference optimization strategies within the RL framework: Direct Preference Optimization (DPO), Proximal Policy Optimization (PPO), and Group Relative Policy Optimization (GRPO). DPO operates off-policy to enhance positive token likelihood, achieving a significant 7.4% PER reduction. PPO and GRPO employ an on-policy approach, training a PER-based reward model to iteratively optimize sequences via reward maximization and KL-regularization, yielding PER reductions of 4.9% and 4.7%, respectively. Comprehensive objective and subjective evaluations confirm that our methods effectively suppress hallucinations while preserving musical quality. Crucially, this work presents a systematic, RL-based solution to hallucination control in lyric-to-song generation. The framework's transferability also unlocks potential for music style adherence and musicality enhancement, opening new avenues for future generative song research.","published":"2025-08-07T03:49:18Z","updated":"2025-08-07T03:49:18Z","categories":["cs.SD","cs.AI","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2508.05011v1","pdf_url":"https://arxiv.org/pdf/2508.05011v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.05004","versioned_id":"2508.05004v4","title":"R-Zero: Self-Evolving Reasoning LLM from Zero Data","authors":["Chengsong Huang","Wenhao Yu","Xiaoyang Wang","Hongming Zhang","Zongxia Li","Ruosen Li","Jiaxin Huang","Haitao Mi","Dong Yu"],"abstract":"Self-evolving Large Language Models (LLMs) offer a scalable path toward super-intelligence by autonomously generating, refining, and learning from their own experiences. However, existing methods for training such models still rely heavily on vast human-curated tasks and labels, typically via fine-tuning or reinforcement learning, which poses a fundamental bottleneck to advancing AI systems toward capabilities beyond human intelligence. To overcome this limitation, we introduce R-Zero, a fully autonomous framework that generates its own training data from scratch. Starting from a single base LLM, R-Zero initializes two independent models with distinct roles, a Challenger and a Solver. These models are optimized separately and co-evolve through interaction: the Challenger is rewarded for proposing tasks near the edge of the Solver capability, and the Solver is rewarded for solving increasingly challenging tasks posed by the Challenger. This process yields a targeted, self-improving curriculum without any pre-existing tasks and labels. Empirically, R-Zero substantially improves reasoning capability across different backbone LLMs, e.g., boosting the Qwen3-4B-Base by +6.49 on math-reasoning benchmarks and +7.54 on general-domain reasoning benchmarks.","published":"2025-08-07T03:38:16Z","updated":"2026-02-13T18:53:32Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.05004v4","pdf_url":"https://arxiv.org/pdf/2508.05004v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.04825","versioned_id":"2508.04825v2","title":"Voost: A Unified and Scalable Diffusion Transformer for Bidirectional Virtual Try-On and Try-Off","authors":["Seungyong Lee","Jeong-gi Kwak"],"abstract":"Virtual try-on aims to synthesize a realistic image of a person wearing a target garment, but accurately modeling garment-body correspondence remains a persistent challenge, especially under pose and appearance variation. In this paper, we propose Voost - a unified and scalable framework that jointly learns virtual try-on and try-off with a single diffusion transformer. By modeling both tasks jointly, Voost enables each garment-person pair to supervise both directions and supports flexible conditioning over generation direction and garment category, enhancing garment-body relational reasoning without task-specific networks, auxiliary losses, or additional labels. In addition, we introduce two inference-time techniques: attention temperature scaling for robustness to resolution or mask variation, and self-corrective sampling that leverages bidirectional consistency between tasks. Extensive experiments demonstrate that Voost achieves state-of-the-art results on both try-on and try-off benchmarks, consistently outperforming strong baselines in alignment accuracy, visual fidelity, and generalization.","published":"2025-08-06T19:10:58Z","updated":"2025-11-05T18:23:44Z","categories":["cs.GR","cs.AI","cs.CV","cs.LG"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2508.04825v2","pdf_url":"https://arxiv.org/pdf/2508.04825v2","comment":"Accepted to SIGGRAPH Asia 2025, project page: https://nxnai.github.io/Voost/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.04495","versioned_id":"2508.04495v2","title":"Causal Reflection with Language Models","authors":["Abi Aryan","Zac Liu"],"abstract":"While LLMs exhibit impressive fluency and factual recall, they struggle with robust causal reasoning, often relying on spurious correlations and brittle patterns. Similarly, traditional Reinforcement Learning agents also lack causal understanding, optimizing for rewards without modeling why actions lead to outcomes. We introduce Causal Reflection, a framework that explicitly models causality as a dynamic function over state, action, time, and perturbation, enabling agents to reason about delayed and nonlinear effects. Additionally, we define a formal Reflect mechanism that identifies mismatches between predicted and observed outcomes and generates causal hypotheses to revise the agent's internal model. In this architecture, LLMs serve not as black-box reasoners, but as structured inference engines translating formal causal outputs into natural language explanations and counterfactuals. Our framework lays the theoretical groundwork for Causal Reflective agents that can adapt, self-correct, and communicate causal understanding in evolving environments.","published":"2025-08-06T14:44:23Z","updated":"2025-09-25T13:51:34Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.04495v2","pdf_url":"https://arxiv.org/pdf/2508.04495v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.04080","versioned_id":"2508.04080v1","title":"GeoSR: Cognitive-Agentic Framework for Probing Geospatial Knowledge Boundaries via Iterative Self-Refinement","authors":["Jinfan Tang","Kunming Wu","Ruifeng Gongxie","Yuya He","Yuankai Wu"],"abstract":"Recent studies have extended the application of large language models (LLMs) to geographic problems, revealing surprising geospatial competence even without explicit spatial supervision. However, LLMs still face challenges in spatial consistency, multi-hop reasoning, and geographic bias. To address these issues, we propose GeoSR, a self-refining agentic reasoning framework that embeds core geographic principles -- most notably Tobler's First Law of Geography -- into an iterative prediction loop. In GeoSR, the reasoning process is decomposed into three collaborating agents: (1) a variable-selection agent that selects relevant covariates from the same location; (2) a point-selection agent that chooses reference predictions at nearby locations generated by the LLM in previous rounds; and (3) a refine agent that coordinates the iterative refinement process by evaluating prediction quality and triggering further rounds when necessary. This agentic loop progressively improves prediction quality by leveraging both spatial dependencies and inter-variable relationships. We validate GeoSR on tasks ranging from physical-world property estimation to socioeconomic prediction. Experimental results show consistent improvements over standard prompting strategies, demonstrating that incorporating geostatistical priors and spatially structured reasoning into LLMs leads to more accurate and equitable geospatial predictions. The code of GeoSR is available at https://github.com/JinfanTang/GeoSR.","published":"2025-08-06T04:45:34Z","updated":"2025-08-06T04:45:34Z","categories":["cs.AI","stat.OT"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.04080v1","pdf_url":"https://arxiv.org/pdf/2508.04080v1","comment":"16 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.03613","versioned_id":"2508.03613v1","title":"Goedel-Prover-V2: Scaling Formal Theorem Proving with Scaffolded Data Synthesis and Self-Correction","authors":["Yong Lin","Shange Tang","Bohan Lyu","Ziran Yang","Jui-Hui Chung","Haoyu Zhao","Lai Jiang","Yihan Geng","Jiawei Ge","Jingruo Sun","Jiayun Wu","Jiri Gesi","Ximing Lu","David Acuna","Kaiyu Yang","Hongzhou Lin","Yejin Choi","Danqi Chen","Sanjeev Arora","Chi Jin"],"abstract":"We introduce Goedel-Prover-V2, a series of open-source language models that set a new state-of-the-art in automated theorem proving. Built on the standard expert iteration and reinforcement learning pipeline, our approach incorporates three key innovations: (1) Scaffolded data synthesis: We generate synthetic tasks of increasing difficulty to train the model to master increasingly complex theorems; (2) Verifier-guided self-correction: We enable the model to iteratively revise its proofs by leveraging feedback from the Lean compiler; (3) Model averaging: We merge model checkpoints to mitigate the decrease in model output diversity in later stages of training. Our small model, Goedel-Prover-V2-8B, reaches 84.6% pass@32 on MiniF2F and outperforms DeepSeek-Prover-V2-671B under the same metric, despite being 80X smaller. Our flagship model, Goedel-Prover-V2-32B, achieves 88.1% on MiniF2F at pass@32 in standard mode and 90.4% in self-correction mode, outperforming prior SOTA by a large margin. Additionally, our flagship model solves 86 problems on PutnamBench at pass@184, securing the first place among open-source models on the leaderboard, surpassing DeepSeek-Prover-V2-671B's record of solving 47 problems by pass@1024 with a significantly smaller model size and compute budget. At the time of its release (July-August 2025), Goedel-Prover-V2 achieves the strongest overall performance among all open-source theorem provers. It also ranks among the top-performing models--including closed-source systems with publicly reported performance--under a constrained test-time compute budget. Our models, code, and data are released at https://github.com/Goedel-LM/Goedel-Prover-V2.","published":"2025-08-05T16:28:22Z","updated":"2025-08-05T16:28:22Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.03613v1","pdf_url":"https://arxiv.org/pdf/2508.03613v1","comment":"24 pages, 10 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.03509","versioned_id":"2508.03509v1","title":"SLA-MORL: SLA-Aware Multi-Objective Reinforcement Learning for HPC Resource Optimization","authors":["Seraj Al Mahmud Mostafa","Aravind Mohan","Jianwu Wang"],"abstract":"Dynamic resource allocation for machine learning workloads in cloud environments remains challenging due to competing objectives of minimizing training time and operational costs while meeting Service Level Agreement (SLA) constraints. Traditional approaches employ static resource allocation or single-objective optimization, leading to either SLA violations or resource waste. We present SLA-MORL, an adaptive multi-objective reinforcement learning framework that intelligently allocates GPU and CPU resources based on user-defined preferences (time, cost, or balanced) while ensuring SLA compliance. Our approach introduces two key innovations: (1) intelligent initialization through historical learning or efficient baseline runs that eliminates cold-start problems, reducing initial exploration overhead by 60%, and (2) dynamic weight adaptation that automatically adjusts optimization priorities based on real-time SLA violation severity, creating a self-correcting system. SLA-MORL constructs a 21-dimensional state representation capturing resource utilization, training progress, and SLA compliance, enabling an actor-critic network to make informed allocation decisions across 9 possible actions. Extensive evaluation on 13 diverse ML workloads using production HPC infrastructure demonstrates that SLA-MORL achieves 67.2% reduction in training time for deadline-critical jobs, 68.8% reduction in costs for budget-constrained workloads, and 73.4% improvement in overall SLA compliance compared to static baselines. By addressing both cold-start inefficiency and dynamic adaptation challenges, SLA-MORL provides a practical solution for cloud resource management that balances performance, cost, and reliability in modern ML training environments.","published":"2025-08-05T14:37:24Z","updated":"2025-08-05T14:37:24Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.03509v1","pdf_url":"https://arxiv.org/pdf/2508.03509v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.03404","versioned_id":"2508.03404v2","title":"Visual Document Understanding and Reasoning: A Multi-Agent Collaboration Framework with Agent-Wise Adaptive Test-Time Scaling","authors":["Xinlei Yu","Chengming Xu","Zhangquan Chen","Yudong Zhang","Shilin Lu","Cheng Yang","Jiangning Zhang","Shuicheng Yan","Xiaobin Hu"],"abstract":"The dominant paradigm of monolithic scaling in Vision-Language Models (VLMs) is failing for understanding and reasoning in documents, yielding diminishing returns as it struggles with the inherent need of this domain for document-based procedural reasoning, cognitive complexity, and factual accuracy. To this end, we introduce MACT, a Multi-Agent Collaboration framework with agent-wise adaptive Test-time scaling that pioneers a paradigm shift to procedural scaling, adapting dynamically to the functional entities of visual documents understanding and reasoning. MACT decomposes the visual document processing flow into four specialized agents, i.e., planning, execution, judgment, and answer, to resolve cognitive overload and introduce a critical self-correction loop for factual grounding. This collaborative architecture is amplified by an agent-wise adaptive test-time scaling strategy that intelligently allocates computational resources based on the complexity and redundancy of each functionality. Evaluated on multiple visual document understanding benchmarks, MACT achieves superior performance with a smaller parameter scale, adapting effectively to various document scenarios without compromising its general or mathematical reasoning capabilities. The three variants of MACT consistently attain top-three average performance rankings, with average performance enhancements of 9.9-11.5% over the base models. The source code will be released publicly.","published":"2025-08-05T12:52:09Z","updated":"2025-11-14T06:48:22Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2508.03404v2","pdf_url":"https://arxiv.org/pdf/2508.03404v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.03396","versioned_id":"2508.03396v1","title":"Hide and Seek with LLMs: An Adversarial Game for Sneaky Error Generation and Self-Improving Diagnosis","authors":["Rui Zou","Mengqi Wei","Yutao Zhu","Jirong Wen","Xin Zhao","Jing Chen"],"abstract":"Large Language Models (LLMs) excel in reasoning and generation across domains, but still struggle with identifying and diagnosing complex errors. This stems mainly from training objectives that prioritize correct answers, limiting exposure to and learning from errors. While recent studies have begun to address this by introducing error signals, most rely on shallow, static errors, restricting improvement in deep diagnostic ability. To overcome this, we propose Hide and Seek Game (HSG), a dynamic adversarial framework for error generation and diagnosis, and evaluate it on mathematical problem-solving. HSG involves two adversarial roles: Sneaky, which \"hides\" by generating subtle, deceptive reasoning errors, and Diagnosis, which \"seeks\" to accurately detect them. Through adversarial co-evolution, both error stealth and diagnostic precision are enhanced. Experiments on several math reasoning tasks show that HSG significantly boosts error diagnosis, achieving 16.8\\%--31.4\\% higher accuracy than baselines like GPT-4o. We also release a challenging dataset of deceptive errors and diagnostic annotations as a benchmark for future research.","published":"2025-08-05T12:45:21Z","updated":"2025-08-05T12:45:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.03396v1","pdf_url":"https://arxiv.org/pdf/2508.03396v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.09155","versioned_id":"2508.09155v1","title":"A Rolling Stone Gathers No Moss: Adaptive Policy Optimization for Stable Self-Evaluation in Large Multimodal Models","authors":["Wenkai Wang","Hongcan Guo","Zheqi Lv","Shengyu Zhang"],"abstract":"Self-evaluation, a model's ability to assess the correctness of its own output, is crucial for Large Multimodal Models (LMMs) to achieve self-improvement in multi-turn conversations, yet largely absent in foundation models. Recent work has employed reinforcement learning (RL) to enhance self-evaluation; however, its fixed reward mechanism suffers from reward hacking when optimizing multiple training objectives, leading to model collapse. In this paper we propose AdaPO, an online reinforcement learning framework capable of adaptively adjusting training objective in real time according to the current training state for each task. Specifically, to mitigate reward hacking , AdaPO introduces an Adaptive Reward Model (ARM) and a Reward Aware Dynamic KL Regularization mechanism. ARM assesses the task's training state from the distribution of model generated multi-turn trajectories' performance. Reward Aware Dynamic KL replaces a fixed penalty with dynamic coefficients which is modulated by the reward gap between different multi-turn situations. Notably, our method automatically and smoothly adjusts its learning focus based on sub-tasks' training progress without manual intervention. Extensive experiments over 8 benchmarks and various models show that our method significantly enhances both direct reasoning and self-evaluation capability. We will release our code to contribute to the community.","published":"2025-08-05T07:54:01Z","updated":"2025-08-05T07:54:01Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.09155v1","pdf_url":"https://arxiv.org/pdf/2508.09155v1","comment":"17 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.03018","versioned_id":"2508.03018v2","title":"Beyond Policy Optimization: A Data Curation Flywheel for Sparse-Reward Long-Horizon Planning","authors":["Yutong Wang","Pengliang Ji","Kaixin Li","Baolong Bi","Tao Feng","Guillaume Sartoretti"],"abstract":"Large Language Reasoning Models have demonstrated remarkable success on static tasks, yet their application to multi-round agentic planning in interactive environments faces two fundamental challenges. First, the intractable credit assignment problem renders conventional reinforcement learning ineffective in sparse-reward settings. Second, the computational overhead of verbose, step-by-step reasoning histories is prohibitive. To address these challenges, we propose BPO, a three-stage framework (bootstrapping, extrapolation, and refinement) that establishes a self-improving data flywheel to develop robust reasoning models for long-horizon, sparse-reward environments. Our framework first bootstraps efficient reasoning using the proposed planning quaternions with long-short chain-of-thought fusion. It then extrapolates to out-of-distribution tasks through complexity-stratified curriculum learning. Finally, the model iteratively refines itself by learning exclusively on experiences selected via reward-gated rejection sampling. Experiments on ALFWorld, ScienceWorld, and WebShop demonstrate that our approach achieves state-of-the-art with significant token efficiency, providing a new recipe for reasoning models in agentic planning.","published":"2025-08-05T02:56:58Z","updated":"2026-05-16T08:56:03Z","categories":["cs.AI","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.03018v2","pdf_url":"https://arxiv.org/pdf/2508.03018v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.02959","versioned_id":"2508.02959v2","title":"Polymath: A Self-Optimizing Agent with Dynamic Hierarchical Workflow","authors":["Chia-Tung Ho","Jing Gong","Xufeng Yao","Yunsheng Bai","Abhishek B Akkur","Haoxing Ren"],"abstract":"Large language models (LLMs) excel at solving complex tasks by executing agentic workflows composed of detailed instructions and structured operations. Yet, building general-purpose agents by manually embedding foundation models into agentic systems such as Chain-of-Thought, Self-Reflection, and ReACT through text interfaces limits scalability and efficiency. Recently, many researchers have sought to automate the generation and optimization of these workflows through code-based representations. However, existing methods often rely on labeled datasets to train and optimize workflows, making them ineffective and inflexible for solving real-world, dynamic problems where labeled data is unavailable. To address this challenge, we introduce Polymath, a self-optimizing agent with dynamic hierarchical workflow that leverages the flexibility of task flow graphs and the expressiveness of code-represented workflows to solve a wide range of real-world, dynamic problems. The proposed optimization methodology integrates multi-grid-inspired graph optimization with a self-reflection-guided evolutionary algorithm to refine workflows without labeled data. Experimental results on six benchmark datasets across coding, math, and multi-turn QA tasks show that Polymath achieves 8.1% average improvement over state-of-the-art baselines.","published":"2025-08-04T23:50:02Z","updated":"2025-08-07T01:30:51Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.02959v2","pdf_url":"https://arxiv.org/pdf/2508.02959v2","comment":"18 pages, 12 figures, under review for AAAI2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.02886","versioned_id":"2508.02886v1","title":"Coherent Multimodal Reasoning with Iterative Self-Evaluation for Vision-Language Models","authors":["Wenjie Luo","Ruocheng Li","Shanshan Zhu","Julian Perry"],"abstract":"Despite significant advancements, current large language models (LLMs) and vision-language models (LVLMs) continue to struggle with complex, multi-step, cross-modal common sense reasoning tasks, often exhibiting a lack of \"deliberative thinking.\" They tend to rely on superficial associations rather than deep, chained inference, particularly when integrating visual information with abstract concepts. To address this, we propose the Coherent Multimodal Reasoning Framework (CMRF), a novel approach that enhances LVLMs' common sense reasoning capabilities through an iterative, self-evaluating inference mechanism. CMRF mimics human problem-solving by decomposing complex queries, generating step-by-step inferences, and self-correcting errors. Our framework integrates three key modules: a Reasoning Decomposition Unit (RDU) for breaking down problems into sub-questions, a Contextual Inference Engine (CIE) for contextual inference, and a Coherence Assessment Module (CAM) for evaluating logical consistency and confidence. Coupled with an Adaptive Iterative Refinement strategy, CMRF systematically refines its reasoning paths. Built upon LLaVA-1.6-34B and trained on a novel Multimodal Daily Activity Reasoning (MDAR) dataset, CMRF achieves state-of-the-art performance among open-source LVLMs on challenging benchmarks like VCR, A-OKVQA, and DailyLife-MRC. It attains an average accuracy of 69.4%, surpassing the best open-source baseline by +2.4 percentage points, with particular strength in complex reasoning scenarios. Extensive ablation studies and human evaluations confirm the critical contributions of each module and the effectiveness of iterative refinement in fostering more coherent and accurate reasoning.","published":"2025-08-04T20:33:58Z","updated":"2025-08-04T20:33:58Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.02886v1","pdf_url":"https://arxiv.org/pdf/2508.02886v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.02629","versioned_id":"2508.02629v2","title":"HyCodePolicy: Hybrid Language Controllers for Multimodal Monitoring and Decision in Embodied Agents","authors":["Yibin Liu","Zhixuan Liang","Zanxin Chen","Tianxing Chen","Mengkang Hu","Wanxi Dong","Congsheng Xu","Zhaoming Han","Yusen Qin","Yao Mu"],"abstract":"Recent advances in multimodal large language models (MLLMs) have enabled richer perceptual grounding for code policy generation in embodied agents. However, most existing systems lack effective mechanisms to adaptively monitor policy execution and repair codes during task completion. In this work, we introduce HyCodePolicy, a hybrid language-based control framework that systematically integrates code synthesis, geometric grounding, perceptual monitoring, and iterative repair into a closed-loop programming cycle for embodied agents. Technically, given a natural language instruction, our system first decomposes it into subgoals and generates an initial executable program grounded in object-centric geometric primitives. The program is then executed in simulation, while a vision-language model (VLM) observes selected checkpoints to detect and localize execution failures and infer failure reasons. By fusing structured execution traces capturing program-level events with VLM-based perceptual feedback, HyCodePolicy infers failure causes and repairs programs. This hybrid dual feedback mechanism enables self-correcting program synthesis with minimal human supervision. Our results demonstrate that HyCodePolicy significantly improves the robustness and sample efficiency of robot manipulation policies, offering a scalable strategy for integrating multimodal reasoning into autonomous decision-making pipelines.","published":"2025-08-04T17:18:14Z","updated":"2025-08-06T07:24:55Z","categories":["cs.RO","cs.AI","cs.CL"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2508.02629v2","pdf_url":"https://arxiv.org/pdf/2508.02629v2","comment":"Accepted to ICCV 2025 Workshop on Multi-Modal Reasoning for Agentic Intelligence","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.02120","versioned_id":"2508.02120v1","title":"Don't Overthink It: A Survey of Efficient R1-style Large Reasoning Models","authors":["Linan Yue","Yichao Du","Yizhi Wang","Weibo Gao","Fangzhou Yao","Li Wang","Ye Liu","Ziyu Xu","Qi Liu","Shimin Di","Min-Ling Zhang"],"abstract":"Recently, Large Reasoning Models (LRMs) have gradually become a research hotspot due to their outstanding performance in handling complex tasks. Among them, DeepSeek R1 has garnered significant attention for its exceptional performance and open-source nature, driving advancements in the research of R1-style LRMs. Unlike traditional Large Language Models (LLMs), these models enhance logical deduction and decision-making capabilities during reasoning by incorporating mechanisms such as long chain-of-thought and self-reflection through reinforcement learning. However, with the widespread application of these models, the problem of overthinking has gradually emerged. Specifically, when generating answers, these models often construct excessively long reasoning chains with redundant or repetitive steps, which leads to reduced reasoning efficiency and may affect the accuracy of the final answer. To this end, various efficient reasoning methods have been proposed, aiming to reduce the length of reasoning paths without compromising model performance and reasoning capability. By reviewing the current research advancements in the field of efficient reasoning methods systematically, we categorize existing works into two main directions based on the lens of single-model optimization versus model collaboration: (1) Efficient Reasoning with Single Model, which focuses on improving the reasoning efficiency of individual models; and (2) Efficient Reasoning with Model Collaboration, which explores optimizing reasoning paths through collaboration among multiple models. Besides, we maintain a public GitHub repository that tracks the latest progress in efficient reasoning methods.","published":"2025-08-04T06:54:31Z","updated":"2025-08-04T06:54:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.02120v1","pdf_url":"https://arxiv.org/pdf/2508.02120v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.01387","versioned_id":"2508.01387v1","title":"Video-based Vehicle Surveillance in the Wild: License Plate, Make, and Model Recognition with Self Reflective Vision-Language Models","authors":["Pouya Parsa","Keya Li","Kara M. Kockelman","Seongjin Choi"],"abstract":"Automatic license plate recognition (ALPR) and vehicle make and model recognition underpin intelligent transportation systems, supporting law enforcement, toll collection, and post-incident investigation. Applying these methods to videos captured by handheld smartphones or non-static vehicle-mounted cameras presents unique challenges compared to fixed installations, including frequent camera motion, varying viewpoints, occlusions, and unknown road geometry. Traditional ALPR solutions, dependent on specialized hardware and handcrafted OCR pipelines, often degrade under these conditions. Recent advances in large vision-language models (VLMs) enable direct recognition of textual and semantic attributes from arbitrary imagery. This study evaluates the potential of VLMs for ALPR and makes and models recognition using monocular videos captured with handheld smartphones and non-static mounted cameras. The proposed license plate recognition pipeline filters to sharp frames, then sends a multimodal prompt to a VLM using several prompt strategies. Make and model recognition pipeline runs the same VLM with a revised prompt and an optional self-reflection module. In the self-reflection module, the model contrasts the query image with a reference from a 134-class dataset, correcting mismatches. Experiments on a smartphone dataset collected on the campus of the University of Texas at Austin, achieve top-1 accuracies of 91.67% for ALPR and 66.67% for make and model recognition. On the public UFPR-ALPR dataset, the approach attains 83.05% and 61.07%, respectively. The self-reflection module further improves results by 5.72% on average for make and model recognition. These findings demonstrate that VLMs provide a cost-effective solution for scalable, in-motion traffic video analysis.","published":"2025-08-02T14:34:19Z","updated":"2025-08-02T14:34:19Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2508.01387v1","pdf_url":"https://arxiv.org/pdf/2508.01387v1","comment":"19 pages, 6 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.05666","versioned_id":"2508.05666v1","title":"HySemRAG: A Hybrid Semantic Retrieval-Augmented Generation Framework for Automated Literature Synthesis and Methodological Gap Analysis","authors":["Alejandro Godinez"],"abstract":"We present HySemRAG, a framework that combines Extract, Transform, Load (ETL) pipelines with Retrieval-Augmented Generation (RAG) to automate large-scale literature synthesis and identify methodological research gaps. The system addresses limitations in existing RAG architectures through a multi-layered approach: hybrid retrieval combining semantic search, keyword filtering, and knowledge graph traversal; an agentic self-correction framework with iterative quality assurance; and post-hoc citation verification ensuring complete traceability. Our implementation processes scholarly literature through eight integrated stages: multi-source metadata acquisition, asynchronous PDF retrieval, custom document layout analysis using modified Docling architecture, bibliographic management, LLM-based field extraction, topic modeling, semantic unification, and knowledge graph construction. The system creates dual data products - a Neo4j knowledge graph enabling complex relationship queries and Qdrant vector collections supporting semantic search - serving as foundational infrastructure for verifiable information synthesis. Evaluation across 643 observations from 60 testing sessions demonstrates structured field extraction achieving 35.1% higher semantic similarity scores (0.655 $\\pm$ 0.178) compared to PDF chunking approaches (0.485 $\\pm$ 0.204, p < 0.000001). The agentic quality assurance mechanism achieves 68.3% single-pass success rates with 99.0% citation accuracy in validated responses. Applied to geospatial epidemiology literature on ozone exposure and cardiovascular disease, the system identifies methodological trends and research gaps, demonstrating broad applicability across scientific domains for accelerating evidence synthesis and discovery.","published":"2025-08-01T20:30:42Z","updated":"2025-08-01T20:30:42Z","categories":["cs.IR","cs.AI","cs.LG"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2508.05666v1","pdf_url":"https://arxiv.org/pdf/2508.05666v1","comment":"47 pages, 10 figures. Code: https://github.com/agodinezmm2007/docling_mod. Demo: https://youtu.be/ZCy5ESJ1gVE?si=K8CttwgTj7yGrWjn. ETL+multi-agent RAG framework for literature synthesis, 35.1% improvement over PDF chunking. Real application: reduced 17,400 papers to 24 relevant ones (99.86%) in 10 minutes for wastewater epidemiology review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.02731","versioned_id":"2508.02731v1","title":"Teaching at Scale: Leveraging AI to Evaluate and Elevate Engineering Education","authors":["Jean-Francois Chamberland","Martin C. Carlisle","Arul Jayaraman","Krishna R. Narayanan","Sunay Palsole","Karan Watson"],"abstract":"Evaluating teaching effectiveness at scale remains a persistent challenge for large universities, particularly within engineering programs that enroll tens of thousands of students. Traditional methods, such as manual review of student evaluations, are often impractical, leading to overlooked insights and inconsistent data use. This article presents a scalable, AI-supported framework for synthesizing qualitative student feedback using large language models. The system employs hierarchical summarization, anonymization, and exception handling to extract actionable themes from open-ended comments while upholding ethical safeguards. Visual analytics contextualize numeric scores through percentile-based comparisons, historical trends, and instructional load. The approach supports meaningful evaluation and aligns with best practices in qualitative analysis and educational assessment, incorporating student, peer, and self-reflective inputs without automating personnel decisions. We report on its successful deployment across a large college of engineering. Preliminary validation through comparisons with human reviewers, faculty feedback, and longitudinal analysis suggests that LLM-generated summaries can reliably support formative evaluation and professional development. This work demonstrates how AI systems, when designed with transparency and shared governance, can promote teaching excellence and continuous improvement at scale within academic institutions.","published":"2025-08-01T20:27:40Z","updated":"2025-08-01T20:27:40Z","categories":["cs.CY","cs.AI","cs.CL"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2508.02731v1","pdf_url":"https://arxiv.org/pdf/2508.02731v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2508.00271","versioned_id":"2508.00271v2","title":"MetaAgent: Toward Self-Evolving Agent via Tool Meta-Learning","authors":["Hongjin Qian","Zheng Liu"],"abstract":"In this work, we propose MetaAgent, an agentic paradigm inspired by the principle of learning-by-doing, where expertise is developed through hands-on practice and continual self-improvement. MetaAgent starts with a minimal workflow, equipped only with basic reasoning and adaptive help-seeking abilities. When a knowledge gap is encountered, MetaAgent generates natural language help requests, which are routed to the most suitable external tool by a dedicated tool router. As MetaAgent solves tasks, it continually conducts self-reflection and answer verification, distilling actionable experience into concise texts that are dynamically incorporated into future task contexts. Besides, MetaAgent autonomously builds in-house tools and a persistent knowledge base by organizing its tool-use history, further enhancing its ability to retrieve and integrate relevant information We term this continual, data-driven process as \\textit{meta tool learning}, through which MetaAgent incrementally refines its reasoning and tool-use strategies, without changing model parameters or requiring further post-training. Evaluated on challenging knowledge discovery benchmarks, including GAIA, WebWalkerQA, and BrowseCamp, MetaAgent consistently outperforms workflow-based baselines and matches or exceeds end-to-end trained agents, demonstrating the promise of self-evolving agentic systems for robust, general-purpose knowledge discovery. We provide our source codes in https://github.com/qhjqhj00/MetaAgent.","published":"2025-08-01T02:30:32Z","updated":"2025-09-01T02:48:41Z","categories":["cs.AI","cs.CL","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.00271v2","pdf_url":"https://arxiv.org/pdf/2508.00271v2","comment":"Technical Report, 14 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.23365","versioned_id":"2507.23365v1","title":"\"I made this (sort of)\": Negotiating authorship, confronting fraudulence, and exploring new musical spaces with prompt-based AI music generation","authors":["Bob L. T. Sturm"],"abstract":"I reflect on my experience creating two music albums centered on state-of-the-art prompt-based AI music generation platforms. The first album explicitly poses the question: What happens when I collide my junk mail with these platforms? The second album is a direct response to the first, and toys with the inability of state-of-the-art prompt-based AI music generation platforms to generate music that is not ``practiced'', ``polished'', and ``produced''. I seed a large language model (LLM) with information about these albums and have it interview me, which results in the exploration of several deeper questions: To what extent am I the author? Where am I in the resulting music? How is my musical identity changing as I am faced with machines that are in some ways far more talented than I? What new musical spaces does my work open, for me or anyone/thing else? I conclude by reflecting on my reflections, as well as LLM-mediated self-reflection as method.","published":"2025-07-31T09:25:55Z","updated":"2025-07-31T09:25:55Z","categories":["cs.SD","cs.AI","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2507.23365v1","pdf_url":"https://arxiv.org/pdf/2507.23365v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.22671","versioned_id":"2507.22671v1","title":"Designing for Self-Regulation in Informal Programming Learning: Insights from a Storytelling-Centric Approach","authors":["Sami Saeed Alghamdi","Christopher Bull","Ahmed Kharrufa"],"abstract":"Many people learn programming independently from online resources and often report struggles in achieving their personal learning goals. Learners frequently describe their experiences as isolating and frustrating, challenged by abundant uncertainties, information overload, and distraction, compounded by limited guidance. At the same time, social media serves as a personal space where many engage in diverse self-regulation practices, including help-seeking, using external memory aids (e.g., self-notes), self-reflection, emotion regulation, and self-motivation. For instance, learners often mark achievements and set milestones through their posts. In response, we developed a system consisting of a web platform and browser extensions to support self-regulation online. The design aims to add learner-defined structure to otherwise unstructured experiences and bring meaning to curation and reflection activities by translating them into learning stories with AI-generated feedback. We position storytelling as an integrative approach to design that connects resource curation, reflective and sensemaking practice, and narrative practices learners already use across social platforms. We recruited 15 informal programming learners who are regular social media users to engage with the system in a self-paced manner; participation concluded upon submitting a learning story and survey. We used three quantitative scales and a qualitative survey to examine users' characteristics and perceptions of the system's support for their self-regulation. User feedback suggests the system's viability as a self-regulation aid. Learners particularly valued in-situ reflection, automated story feedback, and video annotation, while other features received mixed views. We highlight perceived benefits, friction points, and design opportunities for future AI-augmented self-regulation tools.","published":"2025-07-30T13:30:04Z","updated":"2025-07-30T13:30:04Z","categories":["cs.HC","cs.AI","cs.CY","cs.SE"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2507.22671v1","pdf_url":"https://arxiv.org/pdf/2507.22671v1","comment":"10 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.21524","versioned_id":"2507.21524v2","title":"Large Language Models for Wireless Communications: From Adaptation to Autonomy","authors":["Le Liang","Hao Ye","Yucheng Sheng","Ouya Wang","Jiacheng Wang","Shi Jin","Geoffrey Ye Li"],"abstract":"The emergence of large language models (LLMs) has revolutionized artificial intelligence, offering unprecedented capabilities in reasoning, generalization, and zero-shot learning. These strengths open new frontiers in wireless communications, where increasing complexity and dynamics demand intelligent and adaptive solutions. This article explores the role of LLMs in transforming wireless systems across three key directions: adapting pretrained LLMs for communication tasks, developing wireless-specific foundation models to balance versatility and efficiency, and enabling agentic LLMs with autonomous reasoning and coordination capabilities. We highlight recent advances, practical case studies, and the unique benefits of LLM-based approaches over traditional methods. Finally, we outline open challenges and research opportunities, including multimodal fusion, collaboration with lightweight models, and self-improving capabilities, charting a path toward intelligent, adaptive, and autonomous wireless networks.","published":"2025-07-29T06:21:10Z","updated":"2026-03-17T07:29:58Z","categories":["cs.AI","cs.IT"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.21524v2","pdf_url":"https://arxiv.org/pdf/2507.21524v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.20890","versioned_id":"2507.20890v2","title":"$A^2R^2$: Advancing Img2LaTeX Conversion via Visual Reasoning with Attention-Guided Refinement","authors":["Zhecheng Li","Guoxian Song","Yiwei Wang","Zhen Xiong","Junsong Yuan","Yujun Cai"],"abstract":"Img2LaTeX is a practically important task that involves translating mathematical expressions and structured visual content from images into LaTeX code. In recent years, vision-language models (VLMs) have achieved remarkable progress across a range of visual understanding tasks, largely due to their strong generalization capabilities. However, despite initial efforts to apply VLMs to the Img2LaTeX task, their performance remains suboptimal. Empirical evidence shows that VLMs can be challenged by fine-grained visual elements, such as subscripts and superscripts in mathematical expressions, which results in inaccurate LaTeX generation. To address this challenge, we propose $A^2R^2$: Advancing Img2LaTeX Conversion via Visual Reasoning with Attention-Guided Refinement, a framework that effectively integrates attention localization and iterative refinement within a visual reasoning framework, enabling VLMs to perform self-correction and progressively improve LaTeX generation quality. For effective evaluation, we introduce a new dataset, Img2LaTex-Hard-1K, consisting of 1,100 carefully curated and challenging examples designed to rigorously evaluate the capabilities of VLMs within this task domain. Extensive experimental results demonstrate that: (1) $A^2R^2$ significantly improves model performance across various evaluation metrics spanning both textual and visual levels; (2) Increasing the number of inference rounds yields notable performance gains, underscoring the potential of $A^2R^2$ in test-time scaling scenarios; (3) Ablation studies and further evaluations confirm the effectiveness of our approach and the synergy of its core components during inference.","published":"2025-07-28T14:41:57Z","updated":"2025-09-25T22:30:03Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2507.20890v2","pdf_url":"https://arxiv.org/pdf/2507.20890v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.20301","versioned_id":"2507.20301v2","title":"Advancing Dialectal Arabic to Modern Standard Arabic Machine Translation","authors":["Abdullah Alabdullah","Lifeng Han","Chenghua Lin"],"abstract":"Dialectal Arabic (DA) poses a persistent challenge for natural language processing (NLP), as most everyday communication in the Arab world occurs in dialects that diverge significantly from Modern Standard Arabic (MSA). This linguistic divide impedes progress in Arabic machine translation. This paper presents two core contributions to advancing DA-MSA translation for the Levantine, Egyptian, and Gulf dialects, particularly in low-resource and computationally constrained settings: (i) a comprehensive evaluation of training-free prompting techniques, and (ii) the development of a resource-efficient fine-tuning pipeline. Our evaluation of prompting strategies across six large language models (LLMs) found that few-shot prompting consistently outperformed zero-shot, chain-of-thought, and our proposed Ara-TEaR method. Ara-TEaR is designed as a three-stage self-refinement prompting process, targeting frequent meaning-transfer and adaptation errors in DA-MSA translation. In this evaluation, GPT-4o achieved the highest performance across all prompting settings. For fine-tuning LLMs, a quantized Gemma2-9B model achieved a chrF++ score of 49.88, outperforming zero-shot GPT-4o (44.58). Joint multi-dialect trained models outperformed single-dialect counterparts by over 10% chrF++, and 4-bit quantization reduced memory usage by 60% with less than 1% performance loss. The results and insights of our experiments offer a practical blueprint for improving dialectal inclusion in Arabic NLP, showing that high-quality DA-MSA machine translation is achievable even with limited resources and paving the way for more inclusive language technologies.","published":"2025-07-27T14:37:53Z","updated":"2025-09-02T20:29:50Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.20301v2","pdf_url":"https://arxiv.org/pdf/2507.20301v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.20181","versioned_id":"2507.20181v1","title":"SGPO: Self-Generated Preference Optimization based on Self-Improver","authors":["Hyeonji Lee","Daejin Jo","Seohwan Yun","Sungwoong Kim"],"abstract":"Large language models (LLMs), despite their extensive pretraining on diverse datasets, require effective alignment to human preferences for practical and reliable deployment. Conventional alignment methods typically employ off-policy learning and depend on human-annotated datasets, which limits their broad applicability and introduces distribution shift issues during training. To address these challenges, we propose Self-Generated Preference Optimization based on Self-Improver (SGPO), an innovative alignment framework that leverages an on-policy self-improving mechanism. Specifically, the improver refines responses from a policy model to self-generate preference data for direct preference optimization (DPO) of the policy model. Here, the improver and policy are unified into a single model, and in order to generate higher-quality preference data, this self-improver learns to make incremental yet discernible improvements to the current responses by referencing supervised fine-tuning outputs. Experimental results on AlpacaEval 2.0 and Arena-Hard show that the proposed SGPO significantly improves performance over DPO and baseline self-improving methods without using external preference data.","published":"2025-07-27T08:55:40Z","updated":"2025-07-27T08:55:40Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.20181v1","pdf_url":"https://arxiv.org/pdf/2507.20181v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.19867","versioned_id":"2507.19867v1","title":"DRIVE: Disfluency-Rich Synthetic Dialog Data Generation Framework for Intelligent Vehicle Environments","authors":["Anshul Chavda","M Jagadeesh","Chintalapalli Raja Kullayappa","B Jayaprakash","Medchalimi Sruthi","Pushpak Bhattacharyya"],"abstract":"In-car conversational AI is becoming increasingly critical as autonomous vehicles and smart assistants gain widespread adoption. Yet, existing datasets fail to capture the spontaneous disfluencies such as hesitations, false starts, repetitions, and self-corrections that characterize real driver-AI dialogs. To address this, we introduce DiscoDrive, a synthetic corpus of 3500 multi-turn dialogs across seven automotive domains, generated using a two-stage, prompt-driven pipeline that dynamically integrates disfluencies during synthesis. We show that DiscoDrive is effective both as a training resource, enabling DialoGPT-Medium and T5-Base to match or exceed KVRET-trained models on the MultiWOZ 2.2 and Schema-Guided Dialogue (SGD) relevant test sets (BLEU-4 improvements of 0.26 to 0.61; METEOR +2.10; ROUGE-L +3.48; BERTScore F1 improvements of 1.35 to 3.48), and as a data augmentation resource in low-resource scenarios, delivering additional gains of up to BLEU-4 +0.38, METEOR +1.95, ROUGE-L +2.87, and BERTScore F1 +4.00 when combined with 10 percent of KVRET. Human evaluations further confirm that dialogs sampled from DiscoDrive are rated higher than KVRET's human-collected dialogs in naturalness (3.8 vs 3.6) and coherence (4.1 vs 4.0), and are perceived as more context-appropriate than leading post-hoc methods (such as LARD), without compromising clarity. DiscoDrive fills a critical gap in existing resources and serves as a versatile corpus for both training and augmenting conversational AI, enabling robust handling of real-world, disfluent in-car interactions.","published":"2025-07-26T08:48:40Z","updated":"2025-07-26T08:48:40Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.19867v1","pdf_url":"https://arxiv.org/pdf/2507.19867v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.19333","versioned_id":"2507.19333v3","title":"Injecting External Knowledge into the Reasoning Process Enhances Retrieval-Augmented Generation","authors":["Minghao Tang","Shiyu Ni","Jiafeng Guo","Keping Bi"],"abstract":"Retrieval-augmented generation (RAG) has been widely adopted to augment large language models (LLMs) with external knowledge for knowledge-intensive tasks. However, its effectiveness is often undermined by the presence of noisy (i.e., low-quality) retrieved passages. Enhancing LLMs' robustness to such noise is critical for improving the reliability of RAG systems. Recent advances have equipped LLMs with strong reasoning and self-reflection capabilities, allowing them to identify and correct errors in their reasoning process. Inspired by this ability, we propose Passage Injection-a simple yet effective method that explicitly incorporates retrieved passages into LLMs' reasoning process, aiming to enhance the model's ability to recognize and resist noisy passages. We validate Passage Injection under general RAG settings using BM25 as the retriever. Experiments on four reasoning-enhanced LLMs across four factual QA datasets demonstrate that Passage Injection significantly improves overall RAG performance. Further analysis on two noisy retrieval settings-random noise, where the model is provided irrelevant passages, and counterfactual noise, where it is given misleading passages-shows that Passage Injection consistently improves robustness. Controlled experiments confirm that Passage Injection can also effectively leverage helpful passages. These findings suggest that incorporating passages in LLMs' reasoning process is a promising direction for building more robust RAG systems. The code can be found \\href{here}{https://github.com/Trustworthy-Information-Access/Passage-Injection}.","published":"2025-07-25T14:43:31Z","updated":"2025-10-08T08:21:01Z","categories":["cs.IR","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2507.19333v3","pdf_url":"https://arxiv.org/pdf/2507.19333v3","comment":"SIGIR-AP 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.18742","versioned_id":"2507.18742v1","title":"Specification Self-Correction: Mitigating In-Context Reward Hacking Through Test-Time Refinement","authors":["Víctor Gallego"],"abstract":"Language models (LMs) are susceptible to in-context reward hacking, where they exploit flaws in tainted or faulty written specifications or rubrics to achieve high scores without fulfilling the user's true intent. We introduce Specification Self-Correction (SSC), a novel, test-time framework that enables an LM to identify and correct flaws within its own guiding specification. SSC employs a multi-step inference process where the model first generates a response based on a potentially tainted specification, critiques its output, and then revises the specification itself to remove the exploitable loophole. A final, more robust response is then generated using this self-corrected specification. Across experiments spanning creative writing and agentic coding tasks with several LMs, we demonstrate that while models initially game tainted specifications in 50-70\\% of cases, the SSC process reduces this vulnerability by over 90\\%. This dynamic repair occurs at inference time, requires no weight modification, and leads to more robustly aligned model behavior. Code at https://github.com/vicgalle/specification-self-correction .","published":"2025-07-24T18:44:28Z","updated":"2025-07-24T18:44:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.18742v1","pdf_url":"https://arxiv.org/pdf/2507.18742v1","comment":"Accepted to SCALR Workshop @ COLM 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.18576","versioned_id":"2507.18576v3","title":"SafeWork-R1: Coevolving Safety and Intelligence under the AI-45$^{\\circ}$ Law","authors":["Shanghai AI Lab",":","Yicheng Bao","Guanxu Chen","Mingkang Chen","Yunhao Chen","Chiyu Chen","Lingjie Chen","Sirui Chen","Xinquan Chen","Jie Cheng","Yu Cheng","Dengke Deng","Yizhuo Ding","Dan Ding","Xiaoshan Ding","Yi Ding","Zhichen Dong","Lingxiao Du","Yuyu Fan","Xinshun Feng","Yanwei Fu","Yuxuan Gao","Ruijun Ge","Tianle Gu","Lujun Gui","Jiaxuan Guo","Qianxi He","Yuenan Hou","Xuhao Hu","Hong Huang","Kaichen Huang","Shiyang Huang","Yuxian Jiang","Shanzhe Lei","Jie Li","Lijun Li","Hao Li","Juncheng Li","Xiangtian Li","Yafu Li","Lingyu Li","Xueyan Li","Haotian Liang","Dongrui Liu","Qihua Liu","Zhixuan Liu","Bangwei Liu","Huacan Liu","Yuexiao Liu","Zongkai Liu","Chaochao Lu","Yudong Lu","Xiaoya Lu","Zhenghao Lu","Qitan Lv","Caoyuan Ma","Jiachen Ma","Xiaoya Ma","Zhongtian Ma","Lingyu Meng","Ziqi Miao","Yazhe Niu","Yuezhang Peng","Yuan Pu","Han Qi","Chen Qian","Xingge Qiao","Jingjing Qu","Jiashu Qu","Wanying Qu","Wenwen Qu","Xiaoye Qu","Qihan Ren","Qingnan Ren","Qingyu Ren","Jing Shao","Wenqi Shao","Shuai Shao","Dongxing Shi","Xin Song","Xinhao Song","Yan Teng","Xuan Tong","Yingchun Wang","Xuhong Wang","Shujie Wang","Xin Wang","Yige Wang","Yixu Wang","Yuanfu Wang","Futing Wang","Ruofan Wang","Wenjie Wang","Yajie Wang","Muhao Wei","Xiaoyu Wen","Fenghua Weng","Yuqi Wu","Yingtong Xiong","Xingcheng Xu","Chao Yang","Yue Yang","Yang Yao","Yulei Ye","Zhenyun Yin","Yi Yu","Bo Zhang","Qiaosheng Zhang","Jinxuan Zhang","Yexin Zhang","Yinqiang Zheng","Hefeng Zhou","Zhanhui Zhou","Pengyu Zhu","Qingzi Zhu","Yubo Zhu","Bowen Zhou"],"abstract":"We introduce SafeWork-R1, a cutting-edge multimodal reasoning model that demonstrates the coevolution of capabilities and safety. It is developed by our proposed SafeLadder framework, which incorporates large-scale, progressive, safety-oriented reinforcement learning post-training, supported by a suite of multi-principled verifiers. Unlike previous alignment methods such as RLHF that simply learn human preferences, SafeLadder enables SafeWork-R1 to develop intrinsic safety reasoning and self-reflection abilities, giving rise to safety `aha' moments. Notably, SafeWork-R1 achieves an average improvement of $46.54\\%$ over its base model Qwen2.5-VL-72B on safety-related benchmarks without compromising general capabilities, and delivers state-of-the-art safety performance compared to leading proprietary models such as GPT-4.1 and Claude Opus 4. To further bolster its reliability, we implement two distinct inference-time intervention methods and a deliberative search mechanism, enforcing step-level verification. Finally, we further develop SafeWork-R1-InternVL3-78B, SafeWork-R1-DeepSeek-70B, and SafeWork-R1-Qwen2.5VL-7B. All resulting models demonstrate that safety and capability can co-evolve synergistically, highlighting the generalizability of our framework in building robust, reliable, and trustworthy general-purpose AI.","published":"2025-07-24T16:49:19Z","updated":"2025-08-07T08:02:42Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.18576v3","pdf_url":"https://arxiv.org/pdf/2507.18576v3","comment":"47 pages, 18 figures, authors are listed in alphabetical order by their last names; v3 modifies minor issues","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.18190","versioned_id":"2507.18190v2","title":"TN-AutoRCA: Benchmark Construction and Agentic Framework for Self-Improving Alarm-Based Root Cause Analysis in Telecommunication Networks","authors":["Keyu Wu","Qianjin Yu","Manlin Mei","Ruiting Liu","Jun Wang","Kailai Zhang","Yelun Bao"],"abstract":"Root Cause Analysis (RCA) in telecommunication networks is a critical task, yet it presents a formidable challenge for Artificial Intelligence (AI) due to its complex, graph-based reasoning requirements and the scarcity of realistic benchmarks.","published":"2025-07-24T08:40:08Z","updated":"2025-07-28T12:33:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.18190v2","pdf_url":"https://arxiv.org/pdf/2507.18190v2","comment":"10 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.18122","versioned_id":"2507.18122v1","title":"Maximizing Prefix-Confidence at Test-Time Efficiently Improves Mathematical Reasoning","authors":["Matthias Otth","Jonas Hübotter","Ido Hakimi","Andreas Krause"],"abstract":"Recent work has shown that language models can self-improve by maximizing their own confidence in their predictions, without relying on external verifiers or reward signals. In this work, we study the test-time scaling of language models for mathematical reasoning tasks, where the model's own confidence is used to select the most promising attempts. Surprisingly, we find that we can achieve significant performance gains by continuing only the most promising attempt, selected by the model's prefix-confidence. We systematically evaluate prefix-confidence scaling on five mathematical reasoning datasets: the school-level GSM8K and MATH500, and the competition-level AMC23, AIME24, and AIME25. We find that prefix-confidence scaling with prefixes of only 32 tokens achieves a better accuracy-compute trade-off than majority voting. Moreover, prefix-confidence scaling appears less susceptible than BoN to length biases. Finally, we also evaluate test-time training with prefix-confidence and find that, while outperforming the base model, it does not improve over prefix-confidence scaling.","published":"2025-07-24T06:17:39Z","updated":"2025-07-24T06:17:39Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.18122v1","pdf_url":"https://arxiv.org/pdf/2507.18122v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.17896","versioned_id":"2507.17896v1","title":"VeriMinder: Mitigating Analytical Vulnerabilities in NL2SQL","authors":["Shubham Mohole","Sainyam Galhotra"],"abstract":"Application systems using natural language interfaces to databases (NLIDBs) have democratized data analysis. This positive development has also brought forth an urgent challenge to help users who might use these systems without a background in statistical analysis to formulate bias-free analytical questions. Although significant research has focused on text-to-SQL generation accuracy, addressing cognitive biases in analytical questions remains underexplored. We present VeriMinder, https://veriminder.ai, an interactive system for detecting and mitigating such analytical vulnerabilities. Our approach introduces three key innovations: (1) a contextual semantic mapping framework for biases relevant to specific analysis contexts (2) an analytical framework that operationalizes the Hard-to-Vary principle and guides users in systematic data analysis (3) an optimized LLM-powered system that generates high-quality, task-specific prompts using a structured process involving multiple candidates, critic feedback, and self-reflection. User testing confirms the merits of our approach. In direct user experience evaluation, 82.5% participants reported positively impacting the quality of the analysis. In comparative evaluation, VeriMinder scored significantly higher than alternative approaches, at least 20% better when considered for metrics of the analysis's concreteness, comprehensiveness, and accuracy. Our system, implemented as a web application, is set to help users avoid \"wrong question\" vulnerability during data analysis. VeriMinder code base with prompts, https://reproducibility.link/veriminder, is available as an MIT-licensed open-source software to facilitate further research and adoption within the community.","published":"2025-07-23T19:48:12Z","updated":"2025-07-23T19:48:12Z","categories":["cs.CL","cs.AI","cs.DB"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.17896v1","pdf_url":"https://arxiv.org/pdf/2507.17896v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.17273","versioned_id":"2507.17273v1","title":"Leveraging Knowledge Graphs and LLM Reasoning to Identify Operational Bottlenecks for Warehouse Planning Assistance","authors":["Rishi Parekh","Saisubramaniam Gopalakrishnan","Zishan Ahmad","Anirudh Deodhar"],"abstract":"Analyzing large, complex output datasets from Discrete Event Simulations (DES) of warehouse operations to identify bottlenecks and inefficiencies is a critical yet challenging task, often demanding significant manual effort or specialized analytical tools. Our framework integrates Knowledge Graphs (KGs) and Large Language Model (LLM)-based agents to analyze complex Discrete Event Simulation (DES) output data from warehouse operations. It transforms raw DES data into a semantically rich KG, capturing relationships between simulation events and entities. An LLM-based agent uses iterative reasoning, generating interdependent sub-questions. For each sub-question, it creates Cypher queries for KG interaction, extracts information, and self-reflects to correct errors. This adaptive, iterative, and self-correcting process identifies operational issues mimicking human analysis. Our DES approach for warehouse bottleneck identification, tested with equipment breakdowns and process irregularities, outperforms baseline methods. For operational questions, it achieves near-perfect pass rates in pinpointing inefficiencies. For complex investigative questions, we demonstrate its superior diagnostic ability to uncover subtle, interconnected issues. This work bridges simulation modeling and AI (KG+LLM), offering a more intuitive method for actionable insights, reducing time-to-insight, and enabling automated warehouse inefficiency evaluation and diagnosis.","published":"2025-07-23T07:18:55Z","updated":"2025-07-23T07:18:55Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.17273v1","pdf_url":"https://arxiv.org/pdf/2507.17273v1","comment":"12 pages, 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.17131","versioned_id":"2507.17131v2","title":"Enabling Self-Improving Agents to Learn at Test Time With Human-In-The-Loop Guidance","authors":["Yufei He","Ruoyu Li","Alex Chen","Yue Liu","Yulin Chen","Yuan Sui","Cheng Chen","Yi Zhu","Luca Luo","Frank Yang","Bryan Hooi"],"abstract":"Large language model (LLM) agents often struggle in environments where rules and required domain knowledge frequently change, such as regulatory compliance and user risk screening. Current approaches, like offline fine-tuning and standard prompting, are insufficient because they cannot effectively adapt to new knowledge during actual operation. To address this limitation, we propose the Adaptive Reflective Interactive Agent (ARIA), an LLM agent framework designed specifically to continuously learn updated domain knowledge at test time. ARIA assesses its own uncertainty through structured self-dialogue, proactively identifying knowledge gaps and requesting targeted explanations or corrections from human experts. It then systematically updates an internal, timestamped knowledge repository with provided human guidance, detecting and resolving conflicting or outdated knowledge through comparisons and clarification queries. We evaluate ARIA on the realistic customer due diligence name screening task on TikTok Pay, alongside publicly available dynamic knowledge tasks. Results demonstrate significant improvements in adaptability and accuracy compared to baselines using standard offline fine-tuning and existing self-improving agents. ARIA is deployed within TikTok Pay serving over 150 million monthly active users, confirming its practicality and effectiveness for operational use in rapidly evolving environments.","published":"2025-07-23T02:12:32Z","updated":"2025-10-10T06:52:01Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.17131v2","pdf_url":"https://arxiv.org/pdf/2507.17131v2","comment":"EMNLP 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.22074","versioned_id":"2507.22074v1","title":"CIMR: Contextualized Iterative Multimodal Reasoning for Robust Instruction Following in LVLMs","authors":["Yangshu Yuan","Heng Chen","Xinyi Jiang","Christian Ng","Kexin Qiu"],"abstract":"The rapid advancement of Large Language Models (LLMs) and Large Vision-Language Models (LVLMs) has enhanced our ability to process and generate human language and visual information. However, these models often struggle with complex, multi-step multi-modal instructions that require logical reasoning, dynamic feedback integration, and iterative self-correction. To address this, we propose CIMR: Contextualized Iterative Multimodal Reasoning, a novel framework that introduces a context-aware iterative reasoning and self-correction module. CIMR operates in two stages: initial reasoning and response generation, followed by iterative refinement using parsed multi-modal feedback. A dynamic fusion module deeply integrates textual, visual, and contextual features at each step. We fine-tune LLaVA-1.5-7B on the Visual Instruction Tuning (VIT) dataset and evaluate CIMR on the newly introduced Multi-modal Action Planning (MAP) dataset. CIMR achieves 91.5% accuracy, outperforming state-of-the-art models such as GPT-4V (89.2%), LLaVA-1.5 (78.5%), MiniGPT-4 (75.3%), and InstructBLIP (72.8%), demonstrating the efficacy of its iterative reasoning and self-correction capabilities in complex tasks.","published":"2025-07-22T18:39:18Z","updated":"2025-07-22T18:39:18Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.22074v1","pdf_url":"https://arxiv.org/pdf/2507.22074v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.16815","versioned_id":"2507.16815v2","title":"ThinkAct: Vision-Language-Action Reasoning via Reinforced Visual Latent Planning","authors":["Chi-Pin Huang","Yueh-Hua Wu","Min-Hung Chen","Yu-Chiang Frank Wang","Fu-En Yang"],"abstract":"Vision-language-action (VLA) reasoning tasks require agents to interpret multimodal instructions, perform long-horizon planning, and act adaptively in dynamic environments. Existing approaches typically train VLA models in an end-to-end fashion, directly mapping inputs to actions without explicit reasoning, which hinders their ability to plan over multiple steps or adapt to complex task variations. In this paper, we propose ThinkAct, a dual-system framework that bridges high-level reasoning with low-level action execution via reinforced visual latent planning. ThinkAct trains a multimodal LLM to generate embodied reasoning plans guided by reinforcing action-aligned visual rewards based on goal completion and trajectory consistency. These reasoning plans are compressed into a visual plan latent that conditions a downstream action model for robust action execution on target environments. Extensive experiments on embodied reasoning and robot manipulation benchmarks demonstrate that ThinkAct enables few-shot adaptation, long-horizon planning, and self-correction behaviors in complex embodied AI tasks.","published":"2025-07-22T17:59:46Z","updated":"2025-09-18T16:26:53Z","categories":["cs.CV","cs.AI","cs.LG","cs.RO"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2507.16815v2","pdf_url":"https://arxiv.org/pdf/2507.16815v2","comment":"NeurIPS 2025. Project page: https://jasper0314-huang.github.io/thinkact-vla/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.16713","versioned_id":"2507.16713v2","title":"A Pragmatist Robot: Learning to Plan Tasks by Experiencing the Real World","authors":["Kaixian Qu","Guowei Lan","René Zurbrügg","Changan Chen","Christopher E. Mower","Haitham Bou-Ammar","Marco Hutter"],"abstract":"Large language models (LLMs) have emerged as the dominant paradigm for robotic task planning using natural language instructions. However, trained on general internet data, LLMs are not inherently aligned with the embodiment, skill sets, and limitations of real-world robotic systems. Inspired by the emerging paradigm of verbal reinforcement learning-where LLM agents improve through self-reflection and few-shot learning without parameter updates-we introduce PragmaBot, a framework that enables robots to learn task planning through real-world experience. PragmaBot employs a vision-language model (VLM) as the robot's \"brain\" and \"eye\", allowing it to visually evaluate action outcomes and self-reflect on failures. These reflections are stored in a short-term memory (STM), enabling the robot to quickly adapt its behavior during ongoing tasks. Upon task completion, the robot summarizes the lessons learned into its long-term memory (LTM). When facing new tasks, it can leverage retrieval-augmented generation (RAG) to plan more grounded action sequences by drawing on relevant past experiences and knowledge. Experiments on four challenging robotic tasks show that STM-based self-reflection increases task success rates from 35% to 84%, with emergent intelligent object interactions. In 12 real-world scenarios (including eight previously unseen tasks), the robot effectively learns from the LTM and improves single-trial success rates from 22% to 80%, with RAG outperforming naive prompting. These results highlight the effectiveness and generalizability of PragmaBot. Project webpage: https://pragmabot.github.io/","published":"2025-07-22T15:48:49Z","updated":"2026-02-14T07:11:52Z","categories":["cs.RO","cs.AI","cs.CL"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2507.16713v2","pdf_url":"https://arxiv.org/pdf/2507.16713v2","comment":"Accepted to RA-L","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.16663","versioned_id":"2507.16663v2","title":"Turning Internal Gap into Self-Improvement: Promoting the Generation-Understanding Unification in MLLMs","authors":["Yujin Han","Hao Chen","Andi Han","Zhiheng Wang","Xinyu Liu","Yingya Zhang","Shiwei Zhang","Difan Zou"],"abstract":"Although unified MLLMs aim to unify generation and understanding, they are considered to exhibit an internal gap, with understanding outperforming generation. Through large-scale evaluation across multiple MLLMs and tasks, we confirm the widespread non-unification of MLLMs, and demonstrate that it indeed stems from weak generation rather than misunderstanding. This finding motivates us to propose a simple yet effective internal gap-based self-improvement framework, which mitigates internal gaps by leveraging stronger understanding to guide weaker generation without relying on any external signals. We validate this strategy through comprehensive experiments: scoring generations with understanding to construct image data for post-training (e.g., SFT and DPO) significantly improves generation while promoting unification. Furthermore, we empirically discover a co-improvement effect of such self-improvement, a phenomenon well known in pre-training but underexplored in post-training. Specifically, as generation improves, understanding becomes more effective at detecting false positives that were previously misclassified as prompt-aligned. To explain this effect, we extend learning dynamic theory to the MLLM setting, showing that the shared empirical neural tangent kernel between generation and understanding encourages aligned learning dynamics, thereby driving co-improvement. This interplay between generation and understanding further motivates a curriculum learning approach for stronger self-improvement: progressively enhanced understanding and generation revisit samples underutilized by pre-trained MLLMs, dynamically expanding post-training data and leading to improved performance and unification.","published":"2025-07-22T14:56:39Z","updated":"2025-09-25T11:17:06Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.16663v2","pdf_url":"https://arxiv.org/pdf/2507.16663v2","comment":"31 pages, 16 figures, 12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.16518","versioned_id":"2507.16518v3","title":"SyncLoop: A Multimodal Dual-Loop Framework for Self-Improving Mathematical Reasoning","authors":["Xiuwei Chen","Wentao Hu","Hanhui Li","Yongxin Wang Jun Zhou","Zisheng Chen","Meng Cao","Yihan Zeng","Kui Zhang","Yu-Jie Yuan","Jianhua Han","Hang Xu","Xiaodan Liang"],"abstract":"Recent advances in multimodal large language models (MLLMs) have shown impressive reasoning capabilities. However, further enhancing existing MLLMs necessitates high-quality vision-language datasets with carefully curated task complexities, which are both costly and challenging to scale. Although recent self-improving models that iteratively refine themselves offer a feasible solution, they still suffer from two core challenges: (i) most existing methods augment visual or textual data separately, resulting in discrepancies in data complexity (e.g., over-simplified diagrams paired with redundant textual descriptions); and (ii) the evolution of data and models is also separated, leading to scenarios where models are exposed to tasks with mismatched difficulty levels. To address these issues, we propose C2-Evo, an automatic, closed-loop self-improving framework that jointly evolves both training data and model capabilities. Specifically, given a base dataset and a base model, C2-Evo enhances them by a cross-modal data evolution loop and a data-model evolution loop. The former loop expands the base dataset by generating complex multimodal problems that combine structured textual sub-problems with iteratively specified geometric diagrams, while the latter loop adaptively selects the generated problems based on the performance of the base model, to conduct supervised fine-tuning and reinforcement learning alternately. Consequently, our method continuously refines its model and training data, and consistently obtains considerable performance gains across multiple mathematical reasoning benchmarks. Our code, models, and datasets will be released.","published":"2025-07-22T12:27:08Z","updated":"2026-06-24T02:00:50Z","categories":["cs.CV","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2507.16518v3","pdf_url":"https://arxiv.org/pdf/2507.16518v3","comment":"ECCV2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.16280","versioned_id":"2507.16280v1","title":"ResearcherBench: Evaluating Deep AI Research Systems on the Frontiers of Scientific Inquiry","authors":["Tianze Xu","Pengrui Lu","Lyumanshan Ye","Xiangkun Hu","Pengfei Liu"],"abstract":"The emergence of deep research systems presents significant capabilities in problem-solving, extending from basic queries to sophisticated research tasks. However, existing benchmarks primarily evaluate these systems as agents for web retrieval and report generation, overlooking their potential to discover novel insights on the frontiers of scientific research. To address this gap, we introduce ResearcherBench, the first benchmark focused on evaluating the capabilities of these advanced, agentic systems - which we refer to as Deep AI Research Systems (DARS) - on frontier AI scientific questions. We compiled a dataset of 65 research questions expertly selected from real-world scientific scenarios such as laboratory discussions and interviews, spanning 35 different AI subjects and categorized into three types: technical details, literature review, and open consulting. Our dual evaluation framework combines rubric assessment, which uses expert-designed criteria to evaluate insight quality, with factual assessment, which measures citation accuracy (faithfulness) and coverage (groundedness). We evaluated several leading commercial DARS and baseline systems. Results show that OpenAI Deep Research and Gemini Deep Research significantly outperform other systems, with particular strength in open-ended consulting questions. Such capabilities represent a meaningful step toward AI self-improvement, aligning with the vision of ASI for AI. We open-source ResearcherBench to provide a standardized platform for promoting the development of next-generation AI research assistants, hoping to foster a new perspective in AI research evaluation for a novel pattern of scientific collaboration: https://github.com/GAIR-NLP/ResearcherBench.","published":"2025-07-22T06:51:26Z","updated":"2025-07-22T06:51:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.16280v1","pdf_url":"https://arxiv.org/pdf/2507.16280v1","comment":"22 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.15675","versioned_id":"2507.15675v1","title":"P3: Prompts Promote Prompting","authors":["Xinyu Zhang","Yuanquan Hu","Fangchao Liu","Zhicheng Dou"],"abstract":"Current large language model (LLM) applications often employ multi-component prompts, comprising both system and user prompts, to guide model behaviors. While recent advancements have demonstrated the efficacy of automatically optimizing either the system or user prompt to boost performance, such unilateral approaches often yield suboptimal outcomes due to the interdependent nature of these components. In this work, we introduce P3, a novel self-improvement framework that concurrently optimizes both system and user prompts through an iterative process. The offline optimized prompts are further leveraged to promote online prompting by performing query-dependent prompt optimization. Extensive experiments on general tasks (e.g., Arena-hard and Alpaca-eval) and reasoning tasks (e.g., GSM8K and GPQA) demonstrate that P3 achieves superior performance in the realm of automatic prompt optimization. Our results highlight the effectiveness of a holistic optimization strategy in enhancing LLM performance across diverse domains.","published":"2025-07-21T14:37:46Z","updated":"2025-07-21T14:37:46Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.15675v1","pdf_url":"https://arxiv.org/pdf/2507.15675v1","comment":"Accepted to ACL 2025 findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.15512","versioned_id":"2507.15512v3","title":"Step-level Verifier-guided Hybrid Test-Time Scaling for Large Language Models","authors":["Kaiyan Chang","Yonghao Shi","Chenglong Wang","Hang Zhou","Chi Hu","Xiaoqian Liu","Yingfeng Luo","Yuan Ge","Tong Xiao","Jingbo Zhu"],"abstract":"Test-Time Scaling (TTS) is a promising approach to progressively elicit the model's intelligence during inference. Recently, training-based TTS methods, such as continued reinforcement learning (RL), have further surged in popularity, while training-free TTS methods are gradually fading from prominence. However, the additional computation overhead of training amplifies the burden on test-time scaling. In this paper, we focus on training-free TTS methods for reasoning. We first design Conditional Step-level Self-refinement, a fine-grained sequential scaling method guided by process verification. On top of its effectiveness, we further combine it with other classical parallel scaling methods at the step level, to introduce a novel inference paradigm called Hybrid Test-Time Scaling. Extensive experiments on five instruction-tuned LLMs across different scales (3B-14B) and families demonstrate that hybrid strategy incorporating various training-free TTS methods at a fine granularity has considerable potential for expanding the reasoning performance boundaries of LLMs.","published":"2025-07-21T11:28:09Z","updated":"2025-09-09T08:04:09Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.15512v3","pdf_url":"https://arxiv.org/pdf/2507.15512v3","comment":"Accepted by EMNLP 2025. Code: https://github.com/Lucky-259/Hybrid_TTS","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.15152","versioned_id":"2507.15152v1","title":"What Level of Automation is \"Good Enough\"? A Benchmark of Large Language Models for Meta-Analysis Data Extraction","authors":["Lingbo Li","Anuradha Mathrani","Teo Susnjak"],"abstract":"Automating data extraction from full-text randomised controlled trials (RCTs) for meta-analysis remains a significant challenge. This study evaluates the practical performance of three LLMs (Gemini-2.0-flash, Grok-3, GPT-4o-mini) across tasks involving statistical results, risk-of-bias assessments, and study-level characteristics in three medical domains: hypertension, diabetes, and orthopaedics. We tested four distinct prompting strategies (basic prompting, self-reflective prompting, model ensemble, and customised prompts) to determine how to improve extraction quality. All models demonstrate high precision but consistently suffer from poor recall by omitting key information. We found that customised prompts were the most effective, boosting recall by up to 15\\%. Based on this analysis, we propose a three-tiered set of guidelines for using LLMs in data extraction, matching data types to appropriate levels of automation based on task complexity and risk. Our study offers practical advice for automating data extraction in real-world meta-analyses, balancing LLM efficiency with expert oversight through targeted, task-specific automation.","published":"2025-07-20T23:09:04Z","updated":"2025-07-20T23:09:04Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.15152v1","pdf_url":"https://arxiv.org/pdf/2507.15152v1","comment":"","journal_ref":"Research Synthesis Methods (2026)","doi":"10.1017/rsm.2025.10066","discovered_on":"2026-07-17"},{"id":"2507.14975","versioned_id":"2507.14975v2","title":"FCRF: Flexible Constructivism Reflection for Long-Horizon Robotic Task Planning with Large Language Models","authors":["Yufan Song","Jiatao Zhang","Zeng Gu","Qingmiao Liang","Tuocheng Hu","Wei Song","Shiqiang Zhu"],"abstract":"Autonomous error correction is critical for domestic robots to achieve reliable execution of complex long-horizon tasks. Prior work has explored self-reflection in Large Language Models (LLMs) for task planning error correction; however, existing methods are constrained by inflexible self-reflection mechanisms that limit their effectiveness. Motivated by these limitations and inspired by human cognitive adaptation, we propose the Flexible Constructivism Reflection Framework (FCRF), a novel Mentor-Actor architecture that enables LLMs to perform flexible self-reflection based on task difficulty, while constructively integrating historical valuable experience with failure lessons. We evaluated FCRF on diverse domestic tasks through simulation in AlfWorld and physical deployment in the real-world environment. Experimental results demonstrate that FCRF significantly improves overall performance and self-reflection flexibility in complex long-horizon robotic tasks.","published":"2025-07-20T14:15:39Z","updated":"2025-09-16T07:14:59Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2507.14975v2","pdf_url":"https://arxiv.org/pdf/2507.14975v2","comment":"8 pages, 6 figures, IROS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.21124","versioned_id":"2507.21124v1","title":"VizGenie: Toward Self-Refining, Domain-Aware Workflows for Next-Generation Scientific Visualization","authors":["Ayan Biswas","Terece L. Turton","Nishath Rajiv Ranasinghe","Shawn Jones","Bradley Love","William Jones","Aric Hagberg","Han-Wei Shen","Nathan DeBardeleben","Earl Lawrence"],"abstract":"We present VizGenie, a self-improving, agentic framework that advances scientific visualization through large language model (LLM) by orchestrating of a collection of domain-specific and dynamically generated modules. Users initially access core functionalities--such as threshold-based filtering, slice extraction, and statistical analysis--through pre-existing tools. For tasks beyond this baseline, VizGenie autonomously employs LLMs to generate new visualization scripts (e.g., VTK Python code), expanding its capabilities on-demand. Each generated script undergoes automated backend validation and is seamlessly integrated upon successful testing, continuously enhancing the system's adaptability and robustness. A distinctive feature of VizGenie is its intuitive natural language interface, allowing users to issue high-level feature-based queries (e.g., ``visualize the skull\"). The system leverages image-based analysis and visual question answering (VQA) via fine-tuned vision models to interpret these queries precisely, bridging domain expertise and technical implementation. Additionally, users can interactively query generated visualizations through VQA, facilitating deeper exploration. Reliability and reproducibility are further strengthened by Retrieval-Augmented Generation (RAG), providing context-driven responses while maintaining comprehensive provenance records. Evaluations on complex volumetric datasets demonstrate significant reductions in cognitive overhead for iterative visualization tasks. By integrating curated domain-specific tools with LLM-driven flexibility, VizGenie not only accelerates insight generation but also establishes a sustainable, continuously evolving visualization practice. The resulting platform dynamically learns from user interactions, consistently enhancing support for feature-centric exploration and reproducible research in scientific visualization.","published":"2025-07-18T23:54:22Z","updated":"2025-07-18T23:54:22Z","categories":["cs.HC","cs.AI","cs.GR","cs.LG"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2507.21124v1","pdf_url":"https://arxiv.org/pdf/2507.21124v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.12759","versioned_id":"2507.12759v1","title":"Logit Arithmetic Elicits Long Reasoning Capabilities Without Training","authors":["Yunxiang Zhang","Muhammad Khalifa","Lechen Zhang","Xin Liu","Ayoung Lee","Xinliang Frederick Zhang","Farima Fatahi Bayat","Lu Wang"],"abstract":"Large reasoning models (LRMs) can do complex reasoning via long chain-of-thought (CoT) involving cognitive strategies such as backtracking and self-correction. Recent studies suggest that some models inherently possess these long reasoning abilities, which may be unlocked via extra training. Our work first investigates whether we can elicit such behavior without any training. To this end, we propose a decoding-time approach, ThinkLogit, which utilizes logits arithmetic (Liu et al., 2024) to tune a target large LM for long reasoning using a substantially smaller model as guider. We then show that we can further boost performance by training the guider model with preference optimization over correct/incorrect reasoning pairs sampled from both the target and guider model -- a setup we refer to as ThinkLogit-DPO. Our experiments demonstrate that ThinkLogit and ThinkLogit-DPO achieve a relative improvement in pass@1 by 26% and 29%, respectively, over four mathematical datasets using the Qwen2.5-32B when guided by R1-Distill-Qwen-1.5B -- a model 21x smaller. Lastly, we show that ThinkLogit can transfer long reasoning skills acquired through reinforcement learning, improving pass@1 by 13% relative compared to the Qwen2.5-32B base model. Our work presents a computationally-efficient method to elicit long reasoning in large models with minimal or no additional training.","published":"2025-07-17T03:31:36Z","updated":"2025-07-17T03:31:36Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.12759v1","pdf_url":"https://arxiv.org/pdf/2507.12759v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.12379","versioned_id":"2507.12379v1","title":"Probing for Arithmetic Errors in Language Models","authors":["Yucheng Sun","Alessandro Stolfo","Mrinmaya Sachan"],"abstract":"We investigate whether internal activations in language models can be used to detect arithmetic errors. Starting with a controlled setting of 3-digit addition, we show that simple probes can accurately decode both the model's predicted output and the correct answer from hidden states, regardless of whether the model's output is correct. Building on this, we train lightweight error detectors that predict model correctness with over 90% accuracy. We then extend our analysis to structured chain-of-thought traces on addition-only GSM8K problems and find that probes trained on simple arithmetic generalize well to this more complex setting, revealing consistent internal representations. Finally, we demonstrate that these probes can guide selective re-prompting of erroneous reasoning steps, improving task accuracy with minimal disruption to correct outputs. Our findings suggest that arithmetic errors can be anticipated from internal activations alone, and that simple probes offer a viable path toward lightweight model self-correction.","published":"2025-07-16T16:27:50Z","updated":"2025-07-16T16:27:50Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.12379v1","pdf_url":"https://arxiv.org/pdf/2507.12379v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.22069","versioned_id":"2507.22069v2","title":"A Compute-Matched Re-Evaluation of TroVE on MATH","authors":["Tobias Sesterhenn","Ian Berlot-Attwell","Janis Zenkner","Christian Bartelt"],"abstract":"Reusing established theorems and formulas is central to mathematical problem solving, serving as essential building blocks for tackling increasingly complex challenges. Recent work, TroVE, argues that code-generating Large Language Models (LLMs) can benefit similarly on the MATH benchmark by inducing and reusing higher-level toolboxes. By allocating computational budget across an ensemble of three modes -- directly generating code, creating tools, and reusing tools -- TroVE claims to outperform a PRIMITIVE baseline that only performs direct generation. However, recent analysis (Berlot-Attwell et al., 2024) casts doubt on these gains, noting that the tools created are often trivial or rarely reused, suggesting that improvements may stem from self-consistency or self-correction. In this work, we re-evaluate TroVE on MATH, analyze the impact of each of its modes, and show that its benefit does not come from these mechanisms, but simply from a higher computational budget spent for TroVE compared to PRIMITIVE. To this end, we also perform a small correction in the original implementation of TroVE's selection mechanism, boosting TroVE's performance on MATH by 3\\% in accuracy. After matching for compute, the benefit of TroVE reduces to a marginal improvement of 1\\%, suggesting that this toolbox approach does not provide a significant benefit on MATH.","published":"2025-07-16T03:11:43Z","updated":"2025-07-31T07:33:11Z","categories":["cs.PL","cs.AI"],"primary_category":"cs.PL","arxiv_url":"https://arxiv.org/abs/2507.22069v2","pdf_url":"https://arxiv.org/pdf/2507.22069v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.11662","versioned_id":"2507.11662v3","title":"Let's Think in Two Steps: Mitigating Agreement Bias in MLLMs with Self-Grounded Verification","authors":["Moises Andrade","Joonhyuk Cha","Brandon Ho","Vriksha Srihari","Karmesh Yadav","Zsolt Kira"],"abstract":"Verifiers--functions assigning rewards to agent behavior--have been key to AI progress in math, code, and games. However, extending gains to domains without clear-cut success criteria remains a challenge: while humans can recognize desired outcomes, translating this intuition into scalable rules is nontrivial. Multimodal LLMs (MLLMs) offer a promising solution, given their world knowledge, human-preference alignment, and reasoning capabilities. We evaluate MLLM verifiers across web navigation, computer use, and robotics, spanning 13+ models, 28+ designs, and thousands of trajectories from diverse agents. We identify a critical limitation: a strong tendency for MLLMs to over-validate agent behavior--a phenomenon we term agreement bias. This bias is pervasive, resilient to test-time scaling, and can harm applications relying on MLLM judgments/rewards (e.g., self-improvement, steering, online supervision). We discuss several considerations for evaluating and designing MLLM verifiers, and introduce SGV, a lightweight method that better leverages their capabilities by modulating (un)conditional generation. First, an MLLM is elicited to generate broad priors about desired behavior, independent of the data under evaluation. Then, conditioned on self-generated priors, it reasons over and evaluates a candidate trajectory. Our methods yield more human-aligned verifiers, improving failure detection by 25pp and accuracy by 14pp. In self-improvement and online supervision, they boost task completion of a GUI specialist in OSWorld, a diffusion policy in robomimic, and a ReAct agent in VisualWebArena--surpassing the previous state of the art by 20pp. As a byproduct, we release an update of VisualWebArena featuring strong agent baselines, more human-aligned oracles, container parallelism with high fidelity and proper resets, >10x speedups, and VWA-Lite, a 1/3 subset with comparable evaluation fidelity.","published":"2025-07-15T18:50:29Z","updated":"2026-03-08T00:45:24Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.11662v3","pdf_url":"https://arxiv.org/pdf/2507.11662v3","comment":"ICLR 2026. Code, models, and data publicly available at https://mshalimay.github.io/agreement-bias-sgv/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.11277","versioned_id":"2507.11277v2","title":"Taming Uncertainty via Automation: Observing, Analyzing, and Optimizing Agentic AI Systems","authors":["Dany Moshkovich","Sergey Zeltyn"],"abstract":"Large Language Models (LLMs) are increasingly deployed within agentic systems - collections of interacting, LLM-powered agents that execute complex, adaptive workflows using memory, tools, and dynamic planning. While enabling powerful new capabilities, these systems also introduce unique forms of uncertainty stemming from probabilistic reasoning, evolving memory states, and fluid execution paths. Traditional software observability and operations practices fall short in addressing these challenges. This paper presents our vision of AgentOps: a comprehensive framework for observing, analyzing, optimizing, and automating operation of agentic AI systems. We identify distinct needs across four key roles - developers, testers, site reliability engineers (SREs), and business users - each of whom engages with the system at different points in its lifecycle. We present the AgentOps Automation Pipeline, a six-stage process encompassing behavior observation, metric collection, issue detection, root cause analysis, optimized recommendations, and runtime automation. Throughout, we emphasize the critical role of automation in managing uncertainty and enabling self-improving AI systems - not by eliminating uncertainty, but by taming it to ensure safe, adaptive, and effective operation.","published":"2025-07-15T12:54:43Z","updated":"2025-11-20T10:41:15Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.11277v2","pdf_url":"https://arxiv.org/pdf/2507.11277v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.10136","versioned_id":"2507.10136v6","title":"A PBN-RL-XAI Framework for Discovering a \"Hit-and-Run\" Therapeutic Strategy in Melanoma","authors":["Zhonglin Liu"],"abstract":"Innate resistance to anti-PD-1 immunotherapy remains a major clinical challenge in metastatic melanoma, with the underlying molecular networks being poorly understood. To address this, we constructed a dynamic Probabilistic Boolean Network model using transcriptomic data from patient tumor biopsies to elucidate the regulatory logic governing therapy response. We then employed a reinforcement learning agent to systematically discover optimal, multi-step therapeutic interventions and used explainable artificial intelligence to mechanistically interpret the agent's control policy. The analysis revealed that a precisely timed, 4-step temporary inhibition of the lysyl oxidase like 2 protein (LOXL2) was the most effective strategy. Our explainable analysis showed that this ''hit-and-run\" intervention is sufficient to erase the molecular signature driving resistance, allowing the network to self-correct without requiring sustained intervention. This study presents a novel, time-dependent therapeutic hypothesis for overcoming immunotherapy resistance and provides a powerful computational framework for identifying non-obvious intervention protocols in complex biological systems.","published":"2025-07-14T10:35:38Z","updated":"2026-02-11T11:49:35Z","categories":["q-bio.QM","cs.AI"],"primary_category":"q-bio.QM","arxiv_url":"https://arxiv.org/abs/2507.10136v6","pdf_url":"https://arxiv.org/pdf/2507.10136v6","comment":"7 pages, 7 figures. Accepted by the IEEE International Conference on Bioinformatics and Biomedicine (BIBM) 2025. Code is available at https://github.com/Liu-Zhonglin/pbn-melanoma-project","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.10628","versioned_id":"2507.10628v2","title":"GHPO: Adaptive Guidance for Stable and Efficient LLM Reinforcement Learning","authors":["Ziru Liu","Cheng Gong","Xinyu Fu","Yaofang Liu","Ran Chen","Shoubo Hu","Suiyun Zhang","Rui Liu","Qingfu Zhang","Dandan Tu"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) has recently emerged as a powerful paradigm for facilitating the self-improvement of large language models (LLMs), particularly in the domain of complex reasoning tasks. However, prevailing on-policy RL methods often contend with significant training instability and inefficiency. This is primarily due to a capacity-difficulty mismatch, where the complexity of training data frequently outpaces the model's current capabilities, leading to critically sparse reward signals and stalled learning progress. This challenge is particularly acute for smaller, more resource-efficient LLMs. To overcome this, we introduce the Guided Hybrid Policy Optimization (GHPO), a novel difficulty-aware reinforcement learning framework. GHPO dynamically calibrates task difficulty by employing adaptive prompt refinement to provide targeted guidance. This unique approach adaptively balances direct imitation learning for problems currently beyond the model's reach with exploration-based reinforcement learning for more manageable tasks, effectively creating a smooth and optimized learning curriculum. Extensive experiments demonstrate that GHPO achieves an average performance gain of approximately 5% across six challenging mathematics benchmarks, consistently outperforming strong on-policy reinforcement learning and curriculum learning baselines. Further analysis confirms that our framework significantly enhances both training stability and final reasoning performance, thus offering a scalable and efficient solution for developing powerful and robust reasoning models.","published":"2025-07-14T08:10:00Z","updated":"2025-07-16T15:30:11Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.10628v2","pdf_url":"https://arxiv.org/pdf/2507.10628v2","comment":"Code avaiable at https://github.com/hkgc-1/GHPO","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.10007","versioned_id":"2507.10007v2","title":"Deep Hidden Cognition Facilitates Reliable Chain-of-Thought Reasoning","authors":["Zijun Chen","Wenbo Hu","Richang Hong"],"abstract":"Chain of Thought (CoT) reasoning has demonstrated remarkable deep reasoning capabilities in both large language models (LLMs) and multimodal large language models (MLLMs). However, its reliability is often undermined by the accumulation of errors in intermediate steps. This paper introduces an novel approach to calibrate the CoT reasoning accuracy by leveraging the model's intrinsic veracity encoding. We discover that specific attention head activations reliably reflect the truthfulness of reasoning steps in CoT. Based on this insight, we train a confidence predictor to evaluate the correctness of each reasoning step using these truthfulness-sensitive activations, dynamically selecting the most plausible reasoning path via beam search. Experimental results demonstrate that our method significantly outperforms the state-of-the-art baselines (e.g., Few-Shot CoT, Self-Consistency, and Self-Evaluation Guided Beam Search) across the mathematical, symbolic, and commonsense reasoning tasks, exhibiting superior accuracy and reliability in both unimodal and multimodal settings. We further validate the approach on large reasoning models, confirming its applicability to specialized reasoning models. Additionally, we explore the role of the model's self-correction ability in CoT reasoning. This work provides a novel reliability improvement path for CoT reasoning with broad application potential.","published":"2025-07-14T07:41:35Z","updated":"2025-11-25T02:54:52Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.10007v2","pdf_url":"https://arxiv.org/pdf/2507.10007v2","comment":"This paper has been accepted by AAAI-26","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.09592","versioned_id":"2507.09592v3","title":"THOR: Transformer Heuristics for On-Demand Retrieval","authors":["Isaac Shi","Zeyuan Li","Fan Liu","Wenli Wang","Lewei He","Yang Yang","Tianyu Shi"],"abstract":"We introduce the THOR (Transformer Heuristics for On-Demand Retrieval) Module, designed and implemented by eSapiens, a secure, scalable engine that transforms natural-language questions into verified, read-only SQL analytics for enterprise databases. The Text-to-SQL module follows a decoupled orchestration/execution architecture: a Supervisor Agent routes queries, Schema Retrieval dynamically injects table and column metadata, and a SQL Generation Agent emits single-statement SELECT queries protected by a read-only guardrail. An integrated Self-Correction & Rating loop captures empty results, execution errors, or low-quality outputs and triggers up to five LLM-driven regeneration attempts. Finally, a Result Interpretation Agent produces concise, human-readable insights and hands raw rows to the Insight & Intelligence engine for visualization or forecasting. Smoke tests across finance, sales, and operations scenarios demonstrate reliable ad-hoc querying and automated periodic reporting. By embedding schema awareness, fault-tolerant execution, and compliance guardrails, the THOR Module empowers non-technical users to access live data with zero-SQL simplicity and enterprise-grade safety.","published":"2025-07-13T11:48:24Z","updated":"2025-07-17T05:47:22Z","categories":["cs.DB","cs.AI"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2507.09592v3","pdf_url":"https://arxiv.org/pdf/2507.09592v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.09374","versioned_id":"2507.09374v1","title":"EduFlow: Advancing MLLMs' Problem-Solving Proficiency through Multi-Stage, Multi-Perspective Critique","authors":["Chenglin Zhu","Tao Zhang","Chong Li","Mingan Lin","Zenan Zhou","Jian Xie"],"abstract":"Multimodal large language models (MLLMs) still perform poorly on scientific tasks, particularly those requiring multi-step and interpretable reasoning. Their limitations include insufficient scientific reasoning patterns, lack of global coherence in multi-step inference, and the absence of reflective self-correction, making them unreliable in structured scientific contexts. We introduce EduFlow, the first end-to-end framework that covers the full pipeline of educational scientific reasoning, including data selection, MCTS-based trajectory construction, model training, and output optimization. At its core is EduPRM, a process-aware reward model that critiques reasoning steps with tags and justifications. EduPRM is trained via curriculum learning on three complementary supervision sources: MCTS-guided trajectories, error-injected critiques, and teacher-student dialogues, enabling dynamic adaptation to multi-stage problem solving and iterative refinement during inference. We further propose EduMCTS, a domain-adapted search framework that introduces bootstrapping actions specifically designed for educational reasoning, such as a self-reflection mechanism that promotes reflective error correction. It further leverages EduPRM's fine-grained feedback to guide the search toward higher-quality reasoning trajectories. By applying self-consistency and rejection sampling, we constructed EduMCTS-160K, a large-scale dataset of educational reasoning trajectories. Extensive experiments demonstrate that EduFlow enhances reasoning consistency and coherence. Code, data, and models will be released.","published":"2025-07-12T18:44:32Z","updated":"2025-07-12T18:44:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.09374v1","pdf_url":"https://arxiv.org/pdf/2507.09374v1","comment":"14 pages,4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.08967","versioned_id":"2507.08967v1","title":"Self-Improving Model Steering","authors":["Rongyi Zhu","Yuhui Wang","Tanqiu Jiang","Jiacheng Liang","Ting Wang"],"abstract":"Model steering represents a powerful technique that dynamically aligns large language models (LLMs) with human preferences during inference. However, conventional model-steering methods rely heavily on externally annotated data, not only limiting their adaptability to varying contexts but also tethering their effectiveness to annotation quality. In this paper, we present SIMS, the first self-improving model-steering framework that operates without relying on external supervision. At its core, SIMS autonomously generates and refines contrastive samples through iterative self-improvement cycles, enabling adaptive, context-specific steering. Additionally, SIMS employs novel strategies, including prompt ranking and contrast sampling, to further enhance steering efficacy. Extensive evaluation across diverse LLMs and benchmarks demonstrates that SIMS substantially outperforms existing methods in steering effectiveness and adaptability, highlighting self-improving model steering as a promising direction for future research on inference-time LLM alignment.","published":"2025-07-11T18:52:32Z","updated":"2025-07-11T18:52:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.08967v1","pdf_url":"https://arxiv.org/pdf/2507.08967v1","comment":"16 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.10590","versioned_id":"2507.10590v1","title":"Repairing Language Model Pipelines by Meta Self-Refining Competing Constraints at Runtime","authors":["Mojtaba Eshghie"],"abstract":"Language Model (LM) pipelines can dynamically refine their outputs against programmatic constraints. However, their effectiveness collapses when faced with competing soft constraints, leading to inefficient backtracking loops where satisfying one constraint violates another. We introduce Meta Self-Refining, a framework that equips LM pipelines with a meta-corrective layer to repair these competitions at runtime/inference-time. Our approach monitors the pipeline's execution history to detect oscillatory failures. Upon detection, it invokes a meta-repairer LM that analyzes the holistic state of the backtracking attempts and synthesizes a strategic instruction to balance the competing requirements. This self-repair instruction guides the original LM out of a failing refining loop towards a successful output. Our results show Meta Self-Refining can successfully repair these loops, leading to more efficient LM programs.","published":"2025-07-11T17:35:12Z","updated":"2025-07-11T17:35:12Z","categories":["cs.SE","cs.AI","cs.IR"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2507.10590v1","pdf_url":"https://arxiv.org/pdf/2507.10590v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.14172","versioned_id":"2507.14172v2","title":"Self-Improving Language Models for Evolutionary Program Synthesis: A Case Study on ARC-AGI","authors":["Julien Pourcel","Cédric Colas","Pierre-Yves Oudeyer"],"abstract":"Many program synthesis tasks prove too challenging for even state-of-the-art language models to solve in single attempts. Search-based evolutionary methods offer a promising alternative by exploring solution spaces iteratively, but their effectiveness remain limited by the fixed capabilities of the underlying generative model. We propose SOAR, a method that learns program synthesis by integrating language models into a self-improving evolutionary loop. SOAR alternates between (1) an evolutionary search that uses an LLM to sample and refine candidate solutions, and (2) a hindsight learning phase that converts search attempts into valid problem-solution pairs used to fine-tune the LLM's sampling and refinement capabilities\\, -- \\,enabling increasingly effective search in subsequent iterations. On the challenging ARC-AGI benchmark, SOAR achieves significant performance gains across model scales and iterations, leveraging positive transfer between the sampling and refinement finetuning tasks. These improvements carry over to test-time adaptation, enabling SOAR to solve 52\\% of the public test set. Our code is open-sourced at: https://github.com/flowersteam/SOAR","published":"2025-07-10T15:42:03Z","updated":"2026-03-16T09:46:14Z","categories":["cs.LG","cs.AI","cs.NE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.14172v2","pdf_url":"https://arxiv.org/pdf/2507.14172v2","comment":"update related work","journal_ref":"Proceedings of the 42 nd International Conference on Machine Learning, Vancouver, Canada. PMLR 267, 2025","doi":"","discovered_on":"2026-07-17"},{"id":"2507.06892","versioned_id":"2507.06892v3","title":"Squeeze the Soaked Sponge: Efficient Off-policy Reinforcement Finetuning for Large Language Model","authors":["Jing Liang","Hongyao Tang","Yi Ma","Jinyi Liu","Yan Zheng","Shuyue Hu","Lei Bai","Jianye Hao"],"abstract":"Reinforcement Learning (RL) has demonstrated its potential to improve the reasoning ability of Large Language Models (LLMs). One major limitation of most existing Reinforcement Finetuning (RFT) methods is that they are on-policy RL in nature, i.e., data generated during the past learning process is not fully utilized. This inevitably comes at a significant cost of compute and time, posing a stringent bottleneck on continuing economic and efficient scaling. To this end, we launch the renaissance of off-policy RL and propose Reincarnating Mix-policy Proximal Policy Gradient (ReMix), a general approach to enable on-policy RFT methods like PPO and GRPO to leverage off-policy data. ReMix consists of three major components: (1) Mix-policy proximal policy gradient with an increased Update-To-Data (UTD) ratio for efficient training; (2) KL-Convex policy constraint to balance the trade-off between stability and flexibility; (3) Policy reincarnation to achieve a seamless transition from efficient early-stage learning to steady asymptotic improvement. In our experiments, we train a series of ReMix models upon PPO, GRPO and 1.5B, 7B base models. ReMix shows an average Pass@1 accuracy of 52.10% (for 1.5B model) with 0.079M response rollouts, 350 training steps and achieves 63.27%/64.39% (for 7B model) with 0.007M/0.011M response rollouts, 50/75 training steps, on five math reasoning benchmarks (i.e., AIME'24, AMC'23, Minerva, OlympiadBench, and MATH500). Compared with 15 recent advanced models, ReMix shows SOTA-level performance with an over 30x to 450x reduction in training cost in terms of rollout data volume. In addition, we reveal insightful findings via multifaceted analysis, including the implicit preference for shorter responses due to the Whipping Effect of off-policy discrepancy, the collapse mode of self-reflection behavior under the presence of severe off-policyness, etc.","published":"2025-07-09T14:29:45Z","updated":"2025-07-11T10:32:34Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.06892v3","pdf_url":"https://arxiv.org/pdf/2507.06892v3","comment":"Preliminary version, v3, added the missing name of x-axis in the left part of Fig.1 and corrected a wrong number in Fig.3. Project page: https://anitaleungxx.github.io/ReMix","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.06701","versioned_id":"2507.06701v1","title":"Value from Observations: Towards Large-Scale Imitation Learning via Self-Improvement","authors":["Michael Bloesch","Markus Wulfmeier","Philemon Brakel","Todor Davchev","Martina Zambelli","Jost Tobias Springenberg","Abbas Abdolmaleki","William F Whitney","Nicolas Heess","Roland Hafner","Martin Riedmiller"],"abstract":"Imitation Learning from Observation (IfO) offers a powerful way to learn behaviors at large-scale: Unlike behavior cloning or offline reinforcement learning, IfO can leverage action-free demonstrations and thus circumvents the need for costly action-labeled demonstrations or reward functions. However, current IfO research focuses on idealized scenarios with mostly bimodal-quality data distributions, restricting the meaningfulness of the results. In contrast, this paper investigates more nuanced distributions and introduces a method to learn from such data, moving closer to a paradigm in which imitation learning can be performed iteratively via self-improvement. Our method adapts RL-based imitation learning to action-free demonstrations, using a value function to transfer information between expert and non-expert data. Through comprehensive evaluation, we delineate the relation between different data distributions and the applicability of algorithms and highlight the limitations of established methods. Our findings provide valuable insights for developing more robust and practical IfO techniques on a path to scalable behaviour learning.","published":"2025-07-09T09:55:23Z","updated":"2025-07-09T09:55:23Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.06701v1","pdf_url":"https://arxiv.org/pdf/2507.06701v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.06419","versioned_id":"2507.06419v3","title":"Teach a Reward Model to Correct Itself: Reward Guided Adversarial Failure Discovery for Robust Reward Modeling","authors":["Pankayaraj Pathmanathan","Furong Huang"],"abstract":"Reward modeling (RM), which captures human preferences to align large language models (LLMs), is increasingly employed in tasks such as model finetuning, response filtering, and ranking. However, due to the inherent complexity of human preferences and the limited coverage of available datasets, reward models often fail under distributional shifts or adversarial perturbations. Existing approaches for identifying such failure modes typically rely on prior knowledge about preference distributions or failure attributes, limiting their practicality in real-world settings where such information is unavailable. In this work, we propose a tractable, preference-distribution agnostic method for discovering reward model failure modes via reward guided controlled decoding. Building on this, we introduce REFORM, a self-improving reward modeling framework that enhances robustness by using the reward model itself to guide the generation of falsely scored responses. These adversarial examples are then used to augment the training data and patch the reward model's misaligned behavior. We evaluate REFORM on two widely used preference datasets Anthropic Helpful Harmless (HH) and PKU Beavertails and demonstrate that it significantly improves robustness without sacrificing reward quality. Notably, REFORM preserves performance both in direct evaluation and in downstream policy training, and further improves alignment quality by removing spurious correlations.","published":"2025-07-08T21:56:33Z","updated":"2026-06-04T20:44:16Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.06419v3","pdf_url":"https://arxiv.org/pdf/2507.06419v3","comment":"","journal_ref":"ACL 2026 Main Conference [Oral]","doi":"","discovered_on":"2026-07-17"},{"id":"2507.06192","versioned_id":"2507.06192v2","title":"SQLBarber: A System Leveraging Large Language Models to Generate Customized and Realistic SQL Workloads","authors":["Jiale Lao","Immanuel Trummer"],"abstract":"Database research and development often require a large number of SQL queries for benchmarking purposes. However, acquiring real-world SQL queries is challenging due to privacy concerns, and existing SQL generation methods are limited in customization and in satisfying realistic constraints. To address this issue, we present SQLBarber, a system based on Large Language Models (LLMs) to generate customized and realistic SQL workloads. SQLBarber (i) eliminates the need for users to manually craft SQL templates in advance, while providing the flexibility to accept natural language specifications to constrain SQL templates, (ii) scales efficiently to generate large volumes of queries matching any user-defined cost distribution (e.g., cardinality and execution plan cost), and (iii) uses execution statistics from Amazon Redshift and Snowflake to derive SQL template specifications and query cost distributions that reflect real-world query characteristics. SQLBarber introduces (i) a declarative interface for users to effortlessly generate customized SQL templates, (ii) an LLM-powered pipeline augmented with a self-correction module that profiles, refines, and prunes SQL templates based on query costs, and (iii) a Bayesian Optimizer to efficiently explore different predicate values and identify a set of queries that satisfy the target cost distribution. We construct and open-source ten benchmarks of varying difficulty levels and target query cost distributions based on real-world statistics from Snowflake and Amazon Redshift. Extensive experiments on these benchmarks show that SQLBarber is the only system that can generate customized SQL templates. It reduces query generation time by one to three orders of magnitude, and significantly improves alignment with the target cost distribution, compared with existing methods.","published":"2025-07-08T17:20:34Z","updated":"2025-12-02T02:58:55Z","categories":["cs.DB","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2507.06192v2","pdf_url":"https://arxiv.org/pdf/2507.06192v2","comment":"Accepted by SIGMOD 2026; extended version with appendix","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.06138","versioned_id":"2507.06138v1","title":"Coding Triangle: How Does Large Language Model Understand Code?","authors":["Taolin Zhang","Zihan Ma","Maosong Cao","Junnan Liu","Songyang Zhang","Kai Chen"],"abstract":"Large language models (LLMs) have achieved remarkable progress in code generation, yet their true programming competence remains underexplored. We introduce the Code Triangle framework, which systematically evaluates LLMs across three fundamental dimensions: editorial analysis, code implementation, and test case generation. Through extensive experiments on competitive programming benchmarks, we reveal that while LLMs can form a self-consistent system across these dimensions, their solutions often lack the diversity and robustness of human programmers. We identify a significant distribution shift between model cognition and human expertise, with model errors tending to cluster due to training data biases and limited reasoning transfer. Our study demonstrates that incorporating human-generated editorials, solutions, and diverse test cases, as well as leveraging model mixtures, can substantially enhance both the performance and robustness of LLMs. Furthermore, we reveal both the consistency and inconsistency in the cognition of LLMs that may facilitate self-reflection and self-improvement, providing a potential direction for developing more powerful coding models.","published":"2025-07-08T16:20:43Z","updated":"2025-07-08T16:20:43Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.06138v1","pdf_url":"https://arxiv.org/pdf/2507.06138v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.05755","versioned_id":"2507.05755v1","title":"An autonomous agent for auditing and improving the reliability of clinical AI models","authors":["Lukas Kuhn","Florian Buettner"],"abstract":"The deployment of AI models in clinical practice faces a critical challenge: models achieving expert-level performance on benchmarks can fail catastrophically when confronted with real-world variations in medical imaging. Minor shifts in scanner hardware, lighting or demographics can erode accuracy, but currently reliability auditing to identify such catastrophic failure cases before deployment is a bespoke and time-consuming process. Practitioners lack accessible and interpretable tools to expose and repair hidden failure modes. Here we introduce ModelAuditor, a self-reflective agent that converses with users, selects task-specific metrics, and simulates context-dependent, clinically relevant distribution shifts. ModelAuditor then generates interpretable reports explaining how much performance likely degrades during deployment, discussing specific likely failure modes and identifying root causes and mitigation strategies. Our comprehensive evaluation across three real-world clinical scenarios - inter-institutional variation in histopathology, demographic shifts in dermatology, and equipment heterogeneity in chest radiography - demonstrates that ModelAuditor is able correctly identify context-specific failure modes of state-of-the-art models such as the established SIIM-ISIC melanoma classifier. Its targeted recommendations recover 15-25% of performance lost under real-world distribution shift, substantially outperforming both baseline models and state-of-the-art augmentation methods. These improvements are achieved through a multi-agent architecture and execute on consumer hardware in under 10 minutes, costing less than US$0.50 per audit.","published":"2025-07-08T07:58:52Z","updated":"2025-07-08T07:58:52Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.05755v1","pdf_url":"https://arxiv.org/pdf/2507.05755v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.04708","versioned_id":"2507.04708v1","title":"Why We Feel What We Feel: Joint Detection of Emotions and Their Opinion Triggers in E-commerce","authors":["Arnav Attri","Anuj Attri","Pushpak Bhattacharyya","Suman Banerjee","Amey Patil","Muthusamy Chelliah","Nikesh Garera"],"abstract":"Customer reviews on e-commerce platforms capture critical affective signals that drive purchasing decisions. However, no existing research has explored the joint task of emotion detection and explanatory span identification in e-commerce reviews - a crucial gap in understanding what triggers customer emotional responses. To bridge this gap, we propose a novel joint task unifying Emotion detection and Opinion Trigger extraction (EOT), which explicitly models the relationship between causal text spans (opinion triggers) and affective dimensions (emotion categories) grounded in Plutchik's theory of 8 primary emotions. In the absence of labeled data, we introduce EOT-X, a human-annotated collection of 2,400 reviews with fine-grained emotions and opinion triggers. We evaluate 23 Large Language Models (LLMs) and present EOT-DETECT, a structured prompting framework with systematic reasoning and self-reflection. Our framework surpasses zero-shot and chain-of-thought techniques, across e-commerce domains.","published":"2025-07-07T06:59:37Z","updated":"2025-07-07T06:59:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.04708v1","pdf_url":"https://arxiv.org/pdf/2507.04708v1","comment":"23 pages, 11 figures, 7 tables. Dataset and code will be made publicly available","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.05302","versioned_id":"2507.05302v1","title":"CorrDetail: Visual Detail Enhanced Self-Correction for Face Forgery Detection","authors":["Binjia Zhou","Hengrui Lou","Lizhe Chen","Haoyuan Li","Dawei Luo","Shuai Chen","Jie Lei","Zunlei Feng","Yijun Bei"],"abstract":"With the swift progression of image generation technology, the widespread emergence of facial deepfakes poses significant challenges to the field of security, thus amplifying the urgent need for effective deepfake detection.Existing techniques for face forgery detection can broadly be categorized into two primary groups: visual-based methods and multimodal approaches. The former often lacks clear explanations for forgery details, while the latter, which merges visual and linguistic modalities, is more prone to the issue of hallucinations.To address these shortcomings, we introduce a visual detail enhanced self-correction framework, designated CorrDetail, for interpretable face forgery detection. CorrDetail is meticulously designed to rectify authentic forgery details when provided with error-guided questioning, with the aim of fostering the ability to uncover forgery details rather than yielding hallucinated responses. Additionally, to bolster the reliability of its findings, a visual fine-grained detail enhancement module is incorporated, supplying CorrDetail with more precise visual forgery details. Ultimately, a fusion decision strategy is devised to further augment the model's discriminative capacity in handling extreme samples, through the integration of visual information compensation and model bias reduction.Experimental results demonstrate that CorrDetail not only achieves state-of-the-art performance compared to the latest methodologies but also excels in accurately identifying forged details, all while exhibiting robust generalization capabilities.","published":"2025-07-07T06:29:57Z","updated":"2025-07-07T06:29:57Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2507.05302v1","pdf_url":"https://arxiv.org/pdf/2507.05302v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.04625","versioned_id":"2507.04625v1","title":"Knowledge-Aware Self-Correction in Language Models via Structured Memory Graphs","authors":["Swayamjit Saha"],"abstract":"Large Language Models (LLMs) are powerful yet prone to generating factual errors, commonly referred to as hallucinations. We present a lightweight, interpretable framework for knowledge-aware self-correction of LLM outputs using structured memory graphs based on RDF triples. Without retraining or fine-tuning, our method post-processes model outputs and corrects factual inconsistencies via external semantic memory. We demonstrate the approach using DistilGPT-2 and show promising results on simple factual prompts.","published":"2025-07-07T02:55:12Z","updated":"2025-07-07T02:55:12Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.04625v1","pdf_url":"https://arxiv.org/pdf/2507.04625v1","comment":"8 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.04391","versioned_id":"2507.04391v1","title":"Does Learning Mathematical Problem-Solving Generalize to Broader Reasoning?","authors":["Ruochen Zhou","Minrui Xu","Shiqi Chen","Junteng Liu","Yunqi Li","Xinxin Lin","Zhengyu Chen","Junxian He"],"abstract":"There has been a growing interest in enhancing the mathematical problem-solving (MPS) capabilities of large language models. While the majority of research efforts concentrate on creating specialized models to solve mathematical problems, it remains unknown how learning mathematical problem-solving generalizes to help develop other reasoning abilities. In this paper, we present an empirical investigation into the generalization potential of various MPS training approaches, such as continual pretraining, instruction tuning, and rule-based reinforcement learning across various data sources, including both short and long chain-of-thought (CoT) samples. Evaluation on 5 mathematical and 8 general reasoning benchmarks show that continual pretraining on math text is able to generalize to general reasoning tasks to some extent. In constrast, instruction tuning on conventional, short MPS samples provides limited benefits and, in many cases, even impairs generalization performance. Notably, training with long CoT responses for MPS samples and incorporating rule-based reinforcement learning on MPS queries exhibit distinct behavior, significantly enhancing generalization by extending the model's reasoning processes into other domains. These results suggest that traditional approaches to learning MPS with short reasoning chains largely fail to achieve robust generalization. However, the emerging paradigm of longer reasoning chains, coupled with self-reflection, offers a promising direction for improving generalized reasoning abilities through learning from specialized domains.","published":"2025-07-06T13:47:55Z","updated":"2025-07-06T13:47:55Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.04391v1","pdf_url":"https://arxiv.org/pdf/2507.04391v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.04370","versioned_id":"2507.04370v1","title":"WebSynthesis: World-Model-Guided MCTS for Efficient WebUI-Trajectory Synthesis","authors":["Yifei Gao","Junhong Ye","Jiaqi Wang","Jitao Sang"],"abstract":"Recent advancements in large language models (LLMs) have significantly improved the capabilities of web agents. However, effectively navigating complex and dynamic web environments still requires more advanced trajectory-level planning and execution. Prior studies have addressed self-improving agents by collecting extensive GUI trajectories from real-environment interactions. Despite their effectiveness, these approaches encounter two critical challenges: (1) Uncontrollable environment states, where real or sandboxed web environments often yield unstable and non-deterministic feedback, complicating the reproduction and debugging of agent behaviors; and (2) High API costs, as generating even a single interaction trajectory can involve hundreds of queries, leading to considerable API usage and computational expenses. To address these limitations and enable scalable self-improvement for agents, we propose WebSynthesis, a novel framework for trajectory synthesis and training. WebSynthesis leverages a learned world model to simulate virtual web environments, allowing a policy agent to perform efficient and reversible tree-based planning. This approach supports the large-scale generation of diverse and high-quality trajectories, which are subsequently utilized to refine the agent's policy. Experimental results demonstrate that an agent trained using WebSynthesis on a small-scale synthetic dataset achieves performance comparable to or even surpassing that of models trained on large-scale real-world data.","published":"2025-07-06T12:31:10Z","updated":"2025-07-06T12:31:10Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.04370v1","pdf_url":"https://arxiv.org/pdf/2507.04370v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.05288","versioned_id":"2507.05288v1","title":"A Survey on Proactive Defense Strategies Against Misinformation in Large Language Models","authors":["Shuliang Liu","Hongyi Liu","Aiwei Liu","Bingchen Duan","Qi Zheng","Yibo Yan","He Geng","Peijie Jiang","Jia Liu","Xuming Hu"],"abstract":"The widespread deployment of large language models (LLMs) across critical domains has amplified the societal risks posed by algorithmically generated misinformation. Unlike traditional false content, LLM-generated misinformation can be self-reinforcing, highly plausible, and capable of rapid propagation across multiple languages, which traditional detection methods fail to mitigate effectively. This paper introduces a proactive defense paradigm, shifting from passive post hoc detection to anticipatory mitigation strategies. We propose a Three Pillars framework: (1) Knowledge Credibility, fortifying the integrity of training and deployed data; (2) Inference Reliability, embedding self-corrective mechanisms during reasoning; and (3) Input Robustness, enhancing the resilience of model interfaces against adversarial attacks. Through a comprehensive survey of existing techniques and a comparative meta-analysis, we demonstrate that proactive defense strategies offer up to 63\\% improvement over conventional methods in misinformation prevention, despite non-trivial computational overhead and generalization challenges. We argue that future research should focus on co-designing robust knowledge foundations, reasoning certification, and attack-resistant interfaces to ensure LLMs can effectively counter misinformation across varied domains.","published":"2025-07-05T09:52:21Z","updated":"2025-07-05T09:52:21Z","categories":["cs.IR","cs.AI","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2507.05288v1","pdf_url":"https://arxiv.org/pdf/2507.05288v1","comment":"Accepted by ACL 2025 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.08828","versioned_id":"2507.08828v1","title":"Recurrent Expansion: A Pathway Toward the Next Generation of Deep Learning","authors":["Tarek Berghout"],"abstract":"This paper introduces Recurrent Expansion (RE) as a new learning paradigm that advances beyond conventional Machine Learning (ML) and Deep Learning (DL). While DL focuses on learning from static data representations, RE proposes an additional dimension: learning from the evolving behavior of models themselves. RE emphasizes multiple mappings of data through identical deep architectures and analyzes their internal representations (i.e., feature maps) in conjunction with observed performance signals such as loss. By incorporating these behavioral traces, RE enables iterative self-improvement, allowing each model version to gain insight from its predecessors. The framework is extended through Multiverse RE (MVRE), which aggregates signals from parallel model instances, and further through Heterogeneous MVRE (HMVRE), where models of varying architectures contribute diverse perspectives. A scalable and adaptive variant, Sc-HMVRE, introduces selective mechanisms and scale diversity for real-world deployment. Altogether, RE presents a shift in DL: from purely representational learning to behavior-aware, self-evolving systems. It lays the groundwork for a new class of intelligent models capable of reasoning over their own learning dynamics, offering a path toward scalable, introspective, and adaptive artificial intelligence. A simple code example to support beginners in running their own experiments is provided in Code Availability Section of this paper.","published":"2025-07-04T19:26:48Z","updated":"2025-07-04T19:26:48Z","categories":["cs.LG","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.08828v1","pdf_url":"https://arxiv.org/pdf/2507.08828v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.03732","versioned_id":"2507.03732v2","title":"Transforming Calabi-Yau Constructions: Generating New Calabi-Yau Manifolds with Transformers","authors":["Jacky H. T. Yip","Charles Arnal","François Charton","Gary Shiu"],"abstract":"Fine, regular, and star triangulations (FRSTs) of four-dimensional reflexive polytopes give rise to toric varieties, within which generic anticanonical hypersurfaces yield smooth Calabi-Yau threefolds. We introduce CYTransformer, a deep learning model based on the transformer architecture, to automate the generation of FRSTs. We demonstrate that CYTransformer efficiently and unbiasedly samples FRSTs for polytopes across a range of sizes, and can self-improve through retraining on its own output. These results lay the foundation for AICY: a community-driven platform designed to combine self-improving machine learning models with a continuously expanding database to explore and catalog the Calabi-Yau landscape.","published":"2025-07-04T17:42:04Z","updated":"2025-11-13T17:41:20Z","categories":["hep-th","cs.LG","math.AG"],"primary_category":"hep-th","arxiv_url":"https://arxiv.org/abs/2507.03732v2","pdf_url":"https://arxiv.org/pdf/2507.03732v2","comment":"43 pages, 17 figures, 1 table","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.03620","versioned_id":"2507.03620v1","title":"Is It Time To Treat Prompts As Code? A Multi-Use Case Study For Prompt Optimization Using DSPy","authors":["Francisca Lemos","Victor Alves","Filipa Ferraz"],"abstract":"Although prompt engineering is central to unlocking the full potential of Large Language Models (LLMs), crafting effective prompts remains a time-consuming trial-and-error process that relies on human intuition. This study investigates Declarative Self-improving Python (DSPy), an optimization framework that programmatically creates and refines prompts, applied to five use cases: guardrail enforcement, hallucination detection in code, code generation, routing agents, and prompt evaluation. Each use case explores how prompt optimization via DSPy influences performance. While some cases demonstrated modest improvements - such as minor gains in the guardrails use case and selective enhancements in hallucination detection - others showed notable benefits. The prompt evaluation criterion task demonstrated a substantial performance increase, rising accuracy from 46.2% to 64.0%. In the router agent case, the possibility of improving a poorly performing prompt and of a smaller model matching a stronger one through optimized prompting was explored. Although prompt refinement increased accuracy from 85.0% to 90.0%, using the optimized prompt with a cheaper model did not improve performance. Overall, this study's findings suggest that DSPy's systematic prompt optimization can enhance LLM performance, particularly when instruction tuning and example selection are optimized together. However, the impact varies by task, highlighting the importance of evaluating specific use cases in prompt optimization research.","published":"2025-07-04T14:46:56Z","updated":"2025-07-04T14:46:56Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2507.03620v1","pdf_url":"https://arxiv.org/pdf/2507.03620v1","comment":"20 pages with 1 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.02834","versioned_id":"2507.02834v3","title":"ExPO: Unlocking Hard Reasoning with Self-Explanation-Guided Reinforcement Learning","authors":["Ruiyang Zhou","Shuozhe Li","Amy Zhang","Liu Leqi"],"abstract":"Self-improvement via RL often fails on complex reasoning tasks because GRPO-style post-training methods rely on the model's initial ability to generate positive samples. Without guided exploration, these approaches merely reinforce what the model already knows (distribution-sharpening) rather than enabling the model to solve problems where it initially generates no correct solutions. To unlock reasoning ability in such settings, the model must explore new reasoning trajectories beyond its current output distribution. Such exploration requires access to sufficiently good positive samples to guide the learning. While expert demonstrations seem like a natural solution, we find that they are often ineffective in RL post-training. Instead, we identify two key properties of effective positive samples: they should (1) be likely under the current policy, and (2) increase the model's likelihood of predicting the correct answer. Based on these insights, we propose $\\textbf{Self-Explanation Policy Optimization (ExPO)}$-a simple and modular framework that generates such samples by conditioning on the ground-truth answer. It can be integrated with popular RL training methods like GRPO and DPO. ExPO enables efficient exploration and guides the model to produce reasoning trajectories more aligned with its policy than expert-written CoTs, while ensuring higher quality than its own (incorrect) samples. Experiments show that ExPO improves both learning efficiency and final performance on reasoning benchmarks, surpassing expert-demonstration-based methods in challenging settings such as MATH level-5, where the model initially struggles the most. Code is available at https://github.com/HumainLab/ExPO_rl_reasoning_by_explanation .","published":"2025-07-03T17:44:55Z","updated":"2026-01-26T19:36:48Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.02834v3","pdf_url":"https://arxiv.org/pdf/2507.02834v3","comment":"Accepted to NeurIPS 2025 (Poster). Code available at https://github.com/HumainLab/ExPO_rl_reasoning_by_explanation","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.02778","versioned_id":"2507.02778v2","title":"Self-Correction Bench: Uncovering and Addressing the Self-Correction Blind Spot in Large Language Models","authors":["Ken Tsui"],"abstract":"Although large language models (LLMs) have transformed AI, they still make mistakes and can explore unproductive reasoning paths. Self-correction capability is essential for deploying LLMs in safety-critical applications. We uncover a systematic failure: LLMs cannot correct errors in their own outputs while successfully correcting identical errors from external sources - a limitation we term the Self-Correction Blind Spot. To study this phenomenon, we introduce Self-Correction Bench, an evaluation framework to measure this phenomenon through controlled error injection at three complexity levels. Testing 14 open-source non-reasoning models, we find an average 64.5% blind spot rate. We provide multiple lines of evidence suggesting this limitation may be influenced by training data: human demonstrations rarely include error-correction sequences (favoring error-free responses), whereas reinforcement learning (RL) trained models learn error correction via outcome feedback. Remarkably, appending a minimal \"Wait\" prompt activates a 89.3% reduction in blind spots, suggesting dormant capabilities that require triggering. Our work highlights a critical limitation potentially influenced by training distribution and offers a practical approach to enhance LLM reliability and trustworthiness - vital for safety-critical domains.","published":"2025-07-03T16:41:30Z","updated":"2025-10-04T08:57:59Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.02778v2","pdf_url":"https://arxiv.org/pdf/2507.02778v2","comment":"26 pages, 16 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.02660","versioned_id":"2507.02660v1","title":"Hey AI, Generate Me a Hardware Code! Agentic AI-based Hardware Design & Verification","authors":["Deepak Narayan Gadde","Keerthan Kopparam Radhakrishna","Vaisakh Naduvodi Viswambharan","Aman Kumar","Djones Lettnin","Wolfgang Kunz","Sebastian Simon"],"abstract":"Modern Integrated Circuits (ICs) are becoming increasingly complex, and so is their development process. Hardware design verification entails a methodical and disciplined approach to the planning, development, execution, and sign-off of functionally correct hardware designs. This tedious process requires significant effort and time to ensure a bug-free tape-out. The field of Natural Language Processing has undergone a significant transformation with the advent of Large Language Models (LLMs). These powerful models, often referred to as Generative AI (GenAI), have revolutionized how machines understand and generate human language, enabling unprecedented advancements in a wide array of applications, including hardware design verification. This paper presents an agentic AI-based approach to hardware design verification, which empowers AI agents, in collaboration with Humain-in-the-Loop (HITL) intervention, to engage in a more dynamic, iterative, and self-reflective process, ultimately performing end-to-end hardware design and verification. This methodology is evaluated on five open-source designs, achieving over 95% coverage with reduced verification time while demonstrating superior performance, adaptability, and configurability.","published":"2025-07-03T14:20:57Z","updated":"2025-07-03T14:20:57Z","categories":["cs.AI","cs.AR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.02660v1","pdf_url":"https://arxiv.org/pdf/2507.02660v1","comment":"To appear at the 38th SBC/SBMicro/IEEE Symposium on Integrated Circuits and Systems Design (SBCCI), August 25-29, 2025, Manaus, BRAZIL","journal_ref":"","doi":"10.1109/SBCCI66862.2025.11218681","discovered_on":"2026-07-17"},{"id":"2507.02529","versioned_id":"2507.02529v2","title":"RetrySQL: text-to-SQL training with retry data for self-correcting query generation","authors":["Alicja Rączkowska","Riccardo Belluzzo","Piotr Zieliński","Joanna Baran","Paweł Olszewski"],"abstract":"The text-to-SQL task is an active challenge in Natural Language Processing. Many existing solutions focus on using black-box language models extended with specialized components within customized end-to-end text-to-SQL pipelines. While these solutions use both closed-source proprietary language models and coding-oriented open-source models, there is a lack of research regarding SQL-specific generative models. At the same time, recent advancements in self-correcting generation strategies show promise for improving the capabilities of existing architectures. The application of these concepts to the text-to-SQL task remains unexplored. In this paper, we introduce RetrySQL, a new approach to training text-to-SQL generation models. We prepare reasoning steps for reference SQL queries and then corrupt them to create retry data that contains both incorrect and corrected steps, divided with a special token. We continuously pre-train an open-source coding model with this data and demonstrate that retry steps yield an improvement of up to 4 percentage points in both overall and challenging execution accuracy metrics, compared to pre-training without retry data. Additionally, we confirm that supervised fine-tuning with LoRA is ineffective for learning from retry data and that full-parameter pre-training is a necessary requirement for that task. We showcase that the self-correcting behavior is learned by the model and the increase in downstream accuracy metrics is a result of this additional skill. Finally, we incorporate RetrySQL-trained models into the full text-to-SQL pipeline and showcase that they are competitive in terms of execution accuracy with proprietary models that contain orders of magnitude more parameters. RetrySQL demonstrates that self-correction can be learned in the text-to-SQL task and provides a novel way of improving generation accuracy for SQL-oriented language models.","published":"2025-07-03T11:00:49Z","updated":"2025-11-14T13:51:45Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.02529v2","pdf_url":"https://arxiv.org/pdf/2507.02529v2","comment":"AAAI 2026 Camera-ready version","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.02353","versioned_id":"2507.02353v1","title":"OMS: On-the-fly, Multi-Objective, Self-Reflective Ad Keyword Generation via LLM Agent","authors":["Bowen Chen","Zhao Wang","Shingo Takamatsu"],"abstract":"Keyword decision in Sponsored Search Advertising is critical to the success of ad campaigns. While LLM-based methods offer automated keyword generation, they face three major limitations: reliance on large-scale query-keyword pair data, lack of online multi-objective performance monitoring and optimization, and weak quality control in keyword selection. These issues hinder the agentic use of LLMs in fully automating keyword decisions by monitoring and reasoning over key performance indicators such as impressions, clicks, conversions, and CTA effectiveness. To overcome these challenges, we propose OMS, a keyword generation framework that is On-the-fly (requires no training data, monitors online performance, and adapts accordingly), Multi-objective (employs agentic reasoning to optimize keywords based on multiple performance metrics), and Self-reflective (agentically evaluates keyword quality). Experiments on benchmarks and real-world ad campaigns show that OMS outperforms existing methods; ablation and human evaluations confirm the effectiveness of each component and the quality of generated keywords.","published":"2025-07-03T06:37:55Z","updated":"2025-07-03T06:37:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.02353v1","pdf_url":"https://arxiv.org/pdf/2507.02353v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.01599","versioned_id":"2507.01599v1","title":"Data Agent: A Holistic Architecture for Orchestrating Data+AI Ecosystems","authors":["Zhaoyan Sun","Jiayi Wang","Xinyang Zhao","Jiachi Wang","Guoliang Li"],"abstract":"Traditional Data+AI systems utilize data-driven techniques to optimize performance, but they rely heavily on human experts to orchestrate system pipelines, enabling them to adapt to changes in data, queries, tasks, and environments. For instance, while there are numerous data science tools available, developing a pipeline planning system to coordinate these tools remains challenging. This difficulty arises because existing Data+AI systems have limited capabilities in semantic understanding, reasoning, and planning. Fortunately, we have witnessed the success of large language models (LLMs) in enhancing semantic understanding, reasoning, and planning abilities. It is crucial to incorporate LLM techniques to revolutionize data systems for orchestrating Data+AI applications effectively. To achieve this, we propose the concept of a 'Data Agent' - a comprehensive architecture designed to orchestrate Data+AI ecosystems, which focuses on tackling data-related tasks by integrating knowledge comprehension, reasoning, and planning capabilities. We delve into the challenges involved in designing data agents, such as understanding data/queries/environments/tools, orchestrating pipelines/workflows, optimizing and executing pipelines, and fostering pipeline self-reflection. Furthermore, we present examples of data agent systems, including a data science agent, data analytics agents (such as unstructured data analytics agent, semantic structured data analytics agent, data lake analytics agent, and multi-modal data analytics agent), and a database administrator (DBA) agent. We also outline several open challenges associated with designing data agent systems.","published":"2025-07-02T11:04:49Z","updated":"2025-07-02T11:04:49Z","categories":["cs.DB","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2507.01599v1","pdf_url":"https://arxiv.org/pdf/2507.01599v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.00985","versioned_id":"2507.00985v2","title":"Discourse Heuristics For Paradoxically Moral Self-Correction","authors":["Guangliang Liu","Zimo Qi","Xitong Zhang","Kristen Marie Johnson"],"abstract":"Moral self-correction has emerged as a promising approach for aligning the output of Large Language Models (LLMs) with human moral values. However, moral self-correction techniques are subject to two primary paradoxes. First, despite empirical and theoretical evidence to support the effectiveness of self-correction, this LLM capability only operates at a superficial level. Second, while LLMs possess the capability of self-diagnosing immoral aspects of their output, they struggle to identify the cause of this moral inconsistency during their self-correction process. To better understand and address these paradoxes, we analyze the discourse constructions in fine-tuning corpora designed to enhance moral self-correction, uncovering the existence of the heuristics underlying effective constructions. We demonstrate that moral self-correction relies on discourse constructions that reflect heuristic shortcuts, and that the presence of these heuristic shortcuts during self-correction leads to inconsistency when attempting to enhance both self-correction and self-diagnosis capabilities jointly. Based on our findings, we propose a solution to improve moral self-correction by leveraging the heuristics of curated datasets. We also highlight the generalization challenges of this capability, particularly in terms of learning from situated context and model scales.","published":"2025-07-01T17:36:41Z","updated":"2025-11-02T16:52:20Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.00985v2","pdf_url":"https://arxiv.org/pdf/2507.00985v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.00951","versioned_id":"2507.00951v3","title":"Thinking Beyond Tokens: From Brain-Inspired Intelligence to Cognitive Foundations for Artificial General Intelligence and its Societal Impact","authors":["Rizwan Qureshi","Ranjan Sapkota","Abbas Shah","Amgad Muneer","Anas Zafar","Ashmal Vayani","Maged Shoman","Abdelrahman B. M. Eldaly","Kai Zhang","Ferhat Sadak","Shaina Raza","Xinqi Fan","Ravid Shwartz-Ziv","Hong Yan","Vinjia Jain","Aman Chadha","Manoj Karkee","Jia Wu","Seyedali Mirjalili"],"abstract":"Can machines truly think, reason and act in domains like humans? This enduring question continues to shape the pursuit of Artificial General Intelligence (AGI). Despite the growing capabilities of models such as GPT-4.5, DeepSeek, Claude 3.5 Sonnet, Phi-4, and Grok 3, which exhibit multimodal fluency and partial reasoning, these systems remain fundamentally limited by their reliance on token-level prediction and lack of grounded agency. This paper offers a cross-disciplinary synthesis of AGI development, spanning artificial intelligence, cognitive neuroscience, psychology, generative models, and agent-based systems. We analyze the architectural and cognitive foundations of general intelligence, highlighting the role of modular reasoning, persistent memory, and multi-agent coordination. In particular, we emphasize the rise of Agentic RAG frameworks that combine retrieval, planning, and dynamic tool use to enable more adaptive behavior. We discuss generalization strategies, including information compression, test-time adaptation, and training-free methods, as critical pathways toward flexible, domain-agnostic intelligence. Vision-Language Models (VLMs) are reexamined not just as perception modules but as evolving interfaces for embodied understanding and collaborative task completion. We also argue that true intelligence arises not from scale alone but from the integration of memory and reasoning: an orchestration of modular, interactive, and self-improving components where compression enables adaptive behavior. Drawing on advances in neurosymbolic systems, reinforcement learning, and cognitive scaffolding, we explore how recent architectures begin to bridge the gap between statistical learning and goal-directed cognition. Finally, we identify key scientific, technical, and ethical challenges on the path to AGI.","published":"2025-07-01T16:52:25Z","updated":"2025-07-12T02:50:17Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.00951v3","pdf_url":"https://arxiv.org/pdf/2507.00951v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.00417","versioned_id":"2507.00417v1","title":"ASTRO: Teaching Language Models to Reason by Reflecting and Backtracking In-Context","authors":["Joongwon Kim","Anirudh Goyal","Liang Tan","Hannaneh Hajishirzi","Srinivasan Iyer","Tianlu Wang"],"abstract":"We introduce ASTRO, the \"Autoregressive Search-Taught Reasoner\", a framework for training language models to reason like search algorithms, explicitly leveraging self-reflection, backtracking, and exploration in their outputs. Recently, training large language models (LLMs) via reinforcement learning (RL) has led to the advent of reasoning models with greatly enhanced reasoning capabilities. Open-source replications of reasoning models, while successful, build upon models that already exhibit strong reasoning capabilities along with search behavior observed even before RL. As a result, it is yet unclear how to boost the reasoning capabilities of other non-reasoner models including Llama 3. ASTRO teaches such models to internalize structured search behavior through a synthetic dataset derived from Monte Carlo Tree Search (MCTS) over mathematical problem-solving trajectories. By converting search traces into natural language chain-of-thoughts that capture both successes and recoveries from failure, ASTRO bootstraps models with a rich prior for exploration during RL. We finetune our models on these search-derived traces and further improve performance via RL with verifiable rewards. We apply ASTRO to the Llama 3 family of models and achieve absolute performance gains of 16.0% on MATH-500, 26.9% on AMC 2023, and 20.0% on AIME 2024, especially improving upon challenging problems that require iterative correction. Our results demonstrate that search-inspired training offers a principled way to instill robust reasoning capabilities into open LLMs.","published":"2025-07-01T04:10:15Z","updated":"2025-07-01T04:10:15Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.00417v1","pdf_url":"https://arxiv.org/pdf/2507.00417v1","comment":"36 pages, 23 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.23888","versioned_id":"2506.23888v1","title":"Advancing Multi-Step Mathematical Reasoning in Large Language Models through Multi-Layered Self-Reflection with Auto-Prompting","authors":["André de Souza Loureiro","Jorge Valverde-Rebaza","Julieta Noguez","David Escarcega","Ricardo Marcacini"],"abstract":"Recent advancements in Large Language Models (LLMs) have significantly improved their problem-solving capabilities. However, these models still struggle when faced with complex multi-step reasoning tasks. In this paper, we propose the Multi-Layered Self-Reflection with Auto-Prompting (MAPS) framework, a novel approach designed to enhance multi-step mathematical reasoning in LLMs by integrating techniques such as Chain of Thought (CoT), Self-Reflection, and Auto-Prompting. Unlike traditional static prompting methods, MAPS employs an iterative refinement process. Initially, the model generates a solution using CoT prompting. When errors are detected, an adaptive self-reflection mechanism identifies and analyzes them, generating tailored prompts to guide corrections. These dynamically adjusted prompts enable the model to iteratively refine its reasoning. Experiments on four well-established benchmarks across multiple LLMs show that MAPS significantly outperforms standard CoT and achieves competitive results with reasoning-optimized models. In addition, MAPS enables general-purpose LLMs to reach performance levels comparable to specialized reasoning models. While deeper reflection layers improve accuracy, they also increase token usage and costs. To balance this trade-off, MAPS strategically limits reflection depth, ensuring an optimal balance between cost and reasoning performance.","published":"2025-06-30T14:18:35Z","updated":"2025-06-30T14:18:35Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.23888v1","pdf_url":"https://arxiv.org/pdf/2506.23888v1","comment":"Accepted for publication in: European Conference on Machine Learning and Principles and Practice of Knowledge Discovery in Databases (ECML PKDD 2025). Research Track","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2507.00092","versioned_id":"2507.00092v1","title":"Thinking About Thinking: SAGE-nano's Inverse Reasoning for Self-Aware Language Models","authors":["Basab Jha","Firoj Paudel","Ujjwal Puri","Zhang Yuting","Choi Donghyuk","Wang Junhao"],"abstract":"Large Language Models (LLMs) have demonstrated remarkable capabilities at solving complex reasoning tasks with Chain-of-Thought (CoT) prompting, but their decision-making processes remain somewhat blackbox. We introduce textbfinverse reasoning, a novel paradigm enabling LLMs to decompose and explain their own reasoning chains post-hoc. Our approach, used in SAGE-nano, a 4-billion-parameter reasoning model, employs a metacognitive structure that reflects back via attention processes to identify major decision points and generate explanations of reasoning choices. While typical CoT approaches are directed towards forward reasoning generation, inverse reasoning provides insight into why specific reasoning chains were selected over others. Through thorough testing of logical reasoning puzzles, math problems and ethical dilemmas from AQUA-RAT, CommonsenseQA, and customized benchmarks, we demonstrate that SAGE-nano is at the cutting edge both on reasoning accuracy (74.6% on AQUA-RAT) and explanation quality (92.1% human preference score) for its task, and offers performance almost on par with models like Claude-3.5 Sonnet or GPT-4o. Our contributions are: (i) the first rigorous framework for LLM self-reflection via inverse reasoning, (ii) a novel metalearning framework to reverse the attention flow, (iii) comprehensive evaluation frameworks for reasoning transparency, and (iv) evidence that increasing reasoning using inverse reasoning improves interpretability along with reasoning performance. Our work creates new avenues for transparent AI systems and closes significant gaps in AI safety, education, and scientific discovery.","published":"2025-06-30T09:53:41Z","updated":"2025-06-30T09:53:41Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.00092v1","pdf_url":"https://arxiv.org/pdf/2507.00092v1","comment":"19 pages, 2 figures, 9 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.23626","versioned_id":"2506.23626v1","title":"Self-correcting Reward Shaping via Language Models for Reinforcement Learning Agents in Games","authors":["António Afonso","Iolanda Leite","Alessandro Sestini","Florian Fuchs","Konrad Tollmar","Linus Gisslén"],"abstract":"Reinforcement Learning (RL) in games has gained significant momentum in recent years, enabling the creation of different agent behaviors that can transform a player's gaming experience. However, deploying RL agents in production environments presents two key challenges: (1) designing an effective reward function typically requires an RL expert, and (2) when a game's content or mechanics are modified, previously tuned reward weights may no longer be optimal. Towards the latter challenge, we propose an automated approach for iteratively fine-tuning an RL agent's reward function weights, based on a user-defined language based behavioral goal. A Language Model (LM) proposes updated weights at each iteration based on this target behavior and a summary of performance statistics from prior training rounds. This closed-loop process allows the LM to self-correct and refine its output over time, producing increasingly aligned behavior without the need for manual reward engineering. We evaluate our approach in a racing task and show that it consistently improves agent performance across iterations. The LM-guided agents show a significant increase in performance from $9\\%$ to $74\\%$ success rate in just one iteration. We compare our LM-guided tuning against a human expert's manual weight design in the racing task: by the final iteration, the LM-tuned agent achieved an $80\\%$ success rate, and completed laps in an average of $855$ time steps, a competitive performance against the expert-tuned agent's peak $94\\%$ success, and $850$ time steps.","published":"2025-06-30T08:45:04Z","updated":"2025-06-30T08:45:04Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.23626v1","pdf_url":"https://arxiv.org/pdf/2506.23626v1","comment":"16 pages in total, 10 pages of main paper, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.23273","versioned_id":"2506.23273v2","title":"FinStat2SQL: A Text2SQL Pipeline for Financial Statement Analysis","authors":["Quang Hung Nguyen","Phuong Anh Trinh","Phan Quoc Hung Mai","Tuan Phong Trinh"],"abstract":"Despite the advancements of large language models, text2sql still faces many challenges, particularly with complex and domain-specific queries. In finance, database designs and financial reporting layouts vary widely between financial entities and countries, making text2sql even more challenging. We present FinStat2SQL, a lightweight text2sql pipeline enabling natural language queries over financial statements. Tailored to local standards like VAS, it combines large and small language models in a multi-agent setup for entity extraction, SQL generation, and self-correction. We build a domain-specific database and evaluate models on a synthetic QA dataset. A fine-tuned 7B model achieves 61.33\\% accuracy with sub-4-second response times on consumer hardware, outperforming GPT-4o-mini. FinStat2SQL offers a scalable, cost-efficient solution for financial analysis, making AI-powered querying accessible to Vietnamese enterprises.","published":"2025-06-29T14:55:21Z","updated":"2025-09-07T17:52:24Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.23273v2","pdf_url":"https://arxiv.org/pdf/2506.23273v2","comment":"Accepted for The 18th International Natural Language Generation Conference (INLG)","journal_ref":"https://aclanthology.org/2025.inlg-main.27/","doi":"","discovered_on":"2026-07-17"},{"id":"2507.00075","versioned_id":"2507.00075v4","title":"Theoretical Modeling of Large Language Model Self-Improvement Training Dynamics Through Solver-Verifier Gap","authors":["Yifan Sun","Yushan Liang","Zhen Zhang","Xin Liu","Jiaye Teng"],"abstract":"Self-improvement is a significant techniques within the realm of large language model (LLM), aiming to enhance the LLM performance without relying on external data. Despite its significance, generally how LLM performances evolve during the self-improvement process remains underexplored. In this paper, we theoretically model the training dynamics of self-improvement via the concept of solver-verifier gap. This is inspired by the conjecture that the performance enhancement of self-improvement stems from the gap between LLM's solver capability and verifier capability. Based on the theoretical framework, we further show how to model the entire training trajectory. This framework allows quantifying the capability limit of self-improvement by fitting the theoretical model to the experiment results. We validate the effectiveness of the theoretical framework on various LLMs and datasets. Beyond self-improvement, we extend our analysis to investigate how external data influences these dynamics within the framework. Notably, we find that under limited external data regimes, such external data can be utilized at any stage without significantly affecting final performances, which accords with the empirical observations.","published":"2025-06-29T06:48:47Z","updated":"2026-02-09T05:57:51Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.00075v4","pdf_url":"https://arxiv.org/pdf/2507.00075v4","comment":"37 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.23080","versioned_id":"2506.23080v2","title":"AI's Euclid's Elements Moment: From Language Models to Computable Thought","authors":["Xinmin Fang","Lingfeng Tao","Zhengxiong Li"],"abstract":"This paper presents a comprehensive five-stage evolutionary framework for understanding the development of artificial intelligence, arguing that its trajectory mirrors the historical progression of human cognitive technologies. We posit that AI is advancing through distinct epochs, each defined by a revolutionary shift in its capacity for representation and reasoning, analogous to the inventions of cuneiform, the alphabet, grammar and logic, mathematical calculus, and formal logical systems. This \"Geometry of Cognition\" framework moves beyond mere metaphor to provide a systematic, cross-disciplinary model that not only explains AI's past architectural shifts-from expert systems to Transformers-but also charts a concrete and prescriptive path forward. Crucially, we demonstrate that this evolution is not merely linear but reflexive: as AI advances through these stages, the tools and insights it develops create a feedback loop that fundamentally reshapes its own underlying architecture. We are currently transitioning into a \"Metalinguistic Moment,\" characterized by the emergence of self-reflective capabilities like Chain-of-Thought prompting and Constitutional AI. The subsequent stages, the \"Mathematical Symbolism Moment\" and the \"Formal Logic System Moment,\" will be defined by the development of a computable calculus of thought, likely through neuro-symbolic architectures and program synthesis, culminating in provably aligned and reliable AI that reconstructs its own foundational representations. This work serves as the methodological capstone to our trilogy, which previously explored the economic drivers (\"why\") and cognitive nature (\"what\") of AI. Here, we address the \"how,\" providing a theoretical foundation for future research and offering concrete, actionable strategies for startups and developers aiming to build the next generation of intelligent systems.","published":"2025-06-29T04:14:19Z","updated":"2025-07-10T09:48:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.23080v2","pdf_url":"https://arxiv.org/pdf/2506.23080v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.22920","versioned_id":"2506.22920v2","title":"Improving Rationality in the Reasoning Process of Language Models through Self-playing Game","authors":["Pinzheng Wang","Juntao Li","Zecheng Tang","Haijia Gui","Min zhang"],"abstract":"Large language models (LLMs) have demonstrated considerable reasoning abilities in various tasks such as mathematics and coding. However, recent studies indicate that even the best models lack true comprehension of their reasoning processes. In this paper, we explore how self-play can enhance the rationality of models in the reasoning process without supervision from humans or superior models. We design a Critic-Discernment Game(CDG) in which a prover first provides a solution to a given problem and is subsequently challenged by critiques of its solution. These critiques either aim to assist or mislead the prover. The objective of the prover is to maintain the correct answer when faced with misleading comments, while correcting errors in response to constructive feedback. Our experiments on tasks involving mathematical reasoning, stepwise error detection, self-correction, and long-chain reasoning demonstrate that CDG training can significantly improve the ability of well-aligned LLMs to comprehend their reasoning process.","published":"2025-06-28T15:11:23Z","updated":"2025-07-06T13:58:07Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.22920v2","pdf_url":"https://arxiv.org/pdf/2506.22920v2","comment":"Accepted by ICML 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.22058","versioned_id":"2506.22058v3","title":"Lost at the Beginning of Reasoning","authors":["Baohao Liao","Xinyi Chen","Sara Rajaee","Yuhui Xu","Christian Herold","Anders Søgaard","Maarten de Rijke","Christof Monz"],"abstract":"Recent advancements in large language models (LLMs) have significantly advanced complex reasoning capabilities, particularly through extended chain-of-thought (CoT) reasoning that incorporates mechanisms such as backtracking, self-reflection, and self-correction. Despite these developments, the self-correction abilities of LLMs during long CoT reasoning remain underexplored. And recent findings on overthinking suggest that such models often engage in unnecessarily redundant reasoning. In this work, we empirically show that the first reasoning step exerts a disproportionately large influence on the final prediction. I.e., errors introduced at this stage can substantially degrade subsequent reasoning quality. This phenomenon is consistently observed across various state-of-the-art open- and closed-source reasoning models. Leveraging this insight, we propose an efficient sampling strategy that leverages a reward model to identify and retain high-quality first reasoning steps while discarding suboptimal ones, achieving up to a 70% reduction in inference cost without sacrificing any accuracy. Our work highlights the central role of the first reasoning step in generating a high-quality reasoning trajectory, and thus enabling significantly efficient sampling.","published":"2025-06-27T09:53:57Z","updated":"2025-10-18T13:52:47Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.22058v3","pdf_url":"https://arxiv.org/pdf/2506.22058v3","comment":"remove the benchmark part. (10 pages, 6 figures, 5 tables)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.21252","versioned_id":"2506.21252v1","title":"Agent-RewardBench: Towards a Unified Benchmark for Reward Modeling across Perception, Planning, and Safety in Real-World Multimodal Agents","authors":["Tianyi Men","Zhuoran Jin","Pengfei Cao","Yubo Chen","Kang Liu","Jun Zhao"],"abstract":"As Multimodal Large Language Models (MLLMs) advance, multimodal agents show promise in real-world tasks like web navigation and embodied intelligence. However, due to limitations in a lack of external feedback, these agents struggle with self-correction and generalization. A promising approach is to use reward models as external feedback, but there is no clear on how to select reward models for agents. Thus, there is an urgent need to build a reward bench targeted at agents. To address these challenges, we propose Agent-RewardBench, a benchmark designed to evaluate reward modeling ability in MLLMs. The benchmark is characterized by three key features: (1) Multiple dimensions and real-world agent scenarios evaluation. It covers perception, planning, and safety with 7 scenarios; (2) Step-level reward evaluation. It allows for the assessment of agent capabilities at the individual steps of a task, providing a more granular view of performance during the planning process; and (3) Appropriately difficulty and high-quality. We carefully sample from 10 diverse models, difficulty control to maintain task challenges, and manual verification to ensure the integrity of the data. Experiments demonstrate that even state-of-the-art multimodal models show limited performance, highlighting the need for specialized training in agent reward modeling. Code is available at github.","published":"2025-06-26T13:36:12Z","updated":"2025-06-26T13:36:12Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.21252v1","pdf_url":"https://arxiv.org/pdf/2506.21252v1","comment":"ACL 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.20332","versioned_id":"2506.20332v4","title":"Mobile-R1: Towards Interactive Capability for VLM-Based Mobile Agent via Systematic Training","authors":["Jihao Gu","Qihang Ai","Yingyao Wang","Pi Bu","Jingxuan Xing","Zekun Zhu","Wei Jiang","Ziming Wang","Yingxiu Zhao","Ming-Liang Zhang","Jun Song","Yuning Jiang","Bo Zheng"],"abstract":"Vision-language model-based mobile agents have gained the ability to understand complex instructions and mobile screenshots, benefiting from reinforcement learning paradigms like Group Relative Policy Optimization (GRPO). However, existing approaches centers on offline training or local action-level rewards often trap agents in local optima, hindering effective exploration and error correction with the environment. Crucially, we find that directly applying task-level rewards often leads to convergence difficulties due to the sparse nature of GUI interactions. To address these challenges, we present \\textbf{Mobile-R1}, a systematic training recipe that bridges atomic action execution and strategic task completion. We propose a hierarchical curriculum consisting of three stages: (1) format alignment for reasoning structure, (2) on-policy exploration with verifiable action feedback to ground basic execution, and (3) multi-turn task-level training with realistic environment to unlock exploration and self-correction. This hierarchical strategy effectively bootstraps the agent, significantly enhancing its capability for exploration and self-correction (the ``Eureka'' moments). Furthermore, addressing the critical scarcity of diverse GUI data in non-English ecosystems, we contribute a comprehensive Chinese mobile dataset covering 28 applications with 24,521 high-quality manual annotations, and establish a rigorous benchmark with 500 trajectories. We will open source all resources, including the dataset, benchmark, model weight, and codes: https://mobile-r1.github.io/Mobile-R1/.","published":"2025-06-25T11:34:43Z","updated":"2026-04-25T13:54:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.20332v4","pdf_url":"https://arxiv.org/pdf/2506.20332v4","comment":"19 pages, 15 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.20102","versioned_id":"2506.20102v2","title":"Autonomous Cyber Resilience via a Co-Evolutionary Arms Race within a Fortified Digital Twin Sandbox","authors":["Malikussaid","Sutiyo"],"abstract":"The convergence of Information Technology and Operational Technology has exposed Industrial Control Systems to adaptive, intelligent adversaries that render static defenses obsolete. This paper introduces the Adversarial Resilience Co-evolution (ARC) framework, addressing the \"Trinity of Trust\" comprising model fidelity, data integrity, and analytical resilience. ARC establishes a co-evolutionary arms race within a Fortified Secure Digital Twin (F-SCDT), where a Deep Reinforcement Learning \"Red Agent\" autonomously discovers attack paths while an ensemble-based \"Blue Agent\" is continuously hardened against these threats. Experimental validation on the Tennessee Eastman Process (TEP) and Secure Water Treatment (SWaT) testbeds demonstrates superior performance in detecting novel attacks, with F1-scores improving from 0.65 to 0.89 and detection latency reduced from over 1200 seconds to 210 seconds. A comprehensive ablation study reveals that the co-evolutionary process itself contributes a 27% performance improvement. By integrating Explainable AI and proposing a Federated ARC architecture, this work presents a necessary paradigm shift toward dynamic, self-improving security for critical infrastructure.","published":"2025-06-25T03:28:48Z","updated":"2025-10-16T17:44:09Z","categories":["cs.CR","cs.LG","eess.SY"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2506.20102v2","pdf_url":"https://arxiv.org/pdf/2506.20102v2","comment":"6 pages, 2 figures, 4 equations, 1 algorithm, 3 tables, to be published in ISPACS 2025, unabridged version exists as arXiv:2506.20102v1","journal_ref":"Proc. 2025 Int. Symp. on Intell. Signal Process. and Commun. Syst. (ISPACS), 2025, pp. 1-6","doi":"10.1109/ISPACS68724.2025.11383172","discovered_on":"2026-07-17"},{"id":"2506.19607","versioned_id":"2506.19607v1","title":"Correcting Hallucinations in News Summaries: Exploration of Self-Correcting LLM Methods with External Knowledge","authors":["Juraj Vladika","Ihsan Soydemir","Florian Matthes"],"abstract":"While large language models (LLMs) have shown remarkable capabilities to generate coherent text, they suffer from the issue of hallucinations -- factually inaccurate statements. Among numerous approaches to tackle hallucinations, especially promising are the self-correcting methods. They leverage the multi-turn nature of LLMs to iteratively generate verification questions inquiring additional evidence, answer them with internal or external knowledge, and use that to refine the original response with the new corrections. These methods have been explored for encyclopedic generation, but less so for domains like news summarization. In this work, we investigate two state-of-the-art self-correcting systems by applying them to correct hallucinated summaries using evidence from three search engines. We analyze the results and provide insights into systems' performance, revealing interesting practical findings on the benefits of search engine snippets and few-shot prompts, as well as high alignment of G-Eval and human evaluation.","published":"2025-06-24T13:20:31Z","updated":"2025-06-24T13:20:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.19607v1","pdf_url":"https://arxiv.org/pdf/2506.19607v1","comment":"Accepted to FEVER @ ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.19882","versioned_id":"2506.19882v3","title":"Position: Machine Learning Conferences Should Establish a \"Refutations and Critiques\" Track","authors":["Rylan Schaeffer","Joshua Kazdan","Yegor Denisov-Blanch","Brando Miranda","Matthias Gerstgrasser","Susan Zhang","Andreas Haupt","Isha Gupta","Elyas Obbad","Jesse Dodge","Jessica Zosa Forde","Francesco Orabona","Sanmi Koyejo","David Donoho"],"abstract":"Science progresses by iteratively advancing and correcting humanity's understanding of the world. In machine learning (ML) research, rapid advancements have led to an explosion of publications, but have also led to misleading, incorrect, flawed or perhaps even fraudulent studies being accepted and sometimes highlighted at ML conferences due to the fallibility of peer review. While such mistakes are understandable, ML conferences do not offer robust processes to help the field systematically correct when such errors are made. This position paper argues that ML conferences should establish a dedicated \"Refutations and Critiques\" (R&C) Track. This R&C Track would provide a high-profile, reputable platform to support vital research that critically challenges prior research, thereby fostering a dynamic self-correcting research ecosystem. We discuss key considerations including track design, review principles, potential pitfalls, and provide an illustrative example submission concerning a recent ICLR 2025 Oral. We conclude that ML conferences should create official, reputable mechanisms to help ML research self-correct.","published":"2025-06-24T02:19:30Z","updated":"2025-07-07T02:00:46Z","categories":["cs.LG","cs.AI","cs.CL","cs.CY"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.19882v3","pdf_url":"https://arxiv.org/pdf/2506.19882v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.18957","versioned_id":"2506.18957v1","title":"A Comment On \"The Illusion of Thinking\": Reframing the Reasoning Cliff as an Agentic Gap","authors":["Sheraz Khan","Subha Madhavan","Kannan Natarajan"],"abstract":"The recent work by Shojaee et al. (2025), titled The Illusion of Thinking: Understanding the Strengths and Limitations of Reasoning Models via the Lens of Problem Complexity, presents a compelling empirical finding, a reasoning cliff, where the performance of Large Reasoning Models (LRMs) collapses beyond a specific complexity threshold, which the authors posit as an intrinsic scaling limitation of Chain-of-Thought (CoT) reasoning. This commentary, while acknowledging the study's methodological rigor, contends that this conclusion is confounded by experimental artifacts. We argue that the observed failure is not evidence of a fundamental cognitive boundary, but rather a predictable outcome of system-level constraints in the static, text-only evaluation paradigm, including tool use restrictions, context window recall issues, the absence of crucial cognitive baselines, inadequate statistical reporting, and output generation limits. We reframe this performance collapse through the lens of an agentic gap, asserting that the models are not failing at reasoning, but at execution within a profoundly restrictive interface. We empirically substantiate this critique by demonstrating a striking reversal. A model, initially declaring a puzzle impossible when confined to text-only generation, now employs agentic tools to not only solve it but also master variations of complexity far beyond the reasoning cliff it previously failed to surmount. Additionally, our empirical analysis of tool-enabled models like o4-mini and GPT-4o reveals a hierarchy of agentic reasoning, from simple procedural execution to complex meta-cognitive self-correction, which has significant implications for how we define and measure machine intelligence. The illusion of thinking attributed to LRMs is less a reasoning deficit and more a consequence of an otherwise capable mind lacking the tools for action.","published":"2025-06-23T17:14:21Z","updated":"2025-06-23T17:14:21Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.18957v1","pdf_url":"https://arxiv.org/pdf/2506.18957v1","comment":"10 pages, 2 figures, Comment on \"The Illusion of Thinking: Understanding the Strengths and Limitations of Reasoning Models via the Lens of Problem Complexity\" (arXiv:2506.06941v1)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.18237","versioned_id":"2506.18237v1","title":"AdapThink: Adaptive Thinking Preferences for Reasoning Language Model","authors":["Xu Wan","Wei Wang","Wenyue Xu","Wotao Yin","Jie Song","Mingyang Sun"],"abstract":"Reinforcement Learning (RL)-based post-training has significantly advanced the complex reasoning capabilities of language models, fostering sophisticated self-reflection processes. However, this ``slow thinking'' paradigm presents a critical challenge to reasoning efficiency: models may expend excessive computation on simple questions and shift reasoning prematurely for complex ones. Previous mechanisms typically rely on static length budgets or predefined rules, lacking the adaptability for varying question complexities and models' evolving capabilities. To this end, we propose AdapThink, an adaptive post-training framework designed to induce more efficient thinking while maintaining the performance of reasoning language models. Specifically, AdapThink incorporates two key mechanisms: 1) A group-relative reward function that leverages model confidence and response's characteristic to dynamically adjust the preference of reflection-related transition words without resorting to a fixed length preference. 2) A diversity-aware sampling mechanism that balances the training group's solution accuracy with reasoning diversity via an entropy-guided score. Experiments on several mathematical reasoning datasets with DeepSeek-distilled models demonstrate AdapThink's advantages in enabling adaptive reasoning patterns and mitigating the inefficiencies.","published":"2025-06-23T02:06:04Z","updated":"2025-06-23T02:06:04Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.18237v1","pdf_url":"https://arxiv.org/pdf/2506.18237v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.17864","versioned_id":"2506.17864v1","title":"QueueEDIT: Structural Self-Correction for Sequential Model Editing in LLMs","authors":["Taolin Zhang","Haidong Kang","Dongyang Li","Qizhou Chen","Chengyu Wang Xiaofeng He","Richang Hong"],"abstract":"Recently, large language models (LLMs) have demonstrated impressive results but still suffer from hallucinations. Model editing has been proposed to correct factual inaccuracies in LLMs. A challenging case is sequential model editing (SME), which aims to rectify errors continuously rather than treating them as a one-time task. During SME, the general capabilities of LLMs can be negatively affected due to the introduction of new parameters. In this paper, we propose a queue-based self-correction framework (QueueEDIT) that not only enhances SME performance by addressing long-sequence dependency but also mitigates the impact of parameter bias on the general capabilities of LLMs. Specifically, we first introduce a structural mapping editing loss to map the triplets to the knowledge-sensitive neurons within the Transformer layers of LLMs. We then store the located parameters for each piece of edited knowledge in a queue and dynamically align previously edited parameters. In each edit, we select queue parameters most relevant to the currently located parameters to determine whether previous knowledge needs realignment. Irrelevant parameters in the queue are frozen, and we update the parameters at the queue head to the LLM to ensure they do not harm general abilities. Experiments show that our framework significantly outperforms strong baselines across various SME settings and maintains competitiveness in single-turn editing. The resulting LLMs also preserve high capabilities in general NLP tasks throughout the SME process.","published":"2025-06-22T00:58:07Z","updated":"2025-06-22T00:58:07Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.17864v1","pdf_url":"https://arxiv.org/pdf/2506.17864v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.17484","versioned_id":"2506.17484v1","title":"From Unstructured Communication to Intelligent RAG: Multi-Agent Automation for Supply Chain Knowledge Bases","authors":["Yao Zhang","Zaixi Shang","Silpan Patel","Mikel Zuniga"],"abstract":"Supply chain operations generate vast amounts of operational data; however, critical knowledge such as system usage practices, troubleshooting workflows, and resolution techniques often remains buried within unstructured communications like support tickets, emails, and chat logs. While RAG systems aim to leverage such communications as a knowledge base, their effectiveness is limited by raw data challenges: support tickets are typically noisy, inconsistent, and incomplete, making direct retrieval suboptimal. Unlike existing RAG approaches that focus on runtime optimization, we introduce a novel offline-first methodology that transforms these communications into a structured knowledge base. Our key innovation is a LLMs-based multi-agent system orchestrating three specialized agents: Category Discovery for taxonomy creation, Categorization for ticket grouping, and Knowledge Synthesis for article generation. Applying our methodology to real-world support tickets with resolution notes and comments, our system creates a compact knowledge base - reducing total volume to just 3.4% of original ticket data while improving quality. Experiments demonstrate that our prebuilt knowledge base in RAG systems significantly outperforms traditional RAG implementations (48.74% vs. 38.60% helpful answers) and achieves a 77.4% reduction in unhelpful responses. By automating institutional knowledge capture that typically remains siloed in experts' heads, our solution translates to substantial operational efficiency: reducing support workload, accelerating resolution times, and creating self-improving systems that automatically resolve approximately 50% of future supply chain tickets. Our approach addresses a key gap in knowledge management by transforming transient communications into structured, reusable knowledge through intelligent offline processing rather than latency-inducing runtime architectures.","published":"2025-06-20T21:38:06Z","updated":"2025-06-20T21:38:06Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.17484v1","pdf_url":"https://arxiv.org/pdf/2506.17484v1","comment":"Accepted In Proceedings of the 1st Workshop on AI for Supply Chain: Today and Future @ 31st ACM SIGKDD Conference on Knowledge Discovery and Data Mining V.2 (KDD 25), August 3, 2025, Toronto, ON, Canada. ACM, New York, NY, USA, 14 pages, 2 figures","journal_ref":"","doi":"10.1145/XXXXXX.XXXXXX","discovered_on":"2026-07-17"},{"id":"2506.17449","versioned_id":"2506.17449v1","title":"OmniReflect: Discovering Transferable Constitutions for LLM agents via Neuro-Symbolic Reflections","authors":["Manasa Bharadwaj","Nikhil Verma","Kevin Ferreira"],"abstract":"Efforts to improve Large Language Model (LLM) agent performance on complex tasks have largely focused on fine-tuning and iterative self-correction. However, these approaches often lack generalizable mechanisms for longterm learning and remain inefficient in dynamic environments. We introduce OmniReflect, a hierarchical, reflection-driven framework that constructs a constitution, a compact set of guiding principles distilled from task experiences, to enhance the effectiveness and efficiency of an LLM agent. OmniReflect operates in two modes: Self-sustaining, where a single agent periodically curates its own reflections during task execution, and Co-operative, where a Meta-advisor derives a constitution from a small calibration set to guide another agent. To construct these constitutional principles, we employ Neural, Symbolic, and NeuroSymbolic techniques, offering a balance between contextual adaptability and computational efficiency. Empirical results averaged across models show major improvements in task success, with absolute gains of +10.3% on ALFWorld, +23.8% on BabyAI, and +8.3% on PDDL in the Self-sustaining mode. Similar gains are seen in the Co-operative mode, where a lightweight Qwen3-4B ReAct agent outperforms all Reflexion baselines on BabyAI. These findings highlight the robustness and effectiveness of OmniReflect across environments and backbones.","published":"2025-06-20T19:38:21Z","updated":"2025-06-20T19:38:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.17449v1","pdf_url":"https://arxiv.org/pdf/2506.17449v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.17442","versioned_id":"2506.17442v2","title":"Keeping Medical AI Healthy and Trustworthy: A Review of Detection and Correction Methods for System Degradation","authors":["Hao Guan","David Bates","Li Zhou"],"abstract":"Artificial intelligence (AI) is increasingly integrated into modern healthcare, offering powerful support for clinical decision-making. However, in real-world settings, AI systems may experience performance degradation over time, due to factors such as shifting data distributions, changes in patient characteristics, evolving clinical protocols, and variations in data quality. These factors can compromise model reliability, posing safety concerns and increasing the likelihood of inaccurate predictions or adverse outcomes. This review presents a forward-looking perspective on monitoring and maintaining the \"health\" of AI systems in healthcare. We highlight the urgent need for continuous performance monitoring, early degradation detection, and effective self-correction mechanisms. The paper begins by reviewing common causes of performance degradation at both data and model levels. We then summarize key techniques for detecting data and model drift, followed by an in-depth look at root cause analysis. Correction strategies are further reviewed, ranging from model retraining to test-time adaptation. Our survey spans both traditional machine learning models and state-of-the-art large language models (LLMs), offering insights into their strengths and limitations. Finally, we discuss ongoing technical challenges and propose future research directions. This work aims to guide the development of reliable, robust medical AI systems capable of sustaining safe, long-term deployment in dynamic clinical settings.","published":"2025-06-20T19:22:07Z","updated":"2025-12-02T01:53:21Z","categories":["cs.AI","cs.ET","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.17442v2","pdf_url":"https://arxiv.org/pdf/2506.17442v2","comment":"16 pages, 5 figures","journal_ref":"IEEE Transactions on Biomedical Engineering, 2026","doi":"10.1109/TBME.2025.3642706","discovered_on":"2026-07-17"},{"id":"2506.17417","versioned_id":"2506.17417v3","title":"Aha Moment Revisited: Are VLMs Truly Capable of Self Verification in Inference-time Scaling?","authors":["Mingyuan Wu","Meitang Li","Jingcheng Yang","Jize Jiang","Kaizhuo Yan","Zhaoheng Li","Hanchao Yu","Minjia Zhang","Klara Nahrstedt"],"abstract":"Inference time techniques such as decoding time scaling and self refinement have been shown to substantially improve mathematical reasoning in large language models (LLMs), largely attributed to emergent self correction and self verification behaviors often elicited through reinforcement learning (RL). In this work, we ask whether the same recipe transfers to vision language models (VLMs), especially RL finetuned variants that claim strong visual mathematical reasoning. Through extensive evaluation, we reach three main findings that differ markedly from text only models. First, generation time capability matters more than verification and refinement: simple majority voting consistently and substantially outperforms verification centric strategies such as best of N with self verification. Second, behaviors often associated with RL tuned models at inference time, such as the 'Aha moment,' do not yield reliable reasoning performance improvements. Third, visual information is not effectively integrated into the model's self verification process. Overall, our analysis highlights a key limitation: current RL trained VLMs derive limited benefit from self verification in the visual modality, which constrains the effectiveness of inference time scaling for visual mathematical reasoning.","published":"2025-06-20T18:23:48Z","updated":"2026-01-06T03:04:42Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.17417v3","pdf_url":"https://arxiv.org/pdf/2506.17417v3","comment":"Neurips 2025 Multimodal Algorithmic Reasoning Workshop Oral. In submission","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.17114","versioned_id":"2506.17114v4","title":"Mathematical Proof as a Litmus Test: Revealing Failure Modes of Advanced Large Reasoning Models","authors":["Dadi Guo","Jiayu Liu","Zhiyuan Fan","Zhitao He","Haoran Li","Yuxin Li","Yumeng Wang","Yi R. Fung"],"abstract":"Large reasoning models (e.g., R1, o3) have demonstrated remarkable mathematical problem-solving abilities. However, the high reported accuracy of these advanced models on popular datasets, reliance on purely numerical evaluation and potential benchmark leakage, often masks their true reasoning shortcomings. To address this, we propose leveraging the inherent rigor and methodological complexity of mathematical proofs as a diagnostic tool to expose these hidden failures. Specifically, we introduce the RFMDataset (Reveal Failure Modes), a collection of 200 diverse mathematical proof problems, and thoroughly evaluate advanced models' performance on it. Our in-depth analysis of their failures uncovers 10 fine-grained error types, which shows fundamental limitations in current large reasoning models: 1) large reasoning models grapple profoundly with mathematical proofs, with some generating entirely correct proofs for less than 20% of problems and failing even on basic ones; 2) models exhibit a diverse spectrum of reasoning failures, prominently demonstrating the lack of guarantees for the correctness and rigor of single-step reasoning; and 3) models show hallucination and incompleteness during the reasoning process. Our findings reveal that models' self-reflection is insufficient to resolve the current logical dilemmas, necessitating formalized and fine-grained logical training.","published":"2025-06-20T16:14:18Z","updated":"2025-12-09T14:35:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.17114v4","pdf_url":"https://arxiv.org/pdf/2506.17114v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.21609","versioned_id":"2506.21609v1","title":"From Thinking to Output: Chain-of-Thought and Text Generation Characteristics in Reasoning Language Models","authors":["Junhao Liu","Zhenhao Xu","Yuxin Fang","Yichuan Chen","Zuobin Ying","Wenhan Chang"],"abstract":"Recently, there have been notable advancements in large language models (LLMs), demonstrating their growing abilities in complex reasoning. However, existing research largely overlooks a thorough and systematic comparison of these models' reasoning processes and outputs, particularly regarding their self-reflection pattern (also termed \"Aha moment\") and the interconnections across diverse domains. This paper proposes a novel framework for analyzing the reasoning characteristics of four cutting-edge large reasoning models (GPT-o1, DeepSeek-R1, Kimi-k1.5, and Grok-3) using keywords statistic and LLM-as-a-judge paradigm. Our approach connects their internal thinking processes with their final outputs. A diverse dataset consists of real-world scenario-based questions covering logical deduction, causal inference, and multi-step problem-solving. Additionally, a set of metrics is put forward to assess both the coherence of reasoning and the accuracy of the outputs. The research results uncover various patterns of how these models balance exploration and exploitation, deal with problems, and reach conclusions during the reasoning process. Through quantitative and qualitative comparisons, disparities among these models are identified in aspects such as the depth of reasoning, the reliance on intermediate steps, and the degree of similarity between their thinking processes and output patterns and those of GPT-o1. This work offers valuable insights into the trade-off between computational efficiency and reasoning robustness and provides practical recommendations for enhancing model design and evaluation in practical applications. We publicly release our project at: https://github.com/ChangWenhan/FromThinking2Output","published":"2025-06-20T14:02:16Z","updated":"2025-06-20T14:02:16Z","categories":["cs.CL","cs.AI","cs.CR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.21609v1","pdf_url":"https://arxiv.org/pdf/2506.21609v1","comment":"18 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.21606","versioned_id":"2506.21606v1","title":"Large Language Models as symbolic DNA of cultural dynamics","authors":["Parham Pourdavood","Michael Jacob","Terrence Deacon"],"abstract":"This paper proposes a novel conceptualization of Large Language Models (LLMs) as externalized informational substrates that function analogously to DNA for human cultural dynamics. Rather than viewing LLMs as either autonomous intelligence or mere programmed mimicry, we argue they serve a broader role as repositories that preserve compressed patterns of human symbolic expression--\"fossils\" of meaningful dynamics that retain relational residues without their original living contexts. Crucially, these compressed patterns only become meaningful through human reinterpretation, creating a recursive feedback loop where they can be recombined and cycle back to ultimately catalyze human creative processes. Through analysis of four universal features--compression, decompression, externalization, and recursion--we demonstrate that just as DNA emerged as a compressed and externalized medium for preserving useful cellular dynamics without containing explicit reference to goal-directed physical processes, LLMs preserve useful regularities of human culture without containing understanding of embodied human experience. Therefore, we argue that LLMs' significance lies not in rivaling human intelligence, but in providing humanity a tool for self-reflection and playful hypothesis-generation in a low-stakes, simulated environment. This framework positions LLMs as tools for cultural evolvability, enabling humanity to generate novel hypotheses about itself while maintaining the human interpretation necessary to ground these hypotheses in ongoing human aesthetics and norms.","published":"2025-06-20T10:37:29Z","updated":"2025-06-20T10:37:29Z","categories":["cs.CL","cs.AI","cs.CY"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.21606v1","pdf_url":"https://arxiv.org/pdf/2506.21606v1","comment":"28 pages, 1 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.16064","versioned_id":"2506.16064v1","title":"Self-Critique-Guided Curiosity Refinement: Enhancing Honesty and Helpfulness in Large Language Models via In-Context Learning","authors":["Duc Hieu Ho","Chenglin Fan"],"abstract":"Large language models (LLMs) have demonstrated robust capabilities across various natural language tasks. However, producing outputs that are consistently honest and helpful remains an open challenge. To overcome this challenge, this paper tackles the problem through two complementary directions. It conducts a comprehensive benchmark evaluation of ten widely used large language models, including both proprietary and open-weight models from OpenAI, Meta, and Google. In parallel, it proposes a novel prompting strategy, self-critique-guided curiosity refinement prompting. The key idea behind this strategy is enabling models to self-critique and refine their responses without additional training. The proposed method extends the curiosity-driven prompting strategy by incorporating two lightweight in-context steps including self-critique step and refinement step. The experiment results on the HONESET dataset evaluated using the framework $\\mathrm{H}^2$ (honesty and helpfulness), which was executed with GPT-4o as a judge of honesty and helpfulness, show consistent improvements across all models. The approach reduces the number of poor-quality responses, increases high-quality responses, and achieves relative gains in $\\mathrm{H}^2$ scores ranging from 1.4% to 4.3% compared to curiosity-driven prompting across evaluated models. These results highlight the effectiveness of structured self-refinement as a scalable and training-free strategy to improve the trustworthiness of LLMs outputs.","published":"2025-06-19T06:42:35Z","updated":"2025-06-19T06:42:35Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.16064v1","pdf_url":"https://arxiv.org/pdf/2506.16064v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.15894","versioned_id":"2506.15894v1","title":"Language Models can perform Single-Utterance Self-Correction of Perturbed Reasoning","authors":["Sam Silver","Jimin Sun","Ivan Zhang","Sara Hooker","Eddie Kim"],"abstract":"Large Language Models (LLMs) have demonstrated impressive mathematical reasoning capabilities, yet their performance remains brittle to minor variations in problem description and prompting strategy. Furthermore, reasoning is vulnerable to sampling-induced errors which autoregressive models must primarily address using self-correction via additionally-generated tokens. To better understand self-correction capabilities of recent models, we conduct experiments measuring models' ability to self-correct synthetic perturbations introduced into their Chain of Thought (CoT) reasoning. We observe robust single-utterance intrinsic self-correction behavior across a range of open-weight models and datasets, ranging from subtle, implicit corrections to explicit acknowledgments and corrections of errors. Our findings suggest that LLMs, including those not finetuned for long CoT, may possess stronger intrinsic self-correction capabilities than commonly shown in the literature. The presence of this ability suggests that recent \"reasoning\" model work involves amplification of traits already meaningfully present in models.","published":"2025-06-18T21:35:44Z","updated":"2025-06-18T21:35:44Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.15894v1","pdf_url":"https://arxiv.org/pdf/2506.15894v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.15882","versioned_id":"2506.15882v2","title":"Fractional Reasoning via Latent Steering Vectors Improves Inference Time Compute","authors":["Sheng Liu","Tianlang Chen","Pan Lu","Haotian Ye","Yizheng Chen","Lei Xing","James Zou"],"abstract":"Test-time compute has emerged as a powerful paradigm for improving the performance of large language models (LLMs), where generating multiple outputs or refining individual chains can significantly boost answer accuracy. However, existing methods like Best-of-N, majority voting, and self-reflection typically apply reasoning in a uniform way across inputs, overlooking the fact that different problems may require different levels of reasoning depth. In this work, we propose Fractional Reasoning, a training-free and model-agnostic framework that enables continuous control over reasoning intensity at inference time, going beyond the limitations of fixed instructional prompts. Our method operates by extracting the latent steering vector associated with deeper reasoning and reapplying it with a tunable scaling factor, allowing the model to tailor its reasoning process to the complexity of each input. This supports two key modes of test-time scaling: (1) improving output quality in breadth-based strategies (e.g., Best-of-N, majority voting), and (2) enhancing the correctness of individual reasoning chains in depth-based strategies (e.g., self-reflection). Experiments on GSM8K, MATH500, and GPQA demonstrate that Fractional Reasoning consistently improves performance across diverse reasoning tasks and models.","published":"2025-06-18T21:15:59Z","updated":"2025-09-25T09:27:44Z","categories":["cs.LG","cs.AI","cs.CL","eess.SP"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.15882v2","pdf_url":"https://arxiv.org/pdf/2506.15882v2","comment":"18 pages, 5 figures, Project website: https://shengliu66.github.io/fractreason/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.15880","versioned_id":"2506.15880v1","title":"Deep Reinforcement Learning Xiangqi Player with Monte Carlo Tree Search","authors":["Berk Yilmaz","Junyu Hu","Jinsong Liu"],"abstract":"This paper presents a Deep Reinforcement Learning (DRL) system for Xiangqi (Chinese Chess) that integrates neural networks with Monte Carlo Tree Search (MCTS) to enable strategic self-play and self-improvement. Addressing the underexplored complexity of Xiangqi, including its unique board layout, piece movement constraints, and victory conditions, our approach combines policy-value networks with MCTS to simulate move consequences and refine decision-making. By overcoming challenges such as Xiangqi's high branching factor and asymmetrical piece dynamics, our work advances AI capabilities in culturally significant strategy games while providing insights for adapting DRL-MCTS frameworks to domain-specific rule systems.","published":"2025-06-18T21:11:17Z","updated":"2025-06-18T21:11:17Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.15880v1","pdf_url":"https://arxiv.org/pdf/2506.15880v1","comment":"All authors contributed equally to this work.24 pages, 10 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.15649","versioned_id":"2506.15649v1","title":"Dual-Stage Value-Guided Inference with Margin-Based Reward Adjustment for Fast and Faithful VLM Captioning","authors":["Ankan Deria","Adinath Madhavrao Dukre","Feilong Tang","Sara Atito","Sudipta Roy","Muhammad Awais","Muhammad Haris Khan","Imran Razzak"],"abstract":"Despite significant advances in inference-time search for vision-language models (VLMs), existing approaches remain both computationally expensive and prone to unpenalized, low-confidence generations which often lead to persistent hallucinations. We introduce \\textbf{Value-guided Inference with Margin-based Reward (ViMaR)}, a two-stage inference framework that improves both efficiency and output fidelity by combining a temporal-difference value model with a margin-aware reward adjustment. In the first stage, we perform a single pass to identify the highest-value caption among diverse candidates. In the second stage, we selectively refine only those segments that were overlooked or exhibit weak visual grounding, thereby eliminating frequently rewarded evaluations. A calibrated margin-based penalty discourages low-confidence continuations while preserving descriptive richness. Extensive experiments across multiple VLM architectures demonstrate that ViMaR generates captions that are significantly more reliable, factually accurate, detailed, and explanatory, while achieving over 4$\\times$ speedup compared to existing value-guided methods. Specifically, we show that ViMaR trained solely on LLaVA Mistral-7B, \\textit{generalizes effectively to guide decoding in a stronger unseen model}. To further validate this, we adapt the ViMaR to steer generation in LLaVA-OneVision-Qwen2-7B, leading to consistent improvements in caption quality and demonstrating robust cross-model guidance. This cross-model generalization highlights ViMaR's flexibility and modularity, positioning it as a scalable and transferable inference-time decoding strategy. Furthermore, when ViMaR-generated captions are used for self-training, the underlying models achieve substantial gains across a broad suite of visual comprehension benchmarks, underscoring the potential of fast, accurate, and self-improving VLM pipelines.","published":"2025-06-18T17:23:36Z","updated":"2025-06-18T17:23:36Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2506.15649v1","pdf_url":"https://arxiv.org/pdf/2506.15649v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.13485","versioned_id":"2506.13485v1","title":"Curriculum Learning for Biological Sequence Prediction: The Case of De Novo Peptide Sequencing","authors":["Xiang Zhang","Jiaqi Wei","Zijie Qiu","Sheng Xu","Nanqing Dong","Zhiqiang Gao","Siqi Sun"],"abstract":"Peptide sequencing-the process of identifying amino acid sequences from mass spectrometry data-is a fundamental task in proteomics. Non-Autoregressive Transformers (NATs) have proven highly effective for this task, outperforming traditional methods. Unlike autoregressive models, which generate tokens sequentially, NATs predict all positions simultaneously, leveraging bidirectional context through unmasked self-attention. However, existing NAT approaches often rely on Connectionist Temporal Classification (CTC) loss, which presents significant optimization challenges due to CTC's complexity and increases the risk of training failures. To address these issues, we propose an improved non-autoregressive peptide sequencing model that incorporates a structured protein sequence curriculum learning strategy. This approach adjusts protein's learning difficulty based on the model's estimated protein generational capabilities through a sampling process, progressively learning peptide generation from simple to complex sequences. Additionally, we introduce a self-refining inference-time module that iteratively enhances predictions using learned NAT token embeddings, improving sequence accuracy at a fine-grained level. Our curriculum learning strategy reduces NAT training failures frequency by more than 90% based on sampled training over various data distributions. Evaluations on nine benchmark species demonstrate that our approach outperforms all previous methods across multiple metrics and species.","published":"2025-06-16T13:44:25Z","updated":"2025-06-16T13:44:25Z","categories":["q-bio.BM","cs.LG"],"primary_category":"q-bio.BM","arxiv_url":"https://arxiv.org/abs/2506.13485v1","pdf_url":"https://arxiv.org/pdf/2506.13485v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.13358","versioned_id":"2506.13358v1","title":"Socratic RL: A Novel Framework for Efficient Knowledge Acquisition through Iterative Reflection and Viewpoint Distillation","authors":["Xiangfan Wu"],"abstract":"Current Reinforcement Learning (RL) methodologies for Large Language Models (LLMs) often rely on simplistic, outcome-based reward signals (e.g., final answer correctness), which limits the depth of learning from each interaction. This paper introduces Socratic Reinforcement Learning (Socratic-RL), a novel, process-oriented framework designed to address this limitation. Socratic-RL operates on the principle that deeper understanding is achieved by reflecting on the causal reasons for errors and successes within the reasoning process itself. The framework employs a decoupled \"Teacher-Student\" architecture, where a \"Teacher AI\" analyzes interaction histories, extracts causal insights, and formulates them into structured \"viewpoints.\" These viewpoints, acting as distilled guidance, are then used by a \"Student AI\" to enhance its subsequent reasoning. A key innovation is the iterative self-improvement of the Teacher AI, enabling its reflective capabilities to evolve through a meta-learning loop. To manage the accumulation of knowledge, a distillation mechanism compresses learned viewpoints into the Student's parameters. By focusing on process rather than just outcome, Socratic-RL presents a pathway toward enhanced sample efficiency, superior interpretability, and a more scalable architecture for self-improving AI systems. This paper details the foundational concepts, formal mechanisms, synergies, challenges, and a concrete research roadmap for this proposed framework.","published":"2025-06-16T10:57:58Z","updated":"2025-06-16T10:57:58Z","categories":["cs.AI","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.13358v1","pdf_url":"https://arxiv.org/pdf/2506.13358v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.13300","versioned_id":"2506.13300v3","title":"Seewo's Submission to MLC-SLM: Lessons learned from Speech Reasoning Language Models","authors":["Bo Li","Chengben Xu","Wufeng Zhang"],"abstract":"This paper presents Seewo's systems for both tracks of the Multilingual Conversational Speech Language Model Challenge (MLC-SLM), addressing automatic speech recognition (ASR) and speaker diarization with ASR (SD-ASR). We introduce a multi-stage training pipeline that explicitly enhances reasoning and self-correction in speech language models for ASR. Our approach combines curriculum learning for progressive capability acquisition, Chain-of-Thought data augmentation to foster intermediate reflection, and Reinforcement Learning with Verifiable Rewards (RLVR) to further refine self-correction through reward-driven optimization. This approach achieves substantial improvements over the official challenge baselines. On the evaluation set, our best system attains a WER/CER of 11.57% for Track 1 and a tcpWER/tcpCER of 17.67% for Track 2. Comprehensive ablation studies demonstrate the effectiveness of each component under challenge constraints.","published":"2025-06-16T09:42:05Z","updated":"2025-06-18T06:57:58Z","categories":["cs.CL","cs.AI","cs.SD","eess.AS"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.13300v3","pdf_url":"https://arxiv.org/pdf/2506.13300v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.13070","versioned_id":"2506.13070v1","title":"CHILL at SemEval-2025 Task 2: You Can't Just Throw Entities and Hope -- Make Your LLM to Get Them Right","authors":["Jaebok Lee","Yonghyun Ryu","Seongmin Park","Yoonjung Choi"],"abstract":"In this paper, we describe our approach for the SemEval 2025 Task 2 on Entity-Aware Machine Translation (EA-MT). Our system aims to improve the accuracy of translating named entities by combining two key approaches: Retrieval Augmented Generation (RAG) and iterative self-refinement techniques using Large Language Models (LLMs). A distinctive feature of our system is its self-evaluation mechanism, where the LLM assesses its own translations based on two key criteria: the accuracy of entity translations and overall translation quality. We demonstrate how these methods work together and effectively improve entity handling while maintaining high-quality translations.","published":"2025-06-16T03:26:10Z","updated":"2025-06-16T03:26:10Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.13070v1","pdf_url":"https://arxiv.org/pdf/2506.13070v1","comment":"The 19th International Workshop on Semantic Evaluation","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.15734","versioned_id":"2506.15734v1","title":"The Safety Reminder: A Soft Prompt to Reactivate Delayed Safety Awareness in Vision-Language Models","authors":["Peiyuan Tang","Haojie Xin","Xiaodong Zhang","Jun Sun","Qin Xia","Zijiang Yang"],"abstract":"As Vision-Language Models (VLMs) demonstrate increasing capabilities across real-world applications such as code generation and chatbot assistance, ensuring their safety has become paramount. Unlike traditional Large Language Models (LLMs), VLMs face unique vulnerabilities due to their multimodal nature, allowing adversaries to modify visual or textual inputs to bypass safety guardrails and trigger the generation of harmful content. Through systematic analysis of VLM behavior under attack, we identify a novel phenomenon termed ``delayed safety awareness''. Specifically, we observe that safety-aligned VLMs may initially be compromised to produce harmful content, but eventually recognize the associated risks and attempt to self-correct. This pattern suggests that VLMs retain their underlying safety awareness but experience a temporal delay in their activation. Building on this insight, we hypothesize that VLMs' safety awareness can be proactively reactivated through carefully designed prompts. To this end, we introduce ``The Safety Reminder'', a soft prompt tuning approach that optimizes learnable prompt tokens, which are periodically injected during the text generation process to enhance safety awareness, effectively preventing harmful content generation. Additionally, our safety reminder only activates when harmful content is detected, leaving normal conversations unaffected and preserving the model's performance on benign tasks. Through comprehensive evaluation across three established safety benchmarks and one adversarial attacks, we demonstrate that our approach significantly reduces attack success rates while maintaining model utility, offering a practical solution for deploying safer VLMs in real-world applications.","published":"2025-06-15T12:48:38Z","updated":"2025-06-15T12:48:38Z","categories":["cs.AI","cs.CL","cs.CR","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.15734v1","pdf_url":"https://arxiv.org/pdf/2506.15734v1","comment":"23 pages, 10 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.12217","versioned_id":"2506.12217v1","title":"From Emergence to Control: Probing and Modulating Self-Reflection in Language Models","authors":["Xudong Zhu","Jiachen Jiang","Mohammad Mahdi Khalili","Zhihui Zhu"],"abstract":"Self-reflection -- the ability of a large language model (LLM) to revisit, evaluate, and revise its own reasoning -- has recently emerged as a powerful behavior enabled by reinforcement learning with verifiable rewards (RLVR). While self-reflection correlates with improved reasoning accuracy, its origin and underlying mechanisms remain poorly understood. In this work, {\\it we first show that self-reflection is not exclusive to RLVR fine-tuned models: it already emerges, albeit rarely, in pretrained models}. To probe this latent ability, we introduce Reflection-Inducing Probing, a method that injects reflection-triggering reasoning traces from fine-tuned models into pretrained models. This intervention raises self-reflection frequency of Qwen2.5 from 0.6\\% to 18.6\\%, revealing a hidden capacity for reflection. Moreover, our analysis of internal representations shows that both pretrained and fine-tuned models maintain hidden states that distinctly separate self-reflective from non-reflective contexts. Leveraging this observation, {\\it we then construct a self-reflection vector, a direction in activation space associated with self-reflective reasoning}. By manipulating this vector, we enable bidirectional control over the self-reflective behavior for both pretrained and fine-tuned models. Experiments across multiple reasoning benchmarks show that enhancing these vectors improves reasoning performance by up to 12\\%, while suppressing them reduces computational cost, providing a flexible mechanism to navigate the trade-off between reasoning quality and efficiency without requiring additional training. Our findings further our understanding of self-reflection and support a growing body of work showing that understanding model internals can enable precise behavioral control.","published":"2025-06-13T20:40:13Z","updated":"2025-06-13T20:40:13Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.12217v1","pdf_url":"https://arxiv.org/pdf/2506.12217v1","comment":"18 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.11930","versioned_id":"2506.11930v2","title":"Feedback Friction: LLMs Struggle to Fully Incorporate External Feedback","authors":["Dongwei Jiang","Alvin Zhang","Andrew Wang","Nicholas Andrews","Daniel Khashabi"],"abstract":"Recent studies have shown LLMs possess some ability to improve their responses when given external feedback. However, it remains unclear how effectively and thoroughly these models can incorporate extrinsic feedback. In an ideal scenario, if LLMs receive near-perfect and complete feedback, we would expect them to fully integrate the feedback and reach correct solutions. In this paper, we systematically investigate LLMs' ability to incorporate feedback by designing a controlled experimental environment. For each problem, a solver model attempts a solution, then a feedback generator with access to near-complete ground-truth answers produces targeted feedback, after which the solver tries again. We evaluate this pipeline across a diverse range of tasks, including math reasoning, knowledge reasoning, scientific reasoning, and general multi-domain evaluations with state-of-the-art language models including Claude 3.7 with extended thinking. Surprisingly, even under these near-ideal conditions, solver models consistently show resistance to feedback, a limitation that we term Feedback Friction. To mitigate this limitation, we experiment with sampling-based strategies like progressive temperature increases and explicit rejection of previously attempted incorrect answers, which yield improvements but still fail to help models achieve target performance. We analyze Feedback Friction and find that models' confidence on specific questions, measured by semantic entropy, predicts feedback resistance: high-confidence predictions remain resistant to external correction. We hope that highlighting this issue in LLMs will help future research in self-improvement.","published":"2025-06-13T16:31:51Z","updated":"2025-09-21T22:52:02Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.11930v2","pdf_url":"https://arxiv.org/pdf/2506.11930v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.11595","versioned_id":"2506.11595v1","title":"EasyARC: Evaluating Vision Language Models on True Visual Reasoning","authors":["Mert Unsal","Aylin Akkus"],"abstract":"Building on recent advances in language-based reasoning models, we explore multimodal reasoning that integrates vision and text. Existing multimodal benchmarks primarily test visual extraction combined with text-based reasoning, lacking true visual reasoning with more complex interactions between vision and language. Inspired by the ARC challenge, we introduce EasyARC, a vision-language benchmark requiring multi-image, multi-step reasoning, and self-correction. EasyARC is procedurally generated, fully verifiable, and scalable, making it ideal for reinforcement learning (RL) pipelines. The generators incorporate progressive difficulty levels, enabling structured evaluation across task types and complexities. We benchmark state-of-the-art vision-language models and analyze their failure modes. We argue that EasyARC sets a new standard for evaluating true reasoning and test-time scaling capabilities in vision-language models. We open-source our benchmark dataset and evaluation code.","published":"2025-06-13T09:03:33Z","updated":"2025-06-13T09:03:33Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2506.11595v1","pdf_url":"https://arxiv.org/pdf/2506.11595v1","comment":"CVPR2025 Workshop on Test-time Scaling for Computer Vision","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.11559","versioned_id":"2506.11559v1","title":"Leveraging GPT-4 for Vulnerability-Witnessing Unit Test Generation","authors":["Gábor Antal","Dénes Bán","Martin Isztin","Rudolf Ferenc","Péter Hegedűs"],"abstract":"In the life-cycle of software development, testing plays a crucial role in quality assurance. Proper testing not only increases code coverage and prevents regressions but it can also ensure that any potential vulnerabilities in the software are identified and effectively fixed. However, creating such tests is a complex, resource-consuming manual process. To help developers and security experts, this paper explores the automatic unit test generation capability of one of the most widely used large language models, GPT-4, from the perspective of vulnerabilities. We examine a subset of the VUL4J dataset containing real vulnerabilities and their corresponding fixes to determine whether GPT-4 can generate syntactically and/or semantically correct unit tests based on the code before and after the fixes as evidence of vulnerability mitigation. We focus on the impact of code contexts, the effectiveness of GPT-4's self-correction ability, and the subjective usability of the generated test cases. Our results indicate that GPT-4 can generate syntactically correct test cases 66.5\\% of the time without domain-specific pre-training. Although the semantic correctness of the fixes could be automatically validated in only 7. 5\\% of the cases, our subjective evaluation shows that GPT-4 generally produces test templates that can be further developed into fully functional vulnerability-witnessing tests with relatively minimal manual effort. Therefore, despite the limited data, our initial findings suggest that GPT-4 can be effectively used in the generation of vulnerability-witnessing tests. It may not operate entirely autonomously, but it certainly plays a significant role in a partially automated process.","published":"2025-06-13T08:13:07Z","updated":"2025-06-13T08:13:07Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2506.11559v1","pdf_url":"https://arxiv.org/pdf/2506.11559v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.11475","versioned_id":"2506.11475v2","title":"AutoGen Driven Multi Agent Framework for Iterative Crime Data Analysis and Prediction","authors":["Syeda Kisaa Fatima","Tehreem Zubair","Noman Ahmed","Asifullah Khan"],"abstract":"This paper introduces LUCID-MA (Learning and Understanding Crime through Dialogue of Multiple Agents), an innovative AI powered framework where multiple AI agents collaboratively analyze and understand crime data. Our system that consists of three core components: an analysis assistant that highlights spatiotemporal crime patterns; a feedback component that reviews and refines analytical results; and a prediction component that forecasts future crime trends. With a well-designed prompt and the LLaMA-2-13B-Chat-GPTQ model, it runs completely offline and allows the agents undergo self-improvement through 100 rounds of communication with less human interaction. A scoring function is incorporated to evaluate agent performance, providing visual plots to track learning progress. This work demonstrates the potential of AutoGen-style agents for autonomous, scalable, and iterative analysis in social science domains, maintaining data privacy through offline execution. It also showcases a computational model with emergent intelligence, where the system's global behavior emerges from the interactions of its agents. This emergent behavior manifests as enhanced individual agent performance, driven by collaborative dialogue between the LLM-based agents.","published":"2025-06-13T05:39:28Z","updated":"2025-07-20T10:54:02Z","categories":["cs.MA","cs.CL","cs.CV"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2506.11475v2","pdf_url":"https://arxiv.org/pdf/2506.11475v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.11425","versioned_id":"2506.11425v2","title":"Agent-RLVR: Training Software Engineering Agents via Guidance and Environment Rewards","authors":["Jeff Da","Clinton Wang","Xiang Deng","Yuntao Ma","Nikhil Barhate","Sean Hendryx"],"abstract":"Reinforcement Learning from Verifiable Rewards (RLVR) has been widely adopted as the de facto method for enhancing the reasoning capabilities of large language models and has demonstrated notable success in verifiable domains like math and competitive programming tasks. However, the efficacy of RLVR diminishes significantly when applied to agentic environments. These settings, characterized by multi-step, complex problem solving, lead to high failure rates even for frontier LLMs, as the reward landscape is too sparse for effective model training via conventional RLVR. In this work, we introduce Agent-RLVR, a framework that makes RLVR effective in challenging agentic settings, with an initial focus on software engineering tasks. Inspired by human pedagogy, Agent-RLVR introduces agent guidance, a mechanism that actively steers the agent towards successful trajectories by leveraging diverse informational cues. These cues, ranging from high-level strategic plans to dynamic feedback on the agent's errors and environmental interactions, emulate a teacher's guidance, enabling the agent to navigate difficult solution spaces and promotes active self-improvement via additional environment exploration. In the Agent-RLVR training loop, agents first attempt to solve tasks to produce initial trajectories, which are then validated by unit tests and supplemented with agent guidance. Agents then reattempt with guidance, and the agent policy is updated with RLVR based on the rewards of these guided trajectories. Agent-RLVR elevates the pass@1 performance of Qwen-2.5-72B-Instruct from 9.4% to 22.4% on SWE-Bench Verified. We find that our guidance-augmented RLVR data is additionally useful for test-time reward model training, shown by further boosting pass@1 to 27.8%. Agent-RLVR lays the groundwork for training agents with RLVR in complex, real-world environments where conventional RL methods struggle.","published":"2025-06-13T02:46:53Z","updated":"2025-06-20T23:32:06Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.11425v2","pdf_url":"https://arxiv.org/pdf/2506.11425v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.10892","versioned_id":"2506.10892v3","title":"The Diffusion Duality","authors":["Subham Sekhar Sahoo","Justin Deschenaux","Aaron Gokaslan","Guanghan Wang","Justin Chiu","Volodymyr Kuleshov"],"abstract":"Uniform-state discrete diffusion models hold the promise of fast text generation due to their inherent ability to self-correct. However, they are typically outperformed by autoregressive models and masked diffusion models. In this work, we narrow this performance gap by leveraging a key insight: Uniform-state diffusion processes naturally emerge from an underlying Gaussian diffusion. Our method, Duo, transfers powerful techniques from Gaussian diffusion to improve both training and sampling. First, we introduce a curriculum learning strategy guided by the Gaussian process, doubling training speed by reducing variance. Models trained with curriculum learning surpass autoregressive models in zero-shot perplexity on 3 of 7 benchmarks. Second, we present Discrete Consistency Distillation, which adapts consistency distillation from the continuous to the discrete setting. This algorithm unlocks few-step generation in diffusion language models by accelerating sampling by two orders of magnitude. We provide the code, model checkpoints, and video tutorials on the project page: http://s-sahoo.github.io/duo","published":"2025-06-12T16:55:35Z","updated":"2025-12-19T17:14:07Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.10892v3","pdf_url":"https://arxiv.org/pdf/2506.10892v3","comment":"ICML 2025. We provide the code at: https://github.com/s-sahoo/duo [v3] includes improved theory, clearer presentation, and a new future work section","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.10527","versioned_id":"2506.10527v1","title":"LogiPlan: A Structured Benchmark for Logical Planning and Relational Reasoning in LLMs","authors":["Yanan Cai","Ahmed Salem","Besmira Nushi","Mark Russinovich"],"abstract":"We introduce LogiPlan, a novel benchmark designed to evaluate the capabilities of large language models (LLMs) in logical planning and reasoning over complex relational structures. Logical relational reasoning is important for applications that may rely on LLMs to generate and query structured graphs of relations such as network infrastructure, knowledge bases, or business process schema. Our framework allows for dynamic variation of task complexity by controlling the number of objects, relations, and the minimum depth of relational chains, providing a fine-grained assessment of model performance across difficulty levels. LogiPlan encompasses three complementary tasks: (1) Plan Generation, where models must construct valid directed relational graphs meeting specified structural constraints; (2) Consistency Detection, testing models' ability to identify inconsistencies in relational structures; and (3) Comparison Question, evaluating models' capacity to determine the validity of queried relationships within a given graph. Additionally, we assess models' self-correction capabilities by prompting them to verify and refine their initial solutions. We evaluate state-of-the-art models including DeepSeek R1, Gemini 2.0 Pro, Gemini 2 Flash Thinking, GPT-4.5, GPT-4o, Llama 3.1 405B, O3-mini, O1, and Claude 3.7 Sonnet across these tasks, revealing significant performance gaps that correlate with model scale and architecture. Our analysis demonstrates that while recent reasoning-enhanced models show promising results on simpler instances, they struggle with more complex configurations requiring deeper logical planning.","published":"2025-06-12T09:47:02Z","updated":"2025-06-12T09:47:02Z","categories":["cs.AI","cs.PF"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.10527v1","pdf_url":"https://arxiv.org/pdf/2506.10527v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.10501","versioned_id":"2506.10501v2","title":"BugGen: A Self-Correcting Multi-Agent LLM Pipeline for Realistic RTL Bug Synthesis","authors":["Surya Jasper","Minh Luu","Evan Pan","Aakash Tyagi","Michael Quinn","Jiang Hu","David Kebo Houngninou"],"abstract":"Hardware complexity continues to strain verification resources, motivating the adoption of machine learning (ML) methods to improve debug efficiency. However, ML-assisted debugging critically depends on diverse and scalable bug datasets, which existing manual or automated bug insertion methods fail to reliably produce. We introduce BugGen, a first of its kind, fully autonomous, multi-agent pipeline leveraging Large Language Models (LLMs) to systematically generate, insert, and validate realistic functional bugs in RTL. BugGen partitions modules, selects mutation targets via a closed-loop agentic architecture, and employs iterative refinement and rollback mechanisms to ensure syntactic correctness and functional detectability. Evaluated across five OpenTitan IP blocks, BugGen produced 500 unique bugs with 94% functional accuracy and achieved a throughput of 17.7 validated bugs per hour-over five times faster than typical manual expert insertion. Additionally, BugGen identified 104 previously undetected bugs in OpenTitan regressions, highlighting its utility in exposing verification coverage gaps. Compared against Certitude, BugGen demonstrated over twice the syntactic accuracy, deeper exposure of testbench blind spots, and more functionally meaningful and complex bug scenarios. Furthermore, when these BugGen-generated datasets were employed to train ML-based failure triage models, we achieved high classification accuracy (88.1%-93.2%) across different IP blocks, confirming the practical utility and realism of generated bugs. BugGen thus provides a scalable solution for generating high-quality bug datasets, significantly enhancing verification efficiency and ML-assisted debugging.","published":"2025-06-12T09:02:20Z","updated":"2025-06-18T06:29:15Z","categories":["cs.SE","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2506.10501v2","pdf_url":"https://arxiv.org/pdf/2506.10501v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.10406","versioned_id":"2506.10406v1","title":"PAG: Multi-Turn Reinforced LLM Self-Correction with Policy as Generative Verifier","authors":["Yuhua Jiang","Yuwen Xiong","Yufeng Yuan","Chao Xin","Wenyuan Xu","Yu Yue","Qianchuan Zhao","Lin Yan"],"abstract":"Large Language Models (LLMs) have demonstrated impressive capabilities in complex reasoning tasks, yet they still struggle to reliably verify the correctness of their own outputs. Existing solutions to this verification challenge often depend on separate verifier models or require multi-stage self-correction training pipelines, which limit scalability. In this paper, we propose Policy as Generative Verifier (PAG), a simple and effective framework that empowers LLMs to self-correct by alternating between policy and verifier roles within a unified multi-turn reinforcement learning (RL) paradigm. Distinct from prior approaches that always generate a second attempt regardless of model confidence, PAG introduces a selective revision mechanism: the model revises its answer only when its own generative verification step detects an error. This verify-then-revise workflow not only alleviates model collapse but also jointly enhances both reasoning and verification abilities. Extensive experiments across diverse reasoning benchmarks highlight PAG's dual advancements: as a policy, it enhances direct generation and self-correction accuracy; as a verifier, its self-verification outperforms self-consistency.","published":"2025-06-12T06:59:35Z","updated":"2025-06-12T06:59:35Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.10406v1","pdf_url":"https://arxiv.org/pdf/2506.10406v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.09965","versioned_id":"2506.09965v2","title":"Reinforcing Spatial Reasoning in Vision-Language Models with Interwoven Thinking and Visual Drawing","authors":["Junfei Wu","Jian Guan","Kaituo Feng","Qiang Liu","Shu Wu","Liang Wang","Wei Wu","Tieniu Tan"],"abstract":"As textual reasoning with large language models (LLMs) has advanced significantly, there has been growing interest in enhancing the multimodal reasoning capabilities of large vision-language models (LVLMs). However, existing methods primarily approach multimodal reasoning in a straightforward, text-centric manner, where both reasoning and answer derivation are conducted purely through text, with the only difference being the presence of multimodal input. As a result, these methods often encounter fundamental limitations in spatial reasoning tasks that demand precise geometric understanding and continuous spatial tracking-capabilities that humans achieve through mental visualization and manipulation. To address the limitations, we propose drawing to reason in space, a novel paradigm that enables LVLMs to reason through elementary drawing operations in the visual space. By equipping models with basic drawing operations, including annotating bounding boxes and drawing auxiliary lines, we empower them to express and analyze spatial relationships through direct visual manipulation, meanwhile avoiding the performance ceiling imposed by specialized perception tools in previous tool-integrated reasoning approaches. To cultivate this capability, we develop a three-stage training framework: cold-start training with synthetic data to establish basic drawing abilities, reflective rejection sampling to enhance self-reflection behaviors, and reinforcement learning to directly optimize for target rewards. Extensive experiments demonstrate that our model, named VILASR, consistently outperforms existing methods across diverse spatial reasoning benchmarks, involving maze navigation, static spatial reasoning, video-based reasoning, and multi-view-based reasoning tasks, with an average improvement of 18.4%.","published":"2025-06-11T17:41:50Z","updated":"2025-06-19T03:46:55Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2506.09965v2","pdf_url":"https://arxiv.org/pdf/2506.09965v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.13793","versioned_id":"2506.13793v4","title":"Med-REFL: Medical Reasoning Enhancement via Self-Corrected Fine-grained Reflection","authors":["Zongxian Yang","Jiayu Qian","Zegao Peng","Haoyu Zhang","Yu-An Huang","KC Tan","Zhi-An Huang"],"abstract":"Large reasoning models excel in domains like mathematics where intermediate reasoning is straightforward to verify, but struggle to self-correct in medicine fields where evaluating intermediate reasoning is cumbersome and expensive. This verification bottleneck hinders the development of reliable AI reasoners for high-stakes application. Here we propose Med-REFL, a novel framework that learns fine-grained reflection without human labels or model distillation. Med-REFL introduces a deterministic structural assessment of the reasoning space to automatically generate preference data for reflection. By globally evaluating all explored reasoning paths in a tree-of-thoughts, our method quantifies the value of corrective actions, enabling the automated construction of direct preference optimization pairs. This trains the model to recognize and amend its own reasoning fallacies. Extensive experiments show Med-REFL delivers robust gains across diverse models architectures and medical benchmarks, boosting a general-purpose Llama3.1-8B by +5.82% and the state-of-the-art Huatuo-o1 by +4.13% on the MedQA benchmark. Our Med-REFL-8B achieves state-of-the-art performance among 7-8B models while even competing with models twice its size. Crucially, targeted ablations prove its success generalizes to other domains such as logical reasoning and mitigates the `fake reflection' phenomenon in LRMs. Ultimately, our framework provides a scalable solution to the verification bottleneck, paving the way for more reliable AI reasoners in high-stakes domains like medicine. Med-REFL has been made publicly available in https://github.com/TianYin123/Med-REFL.","published":"2025-06-11T14:58:38Z","updated":"2026-02-25T12:16:37Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.13793v4","pdf_url":"https://arxiv.org/pdf/2506.13793v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.09657","versioned_id":"2506.09657v2","title":"Team Anotheroption at SemEval-2025 Task 8: Bridging the Gap Between Open-Source and Proprietary LLMs in Table QA","authors":["Nikolas Evkarpidi","Elena Tutubalina"],"abstract":"This paper presents a system developed for SemEval 2025 Task 8: Question Answering (QA) over tabular data. Our approach integrates several key components: text-to-SQL and text-to-code generation modules, a self-correction mechanism, and a retrieval-augmented generation (RAG). Additionally, it includes an end-to-end (E2E) module, all orchestrated by a large language model (LLM). Through ablation studies, we analyzed the effects of different parts of our pipeline and identified the challenges that are still present in this field. During the evaluation phase of the competition, our solution achieved an accuracy of 80%, resulting in a top-13 ranking among the 38 participating teams. Our pipeline demonstrates a significant improvement in accuracy for open-source models and achieves a performance comparable to proprietary LLMs in QA tasks over tables. The code is available at GitHub repository.","published":"2025-06-11T12:26:08Z","updated":"2025-06-16T07:42:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.09657v2","pdf_url":"https://arxiv.org/pdf/2506.09657v2","comment":"Accepted for publication at the 19th International Workshop on Semantic Evaluation (SemEval-2025), to be held in conjunction with ACL 2025. 15 pages, 5 figures; full paper title was added","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.13983","versioned_id":"2506.13983v1","title":"SANGAM: SystemVerilog Assertion Generation via Monte Carlo Tree Self-Refine","authors":["Adarsh Gupta","Bhabesh Mali","Chandan Karfa"],"abstract":"Recent advancements in the field of reasoning using Large Language Models (LLMs) have created new possibilities for more complex and automatic Hardware Assertion Generation techniques. This paper introduces SANGAM, a SystemVerilog Assertion Generation framework using LLM-guided Monte Carlo Tree Search for the automatic generation of SVAs from industry-level specifications. The proposed framework utilizes a three-stage approach: Stage 1 consists of multi-modal Specification Processing using Signal Mapper, SPEC Analyzer, and Waveform Analyzer LLM Agents. Stage 2 consists of using the Monte Carlo Tree Self-Refine (MCTSr) algorithm for automatic reasoning about SVAs for each signal, and finally, Stage 3 combines the MCTSr-generated reasoning traces to generate SVA assertions for each signal. The results demonstrated that our framework, SANGAM, can generate a robust set of SVAs, performing better in the evaluation process in comparison to the recent methods.","published":"2025-06-11T06:43:24Z","updated":"2025-06-11T06:43:24Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.13983v1","pdf_url":"https://arxiv.org/pdf/2506.13983v1","comment":"Adarsh Gupta and Bhabesh Mali contributed equally to this work","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.11130","versioned_id":"2506.11130v2","title":"A Self-Refining Framework for Enhancing ASR Using TTS-Synthesized Data","authors":["Cheng-Kang Chou","Chan-Jan Hsu","Ho-Lam Chung","Liang-Hsuan Tseng","Hsi-Chun Cheng","Yu-Kuan Fu","Kuan Po Huang","Hung-Yi Lee"],"abstract":"We propose a self-refining framework that enhances ASR performance with only unlabeled datasets. The process starts with an existing ASR model generating pseudo-labels on unannotated speech, which are then used to train a high-fidelity text-to-speech (TTS) system. Then, synthesized speech text pairs are bootstrapped into the original ASR system, completing the closed-loop self-improvement cycle. We demonstrated the effectiveness of the framework on Taiwanese Mandarin speech. Leveraging 6,000 hours of unlabeled speech, a moderate amount of text data, and synthetic content from the AI models, we adapt Whisper-large-v2 into a specialized model, Twister. Twister reduces error rates by up to 20% on Mandarin and 50% on Mandarin-English code-switching benchmarks compared to Whisper. Results highlight the framework as a compelling alternative to pseudo-labeling self-distillation approaches and provides a practical pathway for improving ASR performance in low-resource or domain-specific settings.","published":"2025-06-10T17:30:32Z","updated":"2025-06-16T15:47:41Z","categories":["cs.CL","cs.AI","cs.SD","eess.AS"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.11130v2","pdf_url":"https://arxiv.org/pdf/2506.11130v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.09107","versioned_id":"2506.09107v1","title":"FAIRTOPIA: Envisioning Multi-Agent Guardianship for Disrupting Unfair AI Pipelines","authors":["Athena Vakali","Ilias Dimitriadis"],"abstract":"AI models have become active decision makers, often acting without human supervision. The rapid advancement of AI technology has already caused harmful incidents that have hurt individuals and societies and AI unfairness in heavily criticized. It is urgent to disrupt AI pipelines which largely neglect human principles and focus on computational biases exploration at the data (pre), model(in), and deployment (post) processing stages. We claim that by exploiting the advances of agents technology, we will introduce cautious, prompt, and ongoing fairness watch schemes, under realistic, systematic, and human-centric fairness expectations. We envision agents as fairness guardians, since agents learn from their environment, adapt to new information, and solve complex problems by interacting with external tools and other systems. To set the proper fairness guardrails in the overall AI pipeline, we introduce a fairness-by-design approach which embeds multi-role agents in an end-to-end (human to AI) synergetic scheme. Our position is that we may design adaptive and realistic AI fairness frameworks, and we introduce a generalized algorithm which can be customized to the requirements and goals of each AI decision making scenario. Our proposed, so called FAIRTOPIA framework, is structured over a three-layered architecture, which encapsulates the AI pipeline inside an agentic guardian and a knowledge-based, self-refining layered scheme. Based on our proposition, we enact fairness watch in all of the AI pipeline stages, under robust multi-agent workflows, which will inspire new fairness research hypothesis, heuristics, and methods grounded in human-centric, systematic, interdisciplinary, socio-technical principles.","published":"2025-06-10T17:02:43Z","updated":"2025-06-10T17:02:43Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2506.09107v1","pdf_url":"https://arxiv.org/pdf/2506.09107v1","comment":"11 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.08726","versioned_id":"2506.08726v3","title":"Improved LLM Agents for Financial Document Question Answering","authors":["Nelvin Tan","Zian Seng","Liang Zhang","Yu-Ching Shih","Dong Yang","Amol Salunkhe"],"abstract":"Large language models (LLMs) have shown impressive capabilities on numerous natural language processing tasks. However, LLMs still struggle with numerical question answering for financial documents that include tabular and textual data. Recent works have showed the effectiveness of critic agents (i.e., self-correction) for this task given oracle labels. Building upon this framework, this paper examines the effectiveness of the traditional critic agent when oracle labels are not available, and show, through experiments, that this critic agent's performance deteriorates in this scenario. With this in mind, we present an improved critic agent, along with the calculator agent which outperforms the previous state-of-the-art approach (program-of-thought) and is safer. Furthermore, we investigate how our agents interact with each other, and how this interaction affects their performance.","published":"2025-06-10T12:22:57Z","updated":"2026-01-07T07:50:27Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.08726v3","pdf_url":"https://arxiv.org/pdf/2506.08726v3","comment":"13 pages, 6 figures. More analysis is added to Appendix C","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.08551","versioned_id":"2506.08551v2","title":"DeepForm: Reasoning Large Language Model for Communication System Formulation","authors":["Panlong Wu","Ting Wang","Yifei Zhong","Haoqi Zhang","Zitong Wang","Fangxin Wang"],"abstract":"Communication system formulation is critical for advancing 6G and future wireless technologies, yet it remains a complex, expertise-intensive task. While Large Language Models (LLMs) offer potential, existing general-purpose models often lack the specialized domain knowledge, nuanced reasoning capabilities, and access to high-quality, domain-specific training data required for adapting a general LLM into an LLM specially for communication system formulation. To bridge this gap, we introduce DeepForm, the first reasoning LLM specially for automated communication system formulation. We propose the world-first large-scale, open-source dataset meticulously curated for this domain called Communication System Formulation Reasoning Corpus (CSFRC). Our framework employs a two-stage training strategy: first, Supervised Fine-Tuning (SFT) with Chain-of-Thought (CoT) data to distill domain knowledge; second, a novel rule-based Reinforcement Learning (RL) algorithm, C-ReMax based on ReMax, to cultivate advanced modeling capabilities and elicit sophisticated reasoning patterns like self-correction and verification. Extensive experiments demonstrate that our model achieves state-of-the-art performance, significantly outperforming larger proprietary LLMs on diverse senerios. We will release related resources to foster further research in this area after the paper is accepted.","published":"2025-06-10T08:16:24Z","updated":"2025-06-11T05:56:27Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.08551v2","pdf_url":"https://arxiv.org/pdf/2506.08551v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.08343","versioned_id":"2506.08343v2","title":"Wait, We Don't Need to \"Wait\"! Removing Thinking Tokens Improves Reasoning Efficiency","authors":["Chenlong Wang","Yuanning Feng","Dongping Chen","Zhaoyang Chu","Ranjay Krishna","Tianyi Zhou"],"abstract":"Recent advances in large reasoning models have enabled complex, step-by-step reasoning but often introduce significant overthinking, resulting in verbose and redundant outputs that hinder efficiency. In this study, we examine whether explicit self-reflection, signaled by tokens such as \"Wait\" and \"Hmm\", is necessary for advanced reasoning. We propose NoWait, a simple yet effective approach that disables explicit self-reflection by suppressing these tokens during inference. Extensive experiments on ten benchmarks across textual, visual, and video reasoning tasks show that NoWait reduces chain-of-thought trajectory length by up to 27%-51% in five R1-style model series, without compromising model utility. NoWait thus offers a plug-and-play solution for efficient and utility-preserving multimodal reasoning.","published":"2025-06-10T01:54:04Z","updated":"2025-06-18T14:43:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.08343v2","pdf_url":"https://arxiv.org/pdf/2506.08343v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.08012","versioned_id":"2506.08012v1","title":"GUI-Reflection: Empowering Multimodal GUI Models with Self-Reflection Behavior","authors":["Penghao Wu","Shengnan Ma","Bo Wang","Jiaheng Yu","Lewei Lu","Ziwei Liu"],"abstract":"Multimodal Large Language Models (MLLMs) have shown great potential in revolutionizing Graphical User Interface (GUI) automation. However, existing GUI models mostly rely on learning from nearly error-free offline trajectories, thus lacking reflection and error recovery capabilities. To bridge this gap, we propose GUI-Reflection, a novel framework that explicitly integrates self-reflection and error correction capabilities into end-to-end multimodal GUI models throughout dedicated training stages: GUI-specific pre-training, offline supervised fine-tuning (SFT), and online reflection tuning. GUI-reflection enables self-reflection behavior emergence with fully automated data generation and learning processes without requiring any human annotation. Specifically, 1) we first propose scalable data pipelines to automatically construct reflection and error correction data from existing successful trajectories. While existing GUI models mainly focus on grounding and UI understanding ability, we propose the GUI-Reflection Task Suite to learn and evaluate reflection-oriented abilities explicitly. 2) Furthermore, we built a diverse and efficient environment for online training and data collection of GUI models on mobile devices. 3) We also present an iterative online reflection tuning algorithm leveraging the proposed environment, enabling the model to continuously enhance its reflection and error correction abilities. Our framework equips GUI agents with self-reflection and correction capabilities, paving the way for more robust, adaptable, and intelligent GUI automation, with all data, models, environments, and tools to be released publicly.","published":"2025-06-09T17:59:57Z","updated":"2025-06-09T17:59:57Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.08012v1","pdf_url":"https://arxiv.org/pdf/2506.08012v1","comment":"Project Page at https://penghao-wu.github.io/GUI_Reflection/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.07963","versioned_id":"2506.07963v3","title":"SUDER: Self-Improving Unified Large Multimodal Models for Understanding and Generation with Dual Self-Rewards","authors":["Jixiang Hong","Yiran Zhang","Guanzhong Wang","Yi Liu","Ji-Rong Wen","Rui Yan"],"abstract":"Building upon large language models (LLMs), recent large multimodal models (LMMs) unify cross-model understanding and generation into a single framework. However, LMMs still struggle to achieve accurate vision-language alignment, prone to generating text responses contradicting the visual input or failing to follow the text-to-image prompts. Current solutions require external supervision (e.g., human feedback or reward models) and only address unidirectional tasks-either understanding or generation. In this work, based on the observation that understanding and generation are naturally inverse dual tasks, we propose \\textbf{SUDER} (\\textbf{S}elf-improving \\textbf{U}nified LMMs with \\textbf{D}ual s\\textbf{E}lf-\\textbf{R}ewards), a framework reinforcing the understanding and generation capabilities of LMMs with a self-supervised dual reward mechanism. SUDER leverages the inherent duality between understanding and generation tasks to provide self-supervised optimization signals for each other. Specifically, we sample multiple outputs for a given input in one task domain, then reverse the input-output pairs to compute the dual likelihood within the model as self-rewards for optimization. Extensive experimental results on visual understanding and generation benchmarks demonstrate that our method can effectively enhance the performance of the model without any external supervision, especially achieving remarkable improvements in text-to-image tasks.","published":"2025-06-09T17:38:45Z","updated":"2025-09-08T14:31:08Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.07963v3","pdf_url":"https://arxiv.org/pdf/2506.07963v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.07927","versioned_id":"2506.07927v3","title":"Solving Inequality Proofs with Large Language Models","authors":["Pan Lu","Jiayi Sheng","Luna Lyu","Jikai Jin","Tony Xia","Alex Gu","James Zou"],"abstract":"Inequality proving, crucial across diverse scientific and mathematical fields, tests advanced reasoning skills such as discovering tight bounds and strategic theorem application. This makes it a distinct, demanding frontier for large language models (LLMs), offering insights beyond general mathematical problem-solving. Progress in this area is hampered by existing datasets that are often scarce, synthetic, or rigidly formal. We address this by proposing an informal yet verifiable task formulation, recasting inequality proving into two automatically checkable subtasks: bound estimation and relation prediction. Building on this, we release IneqMath, an expert-curated dataset of Olympiad-level inequalities, including a test set and training corpus enriched with step-wise solutions and theorem annotations. We also develop a novel LLM-as-judge evaluation framework, combining a final-answer judge with four step-wise judges designed to detect common reasoning flaws. A systematic evaluation of 29 leading LLMs on IneqMath reveals a surprising reality: even top models like o1 achieve less than 10% overall accuracy under step-wise scrutiny; this is a drop of up to 65.5% from their accuracy considering only final answer equivalence. This discrepancy exposes fragile deductive chains and a critical gap for current LLMs between merely finding an answer and constructing a rigorous proof. Scaling model size and increasing test-time computation yield limited gains in overall proof correctness. Instead, our findings highlight promising research directions such as theorem-guided reasoning and self-refinement. Code and data are available at https://ineqmath.github.io/.","published":"2025-06-09T16:43:38Z","updated":"2025-12-15T01:49:41Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.07927v3","pdf_url":"https://arxiv.org/pdf/2506.07927v3","comment":"50 pages, 24 figures, accepted as a Spotlight at NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.07915","versioned_id":"2506.07915v2","title":"A Signal Contract for Online Language Grounding and Discovery in Decision-Making","authors":["Dimitris Panagopoulos","Adolfo Perrusquia","Weisi Guo"],"abstract":"Autonomous systems increasingly receive time-sensitive contextual updates from humans through natural language, yet embedding language understanding inside decision-makers couples grounding to learning or planning. This increases redeployment burden when language conventions or domain knowledge change and can hinder diagnosability by confounding grounding errors with control errors. We address online language grounding where messy, evolving verbal reports are converted into control-relevant signals during execution through an interface that localises language updates while keeping downstream decision-makers language-agnostic. We propose LUCIFER (Language Understanding and Context-Infused Framework for Exploration and Behavior Refinement), an inference-only middleware that exposes a Signal Contract. The contract provides four outputs, policy priors, reward potentials, admissible-option constraints, and telemetry-based action prediction for efficient information gathering. We validate LUCIFER in a search-and-rescue (SAR)-inspired testbed using dual-phase, dual-client evaluation: (i) component benchmarks show reasoning-based extraction remains robust on self-correcting reports where pattern-matching baselines degrade, and (ii) system-level ablations with two structurally distinct clients (hierarchical RL and a hybrid A*+heuristics planner) show consistent necessity and synergy. Grounding improves safety, discovery improves information-collection efficiency, and only their combination achieves both.","published":"2025-06-09T16:30:05Z","updated":"2026-03-05T13:07:58Z","categories":["cs.AI","cs.CL","eess.SY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.07915v2","pdf_url":"https://arxiv.org/pdf/2506.07915v2","comment":"10 pages, 4 Figures, 4 Tables, submitted to the IEEE for possible publication","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.07652","versioned_id":"2506.07652v1","title":"FMaMIL: Frequency-Driven Mamba Multi-Instance Learning for Weakly Supervised Lesion Segmentation in Medical Images","authors":["Hangbei Cheng","Xiaorong Dong","Xueyu Liu","Jianan Zhang","Xuetao Ma","Mingqiang Wei","Liansheng Wang","Junxin Chen","Yongfei Wu"],"abstract":"Accurate lesion segmentation in histopathology images is essential for diagnostic interpretation and quantitative analysis, yet it remains challenging due to the limited availability of costly pixel-level annotations. To address this, we propose FMaMIL, a novel two-stage framework for weakly supervised lesion segmentation based solely on image-level labels. In the first stage, a lightweight Mamba-based encoder is introduced to capture long-range dependencies across image patches under the MIL paradigm. To enhance spatial sensitivity and structural awareness, we design a learnable frequency-domain encoding module that supplements spatial-domain features with spectrum-based information. CAMs generated in this stage are used to guide segmentation training. In the second stage, we refine the initial pseudo labels via a CAM-guided soft-label supervision and a self-correction mechanism, enabling robust training even under label noise. Extensive experiments on both public and private histopathology datasets demonstrate that FMaMIL outperforms state-of-the-art weakly supervised methods without relying on pixel-level annotations, validating its effectiveness and potential for digital pathology applications.","published":"2025-06-09T11:18:02Z","updated":"2025-06-09T11:18:02Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2506.07652v1","pdf_url":"https://arxiv.org/pdf/2506.07652v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.07527","versioned_id":"2506.07527v3","title":"Learning What Reinforcement Learning Can't: Interleaved Online Fine-Tuning for Hardest Questions","authors":["Lu Ma","Hao Liang","Meiyi Qiang","Lexiang Tang","Xiaochen Ma","Zhen Hao Wong","Junbo Niu","Chengyu Shen","Runming He","Yanhao Li","Bin Cui","Wentao Zhang"],"abstract":"Recent advances in large language model (LLM) reasoning have shown that sophisticated behaviors such as planning and self-reflection can emerge through reinforcement learning (RL). However, despite these successes, RL in its current form remains insufficient to induce capabilities that exceed the limitations of the base model, as it is primarily optimized based on existing knowledge of the model rather than facilitating the acquisition of new information. To address this limitation, we employ supervised fine-tuning (SFT) to learn what RL cannot, which enables the incorporation of new knowledge and reasoning patterns by leveraging high-quality demonstration data. We analyze the training dynamics of RL and SFT for LLM reasoning and find that RL excels at maintaining and improving performance on questions within the model's original capabilities, while SFT is more effective at enabling progress on questions beyond the current scope of the model. Motivated by the complementary strengths of RL and SFT, we introduce a novel training approach, \\textbf{ReLIFT} (\\textbf{Re}inforcement \\textbf{L}earning \\textbf{I}nterleaved with Online \\textbf{F}ine-\\textbf{T}uning). In ReLIFT, the model is primarily trained using RL, but when it encounters challenging questions, high-quality solutions are collected for fine-tuning, and the training process alternates between RL and fine-tuning to enhance the model's reasoning abilities. ReLIFT achieves an average improvement of over +5.2 points across five competition-level benchmarks and one out-of-distribution benchmark compared to other zero-RL models. Furthermore, we demonstrate that ReLIFT outperforms both RL and SFT while using only 13\\% of the detailed demonstration data, highlighting its scalability. These results provide compelling evidence that ReLIFT overcomes the fundamental limitations of RL and underscores the significant potential.","published":"2025-06-09T08:11:20Z","updated":"2026-03-11T17:08:49Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.07527v3","pdf_url":"https://arxiv.org/pdf/2506.07527v3","comment":"12 pages, 5 figures","journal_ref":"ICLR 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2506.07468","versioned_id":"2506.07468v4","title":"Chasing Moving Targets with Online Self-Play Reinforcement Learning for Safer Language Models","authors":["Mickel Liu","Liwei Jiang","Yancheng Liang","Simon Shaolei Du","Yejin Choi","Tim Althoff","Natasha Jaques"],"abstract":"Conventional large language model (LLM) safety alignment relies on a reactive, disjoint loop: attackers exploit a static model, then defenders patch exposed vulnerabilities. This sequential setup leads to attackers overfitting obsolete exploits while defenders perpetually lag behind emerging threats. To address this, we introduce Self-RedTeam, the first fully online self-play multi-agent reinforcement learning (MARL) algorithm that continuously co-evolves attacker and defender for robust safety alignment. A single policy self-plays as both attacker and defender, generating adversarial prompts and defending against them, with a reward model adjudicating outcomes. Each role uses hidden chain-of-thought for strategic planning. Grounded in two-player zero-sum game theory, we establish a theoretical safety guarantee: if the game converges to Nash Equilibrium, the defender produces safe responses against any adversarial input. Empirically, Self-RedTeam generalizes across five models from the Llama and Qwen families, uncovering more diverse attacks (+17.80% SBERT) and improving safety of RLHF-trained models by up to 95% across 14 benchmarks. Our work motivates a shift from reactive patching to proactive co-evolution, enabling LLM safety self-improvement via online self-play MARL. Link to code: https://github.com/mickelliu/selfplay-redteaming","published":"2025-06-09T06:35:12Z","updated":"2026-07-06T07:31:35Z","categories":["cs.LG","cs.CL","cs.MA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.07468v4","pdf_url":"https://arxiv.org/pdf/2506.07468v4","comment":"ICML 2026 Poster","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.07459","versioned_id":"2506.07459v3","title":"ProteinZero: Self-Improving Protein Generation via Online Reinforcement Learning","authors":["Ziwen Wang","Jiajun Fan","Ruihan Guo","Thao Nguyen","Heng Ji","Ge Liu"],"abstract":"Protein generative models have shown remarkable promise in protein design, yet their success rates remain constrained by reliance on curated sequence-structure datasets and by misalignment between supervised objectives and real design goals. We present ProteinZero, an online reinforcement learning framework for inverse folding models that enables scalable, automated, and continuous self-improvement with computationally efficient feedback. ProteinZero employs a reward pipeline that combines structural guidance from ESMFold with a novel self-derived ddG predictor, providing stable multi-objective signals while avoiding the prohibitive cost of physics-based methods. To ensure robustness in online RL, we further introduce a novel embedding-level diversity regularizer that mitigates mode collapse and promotes functionally meaningful sequence variation. Within a general RL formulation balancing multi-reward optimization, KL-divergence from a reference model, and diversity regularization, ProteinZero achieves robust improvements across designability, stability, recovery, and diversity. On the CATH-4.3 benchmark, it consistently outperforms state-of-the-art baselines including ProteinMPNN, ESM-IF, and InstructPLM, reducing design failure rates by 36-48% and achieving success rates above 90% across diverse folds. Importantly, a complete RL run can be executed on a single 8 X GPU node within three days, including reward computation and data generation. These results indicate that efficient online RL fine-tuning can complement supervised pretraining by allowing protein generative models to evolve continuously from their own outputs and optimize multiple design objectives without labeled data, opening new possibilities for exploring the vast protein design space. Full source code and model checkpoints will be released upon publication.","published":"2025-06-09T06:08:59Z","updated":"2026-03-02T05:31:24Z","categories":["cs.LG","q-bio.QM"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.07459v3","pdf_url":"https://arxiv.org/pdf/2506.07459v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.06923","versioned_id":"2506.06923v1","title":"Boosting LLM Reasoning via Spontaneous Self-Correction","authors":["Xutong Zhao","Tengyu Xu","Xuewei Wang","Zhengxing Chen","Di Jin","Liang Tan","Yen-Ting","Zishun Yu","Zhuokai Zhao","Yun He","Sinong Wang","Han Fang","Sarath Chandar","Chen Zhu"],"abstract":"While large language models (LLMs) have demonstrated remarkable success on a broad range of tasks, math reasoning remains a challenging one. One of the approaches for improving math reasoning is self-correction, which designs self-improving loops to let the model correct its own mistakes. However, existing self-correction approaches treat corrections as standalone post-generation refinements, relying on extra prompt and system designs to elicit self-corrections, instead of performing real-time, spontaneous self-corrections in a single pass. To address this, we propose SPOC, a spontaneous self-correction approach that enables LLMs to generate interleaved solutions and verifications in a single inference pass, with generation dynamically terminated based on verification outcomes, thereby effectively scaling inference time compute. SPOC considers a multi-agent perspective by assigning dual roles -- solution proposer and verifier -- to the same model. We adopt a simple yet effective approach to generate synthetic data for fine-tuning, enabling the model to develop capabilities for self-verification and multi-agent collaboration. We further improve its solution proposal and verification accuracy through online reinforcement learning. Experiments on mathematical reasoning benchmarks show that SPOC significantly improves performance. Notably, SPOC boosts the accuracy of Llama-3.1-8B and 70B Instruct models, achieving gains of 8.8% and 11.6% on MATH500, 10.0% and 20.0% on AMC23, and 3.3% and 6.7% on AIME24, respectively.","published":"2025-06-07T21:23:00Z","updated":"2025-06-07T21:23:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.06923v1","pdf_url":"https://arxiv.org/pdf/2506.06923v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.06698","versioned_id":"2506.06698v1","title":"Contextual Experience Replay for Self-Improvement of Language Agents","authors":["Yitao Liu","Chenglei Si","Karthik Narasimhan","Shunyu Yao"],"abstract":"Large language model (LLM) agents have been applied to sequential decision-making tasks such as web navigation, but without any environment-specific experiences, they often fail in these complex tasks. Moreover, current LLM agents are not designed to continually learn from past experiences during inference time, which could be crucial for them to gain these environment-specific experiences. To address this, we propose Contextual Experience Replay (CER), a training-free framework to enable efficient self-improvement for language agents in their context window. Specifically, CER accumulates and synthesizes past experiences into a dynamic memory buffer. These experiences encompass environment dynamics and common decision-making patterns, allowing the agents to retrieve and augment themselves with relevant knowledge in new tasks, enhancing their adaptability in complex environments. We evaluate CER on the challenging WebArena and VisualWebArena benchmarks. On VisualWebArena, CER achieves a competitive performance of 31.9%. On WebArena, CER also gets a competitive average success rate of 36.7%, relatively improving the success rate of the GPT-4o agent baseline by 51.0%. We also conduct a comprehensive analysis on it to prove its efficiency, validity and understand it better.","published":"2025-06-07T07:47:35Z","updated":"2025-06-07T07:47:35Z","categories":["cs.AI","cs.CL","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.06698v1","pdf_url":"https://arxiv.org/pdf/2506.06698v1","comment":"Accepted to ACL 2025. 20 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.06658","versioned_id":"2506.06658v3","title":"Self-Improving Loops for Visual Robotic Planning","authors":["Calvin Luo","Zilai Zeng","Mingxi Jia","Yilun Du","Chen Sun"],"abstract":"Video generative models trained on expert demonstrations have been utilized as performant text-conditioned visual planners for solving robotic tasks. However, generalization to unseen tasks remains a challenge. Whereas improved generalization may be facilitated by leveraging learned prior knowledge from additional pre-collected offline data sources, such as web-scale video datasets, in the era of experience we aim to design agents that can continuously improve in an online manner from self-collected behaviors. In this work we thus propose the Self-Improving Loops for Visual Robotic Planning (SILVR), where an in-domain video model iteratively updates itself on self-produced trajectories, and steadily improves its performance for a specified task of interest. We apply SILVR to a diverse suite of MetaWorld tasks, as well as two manipulation tasks on a real robot arm, and find that performance improvements continuously emerge over multiple iterations for novel tasks unseen during initial in-domain video model training. We demonstrate that SILVR is robust in the absence of human-provided ground-truth reward functions or expert-quality demonstrations, and is preferable to alternate approaches that utilize online experience in terms of performance and sample efficiency.","published":"2025-06-07T04:34:37Z","updated":"2026-03-11T01:24:50Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2506.06658v3","pdf_url":"https://arxiv.org/pdf/2506.06658v3","comment":"ICLR 2026. Project Page: https://diffusion-supervision.github.io/silvr/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.06020","versioned_id":"2506.06020v1","title":"When to Trust Context: Self-Reflective Debates for Context Reliability","authors":["Zeqi Zhou","Fang Wu","Shayan Talaei","Haokai Zhao","Cheng Meixin","Tinson Xu","Amin Saberi","Yejin Choi"],"abstract":"Large language models frequently encounter conflicts between their parametric knowledge and contextual input, often resulting in factual inconsistencies or hallucinations. We propose Self-Reflective Debate for Contextual Reliability (SR-DCR), a lightweight framework that integrates token-level self-confidence with an asymmetric multi-agent debate to adjudicate such conflicts. A critic, deprived of context, challenges a defender who argues from the given passage; a judge model evaluates the debate and determines the context's reliability. The final answer is selected by combining the verdict with model confidence. Experiments on the ClashEval benchmark demonstrate that SR-DCR consistently enhances robustness to misleading context while maintaining accuracy on trustworthy inputs, outperforming both classical debate and confidence-only baselines with minimal computational overhead. The code is available at https://github.com/smiles724/Self-Reflective-Debates.","published":"2025-06-06T12:09:34Z","updated":"2025-06-06T12:09:34Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.06020v1","pdf_url":"https://arxiv.org/pdf/2506.06020v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.05566","versioned_id":"2506.05566v2","title":"ScaleRTL: Scaling LLMs with Reasoning Data and Test-Time Compute for Accurate RTL Code Generation","authors":["Chenhui Deng","Yun-Da Tsai","Guan-Ting Liu","Zhongzhi Yu","Haoxing Ren"],"abstract":"Recent advances in large language models (LLMs) have enabled near-human performance on software coding benchmarks, but their effectiveness in RTL code generation remains limited due to the scarcity of high-quality training data. While prior efforts have fine-tuned LLMs for RTL tasks, they do not fundamentally overcome the data bottleneck and lack support for test-time scaling due to their non-reasoning nature. In this work, we introduce ScaleRTL, the first reasoning LLM for RTL coding that scales up both high-quality reasoning data and test-time compute. Specifically, we curate a diverse set of long chain-of-thought reasoning traces averaging 56K tokens each, resulting in a dataset of 3.5B tokens that captures rich RTL knowledge. Fine-tuning a general-purpose reasoning model on this corpus yields ScaleRTL that is capable of deep RTL reasoning. Subsequently, we further enhance the performance of ScaleRTL through a novel test-time scaling strategy that extends the reasoning process via iteratively reflecting on and self-correcting previous reasoning steps. Experimental results show that ScaleRTL achieves state-of-the-art performance on VerilogEval and RTLLM, outperforming 18 competitive baselines by up to 18.4% on VerilogEval and 12.7% on RTLLM.","published":"2025-06-05T20:24:58Z","updated":"2025-07-15T21:44:21Z","categories":["cs.AR","cs.AI"],"primary_category":"cs.AR","arxiv_url":"https://arxiv.org/abs/2506.05566v2","pdf_url":"https://arxiv.org/pdf/2506.05566v2","comment":"Accepted to MLCAD 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.05295","versioned_id":"2506.05295v2","title":"Sample Complexity and Representation Ability of Test-time Scaling Paradigms","authors":["Baihe Huang","Shanda Li","Tianhao Wu","Yiming Yang","Ameet Talwalkar","Kannan Ramchandran","Michael I. Jordan","Jiantao Jiao"],"abstract":"Test-time scaling paradigms have significantly advanced the capabilities of large language models (LLMs) on complex tasks. Despite their empirical success, theoretical understanding of the sample efficiency of various test-time strategies -- such as self-consistency, best-of-$n$, and self-correction -- remains limited. In this work, we first establish a separation result between two repeated sampling strategies: self-consistency requires $Θ(1/Δ^2)$ samples to produce the correct answer, while best-of-$n$ only needs $Θ(1/Δ)$, where $Δ< 1$ denotes the probability gap between the correct and second most likely answers. Next, we present an expressiveness result for the self-correction approach with verifier feedback: it enables Transformers to simulate online learning over a pool of experts at test time. Therefore, a single Transformer architecture can provably solve multiple tasks without prior knowledge of the specific task associated with a user query, extending the representation theory of Transformers from single-task to multi-task settings. Finally, we empirically validate our theoretical results, demonstrating the practical effectiveness of self-correction methods.","published":"2025-06-05T17:48:19Z","updated":"2025-06-12T16:25:06Z","categories":["cs.LG","cs.AI","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.05295v2","pdf_url":"https://arxiv.org/pdf/2506.05295v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.05109","versioned_id":"2506.05109v1","title":"Truly Self-Improving Agents Require Intrinsic Metacognitive Learning","authors":["Tennison Liu","Mihaela van der Schaar"],"abstract":"Self-improving agents aim to continuously acquire new capabilities with minimal supervision. However, current approaches face two key limitations: their self-improvement processes are often rigid, fail to generalize across tasks domains, and struggle to scale with increasing agent capabilities. We argue that effective self-improvement requires intrinsic metacognitive learning, defined as an agent's intrinsic ability to actively evaluate, reflect on, and adapt its own learning processes. Drawing inspiration from human metacognition, we introduce a formal framework comprising three components: metacognitive knowledge (self-assessment of capabilities, tasks, and learning strategies), metacognitive planning (deciding what and how to learn), and metacognitive evaluation (reflecting on learning experiences to improve future learning). Analyzing existing self-improving agents, we find they rely predominantly on extrinsic metacognitive mechanisms, which are fixed, human-designed loops that limit scalability and adaptability. Examining each component, we contend that many ingredients for intrinsic metacognition are already present. Finally, we explore how to optimally distribute metacognitive responsibilities between humans and agents, and robustly evaluate and improve intrinsic metacognitive learning, key challenges that must be addressed to enable truly sustained, generalized, and aligned self-improvement.","published":"2025-06-05T14:53:35Z","updated":"2025-06-05T14:53:35Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.05109v1","pdf_url":"https://arxiv.org/pdf/2506.05109v1","comment":"Published as a conference paper at ICML 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.04746","versioned_id":"2506.04746v1","title":"Multi-Layer GRPO: Enhancing Reasoning and Self-Correction in Large Language Models","authors":["Fei Ding","Baiqiao Wang","Zijian Zeng","Youwei Wang"],"abstract":"The Group Relative Policy Optimization (GRPO) algorithm has demonstrated considerable success in enhancing the reasoning capabilities of large language models (LLMs), as evidenced by DeepSeek-R1. However, the absence of intermediate supervision in GRPO frequently leads to inefficient exploration dynamics. A single error in a complex reasoning chain can invalidate the entire solution, resulting in abrupt reward vanishing and compromising training stability.To address these challenges, we propose MGRPO (Multi-layer GRPO). MGRPO operates in two layers: the first layer employs standard GRPO to generate an initial response. This response, along with the original query, is then fed into a second-layer GRPO process. This second layer is specifically trained to identify and correct errors in the initial response, effectively creating a self-correction loop. This mechanism provides implicit process-level supervision by rewarding successful error correction, without requiring an explicit, densely-annotated reward model. Experimental results on several mathematical reasoning benchmarks demonstrate that MGRPO significantly outperforms standard GRPO, achieving superior performance by fostering both reasoning and self-correction abilities.","published":"2025-06-05T08:27:34Z","updated":"2025-06-05T08:27:34Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.04746v1","pdf_url":"https://arxiv.org/pdf/2506.04746v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.04521","versioned_id":"2506.04521v2","title":"Please Translate Again: Two Simple Experiments on Whether Human-Like Reasoning Helps Translation","authors":["Di Wu","Seth Aycock","Christof Monz"],"abstract":"Large Language Models (LLMs) demonstrate strong reasoning capabilities for many tasks, often by explicitly decomposing the task via Chain-of-Thought (CoT) reasoning. Recent work on LLM-based translation designs hand-crafted prompts to decompose translation, or trains models to incorporate intermediate steps. Translating Step-by-step (Briakou et al., 2024), for instance, introduces a multi-step prompt with decomposition and refinement of translation with LLMs, which achieved state-of-the-art results on WMT24 test data. In this work, we scrutinise this strategy's effectiveness. Empirically, we find no clear evidence that performance gains stem from explicitly decomposing the translation process via CoT, at least for the models on test; and we show prompting LLMs to 'translate again' and self-refine yields even better results than human-like step-by-step prompting. While the decomposition influences translation behaviour, faithfulness to the decomposition has both positive and negative effects on translation. Our analysis therefore suggests a divergence between the optimal translation strategies for humans and LLMs.","published":"2025-06-05T00:04:39Z","updated":"2025-09-22T21:51:10Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.04521v2","pdf_url":"https://arxiv.org/pdf/2506.04521v2","comment":"EMNLP Main 2025 17 pages, 15 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.03939","versioned_id":"2506.03939v1","title":"Graph Counselor: Adaptive Graph Exploration via Multi-Agent Synergy to Enhance LLM Reasoning","authors":["Junqi Gao","Xiang Zou","YIng Ai","Dong Li","Yichen Niu","Biqing Qi","Jianxing Liu"],"abstract":"Graph Retrieval Augmented Generation (GraphRAG) effectively enhances external knowledge integration capabilities by explicitly modeling knowledge relationships, thereby improving the factual accuracy and generation quality of Large Language Models (LLMs) in specialized domains. However, existing methods suffer from two inherent limitations: 1) Inefficient Information Aggregation: They rely on a single agent and fixed iterative patterns, making it difficult to adaptively capture multi-level textual, structural, and degree information within graph data. 2) Rigid Reasoning Mechanism: They employ preset reasoning schemes, which cannot dynamically adjust reasoning depth nor achieve precise semantic correction. To overcome these limitations, we propose Graph Counselor, an GraphRAG method based on multi-agent collaboration. This method uses the Adaptive Graph Information Extraction Module (AGIEM), where Planning, Thought, and Execution Agents work together to precisely model complex graph structures and dynamically adjust information extraction strategies, addressing the challenges of multi-level dependency modeling and adaptive reasoning depth. Additionally, the Self-Reflection with Multiple Perspectives (SR) module improves the accuracy and semantic consistency of reasoning results through self-reflection and backward reasoning mechanisms. Experiments demonstrate that Graph Counselor outperforms existing methods in multiple graph reasoning tasks, exhibiting higher reasoning accuracy and generalization ability. Our code is available at https://github.com/gjq100/Graph-Counselor.git.","published":"2025-06-04T13:31:21Z","updated":"2025-06-04T13:31:21Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.03939v1","pdf_url":"https://arxiv.org/pdf/2506.03939v1","comment":"Accepted by ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.03930","versioned_id":"2506.03930v2","title":"VisCoder: Fine-Tuning LLMs for Executable Python Visualization Code Generation","authors":["Yuansheng Ni","Ping Nie","Kai Zou","Xiang Yue","Wenhu Chen"],"abstract":"Large language models (LLMs) often struggle with visualization tasks like plotting diagrams, charts, where success depends on both code correctness and visual semantics. Existing instruction-tuning datasets lack execution-grounded supervision and offer limited support for iterative code correction, resulting in fragile and unreliable plot generation. We present VisCode-200K, a large-scale instruction tuning dataset for Python-based visualization and self-correction. It contains over 200K examples from two sources: (1) validated plotting code from open-source repositories, paired with natural language instructions and rendered plots; and (2) 45K multi-turn correction dialogues from Code-Feedback, enabling models to revise faulty code using runtime feedback. We fine-tune Qwen2.5-Coder-Instruct on VisCode-200K to create VisCoder, and evaluate it on PandasPlotBench. VisCoder significantly outperforms strong open-source baselines and approaches the performance of proprietary models like GPT-4o-mini. We further adopt a self-debug evaluation protocol to assess iterative repair, demonstrating the benefits of feedback-driven learning for executable, visually accurate code generation.","published":"2025-06-04T13:24:44Z","updated":"2025-09-29T00:45:05Z","categories":["cs.SE","cs.AI","cs.CL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2506.03930v2","pdf_url":"https://arxiv.org/pdf/2506.03930v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.04293","versioned_id":"2506.04293v1","title":"AUTOCT: Automating Interpretable Clinical Trial Prediction with LLM Agents","authors":["Fengze Liu","Haoyu Wang","Joonhyuk Cho","Dan Roth","Andrew W. Lo"],"abstract":"Clinical trials are critical for advancing medical treatments but remain prohibitively expensive and time-consuming. Accurate prediction of clinical trial outcomes can significantly reduce research and development costs and accelerate drug discovery. While recent deep learning models have shown promise by leveraging unstructured data, their black-box nature, lack of interpretability, and vulnerability to label leakage limit their practical use in high-stakes biomedical contexts. In this work, we propose AutoCT, a novel framework that combines the reasoning capabilities of large language models with the explainability of classical machine learning. AutoCT autonomously generates, evaluates, and refines tabular features based on public information without human input. Our method uses Monte Carlo Tree Search to iteratively optimize predictive performance. Experimental results show that AutoCT performs on par with or better than SOTA methods on clinical trial prediction tasks within only a limited number of self-refinement iterations, establishing a new paradigm for scalable, interpretable, and cost-efficient clinical trial prediction.","published":"2025-06-04T11:50:55Z","updated":"2025-06-04T11:50:55Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.04293v1","pdf_url":"https://arxiv.org/pdf/2506.04293v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.11078","versioned_id":"2506.11078v1","title":"RoE-FND: A Case-Based Reasoning Approach with Dual Verification for Fake News Detection via LLMs","authors":["Yuzhou Yang","Yangming Zhou","Zhiying Zhu","Zhenxing Qian","Xinpeng Zhang","Sheng Li"],"abstract":"The proliferation of deceptive content online necessitates robust Fake News Detection (FND) systems. While evidence-based approaches leverage external knowledge to verify claims, existing methods face critical limitations: noisy evidence selection, generalization bottlenecks, and unclear decision-making processes. Recent efforts to harness Large Language Models (LLMs) for FND introduce new challenges, including hallucinated rationales and conclusion bias. To address these issues, we propose \\textbf{RoE-FND} (\\textbf{\\underline{R}}eason \\textbf{\\underline{o}}n \\textbf{\\underline{E}}xperiences FND), a framework that reframes evidence-based FND as a logical deduction task by synergizing LLMs with experiential learning. RoE-FND encompasses two stages: (1) \\textit{self-reflective knowledge building}, where a knowledge base is curated by analyzing past reasoning errors, namely the exploration stage, and (2) \\textit{dynamic criterion retrieval}, which synthesizes task-specific reasoning guidelines from historical cases as experiences during deployment. It further cross-checks rationales against internal experience through a devised dual-channel procedure. Key contributions include: a case-based reasoning framework for FND that addresses multiple existing challenges, a training-free approach enabling adaptation to evolving situations, and empirical validation of the framework's superior generalization and effectiveness over state-of-the-art methods across three datasets.","published":"2025-06-04T04:23:58Z","updated":"2025-06-04T04:23:58Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.11078v1","pdf_url":"https://arxiv.org/pdf/2506.11078v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.03541","versioned_id":"2506.03541v1","title":"Debate, Reflect, and Distill: Multi-Agent Feedback with Tree-Structured Preference Optimization for Efficient Language Model Enhancement","authors":["Xiaofeng Zhou","Heyan Huang","Lizi Liao"],"abstract":"Large Language Models (LLMs) continue to set new standards in knowledge-intensive and complex reasoning tasks, yet their high computational demands limit widespread adoption. While distilling large models into smaller ones offers a sustainable solution, current techniques--such as static knowledge distillation, resource-intensive reinforcement learning from human feedback, or limited self-reflection--struggle to yield substantial and lasting performance gains. In this paper, we present a novel Debate and Reflect (D&R) framework that orchestrates multi-turn debates between smaller models and stronger teacher models, eliciting actionable feedback (e.g., error analysis, corrective strategies) to guide student models. Further, we introduce Tree-structured Direct Preference Optimization (T-DPO) to efficiently leverage these debate logs, organizing interactions into a hierarchical format for effective training. Empirical evaluations across diverse NLP benchmarks demonstrate that our approach significantly improves smaller-model accuracy, robustness, and generalization, outperforming conventional baselines by a large margin.","published":"2025-06-04T03:52:20Z","updated":"2025-06-04T03:52:20Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.03541v1","pdf_url":"https://arxiv.org/pdf/2506.03541v1","comment":"16 pages, 10 figures. The camera-ready paper for Findings of ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.03530","versioned_id":"2506.03530v3","title":"How Far Are We from Generating Missing Modalities with Foundation Models?","authors":["Guanzhou Ke","Bo Wang","Guoqing Chao","Weiming Hu","Shengfeng He"],"abstract":"Multimodal foundation models have demonstrated impressive capabilities across diverse tasks. However, their potential as plug-and-play solutions for missing modality reconstruction remains underexplored. To bridge this gap, we identify and formalize three potential paradigms for missing modality reconstruction, and perform a comprehensive evaluation across these paradigms, covering 42 model variants in terms of reconstruction accuracy and adaptability to downstream tasks. Our analysis reveals that current foundation models often fall short in two critical aspects: (i) fine-grained semantic extraction from the available modalities, and (ii) robust validation of generated modalities. These limitations lead to suboptimal and, at times, misaligned generations. To address these challenges, we propose an agentic framework tailored for missing modality reconstruction. This framework dynamically formulates modality-aware mining strategies based on the input context, facilitating the extraction of richer and more discriminative semantic features. In addition, we introduce a self-refinement mechanism, which iteratively verifies and enhances the quality of generated modalities through internal feedback. Experimental results show that our method reduces FID for missing image reconstruction by at least 14\\% and MER for missing text reconstruction by at least 10\\% compared to baselines. Code are released at: https://github.com/Guanzhou-Ke/AFM2.","published":"2025-06-04T03:22:44Z","updated":"2026-05-22T06:55:17Z","categories":["cs.MM","cs.CL","cs.CV"],"primary_category":"cs.MM","arxiv_url":"https://arxiv.org/abs/2506.03530v3","pdf_url":"https://arxiv.org/pdf/2506.03530v3","comment":"T-PAMI","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.03106","versioned_id":"2506.03106v7","title":"Critique-GRPO: Advancing LLM Reasoning with Natural Language and Numerical Feedback","authors":["Xiaoying Zhang","Yipeng Zhang","Hao Sun","Kaituo Feng","Chaochao Lu","Chao Yang","Helen Meng"],"abstract":"Recent advances in reinforcement learning (RL) using numerical rewards have significantly enhanced the complex reasoning capabilities of large language models (LLMs). However, we identify three fundamental limitations of purely numerical feedback: performance plateaus, ineffective spontaneous self-reflection, and persistent failures. We show that plateaued RL models can successfully refine failed solutions when given natural language critiques. Motivated by this, we propose Critique-GRPO, an online RL framework that integrates both natural language and numerical feedback for policy optimization. This approach enables LLMs to learn simultaneously from initial responses and critique-guided refinements, effectively internalizing the exploration benefits of both stages. Extensive experiments show that Critique-GRPO outperforms all compared supervised and RL-based fine-tuning methods, achieving average Pass@1 improvements of approximately +15.0-21.6% on various Qwen models and +7.3% on Llama-3.2-3B-Instruct across eight challenging reasoning tasks. Notably, Critique-GRPO facilitates effective self-improvement through self-critiquing, achieving substantial gains over GRPO, e.g., a +16.7% Pass@1 improvement on AIME 2024. The code and models are released at: https://github.com/zhangxy-2019/critique-GRPO","published":"2025-06-03T17:39:02Z","updated":"2026-06-06T08:11:21Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.03106v7","pdf_url":"https://arxiv.org/pdf/2506.03106v7","comment":"Accepted by ICML 2026 Spotlight","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.05385","versioned_id":"2506.05385v1","title":"LLMs Can Also Do Well! Breaking Barriers in Semantic Role Labeling via Large Language Models","authors":["Xinxin Li","Huiyao Chen","Chengjun Liu","Jing Li","Meishan Zhang","Jun Yu","Min Zhang"],"abstract":"Semantic role labeling (SRL) is a crucial task of natural language processing (NLP). Although generative decoder-based large language models (LLMs) have achieved remarkable success across various NLP tasks, they still lag behind state-of-the-art encoder-decoder (BERT-like) models in SRL. In this work, we seek to bridge this gap by equipping LLMs for SRL with two mechanisms: (a) retrieval-augmented generation and (b) self-correction. The first mechanism enables LLMs to leverage external linguistic knowledge such as predicate and argument structure descriptions, while the second allows LLMs to identify and correct inconsistent SRL outputs. We conduct extensive experiments on three widely-used benchmarks of SRL (CPB1.0, CoNLL-2009, and CoNLL-2012). Results demonstrate that our method achieves state-of-the-art performance in both Chinese and English, marking the first successful application of LLMs to surpass encoder-decoder approaches in SRL.","published":"2025-06-03T12:55:57Z","updated":"2025-06-03T12:55:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.05385v1","pdf_url":"https://arxiv.org/pdf/2506.05385v1","comment":"19 pages, 3 figures, 10 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.02708","versioned_id":"2506.02708v1","title":"Iterative Self-Improvement of Vision Language Models for Image Scoring and Self-Explanation","authors":["Naoto Tanji","Toshihiko Yamasaki"],"abstract":"Image scoring is a crucial task in numerous real-world applications. To trust a model's judgment, understanding its rationale is essential. This paper proposes a novel training method for Vision Language Models (VLMs) to generate not only image scores but also corresponding justifications in natural language. Leveraging only an image scoring dataset and an instruction-tuned VLM, our method enables self-training, utilizing the VLM's generated text without relying on external data or models. In addition, we introduce a simple method for creating a dataset designed to improve alignment between predicted scores and their textual justifications. By iteratively training the model with Direct Preference Optimization on two distinct datasets and merging them, we can improve both scoring accuracy and the coherence of generated explanations.","published":"2025-06-03T10:04:19Z","updated":"2025-06-03T10:04:19Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2506.02708v1","pdf_url":"https://arxiv.org/pdf/2506.02708v1","comment":"Accepted to ICIP2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.02158","versioned_id":"2506.02158v1","title":"Reflection-Based Memory For Web navigation Agents","authors":["Ruhana Azam","Aditya Vempaty","Ashish Jagmohan"],"abstract":"Web navigation agents have made significant progress, yet current systems operate with no memory of past experiences -- leading to repeated mistakes and an inability to learn from previous interactions. We introduce Reflection-Augment Planning (ReAP), a web navigation system to leverage both successful and failed past experiences using self-reflections. Our method improves baseline results by 11 points overall and 29 points on previously failed tasks. These findings demonstrate that reflections can transfer to different web navigation tasks.","published":"2025-06-02T18:39:55Z","updated":"2025-06-02T18:39:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.02158v1","pdf_url":"https://arxiv.org/pdf/2506.02158v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.01713","versioned_id":"2506.01713v3","title":"SRPO: Enhancing Multimodal LLM Reasoning via Reflection-Aware Reinforcement Learning","authors":["Zhongwei Wan","Zhihao Dou","Che Liu","Yu Zhang","Dongfei Cui","Qinjian Zhao","Hui Shen","Jing Xiong","Yi Xin","Yifan Jiang","Chaofan Tao","Yangfan He","Mi Zhang","Shen Yan"],"abstract":"Multimodal large language models (MLLMs) have shown promising capabilities in reasoning tasks, yet still struggle with complex problems requiring explicit self-reflection and self-correction, especially compared to their unimodal text-based counterparts. Existing reflection methods are simplistic and struggle to generate meaningful and instructive feedback, as the reasoning ability and knowledge limits of pre-trained models are largely fixed during initial training. To overcome these challenges, we propose Multimodal Self-Reflection enhanced reasoning with Group Relative Policy Optimization (SRPO), a two-stage reflection-aware reinforcement learning (RL) framework explicitly designed to enhance multimodal LLM reasoning. In the first stage, we construct a high-quality, reflection-focused dataset under the guidance of an advanced MLLM, which generates reflections based on initial responses to help the policy model learn both reasoning and self-reflection. In the second stage, we introduce a novel reward mechanism within the GRPO framework that encourages concise and cognitively meaningful reflection while avoiding redundancy. Extensive experiments across multiple multimodal reasoning benchmarks, including MathVista, MathVision, MathVerse, and MMMU-Pro, using Qwen-2.5-VL-7B and Qwen-2.5-VL-32B demonstrate that SRPO significantly outperforms state-of-the-art models, achieving notable improvements in both reasoning accuracy and reflection quality.","published":"2025-06-02T14:21:44Z","updated":"2025-10-05T05:53:45Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.01713v3","pdf_url":"https://arxiv.org/pdf/2506.01713v3","comment":"NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.01551","versioned_id":"2506.01551v3","title":"EvolveNav: Empowering LLM-Based Vision-Language Navigation via Self-Improving Embodied Reasoning","authors":["Bingqian Lin","Yunshuang Nie","Khun Loun Zai","Ziming Wei","Mingfei Han","Rongtao Xu","Minzhe Niu","Jianhua Han","Hanwang Zhang","Liang Lin","Bokui Chen","Cewu Lu","Xiaodan Liang"],"abstract":"Recent studies have revealed the potential of training open-source Large Language Models (LLMs) to unleash LLMs' reasoning ability for enhancing vision-language navigation (VLN) performance, and simultaneously mitigate the domain gap between LLMs' training corpus and the VLN task. However, these approaches predominantly adopt straightforward input-output mapping paradigms, causing the mapping learning difficult and the navigational decisions unexplainable. Chain-of-Thought (CoT) training is a promising way to improve both navigational decision accuracy and interpretability, while the complexity of the navigation task makes the perfect CoT labels unavailable and may lead to overfitting through pure CoT supervised fine-tuning. To address these issues, we propose EvolveNav, a novel sElf-improving embodied reasoning paradigm that realizes adaptable and generalizable navigational reasoning for boosting LLM-based vision-language Navigation. Specifically, EvolveNav involves a two-stage training process: (1) Formalized CoT Supervised Fine-Tuning, where we train the model with curated formalized CoT labels to first activate the model's navigational reasoning capabilities, and simultaneously increase the reasoning speed; (2) Self-Reflective Post-Training, where the model is iteratively trained with its own reasoning outputs as self-enriched CoT labels to enhance the supervision diversity. A self-reflective auxiliary task is also designed to encourage the model to learn correct reasoning patterns by contrasting with wrong ones. Experimental results under both task-specific and cross-task training paradigms demonstrate the consistent superiority of EvolveNav over previous LLM-based VLN approaches on various popular benchmarks, including R2R, REVERIE, CVDN, and SOON. Code is available at https://github.com/expectorlin/EvolveNav.","published":"2025-06-02T11:28:32Z","updated":"2025-10-14T02:26:03Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2506.01551v3","pdf_url":"https://arxiv.org/pdf/2506.01551v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.01420","versioned_id":"2506.01420v2","title":"Self-Refining Language Model Anonymizers via Adversarial Distillation","authors":["Kyuyoung Kim","Hyunjun Jeon","Jinwoo Shin"],"abstract":"Large language models (LLMs) are increasingly used in sensitive domains, where their ability to infer personal data from seemingly benign text introduces emerging privacy risks. While recent LLM-based anonymization methods help mitigate such risks, they often rely on proprietary models (e.g., GPT-4), raising concerns about cost and the potential exposure of sensitive data to untrusted external systems. To address this, we introduce SElf-refining Anonymization with Language model (SEAL), a novel distillation framework for training small language models (SLMs) to perform effective anonymization without relying on external models at inference time. SEAL leverages adversarial interactions between an LLM anonymizer and an inference model to collect trajectories of anonymized texts and inferred attributes, which are then used to distill anonymization and critique capabilities into SLMs through supervised fine-tuning and preference learning. The resulting models learn both to anonymize text and to evaluate their outputs, enabling iterative improvement of anonymization quality via self-refinement. Experiments on SynthPAI, a dataset of synthetic personal profiles and text comments, demonstrate that SLMs trained with SEAL achieve substantial improvements in anonymization capabilities. Notably, 8B models attain a privacy-utility trade-off comparable to that of the GPT-4 anonymizer and, with self-refinement, even surpass it in terms of privacy protection. These results highlight the effectiveness of our adversarial distillation framework for training SLMs as efficient anonymizers.","published":"2025-06-02T08:21:27Z","updated":"2025-10-23T19:22:08Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.01420v2","pdf_url":"https://arxiv.org/pdf/2506.01420v2","comment":"NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.01326","versioned_id":"2506.01326v2","title":"ORMind: A Cognitive-Inspired End-to-End Reasoning Framework for Operations Research","authors":["Zhiyuan Wang","Bokui Chen","Yinya Huang","Qingxing Cao","Ming He","Jianping Fan","Xiaodan Liang"],"abstract":"Operations research (OR) is widely deployed to solve critical decision-making problems with complex objectives and constraints, impacting manufacturing, logistics, finance, and healthcare outcomes. While Large Language Models (LLMs) have shown promising results in various domains, their practical application in industry-relevant operations research (OR) problems presents significant challenges and opportunities. Preliminary industrial applications of LLMs for operations research face two critical deployment challenges: 1) Self-correction focuses on code syntax rather than mathematical accuracy, causing costly errors; 2) Complex expert selection creates unpredictable workflows that reduce transparency and increase maintenance costs, making them impractical for time-sensitive business applications. To address these business limitations, we introduce ORMind, a cognitive-inspired framework that enhances optimization through counterfactual reasoning. Our approach emulates human cognition, implementing an end-to-end workflow that systematically transforms requirements into mathematical models and executable solver code. It is currently being tested internally in Lenovo's AI Assistant, with plans to enhance optimization capabilities for both business and consumer customers. Experiments demonstrate that ORMind outperforms existing methods, achieving a 9.5\\% improvement on the NL4Opt dataset and a 14.6\\% improvement on the ComplexOR dataset.","published":"2025-06-02T05:11:21Z","updated":"2025-09-03T12:09:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.01326v2","pdf_url":"https://arxiv.org/pdf/2506.01326v2","comment":"Accepted by Annual Meetings of the Association for Computational Linguistics 2025","journal_ref":"In Proceedings of the 63rd Annual Meeting of the Association for Computational Linguistics (Volume 6: Industry Track), 2025,Vienna, Austria. Association for Computational Linguistics","doi":"10.18653/v1/2025.acl-industry.10","discovered_on":"2026-07-17"},{"id":"2506.01250","versioned_id":"2506.01250v3","title":"Neural Variance-aware Dueling Bandits with Deep Representation and Shallow Exploration","authors":["Youngmin Oh","Jinje Park","Taejin Paik"],"abstract":"We introduce the first variance-aware algorithms for contextual dueling bandits that leverage shallow exploration strategies with neural networks for nonlinear utility approximation. A key theoretical challenge is the absence of a closed-form estimator, which led prior work to require an extremely large network width $m$ (i.e., $m = \\widetildeΩ(T^{14})$). We address this constraint with a novel analytical approach that combines iterative self-improvement with spectral analysis. Our analysis significantly reduces the network width requirement to $m = \\widetildeΩ(T^{6})$, and shows that our algorithms achieve a sublinear regret of $\\widetilde{\\mathcal{O}}(d\\sqrt{\\sum_{t=1}^{T} σ_t^2} + \\sqrt{dT})$ under both UCB and TS frameworks. Empirical results show that the proposed algorithms are not only computationally efficient and exhibit sublinear regret in practical settings, but also achieve state-of-the-art performance on both synthetic and real-world tasks.","published":"2025-06-02T01:58:48Z","updated":"2026-06-03T04:29:50Z","categories":["cs.LG","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.01250v3","pdf_url":"https://arxiv.org/pdf/2506.01250v3","comment":"Accepted at AISTATS 2026; code at https://github.com/youngmin0oh/NVLDB-AISTATS2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.01225","versioned_id":"2506.01225v1","title":"Self-Refining Training for Amortized Density Functional Theory","authors":["Majdi Hassan","Cristian Gabellini","Hatem Helal","Dominique Beaini","Kirill Neklyudov"],"abstract":"Density Functional Theory (DFT) allows for predicting all the chemical and physical properties of molecular systems from first principles by finding an approximate solution to the many-body Schrödinger equation. However, the cost of these predictions becomes infeasible when increasing the scale of the energy evaluations, e.g., when calculating the ground-state energy for simulating molecular dynamics. Recent works have demonstrated that, for substantially large datasets of molecular conformations, Deep Learning-based models can predict the outputs of the classical DFT solvers by amortizing the corresponding optimization problems. In this paper, we propose a novel method that reduces the dependency of amortized DFT solvers on large pre-collected datasets by introducing a self-refining training strategy. Namely, we propose an efficient method that simultaneously trains a deep-learning model to predict the DFT outputs and samples molecular conformations that are used as training data for the model. We derive our method as a minimization of the variational upper bound on the KL-divergence measuring the discrepancy between the generated samples and the target Boltzmann distribution defined by the ground state energy. To demonstrate the utility of the proposed scheme, we perform an extensive empirical study comparing it with the models trained on the pre-collected datasets. Finally, we open-source our implementation of the proposed algorithm, optimized with asynchronous training and sampling stages, which enables simultaneous sampling and training. Code is available at https://github.com/majhas/self-refining-dft.","published":"2025-06-02T00:32:32Z","updated":"2025-06-02T00:32:32Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.01225v1","pdf_url":"https://arxiv.org/pdf/2506.01225v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.04255","versioned_id":"2506.04255v1","title":"HASHIRU: Hierarchical Agent System for Hybrid Intelligent Resource Utilization","authors":["Kunal Pai","Parth Shah","Harshil Patel"],"abstract":"Rapid Large Language Model (LLM) advancements are fueling autonomous Multi-Agent System (MAS) development. However, current frameworks often lack flexibility, resource awareness, model diversity, and autonomous tool creation. This paper introduces HASHIRU (Hierarchical Agent System for Hybrid Intelligent Resource Utilization), a novel MAS framework enhancing flexibility, resource efficiency, and adaptability. HASHIRU features a \"CEO\" agent dynamically managing specialized \"employee\" agents, instantiated based on task needs and resource constraints (cost, memory). Its hybrid intelligence prioritizes smaller, local LLMs (via Ollama) while flexibly using external APIs and larger models when necessary. An economic model with hiring/firing costs promotes team stability and efficient resource allocation. The system also includes autonomous API tool creation and a memory function. Evaluations on tasks like academic paper review (58% success), safety assessments (100% on a JailbreakBench subset), and complex reasoning (outperforming Gemini 2.0 Flash on GSM8K: 96% vs. 61%; JEEBench: 80% vs. 68.3%; SVAMP: 92% vs. 84%) demonstrate HASHIRU's capabilities. Case studies illustrate its self-improvement via autonomous cost model generation, tool integration, and budget management. HASHIRU offers a promising approach for more robust, efficient, and adaptable MAS through dynamic hierarchical control, resource-aware hybrid intelligence, and autonomous functional extension. Source code and benchmarks are available at https://github.com/HASHIRU-AI/HASHIRU and https://github.com/HASHIRU-AI/HASHIRUBench respectively, and a live demo is available at https://hashiruagentx-hashiruai.hf.space upon request.","published":"2025-06-01T17:33:16Z","updated":"2025-06-01T17:33:16Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2506.04255v1","pdf_url":"https://arxiv.org/pdf/2506.04255v1","comment":"Submitted as part of the Research Track at AgentX 2025, organized by Berkeley RDI","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.00985","versioned_id":"2506.00985v1","title":"Do LLMs Understand Why We Write Diaries? A Method for Purpose Extraction and Clustering","authors":["Valeriya Goloviznina","Alexander Sergeev","Mikhail Melnichenko","Evgeny Kotelnikov"],"abstract":"Diary analysis presents challenges, particularly in extracting meaningful information from large corpora, where traditional methods often fail to deliver satisfactory results. This study introduces a novel method based on Large Language Models (LLMs) to identify and cluster the various purposes of diary writing. By \"purposes,\" we refer to the intentions behind diary writing, such as documenting life events, self-reflection, or practicing language skills. Our approach is applied to Soviet-era diaries (1922-1929) from the Prozhito digital archive, a rich collection of personal narratives. We evaluate different proprietary and open-source LLMs, finding that GPT-4o and o1-mini achieve the best performance, while a template-based baseline is significantly less effective. Additionally, we analyze the retrieved purposes based on gender, age of the authors, and the year of writing. Furthermore, we examine the types of errors made by the models, providing a deeper understanding of their limitations and potential areas for improvement in future research.","published":"2025-06-01T12:38:01Z","updated":"2025-06-01T12:38:01Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.00985v1","pdf_url":"https://arxiv.org/pdf/2506.00985v1","comment":"Accepted for CompLing-2025 conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.00963","versioned_id":"2506.00963v1","title":"From Objectives to Questions: A Planning-based Framework for Educational Mathematical Question Generation","authors":["Cheng Cheng","Zhenya Huang","Guanhao Zhao","Yuxiang Guo","Xin Lin","Jinze Wu","Xin Li","Shijin Wang"],"abstract":"Automatically generating high-quality mathematical problems that align with educational objectives is a crucial task in NLP-based educational technology. Traditional generation methods focus primarily on textual quality, but they often overlook educational objectives. Moreover, these methods address only single-dimensional, simple question generation, failing to meet complex, multifaceted educational requirements. To address these challenges, we constructed and annotated EduMath, a dataset of 16k mathematical questions with multi-dimensional educational objectives. Based on this dataset, we developed EQGEVAL, which incorporates three evaluation dimensions and is designed to assess the ability of models to generate educational questions. Drawing inspiration from teachers' problem design processes, we propose the Educational Question Planning with self-Reflection (EQPR) method for educational mathematical question generation, following a \"plan-evaluate-optimize\" approach. Specifically, by combining planning algorithm based on Monte Carlo Tree Search with the generative capabilities of Large Language Models, we continuously optimize questions through iterative feedback. This self-optimization mechanism ensures that the generated questions both fit the educational context and strategically achieve specific basic educational objectives. Through extensive experiments based on EQGEVAL, we have demonstrated that EQPR achieves significant improvements in generating questions that meet multi-dimensional educational objectives.","published":"2025-06-01T11:23:18Z","updated":"2025-06-01T11:23:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.00963v1","pdf_url":"https://arxiv.org/pdf/2506.00963v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.00943","versioned_id":"2506.00943v1","title":"Legal Compliance Evaluation of Smart Contracts Generated By Large Language Models","authors":["Chanuka Wijayakoon","Hai Dong","H. M. N. Dilum Bandara","Zahir Tari","Anurag Soin"],"abstract":"Smart contracts can implement and automate parts of legal contracts, but ensuring their legal compliance remains challenging. Existing approaches such as formal specification, verification, and model-based development require expertise in both legal and software development domains, as well as extensive manual effort. Given the recent advances of Large Language Models (LLMs) in code generation, we investigate their ability to generate legally compliant smart contracts directly from natural language legal contracts, addressing these challenges. We propose a novel suite of metrics to quantify legal compliance based on modeling both legal and smart contracts as processes and comparing their behaviors. We select four LLMs, generate 20 smart contracts based on five legal contracts, and analyze their legal compliance. We find that while all LLMs generate syntactically correct code, there is significant variance in their legal compliance with larger models generally showing higher levels of compliance. We also evaluate the proposed metrics against properties of software metrics, showing they provide fine-grained distinctions, enable nuanced comparisons, and are applicable across domains for code from any source, LLM or developer. Our results suggest that LLMs can assist in generating starter code for legally compliant smart contracts with strict reviews, and the proposed metrics provide a foundation for automated and self-improving development workflows.","published":"2025-06-01T10:20:13Z","updated":"2025-06-01T10:20:13Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2506.00943v1","pdf_url":"https://arxiv.org/pdf/2506.00943v1","comment":"Accepted for publication at IEEE International Conference on Blockchain and Cryptocurrency (ICBC) 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.00519","versioned_id":"2506.00519v2","title":"CausalAbstain: Enhancing Multilingual LLMs with Causal Reasoning for Trustworthy Abstention","authors":["Yuxi Sun","Aoqi Zuo","Wei Gao","Jing Ma"],"abstract":"Large Language Models (LLMs) often exhibit knowledge disparities across languages. Encouraging LLMs to \\textit{abstain} when faced with knowledge gaps is a promising strategy to reduce hallucinations in multilingual settings. Current abstention strategies for multilingual scenarios primarily rely on generating feedback in various languages using LLMs and performing self-reflection. However, these methods can be adversely impacted by inaccuracies and biases in the generated feedback. To address this, from a causal perspective, we introduce \\textit{CausalAbstain}, a method that helps LLMs determine whether to utilize multiple generated feedback responses and how to identify the most useful ones. Extensive experiments demonstrate that \\textit{CausalAbstain} effectively selects helpful feedback and enhances abstention decisions with interpretability in both native language (\\textsc{Casual-native}) and multilingual (\\textsc{Causal-multi}) settings, outperforming strong baselines on two benchmark datasets covering encyclopedic and commonsense knowledge QA tasks. Our code and data are open-sourced at https://github.com/peachch/CausalAbstain.","published":"2025-05-31T11:35:31Z","updated":"2025-06-03T09:58:17Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.00519v2","pdf_url":"https://arxiv.org/pdf/2506.00519v2","comment":"Accepted to Association for Computational Linguistics Findings (ACL) 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.00391","versioned_id":"2506.00391v1","title":"SHARE: An SLM-based Hierarchical Action CorREction Assistant for Text-to-SQL","authors":["Ge Qu","Jinyang Li","Bowen Qin","Xiaolong Li","Nan Huo","Chenhao Ma","Reynold Cheng"],"abstract":"Current self-correction approaches in text-to-SQL face two critical limitations: 1) Conventional self-correction methods rely on recursive self-calls of LLMs, resulting in multiplicative computational overhead, and 2) LLMs struggle to implement effective error detection and correction for declarative SQL queries, as they fail to demonstrate the underlying reasoning path. In this work, we propose SHARE, an SLM-based Hierarchical Action corREction assistant that enables LLMs to perform more precise error localization and efficient correction. SHARE orchestrates three specialized Small Language Models (SLMs) in a sequential pipeline, where it first transforms declarative SQL queries into stepwise action trajectories that reveal underlying reasoning, followed by a two-phase granular refinement. We further propose a novel hierarchical self-evolution strategy for data-efficient training. Experimental results demonstrate that SHARE effectively enhances self-correction capabilities while proving robust across various LLMs. Furthermore, our comprehensive analysis shows that SHARE maintains strong performance even in low-resource training settings, which is particularly valuable for text-to-SQL applications with data privacy constraints.","published":"2025-05-31T04:51:12Z","updated":"2025-05-31T04:51:12Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.00391v1","pdf_url":"https://arxiv.org/pdf/2506.00391v1","comment":"Accepted to ACL 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.00320","versioned_id":"2506.00320v3","title":"Dyna-Think: Synergizing Reasoning, Acting, and World Model Simulation in AI Agents","authors":["Xiao Yu","Baolin Peng","Ruize Xu","Michel Galley","Hao Cheng","Suman Nath","Jianfeng Gao","Zhou Yu"],"abstract":"Recent progress in reasoning with large language models (LLMs), such as DeepSeek-R1, demonstrates impressive capabilities in domains like mathematics and coding, by exhibiting complex cognitive behaviors such as verification, goal decomposition, and self-reflection. However, it is unclear what behavior is effective and what behavior is missing for long-horizon AI agents tasks. In this work, we propose Dyna-Think, a thinking framework that integrates planning with an internal world model with reasoning and acting to enhance AI agent performance. To enable Dyna-Think, we propose Dyna-Think Imitation Learning (DIT) and Dyna-Think Dyna Training (DDT). To initialize a policy with Dyna-Think, DIT reconstructs the thinking process of R1 to focus on performing world model simulation relevant to the proposed (and planned) action, and trains the policy using this reconstructed data. To enhance Dyna-Think, DDT uses a two-stage training process to first improve the agent's world modeling ability via objectives such as state prediction or critique generation, and then improve the agent's action via policy training. We evaluate our methods on OSWorld and WindowsAgentArena, and demonstrate that Dyna-Think improves the agent's in-domain and out-of-domain performance, achieving similar best-of-n performance compared to R1 while generating 2x less tokens on average. Our extensive empirical studies reveal that 1) using critique generation for world model training is effective to improve policy performance; and 2) AI agents with better performance correlate with better world modeling abilities. We believe our results suggest a promising research direction to integrate world model simulation into AI agents to enhance their reasoning, planning, and acting capabilities.","published":"2025-05-31T00:10:18Z","updated":"2025-10-10T22:01:33Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.00320v3","pdf_url":"https://arxiv.org/pdf/2506.00320v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.00232","versioned_id":"2506.00232v1","title":"ComposeRAG: A Modular and Composable RAG for Corpus-Grounded Multi-Hop Question Answering","authors":["Ruofan Wu","Youngwon Lee","Fan Shu","Danmei Xu","Seung-won Hwang","Zhewei Yao","Yuxiong He","Feng Yan"],"abstract":"Retrieval-Augmented Generation (RAG) systems are increasingly diverse, yet many suffer from monolithic designs that tightly couple core functions like query reformulation, retrieval, reasoning, and verification. This limits their interpretability, systematic evaluation, and targeted improvement, especially for complex multi-hop question answering. We introduce ComposeRAG, a novel modular abstraction that decomposes RAG pipelines into atomic, composable modules. Each module, such as Question Decomposition, Query Rewriting, Retrieval Decision, and Answer Verification, acts as a parameterized transformation on structured inputs/outputs, allowing independent implementation, upgrade, and analysis. To enhance robustness against errors in multi-step reasoning, ComposeRAG incorporates a self-reflection mechanism that iteratively revisits and refines earlier steps upon verification failure. Evaluated on four challenging multi-hop QA benchmarks, ComposeRAG consistently outperforms strong baselines in both accuracy and grounding fidelity. Specifically, it achieves up to a 15% accuracy improvement over fine-tuning-based methods and up to a 5% gain over reasoning-specialized pipelines under identical retrieval conditions. Crucially, ComposeRAG significantly enhances grounding: its verification-first design reduces ungrounded answers by over 10% in low-quality retrieval settings, and by approximately 3% even with strong corpora. Comprehensive ablation studies validate the modular architecture, demonstrating distinct and additive contributions from each component. These findings underscore ComposeRAG's capacity to deliver flexible, transparent, scalable, and high-performing multi-hop reasoning with improved grounding and interpretability.","published":"2025-05-30T21:10:30Z","updated":"2025-05-30T21:10:30Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.00232v1","pdf_url":"https://arxiv.org/pdf/2506.00232v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.24872","versioned_id":"2505.24872v2","title":"ProxyThinker: Test-Time Guidance through Small Visual Reasoners","authors":["Zilin Xiao","Jaywon Koo","Siru Ouyang","Jefferson Hernandez","Yu Meng","Vicente Ordonez"],"abstract":"Recent advancements in reinforcement learning with verifiable rewards have pushed the boundaries of the visual reasoning capabilities in large vision-language models (LVLMs). However, training LVLMs with reinforcement fine-tuning (RFT) is computationally expensive, posing a significant challenge to scaling model size. In this work, we propose ProxyThinker, an inference-time technique that enables large models to inherit the visual reasoning capabilities from small, slow-thinking visual reasoners without any training. By subtracting the output distributions of base models from those of RFT reasoners, ProxyThinker modifies the decoding dynamics and successfully elicits the slow-thinking reasoning demonstrated by the emerged sophisticated behaviors such as self-verification and self-correction. ProxyThinker consistently boosts performance on challenging visual benchmarks on spatial, mathematical, and multi-disciplinary reasoning, enabling untuned base models to compete with the performance of their full-scale RFT counterparts. Furthermore, our implementation efficiently coordinates multiple language models with parallelism techniques and achieves up to 38 $\\times$ faster inference compared to previous decoding-time methods, paving the way for the practical deployment of ProxyThinker. Code is available at https://github.com/MrZilinXiao/ProxyThinker.","published":"2025-05-30T17:59:43Z","updated":"2025-09-27T02:58:54Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.24872v2","pdf_url":"https://arxiv.org/pdf/2505.24872v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.24726","versioned_id":"2505.24726v1","title":"Reflect, Retry, Reward: Self-Improving LLMs via Reinforcement Learning","authors":["Shelly Bensal","Umar Jamil","Christopher Bryant","Melisa Russak","Kiran Kamble","Dmytro Mozolevskyi","Muayad Ali","Waseem AlShikh"],"abstract":"We explore a method for improving the performance of large language models through self-reflection and reinforcement learning. By incentivizing the model to generate better self-reflections when it answers incorrectly, we demonstrate that a model's ability to solve complex, verifiable tasks can be enhanced even when generating synthetic data is infeasible and only binary feedback is available. Our framework operates in two stages: first, upon failing a given task, the model generates a self-reflective commentary analyzing its previous attempt; second, the model is given another attempt at the task with the self-reflection in context. If the subsequent attempt succeeds, the tokens generated during the self-reflection phase are rewarded. Our experimental results show substantial performance gains across a variety of model architectures, as high as 34.7% improvement at math equation writing and 18.1% improvement at function calling. Notably, smaller fine-tuned models (1.5 billion to 7 billion parameters) outperform models in the same family that are 10 times larger. Our novel paradigm is thus an exciting pathway to more useful and reliable language models that can self-improve on challenging tasks with limited external feedback.","published":"2025-05-30T15:49:42Z","updated":"2025-05-30T15:49:42Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.24726v1","pdf_url":"https://arxiv.org/pdf/2505.24726v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.24671","versioned_id":"2505.24671v2","title":"Multiple LLM Agents Debate for Equitable Cultural Alignment","authors":["Dayeon Ki","Rachel Rudinger","Tianyi Zhou","Marine Carpuat"],"abstract":"Large Language Models (LLMs) need to adapt their predictions to diverse cultural contexts to benefit diverse communities across the world. While previous efforts have focused on single-LLM, single-turn approaches, we propose to exploit the complementary strengths of multiple LLMs to promote cultural adaptability. We introduce a Multi-Agent Debate framework, where two LLM-based agents debate over a cultural scenario and collaboratively reach a final decision. We propose two variants: one where either LLM agents exclusively debate and another where they dynamically choose between self-reflection and debate during their turns. We evaluate these approaches on 7 open-weight LLMs (and 21 LLM combinations) using the NormAd-ETI benchmark for social etiquette norms in 75 countries. Experiments show that debate improves both overall accuracy and cultural group parity over single-LLM baselines. Notably, multi-agent debate enables relatively small LLMs (7-9B) to achieve accuracies comparable to that of a much larger model (27B parameters).","published":"2025-05-30T15:01:52Z","updated":"2025-09-01T12:34:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.24671v2","pdf_url":"https://arxiv.org/pdf/2505.24671v2","comment":"ACL 2025 (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.24230","versioned_id":"2505.24230v1","title":"ProofNet++: A Neuro-Symbolic System for Formal Proof Verification with Self-Correction","authors":["Murari Ambati"],"abstract":"We propose ProofNet++, a neuro-symbolic framework that enhances automated theorem proving by combining large language models (LLMs) with formal proof verification and self-correction mechanisms. Current LLM-based systems suffer from hallucinated logical steps and unverifiable reasoning. ProofNet++ mitigates these limitations by integrating symbolic proof tree supervision, a reinforcement learning loop using verifiers as reward functions, and an iterative self-correction module. Our experiments on miniF2F, Lean's mathlib, and HOL Light show that ProofNet++ significantly improves proof accuracy, correctness, and formal verifiability over prior models. We provide theoretical analysis of the convergence and stability of the verifier-guided RL framework and release our datasets and codebase for future research.","published":"2025-05-30T05:44:34Z","updated":"2025-05-30T05:44:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.24230v1","pdf_url":"https://arxiv.org/pdf/2505.24230v1","comment":"6 pages, 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.24197","versioned_id":"2505.24197v2","title":"Learning API Functionality from In-Context Demonstrations for Tool-based Agents","authors":["Bhrij Patel","Ashish Jagmohan","Aditya Vempaty"],"abstract":"Digital tool-based agents, powered by Large Language Models (LLMs), that invoke external Application Programming Interfaces (APIs) often rely on documentation to understand API functionality. However, such documentation is frequently missing, outdated, privatized, or inconsistent-hindering the development of reliable, general-purpose agents. In this work, we propose a new research direction: learning of API functionality directly from in-context demonstrations. This task is a new paradigm applicable in scenarios without documentation. Using API benchmarks, we collect demonstrations from both expert agents and from self-exploration. To understand what information demonstrations must convey for successful task completion, we extensively study how the number of demonstrations and the use of LLM-generated summaries and evaluations affect the task success rate of the API-based agent. Our experiments across 3 datasets and 6 models show that learning functionality from in-context demonstrations remains a non-trivial challenge, even for state-of-the-art LLMs. We find that providing explicit function calls and natural language critiques significantly improves the agent's task success rate due to more accurate parameter filling. We analyze failure modes, identify sources of error, and highlight key open challenges for future work in documentation-free, self-improving, API-based agents.","published":"2025-05-30T04:17:09Z","updated":"2025-11-12T03:07:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.24197v2","pdf_url":"https://arxiv.org/pdf/2505.24197v2","comment":"19 Pages, 14 Figures, 7 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.24133","versioned_id":"2505.24133v4","title":"R-KV: Redundancy-aware KV Cache Compression for Reasoning Models","authors":["Zefan Cai","Wen Xiao","Hanshi Sun","Cheng Luo","Yikai Zhang","Ke Wan","Yucheng Li","Yeyang Zhou","Li-Wen Chang","Jiuxiang Gu","Zhen Dong","Anima Anandkumar","Abedelkadir Asi","Junjie Hu"],"abstract":"Reasoning models have demonstrated impressive performance in self-reflection and chain-of-thought reasoning. However, they often produce excessively long outputs, leading to prohibitively large key-value (KV) caches during inference. While chain-of-thought inference significantly improves performance on complex reasoning tasks, it can also lead to reasoning failures when deployed with existing KV cache compression approaches. To address this, we propose Redundancy-aware KV Cache Compression for Reasoning models (R-KV), a novel method specifically targeting redundant tokens in reasoning models. Our method preserves nearly 100% of the full KV cache performance using only 10% of the KV cache, substantially outperforming existing KV cache baselines, which reach only 60% of the performance. Remarkably, R-KV even achieves 105% of full KV cache performance with 16% of the KV cache. This KV-cache reduction also leads to a 90% memory saving and a 6.6X throughput over standard chain-of-thought reasoning inference. Experimental results show that R-KV consistently outperforms existing KV cache compression baselines across two mathematical reasoning datasets.","published":"2025-05-30T02:03:24Z","updated":"2026-01-22T01:31:36Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.24133v4","pdf_url":"https://arxiv.org/pdf/2505.24133v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.24073","versioned_id":"2505.24073v2","title":"mRAG: Elucidating the Design Space of Multi-modal Retrieval-Augmented Generation","authors":["Chan-Wei Hu","Yueqi Wang","Shuo Xing","Chia-Ju Chen","Suofei Feng","Ryan Rossi","Zhengzhong Tu"],"abstract":"Large Vision-Language Models (LVLMs) have made remarkable strides in multimodal tasks such as visual question answering, visual grounding, and complex reasoning. However, they remain limited by static training data, susceptibility to hallucinations, and inability to verify claims against up-to-date, external evidence, compromising their performance in dynamic real-world applications. Retrieval-Augmented Generation (RAG) offers a practical solution to mitigate these challenges by allowing the LVLMs to access large-scale knowledge databases via retrieval mechanisms, thereby grounding model outputs in factual, contextually relevant information. Here in this paper, we conduct the first systematic dissection of the multimodal RAG pipeline for LVLMs, explicitly investigating (1) the retrieval phase: on the modality configurations and retrieval strategies, (2) the re-ranking stage: on strategies to mitigate positional biases and improve the relevance of retrieved evidence, and (3) the generation phase: we further investigate how to best integrate retrieved candidates into the final generation process. Finally, we extend to explore a unified agentic framework that integrates re-ranking and generation through self-reflection, enabling LVLMs to select relevant evidence and suppress irrelevant context dynamically. Our full-stack exploration of RAG for LVLMs yields substantial insights, resulting in an average performance boost of 5% without any fine-tuning.","published":"2025-05-29T23:32:03Z","updated":"2025-08-26T16:42:37Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.24073v2","pdf_url":"https://arxiv.org/pdf/2505.24073v2","comment":"16 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.23695","versioned_id":"2505.23695v1","title":"Data-to-Dashboard: Multi-Agent LLM Framework for Insightful Visualization in Enterprise Analytics","authors":["Ran Zhang","Mohannad Elhamod"],"abstract":"The rapid advancement of LLMs has led to the creation of diverse agentic systems in data analysis, utilizing LLMs' capabilities to improve insight generation and visualization. In this paper, we present an agentic system that automates the data-to-dashboard pipeline through modular LLM agents capable of domain detection, concept extraction, multi-perspective analysis generation, and iterative self-reflection. Unlike existing chart QA systems, our framework simulates the analytical reasoning process of business analysts by retrieving domain-relevant knowledge and adapting to diverse datasets without relying on closed ontologies or question templates. We evaluate our system on three datasets across different domains. Benchmarked against GPT-4o with a single-prompt baseline, our approach shows improved insightfulness, domain relevance, and analytical depth, as measured by tailored evaluation metrics and qualitative human assessment. This work contributes a novel modular pipeline to bridge the path from raw data to visualization, and opens new opportunities for human-in-the-loop validation by domain experts in business analytics. All code can be found here: https://github.com/77luvC/D2D_Data2Dashboard","published":"2025-05-29T17:32:15Z","updated":"2025-05-29T17:32:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.23695v1","pdf_url":"https://arxiv.org/pdf/2505.23695v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.23604","versioned_id":"2505.23604v1","title":"Satori-SWE: Evolutionary Test-Time Scaling for Sample-Efficient Software Engineering","authors":["Guangtao Zeng","Maohao Shen","Delin Chen","Zhenting Qi","Subhro Das","Dan Gutfreund","David Cox","Gregory Wornell","Wei Lu","Zhang-Wei Hong","Chuang Gan"],"abstract":"Language models (LMs) perform well on standardized coding benchmarks but struggle with real-world software engineering tasks such as resolving GitHub issues in SWE-Bench, especially when model parameters are less than 100B. While smaller models are preferable in practice due to their lower computational cost, improving their performance remains challenging. Existing approaches primarily rely on supervised fine-tuning (SFT) with high-quality data, which is expensive to curate at scale. An alternative is test-time scaling: generating multiple outputs, scoring them using a verifier, and selecting the best one. Although effective, this strategy often requires excessive sampling and costly scoring, limiting its practical application. We propose Evolutionary Test-Time Scaling (EvoScale), a sample-efficient method that treats generation as an evolutionary process. By iteratively refining outputs via selection and mutation, EvoScale shifts the output distribution toward higher-scoring regions, reducing the number of samples needed to find correct solutions. To reduce the overhead from repeatedly sampling and selection, we train the model to self-evolve using reinforcement learning (RL). Rather than relying on external verifiers at inference time, the model learns to self-improve the scores of its own generations across iterations. Evaluated on SWE-Bench-Verified, EvoScale enables our 32B model, Satori-SWE-32B, to match or exceed the performance of models with over 100B parameters while using a few samples. Code, data, and models will be fully open-sourced.","published":"2025-05-29T16:15:36Z","updated":"2025-05-29T16:15:36Z","categories":["cs.CL","cs.AI","cs.SE"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.23604v1","pdf_url":"https://arxiv.org/pdf/2505.23604v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.23387","versioned_id":"2505.23387v3","title":"Afterburner: Reinforcement Learning Facilitates Self-Improving Code Efficiency Optimization","authors":["Mingzhe Du","Luu Anh Tuan","Yue Liu","Yuhao Qing","Dong Huang","Xinyi He","Qian Liu","Zejun Ma","See-kiong Ng"],"abstract":"Large Language Models (LLMs) generate functionally correct solutions but often fall short in code efficiency, a critical bottleneck for real-world deployment. In this paper, we introduce a novel test-time iterative optimization framework to address this, employing a closed-loop system where LLMs iteratively refine code based on empirical performance feedback from an execution sandbox. We explore three training strategies: Supervised Fine-Tuning (SFT), Direct Preference Optimization (DPO), and Group Relative Policy Optimization (GRPO). Experiments on our Venus dataset and the APPS benchmark show that SFT and DPO rapidly saturate in efficiency gains. In contrast, GRPO, using reinforcement learning (RL) with execution feedback, continuously optimizes code performance, significantly boosting both pass@1 (from 47% to 62%) and the likelihood of outperforming human submissions in efficiency (from 31% to 45%). Our work demonstrates effective test-time code efficiency improvement and critically reveals the power of RL in teaching LLMs to truly self-improve code efficiency.","published":"2025-05-29T12:14:29Z","updated":"2025-06-03T09:55:22Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2505.23387v3","pdf_url":"https://arxiv.org/pdf/2505.23387v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.23229","versioned_id":"2505.23229v2","title":"MCTSr-Zero: Self-Reflective Psychological Counseling Dialogues Generation via Principles and Adaptive Exploration","authors":["Hao Lu","Yanchi Gu","Haoyuan Huang","Yulin Zhou","Ningxin Zhu","Chen Li"],"abstract":"The integration of Monte Carlo Tree Search (MCTS) with Large Language Models (LLMs) has demonstrated significant success in structured, problem-oriented tasks. However, applying these methods to open-ended dialogues, such as those in psychological counseling, presents unique challenges. Unlike tasks with objective correctness, success in therapeutic conversations depends on subjective factors like empathetic engagement, ethical adherence, and alignment with human preferences, for which strict \"correctness\" criteria are ill-defined. Existing result-oriented MCTS approaches can therefore produce misaligned responses. To address this, we introduce MCTSr-Zero, an MCTS framework designed for open-ended, human-centric dialogues. Its core innovation is \"domain alignment\", which shifts the MCTS search objective from predefined end-states towards conversational trajectories that conform to target domain principles (e.g., empathy in counseling). Furthermore, MCTSr-Zero incorporates \"Regeneration\" and \"Meta-Prompt Adaptation\" mechanisms to substantially broaden exploration by allowing the MCTS to consider fundamentally different initial dialogue strategies. We evaluate MCTSr-Zero in psychological counseling by generating multi-turn dialogue data, which is used to fine-tune an LLM, PsyLLM. We also introduce PsyEval, a benchmark for assessing multi-turn psychological counseling dialogues. Experiments demonstrate that PsyLLM achieves state-of-the-art performance on PsyEval and other relevant metrics, validating MCTSr-Zero's effectiveness in generating high-quality, principle-aligned conversational data for human-centric domains and addressing the LLM challenge of consistently adhering to complex psychological standards.","published":"2025-05-29T08:30:15Z","updated":"2025-11-18T09:09:44Z","categories":["cs.CL","cs.AI","cs.CY"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.23229v2","pdf_url":"https://arxiv.org/pdf/2505.23229v2","comment":"48 pages, 3 figures. Accepted in AAAI-2026 (Main Technical Track). For code and model, see this https://github.com/JianChengXingYun/Mctsr-Zero","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.23224","versioned_id":"2505.23224v3","title":"MMBoundary: Advancing MLLM Knowledge Boundary Awareness through Reasoning Step Confidence Calibration","authors":["Zhitao He","Sandeep Polisetty","Zhiyuan Fan","Yuchen Huang","Shujin Wu","Yi R. Fung"],"abstract":"In recent years, multimodal large language models (MLLMs) have made significant progress but continue to face inherent challenges in multimodal reasoning, which requires multi-level (e.g., perception, reasoning) and multi-granular (e.g., multi-step reasoning chain) advanced inferencing. Prior work on estimating model confidence tends to focus on the overall response for training and calibration, but fails to assess confidence in each reasoning step, leading to undesirable hallucination snowballing. In this work, we present MMBoundary, a novel framework that advances the knowledge boundary awareness of MLLMs through reasoning step confidence calibration. To achieve this, we propose to incorporate complementary textual and cross-modal self-rewarding signals to estimate confidence at each step of the MLLM reasoning process. In addition to supervised fine-tuning MLLM on this set of self-rewarded confidence estimation signal for initial confidence expression warm-up, we introduce a reinforcement learning stage with multiple reward functions for further aligning model knowledge and calibrating confidence at each reasoning step, enhancing reasoning chain self-correction. Empirical results show that MMBoundary significantly outperforms existing methods across diverse domain datasets and metrics, achieving an average of 7.5% reduction in multimodal confidence calibration errors and up to 8.3% improvement in task performance.","published":"2025-05-29T08:14:40Z","updated":"2025-06-27T08:40:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.23224v3","pdf_url":"https://arxiv.org/pdf/2505.23224v3","comment":"18 pages, ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.23060","versioned_id":"2505.23060v3","title":"Self-Correcting Code Generation Using Small Language Models","authors":["Jeonghun Cho","Deokhyung Kang","Hyounghun Kim","Gary Geunbae Lee"],"abstract":"Self-correction has demonstrated potential in code generation by allowing language models to revise and improve their outputs through successive refinement. Recent studies have explored prompting-based strategies that incorporate verification or feedback loops using proprietary models, as well as training-based methods that leverage their strong reasoning capabilities. However, whether smaller models possess the capacity to effectively guide their outputs through self-reflection remains unexplored. Our findings reveal that smaller models struggle to exhibit reflective revision behavior across both self-correction paradigms. In response, we introduce CoCoS, an approach designed to enhance the ability of small language models for multi-turn code correction. Specifically, we propose an online reinforcement learning objective that trains the model to confidently maintain correct outputs while progressively correcting incorrect outputs as turns proceed. Our approach features an accumulated reward function that aggregates rewards across the entire trajectory and a fine-grained reward better suited to multi-turn correction scenarios. This facilitates the model in enhancing initial response quality while achieving substantial improvements through self-correction. With 1B-scale models, CoCoS achieves improvements of 35.8% on the MBPP and 27.7% on HumanEval compared to the baselines.","published":"2025-05-29T04:04:44Z","updated":"2025-08-23T09:05:01Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.23060v3","pdf_url":"https://arxiv.org/pdf/2505.23060v3","comment":"Accepted at EMNLP 2025 (Findings, long paper)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.22954","versioned_id":"2505.22954v3","title":"Darwin Godel Machine: Open-Ended Evolution of Self-Improving Agents","authors":["Jenny Zhang","Shengran Hu","Cong Lu","Robert Lange","Jeff Clune"],"abstract":"Today's AI systems have human-designed, fixed architectures and cannot autonomously and continuously improve themselves. The advance of AI could itself be automated. If done safely, that would accelerate AI development and allow us to reap its benefits much sooner. Meta-learning can automate the discovery of novel algorithms, but is limited by first-order improvements and the human design of a suitable search space. The Gödel machine proposed a theoretical alternative: a self-improving AI that repeatedly modifies itself in a provably beneficial manner. Unfortunately, proving that most changes are net beneficial is impossible in practice. We introduce the Darwin Gödel Machine (DGM), a self-improving system that iteratively modifies its own code (thereby also improving its ability to modify its own codebase) and empirically validates each change using coding benchmarks. Inspired by Darwinian evolution and open-endedness research, the DGM maintains an archive of generated coding agents. It grows the archive by sampling an agent from it and using a foundation model to create a new, interesting, version of the sampled agent. This open-ended exploration forms a growing tree of diverse, high-quality agents and allows the parallel exploration of many different paths through the search space. Empirically, the DGM automatically improves its coding capabilities (e.g., better code editing tools, long-context window management, peer-review mechanisms), increasing performance on SWE-bench from 20.0% to 50.0%, and on Polyglot from 14.2% to 30.7%. Furthermore, the DGM significantly outperforms baselines without self-improvement or open-ended exploration. All experiments were done with safety precautions (e.g., sandboxing, human oversight). The DGM is a significant step toward self-improving AI, capable of gathering its own stepping stones along paths that unfold into endless innovation.","published":"2025-05-29T00:26:15Z","updated":"2026-03-12T23:47:40Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.22954v3","pdf_url":"https://arxiv.org/pdf/2505.22954v3","comment":"Code at https://github.com/jennyzzt/dgm","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.22651","versioned_id":"2505.22651v2","title":"Sherlock: Self-Correcting Reasoning in Vision-Language Models","authors":["Yi Ding","Ruqi Zhang"],"abstract":"Reasoning Vision-Language Models (VLMs) have shown promising performance on complex multimodal tasks. However, they still face significant challenges: they are highly sensitive to reasoning errors, require large volumes of annotated data or accurate verifiers, and struggle to generalize beyond specific domains. To address these limitations, we explore self-correction as a strategy to enhance reasoning VLMs. We first conduct an in-depth analysis of reasoning VLMs' self-correction abilities and identify key gaps. Based on our findings, we introduce Sherlock, a self-correction and self-improvement training framework. Sherlock introduces a trajectory-level self-correction objective, a preference data construction method based on visual perturbation, and a dynamic $β$ for preference tuning. Once the model acquires self-correction capabilities using only 20k randomly sampled annotated data, it continues to self-improve without external supervision. Built on the Llama3.2-Vision-11B model, Sherlock achieves remarkable results across eight benchmarks, reaching an average accuracy of 64.1 with direct generation and 65.4 after self-correction. It outperforms LLaVA-CoT (63.2), Mulberry (63.9), and LlamaV-o1 (63.4) while using less than 20% of the annotated data.","published":"2025-05-28T17:58:03Z","updated":"2025-10-23T04:45:46Z","categories":["cs.CV","cs.CL","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.22651v2","pdf_url":"https://arxiv.org/pdf/2505.22651v2","comment":"Published at NeurIPS 2025, 27 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.22453","versioned_id":"2505.22453v2","title":"First SFT, Second RL, Third UPT: Continual Improving Multi-Modal LLM Reasoning via Unsupervised Post-Training","authors":["Lai Wei","Yuting Li","Chen Wang","Yue Wang","Linghe Kong","Weiran Huang","Lichao Sun"],"abstract":"Improving Multi-modal Large Language Models (MLLMs) in the post-training stage typically relies on supervised fine-tuning (SFT) or reinforcement learning (RL), which require expensive and manually annotated multi-modal data--an ultimately unsustainable resource. This limitation has motivated a growing interest in unsupervised paradigms as a third stage of post-training after SFT and RL. While recent efforts have explored this direction, their methods are complex and difficult to iterate. To address this, we propose MM-UPT, a simple yet effective framework for unsupervised post-training of MLLMs, enabling continual self-improvement without any external supervision. The training method of MM-UPT builds upon GRPO, replacing traditional reward signals with a self-rewarding mechanism based on majority voting over multiple sampled responses. Our experiments demonstrate that such training method effectively improves the reasoning ability of Qwen2.5-VL-7B (e.g., 66.3\\%$\\rightarrow$72.9\\% on MathVista, 62.9\\%$\\rightarrow$68.7\\% on We-Math), using standard dataset without ground truth labels. To further explore scalability, we extend our framework to a data self-generation setting, designing two strategies that prompt the MLLM to synthesize new training samples on its own. Additional experiments show that combining these synthetic data with the unsupervised training method can also boost performance, highlighting a promising approach for scalable self-improvement. Overall, MM-UPT offers a new paradigm for autonomous enhancement of MLLMs, serving as a critical third step after initial SFT and RL in the absence of external supervision. Our code is available at https://github.com/waltonfuture/MM-UPT.","published":"2025-05-28T15:11:16Z","updated":"2025-10-27T09:06:32Z","categories":["cs.CL","cs.AI","cs.CV","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.22453v2","pdf_url":"https://arxiv.org/pdf/2505.22453v2","comment":"Accepted by NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.22334","versioned_id":"2505.22334v2","title":"Advancing Multimodal Reasoning via Reinforcement Learning with Cold Start","authors":["Lai Wei","Yuting Li","Kaipeng Zheng","Chen Wang","Yue Wang","Linghe Kong","Lichao Sun","Weiran Huang"],"abstract":"Recent advancements in large language models (LLMs) have demonstrated impressive chain-of-thought reasoning capabilities, with reinforcement learning (RL) playing a crucial role in this progress. While \"aha moment\" patterns--where models exhibit self-correction through reflection--are often attributed to emergent properties from RL, we first demonstrate that these patterns exist in multimodal LLMs (MLLMs) prior to RL training but may not necessarily correlate with improved reasoning performance. Building on these insights, we present a comprehensive study on enhancing multimodal reasoning through a two-stage approach: (1) supervised fine-tuning (SFT) as a cold start with structured chain-of-thought reasoning patterns, followed by (2) reinforcement learning via GRPO to further refine these capabilities. Our extensive experiments show that this combined approach consistently outperforms both SFT-only and RL-only methods across challenging multimodal reasoning benchmarks. The resulting models achieve state-of-the-art performance among open-source MLLMs at both 3B and 7B scales, with our 7B model showing substantial improvements over base models (e.g., 66.3 %$\\rightarrow$73.4 % on MathVista, 62.9 %$\\rightarrow$70.4 % on We-Math) and our 3B model achieving performance competitive with several 7B models. Overall, this work provides practical guidance for building advanced multimodal reasoning models. Our code is available at https://github.com/waltonfuture/RL-with-Cold-Start.","published":"2025-05-28T13:21:38Z","updated":"2025-07-23T07:37:08Z","categories":["cs.CL","cs.AI","cs.CV","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.22334v2","pdf_url":"https://arxiv.org/pdf/2505.22334v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.22131","versioned_id":"2505.22131v2","title":"Enhancing Long-Chain Reasoning Distillation through Error-Aware Self-Reflection","authors":["Zhuoyang Wu","Xinze Li","Zhenghao Liu","Yukun Yan","Zhiyuan Liu","Minghe Yu","Cheng Yang","Yu Gu","Ge Yu","Maosong Sun"],"abstract":"Large Language Models (LLMs) have exhibited strong reasoning capabilities and achieved remarkable performance in mathematical problem-solving tasks. Recently, distilling reasoning ability from long-form Chains-of-Thought (CoTs) has emerged as a promising approach for enhancing Small Language Models (SLMs). Existing studies typically treat SLMs as student models and use long-form CoTs as supervision signals for Supervised Fine-Tuning (SFT) to transfer reasoning ability. However, such long-form CoT teachers are usually unaware of the student model's capacity, which limits the effective utilization of the provided reasoning traces. To overcome this limitation, we propose errOr-aware self-ReflectION (ORION), a framework that refines teacher CoTs through an Error-Aware Reflection process. ORION enables the student model to construct more tailored teacher CoTs by refining teacher CoTs and incorporating its own reasoning errors. Experiments on multiple mathematical reasoning benchmarks demonstrate that ORION consistently improves performance by more than 2% over all baselines. Further analysis reveals that the CoTs constructed by ORION exhibit higher coherence and logical consistency, thereby serving as more effective supervision signals for SFT. All codes are available at https://github.com/NEUIR/ORION.git.","published":"2025-05-28T08:57:03Z","updated":"2025-10-14T07:56:38Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.22131v2","pdf_url":"https://arxiv.org/pdf/2505.22131v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.22053","versioned_id":"2505.22053v2","title":"AudioGenie: A Training-Free Multi-Agent Framework for Diverse Multimodality-to-Multiaudio Generation","authors":["Yan Rong","Jinting Wang","Guangzhi Lei","Shan Yang","Li Liu"],"abstract":"Multimodality-to-Multiaudio (MM2MA) generation faces significant challenges in synthesizing diverse and contextually aligned audio types (e.g., sound effects, speech, music, and songs) from multimodal inputs (e.g., video, text, images), owing to the scarcity of high-quality paired datasets and the lack of robust multi-task learning frameworks. Recently, multi-agent system shows great potential in tackling the above issues. However, directly applying it to MM2MA task presents three critical challenges: (1) inadequate fine-grained understanding of multimodal inputs (especially for video), (2) the inability of single models to handle diverse audio events, and (3) the absence of self-correction mechanisms for reliable outputs. To this end, we propose AudioGenie, a novel training-free multi-agent system featuring a dual-layer architecture with a generation team and a supervisor team. For the generation team, a fine-grained task decomposition and an adaptive Mixture-of-Experts (MoE) collaborative entity are designed for detailed comprehensive multimodal understanding and dynamic model selection, and a trial-and-error iterative refinement module is designed for self-correction. The supervisor team ensures temporal-spatial consistency and verifies outputs through feedback loops. Moreover, we build MA-Bench, the first benchmark for MM2MA tasks, comprising 198 annotated videos with multi-type audios. Experiments demonstrate that our AudioGenie achieves state-of-the-art (SOTA) or comparable performance across 9 metrics in 8 tasks. User study further validates the effectiveness of our method in terms of quality, accuracy, alignment, and aesthetic. The project website with audio samples can be found at https://audiogenie.github.io/.","published":"2025-05-28T07:23:53Z","updated":"2025-08-05T07:47:10Z","categories":["cs.SD","cs.MA","cs.MM","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2505.22053v2","pdf_url":"https://arxiv.org/pdf/2505.22053v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.21940","versioned_id":"2505.21940v1","title":"RISE: Reasoning Enhancement via Iterative Self-Exploration in Multi-hop Question Answering","authors":["Bolei He","Xinran He","Mengke Chen","Xianwei Xue","Ying Zhu","Zhenhua Ling"],"abstract":"Large Language Models (LLMs) excel in many areas but continue to face challenges with complex reasoning tasks, such as Multi-Hop Question Answering (MHQA). MHQA requires integrating evidence from diverse sources while managing intricate logical dependencies, often leads to errors in reasoning. Retrieval-Augmented Generation (RAG), widely employed in MHQA tasks, faces challenges in effectively filtering noisy data and retrieving all necessary evidence, thereby limiting its effectiveness in addressing MHQA challenges. To address these challenges, we propose RISE:Reasoning Enhancement via Iterative Self-Exploration, a novel framework designed to enhance models' reasoning capability through iterative self-exploration. Specifically, RISE involves three key steps in addressing MHQA tasks: question decomposition, retrieve-then-read, and self-critique. By leveraging continuous self-exploration, RISE identifies accurate reasoning paths, iteratively self-improving the model's capability to integrate evidence, maintain logical consistency, and enhance performance in MHQA tasks. Extensive experiments on multiple MHQA benchmarks demonstrate that RISE significantly improves reasoning accuracy and task performance.","published":"2025-05-28T03:48:28Z","updated":"2025-05-28T03:48:28Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.21940v1","pdf_url":"https://arxiv.org/pdf/2505.21940v1","comment":"ACL 2025 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.21496","versioned_id":"2505.21496v1","title":"UI-Genie: A Self-Improving Approach for Iteratively Boosting MLLM-based Mobile GUI Agents","authors":["Han Xiao","Guozhi Wang","Yuxiang Chai","Zimu Lu","Weifeng Lin","Hao He","Lue Fan","Liuyang Bian","Rui Hu","Liang Liu","Shuai Ren","Yafei Wen","Xiaoxin Chen","Aojun Zhou","Hongsheng Li"],"abstract":"In this paper, we introduce UI-Genie, a self-improving framework addressing two key challenges in GUI agents: verification of trajectory outcome is challenging and high-quality training data are not scalable. These challenges are addressed by a reward model and a self-improving pipeline, respectively. The reward model, UI-Genie-RM, features an image-text interleaved architecture that efficiently pro- cesses historical context and unifies action-level and task-level rewards. To sup- port the training of UI-Genie-RM, we develop deliberately-designed data genera- tion strategies including rule-based verification, controlled trajectory corruption, and hard negative mining. To address the second challenge, a self-improvement pipeline progressively expands solvable complex GUI tasks by enhancing both the agent and reward models through reward-guided exploration and outcome verification in dynamic environments. For training the model, we generate UI- Genie-RM-517k and UI-Genie-Agent-16k, establishing the first reward-specific dataset for GUI agents while demonstrating high-quality synthetic trajectory gen- eration without manual annotation. Experimental results show that UI-Genie achieves state-of-the-art performance across multiple GUI agent benchmarks with three generations of data-model self-improvement. We open-source our complete framework implementation and generated datasets to facilitate further research in https://github.com/Euphoria16/UI-Genie.","published":"2025-05-27T17:58:06Z","updated":"2025-05-27T17:58:06Z","categories":["cs.CL","cs.CV","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.21496v1","pdf_url":"https://arxiv.org/pdf/2505.21496v1","comment":"https://github.com/Euphoria16/UI-Genie","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.21444","versioned_id":"2505.21444v2","title":"Can Large Reasoning Models Self-Train?","authors":["Sheikh Shafayat","Fahim Tajwar","Ruslan Salakhutdinov","Jeff Schneider","Andrea Zanette"],"abstract":"Recent successes of reinforcement learning (RL) in training large reasoning models motivate the question of whether self-training - the process where a model learns from its own judgments - can be sustained within RL. In this work, we study this question using majority voting as a simple self-feedback mechanism. On a comprehensive set of experiments on both synthetic and real reasoning tasks, we find that this basic approach improves not only the model's reasoning performance, but also its capability of generating better quality feedback for the next RL iteration, driving further model improvement. Yet our analysis also reveals a critical limitation of such a self-training paradigm - prolonged RL with self-reward leads to reward hacking where models learn to maximize training (pseudo-)reward, resulting in sudden and complete performance collapse. Together, these results highlight feedback design as the central challenge and call for future research on mechanisms to enable prolonged self-improvement.","published":"2025-05-27T17:16:00Z","updated":"2025-10-08T22:32:56Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.21444v2","pdf_url":"https://arxiv.org/pdf/2505.21444v2","comment":"Project website: https://self-rewarding-llm-training.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.21097","versioned_id":"2505.21097v2","title":"Thinker: Learning to Think Fast and Slow","authors":["Stephen Chung","Wenyu Du","Jie Fu"],"abstract":"Recent studies show that the reasoning capabilities of Large Language Models (LLMs) can be improved by applying Reinforcement Learning (RL) to question-answering (QA) tasks in areas such as math and coding. With a long context length, LLMs may learn to perform search, as indicated by the self-correction behavior observed in DeepSeek R1. However, this search behavior is often imprecise and lacks confidence, resulting in long, redundant responses and highlighting deficiencies in intuition and verification. Inspired by the Dual Process Theory in psychology, we introduce a simple modification to the QA task that includes four stages: Fast Thinking, where the LLM must answer within a strict token budget; Verification, where the model evaluates its initial response; Slow Thinking, where it refines the initial response with more deliberation; and Summarization, where it distills the refinement from the previous stage into precise steps. Our proposed task improves average accuracy from 25.6% to 27.3% for Qwen2.5-1.5B, and from 45.9% to 51.0% for DeepSeek-R1-Qwen-1.5B. Notably, for Qwen2.5-1.5B, the Fast Thinking mode alone achieves 25.2% accuracy using fewer than 1000 tokens, demonstrating substantial inference efficiency gains. These findings suggest that intuition and deliberative reasoning are distinct, complementary systems benefiting from targeted training. Additionally, we have open-sourced both the trained models and the source code.","published":"2025-05-27T12:22:46Z","updated":"2025-10-16T16:20:17Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.21097v2","pdf_url":"https://arxiv.org/pdf/2505.21097v2","comment":"23 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20718","versioned_id":"2505.20718v2","title":"VLM Can Be a Good Assistant: Enhancing Embodied Visual Tracking with Self-Improving Vision-Language Models","authors":["Kui Wu","Shuhang Xu","Hao Chen","Churan Wang","Zhoujun Li","Yizhou Wang","Fangwei Zhong"],"abstract":"We introduce a novel self-improving framework that enhances Embodied Visual Tracking (EVT) with Vision-Language Models (VLMs) to address the limitations of current active visual tracking systems in recovering from tracking failure. Our approach combines the off-the-shelf active tracking methods with VLMs' reasoning capabilities, deploying a fast visual policy for normal tracking and activating VLM reasoning only upon failure detection. The framework features a memory-augmented self-reflection mechanism that enables the VLM to progressively improve by learning from past experiences, effectively addressing VLMs' limitations in 3D spatial reasoning. Experimental results demonstrate significant performance improvements, with our framework boosting success rates by $72\\%$ with state-of-the-art RL-based approaches and $220\\%$ with PID-based methods in challenging environments. This work represents the first integration of VLM-based reasoning to assist EVT agents in proactive failure recovery, offering substantial advances for real-world robotic applications that require continuous target monitoring in dynamic, unstructured environments. Project website: https://sites.google.com/view/evt-recovery-assistant.","published":"2025-05-27T04:53:50Z","updated":"2025-05-28T15:54:19Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.20718v2","pdf_url":"https://arxiv.org/pdf/2505.20718v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20579","versioned_id":"2505.20579v6","title":"The challenge of hidden gifts in multi-agent reinforcement learning","authors":["Dane Malenfant","Blake A. Richards"],"abstract":"Sometimes we benefit from actions that others have taken even when we are unaware that they took those actions. For example, if your neighbor chooses not to take a parking spot in front of your house when you are not there, you can benefit, even without being aware that they took this action. These ``hidden gifts'' represent an interesting challenge for multi-agent reinforcement learning (MARL), since assigning credit when the beneficial actions of others are hidden is non-trivial. Here, we study the impact of hidden gifts with a simple MARL task. In this task, agents in a grid-world environment have individual doors to unlock in order to obtain individual rewards. As well, if all the agents unlock their door the group receives a larger collective reward. However, there is only one key for all of the doors, such that the collective reward can only be obtained when the agents drop the key for others after they use it. Notably, there is nothing to indicate to an agent that the other agents have dropped the key, thus this act for others is a ``hidden gift''. We show that several different state-of-the-art MARL algorithms, including MARL specific architectures, fail to learn how to obtain the collective reward in this simple task. Interestingly, we find that decentralized actor-critic policy gradient agents can succeed when we provide them with information about their own action history, but MARL agents still cannot solve the task with action history. Finally, we derive a correction term for policy gradient agents, inspired by learning aware approaches, which reduces the variance in learning and helps them to converge to collective success more reliably. These results show that credit assignment in multi-agent settings can be particularly challenging in the presence of ``hidden gifts'', and demonstrate that self learning-awareness in decentralized agents can benefit these settings.","published":"2025-05-26T23:28:52Z","updated":"2026-04-08T20:58:11Z","categories":["cs.LG","cs.AI","cs.MA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.20579v6","pdf_url":"https://arxiv.org/pdf/2505.20579v6","comment":"Increased analysis of LOLA baselines and moved to main section. Cleaned up proof and fixed error where gradient symbol was left in front of the log(policy). Self correction becomes more intuitive","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20561","versioned_id":"2505.20561v2","title":"Beyond Markovian: Reflective Exploration via Bayes-Adaptive RL for LLM Reasoning","authors":["Shenao Zhang","Yaqing Wang","Yinxiao Liu","Tianqi Liu","Peter Grabowski","Eugene Ie","Zhaoran Wang","Yunxuan Li"],"abstract":"Large Language Models (LLMs) trained via Reinforcement Learning (RL) have exhibited strong reasoning capabilities and emergent reflective behaviors, such as rethinking and error correction, as a form of in-context exploration. However, the Markovian policy obtained from conventional RL training does not give rise to reflective exploration behaviors since the policy depends on the history only through the state and therefore has no incentive to enrich identical states with additional context. Instead, RL exploration is only useful during training to learn the optimal policy in a trial-and-error manner. Therefore, it remains unclear whether reflective reasoning will emerge during RL, or why it is beneficial. To remedy this, we recast reflective exploration within a Bayesian RL framework, which optimizes the expected return under a posterior distribution over Markov decision processes induced by the training data. This Bayesian formulation admits uncertainty-adaptive policies that, through belief updates, naturally incentivize information-gathering actions and induce self-reflection behaviors. Our resulting algorithm, BARL, instructs the LLM to stitch and switch strategies based on the observed outcomes, offering principled guidance on when and how the model should reflectively explore. Empirical results on both synthetic and mathematical reasoning tasks demonstrate that BARL outperforms conventional RL approaches, achieving superior test-time performance and token efficiency. Our code is available at https://github.com/shenao-zhang/BARL.","published":"2025-05-26T22:51:00Z","updated":"2025-12-07T03:32:32Z","categories":["cs.LG","cs.AI","cs.CL","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.20561v2","pdf_url":"https://arxiv.org/pdf/2505.20561v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20521","versioned_id":"2505.20521v2","title":"Project Riley: Multimodal Multi-Agent LLM Collaboration with Emotional Reasoning and Voting","authors":["Ana Rita Ortigoso","Gabriel Vieira","Daniel Fuentes","Luis Frazão","Nuno Costa","António Pereira"],"abstract":"This paper presents Project Riley, a novel multimodal and multi-model conversational AI architecture oriented towards the simulation of reasoning influenced by emotional states. Drawing inspiration from Pixar's Inside Out, the system comprises five distinct emotional agents - Joy, Sadness, Fear, Anger, and Disgust - that engage in structured multi-round dialogues to generate, criticise, and iteratively refine responses. A final reasoning mechanism synthesises the contributions of these agents into a coherent output that either reflects the dominant emotion or integrates multiple perspectives. The architecture incorporates both textual and visual large language models (LLMs), alongside advanced reasoning and self-refinement processes. A functional prototype was deployed locally in an offline environment, optimised for emotional expressiveness and computational efficiency. From this initial prototype, another one emerged, called Armando, which was developed for use in emergency contexts, delivering emotionally calibrated and factually accurate information through the integration of Retrieval-Augmented Generation (RAG) and cumulative context tracking. The Project Riley prototype was evaluated through user testing, in which participants interacted with the chatbot and completed a structured questionnaire assessing three dimensions: Emotional Appropriateness, Clarity and Utility, and Naturalness and Human-likeness. The results indicate strong performance in structured scenarios, particularly with respect to emotional alignment and communicative clarity.","published":"2025-05-26T20:53:53Z","updated":"2025-09-08T16:40:29Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.20521v2","pdf_url":"https://arxiv.org/pdf/2505.20521v2","comment":"28 pages, 5 figures. Submitted for review to Information Fusion","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20192","versioned_id":"2505.20192v3","title":"FunReason: Enhancing Large Language Models' Function Calling via Self-Refinement Multiscale Loss and Automated Data Refinement","authors":["Bingguang Hao","ZengZhuang Xu","Maolin Wang","Yuntao Wen","Yicheng Chen","Cunyin Peng","Long Chen","Dong Wang","Xiangyu Zhao","Jinjie Gu","Chenyi Zhuang","Ji Zhang"],"abstract":"The integration of large language models (LLMs) with function calling has emerged as a crucial capability for enhancing their practical utility in real-world applications. However, effectively combining reasoning processes with accurate function execution remains a significant challenge. Traditional training approaches often struggle to balance the detailed reasoning steps with the precision of function calls, leading to suboptimal performance. To address these limitations, we introduce FunReason, a novel framework that enhances LLMs' function calling capabilities through an automated data refinement strategy and a Self-Refinement Multiscale Loss (SRML) approach. FunReason leverages LLMs' natural reasoning abilities to generate high-quality training examples, focusing on query parseability, reasoning coherence, and function call precision. The SRML approach dynamically balances the contribution of reasoning processes and function call accuracy during training, addressing the inherent trade-off between these two critical aspects. FunReason achieves performance comparable to GPT-4o while effectively mitigating catastrophic forgetting during fine-tuning. FunReason provides a comprehensive solution for enhancing LLMs' function calling capabilities by introducing a balanced training methodology and a data refinement pipeline. For code and dataset, please refer to our repository at GitHub https://github.com/BingguangHao/FunReason","published":"2025-05-26T16:38:06Z","updated":"2025-11-25T07:50:07Z","categories":["cs.LG","cs.IR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.20192v3","pdf_url":"https://arxiv.org/pdf/2505.20192v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20107","versioned_id":"2505.20107v2","title":"Refining Few-Step Text-to-Multiview Diffusion via Reinforcement Learning","authors":["Ziyi Zhang","Li Shen","Deheng Ye","Yong Luo","Huangxuan Zhao","Meng Liu","Wei Yu","Lefei Zhang"],"abstract":"Text-to-multiview (T2MV) diffusion models have shown great promise in generating multiple views of a scene from a single text prompt. While few-step backbones enable real-time T2MV generation, they often compromise key aspects of generation quality, such as per-view fidelity and cross-view consistency. Reinforcement learning (RL) finetuning offers a potential solution, yet existing approaches designed for single-image diffusion do not readily extend to the few-step T2MV setting, as they neglect cross-view coordination and suffer from weak learning signals in few-step regimes. To address this, we propose MVC-ZigAL, a tailored RL finetuning framework for few-step T2MV diffusion models. Specifically, its core insights are: (1) a new MDP formulation that jointly models all generated views and assesses their collective quality via a joint-view reward; (2) a novel advantage learning strategy that exploits the performance gains of a self-refinement sampling scheme over standard sampling, yielding stronger learning signals for effective RL finetuning; and (3) a unified RL framework that extends advantage learning with a Lagrangian dual formulation for multiview-constrained optimization, balancing single-view and joint-view objectives through adaptive primal-dual updates under a self-paced threshold curriculum that harmonizes exploration and constraint enforcement. Collectively, these designs enable robust and balanced RL finetuning for few-step T2MV diffusion models, yielding substantial gains in both per-view fidelity and cross-view consistency. Code is available at https://github.com/ZiyiZhang27/MVC-ZigAL.","published":"2025-05-26T15:11:26Z","updated":"2026-03-17T15:09:09Z","categories":["cs.LG","cs.CV"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.20107v2","pdf_url":"https://arxiv.org/pdf/2505.20107v2","comment":"Accepted to CVPR 2026","journal_ref":"IEEE/CVF Conference on Computer Vision and Pattern Recognition, 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20023","versioned_id":"2505.20023v1","title":"Training LLM-Based Agents with Synthetic Self-Reflected Trajectories and Partial Masking","authors":["Yihan Chen","Benfeng Xu","Xiaorui Wang","Yongdong Zhang","Zhendong Mao"],"abstract":"Autonomous agents, which perceive environments and take actions to achieve goals, have become increasingly feasible with the advancements in large language models (LLMs). However, current powerful agents often depend on sophisticated prompt engineering combined with closed-source LLMs like GPT-4. Although training open-source LLMs using expert trajectories from teacher models has yielded some improvements in agent capabilities, this approach still faces limitations such as performance plateauing and error propagation. To mitigate these challenges, we propose STeP, a novel method for improving LLM-based agent training. We synthesize self-reflected trajectories that include reflections and corrections of error steps, which enhance the effectiveness of LLM agents in learning from teacher models, enabling them to become agents capable of self-reflecting and correcting. We also introduce partial masking strategy that prevents the LLM from internalizing incorrect or suboptimal steps. Experiments demonstrate that our method improves agent performance across three representative tasks: ALFWorld, WebShop, and SciWorld. For the open-source model LLaMA2-7B-Chat, when trained using self-reflected trajectories constructed with Qwen1.5-110B-Chat as the teacher model, it achieves comprehensive improvements with less training data compared to agents trained exclusively on expert trajectories.","published":"2025-05-26T14:11:12Z","updated":"2025-05-26T14:11:12Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.20023v1","pdf_url":"https://arxiv.org/pdf/2505.20023v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20013","versioned_id":"2505.20013v2","title":"WebCoT: Enhancing Web Agent Reasoning by Reconstructing Chain-of-Thought in Reflection, Branching, and Rollback","authors":["Minda Hu","Tianqing Fang","Jianshu Zhang","Junyu Ma","Zhisong Zhang","Jingyan Zhou","Hongming Zhang","Haitao Mi","Dong Yu","Irwin King"],"abstract":"Web agents powered by Large Language Models (LLMs) show promise for next-generation AI, but their limited reasoning in uncertain, dynamic web environments hinders robust deployment. In this paper, we identify key reasoning skills essential for effective web agents, i.e., reflection & lookahead, branching, and rollback, and curate trajectory data that exemplifies these abilities by reconstructing the agent's (inference-time) reasoning algorithms into chain-of-thought rationales. We conduct experiments in the agent self-improving benchmark, OpenWebVoyager, and demonstrate that distilling salient reasoning patterns into the backbone LLM via simple fine-tuning can substantially enhance its performance. Our approach yields significant improvements across multiple benchmarks, including WebVoyager, Mind2web-live, and SimpleQA (web search), highlighting the potential of targeted reasoning skill enhancement for web agents.","published":"2025-05-26T14:03:37Z","updated":"2025-09-18T11:32:15Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.20013v2","pdf_url":"https://arxiv.org/pdf/2505.20013v2","comment":"18 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19855","versioned_id":"2505.19855v1","title":"Editing as Unlearning: Are Knowledge Editing Methods Strong Baselines for Large Language Model Unlearning?","authors":["Zexi Li","Xiangzhu Wang","William F. Shen","Meghdad Kurmanji","Xinchi Qiu","Dongqi Cai","Chao Wu","Nicholas D. Lane"],"abstract":"Large language Model (LLM) unlearning, i.e., selectively removing information from LLMs, is vital for responsible model deployment. Differently, LLM knowledge editing aims to modify LLM knowledge instead of removing it. Though editing and unlearning seem to be two distinct tasks, we find there is a tight connection between them. In this paper, we conceptualize unlearning as a special case of editing where information is modified to a refusal or \"empty set\" $\\emptyset$ response, signifying its removal. This paper thus investigates if knowledge editing techniques are strong baselines for LLM unlearning. We evaluate state-of-the-art (SOTA) editing methods (e.g., ROME, MEMIT, GRACE, WISE, and AlphaEdit) against existing unlearning approaches on pretrained and finetuned knowledge. Results show certain editing methods, notably WISE and AlphaEdit, are effective unlearning baselines, especially for pretrained knowledge, and excel in generating human-aligned refusal answers. To better adapt editing methods for unlearning applications, we propose practical recipes including self-improvement and query merging. The former leverages the LLM's own in-context learning ability to craft a more human-aligned unlearning target, and the latter enables ROME and MEMIT to perform well in unlearning longer sample sequences. We advocate for the unlearning community to adopt SOTA editing methods as baselines and explore unlearning from an editing perspective for more holistic LLM memory control.","published":"2025-05-26T11:39:56Z","updated":"2025-05-26T11:39:56Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.19855v1","pdf_url":"https://arxiv.org/pdf/2505.19855v1","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19850","versioned_id":"2505.19850v2","title":"DISCOVER: Automated Curricula for Sparse-Reward Reinforcement Learning","authors":["Leander Diaz-Bone","Marco Bagatella","Jonas Hübotter","Andreas Krause"],"abstract":"Sparse-reward reinforcement learning (RL) can model a wide range of highly complex tasks. Solving sparse-reward tasks is RL's core premise, requiring efficient exploration coupled with long-horizon credit assignment, and overcoming these challenges is key for building self-improving agents with superhuman ability. Prior work commonly explores with the objective of solving many sparse-reward tasks, making exploration of individual high-dimensional, long-horizon tasks intractable. We argue that solving such challenging tasks requires solving simpler tasks that are relevant to the target task, i.e., whose achieval will teach the agent skills required for solving the target task. We demonstrate that this sense of direction, necessary for effective exploration, can be extracted from existing RL algorithms, without leveraging any prior information. To this end, we propose a method for directed sparse-reward goal-conditioned very long-horizon RL (DISCOVER), which selects exploratory goals in the direction of the target task. We connect DISCOVER to principled exploration in bandits, formally bounding the time until the target task becomes achievable in terms of the agent's initial distance to the target, but independent of the volume of the space of all tasks. We then perform a thorough evaluation in high-dimensional environments. We find that the directed goal selection of DISCOVER solves exploration problems that are beyond the reach of prior state-of-the-art exploration methods in RL.","published":"2025-05-26T11:35:07Z","updated":"2025-10-20T12:58:20Z","categories":["cs.LG","cs.AI","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.19850v2","pdf_url":"https://arxiv.org/pdf/2505.19850v2","comment":"NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19621","versioned_id":"2505.19621v1","title":"Think Again! The Effect of Test-Time Compute on Preferences, Opinions, and Beliefs of Large Language Models","authors":["George Kour","Itay Nakash","Ateret Anaby-Tavor","Michal Shmueli-Scheuer"],"abstract":"As Large Language Models (LLMs) become deeply integrated into human life and increasingly influence decision-making, it's crucial to evaluate whether and to what extent they exhibit subjective preferences, opinions, and beliefs. These tendencies may stem from biases within the models, which may shape their behavior, influence the advice and recommendations they offer to users, and potentially reinforce certain viewpoints. This paper presents the Preference, Opinion, and Belief survey (POBs), a benchmark developed to assess LLMs' subjective inclinations across societal, cultural, ethical, and personal domains. We applied our benchmark to evaluate leading open- and closed-source LLMs, measuring desired properties such as reliability, neutrality, and consistency. In addition, we investigated the effect of increasing the test-time compute, through reasoning and self-reflection mechanisms, on those metrics. While effective in other tasks, our results show that these mechanisms offer only limited gains in our domain. Furthermore, we reveal that newer model versions are becoming less consistent and more biased toward specific viewpoints, highlighting a blind spot and a concerning trend. POBS: https://ibm.github.io/POBS","published":"2025-05-26T07:41:21Z","updated":"2025-05-26T07:41:21Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.19621v1","pdf_url":"https://arxiv.org/pdf/2505.19621v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.20356","versioned_id":"2505.20356v1","title":"LEGO-Compiler: Enhancing Neural Compilation Through Translation Composability","authors":["Shuoming Zhang","Jiacheng Zhao","Chunwei Xia","Zheng Wang","Yunji Chen","Xiaobing Feng","Huimin Cui"],"abstract":"Large language models (LLMs) have the potential to revolutionize how we design and implement compilers and code translation tools. However, existing LLMs struggle to handle long and complex programs. We introduce LEGO-Compiler, a novel neural compilation system that leverages LLMs to translate high-level languages into assembly code. Our approach centers on three key innovations: LEGO translation, which decomposes the input program into manageable blocks; breaking down the complex compilation process into smaller, simpler verifiable steps by organizing it as a verifiable LLM workflow by external tests; and a feedback mechanism for self-correction. Supported by formal proofs of translation composability, LEGO-Compiler demonstrates high accuracy on multiple datasets, including over 99% on ExeBench and 97.9% on industrial-grade AnsiBench. Additionally, LEGO-Compiler has also acheived near one order-of-magnitude improvement on compilable code size scalability. This work opens new avenues for applying LLMs to system-level tasks, complementing traditional compiler technologies.","published":"2025-05-26T07:07:54Z","updated":"2025-05-26T07:07:54Z","categories":["cs.PL","cs.AI","cs.SE"],"primary_category":"cs.PL","arxiv_url":"https://arxiv.org/abs/2505.20356v1","pdf_url":"https://arxiv.org/pdf/2505.20356v1","comment":"30 pages, 8 figures, 4 tables. Preprint. Under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19514","versioned_id":"2505.19514v4","title":"SIPDO: Closed-Loop Prompt Optimization via Synthetic Data Feedback","authors":["Yaoning Yu","Ye Yu","Peiyan Zhang","Kai Wei","Haojing Luo","Haohan Wang"],"abstract":"Prompt quality plays a critical role in the performance of large language models (LLMs), motivating a growing body of work on prompt optimization. Most existing methods optimize prompts over a fixed dataset, assuming static input distributions and offering limited support for iterative improvement. We introduce SIPDO (Self-Improving Prompts through Data-Augmented Optimization), a closed-loop framework for prompt learning that integrates synthetic data generation into the optimization process. SIPDO couples a synthetic data generator with a prompt optimizer, where the generator produces new examples that reveal current prompt weaknesses and the optimizer incrementally refines the prompt in response. This feedback-driven loop enables systematic improvement of prompt performance without assuming access to external supervision or new tasks. Experiments across question answering and reasoning benchmarks show that SIPDO outperforms standard prompt tuning methods, highlighting the value of integrating data synthesis into prompt learning workflows.","published":"2025-05-26T04:56:48Z","updated":"2026-01-27T13:12:54Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.19514v4","pdf_url":"https://arxiv.org/pdf/2505.19514v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19475","versioned_id":"2505.19475v2","title":"Continuous Self-Improvement of Large Language Models by Test-time Training with Verifier-Driven Sample Selection","authors":["Mohammad Mahdi Moradi","Hossam Amer","Sudhir Mudur","Weiwei Zhang","Yang Liu","Walid Ahmed"],"abstract":"Learning to adapt pretrained language models to unlabeled, out-of-distribution data is a critical challenge, as models often falter on structurally novel reasoning tasks even while excelling within their training distribution. We introduce a new framework called VDS-TTT - Verifier-Driven Sample Selection for Test-Time Training to efficiently address this. We use a learned verifier to score a pool of generated responses and select only from high ranking pseudo-labeled examples for fine-tuned adaptation. Specifically, for each input query our LLM generates N candidate answers; the verifier assigns a reliability score to each, and the response with the highest confidence and above a fixed threshold is paired with its query for test-time training. We fine-tune only low-rank LoRA adapter parameters, ensuring adaptation efficiency and fast convergence. Our proposed self-supervised framework is the first to synthesize verifier driven test-time training data for continuous self-improvement of the model. Experiments across three diverse benchmarks and three state-of-the-art LLMs demonstrate that VDS-TTT yields up to a 32.29% relative improvement over the base model and a 6.66% gain compared to verifier-based methods without test-time training, highlighting its effectiveness and efficiency for on-the-fly large language model adaptation.","published":"2025-05-26T03:54:47Z","updated":"2025-05-28T11:04:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.19475v2","pdf_url":"https://arxiv.org/pdf/2505.19475v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19410","versioned_id":"2505.19410v1","title":"Self-Reflective Planning with Knowledge Graphs: Enhancing LLM Reasoning Reliability for Question Answering","authors":["Jiajun Zhu","Ye Liu","Meikai Bao","Kai Zhang","Yanghai Zhang","Qi Liu"],"abstract":"Recently, large language models (LLMs) have demonstrated remarkable capabilities in natural language processing tasks, yet they remain prone to hallucinations when reasoning with insufficient internal knowledge. While integrating LLMs with knowledge graphs (KGs) provides access to structured, verifiable information, existing approaches often generate incomplete or factually inconsistent reasoning paths. To this end, we propose Self-Reflective Planning (SRP), a framework that synergizes LLMs with KGs through iterative, reference-guided reasoning. Specifically, given a question and topic entities, SRP first searches for references to guide planning and reflection. In the planning process, it checks initial relations and generates a reasoning path. After retrieving knowledge from KGs through a reasoning path, it implements iterative reflection by judging the retrieval result and editing the reasoning path until the answer is correctly retrieved. Extensive experiments on three public datasets demonstrate that SRP surpasses various strong baselines and further underscore its reliable reasoning ability.","published":"2025-05-26T01:59:00Z","updated":"2025-05-26T01:59:00Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.19410v1","pdf_url":"https://arxiv.org/pdf/2505.19410v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19255","versioned_id":"2505.19255v4","title":"VTool-R1: VLMs Learn to Think with Images via Reinforcement Learning on Multimodal Tool Use","authors":["Mingyuan Wu","Jingcheng Yang","Jize Jiang","Meitang Li","Kaizhuo Yan","Hanchao Yu","Minjia Zhang","Chengxiang Zhai","Klara Nahrstedt"],"abstract":"Reinforcement Learning Finetuning (RFT) has significantly advanced the reasoning capabilities of large language models (LLMs) by enabling long chains of thought, self-correction, and effective tool use. While recent works attempt to extend RFT to vision-language models (VLMs), these efforts largely produce text-only reasoning conditioned on static image inputs, falling short of true multimodal reasoning in the response. In contrast, test-time methods like Visual Sketchpad incorporate visual steps but lack training mechanisms. We introduce VTool-R1, the first framework that trains VLMs to generate multimodal chains of thought by interleaving text and intermediate visual reasoning steps. VTool-R1 integrates Python-based visual editing tools into the RFT process, enabling VLMs to learn when and how to generate visual reasoning steps that benefit final reasoning. Trained with outcome-based rewards tied to task accuracy, our approach elicits strategic visual tool use for reasoning without relying on process-based supervision. Experiments on structured visual question answering over charts and tables show that VTool-R1 enhances reasoning performance by teaching VLMs to \"think with images\" and generate multimodal chain of thoughts with tools. To support future research in multi-turn multi-modal reasoning, we open-source our code at https://github.com/VTOOL-R1/vtool-r1","published":"2025-05-25T18:23:39Z","updated":"2026-03-04T22:28:47Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.19255v4","pdf_url":"https://arxiv.org/pdf/2505.19255v4","comment":"ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19195","versioned_id":"2505.19195v1","title":"CardioCoT: Hierarchical Reasoning for Multimodal Survival Analysis","authors":["Shaohao Rui","Haoyang Su","Jinyi Xiang","Lian-Ming Wu","Xiaosong Wang"],"abstract":"Accurate prediction of major adverse cardiovascular events recurrence risk in acute myocardial infarction patients based on postoperative cardiac MRI and associated clinical notes is crucial for precision treatment and personalized intervention. Existing methods primarily focus on risk stratification capability while overlooking the need for intermediate robust reasoning and model interpretability in clinical practice. Moreover, end-to-end risk prediction using LLM/VLM faces significant challenges due to data limitations and modeling complexity. To bridge this gap, we propose CardioCoT, a novel two-stage hierarchical reasoning-enhanced survival analysis framework designed to enhance both model interpretability and predictive performance. In the first stage, we employ an evidence-augmented self-refinement mechanism to guide LLM/VLMs in generating robust hierarchical reasoning trajectories based on associated radiological findings. In the second stage, we integrate the reasoning trajectories with imaging data for risk model training and prediction. CardioCoT demonstrates superior performance in MACE recurrence risk prediction while providing interpretable reasoning processes, offering valuable insights for clinical decision-making.","published":"2025-05-25T15:41:18Z","updated":"2025-05-25T15:41:18Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.19195v1","pdf_url":"https://arxiv.org/pdf/2505.19195v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.19095","versioned_id":"2505.19095v1","title":"ScreenExplorer: Training a Vision-Language Model for Diverse Exploration in Open GUI World","authors":["Runliang Niu","Jinglong Ji","Yi Chang","Qi Wang"],"abstract":"The rapid progress of large language models (LLMs) has sparked growing interest in building Artificial General Intelligence (AGI) within Graphical User Interface (GUI) environments. However, existing GUI agents based on LLMs or vision-language models (VLMs) often fail to generalize to novel environments and rely heavily on manually curated, diverse datasets. To overcome these limitations, we introduce ScreenExplorer, a VLM trained via Group Relative Policy Optimization(GRPO) in real, dynamic, and open-ended GUI environments. Innovatively, we introduced a world-model-based curiosity reward function to help the agent overcome the cold-start phase of exploration. Additionally, distilling experience streams further enhances the model's exploration capabilities. Our training framework enhances model exploration in open GUI environments, with trained models showing better environmental adaptation and sustained exploration compared to static deployment models. Our findings offer a scalable pathway toward AGI systems with self-improving capabilities in complex interactive settings.","published":"2025-05-25T11:13:03Z","updated":"2025-05-25T11:13:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.19095v1","pdf_url":"https://arxiv.org/pdf/2505.19095v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.14782","versioned_id":"2506.14782v2","title":"Integrating Dynamical Systems Learning with Foundational Models: A Meta-Evolutionary AI Framework for Clinical Trials","authors":["Joseph Geraci","Bessi Qorri","Christian Cumbaa","Mike Tsay","Paul Leonczyk","Luca Pani"],"abstract":"Artificial intelligence (AI) has evolved into an ecosystem of specialized \"species,\" each with unique strengths. We analyze two: DeepSeek-V3, a 671-billion-parameter Mixture of Experts large language model (LLM) exemplifying scale-driven generality, and NetraAI, a dynamical system-based framework engineered for stability and interpretability on small clinical trial datasets. We formalize NetraAI's foundations, combining contraction mappings, information geometry, and evolutionary algorithms to identify predictive patient cohorts. Features are embedded in a metric space and iteratively contracted toward stable attractors that define latent subgroups. A pseudo-temporal embedding and long-range memory enable exploration of higher-order feature interactions, while an internal evolutionary loop selects compact, explainable 2-4-variable bundles (\"Personas\"). To guide discovery, we introduce an LLM Strategist as a meta-evolutionary layer that observes Persona outputs, prioritizes promising variables, injects domain knowledge, and assesses robustness. This two-tier architecture mirrors the human scientific process: NetraAI as experimentalist, the LLM as theorist, forming a self-improving loop. In case studies (schizophrenia, depression, pancreatic cancer), NetraAI uncovered small, high-effect-size subpopulations that transformed weak baseline models (AUC ~0.50-0.68) into near-perfect classifiers using only a few features. We position NetraAI at the intersection of dynamical systems, information geometry, and evolutionary learning, aligned with emerging concept-level reasoning paradigms such as LeCun's Joint Embedding Predictive Architecture (JEPA). By prioritizing reliable, explainable knowledge, NetraAI offers a new generation of adaptive, self-reflective AI to accelerate clinical discovery.","published":"2025-05-25T03:34:33Z","updated":"2025-06-19T23:50:01Z","categories":["cs.LG","q-bio.QM"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.14782v2","pdf_url":"https://arxiv.org/pdf/2506.14782v2","comment":"27 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.18405","versioned_id":"2505.18405v2","title":"RaDeR: Reasoning-aware Dense Retrieval Models","authors":["Debrup Das","Sam O' Nuallain","Razieh Rahimi"],"abstract":"We propose RaDeR, a set of reasoning-based dense retrieval models trained with data derived from mathematical problem solving using large language models (LLMs). Our method leverages retrieval-augmented reasoning trajectories of an LLM and self-reflective relevance evaluation, enabling the creation of both diverse and hard-negative samples for reasoning-intensive relevance. RaDeR retrievers, trained for mathematical reasoning, effectively generalize to diverse reasoning tasks in the BRIGHT and RAR-b benchmarks, consistently outperforming strong baselines in overall performance. Notably, RaDeR achieves significantly higher performance than baselines on the Math and Coding splits. In addition, RaDeR presents the first dense retriever that outperforms BM25 when queries are Chain-of-Thought reasoning steps, underscoring the critical role of reasoning-based retrieval to augment reasoning language models. Furthermore, RaDeR achieves comparable or superior performance while using only 2.5% of the training data used by the concurrent work REASONIR, highlighting the quality of our synthesized training data.","published":"2025-05-23T22:18:32Z","updated":"2025-05-27T04:20:31Z","categories":["cs.CL","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.18405v2","pdf_url":"https://arxiv.org/pdf/2505.18405v2","comment":"26 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.18116","versioned_id":"2505.18116v3","title":"NFT: Bridging Supervised Learning and Reinforcement Learning in Math Reasoning","authors":["Huayu Chen","Kaiwen Zheng","Qinsheng Zhang","Ganqu Cui","Lifan Yuan","Yin Cui","Haotian Ye","Tsung-Yi Lin","Ming-Yu Liu","Jun Zhu","Haoxiang Wang"],"abstract":"Reinforcement Learning (RL) has played a central role in the recent surge of LLMs' math abilities by enabling self-improvement through binary verifier signals. In contrast, Supervised Learning (SL) is rarely considered for such verification-driven training, largely due to its heavy reliance on reference answers and inability to reflect on mistakes. In this work, we challenge the prevailing notion that self-improvement is exclusive to RL and propose Negative-aware Fine-Tuning (NFT) -- a supervised approach that enables LLMs to reflect on their failures and improve autonomously with no external teachers. In online training, instead of throwing away self-generated negative answers, NFT constructs an implicit negative policy to model them. This implicit policy is parameterized with the same positive LLM we target to optimize on positive data, enabling direct policy optimization on all LLMs' generations. We conduct experiments on 7B and 32B models in math reasoning tasks. Results consistently show that through the additional leverage of negative feedback, NFT significantly improves over SL baselines like Rejection sampling Fine-Tuning, matching or even surpassing leading RL algorithms like GRPO and DAPO. Furthermore, we demonstrate that NFT and GRPO are actually equivalent in strict-on-policy training, even though they originate from entirely different theoretical foundations. Our experiments and theoretical findings bridge the gap between SL and RL methods in binary-feedback learning systems.","published":"2025-05-23T17:17:40Z","updated":"2026-03-01T10:54:34Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.18116v3","pdf_url":"https://arxiv.org/pdf/2505.18116v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17941","versioned_id":"2505.17941v1","title":"VeriThinker: Learning to Verify Makes Reasoning Model Efficient","authors":["Zigeng Chen","Xinyin Ma","Gongfan Fang","Ruonan Yu","Xinchao Wang"],"abstract":"Large Reasoning Models (LRMs) excel at complex tasks using Chain-of-Thought (CoT) reasoning. However, their tendency to overthinking leads to unnecessarily lengthy reasoning chains, dramatically increasing inference costs. To mitigate this issue, we introduce VeriThinker, a novel approach for CoT compression. Unlike conventional methods that fine-tune LRMs directly on the original reasoning task using synthetic concise CoT data, we innovatively fine-tune the model solely through an auxiliary verification task. By training LRMs to accurately verify the correctness of CoT solutions, the LRMs inherently become more discerning about the necessity of subsequent self-reflection steps, thereby effectively suppressing overthinking. Extensive experiments validate that VeriThinker substantially reduces reasoning chain lengths while maintaining or even slightly improving accuracy. When applied to DeepSeek-R1-Distill-Qwen-7B, our approach reduces reasoning tokens on MATH500 from 3790 to 2125 while improving accuracy by 0.8% (94.0% to 94.8%), and on AIME25, tokens decrease from 14321 to 10287 with a 2.1% accuracy gain (38.7% to 40.8%). Additionally, our experiments demonstrate that VeriThinker can also be zero-shot generalized to speculative reasoning. Code is available at https://github.com/czg1225/VeriThinker","published":"2025-05-23T14:17:56Z","updated":"2025-05-23T14:17:56Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.17941v1","pdf_url":"https://arxiv.org/pdf/2505.17941v1","comment":"Working in progress. Code Repo: https://github.com/czg1225/VeriThinker","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17735","versioned_id":"2505.17735v2","title":"SafeAgent: Safeguarding LLM Agents via an Automated Risk Simulator","authors":["Xueyang Zhou","Weidong Wang","Lin Lu","Jiawen Shi","Guiyao Tie","Yongtian Xu","Lixing Chen","Pan Zhou","Neil Zhenqiang Gong","Lichao Sun"],"abstract":"Large Language Model (LLM)-based agents are increasingly deployed in real-world applications such as \"digital assistants, autonomous customer service, and decision-support systems\", where their ability to \"interact in multi-turn, tool-augmented environments\" makes them indispensable. However, ensuring the safety of these agents remains a significant challenge due to the diverse and complex risks arising from dynamic user interactions, external tool usage, and the potential for unintended harmful behaviors. To address this critical issue, we propose AutoSafe, the first framework that systematically enhances agent safety through fully automated synthetic data generation. Concretely, 1) we introduce an open and extensible threat model, OTS, which formalizes how unsafe behaviors emerge from the interplay of user instructions, interaction contexts, and agent actions. This enables precise modeling of safety risks across diverse scenarios. 2) we develop a fully automated data generation pipeline that simulates unsafe user behaviors, applies self-reflective reasoning to generate safe responses, and constructs a large-scale, diverse, and high-quality safety training dataset-eliminating the need for hazardous real-world data collection. To evaluate the effectiveness of our framework, we design comprehensive experiments on both synthetic and real-world safety benchmarks. Results demonstrate that AutoSafe boosts safety scores by 45% on average and achieves a 28.91% improvement on real-world tasks, validating the generalization ability of our learned safety strategies. These results highlight the practical advancement and scalability of AutoSafe in building safer LLM-based agents for real-world deployment. We have released the project page at https://auto-safe.github.io/.","published":"2025-05-23T10:56:06Z","updated":"2025-07-18T07:34:40Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.17735v2","pdf_url":"https://arxiv.org/pdf/2505.17735v2","comment":"38 pages;12 figures;12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17702","versioned_id":"2505.17702v3","title":"Seek-CAD: A Self-refined Generative Modeling for 3D Parametric CAD Using Local Inference via DeepSeek","authors":["Xueyang Li","Jiahao Li","Yu Song","Yunzhong Lou","Xiangdong Zhou"],"abstract":"The advent of Computer-Aided Design (CAD) generative modeling will significantly transform the design of industrial products. The recent research endeavor has extended into the realm of Large Language Models (LLMs). In contrast to fine-tuning methods, training-free approaches typically utilize the advanced closed-source LLMs, thereby offering enhanced flexibility and efficiency in the development of AI agents for generating CAD parametric models. However, the substantial cost and limitations of local deployment of the top-tier closed-source LLMs pose challenges in practical applications. The Seek-CAD is the pioneer exploration of locally deployed open-source inference LLM DeepSeek-R1 for CAD parametric model generation with a training-free methodology. This study is the first investigation to incorporate both visual and Chain-of-Thought (CoT) feedback within the self-refinement mechanism for generating CAD models. Specifically, the initial generated parametric CAD model is rendered into a sequence of step-wise perspective images, which are subsequently processed by a Vision Language Model (VLM) alongside the corresponding CoTs derived from DeepSeek-R1 to assess the CAD model generation. Then, the feedback is utilized by DeepSeek-R1 to refine the initial generated model for the next round of generation. Moreover, we present an innovative 3D CAD model dataset structured around the SSR (Sketch, Sketch-based feature, and Refinements) triple design paradigm. This dataset encompasses a wide range of CAD commands, thereby aligning effectively with industrial application requirements and proving suitable for the generation of LLMs. Extensive experiments validate the effectiveness of Seek-CAD under various metrics.","published":"2025-05-23T10:11:19Z","updated":"2026-02-28T15:25:47Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.17702v3","pdf_url":"https://arxiv.org/pdf/2505.17702v3","comment":"Accepted to ICLR 2026. The datatset has been released publicly and can be acessed in https://github.com/Sunny-Hack/Seek-CAD","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17697","versioned_id":"2505.17697v1","title":"Activation Control for Efficiently Eliciting Long Chain-of-thought Ability of Language Models","authors":["Zekai Zhao","Qi Liu","Kun Zhou","Zihan Liu","Yifei Shao","Zhiting Hu","Biwei Huang"],"abstract":"Despite the remarkable reasoning performance, eliciting the long chain-of-thought (CoT) ability in large language models (LLMs) typically requires costly reinforcement learning or supervised fine-tuning on high-quality distilled data. We investigate the internal mechanisms behind this capability and show that a small set of high-impact activations in the last few layers largely governs long-form reasoning attributes, such as output length and self-reflection. By simply amplifying these activations and inserting \"wait\" tokens, we can invoke the long CoT ability without any training, resulting in significantly increased self-reflection rates and accuracy. Moreover, we find that the activation dynamics follow predictable trajectories, with a sharp rise after special tokens and a subsequent exponential decay. Building on these insights, we introduce a general training-free activation control technique. It leverages a few contrastive examples to identify key activations, and employs simple analytic functions to modulate their values at inference time to elicit long CoTs. Extensive experiments confirm the effectiveness of our method in efficiently eliciting long CoT reasoning in LLMs and improving their performance. Additionally, we propose a parameter-efficient fine-tuning method that trains only a last-layer activation amplification module and a few LoRA layers, outperforming full LoRA fine-tuning on reasoning benchmarks with significantly fewer parameters. Our code and data are publicly released.","published":"2025-05-23T10:07:18Z","updated":"2025-05-23T10:07:18Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17697v1","pdf_url":"https://arxiv.org/pdf/2505.17697v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.18218","versioned_id":"2505.18218v1","title":"CoMet: Metaphor-Driven Covert Communication for Multi-Agent Language Games","authors":["Shuhang Xu","Fangwei Zhong"],"abstract":"Metaphors are a crucial way for humans to express complex or subtle ideas by comparing one concept to another, often from a different domain. However, many large language models (LLMs) struggle to interpret and apply metaphors in multi-agent language games, hindering their ability to engage in covert communication and semantic evasion, which are crucial for strategic communication. To address this challenge, we introduce CoMet, a framework that enables LLM-based agents to engage in metaphor processing. CoMet combines a hypothesis-based metaphor reasoner with a metaphor generator that improves through self-reflection and knowledge integration. This enhances the agents' ability to interpret and apply metaphors, improving the strategic and nuanced quality of their interactions. We evaluate CoMet on two multi-agent language games - Undercover and Adversarial Taboo - which emphasize Covert Communication and Semantic Evasion. Experimental results demonstrate that CoMet significantly enhances the agents' ability to communicate strategically using metaphors.","published":"2025-05-23T08:23:54Z","updated":"2025-05-23T08:23:54Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.18218v1","pdf_url":"https://arxiv.org/pdf/2505.18218v1","comment":"To Appear at ACL 2025 (Main)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17565","versioned_id":"2505.17565v2","title":"p2-TQA: A Process-based Preference Learning Framework for Self-Improving Table Question Answering Models","authors":["Wei Zhou","Mohsen Mesgar","Heike Adel","Annemarie Friedrich"],"abstract":"Table question answering (TQA) focuses on answering questions based on tabular data. Developing TQA systems targets effective interaction with tabular data for tasks such as cell retrieval and data analysis. While recent work has leveraged fine-tuning to improve TQA systems, existing approaches often under-utilize available data and neglect the potential of post-training for further gains. In this work, we introduce p2-TQA, a process-based preference learning framework for TQA post-training. p2-TQA automatically constructs process-based preference data via a table-specific pipeline, eliminating the need for manual or costly data collection. It then optimizes models through contrastive learning on the collected data. Experiments show that p2-TQA effectively improves TQA models by up to 5% on in-domain datasets and 2.4% on out-of-domain datasets with only 8,000 training instances. Furthermore, models enhanced with p2-TQA achieve competitive results against larger, more complex state-of-the-art TQA systems, while maintaining up to five times higher efficiency.","published":"2025-05-23T07:24:53Z","updated":"2025-11-10T20:50:28Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17565v2","pdf_url":"https://arxiv.org/pdf/2505.17565v2","comment":"Accepted at AACL-IJCNLP","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17540","versioned_id":"2505.17540v1","title":"RePrompt: Reasoning-Augmented Reprompting for Text-to-Image Generation via Reinforcement Learning","authors":["Mingrui Wu","Lu Wang","Pu Zhao","Fangkai Yang","Jianjin Zhang","Jianfeng Liu","Yuefeng Zhan","Weihao Han","Hao Sun","Jiayi Ji","Xiaoshuai Sun","Qingwei Lin","Weiwei Deng","Dongmei Zhang","Feng Sun","Qi Zhang","Rongrong Ji"],"abstract":"Despite recent progress in text-to-image (T2I) generation, existing models often struggle to faithfully capture user intentions from short and under-specified prompts. While prior work has attempted to enhance prompts using large language models (LLMs), these methods frequently generate stylistic or unrealistic content due to insufficient grounding in visual semantics and real-world composition. Inspired by recent advances in reasoning for language model, we propose RePrompt, a novel reprompting framework that introduces explicit reasoning into the prompt enhancement process via reinforcement learning. Instead of relying on handcrafted rules or stylistic rewrites, our method trains a language model to generate structured, self-reflective prompts by optimizing for image-level outcomes. The tailored reward models assesse the generated images in terms of human preference, semantic alignment, and visual composition, providing indirect supervision to refine prompt generation. Our approach enables end-to-end training without human-annotated data. Experiments on GenEval and T2I-Compbench show that RePrompt significantly boosts spatial layout fidelity and compositional generalization across diverse T2I backbones, establishing new state-of-the-art results.","published":"2025-05-23T06:44:26Z","updated":"2025-05-23T06:44:26Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.17540v1","pdf_url":"https://arxiv.org/pdf/2505.17540v1","comment":"Code is available at: https://github.com/microsoft/DKI_LLM/tree/main/RePrompt","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17481","versioned_id":"2505.17481v1","title":"MARCO: Meta-Reflection with Cross-Referencing for Code Reasoning","authors":["Yusheng Zhao","Xiao Luo","Weizhi Zhang","Wei Ju","Zhiping Xiao","Philip S. Yu","Ming Zhang"],"abstract":"The ability to reason is one of the most fundamental capabilities of large language models (LLMs), enabling a wide range of downstream tasks through sophisticated problem-solving. A critical aspect of this is code reasoning, which involves logical reasoning with formal languages (i.e., programming code). In this paper, we enhance this capability of LLMs by exploring the following question: how can an LLM agent become progressively smarter in code reasoning with each solution it proposes, thereby achieving substantial cumulative improvement? Most existing research takes a static perspective, focusing on isolated problem-solving using frozen LLMs. In contrast, we adopt a cognitive-evolving perspective and propose a novel framework named Meta-Reflection with Cross-Referencing (MARCO) that enables the LLM to evolve dynamically during inference through self-improvement. From the perspective of human cognitive development, we leverage both knowledge accumulation and lesson sharing. In particular, to accumulate knowledge during problem-solving, we propose meta-reflection that reflects on the reasoning paths of the current problem to obtain knowledge and experience for future consideration. Moreover, to effectively utilize the lessons from other agents, we propose cross-referencing that incorporates the solution and feedback from other agents into the current problem-solving process. We conduct experiments across various datasets in code reasoning, and the results demonstrate the effectiveness of MARCO.","published":"2025-05-23T05:21:11Z","updated":"2025-05-23T05:21:11Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17481v1","pdf_url":"https://arxiv.org/pdf/2505.17481v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17266","versioned_id":"2505.17266v3","title":"Select2Reason: Efficient Instruction-Tuning Data Selection for Long-CoT Reasoning","authors":["Cehao Yang","Xueyuan Lin","Xiaojun Wu","Chengjin Xu","Xuhui Jiang","Honghao Liu","Hui Xiong","Jian Guo"],"abstract":"A practical approach to activate long chain-of-thoughts reasoning ability in pre-trained large language models is to perform supervised fine-tuning on instruction datasets synthesized by strong Large Reasoning Models such as DeepSeek-R1, offering a cost-effective alternative to reinforcement learning. However, large-scale instruction sets with more than 100k samples incur significant training overhead, while effective strategies for automatic long-CoT instruction selection still remain unexplored. In this work, we propose Select2Reason, a novel and efficient instruction-tuning data selection framework for long-CoT reasoning. From the perspective of emergence of rethinking behaviors like self-correction and backtracking, we investigate common metrics that may determine the quality of long-CoT reasoning instructions. Select2Reason leverages a quantifier to estimate difficulty of question and jointly incorporates a reasoning trace length-based heuristic through a weighted scheme for ranking to prioritize high-utility examples. Empirical results on OpenR1-Math-220k demonstrate that fine-tuning LLM on only 10% of the data selected by Select2Reason achieves performance competitive with or superior to full-data tuning and open-source baseline OpenR1-Qwen-7B across three competition-level and six comprehensive mathematical benchmarks. Further experiments highlight the scalability in varying data size, efficiency during inference, and its adaptability to other instruction pools with minimal cost.","published":"2025-05-22T20:24:08Z","updated":"2025-12-23T07:05:40Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17266v3","pdf_url":"https://arxiv.org/pdf/2505.17266v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16927","versioned_id":"2505.16927v2","title":"Latent Principle Discovery for Language Model Self-Improvement","authors":["Keshav Ramji","Tahira Naseem","Ramón Fernandez Astudillo"],"abstract":"When language model (LM) users aim to improve the quality of its generations, it is crucial to specify concrete behavioral attributes that the model should strive to reflect. However, curating such principles across many domains, even non-exhaustively, requires a labor-intensive annotation process. To automate this process, we propose eliciting these latent attributes that guide model reasoning toward human-preferred responses by explicitly modeling them in a self-correction setting. Our approach mines new principles from the LM itself and compresses the discovered elements to an interpretable set via clustering. Specifically, we employ a form of posterior-regularized Monte Carlo Expectation-Maximization to both identify a condensed set of the most effective latent principles and teach the LM to strategically invoke them in order to intrinsically refine its responses. We demonstrate that bootstrapping our algorithm over multiple iterations enables smaller language models (7-8B parameters) to self-improve, achieving +8-10% in AlpacaEval win-rate, an average of +0.3 on MT-Bench, and +19-23% in principle-following win-rate on IFEval. We also show that clustering the principles yields interpretable and diverse model-generated constitutions while retaining model performance. The gains that our method achieves highlight the potential of automated, principle-driven post-training recipes toward continual self-improvement.","published":"2025-05-22T17:20:18Z","updated":"2025-11-14T15:40:16Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.16927v2","pdf_url":"https://arxiv.org/pdf/2505.16927v2","comment":"Accepted at NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16637","versioned_id":"2505.16637v4","title":"SSR-Zero: Simple Self-Rewarding Reinforcement Learning for Machine Translation","authors":["Wenjie Yang","Mao Zheng","Mingyang Song","Zheng Li","Sitong Wang"],"abstract":"Large language models (LLMs) have recently demonstrated remarkable capabilities in machine translation (MT). However, most advanced MT-specific LLMs heavily rely on external supervision signals during training, such as human-annotated reference data or trained reward models (RMs), which are often expensive to obtain and challenging to scale. To overcome this limitation, we propose a Simple Self-Rewarding (SSR) Reinforcement Learning (RL) framework for MT that is reference-free, fully online, and relies solely on self-judging rewards. Training with SSR using 13K monolingual examples and Qwen-2.5-7B as the backbone, our model SSR-Zero-7B outperforms existing MT-specific LLMs, e.g., TowerInstruct-13B and GemmaX-28-9B, as well as larger general LLMs like Qwen2.5-32B-Instruct in English $\\leftrightarrow$ Chinese translation tasks from WMT23, WMT24, and Flores200 benchmarks. Furthermore, by augmenting SSR with external supervision from COMET, our strongest model, SSR-X-Zero-7B, achieves state-of-the-art performance in English $\\leftrightarrow$ Chinese translation, surpassing all existing open-source models under 72B parameters and even outperforming closed-source models. Our analysis highlights the effectiveness of the self-rewarding mechanism compared to the external LLM-as-a-judge approach in MT and demonstrates its complementary benefits when combined with trained RMs. Our findings provide valuable insight into the potential of self-improving RL methods. We have publicly released our code, data and models.","published":"2025-05-22T13:08:25Z","updated":"2026-04-26T05:27:36Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.16637v4","pdf_url":"https://arxiv.org/pdf/2505.16637v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16610","versioned_id":"2505.16610v1","title":"From Generic Empathy to Personalized Emotional Support: A Self-Evolution Framework for User Preference Alignment","authors":["Jing Ye","Lu Xiang","Yaping Zhang","Chengqing Zong"],"abstract":"Effective emotional support hinges on understanding users' emotions and needs to provide meaningful comfort during multi-turn interactions. Large Language Models (LLMs) show great potential for expressing empathy; however, they often deliver generic and one-size-fits-all responses that fail to address users' specific needs. To tackle this issue, we propose a self-evolution framework designed to help LLMs improve their responses to better align with users' implicit preferences concerning user profiles (personalities), emotional states, and specific situations. Our framework consists of two distinct phases: \\textit{(1)} \\textit{Emotional Support Experience Acquisition}, where LLMs are fine-tuned on limited emotional support conversation data to provide basic support, and \\textit{(2)} \\textit{Self-Improvement for Personalized Emotional Support}, where LLMs leverage self-reflection and self-refinement to generate personalized responses. Through iterative direct preference optimization between the pre- and post-refined responses, our model generates responses that reflect a better understanding of the user's implicit preferences. Extensive experiments and evaluations demonstrate that our method significantly enhances the model's performance in emotional support, reducing unhelpful responses and minimizing discrepancies between user preferences and model outputs.","published":"2025-05-22T12:45:12Z","updated":"2025-05-22T12:45:12Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.16610v1","pdf_url":"https://arxiv.org/pdf/2505.16610v1","comment":"27 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16475","versioned_id":"2505.16475v1","title":"ReflectEvo: Improving Meta Introspection of Small LLMs by Learning Self-Reflection","authors":["Jiaqi Li","Xinyi Dong","Yang Liu","Zhizhuo Yang","Quansen Wang","Xiaobo Wang","SongChun Zhu","Zixia Jia","Zilong Zheng"],"abstract":"We present a novel pipeline, ReflectEvo, to demonstrate that small language models (SLMs) can enhance meta introspection through reflection learning. This process iteratively generates self-reflection for self-training, fostering a continuous and self-evolving process. Leveraging this pipeline, we construct ReflectEvo-460k, a large-scale, comprehensive, self-generated reflection dataset with broadened instructions and diverse multi-domain tasks. Building upon this dataset, we demonstrate the effectiveness of reflection learning to improve SLMs' reasoning abilities using SFT and DPO with remarkable performance, substantially boosting Llama-3 from 52.4% to 71.2% and Mistral from 44.4% to 71.1%. It validates that ReflectEvo can rival or even surpass the reasoning capability of the three prominent open-sourced models on BIG-bench without distillation from superior models or fine-grained human annotation. We further conduct a deeper analysis of the high quality of self-generated reflections and their impact on error localization and correction. Our work highlights the potential of continuously enhancing the reasoning performance of SLMs through iterative reflection learning in the long run.","published":"2025-05-22T10:03:05Z","updated":"2025-05-22T10:03:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.16475v1","pdf_url":"https://arxiv.org/pdf/2505.16475v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16322","versioned_id":"2505.16322v3","title":"AdaSTaR: Adaptive Data Sampling for Training Self-Taught Reasoners","authors":["Woosung Koh","Wonbeen Oh","Jaein Jang","MinHyung Lee","Hyeongjin Kim","Ah Yeon Kim","Joonkee Kim","Junghyun Lee","Taehyeon Kim","Se-Young Yun"],"abstract":"Self-Taught Reasoners (STaR), synonymously known as Rejection sampling Fine-Tuning (RFT), is an integral part of the training pipeline of self-improving reasoning Language Models (LMs). The self-improving mechanism often employs random observation (data) sampling. However, this results in trained observation imbalance; inefficiently over-training on solved examples while under-training on challenging ones. In response, we introduce Adaptive STaR (AdaSTaR), a novel algorithm that rectifies this by integrating two adaptive sampling principles: (1) Adaptive Sampling for Diversity: promoting balanced training across observations, and (2) Adaptive Sampling for Curriculum: dynamically adjusting data difficulty to match the model's evolving strength. Across six benchmarks, AdaSTaR achieves best test accuracy in all instances (6/6) and reduces training FLOPs by an average of 58.6% against an extensive list of baselines. These improvements in performance and efficiency generalize to different pre-trained LMs and larger models, paving the way for more efficient and effective self-improving LMs.","published":"2025-05-22T07:24:11Z","updated":"2025-10-06T08:23:36Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.16322v3","pdf_url":"https://arxiv.org/pdf/2505.16322v3","comment":"NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16281","versioned_id":"2505.16281v3","title":"HiMATE: A Hierarchical Multi-Agent Framework for Machine Translation Evaluation","authors":["Shijie Zhang","Renhao Li","Songsheng Wang","Philipp Koehn","Min Yang","Derek F. Wong"],"abstract":"The advancement of Large Language Models (LLMs) enables flexible and interpretable automatic evaluations. In the field of machine translation evaluation, utilizing LLMs with translation error annotations based on Multidimensional Quality Metrics (MQM) yields more human-aligned judgments. However, current LLM-based evaluation methods still face challenges in accurately identifying error spans and assessing their severity. In this paper, we propose HiMATE, a Hierarchical Multi-Agent Framework for Machine Translation Evaluation. We argue that existing approaches inadequately exploit the fine-grained structural and semantic information within the MQM hierarchy. To address this, we develop a hierarchical multi-agent system grounded in the MQM error typology, enabling granular evaluation of subtype errors. Two key strategies are incorporated to further mitigate systemic hallucinations within the framework: the utilization of the model's self-reflection capability and the facilitation of agent discussion involving asymmetric information. Empirically, HiMATE outperforms competitive baselines across different datasets in conducting human-aligned evaluations. Further analyses underscore its significant advantage in error span detection and severity assessment, achieving an average F1-score improvement of 89% over the best-performing baseline. We make our code and data publicly available at https://github.com/nlp2ct-shijie/HiMATE.","published":"2025-05-22T06:24:08Z","updated":"2025-09-16T01:45:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.16281v3","pdf_url":"https://arxiv.org/pdf/2505.16281v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16265","versioned_id":"2505.16265v1","title":"Think-RM: Enabling Long-Horizon Reasoning in Generative Reward Models","authors":["Ilgee Hong","Changlong Yu","Liang Qiu","Weixiang Yan","Zhenghao Xu","Haoming Jiang","Qingru Zhang","Qin Lu","Xin Liu","Chao Zhang","Tuo Zhao"],"abstract":"Reinforcement learning from human feedback (RLHF) has become a powerful post-training paradigm for aligning large language models with human preferences. A core challenge in RLHF is constructing accurate reward signals, where the conventional Bradley-Terry reward models (BT RMs) often suffer from sensitivity to data size and coverage, as well as vulnerability to reward hacking. Generative reward models (GenRMs) offer a more robust alternative by generating chain-of-thought (CoT) rationales followed by a final reward. However, existing GenRMs rely on shallow, vertically scaled reasoning, limiting their capacity to handle nuanced or complex (e.g., reasoning-intensive) tasks. Moreover, their pairwise preference outputs are incompatible with standard RLHF algorithms that require pointwise reward signals. In this work, we introduce Think-RM, a training framework that enables long-horizon reasoning in GenRMs by modeling an internal thinking process. Rather than producing structured, externally provided rationales, Think-RM generates flexible, self-guided reasoning traces that support advanced capabilities such as self-reflection, hypothetical reasoning, and divergent reasoning. To elicit these reasoning abilities, we first warm-up the models by supervised fine-tuning (SFT) over long CoT data. We then further improve the model's long-horizon abilities by rule-based reinforcement learning (RL). In addition, we propose a novel pairwise RLHF pipeline that directly optimizes policies using pairwise preference rewards, eliminating the need for pointwise reward conversion and enabling more effective use of Think-RM outputs. Experiments show that Think-RM achieves state-of-the-art results on RM-Bench, outperforming both BT RM and vertically scaled GenRM by 8%. When combined with our pairwise RLHF pipeline, it demonstrates superior end-policy performance compared to traditional approaches.","published":"2025-05-22T05:56:11Z","updated":"2025-05-22T05:56:11Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.16265v1","pdf_url":"https://arxiv.org/pdf/2505.16265v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.16245","versioned_id":"2505.16245v4","title":"Diverse, not Short: A Length-Controlled Data Selection Strategy for Improving Response Diversity of Language Models","authors":["Vijeta Deshpande","Debasmita Ghose","John D. Patterson","Roger Beaty","Anna Rumshisky"],"abstract":"Diverse language model responses are crucial for creative generation, open-ended tasks, and self-improvement training. We show that common diversity metrics, and even reward models used for preference optimization, systematically bias models toward shorter outputs, limiting expressiveness. To address this, we introduce Diverse, not Short (Diverse-NS), a length-controlled data selection strategy that improves response diversity while maintaining length parity. By generating and filtering preference data that balances diversity, quality, and length, Diverse-NS enables effective training using only 3,000 preference pairs. Applied to LLaMA-3.1-8B and the Olmo-2 family, Diverse-NS substantially enhances lexical and semantic diversity. We show consistent improvement in diversity with minor reduction or gains in response quality on four creative generation tasks: Divergent Associations, Persona Generation, Alternate Uses, and Creative Writing. Surprisingly, experiments with the Olmo-2 model family (7B, and 13B) show that smaller models like Olmo-2-7B can serve as effective \"diversity teachers\" for larger models. By explicitly addressing length bias, our method efficiently pushes models toward more diverse and expressive outputs.","published":"2025-05-22T05:29:47Z","updated":"2026-01-30T14:26:38Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.16245v4","pdf_url":"https://arxiv.org/pdf/2505.16245v4","comment":"Accepted to EMNLP 2025 Main","journal_ref":"","doi":"10.18653/v1/2025.emnlp-main.1721","discovered_on":"2026-07-17"},{"id":"2505.16102","versioned_id":"2505.16102v2","title":"Continually Self-Improving Language Models for Bariatric Surgery Question--Answering","authors":["Yash Kumar Atri","Thomas H Shin","Thomas Hartvigsen"],"abstract":"While bariatric and metabolic surgery (MBS) is considered the gold standard treatment for severe and morbid obesity, its therapeutic efficacy hinges upon active and longitudinal engagement with multidisciplinary providers, including surgeons, dietitians/nutritionists, psychologists, and endocrinologists. This engagement spans the entire patient journey, from preoperative preparation to long-term postoperative management. However, this process is often hindered by numerous healthcare disparities, such as logistical and access barriers, which impair easy patient access to timely, evidence-based, clinician-endorsed information. To address these gaps, we introduce bRAGgen, a novel adaptive retrieval-augmented generation (RAG)-based model that autonomously integrates real-time medical evidence when response confidence dips below dynamic thresholds. This self-updating architecture ensures that responses remain current and accurate, reducing the risk of misinformation. Additionally, we present bRAGq, a curated dataset of 1,302 bariatric surgery--related questions, validated by an expert bariatric surgeon. bRAGq constitutes the first large-scale, domain-specific benchmark for comprehensive MBS care. In a two-phase evaluation, bRAGgen is benchmarked against state-of-the-art models using both large language model (LLM)--based metrics and expert surgeon review. Across all evaluation dimensions, bRAGgen demonstrates substantially superior performance in generating clinically accurate and relevant responses.","published":"2025-05-22T01:02:51Z","updated":"2025-05-23T19:47:03Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.16102v2","pdf_url":"https://arxiv.org/pdf/2505.16102v2","comment":"Data and Code available at https://github.com/yashkumaratri/bRAGgen","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.15779","versioned_id":"2505.15779v1","title":"IA-T2I: Internet-Augmented Text-to-Image Generation","authors":["Chuanhao Li","Jianwen Sun","Yukang Feng","Mingliang Zhai","Yifan Chang","Kaipeng Zhang"],"abstract":"Current text-to-image (T2I) generation models achieve promising results, but they fail on the scenarios where the knowledge implied in the text prompt is uncertain. For example, a T2I model released in February would struggle to generate a suitable poster for a movie premiering in April, because the character designs and styles are uncertain to the model. To solve this problem, we propose an Internet-Augmented text-to-image generation (IA-T2I) framework to compel T2I models clear about such uncertain knowledge by providing them with reference images. Specifically, an active retrieval module is designed to determine whether a reference image is needed based on the given text prompt; a hierarchical image selection module is introduced to find the most suitable image returned by an image search engine to enhance the T2I model; a self-reflection mechanism is presented to continuously evaluate and refine the generated image to ensure faithful alignment with the text prompt. To evaluate the proposed framework's performance, we collect a dataset named Img-Ref-T2I, where text prompts include three types of uncertain knowledge: (1) known but rare. (2) unknown. (3) ambiguous. Moreover, we carefully craft a complex prompt to guide GPT-4o in making preference evaluation, which has been shown to have an evaluation accuracy similar to that of human preference evaluation. Experimental results demonstrate the effectiveness of our framework, outperforming GPT-4o by about 30% in human evaluation.","published":"2025-05-21T17:31:49Z","updated":"2025-05-21T17:31:49Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.15779v1","pdf_url":"https://arxiv.org/pdf/2505.15779v1","comment":"12 pages, 7 figures, a framework that integrates reference images from the Internet into T2I/TI2I models","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.06303","versioned_id":"2506.06303v6","title":"Reward Is Enough: LLMs Are In-Context Reinforcement Learners","authors":["Kefan Song","Amir Moeini","Peng Wang","Lei Gong","Rohan Chandra","Shangtong Zhang","Yanjun Qi"],"abstract":"Reinforcement learning (RL) is a framework for solving sequential decision-making problems. In this work, we demonstrate that, surprisingly, RL emerges during the inference time of large language models (LLMs), a phenomenon we term in-context RL (ICRL). To reveal this capability, we introduce a simple multi-round prompting framework, we call ICRL prompting, for inference-time self-improvement. The goal of ICRL prompting is to guide LLMs to perform reinforcement learning during inference for self-improvement on a given task. After each response, the model receives numerical scalar feedback, denoted as a reward. In the next round, we prompt the LLM again together with a context that concatenates all prior responses and their associated rewards. We consistently observe that response quality improves as the context grows. In other words, the LLM can optimize scalar reward signals during inference, exhibiting behavior analogous to reinforcement learning. We evaluate ICRL prompting on Game of 24, creative writing, ScienceWorld, and Olympiad-level math competitions (AIME and HMMT), demonstrating significant improvements over baselines such as Self-Refine and Reflexion. Notably, even when the reward signals are generated by the same LLM, ICRL prompting still improves performance, highlighting a promising new paradigm for test-time scaling.","published":"2025-05-21T16:15:01Z","updated":"2026-04-24T20:21:17Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.06303v6","pdf_url":"https://arxiv.org/pdf/2506.06303v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.15612","versioned_id":"2505.15612v1","title":"Learn to Reason Efficiently with Adaptive Length-based Reward Shaping","authors":["Wei Liu","Ruochen Zhou","Yiyun Deng","Yuzhen Huang","Junteng Liu","Yuntian Deng","Yizhe Zhang","Junxian He"],"abstract":"Large Reasoning Models (LRMs) have shown remarkable capabilities in solving complex problems through reinforcement learning (RL), particularly by generating long reasoning traces. However, these extended outputs often exhibit substantial redundancy, which limits the efficiency of LRMs. In this paper, we investigate RL-based approaches to promote reasoning efficiency. Specifically, we first present a unified framework that formulates various efficient reasoning methods through the lens of length-based reward shaping. Building on this perspective, we propose a novel Length-bAsed StEp Reward shaping method (LASER), which employs a step function as the reward, controlled by a target length. LASER surpasses previous methods, achieving a superior Pareto-optimal balance between performance and efficiency. Next, we further extend LASER based on two key intuitions: (1) The reasoning behavior of the model evolves during training, necessitating reward specifications that are also adaptive and dynamic; (2) Rather than uniformly encouraging shorter or longer chains of thought (CoT), we posit that length-based reward shaping should be difficulty-aware i.e., it should penalize lengthy CoTs more for easy queries. This approach is expected to facilitate a combination of fast and slow thinking, leading to a better overall tradeoff. The resulting method is termed LASER-D (Dynamic and Difficulty-aware). Experiments on DeepSeek-R1-Distill-Qwen-1.5B, DeepSeek-R1-Distill-Qwen-7B, and DeepSeek-R1-Distill-Qwen-32B show that our approach significantly enhances both reasoning performance and response length efficiency. For instance, LASER-D and its variant achieve a +6.1 improvement on AIME2024 while reducing token usage by 63%. Further analysis reveals our RL-based compression produces more concise reasoning patterns with less redundant \"self-reflections\". Resources are at https://github.com/hkust-nlp/Laser.","published":"2025-05-21T15:03:26Z","updated":"2025-05-21T15:03:26Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.15612v1","pdf_url":"https://arxiv.org/pdf/2505.15612v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17112","versioned_id":"2505.17112v1","title":"Cultural Value Alignment in Large Language Models: A Prompt-based Analysis of Schwartz Values in Gemini, ChatGPT, and DeepSeek","authors":["Robin Segerer"],"abstract":"This study examines cultural value alignment in large language models (LLMs) by analyzing how Gemini, ChatGPT, and DeepSeek prioritize values from Schwartz's value framework. Using the 40-item Portrait Values Questionnaire, we assessed whether DeepSeek, trained on Chinese-language data, exhibits distinct value preferences compared to Western models. Results of a Bayesian ordinal regression model show that self-transcendence values (e.g., benevolence, universalism) were highly prioritized across all models, reflecting a general LLM tendency to emphasize prosocial values. However, DeepSeek uniquely downplayed self-enhancement values (e.g., power, achievement) compared to ChatGPT and Gemini, aligning with collectivist cultural tendencies. These findings suggest that LLMs reflect culturally situated biases rather than a universal ethical framework. To address value asymmetries in LLMs, we propose multi-perspective reasoning, self-reflective feedback, and dynamic contextualization. This study contributes to discussions on AI fairness, cultural neutrality, and the need for pluralistic AI alignment frameworks that integrate diverse moral perspectives.","published":"2025-05-21T14:03:19Z","updated":"2025-05-21T14:03:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17112v1","pdf_url":"https://arxiv.org/pdf/2505.17112v1","comment":"15 pages, 1 table, 1 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.15410","versioned_id":"2505.15410v1","title":"ClickSight: Interpreting Student Clickstreams to Reveal Insights on Learning Strategies via LLMs","authors":["Bahar Radmehr","Ekaterina Shved","Fatma Betül Güreş","Adish Singla","Tanja Käser"],"abstract":"Clickstream data from digital learning environments offer valuable insights into students' learning behaviors, but are challenging to interpret due to their high dimensionality and granularity. Prior approaches have relied mainly on handcrafted features, expert labeling, clustering, or supervised models, therefore often lacking generalizability and scalability. In this work, we introduce ClickSight, an in-context Large Language Model (LLM)-based pipeline that interprets student clickstreams to reveal their learning strategies. ClickSight takes raw clickstreams and a list of learning strategies as input and generates textual interpretations of students' behaviors during interaction. We evaluate four different prompting strategies and investigate the impact of self-refinement on interpretation quality. Our evaluation spans two open-ended learning environments and uses a rubric-based domain-expert evaluation. Results show that while LLMs can reasonably interpret learning strategies from clickstreams, interpretation quality varies by prompting strategy, and self-refinement offers limited improvement. ClickSight demonstrates the potential of LLMs to generate theory-driven insights from educational interaction data.","published":"2025-05-21T11:52:57Z","updated":"2025-05-21T11:52:57Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.15410v1","pdf_url":"https://arxiv.org/pdf/2505.15410v1","comment":"Accepted in Latebreaking results track in AIED 2025(26th International Conference on Artificial Intelligence in Education JULY 22-26, 2025 PALERMO, ITALY)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17107","versioned_id":"2505.17107v1","title":"CRAKEN: Cybersecurity LLM Agent with Knowledge-Based Execution","authors":["Minghao Shao","Haoran Xi","Nanda Rani","Meet Udeshi","Venkata Sai Charan Putrevu","Kimberly Milner","Brendan Dolan-Gavitt","Sandeep Kumar Shukla","Prashanth Krishnamurthy","Farshad Khorrami","Ramesh Karri","Muhammad Shafique"],"abstract":"Large Language Model (LLM) agents can automate cybersecurity tasks and can adapt to the evolving cybersecurity landscape without re-engineering. While LLM agents have demonstrated cybersecurity capabilities on Capture-The-Flag (CTF) competitions, they have two key limitations: accessing latest cybersecurity expertise beyond training data, and integrating new knowledge into complex task planning. Knowledge-based approaches that incorporate technical understanding into the task-solving automation can tackle these limitations. We present CRAKEN, a knowledge-based LLM agent framework that improves cybersecurity capability through three core mechanisms: contextual decomposition of task-critical information, iterative self-reflected knowledge retrieval, and knowledge-hint injection that transforms insights into adaptive attack strategies. Comprehensive evaluations with different configurations show CRAKEN's effectiveness in multi-stage vulnerability detection and exploitation compared to previous approaches. Our extensible architecture establishes new methodologies for embedding new security knowledge into LLM-driven cybersecurity agentic systems. With a knowledge database of CTF writeups, CRAKEN obtained an accuracy of 22% on NYU CTF Bench, outperforming prior works by 3% and achieving state-of-the-art results. On evaluation of MITRE ATT&CK techniques, CRAKEN solves 25-30% more techniques than prior work, demonstrating improved cybersecurity capabilities via knowledge-based execution. We make our framework open source to public https://github.com/NYU-LLM-CTF/nyuctf_agents_craken.","published":"2025-05-21T11:01:11Z","updated":"2025-05-21T11:01:11Z","categories":["cs.CR","cs.AI","cs.LG","cs.MA"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2505.17107v1","pdf_url":"https://arxiv.org/pdf/2505.17107v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.17100","versioned_id":"2505.17100v2","title":"Any Large Language Model Can Be a Reliable Judge: Debiasing with a Reasoning-based Bias Detector","authors":["Haoyan Yang","Runxue Bao","Cao Xiao","Jun Ma","Parminder Bhatia","Shangqian Gao","Taha Kass-Hout"],"abstract":"LLM-as-a-Judge has emerged as a promising tool for automatically evaluating generated outputs, but its reliability is often undermined by potential biases in judgment. Existing efforts to mitigate these biases face key limitations: in-context learning-based methods fail to address rooted biases due to the evaluator's limited capacity for self-reflection, whereas fine-tuning is not applicable to all evaluator types, especially closed-source models. To address this challenge, we introduce the Reasoning-based Bias Detector (RBD), which is a plug-in module that identifies biased evaluations and generates structured reasoning to guide evaluator self-correction. Rather than modifying the evaluator itself, RBD operates externally and engages in an iterative process of bias detection and feedback-driven revision. To support its development, we design a complete pipeline consisting of biased dataset construction, supervision collection, distilled reasoning-based fine-tuning of RBD, and integration with LLM evaluators. We fine-tune four sizes of RBD models, ranging from 1.5B to 14B, and observe consistent performance improvements across all scales. Experimental results on 4 bias types--verbosity, position, bandwagon, and sentiment--evaluated using 8 LLM evaluators demonstrate RBD's strong effectiveness. For example, the RBD-8B model improves evaluation accuracy by an average of 18.5% and consistency by 10.9%, and surpasses prompting-based baselines and fine-tuned judges by 12.8% and 17.2%, respectively. These results highlight RBD's effectiveness and scalability. Additional experiments further demonstrate its strong generalization across biases and domains, as well as its efficiency.","published":"2025-05-21T07:23:05Z","updated":"2025-10-27T22:09:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17100v2","pdf_url":"https://arxiv.org/pdf/2505.17100v2","comment":"Accepted at NeurIPS 2025 (Camera-Ready Version)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.15068","versioned_id":"2505.15068v1","title":"ModelingAgent: Bridging LLMs and Mathematical Modeling for Real-World Challenges","authors":["Cheng Qian","Hongyi Du","Hongru Wang","Xiusi Chen","Yuji Zhang","Avirup Sil","Chengxiang Zhai","Kathleen McKeown","Heng Ji"],"abstract":"Recent progress in large language models (LLMs) has enabled substantial advances in solving mathematical problems. However, existing benchmarks often fail to reflect the complexity of real-world problems, which demand open-ended, interdisciplinary reasoning and integration of computational tools. To address this gap, we introduce ModelingBench, a novel benchmark featuring real-world-inspired, open-ended problems from math modeling competitions across diverse domains, ranging from urban traffic optimization to ecosystem resource planning. These tasks require translating natural language into formal mathematical formulations, applying appropriate tools, and producing structured, defensible reports. ModelingBench also supports multiple valid solutions, capturing the ambiguity and creativity of practical modeling. We also present ModelingAgent, a multi-agent framework that coordinates tool use, supports structured workflows, and enables iterative self-refinement to generate well-grounded, creative solutions. To evaluate outputs, we further propose ModelingJudge, an expert-in-the-loop system leveraging LLMs as domain-specialized judges assessing solutions from multiple expert perspectives. Empirical results show that ModelingAgent substantially outperforms strong baselines and often produces solutions indistinguishable from those of human experts. Together, our work provides a comprehensive framework for evaluating and advancing real-world problem-solving in open-ended, interdisciplinary modeling challenges.","published":"2025-05-21T03:33:23Z","updated":"2025-05-21T03:33:23Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.15068v1","pdf_url":"https://arxiv.org/pdf/2505.15068v1","comment":"36 Pages, 26 Figures, 5 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.14899","versioned_id":"2505.14899v3","title":"REFLEX: Metacognitive Reasoning for Reflective Zero-Shot Robotic Planning with Large Language Models","authors":["Wenjie Lin","Jin Wei-Kocsis","Jiansong Zhang","Byung-Cheol Min","Dongming Gan","Paul Asunda","Ragu Athinarayanan"],"abstract":"While large language models (LLMs) have shown great potential across various domains, their applications in robotics remain largely limited to static prompt-based behaviors and still face challenges in complex tasks under zero-shot or few-shot settings. Inspired by human metacognitive learning and creative problem-solving, we address this limitation by exploring a fundamental question: Can LLMs be empowered with metacognitive capabilities to reason, reflect, and create, thereby enhancing their ability to perform robotic tasks with minimal demonstrations? In this paper, we present REFLEX, a framework that integrates metacognitive learning into LLM-powered multi-robot collaboration. The system equips the LLM-powered robotic agents with a skill decomposition and self-reflection mechanism that identifies modular skills from prior tasks, reflects on failures in unseen task scenarios, and synthesizes effective new solutions. We propose a more challenging robotic benchmark task and evaluate our framework on the existing benchmark and the novel task. Experimental results show that our metacognitive learning framework significantly outperforms existing baselines. Moreover, we observe that our framework can generate solutions that differ from the ground truth yet still successfully complete the tasks. These findings support our hypothesis that metacognitive learning can foster creativity in robotic planning.","published":"2025-05-20T20:51:18Z","updated":"2026-03-02T20:01:50Z","categories":["cs.RO","cs.CL"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2505.14899v3","pdf_url":"https://arxiv.org/pdf/2505.14899v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.14848","versioned_id":"2505.14848v2","title":"MAATS: A Multi-Agent Automated Translation System Based on MQM Evaluation","authors":["George Wang","Jiaqian Hu","Safinah Ali"],"abstract":"We present MAATS, a Multi Agent Automated Translation System that leverages the Multidimensional Quality Metrics (MQM) framework as a fine-grained signal for error detection and refinement. MAATS employs multiple specialized AI agents, each focused on a distinct MQM category (e.g., Accuracy, Fluency, Style, Terminology), followed by a synthesis agent that integrates the annotations to iteratively refine translations. This design contrasts with conventional single-agent methods that rely on self-correction. Evaluated across diverse language pairs and Large Language Models (LLMs), MAATS outperforms zero-shot and single-agent baselines with statistically significant gains in both automatic metrics and human assessments. It excels particularly in semantic accuracy, locale adaptation, and linguistically distant language pairs. Qualitative analysis highlights its strengths in multi-layered error diagnosis, omission detection across perspectives, and context-aware refinement. By aligning modular agent roles with interpretable MQM dimensions, MAATS narrows the gap between black-box LLMs and human translation workflows, shifting focus from surface fluency to deeper semantic and contextual fidelity.","published":"2025-05-20T19:29:05Z","updated":"2025-08-08T15:49:43Z","categories":["cs.CL","cs.LG","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.14848v2","pdf_url":"https://arxiv.org/pdf/2505.14848v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.14582","versioned_id":"2505.14582v3","title":"Can Pruning Improve Reasoning? Revisiting Long-CoT Compression with Capability in Mind for Better Reasoning","authors":["Shangziqi Zhao","Jiahao Yuan","Jinyang Wu","Zhenglin Wang","Guisong Yang","Usman Naseem"],"abstract":"Long chain-of-thought (Long-CoT) reasoning improves accuracy in LLMs, yet its verbose, self-reflective style often hinders effective distillation into small language models (SLMs). We revisit Long-CoT compression through the lens of capability alignment and ask: Can pruning improve reasoning? We propose Prune-on-Logic, a structure-aware framework that transforms Long-CoT into logic graphs and selectively prunes low-utility reasoning steps under self-verification constraints. Through systematic analysis across three pruning strategies targeting entire chains, core reasoning, and verification, we find that verification pruning consistently improves accuracy while reducing token usage, whereas pruning reasoning steps or indiscriminate pruning degrades performance. Our study reveals that effective pruning aligns supervision with model capacity rather than merely shortening inputs. Gains hold across tasks, model scales, and CoT capability, with larger models benefiting more from pruning due to richer but more redundant reasoning. Our empirical findings highlight pruning as a structural optimization strategy for aligning CoT reasoning with SLM capacity.","published":"2025-05-20T16:38:32Z","updated":"2025-12-23T19:59:27Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.14582v3","pdf_url":"https://arxiv.org/pdf/2505.14582v3","comment":"19 pages,6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.14403","versioned_id":"2505.14403v4","title":"Unearthing Gems from Stones: Policy Optimization with Negative Sample Augmentation for LLM Reasoning","authors":["Zhaohui Yang","Yuxiao Ye","Shilei Jiang","Chen Hu","Linjing Li","Shihong Deng","Daxin Jiang"],"abstract":"Recent advances in reasoning language models have witnessed a paradigm shift from short to long CoT pattern. Given the substantial computational cost of rollouts in long CoT models, maximizing the utility of fixed training datasets becomes crucial. Our analysis reveals that negative responses contain valuable components such as self-reflection and error-correction steps, yet primary existing methods either completely discard negative samples (RFT) or apply equal penalization across all tokens (RL), failing to leverage these potential learning signals. In light of this, we propose Behavior Constrained Policy Gradient with Negative Sample Augmentation (BCPG-NSA), a fine-grained offline RL framework that encompasses three stages: 1) sample segmentation, 2) consensus-based step correctness assessment combining LLM and PRM judgers, and 3) policy optimization with NSA designed to effectively mine positive steps within negative samples. Experimental results show that BCPG-NSA outperforms baselines on several challenging math/coding reasoning benchmarks using the same training dataset, achieving improved sample efficiency and demonstrating robustness and scalability when extended to multiple iterations.","published":"2025-05-20T14:16:49Z","updated":"2025-09-15T14:23:10Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.14403v4","pdf_url":"https://arxiv.org/pdf/2505.14403v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.14391","versioned_id":"2505.14391v1","title":"Beyond the First Error: Process Reward Models for Reflective Mathematical Reasoning","authors":["Zhaohui Yang","Chenghua He","Xiaowen Shi","Linjing Li","Qiyue Yin","Shihong Deng","Daxin Jiang"],"abstract":"Many studies focus on data annotation techniques for training effective PRMs. However, current methods encounter a significant issue when applied to long CoT reasoning processes: they tend to focus solely on the first incorrect step and all preceding steps, assuming that all subsequent steps are incorrect. These methods overlook the unique self-correction and reflection mechanisms inherent in long CoT, where correct reasoning steps may still occur after initial reasoning mistakes. To address this issue, we propose a novel data annotation method for PRMs specifically designed to score the long CoT reasoning process. Given that under the reflection pattern, correct and incorrect steps often alternate, we introduce the concepts of Error Propagation and Error Cessation, enhancing PRMs' ability to identify both effective self-correction behaviors and reasoning based on erroneous steps. Leveraging an LLM-based judger for annotation, we collect 1.7 million data samples to train a 7B PRM and evaluate it at both solution and step levels. Experimental results demonstrate that compared to existing open-source PRMs and PRMs trained on open-source datasets, our PRM achieves superior performance across various metrics, including search guidance, BoN, and F1 scores. Compared to widely used MC-based annotation methods, our annotation approach not only achieves higher data efficiency but also delivers superior performance. Detailed analysis is also conducted to demonstrate the stability and generalizability of our method.","published":"2025-05-20T14:12:05Z","updated":"2025-05-20T14:12:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.14391v1","pdf_url":"https://arxiv.org/pdf/2505.14391v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.14038","versioned_id":"2505.14038v1","title":"ProMind-LLM: Proactive Mental Health Care via Causal Reasoning with Sensor Data","authors":["Xinzhe Zheng","Sijie Ji","Jiawei Sun","Renqi Chen","Wei Gao","Mani Srivastava"],"abstract":"Mental health risk is a critical global public health challenge, necessitating innovative and reliable assessment methods. With the development of large language models (LLMs), they stand out to be a promising tool for explainable mental health care applications. Nevertheless, existing approaches predominantly rely on subjective textual mental records, which can be distorted by inherent mental uncertainties, leading to inconsistent and unreliable predictions. To address these limitations, this paper introduces ProMind-LLM. We investigate an innovative approach integrating objective behavior data as complementary information alongside subjective mental records for robust mental health risk assessment. Specifically, ProMind-LLM incorporates a comprehensive pipeline that includes domain-specific pretraining to tailor the LLM for mental health contexts, a self-refine mechanism to optimize the processing of numerical behavioral data, and causal chain-of-thought reasoning to enhance the reliability and interpretability of its predictions. Evaluations of two real-world datasets, PMData and Globem, demonstrate the effectiveness of our proposed methods, achieving substantial improvements over general LLMs. We anticipate that ProMind-LLM will pave the way for more dependable, interpretable, and scalable mental health case solutions.","published":"2025-05-20T07:36:28Z","updated":"2025-05-20T07:36:28Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.14038v1","pdf_url":"https://arxiv.org/pdf/2505.14038v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.13808","versioned_id":"2505.13808v1","title":"RAG/LLM Augmented Switching Driven Polymorphic Metaheuristic Framework","authors":["Faramarz Safi Esfahani","Ghassan Beydoun","Morteza Saberi","Brad McCusker","Biswajeet Pradhan"],"abstract":"Metaheuristic algorithms are widely used for solving complex optimization problems, yet their effectiveness is often constrained by fixed structures and the need for extensive tuning. The Polymorphic Metaheuristic Framework (PMF) addresses this limitation by introducing a self-adaptive metaheuristic switching mechanism driven by real-time performance feedback and dynamic algorithmic selection. PMF leverages the Polymorphic Metaheuristic Agent (PMA) and the Polymorphic Metaheuristic Selection Agent (PMSA) to dynamically select and transition between metaheuristic algorithms based on key performance indicators, ensuring continuous adaptation. This approach enhances convergence speed, adaptability, and solution quality, outperforming traditional metaheuristics in high-dimensional, dynamic, and multimodal environments. Experimental results on benchmark functions demonstrate that PMF significantly improves optimization efficiency by mitigating stagnation and balancing exploration-exploitation strategies across various problem landscapes. By integrating AI-driven decision-making and self-correcting mechanisms, PMF paves the way for scalable, intelligent, and autonomous optimization frameworks, with promising applications in engineering, logistics, and complex decision-making systems.","published":"2025-05-20T01:41:22Z","updated":"2025-05-20T01:41:22Z","categories":["cs.NE","cs.AI"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2505.13808v1","pdf_url":"https://arxiv.org/pdf/2505.13808v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.13445","versioned_id":"2505.13445v1","title":"Trust, But Verify: A Self-Verification Approach to Reinforcement Learning with Verifiable Rewards","authors":["Xiaoyuan Liu","Tian Liang","Zhiwei He","Jiahao Xu","Wenxuan Wang","Pinjia He","Zhaopeng Tu","Haitao Mi","Dong Yu"],"abstract":"Large Language Models (LLMs) show great promise in complex reasoning, with Reinforcement Learning with Verifiable Rewards (RLVR) being a key enhancement strategy. However, a prevalent issue is ``superficial self-reflection'', where models fail to robustly verify their own outputs. We introduce RISE (Reinforcing Reasoning with Self-Verification), a novel online RL framework designed to tackle this. RISE explicitly and simultaneously trains an LLM to improve both its problem-solving and self-verification abilities within a single, integrated RL process. The core mechanism involves leveraging verifiable rewards from an outcome verifier to provide on-the-fly feedback for both solution generation and self-verification tasks. In each iteration, the model generates solutions, then critiques its own on-policy generated solutions, with both trajectories contributing to the policy update. Extensive experiments on diverse mathematical reasoning benchmarks show that RISE consistently improves model's problem-solving accuracy while concurrently fostering strong self-verification skills. Our analyses highlight the advantages of online verification and the benefits of increased verification compute. Additionally, RISE models exhibit more frequent and accurate self-verification behaviors during reasoning. These advantages reinforce RISE as a flexible and effective path towards developing more robust and self-aware reasoners.","published":"2025-05-19T17:59:31Z","updated":"2025-05-19T17:59:31Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.13445v1","pdf_url":"https://arxiv.org/pdf/2505.13445v1","comment":"code available at https://github.com/xyliu-cs/RISE","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.13271","versioned_id":"2505.13271v2","title":"CSC-SQL: Corrective Self-Consistency in Text-to-SQL via Reinforcement Learning","authors":["Lei Sheng","Shuai-Shuai Xu"],"abstract":"Large language models (LLMs) have demonstrated strong capabilities in translating natural language questions about relational databases into SQL queries. In particular, test-time scaling techniques such as Self-Consistency and Self-Correction can enhance SQL generation accuracy by increasing computational effort during inference. However, these methods have notable limitations: Self-Consistency may select suboptimal outputs despite majority votes, while Self-Correction typically addresses only syntactic errors. To leverage the strengths of both approaches, we propose CSC-SQL, a novel method that integrates Self-Consistency and Self-Correction. CSC-SQL selects the two most frequently occurring outputs from parallel sampling and feeds them into a merge revision model for correction. Additionally, we employ the Group Relative Policy Optimization (GRPO) algorithm to fine-tune both the SQL generation and revision models via reinforcement learning, significantly enhancing output quality. Experimental results confirm the effectiveness and generalizability of CSC-SQL. On the BIRD private test set, our 7B model achieves 71.72\\% execution accuracy, while the 32B model achieves 73.67\\%. The code has been open sourced at https://github.com/CycloneBoy/csc_sql.","published":"2025-05-19T15:52:19Z","updated":"2025-06-30T11:12:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.13271v2","pdf_url":"https://arxiv.org/pdf/2505.13271v2","comment":"25 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.13259","versioned_id":"2505.13259v3","title":"From Automation to Autonomy: A Survey on Large Language Models in Scientific Discovery","authors":["Tianshi Zheng","Zheye Deng","Hong Ting Tsang","Weiqi Wang","Jiaxin Bai","Zihao Wang","Yangqiu Song"],"abstract":"Large Language Models (LLMs) are catalyzing a paradigm shift in scientific discovery, evolving from task-specific automation tools into increasingly autonomous agents and fundamentally redefining research processes and human-AI collaboration. This survey systematically charts this burgeoning field, placing a central focus on the changing roles and escalating capabilities of LLMs in science. Through the lens of the scientific method, we introduce a foundational three-level taxonomy-Tool, Analyst, and Scientist-to delineate their escalating autonomy and evolving responsibilities within the research lifecycle. We further identify pivotal challenges and future research trajectories such as robotic automation, self-improvement, and ethical governance. Overall, this survey provides a conceptual architecture and strategic foresight to navigate and shape the future of AI-driven scientific discovery, fostering both rapid innovation and responsible advancement. Github Repository: https://github.com/HKUST-KnowComp/Awesome-LLM-Scientific-Discovery.","published":"2025-05-19T15:41:32Z","updated":"2025-09-17T09:06:42Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.13259v3","pdf_url":"https://arxiv.org/pdf/2505.13259v3","comment":"EMNLP 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.12565","versioned_id":"2505.12565v3","title":"mCLM: A Modular Chemical Language Model that Generates Functional and Makeable Molecules","authors":["Carl Edwards","Chi Han","Gawon Lee","Thao Nguyen","Sara Szymkuć","Chetan Kumar Prasad","Bowen Jin","Jiawei Han","Ying Diao","Ge Liu","Hao Peng","Bartosz A. Grzybowski","Martin D. Burke","Heng Ji"],"abstract":"Despite their ability to understand chemical knowledge, large language models (LLMs) remain limited in their capacity to propose novel molecules with desired functions (e.g., drug-like properties). In addition, the molecules that LLMs propose can often be challenging to make, and are almost never compatible with automated synthesis approaches. To better enable the discovery of functional small molecules, LLMs need to learn a new molecular language that is more effective in predicting properties and inherently synced with automated synthesis technology. Current molecule LLMs are limited by representing molecules based on atoms. In this paper, we argue that just like tokenizing texts into meaning-bearing (sub-)word tokens instead of characters, molecules should be tokenized at the level of functional building blocks, i.e., parts of molecules that bring unique functions and serve as effective building blocks for real-world automated laboratory synthesis. This motivates us to propose mCLM, a modular Chemical-Language Model that comprises a bilingual language model that understands both natural language descriptions of functions and molecular blocks. mCLM front-loads synthesizability considerations while improving the predicted functions of molecules in a principled manner. Experiments on FDA-approved drugs showed that mCLM is capable of significantly improving chemical functions. mCLM, with only 3B parameters, also achieves improvements in synthetic accessibility relative to 7 other leading generative AI methods including GPT-5. When tested on 122 out-of-distribution medicines using only building blocks/tokens that are compatible with automated modular synthesis, mCLM outperforms all baselines in property scores and synthetic accessibility. mCLM can also reason on multiple functions and iteratively self-improve to rescue drug candidates that failed late in clinical trials (\"fallen angels\").","published":"2025-05-18T22:52:39Z","updated":"2026-03-01T18:24:31Z","categories":["cs.AI","cs.CL","cs.LG","q-bio.QM"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.12565v3","pdf_url":"https://arxiv.org/pdf/2505.12565v3","comment":"Accepted to ICLR 2026 (Oral). Code: https://github.com/blender-nlp/mCLM Data and Model: https://huggingface.co/collections/language-plus-molecules/mclm","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.12348","versioned_id":"2505.12348v1","title":"Reasoning-CV: Fine-tuning Powerful Reasoning LLMs for Knowledge-Assisted Claim Verification","authors":["Zhi Zheng","Wee Sun Lee"],"abstract":"Claim verification is essential in combating misinformation, and large language models (LLMs) have recently emerged in this area as powerful tools for assessing the veracity of claims using external knowledge. Existing LLM-based methods for claim verification typically adopt a Decompose-Then-Verify paradigm, which involves decomposing complex claims into several independent sub-claims and verifying each sub-claim separately. However, this paradigm often introduces errors during the claim decomposition process. To mitigate these errors, we propose to develop the Chain-of-Thought (CoT)-Verify paradigm, which leverages LLM reasoning methods to generate CoT-verification paths for the original complex claim without requiring decompositions into sub-claims and separate verification stages. The CoT-Verify paradigm allows us to propose a natural fine-tuning method called Reasoning-CV to enhance the verification capabilities in LLMs. Reasoning-CV includes a supervised fine-tuning (SFT) stage and a self-improvement direct preference optimization (DPO) stage. Utilizing only an 8B pre-trained LLM, Reasoning-CV demonstrates superior knowledge-assisted claim verification performances compared to existing Decompose-Then-Verify methods, as well as powerful black-box LLMs such as GPT-4o+CoT and o1-preview. Our code is available.","published":"2025-05-18T10:28:54Z","updated":"2025-05-18T10:28:54Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.12348v1","pdf_url":"https://arxiv.org/pdf/2505.12348v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.11924","versioned_id":"2505.11924v3","title":"Intrinsic Self-Correction in LLMs: Towards Explainable Prompting via Mechanistic Interpretability","authors":["Yu-Ting Lee","Fu-Chieh Chang","Yu-En Shu","Hui-Ying Shih","Pei-Yuan Wu"],"abstract":"Intrinsic self-correction refers to the phenomenon where a language model refines its own outputs purely through prompting, without external feedback or parameter updates. While this approach improves performance across diverse tasks, its mechanism remains unclear. We show that intrinsic self-correction functions by steering hidden representations along interpretable latent directions, as evidenced by both alignment analysis and activation interventions. To achieve this, we analyze intrinsic self-correction via the representation shift induced by prompting. In parallel, we construct interpretable latent directions with contrastive pairs and verify the causal effect of these directions via activation addition. Evaluating six open-source LLMs, our results demonstrate that prompt-induced representation shifts in text detoxification and text toxification consistently align with latent directions constructed from contrastive pairs. In detoxification, the shifts align with the non-toxic direction; in toxification, they align with the toxic direction. These findings suggest that representation steering is the mechanistic driver of intrinsic self-correction. Our analysis highlights that understanding model internals offers a direct route to analyzing the mechanisms of prompt-driven LLM behaviors.","published":"2025-05-17T09:18:37Z","updated":"2026-02-11T17:06:44Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.11924v3","pdf_url":"https://arxiv.org/pdf/2505.11924v3","comment":"","journal_ref":"4th Deployable AI Workshop at AAAI 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2505.11824","versioned_id":"2505.11824v3","title":"Latent Veracity Inference for Identifying Errors in Stepwise Reasoning","authors":["Minsu Kim","Jean-Pierre Falet","Oliver E. Richardson","Xiaoyin Chen","Moksh Jain","Sungjin Ahn","Sungsoo Ahn","Yoshua Bengio"],"abstract":"Chain-of-Thought (CoT) reasoning has advanced the capabilities and transparency of language models (LMs); however, reasoning chains can contain inaccurate statements that reduce performance and trustworthiness. To address this, we propose to augment each reasoning step in a CoT with a latent veracity (or correctness) variable. To efficiently explore this expanded space, we introduce Veracity Search (VS), a discrete search algorithm over veracity assignments. It performs otherwise intractable inference in the posterior distribution over latent veracity values by leveraging the LM's joint likelihood over veracity and the final answer as a proxy reward. This efficient inference-time verification method facilitates supervised fine-tuning of an Amortized Veracity Inference (AVI) machine by providing pseudo-labels for veracity. AVI generalizes VS, enabling accurate zero-shot veracity inference in novel contexts. Empirical results demonstrate that VS reliably identifies errors in logical (ProntoQA), mathematical (GSM8K), and commonsense (CommonsenseQA) reasoning benchmarks, with AVI achieving comparable zero-shot accuracy. Finally, we demonstrate the utility of latent veracity inference for providing feedback during self-correction and self-improvement.","published":"2025-05-17T04:16:36Z","updated":"2026-02-17T14:35:16Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.11824v3","pdf_url":"https://arxiv.org/pdf/2505.11824v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.11737","versioned_id":"2505.11737v4","title":"TokUR: Token-Level Uncertainty Estimation for Large Language Model Reasoning","authors":["Tunyu Zhang","Haizhou Shi","Yibin Wang","Hengyi Wang","Xiaoxiao He","Zhuowei Li","Haoxian Chen","Ligong Han","Kai Xu","Huan Zhang","Dimitris Metaxas","Hao Wang"],"abstract":"While Large Language Models (LLMs) have demonstrated impressive capabilities, their output quality remains inconsistent across various application scenarios, making it difficult to identify trustworthy responses, especially in complex tasks requiring multi-step reasoning. In this paper, we propose a Token-level Uncertainty estimation framework for Reasoning (TokUR) that enables LLMs to self-assess and self-improve their responses in mathematical reasoning. Specifically, we introduce low-rank random weight perturbation during LLM decoding to generate predictive distributions for token-level uncertainty estimation, and we aggregate these uncertainty quantities to capture the semantic uncertainty of generated responses. Experiments on mathematical reasoning datasets of varying difficulty demonstrate that TokUR exhibits a strong correlation with answer correctness and model robustness, and the uncertainty signals produced by TokUR can be leveraged to enhance the model's reasoning performance at test time. These results highlight the effectiveness of TokUR as a principled and scalable approach for improving the reliability and interpretability of LLMs in challenging reasoning tasks.","published":"2025-05-16T22:47:32Z","updated":"2026-04-11T18:08:02Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.11737v4","pdf_url":"https://arxiv.org/pdf/2505.11737v4","comment":"Accepted to International Conference on Learning Representations (ICLR) 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.11423","versioned_id":"2505.11423v3","title":"When Thinking Fails: The Pitfalls of Reasoning for Instruction-Following in LLMs","authors":["Xiaomin Li","Zhou Yu","Zhiwei Zhang","Xupeng Chen","Ziji Zhang","Yingying Zhuang","Narayanan Sadagopan","Anurag Beniwal"],"abstract":"Reasoning-enhanced large language models (RLLMs), whether explicitly trained for reasoning or prompted via chain-of-thought (CoT), have achieved state-of-the-art performance on many complex reasoning tasks. However, we uncover a surprising and previously overlooked phenomenon: explicit CoT reasoning can significantly degrade instruction-following accuracy. Evaluating 15 models on two benchmarks: IFEval (with simple, rule-verifiable constraints) and ComplexBench (with complex, compositional constraints), we consistently observe performance drops when CoT prompting is applied. Through large-scale case studies and an attention-based analysis, we identify common patterns where reasoning either helps (e.g., with formatting or lexical precision) or hurts (e.g., by neglecting simple constraints or introducing unnecessary content). We propose a metric, constraint attention, to quantify model focus during generation and show that CoT reasoning often diverts attention away from instruction-relevant tokens. To mitigate these effects, we introduce and evaluate four strategies: in-context learning, self-reflection, self-selective reasoning, and classifier-selective reasoning. Our results demonstrate that selective reasoning strategies, particularly classifier-selective reasoning, can substantially recover lost performance. To our knowledge, this is the first work to systematically expose reasoning-induced failures in instruction-following and offer practical mitigation strategies.","published":"2025-05-16T16:36:00Z","updated":"2025-09-02T02:55:17Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.11423v3","pdf_url":"https://arxiv.org/pdf/2505.11423v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.11070","versioned_id":"2505.11070v1","title":"Towards Self-Improvement of Diffusion Models via Group Preference Optimization","authors":["Renjie Chen","Wenfeng Lin","Yichen Zhang","Jiangchuan Wei","Boyuan Liu","Chao Feng","Jiao Ran","Mingyu Guo"],"abstract":"Aligning text-to-image (T2I) diffusion models with Direct Preference Optimization (DPO) has shown notable improvements in generation quality. However, applying DPO to T2I faces two challenges: the sensitivity of DPO to preference pairs and the labor-intensive process of collecting and annotating high-quality data. In this work, we demonstrate that preference pairs with marginal differences can degrade DPO performance. Since DPO relies exclusively on relative ranking while disregarding the absolute difference of pairs, it may misclassify losing samples as wins, or vice versa. We empirically show that extending the DPO from pairwise to groupwise and incorporating reward standardization for reweighting leads to performance gains without explicit data selection. Furthermore, we propose Group Preference Optimization (GPO), an effective self-improvement method that enhances performance by leveraging the model's own capabilities without requiring external data. Extensive experiments demonstrate that GPO is effective across various diffusion models and tasks. Specifically, combining with widely used computer vision models, such as YOLO and OCR, the GPO improves the accurate counting and text rendering capabilities of the Stable Diffusion 3.5 Medium by 20 percentage points. Notably, as a plug-and-play method, no extra overhead is introduced during inference.","published":"2025-05-16T10:04:57Z","updated":"2025-05-16T10:04:57Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.11070v1","pdf_url":"https://arxiv.org/pdf/2505.11070v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.13504","versioned_id":"2505.13504v1","title":"An agentic system with reinforcement-learned subsystem improvements for parsing form-like documents","authors":["Ayesha Amjad","Saurav Sthapit","Tahir Qasim Syed"],"abstract":"Extracting alphanumeric data from form-like documents such as invoices, purchase orders, bills, and financial documents is often performed via vision (OCR) and learning algorithms or monolithic pipelines with limited potential for systemic improvements. We propose an agentic AI system that leverages Large Language Model (LLM) agents and a reinforcement learning (RL) driver agent to automate consistent, self-improving extraction under LLM inference uncertainty. Our work highlights the limitations of monolithic LLM-based extraction and introduces a modular, multi-agent framework with task-specific prompts and an RL policy of rewards and penalties to guide a meta-prompting agent to learn from past errors and improve prompt-based actor agents. This self-corrective adaptive system handles diverse documents, file formats, layouts, and LLMs, aiming to automate accurate information extraction without the need for human intervention. Results as reported on two benchmark datasets of SOIRE, and CORD, are promising for the agentic AI framework.","published":"2025-05-16T09:46:10Z","updated":"2025-05-16T09:46:10Z","categories":["cs.IR","cs.AI","cs.MA"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2505.13504v1","pdf_url":"https://arxiv.org/pdf/2505.13504v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.10844","versioned_id":"2505.10844v4","title":"Creativity or Brute Force? Using Brainteasers as a Window into the Problem-Solving Abilities of Large Language Models","authors":["Simeng Han","Howard Dai","Stephen Xia","Grant Zhang","Chen Liu","Lichang Chen","Hoang Huy Nguyen","Hongyuan Mei","Jiayuan Mao","R. Thomas McCoy"],"abstract":"Accuracy remains a standard metric for evaluating AI systems, but it offers limited insight into how models arrive at their solutions. In this work, we introduce a benchmark based on brainteasers written in long narrative form to probe more deeply into the types of reasoning strategies that models use. Brainteasers are well-suited for this goal because they can be solved with multiple approaches, such as a few-step solution that uses a creative insight or a longer solution that uses more brute force. We investigate large language models (LLMs) across multiple layers of reasoning, focusing not only on correctness but also on the quality and creativity of their solutions. We investigate many aspects of the reasoning process: (1) semantic parsing of the brainteasers into precise mathematical competition style formats; (2) generating solutions from these mathematical forms; (3) self-correcting solutions based on gold solutions; (4) producing step-by-step sketches of solutions; and (5) making use of hints. We find that LLMs are in many cases able to find creative, insightful solutions to brainteasers, suggesting that they capture some of the capacities needed to solve novel problems in creative ways. Nonetheless, there also remain situations where they rely on brute force despite the availability of more efficient, creative solutions, highlighting a potential direction for improvement in the reasoning abilities of LLMs.","published":"2025-05-16T04:23:34Z","updated":"2025-10-28T21:30:31Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.10844v4","pdf_url":"https://arxiv.org/pdf/2505.10844v4","comment":"NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.10838","versioned_id":"2505.10838v1","title":"LARGO: Latent Adversarial Reflection through Gradient Optimization for Jailbreaking LLMs","authors":["Ran Li","Hao Wang","Chengzhi Mao"],"abstract":"Efficient red-teaming method to uncover vulnerabilities in Large Language Models (LLMs) is crucial. While recent attacks often use LLMs as optimizers, the discrete language space make gradient-based methods struggle. We introduce LARGO (Latent Adversarial Reflection through Gradient Optimization), a novel latent self-reflection attack that reasserts the power of gradient-based optimization for generating fluent jailbreaking prompts. By operating within the LLM's continuous latent space, LARGO first optimizes an adversarial latent vector and then recursively call the same LLM to decode the latent into natural language. This methodology yields a fast, effective, and transferable attack that produces fluent and stealthy prompts. On standard benchmarks like AdvBench and JailbreakBench, LARGO surpasses leading jailbreaking techniques, including AutoDAN, by 44 points in attack success rate. Our findings demonstrate a potent alternative to agentic LLM prompting, highlighting the efficacy of interpreting and attacking LLM internals through gradient optimization.","published":"2025-05-16T04:12:16Z","updated":"2025-05-16T04:12:16Z","categories":["cs.LG","cs.CL","cs.CR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.10838v1","pdf_url":"https://arxiv.org/pdf/2505.10838v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.10554","versioned_id":"2505.10554v2","title":"Beyond 'Aha!': Toward Systematic Meta-Abilities Alignment in Large Reasoning Models","authors":["Zhiyuan Hu","Yibo Wang","Hanze Dong","Yuhui Xu","Amrita Saha","Caiming Xiong","Bryan Hooi","Junnan Li"],"abstract":"Large reasoning models (LRMs) already possess a latent capacity for long chain-of-thought reasoning. Prior work has shown that outcome-based reinforcement learning (RL) can incidentally elicit advanced reasoning behaviors such as self-correction, backtracking, and verification phenomena often referred to as the model's \"aha moment\". However, the timing and consistency of these emergent behaviors remain unpredictable and uncontrollable, limiting the scalability and reliability of LRMs' reasoning capabilities. To address these limitations, we move beyond reliance on prompts and coincidental \"aha moments\". Instead, we explicitly align models with three meta-abilities: deduction, induction, and abduction, using automatically generated, self-verifiable tasks. Our three stage-pipeline individual alignment, parameter-space merging, and domain-specific reinforcement learning, boosting performance by over 10\\% relative to instruction-tuned baselines. Furthermore, domain-specific RL from the aligned checkpoint yields an additional gain in performance ceiling for both 7B and 32B models across math, coding, and science benchmarks, demonstrating that explicit meta-ability alignment offers a scalable and dependable foundation for reasoning. Code is available at: https://github.com/zhiyuanhubj/Meta-Ability-Alignment","published":"2025-05-15T17:58:33Z","updated":"2025-05-27T17:41:22Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.10554v2","pdf_url":"https://arxiv.org/pdf/2505.10554v2","comment":"In Progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.10543","versioned_id":"2505.10543v2","title":"Reasoning Capabilities of Large Language Models on Dynamic Tasks","authors":["Annie Wong","Thomas Bäck","Aske Plaat","Niki van Stein","Anna V. Kononova"],"abstract":"Large language models excel on static benchmarks, but their ability as self-learning agents in dynamic environments remains unclear. We evaluate three prompting strategies: self-reflection, heuristic mutation, and planning across dynamic tasks with open-source models. We find that larger models generally outperform smaller ones, but that strategic prompting can close this performance gap. Second, an overly long prompt can negatively impact smaller models on basic reactive tasks, while larger models show more robust behaviour. Third, advanced prompting techniques primarily benefit smaller models on complex games, but offer less improvement for already high-performing large language models. Yet, we find that advanced reasoning methods yield highly variable outcomes: while capable of significantly improving performance when reasoning and decision-making align, they also introduce instability and can lead to big performance drops. Compared to human performance, our findings reveal little evidence of true emergent reasoning. Instead, large language model performance exhibits persistent limitations in areas like planning and spatial coordination, suggesting that large language models still suffer fundamental shortcomings that may not be fully overcome through self-reflective prompting alone. Reasoning is a multi-faceted task, and while methods like Chain-of-thought improve multi-step reasoning on math word problems, our findings using dynamic benchmarks highlight important shortcomings in general reasoning capabilities, indicating a need to move beyond static benchmarks to capture the complexity of reasoning.","published":"2025-05-15T17:53:47Z","updated":"2025-08-10T18:28:40Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.10543v2","pdf_url":"https://arxiv.org/pdf/2505.10543v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.10320","versioned_id":"2505.10320v3","title":"J1: Incentivizing Thinking in LLM-as-a-Judge via Reinforcement Learning","authors":["Chenxi Whitehouse","Tianlu Wang","Ping Yu","Xian Li","Jason Weston","Ilia Kulikov","Swarnadeep Saha"],"abstract":"The progress of AI is bottlenecked by the quality of evaluation, making powerful LLM-as-a-Judge models a core solution. The efficacy of these judges depends on their chain-of-thought reasoning, creating a critical need for methods that can effectively optimize this reasoning process. In this work, we introduce J1, a reinforcement learning framework for teaching LLM judges to think before making decisions. Our core contribution lies in converting all judgment tasks for non-verifiable and verifiable prompts into a unified format with verifiable rewards, enabling direct optimization of evaluation quality while mitigating positional bias. We then use RL to train thinking-judges at scales of 8B, 32B, and 70B and show that they obtain state-of-the-art performance across multiple benchmarks. In particular, J1-Qwen-32B, our multitasked pointwise and pairwise judge also outperforms o1-mini, o3, and a much larger 671B DeepSeek-R1 on some benchmarks, while only training on synthetic data. Through comprehensive ablations of pairwise, pointwise, and multitask J1 variants, we demonstrate the effectiveness of our approach across seed prompts, reward strategies, and training recipes. Qualitative analysis reveals that J1 develops systematic evaluation strategies, including dynamic criteria generation, reference answer creation, iterative self-correction of initial assessments, and feedback generation for low-quality responses.","published":"2025-05-15T14:05:15Z","updated":"2025-10-13T11:06:51Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.10320v3","pdf_url":"https://arxiv.org/pdf/2505.10320v3","comment":"10 pages, 13 tables, 14 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.09819","versioned_id":"2505.09819v2","title":"Visual Feedback of Pattern Separability Improves Myoelectric Decoding Performance of Upper Limb Prostheses","authors":["Ruichen Yang","György M. Lévay","Christopher L. Hunt","Dániel Czeiner","Megan C. Hodgson","Damini Agarwal","Rahul R. Kaliki","Nitish V. Thakor"],"abstract":"State-of-the-art upper limb myoelectric prostheses often use pattern recognition (PR) control systems that translate electromyography (EMG) signals into desired movements. As prosthesis movement complexity increases, users often struggle to produce sufficiently distinct EMG patterns for reliable classification. Existing training typically involves heuristic, trial-and-error user adjustments to static decoder boundaries. Goal: We introduce the Reviewer, a 3D visual interface projecting EMG signals directly into the decoder's classification space, providing intuitive, real-time insight into PR algorithm behavior. This structured feedback reduces cognitive load and fosters mutual, data-driven adaptation between user-generated EMG patterns and decoder boundaries. Methods: A 10-session study with 12 able-bodied participants compared PR performance after motor-based training and updating using the Reviewer versus conventional virtual arm visualization. Performance was assessed using a Fitts law task that involved the aperture of the cursor and the control of orientation. Results: Participants trained with the Reviewer achieved higher completion rates, reduced overshoot, and improved path efficiency and throughput compared to the standard visualization group. Significance: The Reviewer introduces decoder-informed motor training, facilitating immediate and consistent PR-based myoelectric control improvements. By iteratively refining control through real-time feedback, this approach reduces reliance on trial-and-error recalibration, enabling a more adaptive, self-correcting training framework. Conclusion: The 3D visual feedback significantly improves PR control in novice operators through structured training, enabling feedback-driven adaptation and reducing reliance on extensive heuristic adjustments.","published":"2025-05-14T21:47:28Z","updated":"2025-05-16T02:08:42Z","categories":["cs.HC","cs.CV","cs.LG","eess.SY"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2505.09819v2","pdf_url":"https://arxiv.org/pdf/2505.09819v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.09082","versioned_id":"2505.09082v1","title":"CEC-Zero: Chinese Error Correction Solution Based on LLM","authors":["Sophie Zhang","Zhiming Lin"],"abstract":"Recent advancements in large language models (LLMs) demonstrate exceptional Chinese text processing capabilities, particularly in Chinese Spelling Correction (CSC). While LLMs outperform traditional BERT-based models in accuracy and robustness, challenges persist in reliability and generalization. This paper proposes CEC-Zero, a novel reinforcement learning (RL) framework enabling LLMs to self-correct through autonomous error strategy learning without external supervision. By integrating RL with LLMs' generative power, the method eliminates dependency on annotated data or auxiliary models. Experiments reveal RL-enhanced LLMs achieve industry-viable accuracy and superior cross-domain generalization, offering a scalable solution for reliability optimization in Chinese NLP applications. This breakthrough facilitates LLM deployment in practical Chinese text correction scenarios while establishing a new paradigm for self-improving language models.","published":"2025-05-14T02:35:47Z","updated":"2025-05-14T02:35:47Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.09082v1","pdf_url":"https://arxiv.org/pdf/2505.09082v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.08783","versioned_id":"2505.08783v2","title":"CodePDE: An Inference Framework for LLM-driven PDE Solver Generation","authors":["Shanda Li","Tanya Marwah","Junhong Shen","Weiwei Sun","Andrej Risteski","Yiming Yang","Ameet Talwalkar"],"abstract":"Partial differential equations (PDEs) are fundamental to modeling physical systems, yet solving them remains a complex challenge. Traditional numerical solvers rely on expert knowledge to implement and are computationally expensive, while neural-network-based solvers require large training datasets and often lack interpretability. In this work, we frame PDE solving as a code generation task and introduce CodePDE, the first inference framework for generating PDE solvers using large language models (LLMs). With CodePDE, we present a thorough evaluation on critical capacities of LLM for PDE solving: reasoning, debugging, self-refinement, and test-time scaling. CodePDE shows that, with advanced inference-time algorithms and scaling strategies, LLMs can achieve strong performance across a range of representative PDE problems. We also identify novel insights into LLM-driven solver generation, such as trade-offs between solver reliability and sophistication, design principles for LLM-powered PDE solving agents, and failure modes for LLM on hard tasks. These insights offer guidance for building more capable and reliable LLM-based scientific engines.","published":"2025-05-13T17:58:08Z","updated":"2026-02-22T19:11:40Z","categories":["cs.LG","cs.AI","cs.CL","math.NA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.08783v2","pdf_url":"https://arxiv.org/pdf/2505.08783v2","comment":"TMLR. Code available at https://github.com/LithiumDA/CodePDE","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.08827","versioned_id":"2505.08827v2","title":"RLSR: Reinforcement Learning from Self Reward","authors":["Toby Simonds","Kevin Lopez","Akira Yoshiyama","Dominique Garmier"],"abstract":"Large language models can generate solutions to complex problems, but training them with reinforcement learning typically requires verifiable rewards that are expensive to create and not possible for all domains. We demonstrate that LLMs can effectively self-improve through self-judging without reference solutions, leveraging the inherent asymmetry between generating and verifying solutions. Our experiments show that models can provide reliable reward signals without ground truth answers, enabling reinforcement learning in domains where verifiable rewards are impractical. By implementing self-judging across Countdown puzzles and integration problems, we achieve performance comparable to formal verification without ground truth solutions. Most notably, Qwen 2.5 7B DeepSeek Distilled trained with self-rewards qualifies for the prestigious MIT Integration Bee competition, performance through self-supervised improvement. When combined with synthetic question generation, we establish a complete self-improvement loop where models generate practice problems, solve them, and evaluate their own performance without any external validation. Our findings demonstrate that LLM judges can provide effective reward signals for training, unlocking reinforcement learning in countless domains previously limited by reward engineering challenges. This work represents a significant step toward autonomous AI systems that continuously improve through self-directed learning rather than human-guided training, potentially accelerating progress across domains where training data is scarce or evaluation is complex.","published":"2025-05-12T23:51:04Z","updated":"2025-08-06T23:51:16Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.08827v2","pdf_url":"https://arxiv.org/pdf/2505.08827v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.08078","versioned_id":"2505.08078v1","title":"What Matters for Batch Online Reinforcement Learning in Robotics?","authors":["Perry Dong","Suvir Mirchandani","Dorsa Sadigh","Chelsea Finn"],"abstract":"The ability to learn from large batches of autonomously collected data for policy improvement -- a paradigm we refer to as batch online reinforcement learning -- holds the promise of enabling truly scalable robot learning by significantly reducing the need for human effort of data collection while getting benefits from self-improvement. Yet, despite the promise of this paradigm, it remains challenging to achieve due to algorithms not being able to learn effectively from the autonomous data. For example, prior works have applied imitation learning and filtered imitation learning methods to the batch online RL problem, but these algorithms often fail to efficiently improve from the autonomously collected data or converge quickly to a suboptimal point. This raises the question of what matters for effective batch online RL in robotics. Motivated by this question, we perform a systematic empirical study of three axes -- (i) algorithm class, (ii) policy extraction methods, and (iii) policy expressivity -- and analyze how these axes affect performance and scaling with the amount of autonomous data. Through our analysis, we make several observations. First, we observe that the use of Q-functions to guide batch online RL significantly improves performance over imitation-based methods. Building on this, we show that an implicit method of policy extraction -- via choosing the best action in the distribution of the policy -- is necessary over traditional policy extraction methods from offline RL. Next, we show that an expressive policy class is preferred over less expressive policy classes. Based on this analysis, we propose a general recipe for effective batch online RL. We then show a simple addition to the recipe of using temporally-correlated noise to obtain more diversity results in further performance gains. Our recipe obtains significantly better performance and scaling compared to prior methods.","published":"2025-05-12T21:24:22Z","updated":"2025-05-12T21:24:22Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2505.08078v1","pdf_url":"https://arxiv.org/pdf/2505.08078v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.07787","versioned_id":"2505.07787v1","title":"Learning from Peers in Reasoning Models","authors":["Tongxu Luo","Wenyu Du","Jiaxi Bi","Stephen Chung","Zhengyang Tang","Hao Yang","Min Zhang","Benyou Wang"],"abstract":"Large Reasoning Models (LRMs) have the ability to self-correct even when they make mistakes in their reasoning paths. However, our study reveals that when the reasoning process starts with a short but poor beginning, it becomes difficult for the model to recover. We refer to this phenomenon as the \"Prefix Dominance Trap\". Inspired by psychological findings that peer interaction can promote self-correction without negatively impacting already accurate individuals, we propose **Learning from Peers** (LeaP) to address this phenomenon. Specifically, every tokens, each reasoning path summarizes its intermediate reasoning and shares it with others through a routing mechanism, enabling paths to incorporate peer insights during inference. However, we observe that smaller models sometimes fail to follow summarization and reflection instructions effectively. To address this, we fine-tune them into our **LeaP-T** model series. Experiments on AIME 2024, AIME 2025, AIMO 2025, and GPQA Diamond show that LeaP provides substantial improvements. For instance, QwQ-32B with LeaP achieves nearly 5 absolute points higher than the baseline on average, and surpasses DeepSeek-R1-671B on three math benchmarks with an average gain of 3.3 points. Notably, our fine-tuned LeaP-T-7B matches the performance of DeepSeek-R1-Distill-Qwen-14B on AIME 2024. In-depth analysis reveals LeaP's robust error correction by timely peer insights, showing strong error tolerance and handling varied task difficulty. LeaP marks a milestone by enabling LRMs to collaborate during reasoning. Our code, datasets, and models are available at https://learning-from-peers.github.io/ .","published":"2025-05-12T17:39:56Z","updated":"2025-05-12T17:39:56Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.07787v1","pdf_url":"https://arxiv.org/pdf/2505.07787v1","comment":"29 pages, 32 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.07757","versioned_id":"2505.07757v2","title":"Emotion-Gradient Metacognitive RSI (Part I): Theoretical Foundations and Single-Agent Architecture","authors":["Rintaro Ando"],"abstract":"We present the Emotion-Gradient Metacognitive Recursive Self-Improvement (EG-MRSI) framework, a novel architecture that integrates introspective metacognition, emotion-based intrinsic motivation, and recursive self-modification into a unified theoretical system. The framework is explicitly capable of overwriting its own learning algorithm under formally bounded risk. Building upon the Noise-to-Meaning RSI (N2M-RSI) foundation, EG-MRSI introduces a differentiable intrinsic reward function driven by confidence, error, novelty, and cumulative success. This signal regulates both a metacognitive mapping and a self-modification operator constrained by provable safety mechanisms. We formally define the initial agent configuration, emotion-gradient dynamics, and RSI trigger conditions, and derive a reinforcement-compatible optimization objective that guides the agent's development trajectory. Meaning Density and Meaning Conversion Efficiency are introduced as quantifiable metrics of semantic learning, closing the gap between internal structure and predictive informativeness. This Part I paper establishes the single-agent theoretical foundations of EG-MRSI. Future parts will extend this framework to include safety certificates and rollback protocols (Part II), collective intelligence mechanisms (Part III), and feasibility constraints including thermodynamic and computational limits (Part IV). Together, the EG-MRSI series provides a rigorous, extensible foundation for open-ended and safe AGI.","published":"2025-05-12T17:02:47Z","updated":"2026-03-04T12:15:01Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.07757v2","pdf_url":"https://arxiv.org/pdf/2505.07757v2","comment":"Withdrawn due to a critical error discovered in the stability and convergence proofs (specifically Lemma 2, Theorem 12, and Proposition 10) in Section 3. The identified flaw invalidates the core theoretical guarantees regarding capability growth and system stability","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.07512","versioned_id":"2505.07512v1","title":"ToolACE-DEV: Self-Improving Tool Learning via Decomposition and EVolution","authors":["Xu Huang","Weiwen Liu","Xingshan Zeng","Yuefeng Huang","Xinlong Hao","Yuxian Wang","Yirong Zeng","Chuhan Wu","Yasheng Wang","Ruiming Tang","Defu Lian"],"abstract":"The tool-using capability of large language models (LLMs) enables them to access up-to-date external information and handle complex tasks. Current approaches to enhancing this capability primarily rely on distilling advanced models by data synthesis. However, this method incurs significant costs associated with advanced model usage and often results in data compatibility issues, led by the high discrepancy in the knowledge scope between the advanced model and the target model. To address these challenges, we propose ToolACE-DEV, a self-improving framework for tool learning. First, we decompose the tool-learning objective into sub-tasks that enhance basic tool-making and tool-using abilities. Then, we introduce a self-evolving paradigm that allows lightweight models to self-improve, reducing reliance on advanced LLMs. Extensive experiments validate the effectiveness of our approach across models of varying scales and architectures.","published":"2025-05-12T12:48:30Z","updated":"2025-05-12T12:48:30Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.07512v1","pdf_url":"https://arxiv.org/pdf/2505.07512v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.07261","versioned_id":"2505.07261v3","title":"CHD: Coupled Hierarchical Diffusion for Long-Horizon Tasks","authors":["Ce Hao","Anxing Xiao","Zhiwei Xue","Harold Soh"],"abstract":"Diffusion-based planners have shown strong performance in short-horizon tasks but often fail in complex, long-horizon settings. We trace the failure to loose coupling between high-level (HL) sub-goal selection and low-level (LL) trajectory generation, which leads to incoherent plans and degraded performance. We propose Coupled Hierarchical Diffusion (CHD), a framework that models HL sub-goals and LL trajectories jointly within a unified diffusion process. A shared classifier passes LL feedback upstream so that sub-goals self-correct while sampling proceeds. This tight HL-LL coupling improves trajectory coherence and enables scalable long-horizon diffusion planning. Experiments across maze navigation, tabletop manipulation, and household environments show that CHD consistently outperforms both flat and hierarchical diffusion baselines. Our website is: https://sites.google.com/view/chd2025/home","published":"2025-05-12T06:21:48Z","updated":"2025-10-12T04:52:00Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2505.07261v3","pdf_url":"https://arxiv.org/pdf/2505.07261v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.07184","versioned_id":"2505.07184v1","title":"Structural Entropy Guided Agent for Detecting and Repairing Knowledge Deficiencies in LLMs","authors":["Yifan Wei","Xiaoyan Yu","Tengfei Pan","Angsheng Li","Li Du"],"abstract":"Large language models (LLMs) have achieved unprecedented performance by leveraging vast pretraining corpora, yet their performance remains suboptimal in knowledge-intensive domains such as medicine and scientific research, where high factual precision is required. While synthetic data provides a promising avenue for augmenting domain knowledge, existing methods frequently generate redundant samples that do not align with the model's true knowledge gaps. To overcome this limitation, we propose a novel Structural Entropy-guided Knowledge Navigator (SENATOR) framework that addresses the intrinsic knowledge deficiencies of LLMs. Our approach employs the Structure Entropy (SE) metric to quantify uncertainty along knowledge graph paths and leverages Monte Carlo Tree Search (MCTS) to selectively explore regions where the model lacks domain-specific knowledge. Guided by these insights, the framework generates targeted synthetic data for supervised fine-tuning, enabling continuous self-improvement. Experimental results on LLaMA-3 and Qwen2 across multiple domain-specific benchmarks show that SENATOR effectively detects and repairs knowledge deficiencies, achieving notable performance improvements. The code and data for our methods and experiments are available at https://github.com/weiyifan1023/senator.","published":"2025-05-12T02:21:36Z","updated":"2025-05-12T02:21:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.07184v1","pdf_url":"https://arxiv.org/pdf/2505.07184v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.07089","versioned_id":"2505.07089v3","title":"RefPentester: A Knowledge-Informed Self-Reflective Penetration Testing Framework Based on Large Language Models","authors":["Hanzheng Dai","Yuanliang Li","Jun Yan","Zhibo Zhang"],"abstract":"Automated penetration testing (AutoPT) powered by large language models (LLMs) has gained attention for its ability to automate ethical hacking processes and identify vulnerabilities in target systems by leveraging the inherent knowledge of LLMs. However, existing LLM-based AutoPT frameworks often underperform compared to human experts in challenging tasks for several reasons: the imbalanced knowledge used in LLM training, short-sightedness in the planning process, and hallucinations during command generation. Moreover, the trial-and-error nature of the PT process is constrained by existing frameworks lacking mechanisms to learn from previous failures, restricting adaptive improvement of PT strategies. To address these limitations, we propose a knowledge-informed, self-reflective PT framework powered by LLMs, called RefPentester. This AutoPT framework is designed to assist human operators in identifying the current stage of the PT process, selecting appropriate tactics and techniques for each stage, choosing suggested actions, providing step-by-step operational guidance, and reflecting on and learning from previous failed operations. We also modeled the PT process as a seven-state Stage Machine to integrate the proposed framework effectively. The evaluation shows that RefPentester can successfully reveal credentials on Hack The Box's Sau machine, outperforming the baseline GPT-4o model by 16.7%. Across PT stages, RefPentester also demonstrates superior success rates on PT stage transitions.","published":"2025-05-11T18:38:00Z","updated":"2025-06-25T14:14:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.07089v3","pdf_url":"https://arxiv.org/pdf/2505.07089v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.06987","versioned_id":"2505.06987v6","title":"Convert Language Model into a Value-based Strategic Planner","authors":["Xiaoyu Wang","Yue Zhao","Qingqing Gu","Zhonglin Jiang","Xiaokai Chen","Yong Chen","Luo Ji"],"abstract":"Emotional support conversation (ESC) aims to alleviate the emotional distress of individuals through effective conversations. Although large language models (LLMs) have obtained remarkable progress on ESC, most of these studies might not define the diagram from the state model perspective, therefore providing a suboptimal solution for long-term satisfaction. To address such an issue, we leverage the Q-learning on LLMs, and propose a framework called straQ*. Our framework allows a plug-and-play LLM to bootstrap the planning during ESC, determine the optimal strategy based on long-term returns, and finally guide the LLM to response. Substantial experiments on ESC datasets suggest that straQ* outperforms many baselines, including direct inference, self-refine, chain of thought, finetuning, and finite state machines.","published":"2025-05-11T14:13:58Z","updated":"2025-08-27T08:21:50Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.06987v6","pdf_url":"https://arxiv.org/pdf/2505.06987v6","comment":"13 pages, 6 figures, ACL 2025 Industry Track","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.08803","versioned_id":"2505.08803v1","title":"Multi-modal Synthetic Data Training and Model Collapse: Insights from VLMs and Diffusion Models","authors":["Zizhao Hu","Mohammad Rostami","Jesse Thomason"],"abstract":"Recent research has highlighted the risk of generative model collapse, where performance progressively degrades when continually trained on self-generated data. However, existing exploration on model collapse is limited to single, unimodal models, limiting our understanding in more realistic scenarios, such as diverse multi-modal AI agents interacting autonomously through synthetic data and continually evolving. We expand the synthetic data training and model collapse study to multi-modal vision-language generative systems, such as vision-language models (VLMs) and text-to-image diffusion models, as well as recursive generate-train loops with multiple models. We find that model collapse, previously observed in single-modality generative models, exhibits distinct characteristics in the multi-modal context, such as improved vision-language alignment and increased variance in VLM image-captioning task. Additionally, we find that general approaches such as increased decoding budgets, greater model diversity, and relabeling with frozen models can effectively mitigate model collapse. Our findings provide initial insights and practical guidelines for reducing the risk of model collapse in self-improving multi-agent AI systems and curating robust multi-modal synthetic datasets.","published":"2025-05-10T22:42:29Z","updated":"2025-05-10T22:42:29Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.08803v1","pdf_url":"https://arxiv.org/pdf/2505.08803v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.06178","versioned_id":"2505.06178v2","title":"A Large Language Model-Enhanced Q-learning for Capacitated Vehicle Routing Problem with Time Windows","authors":["Linjiang Cao","Maonan Wang","Xi Xiong"],"abstract":"The Capacitated Vehicle Routing Problem with Time Windows (CVRPTW) is a classic NP-hard combinatorial optimization problem widely applied in logistics distribution and transportation management. Its complexity stems from the constraints of vehicle capacity and time windows, which pose significant challenges to traditional approaches. Advances in Large Language Models (LLMs) provide new possibilities for finding approximate solutions to CVRPTW. This paper proposes a novel LLM-enhanced Q-learning framework to address the CVRPTW with real-time emergency constraints. Our solution introduces an adaptive two-phase training mechanism that transitions from the LLM-guided exploration phase to the autonomous optimization phase of Q-network. To ensure reliability, we design a three-tier self-correction mechanism based on the Chain-of-Thought (CoT) for LLMs: syntactic validation, semantic verification, and physical constraint enforcement. In addition, we also prioritized replay of the experience generated by LLMs to amplify the regulatory role of LLMs in the architecture. Experimental results demonstrate that our framework achieves a 7.3\\% average reduction in cost compared to traditional Q-learning, with fewer training steps required for convergence.","published":"2025-05-09T16:45:43Z","updated":"2025-07-21T02:53:14Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.06178v2","pdf_url":"https://arxiv.org/pdf/2505.06178v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.05145","versioned_id":"2505.05145v3","title":"Understanding In-context Learning of Addition via Activation Subspaces","authors":["Xinyan Hu","Kayo Yin","Michael I. Jordan","Jacob Steinhardt","Lijie Chen"],"abstract":"To perform few-shot learning, language models extract signals from a few input-label pairs, aggregate these into a learned prediction rule, and apply this rule to new inputs. How is this implemented in the forward pass of modern transformer models? To explore this question, we study a structured family of few-shot learning tasks for which the true prediction rule is to add an integer $k$ to the input. We introduce a novel optimization method that localizes the model's few-shot ability to only a few attention heads. We then perform an in-depth analysis of individual heads, via dimensionality reduction and decomposition. As an example, on Llama-3-8B-instruct, we reduce its mechanism on our tasks to just three attention heads with six-dimensional subspaces, where four dimensions track the unit digit with trigonometric functions at periods $2$, $5$, and $10$, and two dimensions track magnitude with low-frequency components. To deepen our understanding of the mechanism, we also derive a mathematical identity relating ``aggregation'' and ``extraction'' subspaces for attention heads, allowing us to track the flow of information from individual examples to a final aggregated concept. Using this, we identify a self-correction mechanism where mistakes learned from earlier demonstrations are suppressed by later demonstrations. Our results demonstrate how tracking low-dimensional subspaces of localized heads across a forward pass can provide insight into fine-grained computational structures in language models.","published":"2025-05-08T11:32:46Z","updated":"2025-10-09T17:58:05Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.05145v3","pdf_url":"https://arxiv.org/pdf/2505.05145v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.04966","versioned_id":"2505.04966v1","title":"Position: The AI Conference Peer Review Crisis Demands Author Feedback and Reviewer Rewards","authors":["Jaeho Kim","Yunseok Lee","Seulki Lee"],"abstract":"The peer review process in major artificial intelligence (AI) conferences faces unprecedented challenges with the surge of paper submissions (exceeding 10,000 submissions per venue), accompanied by growing concerns over review quality and reviewer responsibility. This position paper argues for the need to transform the traditional one-way review system into a bi-directional feedback loop where authors evaluate review quality and reviewers earn formal accreditation, creating an accountability framework that promotes a sustainable, high-quality peer review system. The current review system can be viewed as an interaction between three parties: the authors, reviewers, and system (i.e., conference), where we posit that all three parties share responsibility for the current problems. However, issues with authors can only be addressed through policy enforcement and detection tools, and ethical concerns can only be corrected through self-reflection. As such, this paper focuses on reforming reviewer accountability with systematic rewards through two key mechanisms: (1) a two-stage bi-directional review system that allows authors to evaluate reviews while minimizing retaliatory behavior, (2)a systematic reviewer reward system that incentivizes quality reviewing. We ask for the community's strong interest in these problems and the reforms that are needed to enhance the peer review process.","published":"2025-05-08T05:51:48Z","updated":"2025-05-08T05:51:48Z","categories":["cs.AI","cs.CY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.04966v1","pdf_url":"https://arxiv.org/pdf/2505.04966v1","comment":"ICML2025 Position Track Oral","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.03181","versioned_id":"2505.03181v1","title":"VLM Q-Learning: Aligning Vision-Language Models for Interactive Decision-Making","authors":["Jake Grigsby","Yuke Zhu","Michael Ryoo","Juan Carlos Niebles"],"abstract":"Recent research looks to harness the general knowledge and reasoning of large language models (LLMs) into agents that accomplish user-specified goals in interactive environments. Vision-language models (VLMs) extend LLMs to multi-modal data and provide agents with the visual reasoning necessary for new applications in areas such as computer automation. However, agent tasks emphasize skills where accessible open-weight VLMs lag behind their LLM equivalents. For example, VLMs are less capable of following an environment's strict output syntax requirements and are more focused on open-ended question answering. Overcoming these limitations requires supervised fine-tuning (SFT) on task-specific expert demonstrations. Our work approaches these challenges from an offline-to-online reinforcement learning (RL) perspective. RL lets us fine-tune VLMs to agent tasks while learning from the unsuccessful decisions of our own model or more capable (larger) models. We explore an off-policy RL solution that retains the stability and simplicity of the widely used SFT workflow while allowing our agent to self-improve and learn from low-quality datasets. We demonstrate this technique with two open-weight VLMs across three multi-modal agent domains.","published":"2025-05-06T04:51:57Z","updated":"2025-05-06T04:51:57Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.03181v1","pdf_url":"https://arxiv.org/pdf/2505.03181v1","comment":"SSI-FM Workshop ICLR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.03059","versioned_id":"2505.03059v1","title":"Improving Model Alignment Through Collective Intelligence of Open-Source LLMS","authors":["Junlin Wang","Roy Xie","Shang Zhu","Jue Wang","Ben Athiwaratkun","Bhuwan Dhingra","Shuaiwen Leon Song","Ce Zhang","James Zou"],"abstract":"Building helpful and harmless large language models (LLMs) requires effective model alignment approach based on human instructions and feedback, which necessitates high-quality human-labeled data. Constructing such datasets is often expensive and hard to scale, and may face potential limitations on diversity and generalization. To address these challenges, we introduce Mixture of Agents Alignment (MoAA), that leverages the collective strengths of various language models to provide high-quality data for model alignment. By employing MoAA, we enhance both supervised fine-tuning and preference optimization, leading to improved performance compared to using a single model alone to generate alignment data (e.g. using GPT-4o alone). Evaluation results show that our approach can improve win rate of LLaMA-3.1-8B-Instruct from 19.5 to 48.3 on Arena-Hard and from 22.33 to 57.23 on AlpacaEval2, highlighting a promising direction for model alignment through this new scalable and diverse synthetic data recipe. Furthermore, we demonstrate that MoAA enables a self-improvement pipeline, where models finetuned on MoA-generated data surpass their own initial capabilities, providing evidence that our approach can push the frontier of open-source LLMs without reliance on stronger external supervision. Data and code will be released.","published":"2025-05-05T22:40:23Z","updated":"2025-05-05T22:40:23Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.03059v1","pdf_url":"https://arxiv.org/pdf/2505.03059v1","comment":"ICML 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.02888","versioned_id":"2505.02888v2","title":"When Your Own Output Becomes Your Training Data: Noise-to-Meaning Loops and a Formal RSI Trigger","authors":["Rintaro Ando"],"abstract":"We present Noise-to-Meaning Recursive Self-Improvement (N2M-RSI), a minimal formal model showing that once an AI agent feeds its own outputs back as inputs and crosses an explicit information-integration threshold, its internal complexity will grow without bound under our assumptions. The framework unifies earlier ideas on self-prompting large language models, Gödelian self-reference, and AutoML, yet remains implementation-agnostic. The model furthermore scales naturally to interacting swarms of agents, hinting at super-linear effects once communication among instances is permitted. For safety reasons, we omit system-specific implementation details and release only a brief, model-agnostic toy prototype in Appendix C.","published":"2025-05-05T17:03:07Z","updated":"2026-03-04T12:27:29Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.02888v2","pdf_url":"https://arxiv.org/pdf/2505.02888v2","comment":"Withdrawn due to a critical error discovered in the mathematical derivation and proof of Theorem 2 (Unbounded Growth) and related Lemma 2 (Compression gain lower bound). This flaw invalidates the paper's main conclusion that N2M-RSI guarantees unbounded growth, requiring a fundamental revision of the theoretical framework","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.02184","versioned_id":"2505.02184v3","title":"Leveraging LLMs to Automate Energy-Aware Refactoring of Parallel Scientific Codes","authors":["Matthew T. Dearing","Yiheng Tao","Xingfu Wu","Zhiling Lan","Valerie Taylor"],"abstract":"Large language models (LLMs) are increasingly used for generating parallel scientific codes, with a primary focus on generating functionally correct code. Recent work has focused on generating performant code, with an emphasis on its execution time. However, energy efficiency is now recognized as a critical objective, given the significant power demands of large-scale compute systems. This paper addresses the research question of whether LLMs can generate energy-efficient parallel scientific codes when guided by empirical execution feedback. To answer this question, we propose LASSI-EE, an automated LLM-based refactoring framework that generates energy-efficient parallel codes through a multi-stage, iterative approach integrating runtime power profiling, energy-aware prompting, self-correcting feedback loops, and an LLM-as-a-Judge agent for screening generated code. We evaluate LASSI-EE using twenty-two representative scientific benchmarks and applications on NVIDIA A100 and AMD MI100 GPUs. The results indicate an average energy reduction of 36% for MI100 and 34% for A100, across trials that produced passing energy-reducing refactorings.","published":"2025-05-04T17:05:34Z","updated":"2026-05-09T19:15:29Z","categories":["cs.AI","cs.DC","cs.PL","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.02184v3","pdf_url":"https://arxiv.org/pdf/2505.02184v3","comment":"12 pages, 5 figures, version under review at a peer-reviewed conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.01980","versioned_id":"2505.01980v1","title":"LLM-based Text Simplification and its Effect on User Comprehension and Cognitive Load","authors":["Theo Guidroz","Diego Ardila","Jimmy Li","Adam Mansour","Paul Jhun","Nina Gonzalez","Xiang Ji","Mike Sanchez","Sujay Kakarmath","Mathias MJ Bellaiche","Miguel Ángel Garrido","Faruk Ahmed","Divyansh Choudhary","Jay Hartford","Chenwei Xu","Henry Javier Serrano Echeverria","Yifan Wang","Jeff Shaffer","Eric","Cao","Yossi Matias","Avinatan Hassidim","Dale R Webster","Yun Liu","Sho Fujiwara","Peggy Bui","Quang Duong"],"abstract":"Information on the web, such as scientific publications and Wikipedia, often surpasses users' reading level. To help address this, we used a self-refinement approach to develop a LLM capability for minimally lossy text simplification. To validate our approach, we conducted a randomized study involving 4563 participants and 31 texts spanning 6 broad subject areas: PubMed (biomedical scientific articles), biology, law, finance, literature/philosophy, and aerospace/computer science. Participants were randomized to viewing original or simplified texts in a subject area, and answered multiple-choice questions (MCQs) that tested their comprehension of the text. The participants were also asked to provide qualitative feedback such as task difficulty. Our results indicate that participants who read the simplified text answered more MCQs correctly than their counterparts who read the original text (3.9% absolute increase, p<0.05). This gain was most striking with PubMed (14.6%), while more moderate gains were observed for finance (5.5%), aerospace/computer science (3.8%) domains, and legal (3.5%). Notably, the results were robust to whether participants could refer back to the text while answering MCQs. The absolute accuracy decreased by up to ~9% for both original and simplified setups where participants could not refer back to the text, but the ~4% overall improvement persisted. Finally, participants' self-reported perceived ease based on a simplified NASA Task Load Index was greater for those who read the simplified text (absolute change on a 5-point scale 0.33, p<0.05). This randomized study, involving an order of magnitude more participants than prior works, demonstrates the potential of LLMs to make complex information easier to understand. Our work aims to enable a broader audience to better learn and make use of expert knowledge available on the web, improving information accessibility.","published":"2025-05-04T04:00:53Z","updated":"2025-05-04T04:00:53Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.01980v1","pdf_url":"https://arxiv.org/pdf/2505.01980v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.01636","versioned_id":"2505.01636v1","title":"Structured Prompting and Feedback-Guided Reasoning with LLMs for Data Interpretation","authors":["Amit Rath"],"abstract":"Large language models (LLMs) have demonstrated remarkable capabilities in natural language understanding and task generalization. However, their application to structured data analysis remains fragile due to inconsistencies in schema interpretation, misalignment between user intent and model output, and limited mechanisms for self-correction when failures occur. This paper introduces the STROT Framework (Structured Task Reasoning and Output Transformation), a method for structured prompting and feedback-driven transformation logic generation aimed at improving the reliability and semantic alignment of LLM-based analytical workflows. STROT begins with lightweight schema introspection and sample-based field classification, enabling dynamic context construction that captures both the structure and statistical profile of the input data. This contextual information is embedded in structured prompts that guide the model toward generating task-specific, interpretable outputs. To address common failure modes in complex queries, STROT incorporates a refinement mechanism in which the model iteratively revises its outputs based on execution feedback and validation signals. Unlike conventional approaches that rely on static prompts or single-shot inference, STROT treats the LLM as a reasoning agent embedded within a controlled analysis loop -- capable of adjusting its output trajectory through planning and correction. The result is a robust and reproducible framework for reasoning over structured data with LLMs, applicable to diverse data exploration and analysis tasks where interpretability, stability, and correctness are essential.","published":"2025-05-03T00:05:01Z","updated":"2025-05-03T00:05:01Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.01636v1","pdf_url":"https://arxiv.org/pdf/2505.01636v1","comment":"21 pages, 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.01396","versioned_id":"2505.01396v1","title":"SIME: Enhancing Policy Self-Improvement with Modal-level Exploration","authors":["Yang Jin","Jun Lv","Wenye Yu","Hongjie Fang","Yong-Lu Li","Cewu Lu"],"abstract":"Self-improvement requires robotic systems to initially learn from human-provided data and then gradually enhance their capabilities through interaction with the environment. This is similar to how humans improve their skills through continuous practice. However, achieving effective self-improvement is challenging, primarily because robots tend to repeat their existing abilities during interactions, often failing to generate new, valuable data for learning. In this paper, we identify the key to successful self-improvement: modal-level exploration and data selection. By incorporating a modal-level exploration mechanism during policy execution, the robot can produce more diverse and multi-modal interactions. At the same time, we select the most valuable trials and high-quality segments from these interactions for learning. We successfully demonstrate effective robot self-improvement on both simulation benchmarks and real-world experiments. The capability for self-improvement will enable us to develop more robust and high-success-rate robotic control strategies at a lower cost. Our code and experiment scripts are available at https://ericjin2002.github.io/SIME/","published":"2025-05-02T17:13:03Z","updated":"2025-05-02T17:13:03Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2505.01396v1","pdf_url":"https://arxiv.org/pdf/2505.01396v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.21625","versioned_id":"2504.21625v6","title":"Meeseeks: A Feedback-Driven, Iterative Self-Correction Benchmark evaluating LLMs' Instruction Following Capability","authors":["Jiaming wang","Yunke Zhao","Peng Ding","Jun Kuang","Yibin Shen","Zhe Tang","Yilin Jin","ZongYu Wang","Xiaoyu Li","Xuezhi Cao","Xunliang Cai"],"abstract":"The capability to precisely adhere to instructions is a cornerstone for Large Language Models (LLMs) to function as dependable agents in real-world scenarios. However, confronted with complex prompts, LLMs frequently encounter difficulties in fulfilling all specified requirements within a single response. Drawing inspiration from recent advancements in Chain-of-Thought (CoT) prompting and self-correction methodologies, we introduce Meeseeks (The name is inspired by Mr. Meeseeks from \"Rick and Morty,\" a character renowned for efficiently accomplishing assigned tasks. See: https://en.wikipedia.org/wiki/Mr._Meeseeks), a fully automated iterative instruction-following benchmark equipped with an integrated feedback mechanism. Meeseeks identifies erroneous components in model responses and provides corresponding feedback accurately, thereby iteratively guiding the model toward self-correction. The dataset contains over 700 curated instances annotated by 32 distinct capability tags in Chinese and English. Extensive experimental results reveal that different state-of-the-art commercial and open-source LLMs exhibit vastly disparate performance, and even after 20 turns of iterative feedback-driven self-correction, nearly all models demonstrate suboptimal performance. We conducted comprehensive analysis from both macro and instance levels, uncovering numerous common issues prevalent in current state-of-the-art models, as well as several counterintuitive phenomena. We've open-sourced our work on https://github.com/ADoublLEN/Meeseeks.","published":"2025-04-30T13:28:19Z","updated":"2025-10-22T07:50:08Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.21625v6","pdf_url":"https://arxiv.org/pdf/2504.21625v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.20965","versioned_id":"2504.20965v2","title":"AegisLLM: Scaling Agentic Systems for Self-Reflective Defense in LLM Security","authors":["Zikui Cai","Shayan Shabihi","Bang An","Zora Che","Brian R. Bartoldson","Bhavya Kailkhura","Tom Goldstein","Furong Huang"],"abstract":"We introduce AegisLLM, a cooperative multi-agent defense against adversarial attacks and information leakage. In AegisLLM, a structured workflow of autonomous agents - orchestrator, deflector, responder, and evaluator - collaborate to ensure safe and compliant LLM outputs, while self-improving over time through prompt optimization. We show that scaling agentic reasoning system at test-time - both by incorporating additional agent roles and by leveraging automated prompt optimization (such as DSPy)- substantially enhances robustness without compromising model utility. This test-time defense enables real-time adaptability to evolving attacks, without requiring model retraining. Comprehensive evaluations across key threat scenarios, including unlearning and jailbreaking, demonstrate the effectiveness of AegisLLM. On the WMDP unlearning benchmark, AegisLLM achieves near-perfect unlearning with only 20 training examples and fewer than 300 LM calls. For jailbreaking benchmarks, we achieve 51% improvement compared to the base model on StrongReject, with false refusal rates of only 7.9% on PHTest compared to 18-55% for comparable methods. Our results highlight the advantages of adaptive, agentic reasoning over static defenses, establishing AegisLLM as a strong runtime alternative to traditional approaches based on model modifications. Code is available at https://github.com/zikuicai/aegisllm","published":"2025-04-29T17:36:05Z","updated":"2025-06-13T22:43:06Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.20965v2","pdf_url":"https://arxiv.org/pdf/2504.20965v2","comment":"ICLR 2025 Workshop BuildingTrust","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.20571","versioned_id":"2504.20571v3","title":"Reinforcement Learning for Reasoning in Large Language Models with One Training Example","authors":["Yiping Wang","Qing Yang","Zhiyuan Zeng","Liliang Ren","Liyuan Liu","Baolin Peng","Hao Cheng","Xuehai He","Kuan Wang","Jianfeng Gao","Weizhu Chen","Shuohang Wang","Simon Shaolei Du","Yelong Shen"],"abstract":"We show that reinforcement learning with verifiable reward using one training example (1-shot RLVR) is effective in incentivizing the math reasoning capabilities of large language models (LLMs). Applying RLVR to the base model Qwen2.5-Math-1.5B, we identify a single example that elevates model performance on MATH500 from 36.0% to 73.6% (8.6% improvement beyond format correction), and improves the average performance across six common mathematical reasoning benchmarks from 17.6% to 35.7% (7.0% non-format gain). This result matches the performance obtained using the 1.2k DeepScaleR subset (MATH500: 73.6%, average: 35.9%), which contains the aforementioned example. Furthermore, RLVR with only two examples even slightly exceeds these results (MATH500: 74.8%, average: 36.6%). Similar substantial improvements are observed across various models (Qwen2.5-Math-7B, Llama3.2-3B-Instruct, DeepSeek-R1-Distill-Qwen-1.5B), RL algorithms (GRPO and PPO), and different math examples. In addition, we identify some interesting phenomena during 1-shot RLVR, including cross-category generalization, increased frequency of self-reflection, and sustained test performance improvement even after the training accuracy has saturated, a phenomenon we term post-saturation generalization. Moreover, we verify that the effectiveness of 1-shot RLVR primarily arises from the policy gradient loss, distinguishing it from the \"grokking\" phenomenon. We also show the critical role of promoting exploration (e.g., by incorporating entropy loss with an appropriate coefficient) in 1-shot RLVR training. We also further discuss related observations about format correction, label robustness and prompt modification. These findings can inspire future work on RLVR efficiency and encourage a re-examination of recent progress and the underlying mechanisms in RLVR. All resources are open source at https://github.com/ypwang61/One-Shot-RLVR.","published":"2025-04-29T09:24:30Z","updated":"2025-10-24T10:02:36Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.20571v3","pdf_url":"https://arxiv.org/pdf/2504.20571v3","comment":"link: https://github.com/ypwang61/One-Shot-RLVR","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.20342","versioned_id":"2504.20342v2","title":"Narrative-Centered Emotional Reflection: An Early Prototype for AI-Supported Emotional Self-Reflection","authors":["Shou-Tzu Han"],"abstract":"Reflexion is an AI-powered prototype designed to explore structured emotional self-reflection. By integrating emotion detection, layered reflective prompting, and metaphorical storytelling generation, Reflexion was intended to support users in autonomous emotional exploration beyond basic sentiment categorization. Grounded primarily in expressive writing, cognitive restructuring, and self-determination theory, the system was designed to organize reflection as a progressive pathway from surface-level emotional recognition toward value-aligned action planning. Its final action-planning layer is additionally informed by broader questions of agency and empowerment, which remain future directions rather than fully implemented mechanisms in the current prototype. Informal design feedback indicated that some reviewers found the layered interaction model understandable and potentially useful; no empirical efficacy claims are made. As an early prototype, Reflexion documents one direction in theory-informed affective computing.","published":"2025-04-29T01:24:46Z","updated":"2026-07-06T23:46:30Z","categories":["cs.HC","cs.AI","cs.CY"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2504.20342v2","pdf_url":"https://arxiv.org/pdf/2504.20342v2","comment":"7 pages, 1 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.01441","versioned_id":"2505.01441v1","title":"Agentic Reasoning and Tool Integration for LLMs via Reinforcement Learning","authors":["Joykirat Singh","Raghav Magazine","Yash Pandya","Akshay Nambi"],"abstract":"Large language models (LLMs) have achieved remarkable progress in complex reasoning tasks, yet they remain fundamentally limited by their reliance on static internal knowledge and text-only reasoning. Real-world problem solving often demands dynamic, multi-step reasoning, adaptive decision making, and the ability to interact with external tools and environments. In this work, we introduce ARTIST (Agentic Reasoning and Tool Integration in Self-improving Transformers), a unified framework that tightly couples agentic reasoning, reinforcement learning, and tool integration for LLMs. ARTIST enables models to autonomously decide when, how, and which tools to invoke within multi-turn reasoning chains, leveraging outcome-based RL to learn robust strategies for tool use and environment interaction without requiring step-level supervision. Extensive experiments on mathematical reasoning and multi-turn function calling benchmarks show that ARTIST consistently outperforms state-of-the-art baselines, with up to 22% absolute improvement over base models and strong gains on the most challenging tasks. Detailed studies and metric analyses reveal that agentic RL training leads to deeper reasoning, more effective tool use, and higher-quality solutions. Our results establish agentic RL with tool integration as a powerful new frontier for robust, interpretable, and generalizable problem-solving in LLMs.","published":"2025-04-28T10:42:49Z","updated":"2025-04-28T10:42:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.01441v1","pdf_url":"https://arxiv.org/pdf/2505.01441v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2505.00031","versioned_id":"2505.00031v1","title":"Learning to Plan Before Answering: Self-Teaching LLMs to Learn Abstract Plans for Problem Solving","authors":["Jin Zhang","Flood Sung","Zhilin Yang","Yang Gao","Chongjie Zhang"],"abstract":"In the field of large language model (LLM) post-training, the effectiveness of utilizing synthetic data generated by the LLM itself has been well-presented. However, a key question remains unaddressed: what essential information should such self-generated data encapsulate? Existing approaches only produce step-by-step problem solutions, and fail to capture the abstract meta-knowledge necessary for generalization across similar problems. Drawing insights from cognitive science, where humans employ high-level abstraction to simplify complex problems before delving into specifics, we introduce a novel self-training algorithm: LEarning to Plan before Answering (LEPA). LEPA trains the LLM to formulate anticipatory plans, which serve as abstract meta-knowledge for problem-solving, before engaging with the intricacies of problems. This approach not only outlines the solution generation path but also shields the LLM from the distraction of irrelevant details. During data generation, LEPA first crafts an anticipatory plan based on the problem, and then generates a solution that aligns with both the plan and the problem. LEPA refines the plan through self-reflection, aiming to acquire plans that are instrumental in yielding correct solutions. During model optimization, the LLM is trained to predict both the refined plans and the corresponding solutions. By efficiently extracting and utilizing the anticipatory plans, LEPA demonstrates remarkable superiority over conventional algorithms on various challenging natural language reasoning benchmarks.","published":"2025-04-28T06:32:58Z","updated":"2025-04-28T06:32:58Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.00031v1","pdf_url":"https://arxiv.org/pdf/2505.00031v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.19017","versioned_id":"2504.19017v1","title":"Sparks: Multi-Agent Artificial Intelligence Model Discovers Protein Design Principles","authors":["Alireza Ghafarollahi","Markus J. Buehler"],"abstract":"Advances in artificial intelligence (AI) promise autonomous discovery, yet most systems still resurface knowledge latent in their training data. We present Sparks, a multi-modal multi-agent AI model that executes the entire discovery cycle that includes hypothesis generation, experiment design and iterative refinement to develop generalizable principles and a report without human intervention. Applied to protein science, Sparks uncovered two previously unknown phenomena: (i) a length-dependent mechanical crossover whereby beta-sheet-biased peptides surpass alpha-helical ones in unfolding force beyond ~80 residues, establishing a new design principle for peptide mechanics; and (ii) a chain-length/secondary-structure stability map revealing unexpectedly robust beta-sheet-rich architectures and a \"frustration zone\" of high variance in mixed alpha/beta folds. These findings emerged from fully self-directed reasoning cycles that combined generative sequence design, high-accuracy structure prediction and physics-aware property models, with paired generation-and-reflection agents enforcing self-correction and reproducibility. The key result is that Sparks can independently conduct rigorous scientific inquiry and identify previously unknown scientific principles.","published":"2025-04-26T20:43:28Z","updated":"2025-04-26T20:43:28Z","categories":["cs.AI","cond-mat.mtrl-sci","cond-mat.soft","cs.LG","q-bio.BM"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.19017v1","pdf_url":"https://arxiv.org/pdf/2504.19017v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.18765","versioned_id":"2504.18765v3","title":"A Vision for Auto Research with LLM Agents","authors":["Chengwei Liu","Chong Wang","Jiayue Cao","Jingquan Ge","Kun Wang","Lyuye Zhang","Ming-Ming Cheng","Penghai Zhao","Tianlin Li","Xiaojun Jia","Xiang Li","Xingshuai Li","Yang Liu","Yebo Feng","Yihao Huang","Yijia Xu","Yuqiang Sun","Zhenhong Zhou","Zhengzi Xu"],"abstract":"This paper introduces Agent-Based Auto Research, a structured multi-agent framework designed to automate, coordinate, and optimize the full lifecycle of scientific research. Leveraging the capabilities of large language models (LLMs) and modular agent collaboration, the system spans all major research phases, including literature review, ideation, methodology planning, experimentation, paper writing, peer review response, and dissemination. By addressing issues such as fragmented workflows, uneven methodological expertise, and cognitive overload, the framework offers a systematic and scalable approach to scientific inquiry. Preliminary explorations demonstrate the feasibility and potential of Auto Research as a promising paradigm for self-improving, AI-driven research processes.","published":"2025-04-26T02:06:10Z","updated":"2025-07-19T16:30:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.18765v3","pdf_url":"https://arxiv.org/pdf/2504.18765v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.18116","versioned_id":"2504.18116v1","title":"Think, Prune, Train, Improve: Scaling Reasoning without Scaling Models","authors":["Caia Costello","Simon Guo","Anna Goldie","Azalia Mirhoseini"],"abstract":"Large language models (LLMs) have demonstrated strong capabilities in programming and mathematical reasoning tasks, but are constrained by limited high-quality training data. Synthetic data can be leveraged to enhance fine-tuning outcomes, but several factors influence this process, including model size, synthetic data volume, pruning strategy, and number of fine-tuning rounds. We explore these axes and investigate which conditions enable model self-improvement. We introduce the Think, Prune, Train process, a scalable framework that iteratively fine-tunes models on their own reasoning traces, using ground-truth pruning to ensure high-quality training data. This approach yields improved performance: on GSM8K, Gemma2-2B achieves a Pass@1 of 57.6% (from 41.9%), Gemma2-9B reaches 82%, matching LLaMA-3.1-70B, and LLaMA-3.1-70B attains 91%, even surpassing GPT-4o, demonstrating the effectiveness of self-generated reasoning and systematic data selection for improving LLM capabilities.","published":"2025-04-25T06:48:55Z","updated":"2025-04-25T06:48:55Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.18116v1","pdf_url":"https://arxiv.org/pdf/2504.18116v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.17967","versioned_id":"2504.17967v1","title":"LLM Agent Swarm for Hypothesis-Driven Drug Discovery","authors":["Kevin Song","Andrew Trotter","Jake Y. Chen"],"abstract":"Drug discovery remains a formidable challenge: more than 90 percent of candidate molecules fail in clinical evaluation, and development costs often exceed one billion dollars per approved therapy. Disparate data streams, from genomics and transcriptomics to chemical libraries and clinical records, hinder coherent mechanistic insight and slow progress. Meanwhile, large language models excel at reasoning and tool integration but lack the modular specialization and iterative memory required for regulated, hypothesis-driven workflows. We introduce PharmaSwarm, a unified multi-agent framework that orchestrates specialized LLM \"agents\" to propose, validate, and refine hypotheses for novel drug targets and lead compounds. Each agent accesses dedicated functionality--automated genomic and expression analysis; a curated biomedical knowledge graph; pathway enrichment and network simulation; interpretable binding affinity prediction--while a central Evaluator LLM continuously ranks proposals by biological plausibility, novelty, in silico efficacy, and safety. A shared memory layer captures validated insights and fine-tunes underlying submodels over time, yielding a self-improving system. Deployable on low-code platforms or Kubernetes-based microservices, PharmaSwarm supports literature-driven discovery, omics-guided target identification, and market-informed repurposing. We also describe a rigorous four-tier validation pipeline spanning retrospective benchmarking, independent computational assays, experimental testing, and expert user studies to ensure transparency, reproducibility, and real-world impact. By acting as an AI copilot, PharmaSwarm can accelerate translational research and deliver high-confidence hypotheses more efficiently than traditional pipelines.","published":"2025-04-24T22:27:50Z","updated":"2025-04-24T22:27:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.17967v1","pdf_url":"https://arxiv.org/pdf/2504.17967v1","comment":"15 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.17404","versioned_id":"2504.17404v5","title":"Super Co-alignment of Human and AI for Sustainable Symbiotic Society","authors":["Yi Zeng","Feifei Zhao","Yuwei Wang","Enmeng Lu","Yaodong Yang","Lei Wang","Chao Liu","Yitao Liang","Dongcheng Zhao","Bing Han","Haibo Tong","Yao Liang","Dongqi Liang","Kang Sun","Boyuan Chen","Jinyu Fan"],"abstract":"As Artificial Intelligence (AI) advances toward Artificial General Intelligence (AGI) and eventually Artificial Superintelligence (ASI), it may potentially surpass human control, deviate from human values, and even lead to irreversible catastrophic consequences in extreme cases. This looming risk underscores the critical importance of the \"superalignment\" problem - ensuring that AI systems which are much smarter than humans, remain aligned with human (compatible) intentions and values. While current scalable oversight and weak-to-strong generalization methods demonstrate certain applicability, they exhibit fundamental flaws in addressing the superalignment paradigm - notably, the unidirectional imposition of human values cannot accommodate superintelligence's autonomy or ensure AGI/ASI's stable learning. We contend that the values for sustainable symbiotic society should be co-shaped by humans and living AI together, achieving \"Super Co-alignment.\" Guided by this vision, we propose a concrete framework that integrates external oversight and intrinsic proactive alignment. External oversight superalignment should be grounded in human-centered ultimate decision, supplemented by interpretable automated evaluation and correction, to achieve continuous alignment with humanity's evolving values. Intrinsic proactive superalignment is rooted in a profound understanding of the Self, others, and society, integrating self-awareness, self-reflection, and empathy to spontaneously infer human intentions, distinguishing good from evil and proactively prioritizing human well-being. The integration of externally-driven oversight with intrinsically-driven proactive alignment will co-shape symbiotic values and rules through iterative human-ASI co-alignment, paving the way for achieving safe and beneficial AGI and ASI for good, for human, and for a symbiotic ecology.","published":"2025-04-24T09:53:49Z","updated":"2025-06-28T12:44:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.17404v5","pdf_url":"https://arxiv.org/pdf/2504.17404v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.17213","versioned_id":"2504.17213v2","title":"MASR: Self-Reflective Reasoning through Multimodal Hierarchical Attention Focusing for Agent-based Video Understanding","authors":["Shiwen Cao","Zhaoxing Zhang","Junming Jiao","Juyi Qiao","Guowen Song","Rong Shen","Xiangbing Meng"],"abstract":"Even in the era of rapid advances in large models, video understanding remains a highly challenging task. Compared to texts or images, videos commonly contain more information with redundancy, requiring large models to properly allocate attention at a global level for comprehensive and accurate understanding. To address this, we propose a Multimodal hierarchical Attention focusing Self-reflective Reasoning (MASR) framework for agent-based video understanding. The key innovation lies in its ability to detect and prioritize segments of videos that are highly relevant to the query. Firstly, MASR realizes Multimodal Coarse-to-fine Relevance Sensing (MCRS) which enhances the correlation between the acquired contextual information and the query. Secondly, MASR employs Dilated Temporal Expansion (DTE) to mitigate the risk of missing crucial details when extracting semantic information from the focused frames selected through MCRS. By iteratively applying MCRS and DTE in the self-reflective reasoning process, MASR is able to adaptively adjust the attention to extract highly query-relevant context and therefore improve the response accuracy. In the EgoSchema dataset, MASR achieves a remarkable 5% performance gain over previous leading approaches. In the Next-QA and IntentQA datasets, it outperforms the state-of-the-art standards by 0.2% and 0.3% respectively. In the Video-MME dataset that contains long-term videos, MASR also performs better than other agent-based methods.","published":"2025-04-24T02:54:40Z","updated":"2025-04-28T05:05:24Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2504.17213v2","pdf_url":"https://arxiv.org/pdf/2504.17213v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.16760","versioned_id":"2504.16760v1","title":"Lightweight Latent Verifiers for Efficient Meta-Generation Strategies","authors":["Bartosz Piotrowski","Witold Drzewakowski","Konrad Staniszewski","Piotr Miłoś"],"abstract":"Verifiers are auxiliary models that assess the correctness of outputs generated by base large language models (LLMs). They play a crucial role in many strategies for solving reasoning-intensive problems with LLMs. Typically, verifiers are LLMs themselves, often as large (or larger) than the base model they support, making them computationally expensive. In this work, we introduce a novel lightweight verification approach, LiLaVe, which reliably extracts correctness signals from the hidden states of the base LLM. A key advantage of LiLaVe is its ability to operate with only a small fraction of the computational budget required by traditional LLM-based verifiers. To demonstrate its practicality, we couple LiLaVe with popular meta-generation strategies, like best-of-n or self-consistency. Moreover, we design novel LiLaVe-based approaches, like conditional self-correction or conditional majority voting, that significantly improve both accuracy and efficiency in generation tasks with smaller LLMs. Our work demonstrates the fruitfulness of extracting latent information from the hidden states of LLMs, and opens the door to scalable and resource-efficient solutions for reasoning-intensive applications.","published":"2025-04-23T14:33:20Z","updated":"2025-04-23T14:33:20Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.16760v1","pdf_url":"https://arxiv.org/pdf/2504.16760v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.21024","versioned_id":"2504.21024v2","title":"WebEvolver: Enhancing Web Agent Self-Improvement with Coevolving World Model","authors":["Tianqing Fang","Hongming Zhang","Zhisong Zhang","Kaixin Ma","Wenhao Yu","Haitao Mi","Dong Yu"],"abstract":"Agent self-improvement, where the backbone Large Language Model (LLM) of the agent are trained on trajectories sampled autonomously based on their own policies, has emerged as a promising approach for enhancing performance. Recent advancements, particularly in web environments, face a critical limitation: their performance will reach a stagnation point during autonomous learning cycles, hindering further improvement. We argue that this stems from limited exploration of the web environment and insufficient exploitation of pre-trained web knowledge in LLMs. To improve the performance of self-improvement, we propose a novel framework that introduces a co-evolving World Model LLM. This world model predicts the next observation based on the current observation and action within the web environment. Leveraging LLMs' pretrained knowledge of abundant web content, the World Model serves dual roles: (1) as a virtual web server generating self-instructed training data to continuously refine the agent's policy, and (2) as an imagination engine during inference, enabling look-ahead simulation to guide action selection for the agent LLM. Experiments in real-world web environments (Mind2Web-Live, WebVoyager, and GAIA-web) show a 10% performance gain over existing self-evolving agents, demonstrating the efficacy and generalizability of our approach, without using any distillation from more powerful close-sourced models. Our work establishes the necessity of integrating world models into autonomous agent frameworks to unlock sustained adaptability. Code is available at https://github.com/Tencent/SelfEvolvingAgent","published":"2025-04-23T02:54:31Z","updated":"2025-08-21T05:55:43Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.21024v2","pdf_url":"https://arxiv.org/pdf/2504.21024v2","comment":"EMNLP 2025 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.16078","versioned_id":"2504.16078v1","title":"LLMs are Greedy Agents: Effects of RL Fine-tuning on Decision-Making Abilities","authors":["Thomas Schmied","Jörg Bornschein","Jordi Grau-Moya","Markus Wulfmeier","Razvan Pascanu"],"abstract":"The success of Large Language Models (LLMs) has sparked interest in various agentic applications. A key hypothesis is that LLMs, leveraging common sense and Chain-of-Thought (CoT) reasoning, can effectively explore and efficiently solve complex domains. However, LLM agents have been found to suffer from sub-optimal exploration and the knowing-doing gap, the inability to effectively act on knowledge present in the model. In this work, we systematically study why LLMs perform sub-optimally in decision-making scenarios. In particular, we closely examine three prevalent failure modes: greediness, frequency bias, and the knowing-doing gap. We propose mitigation of these shortcomings by fine-tuning via Reinforcement Learning (RL) on self-generated CoT rationales. Our experiments across multi-armed bandits, contextual bandits, and Tic-tac-toe, demonstrate that RL fine-tuning enhances the decision-making abilities of LLMs by increasing exploration and narrowing the knowing-doing gap. Finally, we study both classic exploration mechanisms, such as $ε$-greedy, and LLM-specific approaches, such as self-correction and self-consistency, to enable more effective fine-tuning of LLMs for decision-making.","published":"2025-04-22T17:57:14Z","updated":"2025-04-22T17:57:14Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.16078v1","pdf_url":"https://arxiv.org/pdf/2504.16078v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2506.06282","versioned_id":"2506.06282v1","title":"Understanding Financial Reasoning in AI: A Multimodal Benchmark and Error Learning Approach","authors":["Shuangyan Deng","Haizhou Peng","Jiachen Xu","Chunhou Liu","Ciprian Doru Giurcuaneanu","Jiamou Liu"],"abstract":"Effective financial reasoning demands not only textual understanding but also the ability to interpret complex visual data such as charts, tables, and trend graphs. This paper introduces a new benchmark designed to evaluate how well AI models - especially large language and multimodal models - reason in finance-specific contexts. Covering 3,200 expert-level question-answer pairs across 15 core financial topics, the benchmark integrates both textual and visual modalities to reflect authentic analytical challenges in finance. To address limitations in current reasoning approaches, we propose an error-aware learning framework that leverages historical model mistakes and feedback to guide inference, without requiring fine-tuning. Our experiments across state-of-the-art models show that multimodal inputs significantly enhance performance and that incorporating error feedback leads to consistent and measurable improvements. The results highlight persistent challenges in visual understanding and mathematical logic, while also demonstrating the promise of self-reflective reasoning in financial AI systems. Our code and data can be found at https://anonymous/FinMR/CodeData.","published":"2025-04-22T07:25:03Z","updated":"2025-04-22T07:25:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.06282v1","pdf_url":"https://arxiv.org/pdf/2506.06282v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.15228","versioned_id":"2504.15228v2","title":"A Self-Improving Coding Agent","authors":["Maxime Robeyns","Martin Szummer","Laurence Aitchison"],"abstract":"Recent advancements in Large Language Models (LLMs) have spurred interest in deploying LLM agents to undertake tasks in the world. LLMs are often deployed in agent systems: code that orchestrates LLM calls and provides them with tools. We demonstrate that an agent system, equipped with basic coding tools, can autonomously edit itself, and thereby improve its performance on benchmark tasks. We find performance gains from 17% to 53% on a random subset of SWE Bench Verified, with additional performance gains on LiveCodeBench, as well as synthetically generated agent benchmarks. Our work represents an advancement in the automated and open-ended design of agentic systems, and demonstrates a data-efficient, non gradient-based learning mechanism driven by LLM reflection and code updates.","published":"2025-04-21T16:58:18Z","updated":"2025-05-16T20:58:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.15228v2","pdf_url":"https://arxiv.org/pdf/2504.15228v2","comment":"Submitted as a preprint to NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.15125","versioned_id":"2504.15125v3","title":"Contemplative Artificial Intelligence","authors":["Ruben Laukkonen","Fionn Inglis","Shamil Chandaria","Lars Sandved-Smith","Edmundo Lopez-Sola","Jakob Hohwy","Jonathan Gold","Adam Elwood"],"abstract":"As artificial intelligence (AI) improves, traditional alignment strategies may falter in the face of unpredictable self-improvement, hidden subgoals, and the sheer complexity of intelligent systems. Inspired by contemplative wisdom traditions, we show how four axiomatic principles can instil a resilient Wise World Model in AI systems. First, mindfulness enables self-monitoring and recalibration of emergent subgoals. Second, emptiness forestalls dogmatic goal fixation and relaxes rigid priors. Third, non-duality dissolves adversarial self-other boundaries. Fourth, boundless care motivates the universal reduction of suffering. We find that prompting AI to reflect on these principles improves performance on the AILuminate Benchmark (d=.96) and boosts cooperation and joint-reward on the Prisoner's Dilemma task (d=7+). We offer detailed implementation strategies at the level of architectures, constitutions, and reinforcement on chain-of-thought. For future systems, active inference may offer the self-organizing and dynamic coupling capabilities needed to enact Contemplative AI in embodied agents.","published":"2025-04-21T14:20:49Z","updated":"2025-08-18T10:09:08Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.15125v3","pdf_url":"https://arxiv.org/pdf/2504.15125v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14945","versioned_id":"2504.14945v5","title":"Learning to Reason under Off-Policy Guidance","authors":["Jianhao Yan","Yafu Li","Zican Hu","Zhi Wang","Ganqu Cui","Xiaoye Qu","Yu Cheng","Yue Zhang"],"abstract":"Recent advances in large reasoning models (LRMs) demonstrate that sophisticated behaviors such as multi-step reasoning and self-reflection can emerge via reinforcement learning with verifiable rewards~(\\textit{RLVR}). However, existing \\textit{RLVR} approaches are inherently ``on-policy'', limiting learning to a model's own outputs and failing to acquire reasoning abilities beyond its initial capabilities. To address this issue, we introduce \\textbf{LUFFY} (\\textbf{L}earning to reason \\textbf{U}nder o\\textbf{FF}-polic\\textbf{Y} guidance), a framework that augments \\textit{RLVR} with off-policy reasoning traces. LUFFY dynamically balances imitation and exploration by combining off-policy demonstrations with on-policy rollouts during training. Specifically, LUFFY combines the Mixed-Policy GRPO framework, which has a theoretically guaranteed convergence rate, alongside policy shaping via regularized importance sampling to avoid superficial and rigid imitation during mixed-policy training. Compared with previous RLVR methods, LUFFY achieves an over \\textbf{+6.4} average gain across six math benchmarks and an advantage of over \\textbf{+6.2} points in out-of-distribution tasks. Most significantly, we show that LUFFY successfully trains weak models in scenarios where on-policy RLVR completely fails. These results provide compelling evidence that LUFFY transcends the fundamental limitations of on-policy RLVR and demonstrates the great potential of utilizing off-policy guidance in RLVR.","published":"2025-04-21T08:09:13Z","updated":"2025-06-22T00:18:09Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.14945v5","pdf_url":"https://arxiv.org/pdf/2504.14945v5","comment":"Work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14858","versioned_id":"2504.14858v4","title":"Retrieval is Not Enough: Enhancing RAG Reasoning through Test-Time Critique and Optimization","authors":["Jiaqi Wei","Hao Zhou","Xiang Zhang","Di Zhang","Zijie Qiu","Wei Wei","Jinzhe Li","Wanli Ouyang","Siqi Sun"],"abstract":"Retrieval-augmented generation (RAG) has become a widely adopted paradigm for enabling knowledge-grounded large language models (LLMs). However, standard RAG pipelines often fail to ensure that model reasoning remains consistent with the evidence retrieved, leading to factual inconsistencies or unsupported conclusions. In this work, we reinterpret RAG as Retrieval-Augmented Reasoning and identify a central but underexplored problem: Reasoning Misalignment -- the divergence between an LLM's internal reasoning trajectory and the evidential constraints provided by retrieval. To address this issue, we propose AlignRAG, a novel iterative framework grounded in Critique-Driven Alignment (CDA). We further introduce AlignRAG-auto, an autonomous variant that dynamically terminates refinement, removing the need to pre-specify the number of critique iterations. At the heart of AlignRAG lies a contrastive critique synthesis mechanism that generates retrieval-sensitive critiques while mitigating self-bias. This mechanism trains a dedicated retrieval-augmented Critic Language Model (CLM) using labeled critiques that distinguish between evidence-aligned and misaligned reasoning. Empirical evaluations show that our approach significantly improves reasoning fidelity. Our 8B-parameter CLM improves performance over the Self-Refine baseline by 12.1% on out-of-domain tasks and outperforms a standard 72B-parameter CLM by 2.2%. Furthermore, AlignRAG-auto achieves this state-of-the-art performance while dynamically determining the optimal number of refinement steps, enhancing efficiency and usability. AlignRAG remains compatible with existing RAG architectures as a plug-and-play module and demonstrates strong robustness under both informative and noisy retrieval scenarios.","published":"2025-04-21T04:56:47Z","updated":"2025-10-11T02:05:28Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.14858v4","pdf_url":"https://arxiv.org/pdf/2504.14858v4","comment":"Accepted by NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14808","versioned_id":"2504.14808v1","title":"On Self-improving Token Embeddings","authors":["Mario M. Kubek","Shiraj Pokharel","Thomas Böhme","Emma L. McDaniel","Herwig Unger","Armin R. Mikler"],"abstract":"This article introduces a novel and fast method for refining pre-trained static word or, more generally, token embeddings. By incorporating the embeddings of neighboring tokens in text corpora, it continuously updates the representation of each token, including those without pre-assigned embeddings. This approach effectively addresses the out-of-vocabulary problem, too. Operating independently of large language models and shallow neural networks, it enables versatile applications such as corpus exploration, conceptual search, and word sense disambiguation. The method is designed to enhance token representations within topically homogeneous corpora, where the vocabulary is restricted to a specific domain, resulting in more meaningful embeddings compared to general-purpose pre-trained vectors. As an example, the methodology is applied to explore storm events and their impacts on infrastructure and communities using narratives from a subset of the NOAA Storm Events database. The article also demonstrates how the approach improves the representation of storm-related terms over time, providing valuable insights into the evolving nature of disaster narratives.","published":"2025-04-21T02:17:19Z","updated":"2025-04-21T02:17:19Z","categories":["cs.CL","cs.AI","cs.IR","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.14808v1","pdf_url":"https://arxiv.org/pdf/2504.14808v1","comment":"18 pages, 4 figures, 3 tables, accepted at the 2025 25th International Conference on Innovations for Community Services (I4CS), June 11 - 13, Munich, Germany, 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14597","versioned_id":"2504.14597v1","title":"a1: Steep Test-time Scaling Law via Environment Augmented Generation","authors":["Lingrui Mei","Shenghua Liu","Yiwei Wang","Baolong Bi","Yuyao Ge","Jun Wan","Yurong Wu","Xueqi Cheng"],"abstract":"Large Language Models (LLMs) have made remarkable breakthroughs in reasoning, yet continue to struggle with hallucinations, logical errors, and inability to self-correct during complex multi-step tasks. Current approaches like chain-of-thought prompting offer limited reasoning capabilities that fail when precise step validation is required. We propose Environment Augmented Generation (EAG), a framework that enhances LLM reasoning through: (1) real-time environmental feedback validating each reasoning step, (2) dynamic branch exploration for investigating alternative solution paths when faced with errors, and (3) experience-based learning from successful reasoning trajectories. Unlike existing methods, EAG enables deliberate backtracking and strategic replanning through tight integration of execution feedback with branching exploration. Our a1-32B model achieves state-of-the-art performance among similar-sized models across all benchmarks, matching larger models like o1 on competition mathematics while outperforming comparable models by up to 24.4 percentage points. Analysis reveals EAG's distinctive scaling pattern: initial token investment in environment interaction yields substantial long-term performance dividends, with advantages amplifying proportionally to task complexity. EAG's theoretical framework demonstrates how environment interactivity and systematic branch exploration together establish a new paradigm for reliable machine reasoning, particularly for problems requiring precise multi-step calculation and logical verification.","published":"2025-04-20T12:55:59Z","updated":"2025-04-20T12:55:59Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.14597v1","pdf_url":"https://arxiv.org/pdf/2504.14597v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14588","versioned_id":"2504.14588v1","title":"Phoenix: A Motion-based Self-Reflection Framework for Fine-grained Robotic Action Correction","authors":["Wenke Xia","Ruoxuan Feng","Dong Wang","Di Hu"],"abstract":"Building a generalizable self-correction system is crucial for robots to recover from failures. Despite advancements in Multimodal Large Language Models (MLLMs) that empower robots with semantic reflection ability for failure, translating semantic reflection into how to correct fine-grained robotic actions remains a significant challenge. To address this gap, we build the Phoenix framework, which leverages motion instruction as a bridge to connect high-level semantic reflection with low-level robotic action correction. In this motion-based self-reflection framework, we start with a dual-process motion adjustment mechanism with MLLMs to translate the semantic reflection into coarse-grained motion instruction adjustment. To leverage this motion instruction for guiding how to correct fine-grained robotic actions, a multi-task motion-conditioned diffusion policy is proposed to integrate visual observations for high-frequency robotic action correction. By combining these two models, we could shift the demand for generalization capability from the low-level manipulation policy to the MLLMs-driven motion adjustment model and facilitate precise, fine-grained robotic action correction. Utilizing this framework, we further develop a lifelong learning method to automatically improve the model's capability from interactions with dynamic environments. The experiments conducted in both the RoboMimic simulation and real-world scenarios prove the superior generalization and robustness of our framework across a variety of manipulation tasks. Our code is released at \\href{https://github.com/GeWu-Lab/Motion-based-Self-Reflection-Framework}{https://github.com/GeWu-Lab/Motion-based-Self-Reflection-Framework}.","published":"2025-04-20T12:30:43Z","updated":"2025-04-20T12:30:43Z","categories":["cs.RO","cs.AI","cs.CV"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2504.14588v1","pdf_url":"https://arxiv.org/pdf/2504.14588v1","comment":"Accepted by CVPR2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14520","versioned_id":"2504.14520v1","title":"Meta-Thinking in LLMs via Multi-Agent Reinforcement Learning: A Survey","authors":["Ahsan Bilal","Muhammad Ahmed Mohsin","Muhammad Umer","Muhammad Awais Khan Bangash","Muhammad Ali Jamshed"],"abstract":"This survey explores the development of meta-thinking capabilities in Large Language Models (LLMs) from a Multi-Agent Reinforcement Learning (MARL) perspective. Meta-thinking self-reflection, assessment, and control of thinking processes is an important next step in enhancing LLM reliability, flexibility, and performance, particularly for complex or high-stakes tasks. The survey begins by analyzing current LLM limitations, such as hallucinations and the lack of internal self-assessment mechanisms. It then talks about newer methods, including RL from human feedback (RLHF), self-distillation, and chain-of-thought prompting, and each of their limitations. The crux of the survey is to talk about how multi-agent architectures, namely supervisor-agent hierarchies, agent debates, and theory of mind frameworks, can emulate human-like introspective behavior and enhance LLM robustness. By exploring reward mechanisms, self-play, and continuous learning methods in MARL, this survey gives a comprehensive roadmap to building introspective, adaptive, and trustworthy LLMs. Evaluation metrics, datasets, and future research avenues, including neuroscience-inspired architectures and hybrid symbolic reasoning, are also discussed.","published":"2025-04-20T07:34:26Z","updated":"2025-04-20T07:34:26Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.14520v1","pdf_url":"https://arxiv.org/pdf/2504.14520v1","comment":"Submitted to IEEE Transactions on Artificial Intelligence","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14375","versioned_id":"2504.14375v1","title":"Bottom-Up Synthesis of Knowledge-Grounded Task-Oriented Dialogues with Iteratively Self-Refined Prompts","authors":["Kun Qian","Maximillian Chen","Siyan Li","Arpit Sharma","Zhou Yu"],"abstract":"Training conversational question-answering (QA) systems requires a substantial amount of in-domain data, which is often scarce in practice. A common solution to this challenge is to generate synthetic data. Traditional methods typically follow a top-down approach, where a large language model (LLM) generates multi-turn dialogues from a broad prompt. Although this method produces coherent conversations, it offers limited fine-grained control over the content and is susceptible to hallucinations. We introduce a bottom-up conversation synthesis approach, where QA pairs are generated first and then combined into a coherent dialogue. This method offers greater control and precision by dividing the process into two distinct steps, allowing refined instructions and validations to be handled separately. Additionally, this structure allows the use of non-local models in stages that do not involve proprietary knowledge, enhancing the overall quality of the generated data. Both human and automated evaluations demonstrate that our approach produces more realistic and higher-quality dialogues compared to top-down methods.","published":"2025-04-19T18:25:53Z","updated":"2025-04-19T18:25:53Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.14375v1","pdf_url":"https://arxiv.org/pdf/2504.14375v1","comment":"Accepted by NAACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14165","versioned_id":"2504.14165v1","title":"Self-Correction Makes LLMs Better Parsers","authors":["Ziyan Zhang","Yang Hou","Chen Gong","Zhenghua Li"],"abstract":"Large language models (LLMs) have achieved remarkable success across various natural language processing (NLP) tasks. However, recent studies suggest that they still face challenges in performing fundamental NLP tasks essential for deep language understanding, particularly syntactic parsing. In this paper, we conduct an in-depth analysis of LLM parsing capabilities, delving into the specific shortcomings of their parsing results. We find that LLMs may stem from limitations to fully leverage grammar rules in existing treebanks, which restricts their capability to generate valid syntactic structures. To help LLMs acquire knowledge without additional training, we propose a self-correction method that leverages grammar rules from existing treebanks to guide LLMs in correcting previous errors. Specifically, we automatically detect potential errors and dynamically search for relevant rules, offering hints and examples to guide LLMs in making corrections themselves. Experimental results on three datasets with various LLMs, demonstrate that our method significantly improves performance in both in-domain and cross-domain settings on the English and Chinese datasets.","published":"2025-04-19T03:50:59Z","updated":"2025-04-19T03:50:59Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.14165v1","pdf_url":"https://arxiv.org/pdf/2504.14165v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.14119","versioned_id":"2504.14119v3","title":"CodeCrash: Exposing LLM Fragility to Misleading Natural Language in Code Reasoning","authors":["Man Ho Lam","Chaozheng Wang","Jen-tse Huang","Michael R. Lyu"],"abstract":"Large Language Models (LLMs) have recently demonstrated strong capabilities in code-related tasks, but their robustness in code reasoning under perturbations remains underexplored. We introduce CodeCrash, a stress-testing framework with 1,279 questions from CruxEval and LiveCodeBench, designed to evaluate reasoning reliability under structural perturbations and misleading natural language (NL) contexts. Through a systematic evaluation of 17 LLMs, we find that models often shortcut reasoning by over-relying on NL cues, leading to an average performance degradation of 23.2% in output prediction tasks. Even with Chain-of-Thought reasoning, models on average still have a 13.8% drop due to distractibility and rationalization, revealing a lack of critical reasoning capability to distinguish the actual code behaviors. While Large Reasoning Models with internal reasoning mechanisms improve robustness by fostering critical thinking, plausible yet incorrect hints can trigger pathological self-reflection, causing 2-3 times token consumption and even catastrophic cognitive dissonance in extreme cases for QwQ-32B. We refer to this phenomenon as Reasoning Collapse. CodeCrash provides a rigorous benchmark for evaluating robustness in code reasoning, guiding future research and development toward more reliable and resilient models.","published":"2025-04-19T00:40:28Z","updated":"2025-10-11T09:41:48Z","categories":["cs.AI","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.14119v3","pdf_url":"https://arxiv.org/pdf/2504.14119v3","comment":"NeurIPS 2025; 10 pages of main text; 25 pages of appendices. Website - https://cuhk-arise.github.io/CodeCrash/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.13837","versioned_id":"2504.13837v5","title":"Does Reinforcement Learning Really Incentivize Reasoning Capacity in LLMs Beyond the Base Model?","authors":["Yang Yue","Zhiqi Chen","Rui Lu","Andrew Zhao","Zhaokai Wang","Yang Yue","Shiji Song","Gao Huang"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) has recently demonstrated notable success in enhancing the reasoning performance of large language models (LLMs), particularly on mathematics and programming tasks. Similar to how traditional RL helps agents explore and learn new strategies, RLVR is believed to enable LLMs to continuously self-improve, thus acquiring novel reasoning abilities beyond those of the corresponding base models. In this study we critically examine the current state of RLVR by systematically probing the reasoning capability boundaries of RLVR-trained LLMs across various model families, RL algorithms, and math, coding, and visual reasoning benchmarks, using pass@k at large k values as the evaluation metric. Surprisingly, we find that the current training setup does not elicit fundamentally new reasoning patterns. While RLVR-trained models outperform their base models at small k (e.g., k = 1), the base models achieve a higher pass@k score when k is large. Coverage and perplexity analyses show that the observed reasoning abilities originate from and are bounded by the base model. Treating the base model as an upper bound, our quantitative analysis shows that six popular RLVR algorithms perform similarly and remain far from optimal in leveraging the potential of the base model. By contrast, we find that distillation can introduce new reasoning patterns from the teacher and genuinely expand the model's reasoning capabilities. Overall, our findings suggest that current RLVR methods have not yet realized the potential of RL to elicit truly novel reasoning abilities in LLMs. This highlights the need for improved RL paradigms, such as continual scaling and multi-turn agent-environment interaction, to unlock this potential.","published":"2025-04-18T17:59:56Z","updated":"2025-11-24T06:11:04Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.13837v5","pdf_url":"https://arxiv.org/pdf/2504.13837v5","comment":"31 pages, 27 figures","journal_ref":"NeurIPS 2025 Oral; ICML 2025 AI4MATH workshop best paper","doi":"","discovered_on":"2026-07-17"},{"id":"2504.13359","versioned_id":"2504.13359v2","title":"Cost-of-Pass: An Economic Framework for Evaluating Language Models","authors":["Mehmet Hamza Erol","Batu El","Mirac Suzgun","Mert Yuksekgonul","James Zou"],"abstract":"Widespread adoption of AI systems hinges on their ability to generate economic value that outweighs their inference costs. Evaluating this tradeoff requires metrics accounting for both performance and costs. Building on production theory, we develop an economically grounded framework to evaluate language models' productivity by combining accuracy and inference cost. We formalize cost-of-pass: the expected monetary cost of generating a correct solution. We then define the frontier cost-of-pass: the minimum cost-of-pass achievable across available models or the human-expert(s), using the approx. cost of hiring an expert. Our analysis reveals distinct economic insights. First, lightweight models are most cost-effective for basic quantitative tasks, large models for knowledge-intensive ones, and reasoning models for complex quantitative problems, despite higher per-token costs. Second, tracking the frontier cost-of-pass over the past year reveals significant progress, particularly for complex quant. tasks where the cost roughly halved every few months. Third, to trace key innovations driving this progress, we examine counterfactual frontiers -- estimates of cost-efficiency without specific model classes. We find that innovations in lightweight, large, and reasoning models have been essential for pushing the frontier in basic quant., knowledge-intensive, and complex quant. tasks, respectively. Finally, we assess the cost-reductions from common inference-time techniques (majority voting and self-refinement), and a budget-aware technique (TALE-EP). We find that performance-oriented methods with marginal performance gains rarely justify the costs, while TALE-EP shows some promise. Overall, our findings underscore that complementary model-level innovations are the primary drivers of cost-efficiency and our framework provides a principled tool for measuring this progress and guiding deployment.","published":"2025-04-17T21:58:29Z","updated":"2026-02-26T05:45:42Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.13359v2","pdf_url":"https://arxiv.org/pdf/2504.13359v2","comment":"Code is available at: https://github.com/mhamzaerol/Cost-of-Pass","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.12951","versioned_id":"2504.12951v1","title":"Are Retrials All You Need? Enhancing Large Language Model Reasoning Without Verbalized Feedback","authors":["Nearchos Potamitis","Akhil Arora"],"abstract":"Recent advancements in large language models (LLMs) have catalyzed the development of general-purpose autonomous agents, demonstrating remarkable performance in complex reasoning tasks across various domains. This surge has spurred the evolution of a plethora of prompt-based reasoning frameworks. A recent focus has been on iterative reasoning strategies that refine outputs through self-evaluation and verbalized feedback. However, these strategies require additional computational complexity to enable models to recognize and correct their mistakes, leading to a significant increase in their cost. In this work, we introduce the concept of ``retrials without feedback'', an embarrassingly simple yet powerful mechanism for enhancing reasoning frameworks by allowing LLMs to retry problem-solving attempts upon identifying incorrect answers. Unlike conventional iterative refinement methods, our method does not require explicit self-reflection or verbalized feedback, simplifying the refinement process. Our findings indicate that simpler retrial-based approaches often outperform more sophisticated reasoning frameworks, suggesting that the benefits of complex methods may not always justify their computational costs. By challenging the prevailing assumption that more intricate reasoning strategies inherently lead to better performance, our work offers new insights into how simpler, more efficient approaches can achieve optimal results. So, are retrials all you need?","published":"2025-04-17T13:52:48Z","updated":"2025-04-17T13:52:48Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.12951v1","pdf_url":"https://arxiv.org/pdf/2504.12951v1","comment":"8 pages, 16 figures, 1 table. arXiv admin note: text overlap with arXiv:2405.06691","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.12216","versioned_id":"2504.12216v2","title":"d1: Scaling Reasoning in Diffusion Large Language Models via Reinforcement Learning","authors":["Siyan Zhao","Devaansh Gupta","Qinqing Zheng","Aditya Grover"],"abstract":"Recent large language models (LLMs) have demonstrated strong reasoning capabilities that benefits from online reinforcement learning (RL). These capabilities have primarily been demonstrated within the left-to-right autoregressive (AR) generation paradigm. In contrast, non-autoregressive paradigms based on diffusion generate text in a coarse-to-fine manner. Although recent diffusion-based large language models (dLLMs) have achieved competitive language modeling performance compared to their AR counterparts, it remains unclear if dLLMs can also leverage recent advances in LLM reasoning. To this end, we propose d1, a framework to adapt pre-trained masked dLLMs into reasoning models via a combination of supervised finetuning (SFT) and RL. Specifically, we develop and extend techniques to improve reasoning in pretrained dLLMs: (a) we utilize a masked SFT technique to distill knowledge and instill self-improvement behavior directly from existing datasets, and (b) we introduce a novel critic-free, policy-gradient based RL algorithm called diffu-GRPO, the first integration of policy gradient methods to masked dLLMs. Through empirical studies, we investigate the performance of different post-training recipes on multiple mathematical and planning benchmarks. We find that d1 yields the best performance and significantly improves performance of a state-of-the-art dLLM. Our code is released at https://dllm-reasoning.github.io/.","published":"2025-04-16T16:08:45Z","updated":"2025-06-03T17:02:25Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.12216v2","pdf_url":"https://arxiv.org/pdf/2504.12216v2","comment":"27 pages, project page at https://dllm-reasoning.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.11536","versioned_id":"2504.11536v2","title":"ReTool: Reinforcement Learning for Strategic Tool Use in LLMs","authors":["Jiazhan Feng","Shijue Huang","Xingwei Qu","Ge Zhang","Yujia Qin","Baoquan Zhong","Chengquan Jiang","Jinxin Chi","Wanjun Zhong"],"abstract":"While reasoning models (e.g., DeepSeek R1) trained with reinforcement learning (RL), excel in textual reasoning, they struggle in scenarios requiring structured problem-solving, such as geometric reasoning, concise computation, or complex equation solving-areas where computational tools like code interpreters (CI) demonstrate distinct advantages. To bridge this gap, we propose ReTool, which enhances long-form reasoning with tool-integrated learning, including two key features: (1) dynamic interleaving of real-time code execution within natural language reasoning processes, and (2) an automated RL paradigm that allows policy rollouts with multi-turn real-time code execution and teaches the model in learning when and how to invoke tools based on outcome feedback. ReTool employs a systematic training framework, beginning with synthetic cold-start data generation to produce code-augmented long-form reasoning traces for fine-tuning base models. Subsequent RL training leverages task outcomes as rewards to iteratively refine the model's tool use strategy, enabling autonomous discovery of optimal tool invocation patterns without human priors. Experiments on the challenging MATH Olympiad benchmark AIME demonstrate ReTool's superiority: Our 32B model achieves 67% accuracy with 400 training steps, outperforming text-based RL baseline (40% accuracy, 1080 steps) in efficiency and performance. Remarkably, ReTool-32B attains 72.5% accuracy in extended settings, surpassing OpenAI's o1-preview by 27.9%. Further analysis reveals emergent behaviors such as code self-correction, signaling an ''aha moment'' in which the model autonomously masters adaptive tool use. These findings highlight the promise of outcome-driven tool integration for advancing complex mathematical reasoning and offer new insights into hybrid neuro-symbolic systems.","published":"2025-04-15T18:10:22Z","updated":"2025-04-17T16:46:07Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.11536v2","pdf_url":"https://arxiv.org/pdf/2504.11536v2","comment":"fix typos","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.11301","versioned_id":"2504.11301v2","title":"Learning to Be A Doctor: Searching for Effective Medical Agent Architectures","authors":["Yangyang Zhuang","Wenjia Jiang","Jiayu Zhang","Ze Yang","Joey Tianyi Zhou","Chi Zhang"],"abstract":"Large Language Model (LLM)-based agents have demonstrated strong capabilities across a wide range of tasks, and their application in the medical domain holds particular promise due to the demand for high generalizability and reliance on interdisciplinary knowledge. However, existing medical agent systems often rely on static, manually crafted workflows that lack the flexibility to accommodate diverse diagnostic requirements and adapt to emerging clinical scenarios. Motivated by the success of automated machine learning (AutoML), this paper introduces a novel framework for the automated design of medical agent architectures. Specifically, we define a hierarchical and expressive agent search space that enables dynamic workflow adaptation through structured modifications at the node, structural, and framework levels. Our framework conceptualizes medical agents as graph-based architectures composed of diverse, functional node types and supports iterative self-improvement guided by diagnostic feedback. Experimental results on skin disease diagnosis tasks demonstrate that the proposed method effectively evolves workflow structures and significantly enhances diagnostic accuracy over time. This work represents the first fully automated framework for medical agent architecture design and offers a scalable, adaptable foundation for deploying intelligent agents in real-world clinical environments.","published":"2025-04-15T15:44:21Z","updated":"2025-08-15T08:59:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.11301v2","pdf_url":"https://arxiv.org/pdf/2504.11301v2","comment":"Accepted at ACM MM 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.11101","versioned_id":"2504.11101v4","title":"Consensus Entropy: Harnessing Multi-VLM Agreement for Self-Verifying and Self-Improving OCR","authors":["Yulong Zhang","Tianyi Liang","Xinyue Huang","Erfei Cui","Guoqing Wang","Xu Guo","Chenhui Li","Gongshen Liu"],"abstract":"Optical Character Recognition (OCR) is fundamental to Vision-Language Models (VLMs) and high-quality data generation for LLM training. Yet, despite progress in average OCR accuracy, state-of-the-art VLMs still struggle with detecting sample-level errors and lack effective unsupervised quality control. We introduce Consensus Entropy (CE), a training-free, model-agnostic metric that estimates output reliability by measuring inter-model agreement entropy. The core insight is that correct predictions converge in output space, while errors diverge. Based on CE, we develop CE-OCR, a lightweight multi-model framework that verifies outputs by ensemble agreement, selects the best outputs, and further improves efficiency through adaptive routing. Experiments demonstrate that CE is robust for quality verification, improving F1 scores by 42.1% over VLM-as-Judge. CE-OCR achieves consistent OCR gains, outperforming self-consistency and single-model baselines at the same cost. Notably, CE requires no training or supervision, enabling plug-and-play integration. Code: https://github.com/Aslan-yulong/consensus-entropy.","published":"2025-04-15T11:51:18Z","updated":"2026-05-06T07:49:45Z","categories":["cs.CV","cs.AI","cs.MM"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2504.11101v4","pdf_url":"https://arxiv.org/pdf/2504.11101v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.10481","versioned_id":"2504.10481v2","title":"xVerify: Efficient Answer Verifier for Reasoning Model Evaluations","authors":["Ding Chen","Qingchen Yu","Pengyuan Wang","Mengting Hu","Wentao Zhang","Zhengren Wang","Bo Tang","Feiyu Xiong","Xinchi Li","Chao Wang","Minchuan Yang","Zhiyu Li"],"abstract":"With the release of OpenAI's o1 model, reasoning models that adopt slow-thinking strategies have become increasingly common. Their outputs often contain complex reasoning, intermediate steps, and self-reflection, making existing evaluation methods and reward models inadequate. In particular, they struggle to judge answer equivalence and to reliably extract final answers from long, complex responses. To address this challenge, we propose xVerify, an efficient answer verifier for evaluating reasoning models. xVerify shows strong equivalence judgment capabilities, enabling accurate comparison between model outputs and reference answers across diverse question types. To train and evaluate xVerify, we construct the VAR dataset, which consists of question-answer pairs generated by multiple LLMs across various datasets. The dataset incorporates multiple reasoning models and challenging evaluation sets specifically designed for reasoning assessment, with a multi-round annotation process to ensure label quality. Based on VAR, we train xVerify models at different scales. Experimental results on both test and generalization sets show that all xVerify variants achieve over 95% F1 score and accuracy. Notably, the smallest model, xVerify-0.5B-I, outperforms all evaluation methods except GPT-4o, while xVerify-3B-Ib surpasses GPT-4o in overall performance. In addition, reinforcement learning experiments using xVerify as the reward model yield an 18.4% improvement for Qwen2.5-7B compared with direct generation, exceeding the gains achieved with Math Verify as the reward. These results demonstrate the effectiveness and generalizability of xVerify. All xVerify resources are available on \\href{https://github.com/IAAR-Shanghai/xVerify}{GitHub}.","published":"2025-04-14T17:59:36Z","updated":"2025-12-30T13:22:28Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.10481v2","pdf_url":"https://arxiv.org/pdf/2504.10481v2","comment":"35 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.10551","versioned_id":"2504.10551v1","title":"MiMu: Mitigating Multiple Shortcut Learning Behavior of Transformers","authors":["Lili Zhao","Qi Liu","Wei Chen","Liyi Chen","Ruijun Sun","Min Hou","Yang Wang","Shijin Wang"],"abstract":"Empirical Risk Minimization (ERM) models often rely on spurious correlations between features and labels during the learning process, leading to shortcut learning behavior that undermines robustness generalization performance. Current research mainly targets identifying or mitigating a single shortcut; however, in real-world scenarios, cues within the data are diverse and unknown. In empirical studies, we reveal that the models rely to varying extents on different shortcuts. Compared to weak shortcuts, models depend more heavily on strong shortcuts, resulting in their poor generalization ability. To address these challenges, we propose MiMu, a novel method integrated with Transformer-based ERMs designed to Mitigate Multiple shortcut learning behavior, which incorporates self-calibration strategy and self-improvement strategy. In the source model, we preliminarily propose the self-calibration strategy to prevent the model from relying on shortcuts and make overconfident predictions. Then, we further design self-improvement strategy in target model to reduce the reliance on multiple shortcuts. The random mask strategy involves randomly masking partial attention positions to diversify the focus of target model other than concentrating on a fixed region. Meanwhile, the adaptive attention alignment module facilitates the alignment of attention weights to the calibrated source model, without the need for post-hoc attention maps or supervision. Finally, extensive experiments conducted on Natural Language Processing (NLP) and Computer Vision (CV) demonstrate the effectiveness of MiMu in improving robustness generalization abilities.","published":"2025-04-14T08:11:09Z","updated":"2025-04-14T08:11:09Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.10551v1","pdf_url":"https://arxiv.org/pdf/2504.10551v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.09946","versioned_id":"2504.09946v2","title":"Assessing Judging Bias in Large Reasoning Models: An Empirical Study","authors":["Qian Wang","Zhanzhi Lou","Zhenheng Tang","Nuo Chen","Xuandong Zhao","Wenxuan Zhang","Dawn Song","Bingsheng He"],"abstract":"Large Reasoning Models (LRMs) like DeepSeek-R1 and OpenAI-o1 have demonstrated remarkable reasoning capabilities, raising important questions about their biases in LLM-as-a-judge settings. We present a comprehensive benchmark comparing judging biases between LLMs and LRMs across both subjective preference-alignment datasets and objective fact-based datasets. Through investigation of bandwagon, authority, position, and distraction biases, we uncover four key findings: (1) despite their advanced reasoning capabilities, LRMs remain susceptible to the above biases; (2) LRMs demonstrate better robustness than LLMs specifically on fact-related datasets; (3) LRMs exhibit notable position bias, preferring options in later positions; and (4) we identify a novel \"superficial reflection bias\" where phrases mimicking reasoning (e.g., \"wait, let me think...\") significantly influence model judgments. To address these biases, we design and evaluate three mitigation strategies: specialized system prompts that reduce judging biases by up to 19\\% in preference alignment datasets and 14\\% in fact-related datasets, in-context learning that provides up to 27\\% improvement on preference tasks but shows inconsistent results on factual tasks, and a self-reflection mechanism that reduces biases by up to 10\\% in preference datasets and 16\\% in fact-related datasets, with self-reflection proving particularly effective for LRMs. Our work provides crucial insights for developing more reliable LLM-as-a-Judge frameworks, especially as LRMs become increasingly deployed as automated judges.","published":"2025-04-14T07:14:27Z","updated":"2025-04-18T02:05:38Z","categories":["cs.CY","cs.CL"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2504.09946v2","pdf_url":"https://arxiv.org/pdf/2504.09946v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.09058","versioned_id":"2504.09058v1","title":"Towards Stepwise Domain Knowledge-Driven Reasoning Optimization and Reflection Improvement","authors":["Chengyuan Liu","Shihang Wang","Lizhi Qing","Kaisong Song","Junjie Cao","Jun Lin","Ji Zhang","Ang Li","Kun Kuang","Fei Wu"],"abstract":"Recently, stepwise supervision on Chain of Thoughts (CoTs) presents an enhancement on the logical reasoning tasks such as coding and math, with the help of Monte Carlo Tree Search (MCTS). However, its contribution to tasks requiring domain-specific expertise and knowledge remains unexplored. Motivated by the interest, we identify several potential challenges of vanilla MCTS within this context, and propose the framework of Stepwise Domain Knowledge-Driven Reasoning Optimization, employing the MCTS algorithm to develop step-level supervision for problems that require essential comprehension, reasoning, and specialized knowledge. Additionally, we also introduce the Preference Optimization towards Reflection Paths, which iteratively learns self-reflection on the reasoning thoughts from better perspectives. We have conducted extensive experiments to evaluate the advantage of the methodologies. Empirical results demonstrate the effectiveness on various legal-domain problems. We also report a diverse set of valuable findings, hoping to encourage the enthusiasm to the research of domain-specific LLMs and MCTS.","published":"2025-04-12T03:25:01Z","updated":"2025-04-12T03:25:01Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.09058v1","pdf_url":"https://arxiv.org/pdf/2504.09058v1","comment":"Under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.08696","versioned_id":"2504.08696v2","title":"SeaView: Software Engineering Agent Visual Interface for Enhanced Workflow","authors":["Timothy Bula","Saurabh Pujar","Luca Buratti","Mihaela Bornea","Avirup Sil"],"abstract":"Auto-regressive LLM-based software engineering (SWE) agents, henceforth SWE agents, have made tremendous progress (>60% on SWE-Bench Verified) on real-world coding challenges including GitHub issue resolution. SWE agents use a combination of reasoning, environment interaction and self-reflection to resolve issues thereby generating \"trajectories\". Analysis of SWE agent trajectories is difficult, not only as they exceed LLM sequence length (sometimes, greater than 128k) but also because it involves a relatively prolonged interaction between an LLM and the environment managed by the agent. In case of an agent error, it can be hard to decipher, locate and understand its scope. Similarly, it can be hard to track improvements or regression over multiple runs or experiments. While a lot of research has gone into making these SWE agents reach state-of-the-art, much less focus has been put into creating tools to help analyze and visualize agent output. We propose a novel tool called SeaView: Software Engineering Agent Visual Interface for Enhanced Workflow, with a vision to assist SWE-agent researchers to visualize and inspect their experiments. SeaView's novel mechanisms help compare experimental runs with varying hyper-parameters or LLMs, and quickly get an understanding of LLM or environment related problems. Based on our user study, experienced researchers spend between 10 and 30 minutes to gather the information provided by SeaView, while researchers with little experience can spend between 30 minutes to 1 hour to diagnose their experiment.","published":"2025-04-11T17:03:58Z","updated":"2025-04-14T16:02:38Z","categories":["cs.SE","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2504.08696v2","pdf_url":"https://arxiv.org/pdf/2504.08696v2","comment":"8 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.08672","versioned_id":"2504.08672v1","title":"Genius: A Generalizable and Purely Unsupervised Self-Training Framework For Advanced Reasoning","authors":["Fangzhi Xu","Hang Yan","Chang Ma","Haiteng Zhao","Qiushi Sun","Kanzhi Cheng","Junxian He","Jun Liu","Zhiyong Wu"],"abstract":"Advancing LLM reasoning skills has captivated wide interest. However, current post-training techniques rely heavily on supervisory signals, such as outcome supervision or auxiliary reward models, which face the problem of scalability and high annotation costs. This motivates us to enhance LLM reasoning without the need for external supervision. We introduce a generalizable and purely unsupervised self-training framework, named Genius. Without external auxiliary, Genius requires to seek the optimal response sequence in a stepwise manner and optimize the LLM. To explore the potential steps and exploit the optimal ones, Genius introduces a stepwise foresight re-sampling strategy to sample and estimate the step value by simulating future outcomes. Further, we recognize that the unsupervised setting inevitably induces the intrinsic noise and uncertainty. To provide a robust optimization, we propose an advantage-calibrated optimization (ACO) loss function to mitigate estimation inconsistencies. Combining these techniques together, Genius provides an advanced initial step towards self-improve LLM reasoning with general queries and without supervision, revolutionizing reasoning scaling laws given the vast availability of general queries. The code will be released at https://github.com/xufangzhi/Genius.","published":"2025-04-11T16:26:23Z","updated":"2025-04-11T16:26:23Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.08672v1","pdf_url":"https://arxiv.org/pdf/2504.08672v1","comment":"14 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.08853","versioned_id":"2504.08853v1","title":"Artificial Intelligence (AI) and the Relationship between Agency, Autonomy, and Moral Patiency","authors":["Paul Formosa","Inês Hipólito","Thomas Montefiore"],"abstract":"The proliferation of Artificial Intelligence (AI) systems exhibiting complex and seemingly agentive behaviours necessitates a critical philosophical examination of their agency, autonomy, and moral status. In this paper we undertake a systematic analysis of the differences between basic, autonomous, and moral agency in artificial systems. We argue that while current AI systems are highly sophisticated, they lack genuine agency and autonomy because: they operate within rigid boundaries of pre-programmed objectives rather than exhibiting true goal-directed behaviour within their environment; they cannot authentically shape their engagement with the world; and they lack the critical self-reflection and autonomy competencies required for full autonomy. Nonetheless, we do not rule out the possibility of future systems that could achieve a limited form of artificial moral agency without consciousness through hybrid approaches to ethical decision-making. This leads us to suggest, by appealing to the necessity of consciousness for moral patiency, that such non-conscious AMAs might represent a case that challenges traditional assumptions about the necessary connection between moral agency and moral patiency.","published":"2025-04-11T03:48:40Z","updated":"2025-04-11T03:48:40Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2504.08853v1","pdf_url":"https://arxiv.org/pdf/2504.08853v1","comment":"","journal_ref":"","doi":"10.1007/978-3-032-14537-6_3","discovered_on":"2026-07-17"},{"id":"2504.08837","versioned_id":"2504.08837v3","title":"VL-Rethinker: Incentivizing Self-Reflection of Vision-Language Models with Reinforcement Learning","authors":["Haozhe Wang","Chao Qu","Zuming Huang","Wei Chu","Fangzhen Lin","Wenhu Chen"],"abstract":"Recently, slow-thinking systems like GPT-o1 and DeepSeek-R1 have demonstrated great potential in solving challenging problems through explicit reflection. They significantly outperform the best fast-thinking models, such as GPT-4o, on various math and science benchmarks. However, their multimodal reasoning capabilities remain on par with fast-thinking models. For instance, GPT-o1's performance on benchmarks like MathVista, MathVerse, and MathVision is similar to fast-thinking models. In this paper, we aim to enhance the slow-thinking capabilities of vision-language models using reinforcement learning (without relying on distillation) to advance the state of the art. First, we adapt the GRPO algorithm with a novel technique called Selective Sample Replay (SSR) to address the vanishing advantages problem. While this approach yields strong performance, the resulting RL-trained models exhibit limited self-reflection or self-verification. To further encourage slow-thinking, we introduce Forced Rethinking, which appends a rethinking trigger token to the end of rollouts in RL training, explicitly enforcing a self-reflection reasoning step. By combining these two techniques, our model, VL-Rethinker, advances state-of-the-art scores on MathVista, MathVerse to achieve 80.4%, 63.5% respectively. VL-Rethinker also achieves open-source SoTA on multi-disciplinary benchmarks such as MathVision, MMMU-Pro, EMMA, and MEGA-Bench, narrowing the gap with OpenAI-o1. Our empirical results show the effectiveness of our approaches.","published":"2025-04-10T17:41:56Z","updated":"2025-05-08T06:35:06Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.08837v3","pdf_url":"https://arxiv.org/pdf/2504.08837v3","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.07433","versioned_id":"2504.07433v4","title":"From Token to Line: Enhancing Code Generation with a Long-Term Perspective","authors":["Tingwei Lu","Yangning Li","Liyuan Wang","Binghuai Lin","Qingsong Lv","Zishan Xu","Hai-Tao Zheng","Yinghui Li","Hong-Gee Kim"],"abstract":"The emergence of large language models (LLMs) has significantly promoted the development of code generation task, sparking a surge in pertinent literature. Current research is hindered by redundant generation results and a tendency to overfit local patterns in the short term. Although existing studies attempt to alleviate the issue by adopting a multi-token prediction strategy, there remains limited focus on choosing the appropriate processing length for generations. By analyzing the attention between tokens during the generation process of LLMs, it can be observed that the high spikes of the attention scores typically appear at the end of lines. This insight suggests that it is reasonable to treat each line of code as a fundamental processing unit and generate them sequentially. Inspired by this, we propose the LSR-MCTS algorithm, which leverages MCTS to determine the code line-by-line and select the optimal path. Further, we integrate a self-refine mechanism at each node to enhance diversity and generate higher-quality programs through error correction. Extensive experiments and comprehensive analyses on three public coding benchmarks demonstrate that our method outperforms the state-of-the-art performance approaches.","published":"2025-04-10T04:03:25Z","updated":"2026-02-09T14:48:23Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.07433v4","pdf_url":"https://arxiv.org/pdf/2504.07433v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.07079","versioned_id":"2504.07079v1","title":"SkillWeaver: Web Agents can Self-Improve by Discovering and Honing Skills","authors":["Boyuan Zheng","Michael Y. Fatemi","Xiaolong Jin","Zora Zhiruo Wang","Apurva Gandhi","Yueqi Song","Yu Gu","Jayanth Srinivasa","Gaowen Liu","Graham Neubig","Yu Su"],"abstract":"To survive and thrive in complex environments, humans have evolved sophisticated self-improvement mechanisms through environment exploration, hierarchical abstraction of experiences into reuseable skills, and collaborative construction of an ever-growing skill repertoire. Despite recent advancements, autonomous web agents still lack crucial self-improvement capabilities, struggling with procedural knowledge abstraction, refining skills, and skill composition. In this work, we introduce SkillWeaver, a skill-centric framework enabling agents to self-improve by autonomously synthesizing reusable skills as APIs. Given a new website, the agent autonomously discovers skills, executes them for practice, and distills practice experiences into robust APIs. Iterative exploration continually expands a library of lightweight, plug-and-play APIs, significantly enhancing the agent's capabilities. Experiments on WebArena and real-world websites demonstrate the efficacy of SkillWeaver, achieving relative success rate improvements of 31.8% and 39.8%, respectively. Additionally, APIs synthesized by strong agents substantially enhance weaker agents through transferable skills, yielding improvements of up to 54.3% on WebArena. These results demonstrate the effectiveness of honing diverse website interactions into APIs, which can be seamlessly shared among various web agents.","published":"2025-04-09T17:51:50Z","updated":"2025-04-09T17:51:50Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.07079v1","pdf_url":"https://arxiv.org/pdf/2504.07079v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.06943","versioned_id":"2504.06943v2","title":"Review of Case-Based Reasoning for LLM Agents: Theoretical Foundations, Architectural Components, and Cognitive Integration","authors":["Kostas Hatalis","Despina Christou","Vyshnavi Kondapalli"],"abstract":"Agents powered by Large Language Models (LLMs) have recently demonstrated impressive capabilities in various tasks. Still, they face limitations in tasks requiring specific, structured knowledge, flexibility, or accountable decision-making. While agents are capable of perceiving their environments, forming inferences, planning, and executing actions towards goals, they often face issues such as hallucinations and lack of contextual memory across interactions. This paper explores how Case-Based Reasoning (CBR), a strategy that solves new problems by referencing past experiences, can be integrated into LLM agent frameworks. This integration allows LLMs to leverage explicit knowledge, enhancing their effectiveness. We systematically review the theoretical foundations of these enhanced agents, identify critical framework components, and formulate a mathematical model for the CBR processes of case retrieval, adaptation, and learning. We also evaluate CBR-enhanced agents against other methods like Chain-of-Thought reasoning and standard Retrieval-Augmented Generation, analyzing their relative strengths. Moreover, we explore how leveraging CBR's cognitive dimensions (including self-reflection, introspection, and curiosity) via goal-driven autonomy mechanisms can further enhance the LLM agent capabilities. Contributing to the ongoing research on neuro-symbolic hybrid systems, this work posits CBR as a viable technique for enhancing the reasoning skills and cognitive aspects of autonomous LLM agents.","published":"2025-04-09T14:51:02Z","updated":"2025-04-11T05:34:20Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.06943v2","pdf_url":"https://arxiv.org/pdf/2504.06943v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.08813","versioned_id":"2504.08813v1","title":"SafeMLRM: Demystifying Safety in Multi-modal Large Reasoning Models","authors":["Junfeng Fang","Yukai Wang","Ruipeng Wang","Zijun Yao","Kun Wang","An Zhang","Xiang Wang","Tat-Seng Chua"],"abstract":"The rapid advancement of multi-modal large reasoning models (MLRMs) -- enhanced versions of multimodal language models (MLLMs) equipped with reasoning capabilities -- has revolutionized diverse applications. However, their safety implications remain underexplored. While prior work has exposed critical vulnerabilities in unimodal reasoning models, MLRMs introduce distinct risks from cross-modal reasoning pathways. This work presents the first systematic safety analysis of MLRMs through large-scale empirical studies comparing MLRMs with their base MLLMs. Our experiments reveal three critical findings: (1) The Reasoning Tax: Acquiring reasoning capabilities catastrophically degrades inherited safety alignment. MLRMs exhibit 37.44% higher jailbreaking success rates than base MLLMs under adversarial attacks. (2) Safety Blind Spots: While safety degradation is pervasive, certain scenarios (e.g., Illegal Activity) suffer 25 times higher attack rates -- far exceeding the average 3.4 times increase, revealing scenario-specific vulnerabilities with alarming cross-model and datasets consistency. (3) Emergent Self-Correction: Despite tight reasoning-answer safety coupling, MLRMs demonstrate nascent self-correction -- 16.9% of jailbroken reasoning steps are overridden by safe answers, hinting at intrinsic safeguards. These findings underscore the urgency of scenario-aware safety auditing and mechanisms to amplify MLRMs' self-correction potential. To catalyze research, we open-source OpenSafeMLRM, the first toolkit for MLRM safety evaluation, providing unified interface for mainstream models, datasets, and jailbreaking methods. Our work calls for immediate efforts to harden reasoning-augmented AI, ensuring its transformative potential aligns with ethical safeguards.","published":"2025-04-09T06:53:23Z","updated":"2025-04-09T06:53:23Z","categories":["cs.LG","cs.AI","cs.CR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.08813v1","pdf_url":"https://arxiv.org/pdf/2504.08813v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.06564","versioned_id":"2504.06564v3","title":"Thinking Out Loud: Do Reasoning Models Know When They're Right?","authors":["Qingcheng Zeng","Weihao Xuan","Leyang Cui","Rob Voigt"],"abstract":"Large reasoning models (LRMs) have recently demonstrated impressive capabilities in complex reasoning tasks by leveraging increased test-time computation and exhibiting behaviors reminiscent of human-like self-reflection. While LRMs show a clear capacity for valuable self-reflection, how this ability interacts with other model behaviors remains underexplored. We investigate this connection by analyzing verbalized confidence, how models articulate their certainty, as a lens into the nature of self-reflection in LRMs. We find that supervised fine-tuning on reasoning traces (i.e., distillation) and reinforcement learning can improve verbalized calibration in reasoning-intensive settings in a progressive, laddered fashion. However, our results also indicate that reasoning models may possess a diminished awareness of their own knowledge boundaries, as evidenced by significantly lower \"I don't know\" response rates on factuality benchmarks. Moreover, we examine the relationship between verbalized confidence and reasoning chains, finding that models tend to express higher confidence when providing shorter or less elaborate reasoning. Our findings highlight how reasoning-oriented training can enhance performance in reasoning-centric tasks while potentially incurring a \"reasoning tax,\" a cost reflected in the model's reduced ability to accurately recognize the limits of its own knowledge in small-scale models. More broadly, our work showcases how this erosion of knowledge boundaries can compromise model faithfulness, as models grow more confident without a commensurate understanding of when they should abstain.","published":"2025-04-09T03:58:19Z","updated":"2025-10-19T23:55:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.06564v3","pdf_url":"https://arxiv.org/pdf/2504.06564v3","comment":"EMNLP 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.05614","versioned_id":"2504.05614v1","title":"Two Intermediate Translations Are Better Than One: Fine-tuning LLMs for Document-level Translation Refinement","authors":["Yichen Dong","Xinglin Lyu","Junhui Li","Daimeng Wei","Min Zhang","Shimin Tao","Hao Yang"],"abstract":"Recent research has shown that large language models (LLMs) can enhance translation quality through self-refinement. In this paper, we build on this idea by extending the refinement from sentence-level to document-level translation, specifically focusing on document-to-document (Doc2Doc) translation refinement. Since sentence-to-sentence (Sent2Sent) and Doc2Doc translation address different aspects of the translation process, we propose fine-tuning LLMs for translation refinement using two intermediate translations, combining the strengths of both Sent2Sent and Doc2Doc. Additionally, recognizing that the quality of intermediate translations varies, we introduce an enhanced fine-tuning method with quality awareness that assigns lower weights to easier translations and higher weights to more difficult ones, enabling the model to focus on challenging translation cases. Experimental results across ten translation tasks with LLaMA-3-8B-Instruct and Mistral-Nemo-Instruct demonstrate the effectiveness of our approach.","published":"2025-04-08T02:08:07Z","updated":"2025-04-08T02:08:07Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.05614v1","pdf_url":"https://arxiv.org/pdf/2504.05614v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.05605","versioned_id":"2504.05605v1","title":"ShadowCoT: Cognitive Hijacking for Stealthy Reasoning Backdoors in LLMs","authors":["Gejian Zhao","Hanzhou Wu","Xinpeng Zhang","Athanasios V. Vasilakos"],"abstract":"Chain-of-Thought (CoT) enhances an LLM's ability to perform complex reasoning tasks, but it also introduces new security issues. In this work, we present ShadowCoT, a novel backdoor attack framework that targets the internal reasoning mechanism of LLMs. Unlike prior token-level or prompt-based attacks, ShadowCoT directly manipulates the model's cognitive reasoning path, enabling it to hijack multi-step reasoning chains and produce logically coherent but adversarial outcomes. By conditioning on internal reasoning states, ShadowCoT learns to recognize and selectively disrupt key reasoning steps, effectively mounting a self-reflective cognitive attack within the target model. Our approach introduces a lightweight yet effective multi-stage injection pipeline, which selectively rewires attention pathways and perturbs intermediate representations with minimal parameter overhead (only 0.15% updated). ShadowCoT further leverages reinforcement learning and reasoning chain pollution (RCP) to autonomously synthesize stealthy adversarial CoTs that remain undetectable to advanced defenses. Extensive experiments across diverse reasoning benchmarks and LLMs show that ShadowCoT consistently achieves high Attack Success Rate (94.4%) and Hijacking Success Rate (88.4%) while preserving benign performance. These results reveal an emergent class of cognition-level threats and highlight the urgent need for defenses beyond shallow surface-level consistency.","published":"2025-04-08T01:36:16Z","updated":"2025-04-08T01:36:16Z","categories":["cs.CR","cs.CL"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2504.05605v1","pdf_url":"https://arxiv.org/pdf/2504.05605v1","comment":"Zhao et al., 16 pages, 2025, uploaded by Hanzhou Wu, Shanghai University","journal_ref":"IEEE Transactions on Information Forensics and Security (2026)","doi":"","discovered_on":"2026-07-17"},{"id":"2504.05258","versioned_id":"2504.05258v2","title":"Learning to Reason Over Time: Timeline Self-Reflection for Improved Temporal Reasoning in Language Models","authors":["Adrián Bazaga","Rexhina Blloshmi","Bill Byrne","Adrià de Gispert"],"abstract":"Large Language Models (LLMs) have emerged as powerful tools for generating coherent text, understanding context, and performing reasoning tasks. However, they struggle with temporal reasoning, which requires processing time-related information such as event sequencing, durations, and inter-temporal relationships. These capabilities are critical for applications including question answering, scheduling, and historical analysis. In this paper, we introduce TISER, a novel framework that enhances the temporal reasoning abilities of LLMs through a multi-stage process that combines timeline construction with iterative self-reflection. Our approach leverages test-time scaling to extend the length of reasoning traces, enabling models to capture complex temporal dependencies more effectively. This strategy not only boosts reasoning accuracy but also improves the traceability of the inference process. Experimental results demonstrate state-of-the-art performance across multiple benchmarks, including out-of-distribution test sets, and reveal that TISER enables smaller open-source models to surpass larger closed-weight models on challenging temporal reasoning tasks.","published":"2025-04-07T16:51:45Z","updated":"2025-05-30T15:37:19Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.05258v2","pdf_url":"https://arxiv.org/pdf/2504.05258v2","comment":"ACL 2025 (Main)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.04918","versioned_id":"2504.04918v1","title":"Constitution or Collapse? Exploring Constitutional AI with Llama 3-8B","authors":["Xue Zhang"],"abstract":"As language models continue to grow larger, the cost of acquiring high-quality training data has increased significantly. Collecting human feedback is both expensive and time-consuming, and manual labels can be noisy, leading to an imbalance between helpfulness and harmfulness. Constitutional AI, introduced by Anthropic in December 2022, uses AI to provide feedback to another AI, greatly reducing the need for human labeling. However, the original implementation was designed for a model with around 52 billion parameters, and there is limited information on how well Constitutional AI performs with smaller models, such as LLaMA 3-8B. In this paper, we replicated the Constitutional AI workflow using the smaller LLaMA 3-8B model. Our results show that Constitutional AI can effectively increase the harmlessness of the model, reducing the Attack Success Rate in MT-Bench by 40.8%. However, similar to the original study, increasing harmlessness comes at the cost of helpfulness. The helpfulness metrics, which are an average of the Turn 1 and Turn 2 scores, dropped by 9.8% compared to the baseline. Additionally, we observed clear signs of model collapse in the final DPO-CAI model, indicating that smaller models may struggle with self-improvement due to insufficient output quality, making effective fine-tuning more challenging. Our study suggests that, like reasoning and math ability, self-improvement is an emergent property.","published":"2025-04-07T11:01:25Z","updated":"2025-04-07T11:01:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.04918v1","pdf_url":"https://arxiv.org/pdf/2504.04918v1","comment":"6 pages, 2 figures. Conducted as part of research on alignment techniques for language models","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.04711","versioned_id":"2504.04711v1","title":"Generalising from Self-Produced Data: Model Training Beyond Human Constraints","authors":["Alfath Daryl Alhajir","Jennifer Dodgson","Joseph Lim","Truong Ma Phi","Julian Peh","Akira Rafhael Janson Pattirane","Lokesh Poovaragan"],"abstract":"Current large language models (LLMs) are constrained by human-derived training data and limited by a single level of abstraction that impedes definitive truth judgments. This paper introduces a novel framework in which AI models autonomously generate and validate new knowledge through direct interaction with their environment. Central to this approach is an unbounded, ungamable numeric reward - such as annexed disk space or follower count - that guides learning without requiring human benchmarks. AI agents iteratively generate strategies and executable code to maximize this metric, with successful outcomes forming the basis for self-retraining and incremental generalisation. To mitigate model collapse and the warm start problem, the framework emphasizes empirical validation over textual similarity and supports fine-tuning via GRPO. The system architecture employs modular agents for environment analysis, strategy generation, and code synthesis, enabling scalable experimentation. This work outlines a pathway toward self-improving AI systems capable of advancing beyond human-imposed constraints toward autonomous general intelligence.","published":"2025-04-07T03:48:02Z","updated":"2025-04-07T03:48:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.04711v1","pdf_url":"https://arxiv.org/pdf/2504.04711v1","comment":"16 pages, 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.04383","versioned_id":"2504.04383v2","title":"Retro-Search: Exploring Untaken Paths for Deeper and Efficient Reasoning","authors":["Ximing Lu","Seungju Han","David Acuna","Hyunwoo Kim","Jaehun Jung","Shrimai Prabhumoye","Niklas Muennighoff","Mostofa Patwary","Mohammad Shoeybi","Bryan Catanzaro","Yejin Choi"],"abstract":"Large reasoning models exhibit remarkable reasoning capabilities via long, elaborate reasoning trajectories. Supervised fine-tuning on such reasoning traces, also known as distillation, can be a cost-effective way to boost reasoning capabilities of student models. However, empirical observations reveal that these reasoning trajectories are often suboptimal, switching excessively between different lines of thought, resulting in under-thinking, over-thinking, and even degenerate responses. We introduce Retro-Search, an MCTS-inspired search algorithm, for distilling higher quality reasoning paths from large reasoning models. Retro-Search retrospectively revises reasoning paths to discover better, yet shorter traces, which can then lead to student models with enhanced reasoning capabilities with shorter, thus faster inference. Our approach can enable two use cases: self-improvement, where models are fine-tuned on their own Retro-Search-ed thought traces, and weak-to-strong improvement, where a weaker model revises stronger model's thought traces via Retro-Search. For self-improving, R1-distill-7B, fine-tuned on its own Retro-Search-ed traces, reduces the average reasoning length by 31.2% while improving performance by 7.7% across seven math benchmarks. For weak-to-strong improvement, we retrospectively revise R1-671B's traces from the OpenThoughts dataset using R1-distill-32B as the Retro-Search-er, a model 20x smaller. Qwen2.5-32B, fine-tuned on this refined data, achieves performance comparable to R1-distill-32B, yielding an 11.3% reduction in reasoning length and a 2.4% performance improvement compared to fine-tuning on the original OpenThoughts data. Our work counters recently emergent viewpoints that question the relevance of search algorithms in the era of large reasoning models, by demonstrating that there are still opportunities for algorithmic advancements, even for frontier models.","published":"2025-04-06T06:23:27Z","updated":"2025-04-15T14:07:31Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.04383v2","pdf_url":"https://arxiv.org/pdf/2504.04383v2","comment":"Code and data will be publicly released upon internal approval","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.04022","versioned_id":"2504.04022v1","title":"Rethinking Reflection in Pre-Training","authors":["Essential AI",":","Darsh J Shah","Peter Rushton","Somanshu Singla","Mohit Parmar","Kurt Smith","Yash Vanjani","Ashish Vaswani","Adarsh Chaluvaraju","Andrew Hojel","Andrew Ma","Anil Thomas","Anthony Polloreno","Ashish Tanwer","Burhan Drak Sibai","Divya S Mansingka","Divya Shivaprasad","Ishaan Shah","Karl Stratos","Khoi Nguyen","Michael Callahan","Michael Pust","Mrinal Iyer","Philip Monk","Platon Mazarakis","Ritvik Kapila","Saurabh Srivastava","Tim Romanski"],"abstract":"A language model's ability to reflect on its own reasoning provides a key advantage for solving complex problems. While most recent research has focused on how this ability develops during reinforcement learning, we show that it actually begins to emerge much earlier - during the model's pre-training. To study this, we introduce deliberate errors into chains-of-thought and test whether the model can still arrive at the correct answer by recognizing and correcting these mistakes. By tracking performance across different stages of pre-training, we observe that this self-correcting ability appears early and improves steadily over time. For instance, an OLMo2-7B model pre-trained on 4 trillion tokens displays self-correction on our six self-reflection tasks.","published":"2025-04-05T02:24:07Z","updated":"2025-04-05T02:24:07Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.04022v1","pdf_url":"https://arxiv.org/pdf/2504.04022v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.03846","versioned_id":"2504.03846v3","title":"Do LLM Evaluators Prefer Themselves for a Reason?","authors":["Wei-Lin Chen","Zhepei Wei","Xinyu Zhu","Shi Feng","Yu Meng"],"abstract":"Large language models (LLMs) are increasingly used as automatic evaluators in applications such as benchmarking, reward modeling, and self-refinement. Prior work highlights a potential self-preference bias where LLMs favor their own generated responses, a tendency often intensifying with model size and capability. This raises a critical question: Is self-preference harmful, or does it simply reflect the genuinely higher-quality outputs of stronger models? Answering this has been difficult as prior works mostly relied on subjective tasks that lack an objective ground truth, meaning that either preference can be reasonably justified. To address this ambiguity, we investigate self-preference using verifiable benchmarks (mathematical reasoning, factual knowledge, code generation) that allow objective ground-truth assessment. This enables us to distinguish harmful (favoring objectively worse responses) from legitimate (favoring genuinely superior ones) self-preference. Our large-scale experiments across 7 model families reveal three key findings: (1) While stronger models exhibit greater self-preference, much of this preference aligns with objectively superior performance, indicating stronger models prefer themselves mostly legitimately. (2) Harmful self-preference persists when evaluator models err as generators, and stronger models display more pronounced harmful self-preference bias when they do err. This suggests stronger models struggle more to recognize when they are wrong. (3) Inference-time scaling strategies, such as generating a long Chain-of-Thought before evaluation, effectively reduce the harmful self-preference. Additionally, we experiment with LMArena and show that our findings extend beyond verifiable benchmarks to real-world, subjective domains. These results provide a more nuanced understanding of LLM-based evaluation and practical insights for improving its reliability.","published":"2025-04-04T18:09:23Z","updated":"2025-12-12T23:18:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.03846v3","pdf_url":"https://arxiv.org/pdf/2504.03846v3","comment":"Added LMArena experiments","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.03160","versioned_id":"2504.03160v4","title":"DeepResearcher: Scaling Deep Research via Reinforcement Learning in Real-world Environments","authors":["Yuxiang Zheng","Dayuan Fu","Xiangkun Hu","Xiaojie Cai","Lyumanshan Ye","Pengrui Lu","Pengfei Liu"],"abstract":"Large Language Models (LLMs) equipped with web search capabilities have demonstrated impressive potential for deep research tasks. However, current approaches predominantly rely on either manually engineered prompts (prompt engineering-based) with brittle performance or reinforcement learning within controlled Retrieval-Augmented Generation (RAG) environments (RAG-based) that fail to capture the complexities of real-world interaction. In this paper, we introduce DeepResearcher, the first comprehensive framework for end-to-end training of LLM-based deep research agents through scaling reinforcement learning (RL) in real-world environments with authentic web search interactions. Unlike RAG-based approaches that assume all necessary information exists within a fixed corpus, our method trains agents to navigate the noisy, unstructured, and dynamic nature of the open web. We implement a specialized multi-agent architecture where browsing agents extract relevant information from various webpage structures and overcoming significant technical challenges. Extensive experiments on open-domain research tasks demonstrate that DeepResearcher achieves substantial improvements of up to 28.9 points over prompt engineering-based baselines and up to 7.2 points over RAG-based RL agents. Our qualitative analysis reveals emergent cognitive behaviors from end-to-end RL training, including the ability to formulate plans, cross-validate information from multiple sources, engage in self-reflection to redirect research, and maintain honesty when unable to find definitive answers. Our results highlight that end-to-end training in real-world web environments is not merely an implementation detail but a fundamental requirement for developing robust research capabilities aligned with real-world applications. We release DeepResearcher at https://github.com/GAIR-NLP/DeepResearcher.","published":"2025-04-04T04:41:28Z","updated":"2025-04-17T04:46:08Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.03160v4","pdf_url":"https://arxiv.org/pdf/2504.03160v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.02956","versioned_id":"2504.02956v1","title":"Understanding Aha Moments: from External Observations to Internal Mechanisms","authors":["Shu Yang","Junchao Wu","Xin Chen","Yunze Xiao","Xinyi Yang","Derek F. Wong","Di Wang"],"abstract":"Large Reasoning Models (LRMs), capable of reasoning through complex problems, have become crucial for tasks like programming, mathematics, and commonsense reasoning. However, a key challenge lies in understanding how these models acquire reasoning capabilities and exhibit \"aha moments\" when they reorganize their methods to allocate more thinking time to problems. In this work, we systematically study \"aha moments\" in LRMs, from linguistic patterns, description of uncertainty, \"Reasoning Collapse\" to analysis in latent space. We demonstrate that the \"aha moment\" is externally manifested in a more frequent use of anthropomorphic tones for self-reflection and an adaptive adjustment of uncertainty based on problem difficulty. This process helps the model complete reasoning without succumbing to \"Reasoning Collapse\". Internally, it corresponds to a separation between anthropomorphic characteristics and pure reasoning, with an increased anthropomorphic tone for more difficult problems. Furthermore, we find that the \"aha moment\" helps models solve complex problems by altering their perception of problem difficulty. As the layer of the model increases, simpler problems tend to be perceived as more complex, while more difficult problems appear simpler.","published":"2025-04-03T18:22:20Z","updated":"2025-04-03T18:22:20Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.02956v1","pdf_url":"https://arxiv.org/pdf/2504.02956v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.02902","versioned_id":"2504.02902v1","title":"Beyond Accuracy: The Role of Calibration in Self-Improving Large Language Models","authors":["Liangjie Huang","Dawei Li","Huan Liu","Lu Cheng"],"abstract":"Large Language Models (LLMs) have demonstrated remarkable self-improvement capabilities, whereby models iteratively revise their outputs through self-generated feedback. While this reflective mechanism has shown promise in enhancing task performance, recent studies suggest that it may also introduce undesirable biases-most notably, self-bias, or the tendency of LLMs to favor their own prior outputs. In this work, we extend this line of inquiry by investigating the impact on confidence estimation. We evaluate three representative self-improvement paradigms-basic prompting, Chain-of-Thought (CoT) prompting, and tuning-based methods and find that iterative self-improvement can lead to systematic overconfidence, as evidenced by a steadily increasing Expected Calibration Error (ECE) and lower accuracy with high confidence. We then further explore the integration of confidence calibration techniques with self-improvement. Specifically, we compare three strategies: (1) applying calibration after multiple rounds of self-improvement, (2) calibrating before self-improvement, and (3) applying calibration iteratively at each self-improvement step. Our results show that iterative calibration is most effective in reducing ECE, yielding improved calibration. Our work pioneers the study of self-improving LLMs from a calibration perspective, offering valuable insights into balancing model performance and reliability.","published":"2025-04-03T04:39:54Z","updated":"2025-04-03T04:39:54Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.02902v1","pdf_url":"https://arxiv.org/pdf/2504.02902v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.01407","versioned_id":"2504.01407v2","title":"TimeSearch: Hierarchical Video Search with Spotlight and Reflection for Human-like Long Video Understanding","authors":["Junwen Pan","Rui Zhang","Xin Wan","Yuan Zhang","Ming Lu","Qi She"],"abstract":"Large video-language models (LVLMs) have shown remarkable performance across various video-language tasks. However, they encounter significant challenges when processing long videos because of the large number of video frames involved. Downsampling long videos in either space or time can lead to visual hallucinations, making it difficult to accurately interpret long videos. Motivated by human hierarchical temporal search strategies, we propose \\textbf{TimeSearch}, a novel framework enabling LVLMs to understand long videos in a human-like manner. TimeSearch integrates two human-like primitives into a unified autoregressive LVLM: 1) \\textbf{Spotlight} efficiently identifies relevant temporal events through a Temporal-Augmented Frame Representation (TAFR), explicitly binding visual features with timestamps; 2) \\textbf{Reflection} evaluates the correctness of the identified events, leveraging the inherent temporal self-reflection capabilities of LVLMs. TimeSearch progressively explores key events and prioritizes temporal search based on reflection confidence. Extensive experiments on challenging long-video benchmarks confirm that TimeSearch substantially surpasses previous state-of-the-art, improving the accuracy from 41.8\\% to 51.5\\% on the LVBench. Additionally, experiments on temporal grounding demonstrate that appropriate TAFR is adequate to effectively stimulate the surprising temporal grounding ability of LVLMs in a simpler yet versatile manner, which improves mIoU on Charades-STA by 11.8\\%. The code will be released.","published":"2025-04-02T06:47:19Z","updated":"2025-12-02T06:25:21Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2504.01407v2","pdf_url":"https://arxiv.org/pdf/2504.01407v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.01400","versioned_id":"2504.01400v3","title":"ToolACE-R: Model-aware Iterative Training and Adaptive Refinement for Tool Learning","authors":["Xingshan Zeng","Weiwen Liu","Xu Huang","Zezhong Wang","Lingzhi Wang","Liangyou Li","Yasheng Wang","Lifeng Shang","Xin Jiang","Ruiming Tang","Qun Liu"],"abstract":"Tool learning, which allows Large Language Models (LLMs) to leverage external tools for solving complex user tasks, has emerged as a promising avenue for extending model capabilities. However, existing approaches primarily focus on data synthesis for fine-tuning LLMs to invoke tools effectively, largely ignoring how to fully stimulate the potential of the model. In this paper, we propose ToolACE-R, a novel framework that includes both model-aware iterative training and adaptive refinement for tool learning. ToolACE-R features a model-aware iterative training procedure that progressively adjust training samples based on the model's evolving capabilities to maximize its potential. Additionally, it incorporates self-refinement training corpus which emphasizes LLM's ability to iteratively refine their tool calls, optimizing performance without requiring external feedback. Furthermore, we introduce adaptive self-refinement mechanism for efficient test-time scaling, where the trained model can autonomously determine when to stop the process based on iterative self-refinement. We conduct extensive experiments across several benchmark datasets, showing that ToolACE-R achieves competitive performance compared to advanced API-based models. The performance of tool invocation can be further improved efficiently through adaptive self-refinement. These results highlight the effectiveness and generalizability of ToolACE-R, offering a promising direction for more efficient and scalable tool learning.","published":"2025-04-02T06:38:56Z","updated":"2026-01-10T10:48:00Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.01400v3","pdf_url":"https://arxiv.org/pdf/2504.01400v3","comment":"Accepted by AAAI2026","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.01317","versioned_id":"2504.01317v2","title":"Adaptive Rectification Sampling for Test-Time Compute Scaling","authors":["Zhendong Tan","Xingjun Zhang","Chaoyi Hu","Yancheng Pan","Shaoxun Wang"],"abstract":"The newly released OpenAI-o1 and DeepSeek-R1 have demonstrated that test-time scaling can significantly improve model performance, especially in complex tasks such as logical reasoning. Common test-time scaling methods involve generating more chains of thought (CoTs) or longer CoTs with self-correction. However, while self-correction can improve performance, it may lead to significant token waste and reduce readability of the CoT if the reasoning steps are already correct. To demonstrate that large language models (LLMs) can rectify errors at a more fine-grained level, we propose Adaptive Rectification Sampling (AR-Sampling), which can guide the LLMs to self-correction at the appropriate step. AR-Sampling leverages a process-supervised reward model (PRM) as a verifier and constructed trigger sentences to guide the model in adaptive step-level rethinking. Through the experiments on GSM8K and MATH500, it indicates that our approach enables the models to rethink in more fine-grained level, improving the accuracy of solutions, while generating a reasonable number of additional tokens.","published":"2025-04-02T02:57:52Z","updated":"2025-09-30T02:15:08Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.01317v2","pdf_url":"https://arxiv.org/pdf/2504.01317v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.01253","versioned_id":"2504.01253v1","title":"Grade Guard: A Smart System for Short Answer Automated Grading","authors":["Niharika Dadu","Harsh Vardhan Singh","Romi Banerjee"],"abstract":"The advent of large language models (LLMs) in the education sector has provided impetus to automate grading short answer questions. LLMs make evaluating short answers very efficient, thus addressing issues like staff shortage. However, in the task of Automated Short Answer Grading (ASAG), LLM responses are influenced by diverse perspectives in their training dataset, leading to inaccuracies in evaluating nuanced or partially correct answers. To address this challenge, we propose a novel framework, Grade Guard. 1. To enhance the task-based specialization of the LLMs, the temperature parameter has been fine-tuned using Root Mean Square Error (RMSE). 2. Unlike traditional approaches, LLMs in Grade Guard compute an Indecisiveness Score (IS) along with the grade to reflect uncertainty in predicted grades. 3. Introduced Confidence-Aware Loss (CAL) to generate an optimized Indecisiveness Score (IS). 4. To improve reliability, self-reflection based on the optimized IS has been introduced into the framework, enabling human re-evaluation to minimize incorrect grade assignments. Our experimentation shows that the best setting of Grade Guard outperforms traditional methods by 19.16% RMSE in Upstage Solar Pro, 23.64% RMSE in Upstage Solar Mini, 4.00% RMSE in Gemini 1.5 Flash, and 10.20% RMSE in GPT 4-o Mini. Future work includes improving interpretability by generating rationales for grades to enhance accuracy. Expanding benchmark datasets and annotating them with domain-specific nuances will enhance grading accuracy. Finally, analyzing feedback to enhance confidence in predicted grades, reduce biases, optimize grading criteria, and personalize learning while supporting multilingual grading systems will make the solution more accurate, adaptable, fair, and inclusive.","published":"2025-04-01T23:45:44Z","updated":"2025-04-01T23:45:44Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.01253v1","pdf_url":"https://arxiv.org/pdf/2504.01253v1","comment":"11 pages, 18 figures","journal_ref":"","doi":"10.36227/techrxiv.174114489.93670234/v1","discovered_on":"2026-07-17"},{"id":"2504.02871","versioned_id":"2504.02871v1","title":"Synthesized Annotation Guidelines are Knowledge-Lite Boosters for Clinical Information Extraction","authors":["Enshuo Hsu","Martin Ugbala","Krishna Kumar Kookal","Zouaidi Kawtar","Nicholas L. Rider","Muhammad F. Walji","Kirk Roberts"],"abstract":"Generative information extraction using large language models, particularly through few-shot learning, has become a popular method. Recent studies indicate that providing a detailed, human-readable guideline-similar to the annotation guidelines traditionally used for training human annotators can significantly improve performance. However, constructing these guidelines is both labor- and knowledge-intensive. Additionally, the definitions are often tailored to meet specific needs, making them highly task-specific and often non-reusable. Handling these subtle differences requires considerable effort and attention to detail. In this study, we propose a self-improving method that harvests the knowledge summarization and text generation capacity of LLMs to synthesize annotation guidelines while requiring virtually no human input. Our zero-shot experiments on the clinical named entity recognition benchmarks, 2012 i2b2 EVENT, 2012 i2b2 TIMEX, 2014 i2b2, and 2018 n2c2 showed 25.86%, 4.36%, 0.20%, and 7.75% improvements in strict F1 scores from the no-guideline baseline. The LLM-synthesized guidelines showed equivalent or better performance compared to human-written guidelines by 1.15% to 4.14% in most tasks. In conclusion, this study proposes a novel LLM self-improving method that requires minimal knowledge and human input and is applicable to multiple biomedical domains.","published":"2025-04-01T15:59:04Z","updated":"2025-04-01T15:59:04Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.02871v1","pdf_url":"https://arxiv.org/pdf/2504.02871v1","comment":"","journal_ref":"","doi":"10.1093/jamia/ocag084","discovered_on":"2026-07-17"},{"id":"2504.00698","versioned_id":"2504.00698v2","title":"Command A: An Enterprise-Ready Large Language Model","authors":["Team Cohere",":","Aakanksha","Arash Ahmadian","Marwan Ahmed","Jay Alammar","Milad Alizadeh","Yazeed Alnumay","Sophia Althammer","Arkady Arkhangorodsky","Viraat Aryabumi","Dennis Aumiller","Raphaël Avalos","Zahara Aviv","Sammie Bae","Saurabh Baji","Alexandre Barbet","Max Bartolo","Björn Bebensee","Neeral Beladia","Walter Beller-Morales","Alexandre Bérard","Andrew Berneshawi","Anna Bialas","Phil Blunsom","Matt Bobkin","Adi Bongale","Sam Braun","Maxime Brunet","Samuel Cahyawijaya","David Cairuz","Jon Ander Campos","Cassie Cao","Kris Cao","Roman Castagné","Julián Cendrero","Leila Chan Currie","Yash Chandak","Diane Chang","Giannis Chatziveroglou","Hongyu Chen","Claire Cheng","Alexis Chevalier","Justin T. Chiu","Eugene Cho","Eugene Choi","Eujeong Choi","Tim Chung","Volkan Cirik","Ana Cismaru","Pierre Clavier","Henry Conklin","Lucas Crawhall-Stein","Devon Crouse","Andres Felipe Cruz-Salinas","Ben Cyrus","Daniel D'souza","Hugo Dalla-Torre","John Dang","William Darling","Omar Darwiche Domingues","Saurabh Dash","Antoine Debugne","Théo Dehaze","Shaan Desai","Joan Devassy","Rishit Dholakia","Kyle Duffy","Ali Edalati","Ace Eldeib","Abdullah Elkady","Sarah Elsharkawy","Irem Ergün","Beyza Ermis","Marzieh Fadaee","Boyu Fan","Lucas Fayoux","Yannis Flet-Berliac","Nick Frosst","Matthias Gallé","Wojciech Galuba","Utsav Garg","Matthieu Geist","Mohammad Gheshlaghi Azar","Ellen Gilsenan-McMahon","Seraphina Goldfarb-Tarrant","Tomas Goldsack","Aidan Gomez","Victor Machado Gonzaga","Nithya Govindarajan","Manoj Govindassamy","Nathan Grinsztajn","Nikolas Gritsch","Patrick Gu","Shangmin Guo","Kilian Haefeli","Rod Hajjar","Tim Hawes","Jingyi He","Sebastian Hofstätter","Sungjin Hong","Sara Hooker","Tom Hosking","Stephanie Howe","Eric Hu","Renjie Huang","Hemant Jain","Ritika Jain","Nick Jakobi","Madeline Jenkins","JJ Jordan","Dhruti Joshi","Jason Jung","Trushant Kalyanpur","Siddhartha Rao Kamalakara","Julia Kedrzycki","Gokce Keskin","Edward Kim","Joon Kim","Wei-Yin Ko","Tom Kocmi","Michael Kozakov","Wojciech Kryściński","Arnav Kumar Jain","Komal Kumar Teru","Sander Land","Michael Lasby","Olivia Lasche","Justin Lee","Patrick Lewis","Jeffrey Li","Jonathan Li","Hangyu Lin","Acyr Locatelli","Kevin Luong","Raymond Ma","Lukáš Mach","Marina Machado","Joanne Magbitang","Brenda Malacara Lopez","Aryan Mann","Kelly Marchisio","Olivia Markham","Alexandre Matton","Alex McKinney","Dominic McLoughlin","Jozef Mokry","Adrien Morisot","Autumn Moulder","Harry Moynehan","Maximilian Mozes","Vivek Muppalla","Lidiya Murakhovska","Hemangani Nagarajan","Alekhya Nandula","Hisham Nasir","Shauna Nehra","Josh Netto-Rosen","Daniel Ohashi","James Owers-Bardsley","Jason Ozuzu","Dennis Padilla","Gloria Park","Sam Passaglia","Jeremy Pekmez","Laura Penstone","Aleksandra Piktus","Case Ploeg","Andrew Poulton","Youran Qi","Shubha Raghvendra","Miguel Ramos","Ekagra Ranjan","Pierre Richemond","Cécile Robert-Michon","Aurélien Rodriguez","Sudip Roy","Sebastian Ruder","Laura Ruis","Louise Rust","Anubhav Sachan","Alejandro Salamanca","Kailash Karthik Saravanakumar","Isha Satyakam","Alice Schoenauer Sebag","Priyanka Sen","Sholeh Sepehri","Preethi Seshadri","Ye Shen","Tom Sherborne","Sylvie Shang Shi","Sanal Shivaprasad","Vladyslav Shmyhlo","Anirudh Shrinivason","Inna Shteinbuk","Amir Shukayev","Mathieu Simard","Ella Snyder","Ava Spataru","Victoria Spooner","Trisha Starostina","Florian Strub","Yixuan Su","Jimin Sun","Dwarak Talupuru","Eugene Tarassov","Elena Tommasone","Jennifer Tracey","Billy Trend","Evren Tumer","Ahmet Üstün","Bharat Venkitesh","David Venuto","Pat Verga","Maxime Voisin","Alex Wang","Donglu Wang","Shijian Wang","Edmond Wen","Naomi White","Jesse Willman","Marysia Winkels","Chen Xia","Jessica Xie","Minjie Xu","Bowen Yang","Tan Yi-Chern","Ivan Zhang","Zhenyu Zhao","Zhoujie Zhao"],"abstract":"In this report we describe the development of Command A, a powerful large language model purpose-built to excel at real-world enterprise use cases. Command A is an agent-optimised and multilingual-capable model, with support for 23 languages of global business, and a novel hybrid architecture balancing efficiency with top of the range performance. It offers best-in-class Retrieval Augmented Generation (RAG) capabilities with grounding and tool use to automate sophisticated business processes. These abilities are achieved through a decentralised training approach, including self-refinement algorithms and model merging techniques. We also include results for Command R7B which shares capability and architectural similarities to Command A. Weights for both models have been released for research purposes. This technical report details our original training pipeline and presents an extensive evaluation of our models across a suite of enterprise-relevant tasks and public benchmarks, demonstrating excellent performance and efficiency.","published":"2025-04-01T12:08:07Z","updated":"2025-04-14T12:37:51Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.00698v2","pdf_url":"https://arxiv.org/pdf/2504.00698v2","comment":"55 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.00473","versioned_id":"2504.00473v1","title":"Making Large Language Models Better Reasoners with Orchestrated Streaming Experiences","authors":["Xiangyang Liu","Junliang He","Xipeng Qiu"],"abstract":"Large language models (LLMs) can perform complex reasoning by generating intermediate thoughts under zero-shot or few-shot settings. However, zero-shot prompting always encounters low performance, and the superior performance of few-shot prompting hinges on the manual-crafted demonstrations. In this paper, we present RoSE (Reasoning with Orchestrated Streaming Experiences), a general framework for solving reasoning tasks that can self-improve without complex external efforts. To enable RoSE, we describe an architecture that extends an LLM to store all answered questions and their thoughts in a streaming experience pool then orchestrates helpful questions from the pool to assist in answering new questions. To set up a question-aware orchestration mechanism, RoSE first calculates the similarity of each question in the pool with a new test question. Since the solution to each answered question is not always correct, RoSE will sort the questions according to their similarity with the new question, and then uniformly divide them into multiple buckets. It finally extracts one question from each bucket to make these extracted questions more diverse. To make these extracted questions help RoSE answer new questions as much as possible, we introduce two other attributes of uncertainty and complexity for each question. RoSE will preferentially select the questions with low uncertainty and high complexity from each bucket. We evaluate the versatility of RoSE in various reasoning tasks, LLMs, and CoT methods.","published":"2025-04-01T07:04:04Z","updated":"2025-04-01T07:04:04Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.00473v1","pdf_url":"https://arxiv.org/pdf/2504.00473v1","comment":"Accepted by EMNLP 2024","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.24388","versioned_id":"2503.24388v1","title":"RIG: Synergizing Reasoning and Imagination in End-to-End Generalist Policy","authors":["Zhonghan Zhao","Wenwei Zhang","Haian Huang","Kuikun Liu","Jianfei Gao","Gaoang Wang","Kai Chen"],"abstract":"Reasoning before action and imagining potential outcomes (i.e., world models) are essential for embodied agents operating in complex open-world environments. Yet, prior work either incorporates only one of these abilities in an end-to-end agent or integrates multiple specialized models into an agent system, limiting the learning efficiency and generalization of the policy. Thus, this paper makes the first attempt to synergize Reasoning and Imagination in an end-to-end Generalist policy, termed RIG. To train RIG in an end-to-end manner, we construct a data pipeline that progressively integrates and enriches the content of imagination and reasoning in the trajectories collected from existing agents. The joint learning of reasoning and next image generation explicitly models the inherent correlation between reasoning, action, and dynamics of environments, and thus exhibits more than $17\\times$ sample efficiency improvements and generalization in comparison with previous works. During inference, RIG first reasons about the next action, produces potential action, and then predicts the action outcomes, which offers the agent a chance to review and self-correct based on the imagination before taking real actions. Experimental results show that the synergy of reasoning and imagination not only improves the robustness, generalization, and interoperability of generalist policy but also enables test-time scaling to enhance overall performance.","published":"2025-03-31T17:59:52Z","updated":"2025-03-31T17:59:52Z","categories":["cs.AI","cs.CL","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.24388v1","pdf_url":"https://arxiv.org/pdf/2503.24388v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.23145","versioned_id":"2503.23145v2","title":"CodeARC: Benchmarking Reasoning Capabilities of LLM Agents for Inductive Program Synthesis","authors":["Anjiang Wei","Tarun Suresh","Jiannan Cao","Naveen Kannan","Yuheng Wu","Kai Yan","Thiago S. F. X. Teixeira","Ke Wang","Alex Aiken"],"abstract":"Inductive program synthesis, or programming by example, requires synthesizing functions from input-output examples that generalize to unseen inputs. While large language model agents have shown promise in programming tasks guided by natural language, their ability to perform inductive program synthesis is underexplored. Existing evaluation protocols rely on static sets of examples and held-out tests, offering no feedback when synthesized functions are incorrect and failing to reflect real-world scenarios such as reverse engineering. We propose CodeARC, the Code Abstraction and Reasoning Challenge, a new evaluation framework where agents interact with a hidden target function by querying it with new inputs, synthesizing candidate functions, and iteratively refining their solutions using a differential testing oracle. This interactive setting encourages agents to perform function calls and self-correction based on feedback. We construct the first large-scale benchmark for general-purpose inductive program synthesis, featuring 1114 functions. Among 18 models evaluated, o3-mini performs best with a success rate of 52.7%, highlighting the difficulty of this task. Fine-tuning LLaMA-3.1-8B-Instruct on curated synthesis traces yields up to a 31% relative performance gain. CodeARC provides a more realistic and challenging testbed for evaluating LLM-based program synthesis and inductive reasoning. Our code, data, and models are publicly available at https://github.com/Anjiang-Wei/CodeARC","published":"2025-03-29T16:50:39Z","updated":"2025-08-08T07:13:11Z","categories":["cs.PL","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.PL","arxiv_url":"https://arxiv.org/abs/2503.23145v2","pdf_url":"https://arxiv.org/pdf/2503.23145v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.23037","versioned_id":"2503.23037v3","title":"Agentic Large Language Models, a survey","authors":["Aske Plaat","Max van Duijn","Niki van Stein","Mike Preuss","Peter van der Putten","Kees Joost Batenburg"],"abstract":"Background: There is great interest in agentic LLMs, large language models that act as agents. Objectives: We review the growing body of work in this area and provide a research agenda. Methods: Agentic LLMs are LLMs that (1) reason, (2) act, and (3) interact. We organize the literature according to these three categories. Results: The research in the first category focuses on reasoning, reflection, and retrieval, aiming to improve decision making; the second category focuses on action models, robots, and tools, aiming for agents that act as useful assistants; the third category focuses on multi-agent systems, aiming for collaborative task solving and simulating interaction to study emergent social behavior. We find that works mutually benefit from results in other categories: retrieval enables tool use, reflection improves multi-agent collaboration, and reasoning benefits all categories. Conclusions: We discuss applications of agentic LLMs and provide an agenda for further research. Important applications are in medical diagnosis, logistics and financial market analysis. Meanwhile, self-reflective agents playing roles and interacting with one another augment the process of scientific research itself. Further, agentic LLMs provide a solution for the problem of LLMs running out of training data: inference-time behavior generates new training states, such that LLMs can keep learning without needing ever larger datasets. We note that there is risk associated with LLM assistants taking action in the real world-safety, liability and security are open problems-while agentic LLMs are also likely to benefit society.","published":"2025-03-29T11:02:20Z","updated":"2025-11-22T08:55:19Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.23037v3","pdf_url":"https://arxiv.org/pdf/2503.23037v3","comment":"Website: https://askeplaat.github.io/agentic-llm-survey-site/","journal_ref":"JAIR volume 84, article 29, December 2025","doi":"10.1613/jair.1.18675","discovered_on":"2026-07-17"},{"id":"2503.23029","versioned_id":"2503.23029v1","title":"A Retrieval-Augmented Knowledge Mining Method with Deep Thinking LLMs for Biomedical Research and Clinical Support","authors":["Yichun Feng","Jiawei Wang","Ruikun He","Lu Zhou","Yixue Li"],"abstract":"Knowledge graphs and large language models (LLMs) are key tools for biomedical knowledge integration and reasoning, facilitating structured organization of scientific articles and discovery of complex semantic relationships. However, current methods face challenges: knowledge graph construction is limited by complex terminology, data heterogeneity, and rapid knowledge evolution, while LLMs show limitations in retrieval and reasoning, making it difficult to uncover cross-document associations and reasoning pathways. To address these issues, we propose a pipeline that uses LLMs to construct a biomedical knowledge graph (BioStrataKG) from large-scale articles and builds a cross-document question-answering dataset (BioCDQA) to evaluate latent knowledge retrieval and multi-hop reasoning. We then introduce Integrated and Progressive Retrieval-Augmented Reasoning (IP-RAR) to enhance retrieval accuracy and knowledge reasoning. IP-RAR maximizes information recall through Integrated Reasoning-based Retrieval and refines knowledge via Progressive Reasoning-based Generation, using self-reflection to achieve deep thinking and precise contextual understanding. Experiments show that IP-RAR improves document retrieval F1 score by 20\\% and answer generation accuracy by 25\\% over existing methods. This framework helps doctors efficiently integrate treatment evidence for personalized medication plans and enables researchers to analyze advancements and research gaps, accelerating scientific discovery and decision-making.","published":"2025-03-29T09:56:42Z","updated":"2025-03-29T09:56:42Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.23029v1","pdf_url":"https://arxiv.org/pdf/2503.23029v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.22678","versioned_id":"2503.22678v2","title":"Self-Evolving Multi-Agent Simulations for Realistic Clinical Interactions","authors":["Mohammad Almansoori","Komal Kumar","Hisham Cholakkal"],"abstract":"In this work, we introduce MedAgentSim, an open-source simulated clinical environment with doctor, patient, and measurement agents designed to evaluate and enhance LLM performance in dynamic diagnostic settings. Unlike prior approaches, our framework requires doctor agents to actively engage with patients through multi-turn conversations, requesting relevant medical examinations (e.g., temperature, blood pressure, ECG) and imaging results (e.g., MRI, X-ray) from a measurement agent to mimic the real-world diagnostic process. Additionally, we incorporate self improvement mechanisms that allow models to iteratively refine their diagnostic strategies. We enhance LLM performance in our simulated setting by integrating multi-agent discussions, chain-of-thought reasoning, and experience-based knowledge retrieval, facilitating progressive learning as doctor agents interact with more patients. We also introduce an evaluation benchmark for assessing the LLM's ability to engage in dynamic, context-aware diagnostic interactions. While MedAgentSim is fully automated, it also supports a user-controlled mode, enabling human interaction with either the doctor or patient agent. Comprehensive evaluations in various simulated diagnostic scenarios demonstrate the effectiveness of our approach. Our code, simulation tool, and benchmark are available at \\href{https://medagentsim.netlify.app/}.","published":"2025-03-28T17:59:53Z","updated":"2025-10-01T11:09:34Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.22678v2","pdf_url":"https://arxiv.org/pdf/2503.22678v2","comment":"14 page, 4 figures, 61 references, presented in MICCAI (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.22677","versioned_id":"2503.22677v2","title":"DSO: Aligning 3D Generators with Simulation Feedback for Physical Soundness","authors":["Ruining Li","Chuanxia Zheng","Christian Rupprecht","Andrea Vedaldi"],"abstract":"Most 3D object generators prioritize aesthetic quality, often neglecting the physical constraints necessary for practical applications. One such constraint is that a 3D object should be self-supporting, i.e., remain balanced under gravity. Previous approaches to generating stable 3D objects relied on differentiable physics simulators to optimize geometry at test time, which is slow, unstable, and prone to local optima. Inspired by the literature on aligning generative models with external feedback, we propose Direct Simulation Optimization (DSO). This framework leverages feedback from a (non-differentiable) simulator to increase the likelihood that the 3D generator directly outputs stable 3D objects. We construct a dataset of 3D objects labeled with stability scores obtained from the physics simulator. This dataset enables fine-tuning of the 3D generator using the stability score as an alignment metric, via direct preference optimization (DPO) or direct reward optimization (DRO) - a novel objective we introduce to align diffusion models without requiring pairwise preferences. Our experiments demonstrate that the fine-tuned feed-forward generator, using either the DPO or DRO objective, is significantly faster and more likely to produce stable objects than test-time optimization. Notably, the DSO framework functions even without any ground-truth 3D objects for training, allowing the 3D generator to self-improve by automatically collecting simulation feedback on its own outputs.","published":"2025-03-28T17:59:53Z","updated":"2025-08-28T01:47:51Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.22677v2","pdf_url":"https://arxiv.org/pdf/2503.22677v2","comment":"Accepted at ICCV 2025 (Highlight). Project page: https://ruiningli.com/dso","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.22122","versioned_id":"2503.22122v1","title":"REMAC: Self-Reflective and Self-Evolving Multi-Agent Collaboration for Long-Horizon Robot Manipulation","authors":["Puzhen Yuan","Angyuan Ma","Yunchao Yao","Huaxiu Yao","Masayoshi Tomizuka","Mingyu Ding"],"abstract":"Vision-language models (VLMs) have demonstrated remarkable capabilities in robotic planning, particularly for long-horizon tasks that require a holistic understanding of the environment for task decomposition. Existing methods typically rely on prior environmental knowledge or carefully designed task-specific prompts, making them struggle with dynamic scene changes or unexpected task conditions, e.g., a robot attempting to put a carrot in the microwave but finds the door was closed. Such challenges underscore two critical issues: adaptability and efficiency. To address them, in this work, we propose an adaptive multi-agent planning framework, termed REMAC, that enables efficient, scene-agnostic multi-robot long-horizon task planning and execution through continuous reflection and self-evolution. REMAC incorporates two key modules: a self-reflection module performing pre-condition and post-condition checks in the loop to evaluate progress and refine plans, and a self-evolvement module dynamically adapting plans based on scene-specific reasoning. It offers several appealing benefits: 1) Robots can initially explore and reason about the environment without complex prompt design. 2) Robots can keep reflecting on potential planning errors and adapting the plan based on task-specific insights. 3) After iterations, a robot can call another one to coordinate tasks in parallel, maximizing the task execution efficiency. To validate REMAC's effectiveness, we build a multi-agent environment for long-horizon robot manipulation and navigation based on RoboCasa, featuring 4 task categories with 27 task styles and 50+ different objects. Based on it, we further benchmark state-of-the-art reasoning models, including DeepSeek-R1, o3-mini, QwQ, and Grok3, demonstrating REMAC's superiority by boosting average success rates by 40% and execution efficiency by 52.7% over the single robot baseline.","published":"2025-03-28T03:51:40Z","updated":"2025-03-28T03:51:40Z","categories":["cs.RO","cs.AI","cs.CL","cs.CV"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2503.22122v1","pdf_url":"https://arxiv.org/pdf/2503.22122v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.21949","versioned_id":"2503.21949v1","title":"Reward Design for Reinforcement Learning Agents","authors":["Rati Devidze"],"abstract":"Reward functions are central in reinforcement learning (RL), guiding agents towards optimal decision-making. The complexity of RL tasks requires meticulously designed reward functions that effectively drive learning while avoiding unintended consequences. Effective reward design aims to provide signals that accelerate the agent's convergence to optimal behavior. Crafting rewards that align with task objectives, foster desired behaviors, and prevent undesirable actions is inherently challenging. This thesis delves into the critical role of reward signals in RL, highlighting their impact on the agent's behavior and learning dynamics and addressing challenges such as delayed, ambiguous, or intricate rewards. In this thesis work, we tackle different aspects of reward shaping. First, we address the problem of designing informative and interpretable reward signals from a teacher's/expert's perspective (teacher-driven). Here, the expert, equipped with the optimal policy and the corresponding value function, designs reward signals that expedite the agent's convergence to optimal behavior. Second, we build on this teacher-driven approach by introducing a novel method for adaptive interpretable reward design. In this scenario, the expert tailors the rewards based on the learner's current policy, ensuring alignment and optimal progression. Third, we propose a meta-learning approach, enabling the agent to self-design its reward signals online without expert input (agent-driven). This self-driven method considers the agent's learning and exploration to establish a self-improving feedback loop.","published":"2025-03-27T19:48:02Z","updated":"2025-03-27T19:48:02Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.21949v1","pdf_url":"https://arxiv.org/pdf/2503.21949v1","comment":"Doctoral thesis","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.21696","versioned_id":"2503.21696v2","title":"Embodied-Reasoner: Synergizing Visual Search, Reasoning, and Action for Embodied Interactive Tasks","authors":["Wenqi Zhang","Mengna Wang","Gangao Liu","Xu Huixin","Yiwei Jiang","Yongliang Shen","Guiyang Hou","Zhe Zheng","Hang Zhang","Xin Li","Weiming Lu","Peng Li","Yueting Zhuang"],"abstract":"Recent advances in deep thinking models have demonstrated remarkable reasoning capabilities on mathematical and coding tasks. However, their effectiveness in embodied domains which require continuous interaction with environments through image action interleaved trajectories remains largely -unexplored. We present Embodied Reasoner, a model that extends o1 style reasoning to interactive embodied search tasks. Unlike mathematical reasoning that relies primarily on logical deduction, embodied scenarios demand spatial understanding, temporal reasoning, and ongoing self-reflection based on interaction history. To address these challenges, we synthesize 9.3k coherent Observation-Thought-Action trajectories containing 64k interactive images and 90k diverse thinking processes (analysis, spatial reasoning, reflection, planning, and verification). We develop a three-stage training pipeline that progressively enhances the model's capabilities through imitation learning, self-exploration via rejection sampling, and self-correction through reflection tuning. The evaluation shows that our model significantly outperforms those advanced visual reasoning models, e.g., it exceeds OpenAI o1, o3-mini, and Claude-3.7 by +9\\%, 24\\%, and +13\\%. Analysis reveals our model exhibits fewer repeated searches and logical inconsistencies, with particular advantages in complex long-horizon tasks. Real-world environments also show our superiority while exhibiting fewer repeated searches and logical inconsistency cases.","published":"2025-03-27T17:00:51Z","updated":"2025-05-14T17:48:02Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.21696v2","pdf_url":"https://arxiv.org/pdf/2503.21696v2","comment":"Code: https://github.com/zwq2018/embodied_reasoner Dataset: https://huggingface.co/datasets/zwq2018/embodied_reasoner","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.21847","versioned_id":"2503.21847v1","title":"ReCoM: Realistic Co-Speech Motion Generation with Recurrent Embedded Transformer","authors":["Yong Xie","Yunlian Sun","Hongwen Zhang","Yebin Liu","Jinhui Tang"],"abstract":"We present ReCoM, an efficient framework for generating high-fidelity and generalizable human body motions synchronized with speech. The core innovation lies in the Recurrent Embedded Transformer (RET), which integrates Dynamic Embedding Regularization (DER) into a Vision Transformer (ViT) core architecture to explicitly model co-speech motion dynamics. This architecture enables joint spatial-temporal dependency modeling, thereby enhancing gesture naturalness and fidelity through coherent motion synthesis. To enhance model robustness, we incorporate the proposed DER strategy, which equips the model with dual capabilities of noise resistance and cross-domain generalization, thereby improving the naturalness and fluency of zero-shot motion generation for unseen speech inputs. To mitigate inherent limitations of autoregressive inference, including error accumulation and limited self-correction, we propose an iterative reconstruction inference (IRI) strategy. IRI refines motion sequences via cyclic pose reconstruction, driven by two key components: (1) classifier-free guidance improves distribution alignment between generated and real gestures without auxiliary supervision, and (2) a temporal smoothing process eliminates abrupt inter-frame transitions while ensuring kinematic continuity. Extensive experiments on benchmark datasets validate ReCoM's effectiveness, achieving state-of-the-art performance across metrics. Notably, it reduces the Fréchet Gesture Distance (FGD) from 18.70 to 2.48, demonstrating an 86.7% improvement in motion realism. Our project page is https://yong-xie-xy.github.io/ReCoM/.","published":"2025-03-27T16:39:40Z","updated":"2025-03-27T16:39:40Z","categories":["cs.GR","cs.AI"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2503.21847v1","pdf_url":"https://arxiv.org/pdf/2503.21847v1","comment":"8 pages, 6 figures, Project Page: https://yong-xie-xy.github.io/ReCoM/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.20950","versioned_id":"2503.20950v1","title":"DEMENTIA-PLAN: An Agent-Based Framework for Multi-Knowledge Graph Retrieval-Augmented Generation in Dementia Care","authors":["Yutong Song","Chenhan Lyu","Pengfei Zhang","Sabine Brunswicker","Nikil Dutt","Amir Rahmani"],"abstract":"Mild-stage dementia patients primarily experience two critical symptoms: severe memory loss and emotional instability. To address these challenges, we propose DEMENTIA-PLAN, an innovative retrieval-augmented generation framework that leverages large language models to enhance conversational support. Our model employs a multiple knowledge graph architecture, integrating various dimensional knowledge representations including daily routine graphs and life memory graphs. Through this multi-graph architecture, DEMENTIA-PLAN comprehensively addresses both immediate care needs and facilitates deeper emotional resonance through personal memories, helping stabilize patient mood while providing reliable memory support. Our notable innovation is the self-reflection planning agent, which systematically coordinates knowledge retrieval and semantic integration across multiple knowledge graphs, while scoring retrieved content from daily routine and life memory graphs to dynamically adjust their retrieval weights for optimized response generation. DEMENTIA-PLAN represents a significant advancement in the clinical application of large language models for dementia care, bridging the gap between AI tools and caregivers interventions.","published":"2025-03-26T19:34:04Z","updated":"2025-03-26T19:34:04Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.20950v1","pdf_url":"https://arxiv.org/pdf/2503.20950v1","comment":"Accepted by AAAI 2025 Workshop on Knowledge Graphs for Personalized Public Health","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.20641","versioned_id":"2503.20641v2","title":"Unlocking Efficient Long-to-Short LLM Reasoning with Model Merging","authors":["Han Wu","Yuxuan Yao","Shuqi Liu","Zehua Liu","Xiaojin Fu","Xiongwei Han","Xing Li","Hui-Ling Zhen","Tao Zhong","Mingxuan Yuan"],"abstract":"The transition from System 1 to System 2 reasoning in large language models (LLMs) has marked significant advancements in handling complex tasks through deliberate, iterative thinking. However, this progress often comes at the cost of efficiency, as models tend to overthink, generating redundant reasoning steps without proportional improvements in output quality. Long-to-Short (L2S) reasoning has emerged as a promising solution to this challenge, aiming to balance reasoning depth with practical efficiency. While existing approaches, such as supervised fine-tuning (SFT), reinforcement learning (RL), and prompt engineering, have shown potential, they are either computationally expensive or unstable. Model merging, on the other hand, offers a cost-effective and robust alternative by integrating the quick-thinking capabilities of System 1 models with the methodical reasoning of System 2 models. In this work, we present a comprehensive empirical study on model merging for L2S reasoning, exploring diverse methodologies, including task-vector-based, SVD-based, and activation-informed merging. Our experiments reveal that model merging can reduce average response length by up to 55% while preserving or even improving baseline performance. We also identify a strong correlation between model scale and merging efficacy with extensive evaluations on 1.5B/7B/14B/32B models. Furthermore, we investigate the merged model's ability to self-critique and self-correct, as well as its adaptive response length based on task complexity. Our findings highlight model merging as a highly efficient and effective paradigm for L2S reasoning, offering a practical solution to the overthinking problem while maintaining the robustness of System 2 reasoning. This work can be found on Github https://github.com/hahahawu/Long-to-Short-via-Model-Merging.","published":"2025-03-26T15:34:37Z","updated":"2025-05-23T02:41:43Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.20641v2","pdf_url":"https://arxiv.org/pdf/2503.20641v2","comment":"Technical report","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.22732","versioned_id":"2503.22732v2","title":"Reasoning Beyond Limits: Advances and Open Problems for LLMs","authors":["Mohamed Amine Ferrag","Norbert Tihanyi","Merouane Debbah"],"abstract":"Recent breakthroughs in generative reasoning have fundamentally reshaped how large language models (LLMs) address complex tasks, enabling them to dynamically retrieve, refine, and organize information into coherent multi-step reasoning chains. Techniques such as inference-time scaling, reinforcement learning, supervised fine-tuning, and distillation have been effectively applied to state-of-the-art models, including DeepSeek-R1, OpenAI o1 and o3, GPT-4o, Qwen-32B, and various Llama variants, significantly enhancing their reasoning capabilities. In this paper, we present a comprehensive review of the top 27 LLMs released between 2023 and 2025, such as Mistral AI Small 3 24B, DeepSeek-R1, Search-o1, QwQ-32B, and Phi-4, and analyze their core innovations and performance improvements. We also provide a detailed overview of recent advancements in multilingual large language models (MLLMs), emphasizing methods that improve cross-lingual reasoning and address the limitations of English-centric training. In parallel, we present a comprehensive review of progress in state space model (SSM)-based architectures, including models such as Mamba, which demonstrate improved efficiency for long-context processing compared to transformer-based approaches. Our analysis covers training strategies including general optimization techniques, mixture-of-experts (MoE) configurations, retrieval-augmented generation (RAG), chain-of-thought prompting, self-improvement methods, and test-time compute scaling and distillation frameworks. Finally, we identify key challenges for future research, including enabling multi-step reasoning without human supervision, improving robustness in chained task execution, balancing structured prompting with generative flexibility, and enhancing the integration of long-context retrieval and external tools.","published":"2025-03-26T12:29:40Z","updated":"2026-01-03T13:40:22Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.22732v2","pdf_url":"https://arxiv.org/pdf/2503.22732v2","comment":"The paper is published ICT Express Volume 11, Issue 6, December 2025, Pages 1054-1096","journal_ref":"","doi":"10.1016/j.icte.2025.09.003","discovered_on":"2026-07-17"},{"id":"2503.19602","versioned_id":"2503.19602v1","title":"Innate Reasoning is Not Enough: In-Context Learning Enhances Reasoning Large Language Models with Less Overthinking","authors":["Yuyao Ge","Shenghua Liu","Yiwei Wang","Lingrui Mei","Lizhe Chen","Baolong Bi","Xueqi Cheng"],"abstract":"Recent advances in Large Language Models (LLMs) have introduced Reasoning Large Language Models (RLLMs), which employ extended thinking processes with reflection and self-correction capabilities, demonstrating the effectiveness of test-time scaling. RLLMs exhibit innate Chain-of-Thought (CoT) reasoning capability obtained from training, leading to a natural question: \"Is CoT prompting, a popular In-Context Learning (ICL) method for chat LLMs, necessary to enhance the reasoning capability of RLLMs?\" In this work, we present the first comprehensive analysis of the impacts of Zero-shot CoT and Few-shot CoT on RLLMs across mathematical reasoning tasks. We examine models ranging from 1.5B to 32B parameters, finding that contrary to concerns, CoT prompting significantly enhances RLLMs' performance in most scenarios. Our results reveal distinct patterns: large-capacity models show minimal improvement on simple tasks but substantial gains on complex problems, while smaller models exhibit the opposite behavior. Further analysis demonstrates that CoT prompting effectively controls the distribution of the numbers of thinking tokens and reasoning steps, reducing excessive reflections by approximately 90% in some cases. Moreover, attention logits analysis reveals the RLLMs' overfitting to reflection-related words, which is mitigated by external CoT guidance. Notably, our experiments indicate that for RLLMs, one-shot CoT consistently yields superior performance compared to Few-shot CoT approaches. Our findings provide important insights for optimizing RLLMs' performance through appropriate prompting strategies.","published":"2025-03-25T12:37:22Z","updated":"2025-03-25T12:37:22Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.19602v1","pdf_url":"https://arxiv.org/pdf/2503.19602v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.19470","versioned_id":"2503.19470v3","title":"ReSearch: Learning to Reason with Search for LLMs via Reinforcement Learning","authors":["Mingyang Chen","Linzhuang Sun","Tianpeng Li","Haoze Sun","Yijie Zhou","Chenzheng Zhu","Haofen Wang","Jeff Z. Pan","Wen Zhang","Huajun Chen","Fan Yang","Zenan Zhou","Weipeng Chen"],"abstract":"Large Language Models (LLMs) have shown remarkable capabilities in reasoning, exemplified by the success of OpenAI-o1 and DeepSeek-R1. However, integrating reasoning with external search processes remains challenging, especially for complex multi-hop questions requiring multiple retrieval steps. We propose ReSearch, a novel framework that trains LLMs to Reason with Search via reinforcement learning without using any supervised data on reasoning steps. Our approach treats search operations as integral components of the reasoning chain, where when and how to perform searches is guided by text-based thinking, and search results subsequently influence further reasoning. We train ReSearch on Qwen2.5-7B(-Instruct) and Qwen2.5-32B(-Instruct) models and conduct extensive experiments. Despite being trained on only one dataset, our models demonstrate strong generalizability across various benchmarks. Analysis reveals that ReSearch naturally elicits advanced reasoning capabilities such as reflection and self-correction during the reinforcement learning process.","published":"2025-03-25T09:00:58Z","updated":"2025-09-23T03:45:42Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.19470v3","pdf_url":"https://arxiv.org/pdf/2503.19470v3","comment":"Accepted to NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.19326","versioned_id":"2503.19326v2","title":"Process or Result? Manipulated Ending Tokens Can Mislead Reasoning LLMs to Ignore the Correct Reasoning Steps","authors":["Yu Cui","Bryan Hooi","Yujun Cai","Yiwei Wang"],"abstract":"Recent reasoning large language models (LLMs) have demonstrated remarkable improvements in mathematical reasoning capabilities through long Chain-of-Thought. The reasoning tokens of these models enable self-correction within reasoning chains, enhancing robustness. This motivates our exploration: how vulnerable are reasoning LLMs to subtle errors in their input reasoning chains? We introduce \"Compromising Thought\" (CPT), a vulnerability where models presented with reasoning tokens containing manipulated calculation results tend to ignore correct reasoning steps and adopt incorrect results instead. Through systematic evaluation across multiple reasoning LLMs, we design three increasingly explicit prompting methods to measure CPT resistance, revealing that models struggle significantly to identify and correct these manipulations. Notably, contrary to existing research suggesting structural alterations affect model performance more than content modifications, we find that local ending token manipulations have greater impact on reasoning outcomes than structural changes. Moreover, we discover a security vulnerability in DeepSeek-R1 where tampered reasoning tokens can trigger complete reasoning cessation. Our work enhances understanding of reasoning robustness and highlights security considerations for reasoning-intensive applications.","published":"2025-03-25T03:43:11Z","updated":"2025-04-01T00:07:54Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.19326v2","pdf_url":"https://arxiv.org/pdf/2503.19326v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.19309","versioned_id":"2503.19309v1","title":"Iterative Hypothesis Generation for Scientific Discovery with Monte Carlo Nash Equilibrium Self-Refining Trees","authors":["Gollam Rabby","Diyana Muhammed","Prasenjit Mitra","Sören Auer"],"abstract":"Scientific hypothesis generation is a fundamentally challenging task in research, requiring the synthesis of novel and empirically grounded insights. Traditional approaches rely on human intuition and domain expertise, while purely large language model (LLM) based methods often struggle to produce hypotheses that are both innovative and reliable. To address these limitations, we propose the Monte Carlo Nash Equilibrium Self-Refine Tree (MC-NEST), a novel framework that integrates Monte Carlo Tree Search with Nash Equilibrium strategies to iteratively refine and validate hypotheses. MC-NEST dynamically balances exploration and exploitation through adaptive sampling strategies, which prioritize high-potential hypotheses while maintaining diversity in the search space. We demonstrate the effectiveness of MC-NEST through comprehensive experiments across multiple domains, including biomedicine, social science, and computer science. MC-NEST achieves average scores of 2.65, 2.74, and 2.80 (on a 1-3 scale) for novelty, clarity, significance, and verifiability metrics on the social science, computer science, and biomedicine datasets, respectively, outperforming state-of-the-art prompt-based methods, which achieve 2.36, 2.51, and 2.52 on the same datasets. These results underscore MC-NEST's ability to generate high-quality, empirically grounded hypotheses across diverse domains. Furthermore, MC-NEST facilitates structured human-AI collaboration, ensuring that LLMs augment human creativity rather than replace it. By addressing key challenges such as iterative refinement and the exploration-exploitation balance, MC-NEST sets a new benchmark in automated hypothesis generation. Additionally, MC-NEST's ethical design enables responsible AI use, emphasizing transparency and human supervision in hypothesis generation.","published":"2025-03-25T03:14:53Z","updated":"2025-03-25T03:14:53Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.19309v1","pdf_url":"https://arxiv.org/pdf/2503.19309v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.19271","versioned_id":"2503.19271v2","title":"MARS: Memory-Enhanced Agents with Reflective Self-improvement","authors":["Xuechen Liang","Meiling Tao","Yinghui Xia","Jianhui Wang","Kun Li","Yijin Wang","Jingsong Yang","Tianyu Shi","Yuantao Wang","Miao Zhang","Xueqian Wang"],"abstract":"Large language models (LLMs) have made significant advances in the field of natural language processing, but they still face challenges such as continuous decision-making, lack of long-term memory, and limited context windows in dynamic environments. To address these issues, this paper proposes an innovative framework Memory-Enhanced Agents with Reflective Self-improvement. The MARS framework comprises three agents: the User, the Assistant, and the Checker. By integrating iterative feedback, reflective mechanisms, and a memory optimization mechanism based on the Ebbinghaus forgetting curve, it significantly enhances the agents capabilities in handling multi-tasking and long-span information.","published":"2025-03-25T02:05:46Z","updated":"2025-04-09T07:51:49Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.19271v2","pdf_url":"https://arxiv.org/pdf/2503.19271v2","comment":"We are withdrawing this version because it duplicates our previous submission (arXiv:2409.00872)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.18892","versioned_id":"2503.18892v3","title":"SimpleRL-Zoo: Investigating and Taming Zero Reinforcement Learning for Open Base Models in the Wild","authors":["Weihao Zeng","Yuzhen Huang","Qian Liu","Wei Liu","Keqing He","Zejun Ma","Junxian He"],"abstract":"DeepSeek-R1 has shown that long chain-of-thought (CoT) reasoning can naturally emerge through a simple reinforcement learning (RL) framework with rule-based rewards, where the training may directly start from the base models-a paradigm referred to as zero RL training. Most recent efforts to reproduce zero RL training have primarily focused on the Qwen2.5 model series, which may not be representative as we find the base models already exhibit strong instruction-following and self-reflection abilities. In this work, we investigate zero RL training across 10 diverse base models, spanning different families and sizes including LLama3-8B, Mistral-7B/24B, DeepSeek-Math-7B, Qwen2.5-math-7B, and all Qwen2.5 models from 0.5B to 32B. Leveraging several key design strategies-such as adjusting format reward and controlling query difficulty-we achieve substantial improvements in both reasoning accuracy and response length across most settings. However, by carefully monitoring the training dynamics, we observe that different base models exhibit distinct patterns during training. For instance, the increased response length does not always correlate with the emergence of certain cognitive behaviors such as verification (i.e., the \"aha moment\"). Notably, we observe the \"aha moment\" for the first time in small models not from the Qwen family. We share the key designs that enable successful zero RL training, along with our findings and practices. To facilitate further research, we open-source the code, models, and analysis tools.","published":"2025-03-24T17:06:10Z","updated":"2025-08-06T08:42:32Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.18892v3","pdf_url":"https://arxiv.org/pdf/2503.18892v3","comment":"Published as a conference paper at COLM 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.17726","versioned_id":"2503.17726v1","title":"A Survey on Mathematical Reasoning and Optimization with Large Language Models","authors":["Ali Forootani"],"abstract":"Mathematical reasoning and optimization are fundamental to artificial intelligence and computational problem-solving. Recent advancements in Large Language Models (LLMs) have significantly improved AI-driven mathematical reasoning, theorem proving, and optimization techniques. This survey explores the evolution of mathematical problem-solving in AI, from early statistical learning approaches to modern deep learning and transformer-based methodologies. We review the capabilities of pretrained language models and LLMs in performing arithmetic operations, complex reasoning, theorem proving, and structured symbolic computation. A key focus is on how LLMs integrate with optimization and control frameworks, including mixed-integer programming, linear quadratic control, and multi-agent optimization strategies. We examine how LLMs assist in problem formulation, constraint generation, and heuristic search, bridging theoretical reasoning with practical applications. We also discuss enhancement techniques such as Chain-of-Thought reasoning, instruction tuning, and tool-augmented methods that improve LLM's problem-solving performance. Despite their progress, LLMs face challenges in numerical precision, logical consistency, and proof verification. Emerging trends such as hybrid neural-symbolic reasoning, structured prompt engineering, and multi-step self-correction aim to overcome these limitations. Future research should focus on interpretability, integration with domain-specific solvers, and improving the robustness of AI-driven decision-making. This survey offers a comprehensive review of the current landscape and future directions of mathematical reasoning and optimization with LLMs, with applications across engineering, finance, and scientific research.","published":"2025-03-22T10:49:32Z","updated":"2025-03-22T10:49:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.17726v1","pdf_url":"https://arxiv.org/pdf/2503.17726v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.17439","versioned_id":"2503.17439v2","title":"LEMMA: Learning from Errors for MatheMatical Advancement in LLMs","authors":["Zhuoshi Pan","Yu Li","Honglin Lin","Qizhi Pei","Zinan Tang","Wei Wu","Chenlin Ming","H. Vicky Zhao","Conghui He","Lijun Wu"],"abstract":"Large language models (LLMs) have demonstrated remarkable reasoning capability in solving mathematical problems. However, existing approaches primarily focus on improving the quality of correct training data, e.g., distilling high-quality correct solutions from advanced models, neglecting the value contained in error data, potentially hindering the model's reflective ability. Though some studies attempt to leverage error data, they often involve complex mechanisms, such as Monte Carlo Tree Search (MCTS) to explore error nodes. In this work, we propose to enhance LLMs' reasoning ability by Learning from Errors for Mathematical Advancement (LEMMA). LEMMA constructs data consisting of an incorrect solution with an erroneous step and a reflection connection to a correct solution for fine-tuning. Specifically, we systematically analyze the model-generated error types and introduce an error-type grounded mistake augmentation method to collect diverse and representative errors. Correct solutions are either from fixing the errors or generating a fresh start. Through a model-aware smooth reflection connection, the erroneous solution is transferred to the correct one. By fine-tuning on the constructed dataset, the model is able to self-correct errors autonomously within the generation process without relying on external critique models. Experimental results demonstrate that LEMMA achieves significant performance improvements over other strong baselines.","published":"2025-03-21T17:59:10Z","updated":"2025-05-30T15:19:51Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.17439v2","pdf_url":"https://arxiv.org/pdf/2503.17439v2","comment":"ACL'25 Findings, Code is available at https://github.com/pzs19/LEMMA","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.17352","versioned_id":"2503.17352v3","title":"OpenVLThinker: Complex Vision-Language Reasoning via Iterative SFT-RL Cycles","authors":["Yihe Deng","Hritik Bansal","Fan Yin","Nanyun Peng","Wei Wang","Kai-Wei Chang"],"abstract":"We introduce OpenVLThinker, one of the first open-source large vision-language models (LVLMs) to exhibit sophisticated chain-of-thought reasoning, achieving notable performance gains on challenging visual reasoning tasks. While text-based reasoning models (e.g., Deepseek R1) show promising results in text-only tasks, distilling their reasoning into LVLMs via supervised fine-tuning (SFT) often results in performance degradation due to imprecise visual grounding. Conversely, purely reinforcement learning (RL)-based methods face a large search space, hindering the emergence of reflective behaviors in smaller models (e.g., 7B LVLMs). Surprisingly, alternating between SFT and RL ultimately results in significant performance improvements after a few iterations. Our analysis reveals that the base model rarely exhibits reasoning behaviors initially, but SFT effectively surfaces these latent actions and narrows the RL search space, accelerating the development of reasoning capabilities. Each subsequent RL stage further refines the model's reasoning skills, producing higher-quality SFT data for continued self-improvement. OpenVLThinker-7B consistently advances performance across six benchmarks demanding mathematical and general reasoning, notably improving MathVista by 3.8%, EMMA by 2.4%, and HallusionBench by 1.6%. Beyond demonstrating the synergy between SFT and RL for complex reasoning tasks, our findings provide early evidence towards achieving R1-style reasoning in multimodal contexts. The code, model and data are held at https://github.com/yihedeng9/OpenVLThinker.","published":"2025-03-21T17:52:43Z","updated":"2025-11-11T08:13:33Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.17352v3","pdf_url":"https://arxiv.org/pdf/2503.17352v3","comment":"23 pages, 11 figures, 8 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.16022","versioned_id":"2503.16022v1","title":"Corrective In-Context Learning: Evaluating Self-Correction in Large Language Models","authors":["Mario Sanz-Guerrero","Katharina von der Wense"],"abstract":"In-context learning (ICL) has transformed the use of large language models (LLMs) for NLP tasks, enabling few-shot learning by conditioning on labeled examples without finetuning. Despite its effectiveness, ICL is prone to errors, especially for challenging examples. With the goal of improving the performance of ICL, we propose corrective in-context learning (CICL), an approach that incorporates a model's incorrect predictions alongside ground truth corrections into the prompt, aiming to enhance classification accuracy through self-correction. However, contrary to our hypothesis, extensive experiments on text classification tasks demonstrate that CICL consistently underperforms standard ICL, with performance degrading as the proportion of corrections in the prompt increases. Our findings indicate that CICL introduces confusion by disrupting the model's task understanding, rather than refining its predictions. Additionally, we observe that presenting harder examples in standard ICL does not improve performance, suggesting that example difficulty alone may not be a reliable criterion for effective selection. By presenting these negative results, we provide important insights into the limitations of self-corrective mechanisms in LLMs and offer directions for future research.","published":"2025-03-20T10:39:39Z","updated":"2025-03-20T10:39:39Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.16022v1","pdf_url":"https://arxiv.org/pdf/2503.16022v1","comment":"Accepted to the 6th Workshop on Insights from Negative Results in NLP at NAACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.14495","versioned_id":"2503.14495v1","title":"Temporal Consistency for LLM Reasoning Process Error Identification","authors":["Jiacheng Guo","Yue Wu","Jiahao Qiu","Kaixuan Huang","Xinzhe Juan","Ling Yang","Mengdi Wang"],"abstract":"Verification is crucial for effective mathematical reasoning. We present a new temporal consistency method where verifiers iteratively refine their judgments based on the previous assessment. Unlike one-round verification or multi-model debate approaches, our method leverages consistency in a sequence of self-reflection actions to improve verification accuracy. Empirical evaluations across diverse mathematical process error identification benchmarks (Mathcheck, ProcessBench, and PRM800K) show consistent performance improvements over baseline methods. When applied to the recent DeepSeek R1 distilled models, our method demonstrates strong performance, enabling 7B/8B distilled models to outperform all 70B/72B models and GPT-4o on ProcessBench. Notably, the distilled 14B model with our method achieves performance comparable to Deepseek-R1. Our codes are available at https://github.com/jcguo123/Temporal-Consistency","published":"2025-03-18T17:58:28Z","updated":"2025-03-18T17:58:28Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.14495v1","pdf_url":"https://arxiv.org/pdf/2503.14495v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.14023","versioned_id":"2503.14023v2","title":"Synthetic Data Generation Using Large Language Models: Advances in Text and Code","authors":["Mihai Nadas","Laura Diosan","Andreea Tomescu"],"abstract":"This survey reviews how large language models (LLMs) are transforming synthetic training data generation in both natural language and code domains. By producing artificial but task-relevant examples, these models can significantly augment or even substitute for real-world datasets, particularly in scenarios where labeled data is scarce, expensive, or sensitive. This paper surveys recent advances in leveraging LLMs to create synthetic text and code, highlighting key techniques such as prompt-based generation, retrieval-augmented pipelines, and iterative self-refinement. We examine how these methods can enrich low-resource tasks (e.g., classification, question answering) and facilitate code-centric applications (e.g., instruction tuning, code translation, bug repair) through automated verification of functional correctness. Alongside potential benefits - cost-effectiveness, broad coverage, and controllable diversity - we discuss the accompanying challenges, including factual inaccuracies in generated text, insufficient stylistic or distributional realism, and risks of bias amplification. Proposed mitigation strategies range from filtering and weighting synthetic outputs to reinforcement learning with execution feedback in code domains. We conclude by outlining open research directions, such as automated prompt engineering, cross-modal data synthesis, and robust evaluation frameworks, underscoring the growing importance of LLM-generated synthetic data in accelerating AI development while emphasizing ethical and quality safeguards.","published":"2025-03-18T08:34:03Z","updated":"2025-07-22T10:28:00Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.14023v2","pdf_url":"https://arxiv.org/pdf/2503.14023v2","comment":"24 pages, 6 tables, 1 figure, 64 references","journal_ref":"IEEE Access 13, 134615-134633 (2025)","doi":"10.1109/ACCESS.2025.3589503","discovered_on":"2026-07-17"},{"id":"2503.12937","versioned_id":"2503.12937v2","title":"R1-VL: Learning to Reason with Multimodal Large Language Models via Step-wise Group Relative Policy Optimization","authors":["Jingyi Zhang","Jiaxing Huang","Huanjin Yao","Shunyu Liu","Xikun Zhang","Shijian Lu","Dacheng Tao"],"abstract":"Recent studies generally enhance MLLMs' reasoning capabilities via supervised fine-tuning on high-quality chain-of-thought reasoning data, which often leads models to merely imitate successful reasoning paths without understanding what the wrong reasoning paths are. In this work, we aim to enhance the MLLMs' reasoning ability beyond passively imitating positive reasoning paths. To this end, we design Step-wise Group Relative Policy Optimization (StepGRPO), a new online reinforcement learning framework that enables MLLMs to self-improve reasoning ability via simple, effective and dense step-wise rewarding. Specifically, StepGRPO introduces two novel rule-based reasoning rewards: Step-wise Reasoning Accuracy Reward (StepRAR) and Step-wise Reasoning Validity Reward (StepRVR). StepRAR rewards the reasoning paths that contain necessary intermediate reasoning steps via a soft key-step matching technique, while StepRAR rewards reasoning paths that follow a well-structured and logically consistent reasoning process through a reasoning completeness and logic evaluation strategy. With the proposed StepGRPO, we introduce R1-VL, a series of MLLMs with outstanding capabilities in step-by-step reasoning. Extensive experiments over 8 benchmarks demonstrate the superiority of our methods.","published":"2025-03-17T08:51:44Z","updated":"2025-08-04T04:22:09Z","categories":["cs.AI","cs.CL","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.12937v2","pdf_url":"https://arxiv.org/pdf/2503.12937v2","comment":"ICCV 2025 Camera Ready","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.12854","versioned_id":"2503.12854v3","title":"Enhancing LLM Reasoning with Iterative DPO: A Comprehensive Empirical Investigation","authors":["Songjun Tu","Jiahao Lin","Xiangyu Tian","Qichao Zhang","Linjing Li","Yuqian Fu","Nan Xu","Wei He","Xiangyuan Lan","Dongmei Jiang","Dongbin Zhao"],"abstract":"Recent advancements in post-training methodologies for large language models (LLMs) have highlighted reinforcement learning (RL) as a critical component for enhancing reasoning. However, the substantial computational costs associated with RL-based approaches have led to growing interest in alternative paradigms, such as Direct Preference Optimization (DPO). In this study, we investigate the effectiveness of DPO in facilitating self-improvement for LLMs through iterative preference-based learning. We demonstrate that a single round of DPO with coarse filtering significantly enhances mathematical reasoning performance, particularly for strong base model. Furthermore, we design an iterative enhancement framework for both the generator and the reward model (RM), enabling their mutual improvement through online interaction across multiple rounds of DPO. Finally, with simple verifiable rewards, our model DPO-VP achieves RL-level performance with significantly lower computational overhead. These findings highlight DPO as a scalable and cost-effective alternative to RL, offering a practical solution for enhancing LLM reasoning in resource-constrained situations.","published":"2025-03-17T06:28:25Z","updated":"2025-07-28T17:46:50Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.12854v3","pdf_url":"https://arxiv.org/pdf/2503.12854v3","comment":"23pages","journal_ref":"COLM2025","doi":"","discovered_on":"2026-07-17"},{"id":"2503.13551","versioned_id":"2503.13551v5","title":"Towards Hierarchical Multi-Step Reward Models for Enhanced Reasoning in Large Language Models","authors":["Teng Wang","Zhangyi Jiang","Zhenqi He","Shenyang Tong","Wenhan Yang","Yanan Zheng","Zeyu Li","Zifan He","Hailei Gong","Zewen Ye","Shengjie Ma","Jianping Zhang"],"abstract":"Recent studies show that Large Language Models (LLMs) achieve strong reasoning capabilities through supervised fine-tuning or reinforcement learning. However, a key approach, the Process Reward Model (PRM), suffers from reward hacking, making it unreliable in identifying the best intermediate step. In addition, the cost of annotating reasoning processes for reward modeling is high, making large-scale collection of high-quality data challenging. To address this, we propose a novel reward model approach called the Hierarchical Reward Model (HRM), which evaluates both individual and consecutive reasoning steps at both fine-grained and coarse-grained levels. HRM excels at assessing multi-step reasoning coherence, especially when flawed steps are later corrected through self-reflection. To further reduce the cost of generating training data, we introduce a lightweight and effective data augmentation strategy called Hierarchical Node Compression (HNC), which merges two consecutive reasoning steps into one within the tree structure. By applying HNC to MCTS-generated reasoning trajectories, we enhance the diversity and robustness of HRM training data while introducing controlled noise with minimal computational overhead. Empirical results on the PRM800K dataset show that HRM, together with HNC, provides more stable and reliable evaluations than PRM. Furthermore, cross-domain evaluations on the MATH500 and GSM8K datasets demonstrate HRM's strong generalization and robustness across a variety of reasoning tasks.","published":"2025-03-16T15:18:40Z","updated":"2026-04-09T16:29:33Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.13551v5","pdf_url":"https://arxiv.org/pdf/2503.13551v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.12077","versioned_id":"2503.12077v1","title":"V-Stylist: Video Stylization via Collaboration and Reflection of MLLM Agents","authors":["Zhengrong Yue","Shaobin Zhuang","Kunchang Li","Yanbo Ding","Yali Wang"],"abstract":"Despite the recent advancement in video stylization, most existing methods struggle to render any video with complex transitions, based on an open style description of user query. To fill this gap, we introduce a generic multi-agent system for video stylization, V-Stylist, by a novel collaboration and reflection paradigm of multi-modal large language models. Specifically, our V-Stylist is a systematical workflow with three key roles: (1) Video Parser decomposes the input video into a number of shots and generates their text prompts of key shot content. Via a concise video-to-shot prompting paradigm, it allows our V-Stylist to effectively handle videos with complex transitions. (2) Style Parser identifies the style in the user query and progressively search the matched style model from a style tree. Via a robust tree-of-thought searching paradigm, it allows our V-Stylist to precisely specify vague style preference in the open user query. (3) Style Artist leverages the matched model to render all the video shots into the required style. Via a novel multi-round self-reflection paradigm, it allows our V-Stylist to adaptively adjust detail control, according to the style requirement. With such a distinct design of mimicking human professionals, our V-Stylist achieves a major breakthrough over the primary challenges for effective and automatic video stylization. Moreover,we further construct a new benchmark Text-driven Video Stylization Benchmark (TVSBench), which fills the gap to assess stylization of complex videos on open user queries. Extensive experiments show that, V-Stylist achieves the state-of-the-art, e.g.,V-Stylist surpasses FRESCO and ControlVideo by 6.05% and 4.51% respectively in overall average metrics, marking a significant advance in video stylization.","published":"2025-03-15T10:37:31Z","updated":"2025-03-15T10:37:31Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.12077v1","pdf_url":"https://arxiv.org/pdf/2503.12077v1","comment":"CVPR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.11989","versioned_id":"2503.11989v2","title":"Applications of Large Language Model Reasoning in Feature Generation","authors":["Dharani Chandra"],"abstract":"Large Language Models (LLMs) have revolutionized natural language processing through their state of art reasoning capabilities. This paper explores the convergence of LLM reasoning techniques and feature generation for machine learning tasks. We examine four key reasoning approaches: Chain of Thought, Tree of Thoughts, Retrieval-Augmented Generation, and Thought Space Exploration. Our analysis reveals how these approaches can be used to identify effective feature generation rules without having to manually specify search spaces. The paper categorizes LLM-based feature generation methods across various domains including finance, healthcare, and text analytics. LLMs can extract key information from clinical notes and radiology reports in healthcare, by enabling more efficient data utilization. In finance, LLMs facilitate text generation, summarization, and entity extraction from complex documents. We analyze evaluation methodologies for assessing feature quality and downstream performance, with particular attention to OCTree's decision tree reasoning approach that provides language-based feedback for iterative improvements. Current challenges include hallucination, computational efficiency, and domain adaptation. As of March 2025, emerging approaches include inference-time compute scaling, reinforcement learning, and supervised fine-tuning with model distillation. Future directions point toward multimodal feature generation, self-improving systems, and neuro-symbolic approaches. This paper provides a detailed overview of an emerging field that promises to automate and enhance feature engineering through language model reasoning.","published":"2025-03-15T04:18:01Z","updated":"2025-03-20T02:18:33Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.11989v2","pdf_url":"https://arxiv.org/pdf/2503.11989v2","comment":"I just updated the format of the references in the paper","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.10351","versioned_id":"2503.10351v2","title":"New Trends for Modern Machine Translation with Large Reasoning Models","authors":["Sinuo Liu","Chenyang Lyu","Minghao Wu","Longyue Wang","Weihua Luo","Kaifu Zhang","Zifu Shang"],"abstract":"Recent advances in Large Reasoning Models (LRMs), particularly those leveraging Chain-of-Thought reasoning (CoT), have opened brand new possibility for Machine Translation (MT). This position paper argues that LRMs substantially transformed traditional neural MT as well as LLMs-based MT paradigms by reframing translation as a dynamic reasoning task that requires contextual, cultural, and linguistic understanding and reasoning. We identify three foundational shifts: 1) contextual coherence, where LRMs resolve ambiguities and preserve discourse structure through explicit reasoning over cross-sentence and complex context or even lack of context; 2) cultural intentionality, enabling models to adapt outputs by inferring speaker intent, audience expectations, and socio-linguistic norms; 3) self-reflection, LRMs can perform self-reflection during the inference time to correct the potential errors in translation especially extremely noisy cases, showing better robustness compared to simply mapping X->Y translation. We explore various scenarios in translation including stylized translation, document-level translation and multimodal translation by showcasing empirical examples that demonstrate the superiority of LRMs in translation. We also identify several interesting phenomenons for LRMs for MT including auto-pivot translation as well as the critical challenges such as over-localisation in translation and inference efficiency. In conclusion, we think that LRMs redefine translation systems not merely as text converters but as multilingual cognitive agents capable of reasoning about meaning beyond the text. This paradigm shift reminds us to think of problems in translation beyond traditional translation scenarios in a much broader context with LRMs - what we can achieve on top of it.","published":"2025-03-13T13:27:53Z","updated":"2025-03-14T12:09:34Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.10351v2","pdf_url":"https://arxiv.org/pdf/2503.10351v2","comment":"arXiv admin note: text overlap with arXiv:1701.04715 by other authors","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.10727","versioned_id":"2503.10727v2","title":"Word-level Annotation of GDPR Transparency Compliance in Privacy Policies using Large Language Models","authors":["Thomas Cory","Wolf Rieder","Julia Krämer","Philip Raschke","Patrick Herbke","Axel Küpper"],"abstract":"Ensuring transparency of data practices related to personal information is a core requirement of the General Data Protection Regulation (GDPR). However, large-scale compliance assessment remains challenging due to the complexity and diversity of privacy policy language. Manual audits are labour-intensive and inconsistent, while current automated methods often lack the granularity required to capture nuanced transparency disclosures. In this paper, we present a modular large language model (LLM)-based pipeline for fine-grained word-level annotation of privacy policies with respect to GDPR transparency requirements. Our approach integrates LLM-driven annotation with passage-level classification, retrieval-augmented generation, and a self-correction mechanism to deliver scalable, context-aware annotations across 21 GDPR-derived transparency requirements. To support empirical evaluation, we compile a corpus of 703,791 English-language privacy policies and generate a ground-truth sample of 200 manually annotated policies based on a comprehensive, GDPR-aligned annotation scheme. We propose a two-tiered evaluation methodology capturing both passage-level classification and span-level annotation quality and conduct a comparative analysis of seven state-of-the-art LLMs on two annotation schemes, including the widely used OPP-115 dataset. The results of our evaluation show that decomposing the annotation task and integrating targeted retrieval and classification components significantly improve annotation accuracy, particularly for well-structured requirements. Our work provides new empirical resources and methodological foundations for advancing automated transparency compliance assessment at scale.","published":"2025-03-13T11:41:25Z","updated":"2025-11-24T16:34:25Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.10727v2","pdf_url":"https://arxiv.org/pdf/2503.10727v2","comment":"Accepted to Proceedings on Privacy Enhancing Technologies (PoPETs) 1 (2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.10699","versioned_id":"2503.10699v1","title":"Test-Time Discovery via Hashing Memory","authors":["Fan Lyu","Tianle Liu","Zhang Zhang","Fuyuan Hu","Liang Wang"],"abstract":"We introduce Test-Time Discovery (TTD) as a novel task that addresses class shifts during testing, requiring models to simultaneously identify emerging categories while preserving previously learned ones. A key challenge in TTD is distinguishing newly discovered classes from those already identified. To address this, we propose a training-free, hash-based memory mechanism that enhances class discovery through fine-grained comparisons with past test samples. Leveraging the characteristics of unknown classes, our approach introduces hash representation based on feature scale and directions, utilizing Locality-Sensitive Hashing (LSH) for efficient grouping of similar samples. This enables test samples to be easily and quickly compared with relevant past instances. Furthermore, we design a collaborative classification strategy, combining a prototype classifier for known classes with an LSH-based classifier for novel ones. To enhance reliability, we incorporate a self-correction mechanism that refines memory labels through hash-based neighbor retrieval, ensuring more stable and accurate class assignments. Experimental results demonstrate that our method achieves good discovery of novel categories while maintaining performance on known classes, establishing a new paradigm in model testing. Our code is available at https://github.com/fanlyu/ttd.","published":"2025-03-12T06:43:01Z","updated":"2025-03-12T06:43:01Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.10699v1","pdf_url":"https://arxiv.org/pdf/2503.10699v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.13500","versioned_id":"2503.13500v2","title":"Long-horizon Visual Instruction Generation with Logic and Attribute Self-reflection","authors":["Yucheng Suo","Fan Ma","Kaixin Shen","Linchao Zhu","Yi Yang"],"abstract":"Visual instructions for long-horizon tasks are crucial as they intuitively clarify complex concepts and enhance retention across extended steps. Directly generating a series of images using text-to-image models without considering the context of previous steps results in inconsistent images, increasing cognitive load. Additionally, the generated images often miss objects or the attributes such as color, shape, and state of the objects are inaccurate. To address these challenges, we propose LIGER, the first training-free framework for Long-horizon Instruction GEneration with logic and attribute self-Reflection. LIGER first generates a draft image for each step with the historical prompt and visual memory of previous steps. This step-by-step generation approach maintains consistency between images in long-horizon tasks. Moreover, LIGER utilizes various image editing tools to rectify errors including wrong attributes, logic errors, object redundancy, and identity inconsistency in the draft images. Through this self-reflection mechanism, LIGER improves the logic and object attribute correctness of the images. To verify whether the generated images assist human understanding, we manually curated a new benchmark consisting of various long-horizon tasks. Human-annotated ground truth expressions reflect the human-defined criteria for how an image should appear to be illustrative. Experiments demonstrate the visual instructions generated by LIGER are more comprehensive compared with baseline methods.","published":"2025-03-12T05:11:02Z","updated":"2025-04-06T05:45:51Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.13500v2","pdf_url":"https://arxiv.org/pdf/2503.13500v2","comment":"ICLR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.08681","versioned_id":"2503.08681v1","title":"Self-Taught Self-Correction for Small Language Models","authors":["Viktor Moskvoretskii","Chris Biemann","Irina Nikishina"],"abstract":"Although large language models (LLMs) have achieved remarkable performance across various tasks, they remain prone to errors. A key challenge is enabling them to self-correct. While prior research has relied on external tools or large proprietary models, this work explores self-correction in small language models (SLMs) through iterative fine-tuning using solely self-generated data. We introduce the Self-Taught Self-Correction (STaSC) algorithm, which incorporates multiple algorithmic design choices. Experimental results on a question-answering task demonstrate that STaSC effectively learns self-correction, leading to significant performance improvements. Our analysis further provides insights into the mechanisms of self-correction and the impact of different design choices on learning dynamics and overall performance. To support future research, we release our user-friendly codebase and lightweight models.","published":"2025-03-11T17:57:44Z","updated":"2025-03-11T17:57:44Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.08681v1","pdf_url":"https://arxiv.org/pdf/2503.08681v1","comment":"Code is available at https://github.com/VityaVitalich/STASC","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.07996","versioned_id":"2503.07996v4","title":"SQLCritic: Correcting Text-to-SQL Generation via Clause-wise Critic","authors":["Jikai Chen","Leilei Gan","Ziyu Zhao","Zechuan Wang","Dong Wang","Chenyi Zhuang"],"abstract":"Existing refinement methods in LLM-based Text-to-SQL systems exhibit limited effectiveness. They often introduce new errors during the self-correction process and fail to detect and correct semantic inaccuracies. To address these gaps, we first introduce a clause-wise critique generation task along with a benchmark, SQLCriticBench, which performs fine-grained error localization including both syntax and semantic errors at the clause level. Furthermore, we introduce a variant of DPO for training our SQLCritic model, where the $β$ coefficient is adaptively changed according to the clause-level inconsistencies between the preferred and dispreferred critiques. We also propose an automatically training dataset curation pipeline which annotate clause-wise critique at scale in a cost-effective way. Experiments demonstrate that the SQLCritic model significantly improves SQL accuracy on the BIRD and Spider datasets, and the results on SQLCriticBench further reveals its superior critique capabilities compared to existing models.","published":"2025-03-11T02:52:39Z","updated":"2025-05-21T01:48:22Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.07996v4","pdf_url":"https://arxiv.org/pdf/2503.07996v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.07317","versioned_id":"2503.07317v1","title":"Self-Corrective Task Planning by Inverse Prompting with Large Language Models","authors":["Jiho Lee","Hayun Lee","Jonghyeon Kim","Kyungjae Lee","Eunwoo Kim"],"abstract":"In robot task planning, large language models (LLMs) have shown significant promise in generating complex and long-horizon action sequences. However, it is observed that LLMs often produce responses that sound plausible but are not accurate. To address these problems, existing methods typically employ predefined error sets or external knowledge sources, requiring human efforts and computation resources. Recently, self-correction approaches have emerged, where LLM generates and refines plans, identifying errors by itself. Despite their effectiveness, they are more prone to failures in correction due to insufficient reasoning. In this paper, we introduce InversePrompt, a novel self-corrective task planning approach that leverages inverse prompting to enhance interpretability. Our method incorporates reasoning steps to provide clear, interpretable feedback. It generates inverse actions corresponding to the initially generated actions and verifies whether these inverse actions can restore the system to its original state, explicitly validating the logical coherence of the generated plans. The results on benchmark datasets show an average 16.3% higher success rate over existing LLM-based task planning methods. Our approach offers clearer justifications for feedback in real-world environments, resulting in more successful task completion than existing self-correction approaches across various scenarios.","published":"2025-03-10T13:35:51Z","updated":"2025-03-10T13:35:51Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2503.07317v1","pdf_url":"https://arxiv.org/pdf/2503.07317v1","comment":"7 pages, 5 figures, IEEE International Conference on Robotics and Automation (ICRA) 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.06791","versioned_id":"2503.06791v2","title":"AutoMisty: A Multi-Agent LLM Framework for Automated Code Generation in the Misty Social Robot","authors":["Xiao Wang","Lu Dong","Sahana Rangasrinivasan","Ifeoma Nwogu","Srirangaraj Setlur","Venugopal Govindaraju"],"abstract":"The social robot's open API allows users to customize open-domain interactions. However, it remains inaccessible to those without programming experience. In this work, we introduce AutoMisty, the first multi-agent collaboration framework powered by large language models (LLMs), to enable the seamless generation of executable Misty robot code from natural language instructions. AutoMisty incorporates four specialized agent modules to manage task decomposition, assignment, problem-solving, and result synthesis. Each agent incorporates a two-layer optimization mechanism, with self-reflection for iterative refinement and human-in-the-loop for better alignment with user preferences. AutoMisty ensures a transparent reasoning process, allowing users to iteratively refine tasks through natural language feedback for precise execution. To evaluate AutoMisty's effectiveness, we designed a benchmark task set spanning four levels of complexity and conducted experiments in a real Misty robot environment. Extensive evaluations demonstrate that AutoMisty not only consistently generates high-quality code but also enables precise code control, significantly outperforming direct reasoning with ChatGPT-4o and ChatGPT-o1. All code, optimized APIs, and experimental videos will be publicly released through the webpage: https://wangxiaoshawn.github.io/AutoMisty.html","published":"2025-03-09T22:07:46Z","updated":"2025-08-24T05:44:07Z","categories":["cs.RO","cs.AI","cs.HC","cs.MA"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2503.06791v2","pdf_url":"https://arxiv.org/pdf/2503.06791v2","comment":"Accepted by IROS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.06709","versioned_id":"2503.06709v1","title":"Delusions of Large Language Models","authors":["Hongshen Xu","Zixv yang","Zichen Zhu","Kunyao Lan","Zihan Wang","Mengyue Wu","Ziwei Ji","Lu Chen","Pascale Fung","Kai Yu"],"abstract":"Large Language Models often generate factually incorrect but plausible outputs, known as hallucinations. We identify a more insidious phenomenon, LLM delusion, defined as high belief hallucinations, incorrect outputs with abnormally high confidence, making them harder to detect and mitigate. Unlike ordinary hallucinations, delusions persist with low uncertainty, posing significant challenges to model reliability. Through empirical analysis across different model families and sizes on several Question Answering tasks, we show that delusions are prevalent and distinct from hallucinations. LLMs exhibit lower honesty with delusions, which are harder to override via finetuning or self reflection. We link delusion formation with training dynamics and dataset noise and explore mitigation strategies such as retrieval augmented generation and multi agent debating to mitigate delusions. By systematically investigating the nature, prevalence, and mitigation of LLM delusions, our study provides insights into the underlying causes of this phenomenon and outlines future directions for improving model reliability.","published":"2025-03-09T17:59:16Z","updated":"2025-03-09T17:59:16Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.06709v1","pdf_url":"https://arxiv.org/pdf/2503.06709v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.06011","versioned_id":"2503.06011v1","title":"Intent-Aware Self-Correction for Mitigating Social Biases in Large Language Models","authors":["Panatchakorn Anantaprayoon","Masahiro Kaneko","Naoaki Okazaki"],"abstract":"Self-Correction based on feedback improves the output quality of Large Language Models (LLMs). Moreover, as Self-Correction functions like the slow and conscious System-2 thinking from cognitive psychology's perspective, it can potentially reduce LLMs' social biases. LLMs are sensitive to contextual ambiguities and inconsistencies; therefore, explicitly communicating their intentions during interactions when applying Self-Correction for debiasing is crucial. In this study, we demonstrate that clarifying intentions is essential for effectively reducing biases in LLMs through Self-Correction. We divide the components needed for Self-Correction into three parts: instruction, response, and feedback, and clarify intentions at each component. We incorporate an explicit debiasing prompt to convey the intention of bias mitigation from the instruction for response generation. In the response, we use Chain-of-Thought (CoT) to clarify the reasoning process. In the feedback, we define evaluation aspects necessary for debiasing and propose clear feedback through multi-aspect critiques and scoring. Through experiments, we demonstrate that self-correcting CoT responses obtained from a debiasing prompt based on multi-aspect feedback can reduce biased responses more robustly and consistently than the baselines. We also find the variation in debiasing efficacy when using models with different bias levels or separating models for response and feedback generation.","published":"2025-03-08T02:20:43Z","updated":"2025-03-08T02:20:43Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.06011v1","pdf_url":"https://arxiv.org/pdf/2503.06011v1","comment":"18 pages. Under review","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.05473","versioned_id":"2503.05473v2","title":"The Society of HiveMind: Multi-Agent Optimization of Foundation Model Swarms to Unlock the Potential of Collective Intelligence","authors":["Noah Mamie","Susie Xi Rao"],"abstract":"Multi-agent systems address issues of accessibility and scalability of artificial intelligence (AI) foundation models, which are often represented by large language models. We develop a framework - the \"Society of HiveMind\" (SOHM) - that orchestrates the interaction between multiple AI foundation models, imitating the observed behavior of animal swarms in nature by following modern evolutionary theories. On the one hand, we find that the SOHM provides a negligible benefit on tasks that mainly require real-world knowledge. On the other hand, we remark a significant improvement on tasks that require intensive logical reasoning, indicating that multi-agent systems are capable of increasing the reasoning capabilities of the collective compared to the individual agents. Our findings demonstrate the potential of combining a multitude of diverse AI foundation models to form an artificial swarm intelligence capable of self-improvement through interactions with a given environment.","published":"2025-03-07T14:45:03Z","updated":"2025-03-13T14:20:53Z","categories":["cs.NE","cs.AI"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2503.05473v2","pdf_url":"https://arxiv.org/pdf/2503.05473v2","comment":"11 pages (excl. appendix)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.05132","versioned_id":"2503.05132v2","title":"R1-Zero's \"Aha Moment\" in Visual Reasoning on a 2B Non-SFT Model","authors":["Hengguang Zhou","Xirui Li","Ruochen Wang","Minhao Cheng","Tianyi Zhou","Cho-Jui Hsieh"],"abstract":"Recently DeepSeek R1 demonstrated how reinforcement learning with simple rule-based incentives can enable autonomous development of complex reasoning in large language models, characterized by the \"aha moment\", in which the model manifest self-reflection and increased response length during training. However, attempts to extend this success to multimodal reasoning often failed to reproduce these key characteristics. In this report, we present the first successful replication of these emergent characteristics for multimodal reasoning on only a non-SFT 2B model. Starting with Qwen2-VL-2B and applying reinforcement learning directly on the SAT dataset, our model achieves 59.47% accuracy on CVBench, outperforming the base model by approximately ~30% and exceeding both SFT setting by ~2%. In addition, we share our failed attempts and insights in attempting to achieve R1-like reasoning using RL with instruct models. aiming to shed light on the challenges involved. Our key observations include: (1) applying RL on instruct model often results in trivial reasoning trajectories, and (2) naive length reward are ineffective in eliciting reasoning capabilities. The project code is available at https://github.com/turningpoint-ai/VisualThinker-R1-Zero","published":"2025-03-07T04:21:47Z","updated":"2025-03-10T01:52:08Z","categories":["cs.AI","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.05132v2","pdf_url":"https://arxiv.org/pdf/2503.05132v2","comment":"10 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.04858","versioned_id":"2503.04858v1","title":"SHAPE : Self-Improved Visual Preference Alignment by Iteratively Generating Holistic Winner","authors":["Kejia Chen","Jiawen Zhang","Jiacong Hu","Jiazhen Yang","Jian Lou","Zunlei Feng","Mingli Song"],"abstract":"Large Visual Language Models (LVLMs) increasingly rely on preference alignment to ensure reliability, which steers the model behavior via preference fine-tuning on preference data structured as ``image - winner text - loser text'' triplets. However, existing approaches often suffer from limited diversity and high costs associated with human-annotated preference data, hindering LVLMs from fully achieving their intended alignment capabilities. We present \\projectname, a self-supervised framework capable of transforming the already abundant supervised text-image pairs into holistic preference triplets for more effective and cheaper LVLM alignment, eliminating the need for human preference annotations. Our approach facilitates LVLMs in progressively enhancing alignment capabilities through iterative self-improvement. The key design rationale is to devise preference triplets where the winner text consistently improves in holisticness and outperforms the loser response in quality, thereby pushing the model to ``strive to the utmost'' of alignment performance through preference fine-tuning. For each given text-image pair, SHAPE introduces multiple visual augmentations and pairs them with a summarized text to serve as the winner response, while designating the original text as the loser response. Experiments across \\textbf{12} benchmarks on various model architectures and sizes, including LLaVA and DeepSeek-VL, show that SHAPE achieves significant gains, for example, achieving +11.3\\% on MMVet (comprehensive evaluation), +1.4\\% on MMBench (general VQA), and +8.0\\% on POPE (hallucination robustness) over baselines in 7B models. Notably, qualitative analyses confirm enhanced attention to visual details and better alignment with human preferences for holistic descriptions.","published":"2025-03-06T08:33:11Z","updated":"2025-03-06T08:33:11Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.04858v1","pdf_url":"https://arxiv.org/pdf/2503.04858v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.04104","versioned_id":"2503.04104v2","title":"LLMs Can Generate a Better Answer by Aggregating Their Own Responses","authors":["Zichong Li","Xinyu Feng","Yuheng Cai","Zixuan Zhang","Tianyi Liu","Chen Liang","Weizhu Chen","Haoyu Wang","Tuo Zhao"],"abstract":"Large Language Models (LLMs) have shown remarkable capabilities across tasks, yet they often require additional prompting techniques when facing complex problems. While approaches like self-correction and response selection have emerged as popular solutions, recent studies have shown these methods perform poorly when relying on the LLM itself to provide feedback or selection criteria. We argue this limitation stems from the fact that common LLM post-training procedures lack explicit supervision for discriminative judgment tasks. In this paper, we propose Generative Self-Aggregation (GSA), a novel prompting method that improves answer quality without requiring the model's discriminative capabilities. GSA first samples multiple diverse responses from the LLM, then aggregates them to obtain an improved solution. Unlike previous approaches, our method does not require the LLM to correct errors or compare response quality; instead, it leverages the model's generative abilities to synthesize a new response based on the context of multiple samples. While GSA shares similarities with the self-consistency (SC) approach for response aggregation, SC requires specific verifiable tokens to enable majority voting. In contrast, our approach is more general and can be applied to open-ended tasks. Empirical evaluation demonstrates that GSA effectively improves response quality across various tasks, including mathematical reasoning, knowledge-based problems, and open-ended generation tasks such as code synthesis and conversational responses.","published":"2025-03-06T05:25:43Z","updated":"2025-04-12T21:53:51Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.04104v2","pdf_url":"https://arxiv.org/pdf/2503.04104v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.03730","versioned_id":"2503.03730v2","title":"Towards Understanding Distilled Reasoning Models: A Representational Approach","authors":["David D. Baek","Max Tegmark"],"abstract":"In this paper, we investigate how model distillation impacts the development of reasoning features in large language models (LLMs). To explore this, we train a crosscoder on Qwen-series models and their fine-tuned variants. Our results suggest that the crosscoder learns features corresponding to various types of reasoning, including self-reflection and computation verification. Moreover, we observe that distilled models contain unique reasoning feature directions, which could be used to steer the model into over-thinking or incisive-thinking mode. In particular, we perform analysis on four specific reasoning categories: (a) self-reflection, (b) deductive reasoning, (c) alternative reasoning, and (d) contrastive reasoning. Finally, we examine the changes in feature geometry resulting from the distillation process and find indications that larger distilled models may develop more structured representations, which correlate with enhanced distillation performance. By providing insights into how distillation modifies the model, our study contributes to enhancing the transparency and reliability of AI systems.","published":"2025-03-05T18:40:19Z","updated":"2025-03-25T00:07:50Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.03730v2","pdf_url":"https://arxiv.org/pdf/2503.03730v2","comment":"13 pages, 9 figures","journal_ref":"ICLR 2025 Workshop on Building Trust in Language Models and Applications","doi":"","discovered_on":"2026-07-17"},{"id":"2503.03149","versioned_id":"2503.03149v1","title":"DSVD: Dynamic Self-Verify Decoding for Faithful Generation in Large Language Models","authors":["YiQiu Guo","Yuchen Yang","Zhe Chen","Pingjie Wang","Yusheng Liao","Ya Zhang","Yanfeng Wang","Yu Wang"],"abstract":"The reliability of large language models remains a critical challenge, particularly due to their susceptibility to hallucinations and factual inaccuracies during text generation. Existing solutions either underutilize models' self-correction with preemptive strategies or use costly post-hoc verification. To further explore the potential of real-time self-verification and correction, we present Dynamic Self-Verify Decoding (DSVD), a novel decoding framework that enhances generation reliability through real-time hallucination detection and efficient error correction. DSVD integrates two key components: (1) parallel self-verification architecture for continuous quality assessment, (2) dynamic rollback mechanism for targeted error recovery. Extensive experiments across five benchmarks demonstrate DSVD's effectiveness, achieving significant improvement in truthfulness (Quesetion-Answering) and factual accuracy (FActScore). Results show the DSVD can be further incorporated with existing faithful decoding methods to achieve stronger performance. Our work establishes that real-time self-verification during generation offers a viable path toward more trustworthy language models without sacrificing practical deployability.","published":"2025-03-05T03:45:50Z","updated":"2025-03-05T03:45:50Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.03149v1","pdf_url":"https://arxiv.org/pdf/2503.03149v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.03128","versioned_id":"2503.03128v1","title":"Towards Understanding Multi-Round Large Language Model Reasoning: Approximability, Learnability and Generalizability","authors":["Chenhui Xu","Dancheng Liu","Jiajie Li","Amir Nassereldine","Zhaohui Li","Jinjun Xiong"],"abstract":"Recent advancements in cognitive science and multi-round reasoning techniques for Large Language Models (LLMs) suggest that iterative thinking processes improve problem-solving performance in complex tasks. Inspired by this, approaches like Chain-of-Thought, debating, and self-refinement have been applied to auto-regressive LLMs, achieving significant successes in tasks such as mathematical reasoning, commonsense reasoning, and multi-hop question answering. Despite these successes, the theoretical basis for how multi-round reasoning enhances problem-solving abilities remains underexplored. In this work, we investigate the approximation, learnability, and generalization properties of multi-round auto-regressive models. We show that Transformers with finite context windows are universal approximators for steps of Turing-computable functions and can approximate any Turing-computable sequence-to-sequence function through multi-round reasoning. We extend PAC learning to sequence generation and demonstrate that multi-round generation is learnable even when the sequence length exceeds the model's context window. Finally, we examine how generalization error propagates across rounds, and show how the aforementioned approaches can help constrain this error, ensuring outputs stay within an expectation boundary. This work sheds light on the systemic theoretical foundations of multi-round sequence learning and reasoning, emphasizing its role in inference complexity.","published":"2025-03-05T02:50:55Z","updated":"2025-03-05T02:50:55Z","categories":["cs.AI","cs.CL","cs.LG","stat.ML"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.03128v1","pdf_url":"https://arxiv.org/pdf/2503.03128v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.03040","versioned_id":"2503.03040v2","title":"SAGE: Steering Dialog Generation with Future-Aware State-Action Augmentation","authors":["Yizhe Zhang","Navdeep Jaitly"],"abstract":"Recent advances in large language models have demonstrated impressive capabilities in task-oriented applications, yet building emotionally intelligent chatbots that can engage in natural, strategic conversations remains a challenge. We present a novel approach called SAGE that uses latent variables to control long-horizon behavior in dialogue generation. At the core of our method is the State-Action Chain (SAC), which augments standard language model fine-tuning by introducing latent variables that encapsulate emotional states and conversational strategies between dialogue turns. During inference, these variables are generated before each response, enabling coarse-grained control over dialogue progression while maintaining natural interaction patterns. We also introduce a self-improvement pipeline that leverages dialogue tree search, LLM-based reward modeling, and targeted fine-tuning to optimize conversational trajectories. Our experimental results show that models trained with this approach demonstrate improved performance in emotional intelligence metrics while maintaining strong capabilities on LLM benchmarks. The discrete nature of our latent variables facilitates search-based strategies and provides a foundation for future applications of reinforcement learning to dialogue systems, where learning can occur at the state level rather than the token level. https://github.com/apple/ml-sage-dialog-gen","published":"2025-03-04T22:45:24Z","updated":"2025-07-01T07:35:25Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.03040v2","pdf_url":"https://arxiv.org/pdf/2503.03040v2","comment":"9 pages main text","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.02878","versioned_id":"2503.02878v3","title":"Language Models can Self-Improve at State-Value Estimation for Better Search","authors":["Ethan Mendes","Alan Ritter"],"abstract":"Collecting ground-truth rewards or human demonstrations for multi-step reasoning tasks is often prohibitively expensive, particularly in interactive domains such as web tasks. We introduce Self-Taught Lookahead (STL), a reward-free framework that improves language model-based value functions by reasoning explicitly about state transitions. STL can be viewed as a chain-of-thought analogue of the value iteration algorithm: instead of regressing directly on numeric values, a value LLM is trained to simulate a step of lookahead in natural language - predicting the next action, resulting state, and rationale for its value, thereby refining value estimates without any labeled data. This self-supervised procedure yields more accurate state-value predictions, which in turn enable lightweight search algorithms to expand fewer states while maintaining strong performance. Empirically, STL-trained value models built on moderately sized (8B parameter) open-weight LLMs boost web agent success rates by 39%, achieving comparable performance with proprietary models. STL also generalizes to multi-hop QA and math puzzles. We find that STL enables small open-source models to guide efficient search, reducing inference costs by integrating explicit reasoning with value learning.","published":"2025-03-04T18:58:11Z","updated":"2025-10-29T22:28:23Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.02878v3","pdf_url":"https://arxiv.org/pdf/2503.02878v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.02861","versioned_id":"2503.02861v1","title":"Evaluation of Architectural Synthesis Using Generative AI","authors":["Jingfei Huang","Alexandros Haridis"],"abstract":"Recent advancements in multimodal Generative AI have the potential to democratize specialized architectural tasks, such as interpreting technical drawings and creating 3D CAD models, which traditionally require expert knowledge. This paper presents a comparative evaluation of two systems: GPT-4o and Claude 3.5, in the task of architectural 3D synthesis. We conduct a case study on two buildings from Palladio's Four Books of Architecture (1965): Villa Rotonda and Palazzo Porto. High-level architectural models and drawings of these buildings were prepared, inspired by Palladio's original texts and drawings. Through sequential text and image prompting, we assess the systems' abilities in (1) interpreting 2D and 3D representations of buildings from drawings, (2) encoding the buildings into a CAD software script, and (3) self-improving based on outputs. While both systems successfully generate individual parts, they struggle to accurately assemble these parts into the desired spatial relationships, with Claude 3.5 demonstrating better performance, particularly in self-correcting its output. This study contributes to ongoing research on benchmarking the strengths and weaknesses of off-the-shelf AI systems in performing intelligent human tasks that require discipline-specific knowledge. The findings highlight the potential of language-enabled AI systems to act as collaborative technical assistants in the architectural design process.","published":"2025-03-04T18:39:28Z","updated":"2025-03-04T18:39:28Z","categories":["cs.AI","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.02861v1","pdf_url":"https://arxiv.org/pdf/2503.02861v1","comment":"10 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.02718","versioned_id":"2503.02718v1","title":"Evaluating Knowledge Generation and Self-Refinement Strategies for LLM-based Column Type Annotation","authors":["Keti Korini","Christian Bizer"],"abstract":"Understanding the semantics of columns in relational tables is an important pre-processing step for indexing data lakes in order to provide rich data search. An approach to establishing such understanding is column type annotation (CTA) where the goal is to annotate table columns with terms from a given vocabulary. This paper experimentally compares different knowledge generation and self-refinement strategies for LLM-based column type annotation. The strategies include using LLMs to generate term definitions, error-based refinement of term definitions, self-correction, and fine-tuning using examples and term definitions. We evaluate these strategies along two dimensions: effectiveness measured as F1 performance and efficiency measured in terms of token usage and cost. Our experiments show that the best performing strategy depends on the model/dataset combination. We find that using training data to generate label definitions outperforms using the same data as demonstrations for in-context learning for two out of three datasets using OpenAI models. The experiments further show that using the LLMs to refine label definitions brings an average increase of 3.9% F1 in 10 out of 12 setups compared to the performance of the non-refined definitions. Combining fine-tuned models with self-refined term definitions results in the overall highest performance, outperforming zero-shot prompting fine-tuned models by at least 3% in F1 score. The costs analysis shows that while reaching similar F1 score, self-refinement via prompting is more cost efficient for use cases requiring smaller amounts of tables to be annotated while fine-tuning is more efficient for large amounts of tables.","published":"2025-03-04T15:32:59Z","updated":"2025-03-04T15:32:59Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.02718v1","pdf_url":"https://arxiv.org/pdf/2503.02718v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.04813","versioned_id":"2503.04813v1","title":"Self-Evolved Preference Optimization for Enhancing Mathematical Reasoning in Small Language Models","authors":["Joykirat Singh","Tanmoy Chakraborty","Akshay Nambi"],"abstract":"Large language models (LLMs) have significantly improved their reasoning capabilities; however, they still struggle with complex multi-step mathematical problem-solving due to error propagation, lack of self-correction, and limited adaptability to diverse reasoning styles. Existing methods rely on static fine-tuning or prompt engineering, which fail to generalize across problem complexities, while the scarcity of high-quality preference data further hinders reliable reasoning. We introduce SPHERE, a self-evolving data generation pipeline that enhances reasoning in small language models (SLMs) by iteratively generating, correcting, and diversifying reasoning chains. SPHERE operates in three stages: (i) Self-Generation, where the model autonomously constructs problem-solving steps; (ii) Self-Correction, enabling it to identify and rectify errors; and (iii) Diversity Induction, improving robustness through multiple valid reasoning trajectories. This self-evolution mechanism strengthens mathematical reasoning and enhances model reliability. Evaluations on MATH 500, GSM8K, AIME, AMC, and Olympiad show that SPHERE-trained models achieve significant gains over their base versions and match/surpass GPT-4o on certain benchmarks. Our findings demonstrate that self-evolving models can close the reasoning gap between SLMs and state-of-the-art LLMs, making mathematical AI more reliable, scalable, and efficient.","published":"2025-03-04T14:43:25Z","updated":"2025-03-04T14:43:25Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.04813v1","pdf_url":"https://arxiv.org/pdf/2503.04813v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.02463","versioned_id":"2503.02463v1","title":"It Helps to Take a Second Opinion: Teaching Smaller LLMs to Deliberate Mutually via Selective Rationale Optimisation","authors":["Sohan Patnaik","Milan Aggarwal","Sumit Bhatia","Balaji Krishnamurthy"],"abstract":"Very large language models (LLMs) such as GPT-4 have shown the ability to handle complex tasks by generating and self-refining step-by-step rationales. Smaller language models (SLMs), typically with < 13B parameters, have been improved by using the data generated from very-large LMs through knowledge distillation. However, various practical constraints such as API costs, copyright, legal and ethical policies restrict using large (often opaque) models to train smaller models for commercial use. Limited success has been achieved at improving the ability of an SLM to explore the space of possible rationales and evaluate them by itself through self-deliberation. To address this, we propose COALITION, a trainable framework that facilitates interaction between two variants of the same SLM and trains them to generate and refine rationales optimized for the end-task. The variants exhibit different behaviors to produce a set of diverse candidate rationales during the generation and refinement steps. The model is then trained via Selective Rationale Optimization (SRO) to prefer generating rationale candidates that maximize the likelihood of producing the ground-truth answer. During inference, COALITION employs a controller to select the suitable variant for generating and refining the rationales. On five different datasets covering mathematical problems, commonsense reasoning, and natural language inference, COALITION outperforms several baselines by up to 5%. Our ablation studies reveal that cross-communication between the two variants performs better than using the single model to self-refine the rationales. We also demonstrate the applicability of COALITION for LMs of varying scales (4B to 14B parameters) and model families (Mistral, Llama, Qwen, Phi). We release the code for this work at https://github.com/Sohanpatnaik106/coalition.","published":"2025-03-04T10:17:29Z","updated":"2025-03-04T10:17:29Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.02463v1","pdf_url":"https://arxiv.org/pdf/2503.02463v1","comment":"Accepted at ICLR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.02368","versioned_id":"2503.02368v4","title":"Evolutionary Guided Decoding: Iterative Value Refinement for LLMs","authors":["Zhenhua Liu","Lijun Li","Ruizhe Chen","Yuxian Jiang","Tong Zhu","Zhaochen Su","Wenliang Chen","Jing Shao"],"abstract":"While guided decoding, especially value-guided methods, has emerged as a cost-effective alternative for controlling language model outputs without re-training models, its effectiveness is limited by the accuracy of the value function. We identify that this inaccuracy stems from a core distributional gap: existing methods train static value functions on trajectories sampled exclusively from the base policy, which inherently confines their training to a narrow and suboptimal view of the potential output space. We propose Iterative Value Refinement, a evolutionary framework designed to narrow this gap. It employs Value Exploration to provide a more comprehensive and robust training signal, complemented by Iterative Self-Refinement, which uses the improved value function from one iteration to guide the generation of higher-quality data for the next. Extensive experiments on text summarization, multi-turn dialogue, and instruction following demonstrate the effectiveness of our framework in aligning language models. Our approach not only achieves alignment but also significantly reduces computational costs by leveraging principled value function optimization for efficient and effective control.","published":"2025-03-04T07:49:10Z","updated":"2026-07-06T12:22:05Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.02368v4","pdf_url":"https://arxiv.org/pdf/2503.02368v4","comment":"Accepted to ACL 2026 (main conference)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.02103","versioned_id":"2503.02103v2","title":"Superficial Self-Improved Reasoners Benefit from Model Merging","authors":["Xiangchi Yuan","Chunhui Zhang","Zheyuan Liu","Dachuan Shi","Leyan Pan","Soroush Vosoughi","Wenke Lee"],"abstract":"As scaled language models (LMs) approach human-level reasoning capabilities, self-improvement emerges as a solution to synthesizing high-quality data corpus. While previous research has identified model collapse as a risk in self-improvement, where model outputs become increasingly deterministic, we discover a more fundamental challenge: the superficial self-improved reasoners phenomenon. In particular, our analysis reveals that even when LMs show improved in-domain (ID) reasoning accuracy, they actually compromise their generalized reasoning capabilities on out-of-domain (OOD) tasks due to memorization rather than genuine. Through a systematic investigation of LM architecture, we discover that during self-improvement, LM weight updates are concentrated in less reasoning-critical layers, leading to superficial learning. To address this, we propose Iterative Model Merging (IMM), a method that strategically combines weights from original and self-improved models to preserve generalization while incorporating genuine reasoning improvements. Our approach effectively mitigates both LM collapse and superficial learning, moving towards more stable self-improving systems.","published":"2025-03-03T22:41:25Z","updated":"2025-10-27T17:35:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.02103v2","pdf_url":"https://arxiv.org/pdf/2503.02103v2","comment":"EMNLP 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.01695","versioned_id":"2503.01695v1","title":"Generate, Discriminate, Evolve: Enhancing Context Faithfulness via Fine-Grained Sentence-Level Self-Evolution","authors":["Kun Li","Tianhua Zhang","Yunxiang Li","Hongyin Luo","Abdalla Moustafa","Xixin Wu","James Glass","Helen Meng"],"abstract":"Improving context faithfulness in large language models is essential for developing trustworthy retrieval augmented generation systems and mitigating hallucinations, especially in long-form question answering (LFQA) tasks or scenarios involving knowledge conflicts. Existing methods either intervene LLMs only at inference without addressing their inherent limitations or overlook the potential for self-improvement. In this paper, we introduce GenDiE (Generate, Discriminate, Evolve), a novel self-evolving framework that enhances context faithfulness through fine-grained sentence-level optimization. GenDiE combines both generative and discriminative training, equipping LLMs with self-generation and self-scoring capabilities to facilitate iterative self-evolution. This supports both data construction for model alignment and score-guided search during inference. Furthermore, by treating each sentence in a response as an independent optimization unit, GenDiE effectively addresses the limitations of previous approaches that optimize at the holistic answer level, which may miss unfaithful details. Experiments on ASQA (in-domain LFQA) and ConFiQA (out-of-domain counterfactual QA) datasets demonstrate that GenDiE surpasses various baselines in both faithfulness and correctness, and exhibits robust performance for domain adaptation.","published":"2025-03-03T16:08:33Z","updated":"2025-03-03T16:08:33Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.01695v1","pdf_url":"https://arxiv.org/pdf/2503.01695v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.01940","versioned_id":"2503.01940v2","title":"AskToAct: Enhancing LLMs Tool Use via Self-Correcting Clarification","authors":["Xuan Zhang","Yongliang Shen","Zhe Zheng","Linjuan Wu","Wenqi Zhang","Yuchen Yan","Qiuying Peng","Jun Wang","Weiming Lu"],"abstract":"Large language models (LLMs) have demonstrated remarkable capabilities in tool learning. In real-world scenarios, user queries are often ambiguous and incomplete, requiring effective clarification. However, existing interactive clarification approaches face two critical limitations: reliance on manually constructed datasets, which inherently constrains training data scale and diversity, and lack of error correction mechanisms during multi-turn clarification, leading to error accumulation that compromises both accuracy and efficiency. We present AskToAct, which addresses these challenges by exploiting the structural mapping between queries and their tool invocation solutions. Our key insight is that tool parameters naturally represent explicit user intents. By systematically removing key parameters from queries while retaining them as ground truth, we enable automated construction of high-quality training data. We further enhance model robustness through error-correction pairs and selective masking, enabling dynamic error detection during clarification interactions. Comprehensive experiments demonstrate that AskToAct significantly outperforms existing approaches, achieving above 57% accuracy in recovering critical unspecified intents and enhancing clarification efficiency by an average of 10.46% while maintaining high accuracy in tool invocation. Our framework exhibits robust performance across different model architectures and successfully generalizes to entirely unseen APIs without additional training, achieving performance comparable to GPT-4o with substantially fewer computational resources.","published":"2025-03-03T12:55:49Z","updated":"2025-06-11T12:06:37Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.01940v2","pdf_url":"https://arxiv.org/pdf/2503.01940v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.01490","versioned_id":"2503.01490v1","title":"Improving Retrospective Language Agents via Joint Policy Gradient Optimization","authors":["Xueyang Feng","Bo Lan","Quanyu Dai","Lei Wang","Jiakai Tang","Xu Chen","Zhenhua Dong","Ji-Rong Wen"],"abstract":"In recent research advancements within the community, large language models (LLMs) have sparked great interest in creating autonomous agents. However, current prompt-based agents often heavily rely on large-scale LLMs. Meanwhile, although fine-tuning methods significantly enhance the capabilities of smaller LLMs, the fine-tuned agents often lack the potential for self-reflection and self-improvement. To address these challenges, we introduce a novel agent framework named RetroAct, which is a framework that jointly optimizes both task-planning and self-reflective evolution capabilities in language agents. Specifically, we develop a two-stage joint optimization process that integrates imitation learning and reinforcement learning, and design an off-policy joint policy gradient optimization algorithm with imitation learning regularization to enhance the data efficiency and training stability in agent tasks. RetroAct significantly improves the performance of open-source models, reduces dependency on closed-source LLMs, and enables fine-tuned agents to learn and evolve continuously. We conduct extensive experiments across various testing environments, demonstrating RetroAct has substantial improvements in task performance and decision-making processes.","published":"2025-03-03T12:54:54Z","updated":"2025-03-03T12:54:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.01490v1","pdf_url":"https://arxiv.org/pdf/2503.01490v1","comment":"NAACL2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.01307","versioned_id":"2503.01307v2","title":"Cognitive Behaviors that Enable Self-Improving Reasoners, or, Four Habits of Highly Effective STaRs","authors":["Kanishk Gandhi","Ayush Chakravarthy","Anikait Singh","Nathan Lile","Noah D. Goodman"],"abstract":"Test-time inference has emerged as a powerful paradigm for enabling language models to ``think'' longer and more carefully about complex challenges, much like skilled human experts. While reinforcement learning (RL) can drive self-improvement in language models on verifiable tasks, some models exhibit substantial gains while others quickly plateau. For instance, we find that Qwen-2.5-3B far exceeds Llama-3.2-3B under identical RL training for the game of Countdown. This discrepancy raises a critical question: what intrinsic properties enable effective self-improvement? We introduce a framework to investigate this question by analyzing four key cognitive behaviors -- verification, backtracking, subgoal setting, and backward chaining -- that both expert human problem solvers and successful language models employ. Our study reveals that Qwen naturally exhibits these reasoning behaviors, whereas Llama initially lacks them. In systematic experimentation with controlled behavioral datasets, we find that priming Llama with examples containing these reasoning behaviors enables substantial improvements during RL, matching or exceeding Qwen's performance. Importantly, the presence of reasoning behaviors, rather than correctness of answers, proves to be the critical factor -- models primed with incorrect solutions containing proper reasoning patterns achieve comparable performance to those trained on correct solutions. Finally, leveraging continued pretraining with OpenWebMath data, filtered to amplify reasoning behaviors, enables the Llama model to match Qwen's self-improvement trajectory. Our findings establish a fundamental relationship between initial reasoning behaviors and the capacity for improvement, explaining why some language models effectively utilize additional computation while others plateau.","published":"2025-03-03T08:46:22Z","updated":"2025-08-15T15:21:46Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.01307v2","pdf_url":"https://arxiv.org/pdf/2503.01307v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.00902","versioned_id":"2503.00902v1","title":"Instruct-of-Reflection: Enhancing Large Language Models Iterative Reflection Capabilities via Dynamic-Meta Instruction","authors":["Liping Liu","Chunhong Zhang","Likang Wu","Chuang Zhao","Zheng Hu","Ming He","Jianping Fan"],"abstract":"Self-reflection for Large Language Models (LLMs) has gained significant attention. Existing approaches involve models iterating and improving their previous responses based on LLMs' internal reflection ability or external feedback. However, recent research has raised doubts about whether intrinsic self-correction without external feedback may even degrade performance. Based on our empirical evidence, we find that current static reflection methods may lead to redundant, drift, and stubborn issues. To mitigate this, we introduce Instruct-of-Reflection (IoRT), a novel and general reflection framework that leverages dynamic-meta instruction to enhance the iterative reflection capability of LLMs. Specifically, we propose the instructor driven by the meta-thoughts and self-consistency classifier, generates various instructions, including refresh, stop, and select, to guide the next reflection iteration. Our experiments demonstrate that IoRT achieves an average improvement of 10.1% over established baselines in mathematical and commonsense reasoning tasks, highlighting its efficacy and applicability.","published":"2025-03-02T14:02:03Z","updated":"2025-03-02T14:02:03Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.00902v1","pdf_url":"https://arxiv.org/pdf/2503.00902v1","comment":"23 pages, 5 figures, accepted by NAACL2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.00761","versioned_id":"2503.00761v1","title":"TRACE: A Self-Improving Framework for Robot Behavior Forecasting with Vision-Language Models","authors":["Gokul Puthumanaillam","Paulo Padrao","Jose Fuentes","Pranay Thangeda","William E. Schafer","Jae Hyuk Song","Karan Jagdale","Leonardo Bobadilla","Melkior Ornik"],"abstract":"Predicting the near-term behavior of a reactive agent is crucial in many robotic scenarios, yet remains challenging when observations of that agent are sparse or intermittent. Vision-Language Models (VLMs) offer a promising avenue by integrating textual domain knowledge with visual cues, but their one-shot predictions often miss important edge cases and unusual maneuvers. Our key insight is that iterative, counterfactual exploration--where a dedicated module probes each proposed behavior hypothesis, explicitly represented as a plausible trajectory, for overlooked possibilities--can significantly enhance VLM-based behavioral forecasting. We present TRACE (Tree-of-thought Reasoning And Counterfactual Exploration), an inference framework that couples tree-of-thought generation with domain-aware feedback to refine behavior hypotheses over multiple rounds. Concretely, a VLM first proposes candidate trajectories for the agent; a counterfactual critic then suggests edge-case variations consistent with partial observations, prompting the VLM to expand or adjust its hypotheses in the next iteration. This creates a self-improving cycle where the VLM progressively internalizes edge cases from previous rounds, systematically uncovering not only typical behaviors but also rare or borderline maneuvers, ultimately yielding more robust trajectory predictions from minimal sensor data. We validate TRACE on both ground-vehicle simulations and real-world marine autonomous surface vehicles. Experimental results show that our method consistently outperforms standard VLM-driven and purely model-based baselines, capturing a broader range of feasible agent behaviors despite sparse sensing. Evaluation videos and code are available at trace-robotics.github.io.","published":"2025-03-02T06:58:02Z","updated":"2025-03-02T06:58:02Z","categories":["cs.RO","cs.CV","cs.MA","eess.SY"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2503.00761v1","pdf_url":"https://arxiv.org/pdf/2503.00761v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.01923","versioned_id":"2503.01923v1","title":"Output Length Effect on DeepSeek-R1's Safety in Forced Thinking","authors":["Xuying Li","Zhuo Li","Yuji Kosuga","Victor Bian"],"abstract":"Large Language Models (LLMs) have demonstrated strong reasoning capabilities, but their safety under adversarial conditions remains a challenge. This study examines the impact of output length on the robustness of DeepSeek-R1, particularly in Forced Thinking scenarios. We analyze responses across various adversarial prompts and find that while longer outputs can improve safety through self-correction, certain attack types exploit extended generations. Our findings suggest that output length should be dynamically controlled to balance reasoning effectiveness and security. We propose reinforcement learning-based policy adjustments and adaptive token length regulation to enhance LLM safety.","published":"2025-03-02T06:29:22Z","updated":"2025-03-02T06:29:22Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.01923v1","pdf_url":"https://arxiv.org/pdf/2503.01923v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.00735","versioned_id":"2503.00735v3","title":"LADDER: Self-Improving LLMs Through Recursive Problem Decomposition","authors":["Toby Simonds","Akira Yoshiyama"],"abstract":"We introduce LADDER (Learning through Autonomous Difficulty-Driven Example Recursion), a framework which enables Large Language Models to autonomously improve their problem-solving capabilities through self-guided learning by recursively generating and solving progressively simpler variants of complex problems. Unlike prior approaches that require curated datasets or human feedback, LADDER leverages a model's own capabilities to generate easier question variants. We demonstrate LADDER's effectiveness in the subject of mathematical integration, improving Llama 3.2 3B's accuracy from 1% to 82% on undergraduate-level problems and enabling Qwen2.5 7B Deepseek-R1 Distilled to achieve 73% on the MIT Integration Bee qualifying examination. We also introduce TTRL (Test-Time Reinforcement Learning), where we perform reinforcement learning on variants of test problems at inference time. TTRL enables Qwen2.5 7B Deepseek-R1 Distilled to achieve a state-of-the-art score of 90% on the MIT Integration Bee qualifying examination, surpassing OpenAI o1's performance. These results show how self-directed strategic learning can achieve significant capability improvements without relying on architectural scaling or human supervision.","published":"2025-03-02T05:16:43Z","updated":"2025-03-05T11:50:24Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.00735v3","pdf_url":"https://arxiv.org/pdf/2503.00735v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.00162","versioned_id":"2503.00162v1","title":"PreMind: Multi-Agent Video Understanding for Advanced Indexing of Presentation-style Videos","authors":["Kangda Wei","Zhengyu Zhou","Bingqing Wang","Jun Araki","Lukas Lange","Ruihong Huang","Zhe Feng"],"abstract":"In recent years, online lecture videos have become an increasingly popular resource for acquiring new knowledge. Systems capable of effectively understanding/indexing lecture videos are thus highly desirable, enabling downstream tasks like question answering to help users efficiently locate specific information within videos. This work proposes PreMind, a novel multi-agent multimodal framework that leverages various large models for advanced understanding/indexing of presentation-style videos. PreMind first segments videos into slide-presentation segments using a Vision-Language Model (VLM) to enhance modern shot-detection techniques. Each segment is then analyzed to generate multimodal indexes through three key steps: (1) extracting slide visual content, (2) transcribing speech narratives, and (3) consolidating these visual and speech contents into an integrated understanding. Three innovative mechanisms are also proposed to improve performance: leveraging prior lecture knowledge to refine visual understanding, detecting/correcting speech transcription errors using a VLM, and utilizing a critic agent for dynamic iterative self-reflection in vision analysis. Compared to traditional video indexing methods, PreMind captures rich, reliable multimodal information, allowing users to search for details like abbreviations shown only on slides. Systematic evaluations on the public LPM dataset and an internal enterprise dataset are conducted to validate PreMind's effectiveness, supported by detailed analyses.","published":"2025-02-28T20:17:48Z","updated":"2025-02-28T20:17:48Z","categories":["cs.CV","cs.AI","cs.CL","cs.MA"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.00162v1","pdf_url":"https://arxiv.org/pdf/2503.00162v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.05788","versioned_id":"2503.05788v2","title":"Emergent Abilities in Large Language Models: A Survey","authors":["Leonardo Berti","Flavio Giorgi","Gjergji Kasneci"],"abstract":"Large Language Models (LLMs) are leading a new technological revolution as one of the most promising research streams toward artificial general intelligence. The scaling of these models, accomplished by increasing the number of parameters and the magnitude of the training datasets, has been linked to various so-called emergent abilities that were previously unobserved. These emergent abilities, ranging from advanced reasoning and in-context learning to coding and problem-solving, have sparked an intense scientific debate: Are they truly emergent, or do they simply depend on external factors, such as training dynamics, the type of problems, or the chosen metric? What underlying mechanism causes them? Despite their transformative potential, emergent abilities remain poorly understood, leading to misconceptions about their definition, nature, predictability, and implications. In this work, we shed light on emergent abilities by conducting a comprehensive review of the phenomenon, addressing both its scientific underpinnings and real-world consequences. We first critically analyze existing definitions, exposing inconsistencies in conceptualizing emergent abilities. We then explore the conditions under which these abilities appear, evaluating the role of scaling laws, task complexity, pre-training loss, quantization, and prompting strategies. Our review extends beyond traditional LLMs and includes Large Reasoning Models (LRMs), which leverage reinforcement learning and inference-time search to amplify reasoning and self-reflection. However, emergence is not inherently positive. As AI systems gain autonomous reasoning capabilities, they also develop harmful behaviors, including deception, manipulation, and reward hacking. We highlight growing concerns about safety and governance, emphasizing the need for better evaluation frameworks and regulatory oversight.","published":"2025-02-28T01:20:01Z","updated":"2025-03-14T13:28:04Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.05788v2","pdf_url":"https://arxiv.org/pdf/2503.05788v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.20379","versioned_id":"2502.20379v1","title":"Multi-Agent Verification: Scaling Test-Time Compute with Multiple Verifiers","authors":["Shalev Lifshitz","Sheila A. McIlraith","Yilun Du"],"abstract":"By utilizing more computational resources at test-time, large language models (LLMs) can improve without additional training. One common strategy uses verifiers to evaluate candidate outputs. In this work, we propose a novel scaling dimension for test-time compute: scaling the number of verifiers. We introduce Multi-Agent Verification (MAV) as a test-time compute paradigm that combines multiple verifiers to improve performance. We propose using Aspect Verifiers (AVs), off-the-shelf LLMs prompted to verify different aspects of outputs, as one possible choice for the verifiers in a MAV system. AVs are a convenient building block for MAV since they can be easily combined without additional training. Moreover, we introduce BoN-MAV, a simple multi-agent verification algorithm that combines best-of-n sampling with multiple verifiers. BoN-MAV demonstrates stronger scaling patterns than self-consistency and reward model verification, and we demonstrate both weak-to-strong generalization, where combining weak verifiers improves even stronger LLMs, and self-improvement, where the same base model is used to both generate and verify outputs. Our results establish scaling the number of verifiers as a promising new dimension for improving language model performance at test-time.","published":"2025-02-27T18:53:30Z","updated":"2025-02-27T18:53:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.20379v1","pdf_url":"https://arxiv.org/pdf/2502.20379v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.19861","versioned_id":"2502.19861v1","title":"Social Influence Distorts Ratings in Online Interfaces","authors":["Marina Kontalexi","Alexandros Gelastopoulos","Pantelis P. Analytis"],"abstract":"Theoretical work on sequential choice and large-scale experiments in online ranking and voting systems has demonstrated that social influence can have a drastic impact on social and technological systems. Yet, the effect of social influence on online rating systems remains understudied and the few existing contributions suggest that online ratings would self-correct given enough users. Here, we propose a new framework for studying the effect of social influence on online ratings. We start from the assumption that people are influenced linearly by the observed average rating, but postulate that their propensity to be influenced varies. When the weight people assign to the observed average depends only on their own latent rating, the resulting system is linear, but the long-term rating may substantially deviate from the true mean rating. When the weight people put on the observed average depends on both their own latent rating and the observed average rating, the resulting system is non-linear, and may support multiple equilibria, suggesting that ratings might be path-dependent and deviations dramatic. Our results highlight potential limitations in crowdsourced information aggregation and can inform the design of more robust online rating systems.","published":"2025-02-27T08:05:39Z","updated":"2025-02-27T08:05:39Z","categories":["cs.SI","cs.MA","econ.TH"],"primary_category":"cs.SI","arxiv_url":"https://arxiv.org/abs/2502.19861v1","pdf_url":"https://arxiv.org/pdf/2502.19861v1","comment":"","journal_ref":"","doi":"10.1145/3701716.3715592","discovered_on":"2026-07-17"},{"id":"2502.19629","versioned_id":"2502.19629v1","title":"Agentic Mixture-of-Workflows for Multi-Modal Chemical Search","authors":["Tiffany J. Callahan","Nathaniel H. Park","Sara Capponi"],"abstract":"The vast and complex materials design space demands innovative strategies to integrate multidisciplinary scientific knowledge and optimize materials discovery. While large language models (LLMs) have demonstrated promising reasoning and automation capabilities across various domains, their application in materials science remains limited due to a lack of benchmarking standards and practical implementation frameworks. To address these challenges, we introduce Mixture-of-Workflows for Self-Corrective Retrieval-Augmented Generation (CRAG-MoW) - a novel paradigm that orchestrates multiple agentic workflows employing distinct CRAG strategies using open-source LLMs. Unlike prior approaches, CRAG-MoW synthesizes diverse outputs through an orchestration agent, enabling direct evaluation of multiple LLMs across the same problem domain. We benchmark CRAG-MoWs across small molecules, polymers, and chemical reactions, as well as multi-modal nuclear magnetic resonance (NMR) spectral retrieval. Our results demonstrate that CRAG-MoWs achieve performance comparable to GPT-4o while being preferred more frequently in comparative evaluations, highlighting the advantage of structured retrieval and multi-agent synthesis. By revealing performance variations across data types, CRAG-MoW provides a scalable, interpretable, and benchmark-driven approach to optimizing AI architectures for materials discovery. These insights are pivotal in addressing fundamental gaps in benchmarking LLMs and autonomous AI agents for scientific applications.","published":"2025-02-26T23:48:02Z","updated":"2025-02-26T23:48:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.19629v1","pdf_url":"https://arxiv.org/pdf/2502.19629v1","comment":"PDF includes supplemental material","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.19613","versioned_id":"2502.19613v1","title":"Self-rewarding correction for mathematical reasoning","authors":["Wei Xiong","Hanning Zhang","Chenlu Ye","Lichang Chen","Nan Jiang","Tong Zhang"],"abstract":"We study self-rewarding reasoning large language models (LLMs), which can simultaneously generate step-by-step reasoning and evaluate the correctness of their outputs during the inference time-without external feedback. This integrated approach allows a single model to independently guide its reasoning process, offering computational advantages for model deployment. We particularly focus on the representative task of self-correction, where models autonomously detect errors in their responses, revise outputs, and decide when to terminate iterative refinement loops. To enable this, we propose a two-staged algorithmic framework for constructing self-rewarding reasoning models using only self-generated data. In the first stage, we employ sequential rejection sampling to synthesize long chain-of-thought trajectories that incorporate both self-rewarding and self-correction mechanisms. Fine-tuning models on these curated data allows them to learn the patterns of self-rewarding and self-correction. In the second stage, we further enhance the models' ability to assess response accuracy and refine outputs through reinforcement learning with rule-based signals. Experiments with Llama-3 and Qwen-2.5 demonstrate that our approach surpasses intrinsic self-correction capabilities and achieves performance comparable to systems that rely on external reward models.","published":"2025-02-26T23:01:16Z","updated":"2025-02-26T23:01:16Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.19613v1","pdf_url":"https://arxiv.org/pdf/2502.19613v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.19414","versioned_id":"2502.19414v1","title":"Can Language Models Falsify? Evaluating Algorithmic Reasoning with Counterexample Creation","authors":["Shiven Sinha","Shashwat Goel","Ponnurangam Kumaraguru","Jonas Geiping","Matthias Bethge","Ameya Prabhu"],"abstract":"There is growing excitement about the potential of Language Models (LMs) to accelerate scientific discovery. Falsifying hypotheses is key to scientific progress, as it allows claims to be iteratively refined over time. This process requires significant researcher effort, reasoning, and ingenuity. Yet current benchmarks for LMs predominantly assess their ability to generate solutions rather than challenge them. We advocate for developing benchmarks that evaluate this inverse capability - creating counterexamples for subtly incorrect solutions. To demonstrate this approach, we start with the domain of algorithmic problem solving, where counterexamples can be evaluated automatically using code execution. Specifically, we introduce REFUTE, a dynamically updating benchmark that includes recent problems and incorrect submissions from programming competitions, where human experts successfully identified counterexamples. Our analysis finds that the best reasoning agents, even OpenAI o3-mini (high) with code execution feedback, can create counterexamples for only <9% of incorrect solutions in REFUTE, even though ratings indicate its ability to solve up to 48% of these problems from scratch. We hope our work spurs progress in evaluating and enhancing LMs' ability to falsify incorrect solutions - a capability that is crucial for both accelerating research and making models self-improve through reliable reflective reasoning.","published":"2025-02-26T18:58:13Z","updated":"2025-02-26T18:58:13Z","categories":["cs.LG","cs.SE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.19414v1","pdf_url":"https://arxiv.org/pdf/2502.19414v1","comment":"Technical Report","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.18864","versioned_id":"2502.18864v2","title":"Accelerating scientific discovery with Co-Scientist","authors":["Juraj Gottweis","Wei-Hung Weng","Alexander Daryin","Tao Tu","Petar Sirkovic","Artiom Myaskovsky","Grzegorz Glowaty","Felix Weissenberger","Alessio Orlandi","Dan Popovici","Anil Palepu","Keran Rong","Ryutaro Tanno","Khaled Saab","Fan Zhang","Jacob Blum","Andrew Carroll","Kavita Kulkarni","Nenad Tomasev","Dina Zverinski","Ivor Rendulic","Elahe Vedadi","Florian Hasler","Luka Rimanic","Marina Boia","Ivan Budiselic","Ben Feinstein","Mathias Bellaiche","Tom Sheffer","Jan Freyberg","Jeremy Ratcliff","Ottavia Bertolli","Katherine Chou","Avinatan Hassidim","Burak Gokturk","Amin Vahdat","Yuan Guan","Vikram Dhillon","Eeshit Dhaval Vaishnav","Byron Lee","Tiago R D Costa","José R Penadés","Gary Peltz","Yossi Matias","James Manyika","Demis Hassabis","Yunhan Xu","Pushmeet Kohli","Annalisa Pawlosky","Alan Karthikesalingam","Vivek Natarajan"],"abstract":"Scientific discovery is driven by scientists generating novel hypotheses for complex problems that undergo rigorous experimental validation. To augment this process, we introduce Co-Scientist, a multi-agent AI system built on Gemini for structured scientific thinking and hypothesis generation. Co-Scientist aims to help scientists discover new original knowledge. Conditioned on their research objectives and prior scientific evidence, it formulates demonstrably novel research hypotheses for experimental verification. The system's design involves agents continuously generating, critiquing and refining hypotheses accelerated by scaling test-time compute. Key contributions include: (1) a multi-agent architecture with an asynchronous task execution framework for flexible compute scaling; (2) a tournament evolution process for self-improving hypotheses generation. Automated evaluations show continued benefits of test-time compute scaling, improving hypothesis quality over time. While general purpose, we focus the validation in three biomedical applications: drug repurposing, novel target discovery, and explaining mechanisms of anti-microbial resistance. Specifically, Co-Scientist helped identify new drug repurposing candidates and synergistic combination therapies for acute myeloid leukemia, which were validated through in vitro experiments. These real-world validations demonstrate the potential of Co-Scientist to accelerate scientific discovery and usher in an era of AI empowered scientists.","published":"2025-02-26T06:17:13Z","updated":"2026-06-29T16:12:47Z","categories":["cs.AI","cs.CL","cs.HC","cs.LG","physics.soc-ph","q-bio.OT"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.18864v2","pdf_url":"https://arxiv.org/pdf/2502.18864v2","comment":"157 pages in total (main 42 pages, supplementary information 115 pages), 4 main figures, 1 main table, 6 extended data figures, 2 extended data tables, 9 supplementary figures, 4 supplementary tables, 37 main references, 117 supplementary references. Nature (2026)","journal_ref":"","doi":"10.1038/s41586-026-10644-y","discovered_on":"2026-07-17"},{"id":"2502.18702","versioned_id":"2502.18702v1","title":"A Cooperative Multi-Agent Framework for Zero-Shot Named Entity Recognition","authors":["Zihan Wang","Ziqi Zhao","Yougang Lyu","Zhumin Chen","Maarten de Rijke","Zhaochun Ren"],"abstract":"Zero-shot named entity recognition (NER) aims to develop entity recognition systems from unannotated text corpora. This task presents substantial challenges due to minimal human intervention. Recent work has adapted large language models (LLMs) for zero-shot NER by crafting specialized prompt templates. It advances model self-learning abilities by incorporating self-annotated demonstrations. However, two important challenges persist: (i) Correlations between contexts surrounding entities are overlooked, leading to wrong type predictions or entity omissions. (ii) The indiscriminate use of task demonstrations, retrieved through shallow similarity-based strategies, severely misleads LLMs during inference. In this paper, we introduce the cooperative multi-agent system (CMAS), a novel framework for zero-shot NER that uses the collective intelligence of multiple agents to address the challenges outlined above. CMAS has four main agents: (i) a self-annotator, (ii) a type-related feature (TRF) extractor, (iii) a demonstration discriminator, and (iv) an overall predictor. To explicitly capture correlations between contexts surrounding entities, CMAS reformulates NER into two subtasks: recognizing named entities and identifying entity type-related features within the target sentence. To enable controllable utilization of demonstrations, a demonstration discriminator is established to incorporate the self-reflection mechanism, automatically evaluating helpfulness scores for the target sentence. Experimental results show that CMAS significantly improves zero-shot NER performance across six benchmarks, including both domain-specific and general-domain scenarios. Furthermore, CMAS demonstrates its effectiveness in few-shot settings and with various LLM backbones.","published":"2025-02-25T23:30:43Z","updated":"2025-02-25T23:30:43Z","categories":["cs.IR","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2502.18702v1","pdf_url":"https://arxiv.org/pdf/2502.18702v1","comment":"Accepted at WWW 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.18431","versioned_id":"2502.18431v1","title":"TextGames: Learning to Self-Play Text-Based Puzzle Games via Language Model Reasoning","authors":["Frederikus Hudi","Genta Indra Winata","Ruochen Zhang","Alham Fikri Aji"],"abstract":"Reasoning is a fundamental capability of large language models (LLMs), enabling them to comprehend, analyze, and solve complex problems. In this paper, we introduce TextGames, an innovative benchmark specifically crafted to assess LLMs through demanding text-based games that require advanced skills in pattern recognition, spatial awareness, arithmetic, and logical reasoning. Our analysis probes LLMs' performance in both single-turn and multi-turn reasoning, and their abilities in leveraging feedback to correct subsequent answers through self-reflection. Our findings reveal that, although LLMs exhibit proficiency in addressing most easy and medium-level problems, they face significant challenges with more difficult tasks. In contrast, humans are capable of solving all tasks when given sufficient time. Moreover, we observe that LLMs show improved performance in multi-turn predictions through self-reflection, yet they still struggle with sequencing, counting, and following complex rules consistently. Additionally, models optimized for reasoning outperform pre-trained LLMs that prioritize instruction following, highlighting the crucial role of reasoning skills in addressing highly complex problems.","published":"2025-02-25T18:26:48Z","updated":"2025-02-25T18:26:48Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.18431v1","pdf_url":"https://arxiv.org/pdf/2502.18431v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.18080","versioned_id":"2502.18080v2","title":"Towards Thinking-Optimal Scaling of Test-Time Compute for LLM Reasoning","authors":["Wenkai Yang","Shuming Ma","Yankai Lin","Furu Wei"],"abstract":"Recent studies have shown that making a model spend more time thinking through longer Chain of Thoughts (CoTs) enables it to gain significant improvements in complex reasoning tasks. While current researches continue to explore the benefits of increasing test-time compute by extending the CoT lengths of Large Language Models (LLMs), we are concerned about a potential issue hidden behind the current pursuit of test-time scaling: Would excessively scaling the CoT length actually bring adverse effects to a model's reasoning performance? Our explorations on mathematical reasoning tasks reveal an unexpected finding that scaling with longer CoTs can indeed impair the reasoning performance of LLMs in certain domains. Moreover, we discover that there exists an optimal scaled length distribution that differs across different domains. Based on these insights, we propose a Thinking-Optimal Scaling strategy. Our method first uses a small set of seed data with varying response length distributions to teach the model to adopt different reasoning efforts for deep thinking. Then, the model selects its shortest correct response under different reasoning efforts on additional problems for self-improvement. Our self-improved models built upon Qwen2.5-32B-Instruct outperform other distillation-based 32B o1-like models across various math benchmarks, and achieve performance on par with the teacher model QwQ-32B-Preview that produces the seed data.","published":"2025-02-25T10:48:05Z","updated":"2025-10-12T14:58:06Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.18080v2","pdf_url":"https://arxiv.org/pdf/2502.18080v2","comment":"Accepted at NeurIPS 2025, camera-ready version","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.17888","versioned_id":"2502.17888v1","title":"RankCoT: Refining Knowledge for Retrieval-Augmented Generation through Ranking Chain-of-Thoughts","authors":["Mingyan Wu","Zhenghao Liu","Yukun Yan","Xinze Li","Shi Yu","Zheni Zeng","Yu Gu","Ge Yu"],"abstract":"Retrieval-Augmented Generation (RAG) enhances the performance of Large Language Models (LLMs) by incorporating external knowledge. However, LLMs still encounter challenges in effectively utilizing the knowledge from retrieved documents, often being misled by irrelevant or noisy information. To address this issue, we introduce RankCoT, a knowledge refinement method that incorporates reranking signals in generating CoT-based summarization for knowledge refinement based on given query and all retrieval documents. During training, RankCoT prompts the LLM to generate Chain-of-Thought (CoT) candidates based on the query and individual documents. It then fine-tunes the LLM to directly reproduce the best CoT from these candidate outputs based on all retrieved documents, which requires LLM to filter out irrelevant documents during generating CoT-style summarization. Additionally, RankCoT incorporates a self-reflection mechanism that further refines the CoT outputs, resulting in higher-quality training data. Our experiments demonstrate the effectiveness of RankCoT, showing its superior performance over other knowledge refinement models. Further analysis reveals that RankCoT can provide shorter but effective refinement results, enabling the generator to produce more accurate answers. All code and data are available at https://github.com/NEUIR/RankCoT.","published":"2025-02-25T06:18:05Z","updated":"2025-02-25T06:18:05Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.17888v1","pdf_url":"https://arxiv.org/pdf/2502.17888v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.17848","versioned_id":"2502.17848v4","title":"LR^2Bench: Evaluating Long-chain Reflective Reasoning Capabilities of Large Language Models via Constraint Satisfaction Problems","authors":["Jianghao Chen","Zhenlin Wei","Zhenjiang Ren","Ziyong Li","Jiajun Zhang"],"abstract":"Recent progress in Large Reasoning Models (LRMs) has significantly enhanced the reasoning abilities of Large Language Models (LLMs), empowering them to tackle increasingly complex tasks through reflection capabilities, such as making assumptions, backtracking, and self-refinement. However, effectively evaluating such reflection capabilities remains challenging due to the lack of appropriate benchmarks. To bridge this gap, we introduce LR$^2$Bench, a novel benchmark designed to evaluate the Long-chain Reflective Reasoning capabilities of LLMs. LR$^2$Bench comprises 850 samples across six Constraint Satisfaction Problems (CSPs) where reflective reasoning is crucial for deriving solutions that meet all given constraints. Each type of task focuses on distinct constraint patterns, such as knowledge-based, logical, and spatial constraints, providing a comprehensive evaluation of diverse problem-solving scenarios. Our extensive evaluation on both conventional LLMs and LRMs reveals that even the most advanced LRMs, such as DeepSeek-R1 and OpenAI o1-preview, struggle with tasks in LR$^2$Bench, achieving an average Exact Match score of only 20.0% and 23.6%, respectively. These findings underscore the significant room for improvement in the reflective reasoning capabilities of current LLMs.","published":"2025-02-25T04:51:17Z","updated":"2025-06-25T09:36:23Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.17848v4","pdf_url":"https://arxiv.org/pdf/2502.17848v4","comment":"ACL-2025, our code is available at https://github.com/ZNLP/LR2Bench","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.17840","versioned_id":"2502.17840v1","title":"A Combinatorial Identities Benchmark for Theorem Proving via Automated Theorem Generation","authors":["Beibei Xiong","Hangyu Lv","Haojia Shan","Jianlin Wang","Zhengfeng Yang","Lihong Zhi"],"abstract":"Large language models (LLMs) have significantly advanced formal theorem proving, yet the scarcity of high-quality training data constrains their capabilities in complex mathematical domains. Combinatorics, a cornerstone of mathematics, provides essential tools for analyzing discrete structures and solving optimization problems. However, its inherent complexity makes it particularly challenging for automated theorem proving (ATP) for combinatorial identities. To address this, we manually construct LeanComb, combinatorial identities benchmark in Lean, which is, to our knowledge, the first formalized theorem proving benchmark built for combinatorial identities. We develop an Automated Theorem Generator for Combinatorial Identities, ATG4CI, which combines candidate tactics suggested by a self-improving large language model with a Reinforcement Learning Tree Search approach for tactic prediction. By utilizing ATG4CI, we generate a LeanComb-Enhanced dataset comprising 260K combinatorial identities theorems, each with a complete formal proof in Lean, and experimental evaluations demonstrate that models trained on this dataset can generate more effective tactics, thereby improving success rates in automated theorem proving for combinatorial identities.","published":"2025-02-25T04:41:49Z","updated":"2025-02-25T04:41:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.17840v1","pdf_url":"https://arxiv.org/pdf/2502.17840v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.17812","versioned_id":"2502.17812v2","title":"Can Multimodal LLMs Perform Time Series Anomaly Detection?","authors":["Xiongxiao Xu","Haoran Wang","Yueqing Liang","Philip S. Yu","Yue Zhao","Kai Shu"],"abstract":"Time series anomaly detection (TSAD) has been a long-standing pillar problem in Web-scale systems and online infrastructures, such as service reliability monitoring, system fault diagnosis, and performance optimization. Large language models (LLMs) have demonstrated unprecedented capabilities in time series analysis, the potential of multimodal LLMs (MLLMs), particularly vision-language models, in TSAD remains largely under-explored. One natural way for humans to detect time series anomalies is through visualization and textual description. It motivates our research question: Can multimodal LLMs perform time series anomaly detection? Existing studies often oversimplify the problem by treating point-wise anomalies as special cases of range-wise ones or by aggregating point anomalies to approximate range-wise scenarios. They limit our understanding for realistic scenarios such as multi-granular anomalies and irregular time series. To address the gap, we build a VisualTimeAnomaly benchmark to comprehensively investigate zero-shot capabilities of MLLMs for TSAD, progressively from point-, range-, to variate-wise anomalies, and extends to irregular sampling conditions. Our study reveals several key insights in multimodal MLLMs for TSAD. Built on these findings, we propose a MLLMs-based multi-agent framework TSAD-Agents to achieve automatic TSAD. Our framework comprises scanning, planning, detection, and checking agents that synergistically collaborate to reason, plan, and self-reflect to enable automatic TSAD. These agents adaptively invoke tools such as traditional methods and MLLMs and dynamically switch between text and image modalities to optimize detection performance.","published":"2025-02-25T03:37:43Z","updated":"2026-02-17T17:04:01Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.17812v2","pdf_url":"https://arxiv.org/pdf/2502.17812v2","comment":"ACM Web Conference 2026 (WWW'26)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.17651","versioned_id":"2502.17651v4","title":"METAL: A Multi-Agent Framework for Chart Generation with Test-Time Scaling","authors":["Bingxuan Li","Yiwei Wang","Jiuxiang Gu","Kai-Wei Chang","Nanyun Peng"],"abstract":"Chart generation aims to generate code to produce charts satisfying the desired visual properties, e.g., texts, layout, color, and type. It has great potential to empower the automatic professional report generation in financial analysis, research presentation, education, and healthcare. In this work, we build a vision-language model (VLM) based multi-agent framework for effective automatic chart generation. Generating high-quality charts requires both strong visual design skills and precise coding capabilities that embed the desired visual properties into code. Such a complex multi-modal reasoning process is difficult for direct prompting of VLMs. To resolve these challenges, we propose METAL, a multi-agent framework that decomposes the task of chart generation into the iterative collaboration among specialized agents. METAL achieves 5.2% improvement over the current best result in the chart generation task. The METAL framework exhibits the phenomenon of test-time scaling: its performance increases monotonically as the logarithmic computational budget grows from 512 to 8192 tokens. In addition, we find that separating different modalities during the critique process of METAL boosts the self-correction capability of VLMs in the multimodal context.","published":"2025-02-24T21:01:39Z","updated":"2025-09-17T21:47:50Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2502.17651v4","pdf_url":"https://arxiv.org/pdf/2502.17651v4","comment":"ACL2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.16866","versioned_id":"2502.16866v1","title":"Toward Agentic AI: Generative Information Retrieval Inspired Intelligent Communications and Networking","authors":["Ruichen Zhang","Shunpu Tang","Yinqiu Liu","Dusit Niyato","Zehui Xiong","Sumei Sun","Shiwen Mao","Zhu Han"],"abstract":"The increasing complexity and scale of modern telecommunications networks demand intelligent automation to enhance efficiency, adaptability, and resilience. Agentic AI has emerged as a key paradigm for intelligent communications and networking, enabling AI-driven agents to perceive, reason, decide, and act within dynamic networking environments. However, effective decision-making in telecom applications, such as network planning, management, and resource allocation, requires integrating retrieval mechanisms that support multi-hop reasoning, historical cross-referencing, and compliance with evolving 3GPP standards. This article presents a forward-looking perspective on generative information retrieval-inspired intelligent communications and networking, emphasizing the role of knowledge acquisition, processing, and retrieval in agentic AI for telecom systems. We first provide a comprehensive review of generative information retrieval strategies, including traditional retrieval, hybrid retrieval, semantic retrieval, knowledge-based retrieval, and agentic contextual retrieval. We then analyze their advantages, limitations, and suitability for various networking scenarios. Next, we present a survey about their applications in communications and networking. Additionally, we introduce an agentic contextual retrieval framework to enhance telecom-specific planning by integrating multi-source retrieval, structured reasoning, and self-reflective validation. Experimental results demonstrate that our framework significantly improves answer accuracy, explanation consistency, and retrieval efficiency compared to traditional and semantic retrieval methods. Finally, we outline future research directions.","published":"2025-02-24T06:02:25Z","updated":"2025-02-24T06:02:25Z","categories":["cs.NI","cs.AI"],"primary_category":"cs.NI","arxiv_url":"https://arxiv.org/abs/2502.16866v1","pdf_url":"https://arxiv.org/pdf/2502.16866v1","comment":"7 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.16662","versioned_id":"2502.16662v2","title":"Saarthi: The First AI Formal Verification Engineer","authors":["Aman Kumar","Deepak Narayan Gadde","Keerthan Kopparam Radhakrishna","Djones Lettnin"],"abstract":"Recently, Devin has made a significant buzz in the Artificial Intelligence (AI) community as the world's first fully autonomous AI software engineer, capable of independently developing software code. Devin uses the concept of agentic workflow in Generative AI (GenAI), which empowers AI agents to engage in a more dynamic, iterative, and self-reflective process. In this paper, we present a similar fully autonomous AI formal verification engineer, Saarthi, capable of verifying a given RTL design end-to-end using an agentic workflow. With Saarthi, verification engineers can focus on more complex problems, and verification teams can strive for more ambitious goals. The domain-agnostic implementation of Saarthi makes it scalable for use across various domains such as RTL design, UVM-based verification, and others.","published":"2025-02-23T17:42:50Z","updated":"2025-03-01T13:02:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.16662v2","pdf_url":"https://arxiv.org/pdf/2502.16662v2","comment":"Published at the DVCon U.S. 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.16366","versioned_id":"2502.16366v4","title":"A Generative Approach to LLM Harmfulness Mitigation with Red Flag Tokens","authors":["David Dobre","Mehrnaz Mofakhami","Sophie Xhonneux","Leo Schwinn","Gauthier Gidel"],"abstract":"Many safety post-training methods for large language models (LLMs) are designed to modify the model's behaviour from producing unsafe answers to issuing refusals. However, such distribution shifts are often brittle and degrade performance on desirable tasks. To address these pitfalls, we propose augmenting the model's vocabulary with a special red flag token, and training the model to insert this token whenever harmful content is generated or imminent. This approach enables the model to explicitly learn the concept of harmfulness in its representations, with minimal impact on utility due to the marginal change in the generated distribution of natural language. Moreover, because the token is embedded in the model's vocabulary, we can naturally leverage the LLMs' generalization capabilities, such as in-context learning (ICL) and out-of-distribution generalization to languages that are not formally supported (e.g., Japanese for Llama3). In particular, we demonstrate that through ICL alone, the model can learn to initiate reflective reasoning upon generating the red flag token at inference, which steers the response away from harmful continuations or enables self-correction when the flag is raised falsely. This approach is orthogonal and complementary to existing safety technique (such as safety classifiers or standard safety training) and easier to evaluate in comparison to natural language refusals, as it does not require a human or automated judge to assess the harmlessness of the answers.","published":"2025-02-22T21:48:48Z","updated":"2025-10-06T18:29:16Z","categories":["cs.CL","cs.AI","cs.CR","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.16366v4","pdf_url":"https://arxiv.org/pdf/2502.16366v4","comment":"15 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.16182","versioned_id":"2502.16182v2","title":"IPO: Your Language Model is Secretly a Preference Classifier","authors":["Shivank Garg","Ayush Singh","Shweta Singh","Paras Chopra"],"abstract":"Reinforcement learning from human feedback (RLHF) has emerged as the primary method for aligning large language models (LLMs) with human preferences. While it enables LLMs to achieve human-level alignment, it often incurs significant computational and financial costs due to its reliance on training external reward models or human-labeled preferences. In this work, we propose Implicit Preference Optimization (IPO), an alternative approach that leverages generative LLMs as preference classifiers, thereby reducing the dependence on external human feedback or reward models to obtain preferences. We conduct a comprehensive evaluation on the preference classification ability of LLMs using RewardBench, assessing models across different sizes, architectures, and training levels to validate our hypothesis. Furthermore, we investigate the self-improvement capabilities of LLMs by generating multiple responses for a given instruction and employing the model itself as a preference classifier for Direct Preference Optimization (DPO)-based training. Our findings demonstrate that models trained through IPO achieve performance comparable to those utilizing state-of-the-art reward models for obtaining preferences.","published":"2025-02-22T10:59:11Z","updated":"2025-03-20T10:52:45Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.16182v2","pdf_url":"https://arxiv.org/pdf/2502.16182v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.15365","versioned_id":"2502.15365v2","title":"Identifying Features that Shape Perceived Consciousness in Large Language Model-based AI: A Quantitative Study of Human Responses","authors":["Bongsu Kang","Jundong Kim","Tae-Rim Yun","Hyojin Bae","Chang-Eop Kim"],"abstract":"This study quantitively examines which features of AI-generated text lead humans to perceive subjective consciousness in large language model (LLM)-based AI systems. Drawing on 99 passages from conversations with Claude 3 Opus and focusing on eight features -- metacognitive self-reflection, logical reasoning, empathy, emotionality, knowledge, fluency, unexpectedness, and subjective expressiveness -- we conducted a survey with 123 participants. Using regression and clustering analyses, we investigated how these features influence participants' perceptions of AI consciousness. The results reveal that metacognitive self-reflection and the AI's expression of its own emotions significantly increased perceived consciousness, while a heavy emphasis on knowledge reduced it. Participants clustered into seven subgroups, each showing distinct feature-weighting patterns. Additionally, higher prior knowledge of LLMs and more frequent usage of LLM-based chatbots were associated with greater overall likelihood assessments of AI consciousness. This study underscores the multidimensional and individualized nature of perceived AI consciousness and provides a foundation for better understanding the psychosocial implications of human-AI interaction.","published":"2025-02-21T10:27:28Z","updated":"2025-02-25T01:40:03Z","categories":["cs.HC","cs.AI","cs.CL","cs.CY"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2502.15365v2","pdf_url":"https://arxiv.org/pdf/2502.15365v2","comment":"11 pages, 3 figures, 4 tables","journal_ref":"Computers in Human Behavior Reports, Volume 21 (2026) 100901","doi":"10.1016/j.chbr.2025.100901","discovered_on":"2026-07-17"},{"id":"2502.14815","versioned_id":"2502.14815v1","title":"Optimizing Model Selection for Compound AI Systems","authors":["Lingjiao Chen","Jared Quincy Davis","Boris Hanin","Peter Bailis","Matei Zaharia","James Zou","Ion Stoica"],"abstract":"Compound AI systems that combine multiple LLM calls, such as self-refine and multi-agent-debate, achieve strong performance on many AI tasks. We address a core question in optimizing compound systems: for each LLM call or module in the system, how should one decide which LLM to use? We show that these LLM choices have a large effect on quality, but the search space is exponential. We propose LLMSelector, an efficient framework for model selection in compound systems, which leverages two key empirical insights: (i) end-to-end performance is often monotonic in how well each module performs, with all other modules held fixed, and (ii) per-module performance can be estimated accurately by an LLM. Building upon these insights, LLMSelector iteratively selects one module and allocates to it the model with the highest module-wise performance, as estimated by an LLM, until no further gain is possible. LLMSelector is applicable to any compound system with a bounded number of modules, and its number of API calls scales linearly with the number of modules, achieving high-quality model allocation both empirically and theoretically. Experiments with popular compound systems such as multi-agent debate and self-refine using LLMs such as GPT-4o, Claude 3.5 Sonnet and Gemini 1.5 show that LLMSelector confers 5%-70% accuracy gains compared to using the same LLM for all modules.","published":"2025-02-20T18:36:25Z","updated":"2025-02-20T18:36:25Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.14815v1","pdf_url":"https://arxiv.org/pdf/2502.14815v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.14704","versioned_id":"2502.14704v4","title":"Not All Data are Good Labels: On the Self-supervised Labeling for Time Series Forecasting","authors":["Yuxuan Yang","Dalin Zhang","Yuxuan Liang","Hua Lu","Gang Chen","Huan Li"],"abstract":"Time Series Forecasting (TSF) is a crucial task in various domains, yet existing TSF models rely heavily on high-quality data and insufficiently exploit all available data. This paper explores a novel self-supervised approach to re-label time series datasets by inherently constructing candidate datasets. During the optimization of a simple reconstruction network, intermediates are used as pseudo labels in a self-supervised paradigm, improving generalization for any predictor. We introduce the Self-Correction with Adaptive Mask (SCAM), which discards overfitted components and selectively replaces them with pseudo labels generated from reconstructions. Additionally, we incorporate Spectral Norm Regularization (SNR) to further suppress overfitting from a loss landscape perspective. Our experiments on eleven real-world datasets demonstrate that SCAM consistently improves the performance of various backbone models. This work offers a new perspective on constructing datasets and enhancing the generalization of TSF models through self-supervised learning. The code is available at https://github.com/SuDIS-ZJU/SCAM.","published":"2025-02-20T16:29:37Z","updated":"2025-12-16T12:34:29Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.14704v4","pdf_url":"https://arxiv.org/pdf/2502.14704v4","comment":"Accepted by NeurIPS'25 (spotlight)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.14669","versioned_id":"2502.14669v3","title":"AlphaMaze: Enhancing Large Language Models' Spatial Intelligence via GRPO","authors":["Alan Dao","Dinh Bach Vu"],"abstract":"Large Language Models (LLMs) have demonstrated impressive capabilities in language processing, yet they often struggle with tasks requiring genuine visual spatial reasoning. In this paper, we introduce a novel two-stage training framework designed to equip standard LLMs with visual reasoning abilities for maze navigation. First, we leverage Supervised Fine Tuning (SFT) on a curated dataset of tokenized maze representations to teach the model to predict step-by-step movement commands. Next, we apply Group Relative Policy Optimization (GRPO)-a technique used in DeepSeekR1-with a carefully crafted reward function to refine the model's sequential decision-making and encourage emergent chain-of-thought behaviors. Experimental results on synthetically generated mazes show that while a baseline model fails to navigate the maze, the SFT-trained model achieves 86% accuracy, and further GRPO fine-tuning boosts accuracy to 93%. Qualitative analyses reveal that GRPO fosters more robust and self-corrective reasoning, highlighting the potential of our approach to bridge the gap between language models and visual spatial tasks. These findings offer promising implications for applications in robotics, autonomous navigation, and other domains that require integrated visual and sequential reasoning.","published":"2025-02-20T16:05:18Z","updated":"2025-02-25T08:56:11Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.14669v3","pdf_url":"https://arxiv.org/pdf/2502.14669v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.14565","versioned_id":"2502.14565v2","title":"ReVISE: Learning to Refine at Test-Time via Intrinsic Self-Verification","authors":["Hyunseok Lee","Seunghyuk Oh","Jaehyung Kim","Jinwoo Shin","Jihoon Tack"],"abstract":"Self-awareness, i.e., the ability to assess and correct one's own generation, is a fundamental aspect of human intelligence, making its replication in large language models (LLMs) an important yet challenging task. Previous works tackle this by employing extensive reinforcement learning or rather relying on large external verifiers. In this work, we propose Refine via Intrinsic Self-Verification (ReVISE), an efficient and effective framework that enables LLMs to self-correct their outputs through self-verification. The core idea of ReVISE is to enable LLMs to verify their reasoning processes and continually rethink reasoning trajectories based on its verification. We introduce a structured curriculum based upon online preference learning to implement this efficiently. Specifically, as ReVISE involves two challenging tasks (i.e., self-verification and reasoning correction), we tackle each task sequentially using curriculum learning, collecting both failed and successful reasoning paths to construct preference pairs for efficient training. During inference, our approach enjoys natural test-time scaling by integrating self-verification and correction capabilities, further enhanced by our proposed confidence-aware decoding mechanism. Our experiments on various reasoning tasks demonstrate that ReVISE achieves efficient self-correction and significantly improves reasoning performance.","published":"2025-02-20T13:50:02Z","updated":"2025-07-15T06:30:11Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.14565v2","pdf_url":"https://arxiv.org/pdf/2502.14565v2","comment":"Published as conference proceeding for ICML 2025. First two authors contributed equally","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.14354","versioned_id":"2502.14354v3","title":"Self-Improvement Towards Pareto Optimality: Mitigating Preference Conflicts in Multi-Objective Alignment","authors":["Moxin Li","Yuantao Zhang","Wenjie Wang","Wentao Shi","Zhuo Liu","Fuli Feng","Tat-Seng Chua"],"abstract":"Multi-Objective Alignment (MOA) aims to align LLMs' responses with multiple human preference objectives, with Direct Preference Optimization (DPO) emerging as a prominent approach. However, we find that DPO-based MOA approaches suffer from widespread preference conflicts in the data, where different objectives favor different responses. This results in conflicting optimization directions, hindering the optimization on the Pareto Front. To address this, we propose to construct Pareto-optimal responses to resolve preference conflicts. To efficiently obtain and utilize such responses, we propose a self-improving DPO framework that enables LLMs to self-generate and select Pareto-optimal responses for self-supervised preference alignment. Extensive experiments on two datasets demonstrate the superior Pareto Front achieved by our framework compared to various baselines. Code is available at https://github.com/zyttt-coder/SIPO.","published":"2025-02-20T08:27:00Z","updated":"2025-12-08T04:48:14Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.14354v3","pdf_url":"https://arxiv.org/pdf/2502.14354v3","comment":"ACL findings (2025)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.14932","versioned_id":"2502.14932v1","title":"Learning to Retrieve and Reason on Knowledge Graph through Active Self-Reflection","authors":["Han Zhang","Langshi Zhou","Hanfang Yang"],"abstract":"Extensive research has investigated the integration of large language models (LLMs) with knowledge graphs to enhance the reasoning process. However, understanding how models perform reasoning utilizing structured graph knowledge remains underexplored. Most existing approaches rely on LLMs or retrievers to make binary judgments regarding the utilization of knowledge, which is too coarse. Meanwhile, there is still a lack of feedback mechanisms for reflection and correction throughout the entire reasoning path. This paper proposes an Active self-Reflection framework for knowledge Graph reasoning ARG, introducing for the first time an end-to-end training approach to achieve iterative reasoning grounded on structured graphs. Within the framework, the model leverages special tokens to \\textit{actively} determine whether knowledge retrieval is necessary, performs \\textit{reflective} critique based on the retrieved knowledge, and iteratively reasons over the knowledge graph. The reasoning paths generated by the model exhibit high interpretability, enabling deeper exploration of the model's understanding of structured knowledge. Ultimately, the proposed model achieves outstanding results compared to existing baselines in knowledge graph reasoning tasks.","published":"2025-02-20T06:38:48Z","updated":"2025-02-20T06:38:48Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.14932v1","pdf_url":"https://arxiv.org/pdf/2502.14932v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.13734","versioned_id":"2502.13734v2","title":"CARE: Confidence-Aware Regression Estimation of building density fine-tuning EO Foundation Models","authors":["Nikolaos Dionelis","Jente Bosmans","Nicolas Longépé"],"abstract":"Performing accurate confidence quantification and assessment in pixel-wise regression tasks, which are downstream applications of AI Foundation Models for Earth Observation (EO), is important for deep neural networks to predict their failures, improve their performance and enhance their capabilities in real-world applications, for their practical deployment. For pixel-wise regression tasks, specifically utilizing remote sensing data from satellite imagery in EO Foundation Models, confidence quantification is a critical challenge. The focus of this research work is on developing a Foundation Model using EO satellite data that computes and assigns a confidence metric alongside regression outputs to improve the reliability and interpretability of predictions generated by deep neural networks. To this end, we develop, train and evaluate the proposed Confidence-Aware Regression Estimation (CARE) Foundation Model. Our model CARE computes and assigns confidence to regression results as downstream tasks of a Foundation Model for EO data, and performs a confidence-aware self-corrective learning method for the low-confidence regions. We evaluate the model CARE, and experimental results on multi-spectral data from the Copernicus Sentinel-2 satellite constellation to estimate the building density (i.e. monitoring urban growth), show that the proposed method can be successfully applied to important regression problems in EO and remote sensing. We also show that our model CARE outperforms other baseline methods.","published":"2025-02-19T14:02:00Z","updated":"2025-04-03T10:04:54Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2502.13734v2","pdf_url":"https://arxiv.org/pdf/2502.13734v2","comment":"7 pages, 4 figures, Submitted","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.13550","versioned_id":"2502.13550v1","title":"STaR-SQL: Self-Taught Reasoner for Text-to-SQL","authors":["Mingqian He","Yongliang Shen","Wenqi Zhang","Qiuying Peng","Jun Wang","Weiming Lu"],"abstract":"Generating step-by-step \"chain-of-thought\" rationales has proven effective for improving the performance of large language models on complex reasoning tasks. However, applying such techniques to structured tasks, such as text-to-SQL, remains largely unexplored. In this paper, we introduce Self-Taught Reasoner for text-to-SQL (STaR-SQL), a novel approach that reframes SQL query generation as a reasoning-driven process. Our method prompts the LLM to produce detailed reasoning steps for SQL queries and fine-tunes it on rationales that lead to correct outcomes. Unlike traditional methods, STaR-SQL dedicates additional test-time computation to reasoning, thereby positioning LLMs as spontaneous reasoners rather than mere prompt-based agents. To further scale the inference process, we incorporate an outcome-supervised reward model (ORM) as a verifier, which enhances SQL query accuracy. Experimental results on the challenging Spider benchmark demonstrate that STaR-SQL significantly improves text-to-SQL performance, achieving an execution accuracy of 86.6%. This surpasses a few-shot baseline by 31.6% and a baseline fine-tuned to predict answers directly by 18.0%. Additionally, STaR-SQL outperforms agent-like prompting methods that leverage more powerful yet closed-source models such as GPT-4. These findings underscore the potential of reasoning-augmented training for structured tasks and open the door to extending self-improving reasoning models to text-to-SQL generation and beyond.","published":"2025-02-19T08:58:44Z","updated":"2025-02-19T08:58:44Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.13550v1","pdf_url":"https://arxiv.org/pdf/2502.13550v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.13441","versioned_id":"2502.13441v1","title":"The Self-Improvement Paradox: Can Language Models Bootstrap Reasoning Capabilities without External Scaffolding?","authors":["Yutao Sun","Mingshuai Chen","Tiancheng Zhao","Ruochen Xu","Zilun Zhang","Jianwei Yin"],"abstract":"Self-improving large language models (LLMs) -- i.e., to improve the performance of an LLM by fine-tuning it with synthetic data generated by itself -- is a promising way to advance the capabilities of LLMs while avoiding extensive supervision. Existing approaches to self-improvement often rely on external supervision signals in the form of seed data and/or assistance from third-party models. This paper presents Crescent -- a simple yet effective framework for generating high-quality synthetic question-answer data in a fully autonomous manner. Crescent first elicits the LLM to generate raw questions via a bait prompt, then diversifies these questions leveraging a rejection sampling-based self-deduplication, and finally feeds the questions to the LLM and collects the corresponding answers by means of majority voting. We show that Crescent sheds light on the potential of true self-improvement with zero external supervision signals for math reasoning; in particular, Crescent-generated question-answer pairs suffice to (i) improve the reasoning capabilities of an LLM while preserving its general performance (especially in the 0-shot setting); and (ii) distil LLM knowledge to weaker models more effectively than existing methods based on seed-dataset augmentation.","published":"2025-02-19T05:37:08Z","updated":"2025-02-19T05:37:08Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.13441v1","pdf_url":"https://arxiv.org/pdf/2502.13441v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.13389","versioned_id":"2502.13389v1","title":"Reasoning with Reinforced Functional Token Tuning","authors":["Kongcheng Zhang","Qi Yao","Baisheng Lai","Jiaxing Huang","Wenkai Fang","Dacheng Tao","Mingli Song","Shunyu Liu"],"abstract":"In this work, we propose Reinforced Functional Token Tuning (RFTT), a novel reinforced fine-tuning framework that empowers Large Language Models (LLMs) with self-play learn-to-reason capabilities. Unlike prior prompt-driven reasoning efforts, RFTT embeds a rich set of learnable functional tokens (e.g., <analyze>, <verify>, <refine>) directly into the model vocabulary, enabling chain-of-thought construction with diverse human-like reasoning behaviors. Specifically, RFTT comprises two phases: (1) supervised fine-tuning performs prompt-driven tree search to obtain self-generated training data annotated with functional tokens, which warms up the model to learn these tokens for reasoning; and (2) online reinforcement learning further allows the model to explore different reasoning pathways through functional token sampling without relying on prompts, thereby facilitating effective self-improvement for functional reasoning. Extensive experiments demonstrate the superiority of the proposed RFTT on mathematical benchmarks, significantly boosting Qwen-2.5-7B-Instruct (70.6% to 79.8%) and LLaMA-3.1-8B-Instruct (32.2% to 60.2%) on the MATH dataset. Moreover, the performance of RFTT consistently improves with more search rollouts at inference time. Our code is available at https://github.com/sastpg/RFTT.","published":"2025-02-19T02:59:42Z","updated":"2025-02-19T02:59:42Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.13389v1","pdf_url":"https://arxiv.org/pdf/2502.13389v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.13388","versioned_id":"2502.13388v4","title":"Reflection of Episodes: Learning to Play Game from Expert and Self Experiences","authors":["Xiaojie Xu","Zongyuan Li","Chang Lu","Runnan Qi","Yanan Ni","Lumin Jiang","Xiangbei Liu","Xuebo Zhang","Yongchun Fang","Kuihua Huang","Xian Guo","Zhanghua Wu","Zhenya Li"],"abstract":"StarCraft II is a complex and dynamic real-time strategy (RTS) game environment, which is very suitable for artificial intelligence and reinforcement learning research. To address the problem of Large Language Model(LLM) learning in complex environments through self-reflection, we propose a Reflection of Episodes(ROE) framework based on expert experience and self-experience. This framework first obtains key information in the game through a keyframe selection method, then makes decisions based on expert experience and self-experience. After a game is completed, it reflects on the previous experience to obtain new self-experience. Finally, in the experiment, our method beat the robot under the Very Hard difficulty in TextStarCraft II. We analyze the data of the LLM in the process of the game in detail, verified its effectiveness.","published":"2025-02-19T02:53:43Z","updated":"2026-04-10T14:53:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.13388v4","pdf_url":"https://arxiv.org/pdf/2502.13388v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.12926","versioned_id":"2502.12926v1","title":"Towards more Contextual Agents: An extractor-Generator Optimization Framework","authors":["Mourad Aouini","Jinan Loubani"],"abstract":"Large Language Model (LLM)-based agents have demonstrated remarkable success in solving complex tasks across a wide range of general-purpose applications. However, their performance often degrades in context-specific scenarios, such as specialized industries or research domains, where the absence of domain-relevant knowledge leads to imprecise or suboptimal outcomes. To address this challenge, our work introduces a systematic approach to enhance the contextual adaptability of LLM-based agents by optimizing their underlying prompts-critical components that govern agent behavior, roles, and interactions. Manually crafting optimized prompts for context-specific tasks is labor-intensive, error-prone, and lacks scalability. In this work, we introduce an Extractor-Generator framework designed to automate the optimization of contextual LLM-based agents. Our method operates through two key stages: (i) feature extraction from a dataset of gold-standard input-output examples, and (ii) prompt generation via a high-level optimization strategy that iteratively identifies underperforming cases and applies self-improvement techniques. This framework substantially improves prompt adaptability by enabling more precise generalization across diverse inputs, particularly in context-specific tasks where maintaining semantic consistency and minimizing error propagation are critical for reliable performance. Although developed with single-stage workflows in mind, the approach naturally extends to multi-stage workflows, offering broad applicability across various agent-based systems. Empirical evaluations demonstrate that our framework significantly enhances the performance of prompt-optimized agents, providing a structured and efficient approach to contextual LLM-based agents.","published":"2025-02-18T15:07:06Z","updated":"2025-02-18T15:07:06Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.12926v1","pdf_url":"https://arxiv.org/pdf/2502.12926v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.12853","versioned_id":"2502.12853v1","title":"S$^2$R: Teaching LLMs to Self-verify and Self-correct via Reinforcement Learning","authors":["Ruotian Ma","Peisong Wang","Cheng Liu","Xingyan Liu","Jiaqi Chen","Bang Zhang","Xin Zhou","Nan Du","Jia Li"],"abstract":"Recent studies have demonstrated the effectiveness of LLM test-time scaling. However, existing approaches to incentivize LLMs' deep thinking abilities generally require large-scale data or significant training efforts. Meanwhile, it remains unclear how to improve the thinking abilities of less powerful base models. In this work, we introduce S$^2$R, an efficient framework that enhances LLM reasoning by teaching models to self-verify and self-correct during inference. Specifically, we first initialize LLMs with iterative self-verification and self-correction behaviors through supervised fine-tuning on carefully curated data. The self-verification and self-correction skills are then further strengthened by both outcome-level and process-level reinforcement learning, with minimized resource requirements, enabling the model to adaptively refine its reasoning process during inference. Our results demonstrate that, with only 3.1k self-verifying and self-correcting behavior initialization samples, Qwen2.5-math-7B achieves an accuracy improvement from 51.0\\% to 81.6\\%, outperforming models trained on an equivalent amount of long-CoT distilled data. Extensive experiments and analysis based on three base models across both in-domain and out-of-domain benchmarks validate the effectiveness of S$^2$R. Our code and data are available at https://github.com/NineAbyss/S2R.","published":"2025-02-18T13:40:22Z","updated":"2025-02-18T13:40:22Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.12853v1","pdf_url":"https://arxiv.org/pdf/2502.12853v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.12565","versioned_id":"2502.12565v2","title":"Self Iterative Label Refinement via Robust Unlabeled Learning","authors":["Hikaru Asano","Tadashi Kozuno","Yukino Baba"],"abstract":"Recent advances in large language models (LLMs) have yielded impressive performance on various tasks, yet they often depend on high-quality feedback that can be costly. Self-refinement methods attempt to leverage LLMs' internal evaluation mechanisms with minimal human supervision; however, these approaches frequently suffer from inherent biases and overconfidence, especially in domains where the models lack sufficient internal knowledge, resulting in performance degradation. As an initial step toward enhancing self-refinement for broader applications, we introduce an iterative refinement pipeline that employs the Unlabeled-Unlabeled learning framework to improve LLM-generated pseudo-labels for classification tasks. By exploiting two unlabeled datasets with differing positive class ratios, our approach iteratively denoises and refines the initial pseudo-labels, thereby mitigating the adverse effects of internal biases with minimal human supervision. Evaluations on diverse datasets, including low-resource language corpora, patent classifications, and protein structure categorizations, demonstrate that our method consistently outperforms both initial LLM's classification performance and the self-refinement approaches by cutting-edge models (e.g., GPT-4o and DeepSeek-R1). Moreover, we experimentally confirm that our refined classifier facilitates effective post-training alignment for safety in LLMs and demonstrate successful self-refinement in generative tasks as well.\\footnote{Our code is available at https://github.com/HikaruAsano/self-iterative-label-refinement.}","published":"2025-02-18T06:04:18Z","updated":"2025-11-28T03:29:20Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.12565v2","pdf_url":"https://arxiv.org/pdf/2502.12565v2","comment":"To appear in the Thirty-Ninth Annual Conference on Neural Information Processing Systems (NeurIPS 2025)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.12275","versioned_id":"2502.12275v2","title":"Integrating Expert Knowledge into Logical Programs via LLMs","authors":["Franciszek Górski","Oskar Wysocki","Marco Valentino","Andre Freitas"],"abstract":"This paper introduces ExKLoP, a novel framework designed to evaluate how effectively Large Language Models (LLMs) integrate expert knowledge into logical reasoning systems. This capability is especially valuable in engineering, where expert knowledge-such as manufacturer-recommended operational ranges-can be directly embedded into automated monitoring systems. By mirroring expert verification steps, tasks like range checking and constraint validation help ensure system safety and reliability. Our approach systematically evaluates LLM-generated logical rules, assessing both syntactic fluency and logical correctness in these critical validation tasks. We also explore the models' capacity for self-correction via an iterative feedback loop based on code execution outcomes. ExKLoP presents an extensible dataset comprising 130 engineering premises, 950 prompts, and corresponding validation points. It enables comprehensive benchmarking while allowing control over task complexity and scalability of experiments. We leverage the synthetic data creation methodology to conduct extensive empirical evaluation on a diverse set of LLMs including Llama3, Gemma3, Codestral and QwenCoder. The results reveal that most models generate nearly perfect syntactically correct code and exhibit strong performance in translating expert knowledge into correct code. At the same time, while most LLMs produce nearly flawless syntactic output, their ability to correctly implement logical rules varies, as does their capacity for self-improvement. Overall, ExKLoP serves as a robust evaluation platform that streamlines the selection of effective models for self-correcting systems while clearly delineating the types of errors encountered.","published":"2025-02-17T19:18:23Z","updated":"2025-05-12T08:43:52Z","categories":["cs.AI","cs.CL","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.12275v2","pdf_url":"https://arxiv.org/pdf/2502.12275v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.12257","versioned_id":"2502.12257v2","title":"InfoQuest: Evaluating Multi-Turn Dialogue Agents for Open-Ended Conversations with Hidden Context","authors":["Bryan L. M. de Oliveira","Luana G. B. Martins","Bruno Brandão","Luckeciano C. Melo"],"abstract":"Large language models excel at following explicit instructions, but they often struggle with ambiguous or incomplete user requests, defaulting to verbose, generic responses instead of seeking clarification. We introduce InfoQuest, a multi-turn chat benchmark designed to evaluate how dialogue agents handle hidden context in open-ended user requests. This benchmark presents intentionally ambiguous scenarios that require models to engage in information-seeking dialogue by asking clarifying questions before providing appropriate responses. Our evaluation of both open and closed models reveals that, while proprietary models generally perform better, all current assistants struggle to gather critical information effectively. They often require multiple turns to infer user intent and frequently default to generic responses without proper clarification. We provide a systematic methodology for generating diverse scenarios and evaluating models' information-seeking capabilities, which can be leveraged to automatically generate data for self-improvement. We also offer insights into the current limitations of language models in handling ambiguous requests through multi-turn interactions.","published":"2025-02-17T19:01:10Z","updated":"2025-04-25T23:50:57Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.12257v2","pdf_url":"https://arxiv.org/pdf/2502.12257v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.12065","versioned_id":"2502.12065v3","title":"Autoformalization in the Wild: Assessing LLMs on Real-World Mathematical Definitions","authors":["Lan Zhang","Marco Valentino","Andre Freitas"],"abstract":"Thanks to their linguistic capabilities, LLMs offer an opportunity to bridge the gap between informal mathematics and formal languages through autoformalization. However, it is still unclear how well LLMs generalize to sophisticated and naturally occurring mathematical statements. To address this gap, we investigate the task of autoformalizing real-world mathematical definitions: a critical component of mathematical discourse. Specifically, we introduce two novel resources for autoformalization, collecting definitions from Wikipedia (Def_Wiki) and arXiv papers (Def_ArXiv). We then systematically evaluate a range of LLMs, analyzing their ability to formalize definitions into Isabelle/HOL. Furthermore, we investigate strategies to enhance LLMs' performance including refinement through external feedback from Proof Assistants, and formal definition grounding, where we augment LLMs' formalizations through relevant contextual elements from formal mathematical libraries. Our findings reveal that definitions present a greater challenge compared to existing benchmarks, such as miniF2F. In particular, we found that LLMs still struggle with self-correction, and aligning with relevant mathematical libraries. At the same time, structured refinement methods and definition grounding strategies yield notable improvements of up to 16% on self-correction capabilities and 43% on the reduction of undefined errors, highlighting promising directions for enhancing LLM-based autoformalization in real-world scenarios.","published":"2025-02-17T17:34:48Z","updated":"2025-09-04T12:43:14Z","categories":["cs.CL","cs.FL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.12065v3","pdf_url":"https://arxiv.org/pdf/2502.12065v3","comment":"EMNLP 2025 Camera-Ready Version","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.11959","versioned_id":"2502.11959v2","title":"STRIVE: Structured Reasoning for Self-Improvement in Claim Verification","authors":["Haisong Gong","Jing Li","Junfei Wu","Qiang Liu","Shu Wu","Liang Wang"],"abstract":"Claim verification is the task of determining whether a claim is supported or refuted by evidence. Self-improvement methods, where reasoning chains are generated and those leading to correct results are selected for training, have succeeded in tasks like mathematical problem solving. However, in claim verification, this approach struggles. Low-quality reasoning chains may falsely match binary truth labels, introducing faulty reasoning into the self-improvement process and ultimately degrading performance. To address this, we propose STRIVE: Structured Reasoning for Self-Improved Verification. Our method introduces a structured reasoning design with Claim Decomposition, Entity Analysis, and Evidence Grounding Verification. These components improve reasoning quality, reduce errors, and provide additional supervision signals for self-improvement. STRIVE begins with a warm-up phase, where the base model is fine-tuned on a small number of annotated examples to learn the structured reasoning design. It is then applied to generate reasoning chains for all training examples, selecting only those that are correct and structurally sound for subsequent self-improvement training. We demonstrate that STRIVE achieves significant improvements over baseline models, with a 31.4% performance gain over the base model and 20.7% over Chain of Thought on the HOVER datasets, highlighting its effectiveness.","published":"2025-02-17T16:07:07Z","updated":"2025-09-24T04:12:41Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.11959v2","pdf_url":"https://arxiv.org/pdf/2502.11959v2","comment":"Accepted by Machine Intelligence Research (MIR)","journal_ref":"","doi":"10.1007/s11633-025-1598-5","discovered_on":"2026-07-17"},{"id":"2502.11771","versioned_id":"2502.11771v2","title":"The Validation Gap: A Mechanistic Analysis of How Language Models Compute Arithmetic but Fail to Validate It","authors":["Leonardo Bertolazzi","Philipp Mondorf","Barbara Plank","Raffaella Bernardi"],"abstract":"The ability of large language models (LLMs) to validate their output and identify potential errors is crucial for ensuring robustness and reliability. However, current research indicates that LLMs struggle with self-correction, encountering significant challenges in detecting errors. While studies have explored methods to enhance self-correction in LLMs, relatively little attention has been given to understanding the models' internal mechanisms underlying error detection. In this paper, we present a mechanistic analysis of error detection in LLMs, focusing on simple arithmetic problems. Through circuit analysis, we identify the computational subgraphs responsible for detecting arithmetic errors across four smaller-sized LLMs. Our findings reveal that all models heavily rely on $\\textit{consistency heads}$--attention heads that assess surface-level alignment of numerical values in arithmetic solutions. Moreover, we observe that the models' internal arithmetic computation primarily occurs in higher layers, whereas validation takes place in middle layers, before the final arithmetic results are fully encoded. This structural dissociation between arithmetic computation and validation seems to explain why smaller-sized LLMs struggle to detect even simple arithmetic errors.","published":"2025-02-17T13:00:44Z","updated":"2025-09-25T13:37:54Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.11771v2","pdf_url":"https://arxiv.org/pdf/2502.11771v2","comment":"EMNLP 2025 Main, 38 pages, 33 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.11736","versioned_id":"2502.11736v3","title":"ReviewEval: An Evaluation Framework for AI-Generated Reviews","authors":["Madhav Krishan Garg","Tejash Prasad","Tanmay Singhal","Chhavi Kirtani","Murari Mandal","Dhruv Kumar"],"abstract":"The escalating volume of academic research, coupled with a shortage of qualified reviewers, necessitates innovative approaches to peer review. In this work, we propose: 1. ReviewEval, a comprehensive evaluation framework for AI-generated reviews that measures alignment with human assessments, verifies factual accuracy, assesses analytical depth, identifies degree of constructiveness and adherence to reviewer guidelines; and 2. ReviewAgent, an LLM-based review generation agent featuring a novel alignment mechanism to tailor feedback to target conferences and journals, along with a self-refinement loop that iteratively optimizes its intermediate outputs and an external improvement loop using ReviewEval to improve upon the final reviews. ReviewAgent improves actionable insights by 6.78% and 47.62% over existing AI baselines and expert reviews respectively. Further, it boosts analytical depth by 3.97% and 12.73%, enhances adherence to guidelines by 10.11% and 47.26% respectively. This paper establishes essential metrics for AIbased peer review and substantially enhances the reliability and impact of AI-generated reviews in academic research.","published":"2025-02-17T12:22:11Z","updated":"2025-05-24T17:01:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.11736v3","pdf_url":"https://arxiv.org/pdf/2502.11736v3","comment":"Under review: 8 pages, 2 figures, 5 tables, 9 pages for appendix","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.11705","versioned_id":"2502.11705v2","title":"LLM Agents Making Agent Tools","authors":["Georg Wölflein","Dyke Ferber","Daniel Truhn","Ognjen Arandjelović","Jakob Nikolas Kather"],"abstract":"Tool use has turned large language models (LLMs) into powerful agents that can perform complex multi-step tasks by dynamically utilising external software components. However, these tools must be implemented in advance by human developers, hindering the applicability of LLM agents in domains demanding large numbers of highly specialised tools, like in life sciences and medicine. Motivated by the growing trend of scientific studies accompanied by public code repositories, we propose ToolMaker, an agentic framework that autonomously transforms papers with code into LLM-compatible tools. Given a GitHub URL and short task description, ToolMaker autonomously installs dependencies and generates code to perform the task, using a closed-loop self-correction mechanism for debugging. To evaluate our approach, we introduce a benchmark comprising 15 complex computational tasks spanning various domains with over 100 unit tests to assess correctness and robustness. Our method correctly implements 80% of the tasks, substantially outperforming current state-of-the-art software engineering agents. ToolMaker therefore is a step towards fully autonomous agent-based scientific workflows. Our code and benchmark are publicly available at https://github.com/KatherLab/ToolMaker.","published":"2025-02-17T11:44:11Z","updated":"2025-05-29T18:47:41Z","categories":["cs.CL","cs.AI","cs.LG","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.11705v2","pdf_url":"https://arxiv.org/pdf/2502.11705v2","comment":"Accepted at ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.11422","versioned_id":"2502.11422v3","title":"Planning of Heuristics: Strategic Planning on Large Language Models with Monte Carlo Tree Search for Automating Heuristic Optimization","authors":["Hui Wang","Xufeng Zhang","Chaoxu Mu"],"abstract":"Heuristics have achieved great success in solving combinatorial optimization problems~(COPs). However, heuristics designed by humans require too much domain knowledge and testing time. Since Large Language Models~(LLMs) possess strong capabilities to understand and generate content with a knowledge base that covers various domains, they offer potential ways to automatically optimize heuristics. To this end, we propose Planning of Heuristics~(PoH), an optimization method that integrates LLM self-reflection with Monte Carlo Tree Search, a well-known planning algorithm. PoH iteratively refines generated heuristics by evaluating their performance and providing improvement suggestions. Our method enables to iteratively evaluate the generated heuristics~(states) and improve them based on the improvement suggestions~(actions) and evaluation results~(rewards), by effectively simulating future states to search for paths with higher rewards. In this paper, we apply PoH to solve the Traveling Salesman Problem and the Flow Shop Scheduling Problem. The experimental results show that PoH outperforms hand-crafted heuristics and other Automatic Heuristic Design methods based on LLMs, and achieves the state-of-the-art performance in automating heuristic optimization with LLMs to solve tested COPs, especially with large sizes.","published":"2025-02-17T04:35:01Z","updated":"2025-06-20T07:14:59Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.11422v3","pdf_url":"https://arxiv.org/pdf/2502.11422v3","comment":"17 pages, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.13162","versioned_id":"2502.13162v1","title":"ShieldLearner: A New Paradigm for Jailbreak Attack Defense in LLMs","authors":["Ziyi Ni","Hao Wang","Huacan Wang"],"abstract":"Large Language Models (LLMs) have achieved remarkable success in various domains but remain vulnerable to adversarial jailbreak attacks. Existing prompt-defense strategies, including parameter-modifying and parameter-free approaches, face limitations in adaptability, interpretability, and customization, constraining their effectiveness against evolving threats. To address these challenges, we propose ShieldLearner, a novel paradigm that mimics human learning in defense. Through trial and error, it autonomously distills attack signatures into a Pattern Atlas and synthesizes defense heuristics into a Meta-analysis Framework, enabling systematic and interpretable threat detection. Furthermore, we introduce Adaptive Adversarial Augmentation to generate adversarial variations of successfully defended prompts, enabling continuous self-improvement without model retraining. In addition to standard benchmarks, we create a hard test set by curating adversarial prompts from the Wildjailbreak dataset, emphasizing more concealed malicious intent. Experimental results show that ShieldLearner achieves a significantly higher defense success rate than existing baselines on both conventional and hard test sets, while also operating with lower computational overhead, making it a practical and efficient solution for real-world adversarial defense.","published":"2025-02-16T18:47:41Z","updated":"2025-02-16T18:47:41Z","categories":["cs.CR","cs.AI","cs.CL"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2502.13162v1","pdf_url":"https://arxiv.org/pdf/2502.13162v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.11191","versioned_id":"2502.11191v3","title":"Primus: A Pioneering Collection of Open-Source Datasets for Cybersecurity LLM Training","authors":["Yao-Ching Yu","Tsun-Han Chiang","Cheng-Wei Tsai","Chien-Ming Huang","Wen-Kwang Tsao"],"abstract":"Large Language Models (LLMs) have shown remarkable advancements in specialized fields such as finance, law, and medicine. However, in cybersecurity, we have noticed a lack of open-source datasets, with a particular lack of high-quality cybersecurity pretraining corpora, even though much research indicates that LLMs acquire their knowledge during pretraining. To address this, we present a comprehensive suite of datasets covering all major training stages, including pretraining, instruction fine-tuning, and reasoning distillation with cybersecurity-specific self-reflection data. Extensive ablation studies demonstrate their effectiveness on public cybersecurity benchmarks. In particular, continual pre-training on our dataset yields a 15.9% improvement in the aggregate score, while reasoning distillation leads to a 15.8% gain in security certification (CISSP). We will release all datasets and trained cybersecurity LLMs under the ODC-BY and MIT licenses to encourage further research in the community. For access to all datasets and model weights, please refer to https://huggingface.co/collections/trendmicro-ailab/primus-67b1fd27052b802b4af9d243.","published":"2025-02-16T16:34:49Z","updated":"2025-10-03T07:53:53Z","categories":["cs.CR","cs.AI","cs.CL"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2502.11191v3","pdf_url":"https://arxiv.org/pdf/2502.11191v3","comment":"Accepted to EMNLP 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2504.05309","versioned_id":"2504.05309v1","title":"IterQR: An Iterative Framework for LLM-based Query Rewrite in e-Commercial Search System","authors":["Shangyu Chen","Xinyu Jia","Yingfei Zhang","Shuai Zhang","Xiang Li","Wei Lin"],"abstract":"The essence of modern e-Commercial search system lies in matching user's intent and available candidates depending on user's query, providing personalized and precise service. However, user's query may be incorrect due to ambiguous input and typo, leading to inaccurate search. These cases may be released by query rewrite: modify query to other representation or expansion. However, traditional query rewrite replies on static rewrite vocabulary, which is manually established meanwhile lacks interaction with both domain knowledge in e-Commercial system and common knowledge in the real world. In this paper, with the ability to generate text content of Large Language Models (LLMs), we provide an iterative framework to generate query rewrite. The framework incorporates a 3-stage procedure in each iteration: Rewrite Generation with domain knowledge by Retrieval-Augmented Generation (RAG) and query understanding by Chain-of-Thoughts (CoT); Online Signal Collection with automatic positive rewrite update; Post-training of LLM with multi task objective to generate new rewrites. Our work (named as IterQR) provides a comprehensive framework to generate \\textbf{Q}uery \\textbf{R}ewrite with both domain / real-world knowledge. It automatically update and self-correct the rewrites during \\textbf{iter}ations. \\method{} has been deployed in Meituan Delivery's search system (China's leading food delivery platform), providing service for users with significant improvement.","published":"2025-02-16T09:20:13Z","updated":"2025-02-16T09:20:13Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2504.05309v1","pdf_url":"https://arxiv.org/pdf/2504.05309v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.10694","versioned_id":"2502.10694v1","title":"Simulations of Common Unsupervised Domain Adaptation Algorithms for Image Classification","authors":["Ahmad Chaddad","Yihang Wu","Yuchen Jiang","Ahmed Bouridane","Christian Desrosiers"],"abstract":"Traditional machine learning assumes that training and test sets are derived from the same distribution; however, this assumption does not always hold in practical applications. This distribution disparity can lead to severe performance drops when the trained model is used in new data sets. Domain adaptation (DA) is a machine learning technique that aims to address this problem by reducing the differences between domains. This paper presents simulation-based algorithms of recent DA techniques, mainly related to unsupervised domain adaptation (UDA), where labels are available only in the source domain. Our study compares these techniques with public data sets and diverse characteristics, highlighting their respective strengths and drawbacks. For example, Safe Self-Refinement for Transformer-based DA (SSRT) achieved the highest accuracy (91.6\\%) in the office-31 data set during our simulations, however, the accuracy dropped to 72.4\\% in the Office-Home data set when using limited batch sizes. In addition to improving the reader's comprehension of recent techniques in DA, our study also highlights challenges and upcoming directions for research in this domain. The codes are available at https://github.com/AIPMLab/Domain_Adaptation.","published":"2025-02-15T06:58:57Z","updated":"2025-02-15T06:58:57Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.10694v1","pdf_url":"https://arxiv.org/pdf/2502.10694v1","comment":"Accepted in IEEE TIM","journal_ref":"","doi":"10.1109/TIM.2025.3527531","discovered_on":"2026-07-17"},{"id":"2502.09621","versioned_id":"2502.09621v1","title":"MME-CoT: Benchmarking Chain-of-Thought in Large Multimodal Models for Reasoning Quality, Robustness, and Efficiency","authors":["Dongzhi Jiang","Renrui Zhang","Ziyu Guo","Yanwei Li","Yu Qi","Xinyan Chen","Liuhui Wang","Jianhan Jin","Claire Guo","Shen Yan","Bo Zhang","Chaoyou Fu","Peng Gao","Hongsheng Li"],"abstract":"Answering questions with Chain-of-Thought (CoT) has significantly enhanced the reasoning capabilities of Large Language Models (LLMs), yet its impact on Large Multimodal Models (LMMs) still lacks a systematic assessment and in-depth investigation. In this paper, we introduce MME-CoT, a specialized benchmark evaluating the CoT reasoning performance of LMMs, spanning six domains: math, science, OCR, logic, space-time, and general scenes. As the first comprehensive study in this area, we propose a thorough evaluation suite incorporating three novel metrics that assess the reasoning quality, robustness, and efficiency at a fine-grained level. Leveraging curated high-quality data and a unique evaluation strategy, we conduct an in-depth analysis of state-of-the-art LMMs, uncovering several key insights: 1) Models with reflection mechanism demonstrate a superior CoT quality, with Kimi k1.5 outperforming GPT-4o and demonstrating the highest quality results; 2) CoT prompting often degrades LMM performance on perception-heavy tasks, suggesting a potentially harmful overthinking behavior; and 3) Although the CoT quality is high, LMMs with reflection exhibit significant inefficiency in both normal response and self-correction phases. We hope MME-CoT serves as a foundation for advancing multimodal reasoning in LMMs. Project Page: https://mmecot.github.io/","published":"2025-02-13T18:59:46Z","updated":"2025-02-13T18:59:46Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2502.09621v1","pdf_url":"https://arxiv.org/pdf/2502.09621v1","comment":"Project Page: https://mmecot.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.09156","versioned_id":"2502.09156v1","title":"Improving TCM Question Answering through Tree-Organized Self-Reflective Retrieval with LLMs","authors":["Chang Liu","Ying Chang","Jianmin Li","Yiqian Qu","Yu Li","Lingyong Cao","Shuyuan Lin"],"abstract":"Objectives: Large language models (LLMs) can harness medical knowledge for intelligent question answering (Q&A), promising support for auxiliary diagnosis and medical talent cultivation. However, there is a deficiency of highly efficient retrieval-augmented generation (RAG) frameworks within the domain of Traditional Chinese Medicine (TCM). Our purpose is to observe the effect of the Tree-Organized Self-Reflective Retrieval (TOSRR) framework on LLMs in TCM Q&A tasks. Materials and Methods: We introduce the novel approach of knowledge organization, constructing a tree structure knowledge base with hierarchy. At inference time, our self-reflection framework retrieves from this knowledge base, integrating information across chapters. Questions from the TCM Medical Licensing Examination (MLE) and the college Classics Course Exam (CCE) were randomly selected as benchmark datasets. Results: By coupling with GPT-4, the framework can improve the best performance on the TCM MLE benchmark by 19.85% in absolute accuracy, and improve recall accuracy from 27% to 38% on CCE datasets. In manual evaluation, the framework improves a total of 18.52 points across dimensions of safety, consistency, explainability, compliance, and coherence. Conclusion: The TOSRR framework can effectively improve LLM's capability in Q&A tasks of TCM.","published":"2025-02-13T10:36:18Z","updated":"2025-02-13T10:36:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.09156v1","pdf_url":"https://arxiv.org/pdf/2502.09156v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.08923","versioned_id":"2502.08923v2","title":"CopySpec: Accelerating LLMs with Speculative Copy-and-Paste Without Compromising Quality","authors":["Razvan-Gabriel Dumitru","Minglai Yang","Vikas Yadav","Mihai Surdeanu"],"abstract":"We introduce CopySpec, a simple yet effective technique to tackle the inefficiencies LLMs face when generating responses that closely resemble previous outputs or responses that can be verbatim extracted from context. CopySpec identifies repeated sequences in the model's chat history or context and speculates that the same tokens will follow, enabling seamless copying without compromising output quality and without requiring additional GPU memory. To evaluate the effectiveness of our approach, we conducted experiments using seven LLMs and five datasets: MT-Bench, CNN/DM, GSM8K, HumanEval, and our newly created dataset, MT-Redundant. MT-Redundant, introduced in this paper, transforms the second turn of MT-Bench into a request for variations of the first turn's answer, simulating real-world scenarios where users request modifications to prior responses. Our results demonstrate significant speed-ups: up to 2.35x on CNN/DM, 3.08x on the second turn of select MT-Redundant categories, and 2.66x on the third turn of GSM8K's self-correction tasks. Importantly, we show that CopySpec integrates seamlessly with speculative decoding, yielding an average 49% additional speed-up over speculative decoding for the second turn of MT-Redundant across all eight categories. While LLMs, even with speculative decoding, suffer from slower inference as context size grows, CopySpec leverages larger contexts to accelerate inference, making it a faster complementary solution. Our code and dataset are publicly available at https://github.com/RazvanDu/CopySpec.","published":"2025-02-13T03:19:50Z","updated":"2025-05-23T00:51:17Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.08923v2","pdf_url":"https://arxiv.org/pdf/2502.08923v2","comment":"33 pages, 18 figures, 19 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2503.05705","versioned_id":"2503.05705v1","title":"Inference Scaling Reshapes AI Governance","authors":["Toby Ord"],"abstract":"The shift from scaling up the pre-training compute of AI systems to scaling up their inference compute may have profound effects on AI governance. The nature of these effects depends crucially on whether this new inference compute will primarily be used during external deployment or as part of a more complex training programme within the lab. Rapid scaling of inference-at-deployment would: lower the importance of open-weight models (and of securing the weights of closed models), reduce the impact of the first human-level models, change the business model for frontier AI, reduce the need for power-intense data centres, and derail the current paradigm of AI governance via training compute thresholds. Rapid scaling of inference-during-training would have more ambiguous effects that range from a revitalisation of pre-training scaling to a form of recursive self-improvement via iterated distillation and amplification.","published":"2025-02-12T22:04:16Z","updated":"2025-02-12T22:04:16Z","categories":["cs.CY","cs.AI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2503.05705v1","pdf_url":"https://arxiv.org/pdf/2503.05705v1","comment":"17 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.06217","versioned_id":"2502.06217v2","title":"Examining False Positives under Inference Scaling for Mathematical Reasoning","authors":["Yu Wang","Nan Yang","Liang Wang","Furu Wei","Fuli Feng"],"abstract":"Recent advancements in language models have led to significant improvements in mathematical reasoning across various benchmarks. However, most of these benchmarks rely on automatic evaluation methods that only compare final answers using heuristics, without verifying the underlying reasoning steps. This limitation results in false positive solutions, where models may produce correct final answers but with flawed deduction paths. In this paper, we systematically examine the prevalence of false positive solutions in mathematical problem solving for language models. We analyze the characteristics and extent of this issue across different open-source models, datasets of varying difficulty levels, and decoding strategies. Specifically, we explore how false positives influence the inference time scaling behavior of language models. Our experimental results reveal that: (1) false positive solutions persist across different models, datasets, and decoding methods, (2) sampling-based inference time scaling methods do not alleviate the problem, and (3) the pass@N evaluation metric is more susceptible to false positives, suggesting a significantly lower scaling ceiling than what automatic evaluations indicate. Additionally, we analyze specific instances of false positives and discuss potential limitations in self-improvement techniques and synthetic data generation under such conditions. Our data and code are publicly available at https://github.com/Wloner0809/False-Positives-in-Math.","published":"2025-02-10T07:49:35Z","updated":"2025-09-18T12:31:12Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.06217v2","pdf_url":"https://arxiv.org/pdf/2502.06217v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.06130","versioned_id":"2502.06130v2","title":"Self-Correcting Decoding with Generative Feedback for Mitigating Hallucinations in Large Vision-Language Models","authors":["Ce Zhang","Zifu Wan","Zhehan Kan","Martin Q. Ma","Simon Stepputtis","Deva Ramanan","Russ Salakhutdinov","Louis-Philippe Morency","Katia Sycara","Yaqi Xie"],"abstract":"While recent Large Vision-Language Models (LVLMs) have shown remarkable performance in multi-modal tasks, they are prone to generating hallucinatory text responses that do not align with the given visual input, which restricts their practical applicability in real-world scenarios. In this work, inspired by the observation that the text-to-image generation process is the inverse of image-conditioned response generation in LVLMs, we explore the potential of leveraging text-to-image generative models to assist in mitigating hallucinations in LVLMs. We discover that generative models can offer valuable self-feedback for mitigating hallucinations at both the response and token levels. Building on this insight, we introduce self-correcting Decoding with Generative Feedback (DeGF), a novel training-free algorithm that incorporates feedback from text-to-image generative models into the decoding process to effectively mitigate hallucinations in LVLMs. Specifically, DeGF generates an image from the initial response produced by LVLMs, which acts as an auxiliary visual reference and provides self-feedback to verify and correct the initial response through complementary or contrastive decoding. Extensive experimental results validate the effectiveness of our approach in mitigating diverse types of hallucinations, consistently surpassing state-of-the-art methods across six benchmarks. Code is available at https://github.com/zhangce01/DeGF.","published":"2025-02-10T03:43:55Z","updated":"2025-09-09T18:19:31Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2502.06130v2","pdf_url":"https://arxiv.org/pdf/2502.06130v2","comment":"Accepted by ICLR 2025. Project page: https://zhangce01.github.io/DeGF/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.05605","versioned_id":"2502.05605v6","title":"Evolving LLMs' Self-Refinement Capability via Synergistic Training-Inference Optimization","authors":["Yongcheng Zeng","Xinyu Cui","Xuanfa Jin","Qirui Mi","Guoqing Liu","Zexu Sun","Mengyue Yang","Dong Li","Weiyu Ma","Ning Yang","Jian Zhao","Jianye Hao","Haifeng Zhang","Jun Wang"],"abstract":"Self-Refinement refers to a model's ability to revise its own responses to produce improved outputs. This capability can also serve as a fundamental mechanism for Self-Improvement, for example, by reconstructing datasets with refined results to enhance intrinsic model performance. However, our comprehensive experiments reveal that large language models (LLMs) show no clear evidence of inherent Self-Refinement and may even experience response quality degradation after Self-Refinement. To address this issue, we propose EVOLVE, a simple and effective framework for eliciting and tracking the evolution of Self-Refinement through iterative training. We first explore optimization methods during training to activate the model's Self-Refinement capability. Then, at inference, we investigate various generation strategies to further enhance and utilize Self-Refinement while supplying the necessary data for training. Through synergistic optimization of training and inference stages, we continually evolve the model's Self-Refinement ability, enabling it to better refine its own responses. Moreover, we demonstrate the potential of leveraging Self-Refinement to achieve broader Self-Improvement of intrinsic model abilities. Experiments show that the evolved Self-Refinement ability enables the Llama-3.1-8B base model to surpass GPT-4o, achieving 62.3% length-controlled and 63.3% raw win rates on AlpacaEval 2, and 50.3% on Arena-Hard. It also generalizes effectively to out-of-domain reasoning tasks, improving performance on mathematical reasoning benchmarks such as GSM8K and MATH.","published":"2025-02-08T15:21:55Z","updated":"2025-10-26T16:21:53Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.05605v6","pdf_url":"https://arxiv.org/pdf/2502.05605v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.05449","versioned_id":"2502.05449v2","title":"Iterative Deepening Sampling as Efficient Test-Time Scaling","authors":["Weizhe Chen","Sven Koenig","Bistra Dilkina"],"abstract":"Recent reasoning models, such as OpenAI's O1 series, have demonstrated exceptional performance on complex reasoning tasks and revealed new test-time scaling laws. Inspired by this, many people have been studying how to train models to achieve effective self-evaluation and self-correction to further enable the scaling paradigm. However, less studied is how to efficiently scale test-time compute from a fixed model, and this remains a challenge. In this paper, we address this challenge by focusing on enhancing the quality of self-reflection data generation for complex problem-solving at test time, which can also subsequently improve the training of next-generation large language models (LLMs). Specifically, we explore how systematically triggering a model's self-correction mechanisms can improve performance on challenging reasoning tasks. To this end, we propose a novel iterative deepening sampling algorithm framework designed to enhance self-correction and generate higher-quality samples. Through extensive experiments on Math500 and AIME benchmarks, we demonstrate that our method achieves a higher success rate on difficult tasks and provide detailed ablation studies to analyze its effectiveness across diverse settings.","published":"2025-02-08T04:39:51Z","updated":"2025-06-01T20:14:16Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.05449v2","pdf_url":"https://arxiv.org/pdf/2502.05449v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.05400","versioned_id":"2502.05400v4","title":"Dynamic Noise Preference Optimization: Self-Improvement of Large Language Models with Self-Synthetic Data","authors":["Haoyan Yang","Khiem Le","Ting Hua","Shangqian Gao","Binfeng Xu","Zheng Tang","Jie Xu","Nitesh V. Chawla","Hongxia Jin","Vijay Srinivasan"],"abstract":"Although LLMs have achieved significant success, their reliance on large volumes of human-annotated data has limited their potential for further scaling. In this situation, utilizing self-generated synthetic data has become crucial for fine-tuning LLMs without extensive human annotation. However, current methods often fail to ensure consistent improvements across iterations, with performance stagnating after only minimal updates. To overcome these challenges, we introduce Dynamic Noise Preference Optimization (DNPO), which combines dynamic sample labeling for constructing preference pairs with controlled, trainable noise injection during preference optimization. Our approach effectively prevents stagnation and enables continuous improvement. In experiments with Llama-3.2-3B and Zephyr-7B, DNPO consistently outperforms existing methods across multiple benchmarks. Additionally, with Zephyr-7B, DNPO shows a significant improvement in model-generated data quality, with a 29.4% win-loss rate gap compared to the baseline in GPT-4 evaluations.","published":"2025-02-08T01:20:09Z","updated":"2026-03-15T18:47:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.05400v4","pdf_url":"https://arxiv.org/pdf/2502.05400v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.05368","versioned_id":"2502.05368v2","title":"Otter: Generating Tests from Issues to Validate SWE Patches","authors":["Toufique Ahmed","Jatin Ganhotra","Rangeet Pan","Avraham Shinnar","Saurabh Sinha","Martin Hirzel"],"abstract":"While there has been plenty of work on generating tests from existing code, there has been limited work on generating tests from issues. A correct test must validate the code patch that resolves the issue. This paper focuses on the scenario where that code patch does not yet exist. Doing so supports two major use-cases. First, it supports TDD (test-driven development), the discipline of \"test first, write code later\" that has well-documented benefits for human software engineers. Second, it also validates SWE (software engineering) agents, which generate code patches for resolving issues. This paper introduces TDD-Bench-Verified, a benchmark for generating tests from issues, and Otter, an LLM-based solution for this task. Otter augments LLMs with rule-based analysis to check and repair their outputs, and introduces a novel self-reflective action planner. Experiments show Otter outperforming state-of-the-art systems for generating tests from issues, in addition to enhancing systems that generate patches from issues. We hope that Otter helps make developers more productive at resolving issues and leads to more robust, well-tested code.","published":"2025-02-07T22:41:31Z","updated":"2025-05-30T17:25:04Z","categories":["cs.SE","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2502.05368v2","pdf_url":"https://arxiv.org/pdf/2502.05368v2","comment":"Accepted to the main technical track of the International Conference on Machine Learning (ICML), 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.05007","versioned_id":"2502.05007v1","title":"Analyzing Advanced AI Systems Against Definitions of Life and Consciousness","authors":["Azadeh Alavi","Hossein Akhoundi","Fatemeh Kouchmeshki"],"abstract":"Could artificial intelligence ever become truly conscious in a functional sense; this paper explores that open-ended question through the lens of Life, a concept unifying classical biological criteria (Oxford, NASA, Koshland) with empirical hallmarks such as adaptive self maintenance, emergent complexity, and rudimentary self referential modeling. We propose a number of metrics for examining whether an advanced AI system has gained consciousness, while emphasizing that we do not claim all AI stems can become conscious. Rather, we suggest that sufficiently advanced architectures exhibiting immune like sabotage defenses, mirror self-recognition analogs, or meta-cognitive updates may cross key thresholds akin to life-like or consciousness-like traits. To demonstrate these ideas, we start by assessing adaptive self-maintenance capability, and introduce controlled data corruption sabotage into the training process. The result demonstrates AI capability to detect these inconsistencies and revert or self-correct analogous to regenerative biological processes. We also adapt an animal-inspired mirror self recognition test to neural embeddings, finding that partially trained CNNs can distinguish self from foreign features with complete accuracy. We then extend our analysis by performing a question-based mirror test on five state-of-the-art chatbots (ChatGPT4, Gemini, Perplexity, Claude, and Copilot) and demonstrated their ability to recognize their own answers compared to those of the other chatbots.","published":"2025-02-07T15:27:34Z","updated":"2025-02-07T15:27:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.05007v1","pdf_url":"https://arxiv.org/pdf/2502.05007v1","comment":"78 pages, 15 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.04790","versioned_id":"2502.04790v2","title":"S$^2$-MAD: Breaking the Token Barrier to Enhance Multi-Agent Debate Efficiency","authors":["Yuting Zeng","Weizhe Huang","Lei Jiang","Tongxuan Liu","Xitai Jin","Chen Tianying Tiana","Jing Li","Xiaohua Xu"],"abstract":"Large language models (LLMs) have demonstrated remarkable capabilities across various natural language processing (NLP) scenarios, but they still face challenges when handling complex arithmetic and logical reasoning tasks. While Chain-Of-Thought (CoT) reasoning, self-consistency (SC) and self-correction strategies have attempted to guide models in sequential, multi-step reasoning, Multi-agent Debate (MAD) has emerged as a viable approach for enhancing the reasoning capabilities of LLMs. By increasing both the number of agents and the frequency of debates, the performance of LLMs improves significantly. However, this strategy results in a significant increase in token costs, presenting a barrier to scalability. To address this challenge, we introduce a novel sparsification strategy designed to reduce token costs within MAD. This approach minimizes ineffective exchanges of information and unproductive discussions among agents, thereby enhancing the overall efficiency of the debate process. We conduct comparative experiments on multiple datasets across various models, demonstrating that our approach significantly reduces the token costs in MAD to a considerable extent. Specifically, compared to MAD, our approach achieves an impressive reduction of up to 94.5\\% in token costs while maintaining performance degradation below 2.0\\%.","published":"2025-02-07T09:49:56Z","updated":"2025-04-10T02:29:35Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.04790v2","pdf_url":"https://arxiv.org/pdf/2502.04790v2","comment":"Accepted to NAACL 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.04780","versioned_id":"2502.04780v1","title":"SiriuS: Self-improving Multi-agent Systems via Bootstrapped Reasoning","authors":["Wanjia Zhao","Mert Yuksekgonul","Shirley Wu","James Zou"],"abstract":"Multi-agent AI systems powered by large language models (LLMs) are increasingly applied to solve complex tasks. However, these systems often rely on fragile, manually designed prompts and heuristics, making optimization difficult. A key challenge in optimizing multi-agent systems is acquiring suitable training data for specialized agents. We introduce SiriuS, a self-improving, reasoning-driven optimization framework for multi-agent systems. Central to our approach is the construction of an experience library: a repository of high-quality reasoning trajectories. The library is built by retaining reasoning steps that lead to successful outcomes, providing a robust training set for optimizing multi-agent system. Additionally, we introduce a library augmentation procedure that refines unsuccessful trajectories, further enriching the library. SiriuS boosts performance by 2.86\\% to 21.88\\% on reasoning and biomedical QA and enhances agent negotiation in competitive settings. Our results show that SiriuS enhances multi-agent performance while generating reusable data for self-correction and self-play enhancement in the future.","published":"2025-02-07T09:33:44Z","updated":"2025-02-07T09:33:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.04780v1","pdf_url":"https://arxiv.org/pdf/2502.04780v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.04404","versioned_id":"2502.04404v1","title":"Step Back to Leap Forward: Self-Backtracking for Boosting Reasoning of Language Models","authors":["Xiao-Wen Yang","Xuan-Yi Zhu","Wen-Da Wei","Ding-Chu Zhang","Jie-Jing Shao","Zhi Zhou","Lan-Zhe Guo","Yu-Feng Li"],"abstract":"The integration of slow-thinking mechanisms into large language models (LLMs) offers a promising way toward achieving Level 2 AGI Reasoners, as exemplified by systems like OpenAI's o1. However, several significant challenges remain, including inefficient overthinking and an overreliance on auxiliary reward models. We point out that these limitations stem from LLMs' inability to internalize the search process, a key component of effective reasoning. A critical step toward addressing this issue is enabling LLMs to autonomously determine when and where to backtrack, a fundamental operation in traditional search algorithms. To this end, we propose a self-backtracking mechanism that equips LLMs with the ability to backtrack during both training and inference. This mechanism not only enhances reasoning ability but also efficiency by transforming slow-thinking processes into fast-thinking through self-improvement. Empirical evaluations demonstrate that our proposal significantly enhances the reasoning capabilities of LLMs, achieving a performance gain of over 40 percent compared to the optimal-path supervised fine-tuning method. We believe this study introduces a novel and promising pathway for developing more advanced and robust Reasoners.","published":"2025-02-06T08:52:43Z","updated":"2025-02-06T08:52:43Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.04404v1","pdf_url":"https://arxiv.org/pdf/2502.04404v1","comment":"This is a preprint under review, 15 pages, 13 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.03752","versioned_id":"2502.03752v5","title":"Self-Improving Skill Learning for Robust Skill-based Meta-Reinforcement Learning","authors":["Sanghyeon Lee","Sangjun Bae","Yisak Park","Seungyul Han"],"abstract":"Meta-reinforcement learning (Meta-RL) facilitates rapid adaptation to unseen tasks but faces challenges in long-horizon environments. Skill-based approaches tackle this by decomposing state-action sequences into reusable skills and employing hierarchical decision-making. However, these methods are highly susceptible to noisy offline demonstrations, leading to unstable skill learning and degraded performance. To address this, we propose Self-Improving Skill Learning (SISL), which performs self-guided skill refinement using decoupled high-level and skill improvement policies, while applying skill prioritization via maximum return relabeling to focus updates on task-relevant trajectories, resulting in robust and stable adaptation even under noisy and suboptimal data. By mitigating the effect of noise, SISL achieves reliable skill learning and consistently outperforms other skill-based meta-RL methods on diverse long-horizon tasks. Our code is available at https://epsilog.github.io/SISL.","published":"2025-02-06T03:28:45Z","updated":"2026-05-20T06:52:21Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.03752v5","pdf_url":"https://arxiv.org/pdf/2502.03752v5","comment":"10 pages main, 27 pages appendix with reference. Accepted to ICLR 2026","journal_ref":"International Conference on Learning Representations (ICLR), 2026","doi":"","discovered_on":"2026-07-17"},{"id":"2502.02740","versioned_id":"2502.02740v1","title":"Vision-Language Model Dialog Games for Self-Improvement","authors":["Ksenia Konyushkova","Christos Kaplanis","Serkan Cabi","Misha Denil"],"abstract":"The increasing demand for high-quality, diverse training data poses a significant bottleneck in advancing vision-language models (VLMs). This paper presents VLM Dialog Games, a novel and scalable self-improvement framework for VLMs. Our approach leverages self-play between two agents engaged in a goal-oriented play centered around image identification. By filtering for successful game interactions, we automatically curate a high-quality dataset of interleaved images and text. We demonstrate that fine-tuning on this synthetic data leads to performance gains on downstream tasks and generalises across datasets. Moreover, as the improvements in the model lead to better game play, this procedure can be applied iteratively. This work paves the way for self-improving VLMs, with potential applications in various real-world scenarios especially when the high-quality multimodal data is scarce.","published":"2025-02-04T21:58:07Z","updated":"2025-02-04T21:58:07Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.02740v1","pdf_url":"https://arxiv.org/pdf/2502.02740v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.02534","versioned_id":"2502.02534v2","title":"Adaptive Self-improvement LLM Agentic System for ML Library Development","authors":["Genghan Zhang","Weixin Liang","Olivia Hsu","Kunle Olukotun"],"abstract":"ML libraries, often written in architecture-specific programming languages (ASPLs) that target domain-specific architectures, are key to efficient ML systems. However, writing these high-performance ML libraries is challenging because it requires expert knowledge of ML algorithms and the ASPL. Large language models (LLMs), on the other hand, have shown general coding capabilities. However, challenges remain when using LLMs for generating ML libraries using ASPLs because 1) this task is complicated even for experienced human programmers and 2) there are limited code examples because of the esoteric and evolving nature of ASPLs. Therefore, LLMs need complex reasoning with limited data in order to complete this task. To address these challenges, we introduce an adaptive self-improvement agentic system. In order to evaluate the effectiveness of our system, we construct a benchmark of a typical ML library and generate ASPL code with both open and closed-source LLMs on this benchmark. Our results show improvements of up to $3.9\\times$ over a baseline single LLM.","published":"2025-02-04T17:57:17Z","updated":"2025-09-19T04:28:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.02534v2","pdf_url":"https://arxiv.org/pdf/2502.02534v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.02508","versioned_id":"2502.02508v3","title":"Satori: Reinforcement Learning with Chain-of-Action-Thought Enhances LLM Reasoning via Autoregressive Search","authors":["Maohao Shen","Guangtao Zeng","Zhenting Qi","Zhang-Wei Hong","Zhenfang Chen","Wei Lu","Gregory Wornell","Subhro Das","David Cox","Chuang Gan"],"abstract":"Large language models (LLMs) have demonstrated remarkable reasoning capabilities across diverse domains. Recent studies have shown that increasing test-time computation enhances LLMs' reasoning capabilities. This typically involves extensive sampling at inference time guided by an external LLM verifier, resulting in a two-player system. Despite external guidance, the effectiveness of this system demonstrates the potential of a single LLM to tackle complex tasks. Thus, we pose a new research problem: Can we internalize the searching capabilities to fundamentally enhance the reasoning abilities of a single LLM? This work explores an orthogonal direction focusing on post-training LLMs for autoregressive searching (i.e., an extended reasoning process with self-reflection and self-exploration of new strategies). To achieve this, we propose the Chain-of-Action-Thought (COAT) reasoning and a two-stage training paradigm: 1) a small-scale format tuning stage to internalize the COAT reasoning format and 2) a large-scale self-improvement stage leveraging reinforcement learning. Our approach results in Satori, a 7B LLM trained on open-source models and data. Extensive empirical evaluations demonstrate that Satori achieves state-of-the-art performance on mathematical reasoning benchmarks while exhibits strong generalization to out-of-domain tasks. Code, data, and models are fully open-sourced.","published":"2025-02-04T17:26:58Z","updated":"2025-06-16T03:29:47Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.02508v3","pdf_url":"https://arxiv.org/pdf/2502.02508v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.04352","versioned_id":"2502.04352v2","title":"Investigating the Robustness of Deductive Reasoning with Large Language Models","authors":["Fabian Hoppe","Filip Ilievski","Jan-Christoph Kalo"],"abstract":"Large Language Models (LLMs) have been shown to achieve impressive results for many reasoning-based NLP tasks, suggesting a degree of deductive reasoning capability. However, it remains unclear to which extent LLMs, in both informal and autoformalisation methods, are robust on logical deduction tasks. Moreover, while many LLM-based deduction methods have been proposed, a systematic study that analyses the impact of their design components is lacking. Addressing these two challenges, we propose the first study of the robustness of formal and informal LLM-based deductive reasoning methods. We devise a framework with two families of perturbations: adversarial noise and counterfactual statements, which jointly generate seven perturbed datasets. We organize the landscape of LLM reasoners according to their reasoning format, formalisation syntax, and feedback for error recovery. The results show that adversarial noise affects autoformalisation, while counterfactual statements influence all approaches. Detailed feedback does not improve overall accuracy despite reducing syntax errors, pointing to the challenge of LLM-based methods to self-correct effectively.","published":"2025-02-04T17:16:51Z","updated":"2025-08-25T08:34:46Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.04352v2","pdf_url":"https://arxiv.org/pdf/2502.04352v2","comment":"to be published in ECAI 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.02384","versioned_id":"2502.02384v2","title":"STAIR: Improving Safety Alignment with Introspective Reasoning","authors":["Yichi Zhang","Siyuan Zhang","Yao Huang","Zeyu Xia","Zhengwei Fang","Xiao Yang","Ranjie Duan","Dong Yan","Yinpeng Dong","Jun Zhu"],"abstract":"Ensuring the safety and harmlessness of Large Language Models (LLMs) has become equally critical as their performance in applications. However, existing safety alignment methods typically suffer from safety-performance trade-offs and the susceptibility to jailbreak attacks, primarily due to their reliance on direct refusals for malicious queries. In this paper, we propose STAIR, a novel framework that integrates SafeTy Alignment with Itrospective Reasoning. We enable LLMs to identify safety risks through step-by-step analysis by self-improving chain-of-thought (CoT) reasoning with safety awareness. STAIR first equips the model with a structured reasoning capability and then advances safety alignment via iterative preference optimization on step-level reasoning data generated using our newly proposed Safety-Informed Monte Carlo Tree Search (SI-MCTS). We further train a process reward model on this data to guide test-time searches for improved responses. Extensive experiments show that STAIR effectively mitigates harmful outputs while better preserving helpfulness, compared to instinctive alignment strategies. With test-time scaling, STAIR achieves a safety performance comparable to Claude-3.5 against popular jailbreak attacks. Relevant resources in this work are available at https://github.com/thu-ml/STAIR.","published":"2025-02-04T15:02:55Z","updated":"2025-06-27T07:30:35Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.02384v2","pdf_url":"https://arxiv.org/pdf/2502.02384v2","comment":"22 pages, 8 figures, ICML2025 Oral","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.01612","versioned_id":"2502.01612v2","title":"Self-Improving Transformers Overcome Easy-to-Hard and Length Generalization Challenges","authors":["Nayoung Lee","Ziyang Cai","Avi Schwarzschild","Kangwook Lee","Dimitris Papailiopoulos"],"abstract":"Large language models often struggle with length generalization and solving complex problem instances beyond their training distribution. We present a self-improvement approach where models iteratively generate and learn from their own solutions, progressively tackling harder problems while maintaining a standard transformer architecture. Across diverse tasks including arithmetic, string manipulation, and maze solving, self-improving enables models to solve problems far beyond their initial training distribution-for instance, generalizing from 10-digit to 100-digit addition without apparent saturation. We observe that in some cases filtering for correct self-generated examples leads to exponential improvements in out-of-distribution performance across training rounds. Additionally, starting from pretrained models significantly accelerates this self-improvement process for several tasks. Our results demonstrate how controlled weak-to-strong curricula can systematically teach a model logical extrapolation without any changes to the positional embeddings, or the model architecture.","published":"2025-02-03T18:45:22Z","updated":"2025-02-13T05:32:54Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.01612v2","pdf_url":"https://arxiv.org/pdf/2502.01612v2","comment":"Added references","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.00988","versioned_id":"2502.00988v1","title":"PlotGen: Multi-Agent LLM-based Scientific Data Visualization via Multimodal Feedback","authors":["Kanika Goswami","Puneet Mathur","Ryan Rossi","Franck Dernoncourt"],"abstract":"Scientific data visualization is pivotal for transforming raw data into comprehensible visual representations, enabling pattern recognition, forecasting, and the presentation of data-driven insights. However, novice users often face difficulties due to the complexity of selecting appropriate tools and mastering visualization techniques. Large Language Models (LLMs) have recently demonstrated potential in assisting code generation, though they struggle with accuracy and require iterative debugging. In this paper, we propose PlotGen, a novel multi-agent framework aimed at automating the creation of precise scientific visualizations. PlotGen orchestrates multiple LLM-based agents, including a Query Planning Agent that breaks down complex user requests into executable steps, a Code Generation Agent that converts pseudocode into executable Python code, and three retrieval feedback agents - a Numeric Feedback Agent, a Lexical Feedback Agent, and a Visual Feedback Agent - that leverage multimodal LLMs to iteratively refine the data accuracy, textual labels, and visual correctness of generated plots via self-reflection. Extensive experiments show that PlotGen outperforms strong baselines, achieving a 4-6 percent improvement on the MatPlotBench dataset, leading to enhanced user trust in LLM-generated visualizations and improved novice productivity due to a reduction in debugging time needed for plot errors.","published":"2025-02-03T02:00:29Z","updated":"2025-02-03T02:00:29Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.00988v1","pdf_url":"https://arxiv.org/pdf/2502.00988v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.00757","versioned_id":"2502.00757v4","title":"AgentBreeder: Mitigating the AI Safety Risks of Multi-Agent Scaffolds via Self-Improvement","authors":["J Rosser","Jakob Foerster"],"abstract":"Scaffolding Large Language Models (LLMs) into multi-agent systems often improves performance on complex tasks, but the safety impact of such scaffolds has not been thoroughly explored. We introduce AgentBreeder, a framework for multi-objective self-improving evolutionary search over scaffolds. We evaluate discovered scaffolds on widely recognized reasoning, mathematics, and safety benchmarks and compare them with popular baselines. In \"blue\" mode, we see a 79.4% average uplift in safety benchmark performance while maintaining or improving capability scores. In \"red\" mode, we find adversarially weak scaffolds emerging concurrently with capability optimization. Our work demonstrates the risks of multi-agent scaffolding and provides a framework for mitigating them. Code is available at https://github.com/jrosseruk/AgentBreeder.","published":"2025-02-02T11:40:07Z","updated":"2025-10-14T09:49:14Z","categories":["cs.CR","cs.AI","cs.NE"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2502.00757v4","pdf_url":"https://arxiv.org/pdf/2502.00757v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.00711","versioned_id":"2502.00711v2","title":"VIKSER: Visual Knowledge-Driven Self-Reinforcing Reasoning Framework","authors":["Chao Wang","Chunbai Zhang","Yongxiao Tian","Yang Zhou","Yan Peng"],"abstract":"Visual reasoning refers to the task of solving questions about visual information. Current visual reasoning methods typically employ pre-trained vision-language model (VLM) strategies or deep neural network approaches. However, existing efforts are constrained by limited reasoning interpretability, while hindering by the phenomenon of underspecification in the question text. Additionally, the absence of fine-grained visual knowledge limits the precise understanding of subject behavior in visual reasoning tasks. To address these issues, we propose VIKSER (Visual Knowledge-Driven Self-Reinforcing Reasoning Framework). Specifically, VIKSER, trained using knowledge distilled from large language models, extracts fine-grained visual knowledge with the assistance of visual relationship detection techniques. Subsequently, VIKSER utilizes fine-grained visual knowledge to paraphrase the question with underspecification. Additionally, we design a novel prompting method called Chain-of-Evidence (CoE), which leverages the power of \"evidence for reasoning\" to endow VIKSER with interpretable reasoning capabilities. Meanwhile, the integration of self-reflection technology empowers VIKSER with the ability to learn and improve from its mistakes. Experiments conducted on widely used datasets demonstrate that VIKSER achieves new state-of-the-art (SOTA) results in relevant tasks. Moreover, VIKSER achieves performance on par with leading proprietary models, such as the latest ChatGPT-5.","published":"2025-02-02T07:54:55Z","updated":"2025-09-02T05:28:29Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2502.00711v2","pdf_url":"https://arxiv.org/pdf/2502.00711v2","comment":"14 pages,17 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.00675","versioned_id":"2502.00675v5","title":"ReFoRCE: A Text-to-SQL Agent with Self-Refinement, Consensus Enforcement, and Column Exploration","authors":["Minghang Deng","Ashwin Ramachandran","Canwen Xu","Lanxiang Hu","Zhewei Yao","Anupam Datta","Hao Zhang"],"abstract":"We present ReFoRCE, a Text-to-SQL agent that tops the Spider 2.0 leaderboard--a challenging benchmark reflecting complex, real-world Text-to-SQL scenarios. While Text-to-SQL systems enable natural language queries over structured databases, deploying them in enterprise environments remains difficult due to large, complex schemas (with over 1,000 columns), diverse SQL dialects (e.g., BigQuery, Snowflake), and sophisticated query requirements (e.g., transformations and analytics). ReFoRCE addresses these challenges through: (a) database information compression via pattern-based table grouping and LLM-guided schema linking to alleviate long-context issues; (b) self-refinement to iteratively correct syntax and semantic errors across dialects; (c) majority-vote consensus to select high-confidence candidates while deferring ambiguous cases arising from sophisticated queries; and (d) iterative column exploration guided by execution feedback to resolve those deferred cases. ReFoRCE achieves new state-of-the-art results, with scores of 35.83 on Spider 2.0-Snow and 36.56 on Spider 2.0-Lite.","published":"2025-02-02T05:25:03Z","updated":"2025-06-03T18:03:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.00675v5","pdf_url":"https://arxiv.org/pdf/2502.00675v5","comment":"33 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2502.00330","versioned_id":"2502.00330v1","title":"From Few to Many: Self-Improving Many-Shot Reasoners Through Iterative Optimization and Generation","authors":["Xingchen Wan","Han Zhou","Ruoxi Sun","Hootan Nakhost","Ke Jiang","Sercan Ö. Arık"],"abstract":"Recent advances in long-context large language models (LLMs) have led to the emerging paradigm of many-shot in-context learning (ICL), where it is observed that scaling many more demonstrating examples beyond the conventional few-shot setup in the context can lead to performance benefits. However, despite its promise, it is unclear what aspects dominate the benefits and whether simply scaling to more examples is the most effective way of improving many-shot ICL. In this work, we first provide an analysis of the factors driving many-shot ICL, and we find that 1) many-shot performance can still be attributed to often a few disproportionately influential examples and 2) identifying such influential examples (\"optimize\") and using them as demonstrations to regenerate new examples (\"generate\") can lead to further improvements. Inspired by the findings, we propose BRIDGE, an algorithm that alternates between the optimize step with Bayesian optimization to discover the influential sets of examples and the generate step to reuse this set to expand the reasoning paths of the examples back to the many-shot regime automatically. On Gemini, Claude, and Mistral LLMs of different sizes, we show that BRIDGE to significant improvements across a diverse set of tasks, including symbolic reasoning, numerical reasoning, and code generation.","published":"2025-02-01T06:23:24Z","updated":"2025-02-01T06:23:24Z","categories":["cs.LG","cs.AI","stat.ML"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.00330v1","pdf_url":"https://arxiv.org/pdf/2502.00330v1","comment":"Expanded version of the ICLR 2025 paper","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.19306","versioned_id":"2501.19306v5","title":"SETS: Leveraging Self-Verification and Self-Correction for Improved Test-Time Scaling","authors":["Jiefeng Chen","Jie Ren","Xinyun Chen","Chengrun Yang","Ruoxi Sun","Jinsung Yoon","Sercan Ö Arık"],"abstract":"Recent advancements in Large Language Models (LLMs) have created new opportunities to enhance performance on complex reasoning tasks by leveraging test-time computation. However, existing scaling methods have key limitations: parallel methods like repeated sampling are often inefficient and quickly saturate, while sequential methods like SELF-REFINE struggle to improve after a few rounds. Although combining these approaches shows promise, current methods require fine-tuned reward and revision models. This paper proposes Self-Enhanced Test-Time Scaling (SETS), a simple yet effective approach that overcomes these limitations by strategically combining parallel and sequential techniques and fully leveraging LLMs' self-improvement abilities. SETS exploits the inherent self-verification and self-correction capabilities of LLMs, unifying sampling, verification, and correction within a single framework. This facilitates efficient and scalable test-time computation for enhanced performance on complex tasks without any model training. Our comprehensive experimental results on challenging benchmarks spanning planning, reasoning, math, and coding demonstrate that SETS achieves significant performance improvements and more advantageous test-time scaling behavior than the alternatives.","published":"2025-01-31T17:03:16Z","updated":"2025-12-03T04:21:00Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.19306v5","pdf_url":"https://arxiv.org/pdf/2501.19306v5","comment":"Published in Transactions on Machine Learning Research (11/2025)","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.17974","versioned_id":"2501.17974v2","title":"Think Smarter not Harder: Adaptive Reasoning with Inference Aware Optimization","authors":["Zishun Yu","Tengyu Xu","Di Jin","Karthik Abinav Sankararaman","Yun He","Wenxuan Zhou","Zhouhao Zeng","Eryk Helenowski","Chen Zhu","Sinong Wang","Hao Ma","Han Fang"],"abstract":"Solving mathematics problems has been an intriguing capability of large language models, and many efforts have been made to improve reasoning by extending reasoning length, such as through self-correction and extensive long chain-of-thoughts. While promising in problem-solving, advanced long reasoning chain models exhibit an undesired single-modal behavior, where trivial questions require unnecessarily tedious long chains of thought. In this work, we propose a way to allow models to be aware of inference budgets by formulating it as utility maximization with respect to an inference budget constraint, hence naming our algorithm Inference Budget-Constrained Policy Optimization (IBPO). In a nutshell, models fine-tuned through IBPO learn to ``understand'' the difficulty of queries and allocate inference budgets to harder ones. With different inference budgets, our best models are able to have a $4.14$\\% and $5.74$\\% absolute improvement ($8.08$\\% and $11.2$\\% relative improvement) on MATH500 using $2.16$x and $4.32$x inference budgets respectively, relative to LLaMA3.1 8B Instruct. These improvements are approximately $2$x those of self-consistency under the same budgets.","published":"2025-01-29T20:20:48Z","updated":"2025-01-31T16:06:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.17974v2","pdf_url":"https://arxiv.org/pdf/2501.17974v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.17584","versioned_id":"2501.17584v1","title":"GLLM: Self-Corrective G-Code Generation using Large Language Models with User Feedback","authors":["Mohamed Abdelaal","Samuel Lokadjaja","Gilbert Engert"],"abstract":"This paper introduces GLLM, an innovative tool that leverages Large Language Models (LLMs) to automatically generate G-code from natural language instructions for Computer Numerical Control (CNC) machining. GLLM addresses the challenges of manual G-code writing by bridging the gap between human-readable task descriptions and machine-executable code. The system incorporates a fine-tuned StarCoder-3B model, enhanced with domain-specific training data and a Retrieval-Augmented Generation (RAG) mechanism. GLLM employs advanced prompting strategies and a novel self-corrective code generation approach to ensure both syntactic and semantic correctness of the generated G-code. The architecture includes robust validation mechanisms, including syntax checks, G-code-specific verifications, and functional correctness evaluations using Hausdorff distance. By combining these techniques, GLLM aims to democratize CNC programming, making it more accessible to users without extensive programming experience while maintaining high accuracy and reliability in G-code generation.","published":"2025-01-29T11:40:46Z","updated":"2025-01-29T11:40:46Z","categories":["cs.SE","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2501.17584v1","pdf_url":"https://arxiv.org/pdf/2501.17584v1","comment":"","journal_ref":"Industrial Track of 21st Conference on Database Systems for Business, Technology and Web (BTW), 2025","doi":"","discovered_on":"2026-07-17"},{"id":"2501.16783","versioned_id":"2501.16783v1","title":"A Stochastic Dynamical Theory of LLM Self-Adversariality: Modeling Severity Drift as a Critical Process","authors":["Jack David Carson"],"abstract":"This paper introduces a continuous-time stochastic dynamical framework for understanding how large language models (LLMs) may self-amplify latent biases or toxicity through their own chain-of-thought reasoning. The model posits an instantaneous \"severity\" variable $x(t) \\in [0,1]$ evolving under a stochastic differential equation (SDE) with a drift term $μ(x)$ and diffusion $σ(x)$. Crucially, such a process can be consistently analyzed via the Fokker--Planck approach if each incremental step behaves nearly Markovian in severity space. The analysis investigates critical phenomena, showing that certain parameter regimes create phase transitions from subcritical (self-correcting) to supercritical (runaway severity). The paper derives stationary distributions, first-passage times to harmful thresholds, and scaling laws near critical points. Finally, it highlights implications for agents and extended LLM reasoning models: in principle, these equations might serve as a basis for formal verification of whether a model remains stable or propagates bias over repeated inferences.","published":"2025-01-28T08:08:25Z","updated":"2025-01-28T08:08:25Z","categories":["cs.CL","cs.AI","nlin.AO"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.16783v1","pdf_url":"https://arxiv.org/pdf/2501.16783v1","comment":"Experimental verification and more formal argument for Markov approximation of bias propagation to be released soon. Primarily pushed now to establish novelty and ease of sharing. Please do not cite this work until the forthcoming experimental validation and updated mathematical model are provided","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.14917","versioned_id":"2501.14917v6","title":"Self-reflecting Large Language Models: A Hegelian Dialectical Approach","authors":["Sara Abdali","Can Goksen","Michael Solodko","Saeed Amizadeh","Julie E. Maybee","Kazuhito Koishida"],"abstract":"Investigating NLP through a philosophical lens has recently caught researchers' eyes, as it bridges computational methods with classical schools of philosophy. This paper introduces a philosophical framework inspired by the Hegelian Dialectic to enable LLMs' self-reflection, utilizing a self-dialectical approach to emulate internal critiques and synthesize new scientific ideas (spanning domains such as mathematics, physics, and more). Additionally, we explore the effect of generation temperature in LLMs by introducing a dynamic annealing approach, which encourages creativity in the early stages and gradually focuses on refinement and nuance, as well as a constant-temperature strategy. Furthermore, we implement a Multi-Agent Majority Voting (MAMV) strategy to assess the validity and novelty of the generated ideas, which proves useful in the absence of domain experts. We also evaluate the effectiveness of our method in generating novel scientific ideas and improving LLMs' reasoning capabilities. Our experiments demonstrate promising results in ideation, along with significant improvements in mathematical and symbolic reasoning.","published":"2025-01-24T20:54:29Z","updated":"2025-06-23T18:59:06Z","categories":["cs.CL","cs.HC","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.14917v6","pdf_url":"https://arxiv.org/pdf/2501.14917v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.14492","versioned_id":"2501.14492v1","title":"RealCritic: Towards Effectiveness-Driven Evaluation of Language Model Critiques","authors":["Zhengyang Tang","Ziniu Li","Zhenyang Xiao","Tian Ding","Ruoyu Sun","Benyou Wang","Dayiheng Liu","Fei Huang","Tianyu Liu","Bowen Yu","Junyang Lin"],"abstract":"Critiques are important for enhancing the performance of Large Language Models (LLMs), enabling both self-improvement and constructive feedback for others by identifying flaws and suggesting improvements. However, evaluating the critique capabilities of LLMs presents a significant challenge due to the open-ended nature of the task. In this work, we introduce a new benchmark designed to assess the critique capabilities of LLMs. Unlike existing benchmarks, which typically function in an open-loop fashion, our approach employs a closed-loop methodology that evaluates the quality of corrections generated from critiques. Moreover, the benchmark incorporates features such as self-critique, cross-critique, and iterative critique, which are crucial for distinguishing the abilities of advanced reasoning models from more classical ones. We implement this benchmark using eight challenging reasoning tasks. We have several interesting findings. First, despite demonstrating comparable performance in direct chain-of-thought generation, classical LLMs significantly lag behind the advanced reasoning-based model o1-mini across all critique scenarios. Second, in self-critique and iterative critique settings, classical LLMs may even underperform relative to their baseline capabilities. We hope that this benchmark will serve as a valuable resource to guide future advancements. The code and data are available at \\url{https://github.com/tangzhy/RealCritic}.","published":"2025-01-24T13:48:10Z","updated":"2025-01-24T13:48:10Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.14492v1","pdf_url":"https://arxiv.org/pdf/2501.14492v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.14431","versioned_id":"2501.14431v2","title":"Domaino1s: Guiding LLM Reasoning for Explainable Answers in High-Stakes Domains","authors":["Xu Chu","Zhijie Tan","Hanlin Xue","Guanyu Wang","Tong Mo","Weiping Li"],"abstract":"Large Language Models (LLMs) are widely applied to downstream domains. However, current LLMs for high-stakes domain tasks, such as financial investment and legal QA, typically generate brief answers without reasoning processes and explanations. This limits users' confidence in making decisions based on their responses. While original CoT shows promise, it lacks self-correction mechanisms during reasoning. This work introduces Domain$o1$s, which enhances LLMs' reasoning capabilities on domain tasks through supervised fine-tuning and tree search. We construct CoT-stock-2k and CoT-legal-2k datasets for fine-tuning models that activate domain-specific reasoning steps based on their judgment. Additionally, we propose Selective Tree Exploration to spontaneously explore solution spaces and sample optimal reasoning paths to improve performance. We also introduce PROOF-Score, a new metric for evaluating domain models' explainability, complementing traditional accuracy metrics with richer assessment dimensions. Extensive experiments on stock investment recommendation and legal reasoning QA tasks demonstrate Domaino1s's leading performance and explainability. Our code is available at https://github.com/Hyalinesky/Domaino1s.","published":"2025-01-24T11:57:39Z","updated":"2025-05-28T06:18:34Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.14431v2","pdf_url":"https://arxiv.org/pdf/2501.14431v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.14224","versioned_id":"2501.14224v1","title":"Top Ten Challenges Towards Agentic Neural Graph Databases","authors":["Jiaxin Bai","Zihao Wang","Yukun Zhou","Hang Yin","Weizhi Fei","Qi Hu","Zheye Deng","Jiayang Cheng","Tianshi Zheng","Hong Ting Tsang","Yisen Gao","Zhongwei Xie","Yufei Li","Lixin Fan","Binhang Yuan","Wei Wang","Lei Chen","Xiaofang Zhou","Yangqiu Song"],"abstract":"Graph databases (GDBs) like Neo4j and TigerGraph excel at handling interconnected data but lack advanced inference capabilities. Neural Graph Databases (NGDBs) address this by integrating Graph Neural Networks (GNNs) for predictive analysis and reasoning over incomplete or noisy data. However, NGDBs rely on predefined queries and lack autonomy and adaptability. This paper introduces Agentic Neural Graph Databases (Agentic NGDBs), which extend NGDBs with three core functionalities: autonomous query construction, neural query execution, and continuous learning. We identify ten key challenges in realizing Agentic NGDBs: semantic unit representation, abductive reasoning, scalable query execution, and integration with foundation models like large language models (LLMs). By addressing these challenges, Agentic NGDBs can enable intelligent, self-improving systems for modern data-driven applications, paving the way for adaptable and autonomous data management solutions.","published":"2025-01-24T04:06:50Z","updated":"2025-01-24T04:06:50Z","categories":["cs.AI","cs.DB","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.14224v1","pdf_url":"https://arxiv.org/pdf/2501.14224v1","comment":"12 Pages","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.14037","versioned_id":"2501.14037v2","title":"Emotions, Context, and Substance Use in Adolescents: A Large Language Model Analysis of Reddit Posts","authors":["Jianfeng Zhu","Hailong Jiang","Yulan Wang","Karin G. Coifman","Ruoming Jin","Deric R. Kenne"],"abstract":"Early substance use during adolescence increases the risk of later substance use disorders and mental health problems, yet the emotional and contextual factors driving these behaviors remain poorly understood. This study analyzed 23000 substance-use related posts and an equal number of non-substance posts from Reddit's r/teenagers community (2018-2022). Posts were annotated for six discrete emotions (sadness, anger, joy, guilt, fear, disgust) and contextual factors (family, peers, school) using large language models (LLMs). Statistical analyses compared group differences, and interpretable machine learning (SHAP) identified key predictors of substance-use discussions. LLM-assisted thematic coding further revealed latent psychosocial themes linking emotions with contexts. Negative emotions, especially sadness, guilt, fear, and disgust, were significantly more common in substance-use posts, while joy dominated non-substance discussions. Guilt and shame diverged in function: guilt often reflected regret and self-reflection, whereas shame reinforced risky behaviors through peer performance. Peer influence emerged as the strongest contextual factor, closely tied to sadness, fear, and guilt. Family and school environments acted as both risk and protective factors depending on relational quality and stress levels. Overall, adolescent substance-use discussions reflected a dynamic interplay of emotion, social context, and coping behavior. By integrating statistical analysis, interpretable models, and LLM-based thematic exploration, this study demonstrates the value of mixed computational approaches for uncovering the emotional and contextual mechanisms underlying adolescent risk behavior.","published":"2025-01-23T19:06:26Z","updated":"2025-11-14T15:19:08Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.14037v2","pdf_url":"https://arxiv.org/pdf/2501.14037v2","comment":"19 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.13926","versioned_id":"2501.13926v2","title":"Can We Generate Images with CoT? Let's Verify and Reinforce Image Generation Step by Step","authors":["Ziyu Guo","Renrui Zhang","Chengzhuo Tong","Zhizheng Zhao","Rui Huang","Haoquan Zhang","Manyuan Zhang","Jiaming Liu","Shanghang Zhang","Peng Gao","Hongsheng Li","Pheng-Ann Heng"],"abstract":"Chain-of-Thought (CoT) reasoning has been extensively explored in large models to tackle complex understanding tasks. However, it still remains an open question whether such strategies can be applied to verifying and reinforcing image generation scenarios. In this paper, we provide the first comprehensive investigation of the potential of CoT reasoning to enhance autoregressive image generation. We focus on three techniques: scaling test-time computation for verification, aligning model preferences with Direct Preference Optimization (DPO), and integrating these techniques for complementary effects. Our results demonstrate that these approaches can be effectively adapted and combined to significantly improve image generation performance. Furthermore, given the pivotal role of reward models in our findings, we propose the Potential Assessment Reward Model (PARM) and PARM++, specialized for autoregressive image generation. PARM adaptively assesses each generation step through a potential assessment approach, merging the strengths of existing reward models, and PARM++ further introduces a reflection mechanism to self-correct the generated unsatisfactory image, which is the first to incorporate reflection in autoregressive image generation. Using our investigated reasoning strategies, we enhance a baseline model, Show-o, to achieve superior results, with a significant +24% improvement on the GenEval benchmark, surpassing Stable Diffusion 3 by +15%. We hope our study provides unique insights and paves a new path for integrating CoT reasoning with autoregressive image generation. Code and models are released at https://github.com/ZiyuGuo99/Image-Generation-CoT","published":"2025-01-23T18:59:43Z","updated":"2025-07-23T16:09:10Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2501.13926v2","pdf_url":"https://arxiv.org/pdf/2501.13926v2","comment":"Journal Version. Code and models are released at https://github.com/ZiyuGuo99/Image-Generation-CoT","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.12948","versioned_id":"2501.12948v2","title":"DeepSeek-R1: Incentivizing Reasoning Capability in LLMs via Reinforcement Learning","authors":["DeepSeek-AI","Daya Guo","Dejian Yang","Haowei Zhang","Junxiao Song","Peiyi Wang","Qihao Zhu","Runxin Xu","Ruoyu Zhang","Shirong Ma","Xiao Bi","Xiaokang Zhang","Xingkai Yu","Yu Wu","Z. F. Wu","Zhibin Gou","Zhihong Shao","Zhuoshu Li","Ziyi Gao","Aixin Liu","Bing Xue","Bingxuan Wang","Bochao Wu","Bei Feng","Chengda Lu","Chenggang Zhao","Chengqi Deng","Chenyu Zhang","Chong Ruan","Damai Dai","Deli Chen","Dongjie Ji","Erhang Li","Fangyun Lin","Fucong Dai","Fuli Luo","Guangbo Hao","Guanting Chen","Guowei Li","H. Zhang","Han Bao","Hanwei Xu","Haocheng Wang","Honghui Ding","Huajian Xin","Huazuo Gao","Hui Qu","Hui Li","Jianzhong Guo","Jiashi Li","Jiawei Wang","Jingchang Chen","Jingyang Yuan","Junjie Qiu","Junlong Li","J. L. Cai","Jiaqi Ni","Jian Liang","Jin Chen","Kai Dong","Kai Hu","Kaige Gao","Kang Guan","Kexin Huang","Kuai Yu","Lean Wang","Lecong Zhang","Liang Zhao","Litong Wang","Liyue Zhang","Lei Xu","Leyi Xia","Mingchuan Zhang","Minghua Zhang","Minghui Tang","Meng Li","Miaojun Wang","Mingming Li","Ning Tian","Panpan Huang","Peng Zhang","Qiancheng Wang","Qinyu Chen","Qiushi Du","Ruiqi Ge","Ruisong Zhang","Ruizhe Pan","Runji Wang","R. J. Chen","R. L. Jin","Ruyi Chen","Shanghao Lu","Shangyan Zhou","Shanhuang Chen","Shengfeng Ye","Shiyu Wang","Shuiping Yu","Shunfeng Zhou","Shuting Pan","S. S. Li","Shuang Zhou","Shaoqing Wu","Shengfeng Ye","Tao Yun","Tian Pei","Tianyu Sun","T. Wang","Wangding Zeng","Wanjia Zhao","Wen Liu","Wenfeng Liang","Wenjun Gao","Wenqin Yu","Wentao Zhang","W. L. Xiao","Wei An","Xiaodong Liu","Xiaohan Wang","Xiaokang Chen","Xiaotao Nie","Xin Cheng","Xin Liu","Xin Xie","Xingchao Liu","Xinyu Yang","Xinyuan Li","Xuecheng Su","Xuheng Lin","X. Q. Li","Xiangyue Jin","Xiaojin Shen","Xiaosha Chen","Xiaowen Sun","Xiaoxiang Wang","Xinnan Song","Xinyi Zhou","Xianzu Wang","Xinxia Shan","Y. K. Li","Y. Q. Wang","Y. X. Wei","Yang Zhang","Yanhong Xu","Yao Li","Yao Zhao","Yaofeng Sun","Yaohui Wang","Yi Yu","Yichao Zhang","Yifan Shi","Yiliang Xiong","Ying He","Yishi Piao","Yisong Wang","Yixuan Tan","Yiyang Ma","Yiyuan Liu","Yongqiang Guo","Yuan Ou","Yuduan Wang","Yue Gong","Yuheng Zou","Yujia He","Yunfan Xiong","Yuxiang Luo","Yuxiang You","Yuxuan Liu","Yuyang Zhou","Y. X. Zhu","Yanhong Xu","Yanping Huang","Yaohui Li","Yi Zheng","Yuchen Zhu","Yunxian Ma","Ying Tang","Yukun Zha","Yuting Yan","Z. Z. Ren","Zehui Ren","Zhangli Sha","Zhe Fu","Zhean Xu","Zhenda Xie","Zhengyan Zhang","Zhewen Hao","Zhicheng Ma","Zhigang Yan","Zhiyu Wu","Zihui Gu","Zijia Zhu","Zijun Liu","Zilin Li","Ziwei Xie","Ziyang Song","Zizheng Pan","Zhen Huang","Zhipeng Xu","Zhongyu Zhang","Zhen Zhang"],"abstract":"General reasoning represents a long-standing and formidable challenge in artificial intelligence. Recent breakthroughs, exemplified by large language models (LLMs) and chain-of-thought prompting, have achieved considerable success on foundational reasoning tasks. However, this success is heavily contingent upon extensive human-annotated demonstrations, and models' capabilities are still insufficient for more complex problems. Here we show that the reasoning abilities of LLMs can be incentivized through pure reinforcement learning (RL), obviating the need for human-labeled reasoning trajectories. The proposed RL framework facilitates the emergent development of advanced reasoning patterns, such as self-reflection, verification, and dynamic strategy adaptation. Consequently, the trained model achieves superior performance on verifiable tasks such as mathematics, coding competitions, and STEM fields, surpassing its counterparts trained via conventional supervised learning on human demonstrations. Moreover, the emergent reasoning patterns exhibited by these large-scale models can be systematically harnessed to guide and enhance the reasoning capabilities of smaller models.","published":"2025-01-22T15:19:35Z","updated":"2026-01-04T03:57:36Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.12948v2","pdf_url":"https://arxiv.org/pdf/2501.12948v2","comment":"","journal_ref":"Nature volume 645, pages 633-638 (2025)","doi":"10.1038/s41586-025-09422-z","discovered_on":"2026-07-17"},{"id":"2501.12273","versioned_id":"2501.12273v1","title":"Condor: Enhance LLM Alignment with Knowledge-Driven Data Synthesis and Refinement","authors":["Maosong Cao","Taolin Zhang","Mo Li","Chuyu Zhang","Yunxin Liu","Haodong Duan","Songyang Zhang","Kai Chen"],"abstract":"The quality of Supervised Fine-Tuning (SFT) data plays a critical role in enhancing the conversational capabilities of Large Language Models (LLMs). However, as LLMs become more advanced, the availability of high-quality human-annotated SFT data has become a significant bottleneck, necessitating a greater reliance on synthetic training data. In this work, we introduce Condor, a novel two-stage synthetic data generation framework that incorporates World Knowledge Tree and Self-Reflection Refinement to produce high-quality SFT data at scale. Our experimental results demonstrate that a base model fine-tuned on only 20K Condor-generated samples achieves superior performance compared to counterparts. The additional refinement stage in Condor further enables iterative self-improvement for LLMs at various scales (up to 72B), validating the effectiveness of our approach. Furthermore, our investigation into the scaling for synthetic data in post-training reveals substantial unexplored potential for performance improvements, opening promising avenues for future research.","published":"2025-01-21T16:44:12Z","updated":"2025-01-21T16:44:12Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.12273v1","pdf_url":"https://arxiv.org/pdf/2501.12273v1","comment":"Tech Report. Github: https://github.com/InternLM/Condor","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.13117","versioned_id":"2501.13117v1","title":"MyGO Multiplex CoT: A Method for Self-Reflection in Large Language Models via Double Chain of Thought Thinking","authors":["Shihao Ji","Zihui Song","Fucheng Zhong","Jisen Jia","Zhaobo Wu","Zheyi Cao","Tianhao Xu"],"abstract":"Recent advancements in large language models (LLMs) have demonstrated their impressive abilities in various reasoning and decision-making tasks. However, the quality and coherence of the reasoning process can still benefit from enhanced introspection and self-reflection. In this paper, we introduce Multiplex CoT (Chain of Thought), a method that enables LLMs to simulate a form of self-review while reasoning, by initiating double Chain of Thought (CoT) thinking. Multiplex CoT leverages the power of iterative reasoning, where the model generates an initial chain of thought and subsequently critiques and refines this reasoning with a second round of thought generation. This recursive approach allows for more coherent, logical, and robust answers, improving the overall decision-making process. We demonstrate how this method can be effectively implemented using simple prompt engineering in existing LLM architectures, achieving an effect similar to that of the Learning-Refinement Model (LRM) without the need for additional training. Additionally, we present a practical guide for implementing the method in Google Colab, enabling easy integration into real-world applications.","published":"2025-01-20T12:54:57Z","updated":"2025-01-20T12:54:57Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.13117v1","pdf_url":"https://arxiv.org/pdf/2501.13117v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.11425","versioned_id":"2501.11425v3","title":"Agent-R: Training Language Model Agents to Reflect via Iterative Self-Training","authors":["Siyu Yuan","Zehui Chen","Zhiheng Xi","Junjie Ye","Zhengyin Du","Jiecao Chen"],"abstract":"Large Language Models (LLMs) agents are increasingly pivotal for addressing complex tasks in interactive environments. Existing work mainly focuses on enhancing performance through behavior cloning from stronger experts, yet such approaches often falter in real-world applications, mainly due to the inability to recover from errors. However, step-level critique data is difficult and expensive to collect. Automating and dynamically constructing self-critique datasets is thus crucial to empowering models with intelligent agent capabilities. In this work, we propose an iterative self-training framework, Agent-R, that enables language Agent to Reflect on the fly. Unlike traditional methods that reward or penalize actions based on correctness, Agent-R leverages MCTS to construct training data that recover correct trajectories from erroneous ones. A key challenge of agent reflection lies in the necessity for timely revision rather than waiting until the end of a rollout. To address this, we introduce a model-guided critique construction mechanism: the actor model identifies the first error step (within its current capability) in a failed trajectory. Starting from it, we splice it with the adjacent correct path, which shares the same parent node in the tree. This strategy enables the model to learn reflection based on its current policy, therefore yielding better learning efficiency. To further explore the scalability of this self-improvement paradigm, we investigate iterative refinement of both error correction capabilities and dataset construction. Our findings demonstrate that Agent-R continuously improves the model's ability to recover from errors and enables timely error correction. Experiments on three interactive environments show that Agent-R effectively equips agents to correct erroneous actions while avoiding loops, achieving superior performance compared to baseline methods (+5.59%).","published":"2025-01-20T11:46:04Z","updated":"2025-03-24T10:18:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.11425v3","pdf_url":"https://arxiv.org/pdf/2501.11425v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.11233","versioned_id":"2501.11233v1","title":"PlotEdit: Natural Language-Driven Accessible Chart Editing in PDFs via Multimodal LLM Agents","authors":["Kanika Goswami","Puneet Mathur","Ryan Rossi","Franck Dernoncourt"],"abstract":"Chart visualizations, while essential for data interpretation and communication, are predominantly accessible only as images in PDFs, lacking source data tables and stylistic information. To enable effective editing of charts in PDFs or digital scans, we present PlotEdit, a novel multi-agent framework for natural language-driven end-to-end chart image editing via self-reflective LLM agents. PlotEdit orchestrates five LLM agents: (1) Chart2Table for data table extraction, (2) Chart2Vision for style attribute identification, (3) Chart2Code for retrieving rendering code, (4) Instruction Decomposition Agent for parsing user requests into executable steps, and (5) Multimodal Editing Agent for implementing nuanced chart component modifications - all coordinated through multimodal feedback to maintain visual fidelity. PlotEdit outperforms existing baselines on the ChartCraft dataset across style, layout, format, and data-centric edits, enhancing accessibility for visually challenged users and improving novice productivity.","published":"2025-01-20T02:31:52Z","updated":"2025-01-20T02:31:52Z","categories":["cs.IR","cs.CL","cs.MA"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2501.11233v1","pdf_url":"https://arxiv.org/pdf/2501.11233v1","comment":"Accepted at ECIR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.10316","versioned_id":"2501.10316v4","title":"Know Your Mistakes: Towards Preventing Overreliance on Task-Oriented Conversational AI Through Accountability Modeling","authors":["Suvodip Dey","Yi-Jyun Sun","Gokhan Tur","Dilek Hakkani-Tur"],"abstract":"Recent LLMs have enabled significant advancements for conversational agents. However, they are also well known to hallucinate, producing responses that seem plausible but are factually incorrect. On the other hand, users tend to over-rely on LLM-based AI agents, accepting AI's suggestion even when it is wrong. Adding positive friction, such as explanations or getting user confirmations, has been proposed as a mitigation in AI-supported decision-making systems. In this paper, we propose an accountability model for LLM-based task-oriented dialogue agents to address user overreliance via friction turns in cases of model uncertainty and errors associated with dialogue state tracking (DST). The accountability model is an augmented LLM with an additional accountability head that functions as a binary classifier to predict the relevant slots of the dialogue state mentioned in the conversation. We perform our experiments with multiple backbone LLMs on two established benchmarks (MultiWOZ and Snips). Our empirical findings demonstrate that the proposed approach not only enables reliable estimation of AI agent errors but also guides the decoder in generating more accurate actions. We observe around 3% absolute improvement in joint goal accuracy (JGA) of DST output by incorporating accountability heads into modern LLMs. Self-correcting the detected errors further increases the JGA from 67.13 to 70.51, achieving state-of-the-art DST performance. Finally, we show that error correction through user confirmations (friction turn) achieves a similar performance gain, highlighting its potential to reduce user overreliance.","published":"2025-01-17T17:40:12Z","updated":"2025-06-28T03:44:49Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.10316v4","pdf_url":"https://arxiv.org/pdf/2501.10316v4","comment":"Accepted at ACL 2025 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.09997","versioned_id":"2501.09997v3","title":"Attention-guided Self-reflection for Zero-shot Hallucination Detection in Large Language Models","authors":["Qiang Liu","Xinlong Chen","Yue Ding","Bowen Song","Weiqiang Wang","Shu Wu","Liang Wang"],"abstract":"Hallucination has emerged as a significant barrier to the effective application of Large Language Models (LLMs). In this work, we introduce a novel Attention-Guided SElf-Reflection (AGSER) approach for zero-shot hallucination detection in LLMs. The AGSER method utilizes attention contributions to categorize the input query into attentive and non-attentive queries. Each query is then processed separately through the LLMs, allowing us to compute consistency scores between the generated responses and the original answer. The difference between the two consistency scores serves as a hallucination estimator. In addition to its efficacy in detecting hallucinations, AGSER notably reduces computational overhead, requiring only three passes through the LLM and utilizing two sets of tokens. We have conducted extensive experiments with four widely-used LLMs across three different hallucination benchmarks, demonstrating that our approach significantly outperforms existing methods in zero-shot hallucination detection.","published":"2025-01-17T07:30:01Z","updated":"2025-09-03T10:48:53Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.09997v3","pdf_url":"https://arxiv.org/pdf/2501.09997v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.07875","versioned_id":"2501.07875v1","title":"Continual Learning with Embedding Layer Surgery and Task-wise Beam Search using Whisper","authors":["Chin Yuen Kwok","Jia Qi Yip","Eng Siong Chng"],"abstract":"Current Multilingual ASR models only support a fraction of the world's languages. Continual Learning (CL) aims to tackle this problem by adding new languages to pre-trained models while avoiding the loss of performance on existing languages, also known as Catastrophic Forgetting (CF). However, existing CL methods overlook the adaptation of the token embedding lookup table at the decoder, despite its significant contribution to CF. We propose Embedding Layer Surgery where separate copies of the token embeddings are created for each new languages, and one of the copies is selected to replace the old languages embeddings when transcribing the corresponding new language. Unfortunately, this approach means LID errors also cause incorrect ASR embedding selection. Our Task-wise Beam Search allows self-correction for such mistakes. By adapting Whisper to 10 hours of data for each of 10 unseen languages from Common Voice, results show that our method reduces the Average WER (AWER) of pre-trained languages from 14.2% to 11.9% compared with Experience Replay, without compromising the AWER of the unseen languages.","published":"2025-01-14T06:33:40Z","updated":"2025-01-14T06:33:40Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.07875v1","pdf_url":"https://arxiv.org/pdf/2501.07875v1","comment":"Published in 2024 IEEE Spoken Language Technology Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.05707","versioned_id":"2501.05707v2","title":"Multiagent Finetuning: Self Improvement with Diverse Reasoning Chains","authors":["Vighnesh Subramaniam","Yilun Du","Joshua B. Tenenbaum","Antonio Torralba","Shuang Li","Igor Mordatch"],"abstract":"Large language models (LLMs) have achieved remarkable performance in recent years but are fundamentally limited by the underlying training data. To improve models beyond the training data, recent works have explored how LLMs can be used to generate synthetic data for autonomous self-improvement. However, successive steps of self-improvement can reach a point of diminishing returns. In this work, we propose a complementary approach towards self-improvement where finetuning is applied to a multiagent society of language models. A group of language models, all starting from the same base model, are independently specialized by updating each one using data generated through multiagent interactions among the models. By training each model on independent sets of data, we illustrate how this approach enables specialization across models and diversification over the set of models. As a result, our overall system is able to preserve diverse reasoning chains and autonomously improve over many more rounds of fine-tuning than single-agent self-improvement methods. We quantitatively illustrate the efficacy of the approach across a wide suite of reasoning tasks.","published":"2025-01-10T04:35:46Z","updated":"2025-03-03T18:58:16Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.05707v2","pdf_url":"https://arxiv.org/pdf/2501.05707v2","comment":"ICLR 2025; 22 pages, 13 figures, 7 tables; Project page at https://llm-multiagent-ft.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.02497","versioned_id":"2501.02497v3","title":"A Survey of Test-Time Compute: From Intuitive Inference to Deliberate Reasoning","authors":["Yixin Ji","Juntao Li","Yang Xiang","Hai Ye","Kaixin Wu","Kai Yao","Jia Xu","Linjian Mo","Min Zhang"],"abstract":"The remarkable performance of the o1 model in complex reasoning demonstrates that test-time compute scaling can further unlock the model's potential, enabling powerful System-2 thinking. However, there is still a lack of comprehensive surveys for test-time compute scaling. We trace the concept of test-time compute back to System-1 models. In System-1 models, test-time compute addresses distribution shifts and improves robustness and generalization through parameter updating, input modification, representation editing, and output calibration. In System-2 models, it enhances the model's reasoning ability to solve complex problems through repeated sampling, self-correction, and tree search. We organize this survey according to the trend of System-1 to System-2 thinking, highlighting the key role of test-time compute in the transition from System-1 models to weak System-2 models, and then to strong System-2 models. We also point out advanced topics and future directions.","published":"2025-01-05T10:24:20Z","updated":"2025-06-29T06:49:52Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.02497v3","pdf_url":"https://arxiv.org/pdf/2501.02497v3","comment":"Work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.02295","versioned_id":"2501.02295v4","title":"Explicit vs. Implicit: Investigating Social Bias in Large Language Models through Self-Reflection","authors":["Yachao Zhao","Bo Wang","Yan Wang","Dongming Zhao","Ruifang He","Yuexian Hou"],"abstract":"Large Language Models (LLMs) have been shown to exhibit various biases and stereotypes in their generated content. While extensive research has investigated biases in LLMs, prior work has predominantly focused on explicit bias, with minimal attention to implicit bias and the relation between these two forms of bias. This paper presents a systematic framework grounded in social psychology theories to investigate and compare explicit and implicit biases in LLMs. We propose a novel self-reflection-based evaluation framework that operates in two phases: first measuring implicit bias through simulated psychological assessment methods, then evaluating explicit bias by prompting LLMs to analyze their own generated content. Through extensive experiments on advanced LLMs across multiple social dimensions, we demonstrate that LLMs exhibit a substantial inconsistency between explicit and implicit biases: while explicit bias manifests as mild stereotypes, implicit bias exhibits strong stereotypes. We further investigate the underlying factors contributing to this explicit-implicit bias inconsistency, examining the effects of training data scale, model size, and alignment techniques. Experimental results indicate that while explicit bias declines with increased training data and model size, implicit bias exhibits a contrasting upward trend. Moreover, contemporary alignment methods effectively suppress explicit bias but show limited efficacy in mitigating implicit bias.","published":"2025-01-04T14:08:52Z","updated":"2025-06-03T06:37:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.02295v4","pdf_url":"https://arxiv.org/pdf/2501.02295v4","comment":"Accepted by ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.01702","versioned_id":"2501.01702v2","title":"AgentRefine: Enhancing Agent Generalization through Refinement Tuning","authors":["Dayuan Fu","Keqing He","Yejie Wang","Wentao Hong","Zhuoma Gongque","Weihao Zeng","Wei Wang","Jingang Wang","Xunliang Cai","Weiran Xu"],"abstract":"Large Language Model (LLM) based agents have proved their ability to perform complex tasks like humans. However, there is still a large gap between open-sourced LLMs and commercial models like the GPT series. In this paper, we focus on improving the agent generalization capabilities of LLMs via instruction tuning. We first observe that the existing agent training corpus exhibits satisfactory results on held-in evaluation sets but fails to generalize to held-out sets. These agent-tuning works face severe formatting errors and are frequently stuck in the same mistake for a long while. We analyze that the poor generalization ability comes from overfitting to several manual agent environments and a lack of adaptation to new situations. They struggle with the wrong action steps and can not learn from the experience but just memorize existing observation-action relations. Inspired by the insight, we propose a novel AgentRefine framework for agent-tuning. The core idea is to enable the model to learn to correct its mistakes via observation in the trajectory. Specifically, we propose an agent synthesis framework to encompass a diverse array of environments and tasks and prompt a strong LLM to refine its error action according to the environment feedback. AgentRefine significantly outperforms state-of-the-art agent-tuning work in terms of generalization ability on diverse agent tasks. It also has better robustness facing perturbation and can generate diversified thought in inference. Our findings establish the correlation between agent generalization and self-refinement and provide a new paradigm for future research.","published":"2025-01-03T08:55:19Z","updated":"2025-02-24T12:42:14Z","categories":["cs.AI","cs.CL","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.01702v2","pdf_url":"https://arxiv.org/pdf/2501.01702v2","comment":"ICLR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.02018","versioned_id":"2501.02018v1","title":"Safeguarding Large Language Models in Real-time with Tunable Safety-Performance Trade-offs","authors":["Joao Fonseca","Andrew Bell","Julia Stoyanovich"],"abstract":"Large Language Models (LLMs) have been shown to be susceptible to jailbreak attacks, or adversarial attacks used to illicit high risk behavior from a model. Jailbreaks have been exploited by cybercriminals and blackhat actors to cause significant harm, highlighting the critical need to safeguard widely-deployed models. Safeguarding approaches, which include fine-tuning models or having LLMs \"self-reflect\", may lengthen the inference time of a model, incur a computational penalty, reduce the semantic fluency of an output, and restrict ``normal'' model behavior. Importantly, these Safety-Performance Trade-offs (SPTs) remain an understudied area. In this work, we introduce a novel safeguard, called SafeNudge, that combines Controlled Text Generation with \"nudging\", or using text interventions to change the behavior of a model. SafeNudge triggers during text-generation while a jailbreak attack is being executed, and can reduce successful jailbreak attempts by 30% by guiding the LLM towards a safe responses. It adds minimal latency to inference and has a negligible impact on the semantic fluency of outputs. Further, we allow for tunable SPTs. SafeNudge is open-source and available through https://pypi.org/, and is compatible with models loaded with the Hugging Face \"transformers\" library.","published":"2025-01-02T15:15:38Z","updated":"2025-01-02T15:15:38Z","categories":["cs.CL","cs.AI","cs.CR","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.02018v1","pdf_url":"https://arxiv.org/pdf/2501.02018v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.01264","versioned_id":"2501.01264v2","title":"ProgCo: Program Helps Self-Correction of Large Language Models","authors":["Xiaoshuai Song","Yanan Wu","Weixun Wang","Jiaheng Liu","Wenbo Su","Bo Zheng"],"abstract":"Self-Correction aims to enable large language models (LLMs) to self-verify and self-refine their initial responses without external feedback. However, LLMs often fail to effectively self-verify and generate correct feedback, further misleading refinement and leading to the failure of self-correction, especially in complex reasoning tasks. In this paper, we propose Program-driven Self-Correction (ProgCo). First, program-driven verification (ProgVe) achieves complex verification logic and extensive validation through self-generated, self-executing verification pseudo-programs. Then, program-driven refinement (ProgRe) receives feedback from ProgVe, conducts dual reflection and refinement on both responses and verification programs to mitigate misleading of incorrect feedback in complex reasoning tasks. Experiments on three instruction-following and mathematical benchmarks indicate that ProgCo achieves effective self-correction, and can be further enhance performance when combined with real program tools. We release our code at https://github.com/songxiaoshuai/progco.","published":"2025-01-02T13:59:20Z","updated":"2025-05-27T05:04:23Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.01264v2","pdf_url":"https://arxiv.org/pdf/2501.01264v2","comment":"Accpeted at ACL2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.01237","versioned_id":"2501.01237v2","title":"Self-Refinement Strategies for LLM-based Product Attribute Value Extraction","authors":["Alexander Brinkmann","Christian Bizer"],"abstract":"Structured product data, in the form of attribute-value pairs, is essential for e-commerce platforms to support features such as faceted product search and attribute-based product comparison. However, vendors often provide unstructured product descriptions, making attribute value extraction necessary to ensure data consistency and usability. Large language models (LLMs) have demonstrated their potential for product attribute value extraction in few-shot scenarios. Recent research has shown that self-refinement techniques can improve the performance of LLMs on tasks such as code generation and text-to-SQL translation. For other tasks, the application of these techniques has resulted in increased costs due to processing additional tokens, without achieving any improvement in performance. This paper investigates applying two self-refinement techniques (error-based prompt rewriting and self-correction) to the product attribute value extraction task. The self-refinement techniques are evaluated across zero-shot, few-shot in-context learning, and fine-tuning scenarios using GPT-4o. The experiments show that both self-refinement techniques fail to significantly improve the extraction performance while substantially increasing processing costs. For scenarios with development data, fine-tuning yields the highest performance, while the ramp-up costs of fine-tuning are balanced out as the amount of product descriptions increases.","published":"2025-01-02T12:55:27Z","updated":"2025-02-14T14:47:26Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.01237v2","pdf_url":"https://arxiv.org/pdf/2501.01237v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.00912","versioned_id":"2501.00912v2","title":"AutoPresent: Designing Structured Visuals from Scratch","authors":["Jiaxin Ge","Zora Zhiruo Wang","Xuhui Zhou","Yi-Hao Peng","Sanjay Subramanian","Qinyue Tan","Maarten Sap","Alane Suhr","Daniel Fried","Graham Neubig","Trevor Darrell"],"abstract":"Designing structured visuals such as presentation slides is essential for communicative needs, necessitating both content creation and visual planning skills. In this work, we tackle the challenge of automated slide generation, where models produce slide presentations from natural language (NL) instructions. We first introduce the SlidesBench benchmark, the first benchmark for slide generation with 7k training and 585 testing examples derived from 310 slide decks across 10 domains. SlidesBench supports evaluations that are (i)reference-based to measure similarity to a target slide, and (ii)reference-free to measure the design quality of generated slides alone. We benchmark end-to-end image generation and program generation methods with a variety of models, and find that programmatic methods produce higher-quality slides in user-interactable formats. Built on the success of program generation, we create AutoPresent, an 8B Llama-based model trained on 7k pairs of instructions paired with code for slide generation, and achieve results comparable to the closed-source model GPT-4o. We further explore iterative design refinement where the model is tasked to self-refine its own output, and we found that this process improves the slide's quality. We hope that our work will provide a basis for future work on generating structured visuals.","published":"2025-01-01T18:09:32Z","updated":"2025-06-19T19:27:02Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2501.00912v2","pdf_url":"https://arxiv.org/pdf/2501.00912v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"},{"id":"2501.00747","versioned_id":"2501.00747v1","title":"DIVE: Diversified Iterative Self-Improvement","authors":["Yiwei Qin","Yixiu Liu","Pengfei Liu"],"abstract":"Recent advances in large language models (LLMs) have demonstrated the effectiveness of Iterative Self-Improvement (ISI) techniques. However, continuous training on self-generated data leads to reduced output diversity, a limitation particularly critical in reasoning tasks where diverse solution paths are essential. We present DIVE (Diversified Iterative Self-Improvement), a novel framework that addresses this challenge through two key components: Sample Pool Expansion for broader solution exploration, and Data Selection for balancing diversity and quality in preference pairs. Experiments on MATH and GSM8k datasets show that DIVE achieves a 10% to 45% relative increase in output diversity metrics while maintaining performance quality compared to vanilla ISI. Our ablation studies confirm both components' significance in achieving these improvements. Code is available at https://github.com/qinyiwei/DIVE.","published":"2025-01-01T06:33:45Z","updated":"2025-01-01T06:33:45Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.00747v1","pdf_url":"https://arxiv.org/pdf/2501.00747v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17"}],"query":"(all:\"self improvement\" OR all:\"self-improvement\" OR all:\"self improving\" OR all:\"self-improving\" OR all:\"recursive self-improvement\" OR all:\"self-refinement\" OR all:\"self-reflection\" OR all:\"self-correction\") AND (cat:cs.AI OR cat:cs.CL OR cat:cs.LG OR cat:cs.MA) AND submittedDate:[202501010000 TO 209912312359]","source":"arXiv API","source_url":"https://export.arxiv.org/api/query","last_checked":"2026-07-17T06:39:28+00:00","last_success":"2026-07-17T06:39:28+00:00","new_count":0,"total_cached":1685,"fetch_error":""};
